        "btn-ink-bleed-toggle": ###"""
import SwiftUI

// MARK: - Ink Bleed Toggle
// Toggling drops ink that bleeds outward through irregular feathered edges to
// flood the button in the new color, like dye spreading on wet paper.
// Pure SwiftUI: an opaque base color underneath, a top color revealed through a
// blurred, angularly-irregular blob mask grown from the touch point. No shader.

struct InkBleedToggleView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { geo in
            InkBleedToggleView_InkBleedContent(demo: demo, size: geo.size)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }
}

// MARK: - Button layout (relative to the available size)

private struct InkBleedToggleView_ButtonLayout {
    let rect: CGRect
    let cornerRadius: CGFloat

    init(size: CGSize) {
        let w = max(size.width, 1)
        let h = max(size.height, 1)
        // Inset a little so the drop shadow + bezel breathe inside the tile.
        let bw = w * 0.82
        let bh = min(h * 0.62, bw * 0.46)
        let boxW = min(bw, w - 8)
        let boxH = min(max(bh, 28), h - 8)
        // 0-based, button-local rect. The button is centered in the available
        // size by body's .frame + .position, so all ink math stays in this
        // local space (origin, blob center, clamping, corner distance).
        rect = CGRect(
            x: 0,
            y: 0,
            width: boxW,
            height: boxH
        )
        cornerRadius = min(boxW, boxH) * 0.28
    }

    var shape: RoundedRectangle {
        RoundedRectangle(cornerRadius: cornerRadius, style: .continuous)
    }
}

// MARK: - Content

private struct InkBleedToggleView_InkBleedContent: View {
    let demo: Bool
    let size: CGSize

    // Toggle state: false = "off" color showing, true = "on" color showing.
    @State private var isOn: Bool = false
    // Normalized bleed progress 0...1 (0 = blob fully receded, 1 = fully flooded).
    @State private var progress: CGFloat = 0
    // Where the ink drops from, in this view's coordinate space.
    @State private var origin: CGPoint = .zero
    // Stable per-instance seed so the irregular rim never boils between frames.
    @State private var seed: CGFloat = CGFloat.random(in: 0..<1000)
    // Drives the .selection haptic on interactive taps.
    @State private var feedbackTick: Int = 0
    // Tracks whether the interactive origin has been seeded yet.
    @State private var didSeedOrigin: Bool = false

    var body: some View {
        let layout = InkBleedToggleView_ButtonLayout(size: size)

        ZStack {
            if demo {
                demoButton(layout)
            } else {
                interactiveButton(layout)
            }
        }
        .frame(width: layout.rect.width, height: layout.rect.height)
        .position(x: size.width / 2, y: size.height / 2)
        .onAppear {
            // Default the interactive origin to the button center (local space).
            if !didSeedOrigin {
                origin = CGPoint(x: layout.rect.midX, y: layout.rect.midY)
                didSeedOrigin = true
            }
        }
    }

    // MARK: Interactive (demo == false)

    private func interactiveButton(_ layout: InkBleedToggleView_ButtonLayout) -> some View {
        inkSurface(layout: layout, origin: origin, progress: progress, isOn: isOn)
            .contentShape(layout.shape)
            .gesture(
                SpatialTapGesture(coordinateSpace: .local)
                    .onEnded { value in
                        origin = clampedOrigin(value.location, in: layout.rect)
                        isOn.toggle()
                        feedbackTick &+= 1
                        withAnimation(.easeOut(duration: 0.6)) {
                            progress = isOn ? 1 : 0
                        }
                    }
            )
            .sensoryFeedbackCompat(trigger: feedbackTick)
            .accessibilityElement(children: .ignore)
            .accessibilityLabel("Ink bleed toggle")
            .accessibilityValue(isOn ? "On" : "Off")
            .accessibilityAddTraits(.isButton)
    }

    // MARK: Demo (demo == true) — self-driving, never blank

    private func demoButton(_ layout: InkBleedToggleView_ButtonLayout) -> some View {
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            let phase = demoPhase(at: t, rect: layout.rect)
            inkSurface(
                layout: layout,
                origin: phase.origin,
                progress: phase.progress,
                isOn: phase.isOn
            )
        }
    }

    // A ~3s loop: bloom in (flood new color), hold, bleed back, hold.
    // The drop point shifts each half-cycle so the irregular feathering shows.
    private func demoPhase(at time: TimeInterval, rect: CGRect) -> (origin: CGPoint, progress: CGFloat, isOn: Bool) {
        let period: TimeInterval = 3.0
        let local = time.truncatingRemainder(dividingBy: period) / period // 0..1

        // Two drop points that alternate so the bloom reads as "from a point".
        let dropA = CGPoint(x: rect.minX + rect.width * 0.30, y: rect.midY)
        let dropB = CGPoint(x: rect.minX + rect.width * 0.72, y: rect.midY)

        var p: CGFloat
        var on: Bool
        var pt: CGPoint

        if local < 0.4 {
            // Bloom in from dropA -> flooded "on".
            p = easeOut(CGFloat(local / 0.4))
            on = true
            pt = dropA
        } else if local < 0.5 {
            // Hold flooded.
            p = 1
            on = true
            pt = dropA
        } else if local < 0.9 {
            // Bleed back from dropB -> "off".
            p = easeOut(CGFloat((local - 0.5) / 0.4))
            on = false
            pt = dropB
        } else {
            // Hold receded.
            p = 1
            on = false
            pt = dropB
        }
        return (pt, p, on)
    }

    private func easeOut(_ x: CGFloat) -> CGFloat {
        let c = min(max(x, 0), 1)
        return 1 - (1 - c) * (1 - c)
    }

    // MARK: Shared ink surface

    // Base = the color the button settles toward as progress recedes.
    // Top  = the color flooding in via the blob mask.
    // When isOn: top = onColor over base offColor (blob reveals onColor).
    // When !isOn: top = offColor over base onColor (blob reveals offColor).
    private func inkSurface(layout: InkBleedToggleView_ButtonLayout, origin: CGPoint, progress: CGFloat, isOn: Bool) -> some View {
        let baseColor = isOn ? Self.offColor : Self.onColor
        let topColor = isOn ? Self.onColor : Self.offColor
        let baseLabel = isOn ? Self.offLabel : Self.onLabel
        let topLabel = isOn ? Self.onLabel : Self.offLabel

        // Coverage radius must reach the farthest corner from the origin so an
        // off-center / corner drop still floods the entire button.
        let full = maxCornerDistance(from: origin, in: layout.rect)
        let radius = progress * full
        // Constant feather (not scaled with radius) keeps the blob center opaque.
        let feather: CGFloat = min(layout.rect.width, layout.rect.height) * 0.07 + 3
        let rimVisible = progress > 0.02 && progress < 0.98

        return ZStack {
            // 1. Opaque base — never blank on any frame.
            layout.shape.fill(paper(baseColor))
            label(baseLabel, color: baseColor)

            // 2. Top color revealed through the blurred irregular blob mask.
            ZStack {
                layout.shape.fill(paper(topColor))
                label(topLabel, color: topColor)
            }
            .mask(
                InkBleedToggleView_InkBlobShape(radius: radius, center: origin, seed: seed)
                    .blur(radius: feather)
            )

            // 3. Wet-paper rim sheen on the advancing front for organic feel.
            InkBleedToggleView_InkBlobShape(radius: radius, center: origin, seed: seed)
                .stroke(Color.white.opacity(rimVisible ? 0.10 : 0), lineWidth: 2)
                .blur(radius: feather * 0.8)
                .blendMode(.plusLighter)
                .allowsHitTesting(false)
        }
        .clipShape(layout.shape) // ink must not bleed past the bezel
        .overlay(
            layout.shape.strokeBorder(Color.white.opacity(0.10), lineWidth: 1)
        )
        .shadow(color: Color.black.opacity(0.28), radius: 10, x: 0, y: 6)
        .compositingGroup()
    }

    private func label(_ text: String, color: Color) -> some View {
        let fontSize: CGFloat = max(11, min(size.width, size.height) * 0.085)
        return Text(text)
            .font(.system(size: fontSize, weight: .semibold, design: .rounded))
            .foregroundColor(readableText(on: color))
            .lineLimit(1)
            .minimumScaleFactor(0.6)
            .padding(.horizontal, 8)
    }

    // MARK: Geometry helpers

    private func clampedOrigin(_ p: CGPoint, in rect: CGRect) -> CGPoint {
        CGPoint(
            x: min(max(p.x, rect.minX), rect.maxX),
            y: min(max(p.y, rect.minY), rect.maxY)
        )
    }

    private func maxCornerDistance(from p: CGPoint, in rect: CGRect) -> CGFloat {
        let corners: [CGPoint] = [
            CGPoint(x: rect.minX, y: rect.minY),
            CGPoint(x: rect.maxX, y: rect.minY),
            CGPoint(x: rect.minX, y: rect.maxY),
            CGPoint(x: rect.maxX, y: rect.maxY)
        ]
        var maxD: CGFloat = 0
        for c in corners {
            let dx: CGFloat = c.x - p.x
            let dy: CGFloat = c.y - p.y
            let d: CGFloat = (dx * dx + dy * dy).squareRoot()
            if d > maxD { maxD = d }
        }
        // Pad slightly so the blurred edge fully clears the corner.
        return maxD + 12
    }

    // MARK: Color helpers

    private func paper(_ base: Color) -> LinearGradient {
        LinearGradient(
            colors: [base.opacity(1.0), base.opacity(0.88)],
            startPoint: .top,
            endPoint: .bottom
        )
    }

    private func readableText(on color: Color) -> Color {
        // Both palette colors are mid/dark dye tones, so light text reads on both.
        Color(red: 0.97, green: 0.96, blue: 0.93)
    }

    // MARK: Palette (literals only)

    // "Off" — desaturated slate ink on paper.
    static let offColor = Color(red: 0.20, green: 0.26, blue: 0.34)
    // "On" — a rich indigo/violet dye it bleeds into.
    static let onColor = Color(red: 0.42, green: 0.24, blue: 0.62)

    static let offLabel = "Draft"
    static let onLabel = "Saved"
}

// MARK: - Ink Blob Shape
// An irregular, angularly-modulated blob whose rim lobes are seeded ONCE per
// instance (passed in via `seed`) — no per-frame randomness, so the edge never
// boils. `animatableData` maps to radius for smooth interactive growth.

private struct InkBleedToggleView_InkBlobShape: Shape {
    var radius: CGFloat
    var center: CGPoint
    var seed: CGFloat

    var animatableData: CGFloat {
        get { radius }
        set { radius = newValue }
    }

    func path(in rect: CGRect) -> Path {
        var path = Path()
        guard radius > 0.5 else { return path }

        let steps = 72
        // Three sine harmonics with seed-derived phases create capillary lobes.
        let ph1: CGFloat = seed.truncatingRemainder(dividingBy: 6.283)
        let ph2: CGFloat = (seed * 1.7).truncatingRemainder(dividingBy: 6.283)
        let ph3: CGFloat = (seed * 2.9).truncatingRemainder(dividingBy: 6.283)

        for i in 0...steps {
            let frac = CGFloat(i) / CGFloat(steps)
            let angle = frac * 2 * .pi

            // Angular radius modulation — magnitude eases off as the blob grows
            // large so the final flood reads as full coverage, not a lumpy edge.
            let growth: CGFloat = min(radius / 60.0, 1.0)
            let wobbleScale: CGFloat = 0.16 - 0.10 * growth // 0.16 small -> 0.06 large
            let lobes: CGFloat =
                sin(angle * 3 + ph1) * 0.55 +
                sin(angle * 5 + ph2) * 0.30 +
                sin(angle * 8 + ph3) * 0.15
            let r: CGFloat = radius * (1 + wobbleScale * lobes)

            let x = center.x + cos(angle) * r
            let y = center.y + sin(angle) * r
            let pt = CGPoint(x: x, y: y)
            if i == 0 {
                path.move(to: pt)
            } else {
                path.addLine(to: pt)
            }
        }
        path.closeSubpath()
        return path
    }
}

// MARK: - Sensory feedback compatibility shim
// sensoryFeedback(_:trigger:) is iOS 17+, which matches the deployment target,
// but we guard defensively so the view also compiles on earlier toolchains.

private extension View {
    @ViewBuilder
    func sensoryFeedbackCompat(trigger: Int) -> some View {
        if #available(iOS 17.0, *) {
            self.sensoryFeedback(.selection, trigger: trigger)
        } else {
            self
        }
    }
}
"""###,
        "btn-knob-detent": ###"""
import SwiftUI

/// A circular hardware-style dial. Rotate it like an audio gear knob: it clicks
/// through notched detents with a tactile micro-rotation kickback at each step
/// until it locks on a value.
///
/// - `demo == true`  → a self-driving PhaseAnimator steps the knob across detents
///   (0 → max → 0) so the tile clicks alive with a kickback at each notch.
/// - `demo == false` → a real DragGesture rotary control (atan2 + delta
///   accumulation) that snaps to the nearest detent with an overshoot spring
///   and fires selection haptics on each detent crossing.
struct KnobDetentView: View {

    var demo: Bool = false

    // MARK: Tunables

    private let detentCount: Int = 8
    private let sweepDegrees: Double = 280          // total travel; clamps so it "locks on a value"
    private var startDegrees: Double { -sweepDegrees / 2 }
    private var endDegrees: Double { sweepDegrees / 2 }
    private var detentStep: Double { sweepDegrees / Double(detentCount - 1) }

    // MARK: Interactive state

    @State private var angle: Double = 0            // current rotation in degrees, clamped to sweep
    @State private var lastRawAngle: Double? = nil  // previous frame's raw atan2 angle (for delta accumulation)
    @State private var detentIndex: Int = 0         // changes on each detent crossing → haptic trigger

    // MARK: Demo phase sequence

    /// Bounce out to the far detent then back — discrete stops are the detents,
    /// the spring overshoot between them is the kickback. ~9 phases keeps the
    /// loop in the 2.5–4s window.
    private let demoPhases: [Int] = [0, 2, 4, 6, 7, 5, 3, 1, 0]

    var body: some View {
        GeometryReader { geo in
            let side = min(geo.size.width, geo.size.height)
            let diameter = side * 0.74

            ZStack {
                if demo {
                    demoKnob(diameter: diameter)
                } else {
                    interactiveKnob(diameter: diameter)
                }
            }
            .frame(width: geo.size.width, height: geo.size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .sensoryFeedback(.selection, trigger: detentIndex)
    }

    // MARK: - Demo (self-driving)

    private func demoKnob(diameter: CGFloat) -> some View {
        PhaseAnimator(demoPhases) { phase in
            knobBody(diameter: diameter, angle: angleFor(detent: phase))
        } animation: { _ in
            // Low damping → the per-step overshoot reads as the detent kickback.
            .spring(response: 0.30, dampingFraction: 0.52)
        }
    }

    // MARK: - Interactive

    private func interactiveKnob(diameter: CGFloat) -> some View {
        // The gesture is attached to this diameter×diameter box, and DragGesture
        // reports `location` in that local space — so the pivot is its own center.
        let center = CGPoint(x: diameter / 2, y: diameter / 2)
        return knobBody(diameter: diameter, angle: angle)
            .contentShape(Circle())
            .gesture(rotationDrag(center: center))
    }

    private func rotationDrag(center: CGPoint) -> some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                let raw = rawAngle(at: value.location, center: center)
                guard let previous = lastRawAngle else {
                    lastRawAngle = raw
                    return
                }
                // Delta accumulation avoids the ±180° atan2 wraparound flip.
                var delta = raw - previous
                if delta > 180 { delta -= 360 }
                if delta < -180 { delta += 360 }
                lastRawAngle = raw

                let proposed = (angle + delta).clamped(to: startDegrees...endDegrees)
                let crossedBefore = nearestDetent(for: angle)
                angle = proposed
                let crossedAfter = nearestDetent(for: angle)
                if crossedAfter != crossedBefore {
                    detentIndex = crossedAfter   // fires selection haptic
                }
            }
            .onEnded { _ in
                lastRawAngle = nil
                let snapped = angleFor(detent: nearestDetent(for: angle))
                withAnimation(.spring(response: 0.26, dampingFraction: 0.5)) {
                    angle = snapped
                }
            }
    }

    /// Raw pointer angle in degrees relative to the knob center (0° = up).
    private func rawAngle(at point: CGPoint, center: CGPoint) -> Double {
        let dx = Double(point.x - center.x)
        let dy = Double(point.y - center.y)
        return atan2(dx, -dy) * 180 / .pi
    }

    private func nearestDetent(for deg: Double) -> Int {
        let idx = Int((deg - startDegrees) / detentStep + 0.5)
        return min(max(idx, 0), detentCount - 1)
    }

    private func angleFor(detent index: Int) -> Double {
        startDegrees + Double(index) * detentStep
    }

    // MARK: - Knob visuals (shared by demo + interactive)

    private func knobBody(diameter: CGFloat, angle: Double) -> some View {
        ZStack {
            detentRing(diameter: diameter)
            tickMarks(diameter: diameter, angle: angle)
            dialFace(diameter: diameter)
                .rotationEffect(.degrees(angle))
            valueReadout(diameter: diameter, angle: angle)
        }
        .frame(width: diameter, height: diameter)
    }

    /// The fixed outer collar with the notch ticks drawn around it.
    private func detentRing(diameter: CGFloat) -> some View {
        Circle()
            .stroke(
                AngularGradient(
                    colors: [
                        Color(red: 0.16, green: 0.14, blue: 0.11),
                        Color(red: 0.34, green: 0.30, blue: 0.24),
                        Color(red: 0.16, green: 0.14, blue: 0.11)
                    ],
                    center: .center
                ),
                lineWidth: diameter * 0.05
            )
            .frame(width: diameter * 1.04, height: diameter * 1.04)
    }

    private func tickMarks(diameter: CGFloat, angle: Double) -> some View {
        let activeDetent = nearestDetent(for: angle)
        return ZStack {
            ForEach(0..<detentCount, id: \.self) { i in
                Capsule()
                    .fill(tickColor(active: activeDetent == i))
                    .frame(width: diameter * 0.018, height: diameter * 0.07)
                    .offset(y: -diameter * 0.56)
                    .rotationEffect(.degrees(angleFor(detent: i)))
            }
        }
        .frame(width: diameter, height: diameter)
    }

    /// Highlight the detent the pointer is closest to.
    private func tickColor(active: Bool) -> Color {
        active
            ? Color(red: 1.0, green: 0.78, blue: 0.35)
            : Color(red: 0.42, green: 0.38, blue: 0.32)
    }

    /// The rotating dial: a metallic disc with a brushed sheen and a pointer.
    private func dialFace(diameter: CGFloat) -> some View {
        ZStack {
            Circle()
                .fill(
                    RadialGradient(
                        colors: [
                            Color(red: 0.30, green: 0.27, blue: 0.23),
                            Color(red: 0.13, green: 0.11, blue: 0.09)
                        ],
                        center: .init(x: 0.35, y: 0.30),
                        startRadius: 0,
                        endRadius: diameter * 0.55
                    )
                )

            // Brushed-metal sheen sweeping across the face.
            Circle()
                .fill(
                    AngularGradient(
                        colors: [
                            Color.white.opacity(0.0),
                            Color.white.opacity(0.16),
                            Color.white.opacity(0.0),
                            Color.white.opacity(0.10),
                            Color.white.opacity(0.0)
                        ],
                        center: .center
                    )
                )
                .blendMode(.screen)

            // Knurled rim indentation.
            Circle()
                .strokeBorder(Color.black.opacity(0.45), lineWidth: diameter * 0.03)

            pointer(diameter: diameter)
        }
        .frame(width: diameter * 0.86, height: diameter * 0.86)
        .shadow(color: .black.opacity(0.5), radius: diameter * 0.04, x: 0, y: diameter * 0.02)
    }

    private func pointer(diameter: CGFloat) -> some View {
        Capsule()
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 1.0, green: 0.82, blue: 0.40),
                        Color(red: 0.92, green: 0.55, blue: 0.18)
                    ],
                    startPoint: .top,
                    endPoint: .bottom
                )
            )
            .frame(width: diameter * 0.04, height: diameter * 0.30)
            .offset(y: -diameter * 0.22)
            .shadow(color: Color(red: 1.0, green: 0.7, blue: 0.3).opacity(0.6),
                    radius: diameter * 0.02)
    }

    /// Center hub showing the locked detent index.
    private func valueReadout(diameter: CGFloat, angle: Double) -> some View {
        let value = nearestDetent(for: angle)
        return Circle()
            .fill(
                RadialGradient(
                    colors: [
                        Color(red: 0.10, green: 0.09, blue: 0.07),
                        Color(red: 0.04, green: 0.03, blue: 0.02)
                    ],
                    center: .center,
                    startRadius: 0,
                    endRadius: diameter * 0.18
                )
            )
            .frame(width: diameter * 0.34, height: diameter * 0.34)
            .overlay(
                Text("\(value)")
                    .font(.system(size: diameter * 0.16, weight: .heavy, design: .rounded))
                    .foregroundStyle(Color(red: 1.0, green: 0.80, blue: 0.40))
                    .monospacedDigit()
            )
            .overlay(
                Circle().strokeBorder(Color.white.opacity(0.06), lineWidth: 1)
            )
    }
}

// MARK: - Helpers

private extension Comparable {
    func clamped(to range: ClosedRange<Self>) -> Self {
        min(max(self, range.lowerBound), range.upperBound)
    }
}
"""###,
        "btn-magnetic-snap": ###"""
import SwiftUI

// MARK: - Magnetic Snap
// As the finger nears the button, the label and a small metal nub lean toward
// the touch point with an inverse-falloff attraction, then snap-lock with a
// recoil wobble when pressed. `demo == true` self-drives via TimelineView;
// `demo == false` is the real interactive DragGesture component.

struct MagneticSnapView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { geo in
            let metrics = MagneticSnapView_Metrics(size: geo.size)
            if demo {
                MagneticSnapView_DemoDriver(metrics: metrics)
            } else {
                MagneticSnapView_InteractiveDriver(metrics: metrics)
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }
}

// MARK: - Layout metrics derived from the tile size

private struct MagneticSnapView_Metrics {
    let size: CGSize
    let minSide: CGFloat
    let center: CGPoint
    let buttonWidth: CGFloat
    let buttonHeight: CGFloat
    let cornerRadius: CGFloat
    let nubSize: CGFloat
    let maxLean: CGFloat
    let maxRotation: Double
    let fontSize: CGFloat

    init(size: CGSize) {
        self.size = size
        let minS: CGFloat = max(min(size.width, size.height), 1)
        self.minSide = minS
        self.center = CGPoint(x: size.width / 2, y: size.height / 2)
        self.buttonWidth = min(size.width * 0.74, minS * 1.35)
        self.buttonHeight = minS * 0.42
        self.cornerRadius = minS * 0.10
        self.nubSize = minS * 0.13
        self.maxLean = minS * 0.16
        self.maxRotation = 14
        self.fontSize = minS * 0.16
    }
}

// MARK: - MagneticSnapView_Attraction model (correct-by-inspection, all numerics annotated)

private enum MagneticSnapView_Attraction {
    /// Maps a finger location to a clamped lean vector + rotation. Uses an
    /// inverse falloff with a floored denominator so it can never blow up.
    static func lean(from point: CGPoint, metrics m: MagneticSnapView_Metrics) -> (offset: CGSize, rotation: Double, pull: CGFloat) {
        let dx: CGFloat = point.x - m.center.x
        let dy: CGFloat = point.y - m.center.y
        let distance: CGFloat = sqrt(dx * dx + dy * dy)

        // Influence radius: how far away the finger still affects the nub.
        let radius: CGFloat = max(m.minSide * 0.9, 1)
        // Floored denominator — never divides by ~0.
        let floored: CGFloat = max(distance, m.minSide * 0.18)
        // Inverse falloff in 0...1, strongest when close.
        let raw: CGFloat = radius / (floored + radius)
        let pull: CGFloat = min(max(raw * 1.3, 0), 1)

        // Unit direction toward the finger (guarded).
        let safeDist: CGFloat = max(distance, 0.0001)
        let ux: CGFloat = dx / safeDist
        let uy: CGFloat = dy / safeDist

        let leanX: CGFloat = clampLean(ux * pull * m.maxLean, limit: m.maxLean)
        let leanY: CGFloat = clampLean(uy * pull * m.maxLean, limit: m.maxLean)

        // Tilt toward the horizontal direction of pull.
        let rot: Double = Double(ux * pull) * m.maxRotation

        return (CGSize(width: leanX, height: leanY), rot, pull)
    }

    private static func clampLean(_ value: CGFloat, limit: CGFloat) -> CGFloat {
        min(max(value, -limit), limit)
    }
}

// MARK: - Presentational core (single source of truth for both modes)

private struct MagneticSnapView_MagneticButton: View {
    let metrics: MagneticSnapView_Metrics
    let lean: CGSize          // current attraction lean
    let rotation: Double      // current tilt in degrees
    let pull: CGFloat         // 0...1 proximity strength
    let recoil: CGFloat       // 0...1 snap-recoil envelope (1 = freshly snapped)
    let pressed: Bool

    private var plateColor: Color { Color(red: 0.16, green: 0.18, blue: 0.22) }
    private var plateHi: Color { Color(red: 0.28, green: 0.31, blue: 0.37) }
    private var accent: Color { Color(red: 0.96, green: 0.78, blue: 0.36) }

    // Recoil overshoot: a small extra scale/offset kick that decays with `recoil`.
    private var recoilScale: CGFloat {
        let kick: CGFloat = 0.06 * recoil
        return pressed ? (1 - kick) : (1 + kick * 0.5)
    }

    var body: some View {
        ZStack {
            plate
            nub
            label
        }
        .frame(width: metrics.buttonWidth, height: metrics.buttonHeight)
        .position(metrics.center)
    }

    private var plate: some View {
        let shape = RoundedRectangle(cornerRadius: metrics.cornerRadius, style: .continuous)
        let borderOpacity: Double = 0.30 + Double(pull) * 0.45
        let glowOpacity: Double = 0.25 + Double(pull) * 0.35
        let glowRadius: CGFloat = metrics.minSide * (0.04 + pull * 0.10)
        let borderWidth: CGFloat = max(metrics.minSide * 0.012, 1)
        return shape
            .fill(
                LinearGradient(
                    colors: [plateHi, plateColor],
                    startPoint: .topLeading,
                    endPoint: .bottomTrailing
                )
            )
            .overlay(
                shape.strokeBorder(
                    accent.opacity(borderOpacity),
                    lineWidth: borderWidth
                )
            )
            .shadow(
                color: accent.opacity(glowOpacity),
                radius: glowRadius,
                x: 0,
                y: metrics.minSide * 0.02
            )
            .scaleEffect(recoilScale)
            .rotation3DEffect(
                .degrees(rotation * 0.35),
                axis: (x: 0, y: 1, z: 0),
                perspective: 0.5
            )
            .animation(.spring(response: 0.3, dampingFraction: 0.45), value: pressed)
    }

    private var nub: some View {
        // The little metal nub that leans hardest toward the finger.
        let nubLean = CGSize(
            width: lean.width * 1.35,
            height: lean.height * 1.35
        )
        let nubShadowRadius: CGFloat = metrics.nubSize * 0.5 * (0.5 + pull)
        return Circle()
            .fill(
                RadialGradient(
                    colors: [Color(red: 0.98, green: 0.85, blue: 0.55), accent, Color(red: 0.62, green: 0.46, blue: 0.16)],
                    center: .init(x: 0.35, y: 0.30),
                    startRadius: 0,
                    endRadius: metrics.nubSize * 0.7
                )
            )
            .overlay(
                Circle().strokeBorder(Color.white.opacity(0.5), lineWidth: max(metrics.nubSize * 0.06, 0.5))
            )
            .frame(width: metrics.nubSize, height: metrics.nubSize)
            .shadow(color: accent.opacity(0.6), radius: nubShadowRadius)
            .offset(nubLean)
            .rotationEffect(.degrees(rotation))
            .scaleEffect(1 + recoil * 0.18)
    }

    private var label: some View {
        Text("SNAP")
            .font(.system(size: metrics.fontSize, weight: .heavy, design: .rounded))
            .kerning(metrics.fontSize * 0.08)
            .foregroundStyle(Color.white.opacity(0.92))
            .minimumScaleFactor(0.5)
            .lineLimit(1)
            .offset(x: lean.width * 0.5, y: lean.height * 0.5)
            .rotationEffect(.degrees(rotation * 0.5))
            .shadow(color: accent.opacity(Double(pull) * 0.8), radius: metrics.minSide * 0.03)
    }
}

// MARK: - Demo driver — self-driving phantom touch, NO haptics

private struct MagneticSnapView_DemoDriver: View {
    let metrics: MagneticSnapView_Metrics

    var body: some View {
        // TimelineView gives a continuous clock; we synthesize a phantom finger
        // sweeping in from the edge to center and back, plus a recoil envelope.
        TimelineView(.animation) { context in
            let t = context.date.timeIntervalSinceReferenceDate
            let phase = MagneticSnapView_PhantomPhase(time: t, metrics: metrics)
            MagneticSnapView_MagneticButton(
                metrics: metrics,
                lean: phase.lean,
                rotation: phase.rotation,
                pull: phase.pull,
                recoil: phase.recoil,
                pressed: phase.pressed
            )
        }
    }
}

/// Pure function of time → presentational inputs. Keeps body tiny.
private struct MagneticSnapView_PhantomPhase {
    let lean: CGSize
    let rotation: Double
    let pull: CGFloat
    let recoil: CGFloat
    let pressed: Bool

    init(time t: TimeInterval, metrics m: MagneticSnapView_Metrics) {
        let period: Double = 3.2
        let local: Double = t.truncatingRemainder(dividingBy: period) / period // 0...1

        // Snap moment near the end of the approach.
        let snapAt: Double = 0.55
        let pressed: Bool = local >= snapAt && local < (snapAt + 0.32)

        // Phantom finger sweeps from far edge (local 0) to center (snap) and out.
        let phantom: CGPoint = MagneticSnapView_PhantomPhase.phantomPoint(local: local, snapAt: snapAt, metrics: m)
        let model = MagneticSnapView_Attraction.lean(from: phantom, metrics: m)

        // Recoil envelope: damped sine starting at the snap, so the overshoot
        // and settle are visibly bouncy (signature moment) without haptics.
        let recoil: CGFloat = MagneticSnapView_PhantomPhase.recoilEnvelope(local: local, snapAt: snapAt)

        self.lean = model.offset
        self.rotation = model.rotation
        self.pull = model.pull
        self.recoil = recoil
        self.pressed = pressed
    }

    private static func phantomPoint(local: Double, snapAt: Double, metrics m: MagneticSnapView_Metrics) -> CGPoint {
        if local < snapAt {
            // Ease the finger in from the left edge toward the center.
            let p: Double = local / snapAt
            let eased: Double = p * p * (3 - 2 * p) // smoothstep
            let startX: CGFloat = m.size.width * 0.04
            let x: CGFloat = startX + (m.center.x - startX) * CGFloat(eased)
            let y: CGFloat = m.center.y + sin(CGFloat(local) * 6) * m.size.height * 0.10
            return CGPoint(x: x, y: y)
        } else {
            // After snap, glide back out to the edge.
            let p: Double = min((local - snapAt) / (1 - snapAt), 1)
            let eased: Double = p * p
            let endX: CGFloat = m.size.width * 0.96
            let x: CGFloat = m.center.x + (endX - m.center.x) * CGFloat(eased)
            let y: CGFloat = m.center.y - sin(CGFloat(local) * 5) * m.size.height * 0.08
            return CGPoint(x: x, y: y)
        }
    }

    private static func recoilEnvelope(local: Double, snapAt: Double) -> CGFloat {
        guard local >= snapAt else { return 0 }
        let dt: Double = local - snapAt
        let decay: Double = exp(-dt * 9.0)
        let wobble: Double = cos(dt * 38.0)
        let value: Double = decay * wobble
        return CGFloat(max(value, 0))
    }
}

// MARK: - Interactive driver — real DragGesture over the whole tile

private struct MagneticSnapView_InteractiveDriver: View {
    let metrics: MagneticSnapView_Metrics

    @State private var location: CGPoint? = nil
    @State private var pressed: Bool = false
    @State private var recoil: CGFloat = 0
    @State private var snapCount: Int = 0

    var body: some View {
        let model = currentModel()
        return MagneticSnapView_MagneticButton(
            metrics: metrics,
            lean: model.offset,
            rotation: model.rotation,
            pull: model.pull,
            recoil: recoil,
            pressed: pressed
        )
        .contentShape(Rectangle())
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .gesture(dragGesture)
        // Haptic ONLY in interactive mode, fired on snap.
        .sensoryFeedback(.impact(flexibility: .soft, intensity: 0.9), trigger: snapCount)
    }

    private func currentModel() -> (offset: CGSize, rotation: Double, pull: CGFloat) {
        guard let loc = location else {
            return (.zero, 0, 0)
        }
        return MagneticSnapView_Attraction.lean(from: loc, metrics: metrics)
    }

    private var dragGesture: some Gesture {
        DragGesture(minimumDistance: 0, coordinateSpace: .local)
            .onChanged { value in
                location = value.location
                if pressed == false { pressed = true }
            }
            .onEnded { _ in
                // Snap-lock recoil on release.
                snapCount += 1
                location = nil
                withAnimation(.spring(response: 0.3, dampingFraction: 0.45)) {
                    pressed = false
                }
                fireRecoil()
            }
    }

    private func fireRecoil() {
        // Seed the recoil at full amplitude, then defer the spring-to-rest to the
        // next runloop tick. Without the defer, SwiftUI coalesces both writes
        // before the next body eval (1 → 0) and the wobble never renders.
        recoil = 1
        DispatchQueue.main.async {
            withAnimation(.spring(response: 0.45, dampingFraction: 0.42)) {
                recoil = 0
            }
        }
    }
}
"""###,
        "btn-mercury-fill": ###"""
import SwiftUI

/// Mercury Fill — a press drops a blob of liquid metal that sloshes side to side
/// under gravity, overshoots, and rebalances to fill the button as a progress
/// level with a reflective meniscus. All motion is hand-rolled and driven from a
/// single TimelineView so the slosh overshoot and the perpetual traveling ripple
/// are both genuinely animated frame-by-frame (a plain withAnimation + Canvas
/// read would teleport the level and kill the slosh).
struct MercuryFillView: View {
    var demo: Bool = false

    // Where the fill animation started from / is heading to (0...1).
    @State private var fillStart: CGFloat = 0.12
    @State private var fillTarget: CGFloat = 0.95
    // Reference time for the current transition.
    @State private var transitionStart: Date = .distantPast
    // Seed energy for the slosh, set when a new pour begins.
    @State private var sloshSeed: CGFloat = 1.0
    // Whether the most recent transition has reported its settle haptic.
    @State private var settledFlag: Bool = false
    // Drives sensoryFeedback in interactive mode.
    @State private var settleTick: Int = 0

    // Demo cadence.
    private let demoLow: CGFloat = 0.14
    private let demoHigh: CGFloat = 0.95
    private let demoPeriod: Double = 3.2

    var body: some View {
        GeometryReader { _ in
            TimelineView(.animation) { timeline in
                let now = timeline.date
                content(now: now)
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .contentShape(Rectangle())
        .onTapGesture { handleTap() }
        .sensoryFeedback(.impact(weight: .medium), trigger: settleTick)
        .onAppear {
            // Kick off the first pour so the very first frame is already alive.
            if transitionStart == .distantPast {
                fillStart = demo ? demoLow : 0.12
                fillTarget = demo ? demoHigh : 0.95
                transitionStart = Date()
                sloshSeed = 1.0
            }
        }
    }

    // MARK: - Frame composition

    @ViewBuilder
    private func content(now: Date) -> some View {
        let elapsed = max(0.0, now.timeIntervalSince(transitionStart))
        let cycle: (target: CGFloat, start: CGFloat, restart: Double)? = demo ? demoCycle(now: now) : nil
        let state = resolveState(elapsed: elapsed, cycle: cycle)

        ZStack {
            mercuryCanvas(state: state)
            chrome(state: state)
        }
        .compositingGroup()
    }

    /// In demo mode the pour direction flips automatically each half-period.
    private func demoCycle(now: Date) -> (target: CGFloat, start: CGFloat, restart: Double) {
        let secs = now.timeIntervalSinceReferenceDate
        let phase = secs.truncatingRemainder(dividingBy: demoPeriod)
        let rising = phase < demoPeriod / 2.0
        let segmentStart = secs - (rising ? phase : phase - demoPeriod / 2.0)
        return rising
            ? (demoHigh, demoLow, segmentStart)
            : (demoLow, demoHigh, segmentStart)
    }

    // MARK: - Physics resolution

    struct FillState {
        var fill: CGFloat        // 0...1 settled level (with overshoot baked in)
        var tilt: CGFloat        // -1...1 surface tilt from slosh
        var amp: CGFloat         // traveling-ripple amplitude factor 0...1
        var phase: Double        // perpetual ripple phase
        var glint: CGFloat       // meniscus glint cross-fade 0...1
    }

    private func resolveState(elapsed: Double, cycle: (target: CGFloat, start: CGFloat, restart: Double)?) -> FillState {
        // Use either the persistent interactive transition or the demo's
        // auto-flipping segment as the source of truth.
        let from: CGFloat
        let to: CGFloat
        let t: Double

        if let cycle {
            from = cycle.start
            to = cycle.target
            t = max(0.0, Date().timeIntervalSinceReferenceDate - cycle.restart)
        } else {
            from = fillStart
            to = fillTarget
            t = elapsed
        }

        let level = dampedOvershoot(from: from, to: to, t: t)
        let direction: CGFloat = to >= from ? 1.0 : -1.0

        // Slosh: a fast-decaying sine — fast decay + low frequency reads as
        // metal rather than water.
        let omega: Double = 7.4
        let decay: Double = 3.1
        let env = exp(-decay * t)
        let tilt = direction * sloshSeedFactor() * CGFloat(env * sin(omega * t))

        // Perpetual surface ripple, always present but small at rest.
        let phase = t * 2.2
        let amp = 0.18 + 0.82 * CGFloat(env)  // never fully flat, never blank

        // Meniscus glint crossfades in as the surface settles near the top.
        let glint = max(0.0, min(1.0, level)) * (1.0 - 0.4 * CGFloat(env))

        return FillState(fill: clamp01(level),
                         tilt: clamp(tilt, -1.0, 1.0),
                         amp: clamp01(amp),
                         phase: phase,
                         glint: clamp01(glint))
    }

    private func sloshSeedFactor() -> CGFloat { sloshSeed }

    /// A single overshoot-then-settle curve. Overshoots the target once and
    /// rebalances — the inertia that sells "mercury, not a level snap".
    private func dampedOvershoot(from: CGFloat, to: CGFloat, t: Double) -> CGFloat {
        let span = to - from
        let omega: Double = 6.0
        let zeta: Double = 0.34
        let wd = omega * (1.0 - zeta * zeta).squareRoot()
        let env = exp(-zeta * omega * t)
        // Standard underdamped step response.
        let osc = env * (cos(wd * t) + (zeta * omega / wd) * sin(wd * t))
        let progress = 1.0 - osc
        return from + span * CGFloat(progress)
    }

    // MARK: - Mercury Canvas

    private func mercuryCanvas(state: FillState) -> some View {
        Canvas { ctx, size in
            let radius = min(size.width, size.height) * 0.28
            let bounds = CGRect(origin: .zero, size: size).insetBy(dx: size.width * 0.03,
                                                                    dy: size.height * 0.03)
            let clip = RoundedRectangle(cornerRadius: radius, style: .continuous)
                .path(in: bounds)

            // Dark vial base so the fill always reads against something.
            ctx.fill(clip, with: .linearGradient(
                Gradient(colors: [
                    Color(red: 0.07, green: 0.06, blue: 0.05),
                    Color(red: 0.13, green: 0.11, blue: 0.09)
                ]),
                startPoint: CGPoint(x: bounds.midX, y: bounds.minY),
                endPoint: CGPoint(x: bounds.midX, y: bounds.maxY)
            ))

            var liquid = ctx
            liquid.clip(to: clip)
            drawMercury(in: &liquid, bounds: bounds, state: state)

            // Inner vignette to give the glass vial some depth.
            ctx.stroke(clip, with: .color(Color.black.opacity(0.35)),
                       lineWidth: max(1.0, size.height * 0.012))
        }
    }

    private func drawMercury(in ctx: inout GraphicsContext, bounds: CGRect, state: FillState) {
        let surfaceY = surfaceLevel(bounds: bounds, fill: state.fill)
        let amp = bounds.height * 0.045 * state.amp + bounds.width * 0.012
        let tiltOffset = state.tilt * bounds.height * 0.10

        let body = mercurySurface(bounds: bounds,
                                  surfaceY: surfaceY,
                                  amp: amp,
                                  tilt: tiltOffset,
                                  phase: state.phase)

        // Metallic body: dark steel base → bright specular mid → cool deep.
        ctx.fill(body, with: .linearGradient(
            Gradient(stops: [
                .init(color: Color(red: 0.78, green: 0.80, blue: 0.86), location: 0.0),
                .init(color: Color(red: 0.52, green: 0.55, blue: 0.62), location: 0.18),
                .init(color: Color(red: 0.30, green: 0.32, blue: 0.38), location: 0.55),
                .init(color: Color(red: 0.16, green: 0.17, blue: 0.21), location: 1.0)
            ]),
            startPoint: CGPoint(x: bounds.midX, y: surfaceY - amp),
            endPoint: CGPoint(x: bounds.midX, y: bounds.maxY)
        ))

        // Specular sheen band riding just under the surface.
        let sheen = sheenBand(bounds: bounds, surfaceY: surfaceY, amp: amp,
                              tilt: tiltOffset, phase: state.phase)
        ctx.fill(sheen, with: .linearGradient(
            Gradient(colors: [
                Color.white.opacity(0.0),
                Color.white.opacity(0.55),
                Color.white.opacity(0.0)
            ]),
            startPoint: CGPoint(x: bounds.minX, y: surfaceY),
            endPoint: CGPoint(x: bounds.maxX, y: surfaceY)
        ))

        // Meniscus highlight: a crisp bright line tracing the surface crest.
        let crest = surfaceCrest(bounds: bounds, surfaceY: surfaceY, amp: amp,
                                 tilt: tiltOffset, phase: state.phase)
        ctx.stroke(crest,
                   with: .color(Color.white.opacity(0.45 + 0.45 * Double(state.glint))),
                   style: StrokeStyle(lineWidth: max(1.0, bounds.height * 0.012),
                                      lineCap: .round, lineJoin: .round))

        // Travelling glint dot on the meniscus for the "reflective" pop.
        let glintX = bounds.minX + bounds.width * (0.5 + 0.32 * sin(state.phase))
        let glintY = surfaceY + tiltOffset * (glintX - bounds.midX) / max(1.0, bounds.width / 2.0)
            + amp * CGFloat(sin(state.phase + Double(glintX) * 0.05))
        let dot = CGRect(x: glintX - bounds.width * 0.03,
                         y: glintY - bounds.width * 0.03,
                         width: bounds.width * 0.06,
                         height: bounds.width * 0.06)
        ctx.fill(Ellipse().path(in: dot),
                 with: .radialGradient(
                    Gradient(colors: [Color.white.opacity(0.85 * Double(state.glint)),
                                      Color.white.opacity(0.0)]),
                    center: CGPoint(x: dot.midX, y: dot.midY),
                    startRadius: 0.0,
                    endRadius: bounds.width * 0.04))
    }

    // MARK: - Surface geometry

    private func surfaceLevel(bounds: CGRect, fill: CGFloat) -> CGFloat {
        // fill 0 → bottom, fill 1 → top (with small margins so it never clips).
        let top = bounds.minY + bounds.height * 0.06
        let bottom = bounds.maxY - bounds.height * 0.02
        return bottom - (bottom - top) * fill
    }

    private func waveY(x: CGFloat, bounds: CGRect, surfaceY: CGFloat,
                       amp: CGFloat, tilt: CGFloat, phase: Double) -> CGFloat {
        let half = max(1.0, bounds.width / 2.0)
        let rel = (x - bounds.midX) / half                 // -1...1 across width
        let ripple = amp * CGFloat(sin(Double(x) * 0.06 + phase))
            + amp * 0.4 * CGFloat(sin(Double(x) * 0.13 - phase * 1.6))
        let slant = tilt * rel
        return surfaceY + slant + ripple
    }

    /// Filled liquid body: top is the wavy surface, sides + bottom follow bounds.
    private func mercurySurface(bounds: CGRect, surfaceY: CGFloat, amp: CGFloat,
                                tilt: CGFloat, phase: Double) -> Path {
        var path = Path()
        let steps = 28
        path.move(to: CGPoint(x: bounds.minX, y: bounds.maxY))
        let firstY = waveY(x: bounds.minX, bounds: bounds, surfaceY: surfaceY,
                           amp: amp, tilt: tilt, phase: phase)
        path.addLine(to: CGPoint(x: bounds.minX, y: firstY))
        for i in 1...steps {
            let x = bounds.minX + bounds.width * CGFloat(i) / CGFloat(steps)
            let y = waveY(x: x, bounds: bounds, surfaceY: surfaceY,
                          amp: amp, tilt: tilt, phase: phase)
            path.addLine(to: CGPoint(x: x, y: y))
        }
        path.addLine(to: CGPoint(x: bounds.maxX, y: bounds.maxY))
        path.closeSubpath()
        return path
    }

    /// Just the crest polyline of the surface, for the meniscus highlight.
    private func surfaceCrest(bounds: CGRect, surfaceY: CGFloat, amp: CGFloat,
                              tilt: CGFloat, phase: Double) -> Path {
        var path = Path()
        let steps = 28
        let firstY = waveY(x: bounds.minX, bounds: bounds, surfaceY: surfaceY,
                           amp: amp, tilt: tilt, phase: phase)
        path.move(to: CGPoint(x: bounds.minX, y: firstY))
        for i in 1...steps {
            let x = bounds.minX + bounds.width * CGFloat(i) / CGFloat(steps)
            let y = waveY(x: x, bounds: bounds, surfaceY: surfaceY,
                          amp: amp, tilt: tilt, phase: phase)
            path.addLine(to: CGPoint(x: x, y: y))
        }
        return path
    }

    /// A thin band just below the surface that carries the moving sheen.
    private func sheenBand(bounds: CGRect, surfaceY: CGFloat, amp: CGFloat,
                           tilt: CGFloat, phase: Double) -> Path {
        var path = Path()
        let steps = 28
        let bandDepth = bounds.height * 0.08
        let firstY = waveY(x: bounds.minX, bounds: bounds, surfaceY: surfaceY,
                           amp: amp, tilt: tilt, phase: phase)
        path.move(to: CGPoint(x: bounds.minX, y: firstY))
        for i in 1...steps {
            let x = bounds.minX + bounds.width * CGFloat(i) / CGFloat(steps)
            let y = waveY(x: x, bounds: bounds, surfaceY: surfaceY,
                          amp: amp, tilt: tilt, phase: phase)
            path.addLine(to: CGPoint(x: x, y: y))
        }
        for i in stride(from: steps, through: 0, by: -1) {
            let x = bounds.minX + bounds.width * CGFloat(i) / CGFloat(steps)
            let y = waveY(x: x, bounds: bounds, surfaceY: surfaceY,
                          amp: amp, tilt: tilt, phase: phase) + bandDepth
            path.addLine(to: CGPoint(x: x, y: y))
        }
        path.closeSubpath()
        return path
    }

    // MARK: - Chrome (border + label)

    private func chrome(state: FillState) -> some View {
        GeometryReader { geo in
            let radius = min(geo.size.width, geo.size.height) * 0.28
            ZStack {
                RoundedRectangle(cornerRadius: radius, style: .continuous)
                    .strokeBorder(
                        LinearGradient(
                            colors: [
                                Color(red: 0.92, green: 0.92, blue: 0.96).opacity(0.9),
                                Color(red: 0.40, green: 0.42, blue: 0.48).opacity(0.7)
                            ],
                            startPoint: .topLeading,
                            endPoint: .bottomTrailing
                        ),
                        lineWidth: max(1.0, geo.size.height * 0.02)
                    )
                    .padding(geo.size.width * 0.03)

                label(progress: state.fill, size: geo.size)
            }
            .frame(width: geo.size.width, height: geo.size.height)
        }
        .allowsHitTesting(false)
    }

    private func label(progress: CGFloat, size: CGSize) -> some View {
        let pct = Int((progress * 100).rounded())
        let dim = min(size.width, size.height)
        return VStack(spacing: dim * 0.04) {
            Text(progress > 0.6 ? "FILLED" : "FILL")
                .font(.system(size: dim * 0.16, weight: .heavy, design: .rounded))
                .tracking(dim * 0.02)
            Text("\(pct)%")
                .font(.system(size: dim * 0.12, weight: .semibold, design: .monospaced))
                .opacity(0.85)
        }
        .foregroundStyle(.white)
        .shadow(color: .black.opacity(0.55), radius: dim * 0.02, x: 0, y: dim * 0.01)
        .blendMode(.overlay)
        .overlay {
            VStack(spacing: dim * 0.04) {
                Text(progress > 0.6 ? "FILLED" : "FILL")
                    .font(.system(size: dim * 0.16, weight: .heavy, design: .rounded))
                    .tracking(dim * 0.02)
                Text("\(pct)%")
                    .font(.system(size: dim * 0.12, weight: .semibold, design: .monospaced))
                    .opacity(0.6)
            }
            .foregroundStyle(.white.opacity(0.35))
        }
    }

    // MARK: - Interaction

    private func handleTap() {
        guard !demo else { return }
        // Capture the current resolved level as the new start so the pour is
        // continuous even if tapped mid-animation.
        let elapsed = max(0.0, Date().timeIntervalSince(transitionStart))
        let current = dampedOvershoot(from: fillStart, to: fillTarget, t: elapsed)
        fillStart = clamp01(current)
        fillTarget = fillTarget > 0.5 ? 0.12 : 0.95
        transitionStart = Date()
        sloshSeed = 1.0
        settledFlag = false
        scheduleSettle()
    }

    /// Fire the impact haptic once the slosh has decayed (settle), interactive only.
    private func scheduleSettle() {
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.55) {
            guard !settledFlag else { return }
            settledFlag = true
            settleTick &+= 1
        }
    }

    // MARK: - Helpers

    private func clamp01(_ v: CGFloat) -> CGFloat { min(1.0, max(0.0, v)) }
    private func clamp(_ v: CGFloat, _ lo: CGFloat, _ hi: CGFloat) -> CGFloat {
        min(hi, max(lo, v))
    }
}
"""###,
        "btn-origami-fold": ###"""
import SwiftUI

// MARK: - OrigamiFoldView
// "Paper Plane Fold" — tapping folds the rectangular button along diagonal
// creases into a paper airplane that launches, then unfolds back on reset.
// Pure SwiftUI: rotation3DEffect about diagonal axes + a phased sequence.
public struct OrigamiFoldView: View {
    public var demo: Bool = false

    // Tap trigger for the interactive phase animator.
    @State private var tapCount: Int = 0

    // Explicit phase sequence that begins AND ends on .idle, so the piece
    // rests on a legible flat button regardless of how PhaseAnimator settles
    // (rest-on-first vs rest-on-last). The idle/idle seam is a clean beat.
    private let phases: [OrigamiFoldView_FoldPhase] = [.idle, .creasing, .folded, .launched, .idle]

    public init(demo: Bool = false) {
        self.demo = demo
    }

    public var body: some View {
        GeometryReader { geo in
            let side = min(geo.size.width, geo.size.height)
            ZStack {
                if demo {
                    autoDrivenPlane(side: side)
                } else {
                    interactivePlane(side: side)
                }
            }
            .frame(width: geo.size.width, height: geo.size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .contentShape(Rectangle())
    }

    // MARK: Auto-driven (demo) — continuous loop, no touch, never blank.
    @ViewBuilder
    private func autoDrivenPlane(side: CGFloat) -> some View {
        plane(side: side, phase: .idle)
            .phaseAnimator(phases) { content, phase in
                content
                    .modifier(OrigamiFoldView_FoldEffect(phase: phase, side: side))
            } animation: { phase in
                phase.animation
            }
    }

    // MARK: Interactive — tap to fold + launch, then unfold back to idle.
    @ViewBuilder
    private func interactivePlane(side: CGFloat) -> some View {
        plane(side: side, phase: .idle)
            .phaseAnimator(phases, trigger: tapCount) { content, phase in
                content
                    .modifier(OrigamiFoldView_FoldEffect(phase: phase, side: side))
            } animation: { phase in
                phase.animation
            }
            .onTapGesture {
                tapCount += 1
            }
            .sensoryFeedback(.impact(weight: .medium), trigger: tapCount)
    }

    // MARK: The plane itself — two triangular panels that fold about the
    // shared diagonal crease, plus a fuselage spine and a printed label.
    @ViewBuilder
    private func plane(side: CGFloat, phase: OrigamiFoldView_FoldPhase) -> some View {
        let w = side * 0.78
        let h = side * 0.48

        ZStack {
            // Base body (the "paper") — keeps the silhouette readable in idle.
            bodyPanel(width: w, height: h)

            // Left wing panel, folds up about the body's leading diagonal.
            wingPanel(width: w, height: h, isLeading: true)

            // Right wing panel, folds up about the body's trailing diagonal.
            wingPanel(width: w, height: h, isLeading: false)

            // Center spine / fuselage crease highlight.
            spine(width: w, height: h)

            // Printed glyph on the paper — fades as it folds into a plane.
            label(side: side)
        }
        .frame(width: w, height: h)
    }

    // MARK: Body panel (flat sheet base)
    @ViewBuilder
    private func bodyPanel(width: CGFloat, height: CGFloat) -> some View {
        RoundedRectangle(cornerRadius: height * 0.16, style: .continuous)
            .fill(paperBase)
            .overlay(
                RoundedRectangle(cornerRadius: height * 0.16, style: .continuous)
                    .stroke(creaseLine, lineWidth: 0.8)
            )
            .frame(width: width, height: height)
    }

    // MARK: One triangular wing that creases up about a diagonal axis.
    // The fold angle/perspective are applied by OrigamiFoldView_FoldEffect on the whole
    // plane; here each wing carries its own crease-shaded gradient so the
    // fold reads as 3D paper rather than a flat scale.
    @ViewBuilder
    private func wingPanel(width: CGFloat, height: CGFloat, isLeading: Bool) -> some View {
        OrigamiFoldView_WingTriangle(isLeading: isLeading)
            .fill(isLeading ? wingGradientLeading : wingGradientTrailing)
            .overlay(
                OrigamiFoldView_WingTriangle(isLeading: isLeading)
                    .stroke(creaseLine, lineWidth: 0.9)
            )
            .frame(width: width, height: height)
    }

    // MARK: Fuselage spine — the central diagonal crease the wings fold around.
    @ViewBuilder
    private func spine(width: CGFloat, height: CGFloat) -> some View {
        OrigamiFoldView_SpineShape()
            .stroke(
                LinearGradient(
                    colors: [
                        Color(red: 0.40, green: 0.36, blue: 0.30).opacity(0.0),
                        Color(red: 0.40, green: 0.36, blue: 0.30).opacity(0.55),
                        Color(red: 0.40, green: 0.36, blue: 0.30).opacity(0.0)
                    ],
                    startPoint: .leading,
                    endPoint: .trailing
                ),
                style: StrokeStyle(lineWidth: 1.4, lineCap: .round)
            )
            .frame(width: width, height: height)
    }

    // MARK: Printed label glyph
    @ViewBuilder
    private func label(side: CGFloat) -> some View {
        Image(systemName: "paperplane.fill")
            .font(.system(size: side * 0.16, weight: .semibold))
            .foregroundStyle(Color(red: 0.30, green: 0.26, blue: 0.20).opacity(0.55))
            .rotationEffect(.degrees(-20))
    }

    // MARK: - Paper palette
    private var paperBase: LinearGradient {
        LinearGradient(
            colors: [
                Color(red: 0.97, green: 0.95, blue: 0.90),
                Color(red: 0.91, green: 0.88, blue: 0.81)
            ],
            startPoint: .topLeading,
            endPoint: .bottomTrailing
        )
    }

    private var wingGradientLeading: LinearGradient {
        LinearGradient(
            colors: [
                Color(red: 0.99, green: 0.97, blue: 0.93),
                Color(red: 0.86, green: 0.82, blue: 0.73)
            ],
            startPoint: .top,
            endPoint: .bottom
        )
    }

    private var wingGradientTrailing: LinearGradient {
        LinearGradient(
            colors: [
                Color(red: 0.88, green: 0.84, blue: 0.76),
                Color(red: 0.78, green: 0.73, blue: 0.63)
            ],
            startPoint: .top,
            endPoint: .bottom
        )
    }

    private var creaseLine: Color {
        Color(red: 0.55, green: 0.50, blue: 0.42).opacity(0.45)
    }
}

// MARK: - Fold phases & transforms
private enum OrigamiFoldView_FoldPhase: CaseIterable {
    case idle       // flat, legible button
    case creasing   // wings lifting along the diagonals
    case folded     // fully folded paper airplane
    case launched   // glides toward a corner (PARTIAL exit — never blank)

    // How far the wings are folded up, 0 (flat) → 1 (full).
    var foldProgress: CGFloat {
        switch self {
        case .idle:     return 0
        case .creasing: return 0.55
        case .folded:   return 1
        case .launched: return 1
        }
    }

    // Out-of-plane fold angle for the wings.
    var wingAngle: Double {
        Double(foldProgress) * 74.0
    }

    // Whole-plane pitch as it tips into a 3D paper form.
    var pitch: Double {
        switch self {
        case .idle:     return 0
        case .creasing: return 6
        case .folded:   return 14
        case .launched: return 22
        }
    }

    // Heading rotation when it flies off.
    var heading: Double {
        switch self {
        case .launched: return -28
        case .folded:   return -4
        default:        return 0
        }
    }

    // Screen offset as a FRACTION of the layout side (kept partial so the
    // tile never goes blank — the plane glides toward, not past, the corner).
    var offsetFraction: CGSize {
        switch self {
        case .launched: return CGSize(width: 0.34, height: -0.30)
        case .folded:   return CGSize(width: 0.04, height: -0.02)
        default:        return .zero
        }
    }

    var scale: CGFloat {
        switch self {
        case .idle:     return 1.0
        case .creasing: return 0.98
        case .folded:   return 0.92
        case .launched: return 0.56
        }
    }

    // Always legible — launched stays at 0.7, never disappears.
    var opacity: Double {
        switch self {
        case .launched: return 0.70
        default:        return 1.0
        }
    }

    // Per-phase pacing so a full cycle lands around ~3s with an idle dwell.
    var animation: Animation {
        switch self {
        case .idle:     return .easeInOut(duration: 0.55)
        case .creasing: return .spring(response: 0.45, dampingFraction: 0.78)
        case .folded:   return .spring(response: 0.40, dampingFraction: 0.85)
        case .launched: return .easeIn(duration: 0.75)
        }
    }
}

// MARK: - The fold + launch transform applied to the whole plane.
// Each wing is folded individually via the OrigamiFoldView_FoldEffect-aware WingFolder so the
// crease reads as true 3D paper about the diagonal axes.
private struct OrigamiFoldView_FoldEffect: ViewModifier {
    let phase: OrigamiFoldView_FoldPhase
    let side: CGFloat

    func body(content: Content) -> some View {
        content
            // Fold the two wings up about their diagonal creases. Because the
            // wing triangles share the body's diagonals, a y-axis-biased
            // diagonal rotation reads as the classic paper-plane crease.
            .modifier(OrigamiFoldView_WingFoldModifier(angle: phase.wingAngle))
            // Whole-plane pitch into a 3D paper attitude.
            .rotation3DEffect(
                .degrees(phase.pitch),
                axis: (x: CGFloat(1), y: CGFloat(0), z: CGFloat(0)),
                anchor: .center,
                perspective: 0.6
            )
            // Heading turn as it banks away.
            .rotationEffect(.degrees(phase.heading))
            .scaleEffect(phase.scale)
            .offset(
                x: phase.offsetFraction.width * side,
                y: phase.offsetFraction.height * side
            )
            .opacity(phase.opacity)
    }
}

// MARK: - Folds the symmetric wings about the central diagonal creases.
// A single y-axis rotation3DEffect with a diagonal-biased axis lifts both
// wing halves symmetrically about the spine, giving the dihedral crease.
private struct OrigamiFoldView_WingFoldModifier: ViewModifier {
    let angle: Double

    func body(content: Content) -> some View {
        content
            // Lift wings out of plane about the vertical spine (y) blended
            // toward the diagonal (small x component) for the crease feel.
            .rotation3DEffect(
                .degrees(angle),
                axis: (x: CGFloat(0.18), y: CGFloat(1), z: CGFloat(0)),
                anchor: .center,
                perspective: 0.7
            )
            // A faint counter on the orthogonal diagonal sharpens the crease.
            .rotation3DEffect(
                .degrees(angle * 0.22),
                axis: (x: CGFloat(1), y: CGFloat(0.0), z: CGFloat(0)),
                anchor: .bottom,
                perspective: 0.4
            )
    }
}

// MARK: - Geometry: one wing triangle (half the sheet, split on a diagonal)
private struct OrigamiFoldView_WingTriangle: Shape {
    let isLeading: Bool

    func path(in rect: CGRect) -> Path {
        var p = Path()
        // The nose is the leading mid-height tip; each wing is a triangle from
        // the nose to the trailing top/bottom corner and back along the spine.
        let nose = CGPoint(x: rect.minX, y: rect.midY)
        let tailTop = CGPoint(x: rect.maxX, y: rect.minY)
        let tailBottom = CGPoint(x: rect.maxX, y: rect.maxY)
        let tailMid = CGPoint(x: rect.maxX, y: rect.midY)

        p.move(to: nose)
        if isLeading {
            p.addLine(to: tailTop)
            p.addLine(to: tailMid)
        } else {
            p.addLine(to: tailBottom)
            p.addLine(to: tailMid)
        }
        p.closeSubpath()
        return p
    }
}

// MARK: - Geometry: the fuselage spine (nose → tail center line)
private struct OrigamiFoldView_SpineShape: Shape {
    func path(in rect: CGRect) -> Path {
        var p = Path()
        p.move(to: CGPoint(x: rect.minX, y: rect.midY))
        p.addLine(to: CGPoint(x: rect.maxX, y: rect.midY))
        return p
    }
}
"""###,
        "btn-piston-pump": ###"""
import SwiftUI

// MARK: - Piston Pump
// Hold-to-confirm. A mechanical piston pumps up and down, each stroke building
// pressure in a gauge. The longer you hold, the faster the piston cycles and the
// more the gauge fills, until it redlines and fires. Release early drains it back.
//
// Architecture: ONE TimelineView(.animation) drives a fileprivate integrator
// (PistonPumpView_PistonPumpSim) so the piston oscillation and the gauge fill share a single
// clock — cadence stays perfectly synced. The piston frequency rises with held
// progress, and we integrate PHASE (not scaled time) so the stroke never jumps
// when the speed changes mid-cycle.

struct PistonPumpView: View {
    var demo: Bool = false

    @State private var sim = PistonPumpView_PistonPumpSim()
    @State private var pressing: Bool = false
    @State private var fireTick: Int = 0
    @State private var drainTick: Int = 0

    var body: some View {
        GeometryReader { geo in
            let side = min(geo.size.width, geo.size.height)

            TimelineView(.animation) { timeline in
                // Advance the simulation off a single clock. All per-frame mutable
                // state lives on the class (safe to mutate here — no @State writes
                // inside the view-update closure).
                let snapshot = sim.advance(
                    date: timeline.date,
                    demo: demo,
                    pressing: pressing
                )

                PistonPumpView_PistonPumpScene(
                    state: snapshot,
                    side: side
                )
            }
            .frame(width: geo.size.width, height: geo.size.height)
            .contentShape(Rectangle())
            .modifier(
                PistonPumpView_PistonInteraction(
                    demo: demo,
                    pressing: $pressing,
                    fireTick: $fireTick,
                    drainTick: $drainTick
                )
            )
            .sensoryFeedback(.success, trigger: demo ? 0 : fireTick)
            .sensoryFeedback(.impact(weight: .light), trigger: demo ? 0 : drainTick)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }
}

// MARK: - Interaction (interactive vs. demo)

/// The long-press `onPressingChanged:` callback is the only reliable "while held"
/// signal on iOS 17 — a bare LongPressGesture fires once at the end and cannot
/// drive rising progress. `perform` fires at the redline moment (~2.5s) where
/// bumping a @State trigger is safe. Demo mode attaches no gesture and no haptics.
private struct PistonPumpView_PistonInteraction: ViewModifier {
    let demo: Bool
    @Binding var pressing: Bool
    @Binding var fireTick: Int
    @Binding var drainTick: Int

    func body(content: Content) -> some View {
        if demo {
            content
        } else {
            content.onLongPressGesture(
                minimumDuration: 2.5,
                maximumDistance: 60,
                perform: {
                    fireTick &+= 1
                },
                onPressingChanged: { isPressing in
                    if !isPressing && pressing {
                        // Released before redline -> gauge will drain.
                        drainTick &+= 1
                    }
                    pressing = isPressing
                }
            )
        }
    }
}

// MARK: - Simulation

/// Held on the view as @State (value-type box around a reference). All per-frame
/// mutation happens here, off the SwiftUI state graph, which is the standard
/// pattern for TimelineView-driven sims.
private struct PistonPumpView_PistonPumpSim {
    private let core = Core()

    func advance(date: Date, demo: Bool, pressing: Bool) -> PistonPumpView_PistonState {
        core.advance(date: date, demo: demo, pressing: pressing)
    }

    final class Core {
        private var lastT: TimeInterval?
        private var progress: CGFloat = 0      // 0...1 pressure
        private var pistonPhase: CGFloat = 0   // integrated angle (radians)
        private var fired: Bool = false
        private var holdAfterFire: CGFloat = 0 // brief redline-pop dwell
        private var flash: CGFloat = 0         // 0...1 fire flash

        // Demo auto-cycle: a phantom hold that builds, fires, pops, resets.
        private var demoClock: TimeInterval = 0

        func advance(date: Date, demo: Bool, pressing: Bool) -> PistonPumpView_PistonState {
            let now = date.timeIntervalSinceReferenceDate
            let raw = lastT.map { now - $0 } ?? 0
            lastT = now
            // Clamp dt so a backgrounded/first frame doesn't fast-forward the sim.
            let dt = CGFloat(max(0.0, min(raw, 1.0 / 30.0)))

            let held: Bool
            if demo {
                held = updateDemo(dt: dt)
            } else {
                held = pressing
            }

            updatePressure(dt: dt, held: held)
            integratePiston(dt: dt)
            updateFire(dt: dt)

            return PistonPumpView_PistonState(
                progress: progress,
                pistonOffset: sin(pistonPhase),     // -1...1, used by scene
                flash: flash,
                fired: fired,
                redlined: progress >= 0.999
            )
        }

        // Phantom hold on a ~3.4s loop: hold ~2.6s (build + redline pop), then
        // release and let it drain, never blanking — idle state stays legible.
        private func updateDemo(dt: CGFloat) -> Bool {
            demoClock += TimeInterval(dt)
            let loop: TimeInterval = 3.4
            if demoClock >= loop {
                demoClock -= loop
                fired = false
                holdAfterFire = 0
            }
            // Hold for the first 2.6s of the loop, then release.
            return demoClock < 2.6
        }

        private func updatePressure(dt: CGFloat, held: Bool) {
            if fired {
                // Hold the redline briefly, then bleed off after the pop.
                holdAfterFire += dt
                if holdAfterFire > 0.45 {
                    progress = max(0, progress - dt * 1.6)
                    if progress <= 0.001 {
                        fired = false
                        holdAfterFire = 0
                    }
                }
                return
            }

            if held {
                // Fill so progress ~ 1 at ~2.5s (the long-press redline moment).
                // Slight ease so the last bit feels like it's straining.
                let rate: CGFloat = 0.40 + progress * 0.10
                progress = min(1, progress + dt * rate)
                if progress >= 0.999 {
                    fired = true
                    flash = 1
                    holdAfterFire = 0
                }
            } else {
                // Released early -> drain back down, faster than it filled.
                progress = max(0, progress - dt * 0.95)
            }
        }

        // Integrate phase, never scale time. Frequency rises with progress so the
        // piston visibly accelerates, but offset = sin(phase) stays continuous —
        // no teleport when the speed changes mid-stroke.
        private func integratePiston(dt: CGFloat) {
            let minHz: CGFloat = 0.9
            let maxHz: CGFloat = 5.2
            // Even at rest the piston idles slowly so the tile is never frozen.
            let activity = max(progress, fired ? 1 : 0.18)
            let hz = minHz + (maxHz - minHz) * activity
            pistonPhase += dt * hz * 2 * .pi
            if pistonPhase > 2 * .pi { pistonPhase -= 2 * .pi }
        }

        private func updateFire(dt: CGFloat) {
            if flash > 0 {
                flash = max(0, flash - dt * 2.2)
            }
        }
    }
}

private struct PistonPumpView_PistonState {
    var progress: CGFloat
    var pistonOffset: CGFloat   // -1...1
    var flash: CGFloat          // 0...1
    var fired: Bool
    var redlined: Bool
}

// MARK: - Scene

private struct PistonPumpView_PistonPumpScene: View {
    let state: PistonPumpView_PistonState
    let side: CGFloat

    private var accent: Color {
        // Cool steel-blue ramping toward hot redline as pressure builds.
        let p = state.progress
        return Color(
            red: 0.28 + 0.62 * Double(p),
            green: 0.55 - 0.30 * Double(p),
            blue: 0.78 - 0.55 * Double(p)
        )
    }

    var body: some View {
        ZStack {
            background
            PistonPumpView_GaugeArc(progress: state.progress, side: side)
                .frame(width: side * 0.86, height: side * 0.86)
            PistonPumpView_PistonAssembly(
                offset: state.pistonOffset,
                progress: state.progress,
                redlined: state.redlined,
                accent: accent
            )
            .frame(width: side * 0.50, height: side * 0.66)

            centerLabel
            flashOverlay
        }
        .frame(width: side, height: side)
        .compositingGroup()
    }

    private var background: some View {
        RoundedRectangle(cornerRadius: side * 0.20, style: .continuous)
            .fill(
                RadialGradient(
                    colors: [
                        Color(red: 0.16, green: 0.17, blue: 0.20),
                        Color(red: 0.07, green: 0.075, blue: 0.09)
                    ],
                    center: .center,
                    startRadius: 0,
                    endRadius: side * 0.7
                )
            )
            .overlay(
                RoundedRectangle(cornerRadius: side * 0.20, style: .continuous)
                    .strokeBorder(Color.white.opacity(0.06), lineWidth: side * 0.012)
            )
            .frame(width: side, height: side)
    }

    private var centerLabel: some View {
        let symbol = state.fired ? "checkmark" : "bolt.fill"
        return Image(systemName: symbol)
            .font(.system(size: side * 0.12, weight: .heavy))
            .foregroundStyle(state.fired ? Color(red: 0.45, green: 0.95, blue: 0.55) : accent)
            .opacity(0.0)            // hidden behind piston cap; kept for fired glow
            .allowsHitTesting(false)
            .overlay(alignment: .bottom) {
                Text(state.fired ? "FIRED" : (state.redlined ? "REDLINE" : "HOLD"))
                    .font(.system(size: side * 0.075, weight: .bold, design: .rounded))
                    .tracking(side * 0.012)
                    .foregroundStyle(labelColor)
                    .offset(y: side * 0.40)
            }
    }

    private var labelColor: Color {
        if state.fired { return Color(red: 0.50, green: 0.95, blue: 0.60) }
        if state.redlined { return Color(red: 0.96, green: 0.34, blue: 0.30) }
        return Color.white.opacity(0.55)
    }

    private var flashOverlay: some View {
        RoundedRectangle(cornerRadius: side * 0.20, style: .continuous)
            .fill(Color(red: 1.0, green: 0.95, blue: 0.7))
            .opacity(Double(state.flash) * 0.55)
            .blendMode(.screen)
            .allowsHitTesting(false)
            .frame(width: side, height: side)
    }
}

// MARK: - Gauge arc

private struct PistonPumpView_GaugeArc: View {
    let progress: CGFloat
    let side: CGFloat

    var body: some View {
        ZStack {
            // Track
            Circle()
                .trim(from: 0.0, to: 0.75)
                .stroke(
                    Color.white.opacity(0.10),
                    style: StrokeStyle(lineWidth: trackWidth, lineCap: .round)
                )
                .rotationEffect(.degrees(135))

            // Filled pressure
            Circle()
                .trim(from: 0.0, to: 0.75 * progress)
                .stroke(
                    AngularGradient(
                        gradient: Gradient(stops: [
                            .init(color: Color(red: 0.30, green: 0.62, blue: 0.92), location: 0.0),
                            .init(color: Color(red: 0.40, green: 0.85, blue: 0.70), location: 0.45),
                            .init(color: Color(red: 0.95, green: 0.78, blue: 0.25), location: 0.78),
                            .init(color: Color(red: 0.95, green: 0.28, blue: 0.22), location: 1.0)
                        ]),
                        center: .center,
                        startAngle: .degrees(135),
                        endAngle: .degrees(135 + 270)
                    ),
                    style: StrokeStyle(lineWidth: fillWidth, lineCap: .round)
                )
                .rotationEffect(.degrees(135))
                .shadow(color: glowColor.opacity(Double(min(progress, 1)) * 0.8),
                        radius: fillWidth * 0.9)

            // Redline zone marker (last ~15% of the sweep)
            Circle()
                .trim(from: 0.75 * 0.86, to: 0.75)
                .stroke(
                    Color(red: 0.95, green: 0.25, blue: 0.20).opacity(progress >= 0.999 ? 0.95 : 0.30),
                    style: StrokeStyle(lineWidth: trackWidth * 0.4, lineCap: .butt)
                )
                .rotationEffect(.degrees(135))
        }
        .aspectRatio(1, contentMode: .fit)
    }

    // Scale stroke widths off the tile size so the gauge reads correctly in both
    // a ~120pt grid tile and a large detail view (no fixed-pixel hairlines).
    private var trackWidth: CGFloat { max(2.5, side * 0.026) }
    private var fillWidth: CGFloat { max(3, side * 0.032) }

    private var glowColor: Color {
        progress >= 0.999
            ? Color(red: 0.95, green: 0.30, blue: 0.22)
            : Color(red: 0.35, green: 0.70, blue: 0.90)
    }
}

// MARK: - Piston assembly

private struct PistonPumpView_PistonAssembly: View {
    let offset: CGFloat       // -1...1 from sin(phase)
    let progress: CGFloat
    let redlined: Bool
    let accent: Color

    var body: some View {
        GeometryReader { geo in
            let w = geo.size.width
            let h = geo.size.height
            let cylinderH = h * 0.78
            let cylinderW = w * 0.62
            // Stroke pushes the head down within the cylinder as it pumps.
            let travel = cylinderH * 0.30
            // Map sin(-1...1) -> 0...1 downstroke fraction.
            let down = (offset + 1) / 2
            let headY = -travel * 0.5 + travel * down

            ZStack {
                // Cylinder body
                RoundedRectangle(cornerRadius: cylinderW * 0.18, style: .continuous)
                    .fill(
                        LinearGradient(
                            colors: [
                                Color(red: 0.30, green: 0.31, blue: 0.35),
                                Color(red: 0.14, green: 0.15, blue: 0.18)
                            ],
                            startPoint: .leading, endPoint: .trailing
                        )
                    )
                    .overlay(
                        RoundedRectangle(cornerRadius: cylinderW * 0.18, style: .continuous)
                            .strokeBorder(Color.white.opacity(0.10), lineWidth: 1)
                    )
                    .frame(width: cylinderW, height: cylinderH)

                // Compressed-gas glow at the base, brighter under pressure.
                Capsule()
                    .fill(accent)
                    .frame(width: cylinderW * 0.7, height: cylinderH * 0.26)
                    .blur(radius: cylinderW * 0.18)
                    .opacity(0.25 + Double(progress) * 0.65)
                    .offset(y: cylinderH * 0.30)

                // Connecting rod
                Capsule()
                    .fill(
                        LinearGradient(
                            colors: [
                                Color(red: 0.78, green: 0.80, blue: 0.86),
                                Color(red: 0.45, green: 0.47, blue: 0.52)
                            ],
                            startPoint: .leading, endPoint: .trailing
                        )
                    )
                    .frame(width: cylinderW * 0.22, height: cylinderH * 0.95)
                    .offset(y: headY)

                // Piston head / cap
                pistonHead(width: cylinderW * 0.82)
                    .offset(y: headY - cylinderH * 0.30)
            }
            .frame(width: w, height: h)
            .position(x: w / 2, y: h / 2)
        }
    }

    private func pistonHead(width: CGFloat) -> some View {
        RoundedRectangle(cornerRadius: width * 0.22, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.92, green: 0.93, blue: 0.97),
                        Color(red: 0.55, green: 0.57, blue: 0.63)
                    ],
                    startPoint: .top, endPoint: .bottom
                )
            )
            .overlay(
                RoundedRectangle(cornerRadius: width * 0.22, style: .continuous)
                    .stroke(accent.opacity(redlined ? 0.9 : 0.45), lineWidth: redlined ? 2.5 : 1.2)
            )
            .frame(width: width, height: width * 0.42)
            .shadow(color: accent.opacity(Double(progress) * 0.7), radius: width * 0.12)
    }
}
"""###,
        "btn-sand-pour": ###"""
import SwiftUI

// MARK: - Sand Pour
// On tap the button drains its grains downward like an hourglass: particles
// stream through a central pinch to refill a lower chamber that morphs into a
// success label. Pure SwiftUI Canvas + TimelineView. iOS 17.

public struct SandPourView: View {
    public var demo: Bool = false

    public init(demo: Bool = false) {
        self.demo = demo
    }

    // One full pour in interactive mode, in seconds.
    private let pourDuration: Double = 2.6
    // Demo loop: drain time + a short "settled" hold so the success label reads.
    private let demoCycle: Double = 3.6
    private let demoHold: Double = 0.9

    @State private var pourStart: Date? = nil
    @State private var didComplete: Bool = false

    public var body: some View {
        GeometryReader { proxy in
            content(size: proxy.size)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .contentShape(Rectangle())
        .onTapGesture {
            guard !demo else { return }
            startPour()
        }
        .sensoryFeedback(trigger: didComplete) { _, now in
            now ? .success : nil
        }
    }

    @ViewBuilder
    private func content(size: CGSize) -> some View {
        TimelineView(.animation) { timeline in
            let p = progress(at: timeline.date)
            hourglass(size: size, p: p)
        }
    }

    // MARK: - Progress source

    private func progress(at date: Date) -> CGFloat {
        if demo {
            let t = date.timeIntervalSinceReferenceDate
            let phase = t.truncatingRemainder(dividingBy: demoCycle)
            // Drain over (demoCycle - demoHold), then hold full-pile before wrap.
            let drain = max(demoCycle - demoHold, 0.001)
            let raw = min(max(phase / drain, 0), 1)
            return CGFloat(raw)
        } else {
            guard let start = pourStart else { return 0 }
            let elapsed = date.timeIntervalSince(start)
            return CGFloat(min(max(elapsed / pourDuration, 0), 1))
        }
    }

    private func startPour() {
        didComplete = false
        pourStart = .now
        DispatchQueue.main.asyncAfter(deadline: .now() + pourDuration) {
            didComplete = true
        }
    }

    // MARK: - Composed view

    @ViewBuilder
    private func hourglass(size: CGSize, p: CGFloat) -> some View {
        let geo = SandPourView_HourglassGeometry(size: size)
        ZStack {
            background(geo: geo)
            SandPourView_SandCanvas(geo: geo, progress: p)
            glassFrame(geo: geo)
            successOverlay(geo: geo, p: p)
        }
    }

    // MARK: - Static chrome

    @ViewBuilder
    private func background(geo: SandPourView_HourglassGeometry) -> some View {
        RoundedRectangle(cornerRadius: geo.tileCorner, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.12, green: 0.10, blue: 0.07),
                        Color(red: 0.07, green: 0.06, blue: 0.045)
                    ],
                    startPoint: .top,
                    endPoint: .bottom
                )
            )
            .overlay(
                RoundedRectangle(cornerRadius: geo.tileCorner, style: .continuous)
                    .stroke(Color(red: 0.30, green: 0.26, blue: 0.18).opacity(0.55), lineWidth: 1)
            )
    }

    @ViewBuilder
    private func glassFrame(geo: SandPourView_HourglassGeometry) -> some View {
        let glass = SandPourView_HourglassShape(geo: geo)
        ZStack {
            // Soft glass tint so the chamber reads even when empty.
            glass
                .fill(Color(red: 0.55, green: 0.65, blue: 0.72).opacity(0.06))
            // Specular vertical highlight down the glass.
            glass
                .fill(
                    LinearGradient(
                        colors: [
                            Color(red: 1, green: 1, blue: 1).opacity(0.16),
                            Color(red: 1, green: 1, blue: 1).opacity(0.0)
                        ],
                        startPoint: .leading,
                        endPoint: .trailing
                    )
                )
            glass
                .stroke(
                    LinearGradient(
                        colors: [
                            Color(red: 0.78, green: 0.80, blue: 0.85).opacity(0.85),
                            Color(red: 0.40, green: 0.42, blue: 0.48).opacity(0.55)
                        ],
                        startPoint: .topLeading,
                        endPoint: .bottomTrailing
                    ),
                    lineWidth: geo.frameLine
                )
            // Pinch end-caps.
            Capsule()
                .fill(Color(red: 0.70, green: 0.72, blue: 0.78).opacity(0.85))
                .frame(width: geo.neckHalf * 2.4, height: geo.frameLine * 1.6)
                .position(x: geo.center.x, y: geo.neckY)
        }
    }

    @ViewBuilder
    private func successOverlay(geo: SandPourView_HourglassGeometry, p: CGFloat) -> some View {
        let appear = morphAmount(p)
        ZStack {
            Circle()
                .fill(Color(red: 0.36, green: 0.70, blue: 0.42))
                .frame(width: geo.badge, height: geo.badge)
                .shadow(color: Color(red: 0.36, green: 0.70, blue: 0.42).opacity(0.6),
                        radius: geo.badge * 0.18)
            Image(systemName: "checkmark")
                .font(.system(size: geo.badge * 0.5, weight: .heavy))
                .foregroundStyle(.white)
        }
        .scaleEffect(0.6 + 0.4 * appear)
        .opacity(Double(appear))
        .position(x: geo.center.x, y: geo.lowerCenterY)
        .allowsHitTesting(false)
    }

    // Crossfade window p in [0.82, 1.0].
    private func morphAmount(_ p: CGFloat) -> CGFloat {
        let lo: CGFloat = 0.82
        guard p > lo else { return 0 }
        let t = (p - lo) / (1 - lo)
        // Smoothstep for a gentle pop.
        return t * t * (3 - 2 * t)
    }
}

// MARK: - Geometry

private struct SandPourView_HourglassGeometry {
    let size: CGSize
    let center: CGPoint
    let tileCorner: CGFloat
    let frameLine: CGFloat

    // Vertical anchors.
    let topY: CGFloat       // top inner edge of upper chamber
    let neckY: CGFloat      // pinch
    let bottomY: CGFloat    // bottom inner edge of lower chamber

    // Horizontal half-widths.
    let topHalf: CGFloat
    let neckHalf: CGFloat
    let grainRadius: CGFloat
    let badge: CGFloat

    init(size: CGSize) {
        self.size = size
        let minSide = min(size.width, size.height)
        self.center = CGPoint(x: size.width / 2, y: size.height / 2)
        self.tileCorner = minSide * 0.16

        // Hourglass occupies a centered portrait box.
        let h = minSide * 0.78
        self.topY = center.y - h / 2
        self.bottomY = center.y + h / 2
        self.neckY = center.y

        self.topHalf = minSide * 0.30
        self.neckHalf = max(minSide * 0.035, 2.4)
        self.frameLine = max(minSide * 0.018, 1.4)
        self.grainRadius = max(minSide * 0.012, 1.0)
        self.badge = minSide * 0.42
    }

    var lowerCenterY: CGFloat { (neckY + bottomY) / 2 }

    // Half-width of the glass funnel at a given y.
    func halfWidth(atY y: CGFloat) -> CGFloat {
        if y <= neckY {
            let t = (y - topY) / max(neckY - topY, 0.001) // 0 top -> 1 neck
            return topHalf + (neckHalf - topHalf) * clamp01(t)
        } else {
            let t = (y - neckY) / max(bottomY - neckY, 0.001) // 0 neck -> 1 bottom
            return neckHalf + (topHalf - neckHalf) * clamp01(t)
        }
    }
}

private func clamp01(_ v: CGFloat) -> CGFloat { min(max(v, 0), 1) }

// MARK: - Hourglass outline shape

private struct SandPourView_HourglassShape: Shape {
    let geo: SandPourView_HourglassGeometry

    func path(in rect: CGRect) -> Path {
        var path = Path()
        let cx = geo.center.x
        let cap = geo.topHalf * 0.34 // rounded chamber lip inset

        // Start top-left, go clockwise: upper chamber -> neck -> lower chamber.
        path.move(to: CGPoint(x: cx - geo.topHalf + cap, y: geo.topY))
        path.addLine(to: CGPoint(x: cx + geo.topHalf - cap, y: geo.topY))
        path.addQuadCurve(
            to: CGPoint(x: cx + geo.topHalf, y: geo.topY + cap),
            control: CGPoint(x: cx + geo.topHalf, y: geo.topY)
        )
        // Right wall funnels to neck.
        path.addLine(to: CGPoint(x: cx + geo.neckHalf, y: geo.neckY))
        // Down into lower chamber.
        path.addLine(to: CGPoint(x: cx + geo.topHalf, y: geo.bottomY - cap))
        path.addQuadCurve(
            to: CGPoint(x: cx + geo.topHalf - cap, y: geo.bottomY),
            control: CGPoint(x: cx + geo.topHalf, y: geo.bottomY)
        )
        path.addLine(to: CGPoint(x: cx - geo.topHalf + cap, y: geo.bottomY))
        path.addQuadCurve(
            to: CGPoint(x: cx - geo.topHalf, y: geo.bottomY - cap),
            control: CGPoint(x: cx - geo.topHalf, y: geo.bottomY)
        )
        path.addLine(to: CGPoint(x: cx - geo.neckHalf, y: geo.neckY))
        path.addLine(to: CGPoint(x: cx - geo.topHalf, y: geo.topY + cap))
        path.addQuadCurve(
            to: CGPoint(x: cx - geo.topHalf + cap, y: geo.topY),
            control: CGPoint(x: cx - geo.topHalf, y: geo.topY)
        )
        path.closeSubpath()
        return path
    }
}

// MARK: - Grain seed (immutable, computed once)

private struct SandPourView_GrainSeed {
    let column: CGFloat       // -1...1 horizontal slot in top chamber
    let depth: CGFloat        // 0 (top of upper chamber, leaves last) ... 1 (nearest neck, leaves first)
    let releaseFraction: CGFloat // when in [0,1] this grain begins to fall
    let fallSpan: CGFloat     // how long the fall takes, in progress units
    let pileColumn: CGFloat   // -1...1 landing slot
    let pileRow: CGFloat      // 0 (lands first, bottom) ... 1 (lands last, top)
    let xJitter: CGFloat      // small per-grain offset
    let shade: CGFloat        // 0...1 amber brightness pick
}

private enum SandPourView_SandModel {
    static let grainCount = 360

    static let seeds: [SandPourView_GrainSeed] = {
        var rng = SandPourView_SeededRandom(seed: 0x5A4D)
        var out: [SandPourView_GrainSeed] = []
        out.reserveCapacity(grainCount)
        for i in 0..<grainCount {
            let depth = CGFloat(i) / CGFloat(grainCount - 1)
            // Grains nearer the neck (high depth) leave first.
            let release = depth * 0.62 + rng.next() * 0.06
            let span = 0.16 + rng.next() * 0.10
            let col = rng.next() * 2 - 1
            // Pile fills bottom-up: first-to-leave lands lowest.
            let pileRow = depth
            let pileCol = rng.next() * 2 - 1
            out.append(
                SandPourView_GrainSeed(
                    column: col,
                    depth: depth,
                    releaseFraction: min(release, 0.80),
                    fallSpan: span,
                    pileColumn: pileCol,
                    pileRow: pileRow,
                    xJitter: rng.next() * 2 - 1,
                    shade: rng.next()
                )
            )
        }
        return out
    }()
}

// Tiny deterministic LCG so the grain field is stable across frames & instances.
private struct SandPourView_SeededRandom {
    private var state: UInt64
    init(seed: UInt64) { state = seed &* 2862933555777941757 &+ 3037000493 }
    mutating func next() -> CGFloat {
        state = state &* 6364136223846793005 &+ 1442695040888963407
        let v = (state >> 33) & 0xFFFFFF
        return CGFloat(v) / CGFloat(0xFFFFFF)
    }
}

// MARK: - Grain position as a pure function of progress

private func grainPosition(seed: SandPourView_GrainSeed, p: CGFloat, geo: SandPourView_HourglassGeometry) -> (point: CGPoint, falling: Bool) {
    let release = seed.releaseFraction
    let landed = min(release + seed.fallSpan, 1)

    if p <= release {
        // Resting in the upper chamber. The top sand surface drops as grains
        // leave, so resting grains sit between a descending surface and the neck.
        return (restingTopPoint(seed: seed, p: p, geo: geo), false)
    } else if p >= landed {
        // Parked in the pile.
        return (pilePoint(seed: seed, geo: geo), false)
    } else {
        // Falling through the neck.
        let t = (p - release) / max(seed.fallSpan, 0.001)
        return (fallingPoint(seed: seed, t: clamp01(t), geo: geo), true)
    }
}

// Upper chamber: surface recedes toward the neck as p grows.
private func restingTopPoint(seed: SandPourView_GrainSeed, p: CGFloat, geo: SandPourView_HourglassGeometry) -> CGPoint {
    // Fraction of upper sand already gone (drives the falling surface).
    let drained = clamp01(p / 0.62)
    let surfaceY = geo.topY + (geo.neckY - geo.topY) * (0.10 + 0.78 * drained)
    // This grain's vertical slot among still-resting grains.
    let restY = surfaceY + (geo.neckY - surfaceY) * (1 - seed.depth) * 0.92
    let half = geo.halfWidth(atY: restY) - geo.grainRadius * 2
    let x = geo.center.x + seed.column * max(half, 1)
    return CGPoint(x: x, y: restY)
}

// Falling: top rest spot -> neck pinch -> pile slot, with gravity easing.
private func fallingPoint(seed: SandPourView_GrainSeed, t: CGFloat, geo: SandPourView_HourglassGeometry) -> CGPoint {
    let startY = geo.topY + (geo.neckY - geo.topY) * 0.82
    let endY = pilePoint(seed: seed, geo: geo).y
    // Quadratic (gravity) ease for vertical fall.
    let easedV = t * t
    let y = startY + (endY - startY) * easedV

    // Horizontal: funnel toward the neck (x≈center) around the midpoint, then
    // spread out to the landing column.
    let startX = geo.center.x + seed.column * (geo.topHalf * 0.45)
    let neckX = geo.center.x + seed.xJitter * geo.neckHalf * 0.6
    let endX = pilePoint(seed: seed, geo: geo).x

    let x: CGFloat
    if t < 0.5 {
        let s = t / 0.5
        x = startX + (neckX - startX) * easeInOut(s)
    } else {
        let s = (t - 0.5) / 0.5
        x = neckX + (endX - neckX) * easeInOut(s)
    }
    return CGPoint(x: x, y: y)
}

// Pile in the lower chamber, filling bottom-up.
private func pilePoint(seed: SandPourView_GrainSeed, geo: SandPourView_HourglassGeometry) -> CGPoint {
    // pileRow 0 -> bottom, 1 -> higher. Pile height grows toward the neck.
    let pileTopY = geo.neckY + (geo.bottomY - geo.neckY) * 0.30
    let y = geo.bottomY - (geo.bottomY - pileTopY) * seed.pileRow
    // Cone profile: wider near the bottom.
    let local = (geo.bottomY - y) / max(geo.bottomY - pileTopY, 0.001) // 0 bottom -> 1 top
    let maxHalf = geo.halfWidth(atY: y) - geo.grainRadius * 2
    let coneHalf = maxHalf * (1 - 0.55 * local)
    let x = geo.center.x + seed.pileColumn * max(coneHalf, 1)
    return CGPoint(x: x, y: y - geo.grainRadius)
}

private func easeInOut(_ t: CGFloat) -> CGFloat {
    if t < 0.5 { return 2 * t * t }
    let u = -2 * t + 2
    return 1 - (u * u) / 2
}

// MARK: - Sand Canvas

private struct SandPourView_SandCanvas: View {
    let geo: SandPourView_HourglassGeometry
    let progress: CGFloat

    var body: some View {
        Canvas { context, _ in
            drawSand(into: &context)
        }
    }

    private func drawSand(into context: inout GraphicsContext) {
        // Clip to the glass so grains never spill outside the chamber.
        let clip = SandPourView_HourglassShape(geo: geo).path(in: .zero)
        context.clip(to: clip)

        // Three amber buckets -> 3 fills instead of 360.
        var light = Path()
        var mid = Path()
        var dark = Path()
        let r = geo.grainRadius

        for seed in SandPourView_SandModel.seeds {
            let result = grainPosition(seed: seed, p: progress, geo: geo)
            let pt = result.point
            // Falling grains streak vertically to read as motion through the neck.
            let h = result.falling ? r * 3.6 : r * 2
            let rect = CGRect(x: pt.x - r, y: pt.y - r, width: r * 2, height: h)
            if seed.shade > 0.66 {
                light.addEllipse(in: rect)
            } else if seed.shade > 0.33 {
                mid.addEllipse(in: rect)
            } else {
                dark.addEllipse(in: rect)
            }
        }

        context.fill(light, with: .color(Color(red: 0.93, green: 0.80, blue: 0.52)))
        context.fill(mid, with: .color(Color(red: 0.85, green: 0.69, blue: 0.40)))
        context.fill(dark, with: .color(Color(red: 0.72, green: 0.55, blue: 0.30)))
    }
}
"""###,
        "btn-shatter-reform": ###"""
import SwiftUI

// MARK: - ShatterReformView
// An error-state button that shatters into angular glass shards which scatter
// outward, then magnetically reassemble into the intact button.
//
// demo == true  -> self-driving PhaseAnimator loop (no haptics, never blank).
// demo == false -> tap to trigger the shatter -> reform sequence (with haptics).
struct ShatterReformView: View {
    var demo: Bool = false

    // Tap trigger for the interactive PhaseAnimator.
    @State private var tapCount: Int = 0

    var body: some View {
        GeometryReader { geo in
            let size = geo.size
            let side = min(size.width, size.height)
            // Inset the button so scatter displacement stays inside the frame.
            let buttonSide = side * 0.58
            let center = CGPoint(x: size.width / 2, y: size.height / 2)

            ZStack {
                if demo {
                    demoBody(buttonSide: buttonSide, center: center)
                } else {
                    interactiveBody(buttonSide: buttonSide, center: center)
                }
            }
            .frame(width: size.width, height: size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // MARK: Demo (auto-looping)

    @ViewBuilder
    private func demoBody(buttonSide: CGFloat, center: CGPoint) -> some View {
        PhaseAnimator(ShatterReformView_ShatterPhase.allCases) { phase in
            ShatterReformView_ShardCanvas(
                shards: Self.shards,
                progress: phase.progress,
                buttonSide: buttonSide,
                center: center
            )
        } animation: { phase in
            phase.animation
        }
    }

    // MARK: Interactive (tap-driven)

    @ViewBuilder
    private func interactiveBody(buttonSide: CGFloat, center: CGPoint) -> some View {
        PhaseAnimator(ShatterReformView_ShatterPhase.allCases, trigger: tapCount) { phase in
            ShatterReformView_ShardCanvas(
                shards: Self.shards,
                progress: phase.progress,
                buttonSide: buttonSide,
                center: center
            )
            .contentShape(Rectangle())
            .sensoryFeedback(.error, trigger: phase) { _, newValue in
                newValue == .scattered
            }
            .sensoryFeedback(.success, trigger: phase) { _, newValue in
                newValue == .reformed
            }
        } animation: { phase in
            phase.animation
        }
        .contentShape(Rectangle())
        .onTapGesture {
            tapCount += 1
        }
    }

    // MARK: Precomputed shard geometry (deterministic, computed once)

    static let shards: [ShatterReformView_ShatterShard] = ShatterReformView_ShatterShard.makeShards()
}

// MARK: - Phases

private enum ShatterReformView_ShatterPhase: CaseIterable, Equatable {
    case intact      // fully assembled, resting beat
    case scattered   // glass exploded outward (capped within frame)
    case reformed    // magnetically snapped back together

    // Maps each phase to a single 0...1 scatter progress.
    var progress: CGFloat {
        switch self {
        case .intact:    return 0
        case .scattered: return 1
        case .reformed:  return 0
        }
    }

    // Per-phase animation curve: explosive into scatter, springy magnetic reform,
    // gentle hold before re-shattering.
    var animation: Animation {
        switch self {
        case .scattered:
            // Sharp outward burst.
            return .easeOut(duration: 0.45)
        case .reformed:
            // Magnetic snap-back: overshoot + settle.
            return .interpolatingSpring(stiffness: 180, damping: 12)
                .delay(0.12)
        case .intact:
            // Rest beat so the intact button is legible before the next break.
            return .easeInOut(duration: 0.35).delay(1.1)
        }
    }
}

// MARK: - Shard model

struct ShatterReformView_ShatterShard: Identifiable {
    let id: Int
    // Polygon vertices in unit space (0...1) relative to the button rect.
    let unitPoints: [CGPoint]
    // Centroid in unit space.
    let unitCentroid: CGPoint
    // Direction the shard flies when scattered (scaled at draw time).
    let scatterDir: CGVector
    // Peak rotation in degrees at full scatter.
    let scatterRotation: Double
    // Slight color variance to read as faceted glass.
    let tintBias: CGFloat

    // Builds ~18 angular shards via a deterministic radial Voronoi-ish partition.
    static func makeShards() -> [ShatterReformView_ShatterShard] {
        var rng = ShatterReformView_ShatterRNG(seed: 0xC0FFEE)
        let center = CGPoint(x: 0.5, y: 0.5)

        // Fracture origin slightly off-center for a more believable impact point.
        let impact = CGPoint(x: 0.42, y: 0.38)

        // Generate ring vertices around the impact, then fan facets between
        // consecutive rays. An inner ring + the square boundary gives glass facets.
        let rayCount = 9
        var rays: [[CGPoint]] = []
        for i in 0..<rayCount {
            let baseAngle = (Double(i) / Double(rayCount)) * 2.0 * Double.pi
            let span = (2.0 * Double.pi / Double(rayCount)) * 0.55
            let jitter = (rng.nextUnit() - 0.5) * span
            let angle: Double = baseAngle + jitter
            let innerR: CGFloat = 0.18 + CGFloat(rng.nextUnit()) * 0.10
            let inner = CGPoint(
                x: impact.x + cgCos(angle) * innerR,
                y: impact.y + cgSin(angle) * innerR
            )
            let outer = Self.projectToUnitSquare(from: impact, angle: angle)
            rays.append([inner, outer])
        }

        var result: [ShatterReformView_ShatterShard] = []
        var nextID = 0

        // Inner cap triangles fanning from impact to inner ring.
        for i in 0..<rayCount {
            let a = rays[i][0]
            let b = rays[(i + 1) % rayCount][0]
            let poly: [CGPoint] = [impact, a, b]
            result.append(Self.buildShard(id: nextID, unit: poly, center: center, rng: &rng))
            nextID += 1
        }

        // Outer ring quads between inner ring and the square boundary.
        for i in 0..<rayCount {
            let innerA = rays[i][0]
            let outerA = rays[i][1]
            let innerB = rays[(i + 1) % rayCount][0]
            let outerB = rays[(i + 1) % rayCount][1]
            let poly: [CGPoint] = [innerA, outerA, outerB, innerB]
            result.append(Self.buildShard(id: nextID, unit: poly, center: center, rng: &rng))
            nextID += 1
        }

        return result
    }

    private static func buildShard(
        id: Int,
        unit: [CGPoint],
        center: CGPoint,
        rng: inout ShatterReformView_ShatterRNG
    ) -> ShatterReformView_ShatterShard {
        let centroid = Self.centroidOf(unit)
        // Scatter direction: radially away from the button center.
        var dx: CGFloat = centroid.x - center.x
        var dy: CGFloat = centroid.y - center.y
        let len: CGFloat = max(0.001, (dx * dx + dy * dy).squareRoot())
        dx /= len
        dy /= len
        // Add a little tangential swirl so it doesn't read as a pure radial puff.
        let swirl: CGFloat = CGFloat(rng.nextUnit() - 0.5) * 0.5
        let mag: CGFloat = 0.75 + CGFloat(rng.nextUnit()) * 0.35
        let dir = CGVector(
            dx: dx * mag + (-dy) * swirl,
            dy: dy * mag + dx * swirl
        )
        let rotation: Double = (rng.nextUnit() - 0.5) * 90.0
        let tint = CGFloat(rng.nextUnit())
        return ShatterReformView_ShatterShard(
            id: id,
            unitPoints: unit,
            unitCentroid: centroid,
            scatterDir: dir,
            scatterRotation: rotation,
            tintBias: tint
        )
    }

    private static func centroidOf(_ pts: [CGPoint]) -> CGPoint {
        guard !pts.isEmpty else { return CGPoint(x: 0.5, y: 0.5) }
        var sx: CGFloat = 0
        var sy: CGFloat = 0
        for p in pts {
            sx += p.x
            sy += p.y
        }
        return CGPoint(x: sx / CGFloat(pts.count), y: sy / CGFloat(pts.count))
    }

    // Casts a ray from `origin` at `angle` to the boundary of the unit square.
    private static func projectToUnitSquare(from origin: CGPoint, angle: Double) -> CGPoint {
        let dx: CGFloat = cgCos(angle)
        let dy: CGFloat = cgSin(angle)
        var t: CGFloat = CGFloat.greatestFiniteMagnitude
        if dx > 0.0001 { t = min(t, (1 - origin.x) / dx) }
        if dx < -0.0001 { t = min(t, (0 - origin.x) / dx) }
        if dy > 0.0001 { t = min(t, (1 - origin.y) / dy) }
        if dy < -0.0001 { t = min(t, (0 - origin.y) / dy) }
        if t == CGFloat.greatestFiniteMagnitude { t = 0.5 }
        return CGPoint(x: origin.x + dx * t, y: origin.y + dy * t)
    }
}

// Small trig wrappers annotated to keep the type-checker fast.
private func cgCos(_ a: Double) -> CGFloat { CGFloat(cos(a)) }
private func cgSin(_ a: Double) -> CGFloat { CGFloat(sin(a)) }

// MARK: - Deterministic RNG (so shard geometry is identical every init)

struct ShatterReformView_ShatterRNG {
    private var state: UInt64
    init(seed: UInt64) { self.state = seed != 0 ? seed : 0x9E3779B97F4A7C15 }

    mutating func next() -> UInt64 {
        // xorshift64*
        state ^= state >> 12
        state ^= state << 25
        state ^= state >> 27
        return state &* 0x2545F4914F6CDD1D
    }

    // Returns a value in 0...1.
    mutating func nextUnit() -> Double {
        let v = next() >> 11 // top 53 bits
        return Double(v) / Double(UInt64(1) << 53)
    }
}

// MARK: - Shard rendering

private struct ShatterReformView_ShardCanvas: View {
    let shards: [ShatterReformView_ShatterShard]
    let progress: CGFloat // 0 = intact, 1 = fully scattered
    let buttonSide: CGFloat
    let center: CGPoint

    // Scatter is capped so shards stay inside the frame; opacity is floored
    // so no frame is ever blank.
    private let maxScatter: CGFloat = 0.30 // fraction of buttonSide
    private let opacityFloor: Double = 0.46

    var body: some View {
        ZStack {
            ForEach(shards) { shard in
                shardShape(shard)
            }
            label
        }
    }

    @ViewBuilder
    private func shardShape(_ shard: ShatterReformView_ShatterShard) -> some View {
        let displacement = shardDisplacement(shard)
        let rot: Double = shard.scatterRotation * Double(progress)
        let op: Double = shardOpacity()

        ShatterReformView_ShardPath(unitPoints: shard.unitPoints, buttonSide: buttonSide, center: center)
            .fill(shardGradient(shard))
            .overlay(shardEdge(shard))
            .rotationEffect(.degrees(rot), anchor: shardAnchor(shard))
            .offset(x: displacement.dx, y: displacement.dy)
            .opacity(op)
            .compositingGroup()
            .shadow(
                color: Color(red: 0.0, green: 0.0, blue: 0.0).opacity(0.28 * Double(progress)),
                radius: 3.0 * progress,
                x: displacement.dx * 0.08,
                y: 2.0 + displacement.dy * 0.08
            )
    }

    @ViewBuilder
    private func shardEdge(_ shard: ShatterReformView_ShatterShard) -> some View {
        ShatterReformView_ShardPath(unitPoints: shard.unitPoints, buttonSide: buttonSide, center: center)
            .stroke(highlightStroke(), lineWidth: 0.75)
    }

    // The intact/reformed label; fades in as shards close up.
    @ViewBuilder
    private var label: some View {
        let labelOpacity: Double = max(0.0, 1.0 - Double(progress) * 2.2)
        Text("Confirm")
            .font(.system(size: buttonSide * 0.16, weight: .semibold, design: .rounded))
            .foregroundStyle(Color(red: 0.96, green: 0.97, blue: 1.0))
            .shadow(color: Color(red: 0.0, green: 0.1, blue: 0.25).opacity(0.5), radius: 1, y: 1)
            .opacity(labelOpacity)
            .allowsHitTesting(false)
    }

    private func shardDisplacement(_ shard: ShatterReformView_ShatterShard) -> CGVector {
        let reach: CGFloat = buttonSide * maxScatter
        return CGVector(
            dx: shard.scatterDir.dx * reach * progress,
            dy: shard.scatterDir.dy * reach * progress
        )
    }

    // Floor opacity at the scatter peak so the tile is never blank.
    private func shardOpacity() -> Double {
        let p: Double = Double(progress)
        // 1.0 at intact, easing to the floor at full scatter.
        return opacityFloor + (1.0 - opacityFloor) * (1.0 - p)
    }

    private func shardAnchor(_ shard: ShatterReformView_ShatterShard) -> UnitPoint {
        UnitPoint(x: shard.unitCentroid.x, y: shard.unitCentroid.y)
    }

    // Faceted glass gradient with slight per-shard brightness variance.
    private func shardGradient(_ shard: ShatterReformView_ShatterShard) -> LinearGradient {
        let b: Double = Double(shard.tintBias)
        let top = Color(
            red: 0.30 + b * 0.22,
            green: 0.55 + b * 0.18,
            blue: 0.80 + b * 0.18
        )
        let bottom = Color(
            red: 0.10 + b * 0.10,
            green: 0.22 + b * 0.12,
            blue: 0.42 + b * 0.16
        )
        return LinearGradient(
            colors: [top, bottom],
            startPoint: .topLeading,
            endPoint: .bottomTrailing
        )
    }

    private func highlightStroke() -> Color {
        Color(red: 0.85, green: 0.93, blue: 1.0).opacity(0.55)
    }
}

// MARK: - Shard path (unit -> pixel)

private struct ShatterReformView_ShardPath: Shape {
    let unitPoints: [CGPoint]
    let buttonSide: CGFloat
    let center: CGPoint

    func path(in rect: CGRect) -> Path {
        var path = Path()
        guard unitPoints.count >= 3 else { return path }
        let origin = CGPoint(
            x: center.x - buttonSide / 2,
            y: center.y - buttonSide / 2
        )
        let mapped: [CGPoint] = unitPoints.map { p in
            CGPoint(
                x: origin.x + p.x * buttonSide,
                y: origin.y + p.y * buttonSide
            )
        }
        path.move(to: mapped[0])
        for i in 1..<mapped.count {
            path.addLine(to: mapped[i])
        }
        path.closeSubpath()
        return path
    }
}
"""###,
        "btn-static-discharge": ###"""
import SwiftUI

/// Static Discharge — drag near the charged button to build a crackling electric
/// arc that jumps the gap toward your finger; closing the gap discharges the
/// circuit with a flash + haptic. Pure SwiftUI (Canvas + TimelineView), no shader.
struct StaticDischargeView: View {
    var demo: Bool = false

    // Interactive state
    @State private var finger: CGPoint? = nil
    @State private var dischargeTime: Date? = nil
    @State private var discharged: Bool = false
    @State private var dischargeCount: Int = 0

    // Loop / flash timing
    private let loopPeriod: Double = 3.2
    private let flashDuration: Double = 0.34

    var body: some View {
        GeometryReader { geo in
            let size = geo.size
            TimelineView(.animation) { timeline in
                let now = timeline.date
                Canvas { ctx, canvasSize in
                    draw(ctx: &ctx, size: canvasSize, now: now)
                }
            }
            .gesture(dragGesture(in: size))
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .sensoryFeedback(.impact(flexibility: .solid, intensity: 0.9),
                         trigger: dischargeCount)
        .contentShape(Rectangle())
    }

    // MARK: - Gesture (interactive mode only)

    private func dragGesture(in size: CGSize) -> some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                guard !demo else { return }
                finger = value.location
                let center = anchorPoint(in: size)
                let gap = distance(value.location, center)
                let threshold = dischargeThreshold(in: size)
                if gap < threshold && !discharged {
                    discharged = true
                    dischargeTime = Date()
                    dischargeCount &+= 1
                }
            }
            .onEnded { _ in
                guard !demo else { return }
                finger = nil
                discharged = false
            }
    }

    // MARK: - Geometry helpers

    /// The electrode terminal the arc jumps from — sits left of center.
    private func anchorPoint(in size: CGSize) -> CGPoint {
        let minSide = min(size.width, size.height)
        return CGPoint(x: size.width * 0.5 - minSide * 0.18,
                       y: size.height * 0.5)
    }

    private func dischargeThreshold(in size: CGSize) -> CGFloat {
        min(size.width, size.height) * 0.16
    }

    private func distance(_ a: CGPoint, _ b: CGPoint) -> CGFloat {
        let dx = a.x - b.x
        let dy = a.y - b.y
        return (dx * dx + dy * dy).squareRoot()
    }

    // MARK: - Phantom finger (demo mode)

    /// Demo phase 0...1 across the loop period.
    private func loopPhase(_ now: Date) -> Double {
        let t = now.timeIntervalSinceReferenceDate
        return (t.truncatingRemainder(dividingBy: loopPeriod)) / loopPeriod
    }

    /// Phantom finger sweeps in from the right edge toward the electrode,
    /// reaching the gap near phase ~0.72, then snaps back out for the reset.
    private func phantomFinger(in size: CGSize, phase: Double) -> CGPoint {
        let center = anchorPoint(in: size)
        let startX = size.width * 0.94
        let endX = center.x + dischargeThreshold(in: size) * 0.55
        let approach = min(phase / 0.72, 1.0)
        // ease-in so it accelerates toward contact
        let eased = approach * approach
        let x: CGFloat
        if phase < 0.82 {
            x = startX + (endX - startX) * CGFloat(eased)
        } else {
            // reset: pull back out
            let back = (phase - 0.82) / 0.18
            x = endX + (startX - endX) * CGFloat(back)
        }
        // slight vertical wander so it feels hand-driven
        let wobble = CGFloat(sin(phase * .pi * 4.0)) * size.height * 0.045
        return CGPoint(x: x, y: center.y + wobble)
    }

    // MARK: - Flash intensity (unified for both modes)

    /// 0 = no flash, 1 = peak. Derived from time so it decays smoothly per frame.
    private func flashIntensity(now: Date, size: CGSize) -> Double {
        if demo {
            let phase = loopPhase(now)
            // brief flash window centred at the contact moment
            let start = 0.72
            let span = flashDuration / loopPeriod
            guard phase >= start && phase <= start + span else { return 0 }
            let local = (phase - start) / span
            // fast rise, slower fall
            return local < 0.25 ? local / 0.25 : max(0, 1 - (local - 0.25) / 0.75)
        } else {
            guard let dt = dischargeTime else { return 0 }
            let elapsed = now.timeIntervalSince(dt)
            guard elapsed >= 0 && elapsed <= flashDuration else { return 0 }
            let local = elapsed / flashDuration
            return local < 0.2 ? local / 0.2 : max(0, 1 - (local - 0.2) / 0.8)
        }
    }

    // MARK: - Drawing

    private func draw(ctx: inout GraphicsContext, size: CGSize, now: Date) {
        drawButtonBody(ctx: &ctx, size: size)

        let center = anchorPoint(in: size)
        let threshold = dischargeThreshold(in: size)

        // Resolve the active endpoint + gap.
        let endpoint: CGPoint?
        if demo {
            endpoint = phantomFinger(in: size, phase: loopPhase(now))
        } else {
            endpoint = finger
        }

        // Always-present idle electrode + faint static.
        let gap = endpoint.map { distance($0, center) } ?? .greatestFiniteMagnitude
        let span = max(size.width * 0.45, 1)
        let proximity: Double = endpoint == nil ? 0 : max(0, min(1, Double(1 - (gap - threshold) / span)))
        drawElectrode(ctx: &ctx, at: center, size: size, charge: proximity, now: now)

        // Arc — only when there is a live endpoint beyond the contact point.
        if let end = endpoint, gap > threshold * 0.35 {
            drawArc(ctx: &ctx, from: center, to: end, size: size,
                    proximity: proximity, now: now)
        }

        // Discharge flash (radial bloom at the contact / electrode).
        let flash = flashIntensity(now: now, size: size)
        if flash > 0.001 {
            let bloomAt = endpoint ?? center
            let mid = CGPoint(x: (center.x + bloomAt.x) / 2,
                              y: (center.y + bloomAt.y) / 2)
            drawFlash(ctx: &ctx, at: mid, size: size, intensity: flash)
        }
    }

    private func drawButtonBody(ctx: inout GraphicsContext, size: CGSize) {
        let minSide = min(size.width, size.height)
        let inset = minSide * 0.12
        let rect = CGRect(x: inset, y: size.height * 0.5 - minSide * 0.34,
                          width: max(size.width - inset * 2, 1),
                          height: minSide * 0.68)
        let corner = minSide * 0.16
        let path = Path(roundedRect: rect, cornerRadius: corner)

        // Dark metallic plate.
        let plate = Gradient(stops: [
            .init(color: Color(red: 0.10, green: 0.11, blue: 0.15), location: 0),
            .init(color: Color(red: 0.05, green: 0.06, blue: 0.09), location: 1)
        ])
        ctx.fill(path, with: .linearGradient(plate,
                                             startPoint: CGPoint(x: rect.midX, y: rect.minY),
                                             endPoint: CGPoint(x: rect.midX, y: rect.maxY)))

        // Subtle rim light.
        ctx.stroke(path, with: .color(Color(red: 0.30, green: 0.45, blue: 0.65).opacity(0.5)),
                   lineWidth: max(1, minSide * 0.012))

        // Label.
        let label = Text("PRESS")
            .font(.system(size: minSide * 0.13, weight: .heavy, design: .rounded))
            .kerning(minSide * 0.02)
            .foregroundStyle(Color(red: 0.62, green: 0.78, blue: 0.95))
        ctx.draw(label, at: CGPoint(x: rect.midX + minSide * 0.06, y: rect.midY))
    }

    private func drawElectrode(ctx: inout GraphicsContext, at p: CGPoint,
                               size: CGSize, charge: Double, now: Date) {
        let minSide = min(size.width, size.height)
        let r = minSide * 0.06

        // Charged glow halo (always faintly lit so the tile is never blank).
        let baseGlow = 0.22 + charge * 0.6
        let glowRect = CGRect(x: p.x - r * 2.6, y: p.y - r * 2.6,
                              width: r * 5.2, height: r * 5.2)
        let glow = Gradient(stops: [
            .init(color: Color(red: 0.45, green: 0.7, blue: 1.0).opacity(baseGlow), location: 0),
            .init(color: Color(red: 0.2, green: 0.4, blue: 0.9).opacity(0), location: 1)
        ])
        ctx.fill(Path(ellipseIn: glowRect),
                 with: .radialGradient(glow, center: p, startRadius: 0, endRadius: r * 2.6))

        // Metal nub.
        let nub = Path(ellipseIn: CGRect(x: p.x - r, y: p.y - r, width: r * 2, height: r * 2))
        let metal = Gradient(stops: [
            .init(color: Color(red: 0.85, green: 0.88, blue: 0.95), location: 0),
            .init(color: Color(red: 0.35, green: 0.40, blue: 0.50), location: 1)
        ])
        ctx.fill(nub, with: .radialGradient(metal,
                                            center: CGPoint(x: p.x - r * 0.35, y: p.y - r * 0.35),
                                            startRadius: 0, endRadius: r * 1.8))

        // Tiny idle static sparks crawling on the nub even when idle.
        var rng = StaticDischargeView_LCG(seed: quantizedSeed(now, hz: 14) &+ 991)
        let sparkCount = 3
        for _ in 0..<sparkCount {
            let ang = rng.unit() * 2 * .pi
            let len = r * CGFloat(0.6 + rng.unit() * (0.5 + charge))
            let sp = CGPoint(x: p.x + CGFloat(cos(ang)) * r, y: p.y + CGFloat(sin(ang)) * r)
            let ep = CGPoint(x: sp.x + CGFloat(cos(ang)) * len, y: sp.y + CGFloat(sin(ang)) * len)
            var spark = Path()
            spark.move(to: sp)
            spark.addLine(to: ep)
            ctx.stroke(spark,
                       with: .color(Color(red: 0.7, green: 0.85, blue: 1.0)
                        .opacity(0.35 + charge * 0.4)),
                       lineWidth: max(0.6, minSide * 0.006))
        }
    }

    private func drawArc(ctx: inout GraphicsContext, from a: CGPoint, to b: CGPoint,
                         size: CGSize, proximity: Double, now: Date) {
        let minSide = min(size.width, size.height)
        let intensity = 0.35 + proximity * 0.65
        let roughness = minSide * CGFloat(0.10 + (1 - proximity) * 0.06)

        // Re-jitter at ~16Hz so it crackles without strobing at 120fps.
        let seed = quantizedSeed(now, hz: 16)

        let main = boltPath(from: a, to: b, seed: seed,
                            roughness: roughness, displacement: 0.5, in: size)

        // Wide soft glow underlay.
        ctx.stroke(main,
                   with: .color(Color(red: 0.35, green: 0.6, blue: 1.0)
                    .opacity(0.30 + 0.45 * intensity)),
                   style: StrokeStyle(lineWidth: max(2, minSide * 0.05) * CGFloat(intensity),
                                      lineCap: .round, lineJoin: .round))

        // Mid blue.
        ctx.stroke(main,
                   with: .color(Color(red: 0.55, green: 0.75, blue: 1.0)
                    .opacity(0.55 + 0.4 * intensity)),
                   style: StrokeStyle(lineWidth: max(1.5, minSide * 0.022) * CGFloat(intensity),
                                      lineCap: .round, lineJoin: .round))

        // White-hot core.
        ctx.stroke(main,
                   with: .color(Color(red: 0.9, green: 0.96, blue: 1.0)
                    .opacity(0.7 + 0.3 * intensity)),
                   style: StrokeStyle(lineWidth: max(0.8, minSide * 0.009),
                                      lineCap: .round, lineJoin: .round))

        // A couple of short forks for that electric feel.
        var rng = StaticDischargeView_LCG(seed: seed &+ 7)
        let forkCount = 2
        for _ in 0..<forkCount {
            let t = CGFloat(0.3 + rng.unit() * 0.5)
            let origin = CGPoint(x: a.x + (b.x - a.x) * t,
                                 y: a.y + (b.y - a.y) * t)
            let ang = (rng.unit() - 0.5) * .pi
            let flen = minSide * CGFloat(0.08 + rng.unit() * 0.1)
            let tip = CGPoint(x: origin.x + CGFloat(cos(ang)) * flen,
                              y: origin.y + CGFloat(sin(ang)) * flen)
            let fork = boltPath(from: origin, to: tip, seed: seed &+ UInt64(rng.next() & 0xFF),
                                roughness: roughness * 0.6, displacement: 0.45, in: size)
            ctx.stroke(fork,
                       with: .color(Color(red: 0.6, green: 0.8, blue: 1.0)
                        .opacity(0.4 * intensity)),
                       style: StrokeStyle(lineWidth: max(0.8, minSide * 0.012) * CGFloat(intensity),
                                          lineCap: .round, lineJoin: .round))
        }
    }

    private func drawFlash(ctx: inout GraphicsContext, at p: CGPoint,
                           size: CGSize, intensity: Double) {
        let minSide = min(size.width, size.height)
        let clamped = min(1, intensity)
        let r = minSide * CGFloat(0.25 + 0.45 * clamped)
        let rect = CGRect(x: p.x - r, y: p.y - r, width: r * 2, height: r * 2)
        // Clamp peak opacity so the button is never fully hidden.
        let peak = 0.85 * clamped
        let g = Gradient(stops: [
            .init(color: Color(red: 1.0, green: 1.0, blue: 1.0).opacity(peak), location: 0),
            .init(color: Color(red: 0.6, green: 0.8, blue: 1.0).opacity(peak * 0.5), location: 0.4),
            .init(color: Color(red: 0.3, green: 0.5, blue: 1.0).opacity(0), location: 1)
        ])
        ctx.fill(Path(ellipseIn: rect),
                 with: .radialGradient(g, center: p, startRadius: 0, endRadius: max(r, 1)))
    }

    // MARK: - Bolt geometry (recursive midpoint displacement)

    private func boltPath(from a: CGPoint, to b: CGPoint, seed: UInt64,
                          roughness: CGFloat, displacement: CGFloat,
                          in size: CGSize) -> Path {
        var rng = StaticDischargeView_LCG(seed: seed)
        var points: [CGPoint] = [a, b]
        let passes = 5
        var disp = roughness
        for _ in 0..<passes {
            var next: [CGPoint] = []
            next.reserveCapacity(points.count * 2 - 1)
            for i in 0..<(points.count - 1) {
                let p0 = points[i]
                let p1 = points[i + 1]
                next.append(p0)
                let mid = CGPoint(x: (p0.x + p1.x) / 2, y: (p0.y + p1.y) / 2)
                // perpendicular offset
                let dx = p1.x - p0.x
                let dy = p1.y - p0.y
                let len = (dx * dx + dy * dy).squareRoot()
                let nx = len > 0 ? -dy / len : 0
                let ny = len > 0 ? dx / len : 0
                let off = (CGFloat(rng.unit()) - 0.5) * disp * 2
                next.append(CGPoint(x: mid.x + nx * off, y: mid.y + ny * off))
            }
            next.append(points[points.count - 1])
            points = next
            disp *= displacement
        }

        var path = Path()
        path.move(to: points[0])
        for i in 1..<points.count {
            path.addLine(to: points[i])
        }
        return path
    }

    // MARK: - Seeded RNG / time quantization

    /// Quantize the clock to `hz` ticks so jitter regenerates at a controlled
    /// rate (not every frame) — prevents harsh strobing at 120fps.
    private func quantizedSeed(_ now: Date, hz: Double) -> UInt64 {
        let tick = (now.timeIntervalSinceReferenceDate * hz).rounded(.down)
        return UInt64(bitPattern: Int64(tick))
    }
}

/// Tiny seedable linear-congruential generator. SystemRandomNumberGenerator
/// isn't seedable, so we hand-roll one to get stable per-tick randomness.
private struct StaticDischargeView_LCG {
    private var state: UInt64
    init(seed: UInt64) {
        // avoid a zero state
        state = seed == 0 ? 0x9E3779B97F4A7C15 : seed
    }
    mutating func next() -> UInt64 {
        state = state &* 6364136223846793005 &+ 1442695040888963407
        return state
    }
    /// Returns a Double in 0...1.
    mutating func unit() -> Double {
        Double(next() >> 11) * (1.0 / 9007199254740992.0)
    }
}
"""###,
        "btn-stitch-thread": ###"""
import SwiftUI

// MARK: - Stitch Thread Button
//
// Tapping animates a needle drawing thread stitch-by-stitch around the
// button's border, sewing a dashed seam that completes into a confirmed
// outline. The seam and the needle share ONE Path so they stay perfectly
// aligned: the needle rides `trimmedPath(...).currentPoint` — the exact
// leading edge of the revealed dashes — with no arc-length math.

struct StitchThreadView: View {
    var demo: Bool = false

    @State private var progress: CGFloat = 0
    @State private var didComplete: Bool = false

    var body: some View {
        GeometryReader { geo in
            if demo {
                autoDrivenContent(size: geo.size)
            } else {
                interactiveContent(size: geo.size)
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // MARK: Demo (self-driving)

    private func autoDrivenContent(size: CGSize) -> some View {
        TimelineView(.animation) { timeline in
            let t = triangleWave(at: timeline.date, period: 3.4)
            // Ease the linear triangle wave for a more hand-sewn cadence.
            let eased = easeInOut(t)
            sewingStage(size: size, progress: eased, sewn: eased > 0.985)
        }
    }

    // MARK: Interactive (real component)

    private func interactiveContent(size: CGSize) -> some View {
        sewingStage(size: size, progress: progress, sewn: didComplete)
            .contentShape(Rectangle())
            .onTapGesture {
                if progress >= 0.999 {
                    // Tap again to unstitch and reset.
                    didComplete = false
                    withAnimation(.easeInOut(duration: 0.9)) { progress = 0 }
                } else {
                    withAnimation(.easeInOut(duration: 1.2)) { progress = 1 }
                    // Mark completion slightly after the seam closes so the
                    // success haptic + state land on the final stitch.
                    DispatchQueue.main.asyncAfter(deadline: .now() + 1.2) {
                        if progress >= 0.999 { didComplete = true }
                    }
                }
            }
            .sensoryFeedback(.success, trigger: didComplete) { _, now in now }
    }

    // MARK: Shared stage

    private func sewingStage(size: CGSize, progress: CGFloat, sewn: Bool) -> some View {
        let side = min(size.width, size.height)
        let pad = max(8, side * 0.12)
        let rect = CGRect(
            x: (size.width - (size.width - pad * 2)) / 2,
            y: (size.height - (size.height - pad * 2)) / 2,
            width: max(1, size.width - pad * 2),
            height: max(1, size.height - pad * 2)
        )
        let corner = min(rect.width, rect.height) * 0.30
        let line = max(2.0, side * 0.030)

        return ZStack {
            baseButton(rect: rect, corner: corner, sewn: sewn, side: side)
            guideOutline(rect: rect, corner: corner, line: line)
            seam(rect: rect, corner: corner, line: line, progress: progress)
            needleLayer(rect: rect, corner: corner, progress: progress, side: side)
            label(in: rect, sewn: sewn)
        }
    }

    // MARK: Base filled button

    private func baseButton(rect: CGRect, corner: CGFloat, sewn: Bool, side: CGFloat) -> some View {
        let shape = RoundedRectangle(cornerRadius: corner, style: .continuous)
        return shape
            .fill(buttonFill(sewn: sewn))
            .overlay(
                shape.fill(
                    LinearGradient(
                        colors: [Color.white.opacity(0.10), Color.clear],
                        startPoint: .top,
                        endPoint: .center
                    )
                )
            )
            .frame(width: rect.width, height: rect.height)
            .position(x: rect.midX, y: rect.midY)
            .shadow(color: Color.black.opacity(0.35), radius: side * 0.04, x: 0, y: side * 0.02)
            .animation(.easeInOut(duration: 0.5), value: sewn)
    }

    private func buttonFill(sewn: Bool) -> LinearGradient {
        // Warm fabric tone, deepening once the seam is sewn shut.
        let top: Color = sewn
            ? Color(red: 0.16, green: 0.13, blue: 0.10)
            : Color(red: 0.13, green: 0.11, blue: 0.09)
        let bottom: Color = sewn
            ? Color(red: 0.10, green: 0.08, blue: 0.06)
            : Color(red: 0.09, green: 0.075, blue: 0.06)
        return LinearGradient(colors: [top, bottom], startPoint: .top, endPoint: .bottom)
    }

    // MARK: Faint "unsewn" guide so the tile is never blank

    private func guideOutline(rect: CGRect, corner: CGFloat, line: CGFloat) -> some View {
        StitchThreadView_SeamShape(cornerRadius: corner)
            .stroke(
                Color(red: 0.78, green: 0.70, blue: 0.55).opacity(0.18),
                style: StrokeStyle(lineWidth: max(1, line * 0.55), dash: [line * 1.4, line * 1.4])
            )
            .frame(width: rect.width, height: rect.height)
            .position(x: rect.midX, y: rect.midY)
    }

    // MARK: The sewn dashed seam (the thread)

    private func seam(rect: CGRect, corner: CGFloat, line: CGFloat, progress: CGFloat) -> some View {
        let dash = line * 1.4
        let thread = Color(red: 0.95, green: 0.83, blue: 0.55)
        return ZStack {
            // Soft halo of the thread for depth.
            StitchThreadView_SeamShape(cornerRadius: corner)
                .trim(from: 0, to: progress)
                .stroke(
                    thread.opacity(0.35),
                    style: StrokeStyle(lineWidth: line * 1.9, lineCap: .round, dash: [dash, dash])
                )
                .blur(radius: line * 0.5)
            // The crisp stitch line.
            StitchThreadView_SeamShape(cornerRadius: corner)
                .trim(from: 0, to: progress)
                .stroke(
                    LinearGradient(
                        colors: [thread, Color(red: 0.85, green: 0.66, blue: 0.36)],
                        startPoint: .topLeading,
                        endPoint: .bottomTrailing
                    ),
                    style: StrokeStyle(lineWidth: line, lineCap: .butt, dash: [dash, dash])
                )
        }
        .frame(width: rect.width, height: rect.height)
        .position(x: rect.midX, y: rect.midY)
    }

    // MARK: Needle riding the leading edge of the seam

    private func needleLayer(rect: CGRect, corner: CGFloat, progress: CGFloat, side: CGFloat) -> some View {
        // Translate the seam path into the rect's coordinate space, then read
        // the EXACT endpoint of the revealed segment — identical geometry to
        // the dashed stroke above, so the needle can never drift.
        let localRect = CGRect(origin: .zero, size: rect.size)
        let basePath = seamPath(in: localRect, cornerRadius: corner)
        let tip = pointOnPath(basePath, at: progress) ?? CGPoint(x: localRect.midX, y: localRect.minY)
        let prior = pointOnPath(basePath, at: max(0, progress - 0.012)) ?? tip
        let angle = tangentAngle(from: prior, to: tip)
        let visible = progress > 0.002 && progress < 0.999

        return needle(side: side, angle: angle)
            .position(x: rect.minX + tip.x, y: rect.minY + tip.y)
            .opacity(visible ? 1 : 0)
            .animation(.easeOut(duration: 0.18), value: visible)
    }

    private func needle(side: CGFloat, angle: Angle) -> some View {
        let len = side * 0.34
        let w = max(2.0, side * 0.030)
        return ZStack {
            // Trailing thread tail from the eye of the needle.
            Capsule()
                .fill(Color(red: 0.95, green: 0.83, blue: 0.55).opacity(0.9))
                .frame(width: len * 0.55, height: max(1, w * 0.35))
                .offset(x: -len * 0.55)
            StitchThreadView_NeedleShape()
                .fill(
                    LinearGradient(
                        colors: [
                            Color(red: 0.92, green: 0.93, blue: 0.96),
                            Color(red: 0.62, green: 0.64, blue: 0.70)
                        ],
                        startPoint: .top,
                        endPoint: .bottom
                    )
                )
                .frame(width: len, height: w)
                .shadow(color: Color.black.opacity(0.35), radius: w * 0.4, x: 0, y: w * 0.2)
        }
        .rotationEffect(angle)
    }

    // MARK: Centered label

    private func label(in rect: CGRect, sewn: Bool) -> some View {
        let fontSize = min(rect.width, rect.height) * 0.20
        return Group {
            if sewn {
                HStack(spacing: fontSize * 0.3) {
                    Image(systemName: "checkmark")
                    Text("Sewn")
                }
            } else {
                Text("Confirm")
            }
        }
        .font(.system(size: max(9, fontSize), weight: .semibold, design: .rounded))
        .foregroundStyle(Color(red: 0.96, green: 0.92, blue: 0.84))
        .lineLimit(1)
        .minimumScaleFactor(0.5)
        .frame(width: rect.width * 0.8)
        .position(x: rect.midX, y: rect.midY)
        .animation(.easeInOut(duration: 0.4), value: sewn)
    }

    // MARK: Timing helpers

    private func triangleWave(at date: Date, period: Double) -> CGFloat {
        let t = date.timeIntervalSinceReferenceDate.truncatingRemainder(dividingBy: period)
        let phase = t / period            // 0 ..< 1
        let v = phase < 0.5 ? phase * 2 : (1 - phase) * 2
        return CGFloat(min(1, max(0, v)))
    }

    private func easeInOut(_ x: CGFloat) -> CGFloat {
        // Smoothstep — softens the linear triangle into a hand-sewn cadence.
        let c = min(1, max(0, x))
        return c * c * (3 - 2 * c)
    }
}

// MARK: - Seam geometry: ONE source of truth

/// Builds the perimeter as a rounded rectangle with a known start point
/// (top edge, just right of the top-left corner) winding clockwise, so the
/// dashed stroke and the needle endpoint are guaranteed to agree.
private func seamPath(in rect: CGRect, cornerRadius: CGFloat) -> Path {
    let r = min(cornerRadius, min(rect.width, rect.height) / 2)
    let minX = rect.minX, minY = rect.minY
    let maxX = rect.maxX, maxY = rect.maxY
    var p = Path()

    // Start at top edge after the top-left corner arc.
    p.move(to: CGPoint(x: minX + r, y: minY))
    // Top edge -> top-right corner.
    p.addLine(to: CGPoint(x: maxX - r, y: minY))
    p.addArc(center: CGPoint(x: maxX - r, y: minY + r), radius: r,
             startAngle: .degrees(-90), endAngle: .degrees(0), clockwise: false)
    // Right edge -> bottom-right corner.
    p.addLine(to: CGPoint(x: maxX, y: maxY - r))
    p.addArc(center: CGPoint(x: maxX - r, y: maxY - r), radius: r,
             startAngle: .degrees(0), endAngle: .degrees(90), clockwise: false)
    // Bottom edge -> bottom-left corner.
    p.addLine(to: CGPoint(x: minX + r, y: maxY))
    p.addArc(center: CGPoint(x: minX + r, y: maxY - r), radius: r,
             startAngle: .degrees(90), endAngle: .degrees(180), clockwise: false)
    // Left edge -> top-left corner.
    p.addLine(to: CGPoint(x: minX, y: minY + r))
    p.addArc(center: CGPoint(x: minX + r, y: minY + r), radius: r,
             startAngle: .degrees(180), endAngle: .degrees(270), clockwise: false)
    p.closeSubpath()
    return p
}

/// Endpoint of the revealed segment of the seam at `progress` — the exact
/// leading edge of the dashes, used to anchor the needle.
private func pointOnPath(_ path: Path, at progress: CGFloat) -> CGPoint? {
    let p = min(1, max(0, progress))
    if p <= 0 { return nil }
    let trimmed = path.trimmedPath(from: 0, to: p)
    return trimmed.currentPoint
}

private func tangentAngle(from a: CGPoint, to b: CGPoint) -> Angle {
    let dx = b.x - a.x
    let dy = b.y - a.y
    if abs(dx) < 0.0001 && abs(dy) < 0.0001 { return .zero }
    return Angle(radians: atan2(Double(dy), Double(dx)))
}

// MARK: - Shapes

/// The seam shape — delegates to the shared `seamPath` so the trimmed stroke
/// matches the needle's anchor exactly.
private struct StitchThreadView_SeamShape: Shape {
    var cornerRadius: CGFloat
    func path(in rect: CGRect) -> Path {
        seamPath(in: rect, cornerRadius: cornerRadius)
    }
}

/// A simple sewing needle: a tapered body with an eye, drawn pointing right
/// (it is rotated to follow the seam tangent by the caller).
private struct StitchThreadView_NeedleShape: Shape {
    func path(in rect: CGRect) -> Path {
        var p = Path()
        let w = rect.width
        let h = rect.height
        let midY = rect.midY
        let tipX = rect.maxX
        let bluntX = rect.minX

        // Pointed tip on the right.
        p.move(to: CGPoint(x: tipX, y: midY))
        p.addLine(to: CGPoint(x: tipX - w * 0.18, y: midY - h * 0.5))
        p.addLine(to: CGPoint(x: bluntX + w * 0.10, y: midY - h * 0.32))
        // Rounded blunt (eye) end on the left.
        p.addQuadCurve(
            to: CGPoint(x: bluntX + w * 0.10, y: midY + h * 0.32),
            control: CGPoint(x: bluntX, y: midY)
        )
        p.addLine(to: CGPoint(x: tipX - w * 0.18, y: midY + h * 0.5))
        p.closeSubpath()
        return p
    }
}
"""###,
        "btn-tear-perforation": ###"""
import SwiftUI

// MARK: - TearPerforationView
//
// Swipe along the dotted perforation to rip the button like a coupon stub.
// The torn edge frays with jagged paper detail and a widening gap reveals the
// action underneath. Past threshold the stub detaches and flutters away.
//
// demo == true  -> self-driving TimelineView loop (tear -> flutter -> reform)
// demo == false -> real DragGesture along the perforation seam
//
// Pure SwiftUI, iOS 17. No app dependencies.

struct TearPerforationView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { geo in
            content(size: geo.size)
                .frame(maxWidth: .infinity, maxHeight: .infinity)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    @ViewBuilder
    private func content(size: CGSize) -> some View {
        if demo {
            TearPerforationView_DemoDriver(size: size)
        } else {
            TearPerforationView_InteractiveDriver(size: size)
        }
    }
}

// MARK: - Palette (Color literals only)

private enum TearPerforationView_TearPalette {
    // Warm paper / coupon stub
    static let paperTop = Color(red: 0.98, green: 0.95, blue: 0.88)
    static let paperBottom = Color(red: 0.93, green: 0.88, blue: 0.78)
    static let paperEdge = Color(red: 0.80, green: 0.71, blue: 0.56)
    static let ink = Color(red: 0.24, green: 0.20, blue: 0.14)
    static let perforation = Color(red: 0.55, green: 0.47, blue: 0.36)

    // Revealed action underneath (confirmed / go state)
    static let revealTop = Color(red: 0.16, green: 0.62, blue: 0.42)
    static let revealBottom = Color(red: 0.09, green: 0.45, blue: 0.30)
    static let revealText = Color(red: 0.97, green: 0.99, blue: 0.96)
    static let frayShadow = Color(red: 0.62, green: 0.52, blue: 0.38)
}

// MARK: - Jagged tear edge (Animatable Shape)
//
// A vertical ragged line that lives at a *fixed* perforation x.
// `progress` (0...1) does NOT move the seam sideways; it controls how far the
// paper has receded from that seam, which is what reveals the layer beneath.
//
// `side`:
//   .body  -> fills the region to the LEFT of (seam - recession). As progress
//             rises the right ragged edge pulls back toward the left.
//   .stub  -> fills the region to the RIGHT of (seam + recession). As progress
//             rises the left ragged edge peels rightward.
//
// The ragged offsets come from `jitter(_:)` — a pure deterministic hash — so the
// silhouette is identical on every redraw and never strobes (the named risk).
// Both shapes read the SAME jitter for the shared seam, keeping them complementary.

private struct TearPerforationView_TearEdgeShape: Shape {
    enum Side { case body, stub }

    var progress: CGFloat
    let side: Side
    let seamFraction: CGFloat   // 0...1 position of the perforation across width
    let segments: Int           // number of ragged teeth down the height

    var animatableData: CGFloat {
        get { progress }
        set { progress = newValue }
    }

    func path(in rect: CGRect) -> Path {
        let clamped = max(0, min(1, progress))
        let seamX = rect.minX + seamFraction * rect.width

        // How far the paper recedes from the seam at full tear, per side.
        let maxRecession = rect.width * 0.42
        let recession = maxRecession * clamped

        // Ragged amplitude: a touch larger as the tear opens (fresh fibers).
        let baseAmp = rect.width * 0.045
        let amp = baseAmp + rect.width * 0.02 * clamped

        var path = Path()
        let n = max(2, segments)

        switch side {
        case .body:
            let edgeX = seamX - recession
            path.move(to: CGPoint(x: rect.minX, y: rect.minY))
            // Down the ragged right edge.
            for i in 0...n {
                let t = CGFloat(i) / CGFloat(n)
                let y = rect.minY + t * rect.height
                let offset = (jitter(i) - 0.5) * 2 * amp
                path.addLine(to: CGPoint(x: edgeX + offset, y: y))
            }
            path.addLine(to: CGPoint(x: rect.minX, y: rect.maxY))
            path.closeSubpath()

        case .stub:
            let edgeX = seamX + recession
            path.move(to: CGPoint(x: rect.maxX, y: rect.minY))
            // Down the ragged left edge — same jitter so it mirrors the seam.
            for i in 0...n {
                let t = CGFloat(i) / CGFloat(n)
                let y = rect.minY + t * rect.height
                let offset = (jitter(i) - 0.5) * 2 * amp
                path.addLine(to: CGPoint(x: edgeX + offset, y: y))
            }
            path.addLine(to: CGPoint(x: rect.maxX, y: rect.maxY))
            path.closeSubpath()
        }
        return path
    }

    // Deterministic pseudo-random in 0...1. Stable per segment index, no @State,
    // never re-rolls across frames or re-inits.
    private func jitter(_ i: Int) -> CGFloat {
        let v = sin(Double(i) * 12.9898 + 4.123) * 43758.5453
        return CGFloat(v - v.rounded(.down))
    }
}

// MARK: - Shared visual constants

private enum TearPerforationView_TearLayout {
    static let seamFraction: CGFloat = 0.46
    static let detachThreshold: CGFloat = 0.6
    static let segments = 22
}

// MARK: - Revealed action (always opaque -> guarantees no blank frame)

private struct TearPerforationView_RevealLayer: View {
    let size: CGSize

    var body: some View {
        let corner = size.height * 0.22
        ZStack {
            RoundedRectangle(cornerRadius: corner, style: .continuous)
                .fill(
                    LinearGradient(
                        colors: [TearPerforationView_TearPalette.revealTop, TearPerforationView_TearPalette.revealBottom],
                        startPoint: .top,
                        endPoint: .bottom
                    )
                )
            Label(title: { Text("Confirmed") }, icon: { Image(systemName: "checkmark") })
                .labelStyle(.titleAndIcon)
                .font(.system(size: max(11, size.height * 0.24), weight: .bold, design: .rounded))
                .foregroundStyle(TearPerforationView_TearPalette.revealText)
                .minimumScaleFactor(0.5)
                .lineLimit(1)
                .padding(.horizontal, size.width * 0.06)
        }
    }
}

// MARK: - Paper face (used for both body and stub halves)

private struct TearPerforationView_PaperFace: View {
    let size: CGSize

    var body: some View {
        let corner = size.height * 0.22
        ZStack {
            RoundedRectangle(cornerRadius: corner, style: .continuous)
                .fill(
                    LinearGradient(
                        colors: [TearPerforationView_TearPalette.paperTop, TearPerforationView_TearPalette.paperBottom],
                        startPoint: .top,
                        endPoint: .bottom
                    )
                )
            RoundedRectangle(cornerRadius: corner, style: .continuous)
                .strokeBorder(TearPerforationView_TearPalette.paperEdge.opacity(0.6), lineWidth: 1)

            Text("RIP TO REDEEM")
                .font(.system(size: max(9, size.height * 0.16), weight: .heavy, design: .rounded))
                .tracking(1.2)
                .foregroundStyle(TearPerforationView_TearPalette.ink)
                .minimumScaleFactor(0.4)
                .lineLimit(1)
                .padding(.horizontal, size.width * 0.05)
        }
    }
}

// MARK: - Dotted perforation affordance (rides the fixed seam)

private struct TearPerforationView_PerforationLine: View {
    let size: CGSize
    let progress: CGFloat

    var body: some View {
        let x = TearPerforationView_TearLayout.seamFraction * size.width
        Path { p in
            p.move(to: CGPoint(x: x, y: size.height * 0.06))
            p.addLine(to: CGPoint(x: x, y: size.height * 0.94))
        }
        .stroke(
            TearPerforationView_TearPalette.perforation,
            style: StrokeStyle(lineWidth: 1.6, lineCap: .round, dash: [2.5, 4])
        )
        // Fades as the tear opens — it has "given way".
        .opacity(Double(1 - min(1, progress * 1.4)))
    }
}

// MARK: - Composited torn button (geometry-only; reused by both drivers)

private struct TearPerforationView_TornButton: View {
    let size: CGSize
    let progress: CGFloat   // 0...1 tear amount

    var body: some View {
        let p = max(0, min(1, progress))
        ZStack {
            // Bottom: the revealed action — always opaque, always legible.
            TearPerforationView_RevealLayer(size: size)

            // Body half: clipped to the receding left region.
            TearPerforationView_PaperFace(size: size)
                .overlay(frayHighlight(side: .body))
                .clipShape(
                    TearPerforationView_TearEdgeShape(
                        progress: p,
                        side: .body,
                        seamFraction: TearPerforationView_TearLayout.seamFraction,
                        segments: TearPerforationView_TearLayout.segments
                    )
                )
                .shadow(color: TearPerforationView_TearPalette.frayShadow.opacity(0.5 * Double(p)),
                        radius: 3, x: 3, y: 0)

            // Stub half: clipped to the right region, then flies off past threshold.
            stubView(p: p)

            // Dotted perforation affordance over the closed seam.
            TearPerforationView_PerforationLine(size: size, progress: p)
        }
        .compositingGroup()
    }

    @ViewBuilder
    private func stubView(p: CGFloat) -> some View {
        let detached = max(0, (p - TearPerforationView_TearLayout.detachThreshold) / (1 - TearPerforationView_TearLayout.detachThreshold))
        let flyX = size.width * 0.85 * detached
        let flyY = size.height * 0.55 * detached * detached
        let rot = Angle(degrees: Double(detached) * 26)
        let fade = 1 - Double(detached) * 0.85

        TearPerforationView_PaperFace(size: size)
            .overlay(frayHighlight(side: .stub))
            .clipShape(
                TearPerforationView_TearEdgeShape(
                    progress: p,
                    side: .stub,
                    seamFraction: TearPerforationView_TearLayout.seamFraction,
                    segments: TearPerforationView_TearLayout.segments
                )
            )
            .rotationEffect(rot, anchor: .bottomTrailing)
            .offset(x: flyX, y: flyY)
            .opacity(fade)
            .shadow(color: TearPerforationView_TearPalette.frayShadow.opacity(0.45 * Double(detached)),
                    radius: 4, x: -2, y: 4)
    }

    // A soft warm highlight hugging the torn edge to fake exposed paper fibers.
    @ViewBuilder
    private func frayHighlight(side: TearPerforationView_TearEdgeShape.Side) -> some View {
        let seamX = TearPerforationView_TearLayout.seamFraction * size.width
        let recede = size.width * 0.42 * max(0, min(1, progress))
        let center: CGFloat = side == .body ? (seamX - recede) : (seamX + recede)
        RadialGradient(
            colors: [TearPerforationView_TearPalette.frayShadow.opacity(0.55), .clear],
            center: UnitPoint(x: center / max(1, size.width), y: 0.5),
            startRadius: 0,
            endRadius: size.width * 0.18
        )
        .allowsHitTesting(false)
    }
}

// MARK: - Demo driver (self-running loop, never blank, no haptics)

private struct TearPerforationView_DemoDriver: View {
    let size: CGSize

    var body: some View {
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            TearPerforationView_TornButton(size: size, progress: Self.loopProgress(t))
        }
    }

    // ~3.4s cycle: ease the tear open 0->1, hold detached briefly, ease reform.
    static func loopProgress(_ time: TimeInterval) -> CGFloat {
        let period: TimeInterval = 3.4
        let phase = (time.truncatingRemainder(dividingBy: period)) / period // 0..1

        if phase < 0.45 {
            // tear open
            let u = phase / 0.45
            return easeInOut(CGFloat(u))
        } else if phase < 0.62 {
            // hold fully torn (stub flutters away)
            return 1
        } else {
            // ease back to whole (paper reforms)
            let u = (phase - 0.62) / 0.38
            return 1 - easeInOut(CGFloat(u))
        }
    }

    private static func easeInOut(_ x: CGFloat) -> CGFloat {
        let c = max(0, min(1, x))
        return c * c * (3 - 2 * c)
    }
}

// MARK: - Interactive driver (real DragGesture + gated haptic)

private struct TearPerforationView_InteractiveDriver: View {
    let size: CGSize

    @State private var committed: CGFloat = 0      // resting / settled tear amount
    @State private var live: CGFloat = 0           // live drag delta contribution
    @State private var impactTrigger: Int = 0      // stored Equatable for haptic

    var body: some View {
        let progress = max(0, min(1, committed + live))

        TearPerforationView_TornButton(size: size, progress: progress)
            .contentShape(Rectangle())
            .gesture(dragGesture())
            .sensoryFeedback(.impact(weight: .medium), trigger: impactTrigger)
    }

    private func dragGesture() -> some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                // Map horizontal drag distance to tear progress, relative to width
                // so it feels right in both a 120pt tile and a large detail view.
                let span = size.width * 0.65
                live = max(-committed, min(1 - committed, value.translation.width / max(1, span)))
            }
            .onEnded { _ in
                let final = max(0, min(1, committed + live))
                live = 0
                // Animate both the detach (committed 0->1) AND the snap-back from a
                // partial tear. Wrapping the resets in withAnimation guarantees the
                // spring fires even when `committed` does not change value (e.g. a
                // partial drag that snaps back to the resting 0).
                if final >= TearPerforationView_TearLayout.detachThreshold {
                    withAnimation(.interpolatingSpring(stiffness: 170, damping: 14)) {
                        committed = 1                 // spring the stub free
                    }
                    impactTrigger += 1                // fire haptic once, on the crossing
                } else {
                    withAnimation(.interpolatingSpring(stiffness: 170, damping: 14)) {
                        committed = 0                 // snap back to whole
                    }
                }
            }
    }
}
"""###,
        "btn-thermal-press": ###"""
import SwiftUI

/// Thermal Press — hold to heat the button through color stages from cool blue
/// to glowing orange with a rising heat-shimmer haze; releasing lets it cool and
/// fade. Pure SwiftUI (no shaders): a single TimelineView(.animation) drives both
/// the auto-demo loop and the interactive press, computing a continuous 0→1 heat
/// value per frame that maps through a manual blue→amber→orange gradient plus a
/// growing glow and an oscillating blurred shimmer overlay.
struct ThermalPressView: View {
    var demo: Bool = false

    // Interactive press state. We drive the actual heat ramp from timestamps so
    // the value is frame-accurate and fully controllable (LongPressGesture only
    // fires once and can't express a continuous "while held" ramp).
    @State private var isPressing: Bool = false
    @State private var pressStart: Date = .distantPast
    @State private var releaseDate: Date = .distantPast
    @State private var heatAtRelease: Double = 0

    // Tuning constants.
    private let rampDuration: Double = 2.0      // seconds to reach redline while held
    private let coolDuration: Double = 1.1      // seconds to cool back to zero
    private let demoPeriod: Double = 3.4        // full heat 0→1→0 demo loop
    private let redline: Double = 0.82          // threshold for the warning haptic

    var body: some View {
        GeometryReader { geo in
            TimelineView(.animation) { timeline in
                let now = timeline.date
                let heat = currentHeat(at: now)
                content(heat: heat, size: geo.size, now: now)
                    // Frame-accurate haptic: fires on the render where heat crosses
                    // redline, no @State mutation inside the timeline closure.
                    .sensoryFeedback(.warning, trigger: heat >= redline)
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .contentShape(Rectangle())
        .gesture(pressGesture)
    }

    // MARK: - Gesture

    // DragGesture(minimumDistance:0) gives reliable press-down / release callbacks
    // and wins inside a ScrollView, unlike a bare LongPressGesture.
    private var pressGesture: some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { _ in
                guard !isPressing else { return }
                isPressing = true
                pressStart = Date()
            }
            .onEnded { _ in
                guard isPressing else { return }
                // Capture the heat we actually reached so an early release cools
                // from there instead of snapping to full-hot.
                heatAtRelease = interactiveHeat(at: Date())
                isPressing = false
                releaseDate = Date()
            }
    }

    // MARK: - Heat computation

    private func currentHeat(at date: Date) -> Double {
        if demo {
            return demoHeat(at: date)
        }
        return interactiveHeat(at: date)
    }

    /// Triangle ramp 0→1→0 over `demoPeriod`, smoothed so the auto-demo eases in
    /// and out of the redline rather than turning sharply.
    private func demoHeat(at date: Date) -> Double {
        let t = date.timeIntervalSinceReferenceDate.truncatingRemainder(dividingBy: demoPeriod)
        let phase = t / demoPeriod                 // 0...1
        let triangle = phase < 0.5 ? phase * 2 : (1 - phase) * 2
        return smooth(triangle)
    }

    /// While pressing: ramp from 0 toward 1 over `rampDuration`, clamped.
    /// After release: ease from `heatAtRelease` back to 0 over `coolDuration`.
    private func interactiveHeat(at date: Date) -> Double {
        if isPressing {
            let elapsed = date.timeIntervalSince(pressStart)
            let raw = max(0, elapsed) / rampDuration
            return min(1, raw)
        }
        let sinceRelease = date.timeIntervalSince(releaseDate)
        if sinceRelease < 0 || sinceRelease >= coolDuration {
            return 0
        }
        let k = 1 - (sinceRelease / coolDuration)   // 1→0
        return heatAtRelease * smooth(k)
    }

    /// Smoothstep easing.
    private func smooth(_ x: Double) -> Double {
        let c = min(1, max(0, x))
        return c * c * (3 - 2 * c)
    }

    // MARK: - Content

    @ViewBuilder
    private func content(heat: Double, size: CGSize, now: Date) -> some View {
        let dim = min(size.width, size.height)
        let cornerR = dim * 0.22
        let glowR = heat * dim * 0.34
        let hot = heatColor(heat)
        let labelText = heat >= redline ? "HOT" : "HOLD"

        ZStack {
            buttonBody(heat: heat, hot: hot, cornerR: cornerR, dim: dim)
                .shadow(color: hot.opacity(0.65 * heat + 0.1), radius: glowR)
                .shadow(color: hot.opacity(0.45 * heat), radius: glowR * 0.45)
                .overlay {
                    shimmer(heat: heat, size: size, cornerR: cornerR, now: now)
                }
                .overlay {
                    RoundedRectangle(cornerRadius: cornerR, style: .continuous)
                        .strokeBorder(rimGradient(heat: heat), lineWidth: max(1, dim * 0.012))
                }

            label(text: labelText, heat: heat, dim: dim)
        }
        .padding(dim * 0.12)
    }

    private func buttonBody(heat: Double, hot: Color, cornerR: CGFloat, dim: CGFloat) -> some View {
        RoundedRectangle(cornerRadius: cornerR, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        hot.opacity(1.0),
                        bodyMidColor(heat: heat),
                        coreColor(heat: heat)
                    ],
                    startPoint: .top,
                    endPoint: .bottom
                )
            )
            .overlay {
                // Inner core glow that intensifies with heat (a radial hotspot).
                // Radius is relative to the button size so it reads the same in a
                // small grid tile and a large detail view (no hardcoded pixels).
                RoundedRectangle(cornerRadius: cornerR, style: .continuous)
                    .fill(
                        RadialGradient(
                            colors: [
                                emberColor.opacity(0.85 * heat),
                                .clear
                            ],
                            center: .center,
                            startRadius: 0,
                            endRadius: max(1, dim * 0.5)
                        )
                    )
                    .blendMode(.screen)
            }
    }

    // MARK: - Shimmer overlay

    /// A blurred wavy band that rides up the button. Amplitude and opacity scale
    /// with heat so it is calm-but-present when cool and a rising haze when hot.
    private func shimmer(heat: Double, size: CGSize, cornerR: CGFloat, now: Date) -> some View {
        let t = now.timeIntervalSinceReferenceDate
        let amp = (0.10 + heat * 0.9)
        return ThermalPressView_ShimmerShape(phase: t * 2.4, amplitude: amp)
            .fill(
                LinearGradient(
                    colors: [
                        .white.opacity(0.0),
                        .white.opacity(0.22 + 0.30 * heat),
                        .white.opacity(0.0)
                    ],
                    startPoint: .leading,
                    endPoint: .trailing
                )
            )
            .blur(radius: max(2, size.width * 0.03))
            .blendMode(.screen)
            .opacity(0.35 + 0.65 * heat)
            .clipShape(RoundedRectangle(cornerRadius: cornerR, style: .continuous))
            .allowsHitTesting(false)
    }

    // MARK: - Label

    private func label(text: String, heat: Double, dim: CGFloat) -> some View {
        Text(text)
            .font(.system(size: max(11, dim * 0.16), weight: .heavy, design: .rounded))
            .tracking(dim * 0.02)
            .foregroundStyle(.white)
            .shadow(color: emberColor.opacity(heat), radius: heat * 6)
            .opacity(0.9)
            .scaleEffect(1 + heat * 0.05)
            .allowsHitTesting(false)
    }

    // MARK: - Color model (manual lerps → Color(red:green:blue:))

    /// Blue → amber → orange, routed through a mid stop so it never goes muddy.
    private func heatColor(_ t: Double) -> Color {
        let cool = (r: 0.16, g: 0.42, b: 0.88)   // cool steel blue
        let mid  = (r: 0.92, g: 0.62, b: 0.20)   // amber
        let hot  = (r: 1.00, g: 0.34, b: 0.10)   // glowing orange
        if t < 0.5 {
            let k = t / 0.5
            return lerp(cool, mid, k)
        }
        let k = (t - 0.5) / 0.5
        return lerp(mid, hot, k)
    }

    private func bodyMidColor(heat: Double) -> Color {
        let cool = (r: 0.10, g: 0.27, b: 0.62)
        let hot  = (r: 0.86, g: 0.22, b: 0.06)
        return lerp(cool, hot, heat)
    }

    private func coreColor(heat: Double) -> Color {
        let cool = (r: 0.05, g: 0.14, b: 0.36)
        let hot  = (r: 0.55, g: 0.10, b: 0.02)
        return lerp(cool, hot, heat)
    }

    private func rimGradient(heat: Double) -> LinearGradient {
        let top = heatColor(min(1, heat + 0.15)).opacity(0.9)
        let bottom = coreColor(heat: heat).opacity(0.7)
        return LinearGradient(colors: [top, bottom], startPoint: .top, endPoint: .bottom)
    }

    private var emberColor: Color {
        Color(red: 1.0, green: 0.78, blue: 0.30)
    }

    private func lerp(_ a: (r: Double, g: Double, b: Double),
                      _ b: (r: Double, g: Double, b: Double),
                      _ t: Double) -> Color {
        let k = min(1, max(0, t))
        let r = a.r + (b.r - a.r) * k
        let g = a.g + (b.g - a.g) * k
        let bl = a.b + (b.b - a.b) * k
        return Color(red: r, green: g, blue: bl)
    }
}

// MARK: - Shimmer Shape

/// A vertical wavy band whose horizontal edges ripple with `phase`. Used as the
/// heat-shimmer haze; blurred at the call site so the wave reads as a soft glow.
private struct ThermalPressView_ShimmerShape: Shape {
    var phase: Double
    var amplitude: Double

    func path(in rect: CGRect) -> Path {
        var path = Path()
        let steps = 18
        let h = rect.height
        let baseWidth = rect.width * 0.5
        let wob = rect.width * 0.18 * amplitude

        // Left edge of the band, rippling top→bottom.
        var left: [CGPoint] = []
        var right: [CGPoint] = []
        for i in 0...steps {
            let f = Double(i) / Double(steps)
            let y = h * f
            let s = sin(f * .pi * 3 + phase)
            let s2 = sin(f * .pi * 5 - phase * 0.7)
            let centerX = rect.midX + wob * (s * 0.6 + s2 * 0.4)
            left.append(CGPoint(x: centerX - baseWidth / 2, y: y))
            right.append(CGPoint(x: centerX + baseWidth / 2, y: y))
        }

        guard let first = left.first else { return path }
        path.move(to: first)
        for p in left.dropFirst() { path.addLine(to: p) }
        for p in right.reversed() { path.addLine(to: p) }
        path.closeSubpath()
        return path
    }
}
"""###,
        "btn-vault-dial": ###"""
import SwiftUI

// MARK: - Vault Dial
// Rotate the dial like a safe combination. Correct stops illuminate one by one;
// the final turn swings the whole face open like a vault door, revealing the
// unlocked content behind it.
//
// Shared render state (dialAngle / litStops / doorProgress) is written by either
// of two drivers:
//   • demo == true  -> a self-looping PhaseAnimator scripts the sequence.
//   • demo == false -> a DragGesture + atan2 delta-accumulation matcher.
public struct VaultDialView: View {
    var demo: Bool = false

    public init(demo: Bool = false) {
        self.demo = demo
    }

    public var body: some View {
        GeometryReader { geo in
            let side = min(geo.size.width, geo.size.height)
            ZStack {
                VaultDialView_VaultBackdrop(side: side)

                if demo {
                    VaultDialView_DemoDriver(side: side)
                } else {
                    VaultDialView_InteractiveDriver(side: side)
                }
            }
            .frame(width: geo.size.width, height: geo.size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }
}

// MARK: - Palette

private enum VaultDialView_VaultPalette {
    static let plate0 = Color(red: 0.10, green: 0.11, blue: 0.14)
    static let plate1 = Color(red: 0.16, green: 0.17, blue: 0.21)
    static let steelHi = Color(red: 0.62, green: 0.65, blue: 0.72)
    static let steelLo = Color(red: 0.20, green: 0.22, blue: 0.27)
    static let brass    = Color(red: 0.78, green: 0.62, blue: 0.32)
    static let brassDk  = Color(red: 0.42, green: 0.33, blue: 0.16)
    static let litOn    = Color(red: 0.42, green: 0.92, blue: 0.55)
    static let litOff   = Color(red: 0.22, green: 0.24, blue: 0.28)
    static let vaultBg  = Color(red: 0.07, green: 0.08, blue: 0.10)
    static let reveal0  = Color(red: 0.13, green: 0.30, blue: 0.22)
    static let reveal1  = Color(red: 0.07, green: 0.16, blue: 0.13)
}

// MARK: - Backdrop (vault interior, always opaque so an edge-on door is never blank)

private struct VaultDialView_VaultBackdrop: View {
    let side: CGFloat

    var body: some View {
        RoundedRectangle(cornerRadius: side * 0.12, style: .continuous)
            .fill(VaultDialView_VaultPalette.vaultBg)
            .overlay(
                RoundedRectangle(cornerRadius: side * 0.12, style: .continuous)
                    .strokeBorder(VaultDialView_VaultPalette.steelLo, lineWidth: max(1, side * 0.012))
            )
            .frame(width: side * 0.96, height: side * 0.96)
    }
}

// MARK: - Demo driver (auto-loop, no haptics)

private struct VaultDialView_DemoDriver: View {
    let side: CGFloat

    // Phases scripted CW -> CCW -> CW -> open -> reset.
    enum Phase: CaseIterable {
        case rest, spinCW1, spinCCW, spinCW2, unlockedClosed, doorOpen
    }

    var body: some View {
        PhaseAnimator(Phase.allCases) { phase in
            VaultDialView_DialAssembly(
                side: side,
                dialAngle: angle(for: phase),
                litStops: litStops(for: phase),
                doorProgress: doorProgress(for: phase),
                glow: glow(for: phase)
            )
        } animation: { phase in
            switch phase {
            case .rest:           return .easeInOut(duration: 0.45)
            case .spinCW1:        return .easeInOut(duration: 0.85)
            case .spinCCW:        return .easeInOut(duration: 0.95)
            case .spinCW2:        return .easeInOut(duration: 0.80)
            case .unlockedClosed: return .spring(response: 0.35, dampingFraction: 0.6)
            case .doorOpen:       return .spring(response: 0.7, dampingFraction: 0.78)
            }
        }
    }

    private func angle(for phase: Phase) -> Double {
        switch phase {
        case .rest:           return 0
        case .spinCW1:        return .pi * 1.9
        case .spinCCW:        return .pi * 0.5
        case .spinCW2:        return .pi * 2.6
        case .unlockedClosed: return .pi * 2.6
        case .doorOpen:       return .pi * 2.6
        }
    }

    private func litStops(for phase: Phase) -> Int {
        switch phase {
        case .rest:           return 0
        case .spinCW1:        return 1
        case .spinCCW:        return 2
        case .spinCW2:        return 3
        case .unlockedClosed: return 3
        case .doorOpen:       return 3
        }
    }

    private func doorProgress(for phase: Phase) -> Double {
        phase == .doorOpen ? 1 : 0
    }

    private func glow(for phase: Phase) -> Double {
        switch phase {
        case .unlockedClosed, .doorOpen: return 1
        default: return 0
        }
    }
}

// MARK: - Interactive driver (real safe-cracking)

private struct VaultDialView_InteractiveDriver: View {
    let side: CGFloat

    @State private var dialAngle: Double = 0          // accumulated radians
    @State private var litStops: Int = 0
    @State private var doorProgress: Double = 0
    @State private var unlocked: Bool = false

    // Drag tracking
    @State private var lastTouchAngle: Double? = nil   // raw atan2 of previous frame
    @State private var dirSign: Int = 0                // current travel direction (+1 CW / -1 CCW)
    @State private var directionChanges: Int = 0       // how many reversals matched so far

    // Haptic triggers
    @State private var tickTrigger: Int = 0
    @State private var unlockTrigger: Int = 0

    // The combination is "three reversals": CW, then CCW, then CW.
    private let requiredReversals = 3

    var body: some View {
        VaultDialView_DialAssembly(
            side: side,
            dialAngle: dialAngle,
            litStops: litStops,
            doorProgress: doorProgress,
            glow: unlocked ? 1 : 0
        )
        .contentShape(Circle())
        .gesture(dialGesture)
        .sensoryFeedback(.selection, trigger: tickTrigger)
        .sensoryFeedback(.success, trigger: unlockTrigger)
    }

    private var dialGesture: some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in handleChange(value) }
            .onEnded { _ in lastTouchAngle = nil }
    }

    private func handleChange(_ value: DragGesture.Value) {
        guard !unlocked else { return }

        // atan2 of the touch relative to the dial center (center of the assembly).
        let center = CGPoint(x: side * 0.5, y: side * 0.5)
        let raw = atan2(value.location.y - center.y, value.location.x - center.x)

        guard let prev = lastTouchAngle else {
            lastTouchAngle = raw
            return
        }

        // Normalize the delta into [-pi, pi] so the +/-pi wrap never spuriously
        // reads as a huge jump / fake reversal.
        var delta = raw - prev
        if delta > .pi { delta -= 2 * .pi }
        if delta < -.pi { delta += 2 * .pi }
        lastTouchAngle = raw

        dialAngle += delta

        // Direction-reversal matcher: only count meaningful, sustained motion.
        let threshold: Double = 0.02
        guard abs(delta) > threshold else { return }
        let sign = delta > 0 ? 1 : -1

        // Required pattern of travel directions: CW(+1), CCW(-1), CW(+1)
        let pattern = [1, -1, 1]

        if dirSign == 0 {
            // First sustained motion sets the initial direction.
            dirSign = sign
            if sign == pattern[0] {
                registerStop(index: 0)
            }
        } else if sign != dirSign {
            // A reversal happened.
            dirSign = sign
            let expectedIndex = directionChanges // next slot in pattern
            if expectedIndex < pattern.count, sign == pattern[expectedIndex] {
                registerStop(index: expectedIndex)
            } else {
                resetCombination()
            }
        }
    }

    private func registerStop(index: Int) {
        guard index == directionChanges else { return }
        directionChanges = index + 1
        litStops = directionChanges
        tickTrigger += 1
        if directionChanges >= requiredReversals {
            triggerUnlock()
        }
    }

    private func resetCombination() {
        directionChanges = 0
        dirSign = 0
        withAnimation(.easeInOut(duration: 0.25)) {
            litStops = 0
        }
    }

    private func triggerUnlock() {
        unlocked = true
        lastTouchAngle = nil
        unlockTrigger += 1
        withAnimation(.spring(response: 0.7, dampingFraction: 0.78)) {
            doorProgress = 1
        }
    }
}

// MARK: - Dial Assembly (the door + dial face + lights, swung open by doorProgress)

private struct VaultDialView_DialAssembly: View {
    let side: CGFloat
    let dialAngle: Double      // radians
    let litStops: Int
    let doorProgress: Double   // 0...1
    let glow: Double           // 0...1 unlocked illumination

    private var doorAngle: Double { doorProgress * 92 }

    var body: some View {
        ZStack {
            VaultDialView_RevealedContent(side: side)
                .opacity(min(1, doorProgress * 1.6))

            VaultDialView_VaultDoor(
                side: side,
                dialAngle: dialAngle,
                litStops: litStops,
                glow: glow
            )
            // Hinge at the leading edge -> reads as a real vault door, not a flip.
            .rotation3DEffect(
                .degrees(doorAngle),
                axis: (x: 0, y: 1, z: 0),
                anchor: .leading,
                perspective: 0.55
            )
            // Subtle dim as the door turns edge-on.
            .brightness(-0.18 * doorProgress)
        }
    }
}

// MARK: - Revealed content behind the door

private struct VaultDialView_RevealedContent: View {
    let side: CGFloat

    var body: some View {
        ZStack {
            RoundedRectangle(cornerRadius: side * 0.10, style: .continuous)
                .fill(
                    RadialGradient(
                        colors: [VaultDialView_VaultPalette.reveal0, VaultDialView_VaultPalette.reveal1],
                        center: .center,
                        startRadius: side * 0.04,
                        endRadius: side * 0.55
                    )
                )
            VStack(spacing: side * 0.05) {
                Image(systemName: "lock.open.fill")
                    .font(.system(size: side * 0.20, weight: .semibold))
                Text("UNLOCKED")
                    .font(.system(size: side * 0.085, weight: .heavy, design: .rounded))
                    .tracking(side * 0.012)
            }
            .foregroundStyle(VaultDialView_VaultPalette.litOn)
        }
        .frame(width: side * 0.78, height: side * 0.78)
        .shadow(color: VaultDialView_VaultPalette.litOn.opacity(0.4), radius: side * 0.05)
    }
}

// MARK: - The vault door face: steel plate + indicator lights + spinning dial

private struct VaultDialView_VaultDoor: View {
    let side: CGFloat
    let dialAngle: Double
    let litStops: Int
    let glow: Double

    var body: some View {
        ZStack {
            // Steel door plate
            RoundedRectangle(cornerRadius: side * 0.10, style: .continuous)
                .fill(
                    LinearGradient(
                        colors: [VaultDialView_VaultPalette.plate1, VaultDialView_VaultPalette.plate0],
                        startPoint: .topLeading,
                        endPoint: .bottomTrailing
                    )
                )
                .overlay(
                    RoundedRectangle(cornerRadius: side * 0.10, style: .continuous)
                        .strokeBorder(VaultDialView_VaultPalette.steelLo, lineWidth: max(1, side * 0.014))
                )
                .overlay(rivets)
                .frame(width: side * 0.78, height: side * 0.78)

            VaultDialView_StopLights(side: side, litStops: litStops, glow: glow)

            VaultDialView_DialFace(side: side, angle: dialAngle, glow: glow)
        }
    }

    private var rivets: some View {
        GeometryReader { g in
            let inset = g.size.width * 0.10
            let r = g.size.width * 0.020
            ZStack {
                rivet(at: CGPoint(x: inset, y: inset), r: r)
                rivet(at: CGPoint(x: g.size.width - inset, y: inset), r: r)
                rivet(at: CGPoint(x: inset, y: g.size.height - inset), r: r)
                rivet(at: CGPoint(x: g.size.width - inset, y: g.size.height - inset), r: r)
            }
        }
    }

    private func rivet(at p: CGPoint, r: CGFloat) -> some View {
        Circle()
            .fill(
                RadialGradient(
                    colors: [VaultDialView_VaultPalette.steelHi, VaultDialView_VaultPalette.steelLo],
                    center: .topLeading,
                    startRadius: 0,
                    endRadius: r * 2
                )
            )
            .frame(width: r * 2, height: r * 2)
            .position(p)
    }
}

// MARK: - Stop indicator lights (a small ring of pips above the dial)

private struct VaultDialView_StopLights: View {
    let side: CGFloat
    let litStops: Int
    let glow: Double

    private let total = 3

    var body: some View {
        let pip = side * 0.045
        HStack(spacing: side * 0.045) {
            ForEach(0..<total, id: \.self) { i in
                Circle()
                    .fill(i < litStops ? VaultDialView_VaultPalette.litOn : VaultDialView_VaultPalette.litOff)
                    .frame(width: pip, height: pip)
                    .overlay(
                        Circle().strokeBorder(VaultDialView_VaultPalette.steelLo, lineWidth: max(0.5, side * 0.004))
                    )
                    .shadow(
                        color: VaultDialView_VaultPalette.litOn.opacity(i < litStops ? 0.8 : 0),
                        radius: pip * 0.6
                    )
            }
        }
        .offset(y: -side * 0.27)
        .opacity(0.55 + 0.45 * (litStops > 0 ? 1 : 0))
    }
}

// MARK: - The rotating dial face

private struct VaultDialView_DialFace: View {
    let side: CGFloat
    let angle: Double   // radians
    let glow: Double

    private var dialSize: CGFloat { side * 0.50 }

    var body: some View {
        ZStack {
            // Outer brass collar
            Circle()
                .fill(
                    AngularGradient(
                        colors: [
                            VaultDialView_VaultPalette.brassDk, VaultDialView_VaultPalette.brass,
                            VaultDialView_VaultPalette.brassDk, VaultDialView_VaultPalette.brass,
                            VaultDialView_VaultPalette.brassDk
                        ],
                        center: .center
                    )
                )
                .frame(width: dialSize * 1.20, height: dialSize * 1.20)
                .overlay(
                    Circle()
                        .strokeBorder(VaultDialView_VaultPalette.brassDk, lineWidth: max(1, side * 0.01))
                )
                .shadow(color: VaultDialView_VaultPalette.litOn.opacity(0.7 * glow), radius: side * 0.06 * glow)

            // Knurled dial body with tick marks, this rotates.
            ZStack {
                Circle()
                    .fill(
                        RadialGradient(
                            colors: [VaultDialView_VaultPalette.steelHi, VaultDialView_VaultPalette.steelLo],
                            center: .topLeading,
                            startRadius: 0,
                            endRadius: dialSize * 0.8
                        )
                    )
                VaultDialView_DialTicks(diameter: dialSize, lineWidth: max(0.5, side * 0.006))
                // Grip notch indicating the dial's current heading.
                Capsule()
                    .fill(VaultDialView_VaultPalette.plate0)
                    .frame(width: dialSize * 0.06, height: dialSize * 0.30)
                    .offset(y: -dialSize * 0.30)
            }
            .frame(width: dialSize, height: dialSize)
            .rotationEffect(.radians(angle))

            // Center hub
            Circle()
                .fill(
                    RadialGradient(
                        colors: [VaultDialView_VaultPalette.steelHi, VaultDialView_VaultPalette.plate0],
                        center: .topLeading,
                        startRadius: 0,
                        endRadius: dialSize * 0.18
                    )
                )
                .frame(width: dialSize * 0.30, height: dialSize * 0.30)
                .overlay(
                    Circle().strokeBorder(VaultDialView_VaultPalette.steelLo, lineWidth: max(0.5, side * 0.006))
                )
        }
    }
}

// MARK: - Tick marks around the dial rim

private struct VaultDialView_DialTicks: View {
    let diameter: CGFloat
    let lineWidth: CGFloat

    private let count = 24

    var body: some View {
        ZStack {
            ForEach(0..<count, id: \.self) { i in
                let major = i % 3 == 0
                Capsule()
                    .fill(VaultDialView_VaultPalette.plate0.opacity(major ? 0.9 : 0.5))
                    .frame(
                        width: lineWidth * (major ? 1.6 : 1.0),
                        height: diameter * (major ? 0.10 : 0.06)
                    )
                    .offset(y: -diameter * 0.40)
                    .rotationEffect(.degrees(Double(i) / Double(count) * 360))
            }
        }
        .frame(width: diameter, height: diameter)
    }
}
"""###,
        "btn-zipper-confirm": ###"""
import SwiftUI

// MARK: - ZipperConfirmView
// Long-press then drag a zipper pull across the button. Interlocking teeth
// mesh behind the pull until it fully closes and locks into a confirmed state.
// demo == true  -> self-driving TimelineView loop (silent, no haptics).
// demo == false -> real LongPressGesture.sequenced(before: DragGesture).
struct ZipperConfirmView: View {
    var demo: Bool = false

    // Interactive state
    @State private var progress: CGFloat = 0          // 0 = open, 1 = closed/locked
    @State private var locked: Bool = false           // flips false->true to fire haptic

    // Live drag position during the sequenced gesture. @GestureState auto-resets
    // to nil on release, so meshing follows the finger live, then falls back to the
    // committed `progress` when the drag ends.
    @GestureState private var dragLocationX: CGFloat? = nil

    var body: some View {
        GeometryReader { geo in
            let size = geo.size
            ZStack {
                background

                if demo {
                    demoZipper(in: size)
                } else {
                    interactiveZipper(in: size)
                }
            }
            .frame(width: size.width, height: size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .sensoryFeedback(.success, trigger: locked) // declarative; only flips when !demo
    }

    // MARK: Background

    private var background: some View {
        RoundedRectangle(cornerRadius: 22, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.10, green: 0.09, blue: 0.07),
                        Color(red: 0.16, green: 0.14, blue: 0.10)
                    ],
                    startPoint: .top,
                    endPoint: .bottom
                )
            )
            .overlay(
                RoundedRectangle(cornerRadius: 22, style: .continuous)
                    .stroke(Color.white.opacity(0.06), lineWidth: 1)
            )
            .padding(4)
    }

    // MARK: Demo driver (pure function of timeline.date)

    private func demoZipper(in size: CGSize) -> some View {
        TimelineView(.animation) { context in
            let p = ZipperConfirmView.demoProgress(at: context.date)
            ZipperConfirmView_ZipperBody(progress: p, locked: p >= 0.999, size: size)
        }
    }

    /// Cycle: ease close 0->1 (~2s), hold locked (~0.8s), snap open (~0.4s), pause (~0.6s).
    private static func demoProgress(at date: Date) -> CGFloat {
        let cycle: Double = 3.8
        let t = date.timeIntervalSinceReferenceDate.truncatingRemainder(dividingBy: cycle)

        let closeDur: Double = 2.0
        let holdDur: Double = 0.8
        let openDur: Double = 0.4

        if t < closeDur {
            // ease-in-out close
            let x = t / closeDur
            return CGFloat(easeInOut(x))
        } else if t < closeDur + holdDur {
            return 1.0
        } else if t < closeDur + holdDur + openDur {
            // quick snap open
            let x = (t - closeDur - holdDur) / openDur
            return CGFloat(1.0 - easeInOut(x))
        } else {
            return 0.0
        }
    }

    private static func easeInOut(_ x: Double) -> Double {
        let c = min(max(x, 0), 1)
        return c < 0.5 ? 2 * c * c : 1 - pow(-2 * c + 2, 2) / 2
    }

    // MARK: Interactive driver

    private func interactiveZipper(in size: CGSize) -> some View {
        let width = max(size.width, 1)
        // Effective progress: live drag while the finger is down, committed value otherwise.
        let liveProgress: CGFloat = {
            if let x = dragLocationX {
                return min(max(x / width, 0), 1)
            }
            return progress
        }()

        return ZipperConfirmView_ZipperBody(progress: liveProgress, locked: locked, size: size)
            .contentShape(Rectangle())
            .gesture(zipperGesture(width: width))
    }

    private func zipperGesture(width: CGFloat) -> some Gesture {
        // LongPress arms, then a 0-distance drag drives close progress. We use
        // .updating + .onEnded (not .onChanged): SequenceGesture.Value is not
        // Equatable, so .onChanged would fail to type-check.
        LongPressGesture(minimumDuration: 0.1)
            .sequenced(before: DragGesture(minimumDistance: 0))
            .updating($dragLocationX) { value, state, _ in
                switch value {
                case .first:
                    // long-press arming: keep showing committed state
                    state = nil
                case .second(_, let drag):
                    if let drag {
                        state = drag.location.x
                    }
                }
            }
            .onEnded { value in
                if locked { return } // lock is terminal; ignore further drag
                let endX: CGFloat
                switch value {
                case .first:
                    endX = progress * width
                case .second(_, let drag):
                    endX = drag?.location.x ?? (progress * width)
                }
                let p = min(max(endX / max(width, 1), 0), 1)
                if p >= 0.95 {
                    completeLock()
                } else {
                    withAnimation(.interpolatingSpring(stiffness: 180, damping: 16)) {
                        progress = 0
                    }
                }
            }
    }

    private func completeLock() {
        withAnimation(.interpolatingSpring(stiffness: 200, damping: 14)) {
            progress = 1
        }
        if !locked {
            locked = true // fires .success haptic via sensoryFeedback(trigger:)
        }
    }
}

// MARK: - Zipper body (single renderer used by both drivers)

private struct ZipperConfirmView_ZipperBody: View {
    let progress: CGFloat   // 0 open .. 1 closed
    let locked: Bool
    let size: CGSize

    // Visual tuning
    private let toothCount: Int = 16

    private var confirmedTint: Color {
        Color(red: 0.42, green: 0.78, blue: 0.45) // confirmed green
    }
    private var openTint: Color {
        Color(red: 0.74, green: 0.70, blue: 0.62) // brushed-metal tape
    }
    private var teethMetal: Color {
        Color(red: 0.86, green: 0.84, blue: 0.78)
    }

    var body: some View {
        let w = size.width
        let h = size.height
        let inset: CGFloat = 16
        let usableW = max(w - inset * 2, 1)
        let seamY = h / 2
        let pullX = inset + usableW * progress

        // Max vertical separation of the two tapes at the fully-open far edge.
        let maxGap = min(h * 0.22, 26)

        return ZStack {
            // The two tapes + teeth
            ForEach(0..<toothCount, id: \.self) { i in
                tooth(
                    index: i,
                    inset: inset,
                    usableW: usableW,
                    seamY: seamY,
                    pullX: pullX,
                    maxGap: maxGap
                )
            }

            // Confirmed glow wash on the closed (left) portion
            closedWash(inset: inset, usableW: usableW, pullX: pullX)

            // Pull head straddling the seam
            pullHead(at: pullX, seamY: seamY)

            // Status label
            label
                .frame(width: w, height: h, alignment: .center)
        }
        .frame(width: w, height: h)
    }

    // MARK: Per-tooth pair (top points down, bottom points up, interleaved)

    @ViewBuilder
    private func tooth(
        index i: Int,
        inset: CGFloat,
        usableW: CGFloat,
        seamY: CGFloat,
        pullX: CGFloat,
        maxGap: CGFloat
    ) -> some View {
        let step = usableW / CGFloat(toothCount)
        let toothW = step * 0.92
        let centerX = inset + step * (CGFloat(i) + 0.5)

        // Is this tooth behind (left of) the pull head? -> meshed/closed.
        let meshed = centerX <= pullX

        // Gap below the pull tapers from 0 (at the pull) to maxGap at the far edge.
        let distRight = max(centerX - pullX, 0)
        let denom = max(inset + usableW - pullX, 1)
        let gapFraction = distRight / denom
        let gap = meshed ? 0 : maxGap * gapFraction

        let toothH = min(step * 0.95, seamY * 0.78)
        let toothColor = meshed ? confirmedTint : openTint

        // Top tape tooth points DOWN toward the seam.
        let topY = seamY - gap - toothH / 2
        // Bottom tape tooth points UP toward the seam, offset half a tooth horizontally.
        let bottomY = seamY + gap + toothH / 2
        let bottomX = centerX + step * 0.5

        ZStack {
            ZipperConfirmView_ToothShape(pointingDown: true)
                .fill(
                    LinearGradient(
                        colors: [toothColor.opacity(0.95), toothColor.opacity(0.6)],
                        startPoint: .top, endPoint: .bottom
                    )
                )
                .overlay(
                    ZipperConfirmView_ToothShape(pointingDown: true)
                        .stroke(Color.black.opacity(0.18), lineWidth: 0.6)
                )
                .frame(width: toothW, height: toothH)
                .position(x: centerX, y: topY)

            ZipperConfirmView_ToothShape(pointingDown: false)
                .fill(
                    LinearGradient(
                        colors: [toothColor.opacity(0.6), toothColor.opacity(0.95)],
                        startPoint: .top, endPoint: .bottom
                    )
                )
                .overlay(
                    ZipperConfirmView_ToothShape(pointingDown: false)
                        .stroke(Color.black.opacity(0.18), lineWidth: 0.6)
                )
                .frame(width: toothW, height: toothH)
                .position(x: bottomX, y: bottomY)
        }
        .shadow(color: .black.opacity(meshed ? 0.25 : 0.12), radius: 1, y: 0.5)
    }

    // MARK: Confirmed wash over the meshed section

    private func closedWash(inset: CGFloat, usableW: CGFloat, pullX: CGFloat) -> some View {
        let washW = max(pullX - inset, 0)
        return RoundedRectangle(cornerRadius: 8, style: .continuous)
            .fill(confirmedTint.opacity(0.16))
            .frame(width: washW, height: size.height * 0.5)
            .position(x: inset + washW / 2, y: size.height / 2)
            .blendMode(.plusLighter)
            .allowsHitTesting(false)
    }

    // MARK: Pull head

    private func pullHead(at x: CGFloat, seamY: CGFloat) -> some View {
        let bodyW: CGFloat = 22
        let bodyH = min(size.height * 0.6, 44)
        return ZStack {
            // Slider body (rounded trapezoid-ish)
            ZipperConfirmView_PullHeadShape()
                .fill(
                    LinearGradient(
                        colors: [
                            Color(red: 0.93, green: 0.92, blue: 0.88),
                            Color(red: 0.62, green: 0.60, blue: 0.55)
                        ],
                        startPoint: .top, endPoint: .bottom
                    )
                )
                .overlay(
                    ZipperConfirmView_PullHeadShape().stroke(Color.black.opacity(0.25), lineWidth: 0.8)
                )
                .frame(width: bodyW, height: bodyH)

            // Tab
            Capsule()
                .fill(Color(red: 0.34, green: 0.32, blue: 0.29))
                .frame(width: 5, height: bodyH * 0.5)
                .offset(y: bodyH * 0.5)
        }
        .shadow(color: .black.opacity(0.4), radius: 3, y: 2)
        .position(x: x, y: seamY)
        .allowsHitTesting(false)
    }

    // MARK: Label

    @ViewBuilder
    private var label: some View {
        if locked || progress >= 0.95 {
            HStack(spacing: 6) {
                Image(systemName: "checkmark.circle.fill")
                Text("Confirmed")
                    .fontWeight(.semibold)
            }
            .font(.system(size: 14, design: .rounded))
            .foregroundStyle(confirmedTint)
            .opacity(0.95)
            .transition(.opacity)
        } else {
            Text("Slide to confirm")
                .font(.system(size: 13, weight: .medium, design: .rounded))
                .foregroundStyle(Color.white.opacity(0.55 - Double(progress) * 0.45))
        }
    }
}

// MARK: - Shapes

/// A single zipper tooth: a chamfered triangle/trapezoid pointing up or down.
private struct ZipperConfirmView_ToothShape: Shape {
    let pointingDown: Bool

    func path(in rect: CGRect) -> Path {
        var p = Path()
        let w = rect.width
        let h = rect.height
        let cham = w * 0.28 // chamfer on the tip so teeth read as metal nubs
        if pointingDown {
            p.move(to: CGPoint(x: 0, y: 0))
            p.addLine(to: CGPoint(x: w, y: 0))
            p.addLine(to: CGPoint(x: w, y: h * 0.45))
            p.addLine(to: CGPoint(x: w - cham, y: h))
            p.addLine(to: CGPoint(x: cham, y: h))
            p.addLine(to: CGPoint(x: 0, y: h * 0.45))
        } else {
            p.move(to: CGPoint(x: cham, y: 0))
            p.addLine(to: CGPoint(x: w - cham, y: 0))
            p.addLine(to: CGPoint(x: w, y: h * 0.55))
            p.addLine(to: CGPoint(x: w, y: h))
            p.addLine(to: CGPoint(x: 0, y: h))
            p.addLine(to: CGPoint(x: 0, y: h * 0.55))
        }
        p.closeSubpath()
        return p
    }
}

/// The zipper pull/slider body.
private struct ZipperConfirmView_PullHeadShape: Shape {
    func path(in rect: CGRect) -> Path {
        let w = rect.width
        let h = rect.height
        let r: CGFloat = min(w, h) * 0.28
        var p = Path()
        // Narrower at the bottom (where the tab hangs), wider at the top.
        let topInset = w * 0.04
        let botInset = w * 0.18
        p.move(to: CGPoint(x: topInset + r, y: 0))
        p.addLine(to: CGPoint(x: w - topInset - r, y: 0))
        p.addQuadCurve(to: CGPoint(x: w - topInset, y: r),
                       control: CGPoint(x: w - topInset, y: 0))
        p.addLine(to: CGPoint(x: w - botInset, y: h - r))
        p.addQuadCurve(to: CGPoint(x: w - botInset - r, y: h),
                       control: CGPoint(x: w - botInset, y: h))
        p.addLine(to: CGPoint(x: botInset + r, y: h))
        p.addQuadCurve(to: CGPoint(x: botInset, y: h - r),
                       control: CGPoint(x: botInset, y: h))
        p.addLine(to: CGPoint(x: topInset, y: r))
        p.addQuadCurve(to: CGPoint(x: topInset + r, y: 0),
                       control: CGPoint(x: topInset, y: 0))
        p.closeSubpath()
        return p
    }
}
"""###,
        "ges-accordion-fold-list": ###"""
import SwiftUI

// MARK: - Public View

/// Accordion Fold Reveal — drag the header down and the panel below unfolds in
/// accordion bellows. Each pleat hinges about its top edge with alternating
/// angles, and its gradient brightness is keyed to its signed fold angle so a
/// glint travels down the stack as it opens — reading as a 3D paper bellows
/// rather than a height animation.
struct AccordionFoldListView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { geo in
            if demo {
                DemoDriver(size: geo.size)
            } else {
                InteractiveBellows(size: geo.size)
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }
}

// MARK: - Demo (self-driving)

private struct DemoDriver: View {
    let size: CGSize

    var body: some View {
        TimelineView(.animation) { context in
            let t = context.date.timeIntervalSinceReferenceDate
            BellowsStack(unfold: Self.wave(at: t), size: size)
        }
    }

    /// Smooth 0 → 1 → 0 ease over a ~3.4s loop. Holds briefly open/closed so the
    /// glint can travel and the eye can read the bellows at the extremes.
    static func wave(at time: TimeInterval) -> CGFloat {
        let period: Double = 3.4
        let phase = (time.truncatingRemainder(dividingBy: period)) / period
        // Triangle wave 0→1→0 then ease for organic accel/decel.
        let tri = phase < 0.5 ? phase * 2.0 : (1.0 - phase) * 2.0
        let eased = tri * tri * (3.0 - 2.0 * tri) // smoothstep
        return CGFloat(eased)
    }
}

// MARK: - Interactive

private struct InteractiveBellows: View {
    let size: CGSize

    @State private var unfold: CGFloat = 0
    @State private var dragBase: CGFloat = 0
    @State private var snapTarget: Int = 0

    var body: some View {
        BellowsStack(unfold: unfold, size: size)
            .contentShape(Rectangle())
            .gesture(dragGesture)
            .sensoryFeedback(.impact(weight: .light), trigger: snapTarget)
    }

    private var travel: CGFloat { max(size.height * 0.9, 80) }

    private var dragGesture: some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                let delta = value.translation.height / travel
                unfold = clamp(dragBase + delta)
            }
            .onEnded { _ in
                let open = unfold > 0.5
                dragBase = open ? 1 : 0
                snapTarget = open ? 1 : 0
                withAnimation(.spring(response: 0.55, dampingFraction: 0.62)) {
                    unfold = open ? 1 : 0
                }
            }
    }

    private func clamp(_ v: CGFloat) -> CGFloat { min(max(v, 0), 1) }
}

// MARK: - Bellows Stack (shared render path)

private struct BellowsStack: View {
    /// Global unfold progress 0 (folded) → 1 (open).
    let unfold: CGFloat
    let size: CGSize

    private let pleatCount = 6

    var body: some View {
        let layout = BellowsLayout(size: size, pleatCount: pleatCount)

        VStack(spacing: 0) {
            Header(progress: unfold, layout: layout)

            VStack(spacing: layout.pleatGap) {
                ForEach(0..<pleatCount, id: \.self) { index in
                    PleatStrip(
                        index: index,
                        localProgress: localProgress(for: index),
                        layout: layout
                    )
                }
            }
            .padding(.top, layout.pleatGap)

            Spacer(minLength: 0)
        }
        .padding(layout.outerPadding)
    }

    /// Per-pleat staggered progress: pleat `i` opens after the ones above it,
    /// so a glint travels down the stack ("fold count tied to drag distance").
    private func localProgress(for index: Int) -> CGFloat {
        let n = CGFloat(pleatCount)
        // Overlap the windows a little for a continuous wave.
        let raw = unfold * (n + 0.6) - CGFloat(index)
        return min(max(raw / 1.2, 0), 1)
    }
}

// MARK: - Pleat Strip

private struct PleatStrip: View {
    let index: Int
    /// 0 = fully folded shut, 1 = fully open & flat.
    let localProgress: CGFloat
    let layout: BellowsLayout

    var body: some View {
        // Signed fold angle: alternating sign gives the zig-zag bellows; the
        // sign is what makes neighbouring pleats catch light bright/dark.
        let signedAngle = angle * (index.isMultiple(of: 2) ? 1.0 : -1.0)

        Capsule(style: .continuous)
            .fill(gradient(for: signedAngle))
            .overlay(seam)
            .overlay(spineHighlight(for: signedAngle))
            // Crucial: interpolate the *layout* height by foreshortening so
            // folded pleats compress flush instead of leaving gaps.
            .frame(height: foreshortenedHeight)
            .rotation3DEffect(
                .degrees(signedAngle),
                axis: (x: 1, y: 0, z: 0),
                anchor: .top,
                perspective: 0.65
            )
            .shadow(
                color: .black.opacity(0.28 * Double(1 - localProgress)),
                radius: 3, x: 0, y: 2
            )
    }

    // Folded → steep hinge angle; open → flat (0°).
    private var angle: Double {
        let maxAngle: Double = 78
        return maxAngle * Double(1 - localProgress)
    }

    private var foreshortenedHeight: CGFloat {
        let full = layout.pleatHeight
        let foreshorten = CGFloat(cos(angle * .pi / 180))
        // Floor so a folded pleat still shows a legible edge — never 0.
        return max(full * foreshorten, layout.pleatFloor)
    }

    private func gradient(for signedAngle: Double) -> LinearGradient {
        // Brightness keyed to signed angle: a pleat tilting toward the light
        // (positive) brightens; one tilting away darkens. This is the glint.
        let glint = signedAngle / 78.0 // -1 ... 1
        let base: Double = 0.46
        let top = clampD(base + 0.40 * glint)
        let bottom = clampD(base - 0.22 * glint)
        return LinearGradient(
            colors: [
                paper(top + 0.10),
                paper(top),
                paper(bottom)
            ],
            startPoint: .top,
            endPoint: .bottom
        )
    }

    private var seam: some View {
        // Crisp top fold line where the pleat hinges.
        VStack(spacing: 0) {
            Rectangle()
                .fill(Color.white.opacity(0.22 * Double(1 - localProgress) + 0.05))
                .frame(height: 1)
            Spacer(minLength: 0)
        }
        .clipShape(Capsule(style: .continuous))
    }

    private func spineHighlight(for signedAngle: Double) -> some View {
        // A soft sheen sweeping across the pleat, strongest as it catches light.
        let intensity = max(0, signedAngle / 78.0)
        return Capsule(style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        .white.opacity(0.0),
                        .white.opacity(0.30 * Double(intensity)),
                        .white.opacity(0.0)
                    ],
                    startPoint: .leading,
                    endPoint: .trailing
                )
            )
            .blendMode(.screen)
    }

    private func paper(_ luma: Double) -> Color {
        // Warm-cool paper tone shifting with luminance for a tactile stock.
        let l = clampD(luma)
        return Color(
            red: 0.30 + 0.62 * l,
            green: 0.33 + 0.58 * l,
            blue: 0.42 + 0.52 * l
        )
    }

    private func clampD(_ v: Double) -> Double { min(max(v, 0), 1) }
}

// MARK: - Header

private struct Header: View {
    let progress: CGFloat
    let layout: BellowsLayout

    var body: some View {
        HStack(spacing: layout.headerFont * 0.5) {
            Image(systemName: "rectangle.expand.vertical")
                .font(.system(size: layout.headerFont * 0.9, weight: .semibold))
                .rotationEffect(.degrees(Double(progress) * 180))
                .foregroundStyle(.white.opacity(0.92))

            Text("Bellows")
                .font(.system(size: layout.headerFont, weight: .semibold, design: .rounded))
                .foregroundStyle(.white.opacity(0.95))
                .lineLimit(1)
                .minimumScaleFactor(0.5)

            Spacer(minLength: 0)

            Image(systemName: "chevron.down")
                .font(.system(size: layout.headerFont * 0.78, weight: .bold))
                .rotationEffect(.degrees(Double(progress) * -180))
                .foregroundStyle(.white.opacity(0.7))
        }
        .padding(.horizontal, layout.headerFont * 0.8)
        .frame(height: layout.headerHeight)
        .background(
            Capsule(style: .continuous)
                .fill(
                    LinearGradient(
                        colors: [
                            Color(hexCode: 0x3A4A86),
                            Color(hexCode: 0x222B52)
                        ],
                        startPoint: .top,
                        endPoint: .bottom
                    )
                )
                .overlay(
                    Capsule(style: .continuous)
                        .stroke(.white.opacity(0.12), lineWidth: 1)
                )
        )
        .shadow(color: .black.opacity(0.35), radius: 4, x: 0, y: 2)
    }
}

// MARK: - Layout

private struct BellowsLayout {
    let size: CGSize
    let pleatCount: Int

    var minSide: CGFloat { min(size.width, size.height) }
    var outerPadding: CGFloat { max(minSide * 0.06, 4) }

    private var content: CGSize {
        CGSize(width: size.width - outerPadding * 2,
               height: size.height - outerPadding * 2)
    }

    var headerHeight: CGFloat { max(content.height * 0.16, 22) }
    var headerFont: CGFloat { max(headerHeight * 0.42, 9) }

    var pleatGap: CGFloat { max(content.height * 0.012, 1.5) }

    /// Full (open) height of one pleat — fills the remaining area when open.
    var pleatHeight: CGFloat {
        let n = CGFloat(pleatCount)
        let avail = content.height - headerHeight - pleatGap * (n + 1)
        return max(avail / n, 6)
    }

    /// Minimum visible height of a folded pleat so the stack never collapses
    /// to nothing — keeps a legible compact edge.
    var pleatFloor: CGFloat { max(pleatHeight * 0.22, 3) }
}

// MARK: - Color hex helper

private extension Color {
    init(hexCode hex: UInt32, alpha: Double = 1) {
        let r = Double((hex >> 16) & 0xFF) / 255.0
        let g = Double((hex >> 8) & 0xFF) / 255.0
        let b = Double(hex & 0xFF) / 255.0
        self.init(.sRGB, red: r, green: g, blue: b, opacity: alpha)
    }
}

// MARK: - Preview
"""###,
        "ges-crumple-dismiss": ###"""
import SwiftUI

// MARK: - Crumple-to-Dismiss
// Pinch a note: it crumples inward into a wrinkled paper ball with procedural
// crease shading, then on release tosses off-screen with a tumbling spin.
// Canvas crease facets only — no Metal. Facets are seeded once so they never
// shimmer between frames.

public struct CrumpleDismissView: View {
    public var demo: Bool = false

    public init(demo: Bool = false) {
        self.demo = demo
    }

    public var body: some View {
        GeometryReader { proxy in
            let side = min(proxy.size.width, proxy.size.height)
            if demo {
                DemoCrumple(side: side, canvas: proxy.size)
            } else {
                InteractiveCrumple(side: side, canvas: proxy.size)
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }
}

// MARK: - Shared geometry / state

private struct CrumpleState {
    /// 0 = flat note, 1 = fully balled-up paper.
    var crumple: CGFloat = 0
    /// Tumbling rotation in degrees (used during toss).
    var tumble: Double = 0
    /// Off-screen translation as a fraction of the tile (toss).
    var toss: CGSize = .zero
    /// Overall opacity (fades as it leaves).
    var opacity: Double = 1
}

// MARK: - Demo (self-driving)

private struct DemoCrumple: View {
    let side: CGFloat
    let canvas: CGSize

    private let facets = CreaseField.seeded(count: 22, seed: 0xC0FFEE)

    var body: some View {
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            let phase = Self.phase(at: t)
            let outgoing = Self.outgoingState(phase: phase)
            let incoming = Self.incomingState(phase: phase)

            // Two layers: the note being tossed off, and a fresh note that
            // arrives at center *before* the old one fully leaves — so the
            // tile is never blank, while the toss still flies off-screen.
            ZStack {
                if incoming.opacity > 0.001 {
                    NotePaper(side: side, canvas: canvas,
                              state: incoming, facets: facets)
                }
                if outgoing.opacity > 0.001 {
                    NotePaper(side: side, canvas: canvas,
                              state: outgoing, facets: facets)
                }
                CaptionHint(side: side,
                            label: labelFor(outgoing.crumple, incoming: incoming),
                            opacity: 1)
            }
        }
    }

    private func labelFor(_ outC: CGFloat, incoming: CrumpleState) -> String {
        // Once the incoming fresh note has arrived, prompt to pinch again.
        if incoming.opacity > 0.4 { return "pinch to crumple" }
        if outC < 0.18 { return "pinch to crumple" }
        return outC < 0.92 ? "scrunching…" : ""
    }

    private static func phase(at t: TimeInterval) -> Double {
        let period: Double = 3.4
        return (t.truncatingRemainder(dividingBy: period)) / period // 0..1
    }

    /// The note currently on screen: holds flat → crumples → tosses off.
    private static func outgoingState(phase: Double) -> CrumpleState {
        var s = CrumpleState()
        switch phase {
        case ..<0.12: // settled flat — gentle breathing so it never looks dead
            let p = phase / 0.12
            s.crumple = 0.04 * sin(p * .pi)
        case ..<0.50: // crumple inward
            let p = (phase - 0.12) / 0.38
            s.crumple = easeInOut(p)
        case ..<0.60: // squeeze hold (fully balled)
            s.crumple = 1
            let p = (phase - 0.50) / 0.10
            s.tumble = 8 * sin(p * .pi * 2) // tiny jitter under pressure
        case ..<0.84: // toss off-screen, tumbling
            let p = (phase - 0.60) / 0.24
            let e = easeIn(p)
            s.crumple = 1
            s.tumble = 8 + 560 * e
            s.toss = CGSize(width: 1.5 * e, height: -0.5 * e + 1.2 * e * e)
            s.opacity = Double(1 - max(0, (p - 0.5) / 0.5))
        default: // fully gone for the remainder of the loop
            s.opacity = 0
        }
        return s
    }

    /// A fresh flat note that fades/scales in at center during the toss,
    /// then becomes the resting note until the next cycle's `outgoing` takes
    /// over. Present and legible across the entire handoff window.
    private static func incomingState(phase: Double) -> CrumpleState {
        var s = CrumpleState()
        // Begins arriving while the old ball is still mid-flight (~0.70),
        // fully present by ~0.82, then sits flat through the wrap-around.
        let start = 0.70
        guard phase >= start else { s.opacity = 0; return s }
        let p = min(1, (phase - start) / 0.12)
        s.crumple = 1 - easeOut(p) // unfurls from a ball to flat
        s.opacity = Double(easeOut(p))
        s.tumble = 18 * (1 - p)    // tiny settle wobble
        return s
    }

    private static func easeInOut(_ x: Double) -> CGFloat {
        CGFloat(x < 0.5 ? 2 * x * x : 1 - pow(-2 * x + 2, 2) / 2)
    }
    private static func easeIn(_ x: Double) -> Double { x * x }
    private static func easeOut(_ x: Double) -> Double { 1 - (1 - x) * (1 - x) }
}

// MARK: - Interactive (real gesture)

private struct InteractiveCrumple: View {
    let side: CGFloat
    let canvas: CGSize

    private let facets = CreaseField.seeded(count: 22, seed: 0xC0FFEE)

    @State private var state = CrumpleState()
    @State private var liveCrumple: CGFloat = 0   // tracked during pinch
    @State private var dismissed = false
    @State private var feedback = false

    private let threshold: CGFloat = 0.55

    var body: some View {
        ZStack {
            NotePaper(side: side,
                      canvas: canvas,
                      state: state,
                      facets: facets)
            CaptionHint(side: side, label: label, opacity: 1)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .contentShape(Rectangle())
        .gesture(pinch)
        .sensoryFeedbackCompat(trigger: feedback)
        .onTapGesture { if dismissed { reset() } }
    }

    private var label: String {
        if dismissed { return "tap to restore" }
        if state.crumple < 0.05 { return "pinch to crumple" }
        return state.crumple < threshold ? "release to keep" : "release to toss"
    }

    private var pinch: some Gesture {
        MagnifyGesture(minimumScaleDelta: 0)
            .onChanged { value in
                guard !dismissed else { return }
                // Pinching in => magnification < 1 => crumple grows.
                let raw = 1 - value.magnification
                let c = min(1, max(0, raw * 1.6))
                liveCrumple = c
                state.crumple = c
                state.tumble = Double(c) * 14 * sin(Double(c) * .pi * 3)
            }
            .onEnded { _ in
                guard !dismissed else { return }
                if liveCrumple >= threshold {
                    toss()
                } else {
                    unfold()
                }
                liveCrumple = 0
            }
    }

    private func toss() {
        feedback.toggle()
        dismissed = true
        withAnimation(.spring(response: 0.65, dampingFraction: 0.72)) {
            state.crumple = 1
            state.tumble = 540
            state.toss = CGSize(width: 1.5, height: 1.2)
            state.opacity = 0
        }
    }

    private func unfold() {
        withAnimation(.spring(response: 0.5, dampingFraction: 0.7)) {
            state.crumple = 0
            state.tumble = 0
            state.toss = .zero
            state.opacity = 1
        }
    }

    private func reset() {
        state.toss = .zero
        state.tumble = 0
        state.crumple = 1
        withAnimation(.spring(response: 0.55, dampingFraction: 0.78)) {
            state.crumple = 0
            state.opacity = 1
        }
        dismissed = false
    }
}

// MARK: - The note + crease canvas

private struct NotePaper: View {
    let side: CGFloat
    let canvas: CGSize
    let state: CrumpleState
    let facets: CreaseField

    var body: some View {
        let c = state.crumple
        // Shrink as it balls up; never below a legible size.
        let scale = 1 - 0.42 * c
        // Flat note is a rounded rectangle; balls toward a circle.
        let corner = (0.10 + 0.40 * c) * paperSide

        ZStack {
            paperBody(corner: corner, c: c)
                .frame(width: paperSide, height: paperSide)
                .overlay {
                    CreaseCanvas(field: facets, crumple: c)
                        .clipShape(RoundedRectangle(cornerRadius: corner,
                                                    style: .continuous))
                }
                .overlay {
                    // Ball highlight — a soft rim of light once crumpled.
                    RoundedRectangle(cornerRadius: corner, style: .continuous)
                        .strokeBorder(
                            LinearGradient(colors: [.white.opacity(0.55 * c),
                                                    .clear,
                                                    .black.opacity(0.30 * c)],
                                           startPoint: .topLeading,
                                           endPoint: .bottomTrailing),
                            lineWidth: max(0.5, side * 0.012))
                }
                .compositingGroup()
                .shadow(color: .black.opacity(0.18 + 0.22 * c),
                        radius: side * (0.04 + 0.05 * c),
                        x: 0, y: side * (0.02 + 0.03 * c))
        }
        .frame(width: paperSide, height: paperSide)
        .scaleEffect(scale)
        .rotation3DEffect(.degrees(state.tumble),
                          axis: (x: 0.35, y: 0.85, z: 0.45),
                          perspective: 0.55)
        .offset(x: state.toss.width * canvas.width,
                y: state.toss.height * canvas.height)
        .opacity(state.opacity)
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    private var paperSide: CGFloat { side * 0.72 }

    @ViewBuilder
    private func paperBody(corner: CGFloat, c: CGFloat) -> some View {
        RoundedRectangle(cornerRadius: corner, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [Color(hexCode: 0xFFFDF5),
                             Color.mix(0xF4EFDD, 0xE7DFC6, c)],
                    startPoint: .top, endPoint: .bottom)
            )
            .overlay {
                // Faint ruled lines that survive lightly into the ball.
                RuledLines(side: paperSide)
                    .stroke(Color(hexCode: 0x9FB4D8).opacity(0.45 * (1 - c)),
                            lineWidth: max(0.5, side * 0.006))
                    .clipShape(RoundedRectangle(cornerRadius: corner,
                                                style: .continuous))
            }
    }
}

// MARK: - Tile-anchored caption hint (sits on the tile, not the tossed note)

private struct CaptionHint: View {
    let side: CGFloat
    let label: String
    var opacity: Double = 1

    var body: some View {
        if !label.isEmpty {
            Text(label)
                .font(.system(size: max(8, side * 0.075), weight: .semibold,
                              design: .rounded))
                .foregroundStyle(.white.opacity(0.85))
                .padding(.horizontal, side * 0.06)
                .padding(.vertical, side * 0.025)
                .background(.black.opacity(0.28), in: Capsule())
                .padding(.bottom, side * 0.04)
                .opacity(opacity)
                .frame(maxWidth: .infinity, maxHeight: .infinity,
                       alignment: .bottom)
                .allowsHitTesting(false)
        }
    }
}

// MARK: - Ruled note lines

private struct RuledLines: Shape {
    let side: CGFloat
    func path(in rect: CGRect) -> Path {
        var p = Path()
        let rows = 5
        let inset = rect.width * 0.14
        for i in 1...rows {
            let y = rect.minY + rect.height * CGFloat(i) / CGFloat(rows + 1)
            p.move(to: CGPoint(x: rect.minX + inset, y: y))
            p.addLine(to: CGPoint(x: rect.maxX - inset, y: y))
        }
        return p
    }
}

// MARK: - Procedural crease facets (Canvas, seeded once)

private struct CreaseCanvas: View {
    let field: CreaseField
    let crumple: CGFloat

    var body: some View {
        Canvas { ctx, size in
            guard crumple > 0.001 else { return }
            // Facet opacity ramps in with crumple; each facet has a depth that
            // controls whether it reads as a lit ridge or a shadowed valley.
            let amount = Double(min(1, crumple))
            for facet in field.facets {
                let path = facet.path(in: size)
                let lit = facet.depth > 0
                let mag = abs(facet.depth)
                let base = mag * 0.9 * amount
                let color: Color = lit
                    ? Color.white.opacity(base * 0.7)
                    : Color.black.opacity(base * 0.55)
                ctx.fill(path, with: .color(color))
            }
            // A few sharp crease lines layered on top for definition.
            for line in field.creaseLines {
                var p = Path()
                p.move(to: line.a.scaled(to: size))
                p.addLine(to: line.b.scaled(to: size))
                ctx.stroke(p,
                           with: .color(.black.opacity(0.28 * amount)),
                           lineWidth: max(0.5, size.width * 0.01))
            }
        }
        .blendMode(.softLight)
        .opacity(0.55 + 0.45 * Double(crumple))
    }
}

// MARK: - Seeded crease geometry (generated once, never shimmers)

private struct CreaseField {
    struct Facet {
        var points: [UnitPoint]   // 3–4 polygon points in unit space
        var depth: Double         // signed: + lit ridge, - dark valley

        func path(in size: CGSize) -> Path {
            var p = Path()
            guard let first = points.first else { return p }
            p.move(to: first.scaled(to: size))
            for pt in points.dropFirst() {
                p.addLine(to: pt.scaled(to: size))
            }
            p.closeSubpath()
            return p
        }
    }
    struct Line { var a: UnitPoint; var b: UnitPoint }

    var facets: [Facet]
    var creaseLines: [Line]

    static func seeded(count: Int, seed: UInt64) -> CreaseField {
        var rng = SplitMix64(seed: seed)
        var facets: [Facet] = []
        facets.reserveCapacity(count)

        for _ in 0..<count {
            // Anchor each facet near a random center, give it 3–4 spokes.
            let cx = rng.unit()
            let cy = rng.unit()
            let r = 0.06 + 0.16 * rng.unit()
            let corners = rng.unit() > 0.5 ? 4 : 3
            var pts: [UnitPoint] = []
            let startAngle = rng.unit() * .pi * 2
            for k in 0..<corners {
                let frac = Double(k) / Double(corners)
                let ang = startAngle + frac * .pi * 2 + (rng.unit() - 0.5) * 0.7
                let rad = r * (0.6 + 0.6 * rng.unit())
                let x = cx + CGFloat(cos(ang)) * rad
                let y = cy + CGFloat(sin(ang)) * rad
                pts.append(UnitPoint(x: min(1, max(0, x)),
                                     y: min(1, max(0, y))))
            }
            let depth = (rng.unit() - 0.5) * 2 // -1..1
            facets.append(Facet(points: pts, depth: depth))
        }

        var lines: [Line] = []
        let lineCount = 7
        for _ in 0..<lineCount {
            let a = UnitPoint(x: rng.unit(), y: rng.unit())
            let bx = a.x + (rng.unit() - 0.5) * 0.5
            let by = a.y + (rng.unit() - 0.5) * 0.5
            let b = UnitPoint(x: min(1, max(0, bx)), y: min(1, max(0, by)))
            lines.append(Line(a: a, b: b))
        }

        return CreaseField(facets: facets, creaseLines: lines)
    }
}

// MARK: - Deterministic RNG (so creases are fixed per view)

private struct SplitMix64 {
    private var state: UInt64
    init(seed: UInt64) { state = seed }
    mutating func next() -> UInt64 {
        state &+= 0x9E3779B97F4A7C15
        var z = state
        z = (z ^ (z >> 30)) &* 0xBF58476D1CE4E5B9
        z = (z ^ (z >> 27)) &* 0x94D049BB133111EB
        return z ^ (z >> 31)
    }
    /// Uniform 0..1.
    mutating func unit() -> CGFloat {
        CGFloat(next() >> 11) / CGFloat(UInt64(1) << 53)
    }
}

// MARK: - Helpers

private extension UnitPoint {
    func scaled(to size: CGSize) -> CGPoint {
        CGPoint(x: x * size.width, y: y * size.height)
    }
}

private extension Color {
    init(hexCode hex: UInt32) {
        let r = Double((hex >> 16) & 0xFF) / 255
        let g = Double((hex >> 8) & 0xFF) / 255
        let b = Double(hex & 0xFF) / 255
        self.init(red: r, green: g, blue: b)
    }
    /// Linear RGB blend toward another hex color (0 = self, 1 = other).
    static func mix(_ a: UInt32, _ b: UInt32, _ t: CGFloat) -> Color {
        let k = Double(min(1, max(0, t)))
        func chan(_ h: UInt32, _ shift: UInt32) -> Double {
            Double((h >> shift) & 0xFF) / 255
        }
        let r = chan(a, 16) * (1 - k) + chan(b, 16) * k
        let g = chan(a, 8) * (1 - k) + chan(b, 8) * k
        let bl = chan(a, 0) * (1 - k) + chan(b, 0) * k
        return Color(red: r, green: g, blue: bl)
    }
}

private extension View {
    @ViewBuilder
    func sensoryFeedbackCompat(trigger: Bool) -> some View {
        if #available(iOS 17.0, *) {
            self.sensoryFeedback(.impact(weight: .medium), trigger: trigger)
        } else {
            self
        }
    }
}
"""###,
        "ges-drag-elastic-grid-warp": ###"""
import SwiftUI

// MARK: - Elastic Grid Warp
//
// Drag a point on a uniform dot grid and nearby nodes pull toward it with a
// Gaussian distance falloff, the lattice warping like a stretched fishnet and
// rippling back to flat on release.
//
// Architecture note: a `Canvas` reading a plain `@State` scalar does NOT
// re-evaluate its closure per animation frame, so a release "spring" applied
// via `withAnimation` on a scalar would look dead. Instead a single always-on
// `TimelineView(.animation)` drives BOTH modes, and the release ripple is a
// hand-rolled time-decayed damped oscillation evaluated per frame inside the
// Canvas — the negative lobes make nodes overshoot past flat and settle, which
// is the "rippling bouncy spring" the spec calls for.

public struct DragElasticGridWarpView: View {
    public var demo: Bool = false

    public init(demo: Bool = false) {
        self.demo = demo
    }

    // Drag state (interactive mode only)
    @State private var dragCenter: CGPoint? = nil
    @State private var dragStrength: CGFloat = 0
    @State private var releaseDate: Date? = nil
    @State private var releaseCenter: CGPoint = .zero
    @State private var releaseStrength: CGFloat = 0

    public var body: some View {
        GeometryReader { geo in
            let size = geo.size
            TimelineView(.animation) { timeline in
                let t = timeline.date.timeIntervalSinceReferenceDate
                let warp = resolveWarp(size: size, time: t)
                Canvas { context, canvasSize in
                    drawLattice(
                        context: &context,
                        size: canvasSize,
                        center: warp.center,
                        strength: warp.strength
                    )
                }
                .contentShape(Rectangle())
                .gesture(dragGesture(size: size))
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // MARK: - Warp resolution

    private struct Warp {
        var center: CGPoint
        var strength: CGFloat
    }

    /// Resolves the active warp center + strength for the current frame,
    /// branching on demo vs interactive and folding in the release ripple.
    private func resolveWarp(size: CGSize, time: TimeInterval) -> Warp {
        if demo {
            return demoWarp(size: size, time: time)
        }
        return interactiveWarp(size: size, time: time)
    }

    /// Self-driving Lissajous warp center with a gently pulsing strength.
    private func demoWarp(size: CGSize, time: TimeInterval) -> Warp {
        let period: Double = 3.4
        let phase = (time.truncatingRemainder(dividingBy: period)) / period
        let angle = phase * 2 * Double.pi

        // Travel a soft Lissajous path inside the central region of the tile.
        let cx = 0.5 + 0.30 * cos(angle)
        let cy = 0.5 + 0.22 * sin(angle * 2)
        let center = CGPoint(x: CGFloat(cx) * size.width,
                             y: CGFloat(cy) * size.height)

        // Strength always stays clearly visible (never zero / blank).
        let pulse = 0.5 + 0.5 * sin(angle * 1.5)
        let strength = CGFloat(0.55 + 0.45 * pulse)
        return Warp(center: center, strength: strength)
    }

    /// Interactive warp: active drag wins; otherwise decay the release ripple.
    private func interactiveWarp(size: CGSize, time: TimeInterval) -> Warp {
        if let c = dragCenter {
            return Warp(center: c, strength: dragStrength)
        }
        guard let release = releaseDate, releaseStrength > 0.0001 else {
            return Warp(center: CGPoint(x: size.width / 2, y: size.height / 2),
                        strength: 0)
        }
        let elapsed = time - release.timeIntervalSinceReferenceDate
        let strength = rippleStrength(elapsed: elapsed, base: releaseStrength)
        return Warp(center: releaseCenter, strength: strength)
    }

    /// Time-decayed damped oscillation: overshoots past flat then settles.
    private func rippleStrength(elapsed: TimeInterval, base: CGFloat) -> CGFloat {
        guard elapsed >= 0 else { return base }
        let decay: Double = 6.5          // envelope falloff rate
        let omega: Double = 13.0         // bounce frequency (~2 lobes)
        let envelope = exp(-decay * elapsed)
        let osc = cos(omega * elapsed)
        return base * CGFloat(envelope * osc)
    }

    // MARK: - Drag gesture

    private func dragGesture(size: CGSize) -> some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                dragCenter = clampPoint(value.location, in: size)
                // Pull magnitude grows with how far the finger has travelled,
                // so a small touch warps gently and a big drag pinches hard.
                let dx = value.translation.width
                let dy = value.translation.height
                let travel = sqrt(dx * dx + dy * dy)
                let norm = travel / max(min(size.width, size.height), 1)
                dragStrength = min(1.0, 0.30 + norm * 1.6)
            }
            .onEnded { value in
                releaseCenter = clampPoint(value.location, in: size)
                releaseStrength = max(dragStrength, 0.2)
                releaseDate = Date()
                dragCenter = nil
                dragStrength = 0
            }
    }

    private func clampPoint(_ p: CGPoint, in size: CGSize) -> CGPoint {
        CGPoint(x: min(max(p.x, 0), size.width),
                y: min(max(p.y, 0), size.height))
    }

    // MARK: - Lattice rendering

    /// Draws the fishnet: row polylines + column polylines through displaced
    /// nodes, with a glossy dot at each node. Called from both modes.
    private func drawLattice(context: inout GraphicsContext,
                             size: CGSize,
                             center: CGPoint,
                             strength: CGFloat) {
        let cols = 13
        let rows = 13
        guard size.width > 1, size.height > 1 else { return }

        let inset: CGFloat = max(min(size.width, size.height) * 0.06, 4)
        let usable = CGSize(width: size.width - inset * 2,
                            height: size.height - inset * 2)
        let stepX = usable.width / CGFloat(cols - 1)
        let stepY = usable.height / CGFloat(rows - 1)

        // Sigma controls the falloff radius; max pull keyed to lattice scale.
        let sigma = min(usable.width, usable.height) * 0.34
        let maxPull = min(usable.width, usable.height) * 0.40 * strength

        var nodes = [[CGPoint]](repeating: [CGPoint](repeating: .zero, count: cols),
                                count: rows)
        for r in 0..<rows {
            for c in 0..<cols {
                let rest = CGPoint(x: inset + CGFloat(c) * stepX,
                                   y: inset + CGFloat(r) * stepY)
                nodes[r][c] = displace(rest: rest,
                                       center: center,
                                       sigma: sigma,
                                       maxPull: maxPull)
            }
        }

        drawConnections(context: &context, nodes: nodes, rows: rows, cols: cols,
                        center: center, sigma: sigma)
        drawNodes(context: &context, nodes: nodes, rows: rows, cols: cols,
                  size: size, center: center, sigma: sigma)
    }

    /// Gaussian falloff displacement toward the warp center (pinched well).
    private func displace(rest: CGPoint,
                          center: CGPoint,
                          sigma: CGFloat,
                          maxPull: CGFloat) -> CGPoint {
        guard maxPull != 0, sigma > 0 else { return rest }
        let dx = center.x - rest.x
        let dy = center.y - rest.y
        let dist = sqrt(dx * dx + dy * dy)
        guard dist > 0.0001 else { return rest }
        let ratio = dist / sigma
        let falloff = exp(-(ratio * ratio))
        // Pull cannot exceed the distance to the center (no overshoot collapse).
        let pull = min(maxPull * falloff, dist * 0.92)
        let ux = dx / dist
        let uy = dy / dist
        return CGPoint(x: rest.x + ux * pull, y: rest.y + uy * pull)
    }

    /// Strength of warp influence at a node, for color/width modulation.
    private func influence(at point: CGPoint, center: CGPoint, sigma: CGFloat) -> CGFloat {
        guard sigma > 0 else { return 0 }
        let dx = center.x - point.x
        let dy = center.y - point.y
        let dist = sqrt(dx * dx + dy * dy)
        let ratio = dist / sigma
        return exp(-(ratio * ratio))
    }

    private func drawConnections(context: inout GraphicsContext,
                                 nodes: [[CGPoint]],
                                 rows: Int,
                                 cols: Int,
                                 center: CGPoint,
                                 sigma: CGFloat) {
        // Horizontal strands
        for r in 0..<rows {
            var path = Path()
            path.move(to: nodes[r][0])
            for c in 1..<cols {
                path.addLine(to: nodes[r][c])
            }
            strokeStrand(context: &context, path: path)
        }
        // Vertical strands
        for c in 0..<cols {
            var path = Path()
            path.move(to: nodes[0][c])
            for r in 1..<rows {
                path.addLine(to: nodes[r][c])
            }
            strokeStrand(context: &context, path: path)
        }
    }

    private func strokeStrand(context: inout GraphicsContext, path: Path) {
        let gradient = GraphicsContext.Shading.linearGradient(
            Gradient(colors: [
                Color(hexCode: 0x3A4D8F).opacity(0.55),
                Color(hexCode: 0x6FA8FF).opacity(0.85)
            ]),
            startPoint: .zero,
            endPoint: CGPoint(x: 200, y: 200)
        )
        context.stroke(path, with: gradient,
                       style: StrokeStyle(lineWidth: 1.0, lineCap: .round, lineJoin: .round))
    }

    private func drawNodes(context: inout GraphicsContext,
                           nodes: [[CGPoint]],
                           rows: Int,
                           cols: Int,
                           size: CGSize,
                           center: CGPoint,
                           sigma: CGFloat) {
        let baseRadius = max(min(size.width, size.height) * 0.012, 1.2)
        for r in 0..<rows {
            for c in 0..<nodes[r].count {
                let p = nodes[r][c]
                let inf = influence(at: p, center: center, sigma: sigma)
                // Warped nodes brighten and swell — reads as the pinch well core.
                let radius = baseRadius * (1 + inf * 1.4)
                let dot = Path(ellipseIn: CGRect(x: p.x - radius, y: p.y - radius,
                                                 width: radius * 2, height: radius * 2))
                let color = Color(hexCode: 0x9CC4FF).opacity(0.45 + 0.55 * Double(inf))
                context.fill(dot, with: .color(color))

                // A bright glint on the most-warped nodes for the gravity-lens feel.
                if inf > 0.45 {
                    let glintR = radius * 0.5
                    let glint = Path(ellipseIn: CGRect(
                        x: p.x - glintR - radius * 0.25,
                        y: p.y - glintR - radius * 0.25,
                        width: glintR * 2, height: glintR * 2))
                    context.fill(glint, with: .color(.white.opacity(Double(inf) * 0.7)))
                }
            }
        }
    }
}

// MARK: - Color hex helper

private extension Color {
    init(hexCode hex: UInt32) {
        let r = Double((hex >> 16) & 0xFF) / 255.0
        let g = Double((hex >> 8) & 0xFF) / 255.0
        let b = Double(hex & 0xFF) / 255.0
        self.init(.sRGB, red: r, green: g, blue: b, opacity: 1)
    }
}

// MARK: - Preview
"""###,
        "ges-drag-liquid-fill-tilt": ###"""
import SwiftUI

/// Tilt-Pour Liquid Gauge.
///
/// Drag horizontally to tilt the glass. The liquid surface counter-rotates so it
/// stays level to gravity, sloshing with a wobbling meniscus and a trailing wave
/// whose amplitude tracks how fast you tilt; it settles with a damped spring when
/// you stop. In `demo` mode the tilt auto-rocks on a ~3s loop so the tile pours
/// itself with no touch.
struct DragLiquidFillTiltView: View {
    var demo: Bool = false

    // Live tilt the gesture is pushing toward (radians).
    @State private var targetTilt: CGFloat = 0
    // Smoothed angle actually rendered (integrated toward target each frame).
    @State private var displayTilt: CGFloat = 0
    // Slosh wave amplitude (normalised 0…1-ish) driven by angular velocity.
    @State private var slosh: CGFloat = 0
    // Continuously advancing phase so the meniscus always shimmers.
    @State private var wavePhase: CGFloat = 0
    // Last frame timestamp for fixed-step integration.
    @State private var lastT: Double = 0
    @State private var isDragging: Bool = false
    @State private var velocity: CGFloat = 0

    private let maxTilt: CGFloat = 0.61   // ~35°, clamps the level so corners never drain.
    private let fillRatio: CGFloat = 0.52  // resting liquid level inside the glass.

    var body: some View {
        GeometryReader { geo in
            TimelineView(.animation) { timeline in
                let now = timeline.date.timeIntervalSinceReferenceDate
                content(in: geo.size)
                    .onChange(of: now) { _, t in
                        step(time: t, size: geo.size)
                    }
            }
            .contentShape(Rectangle())
            .gesture(dragGesture(width: geo.size.width))
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // MARK: - Composition

    private func content(in size: CGSize) -> some View {
        let side = min(size.width, size.height) * 0.72
        let glassW = side * 0.74
        let glassH = side

        return ZStack {
            GlassAssembly(
                width: glassW,
                height: glassH,
                tilt: displayTilt,
                slosh: slosh,
                phase: wavePhase,
                fillRatio: fillRatio
            )
            .frame(width: glassW, height: glassH)
        }
        .frame(width: size.width, height: size.height)
    }

    // MARK: - Gesture

    private func dragGesture(width: CGFloat) -> some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                isDragging = true
                let denom = max(width * 0.5, 1)
                let frac = value.translation.width / denom
                targetTilt = clamp(frac * maxTilt, -maxTilt, maxTilt)
            }
            .onEnded { _ in
                isDragging = false
                // Spring back to level; the rebound itself produces the final slosh.
                targetTilt = 0
            }
    }

    // MARK: - Integrator

    private func step(time t: Double, size: CGSize) {
        guard size.width > 0 else { return }
        if lastT == 0 { lastT = t }
        // Clamp dt so a dropped frame can't blow up the spring.
        let dt = CGFloat(min(max(t - lastT, 0), 1.0 / 30.0))
        lastT = t

        if demo {
            // Auto-rock the tilt on a ~3.1s loop.
            let period: CGFloat = 3.1
            let angle = CGFloat(t).truncatingRemainder(dividingBy: Double(period)) / period
            targetTilt = sin(angle * 2 * .pi) * (maxTilt * 0.92)
        }

        // Critically-ish damped follow of displayTilt → targetTilt.
        let stiffness: CGFloat = isDragging ? 26 : 17
        let damping: CGFloat = 2 * sqrt(stiffness) * 0.62
        let prev = displayTilt
        velocity += (stiffness * (targetTilt - displayTilt) - damping * velocity) * dt
        displayTilt += velocity * dt

        // Angular velocity feeds the slosh; spec: amplitude ~ d(tilt)/dt.
        let angVel = dt > 0 ? (displayTilt - prev) / dt : 0
        let drive = min(abs(angVel) * 0.55, 1.0)
        slosh = max(slosh * pow(0.04, dt) /* ~exp decay */, drive)
        // Hard cap so the meniscus never overflows the glass.
        slosh = min(slosh, 1.0)

        // Phase always advances → a permanent faint shimmer keeps the tile alive.
        let baseSpeed: CGFloat = 1.6
        wavePhase += dt * (baseSpeed + slosh * 7.0)
        if wavePhase > 1000 { wavePhase -= 1000 }
    }

    private func clamp(_ v: CGFloat, _ lo: CGFloat, _ hi: CGFloat) -> CGFloat {
        min(max(v, lo), hi)
    }
}

// MARK: - Glass + liquid assembly

private struct GlassAssembly: View {
    let width: CGFloat
    let height: CGFloat
    let tilt: CGFloat
    let slosh: CGFloat
    let phase: CGFloat
    let fillRatio: CGFloat

    private var corner: CGFloat { min(width, height) * 0.16 }

    var body: some View {
        ZStack {
            glassBack
            liquidLayer
            glassRim
            specular
        }
        .rotationEffect(.radians(Double(tilt)))
    }

    // Dark translucent glass body behind the liquid.
    private var glassBack: some View {
        RoundedRectangle(cornerRadius: corner, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [Color(hexCode: 0x1b2030), Color(hexCode: 0x10131d)],
                    startPoint: .top, endPoint: .bottom
                )
            )
            .overlay(
                RoundedRectangle(cornerRadius: corner, style: .continuous)
                    .stroke(Color.white.opacity(0.06), lineWidth: 1)
            )
    }

    // The fill, clipped to the glass. Surface is counter-rotated to stay level.
    private var liquidLayer: some View {
        LiquidShape(
            tilt: tilt,
            slosh: slosh,
            phase: phase,
            fillRatio: fillRatio
        )
        .fill(
            LinearGradient(
                colors: [Color(hexCode: 0x35e0d6), Color(hexCode: 0x17a9c9), Color(hexCode: 0x1d6fb8)],
                startPoint: .top, endPoint: .bottom
            )
        )
        .overlay(meniscusHighlight)
        .clipShape(RoundedRectangle(cornerRadius: corner, style: .continuous))
    }

    // Bright line riding the surface to read as a wet meniscus edge.
    private var meniscusHighlight: some View {
        LiquidSurfaceLine(
            tilt: tilt,
            slosh: slosh,
            phase: phase,
            fillRatio: fillRatio
        )
        .stroke(
            LinearGradient(
                colors: [Color.white.opacity(0.0), Color.white.opacity(0.85), Color(hexCode: 0xbafff8).opacity(0.9), Color.white.opacity(0.0)],
                startPoint: .leading, endPoint: .trailing
            ),
            style: StrokeStyle(lineWidth: max(width * 0.012, 1.2), lineCap: .round)
        )
        .blur(radius: 0.4)
        .clipShape(RoundedRectangle(cornerRadius: corner, style: .continuous))
    }

    // Glass outline + soft inner shading.
    private var glassRim: some View {
        RoundedRectangle(cornerRadius: corner, style: .continuous)
            .stroke(
                LinearGradient(
                    colors: [Color.white.opacity(0.55), Color.white.opacity(0.12), Color.white.opacity(0.30)],
                    startPoint: .topLeading, endPoint: .bottomTrailing
                ),
                lineWidth: max(width * 0.02, 1.5)
            )
    }

    // Vertical glassy specular streak.
    private var specular: some View {
        RoundedRectangle(cornerRadius: corner * 0.5, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [Color.white.opacity(0.28), Color.white.opacity(0.02)],
                    startPoint: .top, endPoint: .bottom
                )
            )
            .frame(width: width * 0.12)
            .blur(radius: 2)
            .offset(x: -width * 0.26)
            .clipShape(RoundedRectangle(cornerRadius: corner, style: .continuous))
            .allowsHitTesting(false)
    }
}

// MARK: - Surface geometry helpers

/// Shared math for where the liquid surface sits in the glass's *local* space.
/// The surface is tilted by −tilt so that when the parent rotates by +tilt the
/// surface reads horizontal to gravity. A sine slosh rides along that line.
private enum SurfaceGeometry {
    /// y of the surface at horizontal position x (local glass coords, origin top-left).
    static func surfaceY(
        x: CGFloat,
        rect: CGRect,
        tilt: CGFloat,
        slosh: CGFloat,
        phase: CGFloat,
        fillRatio: CGFloat
    ) -> CGFloat {
        let cx = rect.midX
        let baseY = rect.maxY - rect.height * fillRatio
        // Counter-tilt: surface line slope is −tan(tilt) about the glass centre.
        let slope = -tan(Double(tilt))
        let tilted = baseY + CGFloat(slope) * (x - cx)
        // Slosh wave: a couple of cycles across the width, amplitude from velocity.
        let amp = rect.height * 0.085 * slosh
        let waves: CGFloat = 1.7
        let wave = sin((x - cx) / rect.width * waves * 2 * .pi + phase * 2 * .pi)
        // A second, faster ripple gives the meniscus a permanent faint shimmer.
        let shimmer = sin((x - cx) / rect.width * 4.3 * 2 * .pi - phase * 1.3 * 2 * .pi)
        let ripple = rect.height * 0.012
        return tilted + amp * wave + ripple * shimmer
    }
}

/// The filled liquid body. Big horizontal/vertical overdraw guarantees the
/// rounded-rect clip never reveals a triangular gap at the tilted corners.
private struct LiquidShape: Shape {
    var tilt: CGFloat
    var slosh: CGFloat
    var phase: CGFloat
    var fillRatio: CGFloat

    var animatableData: AnimatablePair<CGFloat, AnimatablePair<CGFloat, CGFloat>> {
        get { AnimatablePair(tilt, AnimatablePair(slosh, phase)) }
        set {
            tilt = newValue.first
            slosh = newValue.second.first
            phase = newValue.second.second
        }
    }

    func path(in rect: CGRect) -> Path {
        var p = Path()
        let startX = rect.minX - rect.width
        let endX = rect.maxX + rect.width
        let steps = 48
        let dx = (endX - startX) / CGFloat(steps)

        p.move(to: CGPoint(x: startX, y: surface(startX, rect)))
        var x = startX
        for _ in 0...steps {
            p.addLine(to: CGPoint(x: x, y: surface(x, rect)))
            x += dx
        }
        // Close down far below the glass so the fill always reaches the bottom.
        p.addLine(to: CGPoint(x: endX, y: rect.maxY + rect.height))
        p.addLine(to: CGPoint(x: startX, y: rect.maxY + rect.height))
        p.closeSubpath()
        return p
    }

    private func surface(_ x: CGFloat, _ rect: CGRect) -> CGFloat {
        SurfaceGeometry.surfaceY(
            x: x, rect: rect, tilt: tilt, slosh: slosh, phase: phase, fillRatio: fillRatio
        )
    }
}

/// Just the surface polyline, for the bright meniscus stroke.
private struct LiquidSurfaceLine: Shape {
    var tilt: CGFloat
    var slosh: CGFloat
    var phase: CGFloat
    var fillRatio: CGFloat

    var animatableData: AnimatablePair<CGFloat, AnimatablePair<CGFloat, CGFloat>> {
        get { AnimatablePair(tilt, AnimatablePair(slosh, phase)) }
        set {
            tilt = newValue.first
            slosh = newValue.second.first
            phase = newValue.second.second
        }
    }

    func path(in rect: CGRect) -> Path {
        var p = Path()
        let startX = rect.minX - rect.width * 0.2
        let endX = rect.maxX + rect.width * 0.2
        let steps = 48
        let dx = (endX - startX) / CGFloat(steps)
        var x = startX
        p.move(to: CGPoint(x: x, y: surface(x, rect)))
        for _ in 0...steps {
            p.addLine(to: CGPoint(x: x, y: surface(x, rect)))
            x += dx
        }
        return p
    }

    private func surface(_ x: CGFloat, _ rect: CGRect) -> CGFloat {
        SurfaceGeometry.surfaceY(
            x: x, rect: rect, tilt: tilt, slosh: slosh, phase: phase, fillRatio: fillRatio
        )
    }
}

// MARK: - Color hex helper

private extension Color {
    init(hexCode hex: UInt32, alpha: Double = 1) {
        let r = Double((hex >> 16) & 0xFF) / 255
        let g = Double((hex >> 8) & 0xFF) / 255
        let b = Double(hex & 0xFF) / 255
        self.init(.sRGB, red: r, green: g, blue: b, opacity: alpha)
    }
}
"""###,
        "ges-drag-reorder-spring": ###"""
import SwiftUI

/// Spring Reorder List
///
/// Long-press lifts a row that tilts and casts a shadow; as you drag, the other
/// rows shove aside with damped springs and trail slightly behind the gap,
/// settling with a soft jiggle.
///
/// - `demo == true`  → a self-driving TimelineView loop scripts a fake
///   pick-up → move → drop on a ~3.4s cycle so the tile looks alive untouched.
/// - `demo == false` → the real interactive component: a per-row
///   `LongPressGesture(0.3).sequenced(before: DragGesture(minimumDistance: 0))`
///   lifts a row and reorders the list with overshooting springs.
struct DragReorderSpringView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { geo in
            content(in: geo.size)
                .frame(maxWidth: .infinity, maxHeight: .infinity)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    @ViewBuilder
    private func content(in size: CGSize) -> some View {
        if demo {
            DemoReorderList(size: size)
        } else {
            InteractiveReorderList(size: size)
        }
    }
}

// MARK: - Shared model

private struct ReorderItem: Identifiable, Equatable {
    let id: Int
    let hue: Double
    let glyph: String
}

private enum ReorderPalette {
    static let items: [ReorderItem] = [
        ReorderItem(id: 0, hue: 0.58, glyph: "square.stack.3d.up.fill"),
        ReorderItem(id: 1, hue: 0.74, glyph: "wand.and.stars"),
        ReorderItem(id: 2, hue: 0.90, glyph: "paintbrush.pointed.fill"),
        ReorderItem(id: 3, hue: 0.07, glyph: "bolt.fill"),
        ReorderItem(id: 4, hue: 0.42, glyph: "leaf.fill")
    ]
}

// MARK: - Geometry helpers

private enum ReorderMetrics {
    /// Vertical breathing room around the stack so a lifted/tilted row never clips.
    static func layout(for size: CGSize, count: Int) -> (rowHeight: CGFloat, gap: CGFloat, top: CGFloat, inset: CGFloat) {
        let inset: CGFloat = max(8, min(size.width, size.height) * 0.06)
        let usableWidth = max(40, size.width - inset * 2)
        // Keep rows from getting absurdly tall in a big detail view.
        let gap: CGFloat = max(4, usableWidth * 0.03)
        let usableHeight = max(40, size.height - inset * 2)
        let totalGap = gap * CGFloat(count - 1)
        let rowHeight = max(18, (usableHeight - totalGap) / CGFloat(count))
        let stackHeight = rowHeight * CGFloat(count) + totalGap
        let top = (size.height - stackHeight) / 2 + rowHeight / 2
        return (rowHeight, gap, top, inset)
    }

    static func slotCenterY(slot: Int, rowHeight: CGFloat, gap: CGFloat, top: CGFloat) -> CGFloat {
        top + CGFloat(slot) * (rowHeight + gap)
    }
}

// MARK: - Lift state passed to the row renderer

private struct LiftState {
    var lift: CGFloat = 0          // 0…1 how "picked up" the row is
    var dragOffset: CGFloat = 0    // extra Y the finger/clock adds on top of the slot
    var isActive: Bool = false     // is this the row being moved
}

// MARK: - Row renderer (shared by both modes)

private struct ReorderRowView: View {
    let item: ReorderItem
    let width: CGFloat
    let height: CGFloat
    let lift: LiftState

    private var corner: CGFloat { min(height * 0.32, 22) }

    private var baseColor: Color {
        Color(hue: item.hue, saturation: 0.55, brightness: 0.92)
    }

    private var fillGradient: LinearGradient {
        LinearGradient(
            colors: [
                Color(hue: item.hue, saturation: 0.42, brightness: 0.99),
                Color(hue: item.hue, saturation: 0.62, brightness: 0.80)
            ],
            startPoint: .topLeading,
            endPoint: .bottomTrailing
        )
    }

    var body: some View {
        let scale = 1 + lift.lift * 0.06
        let tilt = Double(lift.lift) * 5.0
        let shadowRadius = 3 + lift.lift * 14
        let shadowY = 2 + lift.lift * 9

        rowBody
            .frame(width: width, height: height)
            .scaleEffect(scale)
            .rotation3DEffect(
                .degrees(tilt),
                axis: (x: 1, y: 0, z: 0),
                anchor: .center,
                perspective: 0.4
            )
            .shadow(
                color: baseColor.opacity(0.30 + lift.lift * 0.28),
                radius: shadowRadius,
                x: 0,
                y: shadowY
            )
            .zIndex(lift.isActive ? 10 : 0)
    }

    private var rowBody: some View {
        ZStack {
            RoundedRectangle(cornerRadius: corner, style: .continuous)
                .fill(fillGradient)
                .overlay(
                    RoundedRectangle(cornerRadius: corner, style: .continuous)
                        .stroke(Color.white.opacity(0.35 + lift.lift * 0.25), lineWidth: 1)
                )
                .overlay(glossHighlight)

            HStack(spacing: height * 0.28) {
                handleDots
                Image(systemName: item.glyph)
                    .font(.system(size: height * 0.34, weight: .semibold))
                    .foregroundStyle(.white)
                    .shadow(color: .black.opacity(0.25), radius: 1, y: 1)
                Capsule()
                    .fill(Color.white.opacity(0.85))
                    .frame(width: width * 0.30, height: max(3, height * 0.10))
                Spacer(minLength: 0)
            }
            .padding(.horizontal, height * 0.34)
        }
    }

    private var glossHighlight: some View {
        RoundedRectangle(cornerRadius: corner, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [Color.white.opacity(0.30), .clear],
                    startPoint: .top,
                    endPoint: .center
                )
            )
            .blendMode(.plusLighter)
            .allowsHitTesting(false)
    }

    private var handleDots: some View {
        VStack(spacing: max(2, height * 0.10)) {
            ForEach(0..<2, id: \.self) { _ in
                HStack(spacing: max(2, height * 0.10)) {
                    Circle().frame(width: max(2, height * 0.07))
                    Circle().frame(width: max(2, height * 0.07))
                }
            }
        }
        .foregroundStyle(Color.white.opacity(0.8))
    }
}

// MARK: - Background

private struct ReorderBackground: View {
    var body: some View {
        Color(hexCode: 0x0D0E16)
            .overlay(
                RadialGradient(
                    colors: [Color.white.opacity(0.06), .clear],
                    center: .top,
                    startRadius: 0,
                    endRadius: 260
                )
            )
    }
}

// MARK: - Interactive mode

private struct InteractiveReorderList: View {
    let size: CGSize

    @State private var order: [ReorderItem] = ReorderPalette.items
    @State private var draggingID: Int? = nil
    @State private var dragTranslation: CGFloat = 0
    @State private var liftAmount: CGFloat = 0
    @State private var dragStartSlot: Int = 0
    @State private var pickupTick: Int = 0
    @State private var dropTick: Int = 0

    private let space = "reorder.interactive"

    var body: some View {
        let m = ReorderMetrics.layout(for: size, count: order.count)
        ZStack {
            ReorderBackground()
            ForEach(order) { item in
                let slot = currentSlot(of: item)
                row(item: item, slot: slot, metrics: m)
            }
        }
        .coordinateSpace(name: space)
        .sensoryFeedback(.impact(weight: .medium), trigger: pickupTick)
        .sensoryFeedback(.impact(flexibility: .soft), trigger: dropTick)
    }

    // MARK: row + gesture

    @ViewBuilder
    private func row(item: ReorderItem, slot: Int, metrics m: (rowHeight: CGFloat, gap: CGFloat, top: CGFloat, inset: CGFloat)) -> some View {
        let isDragging = draggingID == item.id
        let baseY = ReorderMetrics.slotCenterY(slot: slot, rowHeight: m.rowHeight, gap: m.gap, top: m.top)
        let extra = isDragging ? dragTranslation : 0
        let width = size.width - m.inset * 2

        ReorderRowView(
            item: item,
            width: width,
            height: m.rowHeight,
            lift: LiftState(
                lift: isDragging ? liftAmount : 0,
                dragOffset: extra,
                isActive: isDragging
            )
        )
        .position(x: size.width / 2, y: baseY + extra)
        .animation(isDragging ? nil : .interpolatingSpring(duration: 0.42, bounce: 0.35), value: slot)
        .gesture(rowGesture(for: item, metrics: m))
    }

    private func rowGesture(for item: ReorderItem, metrics m: (rowHeight: CGFloat, gap: CGFloat, top: CGFloat, inset: CGFloat)) -> some Gesture {
        LongPressGesture(minimumDuration: 0.3)
            .sequenced(before: DragGesture(minimumDistance: 0, coordinateSpace: .named(space)))
            .onChanged { value in
                switch value {
                case .first(true):
                    beginLift(item)
                case .second(true, let drag):
                    if draggingID != item.id { beginLift(item) }
                    if let drag { handleDrag(item: item, translation: drag.translation.height, metrics: m) }
                default:
                    break
                }
            }
            .onEnded { _ in
                endDrag()
            }
    }

    // MARK: state transitions

    private func beginLift(_ item: ReorderItem) {
        guard draggingID != item.id else { return }
        draggingID = item.id
        dragTranslation = 0
        dragStartSlot = order.firstIndex(of: item) ?? 0
        pickupTick &+= 1
        withAnimation(.spring(response: 0.28, dampingFraction: 0.6)) {
            liftAmount = 1
        }
    }

    private func handleDrag(item: ReorderItem, translation: CGFloat, metrics m: (rowHeight: CGFloat, gap: CGFloat, top: CGFloat, inset: CGFloat)) {
        guard let from = order.firstIndex(of: item) else { return }
        let step = m.rowHeight + m.gap
        // Anchor the target to the slot where the press began, not the live
        // index — DragGesture translation is cumulative from gesture start, so
        // mixing it with the already-advanced index double-counts the move.
        let liveSlot = CGFloat(dragStartSlot) + translation / step
        let target = min(max(Int(liveSlot.rounded()), 0), order.count - 1)
        if target != from {
            withAnimation(.interpolatingSpring(duration: 0.45, bounce: 0.35)) {
                let moved = order.remove(at: from)
                order.insert(moved, at: target)
            }
        }
        // Keep the lifted row glued to the finger: its visible Y is
        // slot(currentSlot) + dragTranslation, and we want that to equal
        // slot(dragStartSlot) + translation.
        let currentSlot = order.firstIndex(of: item) ?? from
        dragTranslation = (CGFloat(dragStartSlot) - CGFloat(currentSlot)) * step + translation
    }

    private func endDrag() {
        dropTick &+= 1
        let settlingID = draggingID
        // Keep the row "active" through the settle so the spring on
        // dragTranslation/liftAmount actually renders (a soft jiggle) instead
        // of snapping the instant draggingID clears.
        withAnimation(.interpolatingSpring(duration: 0.5, bounce: 0.32)) {
            dragTranslation = 0
            liftAmount = 0
        } completion: {
            if draggingID == settlingID { draggingID = nil }
        }
    }

    private func currentSlot(of item: ReorderItem) -> Int {
        order.firstIndex(of: item) ?? 0
    }
}

// MARK: - Demo (self-driving) mode

private struct DemoReorderList: View {
    let size: CGSize

    private let items = ReorderPalette.items
    private let cycle: Double = 3.4

    var body: some View {
        let m = ReorderMetrics.layout(for: size, count: items.count)
        TimelineView(.animation) { timeline in
            let t = phase(timeline.date)
            let script = DemoScript(t: t, count: items.count)
            ZStack {
                ReorderBackground()
                ForEach(Array(items.enumerated()), id: \.element.id) { index, item in
                    demoRow(item: item, index: index, script: script, metrics: m)
                }
            }
        }
    }

    private func phase(_ date: Date) -> Double {
        let secs = date.timeIntervalSinceReferenceDate
        return (secs.truncatingRemainder(dividingBy: cycle)) / cycle
    }

    @ViewBuilder
    private func demoRow(item: ReorderItem, index: Int, script: DemoScript, metrics m: (rowHeight: CGFloat, gap: CGFloat, top: CGFloat, inset: CGFloat)) -> some View {
        let isActive = index == script.activeIndex
        let step = m.rowHeight + m.gap
        // Continuous slot position (Double) for every row so neighbors glide
        // into the gap with the same overshoot the active row uses, rather than
        // teleporting a whole slot when an integer threshold flips.
        let continuousSlot = script.continuousSlot(for: index)
        let baseY = m.top + CGFloat(continuousSlot) * step
        let width = size.width - m.inset * 2

        ReorderRowView(
            item: item,
            width: width,
            height: m.rowHeight,
            lift: LiftState(
                lift: isActive ? script.lift : 0,
                dragOffset: 0,
                isActive: isActive
            )
        )
        .position(x: size.width / 2, y: baseY)
    }
}

/// Pure-function description of the scripted pick-up → move → drop loop.
///
/// The active row (index 1) lifts, slides down two slots while the rows it
/// passes shove up to fill the gap (with an overshooting smoothstep that reads
/// as a damped jiggle), holds, then rises back and drops home — a fully
/// symmetric cycle so the TimelineView loops with no teleport on wrap.
private struct DemoScript {
    let t: Double
    let count: Int

    let activeIndex = 1
    private let travel: Int = 2   // how many slots the active row migrates

    // Phase boundaries within the normalized [0,1) cycle.
    private let pPick = 0.12      // finish lifting
    private let pDownEnd = 0.42   // finished moving down
    private let pHoldEnd = 0.58   // dwell at the bottom slot
    private let pUpEnd = 0.86     // returned to original slot
    // remainder: drop + settle back to rest

    var lift: CGFloat {
        if t < pPick {
            return CGFloat(smoothstep(0, pPick, t))
        } else if t < pUpEnd {
            return 1
        } else {
            return CGFloat(1 - smoothstep(pUpEnd, 1.0, t))
        }
    }

    /// Continuous migration of the active row (in slot units): 0 = its original
    /// slot, `travel` = the destination slot. Overshoots on each leg for the
    /// springy jiggle.
    private var activeProgress: Double {
        if t < pPick { return 0 }
        if t < pDownEnd { return overshoot(smoothstep(pPick, pDownEnd, t)) * Double(travel) }
        if t < pHoldEnd { return Double(travel) }
        if t < pUpEnd { return (1 - overshoot(smoothstep(pHoldEnd, pUpEnd, t))) * Double(travel) }
        return 0
    }

    /// Continuous slot position for any row. The active row follows
    /// `activeProgress` directly; every other row is smoothly pushed out of the
    /// way in proportion to how far the active row has swept past it — so the
    /// neighbors glide and jiggle into the gap instead of snapping a whole slot.
    func continuousSlot(for index: Int) -> Double {
        let p = activeProgress                       // active row's signed travel
        if index == activeIndex {
            return Double(activeIndex) + p
        }
        // How far the active row currently is, as an absolute slot position.
        let activeNow = Double(activeIndex) + p
        let origin = Double(activeIndex)
        let other = Double(index)
        // Down-sweep: rows below origin, above the active row's live position,
        // slide up by the fraction of the way the active row has passed them.
        if p >= 0 {
            guard other > origin else { return other }
            // Fraction in [0,1] of this neighbor being "passed" by the active row.
            let f = clamp(activeNow - (other - 1), low: 0, high: 1)
            return other - f
        } else {
            // (Unused in the current script, but symmetric for completeness.)
            guard other < origin else { return other }
            let f = clamp((other + 1) - activeNow, low: 0, high: 1)
            return other + f
        }
    }

    // MARK: math

    private func clamp(_ x: Double, low: Double, high: Double) -> Double {
        min(max(x, low), high)
    }

    private func smoothstep(_ a: Double, _ b: Double, _ x: Double) -> Double {
        guard b > a else { return x < a ? 0 : 1 }
        let u = min(max((x - a) / (b - a), 0), 1)
        return u * u * (3 - 2 * u)
    }

    /// A unit ease that overshoots past 1 then settles, for the springy jiggle.
    private func overshoot(_ u: Double) -> Double {
        let c: Double = 1.70158
        let x = u - 1
        return 1 + (c + 1) * x * x * x + c * x * x
    }
}

// MARK: - Color hex helper

private extension Color {
    init(hexCode hex: UInt32, alpha: Double = 1) {
        let r = Double((hex >> 16) & 0xFF) / 255
        let g = Double((hex >> 8) & 0xFF) / 255
        let b = Double(hex & 0xFF) / 255
        self = Color(.sRGB, red: r, green: g, blue: b, opacity: alpha)
    }
}
"""###,
        "ges-drag-rope-bridge": ###"""
import SwiftUI

// MARK: - Sag Rope Bridge
// Drag a point along a taut rope and it sags into a catenary-like curve under
// the load; the planks tilt to follow the line, and on release the sag springs
// back to taut with a bouncy "twang".
//
// Single source of truth: a normalized load position `loadX` (0…1 across the
// span) and a `sag` amount (0 = taut, 1 = max droop). Both the rope `Shape`
// and the plank layout derive from the SAME `profile(x:loadX:)` function, and
// the rope height is *linear* in `sag` — so the Shape's animatableData
// interpolation and the planks' per-view interpolation move identically during
// the release spring and never drift apart.
struct DragRopeBridgeView: View {
    var demo: Bool = false

    // Interactive state (used only when demo == false).
    @State private var loadX: CGFloat = 0.5
    @State private var sag: CGFloat = 0
    @State private var isPressing: Bool = false

    var body: some View {
        GeometryReader { geo in
            if demo {
                demoBody(size: geo.size)
            } else {
                interactiveBody(size: geo.size)
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // MARK: Demo (self-driving)

    @ViewBuilder
    private func demoBody(size: CGSize) -> some View {
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            let phase = autoPhase(at: t)
            bridge(size: size, loadX: phase.loadX, sag: phase.sag, pressing: phase.pressing)
        }
    }

    // ~3.4s loop: glide the load point across the span while pulsing the sag,
    // then let it twang back taut. Never blank — the rope is always drawn.
    private func autoPhase(at time: TimeInterval) -> (loadX: CGFloat, sag: CGFloat, pressing: Bool) {
        let period: Double = 3.4
        let p = (time.truncatingRemainder(dividingBy: period)) / period   // 0…1

        // Load point sweeps side to side (smooth cosine ease).
        let sweep = CGFloat(0.5 - 0.32 * cos(p * 2 * .pi))

        // Sag: ease in to a held droop for the first ~70% of the loop, then a
        // springy twang back to taut for the last ~30% (the release).
        let sagVal: CGFloat
        let pressing: Bool
        if p < 0.70 {
            let q = CGFloat(p / 0.70)
            sagVal = easeInOut(q)
            pressing = true
        } else {
            let q = CGFloat((p - 0.70) / 0.30)
            sagVal = 1 - twang(q)          // 1 → 0 with bouncy overshoot
            pressing = false
        }
        return (sweep, max(0, min(1, sagVal)), pressing)
    }

    // MARK: Interactive

    @ViewBuilder
    private func interactiveBody(size: CGSize) -> some View {
        bridge(size: size, loadX: loadX, sag: sag, pressing: isPressing)
            .contentShape(Rectangle())
            .gesture(dragGesture(size: size))
    }

    private func dragGesture(size: CGSize) -> some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                isPressing = true
                let span = restGeometry(size: size)
                // Horizontal → which point on the rope is loaded.
                loadX = clamp((value.location.x - span.startX) / span.width, 0, 1)
                // Vertical → how far the rope is pulled down past the rest line.
                let pulled = value.location.y - span.restY
                let maxDrop = span.maxSag
                sag = clamp(pulled / maxDrop, 0, 1)
            }
            .onEnded { _ in
                isPressing = false
                withAnimation(.interpolatingSpring(stiffness: 170, damping: 9)) {
                    sag = 0   // twang back to taut; loadX stays put (keeps it linear)
                }
            }
    }

    // MARK: Composed bridge

    @ViewBuilder
    private func bridge(size: CGSize, loadX: CGFloat, sag: CGFloat, pressing: Bool) -> some View {
        let g = restGeometry(size: size)
        ZStack {
            postsAndDeck(geo: g)
            RopeShape(loadX: loadX, sag: sag, geo: g)
                .stroke(ropeGradient, style: StrokeStyle(lineWidth: g.ropeWidth, lineCap: .round))
                .shadow(color: .black.opacity(0.45), radius: g.ropeWidth * 0.5, y: g.ropeWidth * 0.6)
            planks(loadX: loadX, sag: sag, geo: g)
            loadKnob(loadX: loadX, sag: sag, geo: g, pressing: pressing)
        }
    }

    // Two anchor posts plus a faint shadow line showing the taut rest position.
    @ViewBuilder
    private func postsAndDeck(geo g: RestGeometry) -> some View {
        let postW = g.ropeWidth * 1.4
        let postTop = g.restY - g.ropeWidth * 2.2
        let postBottom = min(g.size.height - g.ropeWidth, g.restY + g.maxSag + g.plankH)
        Path { p in
            p.move(to: CGPoint(x: g.startX, y: g.restY))
            p.addLine(to: CGPoint(x: g.endX, y: g.restY))
        }
        .stroke(Color.white.opacity(0.08), style: StrokeStyle(lineWidth: 1, dash: [4, 5]))

        ForEach([g.startX, g.endX], id: \.self) { x in
            RoundedRectangle(cornerRadius: postW * 0.4)
                .fill(postGradient)
                .frame(width: postW, height: max(postW, postBottom - postTop))
                .position(x: x, y: (postTop + postBottom) / 2)
                .shadow(color: .black.opacity(0.4), radius: 3, y: 2)
        }
    }

    // Wooden planks sampled along the live curve, each tilted to the local tangent.
    @ViewBuilder
    private func planks(loadX: CGFloat, sag: CGFloat, geo g: RestGeometry) -> some View {
        let count = g.plankCount
        ForEach(0..<count, id: \.self) { i in
            let n = CGFloat(i) + 1
            let u = n / CGFloat(count + 1)               // 0…1 along the span (skip anchors)
            let x = g.startX + u * g.width
            let y = ropeY(at: x, loadX: loadX, sag: sag, geo: g)
            let angle = tangentAngle(at: x, loadX: loadX, sag: sag, geo: g)
            // Glint: planks nearer the load (deeper) catch a touch more light.
            let depth = (y - g.restY) / max(1, g.maxSag)
            RoundedRectangle(cornerRadius: g.plankH * 0.32)
                .fill(plankGradient(depth: depth))
                .frame(width: g.plankW, height: g.plankH)
                .overlay(
                    RoundedRectangle(cornerRadius: g.plankH * 0.32)
                        .stroke(Color.black.opacity(0.25), lineWidth: 0.6)
                )
                .rotationEffect(.radians(angle))
                .position(x: x, y: y + g.plankH * 0.5 + g.ropeWidth * 0.2)
                .shadow(color: .black.opacity(0.3), radius: 1.5, y: 1)
        }
    }

    // The grabbable load point — a rope clip / carabiner that rides the curve.
    @ViewBuilder
    private func loadKnob(loadX: CGFloat, sag: CGFloat, geo g: RestGeometry, pressing: Bool) -> some View {
        let x = g.startX + loadX * g.width
        let y = ropeY(at: x, loadX: loadX, sag: sag, geo: g)
        let r = g.ropeWidth * (pressing ? 2.0 : 1.6)
        ZStack {
            Circle()
                .fill(RadialGradient(
                    colors: [Color(hexCode: "#FFE9B0"), Color(hexCode: "#E0A23C")],
                    center: .init(x: 0.35, y: 0.3), startRadius: 0, endRadius: r))
            Circle()
                .stroke(Color(hexCode: "#7A5418"), lineWidth: max(1, r * 0.16))
        }
        .frame(width: r * 2, height: r * 2)
        .position(x: x, y: y)
        .shadow(color: Color(hexCode: "#E0A23C").opacity(pressing ? 0.6 : 0.0), radius: pressing ? 8 : 0)
        .animation(.easeOut(duration: 0.18), value: pressing)
    }

    // MARK: Curve math (single source of truth)

    // Rope height at a given screen-x. Linear in `sag` so Shape interpolation
    // and plank interpolation move in lockstep during the release spring.
    private func ropeY(at x: CGFloat, loadX: CGFloat, sag: CGFloat, geo g: RestGeometry) -> CGFloat {
        let u = clamp((x - g.startX) / g.width, 0, 1)
        return g.restY + g.maxSag * sag * profile(u, loadX: loadX)
    }

    // Local tangent angle from a cheap symmetric finite difference.
    private func tangentAngle(at x: CGFloat, loadX: CGFloat, sag: CGFloat, geo g: RestGeometry) -> CGFloat {
        let dx: CGFloat = max(2, g.width * 0.02)
        let y1 = ropeY(at: x - dx, loadX: loadX, sag: sag, geo: g)
        let y2 = ropeY(at: x + dx, loadX: loadX, sag: sag, geo: g)
        return atan2(y2 - y1, dx * 2)
    }

    // Static droop profile peaked under the load and pinned to 0 at both
    // anchors. A blend of a triangular "load cusp" and a smooth catenary bowl
    // gives a believable rope: a sharp dip at the finger easing into a hanging
    // curve toward the posts.
    private func profile(_ u: CGFloat, loadX: CGFloat) -> CGFloat {
        let lx = clamp(loadX, 0.001, 0.999)
        // Triangular component: 1 at the load, linearly to 0 at the anchors.
        let tri: CGFloat = u <= lx ? (u / lx) : ((1 - u) / (1 - lx))
        // Catenary-ish bowl: a smooth symmetric sag (parabolic), softened.
        let bowl = 4 * u * (1 - u)                // 0 at ends, 1 at center
        // Weight the cusp toward the load, blend in the bowl for a hanging feel.
        let shaped = pow(max(0, tri), 1.35)
        return clamp(0.62 * shaped + 0.38 * bowl * tri, 0, 1)
    }

    // MARK: Rest geometry

    private func restGeometry(size: CGSize) -> RestGeometry {
        let w = size.width
        let h = size.height
        let inset = w * 0.10
        let startX = inset
        let endX = w - inset
        let width = max(1, endX - startX)
        // Rope hangs in the upper-middle so it has room to sag downward.
        let restY = h * 0.34
        let maxSag = max(8, (h * 0.5) - h * 0.04)
        let ropeWidth = max(2.5, min(w, h) * 0.022)
        // Plank count scales a little with width so a small tile isn't crowded.
        let plankCount = w < 200 ? 6 : 8
        let plankW = (width / CGFloat(plankCount + 1)) * 0.82
        let plankH = max(5, min(w, h) * 0.05)
        return RestGeometry(size: size, startX: startX, endX: endX, width: width,
                            restY: restY, maxSag: maxSag, ropeWidth: ropeWidth,
                            plankCount: plankCount, plankW: plankW, plankH: plankH)
    }

    // MARK: Palette

    private var ropeGradient: LinearGradient {
        LinearGradient(colors: [Color(hexCode: "#C9A26B"), Color(hexCode: "#A07A45"), Color(hexCode: "#C9A26B")],
                       startPoint: .leading, endPoint: .trailing)
    }
    private var postGradient: LinearGradient {
        LinearGradient(colors: [Color(hexCode: "#5B4630"), Color(hexCode: "#3A2C1C")],
                       startPoint: .top, endPoint: .bottom)
    }
    private func plankGradient(depth: CGFloat) -> LinearGradient {
        // Planks sitting deeper under the load catch a touch more top light —
        // interpolate the top face between a base and a brighter highlight.
        let glint = clamp(depth, 0, 1) * 0.35
        let top = Color.lerpRGB(
            from: (0.710, 0.521, 0.298),   // #B5854C
            to:   (0.910, 0.773, 0.537),   // #E8C589
            fraction: glint)
        return LinearGradient(colors: [top, Color(hexCode: "#7C5A33")],
                              startPoint: .top, endPoint: .bottom)
    }

    // MARK: Tiny helpers

    private func clamp(_ v: CGFloat, _ lo: CGFloat, _ hi: CGFloat) -> CGFloat { min(max(v, lo), hi) }

    private func easeInOut(_ x: CGFloat) -> CGFloat {
        let c = clamp(x, 0, 1)
        return c * c * (3 - 2 * c)
    }

    // Damped bounce 0→1 used for the auto-release twang.
    private func twang(_ x: CGFloat) -> CGFloat {
        let c = clamp(x, 0, 1)
        let decay = exp(-4.0 * c)
        let osc = cos(c * .pi * 3.0)
        return CGFloat(1 - decay * osc)
    }
}

// MARK: - Rest geometry container

private struct RestGeometry {
    let size: CGSize
    let startX: CGFloat
    let endX: CGFloat
    let width: CGFloat
    let restY: CGFloat
    let maxSag: CGFloat
    let ropeWidth: CGFloat
    let plankCount: Int
    let plankW: CGFloat
    let plankH: CGFloat
}

// MARK: - Animatable rope Shape

private struct RopeShape: Shape {
    var loadX: CGFloat
    var sag: CGFloat
    let geo: RestGeometry

    // Animate both load position and sag so the release spring (and any change)
    // interpolates smoothly. Linear-in-sag profile keeps it glued to the planks.
    var animatableData: AnimatablePair<CGFloat, CGFloat> {
        get { AnimatablePair(loadX, sag) }
        set { loadX = newValue.first; sag = newValue.second }
    }

    func path(in rect: CGRect) -> Path {
        var path = Path()
        let samples = 48
        for i in 0...samples {
            let u = CGFloat(i) / CGFloat(samples)
            let x = geo.startX + u * geo.width
            let y = geo.restY + geo.maxSag * sag * profile(u, loadX: loadX)
            if i == 0 { path.move(to: CGPoint(x: x, y: y)) }
            else { path.addLine(to: CGPoint(x: x, y: y)) }
        }
        return path
    }

    // Must match DragRopeBridgeView.profile exactly (same source of truth).
    private func profile(_ u: CGFloat, loadX: CGFloat) -> CGFloat {
        let lx = min(max(loadX, 0.001), 0.999)
        let tri: CGFloat = u <= lx ? (u / lx) : ((1 - u) / (1 - lx))
        let bowl = 4 * u * (1 - u)
        let shaped = pow(max(0, tri), 1.35)
        let v = 0.62 * shaped + 0.38 * bowl * tri
        return min(max(v, 0), 1)
    }
}

// MARK: - Color helpers

private extension Color {
    init(hexCode hex: String) {
        let s = hex.trimmingCharacters(in: CharacterSet(charactersIn: "#"))
        var rgb: UInt64 = 0
        Scanner(string: s).scanHexInt64(&rgb)
        let r, g, b, a: Double
        if s.count == 8 {
            r = Double((rgb & 0xFF000000) >> 24) / 255
            g = Double((rgb & 0x00FF0000) >> 16) / 255
            b = Double((rgb & 0x0000FF00) >> 8) / 255
            a = Double(rgb & 0x000000FF) / 255
        } else {
            r = Double((rgb & 0xFF0000) >> 16) / 255
            g = Double((rgb & 0x00FF00) >> 8) / 255
            b = Double(rgb & 0x0000FF) / 255
            a = 1
        }
        self.init(.sRGB, red: r, green: g, blue: b, opacity: a)
    }

    // Linearly interpolate between two sRGB component triples.
    static func lerpRGB(from a: (Double, Double, Double),
                        to b: (Double, Double, Double),
                        fraction: Double) -> Color {
        let f = min(max(fraction, 0), 1)
        return Color(.sRGB,
                     red: a.0 + (b.0 - a.0) * f,
                     green: a.1 + (b.1 - a.1) * f,
                     blue: a.2 + (b.2 - a.2) * f,
                     opacity: 1)
    }
}
"""###,
        "ges-drag-spring-net": ###"""
import SwiftUI

// MARK: - Trampoline Net Drag
/// Press into a woven mesh net and it deforms into a stretched pocket with the
/// surrounding grid lines pulling taut; release launches a ball upward
/// proportional to the depression depth.
///
/// - `demo == true`  : a self-driving loop pushes a virtual press point down and
///                     releases, flinging the ball on rebound (no touch needed).
/// - `demo == false` : the real interactive component — drag into the net, lift
///                     to fling the ball.
struct DragSpringNetView: View {
    var demo: Bool = false

    // Grid resolution (kept coarse for perf — ~10×10 nodes).
    private let cols = 10
    private let rows = 10

    // Interactive state ---------------------------------------------------
    // NOTE: Canvas reads these synchronously inside its closure and does NOT
    // interpolate withAnimation-driven values. So all motion (ball arc + net
    // twang) is derived from `timeline.date` against `launchTime`, exactly like
    // the demo path — never from a @State mutated under withAnimation.
    @State private var pressUnit: CGPoint = CGPoint(x: 0.5, y: 0.5) // press point in 0…1
    @State private var pressDepth: CGFloat = 0                      // live pocket depth while pressing 0…1
    @State private var ballX: CGFloat = 0.5                         // horizontal unit position
    @State private var isPressing: Bool = false

    // Flight state (release → ballistic arc + twang) ----------------------
    @State private var launchTime: Date? = nil   // when the finger lifted
    @State private var launchDepth: CGFloat = 0  // depression depth captured at release
    @State private var launchTrigger: Int = 0    // bumped on release → haptic (interactive only)

    var body: some View {
        GeometryReader { geo in
            let size = geo.size
            if demo {
                demoCanvas(size: size)
            } else {
                interactiveCanvas(size: size)
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .background(Color(hexCode: "#0d0e16"))
    }

    // MARK: - Demo (self-driving)

    private func demoCanvas(size: CGSize) -> some View {
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            let s = demoState(time: t)
            netCanvas(size: size,
                      press: s.press,
                      depth: s.depth,
                      ballX: s.ballX,
                      ballY: s.ballY)
        }
    }

    /// Drives press/depth/ball from a ~3.4s loop clock.
    private func demoState(time: TimeInterval) -> (press: CGPoint, depth: CGFloat, ballX: CGFloat, ballY: CGFloat) {
        let period: Double = 3.4
        let phase = (time.truncatingRemainder(dividingBy: period)) / period // 0…1

        // Press point drifts gently so the pocket isn't always dead-center.
        let px = 0.5 + 0.16 * CGFloat(sin(time * 0.9))
        let py = 0.52 + 0.05 * CGFloat(cos(time * 0.7))
        let press = CGPoint(x: px, y: py)

        // Phase A (0…0.45): push in, depth ramps up with ease.
        // Phase B (0.45…1): release — net twangs flat, ball arcs up & falls back.
        if phase < 0.45 {
            let p = phase / 0.45
            let d = CGFloat(easeInOut(p))
            return (press, d, px, 0) // ball rides the pocket center while pressing
        } else {
            // Real seconds since release so the shared physics helpers apply.
            let launchDepth: CGFloat = 1.0
            let releaseSeconds = (phase - 0.45) * period
            let by = ballisticArc(t: releaseSeconds, depth: launchDepth)
            let dp = launchDepth * springTwang(t: releaseSeconds)
            return (press, dp, px, by)
        }
    }

    // MARK: - Interactive

    private func interactiveCanvas(size: CGSize) -> some View {
        TimelineView(.animation) { timeline in
            let s = interactiveState(now: timeline.date)
            netCanvas(size: size,
                      press: pressUnit,
                      depth: s.depth,
                      ballX: ballX,
                      ballY: s.ballY)
        }
        .contentShape(Rectangle())
        .gesture(dragGesture(size: size))
        .sensoryFeedback(.impact(weight: .medium), trigger: launchTrigger)
    }

    /// Derives the rendered depth + ball height from the clock, never from a
    /// withAnimation-mutated @State (Canvas would not interpolate that).
    private func interactiveState(now: Date) -> (depth: CGFloat, ballY: CGFloat) {
        if isPressing {
            // Live press: net follows the finger, ball waits in the pocket.
            return (pressDepth, 0)
        }
        guard let start = launchTime else {
            return (0, 0) // at rest, ready for the next drag
        }
        let t = now.timeIntervalSince(start)
        let flight = flightDuration(depth: launchDepth)
        if t >= flight {
            return (0, 0) // settled — repeatable
        }
        let by = ballisticArc(t: t, depth: launchDepth)
        let dp = launchDepth * springTwang(t: t) // net relaxes flat with a twang (signed = overshoot)
        return (dp, by)
    }

    private func dragGesture(size: CGSize) -> some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                isPressing = true
                launchTime = nil // cancel any in-flight ball; finger grabs the net
                let ux = clampUnit(value.location.x / max(size.width, 1))
                let uy = clampUnit(value.location.y / max(size.height, 1))
                pressUnit = CGPoint(x: ux, y: uy)
                ballX = ux

                // Depth grows with how far the finger has pulled "into" the net
                // (downward translation), normalized by view height.
                let pull = max(0, value.translation.height) / max(size.height, 1)
                pressDepth = min(1, pull * 1.6 + 0.15) // a little depth on touch-down
            }
            .onEnded { _ in
                launchDepth = pressDepth
                isPressing = false
                launchTime = .now           // start the clock-driven flight
                launchTrigger &+= 1          // haptic (interactive only)
            }
    }

    // MARK: - Unified Net Renderer (shared by both modes)

    private func netCanvas(size: CGSize,
                           press: CGPoint,
                           depth: CGFloat,
                           ballX: CGFloat,
                           ballY: CGFloat) -> some View {
        Canvas { ctx, canvasSize in
            let layout = NetLayout(size: canvasSize, cols: cols, rows: rows)

            // Pocket-center darkening to sell the well.
            drawWellShadow(ctx: &ctx, layout: layout, press: press, depth: depth)

            // Woven grid (taut lines between displaced nodes).
            drawWeave(ctx: &ctx, layout: layout, press: press, depth: depth)

            // The launched ball.
            drawBall(ctx: &ctx, layout: layout,
                     press: press, depth: depth,
                     ballX: ballX, ballY: ballY)
        }
        .frame(width: size.width, height: size.height)
    }

    // MARK: - Node displacement

    /// A single net node's position after radial pull toward the press point.
    private func displacedNode(row: Int, col: Int,
                               layout: NetLayout,
                               press: CGPoint, depth: CGFloat) -> CGPoint {
        let base = layout.basePoint(row: row, col: col)
        guard abs(depth) > 0.0005 else { return base } // signed: <0 = rebound overshoot

        let pressPx = CGPoint(x: press.x * layout.size.width,
                              y: press.y * layout.size.height)
        let dx = pressPx.x - base.x
        let dy = pressPx.y - base.y
        let dist2 = dx * dx + dy * dy

        // Cheap Gaussian-ish falloff: nodes near the press get pulled most.
        let sigma = layout.minDim * 0.42
        let falloff = exp(-dist2 / (2 * sigma * sigma))
        let pull = falloff * depth

        // Horizontal pull toward the press (the weave converging) + a vertical
        // sag component so the pocket reads as a depression.
        let nx = base.x + dx * pull * 0.55
        let sag = layout.minDim * 0.30 * pull
        let ny = base.y + dy * pull * 0.45 + sag
        return CGPoint(x: nx, y: ny)
    }

    // MARK: - Drawing helpers

    private func drawWellShadow(ctx: inout GraphicsContext,
                                layout: NetLayout,
                                press: CGPoint, depth: CGFloat) {
        guard depth > 0.02 else { return }
        let center = CGPoint(x: press.x * layout.size.width,
                             y: press.y * layout.size.height + layout.minDim * 0.20 * depth)
        let r = layout.minDim * (0.18 + 0.30 * depth)
        let rect = CGRect(x: center.x - r, y: center.y - r, width: r * 2, height: r * 2)
        let shade = GraphicsContext.Shading.radialGradient(
            Gradient(colors: [
                Color.black.opacity(0.45 * Double(depth)),
                Color.clear
            ]),
            center: center, startRadius: 0, endRadius: r)
        ctx.fill(Path(ellipseIn: rect), with: shade)
    }

    private func drawWeave(ctx: inout GraphicsContext,
                           layout: NetLayout,
                           press: CGPoint, depth: CGFloat) {
        // Precompute displaced nodes once per frame.
        var pts = [[CGPoint]](repeating: [CGPoint](repeating: .zero, count: cols),
                              count: rows)
        for r in 0..<rows {
            for c in 0..<cols {
                pts[r][c] = displacedNode(row: r, col: c, layout: layout,
                                          press: press, depth: depth)
            }
        }

        let baseColor = Color(hexCode: "#5b7cff")
        let hotColor = Color(hexCode: "#8fa9ff")
        let lineW: CGFloat = max(0.8, layout.minDim * 0.012)

        // Horizontal threads.
        for r in 0..<rows {
            var path = Path()
            path.move(to: pts[r][0])
            for c in 1..<cols { path.addLine(to: pts[r][c]) }
            let tension = threadTension(rowOrCol: r, count: rows, depth: depth)
            ctx.stroke(path,
                       with: .color(baseColor.opacity(0.55 + 0.4 * tension)),
                       lineWidth: lineW)
        }
        // Vertical threads.
        for c in 0..<cols {
            var path = Path()
            path.move(to: pts[0][c])
            for r in 1..<rows { path.addLine(to: pts[r][c]) }
            let tension = threadTension(rowOrCol: c, count: cols, depth: depth)
            ctx.stroke(path,
                       with: .color(hotColor.opacity(0.40 + 0.45 * tension)),
                       lineWidth: lineW)
        }

        // Glow nodes near the pocket.
        if depth > 0.05 {
            let nodeR = max(0.8, layout.minDim * 0.014)
            for r in stride(from: 0, to: rows, by: 1) {
                for c in stride(from: 0, to: cols, by: 1) {
                    let p = pts[r][c]
                    let d = nodeGlow(at: p, press: press, layout: layout)
                    guard d > 0.15 else { continue }
                    let rect = CGRect(x: p.x - nodeR, y: p.y - nodeR,
                                      width: nodeR * 2, height: nodeR * 2)
                    ctx.fill(Path(ellipseIn: rect),
                             with: .color(Color(hexCode: "#cfe0ff").opacity(Double(d) * Double(depth))))
                }
            }
        }
    }

    /// Brightens threads as the net tightens.
    private func threadTension(rowOrCol: Int, count: Int, depth: CGFloat) -> Double {
        let center = Double(count - 1) / 2.0
        let dist = abs(Double(rowOrCol) - center) / max(center, 1)
        let proximity = 1.0 - dist
        return Double(depth) * (0.4 + 0.6 * proximity)
    }

    private func nodeGlow(at p: CGPoint, press: CGPoint, layout: NetLayout) -> CGFloat {
        let pressPx = CGPoint(x: press.x * layout.size.width,
                              y: press.y * layout.size.height)
        let dx = pressPx.x - p.x
        let dy = pressPx.y - p.y
        let d2 = dx * dx + dy * dy
        let sigma = layout.minDim * 0.34
        return exp(-d2 / (2 * sigma * sigma))
    }

    private func drawBall(ctx: inout GraphicsContext,
                          layout: NetLayout,
                          press: CGPoint, depth: CGFloat,
                          ballX: CGFloat, ballY: CGFloat) {
        let r = layout.minDim * 0.085

        // Resting plane = net surface at the press point (sinks with depth).
        let restY = layout.size.height * press.y + layout.minDim * 0.30 * depth
        // Launch height lifts the ball up; clamp so it never leaves the frame.
        let lift = layout.size.height * 0.62 * ballY
        let cy = max(r + 2, restY - lift)
        let cx = max(r, min(layout.size.width - r, ballX * layout.size.width))
        let center = CGPoint(x: cx, y: cy)

        // Soft contact shadow on the net plane.
        let shadowScale = 1.0 - 0.5 * Double(ballY)
        let sr = r * CGFloat(shadowScale)
        let srect = CGRect(x: cx - sr, y: restY - sr * 0.35,
                           width: sr * 2, height: sr * 0.7)
        ctx.fill(Path(ellipseIn: srect),
                 with: .color(Color.black.opacity(0.30 * shadowScale)))

        // The ball: glossy radial gradient.
        let brect = CGRect(x: center.x - r, y: center.y - r, width: r * 2, height: r * 2)
        let grad = GraphicsContext.Shading.radialGradient(
            Gradient(colors: [
                Color(hexCode: "#ffd36b"),
                Color(hexCode: "#ff8c42"),
                Color(hexCode: "#e0591f")
            ]),
            center: CGPoint(x: center.x - r * 0.3, y: center.y - r * 0.35),
            startRadius: 0, endRadius: r * 1.4)
        ctx.fill(Path(ellipseIn: brect), with: grad)

        // Specular highlight.
        let hr = r * 0.34
        let hrect = CGRect(x: center.x - r * 0.42, y: center.y - r * 0.5,
                           width: hr * 2, height: hr * 2)
        ctx.fill(Path(ellipseIn: hrect),
                 with: .color(Color.white.opacity(0.7)))
    }

    // MARK: - Shared flight physics (clock-driven, used by both modes)

    /// Total seconds the launched ball stays in the air, scaled by launch depth.
    private func flightDuration(depth: CGFloat) -> Double {
        let apex = min(1.0, max(0.12, Double(depth)))
        return 0.85 + 0.75 * apex
    }

    /// Ball height in unit space (0 = net plane, 1 = full apex) at time `t`
    /// seconds after release. Asymmetric arc: snappy rise, gravity-weighted fall.
    private func ballisticArc(t: Double, depth: CGFloat) -> CGFloat {
        let dur = flightDuration(depth: depth)
        guard t > 0, t < dur else { return 0 }
        let apex = min(1.0, max(0.12, Double(depth)))
        let p = t / dur                    // 0…1 over the flight
        // Parabolic arc 0→1→0 with a slight skew so the fall lingers.
        let skew = pow(p, 0.85)            // reach apex a touch sooner
        let arc = 4 * skew * (1 - skew)
        return CGFloat(apex * arc)
    }

    /// Damped-spring relaxation for the net "twang" after release:
    /// exp(-k·t)·cos(ω·t) → ~bounce 0.5. Returns a multiplier on launch depth.
    private func springTwang(t: Double) -> CGFloat {
        guard t > 0 else { return 1 }
        let k = 7.5        // decay
        let omega = 17.0   // oscillation
        let v = exp(-k * t) * cos(omega * t)
        return CGFloat(max(-0.25, v)) // allow a small overshoot below the plane
    }

    // MARK: - Math utilities

    private func easeInOut(_ t: Double) -> Double {
        t < 0.5 ? 2 * t * t : 1 - pow(-2 * t + 2, 2) / 2
    }

    private func clampUnit(_ v: CGFloat) -> CGFloat { min(1, max(0, v)) }
}

// MARK: - Net layout geometry

private struct NetLayout {
    let size: CGSize
    let cols: Int
    let rows: Int
    let inset: CGFloat
    let minDim: CGFloat

    init(size: CGSize, cols: Int, rows: Int) {
        self.size = size
        self.cols = cols
        self.rows = rows
        self.minDim = min(size.width, size.height)
        self.inset = self.minDim * 0.10
    }

    func basePoint(row: Int, col: Int) -> CGPoint {
        let usableW = size.width - inset * 2
        let usableH = size.height - inset * 2
        let x = inset + usableW * CGFloat(col) / CGFloat(max(cols - 1, 1))
        let y = inset + usableH * CGFloat(row) / CGFloat(max(rows - 1, 1))
        return CGPoint(x: x, y: y)
    }
}

// MARK: - Hex color helper

private extension Color {
    init(hexCode hex: String) {
        let s = hex.trimmingCharacters(in: CharacterSet.alphanumerics.inverted)
        var int: UInt64 = 0
        Scanner(string: s).scanHexInt64(&int)
        let r, g, b, a: UInt64
        switch s.count {
        case 3: // RGB (12-bit)
            (r, g, b, a) = ((int >> 8) * 17, (int >> 4 & 0xF) * 17, (int & 0xF) * 17, 255)
        case 6: // RGB (24-bit)
            (r, g, b, a) = (int >> 16, int >> 8 & 0xFF, int & 0xFF, 255)
        case 8: // ARGB (32-bit)
            (r, g, b, a) = (int >> 16 & 0xFF, int >> 8 & 0xFF, int & 0xFF, int >> 24)
        default:
            (r, g, b, a) = (255, 255, 255, 255)
        }
        self.init(.sRGB,
                  red: Double(r) / 255,
                  green: Double(g) / 255,
                  blue: Double(b) / 255,
                  opacity: Double(a) / 255)
    }
}

// MARK: - Preview
"""###,
        "ges-edge-swipe-page-curl": ###"""
import SwiftUI

/// Edge-Swipe Page Curl
///
/// Swipe from the trailing edge and the page lifts and curls back like turning a
/// leaf. The crease line tracks the finger; the folded strip rotates about its own
/// leading edge (single-axis `rotation3DEffect` cylinder approximation) and shows a
/// shaded paper backside, while the next page is revealed underneath with a soft
/// shadow gradient hugging the crease.
///
/// - `demo == true`  : self-driving TimelineView loop that eases the curl 0→1→0.
/// - `demo == false` : interactive trailing-edge `DragGesture(minimumDistance: 0)`.
struct EdgeSwipePageCurlView: View {

    var demo: Bool = false

    var body: some View {
        GeometryReader { geo in
            content(in: geo.size)
                .frame(width: geo.size.width, height: geo.size.height)
                .clipped()
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    @ViewBuilder
    private func content(in size: CGSize) -> some View {
        if demo {
            DemoCurl(size: size)
        } else {
            InteractiveCurl(size: size)
        }
    }
}

// MARK: - Demo (self-driving loop)

private struct DemoCurl: View {
    let size: CGSize

    var body: some View {
        TimelineView(.animation) { timeline in
            let p = Self.loopProgress(timeline.date)
            PageCurlStage(size: size, progress: p, pageIndex: Self.pageIndex(timeline.date))
        }
    }

    /// 0 → 1 → 0 ease over a ~3.4s cycle (a peek-and-return turn, never committed).
    private static func loopProgress(_ date: Date) -> CGFloat {
        let period: Double = 3.4
        let t = date.timeIntervalSinceReferenceDate.truncatingRemainder(dividingBy: period) / period
        // Hold flat briefly, then a smooth out-and-back.
        let phase = (t - 0.08) / 0.84
        guard phase > 0, phase < 1 else { return 0 }
        let tri = phase < 0.5 ? phase * 2 : (1 - phase) * 2          // 0→1→0 triangle
        return CGFloat(smoothstep(tri))
    }

    /// Advance the "current page" content each completed cycle so the loop feels like
    /// real turning rather than the same leaf flapping.
    private static func pageIndex(_ date: Date) -> Int {
        let period: Double = 3.4
        let cycles = date.timeIntervalSinceReferenceDate / period
        return Int(cycles)
    }

    private static func smoothstep(_ x: Double) -> Double {
        let c = min(max(x, 0), 1)
        return c * c * (3 - 2 * c)
    }
}

// MARK: - Interactive (real edge swipe)

private struct InteractiveCurl: View {
    let size: CGSize

    @State private var progress: CGFloat = 0
    @State private var pageIndex: Int = 0
    @GestureState private var dragging: Bool = false

    var body: some View {
        // Trailing-edge gate: only swipes starting in the trailing ~28% begin a turn.
        let edgeGate = max(size.width * 0.28, 36)

        PageCurlStage(size: size, progress: progress, pageIndex: pageIndex)
            .contentShape(Rectangle())
            .gesture(curlGesture(edgeGate: edgeGate))
            .sensoryFeedback(.selection, trigger: pageIndex)
    }

    private func curlGesture(edgeGate: CGFloat) -> some Gesture {
        DragGesture(minimumDistance: 0)
            .updating($dragging) { _, state, _ in state = true }
            .onChanged { value in
                guard size.width > 0 else { return }
                let startX = value.startLocation.x
                // Only react if the gesture began near the trailing edge.
                guard startX >= size.width - edgeGate else { return }
                // location.x sweeps right → left; map to crease position → progress.
                let creaseX = min(max(value.location.x, 0), size.width)
                progress = 1 - (creaseX / size.width)
            }
            .onEnded { value in
                let startX = value.startLocation.x
                guard startX >= size.width - edgeGate else { return }
                commit(velocity: value.predictedEndLocation.x - value.location.x)
            }
    }

    private func commit(velocity: CGFloat) {
        // Fast leftward fling, or already past halfway → complete the turn.
        let shouldTurn = progress > 0.5 || velocity < -size.width * 0.18
        if shouldTurn {
            withAnimation(.spring(response: 0.45, dampingFraction: 0.82)) {
                progress = 1
            }
            // Snap to the next page once the leaf has laid over, then reset flat.
            DispatchQueue.main.asyncAfter(deadline: .now() + 0.42) {
                pageIndex += 1
                progress = 0
            }
        } else {
            withAnimation(.spring(response: 0.5, dampingFraction: 0.7)) {
                progress = 0
            }
        }
    }
}

// MARK: - The three-layer stage

private struct PageCurlStage: View {
    let size: CGSize
    let progress: CGFloat
    let pageIndex: Int

    var body: some View {
        let p = min(max(progress, 0), 1)
        let width = size.width
        let creaseX = width * (1 - p)        // crease sweeps from right edge leftward
        let curlWidth = width * p            // width of the folded-back strip

        ZStack(alignment: .topLeading) {
            // 1 — desk / book backdrop so edges never read as blank.
            Backdrop()

            // 2 — the next page, revealed beneath, with a shadow hugging the crease.
            PageFace(seed: pageIndex + 1, size: size)
                .overlay(alignment: .leading) {
                    creaseShadow(creaseX: creaseX, width: width)
                }
                .clipped()

            // 3 — the flat remainder of the current page (left of the crease).
            PageFace(seed: pageIndex, size: size)
                .frame(width: max(creaseX, 0), height: size.height, alignment: .leading)
                .clipped()

            // 4 — the curled strip: the back of the leaf, folding about its leading edge.
            CurledStrip(progress: p, curlWidth: curlWidth, size: size)
                .frame(width: max(curlWidth, 0.5), height: size.height, alignment: .leading)
                .rotation3DEffect(
                    .degrees(Double(foldAngle(p))),
                    axis: (x: 0, y: 1, z: 0),
                    anchor: .leading,
                    perspective: 0.55
                )
                .offset(x: creaseX)
                .opacity(p > 0.001 ? 1 : 0)
        }
        .frame(width: size.width, height: size.height)
        .clipped()
    }

    /// 0° flat → ~168° fully turned. The rotation itself mirrors the strip, so we never
    /// flip it manually (that would double-count the mirror).
    private func foldAngle(_ p: CGFloat) -> CGFloat {
        168 * p
    }

    private func creaseShadow(creaseX: CGFloat, width: CGFloat) -> some View {
        // Darkest at the crease, fading right across the revealed next page.
        let span = max(width * 0.32, 1)
        return LinearGradient(
            stops: [
                .init(color: .black.opacity(0.34), location: 0.0),
                .init(color: .black.opacity(0.12), location: 0.5),
                .init(color: .clear, location: 1.0)
            ],
            startPoint: .leading,
            endPoint: .trailing
        )
        .frame(width: span)
        .offset(x: creaseX)
        .allowsHitTesting(false)
        .opacity(creaseX < width ? 1 : 0)
    }
}

// MARK: - The folded strip (paper backside)

private struct CurledStrip: View {
    let progress: CGFloat
    let curlWidth: CGFloat
    let size: CGSize

    var body: some View {
        ZStack {
            // Paper backside base.
            Rectangle()
                .fill(Self.paperBack)

            // Cylinder shading: crease (leading) is lit, far edge falls into shadow.
            LinearGradient(
                stops: [
                    .init(color: glint, location: 0.0),
                    .init(color: .white.opacity(0.04), location: 0.16),
                    .init(color: .black.opacity(0.10), location: 0.55),
                    .init(color: .black.opacity(0.30 + 0.16 * progress), location: 1.0)
                ],
                startPoint: .leading,
                endPoint: .trailing
            )

            // Faint ruled ghost of the paper backside for texture.
            backRuling
        }
        .overlay(
            // Crisp lit highlight riding the crease edge — the "lift" off the page.
            Rectangle()
                .fill(.white.opacity(0.5 * progress))
                .frame(width: max(curlWidth * 0.06, 1))
                .blur(radius: 1.5),
            alignment: .leading
        )
        .compositingGroup()
        .clipped()
    }

    /// Brightness of the leading glint rises as the leaf lifts.
    private var glint: Color {
        .white.opacity(0.18 + 0.34 * Double(progress))
    }

    private var backRuling: some View {
        GeometryReader { g in
            let h = g.size.height
            let rows = 6
            ZStack {
                ForEach(0..<rows, id: \.self) { i in
                    let y = h * (0.2 + 0.6 * (CGFloat(i) / CGFloat(rows - 1)))
                    Rectangle()
                        .fill(.black.opacity(0.05))
                        .frame(height: 1)
                        .offset(y: y - h / 2)
                }
            }
        }
        .allowsHitTesting(false)
    }

    private static let paperBack = LinearGradient(
        colors: [Color(hexCode: "#ece7df"), Color(hexCode: "#ddd6ca")],
        startPoint: .top,
        endPoint: .bottom
    )
}

// MARK: - A legible page

private struct PageFace: View {
    let seed: Int
    let size: CGSize

    var body: some View {
        let pad = size.width * 0.1
        let accent = Self.accents[((seed % Self.accents.count) + Self.accents.count) % Self.accents.count]

        ZStack(alignment: .topLeading) {
            Rectangle().fill(Self.paper)

            VStack(alignment: .leading, spacing: size.height * 0.055) {
                header(accent: accent, width: size.width)
                textBars(width: size.width)
                Spacer(minLength: 0)
                footer(accent: accent, width: size.width)
            }
            .padding(pad)
            .frame(width: size.width, height: size.height, alignment: .topLeading)

            // Page number, lower trailing — sells "leaf in a book".
            Text("\(((seed % 99) + 99) % 99 + 1)")
                .font(.system(size: max(size.width * 0.07, 8), weight: .semibold, design: .serif))
                .foregroundStyle(.black.opacity(0.32))
                .padding(pad * 0.7)
                .frame(width: size.width, height: size.height, alignment: .bottomTrailing)
        }
        .overlay(
            // Subtle spine shading on the left edge.
            LinearGradient(
                colors: [.black.opacity(0.10), .clear],
                startPoint: .leading,
                endPoint: .trailing
            )
            .frame(width: size.width * 0.16),
            alignment: .leading
        )
    }

    private func header(accent: Color, width: CGFloat) -> some View {
        HStack(spacing: width * 0.04) {
            RoundedRectangle(cornerRadius: 3)
                .fill(accent)
                .frame(width: width * 0.14, height: width * 0.14)
            VStack(alignment: .leading, spacing: width * 0.03) {
                Capsule().fill(.black.opacity(0.7)).frame(width: width * 0.42, height: width * 0.055)
                Capsule().fill(.black.opacity(0.28)).frame(width: width * 0.3, height: width * 0.04)
            }
        }
    }

    private func textBars(width: CGFloat) -> some View {
        VStack(alignment: .leading, spacing: width * 0.045) {
            ForEach(barWidths, id: \.self) { w in
                Capsule()
                    .fill(.black.opacity(0.18))
                    .frame(width: width * w, height: width * 0.035)
            }
        }
    }

    private func footer(accent: Color, width: CGFloat) -> some View {
        HStack(spacing: width * 0.03) {
            Capsule().fill(accent.opacity(0.85)).frame(width: width * 0.26, height: width * 0.08)
            Capsule().fill(.black.opacity(0.12)).frame(width: width * 0.16, height: width * 0.08)
        }
    }

    /// Deterministic per-page line lengths so content varies but never shimmers.
    private var barWidths: [CGFloat] {
        let base: [CGFloat] = [0.78, 0.66, 0.8, 0.54, 0.72, 0.6]
        let shift = ((seed % base.count) + base.count) % base.count
        return Array(base[shift...] + base[..<shift])
    }

    private static let paper = LinearGradient(
        colors: [Color(hexCode: "#fbf9f4"), Color(hexCode: "#f1ece2")],
        startPoint: .top,
        endPoint: .bottom
    )

    private static let accents: [Color] = [
        Color(hexCode: "#e8743b"), Color(hexCode: "#3b8de8"),
        Color(hexCode: "#34a06b"), Color(hexCode: "#b5519a")
    ]
}

// MARK: - Backdrop

private struct Backdrop: View {
    var body: some View {
        Color(hexCode: "#0d0e16")
            .overlay(
                RadialGradient(
                    colors: [Color(hexCode: "#1b1d2b"), Color(hexCode: "#0d0e16")],
                    center: .center,
                    startRadius: 2,
                    endRadius: 240
                )
            )
            .ignoresSafeArea()
    }
}

// MARK: - Color hex helper

private extension Color {
    init(hexCode hex: String) {
        let s = hex.hasPrefix("#") ? String(hex.dropFirst()) : hex
        var v: UInt64 = 0
        Scanner(string: s).scanHexInt64(&v)
        let r, g, b, a: Double
        switch s.count {
        case 8:
            r = Double((v >> 24) & 0xFF) / 255
            g = Double((v >> 16) & 0xFF) / 255
            b = Double((v >> 8) & 0xFF) / 255
            a = Double(v & 0xFF) / 255
        case 6:
            r = Double((v >> 16) & 0xFF) / 255
            g = Double((v >> 8) & 0xFF) / 255
            b = Double(v & 0xFF) / 255
            a = 1
        default:
            r = 1; g = 1; b = 1; a = 1
        }
        self = Color(.sRGB, red: r, green: g, blue: b, opacity: a)
    }
}
"""###,
        "ges-fling-paper-plane": ###"""
import SwiftUI

/// Fling a folded paper plane and it launches along your vector, then glides in a
/// gentle banking descent with subtle pitch bobbing before nosing down to land.
///
/// - `demo == true`  → a self-driving `TimelineView(.animation)` loop auto-launches the
///   plane each cycle, glides it in a banking descent and lands it on the pad, then resets.
/// - `demo == false` → a real interactive component: drag the plane, release to fling it
///   along your vector (seeded from `predictedEndTranslation`), watch it glide and land,
///   then drag again to re-throw.
struct FlingPaperPlaneView: View {
    var demo: Bool = false

    // Interactive launch parameters. The TimelineView closure is a PURE function of these
    // plus elapsed time — nothing is integrated/accumulated during the render pass.
    @State private var launchDate: Date? = nil
    @State private var launchVelocity: CGVector = .zero   // normalized units / second
    @State private var dragOrigin: CGPoint = .zero        // normalized launch point
    @State private var dragTranslation: CGSize = .zero    // live finger offset (points)
    @State private var isDragging: Bool = false

    var body: some View {
        GeometryReader { geo in
            let size = geo.size
            ZStack {
                background
                if demo {
                    demoLayer(in: size)
                } else {
                    interactiveLayer(in: size)
                }
            }
            .frame(width: size.width, height: size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .clipped()
    }
}

// MARK: - Backdrop

private extension FlingPaperPlaneView {
    var background: some View {
        LinearGradient(
            colors: [
                Color(red: 0.09, green: 0.12, blue: 0.22),
                Color(red: 0.05, green: 0.06, blue: 0.12)
            ],
            startPoint: .top,
            endPoint: .bottom
        )
    }
}

// MARK: - Demo (self-driving) layer

private extension FlingPaperPlaneView {
    /// Total loop length in seconds. The last `restFraction` of it shows the plane resting
    /// on the pad so the cycle seam reads as an intentional pause, never a blank teleport.
    var cycle: Double { 3.4 }
    var restFraction: Double { 0.16 }

    func demoLayer(in size: CGSize) -> some View {
        TimelineView(.animation) { timeline in
            let phase = loopPhase(timeline.date)
            let launch = demoLaunchVelocity()
            let origin = demoOrigin
            let flightSpan = cycle * (1.0 - restFraction)
            // During the rest beat, freeze at the landed state of the last flight frame.
            let elapsed = min(phase, flightSpan)
            let state = glideState(t: elapsed, v0: launch, origin: origin, in: size)

            ZStack(alignment: .topLeading) {
                landingPad(at: demoLandingPoint, in: size)
                glideTrail(state: state, in: size)
                planeAndShadow(state: state, in: size)
            }
            .frame(width: size.width, height: size.height)
        }
    }

    /// Position within the current loop, in seconds [0, cycle).
    func loopPhase(_ date: Date) -> Double {
        let t = date.timeIntervalSinceReferenceDate
        return t.truncatingRemainder(dividingBy: cycle)
    }

    /// Launch point for the auto loop: lower-left pad.
    var demoOrigin: CGPoint { CGPoint(x: 0.16, y: 0.78) }

    /// Fixed launch vector for the loop. Negative y == upward in view space.
    func demoLaunchVelocity() -> CGVector {
        CGVector(dx: 0.62, dy: -0.92)
    }

    /// Where the demo plane actually touches down — derived from the same closed-form
    /// glide model (and pinned to `ground`) so the pad sits exactly under the landed plane.
    /// The four constants MUST match the locals in `glideState`.
    var demoLandingPoint: CGPoint {
        let v = demoLaunchVelocity()
        let o = demoOrigin
        let k: Double = 1.55
        let gravity: Double = 0.46
        let lift: Double = 0.34
        let ground: CGFloat = 0.82
        let tLand = landingTime(v0: v, origin: o, k: k, gravity: gravity,
                                lift: lift, ground: ground)
        let landed = trajectory(t: tLand, v0: v, origin: o,
                                k: k, gravity: gravity, lift: lift)
        return CGPoint(x: landed.x, y: Double(ground))
    }
}

// MARK: - Interactive layer

private extension FlingPaperPlaneView {
    func interactiveLayer(in size: CGSize) -> some View {
        TimelineView(.animation) { timeline in
            let state = currentInteractiveState(now: timeline.date, in: size)
            ZStack(alignment: .topLeading) {
                landingPad(at: restOrigin, in: size)
                glideTrail(state: state, in: size)
                planeAndShadow(state: state, in: size)
            }
            .frame(width: size.width, height: size.height)
            .contentShape(Rectangle())
            .gesture(dragGesture(in: size))
        }
    }

    /// Resolve the plane state for interactive mode across its three beats:
    /// idle-at-rest, dragging-with-finger, and post-release glide.
    func currentInteractiveState(now: Date, in size: CGSize) -> GlideState {
        if isDragging {
            return draggingState(in: size)
        }
        guard let launchDate else {
            return restState(at: restOrigin)
        }
        let t = now.timeIntervalSince(launchDate)
        return glideState(t: t, v0: launchVelocity, origin: dragOrigin, in: size)
    }

    /// The home pad position for the interactive plane.
    var restOrigin: CGPoint { CGPoint(x: 0.5, y: 0.7) }

    /// Plane held under the finger: tracks the live translation, nose tilts toward motion.
    func draggingState(in size: CGSize) -> GlideState {
        let w = max(size.width, 1)
        let h = max(size.height, 1)
        let pos = CGPoint(
            x: dragOrigin.x + dragTranslation.width / w,
            y: dragOrigin.y + dragTranslation.height / h
        )
        // Tilt the nose toward where the launch will go (opposite the pull-back).
        let pullX = -dragTranslation.width
        let pullY = -dragTranslation.height
        let mag = hypot(pullX, pullY)
        let heading: Double = mag > 6 ? atan2(pullY, pullX) : -.pi / 2
        return GlideState(
            position: clampInside(pos),
            rotation: heading,
            scale: 1.06,
            shadowSpread: 0.9
        )
    }

    func dragGesture(in size: CGSize) -> some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                if !isDragging {
                    isDragging = true
                    launchDate = nil
                    // Grab from wherever the plane rests.
                    dragOrigin = restOrigin
                }
                dragTranslation = value.translation
            }
            .onEnded { value in
                isDragging = false
                let w = max(size.width, 1)
                let h = max(size.height, 1)
                // Seed the launch vector from the overshoot (predicted - current).
                // `predictedEndTranslation` is available since iOS 13; this avoids relying
                // on `DragGesture.Value.velocity`.
                let overX = value.predictedEndTranslation.width - value.translation.width
                let overY = value.predictedEndTranslation.height - value.translation.height
                let releasePoint = CGPoint(
                    x: dragOrigin.x + value.translation.width / w,
                    y: dragOrigin.y + value.translation.height / h
                )
                let vScale: CGFloat = 1.9
                var v = CGVector(dx: overX / w * vScale, dy: overY / h * vScale)
                v = clampVelocity(v)
                dragOrigin = clampInside(releasePoint)
                launchVelocity = v
                launchDate = Date()
            }
    }
}

// MARK: - Shared glide model (pure function of time)

/// A fully-resolved render state. Computed deterministically from launch params + time;
/// never mutated during the render pass.
private struct GlideState {
    var position: CGPoint      // normalized [0,1] view fractions
    var rotation: Double       // radians; 0 == nose pointing +x
    var scale: CGFloat         // 1 == baseline
    var shadowSpread: CGFloat  // 0 (tight, near ground) .. 1 (soft, high up)
}

private extension FlingPaperPlaneView {
    /// Closed-form glide. No ODE stepping — every value is a direct function of `t`.
    ///
    /// Horizontal drift bleeds off exponentially (lift/drag): `x = v0x·(1 − e^(−k t))/k`.
    /// Vertically the plane holds (lift) then steepens (gravity wins) into a nose-down
    /// descent. Heading follows the velocity derivative so "nosing down to land" falls out
    /// for free. After touchdown the plane is pinned and a damped-sinusoid settle owns the
    /// rotation (so an at-rest `atan2` of near-zero velocity can't jitter the nose).
    func glideState(t: Double, v0: CGVector, origin: CGPoint, in size: CGSize) -> GlideState {
        guard t > 0 else { return restState(at: origin) }

        let k: Double = 1.55         // horizontal drag constant
        let gravity: Double = 0.46   // descent strength
        let lift: Double = 0.34      // early upward hold
        let ground: CGFloat = 0.82   // landing height (view fraction)

        let raw = trajectory(t: t, v0: v0, origin: origin, k: k, gravity: gravity, lift: lift)
        let tLand = landingTime(v0: v0, origin: origin, k: k, gravity: gravity,
                                lift: lift, ground: ground)

        if t >= tLand {
            // Post-landing: pin on the ground; rotation eases via a damped wobble settle.
            let landed = trajectory(t: tLand, v0: v0, origin: origin,
                                    k: k, gravity: gravity, lift: lift)
            let landedPos = CGPoint(x: landed.x, y: Double(ground))
            let settle = landingSettle(since: t - tLand)
            return GlideState(
                position: clampInside(landedPos),
                rotation: settle,
                scale: 1.0,
                shadowSpread: 0.05
            )
        }

        // In-flight: heading from the trajectory's velocity, plus pitch-bob and bank.
        let vel = trajectoryVelocity(t: t, v0: v0, k: k, gravity: gravity, lift: lift)
        let heading = atan2(vel.dy, vel.dx)
        let pitchBob: Double = 0.10 * sin(t * 6.2)
        let bank = bankAngle(forwardSpeed: vel.dx)
        let altitude = max(0.0, Double((ground - CGFloat(raw.y)) / ground))

        return GlideState(
            position: clampInside(raw),
            rotation: heading + pitchBob + bank,
            scale: 1.0 + 0.05 * CGFloat(altitude),
            shadowSpread: CGFloat(altitude)
        )
    }

    /// Closed-form position at time `t` (normalized view fractions).
    func trajectory(t: Double, v0: CGVector, origin: CGPoint,
                    k: Double, gravity: Double, lift: Double) -> CGPoint {
        let decay = (1.0 - exp(-k * t)) / k
        let x = Double(origin.x) + Double(v0.dx) * decay
        // Vertical: initial velocity (incl. lift hold) bleeds via the same decay,
        // then gravity adds an accelerating downward term.
        let vy0 = Double(v0.dy) - lift   // more negative early -> rises/holds
        let y = Double(origin.y) + vy0 * decay + 0.5 * gravity * t * t
        return CGPoint(x: x, y: y)
    }

    /// Analytic velocity (derivative of `trajectory`) used for the flight heading.
    func trajectoryVelocity(t: Double, v0: CGVector,
                            k: Double, gravity: Double, lift: Double) -> CGVector {
        let dDecay = exp(-k * t)         // d/dt of (1 − e^(−k t))/k
        let vx = Double(v0.dx) * dDecay
        let vy0 = Double(v0.dy) - lift
        let vy = vy0 * dDecay + gravity * t
        return CGVector(dx: vx, dy: vy)
    }

    /// Find (by sampling) the first time the path crosses the ground line.
    func landingTime(v0: CGVector, origin: CGPoint, k: Double, gravity: Double,
                     lift: Double, ground: CGFloat) -> Double {
        var t = 0.04
        let step = 0.02
        let limit = 6.0
        while t < limit {
            let p = trajectory(t: t, v0: v0, origin: origin,
                               k: k, gravity: gravity, lift: lift)
            if CGFloat(p.y) >= ground { return t }
            t += step
        }
        return limit
    }

    /// Damped-sinusoid settle for the post-landing nose wobble, easing to level (0).
    func landingSettle(since dt: Double) -> Double {
        let amp = 0.20
        let damp = 5.0
        let omega = 13.0
        return amp * exp(-damp * dt) * cos(omega * dt)
    }

    /// Bank scaled by forward speed — faster drift, more bank.
    func bankAngle(forwardSpeed vx: Double) -> Double {
        let normalized = max(-1.0, min(1.0, vx / 0.8))
        return 0.12 * normalized
    }

    func restState(at origin: CGPoint) -> GlideState {
        GlideState(
            position: origin,
            rotation: -.pi / 2 + 0.05,   // resting nose slightly up
            scale: 1.0,
            shadowSpread: 0.05
        )
    }

    func clampInside(_ p: CGPoint) -> CGPoint {
        CGPoint(
            x: min(0.94, max(0.06, p.x)),
            y: min(0.92, max(0.06, p.y))
        )
    }

    func clampVelocity(_ v: CGVector) -> CGVector {
        let maxMag: CGFloat = 1.7
        let mag = hypot(v.dx, v.dy)
        guard mag > maxMag else { return v }
        let s = maxMag / mag
        return CGVector(dx: v.dx * s, dy: v.dy * s)
    }
}

// MARK: - Rendering

private extension FlingPaperPlaneView {
    func planeAndShadow(state: GlideState, in size: CGSize) -> some View {
        let span = min(size.width, size.height)
        let planeSize = span * 0.22 * state.scale
        let center = CGPoint(x: state.position.x * size.width,
                             y: state.position.y * size.height)
        // Contact shadow sits below the plane; softens & spreads with altitude.
        let shadowDrop = span * (0.06 + 0.18 * state.shadowSpread)
        let shadowScale = 1.0 - 0.45 * state.shadowSpread
        let shadowOpacity = 0.30 - 0.18 * Double(state.shadowSpread)

        return ZStack {
            Ellipse()
                .fill(Color(red: 0, green: 0, blue: 0).opacity(shadowOpacity))
                .frame(width: planeSize * 0.9 * shadowScale,
                       height: planeSize * 0.26 * shadowScale)
                .blur(radius: 3 + 6 * state.shadowSpread)
                .position(x: center.x, y: center.y + shadowDrop)

            PaperPlaneShape()
                .fill(planeBodyGradient)
                .overlay(
                    PaperPlaneShape()
                        .stroke(Color(red: 1, green: 1, blue: 1).opacity(0.55),
                                lineWidth: 0.8)
                )
                .overlay(
                    PaperCreaseShape()
                        .stroke(Color(red: 0.10, green: 0.12, blue: 0.20).opacity(0.5),
                                lineWidth: 0.8)
                )
                .frame(width: planeSize, height: planeSize)
                .rotationEffect(.radians(state.rotation))
                .shadow(color: Color(red: 0, green: 0, blue: 0).opacity(0.25),
                        radius: 2, x: 0, y: 1)
                .position(center)
        }
    }

    var planeBodyGradient: LinearGradient {
        LinearGradient(
            colors: [
                Color(red: 0.98, green: 0.98, blue: 1.0),
                Color(red: 0.80, green: 0.84, blue: 0.94)
            ],
            startPoint: .topLeading,
            endPoint: .bottomTrailing
        )
    }

    /// A faint motion trail behind the plane while it is airborne and moving.
    func glideTrail(state: GlideState, in size: CGSize) -> some View {
        let span = min(size.width, size.height)
        let center = CGPoint(x: state.position.x * size.width,
                             y: state.position.y * size.height)
        let len = span * 0.5 * state.shadowSpread
        let dx = cos(state.rotation)
        let dy = sin(state.rotation)
        let tail = CGPoint(x: center.x - dx * len, y: center.y - dy * len)
        let tipOpacity = 0.22 * Double(state.shadowSpread)

        return Path { p in
            p.move(to: center)
            p.addLine(to: tail)
        }
        .stroke(
            LinearGradient(
                colors: [
                    Color(red: 1, green: 1, blue: 1).opacity(0.0),
                    Color(red: 0.7, green: 0.8, blue: 1.0).opacity(tipOpacity)
                ],
                startPoint: .leading,
                endPoint: .trailing
            ),
            style: StrokeStyle(lineWidth: 2, lineCap: .round)
        )
        .allowsHitTesting(false)
    }

    func landingPad(at origin: CGPoint, in size: CGSize) -> some View {
        let w = min(size.width, size.height) * 0.22
        let p = CGPoint(x: origin.x * size.width, y: origin.y * size.height)
        return Capsule()
            .fill(Color(red: 1, green: 1, blue: 1).opacity(0.05))
            .frame(width: w, height: w * 0.16)
            .position(x: p.x, y: p.y + w * 0.30)
            .allowsHitTesting(false)
    }
}

// MARK: - Plane geometry

/// A folded paper-plane silhouette. Nose points toward +x (rotation 0).
private struct PaperPlaneShape: Shape {
    func path(in rect: CGRect) -> Path {
        var p = Path()
        let w = rect.width
        let h = rect.height
        let nose = CGPoint(x: rect.minX + w * 0.98, y: rect.midY)
        let topTail = CGPoint(x: rect.minX + w * 0.02, y: rect.minY + h * 0.16)
        let tailNotch = CGPoint(x: rect.minX + w * 0.28, y: rect.midY)
        let bottomTail = CGPoint(x: rect.minX + w * 0.02, y: rect.maxY - h * 0.16)

        p.move(to: nose)
        p.addLine(to: topTail)
        p.addLine(to: tailNotch)
        p.addLine(to: bottomTail)
        p.closeSubpath()
        return p
    }
}

/// The center crease line of the fold (drawn as a subtle dividing line).
private struct PaperCreaseShape: Shape {
    func path(in rect: CGRect) -> Path {
        var p = Path()
        let nose = CGPoint(x: rect.minX + rect.width * 0.98, y: rect.midY)
        let tail = CGPoint(x: rect.minX + rect.width * 0.28, y: rect.midY)
        p.move(to: nose)
        p.addLine(to: tail)
        return p
    }
}
"""###,
        "ges-fling-pinball-bumpers": ###"""
import SwiftUI

// MARK: - FlingPinballBumpersView
// Fling a ball into a field of bumpers. Each hit reflects the ball with a touch
// of extra energy (restitution > 1) and flashes / scale-pops the bumper. The ball
// ricochets, decays with friction, and (interactively) you can fling it with a drag.
// demo == true  -> self-playing: auto re-launches the ball every few seconds.
// demo == false -> drag to fling; physics keeps coasting between flings.
struct FlingPinballBumpersView: View {
    var demo: Bool = false

    // MARK: Simulation state
    @State private var sim = PinballSim()
    @State private var lastTick: Date? = nil
    @State private var lastLaunch: Date? = nil
    @State private var configuredSize: CGSize = .zero
    @State private var hitCount: Int = 0
    @State private var dragStart: CGPoint? = nil

    var body: some View {
        GeometryReader { geo in
            TimelineView(.animation) { context in
                Canvas { ctx, _ in
                    drawField(into: ctx, size: geo.size, now: context.date)
                } symbols: {
                    // no external symbols needed
                }
                .contentShape(Rectangle())
                .gesture(flingGesture(size: geo.size))
                .onChange(of: context.date) { _, now in
                    advance(now: now, size: geo.size)
                }
            }
            .onChange(of: geo.size) { _, newSize in
                configureIfNeeded(size: newSize)
            }
            .onAppear { configureIfNeeded(size: geo.size) }
        }
        .background(boardBackground)
        .clipShape(RoundedRectangle(cornerRadius: 18, style: .continuous))
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .sensoryFeedback(.impact(flexibility: .soft), trigger: hitCount)
    }

    // MARK: Background
    private var boardBackground: some View {
        RoundedRectangle(cornerRadius: 18, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.05, green: 0.05, blue: 0.10),
                        Color(red: 0.10, green: 0.08, blue: 0.18)
                    ],
                    startPoint: .top,
                    endPoint: .bottom
                )
            )
    }

    // MARK: Configuration (first valid frame only)
    private func configureIfNeeded(size: CGSize) {
        guard size.width > 1, size.height > 1 else { return }
        guard size != configuredSize else { return }
        configuredSize = size
        sim.configure(size: size)
        if lastLaunch == nil {
            // Seed an initial launch so demo never starts blank / static.
            launch(in: size, seededByTime: true)
        } else {
            // On resize, keep the ball but re-clamp it into the new bounds.
            sim.clampIntoBounds(size: size)
        }
    }

    // MARK: Per-frame advance
    private func advance(now: Date, size: CGSize) {
        guard size.width > 1, size.height > 1 else { return }
        guard sim.isConfigured else {
            configureIfNeeded(size: size)
            lastTick = now
            return
        }

        let previous: Date = lastTick ?? now
        lastTick = now
        var dt: Double = now.timeIntervalSince(previous)
        if dt <= 0 { return }
        // Clamp dt so a stalled frame can't teleport the ball through a bumper.
        dt = min(dt, 1.0 / 30.0)

        // Demo: time-based re-launch keeps it alive regardless of where the ball rests.
        if demo {
            let elapsed: Double = now.timeIntervalSince(lastLaunch ?? now)
            if elapsed > 3.4 {
                launch(in: size, seededByTime: true)
            }
        }

        let hits: Int = sim.step(dt: dt, size: size, now: now)
        if hits > 0 {
            hitCount += hits
        }
    }

    // MARK: Launch helpers
    private func launch(in size: CGSize, seededByTime: Bool) {
        let now = Date()
        lastLaunch = now
        sim.resetBall(size: size, now: now, seeded: seededByTime)
    }

    private func flingGesture(size: CGSize) -> some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                if dragStart == nil {
                    dragStart = value.startLocation
                    // Park the ball under the finger while aiming.
                    sim.holdBall(at: value.location, size: size)
                } else {
                    sim.holdBall(at: value.location, size: size)
                }
            }
            .onEnded { value in
                dragStart = nil
                // velocity is CGSize, points/sec, available iOS 17+.
                let v: CGSize = value.velocity
                sim.flingBall(from: value.location, velocity: v, size: size)
                lastLaunch = Date()
            }
    }

    // MARK: Drawing
    private func drawField(into ctx: GraphicsContext, size: CGSize, now: Date) {
        guard sim.isConfigured else { return }
        drawWalls(into: ctx, size: size)
        for bumper in sim.bumpers {
            drawBumper(bumper, into: ctx, size: size, now: now)
        }
        drawBall(into: ctx, size: size)
    }

    private func drawWalls(into ctx: GraphicsContext, size: CGSize) {
        let inset: CGFloat = wallInset(size)
        let rect = CGRect(
            x: inset, y: inset,
            width: size.width - inset * 2,
            height: size.height - inset * 2
        )
        let path = Path(roundedRect: rect, cornerRadius: 14, style: .continuous)
        ctx.stroke(
            path,
            with: .color(Color(red: 0.30, green: 0.34, blue: 0.55).opacity(0.55)),
            lineWidth: max(1.0, size.width * 0.012)
        )
    }

    private func drawBumper(_ bumper: Bumper, into ctx: GraphicsContext, size: CGSize, now: Date) {
        let center = bumper.center(in: size)
        let radius: CGFloat = bumper.radius(in: size)
        let pop: CGFloat = bumper.popScale(now: now)
        let glow: Double = bumper.glow(now: now)
        let r: CGFloat = radius * pop

        let rect = CGRect(x: center.x - r, y: center.y - r, width: r * 2, height: r * 2)

        // Outer halo when freshly hit.
        if glow > 0.02 {
            let haloR: CGFloat = r * 1.55
            let haloRect = CGRect(
                x: center.x - haloR, y: center.y - haloR,
                width: haloR * 2, height: haloR * 2
            )
            ctx.fill(
                Circle().path(in: haloRect),
                with: .color(bumper.tint.color.opacity(0.35 * glow))
            )
        }

        // Body with a radial-ish gradient feel (two stacked fills).
        let base: RGB = bumper.tint
        let lit: RGB = base.mix(with: .white, amount: 0.55 * glow + 0.10)
        ctx.fill(Circle().path(in: rect), with: .color(lit.color))

        let innerR: CGFloat = r * 0.62
        let innerRect = CGRect(
            x: center.x - innerR, y: center.y - innerR,
            width: innerR * 2, height: innerR * 2
        )
        ctx.fill(
            Circle().path(in: innerRect),
            with: .color(base.mix(with: .black, amount: 0.25).color)
        )

        // Bright center cap.
        let capR: CGFloat = r * 0.30
        let capRect = CGRect(
            x: center.x - capR, y: center.y - capR,
            width: capR * 2, height: capR * 2
        )
        ctx.fill(
            Circle().path(in: capRect),
            with: .color(RGB.white.mix(with: base, amount: 0.30).color.opacity(0.85))
        )

        // Rim ring.
        ctx.stroke(
            Circle().path(in: rect),
            with: .color(Color.white.opacity(0.25 + 0.5 * glow)),
            lineWidth: max(1.0, r * 0.07)
        )
    }

    private func drawBall(into ctx: GraphicsContext, size: CGSize) {
        let radius: CGFloat = sim.ballRadius(in: size)
        let p = sim.ball
        // Contact shadow.
        let shadowRect = CGRect(
            x: p.x - radius * 1.05,
            y: p.y - radius * 0.85 + radius * 0.6,
            width: radius * 2.1,
            height: radius * 1.7
        )
        ctx.fill(Ellipse().path(in: shadowRect), with: .color(Color.black.opacity(0.30)))

        let rect = CGRect(x: p.x - radius, y: p.y - radius, width: radius * 2, height: radius * 2)
        // Steel body.
        ctx.fill(
            Circle().path(in: rect),
            with: .color(Color(red: 0.78, green: 0.82, blue: 0.90))
        )
        // Shading underside.
        let lowR: CGFloat = radius * 0.85
        let lowRect = CGRect(
            x: p.x - lowR + radius * 0.10,
            y: p.y - lowR + radius * 0.25,
            width: lowR * 2, height: lowR * 2
        )
        ctx.fill(
            Circle().path(in: lowRect),
            with: .color(Color(red: 0.45, green: 0.50, blue: 0.62).opacity(0.65))
        )
        // Specular highlight.
        let hiR: CGFloat = radius * 0.34
        let hiRect = CGRect(
            x: p.x - radius * 0.40 - hiR * 0.5,
            y: p.y - radius * 0.40 - hiR * 0.5,
            width: hiR * 2, height: hiR * 2
        )
        ctx.fill(Circle().path(in: hiRect), with: .color(Color.white.opacity(0.9)))
    }

    // MARK: Layout helpers
    private func wallInset(_ size: CGSize) -> CGFloat {
        return min(size.width, size.height) * 0.04
    }
}

// MARK: - Self-contained RGB color (no UIKit dependency)
private struct RGB {
    var r: Double
    var g: Double
    var b: Double

    var color: Color { Color(red: r, green: g, blue: b) }

    static let white = RGB(r: 1, g: 1, b: 1)
    static let black = RGB(r: 0, g: 0, b: 0)

    func mix(with other: RGB, amount: Double) -> RGB {
        let t = max(0.0, min(1.0, amount))
        return RGB(
            r: r + (other.r - r) * t,
            g: g + (other.g - g) * t,
            b: b + (other.b - b) * t
        )
    }
}

// MARK: - Bumper model
private struct Bumper: Identifiable {
    let id: Int
    var nx: CGFloat          // normalized center x [0,1]
    var ny: CGFloat          // normalized center y [0,1]
    var nr: CGFloat          // normalized radius (relative to min dimension)
    var tint: RGB
    var lastHit: Date? = nil

    func center(in size: CGSize) -> CGPoint {
        CGPoint(x: nx * size.width, y: ny * size.height)
    }

    func radius(in size: CGSize) -> CGFloat {
        nr * min(size.width, size.height)
    }

    // Brief spring-like scale pop after a hit (decays over ~0.45s).
    func popScale(now: Date) -> CGFloat {
        guard let hit = lastHit else { return 1.0 }
        let t: Double = now.timeIntervalSince(hit)
        if t < 0 || t > 0.5 { return 1.0 }
        let decay: Double = exp(-t * 9.0)
        let wobble: Double = sin(t * 26.0)
        return 1.0 + CGFloat(0.22 * decay * wobble + 0.10 * decay)
    }

    // Flash brightness after a hit (decays over ~0.35s).
    func glow(now: Date) -> Double {
        guard let hit = lastHit else { return 0 }
        let t: Double = now.timeIntervalSince(hit)
        if t < 0 || t > 0.5 { return 0 }
        return exp(-t * 8.0)
    }
}

// MARK: - Pinball simulation
private struct PinballSim {
    var ball: CGPoint = .zero
    var velocity: CGSize = .zero      // points / second
    var bumpers: [Bumper] = []
    var isConfigured: Bool = false
    var held: Bool = false

    // Tunable constants (relative to min dimension where spatial).
    private let ballNR: CGFloat = 0.052
    private let friction: Double = 0.55          // per-second velocity retention base
    private let restitution: Double = 1.08       // > 1 adds energy on bumper hits
    private let wallRestitution: Double = 0.86
    private let maxSpeedFactor: Double = 3.2     // * minDim per second (anti-runaway)
    private let minLaunchFactor: Double = 1.6

    func ballRadius(in size: CGSize) -> CGFloat {
        ballNR * min(size.width, size.height)
    }

    private func wallInset(_ size: CGSize) -> CGFloat {
        min(size.width, size.height) * 0.04
    }

    mutating func configure(size: CGSize) {
        bumpers = Self.makeBumpers()
        if !isConfigured {
            ball = CGPoint(x: size.width * 0.5, y: size.height * 0.72)
            velocity = .zero
        }
        isConfigured = true
    }

    private static func makeBumpers() -> [Bumper] {
        // Normalized layout — looks balanced in a tile and a big detail view.
        let tintA = RGB(r: 0.96, g: 0.36, b: 0.45)
        let tintB = RGB(r: 0.36, g: 0.72, b: 0.98)
        let tintC = RGB(r: 0.99, g: 0.78, b: 0.30)
        let tintD = RGB(r: 0.55, g: 0.92, b: 0.62)
        return [
            Bumper(id: 0, nx: 0.30, ny: 0.26, nr: 0.105, tint: tintA),
            Bumper(id: 1, nx: 0.70, ny: 0.26, nr: 0.105, tint: tintB),
            Bumper(id: 2, nx: 0.50, ny: 0.45, nr: 0.115, tint: tintC),
            Bumper(id: 3, nx: 0.25, ny: 0.60, nr: 0.090, tint: tintD),
            Bumper(id: 4, nx: 0.75, ny: 0.60, nr: 0.090, tint: tintD),
            Bumper(id: 5, nx: 0.50, ny: 0.78, nr: 0.080, tint: tintA)
        ]
    }

    private func maxSpeed(in size: CGSize) -> Double {
        maxSpeedFactor * Double(min(size.width, size.height))
    }

    mutating func clampIntoBounds(size: CGSize) {
        let r: CGFloat = ballRadius(in: size)
        let inset: CGFloat = wallInset(size)
        ball.x = min(max(ball.x, inset + r), size.width - inset - r)
        ball.y = min(max(ball.y, inset + r), size.height - inset - r)
    }

    mutating func resetBall(size: CGSize, now: Date, seeded: Bool) {
        held = false
        ball = CGPoint(x: size.width * 0.5, y: size.height * 0.80)
        let minDim = Double(min(size.width, size.height))
        if seeded {
            // Aim generally upward into the bumper field, with horizontal variety.
            let spread: Double = Double.random(in: -0.5 ... 0.5)
            let speed: Double = minDim * Double.random(in: 1.9 ... 2.6)
            let angle: Double = (-Double.pi / 2) + spread
            velocity = CGSize(width: cos(angle) * speed, height: sin(angle) * speed)
        }
    }

    mutating func holdBall(at point: CGPoint, size: CGSize) {
        held = true
        velocity = .zero
        ball = point
        clampIntoBounds(size: size)
    }

    mutating func flingBall(from point: CGPoint, velocity v: CGSize, size: CGSize) {
        held = false
        ball = point
        clampIntoBounds(size: size)
        var vx = Double(v.width)
        var vy = Double(v.height)
        let minDim = Double(min(size.width, size.height))
        let minLaunch = minLaunchFactor * minDim
        let speed = (vx * vx + vy * vy).squareRoot()
        if speed < minLaunch {
            // Give a gentle default shove upward if the flick was tiny.
            if speed < 1 {
                vx = 0
                vy = -minLaunch
            } else {
                let scale = minLaunch / speed
                vx *= scale
                vy *= scale
            }
        }
        velocity = CGSize(width: vx, height: vy)
        clampSpeed(in: size)
    }

    private mutating func clampSpeed(in size: CGSize) {
        let limit = maxSpeed(in: size)
        let vx = Double(velocity.width)
        let vy = Double(velocity.height)
        let s = (vx * vx + vy * vy).squareRoot()
        if s > limit, s > 0 {
            let k = limit / s
            velocity = CGSize(width: vx * k, height: vy * k)
        }
    }

    // Returns number of bumper hits this frame (for haptics).
    mutating func step(dt: Double, size: CGSize, now: Date) -> Int {
        if held { return 0 }
        var hits = 0
        let substeps = 3
        let h = dt / Double(substeps)
        for _ in 0..<substeps {
            hits += integrate(h: h, size: size, now: now)
        }
        // Friction (frame-rate independent exponential-ish decay).
        let retain = pow(friction, dt)
        velocity = CGSize(width: Double(velocity.width) * retain,
                          height: Double(velocity.height) * retain)
        // Settle to rest if very slow to avoid endless micro-drift.
        let minDim = Double(min(size.width, size.height))
        let restThreshold = minDim * 0.06
        let sp = (Double(velocity.width) * Double(velocity.width)
                  + Double(velocity.height) * Double(velocity.height)).squareRoot()
        if sp < restThreshold {
            velocity = CGSize(width: Double(velocity.width) * 0.85,
                              height: Double(velocity.height) * 0.85)
        }
        return hits
    }

    private mutating func integrate(h: Double, size: CGSize, now: Date) -> Int {
        ball.x += CGFloat(Double(velocity.width) * h)
        ball.y += CGFloat(Double(velocity.height) * h)
        var hits = 0
        hits += resolveWalls(size: size)
        hits += resolveBumpers(size: size, now: now)
        clampSpeed(in: size)
        return hits
    }

    private mutating func resolveWalls(size: CGSize) -> Int {
        let r: CGFloat = ballRadius(in: size)
        let inset: CGFloat = wallInset(size)
        let left = inset + r
        let right = size.width - inset - r
        let top = inset + r
        let bottom = size.height - inset - r
        var bounced = false

        if ball.x < left {
            ball.x = left
            velocity.width = abs(velocity.width) * CGFloat(wallRestitution)
            bounced = true
        } else if ball.x > right {
            ball.x = right
            velocity.width = -abs(velocity.width) * CGFloat(wallRestitution)
            bounced = true
        }
        if ball.y < top {
            ball.y = top
            velocity.height = abs(velocity.height) * CGFloat(wallRestitution)
            bounced = true
        } else if ball.y > bottom {
            ball.y = bottom
            velocity.height = -abs(velocity.height) * CGFloat(wallRestitution)
            bounced = true
        }
        return bounced ? 0 : 0   // wall bounces don't fire bumper haptics
    }

    private mutating func resolveBumpers(size: CGSize, now: Date) -> Int {
        let br: CGFloat = ballRadius(in: size)
        var hits = 0
        for i in bumpers.indices {
            let c = bumpers[i].center(in: size)
            let rad = bumpers[i].radius(in: size)
            let dx = Double(ball.x - c.x)
            let dy = Double(ball.y - c.y)
            let dist = (dx * dx + dy * dy).squareRoot()
            let minDist = Double(br + rad)
            if dist < minDist && dist > 0.0001 {
                // Push ball out along the contact normal.
                let nx = dx / dist
                let ny = dy / dist
                let overlap = minDist - dist
                ball.x += CGFloat(nx * overlap)
                ball.y += CGFloat(ny * overlap)

                // Reflect velocity about the normal, add restitution energy.
                let vx = Double(velocity.width)
                let vy = Double(velocity.height)
                let vDotN = vx * nx + vy * ny
                if vDotN < 0 {
                    let rx = vx - 2 * vDotN * nx
                    let ry = vy - 2 * vDotN * ny
                    velocity = CGSize(width: rx * restitution, height: ry * restitution)
                    // Add a small radial kick so it feels lively even on grazes.
                    let minDim = Double(min(size.width, size.height))
                    let kick = minDim * 0.20
                    velocity.width += CGFloat(nx * kick)
                    velocity.height += CGFloat(ny * kick)
                    clampSpeed(in: size)
                    bumpers[i].lastHit = now
                    hits += 1
                }
            }
        }
        return hits
    }
}
"""###,
        "ges-fling-spinner-coast": ###"""
import SwiftUI

/// Fortune Wheel Flick — flick a segmented wheel and it spins with angular
/// momentum, a ticking flap clacking past each segment and slowing with
/// friction until the pointer eases into a final wedge.
///
/// - `demo == true`  : self-driving loop re-flicks the wheel every cycle.
/// - `demo == false` : real `DragGesture` flick with friction-decay coast,
///                     analytic snap-to-wedge, deflecting clicker flap and
///                     per-tick haptics.
struct FlingSpinnerCoastView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { geo in
            let side = min(geo.size.width, geo.size.height)
            let center = CGPoint(x: geo.size.width / 2, y: geo.size.height / 2)

            if demo {
                DemoSpinner(side: side, center: center)
            } else {
                InteractiveSpinner(side: side, center: center)
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .background(Color(red: 0.051, green: 0.055, blue: 0.086))
    }
}

// MARK: - Shared geometry / palette

private enum Wheel {
    static let segments: Int = 8
    static var seg: Double { (2 * .pi) / Double(segments) }

    /// The fixed pointer sits at 12 o'clock. In screen space that direction is
    /// `-.pi/2` (straight up). A wedge "center" is what we want resting under
    /// the pointer, so the snap target solves for the wedge center aligning
    /// with the pointer angle.
    static let pointerAngle: Double = -.pi / 2

    /// Decay constant (1/seconds). k·cycleDuration must stay ≥ ~5 so the
    /// residual position gap at a demo cycle boundary is invisible.
    static let friction: Double = 1.9

    static let wedgeColors: [Color] = [
        Color(red: 0.93, green: 0.36, blue: 0.42),
        Color(red: 0.98, green: 0.70, blue: 0.32),
        Color(red: 0.40, green: 0.80, blue: 0.58),
        Color(red: 0.36, green: 0.62, blue: 0.93),
        Color(red: 0.74, green: 0.50, blue: 0.93),
        Color(red: 0.98, green: 0.52, blue: 0.66),
        Color(red: 0.46, green: 0.84, blue: 0.86),
        Color(red: 0.96, green: 0.84, blue: 0.40)
    ]

    /// Rotation that lands the nearest wedge center under the fixed pointer.
    ///
    /// Wedge `i` spans `[i·seg, (i+1)·seg]` with center `i·seg + seg/2`. After a
    /// wheel rotation `θ` that center sits at screen angle `i·seg + seg/2 + θ`.
    /// Requiring it to equal `pointerAngle` gives valid rotations
    /// `θ = (pointerAngle - seg/2) + n·seg`. We snap to the one nearest `rest`.
    static func snappedRest(_ rest: Double) -> Double {
        let offset = pointerAngle - seg / 2
        let n = (rest - offset) / seg
        return n.rounded() * seg + offset
    }
}

// MARK: - Spin model (pure, analytic)

private struct SpinModel {
    /// angle(t) = S − (S − start)·exp(−k·t)
    /// At t=0 → start, at t→∞ → S (a snapped wedge center under the pointer).
    static func angle(start: Double, target: Double, elapsed: Double) -> Double {
        let k = Wheel.friction
        return target - (target - start) * exp(-k * elapsed)
    }

    /// Instantaneous angular speed magnitude — drives flap deflection so the
    /// clicker only flicks while the wheel is actually moving.
    static func angularSpeed(start: Double, target: Double, elapsed: Double) -> Double {
        let k = Wheel.friction
        return abs((target - start) * k * exp(-k * elapsed))
    }

    /// Signed direction of rotation (for flap lean side).
    static func direction(start: Double, target: Double) -> Double {
        (target - start) >= 0 ? 1 : -1
    }
}

// MARK: - Demo (self-driving)

private struct DemoSpinner: View {
    let side: CGFloat
    let center: CGPoint

    private let cycle: Double = 3.4

    var body: some View {
        TimelineView(.animation) { context in
            let t = context.date.timeIntervalSinceReferenceDate
            let cycleIndex = floor(t / cycle)
            let tau = t - cycleIndex * cycle

            // Each cycle advances an integer number of wedges so every target
            // is a true wedge center; accumulating the base gives a continuous
            // re-flick with no backwards jump.
            let wedgesPerCycle: Double = 5
            let baseStart = Wheel.snappedRest(0)
            let start = baseStart + cycleIndex * wedgesPerCycle * Wheel.seg
            let target = start + wedgesPerCycle * Wheel.seg

            let angle = SpinModel.angle(start: start, target: target, elapsed: tau)
            let speed = SpinModel.angularSpeed(start: start, target: target, elapsed: tau)
            let dir = SpinModel.direction(start: start, target: target)

            SpinnerStage(
                side: side,
                center: center,
                rotation: angle,
                flapDeflection: flapDeflection(angle: angle, speed: speed, dir: dir),
                tickIndex: 0,
                hapticsEnabled: false
            )
        }
    }
}

// MARK: - Interactive

private struct InteractiveSpinner: View {
    let side: CGFloat
    let center: CGPoint

    // Coasting state
    @State private var startAngle: Double = Wheel.snappedRest(0)
    @State private var targetAngle: Double = Wheel.snappedRest(0)
    @State private var flingDate: Date = .distantPast

    // Dragging state
    @State private var isDragging: Bool = false
    @State private var dragBaseAngle: Double = Wheel.snappedRest(0)
    @State private var accumulatedFinger: Double = 0
    @State private var lastFingerAngle: Double = 0

    var body: some View {
        TimelineView(.animation) { context in
            let elapsed = context.date.timeIntervalSince(flingDate)
            let render = renderState(elapsed: elapsed)

            SpinnerStage(
                side: side,
                center: center,
                rotation: render.angle,
                flapDeflection: flapDeflection(angle: render.angle, speed: render.speed, dir: render.dir),
                tickIndex: render.tickIndex,
                hapticsEnabled: true
            )
        }
        .contentShape(Rectangle())
        .gesture(spinGesture)
    }

    private struct RenderState {
        var angle: Double
        var speed: Double
        var dir: Double
        var tickIndex: Int
    }

    private func renderState(elapsed: Double) -> RenderState {
        let angle: Double
        let speed: Double
        let dir: Double
        if isDragging {
            angle = dragBaseAngle + accumulatedFinger
            speed = 0
            dir = accumulatedFinger >= 0 ? 1 : -1
        } else {
            angle = SpinModel.angle(start: startAngle, target: targetAngle, elapsed: max(0, elapsed))
            speed = SpinModel.angularSpeed(start: startAngle, target: targetAngle, elapsed: max(0, elapsed))
            dir = SpinModel.direction(start: startAngle, target: targetAngle)
        }
        let tickIndex = Int(floor(angle / Wheel.seg))
        return RenderState(angle: angle, speed: speed, dir: dir, tickIndex: tickIndex)
    }

    private var spinGesture: some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                let fingerAngle = atan2(
                    value.location.y - center.y,
                    value.location.x - center.x
                )
                if !isDragging {
                    isDragging = true
                    // Resume from wherever the coast currently sits.
                    let elapsed = Date().timeIntervalSince(flingDate)
                    dragBaseAngle = SpinModel.angle(
                        start: startAngle, target: targetAngle, elapsed: max(0, elapsed)
                    )
                    accumulatedFinger = 0
                    lastFingerAngle = fingerAngle
                }
                // Normalize wrap-around to [-pi, pi] so crossing the atan2 seam
                // doesn't produce a giant jump.
                var delta = fingerAngle - lastFingerAngle
                if delta > .pi { delta -= 2 * .pi }
                if delta < -.pi { delta += 2 * .pi }
                accumulatedFinger += delta
                lastFingerAngle = fingerAngle
            }
            .onEnded { value in
                let current = dragBaseAngle + accumulatedFinger
                let omega = angularVelocity(value: value)

                // Natural exponential rest, then snap that rest to a wedge center.
                let rest = current + omega / Wheel.friction
                let snapped = Wheel.snappedRest(rest)

                startAngle = current
                targetAngle = snapped
                flingDate = Date()

                isDragging = false
                accumulatedFinger = 0
            }
    }

    /// Angular launch velocity from the drag's predicted end (iOS 17-safe).
    private func angularVelocity(value: DragGesture.Value) -> Double {
        let rx = value.location.x - center.x
        let ry = value.location.y - center.y
        let r2 = rx * rx + ry * ry
        guard r2 > 1 else { return 0 }

        // Predicted "remaining" motion is proportional to release velocity.
        let px = value.predictedEndTranslation.width - value.translation.width
        let py = value.predictedEndTranslation.height - value.translation.height

        let gain: Double = 7.5
        let cross = rx * py - ry * px
        return gain * cross / r2
    }
}

// MARK: - Flap deflection (shared, analytic)

/// The clicker flap deflects sharply as a peg passes 12 o'clock, scaled by the
/// current angular speed so it sits flat at rest. `pow(.., 8)` produces a tight
/// clack right at each boundary that springs back across the wedge.
private func flapDeflection(angle: Double, speed: Double, dir: Double) -> Double {
    let phase = angle / Wheel.seg
    let frac = phase - floor(phase)            // 0..1 across one wedge
    // Distance to the nearest boundary (0 or 1), folded to 0..0.5.
    let toBoundary = min(frac, 1 - frac)
    let edge = pow(1 - toBoundary * 2, 8)      // 1 at a boundary, ~0 mid-wedge
    let speedFactor = min(1.0, speed / 6.0)
    let maxDefl: Double = 0.42
    return maxDefl * speedFactor * edge * (dir >= 0 ? 1 : -1)
}

// MARK: - Visual stage

private struct SpinnerStage: View {
    let side: CGFloat
    let center: CGPoint
    let rotation: Double
    let flapDeflection: Double
    let tickIndex: Int
    let hapticsEnabled: Bool

    var body: some View {
        let r = side * 0.40

        ZStack {
            WheelFace(radius: r)
                .rotationEffect(.radians(rotation))
                .position(center)

            HubCap(radius: r * 0.18)
                .position(center)

            ClickerFlap(radius: r, deflection: flapDeflection)
                .position(x: center.x, y: center.y - r)
        }
        .modifier(TickHaptics(enabled: hapticsEnabled, tickIndex: tickIndex))
    }
}

// MARK: - Wheel face

private struct WheelFace: View {
    let radius: CGFloat

    var body: some View {
        Canvas { ctx, size in
            let c = CGPoint(x: size.width / 2, y: size.height / 2)
            let r = radius
            let seg = Wheel.seg

            // Outer rim
            let rimRect = CGRect(x: c.x - r, y: c.y - r, width: r * 2, height: r * 2)
            ctx.fill(
                Circle().path(in: rimRect.insetBy(dx: -r * 0.06, dy: -r * 0.06)),
                with: .color(Color(red: 0.16, green: 0.17, blue: 0.22))
            )

            // Wedges
            for i in 0..<Wheel.segments {
                let a0 = Double(i) * seg
                let a1 = Double(i + 1) * seg
                var path = Path()
                path.move(to: c)
                path.addArc(
                    center: c,
                    radius: r,
                    startAngle: .radians(a0),
                    endAngle: .radians(a1),
                    clockwise: false
                )
                path.closeSubpath()

                let base = Wheel.wedgeColors[i % Wheel.wedgeColors.count]
                ctx.fill(path, with: .color(base))

                // Subtle radial shade for depth, clipped to the wedge.
                ctx.fill(
                    path,
                    with: .radialGradient(
                        Gradient(colors: [
                            Color.white.opacity(0.12),
                            Color.clear,
                            Color.black.opacity(0.18)
                        ]),
                        center: c,
                        startRadius: 0,
                        endRadius: r
                    )
                )
            }

            // Pegs at each boundary (what the flap clacks against).
            for i in 0..<Wheel.segments {
                let a = Double(i) * seg
                let p = CGPoint(
                    x: c.x + cos(a) * r * 0.97,
                    y: c.y + sin(a) * r * 0.97
                )
                let pegR = r * 0.045
                let pegRect = CGRect(
                    x: p.x - pegR, y: p.y - pegR,
                    width: pegR * 2, height: pegR * 2
                )
                ctx.fill(Circle().path(in: pegRect), with: .color(.white.opacity(0.9)))
                ctx.fill(
                    Circle().path(in: pegRect.insetBy(dx: pegR * 0.4, dy: pegR * 0.4)),
                    with: .color(Color(red: 0.22, green: 0.23, blue: 0.30))
                )
            }
        }
        .frame(width: radius * 2.2, height: radius * 2.2)
    }
}

// MARK: - Hub

private struct HubCap: View {
    let radius: CGFloat

    var body: some View {
        ZStack {
            Circle()
                .fill(
                    RadialGradient(
                        colors: [
                            Color(red: 0.93, green: 0.94, blue: 0.98),
                            Color(red: 0.62, green: 0.64, blue: 0.72)
                        ],
                        center: .topLeading,
                        startRadius: 0,
                        endRadius: radius * 2
                    )
                )
            Circle()
                .stroke(Color.black.opacity(0.25), lineWidth: max(1, radius * 0.12))
        }
        .frame(width: radius * 2, height: radius * 2)
        .shadow(color: .black.opacity(0.4), radius: radius * 0.3, y: radius * 0.2)
    }
}

// MARK: - Clicker flap (fixed at 12 o'clock)

private struct ClickerFlap: View {
    let radius: CGFloat
    let deflection: Double

    var body: some View {
        let w = radius * 0.16
        let h = radius * 0.34

        FlapShape()
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.97, green: 0.97, blue: 1.0),
                        Color(red: 0.78, green: 0.80, blue: 0.88)
                    ],
                    startPoint: .top,
                    endPoint: .bottom
                )
            )
            .overlay(
                FlapShape().stroke(Color.black.opacity(0.25), lineWidth: 1)
            )
            .frame(width: w, height: h)
            .shadow(color: .black.opacity(0.35), radius: 2, y: 1)
            // Pivot at the top so the flap swings like a hinged clicker.
            .rotationEffect(.radians(deflection), anchor: .top)
            .offset(y: -h * 0.15)
    }
}

private struct FlapShape: Shape {
    func path(in rect: CGRect) -> Path {
        var p = Path()
        let topInset = rect.width * 0.12
        p.move(to: CGPoint(x: rect.minX + topInset, y: rect.minY))
        p.addLine(to: CGPoint(x: rect.maxX - topInset, y: rect.minY))
        p.addLine(to: CGPoint(x: rect.maxX - topInset, y: rect.maxY * 0.55))
        p.addLine(to: CGPoint(x: rect.midX, y: rect.maxY))           // point
        p.addLine(to: CGPoint(x: rect.minX + topInset, y: rect.maxY * 0.55))
        p.closeSubpath()
        return p
    }
}

// MARK: - Haptics modifier

private struct TickHaptics: ViewModifier {
    let enabled: Bool
    let tickIndex: Int

    func body(content: Content) -> some View {
        if enabled {
            content.sensoryFeedback(.impact(weight: .light), trigger: tickIndex)
        } else {
            content
        }
    }
}
"""###,
        "ges-gravity-bin-toss": ###"""
import SwiftUI

// MARK: - Gravity Bin Toss
// Fling chips toward a bin; they arc under gravity, bounce off the rim and each
// other, and pile up with stacking collisions. demo == true self-drives by
// auto-tossing one chip per cycle; demo == false reads a DragGesture fling.
//
// Single shared simulation core: only the spawn trigger differs between modes.
// All physics scale to the GeometryReader size so it works in a 120pt tile and
// a large detail area alike. iOS 17. No external dependencies.

struct GravityBinTossView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { geo in
            GravityBinTossCore(demo: demo, size: geo.size)
                .frame(width: geo.size.width, height: geo.size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }
}

// MARK: - GravityBinTossView_Chip model

private struct GravityBinTossView_Chip: Identifiable {
    let id: Int
    var position: CGPoint
    var velocity: CGVector
    var radius: CGFloat
    var spin: CGFloat        // current rotation, radians
    var spinRate: CGFloat    // radians / second
    var hue: Double          // base color hue 0..1
    var settled: Bool = false
    var bornAt: TimeInterval
}

// MARK: - Simulation core

private struct GravityBinTossCore: View {
    let demo: Bool
    let size: CGSize

    @State private var chips: [GravityBinTossView_Chip] = []
    @State private var nextID: Int = 0
    @State private var lastTick: Date? = nil
    @State private var spawnAccumulator: Double = 0
    @State private var collisionCount: Int = 0   // haptic trigger (only bumped when !demo)
    @State private var fadeOut: Double = 1.0      // demo reset fade
    @State private var resetting: Bool = false

    // Live drag preview
    @State private var dragStart: CGPoint? = nil
    @State private var dragCurrent: CGPoint? = nil

    var body: some View {
        TimelineView(.animation) { timeline in
            ZStack {
                background
                Canvas { ctx, _ in
                    drawScene(into: ctx)
                }
                .opacity(fadeOut)

                // Aim preview line while dragging (interactive only).
                aimPreview
            }
            .onChange(of: timeline.date) { _, now in
                tick(now)
            }
        }
        .contentShape(Rectangle())
        .gesture(flingGesture, including: demo ? .subviews : .all)
        .sensoryFeedback(.impact(weight: .light, intensity: 0.6), trigger: collisionCount)
    }

    // MARK: Layout helpers (all proportional to size)

    private var unit: CGFloat { min(size.width, size.height) }

    private var chipRadius: CGFloat { max(unit * 0.052, 3) }

    private var gravity: CGFloat { size.height * 3.4 } // pt / s^2

    private var binRect: CGRect {
        let w = size.width * 0.46
        let h = size.height * 0.5
        let x = (size.width - w) / 2
        let y = size.height - h - size.height * 0.06
        return CGRect(x: x, y: y, width: w, height: h)
    }

    private var wallThickness: CGFloat { max(unit * 0.022, 2) }

    private var floorY: CGFloat { binRect.maxY }

    private var maxChips: Int { 16 }

    // Spawn origin for demo / auto toss.
    private var spawnPoint: CGPoint {
        CGPoint(x: size.width * 0.16, y: size.height * 0.26)
    }

    // MARK: Background

    private var background: some View {
        LinearGradient(
            colors: [
                Color(red: 0.05, green: 0.055, blue: 0.09),
                Color(red: 0.10, green: 0.11, blue: 0.17)
            ],
            startPoint: .top,
            endPoint: .bottom
        )
    }

    // MARK: Aim preview overlay

    @ViewBuilder
    private var aimPreview: some View {
        if let start = dragStart, let current = dragCurrent {
            Path { p in
                p.move(to: start)
                p.addLine(to: current)
            }
            .stroke(
                Color(red: 1.0, green: 0.82, blue: 0.35).opacity(0.55),
                style: StrokeStyle(lineWidth: max(unit * 0.012, 1.5), lineCap: .round, dash: [unit * 0.05, unit * 0.04])
            )
            Circle()
                .fill(Color(red: 1.0, green: 0.82, blue: 0.35).opacity(0.85))
                .frame(width: chipRadius * 1.8, height: chipRadius * 1.8)
                .position(current)
        }
    }

    // MARK: Drawing

    private func drawScene(into ctx: GraphicsContext) {
        drawBin(into: ctx)
        for chip in chips {
            drawChip(chip, into: ctx)
        }
    }

    private func drawBin(into ctx: GraphicsContext) {
        let r = binRect
        let wt = wallThickness
        let rimColor = Color(red: 0.62, green: 0.66, blue: 0.82)
        let innerColor = Color(red: 0.13, green: 0.14, blue: 0.22)

        // Inner well (subtle, so empty bin is never blank-looking).
        let well = Path(roundedRect: r.insetBy(dx: wt * 0.4, dy: wt * 0.4),
                        cornerRadius: wt)
        ctx.fill(well, with: .color(innerColor))

        // Left wall
        let leftWall = Path(roundedRect: CGRect(x: r.minX - wt / 2, y: r.minY, width: wt, height: r.height),
                            cornerRadius: wt / 2)
        // Right wall
        let rightWall = Path(roundedRect: CGRect(x: r.maxX - wt / 2, y: r.minY, width: wt, height: r.height),
                             cornerRadius: wt / 2)
        // Floor
        let floor = Path(roundedRect: CGRect(x: r.minX - wt / 2, y: r.maxY - wt / 2, width: r.width + wt, height: wt),
                         cornerRadius: wt / 2)

        ctx.fill(leftWall, with: .color(rimColor))
        ctx.fill(rightWall, with: .color(rimColor))
        ctx.fill(floor, with: .color(rimColor))

        // Rim caps (highlight) so the rim reads as a tactile lip the chips hit.
        let cap = chipRadius * 0.5
        for x in [r.minX, r.maxX] {
            let dot = Path(ellipseIn: CGRect(x: x - cap, y: r.minY - cap, width: cap * 2, height: cap * 2))
            ctx.fill(dot, with: .color(Color(red: 0.85, green: 0.88, blue: 1.0)))
        }
    }

    private func drawChip(_ chip: GravityBinTossView_Chip, into ctx: GraphicsContext) {
        let rect = CGRect(x: chip.position.x - chip.radius,
                          y: chip.position.y - chip.radius,
                          width: chip.radius * 2,
                          height: chip.radius * 2)

        let base = chipColor(chip.hue)
        let highlight = chipColor(chip.hue, brighten: 0.28)

        // Soft contact shadow under the chip.
        let shadow = Path(ellipseIn: rect.offsetBy(dx: 0, dy: chip.radius * 0.35))
        ctx.fill(shadow, with: .color(Color.black.opacity(0.22)))

        // GravityBinTossView_Chip body with a radial sheen.
        let body = Path(ellipseIn: rect)
        ctx.fill(
            body,
            with: .radialGradient(
                Gradient(colors: [highlight, base]),
                center: CGPoint(x: chip.position.x - chip.radius * 0.35,
                                y: chip.position.y - chip.radius * 0.35),
                startRadius: 0,
                endRadius: chip.radius * 1.4
            )
        )

        // Rim ring + a notch mark to convey spin.
        ctx.stroke(body, with: .color(Color.white.opacity(0.32)), lineWidth: max(chip.radius * 0.12, 0.6))

        let notchLen = chip.radius * 0.72
        var notch = Path()
        notch.move(to: chip.position)
        notch.addLine(to: CGPoint(x: chip.position.x + cos(chip.spin) * notchLen,
                                  y: chip.position.y + sin(chip.spin) * notchLen))
        ctx.stroke(notch, with: .color(Color.white.opacity(0.5)), lineWidth: max(chip.radius * 0.14, 0.7))
    }

    private func chipColor(_ hue: Double, brighten: Double = 0) -> Color {
        Color(hue: hue, saturation: 0.62, brightness: min(0.95, 0.78 + brighten))
    }

    // MARK: Physics tick

    private func tick(_ now: Date) {
        guard let last = lastTick else {
            lastTick = now
            return
        }
        let rawDt = now.timeIntervalSince(last)
        lastTick = now
        // Clamp dt: first frames / return-from-background must not fling chips through walls.
        let dt = CGFloat(min(max(rawDt, 0), 1.0 / 30.0))
        guard dt > 0 else { return }

        handleSpawning(now: now)
        if dt > 0 {
            stepPhysics(dt: dt, now: now.timeIntervalSince1970)
        }
        handleDemoReset(now: now)
    }

    // MARK: Spawning

    private func handleSpawning(now: Date) {
        guard demo else { return }
        guard !resetting else { return }
        spawnAccumulator += 1.0 / 60.0
        // One toss roughly every ~0.85s; cycle of fill -> reset handled separately.
        let interval: Double = 0.85
        if spawnAccumulator >= interval && chips.count < maxChips {
            spawnAccumulator = 0
            spawnDemoChip(now: now)
        }
    }

    private func spawnDemoChip(now: Date) {
        // Aim into the bin with a pleasing arc; vary slightly per toss.
        let target = CGPoint(x: binRect.midX + CGFloat.random(in: -binRect.width * 0.25...binRect.width * 0.25),
                             y: binRect.minY + binRect.height * 0.3)
        let vx = (target.x - spawnPoint.x) * 1.7
        let vy = -size.height * CGFloat.random(in: 1.05...1.35)
        spawnChip(at: spawnPoint,
                  velocity: CGVector(dx: vx, dy: vy),
                  now: now)
    }

    private func spawnChip(at point: CGPoint, velocity: CGVector, now: Date) {
        guard chips.count < maxChips else { return }
        let chip = GravityBinTossView_Chip(
            id: nextID,
            position: point,
            velocity: velocity,
            radius: chipRadius * CGFloat.random(in: 0.9...1.12),
            spin: CGFloat.random(in: 0...(.pi * 2)),
            spinRate: CGFloat.random(in: -6...6),
            hue: Double.random(in: 0...1),
            bornAt: now.timeIntervalSince1970
        )
        nextID += 1
        chips.append(chip)
    }

    // MARK: Demo reset (fade, never hard-clear)

    private func handleDemoReset(now: Date) {
        guard demo else { return }
        if resetting {
            fadeOut = max(0, fadeOut - 0.06)
            if fadeOut <= 0 {
                chips.removeAll()
                fadeOut = 1.0
                resetting = false
                spawnAccumulator = 0
            }
            return
        }
        // When the bin is full and everything settled, start a graceful fade reset.
        if chips.count >= maxChips && chips.allSatisfy({ $0.settled }) {
            resetting = true
        }
    }

    // MARK: Integration + collisions

    private func stepPhysics(dt: CGFloat, now: TimeInterval) {
        let restitution: CGFloat = 0.42
        let airDrag: CGFloat = 0.0
        let restSpeed: CGFloat = size.height * 0.06   // below this near support -> sleep
        let r = binRect
        let wt = wallThickness

        // 1. Integrate non-settled chips (gravity + motion + spin).
        for i in chips.indices {
            if chips[i].settled { continue }
            chips[i].velocity.dy += gravity * dt
            if airDrag > 0 {
                chips[i].velocity.dx *= (1 - airDrag * dt)
                chips[i].velocity.dy *= (1 - airDrag * dt)
            }
            chips[i].position.x += chips[i].velocity.dx * dt
            chips[i].position.y += chips[i].velocity.dy * dt
            chips[i].spin += chips[i].spinRate * dt
        }

        // 2. World collisions: bin walls / floor + overall bounds.
        for i in chips.indices {
            if chips[i].settled { continue }
            resolveWorld(index: i, rect: r, wallThickness: wt, restitution: restitution)
        }

        // 3. Pairwise chip-vs-chip collisions (N^2 over <=16 bodies).
        resolveChipPairs(restitution: restitution)

        // 4. Rest detection: a chip slow + supported goes to sleep.
        for i in chips.indices {
            if chips[i].settled { continue }
            let rad = chips[i].radius
            let onFloor = chips[i].position.y + rad >= floorY - 0.5
            let supported = onFloor || restingOnChip(i)
            let speed = hypot(chips[i].velocity.dx, chips[i].velocity.dy)
            if supported && speed < restSpeed {
                chips[i].velocity = .zero
                chips[i].spinRate *= 0.5
                chips[i].settled = true
            }
        }
    }

    private func resolveWorld(index i: Int, rect r: CGRect, wallThickness wt: CGFloat, restitution: CGFloat) {
        let rad = chips[i].radius
        // Floor of the bin.
        let fy = r.maxY - wt * 0.5
        if chips[i].position.y + rad > fy {
            // Only collide with floor if horizontally inside the bin mouth.
            if chips[i].position.x > r.minX - rad && chips[i].position.x < r.maxX + rad {
                let pen = (chips[i].position.y + rad) - fy
                chips[i].position.y -= pen
                if chips[i].velocity.dy > 0 {
                    chips[i].velocity.dy = -chips[i].velocity.dy * restitution
                    chips[i].velocity.dx *= 0.86
                    bumpCollision()
                }
            }
        }
        // Inner walls (only when below the rim line, so chips can drop in from above).
        let leftInner = r.minX + wt * 0.5
        let rightInner = r.maxX - wt * 0.5
        let belowRim = chips[i].position.y > r.minY
        if belowRim {
            if chips[i].position.x - rad < leftInner {
                let pen = leftInner - (chips[i].position.x - rad)
                chips[i].position.x += pen
                if chips[i].velocity.dx < 0 {
                    chips[i].velocity.dx = -chips[i].velocity.dx * restitution
                    bumpCollision()
                }
            }
            if chips[i].position.x + rad > rightInner {
                let pen = (chips[i].position.x + rad) - rightInner
                chips[i].position.x -= pen
                if chips[i].velocity.dx > 0 {
                    chips[i].velocity.dx = -chips[i].velocity.dx * restitution
                    bumpCollision()
                }
            }
        } else {
            // Above the rim: bounce off the rim lips so flung chips can ricochet.
            collideRimCap(index: i, capCenter: CGPoint(x: r.minX, y: r.minY), restitution: restitution)
            collideRimCap(index: i, capCenter: CGPoint(x: r.maxX, y: r.minY), restitution: restitution)
        }

        // Keep chips inside the overall view so nothing escapes off-screen.
        clampToBounds(index: i)
    }

    private func collideRimCap(index i: Int, capCenter: CGPoint, restitution: CGFloat) {
        let rad = chips[i].radius
        let capR = chipRadius * 0.5
        let dx = chips[i].position.x - capCenter.x
        let dy = chips[i].position.y - capCenter.y
        let dist = hypot(dx, dy)
        let minDist = rad + capR
        if dist < minDist && dist > 0.0001 {
            let nx = dx / dist
            let ny = dy / dist
            let pen = minDist - dist
            chips[i].position.x += nx * pen
            chips[i].position.y += ny * pen
            let vn = chips[i].velocity.dx * nx + chips[i].velocity.dy * ny
            if vn < 0 {
                chips[i].velocity.dx -= (1 + restitution) * vn * nx
                chips[i].velocity.dy -= (1 + restitution) * vn * ny
                bumpCollision()
            }
        }
    }

    private func clampToBounds(index i: Int) {
        let rad = chips[i].radius
        if chips[i].position.x < rad {
            chips[i].position.x = rad
            chips[i].velocity.dx = abs(chips[i].velocity.dx) * 0.4
        }
        if chips[i].position.x > size.width - rad {
            chips[i].position.x = size.width - rad
            chips[i].velocity.dx = -abs(chips[i].velocity.dx) * 0.4
        }
        if chips[i].position.y > size.height - rad {
            chips[i].position.y = size.height - rad
            if chips[i].velocity.dy > 0 {
                chips[i].velocity.dy = -chips[i].velocity.dy * 0.3
            }
        }
    }

    private func resolveChipPairs(restitution: CGFloat) {
        guard chips.count > 1 else { return }
        for a in 0..<(chips.count - 1) {
            for b in (a + 1)..<chips.count {
                resolvePair(a, b, restitution: restitution)
            }
        }
    }

    private func resolvePair(_ a: Int, _ b: Int, restitution: CGFloat) {
        let pa = chips[a].position
        let pb = chips[b].position
        let dx = pb.x - pa.x
        let dy = pb.y - pa.y
        let dist = hypot(dx, dy)
        let minDist = chips[a].radius + chips[b].radius
        guard dist < minDist else { return }

        let safeDist = dist > 0.0001 ? dist : 0.0001
        let nx = dx / safeDist
        let ny = dy / safeDist
        let pen = minDist - safeDist

        let aSettled = chips[a].settled
        let bSettled = chips[b].settled

        // Positional correction: push out by half the penetration (or full, if
        // one body is asleep, so the awake chip stacks on top cleanly).
        if aSettled && !bSettled {
            chips[b].position.x += nx * pen
            chips[b].position.y += ny * pen
        } else if bSettled && !aSettled {
            chips[a].position.x -= nx * pen
            chips[a].position.y -= ny * pen
        } else if !aSettled && !bSettled {
            chips[a].position.x -= nx * pen * 0.5
            chips[a].position.y -= ny * pen * 0.5
            chips[b].position.x += nx * pen * 0.5
            chips[b].position.y += ny * pen * 0.5
        } else {
            // Both settled and overlapping (rare) — nudge apart gently, stay asleep.
            chips[a].position.x -= nx * pen * 0.5
            chips[b].position.x += nx * pen * 0.5
            return
        }

        // Velocity response along the normal (equal mass).
        let rvx = chips[b].velocity.dx - chips[a].velocity.dx
        let rvy = chips[b].velocity.dy - chips[a].velocity.dy
        let vn = rvx * nx + rvy * ny
        guard vn < 0 else { return }

        let impulse = -(1 + restitution) * vn / 2
        if !aSettled {
            chips[a].velocity.dx -= impulse * nx
            chips[a].velocity.dy -= impulse * ny
            // A sleeping neighbor getting struck should wake if hit hard.
        }
        if !bSettled {
            chips[b].velocity.dx += impulse * nx
            chips[b].velocity.dy += impulse * ny
        }
        // Wake a settled chip only on a strong hit so the pile doesn't jitter.
        let strong = abs(vn) > size.height * 0.25
        if strong {
            if aSettled { chips[a].settled = false }
            if bSettled { chips[b].settled = false }
        }
        bumpCollision()
    }

    // Is chip i resting on top of any settled chip (for rest detection)?
    private func restingOnChip(_ i: Int) -> Bool {
        let pi = chips[i].position
        let ri = chips[i].radius
        for j in chips.indices where j != i {
            guard chips[j].settled else { continue }
            let dx = chips[j].position.x - pi.x
            let dy = chips[j].position.y - pi.y
            let dist = hypot(dx, dy)
            let touch = ri + chips[j].radius
            // Supported if a settled chip is essentially below/touching it.
            if dist <= touch + 1.0 && chips[j].position.y > pi.y {
                return true
            }
        }
        return false
    }

    private func bumpCollision() {
        // Only fire haptics in interactive mode; demo tiles must stay silent.
        guard !demo else { return }
        collisionCount &+= 1
    }

    // MARK: Gesture (interactive mode)

    private var flingGesture: some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                if dragStart == nil { dragStart = value.startLocation }
                dragCurrent = value.location
            }
            .onEnded { value in
                let now = Date()
                // Velocity from predicted end translation (momentum), not raw drag.
                let predicted = value.predictedEndTranslation
                let drag = value.translation
                let scale: CGFloat = 6.0
                var vx = (predicted.width - drag.width) * scale
                var vy = (predicted.height - drag.height) * scale

                // If it was basically a tap, give it a gentle lob toward the bin.
                let predLen = hypot(predicted.width, predicted.height)
                if predLen < 6 {
                    vx = (binRect.midX - value.startLocation.x) * 1.6
                    vy = -size.height * 1.1
                }
                // Clamp launch speed so it never blows through walls.
                let maxSpeed = size.height * 6.0
                let speed = hypot(vx, vy)
                if speed > maxSpeed {
                    vx *= maxSpeed / speed
                    vy *= maxSpeed / speed
                }
                spawnChip(at: value.startLocation,
                          velocity: CGVector(dx: vx, dy: vy),
                          now: now)
                if chips.count > maxChips {
                    // FIFO drop the oldest settled chip to keep the cap.
                    if let idx = chips.firstIndex(where: { $0.settled }) {
                        chips.remove(at: idx)
                    }
                }
                dragStart = nil
                dragCurrent = nil
            }
    }
}
"""###,
        "ges-hold-charge-burst": ###"""
import SwiftUI

// MARK: - Hold-to-Charge Burst
//
// Press and hold to charge a core that pulses, swells, and accumulates
// orbiting energy rings; release fires a particle burst whose size scales
// with how long you held.
//
// Architecture (per design review):
//  - A single always-on TimelineView(.animation) drives BOTH the auto demo
//    loop and the real interactive component.
//  - Charge is TIME-driven (elapsed since pressStart), never delta-driven,
//    so a perfectly still hold still charges.
//  - All @State writes happen only in gesture callbacks; the timeline closure
//    is a pure function of (now, pressStart, burstStart, chargeAtRelease).
//  - Particle randomness is precomputed once per index (deterministic), so the
//    burst is a coherent explosion rather than per-frame noise.
//  - Pulse uses a fixed frequency with charge-driven amplitude (no
//    instantaneous-frequency seam stutter).
public struct HoldChargeBurstView: View {
    public var demo: Bool = false

    // Interactive state — written ONLY in gesture callbacks.
    @State private var pressStart: Date? = nil
    @State private var burstStart: Date? = nil
    @State private var chargeAtRelease: Double = 0

    public init(demo: Bool = false) {
        self.demo = demo
    }

    public var body: some View {
        GeometryReader { proxy in
            let size = proxy.size
            let side = min(size.width, size.height)

            TimelineView(.animation) { timeline in
                let now = timeline.date
                let frame = makeFrame(now: now)

                ChargeBurstScene(state: frame, side: side)
                    .frame(width: size.width, height: size.height)
            }
            .contentShape(Rectangle())
            // iOS-17-safe gesture wiring: the `including:` mask disables this
            // gesture in demo (no subview gestures exist, so nothing fires and
            // no @State is written), and enables it in interactive mode.
            .gesture(chargeGesture, including: demo ? .subviews : .all)
            // Escalating haptic per charge band (interactive only).
            .modifier(
                ChargeHaptics(
                    enabled: !demo,
                    band: liveChargeBand,
                    burstStart: burstStart
                )
            )
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .clipped()
    }

    // MARK: Gesture

    private var chargeGesture: some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { _ in
                // Fire once per press: start the charge clock. onChanged may
                // never fire again if the finger holds still — that's fine,
                // charge is derived from elapsed time, not deltas.
                if pressStart == nil {
                    pressStart = Date()
                    burstStart = nil
                }
            }
            .onEnded { _ in
                if let start = pressStart {
                    let held = Date().timeIntervalSince(start)
                    chargeAtRelease = charge(forHeld: held)
                }
                pressStart = nil
                burstStart = Date()
            }
    }

    // Live charge band for haptics — pure derivation, fires on band crossings.
    private var liveChargeBand: Int {
        guard !demo, let start = pressStart else { return 0 }
        let held = Date().timeIntervalSince(start)
        return Int(charge(forHeld: held) * 5.0)
    }

    // MARK: Frame model

    /// Computes the full visual state for `now`, branching on demo vs interactive.
    private func makeFrame(now: Date) -> ChargeState {
        if demo {
            return demoState(now: now)
        } else {
            return interactiveState(now: now)
        }
    }

    /// Demo path: a pure function of the timeline date. No phase @State.
    private func demoState(now: Date) -> ChargeState {
        let loop: Double = 3.4
        let t = now.timeIntervalSinceReferenceDate.truncatingRemainder(dividingBy: loop)

        let chargeWindow: Double = 2.2   // build-up
        let burstWindow: Double = 1.0    // explosion + reform
        // (small idle tail fills the remainder of the loop)

        var charge: Double = 0
        var burstProgress: Double = -1   // <0 => not bursting
        var pulsePhase: Double = now.timeIntervalSinceReferenceDate

        if t < chargeWindow {
            // Ease-in build so the swell feels like accumulating strain.
            let p = t / chargeWindow
            charge = easeInOut(p)
        } else if t < chargeWindow + burstWindow {
            // Hold peak charge as the burst plays; core re-forms within it.
            charge = 1.0
            burstProgress = (t - chargeWindow) / burstWindow
        } else {
            charge = 0
        }

        // Keep pulse phase continuous and seam-safe (fixed frequency).
        pulsePhase = now.timeIntervalSinceReferenceDate

        return ChargeState(
            charge: charge,
            burstProgress: burstProgress,
            burstCharge: 1.0,
            pulsePhase: pulsePhase
        )
    }

    /// Interactive path: derived purely from Date/Double @State + now.
    private func interactiveState(now: Date) -> ChargeState {
        let burstWindow: Double = 1.1
        let pulsePhase = now.timeIntervalSinceReferenceDate

        // Bursting takes precedence and is finite.
        if let bStart = burstStart {
            let bt = now.timeIntervalSince(bStart)
            if bt < burstWindow {
                return ChargeState(
                    charge: 0,
                    burstProgress: bt / burstWindow,
                    burstCharge: chargeAtRelease,
                    pulsePhase: pulsePhase
                )
            }
            // Burst finished — fall through to idle WITHOUT writing state.
            return ChargeState(
                charge: 0,
                burstProgress: -1,
                burstCharge: chargeAtRelease,
                pulsePhase: pulsePhase
            )
        }

        // Charging: charge grows with elapsed hold time (still-hold safe).
        if let pStart = pressStart {
            let held = now.timeIntervalSince(pStart)
            return ChargeState(
                charge: charge(forHeld: held),
                burstProgress: -1,
                burstCharge: 0,
                pulsePhase: pulsePhase
            )
        }

        // Idle.
        return ChargeState(
            charge: 0,
            burstProgress: -1,
            burstCharge: 0,
            pulsePhase: pulsePhase
        )
    }

    // MARK: Helpers

    /// Maps a held duration (seconds) to a clamped 0...1 charge with ease-in.
    private func charge(forHeld held: Double) -> Double {
        let full: Double = 1.8 // seconds to fully charge
        let raw = min(max(held / full, 0), 1)
        return easeInOut(raw)
    }

    private func easeInOut(_ x: Double) -> Double {
        let c = min(max(x, 0), 1)
        return c * c * (3.0 - 2.0 * c)
    }
}

// MARK: - Visual state passed each frame

private struct ChargeState {
    var charge: Double          // 0...1 current charge (drives swell/rings)
    var burstProgress: Double   // <0 = not bursting, else 0...1
    var burstCharge: Double     // 0...1 charge captured at release (burst size)
    var pulsePhase: Double      // continuous time for pulse oscillation
}

// MARK: - Scene renderer

private struct ChargeBurstScene: View {
    let state: ChargeState
    let side: CGFloat

    var body: some View {
        ZStack {
            background
            orbitingRings
            coreView
            burstCanvas
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    private var isBursting: Bool { state.burstProgress >= 0 }

    // Charge color ramps from cool teal to hot magenta as it builds.
    private func chargeColor(_ c: Double) -> Color {
        let t = min(max(c, 0), 1)
        let r = 0.30 + 0.62 * t
        let g = 0.78 - 0.40 * t
        let b = 0.92 - 0.30 * t
        return Color(red: r, green: g, blue: b)
    }

    // MARK: Layers

    private var background: some View {
        let glow = chargeColor(max(state.charge, isBursting ? state.burstCharge * 0.6 : 0))
        let intensity = isBursting ? 0.18 : (0.08 + 0.20 * state.charge)
        return RadialGradient(
            colors: [
                glow.opacity(intensity),
                Color(red: 0.05, green: 0.05, blue: 0.09).opacity(0.0)
            ],
            center: .center,
            startRadius: 0,
            endRadius: side * 0.55
        )
        .blendMode(.plusLighter)
    }

    private var coreView: some View {
        // The core is ALWAYS visible: it never fades through zero. During a
        // burst it re-forms (scales up from a small idle size) instead of
        // disappearing, guaranteeing no blank frame at the loop seam.
        let baseRadius = side * 0.085
        let swell = 1.0 + 0.85 * state.charge
        // Fixed-frequency pulse, charge-driven amplitude (seam-safe).
        let pulseAmp = 0.04 + 0.16 * state.charge
        let pulse = 1.0 + pulseAmp * sin(state.pulsePhase * 6.0)

        var scale = swell * pulse

        if isBursting {
            // Core flashes outward then re-forms small -> grows back.
            let p = state.burstProgress
            let reform = reformScale(p)
            scale = reform
        }

        let radius = baseRadius * scale
        let c = chargeColor(state.charge)
        let hot = chargeColor(min(state.charge + 0.25, 1.0))

        return ZStack {
            // Soft halo
            Circle()
                .fill(c.opacity(0.35))
                .frame(width: radius * 2.6, height: radius * 2.6)
                .blur(radius: side * 0.03)

            // Solid core
            Circle()
                .fill(
                    RadialGradient(
                        colors: [Color(red: 1, green: 1, blue: 1), hot, c],
                        center: .center,
                        startRadius: 0,
                        endRadius: radius
                    )
                )
                .frame(width: radius * 2, height: radius * 2)
                .overlay(
                    Circle()
                        .strokeBorder(Color(red: 1, green: 1, blue: 1).opacity(0.55), lineWidth: side * 0.006)
                        .frame(width: radius * 2, height: radius * 2)
                )
                .shadow(color: c.opacity(0.8), radius: side * 0.05 * (0.4 + state.charge))
        }
    }

    /// Core scale during burst: a quick flash-out, then re-form from small.
    private func reformScale(_ p: Double) -> Double {
        if p < 0.18 {
            // Flash outward
            return 1.0 + 3.5 * (p / 0.18)
        } else {
            // Re-form: shrink to a small seed then ease back to idle size.
            let q = (p - 0.18) / 0.82
            let seed = 0.25
            return seed + (1.0 - seed) * easeOut(q)
        }
    }

    // Orbiting energy rings — count and brightness grow with charge.
    private var orbitingRings: some View {
        let ringCount = Int((state.charge * 4.0).rounded(.down)) // 0...4
        let baseR = side * 0.14
        let c = chargeColor(state.charge)
        let spin = state.pulsePhase

        return ZStack {
            ForEach(0..<max(ringCount, 0), id: \.self) { i in
                let idx = Double(i)
                let ringRadius = baseR + idx * side * 0.055
                let tilt = 18.0 + idx * 26.0
                let speed = 1.2 + idx * 0.5
                let opacity = isBursting ? 0.0 : (0.65 - 0.1 * idx)

                Ellipse()
                    .strokeBorder(c.opacity(opacity), lineWidth: side * 0.012)
                    .frame(width: ringRadius * 2, height: ringRadius * 2 * 0.42)
                    .rotation3DEffect(
                        .degrees(tilt),
                        axis: (x: 1, y: 0.35, z: 0)
                    )
                    .rotationEffect(.radians(spin * speed))
                    .overlay(orbitDot(ringRadius: ringRadius, spin: spin * speed, color: c, opacity: opacity))
            }
        }
    }

    private func orbitDot(ringRadius: CGFloat, spin: Double, color: Color, opacity: Double) -> some View {
        let dotSize = side * 0.028
        let x = cos(spin) * ringRadius
        let y = sin(spin) * ringRadius * 0.42
        return Circle()
            .fill(color.opacity(opacity + 0.2))
            .frame(width: dotSize, height: dotSize)
            .shadow(color: color.opacity(opacity), radius: side * 0.02)
            .offset(x: x, y: y)
            .rotation3DEffect(.degrees(0), axis: (x: 1, y: 0, z: 0))
    }

    // Particle burst — Canvas, sized by captured charge.
    private var burstCanvas: some View {
        Canvas { ctx, canvasSize in
            guard isBursting else { return }
            let p = state.burstProgress
            let center = CGPoint(x: canvasSize.width / 2, y: canvasSize.height / 2)
            let maxReach = side * (0.30 + 0.55 * state.burstCharge)
            let particleCount = 14 + Int(state.burstCharge * 22) // 14...36
            let baseColor = chargeColor(min(state.burstCharge + 0.2, 1.0))

            let eased = easeOutCubic(p)
            let fade = 1.0 - smoothFade(p)

            for i in 0..<particleCount {
                let seed = BurstParticles.seeds[i % BurstParticles.seeds.count]
                let angle = seed.angle
                let speed = seed.speed
                let sizeJitter = seed.sizeJitter

                let dist = maxReach * speed * eased
                let x = center.x + cos(angle) * dist
                let y = center.y + sin(angle) * dist

                let pSize = side * (0.014 + 0.02 * sizeJitter) * (1.0 - 0.4 * eased)
                let rect = CGRect(
                    x: x - pSize / 2,
                    y: y - pSize / 2,
                    width: pSize,
                    height: pSize
                )

                var sub = ctx
                sub.opacity = fade
                sub.addFilter(.blur(radius: side * 0.004))
                sub.fill(Path(ellipseIn: rect), with: .color(baseColor.opacity(0.9)))

                // Trailing spark line for energy streaking outward.
                if i % 3 == 0 {
                    var line = Path()
                    let tailDist = dist - maxReach * speed * 0.12
                    let tx = center.x + cos(angle) * max(tailDist, 0)
                    let ty = center.y + sin(angle) * max(tailDist, 0)
                    line.move(to: CGPoint(x: tx, y: ty))
                    line.addLine(to: CGPoint(x: x, y: y))
                    var ls = ctx
                    ls.opacity = fade * 0.7
                    ls.stroke(
                        line,
                        with: .color(baseColor.opacity(0.8)),
                        style: StrokeStyle(lineWidth: pSize * 0.6, lineCap: .round)
                    )
                }
            }

            // Expanding shockwave ring.
            let ringR = maxReach * eased * 1.05
            let ringRect = CGRect(
                x: center.x - ringR,
                y: center.y - ringR,
                width: ringR * 2,
                height: ringR * 2
            )
            var ring = ctx
            ring.opacity = (1.0 - eased) * 0.8
            ring.stroke(
                Path(ellipseIn: ringRect),
                with: .color(Color(red: 1, green: 1, blue: 1).opacity(0.9)),
                style: StrokeStyle(lineWidth: side * 0.01 * (1.0 - eased) + side * 0.002)
            )
        }
        .allowsHitTesting(false)
    }

    // MARK: Easing

    private func easeOut(_ x: Double) -> Double {
        let c = min(max(x, 0), 1)
        return 1 - (1 - c) * (1 - c)
    }

    private func easeOutCubic(_ x: Double) -> Double {
        let c = min(max(x, 0), 1)
        let inv = 1 - c
        return 1 - inv * inv * inv
    }

    /// Fade-out of burst particles toward the end of the burst window.
    private func smoothFade(_ p: Double) -> Double {
        let start = 0.55
        guard p > start else { return 0 }
        let q = (p - start) / (1.0 - start)
        return min(max(q, 0), 1)
    }
}

// MARK: - Deterministic precomputed particle seeds
//
// Generated ONCE at type-load with a fixed seed so the burst is a coherent
// explosion. Never call random() inside the per-frame Canvas closure.
private enum BurstParticles {
    struct Seed {
        let angle: Double
        let speed: Double
        let sizeJitter: Double
    }

    static let seeds: [Seed] = {
        var rng = SplitMix64(seed: 0x9E3779B97F4A7C15)
        var out: [Seed] = []
        let count = 40
        for i in 0..<count {
            // Spread base angle evenly, then jitter for organic look.
            let base = (Double(i) / Double(count)) * 2.0 * .pi
            let jitter = (rng.nextDouble() - 0.5) * (2.0 * .pi / Double(count)) * 1.6
            let angle = base + jitter
            let speed = 0.55 + rng.nextDouble() * 0.45      // 0.55...1.0
            let sizeJitter = rng.nextDouble()               // 0...1
            out.append(Seed(angle: angle, speed: speed, sizeJitter: sizeJitter))
        }
        return out
    }()
}

// Tiny deterministic PRNG so seeds are stable & reproducible.
private struct SplitMix64 {
    private var state: UInt64
    init(seed: UInt64) { state = seed }

    mutating func next() -> UInt64 {
        state = state &+ 0x9E3779B97F4A7C15
        var z = state
        z = (z ^ (z >> 30)) &* 0xBF58476D1CE4E5B9
        z = (z ^ (z >> 27)) &* 0x94D049BB133111EB
        return z ^ (z >> 31)
    }

    mutating func nextDouble() -> Double {
        return Double(next() >> 11) * (1.0 / 9007199254740992.0)
    }
}

// MARK: - Haptics modifier
//
// Two distinct triggers, both gated on the interactive path:
//  - escalating .impact on charge-band crossings
//  - .success once on release (burstStart changes exactly once)
private struct ChargeHaptics: ViewModifier {
    let enabled: Bool
    let band: Int
    let burstStart: Date?

    func body(content: Content) -> some View {
        content
            .sensoryFeedback(.impact(weight: .light, intensity: 0.7), trigger: enabled ? band : 0)
            .sensoryFeedback(.success, trigger: burstTriggerValue)
    }

    // Changes exactly once per release; stays constant otherwise.
    private var burstTriggerValue: Int {
        guard enabled, let s = burstStart else { return 0 }
        return Int(s.timeIntervalSinceReferenceDate)
    }
}
"""###,
        "ges-hold-drag-slingshot-aim": ###"""
import SwiftUI

// MARK: - HoldDragSlingshotAimView
// "Hold-Aim Trajectory Cannon"
// Press and drag back from a cannon to set power + angle; a dotted predicted
// arc updates live. Release fires a ball that follows that EXACT parametric
// arc and bounces on landing.
//
// Core idea: a single closed-form projectile function f(t) drives BOTH the
// dotted preview AND the live flight, so the shot lands precisely on the
// previewed path. Everything is normalized to the GeometryReader size so it
// reads identically in a 120pt tile and a large detail area.

public struct HoldDragSlingshotAimView: View {
    var demo: Bool = false

    public init(demo: Bool = false) {
        self.demo = demo
    }

    // Interactive aim state (normalized 0...1 of the smaller dimension).
    @State private var pull: CGSize = .zero          // current pull-back vector
    @State private var isAiming: Bool = false
    @State private var isFlying: Bool = false
    @State private var firePull: CGSize = .zero       // pull captured at release
    @State private var fireStart: Date = .distantPast

    public var body: some View {
        GeometryReader { geo in
            let size = geo.size
            content(in: size)
                .frame(width: size.width, height: size.height)
                .contentShape(Rectangle())
                .gesture(demo ? nil : aimGesture(in: size))
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .background(Self.backdrop)
    }

    // MARK: Layout content

    @ViewBuilder
    private func content(in size: CGSize) -> some View {
        let unit = min(size.width, size.height)
        let origin = launchOrigin(in: size)
        let g = Physics.gravity * unit

        TimelineView(.animation) { timeline in
            let now = timeline.date
            let state = resolvedState(now: now, size: size, unit: unit)

            ZStack {
                GroundView(y: Physics.groundY * size.height, width: size.width)

                // Dotted predicted arc (first arc to landing).
                TrajectoryDots(
                    points: previewPoints(
                        v0: state.v0, origin: origin, g: g, size: size, unit: unit
                    ),
                    unit: unit,
                    active: state.aimStrength > 0.001
                )

                // Aim guide line from origin showing the pull-back.
                AimGuide(
                    origin: origin,
                    pull: state.pull,
                    strength: state.aimStrength,
                    unit: unit
                )

                // The flying ball follows the SAME f(t) used for the dots.
                if let ballPos = state.ballPosition {
                    Ball(unit: unit)
                        .position(ballPos)
                        .shadow(color: Self.glow.opacity(0.55), radius: unit * 0.04)
                }

                // Cannon barrel, anchored at origin, aimed along launch vector.
                CannonView(
                    origin: origin,
                    aimAngle: state.barrelAngle,
                    charge: state.aimStrength,
                    unit: unit
                )
            }
            .sensoryFeedback(.impact(flexibility: .solid, intensity: 0.9),
                             trigger: state.bounceTrigger)
        }
    }

    // MARK: Resolved per-frame state

    private struct FrameState {
        var pull: CGSize          // visual pull (for guide + barrel)
        var v0: CGVector          // launch velocity (px/sec)
        var aimStrength: CGFloat  // 0...1 for tint / charge
        var barrelAngle: CGFloat  // radians, barrel direction
        var ballPosition: CGPoint?
        var bounceTrigger: Int
    }

    private func resolvedState(now: Date, size: CGSize, unit: CGFloat) -> FrameState {
        let origin = launchOrigin(in: size)
        let g = Physics.gravity * unit

        if demo {
            return demoState(now: now, origin: origin, g: g, size: size, unit: unit)
        } else {
            return interactiveState(now: now, origin: origin, g: g, size: size, unit: unit)
        }
    }

    // MARK: Interactive state

    private func interactiveState(now: Date, origin: CGPoint, g: CGFloat,
                                  size: CGSize, unit: CGFloat) -> FrameState {
        let activePull = isFlying ? firePull : pull
        let v0 = launchVelocity(fromPull: activePull, unit: unit)
        let strength = aimStrength(fromPull: activePull, unit: unit)
        let angle = barrelAngle(fromPull: activePull)

        var ballPos: CGPoint? = nil
        var trigger = 0

        if isFlying {
            let t = max(0, now.timeIntervalSince(fireStart))
            let flight = flightPoint(t: t, v0: v0, origin: origin, g: g, size: size)
            ballPos = flight.point
            trigger = flight.bounceIndex
        } else if isAiming {
            // While aiming, rest the ball at the muzzle so it never disappears.
            ballPos = muzzlePoint(origin: origin, angle: angle, unit: unit)
        } else {
            ballPos = loadedPoint(origin: origin, unit: unit)
        }

        return FrameState(
            pull: activePull, v0: v0, aimStrength: strength,
            barrelAngle: angle, ballPosition: ballPos, bounceTrigger: trigger
        )
    }

    // MARK: Demo state (self-driving loop)

    private func demoState(now: Date, origin: CGPoint, g: CGFloat,
                           size: CGSize, unit: CGFloat) -> FrameState {
        let period: Double = 3.4
        let phase = now.timeIntervalSinceReferenceDate.truncatingRemainder(dividingBy: period)

        // Timeline split: pull-back (0..0.9), hold (0.9..1.2), flight (1.2..end).
        let drawDur: Double = 0.9
        let holdDur: Double = 0.35
        let flightStart = drawDur + holdDur

        // Aim sweeps slowly across cycles so the arc visibly redraws.
        let cycleSeed = floor(now.timeIntervalSinceReferenceDate / period)
        let aimT = (sin(cycleSeed * 1.3) + 1) * 0.5            // 0...1
        let angleDeg = 30 + aimT * 30                          // 30°...60° up-right
        let angleRad = angleDeg * .pi / 180
        let maxPullMag = unit * 0.30

        // Pull magnitude eases in during the draw window.
        let drawProgress = min(1, phase / drawDur)
        let eased = easeOut(drawProgress)
        let pullMag: CGFloat = (phase < flightStart) ? maxPullMag * eased : maxPullMag

        // Pull vector points DOWN-LEFT (opposite of fire direction).
        let pullVec = CGSize(width: -cos(angleRad) * pullMag,
                             height: sin(angleRad) * pullMag)

        let v0 = launchVelocity(fromPull: pullVec, unit: unit)
        let strength = aimStrength(fromPull: pullVec, unit: unit)
        let barrel = barrelAngle(fromPull: pullVec)

        var ballPos: CGPoint?
        var trigger = 0

        if phase < flightStart {
            // Aiming: ball sits at the muzzle, arc is fully drawn.
            ballPos = muzzlePoint(origin: origin, angle: barrel, unit: unit)
        } else {
            let t = phase - flightStart
            let flight = flightPoint(t: t, v0: v0, origin: origin, g: g, size: size)
            ballPos = flight.point
            trigger = 0   // no haptics in demo (avoid buzzing idle tiles)
        }

        return FrameState(
            pull: pullVec, v0: v0, aimStrength: strength,
            barrelAngle: barrel, ballPosition: ballPos, bounceTrigger: trigger
        )
    }

    // MARK: Physics — single source of truth f(t)

    private enum Physics {
        static let gravity: CGFloat = 2.4      // * unit -> px/s^2
        static let groundY: CGFloat = 0.86     // fraction of height
        static let restitution: CGFloat = 0.55
        static let maxBounces = 2
        static let powerScale: CGFloat = 3.1   // pull -> launch speed multiplier
    }

    /// Launch velocity (px/sec) derived from the pull-back vector.
    /// Pull back+down -> fire up+forward, so v0 = -pull * scale (per frame -> per sec).
    private func launchVelocity(fromPull pull: CGSize, unit: CGFloat) -> CGVector {
        let mag = hypot(pull.width, pull.height)
        let capped = min(mag, unit * 0.34)
        guard mag > 0.0001 else { return .zero }
        let dirX = -pull.width / mag
        let dirY = -pull.height / mag
        let speed = capped * Physics.powerScale * 3.2   // tuned px/sec
        return CGVector(dx: dirX * speed, dy: dirY * speed)
    }

    private func aimStrength(fromPull pull: CGSize, unit: CGFloat) -> CGFloat {
        let mag = hypot(pull.width, pull.height)
        return min(1, mag / (unit * 0.30))
    }

    private func barrelAngle(fromPull pull: CGSize) -> CGFloat {
        let mag = hypot(pull.width, pull.height)
        guard mag > 0.0001 else { return -.pi / 4 }    // default up-right
        // Barrel points opposite the pull (the fire direction).
        return atan2(-pull.height, -pull.width)
    }

    /// Closed-form projectile position with restitution bounces along the ground.
    /// Returns the live point and how many landings have occurred by time t.
    private func flightPoint(t: Double, v0: CGVector, origin: CGPoint,
                             g: CGFloat, size: CGSize) -> (point: CGPoint, bounceIndex: Int) {
        let groundLine = Physics.groundY * size.height
        let ballR = ballRadius(unit: min(size.width, size.height))
        let restLine = groundLine - ballR

        guard hypot(v0.dx, v0.dy) > 0.001 else {
            return (CGPoint(x: origin.x, y: restLine), 0)
        }

        // Simulate piecewise parabolas, advancing through bounces.
        var segVx = v0.dx
        var segVy = v0.dy
        var segX0 = origin.x
        var segY0 = origin.y
        var segT0: Double = 0
        var bounces = 0

        while bounces <= Physics.maxBounces {
            let landT = parabolaLandTime(y0: segY0, vy: segVy, g: g, groundY: restLine)
            // No real future landing this segment (shouldn't happen with gravity > 0).
            guard let absLand = landT, absLand.isFinite else { break }
            let segLandTime = segT0 + absLand

            if t <= segLandTime {
                let lt = t - segT0
                let x = segX0 + segVx * lt
                let y = segY0 + segVy * lt + 0.5 * Double(g) * lt * lt
                let cx = clampX(x, size: size, r: ballR)
                return (CGPoint(x: cx, y: y), bounces)
            }

            // Advance to landing, reflect vertical velocity, damp.
            let lt = absLand
            segX0 = segX0 + segVx * lt
            segY0 = restLine
            let vyAtLand = segVy + Double(g) * lt
            segVy = -vyAtLand * Double(Physics.restitution)
            segVx = segVx * 0.86
            segT0 = segLandTime
            bounces += 1

            // If the bounce is too weak, settle at rest.
            if abs(segVy) < Double(g) * 0.05 || bounces > Physics.maxBounces {
                let cx = clampX(segX0, size: size, r: ballR)
                return (CGPoint(x: cx, y: restLine), bounces)
            }
        }

        let cx = clampX(segX0, size: size, r: ballR)
        return (CGPoint(x: cx, y: restLine), bounces)
    }

    /// Time for a parabola y(t)=y0+vy t+0.5 g t^2 to reach groundY (first future root).
    private func parabolaLandTime(y0: Double, vy: Double, g: CGFloat, groundY: CGFloat) -> Double? {
        let gg = Double(g)
        let target = Double(groundY)
        // 0.5 g t^2 + vy t + (y0 - target) = 0
        let a = 0.5 * gg
        let b = vy
        let c = y0 - target
        guard a != 0 else {
            if b == 0 { return nil }
            let t = -c / b
            return t > 0 ? t : nil
        }
        let disc = b * b - 4 * a * c
        guard disc >= 0 else { return nil }
        let sq = disc.squareRoot()
        let t1 = (-b - sq) / (2 * a)
        let t2 = (-b + sq) / (2 * a)
        let candidates = [t1, t2].filter { $0 > 1e-5 }.sorted()
        return candidates.first
    }

    /// Sample the first arc (origin -> first landing) for the dotted preview.
    private func previewPoints(v0: CGVector, origin: CGPoint, g: CGFloat,
                               size: CGSize, unit: CGFloat) -> [CGPoint] {
        guard hypot(v0.dx, v0.dy) > 0.001 else { return [] }
        let restLine = Physics.groundY * size.height - ballRadius(unit: unit)
        guard let landT = parabolaLandTime(y0: origin.y, vy: v0.dy, g: g, groundY: restLine),
              landT.isFinite, landT > 0 else { return [] }

        let count = 26
        var pts: [CGPoint] = []
        pts.reserveCapacity(count)
        for i in 0...count {
            let t = landT * Double(i) / Double(count)
            let x = origin.x + v0.dx * t
            let y = origin.y + v0.dy * t + 0.5 * Double(g) * t * t
            let cx = clampX(x, size: size, r: ballRadius(unit: unit))
            pts.append(CGPoint(x: cx, y: y))
        }
        return pts
    }

    // MARK: Geometry helpers

    private func launchOrigin(in size: CGSize) -> CGPoint {
        let unit = min(size.width, size.height)
        return CGPoint(x: size.width * 0.16,
                       y: Physics.groundY * size.height - unit * 0.12)
    }

    private func ballRadius(unit: CGFloat) -> CGFloat { unit * 0.052 }

    private func muzzlePoint(origin: CGPoint, angle: CGFloat, unit: CGFloat) -> CGPoint {
        let len = unit * 0.17
        return CGPoint(x: origin.x + cos(angle) * len,
                       y: origin.y + sin(angle) * len)
    }

    private func loadedPoint(origin: CGPoint, unit: CGFloat) -> CGPoint {
        muzzlePoint(origin: origin, angle: -.pi / 4, unit: unit)
    }

    private func clampX(_ x: CGFloat, size: CGSize, r: CGFloat) -> CGFloat {
        min(max(x, r), size.width - r)
    }

    private func easeOut(_ t: Double) -> CGFloat {
        let c = min(max(t, 0), 1)
        return CGFloat(1 - pow(1 - c, 3))
    }

    // MARK: Gesture (long-press, then drag to aim, release to fire)

    private func aimGesture(in size: CGSize) -> some Gesture {
        let unit = min(size.width, size.height)
        let maxPull = unit * 0.34

        let drag = DragGesture(minimumDistance: 0)
            .onChanged { value in
                isFlying = false
                isAiming = true
                // Clamp pull magnitude so power stays bounded.
                var p = value.translation
                let mag = hypot(p.width, p.height)
                if mag > maxPull, mag > 0 {
                    p.width = p.width / mag * maxPull
                    p.height = p.height / mag * maxPull
                }
                pull = p
            }
            .onEnded { value in
                var p = value.translation
                let mag = hypot(p.width, p.height)
                if mag > maxPull, mag > 0 {
                    p.width = p.width / mag * maxPull
                    p.height = p.height / mag * maxPull
                }
                firePull = p
                pull = .zero
                isAiming = false
                if mag > unit * 0.04 {
                    fireStart = Date()
                    isFlying = true
                }
            }

        return LongPressGesture(minimumDuration: 0.08)
            .sequenced(before: drag)
            .onEnded { _ in }
    }

    // MARK: Palette

    static let backdrop = LinearGradient(
        colors: [Color(red: 0.05, green: 0.055, blue: 0.09),
                 Color(red: 0.09, green: 0.10, blue: 0.16)],
        startPoint: .top, endPoint: .bottom
    )
    static let glow = Color(red: 0.45, green: 0.85, blue: 1.0)
    static let warm = Color(red: 1.0, green: 0.62, blue: 0.30)
}

// MARK: - Cannon

private struct CannonView: View {
    let origin: CGPoint
    let aimAngle: CGFloat
    let charge: CGFloat        // 0...1
    let unit: CGFloat

    var body: some View {
        let barrelLen = unit * 0.22
        let barrelW = unit * 0.085
        let tint = HoldDragSlingshotAimView.glow

        ZStack {
            // Barrel
            Capsule()
                .fill(
                    LinearGradient(
                        colors: [Color(red: 0.30, green: 0.34, blue: 0.42),
                                 Color(red: 0.16, green: 0.18, blue: 0.24)],
                        startPoint: .top, endPoint: .bottom
                    )
                )
                .overlay(
                    Capsule()
                        .stroke(tint.opacity(0.25 + charge * 0.55),
                                lineWidth: max(1, unit * 0.01))
                )
                .frame(width: barrelLen, height: barrelW)
                .offset(x: barrelLen / 2)
                .rotationEffect(.radians(Double(aimAngle)))
                .position(origin)

            // Base / wheel
            Circle()
                .fill(
                    RadialGradient(
                        colors: [Color(red: 0.24, green: 0.27, blue: 0.34),
                                 Color(red: 0.12, green: 0.13, blue: 0.18)],
                        center: .center, startRadius: 0, endRadius: unit * 0.13
                    )
                )
                .overlay(
                    Circle().stroke(tint.opacity(0.4), lineWidth: max(1, unit * 0.012))
                )
                .frame(width: unit * 0.20, height: unit * 0.20)
                .position(origin)

            // Charge core glows as power builds.
            Circle()
                .fill(tint)
                .frame(width: unit * 0.07, height: unit * 0.07)
                .opacity(0.35 + Double(charge) * 0.65)
                .blur(radius: unit * 0.01 + Double(charge) * unit * 0.02)
                .position(origin)
        }
    }
}

// MARK: - Trajectory dots

private struct TrajectoryDots: View {
    let points: [CGPoint]
    let unit: CGFloat
    let active: Bool

    var body: some View {
        Canvas { ctx, _ in
            guard points.count > 1 else { return }
            let baseR = unit * 0.013
            let n = points.count
            for (i, p) in points.enumerated() {
                let f = Double(i) / Double(max(1, n - 1))
                // Dots fade & shrink toward the landing for a "lead" look.
                let r = baseR * (1.0 - 0.45 * f)
                let alpha = active ? (0.85 - 0.5 * f) : 0.18
                let rect = CGRect(x: p.x - r, y: p.y - r, width: r * 2, height: r * 2)
                let color = HoldDragSlingshotAimView.glow.opacity(max(0.08, alpha))
                ctx.fill(Path(ellipseIn: rect), with: .color(color))
            }
            // Landing marker.
            if active, let last = points.last {
                let r = unit * 0.03
                let ring = Path(ellipseIn: CGRect(x: last.x - r, y: last.y - r,
                                                  width: r * 2, height: r * 2))
                ctx.stroke(ring, with: .color(HoldDragSlingshotAimView.warm.opacity(0.7)),
                           lineWidth: unit * 0.008)
            }
        }
        .allowsHitTesting(false)
    }
}

// MARK: - Aim guide

private struct AimGuide: View {
    let origin: CGPoint
    let pull: CGSize
    let strength: CGFloat
    let unit: CGFloat

    var body: some View {
        let endX = origin.x + pull.width
        let endY = origin.y + pull.height
        Path { p in
            p.move(to: origin)
            p.addLine(to: CGPoint(x: endX, y: endY))
        }
        .stroke(
            HoldDragSlingshotAimView.warm.opacity(0.25 + Double(strength) * 0.5),
            style: StrokeStyle(lineWidth: max(1, unit * 0.012),
                               lineCap: .round, dash: [unit * 0.03, unit * 0.025])
        )
        .opacity(strength > 0.01 ? 1 : 0)
        .allowsHitTesting(false)
    }
}

// MARK: - Ball

private struct Ball: View {
    let unit: CGFloat

    var body: some View {
        let d = unit * 0.104
        Circle()
            .fill(
                RadialGradient(
                    colors: [Color(red: 1.0, green: 0.95, blue: 0.82),
                             HoldDragSlingshotAimView.warm,
                             Color(red: 0.85, green: 0.40, blue: 0.16)],
                    center: UnitPoint(x: 0.35, y: 0.3),
                    startRadius: 0, endRadius: d * 0.7
                )
            )
            .overlay(
                Circle().stroke(Color.white.opacity(0.35), lineWidth: max(0.5, unit * 0.004))
            )
            .frame(width: d, height: d)
    }
}

// MARK: - Ground

private struct GroundView: View {
    let y: CGFloat
    let width: CGFloat

    var body: some View {
        ZStack(alignment: .top) {
            Path { p in
                p.move(to: CGPoint(x: 0, y: y))
                p.addLine(to: CGPoint(x: width, y: y))
            }
            .stroke(
                LinearGradient(
                    colors: [HoldDragSlingshotAimView.glow.opacity(0.0),
                             HoldDragSlingshotAimView.glow.opacity(0.55),
                             HoldDragSlingshotAimView.glow.opacity(0.0)],
                    startPoint: .leading, endPoint: .trailing
                ),
                lineWidth: 1.5
            )

            // Soft fade beneath the line for depth.
            LinearGradient(
                colors: [HoldDragSlingshotAimView.glow.opacity(0.10),
                         Color.clear],
                startPoint: .top, endPoint: .bottom
            )
            .frame(height: 24)
            .offset(y: y)
        }
        .allowsHitTesting(false)
    }
}
"""###,
        "ges-inertial-marble-throw": ###"""
import SwiftUI

// MARK: - Inertial Marble Tray
// Fling a marble across a bordered tray; it coasts with friction, banks off the
// walls with energy loss, and rolls to a stop, casting a moving contact shadow.
//
// demo == true  -> self-driving loop: auto-launches with a seeded velocity,
//                  banks off the walls, decays to rest, then re-launches.
// demo == false -> interactive: DragGesture finger-follow, release seeds launch
//                  velocity from predictedEndTranslation.

struct InertialMarbleThrowView: View {
    var demo: Bool = false

    @State private var sim = MarbleSim()
    @State private var lastBounce: Int = 0

    var body: some View {
        GeometryReader { geo in
            TimelineView(.animation) { timeline in
                Canvas { context, size in
                    let bounds = MarbleBounds(size: size, radius: marbleRadius(for: size))
                    drawTray(in: &context, size: size)
                    drawShadow(in: &context, bounds: bounds)
                    drawMarble(in: &context, bounds: bounds)
                }
                .onChange(of: timeline.date) { _, now in
                    sim.step(date: now, bounds: MarbleBounds(size: geo.size,
                                                             radius: marbleRadius(for: geo.size)),
                             demo: demo)
                    lastBounce = sim.bounceCount
                }
            }
            .contentShape(Rectangle())
            .gesture(dragGesture(in: geo.size))
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .sensoryFeedback(.impact(weight: .light, intensity: 0.7),
                         trigger: demo ? 0 : lastBounce)
    }

    // MARK: Sizing

    private func marbleRadius(for size: CGSize) -> CGFloat {
        let minSide = min(size.width, size.height)
        return max(7, minSide * 0.13)
    }

    // MARK: Gesture

    private func dragGesture(in size: CGSize) -> some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                guard !demo else { return }
                let bounds = MarbleBounds(size: size, radius: marbleRadius(for: size))
                sim.beginDragIfNeeded(at: value.startLocation, bounds: bounds)
                sim.dragTo(value.location, bounds: bounds)
            }
            .onEnded { value in
                guard !demo else { return }
                let bounds = MarbleBounds(size: size, radius: marbleRadius(for: size))
                let predicted = value.predictedEndTranslation
                let current = value.translation
                let vx = (predicted.width - current.width)
                let vy = (predicted.height - current.height)
                sim.release(velocity: CGVector(dx: vx, dy: vy), bounds: bounds)
            }
    }

    // MARK: Drawing

    private func drawTray(in context: inout GraphicsContext, size: CGSize) {
        let inset: CGFloat = 4
        let rect = CGRect(x: inset, y: inset,
                          width: size.width - inset * 2,
                          height: size.height - inset * 2)
        let corner = min(rect.width, rect.height) * 0.16
        let shape = Path(roundedRect: rect, cornerRadius: corner)

        let floor = Gradient(colors: [
            Color(red: 0.10, green: 0.11, blue: 0.16),
            Color(red: 0.05, green: 0.05, blue: 0.09)
        ])
        context.fill(shape, with: .linearGradient(
            floor,
            startPoint: CGPoint(x: rect.minX, y: rect.minY),
            endPoint: CGPoint(x: rect.maxX, y: rect.maxY)))

        // Inner rim highlight for a raised-tray feel.
        let rimColor = Color(red: 0.42, green: 0.46, blue: 0.58).opacity(0.55)
        context.stroke(shape, with: .color(rimColor), lineWidth: 2)

        let innerRect = rect.insetBy(dx: 3, dy: 3)
        let innerShape = Path(roundedRect: innerRect,
                              cornerRadius: max(0, corner - 3))
        context.stroke(innerShape,
                       with: .color(Color(red: 0.0, green: 0.0, blue: 0.0).opacity(0.35)),
                       lineWidth: 1.5)
    }

    private func drawShadow(in context: inout GraphicsContext, bounds: MarbleBounds) {
        let p = sim.displayPosition(in: bounds)
        let r = bounds.radius
        // Shadow drifts slightly below/right of the marble and softens with height-feel.
        let shadowRect = CGRect(x: p.x - r * 1.05 + 3,
                                y: p.y - r * 0.55 + r * 0.85,
                                width: r * 2.1,
                                height: r * 1.05)
        var shadowCtx = context
        shadowCtx.addFilter(.blur(radius: r * 0.35))
        shadowCtx.fill(Path(ellipseIn: shadowRect),
                       with: .color(Color(red: 0, green: 0, blue: 0).opacity(0.45)))
    }

    private func drawMarble(in context: inout GraphicsContext, bounds: MarbleBounds) {
        let p = sim.displayPosition(in: bounds)
        let r = bounds.radius
        let rect = CGRect(x: p.x - r, y: p.y - r, width: r * 2, height: r * 2)
        let sphere = Path(ellipseIn: rect)

        // Body: cool glass marble with an off-center light center.
        let body = Gradient(stops: [
            .init(color: Color(red: 0.55, green: 0.78, blue: 0.95), location: 0.0),
            .init(color: Color(red: 0.24, green: 0.46, blue: 0.78), location: 0.45),
            .init(color: Color(red: 0.08, green: 0.16, blue: 0.36), location: 1.0)
        ])
        context.fill(sphere, with: .radialGradient(
            body,
            center: CGPoint(x: p.x - r * 0.32, y: p.y - r * 0.36),
            startRadius: 0,
            endRadius: r * 1.7))

        // Rim shade for volume.
        context.stroke(sphere,
                       with: .color(Color(red: 0, green: 0, blue: 0).opacity(0.35)),
                       lineWidth: max(1, r * 0.06))

        // Specular highlight.
        let hi = CGRect(x: p.x - r * 0.55, y: p.y - r * 0.62,
                        width: r * 0.7, height: r * 0.5)
        context.fill(Path(ellipseIn: hi),
                     with: .color(Color(red: 1, green: 1, blue: 1).opacity(0.85)))

        // Tiny secondary glint.
        let glint = CGRect(x: p.x + r * 0.2, y: p.y + r * 0.28,
                           width: r * 0.22, height: r * 0.18)
        context.fill(Path(ellipseIn: glint),
                     with: .color(Color(red: 1, green: 1, blue: 1).opacity(0.35)))
    }
}

// MARK: - Bounds helper

private struct MarbleBounds {
    let size: CGSize
    let radius: CGFloat

    // Playable rect (tray interior) the marble center is confined to.
    var inset: CGFloat { 7 + radius }
    var minX: CGFloat { inset }
    var maxX: CGFloat { max(inset, size.width - inset) }
    var minY: CGFloat { inset }
    var maxY: CGFloat { max(inset, size.height - inset) }
    var center: CGPoint { CGPoint(x: size.width / 2, y: size.height / 2) }
}

// MARK: - Inertial simulation (reference type: safe to mutate from onChange)

private final class MarbleSim {
    enum Phase { case idle, dragging, free }

    var position: CGPoint = .zero
    var velocity: CGVector = .zero
    var phase: Phase = .idle
    var bounceCount: Int = 0

    private var lastTick: Date?
    private var seeded = false
    private var restTimer: TimeInterval = 0      // time spent essentially at rest
    private var demoLaunchTimer: TimeInterval = 0 // safety re-launch guard

    private let friction: CGFloat = 1.6      // per-second velocity damping coefficient
    private let restitution: CGFloat = 0.72  // wall energy retained on bounce
    private let stopSpeed: CGFloat = 8       // px/s below which we consider "resting"

    // MARK: Step

    func step(date: Date, bounds: MarbleBounds, demo: Bool) {
        guard bounds.size.width > 1, bounds.size.height > 1 else { return }

        if !seeded {
            seeded = true
            position = bounds.center
            if demo { seedLaunch(in: bounds) } else { phase = .idle }
        }

        let dt = clampedDelta(to: date)
        guard dt > 0 else { return }

        if phase == .dragging {
            confine(to: bounds) // keep finger-following marble inside the tray
            return
        }

        integrate(dt: dt, bounds: bounds)

        let speed = hypot(velocity.dx, velocity.dy)
        if speed < stopSpeed {
            velocity = .zero
            restTimer += dt
            if phase == .free { phase = .idle }
        } else {
            restTimer = 0
        }

        if demo {
            demoLaunchTimer += dt
            // Re-launch once it has settled, or as a hard safety after ~3.4s.
            if (phase == .idle && restTimer > 0.5) || demoLaunchTimer > 3.4 {
                seedLaunch(in: bounds)
            }
        }
    }

    private func integrate(dt: CGFloat, bounds: MarbleBounds) {
        // Semi-implicit: advance position, apply friction, then resolve walls.
        position.x += velocity.dx * dt
        position.y += velocity.dy * dt

        let damp = max(0, 1 - friction * dt)
        velocity.dx *= damp
        velocity.dy *= damp

        reflectWalls(bounds: bounds)
    }

    private func reflectWalls(bounds: MarbleBounds) {
        var didBounce = false

        if position.x < bounds.minX {
            position.x = bounds.minX
            if velocity.dx < 0 { velocity.dx = -velocity.dx * restitution; didBounce = true }
        } else if position.x > bounds.maxX {
            position.x = bounds.maxX
            if velocity.dx > 0 { velocity.dx = -velocity.dx * restitution; didBounce = true }
        }

        if position.y < bounds.minY {
            position.y = bounds.minY
            if velocity.dy < 0 { velocity.dy = -velocity.dy * restitution; didBounce = true }
        } else if position.y > bounds.maxY {
            position.y = bounds.maxY
            if velocity.dy > 0 { velocity.dy = -velocity.dy * restitution; didBounce = true }
        }

        if didBounce { bounceCount &+= 1 }
    }

    // MARK: Launch / drag

    private func seedLaunch(in bounds: MarbleBounds) {
        // Start near a corner-ish point and throw across the tray on a diagonal.
        let startX = bounds.minX + (bounds.maxX - bounds.minX) * 0.22
        let startY = bounds.maxY - (bounds.maxY - bounds.minY) * 0.18
        position = CGPoint(x: startX, y: startY)

        let minSide = max(1, min(bounds.size.width, bounds.size.height))
        let base = minSide * 6.0 // scale launch speed to the tile so it banks a couple walls
        // Alternate the throw direction each launch for variety.
        let dir: CGFloat = (bounceCount % 2 == 0) ? 1 : -1
        velocity = CGVector(dx: base * 0.95 * dir, dy: -base * 0.75)
        phase = .free
        restTimer = 0
        demoLaunchTimer = 0
    }

    func beginDragIfNeeded(at start: CGPoint, bounds: MarbleBounds) {
        guard phase != .dragging else { return }
        phase = .dragging
        velocity = .zero
        restTimer = 0
        demoLaunchTimer = 0
    }

    func dragTo(_ location: CGPoint, bounds: MarbleBounds) {
        position = location
        confine(to: bounds)
    }

    func release(velocity v: CGVector, bounds: MarbleBounds) {
        // Tune raw predicted-translation delta into px/s. predictedEndTranslation
        // already represents the projected fling; scale gives it real momentum.
        let k: CGFloat = 5.0
        velocity = CGVector(dx: v.dx * k, dy: v.dy * k)
        phase = .free
        restTimer = 0
    }

    // MARK: Helpers

    private func confine(to bounds: MarbleBounds) {
        position.x = min(max(position.x, bounds.minX), bounds.maxX)
        position.y = min(max(position.y, bounds.minY), bounds.maxY)
    }

    private func clampedDelta(to date: Date) -> CGFloat {
        defer { lastTick = date }
        guard let last = lastTick else { return 0 }
        let raw = date.timeIntervalSince(last)
        if raw <= 0 { return 0 }
        return CGFloat(min(raw, 1.0 / 30.0)) // clamp so a stalled frame can't teleport
    }

    func displayPosition(in bounds: MarbleBounds) -> CGPoint {
        if position == .zero { return bounds.center }
        return position
    }
}
"""###,
        "ges-jelly-drag-blob": ###"""
import SwiftUI

// MARK: - Jelly Drag Blob
// Drag a soft blob: its trailing edge lags into a teardrop tip while the
// leading edge bulges; release lets it wobble back round like gelatin.
// The deformation lives in the Shape's animatableData so the release spring
// actually re-evaluates the silhouette each frame (that IS the jiggle).

struct JellyDragBlobView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { proxy in
            let size: CGSize = proxy.size
            ZStack {
                JellyBackground()
                if demo {
                    DemoBlob(size: size)
                } else {
                    InteractiveBlob(size: size)
                }
            }
            .frame(width: size.width, height: size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }
}

// MARK: - Shared stretch clamp helper

// Caps the stretch vector magnitude so fast drags can't blow up the silhouette.
private func clampStretch(_ v: CGVector, baseRadius: CGFloat) -> CGVector {
    let mag: CGFloat = hypot(v.dx, v.dy)
    let cap: CGFloat = baseRadius * 1.2
    guard mag > cap, mag > 0 else { return v }
    let scale: CGFloat = cap / mag
    return CGVector(dx: v.dx * scale, dy: v.dy * scale)
}

// MARK: - Background

private struct JellyBackground: View {
    var body: some View {
        LinearGradient(
            colors: [
                Color(red: 0.05, green: 0.05, blue: 0.09),
                Color(red: 0.10, green: 0.09, blue: 0.16)
            ],
            startPoint: .topLeading,
            endPoint: .bottomTrailing
        )
    }
}

// MARK: - Demo (self-driving) variant

private struct DemoBlob: View {
    let size: CGSize

    // ~3.2s loop. Speed eases via sin^2 so the blob stretches while moving
    // and rounds out at the slow points of the orbit — "wobbles round when it pauses".
    private let period: Double = 3.2

    var body: some View {
        TimelineView(.animation) { context in
            let t: Double = context.date.timeIntervalSinceReferenceDate
            let phase: Double = (t.truncatingRemainder(dividingBy: period)) / period
            let state = orbitState(phase: phase)
            BlobBody(
                center: state.center,
                stretch: state.stretch,
                baseRadius: baseRadius
            )
        }
    }

    private var baseRadius: CGFloat {
        min(size.width, size.height) * 0.26
    }

    private var orbitCenter: CGPoint {
        CGPoint(x: size.width / 2, y: size.height / 2)
    }

    private func orbitState(phase: Double) -> (center: CGPoint, stretch: CGVector) {
        // Eased angular progress: fast through the middle, slow at the ends.
        let eased: Double = phase - (sin(2 * .pi * phase) / (2 * .pi))
        let angle: Double = eased * 2 * .pi

        let orbitR: CGFloat = baseRadius * 0.55
        let cx: CGFloat = orbitCenter.x + orbitR * CGFloat(cos(angle))
        let cy: CGFloat = orbitCenter.y + orbitR * CGFloat(sin(angle) * 0.7)
        let center = CGPoint(x: cx, y: cy)

        // Analytic tangential velocity of the eased orbit drives the stretch.
        let speed: Double = pow(sin(.pi * phase), 2) // 0 at ends, 1 mid-loop
        let vScale: CGFloat = baseRadius * 1.1
        let dx: CGFloat = -CGFloat(sin(angle)) * vScale * CGFloat(speed)
        let dy: CGFloat = CGFloat(cos(angle)) * 0.7 * vScale * CGFloat(speed)

        return (center, clampStretch(CGVector(dx: dx, dy: dy), baseRadius: baseRadius))
    }
}

// MARK: - Interactive variant

private struct InteractiveBlob: View {
    let size: CGSize

    @State private var center: CGPoint = .zero
    @State private var stretch: CGVector = .zero
    @State private var didPlace: Bool = false

    var body: some View {
        BlobBody(center: resolvedCenter, stretch: stretch, baseRadius: baseRadius)
            .contentShape(Rectangle())
            .gesture(dragGesture)
            .onAppear { placeIfNeeded() }
    }

    private var baseRadius: CGFloat {
        min(size.width, size.height) * 0.26
    }

    private var home: CGPoint {
        CGPoint(x: size.width / 2, y: size.height / 2)
    }

    private var resolvedCenter: CGPoint {
        didPlace ? center : home
    }

    private func placeIfNeeded() {
        guard !didPlace else { return }
        center = home
        didPlace = true
    }

    private var dragGesture: some Gesture {
        // minimumDistance: 0 so the blob wins inside a ScrollView.
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                placeIfNeeded()
                // Track the finger 1:1 (no animation) for a live, tactile feel.
                center = CGPoint(
                    x: home.x + value.translation.width,
                    y: home.y + value.translation.height
                )
                // Derive a velocity-like vector from predictedEndTranslation
                // (iOS 17 safe) and feed it into the live stretch.
                let raw: CGVector = predictedVelocity(value)
                stretch = clampStretch(scaledVelocity(raw), baseRadius: baseRadius)
            }
            .onEnded { _ in
                // One spring drives BOTH the silhouette wobble (animatableData)
                // and the glide home — overshooting through round.
                withAnimation(.interpolatingSpring(stiffness: 170, damping: 12)) {
                    stretch = .zero
                    center = home
                }
            }
    }

    // predictedEndTranslation - translation approximates the throw direction
    // and magnitude using only APIs guaranteed on iOS 17.
    private func predictedVelocity(_ value: DragGesture.Value) -> CGVector {
        let pred: CGSize = value.predictedEndTranslation
        return CGVector(
            dx: pred.width - value.translation.width,
            dy: pred.height - value.translation.height
        )
    }

    private func scaledVelocity(_ v: CGVector) -> CGVector {
        // Compress the predicted delta into a stretch-sized vector.
        let k: CGFloat = 2.0
        return CGVector(dx: v.dx * k, dy: v.dy * k)
    }
}

// MARK: - Shared blob body (fill + specular highlight)

private struct BlobBody: View {
    let center: CGPoint
    let stretch: CGVector
    let baseRadius: CGFloat

    var body: some View {
        ZStack {
            shape
                .fill(bodyGradient)
                .overlay(rim)
                .overlay(specular)
                .shadow(color: Color(red: 0.30, green: 0.55, blue: 0.95).opacity(0.35),
                        radius: 14, x: 0, y: 8)
        }
    }

    private var shape: JellyDragBlobView_BlobShape {
        JellyDragBlobView_BlobShape(center: center, stretch: stretch, baseRadius: baseRadius)
    }

    private var bodyGradient: LinearGradient {
        LinearGradient(
            colors: [
                Color(red: 0.45, green: 0.78, blue: 1.00),
                Color(red: 0.30, green: 0.50, blue: 0.96),
                Color(red: 0.42, green: 0.30, blue: 0.92)
            ],
            startPoint: .top,
            endPoint: .bottom
        )
    }

    private var rim: some View {
        shape.stroke(Color.white.opacity(0.18), lineWidth: 1.0)
    }

    // A small clipped specular highlight sells the gelatin sheen.
    private var specular: some View {
        let r: CGFloat = baseRadius
        return Ellipse()
            .fill(
                RadialGradient(
                    colors: [Color.white.opacity(0.55), Color.white.opacity(0.0)],
                    center: .center,
                    startRadius: 0,
                    endRadius: r * 0.6
                )
            )
            .frame(width: r * 0.9, height: r * 0.6)
            .position(x: center.x - r * 0.28, y: center.y - r * 0.34)
            .clipShape(shape)
            .allowsHitTesting(false)
    }
}

// MARK: - Animatable teardrop shape

private struct JellyDragBlobView_BlobShape: Shape {
    var center: CGPoint
    var stretch: CGVector
    var baseRadius: CGFloat

    // Expose the stretch (and center) through animatableData so the release
    // spring re-evaluates path(in:) every frame — without this the wobble dies.
    var animatableData: AnimatablePair<
        AnimatablePair<CGFloat, CGFloat>,
        AnimatablePair<CGFloat, CGFloat>
    > {
        get {
            AnimatablePair(
                AnimatablePair(stretch.dx, stretch.dy),
                AnimatablePair(center.x, center.y)
            )
        }
        set {
            stretch = CGVector(dx: newValue.first.first, dy: newValue.first.second)
            center = CGPoint(x: newValue.second.first, y: newValue.second.second)
        }
    }

    func path(in rect: CGRect) -> Path {
        let mag: CGFloat = hypot(stretch.dx, stretch.dy)

        // Near-rest: clean circle (avoids divide-by-zero on direction).
        guard mag > 0.5 else {
            let d: CGFloat = baseRadius * 2
            let origin = CGPoint(x: center.x - baseRadius, y: center.y - baseRadius)
            return Path(ellipseIn: CGRect(origin: origin, size: CGSize(width: d, height: d)))
        }

        let dirX: CGFloat = stretch.dx / mag
        let dirY: CGFloat = stretch.dy / mag
        let motionAngle: Double = atan2(Double(dirY), Double(dirX))

        // Deform amount in [0, 0.85] of baseRadius.
        let cap: CGFloat = baseRadius * 0.85
        let deform: CGFloat = min(mag, cap) / baseRadius

        return teardropPath(motionAngle: motionAngle, deform: deform)
    }

    private func teardropPath(motionAngle: Double, deform: CGFloat) -> Path {
        var path = Path()
        let samples: Int = 60
        let twoPi: Double = 2 * .pi

        for i in 0...samples {
            let theta: Double = (Double(i) / Double(samples)) * twoPi
            let radius: CGFloat = radiusAt(theta: theta, motionAngle: motionAngle, deform: deform)
            let px: CGFloat = center.x + radius * CGFloat(cos(theta))
            let py: CGFloat = center.y + radius * CGFloat(sin(theta))
            let point = CGPoint(x: px, y: py)
            if i == 0 {
                path.move(to: point)
            } else {
                path.addLine(to: point)
            }
        }
        path.closeSubpath()
        return path
    }

    // Asymmetric radial profile: leading pole bulges, trailing pole pulls into a tip.
    private func radiusAt(theta: Double, motionAngle: Double, deform: CGFloat) -> CGFloat {
        // cos(theta - motionAngle): +1 at leading pole, -1 at trailing pole.
        let lead: CGFloat = CGFloat(cos(theta - motionAngle))

        // Leading side bulges outward (positive lead), trailing side flattens then
        // spikes into a teardrop tip. Cubic term sharpens the trailing tip.
        let bulge: CGFloat = lead * deform * 0.55
        let trailingTip: CGFloat = max(0, -lead) // 0..1 on the trailing half
        let tip: CGFloat = pow(trailingTip, 2.0) * deform * 0.95

        // Slight lateral squash keeps volume believable on fast drags.
        let squash: CGFloat = (1 - abs(lead)) * deform * 0.18

        let factor: CGFloat = 1.0 + bulge + tip - squash
        return baseRadius * max(0.35, factor)
    }
}
"""###,
        "ges-long-press-melt": ###"""
import SwiftUI

/// Long-Press Melt Button
/// Hold the button and it softens, drooping and sagging while gooey teardrop
/// drips form and lengthen along the bottom edge; release springs it back solid.
///
/// The goo is achieved with a Canvas metaball: a rounded-rect body plus several
/// drip circles are drawn into a single `drawLayer` with `.alphaThreshold` + `.blur`
/// filters so overlapping shapes fuse into one liquid mass. That mass is used as a
/// `.mask` over a gradient so the button keeps its color and a glossy highlight.
///
/// Redraw engine is `TimelineView(.animation)` for BOTH demo and interactive modes
/// (PhaseAnimator hands the closure a discrete phase, which would snap the Canvas
/// rather than melt it smoothly). `meltLevel` is derived from time/state each tick.
struct LongPressMeltView: View {
    var demo: Bool = false

    // Interactive press state.
    @State private var pressStart: Date? = nil
    @State private var releaseStart: Date? = nil
    @State private var releaseFromLevel: CGFloat = 0

    // Time to reach full melt while holding.
    private let chargeDuration: Double = 1.6
    // Bouncy snap-back duration on release.
    private let releaseDuration: Double = 0.9

    var body: some View {
        GeometryReader { geo in
            TimelineView(.animation) { timeline in
                let now = timeline.date
                let level = currentMeltLevel(now: now)
                meltCanvas(level: level, size: geo.size)
            }
            .frame(maxWidth: .infinity, maxHeight: .infinity)
            .contentShape(Rectangle())
            // Keep the gesture attached in both modes; in demo, route the press to
            // subviews so the self-driving TimelineView loop owns the animation.
            // (An `Optional` gesture via `demo ? nil : pressGesture` does NOT compile
            // on iOS 17 because Optional does not conform to Gesture.)
            .gesture(pressGesture, including: demo ? .subviews : .all)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // MARK: - Melt level

    /// Returns the current melt amount 0...1 for this frame.
    private func currentMeltLevel(now: Date) -> CGFloat {
        if demo {
            return demoMeltLevel(now: now)
        }
        return interactiveMeltLevel(now: now)
    }

    /// Self-driving loop: rest → sag+drip → bouncy snap-back → rest, on ~3.2s.
    private func demoMeltLevel(now: Date) -> CGFloat {
        let period: Double = 3.2
        let t = now.timeIntervalSinceReferenceDate.truncatingRemainder(dividingBy: period) / period
        // Hold a short solid beat, ramp up with ease, hold full briefly, then a
        // bouncy spring snap-back to solid.
        if t < 0.12 {
            return 0
        } else if t < 0.55 {
            let p = (t - 0.12) / 0.43
            return easeInOut(p)
        } else if t < 0.62 {
            return 1
        } else {
            let p = (t - 0.62) / 0.38
            return springBack(from: 1, progress: p)
        }
    }

    /// Interactive: while pressed, melt grows; on release it springs back to solid.
    private func interactiveMeltLevel(now: Date) -> CGFloat {
        if let start = pressStart {
            let elapsed = now.timeIntervalSince(start)
            return clamp01(CGFloat(elapsed / chargeDuration))
        }
        if let rel = releaseStart {
            let elapsed = now.timeIntervalSince(rel)
            let p = CGFloat(elapsed / releaseDuration)
            if p >= 1 { return 0 }
            return springBack(from: releaseFromLevel, progress: Double(p))
        }
        return 0
    }

    // MARK: - Gesture

    private var pressGesture: some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { _ in
                // DragGesture does not keep firing while stationary, so we record a
                // start instant once and integrate elapsed time in the timeline.
                if pressStart == nil {
                    pressStart = Date()
                    releaseStart = nil
                }
            }
            .onEnded { _ in
                let level = interactiveMeltLevel(now: Date())
                releaseFromLevel = level
                releaseStart = Date()
                pressStart = nil
            }
    }

    // MARK: - Canvas

    @ViewBuilder
    private func meltCanvas(level: CGFloat, size: CGSize) -> some View {
        let metrics = layout(for: size)
        // The fused metaball mass (alphaThreshold + blur) acts as a mask so the
        // gradient body + highlight show through, keeping the button colorful.
        gradientBody(metrics: metrics, level: level)
            .mask(
                Canvas { context, _ in
                    drawGooMask(into: &context, metrics: metrics, level: level)
                }
            )
            .overlay(glossHighlight(metrics: metrics, level: level))
            .overlay(label(metrics: metrics, level: level))
    }

    /// Draws the rounded-rect body and the drip circles into one filtered layer so
    /// overlapping shapes merge into a single liquid blob.
    private func drawGooMask(into context: inout GraphicsContext,
                             metrics: Metrics,
                             level: CGFloat) {
        let blur = metrics.blobRadius * (0.55 + level * 0.35)
        context.addFilter(.alphaThreshold(min: 0.5, color: .white))
        context.addFilter(.blur(radius: blur))
        context.drawLayer { layer in
            // Body sags downward as it melts.
            let sag = metrics.maxSag * level
            let bodyRect = CGRect(
                x: metrics.bodyRect.minX,
                y: metrics.bodyRect.minY,
                width: metrics.bodyRect.width,
                height: metrics.bodyRect.height + sag * 0.6
            )
            let corner = metrics.corner + sag * 0.5
            let bodyPath = Path(roundedRect: bodyRect, cornerRadius: corner)
            layer.fill(bodyPath, with: .color(.white))

            for blob in drips(metrics: metrics, level: level) {
                let circle = Path(ellipseIn: CGRect(
                    x: blob.center.x - blob.radius,
                    y: blob.center.y - blob.radius,
                    width: blob.radius * 2,
                    height: blob.radius * 2
                ))
                layer.fill(circle, with: .color(.white))
            }
        }
    }

    /// Computes drip blob centers + radii along the bottom edge for this melt level.
    private func drips(metrics: Metrics, level: CGFloat) -> [(center: CGPoint, radius: CGFloat)] {
        guard level > 0.02 else { return [] }
        var result: [(center: CGPoint, radius: CGFloat)] = []
        let baseY = metrics.bodyRect.maxY + metrics.maxSag * level * 0.6
        let count = metrics.dripCount
        for i in 0..<count {
            // Each drip has its own phase so they grow at slightly different rates.
            let phase = CGFloat(i) / CGFloat(max(count - 1, 1))
            let xFraction = 0.18 + phase * 0.64
            let x = metrics.bodyRect.minX + metrics.bodyRect.width * xFraction
            // Stagger thresholds so drips appear progressively, center ones first.
            let centerBias = 1 - abs(phase - 0.5) * 1.4
            let threshold = 0.12 + (1 - clamp01(centerBias)) * 0.22
            guard level > threshold else { continue }
            let local = clamp01((level - threshold) / (1 - threshold))
            let eased = easeOut(local)
            // The drip hangs down; its length grows with melt, tip stays in-frame.
            let length = metrics.maxDripLength * eased * (0.7 + centerBias * 0.3)
            let radius = metrics.blobRadius * (0.5 + eased * 0.55)
            let tipY = min(baseY + length, metrics.maxTipY)
            result.append((center: CGPoint(x: x, y: tipY), radius: radius))

            // A thin neck blob connecting the tip toward the body keeps the goo fused.
            let neckY = (baseY + tipY) / 2
            let neckR = radius * 0.75
            result.append((center: CGPoint(x: x, y: neckY), radius: neckR))
        }
        return result
    }

    // MARK: - Decorative layers

    private func gradientBody(metrics: Metrics, level: CGFloat) -> some View {
        // Color warms slightly as it heats / melts.
        let top = Color(red: 0.42 + Double(level) * 0.14,
                        green: 0.36,
                        blue: 0.95 - Double(level) * 0.12)
        let bottom = Color(red: 0.78 + Double(level) * 0.12,
                           green: 0.28,
                           blue: 0.62)
        return LinearGradient(
            colors: [top, bottom],
            startPoint: .top,
            endPoint: .bottom
        )
        .frame(width: metrics.size.width, height: metrics.size.height)
    }

    private func glossHighlight(metrics: Metrics, level: CGFloat) -> some View {
        // A soft top highlight that fades as the surface liquefies.
        let r = metrics.bodyRect
        let glossRect = CGRect(
            x: r.minX + r.width * 0.12,
            y: r.minY + r.height * 0.16,
            width: r.width * 0.76,
            height: r.height * 0.30
        )
        return Capsule()
            .fill(
                LinearGradient(
                    colors: [Color.white.opacity(0.55), Color.white.opacity(0.0)],
                    startPoint: .top,
                    endPoint: .bottom
                )
            )
            .frame(width: glossRect.width, height: glossRect.height)
            .position(x: glossRect.midX, y: glossRect.midY)
            .opacity(0.9 - Double(level) * 0.6)
            .blendMode(.screen)
            .allowsHitTesting(false)
            .mask(
                Canvas { context, _ in
                    drawGooMask(into: &context, metrics: metrics, level: level)
                }
            )
    }

    private func label(metrics: Metrics, level: CGFloat) -> some View {
        let r = metrics.bodyRect
        // Label drips with the body and fades as goo takes over.
        return Text("HOLD")
            .font(.system(size: metrics.fontSize, weight: .heavy, design: .rounded))
            .kerning(metrics.fontSize * 0.08)
            .foregroundStyle(Color.white.opacity(0.92))
            .scaleEffect(y: 1 + level * 0.18, anchor: .top)
            .position(x: r.midX, y: r.midY + metrics.maxSag * level * 0.35)
            .opacity(0.95 - Double(level) * 0.7)
            .allowsHitTesting(false)
    }

    // MARK: - Layout

    private struct Metrics {
        let size: CGSize
        let bodyRect: CGRect
        let corner: CGFloat
        let blobRadius: CGFloat
        let maxSag: CGFloat
        let maxDripLength: CGFloat
        let maxTipY: CGFloat
        let dripCount: Int
        let fontSize: CGFloat
    }

    /// All geometry scales to the GeometryReader size so the goo fuses correctly in
    /// both a 120pt tile and a large detail area.
    private func layout(for size: CGSize) -> Metrics {
        let w = size.width
        let h = size.height
        let minDim = min(w, h)

        let bodyW = w * 0.62
        let bodyH = h * 0.30
        // Button sits upper-middle so drips have room to hang in-frame.
        let bodyX = (w - bodyW) / 2
        let bodyY = h * 0.22
        let bodyRect = CGRect(x: bodyX, y: bodyY, width: bodyW, height: bodyH)

        let corner = bodyH * 0.42
        let blobRadius = minDim * 0.052
        let maxSag = bodyH * 0.55
        let maxDripLength = h * 0.30
        // Clamp tips so the longest drip never leaves the frame.
        let maxTipY = h * 0.94

        return Metrics(
            size: size,
            bodyRect: bodyRect,
            corner: corner,
            blobRadius: blobRadius,
            maxSag: maxSag,
            maxDripLength: maxDripLength,
            maxTipY: maxTipY,
            dripCount: 4,
            fontSize: bodyH * 0.42
        )
    }

    // MARK: - Math helpers

    private func clamp01(_ x: CGFloat) -> CGFloat {
        min(max(x, 0), 1)
    }

    private func easeInOut(_ x: Double) -> CGFloat {
        let c = min(max(x, 0), 1)
        return CGFloat(c * c * (3 - 2 * c))
    }

    private func easeOut(_ x: CGFloat) -> CGFloat {
        let c = clamp01(x)
        return 1 - (1 - c) * (1 - c)
    }

    /// Analytic damped-spring decay from `from` toward 0 over progress 0...1,
    /// producing the bouncy snap-back. Clamped to never go below 0.
    private func springBack(from: CGFloat, progress: Double) -> CGFloat {
        let p = min(max(progress, 0), 1)
        // Damped cosine: starts at `from`, overshoots slightly through 0, settles.
        let decay = exp(-5.5 * p)
        let osc = cos(7.5 * p)
        let value = from * CGFloat(decay * osc)
        return max(value, 0)
    }
}
"""###,
        "ges-magnetic-cursor-ferrofluid": ###"""
import SwiftUI

// MARK: - Ferrofluid Magnet Pull
// Drag a magnet over a pool of dark fluid: spiky tendrils rise and lean toward it,
// merging and splitting via a metaball (alphaThreshold + blur) Canvas, slumping flat
// when the magnet leaves. demo == true self-drives a slow figure-eight.

public struct MagneticCursorFerrofluidView: View {
    public var demo: Bool = false

    public init(demo: Bool = false) {
        self.demo = demo
    }

    public var body: some View {
        GeometryReader { geo in
            FerrofluidStage(demo: demo, size: geo.size)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }
}

// MARK: - Stage

private struct FerrofluidStage: View {
    let demo: Bool
    let size: CGSize

    // Interactive state: where the magnet currently is (in points), whether it is engaged,
    // and the reference time used for the closed-form springy slump after release.
    @State private var dragPoint: CGPoint? = nil
    @State private var lastPoint: CGPoint = .zero
    @State private var releaseTime: Double? = nil
    @State private var engagedSince: Double = 0

    var body: some View {
        TimelineView(.animation) { timeline in
            let now = timeline.date.timeIntervalSinceReferenceDate
            let resolved = resolveMagnet(now: now)
            ZStack {
                background
                fluidCanvas(magnet: resolved.point,
                            strength: resolved.strength)
                magnetIndicator(at: resolved.point,
                                strength: resolved.strength)
            }
            .contentShape(Rectangle())
            .gesture(dragGesture(now: now))
        }
        .clipped()
    }

    // MARK: Layers

    private var background: some View {
        LinearGradient(
            colors: [
                Color(red: 0.07, green: 0.08, blue: 0.13),
                Color(red: 0.03, green: 0.03, blue: 0.06)
            ],
            startPoint: .top,
            endPoint: .bottom
        )
    }

    private func fluidCanvas(magnet: CGPoint, strength: Double) -> some View {
        let unit = min(size.width, size.height)
        let blur = max(unit * 0.045, 2.0)
        let threshold = 0.55
        let fluid = Color(red: 0.10, green: 0.11, blue: 0.20)

        return Canvas { context, _ in
            context.addFilter(.alphaThreshold(min: threshold, color: fluid))
            context.addFilter(.blur(radius: blur))
            context.drawLayer { layer in
                let blobs = buildBlobs(magnet: magnet, strength: strength, unit: unit)
                for blob in blobs {
                    let rect = CGRect(
                        x: blob.center.x - blob.radius,
                        y: blob.center.y - blob.radius,
                        width: blob.radius * 2,
                        height: blob.radius * 2
                    )
                    layer.fill(Path(ellipseIn: rect), with: .color(.white))
                }
            }
        }
        // A subtle sheen highlight overlaid via blend so the fluid reads metallic.
        .overlay(sheenOverlay(unit: unit))
    }

    private func sheenOverlay(unit: CGFloat) -> some View {
        LinearGradient(
            colors: [
                Color(red: 0.45, green: 0.50, blue: 0.75).opacity(0.0),
                Color(red: 0.55, green: 0.62, blue: 0.90).opacity(0.18),
                Color(red: 0.10, green: 0.12, blue: 0.22).opacity(0.0)
            ],
            startPoint: .leading,
            endPoint: .trailing
        )
        .blendMode(.plusLighter)
        .allowsHitTesting(false)
        .mask(
            Rectangle()
                .frame(height: unit * 0.55)
                .frame(maxHeight: .infinity, alignment: .bottom)
        )
    }

    private func magnetIndicator(at point: CGPoint, strength: Double) -> some View {
        let unit = min(size.width, size.height)
        let r = unit * 0.085
        let glow = 0.25 + 0.55 * strength
        return ZStack {
            Circle()
                .fill(
                    RadialGradient(
                        colors: [
                            Color(red: 0.95, green: 0.55, blue: 0.35).opacity(glow),
                            Color(red: 0.85, green: 0.30, blue: 0.25).opacity(0.0)
                        ],
                        center: .center,
                        startRadius: 0,
                        endRadius: r * 2.4
                    )
                )
                .frame(width: r * 4, height: r * 4)
            Circle()
                .fill(
                    LinearGradient(
                        colors: [
                            Color(red: 0.98, green: 0.72, blue: 0.45),
                            Color(red: 0.80, green: 0.28, blue: 0.22)
                        ],
                        startPoint: .top,
                        endPoint: .bottom
                    )
                )
                .frame(width: r * 1.5, height: r * 1.5)
                .overlay(
                    Circle()
                        .stroke(Color.white.opacity(0.5), lineWidth: max(unit * 0.006, 0.6))
                )
                .shadow(color: .black.opacity(0.4), radius: r * 0.3, y: r * 0.15)
        }
        .position(point)
        .allowsHitTesting(false)
    }

    // MARK: Blob field

    private struct Blob {
        var center: CGPoint
        var radius: CGFloat
    }

    /// Builds the base pool slab plus a row of spikes leaning toward the magnet.
    private func buildBlobs(magnet: CGPoint, strength: Double, unit: CGFloat) -> [Blob] {
        var blobs: [Blob] = []
        let w = size.width
        let h = size.height
        guard w > 1, h > 1 else { return blobs }

        // Base pool: a thick row of overlapping circles along the bottom so the
        // metaball never disappears — guarantees a legible state on every frame.
        let baseY = h * 0.82
        let baseRadius = unit * 0.16
        let baseCount = max(Int((w / (baseRadius * 0.9)).rounded(.up)) + 1, 3)
        for i in 0..<baseCount {
            let frac = baseCount > 1 ? CGFloat(i) / CGFloat(baseCount - 1) : 0.5
            let x = frac * w
            blobs.append(Blob(center: CGPoint(x: x, y: baseY), radius: baseRadius))
        }

        // Spikes: evenly spaced anchors rising from the pool surface.
        let spikeCount = 11
        let surfaceY = baseY - baseRadius * 0.35
        let maxSpike = h * 0.62
        let reach = unit * 1.05

        for i in 0..<spikeCount {
            let frac = CGFloat(i) / CGFloat(spikeCount - 1)
            let anchorX = w * (0.06 + 0.88 * frac)
            let anchor = CGPoint(x: anchorX, y: surfaceY)

            let d = distance(anchor, magnet)
            let falloff = falloffCurve(distance: d, reach: reach)
            let rise = maxSpike * falloff * CGFloat(strength)

            guard rise > unit * 0.02 else { continue }

            // Lean the tip toward the magnet, proportional to height.
            let dirX = magnet.x - anchorX
            let lean = clamp(dirX, -reach, reach) / reach
            let tipLean = lean * rise * 0.55

            // Stack shrinking circles from base to tip.
            let segments = 6
            for s in 0..<segments {
                let t = CGFloat(s) / CGFloat(segments - 1)
                let y = surfaceY - rise * t
                let x = anchorX + tipLean * t * t
                // Radius tapers from fat base to thin tip.
                let baseR = unit * 0.085
                let tipR = unit * 0.018
                let radius = baseR + (tipR - baseR) * t
                blobs.append(Blob(center: CGPoint(x: x, y: y), radius: radius))
            }
        }

        return blobs
    }

    /// Smooth falloff in [0,1]: full strength at the magnet, fading to 0 past `reach`.
    private func falloffCurve(distance: CGFloat, reach: CGFloat) -> CGFloat {
        guard reach > 0 else { return 0 }
        let x = clamp(distance / reach, 0, 1)
        // Smoothstep-ish: emphasizes a sharp local pull.
        let v = 1 - x
        return v * v
    }

    // MARK: Magnet resolution (closed-form so Canvas slump is smooth)

    private struct ResolvedMagnet {
        var point: CGPoint
        var strength: Double
    }

    private func resolveMagnet(now: Double) -> ResolvedMagnet {
        if demo {
            return demoMagnet(now: now)
        }

        if let p = dragPoint {
            // Actively dragging: full strength, smoothly ramping up after engage.
            let t = now - engagedSince
            let s = 1 - exp(-t / 0.18)
            return ResolvedMagnet(point: p, strength: min(1.0, 0.2 + 0.8 * s))
        }

        if let rel = releaseTime {
            // Released: spring-decaying field strength (damped oscillation 1 -> 0).
            let t = now - rel
            let strength = dampedRelease(t)
            return ResolvedMagnet(point: lastPoint, strength: max(0, strength))
        }

        // Idle, untouched: park the magnet just off-pool so a gentle base wobble shows.
        let idle = CGPoint(x: size.width * 0.5, y: size.height * 0.32)
        let pulse = 0.12 + 0.05 * (1 + sin(now * 1.4)) / 2
        return ResolvedMagnet(point: idle, strength: pulse)
    }

    /// Damped spring envelope: starts near 1, overshoots toward 0, settles flat.
    private func dampedRelease(_ t: Double) -> Double {
        guard t >= 0 else { return 1 }
        let decay = exp(-t * 3.2)
        let osc = cos(t * 7.0)
        // Keep it positive-ish but let it wobble as it slumps.
        let env = decay * (0.5 + 0.5 * osc)
        return env
    }

    /// demo mode: slow figure-eight (lemniscate) over the pool surface.
    private func demoMagnet(now: Double) -> ResolvedMagnet {
        let period: Double = 3.4
        let phase = (now.truncatingRemainder(dividingBy: period)) / period
        let theta = phase * 2 * .pi

        // Lemniscate of Gerono: x = sin, y = sin*cos — stays inside bounds when scaled.
        let nx = sin(theta)
        let ny = sin(theta) * cos(theta)

        let cx = size.width * 0.5
        let cy = size.height * 0.40
        let ampX = size.width * 0.34
        let ampY = size.height * 0.22

        let point = CGPoint(x: cx + CGFloat(nx) * ampX,
                            y: cy + CGFloat(ny) * ampY)
        // Pulse strength a little so the fluid breathes; never below a legible floor.
        let strength = 0.78 + 0.22 * (1 + sin(now * 2.1)) / 2
        return ResolvedMagnet(point: point, strength: strength)
    }

    // MARK: Gesture

    private func dragGesture(now: Double) -> some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                if dragPoint == nil {
                    engagedSince = Date().timeIntervalSinceReferenceDate
                }
                dragPoint = value.location
                lastPoint = value.location
                releaseTime = nil
            }
            .onEnded { value in
                lastPoint = value.location
                dragPoint = nil
                releaseTime = Date().timeIntervalSinceReferenceDate
            }
    }

    // MARK: Math helpers

    private func distance(_ a: CGPoint, _ b: CGPoint) -> CGFloat {
        let dx = a.x - b.x
        let dy = a.y - b.y
        return (dx * dx + dy * dy).squareRoot()
    }

    private func clamp(_ v: CGFloat, _ lo: CGFloat, _ hi: CGFloat) -> CGFloat {
        min(max(v, lo), hi)
    }
}
"""###,
        "ges-peel-away-card": ###"""
import SwiftUI
import Foundation

// MARK: - Peel-Away Sticker
//
// Drag the bottom-right corner of the card and it peels up like a sticker:
// a curling, lit underside is revealed, a soft drop shadow trails the lifted
// edge, and the corner snaps flat or tears free depending on release velocity.
//
// Implementation: a pure 2D reflection-fold rendered in a single Canvas.
// Folding corner `c` so it lands at lifted point `c'` means the crease is the
// perpendicular bisector of the segment c -> c'. The lifted flap is the mirror
// of the corner triangle across that crease; the "3D curl" is sold by a
// LinearGradient sheen, brightest at the bend. Renders identically at any size.

public struct PeelAwayCardView: View {
    public var demo: Bool = false

    public init(demo: Bool = false) {
        self.demo = demo
    }

    public var body: some View {
        GeometryReader { geo in
            let box = cardRect(in: geo.size)
            if demo {
                demoCanvas(box: box)
            } else {
                interactiveCanvas(box: box)
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // MARK: Demo (self-driving) branch

    @ViewBuilder
    private func demoCanvas(box: CGRect) -> some View {
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            let progress = demoProgress(at: t)
            let lifted = demoLiftedPoint(box: box, progress: progress)
            peelCanvas(box: box, lifted: lifted, flapOpacity: 1.0)
        }
    }

    /// Eases peel progress 0 -> 0.6 -> 0 on a ~3.2s loop. Never reaches a blank
    /// state: progress 0 is simply the flat, fully-legible card.
    private func demoProgress(at time: TimeInterval) -> CGFloat {
        let period: Double = 3.2
        let phase = (time.truncatingRemainder(dividingBy: period)) / period // 0..1
        // Smooth up-and-down: half a sine so it dwells gently at both ends.
        let wave = sin(phase * .pi) // 0 -> 1 -> 0
        let eased = wave * wave * (3.0 - 2.0 * wave) // smoothstep for softer ease
        return CGFloat(eased) * 0.6
    }

    private func demoLiftedPoint(box: CGRect, progress: CGFloat) -> CGPoint {
        let corner = CGPoint(x: box.maxX, y: box.maxY)
        // Lift along the diagonal toward the card's top-left.
        let diag = CGPoint(x: box.minX - corner.x, y: box.minY - corner.y)
        let liftFraction = progress // up to 0.6 of the way across
        return CGPoint(x: corner.x + diag.x * liftFraction,
                       y: corner.y + diag.y * liftFraction)
    }

    // MARK: Interactive branch

    @ViewBuilder
    private func interactiveCanvas(box: CGRect) -> some View {
        InteractivePeel(box: box, drawFlat: { ctx, size in
            drawFlatCard(in: &ctx, box: box)
        }, drawPeel: { ctx, size, lifted, opacity in
            drawPeel(in: &ctx, size: size, box: box, lifted: lifted, flapOpacity: opacity)
        })
    }

    // MARK: Shared canvas wrapper

    @ViewBuilder
    private func peelCanvas(box: CGRect, lifted: CGPoint, flapOpacity: Double) -> some View {
        Canvas { ctx, size in
            drawPeel(in: &ctx, size: size, box: box, lifted: lifted, flapOpacity: flapOpacity)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }
}

// MARK: - Interactive container

private struct InteractivePeel: View {
    let box: CGRect
    let drawFlat: (inout GraphicsContext, CGSize) -> Void
    let drawPeel: (inout GraphicsContext, CGSize, CGPoint, Double) -> Void

    /// Current lifted-corner location (the destination of the folded corner).
    @State private var lifted: CGPoint?
    @State private var flapOpacity: Double = 1.0
    @State private var torn: Bool = false

    var body: some View {
        Canvas { ctx, size in
            if let lifted, !torn {
                drawPeel(&ctx, size, lifted, flapOpacity)
            } else if torn {
                // Briefly empty while torn free; restored shortly after.
                ctx.opacity = flapOpacity
                drawFlat(&ctx, size)
            } else {
                drawFlat(&ctx, size)
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .contentShape(Rectangle())
        .gesture(dragGesture)
        .sensoryFeedback(.impact(flexibility: .soft), trigger: torn) { _, now in now }
    }

    private var dragGesture: some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                torn = false
                flapOpacity = 1.0
                lifted = clampLifted(value.location, box: box)
            }
            .onEnded { value in
                let predicted = value.predictedEndTranslation
                let velocityMag = hypot(predicted.width - value.translation.width,
                                        predicted.height - value.translation.height)
                let pulled = pullDistance(value.location, box: box)
                // Fast flick OR pulled most of the way across -> tear free.
                if velocityMag > 220 || pulled > tearThreshold(box: box) {
                    tearFree()
                } else {
                    snapFlat()
                }
            }
    }

    private func snapFlat() {
        withAnimation(.spring(response: 0.45, dampingFraction: 0.62)) {
            lifted = CGPoint(x: box.maxX, y: box.maxY)
            flapOpacity = 1.0
        }
        // Once settled flat, drop the flap so we render the clean flat card.
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.5) {
            if let l = lifted, hypot(l.x - box.maxX, l.y - box.maxY) < 2 {
                lifted = nil
            }
        }
    }

    private func tearFree() {
        torn = true
        // Fling the corner away and fade out.
        withAnimation(.easeOut(duration: 0.35)) {
            flapOpacity = 0.0
        }
        // Reset to a fresh flat card so the component stays reusable.
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.55) {
            lifted = nil
            torn = false
            withAnimation(.easeIn(duration: 0.4)) {
                flapOpacity = 1.0
            }
        }
    }

    private func tearThreshold(box: CGRect) -> CGFloat {
        hypot(box.width, box.height) * 0.62
    }

    private func pullDistance(_ point: CGPoint, box: CGRect) -> CGFloat {
        hypot(point.x - box.maxX, point.y - box.maxY)
    }

    /// Keep the lifted point inside a sane region so the crease stays a clean
    /// diagonal across the bottom-right corner.
    private func clampLifted(_ raw: CGPoint, box: CGRect) -> CGPoint {
        let corner = CGPoint(x: box.maxX, y: box.maxY)
        let maxReach = hypot(box.width, box.height) * 0.9
        var dx = raw.x - corner.x
        var dy = raw.y - corner.y
        let d = hypot(dx, dy)
        if d > maxReach, d > 0 {
            let s = maxReach / d
            dx *= s
            dy *= s
        }
        // Bias toward the top-left half-plane so it reads as a lift, not a poke.
        if dx > 0 { dx = 0 }
        if dy > 0 { dy = 0 }
        return CGPoint(x: corner.x + dx, y: corner.y + dy)
    }
}

// MARK: - Geometry & drawing (pure, shared by both modes)

private extension PeelAwayCardView {

    /// Centered card rect that scales with the available size.
    fileprivate func cardRect(in size: CGSize) -> CGRect {
        let inset = min(size.width, size.height) * 0.14
        let side = min(size.width, size.height) - inset * 2
        let w = side
        let h = side
        let x = (size.width - w) / 2
        let y = (size.height - h) / 2
        return CGRect(x: x, y: y, width: w, height: h)
    }

    fileprivate func drawFlatCard(in ctx: inout GraphicsContext, box: CGRect) {
        let rounded = Path(roundedRect: box, cornerRadius: box.width * 0.06)
        ctx.fill(rounded, with: .linearGradient(cardFaceGradient(),
                                                startPoint: box.origin,
                                                endPoint: CGPoint(x: box.maxX, y: box.maxY)))
        // Subtle face emblem so the card reads as content, not a blank slab.
        drawFaceEmblem(in: &ctx, box: box)
        // Hairline border for crispness.
        ctx.stroke(rounded, with: .color(Color(red: 1, green: 1, blue: 1, opacity: 0.10)),
                   lineWidth: 1)
    }

    fileprivate func drawPeel(in ctx: inout GraphicsContext,
                              size: CGSize,
                              box: CGRect,
                              lifted: CGPoint,
                              flapOpacity: Double) {
        let corner = CGPoint(x: box.maxX, y: box.maxY)
        let dist = hypot(lifted.x - corner.x, lifted.y - corner.y)

        // Degenerate / near-flat: just draw the flat card.
        if dist < 1.5 {
            drawFlatCard(in: &ctx, box: box)
            return
        }

        // Crease = perpendicular bisector of corner -> lifted.
        guard let (p1, p2) = creaseIntersections(corner: corner, lifted: lifted, box: box) else {
            drawFlatCard(in: &ctx, box: box)
            return
        }

        // 1) Card face with the triangular hole removed.
        drawFaceWithHole(in: &ctx, box: box, hole: [p1, corner, p2])

        // 2) Revealed surface under the lifted corner (the sticker backing).
        drawRevealedHole(in: &ctx, p1: p1, p2: p2, corner: corner)

        // 3) Soft drop shadow of the flap, offset toward the lift direction.
        drawFlapShadow(in: &ctx, p1: p1, p2: p2, lifted: lifted, corner: corner, opacity: flapOpacity)

        // 4) The lifted flap with its lit, curling underside.
        drawFlap(in: &ctx, p1: p1, p2: p2, lifted: lifted, corner: corner, opacity: flapOpacity)
    }

    // MARK: helpers

    /// Reflect `point` across the line that is the perpendicular bisector of
    /// segment a..b (i.e. the crease for folding `a` onto `b` reflects across it).
    fileprivate func reflect(_ point: CGPoint, acrossBisectorOf a: CGPoint, and b: CGPoint) -> CGPoint {
        // The bisector passes through midpoint m with normal n = (b - a).
        let mx = (a.x + b.x) / 2
        let my = (a.y + b.y) / 2
        let nx = b.x - a.x
        let ny = b.y - a.y
        let nLen2 = nx * nx + ny * ny
        if nLen2 == 0 { return point }
        // Signed distance along normal from the line.
        let d = ((point.x - mx) * nx + (point.y - my) * ny) / nLen2
        return CGPoint(x: point.x - 2 * d * nx, y: point.y - 2 * d * ny)
    }

    /// Where the crease (perp. bisector of corner->lifted) crosses the two card
    /// edges meeting at the bottom-right corner: the right edge (x = maxX) and
    /// the bottom edge (y = maxY).
    fileprivate func creaseIntersections(corner: CGPoint, lifted: CGPoint, box: CGRect) -> (CGPoint, CGPoint)? {
        let mx = (corner.x + lifted.x) / 2
        let my = (corner.y + lifted.y) / 2
        let nx = lifted.x - corner.x   // crease normal direction
        let ny = lifted.y - corner.y
        // Crease line: nx*(x-mx) + ny*(y-my) = 0.

        // Intersect with right edge x = box.maxX  -> solve for y.
        var pRight: CGPoint?
        if abs(ny) > 0.0001 {
            let y = my - (nx * (box.maxX - mx)) / ny
            if y >= box.minY - 0.5 && y <= box.maxY + 0.5 {
                pRight = CGPoint(x: box.maxX, y: min(max(y, box.minY), box.maxY))
            }
        }

        // Intersect with bottom edge y = box.maxY -> solve for x.
        var pBottom: CGPoint?
        if abs(nx) > 0.0001 {
            let x = mx - (ny * (box.maxY - my)) / nx
            if x >= box.minX - 0.5 && x <= box.maxX + 0.5 {
                pBottom = CGPoint(x: min(max(x, box.minX), box.maxX), y: box.maxY)
            }
        }

        guard let r = pRight, let b = pBottom else { return nil }
        return (r, b)
    }

    fileprivate func drawFaceWithHole(in ctx: inout GraphicsContext, box: CGRect, hole: [CGPoint]) {
        let rounded = Path(roundedRect: box, cornerRadius: box.width * 0.06)
        // Clip the face drawing to the card minus the hole triangle.
        ctx.drawLayer { layer in
            layer.clip(to: rounded)
            // Subtract the hole by clipping with inverse of the triangle.
            var holePath = Path()
            holePath.move(to: hole[0])
            holePath.addLine(to: hole[1])
            holePath.addLine(to: hole[2])
            holePath.closeSubpath()
            layer.clip(to: holePath, options: .inverse)

            layer.fill(rounded, with: .linearGradient(self.cardFaceGradient(),
                                                      startPoint: box.origin,
                                                      endPoint: CGPoint(x: box.maxX, y: box.maxY)))
            self.drawFaceEmblem(in: &layer, box: box)
        }
        ctx.stroke(rounded, with: .color(Color(red: 1, green: 1, blue: 1, opacity: 0.10)), lineWidth: 1)
    }

    fileprivate func drawRevealedHole(in ctx: inout GraphicsContext, p1: CGPoint, p2: CGPoint, corner: CGPoint) {
        var hole = Path()
        hole.move(to: p1)
        hole.addLine(to: corner)
        hole.addLine(to: p2)
        hole.closeSubpath()
        // Darker backing surface revealed where the sticker lifted off.
        let backing = Color(red: 0.07, green: 0.08, blue: 0.11)
        ctx.fill(hole, with: .color(backing))
        // A faint inner shading near the crease so the cavity has depth.
        ctx.fill(hole, with: .linearGradient(
            Gradient(colors: [
                Color(red: 0, green: 0, blue: 0, opacity: 0.0),
                Color(red: 0, green: 0, blue: 0, opacity: 0.35)
            ]),
            startPoint: midpoint(p1, p2),
            endPoint: corner))
    }

    fileprivate func drawFlapShadow(in ctx: inout GraphicsContext,
                                    p1: CGPoint, p2: CGPoint,
                                    lifted: CGPoint, corner: CGPoint,
                                    opacity: Double) {
        let liftedCorner = lifted
        var shadow = Path()
        shadow.move(to: p1)
        shadow.addLine(to: liftedCorner)
        shadow.addLine(to: p2)
        shadow.closeSubpath()

        // Offset the shadow toward the lift direction for a floating feel.
        let dir = normalize(CGPoint(x: lifted.x - corner.x, y: lifted.y - corner.y))
        let lift = hypot(lifted.x - corner.x, lifted.y - corner.y)
        let offset = min(lift * 0.10, 14)
        ctx.drawLayer { layer in
            layer.opacity = opacity * 0.5
            layer.translateBy(x: dir.x * offset + 3, y: dir.y * offset + 4)
            layer.addFilter(.blur(radius: max(4, offset)))
            layer.fill(shadow, with: .color(Color(red: 0, green: 0, blue: 0, opacity: 0.55)))
        }
    }

    fileprivate func drawFlap(in ctx: inout GraphicsContext,
                              p1: CGPoint, p2: CGPoint,
                              lifted: CGPoint, corner: CGPoint,
                              opacity: Double) {
        var flap = Path()
        flap.move(to: p1)
        flap.addLine(to: lifted)
        flap.addLine(to: p2)
        flap.closeSubpath()

        // Underside sheen runs from the crease (bright bend) to the lifted tip.
        let creaseMid = midpoint(p1, p2)
        ctx.drawLayer { layer in
            layer.opacity = opacity
            // Backside paper color with a curl gradient — brightest at the bend.
            layer.fill(flap, with: .linearGradient(
                Gradient(stops: [
                    .init(color: Color(red: 0.96, green: 0.95, blue: 0.99), location: 0.0),
                    .init(color: Color(red: 0.82, green: 0.83, blue: 0.90), location: 0.45),
                    .init(color: Color(red: 0.60, green: 0.62, blue: 0.72), location: 1.0)
                ]),
                startPoint: creaseMid,
                endPoint: lifted))

            // A glossy specular streak across the curl.
            layer.fill(flap, with: .linearGradient(
                Gradient(stops: [
                    .init(color: Color(red: 1, green: 1, blue: 1, opacity: 0.0), location: 0.0),
                    .init(color: Color(red: 1, green: 1, blue: 1, opacity: 0.55), location: 0.30),
                    .init(color: Color(red: 1, green: 1, blue: 1, opacity: 0.0), location: 0.55)
                ]),
                startPoint: creaseMid,
                endPoint: lifted))
        }

        // Bright highlight line along the crease (the catching bend).
        var crease = Path()
        crease.move(to: p1)
        crease.addLine(to: p2)
        ctx.drawLayer { layer in
            layer.opacity = opacity
            layer.addFilter(.blur(radius: 0.6))
            layer.stroke(crease, with: .color(Color(red: 1, green: 1, blue: 1, opacity: 0.75)),
                         lineWidth: 1.8)
        }

        // Crisp flap outline for definition.
        ctx.stroke(flap, with: .color(Color(red: 0.45, green: 0.47, blue: 0.56, opacity: opacity * 0.6)),
                   lineWidth: 0.8)
    }

    // MARK: face content & palette

    fileprivate func cardFaceGradient() -> Gradient {
        Gradient(colors: [
            Color(red: 0.36, green: 0.42, blue: 0.95),
            Color(red: 0.58, green: 0.30, blue: 0.92),
            Color(red: 0.92, green: 0.40, blue: 0.66)
        ])
    }

    /// A simple radial bloom + ring emblem so the card face is visually alive.
    fileprivate func drawFaceEmblem(in ctx: inout GraphicsContext, box: CGRect) {
        let c = CGPoint(x: box.midX, y: box.midY)
        let r = box.width * 0.30
        let bloom = Path(ellipseIn: CGRect(x: c.x - r, y: c.y - r, width: r * 2, height: r * 2))
        ctx.fill(bloom, with: .radialGradient(
            Gradient(colors: [
                Color(red: 1, green: 1, blue: 1, opacity: 0.28),
                Color(red: 1, green: 1, blue: 1, opacity: 0.0)
            ]),
            center: c, startRadius: 0, endRadius: r))

        let ringR = box.width * 0.20
        let ring = Path(ellipseIn: CGRect(x: c.x - ringR, y: c.y - ringR, width: ringR * 2, height: ringR * 2))
        ctx.stroke(ring, with: .color(Color(red: 1, green: 1, blue: 1, opacity: 0.30)),
                   lineWidth: box.width * 0.012)
    }

    // MARK: tiny math helpers

    fileprivate func midpoint(_ a: CGPoint, _ b: CGPoint) -> CGPoint {
        CGPoint(x: (a.x + b.x) / 2, y: (a.y + b.y) / 2)
    }

    fileprivate func normalize(_ v: CGPoint) -> CGPoint {
        let len = hypot(v.x, v.y)
        if len == 0 { return CGPoint(x: 0, y: 0) }
        return CGPoint(x: v.x / len, y: v.y / len)
    }
}
"""###,
        "ges-pinch-collapse-grid": ###"""
import SwiftUI

/// Pinch-to-Collapse Stack
///
/// Pinching a photo grid closed makes every tile fly inward and fan-stack into a
/// single tilted pile in the center; spreading fingers re-deals them back out
/// across the grid with staggered timing.
///
/// - `demo == true`  → a self-driving TimelineView loop oscillates a virtual pinch
///   so the tile reads as a self-shuffling deck with no touch.
/// - `demo == false` → a real `MagnifyGesture` scrubs the collapse continuously,
///   snapping open/closed with a bouncy spring on release.
struct PinchCollapseGridView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { geo in
            let size = geo.size
            ZStack {
                background
                if demo {
                    DemoDeck(size: size)
                } else {
                    InteractiveDeck(size: size)
                }
            }
            .frame(width: size.width, height: size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    private var background: some View {
        LinearGradient(
            colors: [
                Color(red: 0.05, green: 0.05, blue: 0.09),
                Color(red: 0.10, green: 0.10, blue: 0.17)
            ],
            startPoint: .topLeading,
            endPoint: .bottomTrailing
        )
    }
}

// MARK: - Demo (self-driving)

private struct DemoDeck: View {
    let size: CGSize

    var body: some View {
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            DeckCanvas(size: size, progress: PinchDeckMath.demoProgress(at: t))
        }
    }
}

// MARK: - Interactive (real gesture)

private struct InteractiveDeck: View {
    let size: CGSize

    @State private var base: Double = 0          // committed progress
    @State private var live: Double = 0          // live progress during pinch
    @State private var pinching: Bool = false

    private var progress: Double { pinching ? live : base }

    var body: some View {
        DeckCanvas(size: size, progress: progress)
            .contentShape(Rectangle())
            .gesture(pinch)
    }

    private var pinch: some Gesture {
        MagnifyGesture()
            .onChanged { value in
                pinching = true
                // magnification < 1 (pinch in) collapses, > 1 (spread) expands.
                let delta = 1.0 - value.magnification
                live = PinchDeckMath.clamp01(base + delta)
            }
            .onEnded { _ in
                // Snap to the nearer extreme with a bouncy settle.
                let target: Double = live > 0.5 ? 1.0 : 0.0
                // Commit the live value first (no jump), then keep reading `base`.
                base = live
                pinching = false
                withAnimation(.spring(duration: 0.5, bounce: 0.3)) {
                    base = target
                }
            }
    }
}

// MARK: - Shared deck renderer

private struct DeckCanvas: View {
    let size: CGSize
    let progress: Double

    private let cols: Int = 4
    private let rows: Int = 4
    private var count: Int { cols * rows }

    var body: some View {
        let layout = PinchDeckMath.Layout(size: size, cols: cols, rows: rows)
        ZStack {
            ForEach(0..<count, id: \.self) { index in
                tile(index: index, layout: layout)
            }
        }
    }

    private func tile(index: Int, layout: PinchDeckMath.Layout) -> some View {
        let xf = PinchDeckMath.transform(
            index: index,
            count: count,
            progress: progress,
            layout: layout
        )
        return TileFace(index: index, tileSize: layout.tileSize)
            .frame(width: layout.tileSize.width, height: layout.tileSize.height)
            .scaleEffect(xf.scale)
            .rotationEffect(.degrees(xf.rotation))
            .position(xf.position)
            .zIndex(xf.z)
            .shadow(
                color: Color.black.opacity(0.35 * progress),
                radius: 6 * progress,
                x: 0,
                y: 4 * progress
            )
    }
}

// MARK: - A single photo-like tile

private struct TileFace: View {
    let index: Int
    let tileSize: CGSize

    var body: some View {
        let corner: CGFloat = min(tileSize.width, tileSize.height) * 0.16
        RoundedRectangle(cornerRadius: corner, style: .continuous)
            .fill(PinchDeckMath.tileGradient(index: index))
            .overlay(
                RoundedRectangle(cornerRadius: corner, style: .continuous)
                    .strokeBorder(Color.white.opacity(0.16), lineWidth: 1)
            )
            .overlay(sheen(corner: corner))
    }

    private func sheen(corner: CGFloat) -> some View {
        RoundedRectangle(cornerRadius: corner, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color.white.opacity(0.22),
                        Color.white.opacity(0.0)
                    ],
                    startPoint: .topLeading,
                    endPoint: .center
                )
            )
            .blendMode(.screen)
    }
}

// MARK: - Math (factored out for type-checker hygiene)

private enum PinchDeckMath {

    struct Layout {
        let size: CGSize
        let cols: Int
        let rows: Int
        let tileSize: CGSize
        let center: CGPoint

        init(size: CGSize, cols: Int, rows: Int) {
            self.size = size
            self.cols = cols
            self.rows = rows
            let pad: CGFloat = min(size.width, size.height) * 0.06
            let usableW = max(size.width - pad * 2, 1)
            let usableH = max(size.height - pad * 2, 1)
            let cellW = usableW / CGFloat(cols)
            let cellH = usableH / CGFloat(rows)
            // Slight inner gap so tiles read as separate photos.
            self.tileSize = CGSize(width: cellW * 0.86, height: cellH * 0.86)
            self.center = CGPoint(x: size.width / 2, y: size.height / 2)
        }

        func gridCenter(of index: Int) -> CGPoint {
            let col = index % cols
            let row = index / cols
            let pad: CGFloat = min(size.width, size.height) * 0.06
            let cellW = (size.width - pad * 2) / CGFloat(cols)
            let cellH = (size.height - pad * 2) / CGFloat(rows)
            let x = pad + cellW * (CGFloat(col) + 0.5)
            let y = pad + cellH * (CGFloat(row) + 0.5)
            return CGPoint(x: x, y: y)
        }
    }

    struct TileTransform {
        let position: CGPoint
        let rotation: Double
        let scale: CGFloat
        let z: Double
    }

    static func clamp01(_ v: Double) -> Double {
        min(max(v, 0.0), 1.0)
    }

    /// Self-driving virtual pinch: oscillates 0 → ~0.85 → 0 on a ~3s loop.
    /// Never reaches a blank extreme; the deck is always legible.
    static func demoProgress(at time: TimeInterval) -> Double {
        let period: Double = 3.2
        let phase = (time.truncatingRemainder(dividingBy: period)) / period
        // Smooth ease in/out via cosine, scaled so it dwells a touch at each end.
        let raw = (1.0 - cos(phase * 2.0 * .pi)) / 2.0   // 0→1→0
        return 0.06 + raw * 0.82
    }

    /// Per-tile staggered progress so the re-deal cascades instead of snapping
    /// all at once. Clamped to [0,1].
    static func staggered(index: Int, count: Int, progress: Double) -> Double {
        let n = max(count - 1, 1)
        let totalStagger: Double = 0.45
        let step = totalStagger / Double(n)
        let start = step * Double(index)
        let span = max(1.0 - totalStagger, 0.2)
        return clamp01((progress - start) / span)
    }

    static func transform(
        index: Int,
        count: Int,
        progress: Double,
        layout: Layout
    ) -> TileTransform {
        let gp = staggered(index: index, count: count, progress: progress)
        let eased = easeInOut(gp)

        let grid = layout.gridCenter(of: index)
        let stack = layout.center

        // Fan-stack: each card lands at a slightly different tilt + jitter so the
        // collapsed pile reads as a shuffled tilted deck.
        let n = max(count - 1, 1)
        let centered = Double(index) - Double(n) / 2.0
        let fanAngle = centered * 4.0                       // degrees across the fan
        let wobble = sin(Double(index) * 1.7) * 3.0         // pseudo-random extra tilt
        let stackRotation = fanAngle + wobble

        let jitterX = CGFloat(cos(Double(index) * 2.3)) * layout.tileSize.width * 0.10
        let jitterY = CGFloat(sin(Double(index) * 1.9)) * layout.tileSize.height * 0.10
        let stackPoint = CGPoint(x: stack.x + jitterX, y: stack.y + jitterY)

        let pos = lerpPoint(grid, stackPoint, eased)
        let rot = lerpD(0.0, stackRotation, eased)

        // Pile slightly larger than a single grid cell to feel like a held deck.
        let scale = CGFloat(lerpD(1.0, 1.12, eased))

        // Stacking order: later cards sit on top of the pile.
        let z = Double(index) * 0.01 + eased * Double(index)

        return TileTransform(position: pos, rotation: rot, scale: scale, z: z)
    }

    // MARK: helpers

    static func easeInOut(_ t: Double) -> Double {
        let c = clamp01(t)
        return c * c * (3.0 - 2.0 * c)
    }

    static func lerpD(_ a: Double, _ b: Double, _ t: Double) -> Double {
        a + (b - a) * t
    }

    static func lerpPoint(_ a: CGPoint, _ b: CGPoint, _ t: Double) -> CGPoint {
        CGPoint(
            x: a.x + (b.x - a.x) * CGFloat(t),
            y: a.y + (b.y - a.y) * CGFloat(t)
        )
    }

    /// Distinct, photo-like gradients per index — no assets, no Color(hex:).
    static func tileGradient(index: Int) -> LinearGradient {
        let palette: [(Double, Double, Double)] = [
            (0.95, 0.45, 0.42), (0.98, 0.70, 0.36), (0.55, 0.80, 0.52),
            (0.36, 0.74, 0.86), (0.52, 0.55, 0.95), (0.86, 0.50, 0.88),
            (0.99, 0.55, 0.66), (0.40, 0.84, 0.74)
        ]
        let a = palette[index % palette.count]
        let b = palette[(index * 3 + 2) % palette.count]
        return LinearGradient(
            colors: [
                Color(red: a.0, green: a.1, blue: a.2),
                Color(red: b.0 * 0.7, green: b.1 * 0.7, blue: b.2 * 0.8)
            ],
            startPoint: .topLeading,
            endPoint: .bottomTrailing
        )
    }
}
"""###,
        "ges-pinch-focus-depth": ###"""
import SwiftUI

// MARK: - Pinch Depth Diorama
// Pinch to dolly a virtual camera through stacked parallax planes.
// Foreground scales/slides faster than background; blur tracks the focused depth.
// demo == true  -> self-driving TimelineView dolly loop (front -> back -> front).
// demo == false -> interactive MagnifyGesture mapped to focusDepth, snaps on release.

struct PinchFocusDepthView: View {
    var demo: Bool = false

    // Committed camera depth (0 = front plane in focus, 1 = back plane in focus).
    @State private var focusDepth: CGFloat = 0.35
    // Live additive delta produced while a pinch is in progress.
    @State private var liveDelta: CGFloat = 0

    private let planeCount: Int = 4

    var body: some View {
        GeometryReader { geo in
            if demo {
                TimelineView(.animation) { context in
                    let t = context.date.timeIntervalSinceReferenceDate
                    diorama(size: geo.size, depth: loopDepth(t))
                }
            } else {
                interactive(size: geo.size)
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .clipped()
    }

    // MARK: Interactive branch

    private func interactive(size: CGSize) -> some View {
        let depth = clampDepth(focusDepth + liveDelta)
        return diorama(size: size, depth: depth)
            .contentShape(Rectangle())
            .gesture(
                MagnifyGesture(minimumScaleDelta: 0)
                    .onChanged { value in
                        // MagnifyGesture is relative: magnification == 1 at pinch start.
                        // Pinch OUT (mag > 1) dollies toward the front (depth -> 0).
                        let sensitivity: CGFloat = 0.9
                        liveDelta = -(CGFloat(value.magnification) - 1) * sensitivity
                    }
                    .onEnded { _ in
                        let committed = clampDepth(focusDepth + liveDelta)
                        liveDelta = 0
                        // Snap to the nearest plane's depth.
                        let snapped = nearestPlaneDepth(committed)
                        withAnimation(.spring(response: 0.45, dampingFraction: 0.72)) {
                            focusDepth = snapped
                        }
                    }
            )
            .animation(.spring(response: 0.5, dampingFraction: 0.8), value: focusDepth)
    }

    // MARK: Shared render path (used by BOTH demo loop and interactive view)

    private func diorama(size: CGSize, depth: CGFloat) -> some View {
        ZStack {
            backdrop(size: size, focusDepth: depth)
            ForEach(0..<planeCount, id: \.self) { index in
                planeLayer(index: index, size: size, focusDepth: depth)
            }
            vignette(size: size)
            focusReadout(size: size, focusDepth: depth)
        }
        .frame(width: size.width, height: size.height)
    }

    // MARK: Backdrop sky

    private func backdrop(size: CGSize, focusDepth: CGFloat) -> some View {
        // Sky warms slightly as the camera dollies toward the front.
        let warmth = 1 - focusDepth
        let top = Color(red: 0.07 + 0.04 * warmth, green: 0.08, blue: 0.16)
        let bottom = Color(red: 0.16 + 0.10 * warmth, green: 0.11, blue: 0.22)
        return LinearGradient(
            colors: [top, bottom],
            startPoint: .top,
            endPoint: .bottom
        )
    }

    // MARK: A single parallax plane

    @ViewBuilder
    private func planeLayer(index: Int, size: CGSize, focusDepth: CGFloat) -> some View {
        let layerDepth = planeDepth(index)            // 0 (front) ... 1 (back)
        let coeff = depthCoeff(layerDepth)            // far planes move/scale less
        let dolly = focusDepth - layerDepth           // signed distance from camera

        // Foreground planes (low layerDepth) react harder than the background.
        let scale = clampScale(1 + dolly * (0.55 * (1 - coeff) + 0.12))
        let slide = -dolly * (1 - coeff) * size.height * 0.34

        let dist = abs(layerDepth - focusDepth)
        let blurRadius = min(dist * 9.0, 7.5)         // clamped, modest radii
        let opacity = max(0.42, 1 - dist * 0.55)      // opacity floor: never blank

        planeContent(index: index, size: size)
            .scaleEffect(scale, anchor: .center)
            .offset(y: slide)
            .blur(radius: blurRadius)
            .opacity(opacity)
    }

    // MARK: Plane artwork (back -> front)

    @ViewBuilder
    private func planeContent(index: Int, size: CGSize) -> some View {
        switch index {
        case 0: backHills(size: size)      // farthest
        case 1: midOrbs(size: size)
        case 2: foreRidge(size: size)
        default: nearLeaves(size: size)    // closest
        }
    }

    // Plane 0 — distant rolling hills + sun
    private func backHills(size: CGSize) -> some View {
        let w = size.width
        let h = size.height
        return ZStack {
            Circle()
                .fill(
                    RadialGradient(
                        colors: [Color(red: 1.0, green: 0.86, blue: 0.62),
                                 Color(red: 0.96, green: 0.62, blue: 0.42)],
                        center: .center, startRadius: 0, endRadius: w * 0.22
                    )
                )
                .frame(width: w * 0.38, height: w * 0.38)
                .offset(x: w * 0.18, y: -h * 0.18)
            HillShape(crest: 0.62, amp: 0.05)
                .fill(Color(red: 0.30, green: 0.27, blue: 0.46))
        }
    }

    // Plane 1 — drifting orbs / mid clouds
    private func midOrbs(size: CGSize) -> some View {
        let w = size.width
        let h = size.height
        let spots: [(CGFloat, CGFloat, CGFloat)] = [
            (-0.30, -0.05, 0.30),
            (0.05, 0.10, 0.42),
            (0.34, -0.12, 0.26)
        ]
        return ZStack {
            ForEach(0..<spots.count, id: \.self) { i in
                let s = spots[i]
                Circle()
                    .fill(Color(red: 0.62, green: 0.55, blue: 0.82).opacity(0.85))
                    .frame(width: w * s.2, height: w * s.2)
                    .offset(x: w * s.0, y: h * s.1)
            }
        }
    }

    // Plane 2 — nearer ridge silhouette
    private func foreRidge(size: CGSize) -> some View {
        HillShape(crest: 0.74, amp: 0.10)
            .fill(
                LinearGradient(
                    colors: [Color(red: 0.20, green: 0.16, blue: 0.32),
                             Color(red: 0.12, green: 0.10, blue: 0.22)],
                    startPoint: .top, endPoint: .bottom
                )
            )
    }

    // Plane 3 — foreground foliage framing the bottom corners (closest, moves most)
    private func nearLeaves(size: CGSize) -> some View {
        let w = size.width
        let h = size.height
        let leaf = LinearGradient(
            colors: [Color(red: 0.10, green: 0.13, blue: 0.10),
                     Color(red: 0.04, green: 0.06, blue: 0.05)],
            startPoint: .top, endPoint: .bottom
        )
        return ZStack {
            LeafShape()
                .fill(leaf)
                .frame(width: w * 0.7, height: h * 0.7)
                .rotationEffect(.degrees(-24))
                .offset(x: -w * 0.34, y: h * 0.40)
            LeafShape()
                .fill(leaf)
                .frame(width: w * 0.62, height: h * 0.62)
                .rotationEffect(.degrees(34))
                .scaleEffect(x: -1, y: 1)
                .offset(x: w * 0.36, y: h * 0.44)
        }
    }

    // MARK: Overlays

    private func vignette(size: CGSize) -> some View {
        RadialGradient(
            colors: [Color.clear, Color(red: 0.02, green: 0.02, blue: 0.05).opacity(0.55)],
            center: .center,
            startRadius: min(size.width, size.height) * 0.30,
            endRadius: max(size.width, size.height) * 0.72
        )
        .allowsHitTesting(false)
    }

    // A small depth indicator dot strip so the focused plane is always legible.
    private func focusReadout(size: CGSize, focusDepth: CGFloat) -> some View {
        let dotSize = max(4.0, min(size.width, size.height) * 0.035)
        let gap = dotSize * 1.4
        return HStack(spacing: gap) {
            ForEach(0..<planeCount, id: \.self) { index in
                let d = planeDepth(index)
                let active = abs(d - focusDepth) < (0.5 / CGFloat(planeCount))
                Circle()
                    .fill(Color.white.opacity(active ? 0.95 : 0.30))
                    .frame(width: active ? dotSize * 1.25 : dotSize,
                           height: active ? dotSize * 1.25 : dotSize)
            }
        }
        .padding(.vertical, dotSize)
        .padding(.horizontal, dotSize * 1.6)
        .background(
            Capsule().fill(Color(red: 0.0, green: 0.0, blue: 0.0).opacity(0.28))
        )
        .frame(maxWidth: .infinity, maxHeight: .infinity, alignment: .bottom)
        .padding(.bottom, max(6.0, size.height * 0.06))
        .allowsHitTesting(false)
    }

    // MARK: Math helpers

    private func planeDepth(_ index: Int) -> CGFloat {
        guard planeCount > 1 else { return 0 }
        // index 0 = back (depth 1) ... last = front (depth 0)
        return CGFloat(planeCount - 1 - index) / CGFloat(planeCount - 1)
    }

    private func depthCoeff(_ layerDepth: CGFloat) -> CGFloat {
        // Larger for far planes -> they scale/slide less.
        return 0.30 + 0.55 * layerDepth
    }

    private func nearestPlaneDepth(_ value: CGFloat) -> CGFloat {
        var best = planeDepth(0)
        var bestDist = abs(best - value)
        for i in 1..<planeCount {
            let d = planeDepth(i)
            let dist = abs(d - value)
            if dist < bestDist {
                best = d
                bestDist = dist
            }
        }
        return best
    }

    private func clampDepth(_ v: CGFloat) -> CGFloat {
        min(max(v, 0), 1)
    }

    private func clampScale(_ v: CGFloat) -> CGFloat {
        min(max(v, 0.55), 1.85)
    }

    // Eased front -> back -> front loop (~3.4s) for the demo tile.
    private func loopDepth(_ time: TimeInterval) -> CGFloat {
        let period: Double = 3.4
        let phase = (time.truncatingRemainder(dividingBy: period)) / period // 0..1
        // Triangle wave 0 -> 1 -> 0, then smootherstep for an eased dolly.
        let tri = phase < 0.5 ? phase * 2 : (1 - phase) * 2
        let eased = tri * tri * (3 - 2 * tri)
        return clampDepth(CGFloat(eased))
    }
}

// MARK: - Shapes

private struct HillShape: Shape {
    var crest: CGFloat   // baseline height (fraction of height, from top)
    var amp: CGFloat     // hump amplitude (fraction of height)

    func path(in rect: CGRect) -> Path {
        var p = Path()
        let baseY = rect.height * crest
        let a = rect.height * amp
        p.move(to: CGPoint(x: rect.minX, y: baseY))
        let steps = 24
        for i in 0...steps {
            let x = rect.width * CGFloat(i) / CGFloat(steps)
            let phase = CGFloat(i) / CGFloat(steps) * .pi * 2
            let y = baseY - sin(phase) * a - sin(phase * 0.5) * a * 0.5
            p.addLine(to: CGPoint(x: x, y: y))
        }
        p.addLine(to: CGPoint(x: rect.maxX, y: rect.maxY))
        p.addLine(to: CGPoint(x: rect.minX, y: rect.maxY))
        p.closeSubpath()
        return p
    }
}

private struct LeafShape: Shape {
    func path(in rect: CGRect) -> Path {
        var p = Path()
        let w = rect.width
        let h = rect.height
        p.move(to: CGPoint(x: rect.midX, y: rect.maxY))
        p.addQuadCurve(
            to: CGPoint(x: rect.midX, y: rect.minY),
            control: CGPoint(x: rect.minX - w * 0.05, y: rect.midY)
        )
        p.addQuadCurve(
            to: CGPoint(x: rect.midX, y: rect.maxY),
            control: CGPoint(x: rect.maxX + w * 0.05, y: rect.midY)
        )
        // a couple of veins for texture
        p.move(to: CGPoint(x: rect.midX, y: rect.maxY))
        p.addLine(to: CGPoint(x: rect.midX, y: rect.minY + h * 0.1))
        p.closeSubpath()
        return p
    }
}
"""###,
        "ges-pinch-origami-crane": ###"""
import SwiftUI

// MARK: - Public View

/// Pinch a flat square and it folds along crease lines through intermediate
/// origami states into a standing crane, each facet catching directional light.
/// Pinch (magnification < 1) folds toward the crane; spread unfolds it.
/// All APIs used are iOS 17+: MagnifyGesture, TimelineView, rotation3DEffect,
/// and a manual keyframed vertex lerp on an Animatable Shape.
struct PinchOrigamiCraneView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { geo in
            let side = min(geo.size.width, geo.size.height)
            ZStack {
                background
                if demo {
                    DemoFoldStage(side: side)
                } else {
                    InteractiveFoldStage(side: side)
                }
            }
            .frame(width: geo.size.width, height: geo.size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    private var background: some View {
        LinearGradient(
            colors: [
                Color(red: 0.05, green: 0.05, blue: 0.09),
                Color(red: 0.10, green: 0.11, blue: 0.17)
            ],
            startPoint: .top,
            endPoint: .bottom
        )
    }
}

// MARK: - Demo (self-driving loop)

private struct DemoFoldStage: View {
    let side: CGFloat

    var body: some View {
        TimelineView(.animation) { context in
            let t = context.date.timeIntervalSinceReferenceDate
            let progress = triangleWave(t)
            CraneFigure(progress: progress, side: side)
        }
    }

    /// 0 -> 1 -> 0 triangle wave on a ~3.4s loop. Never rests at a blank state:
    /// both endpoints are legible (flat square / standing crane).
    private func triangleWave(_ t: TimeInterval) -> CGFloat {
        let period: Double = 3.4
        let phase = (t.truncatingRemainder(dividingBy: period)) / period
        let raw = phase < 0.5 ? phase * 2.0 : (1.0 - phase) * 2.0
        // ease in/out so the dwell at flat / crane reads as a held pose
        let eased = raw * raw * (3.0 - 2.0 * raw)
        return CGFloat(eased)
    }
}

// MARK: - Interactive (real pinch)

private struct InteractiveFoldStage: View {
    let side: CGFloat

    @State private var committedFold: CGFloat = 0.0
    @State private var liveFold: CGFloat = 0.0

    var body: some View {
        CraneFigure(progress: liveFold, side: side)
            .gesture(pinch)
            .accessibilityLabel("Origami crane. Pinch to fold, spread to unfold.")
    }

    private var pinch: some Gesture {
        MagnifyGesture(minimumScaleDelta: 0.0)
            .onChanged { value in
                // pinch closed (magnification < 1) folds toward crane.
                let delta = (1.0 - CGFloat(value.magnification)) * 1.4
                liveFold = clamp(committedFold + delta)
            }
            .onEnded { _ in
                let snapped = nearestKeyframe(liveFold)
                committedFold = snapped
                withAnimation(.spring(response: 0.55, dampingFraction: 0.62)) {
                    liveFold = snapped
                }
            }
    }

    private func clamp(_ v: CGFloat) -> CGFloat {
        min(1.0, max(0.0, v))
    }

    /// Snap to one of the three keyframe poses: flat, kite base, crane.
    private func nearestKeyframe(_ v: CGFloat) -> CGFloat {
        let stops: [CGFloat] = [0.0, 0.5, 1.0]
        var best: CGFloat = 0.0
        var bestDist: CGFloat = .greatestFiniteMagnitude
        for s in stops {
            let d = abs(s - v)
            if d < bestDist {
                bestDist = d
                best = s
            }
        }
        return best
    }
}

// MARK: - Crane figure (composes all facets)

private struct CraneFigure: View {
    let progress: CGFloat
    let side: CGFloat

    var body: some View {
        ZStack {
            ground
            ForEach(CraneFacet.all) { facet in
                FacetView(facet: facet, progress: progress, side: side)
            }
        }
        .frame(width: side, height: side)
        // gentle settle so the standing crane feels alive at full fold
        .rotation3DEffect(
            .degrees(Double(progress) * 8.0),
            axis: (x: 1.0, y: 0.0, z: 0.0),
            perspective: 0.6
        )
    }

    /// Soft contact shadow that tightens as the crane stands up.
    private var ground: some View {
        let w = side * (0.62 - 0.18 * progress)
        let h = side * 0.10
        return Ellipse()
            .fill(Color.black.opacity(0.32))
            .frame(width: w, height: h)
            .blur(radius: 9)
            .offset(y: side * 0.34)
            .opacity(0.55 + 0.3 * Double(progress))
    }
}

// MARK: - Single facet rendering

private struct FacetView: View {
    let facet: CraneFacet
    let progress: CGFloat
    let side: CGFloat

    var body: some View {
        FacetShape(facet: facet, progress: progress, side: side)
            .fill(gradient)
            .overlay(creaseStroke)
            .rotation3DEffect(
                .degrees(tiltAngle),
                axis: facet.axis,
                anchor: .center,
                perspective: 0.5
            )
            .compositingGroup()
    }

    // Crease lines on the paper edges sell the fold geometry.
    private var creaseStroke: some View {
        FacetShape(facet: facet, progress: progress, side: side)
            .stroke(Color.black.opacity(0.18), lineWidth: 0.6)
    }

    /// Directional light: brightness keys off the facet's fold tilt so each
    /// plane catches the light differently as it rotates.
    private var gradient: LinearGradient {
        let lit = facet.brightness(progress: progress)
        let base = facet.tone
        let top = shade(base, by: 0.55 + 0.45 * lit)
        let bottom = shade(base, by: 0.30 + 0.35 * lit)
        return LinearGradient(
            colors: [top, bottom],
            startPoint: .topLeading,
            endPoint: .bottomTrailing
        )
    }

    private var tiltAngle: Double {
        // facets lean out of plane as the fold completes
        Double(progress) * facet.maxTilt
    }

    private func shade(_ c: PaperTone, by k: CGFloat) -> Color {
        let f = min(1.0, max(0.0, k))
        return Color(red: c.r * f, green: c.g * f, blue: c.b * f)
    }
}

// MARK: - Animatable Shape (vertex lerp lives here for spring morphing)

private struct FacetShape: Shape {
    let facet: CraneFacet
    var progress: CGFloat
    let side: CGFloat

    // Lets the onEnded .spring actually interpolate the path, not snap it.
    var animatableData: CGFloat {
        get { progress }
        set { progress = newValue }
    }

    func path(in rect: CGRect) -> Path {
        let pts = facet.vertices(progress: progress)
        var path = Path()
        guard let first = pts.first else { return path }
        let s: CGFloat = side
        let cx: CGFloat = rect.midX
        let cy: CGFloat = rect.midY
        path.move(to: project(first, s: s, cx: cx, cy: cy))
        for i in 1..<pts.count {
            path.addLine(to: project(pts[i], s: s, cx: cx, cy: cy))
        }
        path.closeSubpath()
        return path
    }

    /// Map a normalized point in [-0.5, 0.5] space to view coordinates.
    private func project(_ p: CGPoint, s: CGFloat, cx: CGFloat, cy: CGFloat) -> CGPoint {
        let x: CGFloat = cx + p.x * s
        let y: CGFloat = cy + p.y * s
        return CGPoint(x: x, y: y)
    }
}

// MARK: - Paper tone

private struct PaperTone {
    let r: CGFloat
    let g: CGFloat
    let b: CGFloat
}

// MARK: - Facet model (keyframed vertex sets + lighting key)

private struct CraneFacet: Identifiable {
    let id: Int
    /// Three keyframe poses in normalized [-0.5, 0.5] space:
    /// 0 = flat square region, 1 = kite/diamond base, 2 = standing crane.
    let flat: [CGPoint]
    let base: [CGPoint]
    let crane: [CGPoint]
    let tone: PaperTone
    let maxTilt: Double
    let axis: (x: CGFloat, y: CGFloat, z: CGFloat)
    /// Phase of the fold lighting sweep so facets brighten at different times.
    let litPhase: CGFloat

    /// Piecewise lerp: flat -> base over [0, 0.5], base -> crane over [0.5, 1].
    func vertices(progress: CGFloat) -> [CGPoint] {
        if progress <= 0.5 {
            let t = progress / 0.5
            return lerp(flat, base, smooth(t))
        } else {
            let t = (progress - 0.5) / 0.5
            return lerp(base, crane, smooth(t))
        }
    }

    func brightness(progress: CGFloat) -> CGFloat {
        // a moving highlight band that travels across facets during the fold
        let center = progress
        let d = abs(litPhase - center)
        let lit = max(0.0, 1.0 - d * 1.8)
        return 0.35 + 0.65 * lit
    }

    private func smooth(_ t: CGFloat) -> CGFloat {
        let c = min(1.0, max(0.0, t))
        return c * c * (3.0 - 2.0 * c)
    }

    private func lerp(_ a: [CGPoint], _ b: [CGPoint], _ t: CGFloat) -> [CGPoint] {
        let n = min(a.count, b.count)
        var out: [CGPoint] = []
        out.reserveCapacity(n)
        for i in 0..<n {
            let x: CGFloat = a[i].x + (b[i].x - a[i].x) * t
            let y: CGFloat = a[i].y + (b[i].y - a[i].y) * t
            out.append(CGPoint(x: x, y: y))
        }
        return out
    }
}

