"""###,
        "ges-pinch-zoom-clamp-frame": ###"""
import SwiftUI

/// Pinch-Clamp Crop Frame
/// Pinch within an image and a crop frame resists past content edges with
/// rubber-band overscroll; the dimmed outside region springs taut when you
/// release beyond bounds. A fixed centered crop window sits over a synthesized
/// photo that scales/pans behind it; the image must always cover the window,
/// and any overshoot is rubber-banded then sprung back into legal range.
struct PinchZoomClampFrameView: View {
    var demo: Bool = false

    // Committed transform (the source of truth between gestures).
    @State private var baseScale: CGFloat = 1.0
    @State private var baseOffset: CGSize = .zero

    // Live transform while a gesture is in flight.
    @State private var liveScale: CGFloat = 1.0
    @State private var liveOffset: CGSize = .zero
    @State private var isGesturing: Bool = false

    // Gesture-start snapshot for focal-anchor math.
    @State private var gestureStartScale: CGFloat = 1.0
    @State private var gestureStartOffset: CGSize = .zero
    @State private var panStartOffset: CGSize = .zero

    // Haptic trigger: bumped on each snap-back so feedback fires on the clamp.
    @State private var snapTick: Int = 0

    // Tuning constants.
    private let minScale: CGFloat = 1.0      // cover threshold (image must fill window)
    private let maxScale: CGFloat = 3.2
    private let cropInset: CGFloat = 0.16     // fraction of min dimension used as margin

    var body: some View {
        GeometryReader { geo in
            content(in: geo.size)
                .frame(maxWidth: .infinity, maxHeight: .infinity)
        }
        .background(Color(red: 0.05, green: 0.055, blue: 0.086))
    }

    // MARK: - Routing

    @ViewBuilder
    private func content(in size: CGSize) -> some View {
        if demo {
            demoContent(in: size)
        } else {
            interactiveContent(in: size)
        }
    }

    // MARK: - Demo (self-driving)

    @ViewBuilder
    private func demoContent(in size: CGSize) -> some View {
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            let driven = demoTransform(at: t, size: size)
            cropStage(scale: driven.scale,
                      offset: driven.offset,
                      overshoot: driven.overshoot,
                      size: size)
        }
    }

    /// A ~3.6s loop that zooms in, then deliberately over-pans to an edge so the
    /// rubber-band give and dim are demonstrated, then snaps taut to bounds.
    private func demoTransform(at time: TimeInterval, size: CGSize)
        -> (scale: CGFloat, offset: CGSize, overshoot: CGFloat) {
        let period: Double = 3.6
        let phase = (time.truncatingRemainder(dividingBy: period)) / period // 0..1

        // Scale eases 1 -> 2.0 -> 1 over the loop.
        let zoom = (1.0 - cos(phase * 2.0 * .pi)) * 0.5            // 0..1..0
        let scale = 1.0 + CGFloat(zoom) * 1.0                      // 1.0..2.0

        let window = cropRect(in: size)
        let limits = panLimits(forScale: scale, window: window, size: size)

        // Push the pan toward an edge and beyond it during the middle of the loop.
        let pushPhase = sin(phase * 2.0 * .pi)                     // -1..1
        let targetX = CGFloat(pushPhase) * (limits.width + 46)     // intentionally past the limit
        let targetY = CGFloat(sin(phase * 4.0 * .pi)) * (limits.height + 26)

        let resistedX = rubberClamped(targetX, limit: limits.width, dimension: window.width)
        let resistedY = rubberClamped(targetY, limit: limits.height, dimension: window.height)

        let overX = max(0, abs(targetX) - limits.width)
        let overY = max(0, abs(targetY) - limits.height)
        let overshoot = min(1.0, (overX + overY) / 70.0)

        return (scale, CGSize(width: resistedX, height: resistedY), overshoot)
    }

    // MARK: - Interactive

    @ViewBuilder
    private func interactiveContent(in size: CGSize) -> some View {
        let scale = isGesturing ? liveScale : baseScale
        let offset = isGesturing ? liveOffset : baseOffset
        let overshoot = currentOvershoot(scale: scale, offset: offset, size: size)

        cropStage(scale: scale, offset: offset, overshoot: overshoot, size: size)
            .contentShape(Rectangle())
            .gesture(combinedGesture(size: size))
            .sensoryFeedback(.impact(weight: .light), trigger: snapTick)
    }

    private func combinedGesture(size: CGSize) -> some Gesture {
        let magnify = MagnifyGesture(minimumScaleDelta: 0)
            .onChanged { value in
                beginIfNeeded()
                applyMagnify(value, size: size)
            }
            .onEnded { _ in
                commitAndSpring(size: size)
            }

        let pan = DragGesture(minimumDistance: 0)
            .onChanged { value in
                beginIfNeeded()
                applyPan(value, size: size)
            }
            .onEnded { _ in
                commitAndSpring(size: size)
            }

        return magnify.simultaneously(with: pan)
    }

    private func beginIfNeeded() {
        guard !isGesturing else { return }
        isGesturing = true
        gestureStartScale = baseScale
        gestureStartOffset = baseOffset
        panStartOffset = baseOffset
        liveScale = baseScale
        liveOffset = baseOffset
    }

    /// Focal-anchor zoom: keep the pinch point fixed in window space.
    /// offset = (focal - center) * (1 - m) + baseOffset * m,  scale = baseScale * m
    private func applyMagnify(_ value: MagnifyGesture.Value, size: CGSize) {
        let m = value.magnification
        let rawScale = gestureStartScale * m
        let clampedScale = clampScale(rawScale, allowOvershoot: true)

        let window = cropRect(in: size)
        let center = CGPoint(x: window.midX, y: window.midY)
        let focal = CGPoint(x: window.minX + value.startAnchor.x * window.width,
                            y: window.minY + value.startAnchor.y * window.height)

        let fx = (focal.x - center.x) * (1 - m) + gestureStartOffset.width * m
        let fy = (focal.y - center.y) * (1 - m) + gestureStartOffset.height * m

        let limits = panLimits(forScale: clampedScale, window: window, size: size)
        liveScale = clampedScale
        liveOffset = CGSize(
            width: rubberClamped(fx, limit: limits.width, dimension: window.width),
            height: rubberClamped(fy, limit: limits.height, dimension: window.height)
        )
    }

    private func applyPan(_ value: DragGesture.Value, size: CGSize) {
        let window = cropRect(in: size)
        let proposedX = panStartOffset.width + value.translation.width
        let proposedY = panStartOffset.height + value.translation.height
        let limits = panLimits(forScale: liveScale, window: window, size: size)
        liveOffset = CGSize(
            width: rubberClamped(proposedX, limit: limits.width, dimension: window.width),
            height: rubberClamped(proposedY, limit: limits.height, dimension: window.height)
        )
    }

    private func commitAndSpring(size: CGSize) {
        let window = cropRect(in: size)
        let targetScale = clampScale(liveScale, allowOvershoot: false)
        let limits = panLimits(forScale: targetScale, window: window, size: size)
        let targetOffset = CGSize(
            width: hardClamp(liveOffset.width, limit: limits.width),
            height: hardClamp(liveOffset.height, limit: limits.height)
        )

        let wasOut = abs(liveScale - targetScale) > 0.001
            || abs(liveOffset.width - targetOffset.width) > 0.5
            || abs(liveOffset.height - targetOffset.height) > 0.5

        baseScale = liveScale
        baseOffset = liveOffset
        isGesturing = false

        withAnimation(.spring(response: 0.42, dampingFraction: 0.72)) {
            baseScale = targetScale
            baseOffset = targetOffset
        }
        if wasOut { snapTick &+= 1 }
    }

    private func currentOvershoot(scale: CGFloat, offset: CGSize, size: CGSize) -> CGFloat {
        let window = cropRect(in: size)
        let limits = panLimits(forScale: scale, window: window, size: size)
        let overX = max(0, abs(offset.width) - limits.width)
        let overY = max(0, abs(offset.height) - limits.height)
        let scaleOver = max(0, scale - maxScale) * 60 + max(0, minScale - scale) * 60
        return min(1.0, (overX + overY + scaleOver) / 70.0)
    }

    // MARK: - Shared renderer

    @ViewBuilder
    private func cropStage(scale: CGFloat, offset: CGSize, overshoot: CGFloat, size: CGSize) -> some View {
        let window = cropRect(in: size)
        let corner = min(window.width, window.height) * 0.06

        ZStack {
            // The photo, scaled + panned behind everything.
            photo(in: size)
                .scaleEffect(scale)        // center anchor (default) — required by focal math
                .offset(offset)
                .clipped()

            // Dim everything outside the crop window. Brighten the dim slightly
            // while overscrolling so the boundary tension reads.
            dimMask(window: window, corner: corner, size: size, overshoot: overshoot)

            // The crop frame chrome: border, rule-of-thirds grid, corner handles.
            cropChrome(window: window, corner: corner, overshoot: overshoot)
        }
        .compositingGroup()
    }

    private func dimMask(window: CGRect, corner: CGFloat, size: CGSize, overshoot: CGFloat) -> some View {
        let dim = 0.46 + overshoot * 0.18
        return Rectangle()
            .fill(Color.black.opacity(dim))
            .reverseMask {
                RoundedRectangle(cornerRadius: corner, style: .continuous)
                    .frame(width: window.width, height: window.height)
                    .position(x: window.midX, y: window.midY)
            }
            .allowsHitTesting(false)
    }

    @ViewBuilder
    private func cropChrome(window: CGRect, corner: CGFloat, overshoot: CGFloat) -> some View {
        let borderTint = Color(red: 1, green: 1, blue: 1)
            .opacity(0.85 + overshoot * 0.15)

        ZStack {
            // Rule-of-thirds grid.
            thirdsGrid(window: window)
                .stroke(Color.white.opacity(0.28), lineWidth: 0.75)

            // Main frame border. Tints warm when rubber-banding past bounds.
            RoundedRectangle(cornerRadius: corner, style: .continuous)
                .stroke(
                    overshoot > 0.02
                        ? AnyShapeStyle(Color(red: 1.0, green: 0.62, blue: 0.32).opacity(0.95))
                        : AnyShapeStyle(borderTint),
                    lineWidth: 1.6 + overshoot * 1.2
                )
                .frame(width: window.width, height: window.height)
                .position(x: window.midX, y: window.midY)

            cornerHandles(window: window, overshoot: overshoot)
        }
        .allowsHitTesting(false)
    }

    private func cornerHandles(window: CGRect, overshoot: CGFloat) -> some View {
        let len = min(window.width, window.height) * 0.13
        let tint = overshoot > 0.02
            ? Color(red: 1.0, green: 0.62, blue: 0.32)
            : Color(red: 1, green: 1, blue: 1)
        return ForEach(0..<4, id: \.self) { i in
            CornerBracket(corner: i, length: len)
                .stroke(tint.opacity(0.95), style: StrokeStyle(lineWidth: 2.4, lineCap: .round))
                .frame(width: window.width, height: window.height)
                .position(x: window.midX, y: window.midY)
        }
    }

    // MARK: - Synthesized photo (no assets)

    @ViewBuilder
    private func photo(in size: CGSize) -> some View {
        ZStack {
            // Sky gradient.
            LinearGradient(
                colors: [
                    Color(red: 0.20, green: 0.30, blue: 0.55),
                    Color(red: 0.55, green: 0.52, blue: 0.70),
                    Color(red: 0.96, green: 0.74, blue: 0.52)
                ],
                startPoint: .top,
                endPoint: .bottom
            )

            // Sun.
            Circle()
                .fill(
                    RadialGradient(
                        colors: [
                            Color(red: 1.0, green: 0.96, blue: 0.82),
                            Color(red: 1.0, green: 0.82, blue: 0.5).opacity(0.0)
                        ],
                        center: .center,
                        startRadius: 0,
                        endRadius: size.width * 0.22
                    )
                )
                .frame(width: size.width * 0.42, height: size.width * 0.42)
                .position(x: size.width * 0.68, y: size.height * 0.34)

            // Distant hill.
            HillShape(baseY: 0.66, peakY: 0.5, skew: 0.35)
                .fill(Color(red: 0.42, green: 0.46, blue: 0.55))

            // Mid hill.
            HillShape(baseY: 0.74, peakY: 0.58, skew: -0.4)
                .fill(Color(red: 0.32, green: 0.40, blue: 0.40))

            // Foreground hill.
            HillShape(baseY: 0.82, peakY: 0.68, skew: 0.15)
                .fill(Color(red: 0.16, green: 0.30, blue: 0.26))
        }
        .frame(width: size.width, height: size.height)
    }

    // MARK: - Geometry helpers

    /// The fixed, centered crop window in the view's coordinate space.
    private func cropRect(in size: CGSize) -> CGRect {
        let minDim = min(size.width, size.height)
        let side = minDim * (1 - cropInset * 2)
        // Slight landscape aspect so the photo reads as a photo.
        let w = min(size.width * (1 - cropInset * 1.4), side * 1.28)
        let h = side
        return CGRect(x: (size.width - w) / 2,
                      y: (size.height - h) / 2,
                      width: w, height: h)
    }

    /// How far (in points) the photo may pan in each axis before the crop window
    /// would expose an uncovered edge, for a given scale.
    private func panLimits(forScale scale: CGFloat, window: CGRect, size: CGSize) -> CGSize {
        // The photo fills the full view; at scale s its visible half-extent grows.
        let photoHalfW = size.width * scale / 2
        let photoHalfH = size.height * scale / 2
        let windowHalfW = window.width / 2
        let windowHalfH = window.height / 2
        // Window is centered; available slack is photo half minus window half,
        // minus the window's own centered offset within the view.
        let slackW = max(0, photoHalfW - windowHalfW)
        let slackH = max(0, photoHalfH - windowHalfH)
        return CGSize(width: slackW, height: slackH)
    }

    private func clampScale(_ s: CGFloat, allowOvershoot: Bool) -> CGFloat {
        if allowOvershoot {
            // Soft resistance past hard limits but never wildly off.
            if s < minScale {
                return minScale - rubber(minScale - s, dimension: 0.6)
            } else if s > maxScale {
                return maxScale + rubber(s - maxScale, dimension: 1.2)
            }
            return s
        }
        return min(max(s, minScale), maxScale)
    }

    private func rubber(_ x: CGFloat, dimension: CGFloat) -> CGFloat {
        // Asymptotic give for scale overshoot.
        (1 - 1 / (x / dimension + 1)) * dimension * 0.5
    }

    /// Classic iOS rubber-band: within [-limit, limit] pass through; beyond,
    /// apply asymptotic resistance scaled by the dimension.
    private func rubberClamped(_ value: CGFloat, limit: CGFloat, dimension: CGFloat) -> CGFloat {
        if value > limit {
            return limit + rubberBand(value - limit, dimension: dimension)
        } else if value < -limit {
            return -limit - rubberBand(-value - limit, dimension: dimension)
        }
        return value
    }

    private func rubberBand(_ overshoot: CGFloat, dimension: CGFloat) -> CGFloat {
        let d = max(dimension, 1)
        return (1 - 1 / (overshoot * 0.55 / d + 1)) * d
    }

    private func hardClamp(_ value: CGFloat, limit: CGFloat) -> CGFloat {
        min(max(value, -limit), limit)
    }
}

// MARK: - Shapes

private struct HillShape: Shape {
    var baseY: CGFloat   // fraction of height where the hill base sits
    var peakY: CGFloat   // fraction of height of the peak
    var skew: CGFloat    // -1..1, shifts the peak horizontally

    func path(in rect: CGRect) -> Path {
        var p = Path()
        let w = rect.width
        let h = rect.height
        let base = h * baseY
        let peak = h * peakY
        let peakX = w * (0.5 + skew * 0.3)
        p.move(to: CGPoint(x: 0, y: base))
        p.addQuadCurve(
            to: CGPoint(x: w, y: base),
            control: CGPoint(x: peakX, y: peak)
        )
        p.addLine(to: CGPoint(x: w, y: h))
        p.addLine(to: CGPoint(x: 0, y: h))
        p.closeSubpath()
        return p
    }
}

private struct CornerBracket: Shape {
    var corner: Int       // 0 TL, 1 TR, 2 BR, 3 BL
    var length: CGFloat

    func path(in rect: CGRect) -> Path {
        var p = Path()
        let l = length
        switch corner {
        case 0:
            p.move(to: CGPoint(x: rect.minX, y: rect.minY + l))
            p.addLine(to: CGPoint(x: rect.minX, y: rect.minY))
            p.addLine(to: CGPoint(x: rect.minX + l, y: rect.minY))
        case 1:
            p.move(to: CGPoint(x: rect.maxX - l, y: rect.minY))
            p.addLine(to: CGPoint(x: rect.maxX, y: rect.minY))
            p.addLine(to: CGPoint(x: rect.maxX, y: rect.minY + l))
        case 2:
            p.move(to: CGPoint(x: rect.maxX, y: rect.maxY - l))
            p.addLine(to: CGPoint(x: rect.maxX, y: rect.maxY))
            p.addLine(to: CGPoint(x: rect.maxX - l, y: rect.maxY))
        default:
            p.move(to: CGPoint(x: rect.minX + l, y: rect.maxY))
            p.addLine(to: CGPoint(x: rect.minX, y: rect.maxY))
            p.addLine(to: CGPoint(x: rect.minX, y: rect.maxY - l))
        }
        return p
    }
}

private struct ThirdsGridPlaceholder { }

private extension PinchZoomClampFrameView {
    func thirdsGrid(window: CGRect) -> Path {
        var p = Path()
        let oneThirdW = window.width / 3
        let oneThirdH = window.height / 3
        // Vertical lines.
        for i in 1...2 {
            let x = window.minX + oneThirdW * CGFloat(i)
            p.move(to: CGPoint(x: x, y: window.minY))
            p.addLine(to: CGPoint(x: x, y: window.maxY))
        }
        // Horizontal lines.
        for i in 1...2 {
            let y = window.minY + oneThirdH * CGFloat(i)
            p.move(to: CGPoint(x: window.minX, y: y))
            p.addLine(to: CGPoint(x: window.maxX, y: y))
        }
        return p
    }
}

// MARK: - Reverse mask helper

private extension View {
    @ViewBuilder
    func reverseMask<Mask: View>(@ViewBuilder _ mask: () -> Mask) -> some View {
        self.mask {
            ZStack {
                Rectangle()
                mask()
                    .blendMode(.destinationOut)
            }
            .compositingGroup()
        }
    }
}
"""###,
        "ges-pull-to-trigger-bow": ###"""
import SwiftUI

// MARK: - Slingshot Launcher
// Pull a projectile back against a stretching elastic band that thins and tints
// under tension, then release to fling it forward along the loaded vector while
// the band recoils with a twang wobble.
struct PullToTriggerBowView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { proxy in
            let size = proxy.size
            ZStack {
                PullToTriggerBowView_SlingBackground()
                if demo {
                    PullToTriggerBowView_DemoDriver(size: size)
                } else {
                    PullToTriggerBowView_InteractiveDriver(size: size)
                }
            }
            .frame(width: size.width, height: size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }
}

// MARK: - Geometry helpers (all fractions of the rendered size)

private struct PullToTriggerBowView_SlingGeometry {
    let size: CGSize

    // The Y-frame: a base post rising to two splayed fork tips.
    var basePost: CGPoint { CGPoint(x: size.width * 0.5, y: size.height * 0.92) }
    var forkJoint: CGPoint { CGPoint(x: size.width * 0.5, y: size.height * 0.56) }
    var forkLeft: CGPoint { CGPoint(x: size.width * 0.5 - tineSpread, y: size.height * 0.30) }
    var forkRight: CGPoint { CGPoint(x: size.width * 0.5 + tineSpread, y: size.height * 0.30) }

    // Resting nock sits between the two tines.
    var nock: CGPoint {
        CGPoint(x: (forkLeft.x + forkRight.x) / 2, y: (forkLeft.y + forkRight.y) / 2)
    }

    var tineSpread: CGFloat { min(size.width, size.height) * 0.26 }
    var maxPull: CGFloat { min(size.width, size.height) * 0.34 }
    var projectileRadius: CGFloat { min(size.width, size.height) * 0.075 }
    var slingStroke: CGFloat { min(size.width, size.height) * 0.018 }
}

// MARK: - Shared math

private func clampLength(_ v: CGSize, max maxLen: CGFloat) -> CGSize {
    let len = hypot(v.width, v.height)
    if len <= maxLen || len == 0 { return v }
    // Rubber-band past the cap so over-drag still resists but never runs away.
    let over = len - maxLen
    let damped = maxLen + over * 0.18
    let scale = damped / len
    return CGSize(width: v.width * scale, height: v.height * scale)
}

private func tensionValue(pull: CGSize, maxPull: CGFloat) -> CGFloat {
    guard maxPull > 0 else { return 0 }
    let t = hypot(pull.width, pull.height) / maxPull
    return min(max(t, 0), 1)
}

private func bandWidth(tension t: CGFloat, base: CGFloat) -> CGFloat {
    // Thins as it stretches: 1.0x slack -> 0.45x taut.
    let factor: CGFloat = 1.0 - 0.55 * t
    return base * factor
}

private func bandColor(tension t: CGFloat) -> Color {
    // Cool amber slack -> hot red-orange taut (hue interpolation).
    let hue = 0.11 - 0.11 * Double(t)            // ~0.11 (amber) -> 0.0 (red)
    let sat = 0.55 + 0.40 * Double(t)
    let bri = 0.95 - 0.10 * Double(t)
    return Color(hue: max(hue, 0.0), saturation: min(sat, 1.0), brightness: bri)
}

// MARK: - Background

private struct PullToTriggerBowView_SlingBackground: View {
    var body: some View {
        LinearGradient(
            colors: [
                Color(red: 0.05, green: 0.05, blue: 0.09),
                Color(red: 0.09, green: 0.08, blue: 0.14)
            ],
            startPoint: .top, endPoint: .bottom
        )
        .ignoresSafeArea()
    }
}

// MARK: - Static frame (the Y posts + tines)

private struct PullToTriggerBowView_SlingFrame: View {
    let geo: PullToTriggerBowView_SlingGeometry

    var body: some View {
        let woodLight = Color(red: 0.42, green: 0.30, blue: 0.20)
        let woodDark = Color(red: 0.24, green: 0.16, blue: 0.10)
        Path { p in
            p.move(to: geo.basePost)
            p.addLine(to: geo.forkJoint)
            p.move(to: geo.forkJoint)
            p.addLine(to: geo.forkLeft)
            p.move(to: geo.forkJoint)
            p.addLine(to: geo.forkRight)
        }
        .stroke(
            LinearGradient(colors: [woodLight, woodDark], startPoint: .top, endPoint: .bottom),
            style: StrokeStyle(lineWidth: geo.slingStroke * 2.6, lineCap: .round, lineJoin: .round)
        )
        .overlay {
            // Tine cap knobs where the band ties on.
            ForEach([geo.forkLeft, geo.forkRight], id: \.self) { pt in
                Circle()
                    .fill(woodDark)
                    .frame(width: geo.slingStroke * 3.2, height: geo.slingStroke * 3.2)
                    .position(pt)
            }
        }
    }
}

// MARK: - The elastic band + projectile (the shared, parameterized render)

private struct PullToTriggerBowView_SlingBand: View {
    let geo: PullToTriggerBowView_SlingGeometry
    /// Live position of the projectile / nock pocket.
    let projectile: CGPoint
    /// Tension 0...1 used for thinning + tinting.
    let tension: CGFloat
    /// 0 = projectile present, 1 = launched (fades the ball, slack band only).
    var launchFade: CGFloat = 0

    var body: some View {
        let width = bandWidth(tension: tension, base: geo.slingStroke * 2.4)
        let color = bandColor(tension: tension)
        ZStack {
            // Two band lines from each fork tip to the projectile pocket.
            bandLine(from: geo.forkLeft, to: projectile)
                .stroke(color, style: StrokeStyle(lineWidth: width, lineCap: .round))
            bandLine(from: geo.forkRight, to: projectile)
                .stroke(color, style: StrokeStyle(lineWidth: width, lineCap: .round))

            // Leather pocket cradling the projectile.
            pocketView(color: color)
                .opacity(1 - launchFade)

            PullToTriggerBowView_ProjectileView(radius: geo.projectileRadius, glow: tension)
                .position(projectile)
                .opacity(1 - launchFade)
                .scaleEffect(1 - 0.25 * launchFade)
        }
    }

    private func bandLine(from a: CGPoint, to b: CGPoint) -> Path {
        Path { p in
            p.move(to: a)
            p.addLine(to: b)
        }
    }

    private func pocketView(color: Color) -> some View {
        let w = geo.projectileRadius * 1.5
        return Capsule()
            .fill(Color(red: 0.30, green: 0.20, blue: 0.14))
            .frame(width: w * 0.5, height: w * 1.4)
            .overlay(Capsule().stroke(color.opacity(0.7), lineWidth: geo.slingStroke))
            .rotationEffect(pocketAngle)
            .position(projectile)
    }

    private var pocketAngle: Angle {
        let dx = projectile.x - geo.nock.x
        let dy = projectile.y - geo.nock.y
        if abs(dx) < 0.001 && abs(dy) < 0.001 { return .degrees(0) }
        return .radians(atan2(dy, dx) - .pi / 2)
    }
}

private struct PullToTriggerBowView_ProjectileView: View {
    let radius: CGFloat
    let glow: CGFloat

    var body: some View {
        Circle()
            .fill(
                RadialGradient(
                    colors: [
                        Color(red: 0.95, green: 0.95, blue: 1.0),
                        Color(red: 0.55, green: 0.60, blue: 0.78),
                        Color(red: 0.30, green: 0.34, blue: 0.52)
                    ],
                    center: .init(x: 0.35, y: 0.30),
                    startRadius: 0,
                    endRadius: radius * 1.4
                )
            )
            .frame(width: radius * 2, height: radius * 2)
            .shadow(color: bandColor(tension: glow).opacity(0.55 + 0.4 * glow),
                    radius: 4 + 8 * glow)
    }
}

// MARK: - Interactive driver (real DragGesture)

private struct PullToTriggerBowView_InteractiveDriver: View {
    let size: CGSize

    @State private var pull: CGSize = .zero      // current drag offset from nock
    @State private var isDragging = false
    @State private var launchCount = 0
    @State private var launchFade: CGFloat = 0    // projectile vanish on flight
    @State private var flightOffset: CGSize = .zero

    private var geo: PullToTriggerBowView_SlingGeometry { PullToTriggerBowView_SlingGeometry(size: size) }

    private var projectilePoint: CGPoint {
        CGPoint(x: geo.nock.x + pull.width + flightOffset.width,
                y: geo.nock.y + pull.height + flightOffset.height)
    }

    private var tension: CGFloat {
        tensionValue(pull: pull, maxPull: geo.maxPull)
    }

    var body: some View {
        ZStack {
            PullToTriggerBowView_SlingFrame(geo: geo)
            PullToTriggerBowView_SlingBand(geo: geo,
                      projectile: projectilePoint,
                      tension: isDragging ? tension : (flightOffset == .zero ? tension : 0),
                      launchFade: launchFade)
            PullToTriggerBowView_HintLabel(text: isDragging ? "release to fire" : "drag & release")
                .position(x: size.width / 2, y: size.height * 0.05)
                .opacity(launchFade > 0.2 ? 0 : 0.85)
        }
        .contentShape(Rectangle())
        .gesture(dragGesture)
        .sensoryFeedback(.impact(weight: .medium, intensity: 0.9), trigger: launchCount)
    }

    private var dragGesture: some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                guard launchFade == 0 else { return }
                isDragging = true
                pull = clampLength(value.translation, max: geo.maxPull)
            }
            .onEnded { _ in
                isDragging = false
                fire()
            }
    }

    private func fire() {
        let firedTension = tension
        // Fire forward along the negative of the pull vector.
        guard firedTension > 0.05 else {
            withAnimation(.interpolatingSpring(stiffness: 170, damping: 9)) { pull = .zero }
            return
        }
        launchCount += 1

        // Flight: project the ball outward opposite to the pull, off-screen.
        let dir = CGSize(width: -pull.width, height: -pull.height)
        let len = max(hypot(dir.width, dir.height), 0.001)
        let travel = max(size.width, size.height) * (1.1 + Double(firedTension))
        let flight = CGSize(width: dir.width / len * travel,
                            height: dir.height / len * travel)

        // Band twangs back to slack with a low-damping spring while ball coasts away.
        withAnimation(.interpolatingSpring(stiffness: 130, damping: 6)) {
            pull = .zero
        }
        withAnimation(.easeOut(duration: 0.55)) {
            flightOffset = flight
            launchFade = 1
        }
        // Respawn the projectile in the nock so it is re-draggable.
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.62) {
            flightOffset = .zero
            withAnimation(.easeIn(duration: 0.25)) { launchFade = 0 }
        }
    }
}

// MARK: - Demo driver (self-driving PhaseAnimator loop)

private enum PullToTriggerBowView_SlingPhase: CaseIterable {
    case idle, drawn, fired
}

private struct PullToTriggerBowView_DemoDriver: View {
    let size: CGSize

    private var geo: PullToTriggerBowView_SlingGeometry { PullToTriggerBowView_SlingGeometry(size: size) }

    var body: some View {
        // Drive the loop with a timeline that flips phase on a ~3.2s cadence,
        // and let PhaseAnimator's spring give the twang for free.
        TimelineView(.animation) { context in
            let t = context.date.timeIntervalSinceReferenceDate
            let trigger = Int(t / 1.07)   // advances the phase animator periodically
            PhaseAnimator(PullToTriggerBowView_SlingPhase.allCases, trigger: trigger) { phase in
                content(for: phase)
            } animation: { phase in
                animation(into: phase)
            }
        }
    }

    @ViewBuilder
    private func content(for phase: PullToTriggerBowView_SlingPhase) -> some View {
        let pull = pullVector(for: phase)
        let tension = tensionValue(pull: pull, maxPull: geo.maxPull)
        let projectile = CGPoint(x: geo.nock.x + pull.width,
                                 y: geo.nock.y + pull.height)
        ZStack {
            PullToTriggerBowView_SlingFrame(geo: geo)
            PullToTriggerBowView_SlingBand(geo: geo,
                      projectile: projectile,
                      tension: phase == .fired ? 0 : tension,
                      launchFade: phase == .fired ? firedFade : 0)
            // A second "in-flight" tracer ball on the fired phase keeps the tile
            // alive and shows the launch direction, never fully blank.
            if phase == .fired {
                PullToTriggerBowView_ProjectileView(radius: geo.projectileRadius, glow: 0.0)
                    .position(flightTarget)
                    .opacity(0.9)
            }
        }
    }

    // Demo states: idle slack, drawn-back taut, fired (slack + tracer in flight).
    private func pullVector(for phase: PullToTriggerBowView_SlingPhase) -> CGSize {
        switch phase {
        case .idle:  return .zero
        case .drawn: return CGSize(width: geo.maxPull * 0.30, height: geo.maxPull * 0.92)
        case .fired: return .zero
        }
    }

    private var firedFade: CGFloat { 1 }

    // Forward (up + slightly left) launch target, opposite the drawn vector.
    private var flightTarget: CGPoint {
        CGPoint(x: geo.nock.x - geo.maxPull * 0.30 * 2.4,
                y: geo.nock.y - geo.maxPull * 0.92 * 2.2)
    }

    private func animation(into phase: PullToTriggerBowView_SlingPhase) -> Animation {
        switch phase {
        case .idle:  return .interpolatingSpring(stiffness: 120, damping: 7)  // twang back to rest
        case .drawn: return .easeInOut(duration: 0.7)                          // smooth pull-back
        case .fired: return .easeOut(duration: 0.22)                           // snap release
        }
    }
}

// MARK: - Hint label

private struct PullToTriggerBowView_HintLabel: View {
    let text: String
    var body: some View {
        Text(text)
            .font(.system(size: 11, weight: .semibold, design: .rounded))
            .foregroundStyle(.white.opacity(0.7))
            .padding(.horizontal, 8)
            .padding(.vertical, 3)
            .background(.white.opacity(0.08), in: Capsule())
    }
}
"""###,
        "ges-rotate-clock-rewind": ###"""
import SwiftUI

// Twist-to-Rewind Clock
// Rotate the clock face and the hands wind backward/forward while a ghosted
// scene (a sun arcing over a day/night sky) visually un-happens or replays.
// demo == true  -> self-driving triangle-wave time scrub (no touch).
// demo == false -> two-finger RotateGesture scrubs time; eases to nearest hour.

struct RotateClockRewindView: View {
    var demo: Bool = false

    // Time scrubber, expressed in "hours" across a 12h dial.
    // 0 ... maxHours. The hour hand makes one full turn over this range.
    private let maxHours: Double = 12.0

    // Interactive state.
    @State private var committedT: Double = 7.5      // resting time
    @State private var liveDelta: Double = 0          // hours added by the in-flight twist
    @State private var lastTickHour: Int = 7

    var body: some View {
        GeometryReader { proxy in
            let size = proxy.size
            if demo {
                demoBody(size: size)
            } else {
                interactiveBody(size: size)
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // MARK: - Demo (self-driving)

    private func demoBody(size: CGSize) -> some View {
        TimelineView(.animation) { timeline in
            let t = demoTime(at: timeline.date)
            ClockScene(t: t, maxHours: maxHours, size: size)
        }
    }

    /// Triangle wave: sweep time forward then backward over a ~3.4s loop so the
    /// clock visibly winds and un-winds. Stays inside [0, maxHours].
    private func demoTime(at date: Date) -> Double {
        let period: Double = 3.4
        let phase = date.timeIntervalSinceReferenceDate.truncatingRemainder(dividingBy: period) / period
        // 0->1->0 triangle.
        let tri = phase < 0.5 ? (phase * 2.0) : (2.0 - phase * 2.0)
        // Sweep across most of the dial, but never to the absolute edges so the
        // scene never reads as fully "off".
        let lo = 0.5
        let hi = maxHours - 0.5
        return lo + tri * (hi - lo)
    }

    // MARK: - Interactive

    private var currentT: Double {
        clampTime(committedT + liveDelta)
    }

    private func interactiveBody(size: CGSize) -> some View {
        ClockScene(t: currentT, maxHours: maxHours, size: size)
            .contentShape(Rectangle())
            .gesture(rotationGesture)
            .sensoryFeedback(.selection, trigger: tickHour)
    }

    private var tickHour: Int {
        // Hour 0...11 derived from current time, used to fire a haptic per tick.
        Int(currentT.rounded(.down)) % 12
    }

    private var rotationGesture: some Gesture {
        RotateGesture()
            .onChanged { value in
                // One full rotation (2π) scrubs the whole 12h dial.
                let hours = value.rotation.radians / (2.0 * .pi) * maxHours
                liveDelta = hours
                let h = Int(clampTime(committedT + hours).rounded(.down)) % 12
                if h != lastTickHour { lastTickHour = h }
            }
            .onEnded { value in
                let hours = value.rotation.radians / (2.0 * .pi) * maxHours
                let target = nearestHour(clampTime(committedT + hours))
                withAnimation(.spring(response: 0.45, dampingFraction: 0.72)) {
                    committedT = target
                    liveDelta = 0
                }
            }
    }

    private func clampTime(_ v: Double) -> Double {
        min(max(v, 0), maxHours)
    }

    private func nearestHour(_ v: Double) -> Double {
        let r = v.rounded()
        return min(max(r, 0), maxHours)
    }
}

// MARK: - Scene (single rendering source of truth)

private struct ClockScene: View {
    let t: Double          // time in hours, 0 ... maxHours
    let maxHours: Double
    let size: CGSize

    private var radius: CGFloat { min(size.width, size.height) * 0.5 }

    /// Day progress 0...1 across the dial, used to drive the ghost scene.
    private var dayProgress: Double {
        guard maxHours > 0 else { return 0 }
        return min(max(t / maxHours, 0), 1)
    }

    var body: some View {
        ZStack {
            GhostScene(progress: dayProgress, radius: radius)
            ClockFace(radius: radius)
            ClockHands(t: t, maxHours: maxHours, radius: radius)
            CenterCap(radius: radius)
        }
        .frame(width: radius * 2, height: radius * 2)
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }
}

// MARK: - Ghost scene (day/night the hands scrub through)

private struct GhostScene: View {
    let progress: Double   // 0 = start of day, 1 = end of day
    let radius: CGFloat

    var body: some View {
        ZStack {
            Circle()
                .fill(skyGradient)
            sun
            stars
        }
        .frame(width: radius * 1.9, height: radius * 1.9)
        .clipShape(Circle())
        .opacity(0.92)
    }

    // Sun travels along an arc from left horizon, up over the top, down to right.
    private var sunAngle: Double {
        // Map progress 0...1 to angle 180°...360° going over the top (clockwise arc).
        // We trace a semicircle: angle from 180° (left) to 360° (right)
        // measured so the sun peaks at the top.
        180.0 + progress * 180.0
    }

    private var sunPoint: CGPoint {
        let r = radius * 0.62
        let rad = sunAngle * .pi / 180.0
        let x = cos(rad) * r
        let y = sin(rad) * r   // sin negative for top half in screen coords handled below
        return CGPoint(x: x, y: y)
    }

    // How high the sun is (1 at noon, 0 at horizons) -> drives sky color + brightness.
    private var elevation: Double {
        // peaks at progress 0.5
        let e = sin(progress * .pi)
        return max(0, e)
    }

    private var sun: some View {
        let d = radius * 0.34
        // Convert sunPoint (centered, y grows toward bottom of arc) into screen offset.
        // sin(rad) for angles 180->360 is 0 -> negative -> 0, so the sun rides the TOP.
        return Circle()
            .fill(
                RadialGradient(
                    colors: [
                        sunCore.opacity(0.95 * (0.4 + 0.6 * elevation)),
                        sunCore.opacity(0.0)
                    ],
                    center: .center,
                    startRadius: 0,
                    endRadius: d * 0.85
                )
            )
            .overlay(
                Circle()
                    .fill(sunCore.opacity(0.35 + 0.55 * elevation))
                    .frame(width: d * 0.46, height: d * 0.46)
            )
            .frame(width: d, height: d)
            .offset(x: sunPoint.x, y: sunPoint.y)
    }

    // Stars fade in as the sun sets (low elevation), giving the "un-happens" feel
    // when time reverses.
    private var stars: some View {
        let nightAmount = 1.0 - elevation
        return Canvas { ctx, sz in
            let pts: [(CGFloat, CGFloat, CGFloat)] = [
                (0.22, 0.24, 1.4), (0.72, 0.20, 1.0), (0.58, 0.34, 1.6),
                (0.34, 0.16, 1.1), (0.82, 0.40, 1.3), (0.16, 0.40, 0.9),
                (0.66, 0.50, 1.2), (0.46, 0.22, 1.0)
            ]
            for (fx, fy, r) in pts {
                let rect = CGRect(
                    x: fx * sz.width - r,
                    y: fy * sz.height - r,
                    width: r * 2,
                    height: r * 2
                )
                ctx.opacity = nightAmount * 0.9
                ctx.fill(Path(ellipseIn: rect), with: .color(starColor))
            }
        }
        .frame(width: radius * 1.9, height: radius * 1.9)
        .allowsHitTesting(false)
    }

    private var skyGradient: LinearGradient {
        // Interpolate between night (low elevation) and day (high elevation).
        let e = elevation
        let top = mix(nightTop, dayTop, e)
        let bottom = mix(nightBottom, dayBottom, e)
        return LinearGradient(
            colors: [top, bottom],
            startPoint: .top,
            endPoint: .bottom
        )
    }

    // Palette helpers (Color(red:green:blue:) literals only).
    private var dayTop: (Double, Double, Double) { (0.30, 0.58, 0.92) }
    private var dayBottom: (Double, Double, Double) { (0.72, 0.86, 0.98) }
    private var nightTop: (Double, Double, Double) { (0.05, 0.06, 0.15) }
    private var nightBottom: (Double, Double, Double) { (0.13, 0.10, 0.26) }
    private var sunCore: Color { Color(red: 1.0, green: 0.86, blue: 0.42) }
    private var starColor: Color { Color(red: 0.92, green: 0.94, blue: 1.0) }

    private func mix(_ a: (Double, Double, Double), _ b: (Double, Double, Double), _ f: Double) -> Color {
        let cf = min(max(f, 0), 1)
        return Color(
            red: a.0 + (b.0 - a.0) * cf,
            green: a.1 + (b.1 - a.1) * cf,
            blue: a.2 + (b.2 - a.2) * cf
        )
    }
}

// MARK: - Clock face (rim + ticks)

private struct ClockFace: View {
    let radius: CGFloat

    var body: some View {
        ZStack {
            // Translucent bezel so the ghost scene reads through.
            Circle()
                .strokeBorder(
                    LinearGradient(
                        colors: [
                            Color(red: 0.95, green: 0.95, blue: 0.97).opacity(0.9),
                            Color(red: 0.55, green: 0.57, blue: 0.66).opacity(0.7)
                        ],
                        startPoint: .topLeading,
                        endPoint: .bottomTrailing
                    ),
                    lineWidth: max(2, radius * 0.05)
                )
                .frame(width: radius * 1.96, height: radius * 1.96)

            ticks
        }
    }

    private var ticks: some View {
        ForEach(0..<12, id: \.self) { i in
            let isMajor = i % 3 == 0
            let len: CGFloat = isMajor ? radius * 0.16 : radius * 0.09
            let w: CGFloat = isMajor ? max(2, radius * 0.035) : max(1, radius * 0.02)
            Capsule()
                .fill(Color(red: 0.96, green: 0.97, blue: 1.0).opacity(isMajor ? 0.95 : 0.65))
                .frame(width: w, height: len)
                .offset(y: -(radius * 0.86 - len / 2))
                .rotationEffect(.degrees(Double(i) * 30.0))
        }
    }
}

// MARK: - Hands

private struct ClockHands: View {
    let t: Double          // hours, 0 ... maxHours
    let maxHours: Double
    let radius: CGFloat

    // Hour hand: one full turn across the whole dial scrub.
    private var hourAngle: Angle {
        .degrees((t / maxHours) * 360.0)
    }

    // Minute hand: 12x faster, so it whirls as you scrub — the "winding" cue.
    private var minuteAngle: Angle {
        .degrees((t / maxHours) * 360.0 * 12.0)
    }

    var body: some View {
        ZStack {
            hand(length: radius * 0.5, width: max(3, radius * 0.065),
                 color: Color(red: 0.97, green: 0.97, blue: 1.0), angle: hourAngle)
            hand(length: radius * 0.74, width: max(2, radius * 0.04),
                 color: Color(red: 0.85, green: 0.88, blue: 0.98), angle: minuteAngle)
            secondHand
        }
    }

    private func hand(length: CGFloat, width: CGFloat, color: Color, angle: Angle) -> some View {
        Capsule()
            .fill(color)
            .frame(width: width, height: length)
            .offset(y: -length / 2)
            .rotationEffect(angle)
            .shadow(color: Color.black.opacity(0.35), radius: 2, x: 0, y: 1)
    }

    private var secondAngle: Angle {
        .degrees((t / maxHours) * 360.0 * 60.0)
    }

    private var secondHand: some View {
        let length = radius * 0.82
        return Capsule()
            .fill(Color(red: 1.0, green: 0.42, blue: 0.38))
            .frame(width: max(1, radius * 0.018), height: length)
            .offset(y: -length / 2 + radius * 0.12)
            .rotationEffect(secondAngle)
    }
}

private struct CenterCap: View {
    let radius: CGFloat
    var body: some View {
        Circle()
            .fill(
                RadialGradient(
                    colors: [
                        Color(red: 0.98, green: 0.98, blue: 1.0),
                        Color(red: 0.62, green: 0.64, blue: 0.74)
                    ],
                    center: .topLeading,
                    startRadius: 0,
                    endRadius: radius * 0.14
                )
            )
            .frame(width: radius * 0.14, height: radius * 0.14)
            .shadow(color: Color.black.opacity(0.4), radius: 2, x: 0, y: 1)
    }
}
"""###,
        "ges-rotate-combination-lock": ###"""
import SwiftUI

// MARK: - Public View

/// Combination Safe Dial — rotate a numbered dial; correct numbers in sequence
/// light up, then the bolt retracts and the door eases open.
///
/// - `demo == true`: a self-driving PhaseAnimator scripts the full solve loop
///   (dial turns to each number, pips light, bolt retracts, door swings open,
///   then re-closes) so the tile stays alive with no touch.
/// - `demo == false`: a real one-finger circular drag (atan2) turns the dial,
///   snapping to integers; reversing direction commits a number; matching the
///   secret combo unlocks the safe.
struct RotateCombinationLockView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { geo in
            let side = min(geo.size.width, geo.size.height)
            ZStack {
                backdrop(side: side)
                if demo {
                    DemoSafe(side: side)
                } else {
                    InteractiveSafe(side: side)
                }
            }
            .frame(width: geo.size.width, height: geo.size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    private func backdrop(side: CGFloat) -> some View {
        LinearGradient(
            colors: [
                Color(red: 0.05, green: 0.06, blue: 0.10),
                Color(red: 0.02, green: 0.02, blue: 0.05)
            ],
            startPoint: .top, endPoint: .bottom
        )
    }
}

// MARK: - Shared lock state model

/// Snapshot of everything the renderer needs to draw a frame.
private struct LockState {
    var dialAngle: Double = 0      // radians, dial rotation
    var litCount: Int = 0          // how many combo stages are satisfied (0...3)
    var boltRetract: CGFloat = 0   // 0 = locked/extended, 1 = fully retracted
    var doorOpen: CGFloat = 0      // 0 = shut, 1 = fully swung open
    var solved: Bool = false       // glow accent when fully solved
}

private let comboCount = 3
private let dialNumbers = 40            // classic safe dial 0...39
private let unlockDoorAngle: Double = 78 // cap < 90 so we never see the back face

// MARK: - Demo (self-driving)

private struct DemoSafe: View {
    let side: CGFloat

    private enum Phase: CaseIterable {
        case closed, dialOne, dialTwo, dialThree, retract, open, hold, reclose
    }

    var body: some View {
        // No trigger → PhaseAnimator loops the phase sequence forever, so the
        // tile self-plays the full solve cycle with no touch.
        PhaseAnimator(Phase.allCases) { phase in
            SafeBody(state: state(for: phase), side: side, accent: accent(for: phase))
        } animation: { phase in
            animation(for: phase)
        }
    }

    private func state(for phase: Phase) -> LockState {
        var s = LockState()
        switch phase {
        case .closed:
            s.dialAngle = 0
        case .dialOne:
            s.dialAngle = turns(1.6)         // spin clockwise to first number
            s.litCount = 1
        case .dialTwo:
            s.dialAngle = turns(0.7)         // reverse to second
            s.litCount = 2
        case .dialThree:
            s.dialAngle = turns(1.25)        // reverse again to third
            s.litCount = 3
        case .retract:
            s.dialAngle = turns(1.25)
            s.litCount = 3
            s.solved = true
            s.boltRetract = 1
        case .open:
            s.dialAngle = turns(1.25)
            s.litCount = 3
            s.solved = true
            s.boltRetract = 1
            s.doorOpen = 1
        case .hold:
            s.dialAngle = turns(1.25)
            s.litCount = 3
            s.solved = true
            s.boltRetract = 1
            s.doorOpen = 1
        case .reclose:
            s.dialAngle = turns(1.25)
            s.litCount = 0
            s.boltRetract = 0
            s.doorOpen = 0
        }
        return s
    }

    private func accent(for phase: Phase) -> Bool {
        switch phase {
        case .retract, .open, .hold: return true
        default: return false
        }
    }

    private func animation(for phase: Phase) -> Animation? {
        switch phase {
        case .closed:    return .easeInOut(duration: 0.25)
        case .dialOne:   return .easeInOut(duration: 0.75)
        case .dialTwo:   return .easeInOut(duration: 0.65)
        case .dialThree: return .easeInOut(duration: 0.6)
        case .retract:   return .spring(response: 0.35, dampingFraction: 0.55)
        case .open:      return .spring(response: 0.7, dampingFraction: 0.78)
        case .hold:      return .easeInOut(duration: 0.6)
        case .reclose:   return .easeInOut(duration: 0.55)
        }
    }

    private func turns(_ t: Double) -> Double { t * 2 * .pi }
}

// MARK: - Interactive

private struct InteractiveSafe: View {
    let side: CGFloat

    // Secret combination (indices into 0...39).
    private let combo = [12, 30, 4]

    @State private var angle: Double = 0          // committed dial rotation (radians)
    @State private var lastFinger: Double = 0      // last finger angle (radians)
    @State private var dragActive: Bool = false    // true once a drag is in flight
    @State private var lastSign: Int = 0           // sign of last applied delta
    @State private var stage: Int = 0              // matched count
    @State private var solved: Bool = false
    @State private var boltRetract: CGFloat = 0
    @State private var doorOpen: CGFloat = 0
    @State private var snappedNumber: Int = 0      // number under the indicator

    var body: some View {
        let state = LockState(
            dialAngle: angle,
            litCount: stage,
            boltRetract: boltRetract,
            doorOpen: doorOpen,
            solved: solved
        )
        SafeBody(state: state, side: side, accent: solved)
            .contentShape(Rectangle())
            .gesture(dialDrag(side: side))
            .sensoryFeedback(.selection, trigger: snappedNumber)
            .sensoryFeedback(.impact(weight: .medium), trigger: stage)
            .sensoryFeedback(.success, trigger: solved) { _, now in now }
    }

    private func dialDrag(side: CGFloat) -> some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                let center = CGPoint(x: side / 2, y: side / 2)
                let f = atan2(value.location.y - center.y,
                              value.location.x - center.x)
                // First sample of a fresh drag has zero translation: seed the
                // reference finger angle and wait for the next sample.
                if isGestureStart(value) || !dragActive {
                    dragActive = true
                    lastFinger = f
                    return
                }
                var delta = f - lastFinger
                if delta > .pi { delta -= 2 * .pi }
                if delta < -.pi { delta += 2 * .pi }
                lastFinger = f
                applyDelta(delta)
            }
            .onEnded { _ in
                snapAndCommit()
                lastFinger = 0
                lastSign = 0
                dragActive = false
            }
    }

    private func isGestureStart(_ value: DragGesture.Value) -> Bool {
        value.translation == .zero
    }

    private func applyDelta(_ delta: Double) {
        guard !solved else { return }
        angle += delta

        // Track direction; a reversal commits the current number as a candidate.
        let sign = delta > 0 ? 1 : (delta < 0 ? -1 : 0)
        if sign != 0 {
            if lastSign != 0 && sign != lastSign {
                commitCandidate()
            }
            lastSign = sign
        }

        // Haptic + visual snap as we cross each integer number.
        let n = currentNumber()
        if n != snappedNumber {
            snappedNumber = n
        }
    }

    /// The dial number currently under the indicator (0...39).
    private func currentNumber() -> Int {
        let perNum = 2 * .pi / Double(dialNumbers)
        // Negative rotation moves higher numbers up (clockwise dial convention).
        let raw = (-angle / perNum)
        var n = Int(raw.rounded()) % dialNumbers
        if n < 0 { n += dialNumbers }
        return n
    }

    private func commitCandidate() {
        guard stage < comboCount else { return }
        let candidate = currentNumber()
        if candidate == combo[stage] {
            stage += 1
            if stage == comboCount {
                unlock()
            }
        } else if candidate == combo[0] {
            stage = 1
        } else {
            stage = 0
        }
    }

    private func snapAndCommit() {
        guard !solved else { return }
        // Snap committed angle to the nearest integer number with a small spring.
        let perNum = 2 * .pi / Double(dialNumbers)
        let snapped = (angle / perNum).rounded() * perNum
        withAnimation(.spring(response: 0.3, dampingFraction: 0.6)) {
            angle = snapped
        }
        // A pause-and-release also reads as a reversal for the final number.
        commitCandidate()
        lastSign = 0
    }

    private func unlock() {
        solved = true
        withAnimation(.spring(response: 0.35, dampingFraction: 0.55)) {
            boltRetract = 1
        }
        withAnimation(.spring(response: 0.7, dampingFraction: 0.78).delay(0.2)) {
            doorOpen = 1
        }
        // Auto re-lock after a beat so the demo-able interactive state recovers.
        DispatchQueue.main.asyncAfter(deadline: .now() + 3.2) {
            withAnimation(.easeInOut(duration: 0.55)) {
                doorOpen = 0
                boltRetract = 0
            }
            stage = 0
            solved = false
            lastSign = 0
        }
    }
}

// MARK: - Safe body (shared renderer)

private struct SafeBody: View {
    let state: LockState
    let side: CGFloat
    let accent: Bool

    var body: some View {
        let s = side
        ZStack {
            // Interior cavity revealed when the door swings — keeps an open
            // frame legible (never blank).
            InteriorCavity(side: s)

            // The swinging door carries the dial, hinged on the left edge.
            DoorFace(state: state, side: s, accent: accent)
                .rotation3DEffect(
                    .degrees(Double(state.doorOpen) * unlockDoorAngle),
                    axis: (x: 0, y: 1, z: 0),
                    anchor: .leading,
                    perspective: 0.55
                )
        }
        .frame(width: s, height: s)
    }
}

private struct InteriorCavity: View {
    let side: CGFloat

    var body: some View {
        let inset = side * 0.10
        RoundedRectangle(cornerRadius: side * 0.06, style: .continuous)
            .fill(
                RadialGradient(
                    colors: [
                        Color(red: 0.10, green: 0.10, blue: 0.13),
                        Color(red: 0.02, green: 0.02, blue: 0.03)
                    ],
                    center: .center,
                    startRadius: 0,
                    endRadius: side * 0.5
                )
            )
            .overlay(
                // Suggestion of a shelf so the open interior reads as a safe.
                RoundedRectangle(cornerRadius: side * 0.01)
                    .fill(Color(red: 0.16, green: 0.16, blue: 0.19))
                    .frame(width: side * 0.55, height: side * 0.03)
                    .offset(y: side * 0.05)
            )
            .padding(inset)
    }
}

// MARK: - Door face (bolt + dial)

private struct DoorFace: View {
    let state: LockState
    let side: CGFloat
    let accent: Bool

    var body: some View {
        let s = side
        ZStack {
            doorPlate(s: s)
            Bolt(retract: state.boltRetract, side: s)
            VStack(spacing: s * 0.04) {
                ProgressPips(litCount: state.litCount, side: s)
                Dial(angle: state.dialAngle, accent: accent, side: s)
            }
        }
        .frame(width: s, height: s)
        // Subtle parallax shadow as the door lifts off the body.
        .shadow(color: .black.opacity(0.35 * Double(state.doorOpen)),
                radius: s * 0.04 * state.doorOpen,
                x: s * 0.05 * state.doorOpen, y: 0)
    }

    private func doorPlate(s: CGFloat) -> some View {
        RoundedRectangle(cornerRadius: s * 0.06, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.28, green: 0.30, blue: 0.36),
                        Color(red: 0.16, green: 0.17, blue: 0.22)
                    ],
                    startPoint: .topLeading, endPoint: .bottomTrailing
                )
            )
            .overlay(
                RoundedRectangle(cornerRadius: s * 0.06, style: .continuous)
                    .strokeBorder(
                        LinearGradient(
                            colors: [Color.white.opacity(0.18), Color.black.opacity(0.25)],
                            startPoint: .top, endPoint: .bottom
                        ),
                        lineWidth: max(1, s * 0.008)
                    )
            )
            .padding(s * 0.10)
    }
}

// MARK: - Bolt

private struct Bolt: View {
    let retract: CGFloat
    let side: CGFloat

    var body: some View {
        let s = side
        let travel = s * 0.16
        // Bolt sits on the right edge of the door, slides left to retract.
        Capsule()
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.78, green: 0.80, blue: 0.86),
                        Color(red: 0.50, green: 0.52, blue: 0.58)
                    ],
                    startPoint: .top, endPoint: .bottom
                )
            )
            .frame(width: s * 0.20, height: s * 0.055)
            .overlay(
                Capsule().stroke(Color.black.opacity(0.25), lineWidth: max(0.5, s * 0.004))
            )
            .offset(x: s * 0.33 - travel * retract, y: -s * 0.30)
    }
}

// MARK: - Progress pips

private struct ProgressPips: View {
    let litCount: Int
    let side: CGFloat

    var body: some View {
        let s = side
        HStack(spacing: s * 0.025) {
            ForEach(0..<comboCount, id: \.self) { i in
                Circle()
                    .fill(i < litCount ? litColor : Color(red: 0.20, green: 0.21, blue: 0.26))
                    .frame(width: s * 0.035, height: s * 0.035)
                    .overlay(
                        Circle()
                            .fill(Color.white)
                            .frame(width: s * 0.012, height: s * 0.012)
                            .opacity(i < litCount ? 0.9 : 0)
                    )
                    .shadow(color: i < litCount ? litColor.opacity(0.8) : .clear,
                            radius: s * 0.02)
                    .animation(.spring(response: 0.3, dampingFraction: 0.6), value: litCount)
            }
        }
        .padding(.top, s * 0.02)
    }

    private var litColor: Color {
        litCount >= comboCount
            ? Color(red: 0.45, green: 0.95, blue: 0.55)
            : Color(red: 1.0, green: 0.78, blue: 0.30)
    }
}

// MARK: - Dial

private struct Dial: View {
    let angle: Double
    let accent: Bool
    let side: CGFloat

    var body: some View {
        let s = side
        let d = s * 0.50
        ZStack {
            indicator(s: s, d: d)
            ringFace(d: d)
            ticksAndNumerals(d: d)
                .rotationEffect(.radians(angle))
            knob(d: d)
                .rotationEffect(.radians(angle))
        }
        .frame(width: d, height: d)
    }

    // Fixed pointer above the dial showing the reading position.
    private func indicator(s: CGFloat, d: CGFloat) -> some View {
        Triangle()
            .fill(accent
                  ? Color(red: 0.45, green: 0.95, blue: 0.55)
                  : Color(red: 0.95, green: 0.85, blue: 0.55))
            .frame(width: d * 0.10, height: d * 0.09)
            .offset(y: -d * 0.56)
            .shadow(color: .black.opacity(0.4), radius: d * 0.01, y: d * 0.01)
    }

    private func ringFace(d: CGFloat) -> some View {
        Circle()
            .fill(
                RadialGradient(
                    colors: [
                        Color(red: 0.20, green: 0.21, blue: 0.26),
                        Color(red: 0.10, green: 0.10, blue: 0.13)
                    ],
                    center: .center, startRadius: 0, endRadius: d * 0.55
                )
            )
            .overlay(
                Circle().strokeBorder(
                    accent
                        ? Color(red: 0.45, green: 0.95, blue: 0.55).opacity(0.85)
                        : Color.white.opacity(0.10),
                    lineWidth: max(1, d * 0.02)
                )
            )
            .shadow(color: accent
                    ? Color(red: 0.45, green: 0.95, blue: 0.55).opacity(0.6)
                    : .clear,
                    radius: d * 0.06)
    }

    private func ticksAndNumerals(d: CGFloat) -> some View {
        // Show every tick; numerals only on the majors (every 5) and only when
        // the dial is large enough to read them — keeps a 120pt tile uncluttered.
        let showNumerals = side > 220
        return ZStack {
            ForEach(0..<dialNumbers, id: \.self) { i in
                tick(i: i, d: d)
            }
            if showNumerals {
                ForEach(0..<8, id: \.self) { j in
                    numeral(major: j * 5, d: d)
                }
            }
        }
    }

    private func tick(i: Int, d: CGFloat) -> some View {
        let isMajor = i % 5 == 0
        let len = isMajor ? d * 0.10 : d * 0.05
        return Rectangle()
            .fill(Color.white.opacity(isMajor ? 0.75 : 0.35))
            .frame(width: max(0.6, d * (isMajor ? 0.014 : 0.008)), height: len)
            .offset(y: -d * 0.43)
            .rotationEffect(.degrees(Double(i) / Double(dialNumbers) * 360))
    }

    private func numeral(major: Int, d: CGFloat) -> some View {
        Text("\(major)")
            .font(.system(size: d * 0.085, weight: .semibold, design: .rounded))
            .foregroundStyle(Color.white.opacity(0.85))
            .offset(y: -d * 0.30)
            .rotationEffect(.degrees(Double(major) / Double(dialNumbers) * 360))
    }

    // Center knurled grip that turns with the dial.
    private func knob(d: CGFloat) -> some View {
        ZStack {
            Circle()
                .fill(
                    RadialGradient(
                        colors: [
                            Color(red: 0.62, green: 0.64, blue: 0.70),
                            Color(red: 0.34, green: 0.36, blue: 0.42)
                        ],
                        center: .topLeading, startRadius: 0, endRadius: d * 0.30
                    )
                )
                .frame(width: d * 0.46, height: d * 0.46)
            // Knurl ridges.
            ForEach(0..<24, id: \.self) { k in
                Capsule()
                    .fill(Color.black.opacity(0.18))
                    .frame(width: max(0.5, d * 0.006), height: d * 0.07)
                    .offset(y: -d * 0.19)
                    .rotationEffect(.degrees(Double(k) / 24 * 360))
            }
            // Grip groove marking the dial's zero so rotation is visible.
            Capsule()
                .fill(Color(red: 0.95, green: 0.85, blue: 0.55))
                .frame(width: d * 0.03, height: d * 0.20)
                .offset(y: -d * 0.10)
        }
    }
}

// MARK: - Triangle helper

private struct Triangle: Shape {
    func path(in rect: CGRect) -> Path {
        var p = Path()
        p.move(to: CGPoint(x: rect.midX, y: rect.maxY))
        p.addLine(to: CGPoint(x: rect.minX, y: rect.minY))
        p.addLine(to: CGPoint(x: rect.maxX, y: rect.minY))
        p.closeSubpath()
        return p
    }
}
"""###,
        "ges-rotate-dial-knob": ###"""
import SwiftUI

// MARK: - Tactile Detent Dial
// Twist a knurled dial; it clicks through evenly spaced detents with a
// micro-overshoot at each notch and a tick flash as it passes.
// demo == true  -> self-driving PhaseAnimator that auto-clicks notch to notch.
// demo == false -> single-finger DragGesture + atan2 delta accumulation,
//                  spring(bounce:) snap-to-detent and haptic per notch crossing.

public struct RotateDialKnobView: View {
    public var demo: Bool = false

    // Number of evenly spaced detents around the dial.
    private let detentCount: Int = 8

    // Live interactive state.
    @State private var angle: Double = 0          // current dial angle (radians)
    @State private var lastTouchAngle: Double = 0 // previous sample for delta accumulation
    @State private var isDragging: Bool = false
    @State private var currentDetent: Int = 0     // nearest detent index, updates live
    @State private var flashDetent: Int = -1      // which tick is flashing

    public init(demo: Bool = false) {
        self.demo = demo
    }

    public var body: some View {
        GeometryReader { geo in
            let side = min(geo.size.width, geo.size.height)
            let dim = side * 0.86
            ZStack {
                background
                // DragGesture reports location in the dialStack's local space,
                // so the rotation center is the local mid-point (dim/2, dim/2),
                // NOT the GeometryReader's full-size center.
                content(dim: dim, center: CGPoint(x: dim / 2, y: dim / 2))
            }
            .frame(width: geo.size.width, height: geo.size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // MARK: Background

    private var background: some View {
        RadialGradient(
            colors: [
                Color(red: 0.10, green: 0.11, blue: 0.16),
                Color(red: 0.05, green: 0.05, blue: 0.09)
            ],
            center: .center,
            startRadius: 0,
            endRadius: 220
        )
        .ignoresSafeArea()
    }

    // MARK: Content router

    @ViewBuilder
    private func content(dim: CGFloat, center: CGPoint) -> some View {
        if demo {
            demoContent(dim: dim)
        } else {
            interactiveContent(dim: dim, center: center)
        }
    }

    // MARK: Demo (self-driving)

    @ViewBuilder
    private func demoContent(dim: CGFloat) -> some View {
        // PhaseAnimator steps over detent indices; each transition uses a
        // spring(bounce:) so the needle micro-overshoots into every notch.
        PhaseAnimator(demoSequence, content: { idx in
            dialStack(dim: dim,
                      liveAngle: detentAngle(for: idx),
                      flashedDetent: ((idx % detentCount) + detentCount) % detentCount)
        }, animation: { _ in
            .spring(duration: 0.34, bounce: 0.42)
        })
    }

    // Sweep up through a handful of detents and back so the dial auto-clicks
    // on a lively ~3s loop (kept short of a full revolution on purpose).
    private var demoSequence: [Int] {
        var seq: [Int] = []
        for i in 0...4 { seq.append(i) }
        for i in stride(from: 3, through: 0, by: -1) { seq.append(i) }
        return seq
    }

    // MARK: Interactive (single-finger twist)

    @ViewBuilder
    private func interactiveContent(dim: CGFloat, center: CGPoint) -> some View {
        dialStack(dim: dim, liveAngle: angle, flashedDetent: flashDetent)
            .contentShape(Circle())
            .gesture(twistGesture(center: center))
            .modifier(DetentHaptic(trigger: currentDetent, enabled: !demo))
    }

    private func twistGesture(center: CGPoint) -> some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                let touchAngle = atan2(value.location.y - center.y,
                                       value.location.x - center.x)
                if !isDragging {
                    isDragging = true
                    lastTouchAngle = touchAngle
                    return
                }
                // Shortest-arc delta avoids the atan2 ±pi wrap discontinuity.
                var delta = touchAngle - lastTouchAngle
                delta = normalizedAngle(delta)
                lastTouchAngle = touchAngle
                angle += delta
                updateLiveDetent()
            }
            .onEnded { _ in
                isDragging = false
                let target = nearestDetentIndex(for: angle)
                withAnimation(.spring(duration: 0.45, bounce: 0.4)) {
                    angle = detentAngle(for: target)
                }
                fireDetent(index: target)
            }
    }

    // Update nearest-detent index live so haptic + tick flash fire as we pass.
    private func updateLiveDetent() {
        let idx = nearestDetentIndex(for: angle)
        let wrapped = ((idx % detentCount) + detentCount) % detentCount
        if wrapped != currentDetent {
            fireDetent(index: idx)
        }
    }

    private func fireDetent(index: Int) {
        let wrapped = ((index % detentCount) + detentCount) % detentCount
        currentDetent = wrapped
        withAnimation(.easeOut(duration: 0.08)) {
            flashDetent = wrapped
        }
        withAnimation(.easeIn(duration: 0.45).delay(0.10)) {
            flashDetent = -1
        }
    }

    // MARK: Detent math

    private var detentStep: Double { (2 * Double.pi) / Double(detentCount) }

    private func detentAngle(for index: Int) -> Double {
        Double(index) * detentStep
    }

    private func nearestDetentIndex(for a: Double) -> Int {
        Int((a / detentStep).rounded())
    }

    private func normalizedAngle(_ a: Double) -> Double {
        var v = a
        while v > Double.pi { v -= 2 * Double.pi }
        while v < -Double.pi { v += 2 * Double.pi }
        return v
    }

    // MARK: Dial assembly

    private func dialStack(dim: CGFloat, liveAngle: Double, flashedDetent: Int) -> some View {
        ZStack {
            DetentTicks(count: detentCount,
                        diameter: dim,
                        flashedDetent: flashedDetent)
            KnobBody(diameter: dim, angle: liveAngle)
            Needle(diameter: dim, angle: liveAngle)
            CenterCap(diameter: dim)
        }
        .frame(width: dim, height: dim)
    }
}

// MARK: - Detent tick ring (the notches)

private struct DetentTicks: View {
    let count: Int
    let diameter: CGFloat
    let flashedDetent: Int

    var body: some View {
        ZStack {
            ForEach(0..<count, id: \.self) { i in
                tick(at: i)
            }
        }
        .frame(width: diameter, height: diameter)
    }

    private func tick(at i: Int) -> some View {
        let isFlash = (i == flashedDetent)
        let lit = Color(red: 1.0, green: 0.82, blue: 0.36)
        let dim = Color(red: 0.34, green: 0.36, blue: 0.45)
        let h: CGFloat = diameter * (isFlash ? 0.10 : 0.066)
        let w: CGFloat = diameter * (isFlash ? 0.022 : 0.016)
        return Capsule(style: .continuous)
            .fill(isFlash ? lit : dim)
            .frame(width: w, height: h)
            .shadow(color: isFlash ? lit.opacity(0.9) : .clear,
                    radius: isFlash ? 7 : 0)
            .offset(y: -diameter * 0.5 + h * 0.5 + diameter * 0.012)
            .rotationEffect(.radians(Double(i) * tickStep))
    }

    private var tickStep: Double { (2 * Double.pi) / Double(count) }
}

// MARK: - Knurled knob body

private struct KnobBody: View {
    let diameter: CGFloat
    let angle: Double

    private let ridgeCount: Int = 36

    var body: some View {
        ZStack {
            // Recessed bezel.
            Circle()
                .fill(
                    RadialGradient(
                        colors: [
                            Color(red: 0.07, green: 0.08, blue: 0.12),
                            Color(red: 0.03, green: 0.03, blue: 0.06)
                        ],
                        center: .center,
                        startRadius: diameter * 0.30,
                        endRadius: diameter * 0.50
                    )
                )
                .frame(width: diameter * 0.92, height: diameter * 0.92)

            // Knob plate with directional sheen.
            Circle()
                .fill(
                    LinearGradient(
                        colors: [
                            Color(red: 0.26, green: 0.28, blue: 0.36),
                            Color(red: 0.13, green: 0.14, blue: 0.20),
                            Color(red: 0.08, green: 0.09, blue: 0.13)
                        ],
                        startPoint: .top,
                        endPoint: .bottom
                    )
                )
                .frame(width: diameter * 0.78, height: diameter * 0.78)
                .overlay(knurling)
                .overlay(
                    Circle()
                        .strokeBorder(Color.white.opacity(0.10), lineWidth: 1)
                        .frame(width: diameter * 0.78, height: diameter * 0.78)
                )
                .rotationEffect(.radians(angle))
                .shadow(color: .black.opacity(0.55), radius: 10, x: 0, y: 6)
        }
    }

    // Ridged grip texture around the plate rim.
    private var knurling: some View {
        ZStack {
            ForEach(0..<ridgeCount, id: \.self) { i in
                ridge(at: i)
            }
        }
        .frame(width: diameter * 0.78, height: diameter * 0.78)
        .mask(
            Circle()
                .strokeBorder(Color.black, lineWidth: diameter * 0.11)
                .frame(width: diameter * 0.78, height: diameter * 0.78)
        )
    }

    private func ridge(at i: Int) -> some View {
        let shade = (i % 2 == 0)
            ? Color.white.opacity(0.16)
            : Color.black.opacity(0.30)
        return Rectangle()
            .fill(shade)
            .frame(width: ridgeWidth, height: diameter * 0.78)
            .rotationEffect(.radians(Double(i) * ridgeStep))
    }

    private var ridgeWidth: CGFloat { diameter * 0.013 }
    private var ridgeStep: Double { Double.pi / Double(ridgeCount) }
}

// MARK: - Pointer needle

private struct Needle: View {
    let diameter: CGFloat
    let angle: Double

    var body: some View {
        Capsule(style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 1.0, green: 0.88, blue: 0.52),
                        Color(red: 0.96, green: 0.55, blue: 0.20)
                    ],
                    startPoint: .top,
                    endPoint: .bottom
                )
            )
            .frame(width: diameter * 0.030, height: diameter * 0.30)
            .offset(y: -diameter * 0.16)
            .shadow(color: Color(red: 0.96, green: 0.55, blue: 0.20).opacity(0.55),
                    radius: 5)
            .rotationEffect(.radians(angle))
    }
}

// MARK: - Center cap

private struct CenterCap: View {
    let diameter: CGFloat

    var body: some View {
        Circle()
            .fill(
                RadialGradient(
                    colors: [
                        Color(red: 0.30, green: 0.32, blue: 0.40),
                        Color(red: 0.10, green: 0.11, blue: 0.16)
                    ],
                    center: .init(x: 0.4, y: 0.35),
                    startRadius: 0,
                    endRadius: diameter * 0.12
                )
            )
            .frame(width: diameter * 0.20, height: diameter * 0.20)
            .overlay(
                Circle().strokeBorder(Color.white.opacity(0.12), lineWidth: 1)
            )
    }
}

// MARK: - Haptic helper (gated to interactive mode)

private struct DetentHaptic: ViewModifier {
    let trigger: Int
    let enabled: Bool

    func body(content: Content) -> some View {
        if enabled {
            content.sensoryFeedback(.impact(weight: .light, intensity: 0.8),
                                    trigger: trigger)
        } else {
            content
        }
    }
}
"""###,
        "ges-rotate-gear-train": ###"""
import SwiftUI

// MARK: - Public View

/// Meshed Gear Train — rotate the drive gear and a train of meshed gears turns
/// in alternating directions at tooth-ratio-scaled speeds, with a brief backlash
/// jiggle on direction reversal.
///
/// - `demo == true`  : self-driving auto-crank loop (forward → pause → reverse).
/// - `demo == false` : one-finger interactive crank (atan2 DragGesture on the drive gear).
struct RotateGearTrainView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { proxy in
            GearTrainStage(size: proxy.size, demo: demo)
                .frame(width: proxy.size.width, height: proxy.size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }
}

// MARK: - Gear specification (tooth counts chosen so the middle gear is ODD,
// which is the parity condition for both meshes to align by construction).

private enum GearTrainConfig {
    /// Tooth counts. Index 0 is the drive gear. Middle (index 1) MUST be odd.
    static let teeth: [Int] = [12, 15, 9]
    /// Sum of tooth counts — drives pitch-radius packing along the train axis.
    static var teethSum: CGFloat { CGFloat(teeth.reduce(0, +)) }
    static var maxTeeth: CGFloat { CGFloat(teeth.max() ?? 12) }
    /// Addendum in module units (tooth tip extends 1 module beyond pitch radius).
    static let addendum: CGFloat = 1.0
}

// MARK: - Stage: lays out the train, owns the crank state, hosts both drivers.

private struct GearTrainStage: View {
    let size: CGSize
    let demo: Bool

    // Interactive crank state.
    @State private var driveAngle: Double = 0          // accumulated drive rotation (radians)
    @State private var lastTouchAngle: Double? = nil    // atan2 of previous drag sample
    @State private var reverseTrigger: Int = 0          // backlash impulse source
    @State private var backlashSign: Double = 1         // direction of the last jiggle
    @State private var meshTick: Int = 0                // haptic per tooth-mesh crossing

    // Backlash transient: a decaying spring offset added to downstream gears.
    @State private var backlash: Double = 0

    var body: some View {
        let layout = GearLayout(size: size)

        ZStack {
            backdrop
            if demo {
                demoContent(layout: layout)
            } else {
                interactiveContent(layout: layout)
            }
        }
        .compositingGroup()
        // Subtle haptics where supported; harmless no-op elsewhere.
        .sensoryFeedback(.selection, trigger: meshTick)
        .sensoryFeedback(.impact(weight: .light, intensity: 0.5), trigger: reverseTrigger)
    }

    // MARK: Backdrop

    private var backdrop: some View {
        RoundedRectangle(cornerRadius: 18, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.07, green: 0.08, blue: 0.11),
                        Color(red: 0.10, green: 0.11, blue: 0.15)
                    ],
                    startPoint: .topLeading,
                    endPoint: .bottomTrailing
                )
            )
            .overlay(
                RoundedRectangle(cornerRadius: 18, style: .continuous)
                    .strokeBorder(Color(red: 1, green: 1, blue: 1).opacity(0.05), lineWidth: 1)
            )
    }

    // MARK: Interactive (demo == false)

    private func interactiveContent(layout: GearLayout) -> some View {
        trainBody(layout: layout, drive: driveAngle, backlash: backlash)
            .contentShape(Rectangle())
            .gesture(crankGesture(layout: layout))
    }

    private func crankGesture(layout: GearLayout) -> some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                let c = layout.center(of: 0)
                let current = atan2(value.location.y - c.y, value.location.x - c.x)
                guard let previous = lastTouchAngle else {
                    lastTouchAngle = current
                    return
                }
                var delta = current - previous
                // Unwrap across the ±π seam so a continuous crank stays continuous.
                if delta > .pi { delta -= 2 * .pi }
                if delta < -.pi { delta += 2 * .pi }
                lastTouchAngle = current

                let newAngle = driveAngle + delta
                detectReversalAndMesh(old: driveAngle, new: newAngle)
                driveAngle = newAngle
            }
            .onEnded { _ in
                lastTouchAngle = nil
            }
    }

    /// Fires a backlash impulse on drive-direction reversal and a mesh tick per
    /// tooth crossing of the drive gear. Kept additive + clamped so teeth never
    /// appear to unmesh.
    private func detectReversalAndMesh(old: Double, new: Double) {
        let movement = new - old
        if movement != 0 {
            let dir = movement > 0 ? 1.0 : -1.0
            if dir != backlashSign {
                backlashSign = dir
                fireBacklash(direction: dir)
            }
        }
        // One tick per tooth of the drive gear passing the mesh point.
        let pitch = 2 * Double.pi / Double(GearTrainConfig.teeth[0])
        let oldTooth = Int((old / pitch).rounded(.down))
        let newTooth = Int((new / pitch).rounded(.down))
        if oldTooth != newTooth { meshTick &+= 1 }
    }

    private func fireBacklash(direction: Double) {
        reverseTrigger &+= 1
        // Peak amplitude is a small fraction of one tooth pitch on the SMALLEST
        // downstream gear, so the jiggle never reads as the mesh letting go.
        let smallestDownstream = GearTrainConfig.teeth.dropFirst().min() ?? 9
        let cap = (Double.pi / Double(smallestDownstream)) * 0.28
        backlash = direction * cap
        withAnimation(.interpolatingSpring(stiffness: 220, damping: 7)) {
            backlash = 0
        }
    }

    // MARK: Demo (demo == true) — self-driving crank loop.

    private func demoContent(layout: GearLayout) -> some View {
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            let phase = DemoCrank.drive(at: t)
            trainBody(layout: layout, drive: phase.angle, backlash: phase.backlash)
        }
    }

    // MARK: Shared train rendering

    private func trainBody(layout: GearLayout, drive: Double, backlash: Double) -> some View {
        ZStack {
            // Connecting baseplate "shaft rail" for mechanical grounding.
            shaftRail(layout: layout)
            ForEach(GearTrainConfig.teeth.indices, id: \.self) { index in
                gearView(index: index, layout: layout, drive: drive, backlash: backlash)
            }
            crankHint(layout: layout, drive: drive)
        }
    }

    private func shaftRail(layout: GearLayout) -> some View {
        let c0 = layout.center(of: 0)
        let cN = layout.center(of: GearTrainConfig.teeth.count - 1)
        return Path { p in
            p.move(to: c0)
            p.addLine(to: cN)
        }
        .stroke(Color(red: 0.18, green: 0.20, blue: 0.27).opacity(0.7),
                style: StrokeStyle(lineWidth: max(2, layout.module * 0.5), lineCap: .round))
    }

    @ViewBuilder
    private func gearView(index: Int, layout: GearLayout, drive: Double, backlash: Double) -> some View {
        let teeth = GearTrainConfig.teeth[index]
        let center = layout.center(of: index)
        let pitchR = layout.pitchRadius(of: index)
        let angle = gearAngle(index: index, drive: drive, backlash: backlash)

        Gear(teeth: teeth, pitchRadius: pitchR, module: layout.module)
            .fill(gearFill(index: index))
            .overlay(
                Gear(teeth: teeth, pitchRadius: pitchR, module: layout.module)
                    .stroke(Color(red: 0.02, green: 0.03, blue: 0.05).opacity(0.55),
                            lineWidth: max(0.6, layout.module * 0.12))
            )
            .overlay(hubDecoration(index: index, pitchR: pitchR, layout: layout))
            .rotationEffect(.radians(angle))
            .position(center)
            .shadow(color: Color(red: 0, green: 0, blue: 0).opacity(0.35),
                    radius: layout.module * 0.6, x: 0, y: layout.module * 0.35)
    }

    /// Closed-form rotation. Telescopes — no per-frame chaining, so no drift.
    /// rot_i = (-1)^i * (N0 / Ni) * drive + restPhase_i  (+ backlash for i >= 1)
    private func gearAngle(index: Int, drive: Double, backlash: Double) -> Double {
        let n0 = Double(GearTrainConfig.teeth[0])
        let ni = Double(GearTrainConfig.teeth[index])
        let sign: Double = (index % 2 == 0) ? 1 : -1
        let ratioRotation = sign * (n0 / ni) * drive
        let rest = restPhase(index: index)
        // Backlash only on downstream gears, scaled with ratio so the visual
        // jiggle magnitude stays roughly uniform across the train.
        let jiggle = (index == 0) ? 0 : backlash * (n0 / ni)
        return ratioRotation + rest + jiggle
    }

    /// Rest (mesh) phase, written against the Path convention that a TOOTH TIP
    /// sits at local angle 0. Drive gear has zero offset; each downstream gear is
    /// offset so a VALLEY faces its left neighbor (angle π). Middle-gear odd-parity
    /// guarantees a tooth TIP simultaneously faces the right neighbor.
    private func restPhase(index: Int) -> Double {
        guard index > 0 else { return 0 }
        let ni = Double(GearTrainConfig.teeth[index])
        return Double.pi - Double.pi / ni
    }

    // MARK: Decoration

    private func gearFill(index: Int) -> RadialGradient {
        let palettes: [(Color, Color)] = [
            (Color(red: 0.55, green: 0.78, blue: 0.95), Color(red: 0.16, green: 0.34, blue: 0.55)),
            (Color(red: 0.96, green: 0.74, blue: 0.45), Color(red: 0.55, green: 0.30, blue: 0.12)),
            (Color(red: 0.62, green: 0.86, blue: 0.66), Color(red: 0.18, green: 0.44, blue: 0.30))
        ]
        let pair = palettes[index % palettes.count]
        return RadialGradient(
            colors: [pair.0, pair.1],
            center: .init(x: 0.38, y: 0.34),
            startRadius: 1,
            endRadius: 120
        )
    }

    @ViewBuilder
    private func hubDecoration(index: Int, pitchR: CGFloat, layout: GearLayout) -> some View {
        let hubR = pitchR * 0.42
        ZStack {
            Circle()
                .fill(Color(red: 0.10, green: 0.11, blue: 0.15))
                .frame(width: hubR * 2, height: hubR * 2)
            Circle()
                .strokeBorder(Color(red: 1, green: 1, blue: 1).opacity(0.10),
                              lineWidth: max(0.8, layout.module * 0.18))
                .frame(width: hubR * 2, height: hubR * 2)
            // A spoke marker so rotation is visually unambiguous.
            Capsule()
                .fill(Color(red: 1, green: 1, blue: 1).opacity(0.75))
                .frame(width: max(1.5, layout.module * 0.32), height: pitchR * 0.72)
                .offset(y: -pitchR * 0.34)
            Circle()
                .fill(Color(red: 0.45, green: 0.47, blue: 0.55))
                .frame(width: hubR * 0.7, height: hubR * 0.7)
        }
    }

    /// A faint rotating arc on the drive gear to read as "this is the one you turn".
    @ViewBuilder
    private func crankHint(layout: GearLayout, drive: Double) -> some View {
        let c0 = layout.center(of: 0)
        let r = layout.outerRadius(of: 0) + layout.module * 0.7
        Circle()
            .trim(from: 0, to: 0.16)
            .stroke(Color(red: 1, green: 1, blue: 1).opacity(0.22),
                    style: StrokeStyle(lineWidth: max(1, layout.module * 0.25), lineCap: .round))
            .frame(width: r * 2, height: r * 2)
            .rotationEffect(.radians(drive))
            .position(c0)
    }
}

// MARK: - Layout: derives module + centers from the available size.

private struct GearLayout {
    let size: CGSize
    let module: CGFloat
    private let centers: [CGPoint]

    init(size: CGSize) {
        self.size = size

        // Train extent along X = first gear outer radius + Σ center distances +
        // last gear outer radius. Center distance between meshed gears i,i+1 =
        // (Ni + N(i+1))/2 * module. Bound module by BOTH width and height.
        let teeth = GearTrainConfig.teeth
        var widthUnits: CGFloat = 0
        widthUnits += CGFloat(teeth.first ?? 12) / 2 + GearTrainConfig.addendum    // first outer
        widthUnits += CGFloat(teeth.last ?? 9) / 2 + GearTrainConfig.addendum      // last outer
        for i in 0..<(teeth.count - 1) {
            widthUnits += CGFloat(teeth[i] + teeth[i + 1]) / 2                      // center gaps
        }
        let widthSlack: CGFloat = 2.4
        let moduleByWidth = size.width / (widthUnits + widthSlack)

        // Height bound: tallest gear diameter = (maxN/2 + addendum) * 2 * module.
        let heightUnits = (GearTrainConfig.maxTeeth / 2 + GearTrainConfig.addendum) * 2
        let heightSlack: CGFloat = 1.6
        let moduleByHeight = size.height / (heightUnits + heightSlack)

        self.module = max(0.5, min(moduleByWidth, moduleByHeight))

        // Build centers, colinear along the mid-height line, centered horizontally.
        let m = self.module
        let radii: [CGFloat] = teeth.map { CGFloat($0) / 2 * m }    // pitch radii
        let add = GearTrainConfig.addendum * m
        var xs: [CGFloat] = []
        var cursor: CGFloat = 0
        for i in radii.indices {
            if i == 0 {
                cursor = add + radii[0]
            } else {
                cursor += radii[i - 1] + radii[i]                   // center distance
            }
            xs.append(cursor)
        }
        let trainWidth = (xs.last ?? 0) + (radii.last ?? 0) + add
        let leftPad = (size.width - trainWidth) / 2
        let midY = size.height / 2
        self.centers = xs.map { CGPoint(x: leftPad + $0, y: midY) }
    }

    func center(of index: Int) -> CGPoint {
        guard centers.indices.contains(index) else {
            return CGPoint(x: size.width / 2, y: size.height / 2)
        }
        return centers[index]
    }

    func pitchRadius(of index: Int) -> CGFloat {
        CGFloat(GearTrainConfig.teeth[index]) / 2 * module
    }

    func outerRadius(of index: Int) -> CGFloat {
        pitchRadius(of: index) + GearTrainConfig.addendum * module
    }
}

// MARK: - Gear shape (Path convention: a TOOTH TIP is centered at local angle 0).

private struct Gear: Shape {
    let teeth: Int
    let pitchRadius: CGFloat
    let module: CGFloat

    func path(in rect: CGRect) -> Path {
        let center = CGPoint(x: rect.midX, y: rect.midY)
        let n = max(4, teeth)
        let rPitch = pitchRadius
        let rOuter = rPitch + module * GearTrainConfig.addendum                       // tip radius
        let rRoot = max(module, rPitch - module * GearTrainConfig.addendum * 1.05)     // dedendum

        // Each tooth spans one pitch = 2π/n. Per pitch we draw, in order:
        // [tip-flat | down-flank | root-flat | up-flank], with the TIP centered at
        // the tooth's nominal angle so tooth k=0's tip sits exactly at local angle 0.
        let pitch = (2 * Double.pi) / Double(n)
        let tipHalf = pitch * 0.20      // half-width of the flat tooth tip
        let rootHalf = pitch * 0.20     // half-width of the flat valley

        var path = Path()
        for k in 0..<n {
            let toothCenter = pitch * Double(k)     // tip centered here (k=0 → angle 0)

            let aTipStart = toothCenter - tipHalf
            let aTipEnd = toothCenter + tipHalf
            let aRootStart = toothCenter + tipHalf + (pitch / 2 - tipHalf - rootHalf)
            let aRootEnd = aRootStart + 2 * rootHalf

            let pTipStart = point(center, rOuter, aTipStart)
            if k == 0 {
                path.move(to: pTipStart)
            } else {
                path.addLine(to: pTipStart)         // up-flank from previous valley
            }
            path.addLine(to: point(center, rOuter, aTipEnd))    // tip flat
            path.addLine(to: point(center, rRoot, aRootStart))  // down flank
            path.addLine(to: point(center, rRoot, aRootEnd))    // root flat
            // Up-flank to the next tip start is drawn by the next iteration
            // (or by closeSubpath for the final tooth back to k == 0).
        }
        path.closeSubpath()
        return path
    }

    private func point(_ c: CGPoint, _ r: CGFloat, _ angle: Double) -> CGPoint {
        CGPoint(x: c.x + r * CGFloat(cos(angle)),
                y: c.y + r * CGFloat(sin(angle)))
    }
}

// MARK: - Demo crank script (forward → dwell → reverse → dwell), firing a backlash
// impulse at each reversal. Period ~3.4s. Never blank: gears are always visible.

private enum DemoCrank {
    static let period: Double = 3.4

    struct Phase { let angle: Double; let backlash: Double }

    static func drive(at time: Double) -> Phase {
        let t = time.truncatingRemainder(dividingBy: period)
        let u = t / period                      // 0..1

        let span: Double = 2.6 * .pi            // total forward sweep in radians

        let angle: Double
        let pulse: Double
        if u < 0.40 {
            let p = u / 0.40
            angle = span * easeInOut(p)
            pulse = 0
        } else if u < 0.50 {
            angle = span
            pulse = reversalPulse((u - 0.40) / 0.10)   // top dwell → jiggle in
        } else if u < 0.90 {
            let p = (u - 0.50) / 0.40
            angle = span * (1 - easeInOut(p))
            pulse = 0
        } else {
            angle = 0
            pulse = reversalPulse((u - 0.90) / 0.10)   // bottom dwell → jiggle in
        }

        // Backlash transient expressed in DRIVE units (gearAngle re-scales by ratio).
        let n0 = Double(GearTrainConfig.teeth[0])
        let smallest = Double(GearTrainConfig.teeth.dropFirst().min() ?? 9)
        let cap = (Double.pi / smallest) * 0.26 / (n0 / smallest)
        let dir: Double = (u >= 0.40 && u < 0.50) ? -1 : 1
        let backlash = dir * cap * pulse

        return Phase(angle: angle, backlash: backlash)
    }

    /// A decaying oscillation over a 0..1 window (1 at start, ringing down to 0).
    private static func reversalPulse(_ x: Double) -> Double {
        let clamped = min(max(x, 0), 1)
        let decay = exp(-4.0 * clamped)
        let ring = cos(clamped * 2 * Double.pi * 1.5)
        return decay * ring
    }

    private static func easeInOut(_ x: Double) -> Double {
        let c = min(max(x, 0), 1)
        return c * c * (3 - 2 * c)
    }
}
"""###,
        "ges-rotate-vinyl-scrub": ###"""
import SwiftUI

// MARK: - Vinyl Scrub Platter
// Spin a record platter with a one-finger rotate (atan2) gesture; it keeps
// momentum and slows by friction. Dragging against the spin scrubs it back
// with a pitch-bent scale/opacity/blur wobble of the label art.
// iOS 17. No Metal.

struct RotateVinylScrubView: View {
    var demo: Bool = false

    // Physics state ----------------------------------------------------------
    @State private var angle: Double = 0            // radians, accumulated
    @State private var velocity: Double = 0         // radians / second
    @State private var wobble: Double = 0           // 0...1 transient back-cue
    @State private var lastDate: Date? = nil

    // Gesture tracking -------------------------------------------------------
    @State private var isDragging: Bool = false
    @State private var lastTouchAngle: Double = 0   // radians
    @State private var smoothedDelta: Double = 0    // EMA of per-frame delta
    @State private var lastDragDelta: Double = 0     // last raw drag delta sign

    // Demo scripting ---------------------------------------------------------
    @State private var demoStart: Date? = nil

    // Tuning -----------------------------------------------------------------
    private let decay: Double = 1.15                 // friction (per second, exp)
    private let maxVelocity: Double = 34.0           // clamp flick
    private let tau: Double = 2.0 * .pi

    // Per-revolution tick for haptics (interactive only)
    private var revolutionTick: Int { Int(angle / tau) }

    var body: some View {
        GeometryReader { geo in
            let side = min(geo.size.width, geo.size.height)
            let center = CGPoint(x: geo.size.width / 2, y: geo.size.height / 2)

            TimelineView(.animation) { timeline in
                platter(side: side)
                    .frame(width: geo.size.width, height: geo.size.height)
                    .contentShape(Rectangle())
                    .gesture(scrubGesture(center: center), including: demo ? .none : .all)
                    .onChange(of: timeline.date) { _, now in
                        step(now: now)
                    }
            }
            .frame(maxWidth: .infinity, maxHeight: .infinity)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .modifier(RotateVinylScrubView_RevolutionHaptic(tick: revolutionTick, enabled: !demo))
    }

    // MARK: - Visual

    @ViewBuilder
    private func platter(side: CGFloat) -> some View {
        let discSize = side * 0.86
        let labelSize = discSize * 0.40
        let spindle = discSize * 0.045

        ZStack {
            // Backing / turntable felt glow
            Circle()
                .fill(
                    RadialGradient(
                        colors: [
                            Color(red: 0.10, green: 0.10, blue: 0.13),
                            Color(red: 0.04, green: 0.04, blue: 0.06)
                        ],
                        center: .center,
                        startRadius: 0,
                        endRadius: side * 0.6
                    )
                )
                .frame(width: side, height: side)

            // The rotating disc (grooves + asymmetric label) — everything that
            // visibly moves lives in here under one rotationEffect.
            ZStack {
                vinylBody(size: discSize)
                grooveSheen(size: discSize)
                label(size: labelSize)
            }
            .rotationEffect(.radians(angle))

            // Fixed tonearm-style sheen sweep across the platter so even the
            // grooves catch a moving glint as the disc spins under it.
            staticSheen(size: discSize)
                .allowsHitTesting(false)

            // Spindle (fixed, centered)
            Circle()
                .fill(
                    LinearGradient(
                        colors: [Color(red: 0.85, green: 0.86, blue: 0.90),
                                 Color(red: 0.55, green: 0.56, blue: 0.62)],
                        startPoint: .topLeading, endPoint: .bottomTrailing
                    )
                )
                .frame(width: spindle, height: spindle)
                .shadow(color: .black.opacity(0.4), radius: 1, y: 0.5)
        }
    }

    @ViewBuilder
    private func vinylBody(size: CGFloat) -> some View {
        ZStack {
            Circle()
                .fill(Color(red: 0.07, green: 0.07, blue: 0.09))
            // Concentric grooves
            ForEach(0..<14, id: \.self) { i in
                let t = Double(i) / 13.0
                Circle()
                    .stroke(
                        Color.white.opacity(0.04 + 0.03 * (1 - t)),
                        lineWidth: max(0.5, size * 0.004)
                    )
                    .frame(width: size * (0.46 + 0.52 * t),
                           height: size * (0.46 + 0.52 * t))
            }
            // Asymmetric colored groove sector so rotation is always legible
            grooveSector(size: size)
        }
        .frame(width: size, height: size)
        .clipShape(Circle())
        .shadow(color: .black.opacity(0.55), radius: size * 0.03, y: size * 0.012)
    }

    @ViewBuilder
    private func grooveSector(size: CGFloat) -> some View {
        // A faint warm wedge sweeping a slice of the grooves — an asymmetric
        // mark that makes the spin readable on every frame.
        Path { p in
            let c = CGPoint(x: size / 2, y: size / 2)
            let r = size * 0.49
            p.move(to: c)
            p.addArc(center: c, radius: r,
                     startAngle: .degrees(-14), endAngle: .degrees(14),
                     clockwise: false)
            p.closeSubpath()
        }
        .fill(
            AngularGradient(
                colors: [Color(red: 1.0, green: 0.62, blue: 0.25).opacity(0.0),
                         Color(red: 1.0, green: 0.62, blue: 0.25).opacity(0.22),
                         Color(red: 1.0, green: 0.62, blue: 0.25).opacity(0.0)],
                center: .center
            )
        )
        .blendMode(.screen)
    }

    @ViewBuilder
    private func grooveSheen(size: CGFloat) -> some View {
        // A subtle rotating highlight ring giving the vinyl its plastic gleam.
        Circle()
            .trim(from: 0.0, to: 0.5)
            .stroke(
                LinearGradient(
                    colors: [Color.white.opacity(0.0),
                             Color.white.opacity(0.10),
                             Color.white.opacity(0.0)],
                    startPoint: .leading, endPoint: .trailing
                ),
                lineWidth: size * 0.5
            )
            .frame(width: size * 0.74, height: size * 0.74)
            .blendMode(.screen)
            .opacity(0.5)
    }

    @ViewBuilder
    private func label(size: CGFloat) -> some View {
        // The pitch-bend wobble: opposing the spin transiently squashes,
        // fades and blurs the label art.
        let squash = 1.0 - 0.16 * wobble
        let blurAmt = CGFloat(2.5 * wobble)
        let fade = 1.0 - 0.30 * wobble

        ZStack {
            Circle()
                .fill(
                    AngularGradient(
                        colors: [
                            Color(red: 0.94, green: 0.27, blue: 0.36),
                            Color(red: 0.99, green: 0.55, blue: 0.30),
                            Color(red: 0.96, green: 0.80, blue: 0.32),
                            Color(red: 0.94, green: 0.27, blue: 0.36)
                        ],
                        center: .center
                    )
                )
            // Concentric label rings
            Circle().stroke(Color.black.opacity(0.18), lineWidth: size * 0.02)
                .frame(width: size * 0.78, height: size * 0.78)
            // Asymmetric label mark — a notch + text arc that read the spin.
            labelMark(size: size)
            // Center hole
            Circle()
                .fill(Color(red: 0.05, green: 0.05, blue: 0.07))
                .frame(width: size * 0.16, height: size * 0.16)
        }
        .frame(width: size, height: size)
        .clipShape(Circle())
        .scaleEffect(x: squash, y: 2.0 - squash, anchor: .center)
        .opacity(fade)
        .blur(radius: blurAmt)
        .overlay(
            Circle()
                .stroke(Color.white.opacity(0.10), lineWidth: 1)
        )
    }

    @ViewBuilder
    private func labelMark(size: CGFloat) -> some View {
        ZStack {
            // A bold notch at "12 o'clock" of the label.
            Capsule()
                .fill(Color.white.opacity(0.92))
                .frame(width: size * 0.05, height: size * 0.20)
                .offset(y: -size * 0.26)
            Text("33⅓")
                .font(.system(size: size * 0.13, weight: .heavy, design: .rounded))
                .foregroundStyle(Color.black.opacity(0.55))
                .offset(y: size * 0.24)
        }
    }

    @ViewBuilder
    private func staticSheen(size: CGFloat) -> some View {
        Circle()
            .fill(
                LinearGradient(
                    colors: [Color.white.opacity(0.12),
                             Color.white.opacity(0.0),
                             Color.white.opacity(0.0),
                             Color.white.opacity(0.05)],
                    startPoint: .topLeading, endPoint: .bottomTrailing
                )
            )
            .frame(width: size, height: size)
            .blendMode(.screen)
    }

    // MARK: - Gesture (one-finger atan2 scrub)

    private func scrubGesture(center: CGPoint) -> some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                let touchAngle = atan2(value.location.y - center.y,
                                       value.location.x - center.x)
                if !isDragging {
                    isDragging = true
                    lastTouchAngle = touchAngle
                    smoothedDelta = 0
                    return
                }
                var delta = touchAngle - lastTouchAngle
                // Unwrap across the -pi/pi boundary
                if delta > .pi { delta -= tau }
                if delta < -.pi { delta += tau }

                // Back-cue detection: finger opposes current spin direction.
                if velocity != 0, sign(delta) != sign(velocity), abs(delta) > 0.001 {
                    let intensity = min(1.0, abs(delta) * 6.0)
                    wobble = max(wobble, intensity)
                }

                angle += delta
                lastDragDelta = delta
                // EMA of delta to estimate release velocity smoothly.
                smoothedDelta = smoothedDelta * 0.7 + delta * 0.3
                lastTouchAngle = touchAngle
            }
            .onEnded { _ in
                isDragging = false
                // Convert smoothed per-frame delta into angular velocity.
                // At ~60fps a frame is ~1/60s; scale up to per-second.
                let v = smoothedDelta * 60.0
                velocity = clampVelocity(velocity * 0.2 + v)
            }
    }

    // MARK: - Physics integrator (runs every frame for demo & interactive)

    private func step(now: Date) {
        guard let last = lastDate else {
            lastDate = now
            if demo { demoStart = now }
            return
        }
        var dt = now.timeIntervalSince(last)
        lastDate = now
        if dt <= 0 { return }
        dt = min(dt, 1.0 / 20.0) // guard against long stalls

        if demo {
            driveDemo(now: now, dt: dt)
        }

        if !isDragging {
            // Framerate-independent friction.
            velocity *= exp(-decay * dt)
            if abs(velocity) < 0.02 { velocity = 0 }
            angle += velocity * dt
        }

        // Wobble eases out on its own.
        if wobble > 0 {
            wobble = max(0, wobble - dt * 2.2)
        }
    }

    // MARK: - Demo loop (scripted impulses on a ~3.2s cycle)

    private func driveDemo(now: Date, dt: Double) {
        guard let start = demoStart else { demoStart = now; return }
        let period = 3.2
        let t = now.timeIntervalSince(start).truncatingRemainder(dividingBy: period)

        switch t {
        case 0.0..<0.10:
            // Kick: spin up forward.
            velocity = 16.0
        case 1.85..<1.95:
            // Back-cue nudge: shove against the spin, trip the wobble.
            velocity = -7.0
            wobble = 1.0
        case 2.55..<2.62:
            // Tiny forward re-nudge so it never sits dead-still.
            if abs(velocity) < 0.5 { velocity = 3.0 }
        default:
            break
        }
        // Even at rest, keep a faint idle drift so the tile is never frozen.
        if abs(velocity) < 0.15 {
            velocity = 0.6
        }
    }

    // MARK: - Helpers

    private func clampVelocity(_ v: Double) -> Double {
        max(-maxVelocity, min(maxVelocity, v))
    }

    private func sign(_ x: Double) -> Double {
        x > 0 ? 1 : (x < 0 ? -1 : 0)
    }
}

// MARK: - Per-revolution haptic (interactive only)

private struct RotateVinylScrubView_RevolutionHaptic: ViewModifier {
    let tick: Int
    let enabled: Bool

    func body(content: Content) -> some View {
        if enabled {
            content.sensoryFeedback(.selection, trigger: tick)
        } else {
            content
        }
    }
}
"""###,
        "ges-rubberband-sheet-morph": ###"""
//
//  RubberBandSheetMorphView.swift
//  InspireCreativityApp — Bespoke catalog animation
//
//  Rubber-Band Sheet Morph: a bottom sheet you drag upward stretches past its
//  rest height with rubber-band resistance, and its contents re-flow from a
//  compact summary row into a multi-column grid as it rises, snapping back with
//  an overshoot spring.
//
//  Self-contained: SwiftUI only, no app dependencies (paste-and-run).
//  `demo == true`  → self-driving loop (grid tile, no finger).
//  `demo == false` → real DragGesture (Detail view + the buyer's code).
//

import SwiftUI

struct RubberBandSheetMorphView: View {
    /// Drives the self-playing demo loop in non-interactive grid tiles.
    var demo: Bool = false

    var body: some View {
        if demo {
            TimelineView(.animation) { ctx in
                SheetMorphStage(progress: Self.loopProgress(ctx.date))
            }
        } else {
            InteractiveSheetMorph()
        }
    }

    /// Eased 0→1→0 triangle wave on a ~3.6s period for the demo loop.
    static func loopProgress(_ date: Date) -> CGFloat {
        let period = 3.6
        let t = date.timeIntervalSinceReferenceDate.truncatingRemainder(dividingBy: period) / period
        let triangle = t < 0.5 ? t * 2 : (1 - t) * 2
        let eased = triangle * triangle * (3 - 2 * triangle) // smoothstep
        return CGFloat(eased)
    }
}

// MARK: - Interactive variant (real drag)

private struct InteractiveSheetMorph: View {
    @State private var progress: CGFloat = 0      // 0 collapsed … 1 expanded
    @GestureState private var dragProgress: CGFloat = 0

    var body: some View {
        GeometryReader { geo in
            let live = clampRubber(progress + dragProgress)
            SheetMorphStage(progress: live)
                .contentShape(Rectangle())
                .gesture(
                    DragGesture(minimumDistance: 0)
                        .updating($dragProgress) { value, state, _ in
                            // Upward drag (negative y) increases progress.
                            state = -value.translation.height / max(120, geo.size.height * 0.6)
                        }
                        .onEnded { value in
                            let predicted = progress - value.predictedEndTranslation.height
                                / max(120, geo.size.height * 0.6)
                            withAnimation(.snappy(duration: 0.45, extraBounce: 0.2)) {
                                progress = predicted > 0.5 ? 1 : 0
                            }
                        }
                )
        }
    }

    /// Asymptotic rubber-band clamp so it can stretch a little past 0…1.
    private func clampRubber(_ p: CGFloat) -> CGFloat {
        if p < 0 { return -0.06 * (1 - 1 / (-p * 6 + 1)) }
        if p > 1 { return 1 + 0.06 * (1 - 1 / ((p - 1) * 6 + 1)) }
        return p
    }
}

// MARK: - Shared visual (used by both demo loop and interactive)

private struct SheetMorphStage: View {
    /// May slightly exceed 0…1 for the rubber-band overshoot.
    let progress: CGFloat

    var body: some View {
        GeometryReader { geo in
            let p = min(max(progress, 0), 1)
            let minH: CGFloat = 56
            let maxH = max(minH + 40, geo.size.height * 0.92)
            let overshoot = max(0, progress - 1) * 60
            let height = minH + (maxH - minH) * p + overshoot

            ZStack {
                backdrop(p: p)
                VStack {
                    Spacer(minLength: 0)
                    sheet(width: geo.size.width, height: height, p: p)
                }
            }
            .frame(maxWidth: .infinity, maxHeight: .infinity)
        }
    }

    private func backdrop(p: CGFloat) -> some View {
        LinearGradient(
            colors: [Color(red: 0.10, green: 0.11, blue: 0.18),
                     Color(red: 0.05, green: 0.06, blue: 0.10)],
            startPoint: .top, endPoint: .bottom
        )
        .overlay(Color.black.opacity(0.35 * p)) // dim as the sheet rises
    }

    private func sheet(width: CGFloat, height: CGFloat, p: CGFloat) -> some View {
        VStack(spacing: 10) {
            Capsule()
                .fill(.white.opacity(0.35))
                .frame(width: 36, height: 5)
                .padding(.top, 8)

            ZStack {
                compactRow.opacity(Double(1 - min(p * 1.6, 1)))
                expandedGrid.opacity(Double(max(0, p * 1.6 - 0.6)))
            }
            .padding(.horizontal, 14)
            Spacer(minLength: 0)
        }
        .frame(width: width, height: height, alignment: .top)
        .background(
            RoundedRectangle(cornerRadius: 22, style: .continuous)
                .fill(Color(red: 0.13, green: 0.14, blue: 0.22))
        )
        .overlay(
            RoundedRectangle(cornerRadius: 22, style: .continuous)
                .strokeBorder(.white.opacity(0.10), lineWidth: 0.5)
        )
        .shadow(color: .black.opacity(0.4), radius: 16, y: -4)
    }

    private var compactRow: some View {
        HStack(spacing: 10) {
            RoundedRectangle(cornerRadius: 8).fill(.cyan.opacity(0.85))
                .frame(width: 34, height: 34)
            VStack(alignment: .leading, spacing: 3) {
                Capsule().fill(.white.opacity(0.8)).frame(width: 90, height: 8)
                Capsule().fill(.white.opacity(0.4)).frame(width: 56, height: 6)
            }
            Spacer()
            Image(systemName: "chevron.up").font(.system(size: 12, weight: .bold))
                .foregroundStyle(.white.opacity(0.6))
        }
    }

    private var expandedGrid: some View {
        let cols = [GridItem(.flexible(), spacing: 8), GridItem(.flexible(), spacing: 8)]
        return LazyVGrid(columns: cols, spacing: 8) {
            ForEach(0..<4, id: \.self) { i in
                RoundedRectangle(cornerRadius: 10, style: .continuous)
                    .fill([Color.cyan, .purple, .pink, .orange][i].opacity(0.8))
                    .frame(height: 34)
                    .overlay(
                        Image(systemName: ["star.fill", "bolt.fill", "heart.fill", "leaf.fill"][i])
                            .font(.system(size: 13, weight: .bold))
                            .foregroundStyle(.white)
                    )
            }
        }
    }
}
"""###,
        "ges-swipe-curtain-part": ###"""
import SwiftUI

// MARK: - SwipeCurtainPartView
// Swipe outward and two heavy fabric curtains part with rippling folds and
// weighted drag, gathering at the edges with bunched pleats to reveal a lit
// content stage. The inner edges ripple with a sine fold; the pleats compress
// and gain contrast as the cloth gathers. demo == true self-drives a theatrical
// open/close loop; demo == false is an interactive DragGesture.
struct SwipeCurtainPartView: View {
    var demo: Bool = false

    // Interactive state: 0 = fully closed, 1 = fully parted.
    @State private var progress: CGFloat = 0
    @State private var dragStartProgress: CGFloat = 0

    var body: some View {
        GeometryReader { geo in
            let size = geo.size
            if demo {
                demoBody(size: size)
            } else {
                interactiveBody(size: size)
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // MARK: Demo (self-driving)

    private func demoBody(size: CGSize) -> some View {
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            let p = Self.loopProgress(time: t)
            // A gentle phase used to ripple the folds while parting, so the
            // cloth looks alive even when fully open or closed.
            let phase = CGFloat((t.truncatingRemainder(dividingBy: 3.4)) / 3.4)
            stageScene(size: size, progress: p, foldPhase: phase)
        }
    }

    /// Eased ping-pong 0 -> 1 -> 0 on a ~3.4s loop with smooth ends.
    static func loopProgress(time: TimeInterval) -> CGFloat {
        let period: TimeInterval = 3.4
        let x = time.truncatingRemainder(dividingBy: period) / period // 0..1
        // Triangle wave 0..1..0
        let tri = x < 0.5 ? (x / 0.5) : (1 - (x - 0.5) / 0.5)
        // Smoothstep for eased ends.
        let e = tri * tri * (3 - 2 * tri)
        return CGFloat(e)
    }

    // MARK: Interactive

    private func interactiveBody(size: CGSize) -> some View {
        stageScene(size: size, progress: progress, foldPhase: 0.18)
            .contentShape(Rectangle())
            .gesture(dragGesture(width: size.width))
    }

    private func dragGesture(width: CGFloat) -> some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                let half = max(width * 0.5, 1)
                // Map outward swipe distance to part-progress. Either direction
                // of horizontal travel opens the curtains.
                let delta = abs(value.translation.width) / half
                let raw = dragStartProgress + delta * 0.85
                progress = min(max(raw, 0), 1)
            }
            .onEnded { _ in
                let target: CGFloat = progress > 0.5 ? 1 : 0
                // Heavier damping conveys cloth weight.
                withAnimation(.spring(duration: 0.6, bounce: 0.15)) {
                    progress = target
                }
                dragStartProgress = target
            }
    }

    // MARK: Scene composition

    private func stageScene(size: CGSize, progress p: CGFloat, foldPhase: CGFloat) -> some View {
        ZStack {
            SwipeCurtainPartView_StageBackdrop(progress: p)
            SwipeCurtainPartView_CurtainPanel(progress: p, foldPhase: foldPhase, side: .left)
            SwipeCurtainPartView_CurtainPanel(progress: p, foldPhase: foldPhase, side: .right)
            SwipeCurtainPartView_ValanceTrim()
        }
        .clipShape(RoundedRectangle(cornerRadius: cornerRadius(for: size), style: .continuous))
    }

    private func cornerRadius(for size: CGSize) -> CGFloat {
        min(size.width, size.height) * 0.10
    }
}

// MARK: - Curtain side

private enum SwipeCurtainPartView_CurtainSide {
    case left, right
}

// MARK: - Animatable curtain shape

/// One half of the stage curtain. Its outer edge is pinned at the wall; its
/// inner edge travels toward the wall as `progress` -> 1, and the inner edge
/// ripples with a sine fold whose amplitude grows as the cloth gathers.
private struct SwipeCurtainPartView_CurtainShape: Shape {
    var progress: CGFloat   // 0 closed, 1 parted
    var foldPhase: CGFloat  // animates the ripple
    var side: SwipeCurtainPartView_CurtainSide

    var animatableData: AnimatablePair<CGFloat, CGFloat> {
        get { AnimatablePair(progress, foldPhase) }
        set {
            progress = newValue.first
            foldPhase = newValue.second
        }
    }

    func path(in rect: CGRect) -> Path {
        let w = rect.width
        let h = rect.height
        let half = w * 0.5

        // Gathered (bunched) width never collapses to zero — keep a heavy strip.
        let bunchWidth = max(w * 0.16, 22)
        let visibleWidth = bunchWidth + (half - bunchWidth) * (1 - progress)

        // Ripple amplitude grows as it gathers; folds deepen near the edge.
        let amp = (w * 0.012) + (w * 0.05) * progress
        let waves: CGFloat = 3.2

        var path = Path()
        let steps = 26

        switch side {
        case .left:
            // Outer edge pinned at x = 0; inner edge near x = visibleWidth.
            let innerBase = visibleWidth
            path.move(to: CGPoint(x: 0, y: 0))
            path.addLine(to: CGPoint(x: innerBase, y: 0))
            for i in 0...steps {
                let frac = CGFloat(i) / CGFloat(steps)
                let y = frac * h
                let wobble = sin(frac * .pi * waves + foldPhase * .pi * 2)
                let x = innerBase + wobble * amp
                path.addLine(to: CGPoint(x: x, y: y))
            }
            path.addLine(to: CGPoint(x: 0, y: h))
            path.closeSubpath()

        case .right:
            let innerBase = w - visibleWidth
            path.move(to: CGPoint(x: w, y: 0))
            path.addLine(to: CGPoint(x: innerBase, y: 0))
            for i in 0...steps {
                let frac = CGFloat(i) / CGFloat(steps)
                let y = frac * h
                let wobble = sin(frac * .pi * waves + foldPhase * .pi * 2)
                let x = innerBase - wobble * amp
                path.addLine(to: CGPoint(x: x, y: y))
            }
            path.addLine(to: CGPoint(x: w, y: h))
            path.closeSubpath()
        }
        return path
    }
}

// MARK: - Curtain panel (fabric + pleats)

private struct SwipeCurtainPartView_CurtainPanel: View {
    var progress: CGFloat
    var foldPhase: CGFloat
    var side: SwipeCurtainPartView_CurtainSide

    var body: some View {
        GeometryReader { geo in
            let size = geo.size
            SwipeCurtainPartView_CurtainShape(progress: progress, foldPhase: foldPhase, side: side)
                .fill(baseGradient)
                .overlay {
                    SwipeCurtainPartView_PleatOverlay(progress: progress, side: side)
                        .clipShape(SwipeCurtainPartView_CurtainShape(progress: progress, foldPhase: foldPhase, side: side))
                }
                .overlay {
                    // Soft inner-edge shadow that deepens as cloth gathers.
                    SwipeCurtainPartView_CurtainShape(progress: progress, foldPhase: foldPhase, side: side)
                        .fill(edgeShade(width: size.width))
                }
                .shadow(color: .black.opacity(0.45), radius: 8, x: shadowX, y: 4)
        }
        .allowsHitTesting(false)
    }

    private var shadowX: CGFloat {
        let mag: CGFloat = 6
        return side == .left ? mag : -mag
    }

    // Deep theatrical red velvet.
    private var baseGradient: LinearGradient {
        let dark = Color(red: 0.32, green: 0.04, blue: 0.07)
        let mid = Color(red: 0.58, green: 0.09, blue: 0.13)
        let bright = Color(red: 0.72, green: 0.13, blue: 0.18)
        let stops: [Gradient.Stop]
        switch side {
        case .left:
            stops = [
                .init(color: dark, location: 0.0),
                .init(color: mid, location: 0.55),
                .init(color: bright, location: 1.0)
            ]
        case .right:
            stops = [
                .init(color: bright, location: 0.0),
                .init(color: mid, location: 0.45),
                .init(color: dark, location: 1.0)
            ]
        }
        return LinearGradient(stops: stops, startPoint: .leading, endPoint: .trailing)
    }

    private func edgeShade(width: CGFloat) -> LinearGradient {
        let intensity = 0.20 + 0.35 * Double(progress)
        let shadow = Color.black.opacity(intensity)
        let clear = Color.black.opacity(0)
        switch side {
        case .left:
            return LinearGradient(
                stops: [
                    .init(color: clear, location: 0.55),
                    .init(color: shadow, location: 1.0)
                ],
                startPoint: .leading, endPoint: .trailing
            )
        case .right:
            return LinearGradient(
                stops: [
                    .init(color: shadow, location: 0.0),
                    .init(color: clear, location: 0.45)
                ],
                startPoint: .leading, endPoint: .trailing
            )
        }
    }
}

// MARK: - Pleat overlay
// Vertical light/shadow stripes that read as cloth folds. They compress
// horizontally and gain contrast as the curtain gathers (progress -> 1).
private struct SwipeCurtainPartView_PleatOverlay: View {
    var progress: CGFloat
    var side: SwipeCurtainPartView_CurtainSide

    private let pleatCount = 9

    var body: some View {
        Canvas { context, size in
            draw(into: &context, size: size)
        }
    }

    private func draw(into context: inout GraphicsContext, size: CGSize) {
        let w = size.width
        let h = size.height
        // As progress grows the pleats crowd toward the gathering edge.
        let compression = 1 - 0.62 * progress
        let usable = w * compression
        // Anchor the pleat field at the gathering edge: the left curtain
        // gathers at the left wall (x = 0), the right curtain at the right wall.
        let originX: CGFloat = side == .left ? 0 : (w - usable)

        let contrast = 0.18 + 0.42 * progress
        let bandWidth = usable / CGFloat(pleatCount)
        guard bandWidth > 0 else { return }

        for i in 0..<pleatCount {
            let x0 = originX + CGFloat(i) * bandWidth
            let phaseShade = sin(CGFloat(i) / CGFloat(pleatCount) * .pi * 2)
            // Alternate highlight/shadow per band for fold relief.
            let isHighlight = (i % 2 == 0)
            let baseOpacity = contrast * (0.6 + 0.4 * abs(phaseShade))
            let stripe = Path(CGRect(x: x0, y: 0, width: bandWidth, height: h))
            if isHighlight {
                context.fill(stripe, with: .color(.white.opacity(baseOpacity * 0.5)))
            } else {
                context.fill(stripe, with: .color(.black.opacity(baseOpacity)))
            }
            // Thin crease line at each band boundary.
            var crease = Path()
            crease.move(to: CGPoint(x: x0, y: 0))
            crease.addLine(to: CGPoint(x: x0, y: h))
            context.stroke(crease, with: .color(.black.opacity(0.18 + 0.2 * progress)), lineWidth: 0.75)
        }
    }
}

// MARK: - Stage backdrop (the revealed content)

private struct SwipeCurtainPartView_StageBackdrop: View {
    var progress: CGFloat

    var body: some View {
        GeometryReader { geo in
            let size = geo.size
            ZStack {
                // Dark stage floor + warm rear wall.
                LinearGradient(
                    colors: [
                        Color(red: 0.05, green: 0.04, blue: 0.09),
                        Color(red: 0.12, green: 0.09, blue: 0.16)
                    ],
                    startPoint: .top, endPoint: .bottom
                )

                // Warm spotlight that brightens as the curtains part.
                RadialGradient(
                    colors: [
                        Color(red: 1.0, green: 0.86, blue: 0.55).opacity(0.85 * Double(progress) + 0.08),
                        Color(red: 1.0, green: 0.78, blue: 0.40).opacity(0.0)
                    ],
                    center: .init(x: 0.5, y: 0.42),
                    startRadius: 2,
                    endRadius: max(size.width, size.height) * 0.62
                )

                spotlightStar(size: size)
            }
        }
    }

    // A glowing star at center stage — legible "content" being revealed.
    private func spotlightStar(size: CGSize) -> some View {
        let s = min(size.width, size.height)
        let scale = 0.55 + 0.45 * progress
        return SwipeCurtainPartView_Star(points: 5, inset: 0.45)
            .fill(
                RadialGradient(
                    colors: [
                        Color(red: 1.0, green: 0.95, blue: 0.7),
                        Color(red: 1.0, green: 0.78, blue: 0.32)
                    ],
                    center: .center, startRadius: 1, endRadius: s * 0.22
                )
            )
            .frame(width: s * 0.34, height: s * 0.34)
            .scaleEffect(scale)
            .shadow(color: Color(red: 1.0, green: 0.8, blue: 0.4).opacity(0.7 * Double(progress)),
                    radius: 14 * progress)
            .opacity(0.25 + 0.75 * Double(progress))
            .position(x: size.width * 0.5, y: size.height * 0.46)
    }
}

// MARK: - Valance (top fabric trim)

private struct SwipeCurtainPartView_ValanceTrim: View {
    var body: some View {
        GeometryReader { geo in
            let size = geo.size
            let h = size.height * 0.16
            ZStack(alignment: .top) {
                SwipeCurtainPartView_Scallop(scallops: 6)
                    .fill(
                        LinearGradient(
                            colors: [
                                Color(red: 0.5, green: 0.07, blue: 0.11),
                                Color(red: 0.34, green: 0.04, blue: 0.07)
                            ],
                            startPoint: .top, endPoint: .bottom
                        )
                    )
                    .frame(height: h)
                    .shadow(color: .black.opacity(0.4), radius: 5, y: 3)
            }
            .frame(width: size.width, height: size.height, alignment: .top)
        }
        .allowsHitTesting(false)
    }
}

private struct SwipeCurtainPartView_Scallop: Shape {
    var scallops: Int

    func path(in rect: CGRect) -> Path {
        var path = Path()
        let w = rect.width
        let h = rect.height
        path.move(to: CGPoint(x: 0, y: 0))
        path.addLine(to: CGPoint(x: w, y: 0))
        path.addLine(to: CGPoint(x: w, y: h * 0.4))
        let bumpWidth = w / CGFloat(scallops)
        var x = w
        for i in 0..<scallops {
            let nextX = w - CGFloat(i + 1) * bumpWidth
            let midX = (x + nextX) / 2
            path.addQuadCurve(
                to: CGPoint(x: nextX, y: h * 0.4),
                control: CGPoint(x: midX, y: h)
            )
            x = nextX
        }
        path.addLine(to: CGPoint(x: 0, y: 0))
        path.closeSubpath()
        return path
    }
}

// MARK: - SwipeCurtainPartView_Star shape

private struct SwipeCurtainPartView_Star: Shape {
    var points: Int
    var inset: CGFloat // 0..1 inner radius ratio

    func path(in rect: CGRect) -> Path {
        var path = Path()
        let center = CGPoint(x: rect.midX, y: rect.midY)
        let outer = min(rect.width, rect.height) / 2
        let inner = outer * inset
        let total = points * 2
        for i in 0..<total {
            let isOuter = (i % 2 == 0)
            let r = isOuter ? outer : inner
            let angle = (CGFloat(i) / CGFloat(total)) * .pi * 2 - .pi / 2
            let pt = CGPoint(x: center.x + cos(angle) * r,
                             y: center.y + sin(angle) * r)
            if i == 0 { path.move(to: pt) } else { path.addLine(to: pt) }
        }
        path.closeSubpath()
        return path
    }
}
"""###,
        "ges-swipe-domino-cascade": ###"""
import SwiftUI

// MARK: - Domino Swipe Cascade
// Swipe across a row of standing tiles and they topple in sequence, each
// knocking the next with a slight delay and angular fall; the last one fires
// the action. A single `progress` value (the topple-front position) drives
// both the self-running demo loop and the live drag interaction.

struct SwipeDominoCascadeView: View {
    var demo: Bool = false

    // Live interactive state
    @State private var dragProgress: Double = 0
    @State private var isDragging: Bool = false
    @State private var fallenCount: Int = 0
    @State private var didComplete: Bool = false

    private let tileCount: Int = 6

    var body: some View {
        GeometryReader { geo in
            content(in: geo.size)
                .frame(maxWidth: .infinity, maxHeight: .infinity)
        }
        // Haptics only in the live (non-demo) component.
        .modifier(
            SwipeDominoCascadeView_DominoHaptics(
                enabled: !demo,
                fallenCount: fallenCount,
                didComplete: didComplete
            )
        )
    }

    // MARK: Content

    @ViewBuilder
    private func content(in size: CGSize) -> some View {
        if demo {
            TimelineView(.animation) { timeline in
                let p = demoProgress(at: timeline.date)
                row(progress: p, in: size, completed: p > 0.96)
            }
        } else {
            row(progress: dragProgress, in: size, completed: didComplete)
                .contentShape(Rectangle())
                .gesture(dragGesture(in: size))
        }
    }

    // MARK: Row of tiles

    private func row(progress: Double, in size: CGSize, completed: Bool) -> some View {
        let layout = SwipeDominoCascadeView_DominoLayout(size: size, count: tileCount)
        return ZStack {
            backdrop(in: size)
            floor(in: size, layout: layout)

            ForEach(0..<tileCount, id: \.self) { index in
                let a = angle(index: index, progress: progress)
                SwipeDominoCascadeView_DominoTile(
                    isLast: index == tileCount - 1,
                    triggered: completed && index == tileCount - 1,
                    width: layout.tileWidth,
                    height: layout.tileHeight
                )
                .rotation3DEffect(
                    .degrees(a),
                    axis: (x: 1, y: 0, z: 0),
                    anchor: .bottom,
                    perspective: 0.42
                )
                .frame(width: layout.tileWidth, height: layout.tileHeight, alignment: .bottom)
                .position(
                    x: layout.x(for: index),
                    y: layout.baselineY - layout.tileHeight / 2
                )
            }

            rewardBurst(in: size, layout: layout, show: completed)
        }
        .compositingGroup()
    }

    // MARK: Backdrop

    private func backdrop(in size: CGSize) -> some View {
        let dim = min(size.width, size.height)
        return RoundedRectangle(cornerRadius: dim * 0.10, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.07, green: 0.08, blue: 0.13),
                        Color(red: 0.04, green: 0.05, blue: 0.09)
                    ],
                    startPoint: .top,
                    endPoint: .bottom
                )
            )
    }

    // MARK: Floor / baseline (always visible so a frame is never blank)

    private func floor(in size: CGSize, layout: SwipeDominoCascadeView_DominoLayout) -> some View {
        let y = layout.baselineY + layout.tileHeight * 0.02
        return Path { path in
            path.move(to: CGPoint(x: layout.leftInset, y: y))
            path.addLine(to: CGPoint(x: size.width - layout.leftInset, y: y))
        }
        .stroke(
            LinearGradient(
                colors: [
                    Color(red: 0.20, green: 0.22, blue: 0.30).opacity(0.0),
                    Color(red: 0.36, green: 0.40, blue: 0.52).opacity(0.9),
                    Color(red: 0.20, green: 0.22, blue: 0.30).opacity(0.0)
                ],
                startPoint: .leading,
                endPoint: .trailing
            ),
            style: StrokeStyle(lineWidth: max(1.0, layout.tileWidth * 0.06), lineCap: .round)
        )
    }

    // MARK: Reward burst on the last tile

    @ViewBuilder
    private func rewardBurst(in size: CGSize, layout: SwipeDominoCascadeView_DominoLayout, show: Bool) -> some View {
        let cx = layout.x(for: tileCount - 1)
        let cy = layout.baselineY - layout.tileHeight * 0.18
        let r = layout.tileWidth * 1.9

        ZStack {
            Circle()
                .fill(
                    RadialGradient(
                        colors: [
                            Color(red: 0.35, green: 0.95, blue: 0.62).opacity(0.55),
                            Color(red: 0.35, green: 0.95, blue: 0.62).opacity(0.0)
                        ],
                        center: .center,
                        startRadius: 0,
                        endRadius: r
                    )
                )
                .frame(width: r * 2, height: r * 2)
                .scaleEffect(show ? 1.0 : 0.2)
                .opacity(show ? 1.0 : 0.0)

            Image(systemName: "checkmark.circle.fill")
                .font(.system(size: layout.tileWidth * 1.05, weight: .bold))
                .foregroundStyle(Color(red: 0.40, green: 0.98, blue: 0.66))
                .shadow(color: Color(red: 0.20, green: 0.80, blue: 0.50).opacity(0.8), radius: 6)
                .scaleEffect(show ? 1.0 : 0.4)
                .opacity(show ? 1.0 : 0.0)
        }
        .position(x: cx, y: cy)
        .animation(.spring(duration: 0.45, bounce: 0.55), value: show)
        .allowsHitTesting(false)
    }

    // MARK: Cascade angle — continuous function of (index, progress)

    /// Each tile begins to fall as the topple-front passes its position, with a
    /// spatial stagger that *is* the per-index delay and the propagating wave.
    private func angle(index: Int, progress: Double) -> Double {
        let maxAngle: Double = 80.0           // capped < 90 to avoid the invisible sliver
        let window: Double = 0.26             // how long a single tile takes to fall
        let span: Double = 0.74               // fraction of progress the front travels over tiles
        let start = (Double(index) / Double(max(1, tileCount - 1))) * span
        let local = (progress - start) / window
        return maxAngle * smoothstep(local)
    }

    private func smoothstep(_ x: Double) -> Double {
        let t = min(1.0, max(0.0, x))
        return t * t * (3.0 - 2.0 * t)
    }

    // MARK: Demo loop — triangle wave 0 -> 1 -> 0 (cascade falls then stands)

    private func demoProgress(at date: Date) -> Double {
        let period: Double = 3.4
        let t = date.timeIntervalSinceReferenceDate.truncatingRemainder(dividingBy: period) / period
        // Hold a beat at the top so the completed reward is readable.
        let up = 0.46, hold = 0.16
        if t < up {
            return easeInOut(t / up)
        } else if t < up + hold {
            return 1.0
        } else {
            let d = (t - up - hold) / (1.0 - up - hold)
            return 1.0 - easeInOut(d)
        }
    }

    private func easeInOut(_ x: Double) -> Double {
        let t = min(1.0, max(0.0, x))
        return t * t * (3.0 - 2.0 * t)
    }

    // MARK: Live drag — location.x is the topple-front

    private func dragGesture(in size: CGSize) -> some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                isDragging = true
                let layout = SwipeDominoCascadeView_DominoLayout(size: size, count: tileCount)
                let raw = (value.location.x - layout.leftInset)
                    / max(1.0, layout.usableWidth)
                let p = min(1.0, max(0.0, raw))
                dragProgress = p
                updateDerivedState(progress: p)
            }
            .onEnded { _ in
                isDragging = false
                if dragProgress > 0.9 {
                    // Settle fully toppled, show reward, then reset to standing.
                    withAnimation(.spring(duration: 0.4, bounce: 0.2)) {
                        dragProgress = 1.0
                        didComplete = true
                        fallenCount = tileCount
                    }
                    DispatchQueue.main.asyncAfter(deadline: .now() + 1.1) {
                        guard !isDragging else { return }
                        withAnimation(.spring(duration: 0.6, bounce: 0.3)) {
                            dragProgress = 0
                        }
                        didComplete = false
                        fallenCount = 0
                    }
                } else {
                    withAnimation(.spring(duration: 0.55, bounce: 0.35)) {
                        dragProgress = 0
                    }
                    didComplete = false
                    fallenCount = 0
                }
            }
    }

    /// Count how many tiles have visibly fallen, to drive per-topple haptics.
    private func updateDerivedState(progress: Double) {
        var count = 0
        for i in 0..<tileCount where angle(index: i, progress: progress) > 60.0 {
            count += 1
        }
        if count != fallenCount {
            fallenCount = count
        }
        let complete = progress > 0.96
        if complete != didComplete {
            didComplete = complete
        }
    }
}

// MARK: - Layout helper

private struct SwipeDominoCascadeView_DominoLayout {
    let size: CGSize
    let count: Int

    var minDim: CGFloat { min(size.width, size.height) }
    var leftInset: CGFloat { size.width * 0.10 }
    var usableWidth: CGFloat { size.width - leftInset * 2 }
    var tileWidth: CGFloat { max(6.0, usableWidth / (CGFloat(count) * 1.7)) }
    var tileHeight: CGFloat { tileWidth * 2.6 }
    var baselineY: CGFloat { size.height * 0.66 }

    func x(for index: Int) -> CGFloat {
        let denom = CGFloat(max(1, count - 1))
        return leftInset + usableWidth * (CGFloat(index) / denom)
    }
}

// MARK: - A single domino tile

private struct SwipeDominoCascadeView_DominoTile: View {
    let isLast: Bool
    let triggered: Bool
    let width: CGFloat
    let height: CGFloat

    var body: some View {
        ZStack {
            RoundedRectangle(cornerRadius: width * 0.18, style: .continuous)
                .fill(faceGradient)
                .overlay(
                    RoundedRectangle(cornerRadius: width * 0.18, style: .continuous)
                        .stroke(
                            LinearGradient(
                                colors: [
                                    Color.white.opacity(0.35),
                                    Color.black.opacity(0.25)
                                ],
                                startPoint: .topLeading,
                                endPoint: .bottomTrailing
                            ),
                            lineWidth: max(0.75, width * 0.04)
                        )
                )
                .shadow(color: Color.black.opacity(0.45), radius: width * 0.18, x: 0, y: width * 0.12)

            pips
        }
        .frame(width: width, height: height)
    }

    private var faceGradient: LinearGradient {
        if isLast {
            return LinearGradient(
                colors: triggered
                    ? [Color(red: 0.35, green: 0.95, blue: 0.62),
                       Color(red: 0.20, green: 0.72, blue: 0.46)]
                    : [Color(red: 0.98, green: 0.78, blue: 0.36),
                       Color(red: 0.86, green: 0.55, blue: 0.20)],
                startPoint: .top,
                endPoint: .bottom
            )
        }
        return LinearGradient(
            colors: [
                Color(red: 0.93, green: 0.94, blue: 0.98),
                Color(red: 0.72, green: 0.76, blue: 0.86)
            ],
            startPoint: .top,
            endPoint: .bottom
        )
    }

    // A center divider line plus a couple of pips so each tile reads as a domino.
    private var pips: some View {
        VStack(spacing: height * 0.10) {
            pip
            Rectangle()
                .fill(Color.black.opacity(0.18))
                .frame(width: width * 0.6, height: max(1.0, height * 0.02))
            pip
        }
    }

    private var pip: some View {
        Circle()
            .fill(
                isLast
                    ? Color.black.opacity(0.28)
                    : Color(red: 0.30, green: 0.34, blue: 0.46).opacity(0.85)
            )
            .frame(width: width * 0.22, height: width * 0.22)
    }
}

// MARK: - Haptics modifier (live mode only)

private struct SwipeDominoCascadeView_DominoHaptics: ViewModifier {
    let enabled: Bool
    let fallenCount: Int
    let didComplete: Bool

    func body(content: Content) -> some View {
        if enabled {
            content
                .sensoryFeedback(.impact(weight: .light), trigger: fallenCount)
                .sensoryFeedback(.success, trigger: didComplete) { _, now in now }
        } else {
            content
        }
    }
}
"""###,
        "ges-swipe-elastic-reveal": ###"""
import SwiftUI

/// Elastic Action Reveal
///
/// Swiping a list row left stretches a single trailing action button that
/// elongates elastically with diminishing-return resistance. Past a threshold
/// it pops into a wide pill that springs to full width and auto-fires with a
/// haptic confirmation.
///
/// - `demo == true`  → a self-driving PhaseAnimator loop cycles
///   rest → stretch → commit → rest so the tile is always alive (and never blank).
/// - `demo == false` → a real DragGesture(minimumDistance: 0) drives the pill
///   width via a rubber-band curve; past threshold it springs full + fires.
struct SwipeElasticRevealView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { geo in
            content(in: geo.size)
                .frame(maxWidth: .infinity, maxHeight: .infinity)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    @ViewBuilder
    private func content(in size: CGSize) -> some View {
        if demo {
            SwipeElasticRevealView_DemoReveal(size: size)
        } else {
            SwipeElasticRevealView_InteractiveReveal(size: size)
        }
    }
}

// MARK: - Shared geometry helpers

private enum SwipeElasticRevealView_RevealMath {
    /// Trailing inset so the row never bleeds into the tile edge.
    static func inset(for size: CGSize) -> CGFloat {
        max(8, min(size.width, size.height) * 0.07)
    }

    /// Resting width of the action pill (a tidy circle-ish nub).
    static func restWidth(for size: CGSize) -> CGFloat {
        max(34, min(size.width, size.height) * 0.30)
    }

    /// Width past which a release commits and fires.
    static func threshold(for size: CGSize) -> CGFloat {
        max(restWidth(for: size) + 18, size.width * 0.46)
    }

    /// Fully-committed width — spans the row, leaving the trailing inset.
    static func fullWidth(for size: CGSize) -> CGFloat {
        max(threshold(for: size) + 8, size.width - inset(for: size) * 2)
    }

    /// Diminishing-return resistance: grows quickly early, eases toward a soft
    /// cap so the pill feels stretchy and tactile rather than 1:1 linear.
    static func rubberBand(drag: CGFloat, size: CGSize) -> CGFloat {
        let rest = restWidth(for: size)
        let raw = max(0, drag)                 // leftward only
        let softCap: CGFloat = (fullWidth(for: size) - rest) * 1.15
        let eased = softCap * (1 - 1 / (raw / softCap + 1))
        return rest + eased
    }
}

// MARK: - Palette

private enum SwipeElasticRevealView_RevealPalette {
    static let panel = Color(red: 0.12, green: 0.13, blue: 0.18)
    static let panelEdge = Color(red: 0.22, green: 0.24, blue: 0.32)
    static let bar = Color(red: 0.32, green: 0.35, blue: 0.45)
    static let icon = Color(red: 0.55, green: 0.60, blue: 0.74)

    static let actionTop = Color(red: 0.98, green: 0.32, blue: 0.36)
    static let actionBottom = Color(red: 0.86, green: 0.16, blue: 0.42)

    static let firedTop = Color(red: 0.20, green: 0.78, blue: 0.52)
    static let firedBottom = Color(red: 0.10, green: 0.62, blue: 0.46)
}

// MARK: - Row content (always visible — guarantees "never blank")

private struct SwipeElasticRevealView_RevealRow: View {
    let size: CGSize
    /// How far the row content is pushed left by the growing pill.
    let push: CGFloat

    var body: some View {
        let inset = SwipeElasticRevealView_RevealMath.inset(for: size)
        let scale = min(size.width, size.height) / 120

        HStack(spacing: max(8, 12 * scale)) {
            avatar(scale: scale)
            VStack(alignment: .leading, spacing: max(5, 7 * scale)) {
                bar(widthFraction: 0.62, height: max(6, 9 * scale))
                bar(widthFraction: 0.40, height: max(5, 7 * scale))
                    .opacity(0.7)
            }
            Spacer(minLength: 0)
        }
        .padding(.horizontal, inset)
        .frame(maxWidth: .infinity, alignment: .leading)
        .offset(x: -push)
    }

    private func avatar(scale: CGFloat) -> some View {
        let d = max(26, 38 * scale)
        return Circle()
            .fill(
                LinearGradient(
                    colors: [SwipeElasticRevealView_RevealPalette.bar, SwipeElasticRevealView_RevealPalette.panelEdge],
                    startPoint: .topLeading,
                    endPoint: .bottomTrailing
                )
            )
            .frame(width: d, height: d)
            .overlay(
                Image(systemName: "envelope.fill")
                    .font(.system(size: d * 0.42, weight: .semibold))
                    .foregroundStyle(SwipeElasticRevealView_RevealPalette.icon)
            )
    }

    private func bar(widthFraction: CGFloat, height: CGFloat) -> some View {
        Capsule()
            .fill(SwipeElasticRevealView_RevealPalette.bar)
            .frame(height: height)
            .frame(maxWidth: .infinity, alignment: .leading)
            .scaleEffect(x: widthFraction, anchor: .leading)
    }
}

// MARK: - The stretchy trailing action pill

private struct SwipeElasticRevealView_ActionPill: View {
    let size: CGSize
    let width: CGFloat
    let fired: Bool

    var body: some View {
        let inset = SwipeElasticRevealView_RevealMath.inset(for: size)
        let rest = SwipeElasticRevealView_RevealMath.restWidth(for: size)
        let height = pillHeight
        // Label fades in only once the pill is comfortably wider than its nub.
        let labelReveal = clamped((width - rest * 1.4) / (rest * 1.6))

        ZStack {
            Capsule()
                .fill(fillGradient)
                .overlay(
                    Capsule()
                        .stroke(Color.white.opacity(0.16), lineWidth: 1)
                )
                .shadow(color: shadowColor, radius: 8, x: -2, y: 3)

            HStack(spacing: 6 * scale) {
                Image(systemName: fired ? "checkmark" : "trash.fill")
                    .font(.system(size: height * 0.40, weight: .bold))
                    .foregroundStyle(.white)
                    .contentTransition(.symbolEffect(.replace))

                if labelReveal > 0.02 {
                    Text(fired ? "Done" : "Delete")
                        .font(.system(size: height * 0.34, weight: .semibold))
                        .foregroundStyle(.white)
                        .lineLimit(1)
                        .fixedSize()
                        .opacity(labelReveal)
                        .scaleEffect(0.7 + 0.3 * labelReveal, anchor: .leading)
                }
            }
            .padding(.horizontal, height * 0.30)
        }
        .frame(width: max(rest, width), height: height)
        .padding(.trailing, inset)
        .frame(maxWidth: .infinity, alignment: .trailing)
    }

    private var scale: CGFloat { min(size.width, size.height) / 120 }

    private var pillHeight: CGFloat {
        max(30, min(size.height * 0.52, SwipeElasticRevealView_RevealMath.restWidth(for: size)))
    }

    private var fillGradient: LinearGradient {
        let top = fired ? SwipeElasticRevealView_RevealPalette.firedTop : SwipeElasticRevealView_RevealPalette.actionTop
        let bottom = fired ? SwipeElasticRevealView_RevealPalette.firedBottom : SwipeElasticRevealView_RevealPalette.actionBottom
        return LinearGradient(
            colors: [top, bottom],
            startPoint: .top,
            endPoint: .bottom
        )
    }

    private var shadowColor: Color {
        (fired ? SwipeElasticRevealView_RevealPalette.firedBottom : SwipeElasticRevealView_RevealPalette.actionBottom).opacity(0.5)
    }

    private func clamped(_ v: CGFloat) -> CGFloat { min(1, max(0, v)) }
}

// MARK: - Card chrome shared by both modes

private struct SwipeElasticRevealView_RevealCard<Pill: View>: View {
    let size: CGSize
    let push: CGFloat
    @ViewBuilder var pill: () -> Pill

    var body: some View {
        let corner = max(12, min(size.width, size.height) * 0.16)
        ZStack {
            RoundedRectangle(cornerRadius: corner, style: .continuous)
                .fill(SwipeElasticRevealView_RevealPalette.panel)
                .overlay(
                    RoundedRectangle(cornerRadius: corner, style: .continuous)
                        .stroke(SwipeElasticRevealView_RevealPalette.panelEdge, lineWidth: 1)
                )

            SwipeElasticRevealView_RevealRow(size: size, push: push)
            pill()
        }
        .clipShape(RoundedRectangle(cornerRadius: corner, style: .continuous))
        .padding(max(6, min(size.width, size.height) * 0.06))
    }
}

// MARK: - Interactive (demo == false)

private struct SwipeElasticRevealView_InteractiveReveal: View {
    let size: CGSize

    @State private var pillWidth: CGFloat
    @State private var fired = false
    @State private var fireTick = 0

    init(size: CGSize) {
        self.size = size
        _pillWidth = State(initialValue: SwipeElasticRevealView_RevealMath.restWidth(for: size))
    }

    var body: some View {
        let rest = SwipeElasticRevealView_RevealMath.restWidth(for: size)
        let push = max(0, pillWidth - rest)

        SwipeElasticRevealView_RevealCard(size: size, push: push) {
            SwipeElasticRevealView_ActionPill(size: size, width: pillWidth, fired: fired)
        }
        .contentShape(Rectangle())
        .gesture(dragGesture)
        .sensoryFeedback(.success, trigger: fireTick)
    }

    private var dragGesture: some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                guard !fired else { return }
                let drag = max(0, -value.translation.width)
                pillWidth = SwipeElasticRevealView_RevealMath.rubberBand(drag: drag, size: size)
            }
            .onEnded { _ in
                guard !fired else { return }
                if pillWidth >= SwipeElasticRevealView_RevealMath.threshold(for: size) {
                    commit()
                } else {
                    springBack()
                }
            }
    }

    private func commit() {
        fired = true
        fireTick &+= 1
        withAnimation(.bouncy(duration: 0.45, extraBounce: 0.25)) {
            pillWidth = SwipeElasticRevealView_RevealMath.fullWidth(for: size)
        }
        // Reset so the tile stays reusable after firing.
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.9) {
            withAnimation(.spring(response: 0.5, dampingFraction: 0.78)) {
                pillWidth = SwipeElasticRevealView_RevealMath.restWidth(for: size)
            }
            withAnimation(.easeInOut(duration: 0.3).delay(0.15)) {
                fired = false
            }
        }
    }

    private func springBack() {
        withAnimation(.spring(response: 0.4, dampingFraction: 0.6)) {
            pillWidth = SwipeElasticRevealView_RevealMath.restWidth(for: size)
        }
    }
}

// MARK: - Demo (demo == true) — self-driving, never blank

private enum SwipeElasticRevealView_RevealPhase: CaseIterable {
    case rest, stretch, commit
}

private struct SwipeElasticRevealView_DemoReveal: View {
    let size: CGSize

    var body: some View {
        PhaseAnimator(SwipeElasticRevealView_RevealPhase.allCases) { phase in
            frame(for: phase)
        } animation: { phase in
            animation(for: phase)
        }
    }

    @ViewBuilder
    private func frame(for phase: SwipeElasticRevealView_RevealPhase) -> some View {
        let width = pillWidth(for: phase)
        let rest = SwipeElasticRevealView_RevealMath.restWidth(for: size)
        let push = max(0, width - rest)

        SwipeElasticRevealView_RevealCard(size: size, push: push) {
            SwipeElasticRevealView_ActionPill(size: size, width: width, fired: phase == .commit)
        }
    }

    private func pillWidth(for phase: SwipeElasticRevealView_RevealPhase) -> CGFloat {
        switch phase {
        case .rest:    return SwipeElasticRevealView_RevealMath.restWidth(for: size)
        case .stretch: return SwipeElasticRevealView_RevealMath.threshold(for: size) + 6
        case .commit:  return SwipeElasticRevealView_RevealMath.fullWidth(for: size)
        }
    }

    private func animation(for phase: SwipeElasticRevealView_RevealPhase) -> Animation {
        switch phase {
        case .rest:    return .easeInOut(duration: 0.55)          // recoil back
        case .stretch: return .easeOut(duration: 1.25)            // slow elastic pull
        case .commit:  return .bouncy(duration: 0.5, extraBounce: 0.3) // snap wide
        }
    }
}
"""###,
        "ges-swipe-stack-shuffle": ###"""
import SwiftUI

/// Swipe Deck Shuffle
/// Swipe the top card off a fanned stack; the cards beneath glide up and
/// re-fan with slight per-card rotation jitter, while the flung card tumbles
/// away with spin proportional to swipe speed.
///
/// - `demo == true`  : a self-driving TimelineView loop that auto-flings the
///                     top card each cycle and re-fans the deck, then cycles
///                     the faces so the flung card "returns to the back".
/// - `demo == false` : the real interactive component. Drag the top card; past
///                     a velocity/translation threshold it flings off with spin
///                     and the deck advances + re-fans; otherwise it springs back.
struct SwipeStackShuffleView: View {

    var demo: Bool = false

    // A small fixed palette of card "faces" — drawn, no assets.
    private static let faces: [CardFace] = [
        CardFace(top: Color(red: 0.97, green: 0.45, blue: 0.42),
                 bottom: Color(red: 0.93, green: 0.27, blue: 0.45), glyph: "spade"),
        CardFace(top: Color(red: 0.40, green: 0.70, blue: 0.98),
                 bottom: Color(red: 0.30, green: 0.46, blue: 0.92), glyph: "heart"),
        CardFace(top: Color(red: 0.62, green: 0.82, blue: 0.50),
                 bottom: Color(red: 0.36, green: 0.66, blue: 0.46), glyph: "club"),
        CardFace(top: Color(red: 0.98, green: 0.80, blue: 0.42),
                 bottom: Color(red: 0.95, green: 0.58, blue: 0.28), glyph: "diamond"),
        CardFace(top: Color(red: 0.78, green: 0.62, blue: 0.97),
                 bottom: Color(red: 0.56, green: 0.40, blue: 0.92), glyph: "spade")
    ]

    // Interactive state.
    @State private var order: [Int] = Array(0..<SwipeStackShuffleView.faces.count)
    @State private var drag: CGSize = .zero
    @State private var flying: FlyingCard? = nil
    @State private var commitTick: Int = 0

    var body: some View {
        GeometryReader { geo in
            let side = min(geo.size.width, geo.size.height)
            ZStack {
                background
                if demo {
                    SwipeStackShuffleView_DemoStack(faces: Self.faces, side: side)
                } else {
                    interactiveStack(side: side)
                }
            }
            .frame(width: geo.size.width, height: geo.size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .sensoryFeedback(.impact(weight: .medium), trigger: commitTick)
    }

    // MARK: Background

    private var background: some View {
        LinearGradient(
            colors: [Color(red: 0.07, green: 0.08, blue: 0.13),
                     Color(red: 0.12, green: 0.10, blue: 0.18)],
            startPoint: .top, endPoint: .bottom
        )
    }

    // MARK: Interactive stack

    @ViewBuilder
    private func interactiveStack(side: CGFloat) -> some View {
        let cardW: CGFloat = side * 0.46
        let cardH: CGFloat = cardW * 1.42
        let visible = min(order.count, 4)

        ZStack {
            // Cards beneath, drawn back-to-front so the top is last.
            ForEach(Array(order.suffix(order.count).enumerated()), id: \.element) { pair in
                let depth = order.count - 1 - pair.offset // 0 == top
                if depth < visible {
                    beneathOrTopCard(faceIndex: pair.element,
                                     depth: depth,
                                     cardW: cardW, cardH: cardH)
                }
            }

            // The currently-flying card (a flung copy that tumbles away).
            if let fc = flying {
                Self.cardView(face: Self.faces[fc.faceIndex],
                              width: cardW, height: cardH)
                    .rotationEffect(.degrees(fc.rotation),
                                    anchor: UnitPoint(x: 0.5, y: 1.35))
                    .offset(fc.offset)
                    .opacity(fc.opacity)
            }
        }
        .animation(nil, value: drag)
    }

    @ViewBuilder
    private func beneathOrTopCard(faceIndex: Int, depth: Int,
                                  cardW: CGFloat, cardH: CGFloat) -> some View {
        let base = Self.fan(depth: depth, side: cardW)
        let isTop = depth == 0
        let liveOffset: CGSize = isTop ? combinedTopOffset(base.offset) : base.offset
        let liveRot: Double = isTop ? base.rotation + Double(drag.width) * 0.10 : base.rotation

        Self.cardView(face: Self.faces[faceIndex], width: cardW, height: cardH)
            .scaleEffect(base.scale)
            .rotationEffect(.degrees(liveRot), anchor: UnitPoint(x: 0.5, y: 1.35))
            .offset(liveOffset)
            .zIndex(Double(10 - depth))
            .allowsHitTesting(isTop)
            .gesture(topDragGesture(cardW: cardW), including: isTop ? .all : .subviews)
            .animation(.spring(response: 0.5, dampingFraction: 0.72), value: commitTick)
    }

    private func combinedTopOffset(_ base: CGSize) -> CGSize {
        CGSize(width: base.width + drag.width, height: base.height + drag.height)
    }

    private func topDragGesture(cardW: CGFloat) -> some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                drag = value.translation
            }
            .onEnded { value in
                handleRelease(value, cardW: cardW)
            }
    }

    private func handleRelease(_ value: DragGesture.Value, cardW: CGFloat) {
        let dx = value.translation.width
        let vx = value.predictedEndTranslation.width - value.translation.width
        let throwScore = abs(dx) + abs(vx) * 0.35
        let threshold: CGFloat = cardW * 0.55

        if throwScore > threshold, let topFace = order.last {
            fling(faceIndex: topFace, value: value)
        } else {
            withAnimation(.spring(response: 0.45, dampingFraction: 0.7)) {
                drag = .zero
            }
        }
    }

    private func fling(faceIndex: Int, value: DragGesture.Value) {
        let dx = value.translation.width
        let dy = value.translation.height
        let vx = value.predictedEndTranslation.width
        let vy = value.predictedEndTranslation.height
        let dir: CGFloat = dx >= 0 ? 1 : -1
        let speed = abs(vx - dx) + abs(dx)
        let spin = Double(dir) * Double(180 + min(speed, 600) * 0.5)

        // Seed the flying copy at the current drag position so it doesn't jump.
        flying = FlyingCard(faceIndex: faceIndex,
                            offset: CGSize(width: dx, height: dy),
                            rotation: Double(dx) * 0.10,
                            opacity: 1)
        // Clear the live drag and advance the deck immediately.
        drag = .zero
        rotateDeck()
        commitTick &+= 1

        // Tumble the flying copy away.
        withAnimation(.easeOut(duration: 0.55)) {
            flying?.offset = CGSize(width: dir * 1100, height: dy + vy * 0.6 - 120)
            flying?.rotation = spin
            flying?.opacity = 0
        }
        // Retire the copy after the tumble finishes.
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.6) {
            if flying?.faceIndex == faceIndex { flying = nil }
        }
    }

    private func rotateDeck() {
        guard let top = order.last else { return }
        order.removeLast()
        order.insert(top, at: 0)
    }

    // MARK: Shared geometry & drawing

    /// Deterministic fan transform for a card at a given depth (0 == top).
    static func fan(depth: Int, side cardW: CGFloat) -> FanTransform {
        let d = CGFloat(depth)
        let jitterR = Self.jitter(seed: depth, salt: 1.0)        // -1...1
        let jitterX = Self.jitter(seed: depth, salt: 7.0)        // -1...1
        let rot: Double = Double(d) * -4.0 + Double(jitterR) * 3.5
        let offX: CGFloat = d * cardW * 0.030 + jitterX * cardW * 0.045
        let offY: CGFloat = d * cardW * 0.085
        let scale: CGFloat = max(0.80, 1.0 - d * 0.055)
        return FanTransform(offset: CGSize(width: offX, height: offY),
                            rotation: rot, scale: scale)
    }

    /// Stable pseudo-random in -1...1 from an integer seed (computed once, never per-frame).
    static func jitter(seed: Int, salt: Double) -> CGFloat {
        let x = sin(Double(seed) * 12.9898 + salt * 78.233) * 43758.5453
        let frac = x - x.rounded(.down)        // 0..<1
        return CGFloat(frac * 2.0 - 1.0)
    }

    @ViewBuilder
    static func cardView(face: CardFace, width: CGFloat, height: CGFloat) -> some View {
        let corner: CGFloat = width * 0.12
        ZStack {
            RoundedRectangle(cornerRadius: corner, style: .continuous)
                .fill(
                    LinearGradient(colors: [face.top, face.bottom],
                                   startPoint: .topLeading, endPoint: .bottomTrailing)
                )
            RoundedRectangle(cornerRadius: corner, style: .continuous)
                .strokeBorder(Color.white.opacity(0.25), lineWidth: max(1, width * 0.012))

            cardGlyph(face: face, size: width)

            // Soft top-edge sheen.
            RoundedRectangle(cornerRadius: corner, style: .continuous)
                .fill(
                    LinearGradient(colors: [Color.white.opacity(0.22), .clear],
                                   startPoint: .top, endPoint: .center)
                )
                .blendMode(.softLight)
        }
        .frame(width: width, height: height)
        .shadow(color: .black.opacity(0.35), radius: width * 0.08, x: 0, y: width * 0.05)
    }

    @ViewBuilder
    private static func cardGlyph(face: CardFace, size: CGFloat) -> some View {
        let symbol: String = {
            switch face.glyph {
            case "heart":   return "suit.heart.fill"
            case "club":    return "suit.club.fill"
            case "diamond": return "suit.diamond.fill"
            default:        return "suit.spade.fill"
            }
        }()
        VStack {
            HStack {
                Image(systemName: symbol)
                    .font(.system(size: size * 0.13, weight: .bold))
                Spacer()
            }
            Spacer()
            Image(systemName: symbol)
                .font(.system(size: size * 0.40, weight: .bold))
            Spacer()
            HStack {
                Spacer()
                Image(systemName: symbol)
                    .font(.system(size: size * 0.13, weight: .bold))
                    .rotationEffect(.degrees(180))
            }
        }
        .foregroundStyle(Color.white.opacity(0.9))
        .padding(size * 0.10)
    }
}

// MARK: - Demo (self-driving, pure function of timeline time)

private struct SwipeStackShuffleView_DemoStack: View {
    let faces: [SwipeStackShuffleView.CardFace]
    let side: CGFloat

    private let period: Double = 3.2

    var body: some View {
        let cardW: CGFloat = side * 0.46
        let cardH: CGFloat = cardW * 1.42

        TimelineView(.animation) { context in
            let t = context.date.timeIntervalSinceReferenceDate
            let cycle = Int(floor(t / period))
            let phase = (t / period) - floor(t / period)   // 0..<1
            content(cycle: cycle, phase: phase, cardW: cardW, cardH: cardH)
        }
    }

    @ViewBuilder
    private func content(cycle: Int, phase: Double,
                         cardW: CGFloat, cardH: CGFloat) -> some View {
        let visible = min(faces.count, 4)
        ZStack {
            ForEach(0..<visible, id: \.self) { slot in
                demoCard(slot: slot, cycle: cycle, phase: phase,
                         cardW: cardW, cardH: cardH, visible: visible)
            }
        }
    }

    @ViewBuilder
    private func demoCard(slot: Int, cycle: Int, phase: Double,
                          cardW: CGFloat, cardH: CGFloat, visible: Int) -> some View {
        // Which face sits in this depth slot this cycle (rotates so flung card returns to back).
        let faceIndex = (slot + cycle) % faces.count

        if slot == 0 {
            // Top card: flings off, a fresh one rises into its place.
            demoTopCard(faceIndex: faceIndex, phase: phase, cardW: cardW, cardH: cardH)
        } else {
            // Beneath cards glide up one slot as the deck advances.
            demoBeneathCard(faceIndex: faceIndex, slot: slot, phase: phase,
                            cardW: cardW, cardH: cardH)
        }
    }

    @ViewBuilder
    private func demoTopCard(faceIndex: Int, phase: Double,
                             cardW: CGFloat, cardH: CGFloat) -> some View {
        let base = SwipeStackShuffleView.fan(depth: 0, side: cardW)
        // Fling occupies the first ~45% of the cycle; rest is the new top settling.
        let flingP = smooth(clamp(phase / 0.45))
        let throwX: CGFloat = flingP * cardW * 4.2
        let throwY: CGFloat = -flingP * cardW * 0.6
        let spin: Double = Double(flingP) * 320

        SwipeStackShuffleView.cardView(face: faces[faceIndex], width: cardW, height: cardH)
            .scaleEffect(base.scale)
            .rotationEffect(.degrees(base.rotation + spin),
                            anchor: UnitPoint(x: 0.5, y: 1.35))
            .offset(x: base.offset.width + throwX, y: base.offset.height + throwY)
            .opacity(1.0 - Double(flingP) * 0.9)
            .zIndex(20)
    }

    @ViewBuilder
    private func demoBeneathCard(faceIndex: Int, slot: Int, phase: Double,
                                 cardW: CGFloat, cardH: CGFloat) -> some View {
        // After the fling (~45%), beneath cards interpolate up one slot.
        let riseP = smooth(clamp((phase - 0.35) / 0.5))
        let from = SwipeStackShuffleView.fan(depth: slot, side: cardW)
        let to = SwipeStackShuffleView.fan(depth: slot - 1, side: cardW)
        let off = lerp(from.offset, to.offset, riseP)
        let rot = from.rotation + (to.rotation - from.rotation) * Double(riseP)
        let scl = from.scale + (to.scale - from.scale) * riseP

        SwipeStackShuffleView.cardView(face: faces[faceIndex], width: cardW, height: cardH)
            .scaleEffect(scl)
            .rotationEffect(.degrees(rot), anchor: UnitPoint(x: 0.5, y: 1.35))
            .offset(off)
            .zIndex(Double(10 - slot))
    }

    // MARK: small helpers

    private func clamp(_ v: Double) -> CGFloat { CGFloat(min(1.0, max(0.0, v))) }

    private func smooth(_ v: CGFloat) -> CGFloat { v * v * (3 - 2 * v) } // smoothstep

    private func lerp(_ a: CGSize, _ b: CGSize, _ t: CGFloat) -> CGSize {
        CGSize(width: a.width + (b.width - a.width) * t,
               height: a.height + (b.height - a.height) * t)
    }
}

// MARK: - Model types

extension SwipeStackShuffleView {

    struct CardFace: Identifiable {
        let id = UUID()
        let top: Color
        let bottom: Color
        let glyph: String
    }

    struct FanTransform {
        let offset: CGSize
        let rotation: Double
        let scale: CGFloat
    }

    struct FlyingCard {
        let faceIndex: Int
        var offset: CGSize
        var rotation: Double
        var opacity: Double
    }
}
"""###,
        "ges-swipe-stamp-impress": ###"""
import SwiftUI

// Swipe-Stamp Impress
// Drag a rubber stamp down onto the surface; it presses in with a squash,
// leaving an ink impression that blooms outward with a feathered ink-bleed edge.
//
// demo == true  -> self-driving PhaseAnimator loop drops / squashes / blooms / lifts.
// demo == false -> interactive DragGesture: downward drag drives approach + squash,
//                  contact blooms the ink (with .impact haptic), release lifts the stamp
//                  leaving the persisted impression.

struct SwipeStampImpressView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { geo in
            let side: CGFloat = min(geo.size.width, geo.size.height)
            ZStack {
                if demo {
                    SwipeStampImpressView_DemoStage(side: side)
                } else {
                    SwipeStampImpressView_InteractiveStage(side: side)
                }
            }
            .frame(width: geo.size.width, height: geo.size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }
}

// MARK: - Phases (demo loop)

private enum SwipeStampImpressView_StampPhase: CaseIterable {
    case up
    case pressed
    case lifted

    var pressProgress: CGFloat {
        switch self {
        case .up:      return 0.0
        case .pressed: return 1.0
        case .lifted:  return 0.0
        }
    }

    // Ink stays inked after the press so the impression reads as left behind.
    var inkProgress: CGFloat {
        switch self {
        case .up:      return 0.0
        case .pressed: return 1.0
        case .lifted:  return 1.0
        }
    }

    var animation: Animation {
        switch self {
        case .up:      return .spring(duration: 0.85, bounce: 0.20)
        case .pressed: return .spring(duration: 0.55, bounce: 0.45)
        case .lifted:  return .easeInOut(duration: 0.70)
        }
    }
}

// MARK: - Demo (self-driving)

private struct SwipeStampImpressView_DemoStage: View {
    let side: CGFloat

    var body: some View {
        PhaseAnimator(SwipeStampImpressView_StampPhase.allCases) { phase in
            SwipeStampImpressView_StampScene(side: side,
                       pressProgress: phase.pressProgress,
                       inkProgress: phase.inkProgress,
                       contactUnit: 0.5)
        } animation: { phase in
            phase.animation
        }
    }
}

// MARK: - Interactive

private struct SwipeStampImpressView_InteractiveStage: View {
    let side: CGFloat

    @State private var pressProgress: CGFloat = 0
    @State private var inkProgress: CGFloat = 0
    // Horizontal contact location in [0,1]; 0.5 == centered.
    @State private var contactUnit: CGFloat = 0.5
    @State private var didContact: Bool = false
    @State private var contactPulse: Int = 0

    private let contactThreshold: CGFloat = 0.55

    var body: some View {
        SwipeStampImpressView_StampScene(side: side,
                   pressProgress: pressProgress,
                   inkProgress: inkProgress,
                   contactUnit: contactUnit)
            .contentShape(Rectangle())
            .gesture(dragGesture)
            .sensoryFeedback(.impact(weight: .medium), trigger: contactPulse)
    }

    private var dragGesture: some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                let travel: CGFloat = side * 0.55
                let raw: CGFloat = max(0, value.translation.height) / max(travel, 1)
                let p: CGFloat = min(1, raw)
                pressProgress = p
                contactUnit = clampUnit(value.location.x / max(side, 1))

                let inContact: Bool = p >= contactThreshold
                if inContact {
                    let bloom: CGFloat = (p - contactThreshold) / (1 - contactThreshold)
                    inkProgress = max(inkProgress, min(1, bloom))
                    if !didContact {
                        didContact = true
                        contactPulse += 1
                        withAnimation(.spring(duration: 0.45, bounce: 0.40)) {
                            inkProgress = 1
                        }
                    }
                } else {
                    didContact = false
                }
            }
            .onEnded { _ in
                didContact = false
                withAnimation(.spring(duration: 0.55, bounce: 0.22)) {
                    pressProgress = 0
                }
            }
    }

    private func clampUnit(_ v: CGFloat) -> CGFloat {
        min(0.85, max(0.15, v))
    }
}

// MARK: - Scene composition

private struct SwipeStampImpressView_StampScene: View {
    let side: CGFloat
    let pressProgress: CGFloat
    let inkProgress: CGFloat
    let contactUnit: CGFloat

    var body: some View {
        ZStack {
            SwipeStampImpressView_SurfaceCard(side: side)
            SwipeStampImpressView_InkImpression(side: side,
                          inkProgress: inkProgress,
                          contactUnit: contactUnit)
            SwipeStampImpressView_RubberStamp(side: side,
                        pressProgress: pressProgress,
                        contactUnit: contactUnit)
        }
        .frame(width: side, height: side)
    }
}

// MARK: - Surface (paper card)

private struct SwipeStampImpressView_SurfaceCard: View {
    let side: CGFloat

    private let paperTop = Color(red: 0.96, green: 0.95, blue: 0.91)
    private let paperBottom = Color(red: 0.90, green: 0.88, blue: 0.82)

    var body: some View {
        let inset: CGFloat = side * 0.10
        let radius: CGFloat = side * 0.07
        RoundedRectangle(cornerRadius: radius, style: .continuous)
            .fill(
                LinearGradient(colors: [paperTop, paperBottom],
                               startPoint: .top, endPoint: .bottom)
            )
            .overlay(
                RoundedRectangle(cornerRadius: radius, style: .continuous)
                    .strokeBorder(Color(red: 0.78, green: 0.75, blue: 0.68), lineWidth: 1)
            )
            .frame(width: side - inset, height: side - inset)
            .shadow(color: Color.black.opacity(0.18),
                    radius: side * 0.03, x: 0, y: side * 0.012)
    }
}

// MARK: - Ink impression (feathered bloom)

private struct SwipeStampImpressView_InkImpression: View {
    let side: CGFloat
    let inkProgress: CGFloat
    let contactUnit: CGFloat

    private let ink = Color(red: 0.10, green: 0.16, blue: 0.55)

    var body: some View {
        let p: CGFloat = max(0, min(1, inkProgress))
        let cx: CGFloat = side * contactUnit
        // Contact line sits in the lower-middle band of the card.
        let cy: CGFloat = side * 0.56
        let markW: CGFloat = side * 0.40
        let markH: CGFloat = side * 0.40

        markGlyph(width: markW, height: markH)
            .position(x: cx, y: cy)
            .opacity(Double(min(1, p * 1.4)))
            .mask(
                bloomMask(width: markW * 2.0, height: markH * 2.0, progress: p)
                    .position(x: cx, y: cy)
            )
    }

    // The actual stamped emblem: ring + star, in ink color.
    private func markGlyph(width: CGFloat, height: CGFloat) -> some View {
        ZStack {
            Circle()
                .strokeBorder(ink, lineWidth: max(2, width * 0.055))
                .frame(width: width, height: height)
            SwipeStampImpressView_StarShape(points: 5)
                .fill(ink)
                .frame(width: width * 0.52, height: height * 0.52)
        }
        // slight bleed: blur grows with bloom so edges feather as it spreads
        .blur(radius: max(0.3, width * 0.012))
    }

    // Feathered radial reveal — opaque center fading to clear at the edge.
    private func bloomMask(width: CGFloat, height: CGFloat, progress: CGFloat) -> some View {
        let scale: CGFloat = 0.25 + progress * 1.05
        return RadialGradient(
            gradient: Gradient(stops: [
                .init(color: .black, location: 0.0),
                .init(color: .black, location: 0.62),
                .init(color: .black.opacity(0.45), location: 0.82),
                .init(color: .clear, location: 1.0)
            ]),
            center: .center,
            startRadius: 0,
            endRadius: width * 0.5
        )
        .frame(width: width, height: height)
        .scaleEffect(scale)
    }
}

// MARK: - Rubber stamp body

private struct SwipeStampImpressView_RubberStamp: View {
    let side: CGFloat
    let pressProgress: CGFloat
    let contactUnit: CGFloat

    private let woodTop = Color(red: 0.45, green: 0.27, blue: 0.16)
    private let woodBottom = Color(red: 0.32, green: 0.18, blue: 0.10)
    private let padColor = Color(red: 0.16, green: 0.13, blue: 0.12)

    var body: some View {
        let p: CGFloat = max(0, min(1, pressProgress))
        let contactThreshold: CGFloat = 0.55
        let squash: CGFloat = squashAmount(p, threshold: contactThreshold)

        let restY: CGFloat = -side * 0.30
        let contactY: CGFloat = side * 0.04
        let yOffset: CGFloat = restY + (contactY - restY) * p
        let xOffset: CGFloat = (contactUnit - 0.5) * side

        VStack(spacing: 0) {
            handle
            base
        }
        .frame(width: side * 0.30, height: side * 0.40)
        .scaleEffect(x: 1 + squash * 0.10, y: 1 - squash * 0.16, anchor: .bottom)
        .offset(x: xOffset, y: yOffset)
        .shadow(color: Color.black.opacity(0.22 + Double(p) * 0.12),
                radius: side * 0.025, x: 0, y: side * 0.02)
    }

    // Squash only kicks in once the pad makes contact.
    private func squashAmount(_ p: CGFloat, threshold: CGFloat) -> CGFloat {
        guard p > threshold else { return 0 }
        return (p - threshold) / (1 - threshold)
    }

    private var handle: some View {
        let w: CGFloat = side * 0.18
        let h: CGFloat = side * 0.20
        return RoundedRectangle(cornerRadius: w * 0.30, style: .continuous)
            .fill(
                LinearGradient(colors: [woodTop, woodBottom],
                               startPoint: .top, endPoint: .bottom)
            )
            .overlay(
                RoundedRectangle(cornerRadius: w * 0.30, style: .continuous)
                    .stroke(Color.white.opacity(0.18), lineWidth: 1)
            )
            .frame(width: w, height: h)
    }

    private var base: some View {
        let w: CGFloat = side * 0.30
        let h: CGFloat = side * 0.18
        return RoundedRectangle(cornerRadius: side * 0.03, style: .continuous)
            .fill(
                LinearGradient(colors: [woodTop, woodBottom],
                               startPoint: .top, endPoint: .bottom)
            )
            .overlay(alignment: .bottom) {
                RoundedRectangle(cornerRadius: side * 0.02, style: .continuous)
                    .fill(padColor)
                    .frame(width: w * 0.88, height: h * 0.34)
                    .offset(y: h * 0.04)
            }
            .frame(width: w, height: h)
    }
}

// MARK: - Star shape (stamp emblem)

private struct SwipeStampImpressView_StarShape: Shape {
    let points: Int

    func path(in rect: CGRect) -> Path {
        var path = Path()
        let count: Int = max(3, points)
        let center = CGPoint(x: rect.midX, y: rect.midY)
        let outer: CGFloat = min(rect.width, rect.height) / 2
        let inner: CGFloat = outer * 0.42
        let step: Double = .pi / Double(count)
        var angle: Double = -.pi / 2

        for i in 0..<(count * 2) {
            let r: CGFloat = (i % 2 == 0) ? outer : inner
            let x: CGFloat = center.x + cos(angle) * r
            let y: CGFloat = center.y + sin(angle) * r
            if i == 0 {
                path.move(to: CGPoint(x: x, y: y))
            } else {
                path.addLine(to: CGPoint(x: x, y: y))
            }
            angle += step
        }
        path.closeSubpath()
        return path
    }
}
"""###,
        "ges-tear-receipt": ###"""
import SwiftUI

// MARK: - TearReceiptView
// Drag the perforated stub downward to tear it along a procedurally ragged
// perforation. Past the threshold the freed piece detaches and flutters away
// while the remainder springs back up. The jagged edge is generated ONCE with a
// seeded RNG (stable across every frame); only the cut position animates.
struct TearReceiptView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { geo in
            content(in: geo.size)
                .frame(maxWidth: .infinity, maxHeight: .infinity)
        }
    }

    @ViewBuilder
    private func content(in size: CGSize) -> some View {
        if demo {
            TearReceiptView_DemoReceipt(canvas: size)
        } else {
            TearReceiptView_InteractiveReceipt(canvas: size)
        }
    }
}

// MARK: - Seeded deterministic RNG
// A small, fast, fully deterministic generator. Seeded with a constant so the
// ragged perforation profile is byte-identical on every view re-init.
private struct TearReceiptView_SeededRNG: RandomNumberGenerator {
    private var state: UInt64
    init(seed: UInt64) { state = seed == 0 ? 0x9E3779B97F4A7C15 : seed }
    mutating func next() -> UInt64 {
        // SplitMix64
        state &+= 0x9E3779B97F4A7C15
        var z = state
        z = (z ^ (z >> 30)) &* 0xBF58476D1CE4E5B9
        z = (z ^ (z >> 27)) &* 0x94D049BB133111EB
        return z ^ (z >> 31)
    }
}

// MARK: - Perforation profile (generated once, normalized)
// Amplitudes are stored normalized in roughly [-1, 1] and scaled by geometry at
// draw time, so the same profile reads correctly at 120pt and at full size.
private enum TearReceiptView_Perf {
    static let teeth = 26

    // Normalized vertical wobble of the tear line per tooth, in [-1, 1].
    static let wobble: [CGFloat] = makeWobble()

    // Normalized fiber-fringe length per tooth, in [0.3, 1].
    static let fringe: [CGFloat] = makeFringe()

    private static func makeWobble() -> [CGFloat] {
        var rng = TearReceiptView_SeededRNG(seed: 0xBEEF_CAFE_1234)
        return (0...teeth).map { _ in
            let r = Double(rng.next() >> 11) / Double(1 << 53) // 0..1
            return CGFloat(r * 2.0 - 1.0)
        }
    }

    private static func makeFringe() -> [CGFloat] {
        var rng = TearReceiptView_SeededRNG(seed: 0x00FF_1357_9BDF)
        return (0...teeth).map { _ in
            let r = Double(rng.next() >> 11) / Double(1 << 53) // 0..1
            return CGFloat(0.3 + r * 0.7)
        }
    }
}

// MARK: - Palette helpers (no app dependencies)
private enum TearReceiptView_Paper {
    static let ink = Color(red: 0.13, green: 0.14, blue: 0.20)
    static let faint = Color(red: 0.74, green: 0.75, blue: 0.80)
    static let sheetTop = Color(red: 0.99, green: 0.985, blue: 0.96)
    static let sheetBottom = Color(red: 0.95, green: 0.94, blue: 0.90)
    static let edgeShadow = Color(red: 0.0, green: 0.0, blue: 0.0).opacity(0.18)
    static let accent = Color(red: 0.92, green: 0.32, blue: 0.30)
}

// MARK: - Ragged perforation edge as an Animatable Shape
// `animatableData` is the tear progress ONLY (how far the cut has opened, 0...1).
// The jag arrays are constant stored data and never part of animatableData.
private struct TearReceiptView_RaggedTearEdge: Shape, Animatable {
    /// 0 = perforation still closed, 1 = fully separated.
    var progress: CGFloat
    /// true = clip the KEPT (upper) sheet; false = clip the FREED (lower) stub.
    var keepingUpper: Bool

    var animatableData: CGFloat {
        get { progress }
        set { progress = newValue }
    }

    func path(in rect: CGRect) -> Path {
        // Pure function of rect + stored props + progress. No RNG here.
        // The ragged edge is anchored at the SHARED SEAM: for the upper sheet
        // that seam is the bottom of its frame (maxY); for the lower stub it is
        // the top of its frame (minY). This makes the two halves abut at the
        // perforation at rest and pull apart only as `progress` rises.
        let teeth = TearReceiptView_Perf.teeth
        let stepX = rect.width / CGFloat(teeth)
        let amp = max(rect.height * 0.06, 6)
        let fringeMax = max(rect.height * 0.05, 5)

        // As progress rises, the two halves pull apart by `gap`.
        let gap = progress * (rect.height * 0.5 + 4)

        var p = Path()
        if keepingUpper {
            let baseY = rect.maxY
            p.move(to: CGPoint(x: rect.minX, y: rect.minY))
            p.addLine(to: CGPoint(x: rect.maxX, y: rect.minY))
            // Travel right-to-left along the ragged cut, pulled UP by gap.
            for i in stride(from: teeth, through: 0, by: -1) {
                let x = rect.minX + CGFloat(i) * stepX
                let wob = TearReceiptView_Perf.wobble[i] * amp
                let fr = TearReceiptView_Perf.fringe[i] * fringeMax
                let y = baseY + wob - gap - fr
                p.addLine(to: CGPoint(x: x, y: y))
            }
            p.closeSubpath()
        } else {
            let baseY = rect.minY
            p.move(to: CGPoint(x: rect.maxX, y: rect.maxY))
            p.addLine(to: CGPoint(x: rect.minX, y: rect.maxY))
            // Travel left-to-right along the ragged cut, pushed DOWN by gap.
            for i in stride(from: 0, through: teeth, by: 1) {
                let x = rect.minX + CGFloat(i) * stepX
                let wob = TearReceiptView_Perf.wobble[i] * amp
                let fr = TearReceiptView_Perf.fringe[i] * fringeMax
                let y = baseY + wob + gap + fr
                p.addLine(to: CGPoint(x: x, y: y))
            }
            p.closeSubpath()
        }
        return p
    }
}

// MARK: - The dotted perforation guide line (drawn at the seam when closed)
private struct TearReceiptView_PerforationGuide: Shape {
    func path(in rect: CGRect) -> Path {
        // The guide is drawn in a frame the same height as the upper sheet and
        // top-aligned, so the shared seam sits at the BOTTOM of this rect.
        let teeth = TearReceiptView_Perf.teeth
        let stepX = rect.width / CGFloat(teeth)
        let baseY = rect.maxY
        let amp = max(rect.height * 0.06, 6)
        var p = Path()
        for i in 0...teeth {
            let x = rect.minX + CGFloat(i) * stepX
            let y = baseY + TearReceiptView_Perf.wobble[i] * amp
            if i == 0 { p.move(to: CGPoint(x: x, y: y)) }
            else { p.addLine(to: CGPoint(x: x, y: y)) }
        }
        return p
    }
}

// MARK: - Receipt face content (printed rows). Scales with the rect.
private struct TearReceiptView_ReceiptFace: View {
    var size: CGSize
    var header: Bool

    var body: some View {
        let pad = max(size.width * 0.10, 8)
        VStack(alignment: .leading, spacing: max(size.height * 0.018, 3)) {
            if header {
                HStack(spacing: max(size.width * 0.03, 4)) {
                    Circle()
                        .fill(TearReceiptView_Paper.accent)
                        .frame(width: max(size.width * 0.08, 7),
                               height: max(size.width * 0.08, 7))
                    bar(widthFactor: 0.42, tall: true)
                    Spacer(minLength: 0)
                }
                .padding(.bottom, max(size.height * 0.01, 2))
            }
            ForEach(0..<rowCount, id: \.self) { idx in
                HStack(spacing: 0) {
                    bar(widthFactor: rowWidths[idx % rowWidths.count])
                    Spacer(minLength: max(size.width * 0.05, 5))
                    bar(widthFactor: 0.16)
                }
            }
        }
        .padding(.horizontal, pad)
        .padding(.vertical, max(size.height * 0.05, 5))
        .frame(width: size.width, alignment: .leading)
    }

    private var rowCount: Int {
        let n = Int(size.height / max(size.height * 0.10, 14))
        return min(max(n, 2), 6)
    }

    private let rowWidths: [CGFloat] = [0.50, 0.62, 0.40, 0.55, 0.34, 0.46]

    private func bar(widthFactor: CGFloat, tall: Bool = false) -> some View {
        RoundedRectangle(cornerRadius: 2, style: .continuous)
            .fill(tall ? TearReceiptView_Paper.ink : TearReceiptView_Paper.faint)
            .frame(width: size.width * widthFactor,
                   height: max(size.height * (tall ? 0.05 : 0.035), tall ? 5 : 3))
    }
}

// MARK: - Sheet background (the paper itself with a soft cut shadow)
private struct TearReceiptView_PaperSheet<Content: View>: View {
    var size: CGSize
    var shadowAtBottom: Bool
    var shadowAtTop: Bool
    @ViewBuilder var content: () -> Content

    var body: some View {
        ZStack {
            RoundedRectangle(cornerRadius: max(size.width * 0.04, 6), style: .continuous)
                .fill(
                    LinearGradient(colors: [TearReceiptView_Paper.sheetTop, TearReceiptView_Paper.sheetBottom],
                                   startPoint: .top, endPoint: .bottom)
                )
            content()
            if shadowAtBottom {
                LinearGradient(colors: [.clear, TearReceiptView_Paper.edgeShadow],
                               startPoint: .center, endPoint: .bottom)
                    .allowsHitTesting(false)
            }
            if shadowAtTop {
                LinearGradient(colors: [TearReceiptView_Paper.edgeShadow, .clear],
                               startPoint: .top, endPoint: .center)
                    .allowsHitTesting(false)
            }
        }
        .frame(width: size.width, height: size.height)
    }
}

// MARK: - Shared rip renderer
// Renders the upper (kept) sheet springing up and the lower (freed) stub
// tearing/fluttering away, given a single `progress` (0...1 tear) and a
// detach state for the flutter.
private struct TearReceiptView_RipStack: View {
    var canvas: CGSize
    var progress: CGFloat       // 0 closed ... 1 fully torn
    var detached: Bool          // freed piece is flying away
    var flutter: CGFloat        // 0...1 flutter timeline for the freed piece

    private var sheetWidth: CGFloat { min(canvas.width * 0.78, canvas.height * 0.62) }
    private var sheetHeight: CGFloat { min(canvas.height * 0.92, sheetWidth * 1.5) }
    private var splitY: CGFloat { sheetHeight * 0.58 } // perforation sits here

    var body: some View {
        ZStack {
            upperSheet
            seamGuide
            lowerStub
        }
        .frame(width: sheetWidth, height: sheetHeight)
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // The kept top portion. Springs UP slightly as the tear opens. Always opaque.
    private var upperSheet: some View {
        let topSize = CGSize(width: sheetWidth, height: splitY)
        return TearReceiptView_PaperSheet(size: topSize, shadowAtBottom: true, shadowAtTop: false) {
            TearReceiptView_ReceiptFace(size: topSize, header: true)
        }
        .clipShape(TearReceiptView_RaggedTearEdge(progress: progress, keepingUpper: true))
        .frame(height: sheetHeight, alignment: .top)
        .offset(y: -progress * (sheetHeight * 0.04))
    }

    // Dotted perforation, only visible while the seam is still mostly closed.
    private var seamGuide: some View {
        let topSize = CGSize(width: sheetWidth, height: splitY)
        return TearReceiptView_PerforationGuide()
            .stroke(style: StrokeStyle(lineWidth: max(sheetWidth * 0.012, 1.2),
                                       lineCap: .round, dash: [3, 4]))
            .foregroundColor(TearReceiptView_Paper.faint)
            .frame(width: topSize.width, height: topSize.height)
            .frame(height: sheetHeight, alignment: .top)
            .opacity(Double(max(0, 1 - progress * 2.4)))
            .allowsHitTesting(false)
    }

    // The freed bottom stub. Tears down, then on detach flutters away & fades.
    private var lowerStub: some View {
        let botHeight = sheetHeight - splitY
        let botSize = CGSize(width: sheetWidth, height: botHeight)
        // Flutter physics: grow offset, tilt in 3D, spin a touch, fade only THIS piece.
        let fall = detached ? flutter * (canvas.height * 0.9 + botHeight) : progress * (botHeight * 0.5)
        let drift = detached ? sin(flutter * .pi * 3) * (sheetWidth * 0.22) : 0
        let tilt = detached ? Double(flutter) * 26 : 0
        let spin = detached ? Double(flutter) * 14 : 0
        let fade = detached ? Double(max(0, 1 - flutter * 1.05)) : 1

        return TearReceiptView_PaperSheet(size: botSize, shadowAtBottom: false, shadowAtTop: false) {
            TearReceiptView_ReceiptFace(size: botSize, header: false)
        }
        .clipShape(TearReceiptView_RaggedTearEdge(progress: progress, keepingUpper: false))
        .frame(height: sheetHeight, alignment: .bottom)
        .offset(x: drift, y: fall)
        .rotation3DEffect(.degrees(tilt), axis: (x: 1, y: 0.15, z: 0.4),
                          anchor: .top, perspective: 0.7)
        .rotationEffect(.degrees(spin), anchor: .center)
        .opacity(fade)
    }
}

// MARK: - Interactive variant (demo == false)
private struct TearReceiptView_InteractiveReceipt: View {
    var canvas: CGSize

    @State private var progress: CGFloat = 0
    @State private var detached: Bool = false
    @State private var flutter: CGFloat = 0
    @State private var tickCount: Int = 0

    private let threshold: CGFloat = 0.62

    var body: some View {
        TearReceiptView_RipStack(canvas: canvas, progress: progress, detached: detached, flutter: flutter)
            .contentShape(Rectangle())
            .gesture(dragGesture)
            .sensoryFeedback(.selection, trigger: tickCount)
            .sensoryFeedback(.success, trigger: detached) { _, now in now }
    }

    private var dragGesture: some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                guard !detached else { return }
                let span = max(canvas.height * 0.45, 60)
                let raw = max(0, value.translation.height) / span
                let clamped = min(raw, 1)
                // Tick haptics as the tear crosses perforation notches.
                let newTick = Int(clamped * CGFloat(TearReceiptView_Perf.teeth))
                if newTick != tickCount { tickCount = newTick }
                progress = clamped
            }
            .onEnded { _ in
                guard !detached else { return }
                if progress >= threshold {
                    // Finish the rip, then detach and flutter the freed stub away.
                    withAnimation(.easeIn(duration: 0.16)) { progress = 1 }
                    detached = true
                    withAnimation(.easeIn(duration: 1.05)) { flutter = 1 }
                    // The kept receipt springs up as the piece leaves.
                    DispatchQueue.main.asyncAfter(deadline: .now() + 1.15) {
                        resetForNextTear()
                    }
                } else {
                    // Not far enough — perforation springs back together.
                    withAnimation(.spring(response: 0.4, dampingFraction: 0.6)) {
                        progress = 0
                    }
                }
            }
    }

    private func resetForNextTear() {
        // Re-arm with a gentle reveal so a fresh stub is tearable again.
        flutter = 0
        detached = false
        progress = 1
        withAnimation(.spring(response: 0.55, dampingFraction: 0.7)) {
            progress = 0
        }
    }
}

// MARK: - Demo variant (demo == true) — self-driving, never blank
// Hand-shaped time -> state mapping via TimelineView(.animation) for a clean,
// flash-free loop reset and a guaranteed-legible kept receipt on every frame.
private struct TearReceiptView_DemoReceipt: View {
    var canvas: CGSize
    private let cycle: Double = 3.4 // seconds

    var body: some View {
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            let phase = (t.truncatingRemainder(dividingBy: cycle)) / cycle
            let s = state(for: phase)
            TearReceiptView_RipStack(canvas: canvas,
                     progress: s.progress,
                     detached: s.detached,
                     flutter: s.flutter)
        }
    }

    struct LoopState { var progress: CGFloat; var detached: Bool; var flutter: CGFloat }

    // phase 0.00..0.45 : tear opens (intact -> tearing)
    // phase 0.45..0.80 : freed piece flutters away (the upper sheet stays put)
    // phase 0.80..1.00 : hold + gentle re-arm so the reset never flashes blank
    private func state(for phase: Double) -> LoopState {
        if phase < 0.45 {
            let p = ease(phase / 0.45)
            return LoopState(progress: CGFloat(p), detached: false, flutter: 0)
        } else if phase < 0.80 {
            let f = (phase - 0.45) / 0.35
            return LoopState(progress: 1, detached: true, flutter: CGFloat(ease(f)))
        } else {
            // Re-arm: a fresh stub eases back into place (progress 1 -> 0).
            let r = (phase - 0.80) / 0.20
            let prog = 1 - ease(r)
            return LoopState(progress: CGFloat(prog), detached: false, flutter: 0)
        }
    }

    private func ease(_ x: Double) -> Double {
        let c = min(max(x, 0), 1)
        return c * c * (3 - 2 * c) // smoothstep
    }
}
"""###,
        "ges-throw-and-catch-orbit": ###"""
import SwiftUI

// MARK: - Boomerang Toss
/// Fling the puck and it arcs out, decelerates, curves back along a banking
/// return path, and lands home in the launch slot with a catch bounce.
struct ThrowAndCatchOrbitView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { proxy in
            let size = proxy.size
            ZStack {
                ThrowAndCatchOrbitView_BackgroundField()
                if demo {
                    ThrowAndCatchOrbitView_DemoFlight(size: size)
                } else {
                    ThrowAndCatchOrbitView_InteractiveFlight(size: size)
                }
            }
            .frame(width: size.width, height: size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }
}

// MARK: - Shared geometry & math

private enum ThrowAndCatchOrbitView_Orbit {
    /// Where the slot sits within the view (slightly below-center, low-left
    /// launch feel). Returned as a concrete point for a given size.
    static func slot(in size: CGSize) -> CGPoint {
        CGPoint(x: size.width * 0.34, y: size.height * 0.66)
    }

    /// Flight reach as a fraction of the view's short edge.
    static func reach(in size: CGSize) -> CGFloat {
        min(size.width, size.height) * 0.62
    }

    /// Pure position function shared by demo and interactive modes.
    /// `progress` 0 -> 1. Both p=0 and p=1 land exactly on the slot because
    /// sin(pi*p) is zero at the endpoints; the rotating `angle` makes the
    /// return leg curve home instead of retracing the outbound leg.
    static func position(progress p: CGFloat,
                         launchAngle: CGFloat,
                         curl: CGFloat,
                         in size: CGSize) -> CGPoint {
        let s = slot(in: size)
        let r = reach(in: size)
        let angle = launchAngle + curl * (p - 0.5)
        let radius = r * sin(.pi * p)
        let dx = radius * cos(angle)
        let dy = radius * sin(angle)
        return CGPoint(x: s.x + dx, y: s.y + dy)
    }

    /// Banking rotation = tangent direction via finite difference, eased to
    /// rest near the endpoints where speed -> 0 and the tangent gets noisy.
    static func banking(progress p: CGFloat,
                        launchAngle: CGFloat,
                        curl: CGFloat,
                        in size: CGSize) -> Angle {
        let edge: CGFloat = 0.06
        let calmP = min(max(p, edge), 1 - edge)
        let h: CGFloat = 0.012
        let a = position(progress: calmP - h, launchAngle: launchAngle, curl: curl, in: size)
        let b = position(progress: calmP + h, launchAngle: launchAngle, curl: curl, in: size)
        let dirAngle = atan2(b.y - a.y, b.x - a.x)
        // Fade the bank toward zero at the very ends so the catch doesn't twitch.
        let endFade = sin(.pi * p)
        return Angle(radians: Double(dirAngle * endFade))
    }

    /// Ease-out: decelerate on the way out, like a real toss.
    static func easeOut(_ raw: CGFloat) -> CGFloat {
        let clamped = min(max(raw, 0), 1)
        return 1 - pow(1 - clamped, 2.0)
    }
}

// MARK: - Background field & slot

private struct ThrowAndCatchOrbitView_BackgroundField: View {
    var body: some View {
        GeometryReader { proxy in
            let size = proxy.size
            let s = ThrowAndCatchOrbitView_Orbit.slot(in: size)
            let r = ThrowAndCatchOrbitView_Orbit.reach(in: size)
            ZStack {
                RadialGradient(
                    colors: [
                        Color(red: 0.10, green: 0.11, blue: 0.18),
                        Color(red: 0.05, green: 0.05, blue: 0.09)
                    ],
                    center: .center,
                    startRadius: 0,
                    endRadius: max(size.width, size.height) * 0.75
                )
                // Faint hint of the boomerang's return loop.
                ThrowAndCatchOrbitView_ReturnPathHint(launchAngle: -1.05, curl: 1.5)
                    .stroke(
                        Color(red: 0.42, green: 0.50, blue: 0.95).opacity(0.12),
                        style: StrokeStyle(lineWidth: max(1.2, r * 0.012),
                                           lineCap: .round, dash: [2, 7])
                    )
                ThrowAndCatchOrbitView_LaunchSlot(slot: s, radius: max(10, r * 0.16))
            }
        }
    }
}

private struct ThrowAndCatchOrbitView_ReturnPathHint: Shape {
    var launchAngle: CGFloat
    var curl: CGFloat
    func path(in rect: CGRect) -> Path {
        var path = Path()
        let size = rect.size
        let steps = 48
        for i in 0...steps {
            let p = CGFloat(i) / CGFloat(steps)
            let pt = ThrowAndCatchOrbitView_Orbit.position(progress: p, launchAngle: launchAngle, curl: curl, in: size)
            if i == 0 { path.move(to: pt) } else { path.addLine(to: pt) }
        }
        return path
    }
}

private struct ThrowAndCatchOrbitView_LaunchSlot: View {
    var slot: CGPoint
    var radius: CGFloat
    var body: some View {
        ZStack {
            Circle()
                .fill(
                    RadialGradient(
                        colors: [
                            Color(red: 0.10, green: 0.12, blue: 0.22),
                            Color(red: 0.06, green: 0.07, blue: 0.12)
                        ],
                        center: .center, startRadius: 0, endRadius: radius
                    )
                )
                .frame(width: radius * 2, height: radius * 2)
            Circle()
                .strokeBorder(
                    Color(red: 0.40, green: 0.48, blue: 0.92).opacity(0.55),
                    lineWidth: max(1.5, radius * 0.10)
                )
                .frame(width: radius * 2, height: radius * 2)
            Circle()
                .strokeBorder(
                    Color(red: 0.55, green: 0.62, blue: 1.0).opacity(0.18),
                    lineWidth: max(1, radius * 0.04)
                )
                .frame(width: radius * 2.5, height: radius * 2.5)
        }
        .position(slot)
    }
}

// MARK: - The flung object (a boomerang puck)

private struct ThrowAndCatchOrbitView_Puck: View {
    var diameter: CGFloat
    var squash: CGFloat        // 1 = round, <1 vertical squash, >1 stretch
    var glow: CGFloat          // 0...1 trail glow intensity

    var body: some View {
        ZStack {
            // Soft motion glow behind the body.
            Circle()
                .fill(Color(red: 0.45, green: 0.55, blue: 1.0))
                .frame(width: diameter * 1.55, height: diameter * 1.55)
                .blur(radius: diameter * 0.45)
                .opacity(0.22 + 0.35 * glow)

            // Boomerang body: an elbow drawn from two fat capsules.
            ThrowAndCatchOrbitView_BoomerangShape()
                .fill(
                    LinearGradient(
                        colors: [
                            Color(red: 0.98, green: 0.78, blue: 0.42),
                            Color(red: 0.93, green: 0.45, blue: 0.55)
                        ],
                        startPoint: .topLeading, endPoint: .bottomTrailing
                    )
                )
                .overlay(
                    ThrowAndCatchOrbitView_BoomerangShape()
                        .stroke(Color.white.opacity(0.45), lineWidth: max(0.8, diameter * 0.03))
                )
                .frame(width: diameter, height: diameter)
                .shadow(color: Color.black.opacity(0.45),
                        radius: diameter * 0.12, x: 0, y: diameter * 0.10)

            // Center hub highlight.
            Circle()
                .fill(Color.white.opacity(0.75))
                .frame(width: diameter * 0.16, height: diameter * 0.16)
        }
        .scaleEffect(x: 2 - squash, y: squash, anchor: .center)
    }
}

private struct ThrowAndCatchOrbitView_BoomerangShape: Shape {
    func path(in rect: CGRect) -> Path {
        let w = rect.width
        let h = rect.height
        let t = w * 0.30          // arm thickness
        var path = Path()
        // A rounded "V" / elbow.
        path.move(to: CGPoint(x: w * 0.12, y: h * 0.12))
        path.addLine(to: CGPoint(x: w * 0.12 + t, y: h * 0.12))
        path.addLine(to: CGPoint(x: w * 0.55, y: h * 0.55 - t * 0.2))
        path.addLine(to: CGPoint(x: w * 0.88, y: h * 0.88 - t))
        path.addLine(to: CGPoint(x: w * 0.88, y: h * 0.88))
        path.addLine(to: CGPoint(x: w * 0.88 - t, y: h * 0.88))
        path.addLine(to: CGPoint(x: w * 0.45, y: h * 0.45 + t * 0.2))
        path.addLine(to: CGPoint(x: w * 0.12, y: h * 0.12 + t))
        path.closeSubpath()
        return path.applying(
            CGAffineTransform(translationX: -w / 2, y: -h / 2)
                .concatenating(CGAffineTransform(rotationAngle: -.pi / 4))
                .concatenating(CGAffineTransform(translationX: w / 2, y: h / 2))
        )
    }
}

// MARK: - Demo (self-driving, pure time -> position; no state writes)

private struct ThrowAndCatchOrbitView_DemoFlight: View {
    var size: CGSize
    private let loop: Double = 3.4        // total cycle
    private let flightFraction: Double = 0.72   // rest in the slot the remainder
    private let launchAngle: CGFloat = -1.05
    private let curl: CGFloat = 1.5

    var body: some View {
        TimelineView(.animation) { context in
            let t = context.date.timeIntervalSinceReferenceDate
            let phase = (t.truncatingRemainder(dividingBy: loop)) / loop   // 0...1
            content(for: phase)
        }
    }

    @ViewBuilder
    private func content(for phase: Double) -> some View {
        let d = puckDiameter
        let prog = flightProgress(phase)
        let pos = ThrowAndCatchOrbitView_Orbit.position(progress: prog, launchAngle: launchAngle, curl: curl, in: size)
        let bank = ThrowAndCatchOrbitView_Orbit.banking(progress: prog, launchAngle: launchAngle, curl: curl, in: size)
        let spin = Double(prog) * 720.0     // boomerang spins as it flies
        let glow = sin(.pi * prog)          // brightest mid-flight
        let squash = catchSquash(phase)
        ThrowAndCatchOrbitView_Puck(diameter: d, squash: squash, glow: glow)
            .rotationEffect(bank)
            .rotationEffect(.degrees(spin))
            .position(pos)
    }

    private var puckDiameter: CGFloat { min(size.width, size.height) * 0.20 }

    /// Maps the loop phase to flight progress 0->1, then holds at 0 (resting in
    /// the slot) for the remainder so the object is always visible.
    private func flightProgress(_ phase: Double) -> CGFloat {
        guard phase < flightFraction else { return 0 }
        let raw = CGFloat(phase / flightFraction)
        // Ease-out so it decelerates on the way out, like a real toss.
        return ThrowAndCatchOrbitView_Orbit.easeOut(raw)
    }

    /// A brief squash right at the catch (flight end) and on the rest segment.
    private func catchSquash(_ phase: Double) -> CGFloat {
        let restStart = flightFraction
        guard phase >= restStart else { return 1.0 }
        // Decaying bounce just after landing.
        let local = (phase - restStart) / (1 - restStart)   // 0...1 in rest
        let damp = exp(-local * 6.0)
        let wobble = cos(local * .pi * 4.0)
        return 1.0 + CGFloat(0.22 * damp * wobble)
    }
}

// MARK: - Interactive (drag to wind up, fling to launch, catch on completion)

private enum ThrowAndCatchOrbitView_FlightPhase { case idle, aiming, flying }

private struct ThrowAndCatchOrbitView_InteractiveFlight: View {
    var size: CGSize

    @State private var phase: ThrowAndCatchOrbitView_FlightPhase = .idle
    @State private var aimOffset: CGSize = .zero       // wind-up pull from slot
    @State private var launchAngle: CGFloat = -1.05
    @State private var curl: CGFloat = 1.5
    @State private var spinBase: Double = 0            // accumulated rest spin
    @State private var spinRevs: Double = 1.5          // revolutions this flight
    @State private var catchScale: CGFloat = 1.0       // spring-driven squash
    @State private var catchTrigger: Int = 0

    // Time-driven flight: TimelineView re-samples the path each frame so the
    // puck actually traces the curved return arc (unlike a withAnimation tween
    // of .position, which would interpolate slot->slot and never travel).
    @State private var flightStart: Date = .distantPast
    private let flightDuration: Double = 0.95

    private var puckDiameter: CGFloat { min(size.width, size.height) * 0.20 }

    var body: some View {
        let slot = ThrowAndCatchOrbitView_Orbit.slot(in: size)
        // Pause the timeline whenever we're not flying so idle/aiming render
        // purely from state changes without burning the frame clock.
        TimelineView(.animation(paused: phase != .flying)) { context in
            let prog = currentProgress(now: context.date)
            content(slot: slot, progress: prog)
        }
    }

    @ViewBuilder
    private func content(slot: CGPoint, progress prog: CGFloat) -> some View {
        let pos = currentPosition(slot: slot, progress: prog)
        let bank = currentBanking(progress: prog)
        let glow: Double = phase == .flying ? Double(sin(.pi * prog)) : 0.0
        let spin = spinBase + (phase == .flying ? Double(prog) * 360.0 * spinRevs : 0)
        let grab = puckDiameter * 2.2

        ThrowAndCatchOrbitView_Puck(diameter: puckDiameter, squash: catchScale, glow: glow)
            .rotationEffect(bank)
            .rotationEffect(.degrees(spin))
            .position(pos)
            .contentShape(
                Circle().path(in: CGRect(x: pos.x - grab / 2, y: pos.y - grab / 2,
                                         width: grab, height: grab))
            )
            .gesture(dragGesture(slot: slot))
            .sensoryFeedback(.impact(flexibility: .soft), trigger: catchTrigger)
    }

    // MARK: progress / position

    private func currentProgress(now: Date) -> CGFloat {
        guard phase == .flying else { return 0 }
        let elapsed = now.timeIntervalSince(flightStart)
        let raw = CGFloat(elapsed / flightDuration)
        return ThrowAndCatchOrbitView_Orbit.easeOut(raw)
    }

    private func currentPosition(slot: CGPoint, progress prog: CGFloat) -> CGPoint {
        switch phase {
        case .idle:
            return slot
        case .aiming:
            return CGPoint(x: slot.x + aimOffset.width, y: slot.y + aimOffset.height)
        case .flying:
            return ThrowAndCatchOrbitView_Orbit.position(progress: prog,
                                  launchAngle: launchAngle, curl: curl, in: size)
        }
    }

    private func currentBanking(progress prog: CGFloat) -> Angle {
        guard phase == .flying else { return .zero }
        return ThrowAndCatchOrbitView_Orbit.banking(progress: prog,
                             launchAngle: launchAngle, curl: curl, in: size)
    }

    // MARK: gesture

    private func dragGesture(slot: CGPoint) -> some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                guard phase != .flying else { return }
                phase = .aiming
                // Pull the puck back from the slot to aim (resisted wind-up).
                aimOffset = CGSize(width: value.translation.width * 0.6,
                                   height: value.translation.height * 0.6)
            }
            .onEnded { value in
                guard phase != .flying else { return }
                launch(with: value)
            }
    }

    private func launch(with value: DragGesture.Value) {
        // Outbound vector = opposite the wind-up pull, biased by fling velocity.
        let pe = value.predictedEndTranslation
        let vx = -value.translation.width - pe.width * 0.18
        let vy = -value.translation.height - pe.height * 0.18
        let magnitude = max(sqrt(vx * vx + vy * vy), 1)

        launchAngle = atan2(vy, vx)
        // Curl direction follows the sideways throw component; clamp the span.
        let lateral = vx                     // sign gives curl handedness
        let curlMag = min(2.0, 0.9 + Double(magnitude) / 400.0)
        curl = CGFloat(lateral >= 0 ? curlMag : -curlMag)

        // Spin scales with throw strength for tactility.
        spinRevs = 1.5 + Double(min(magnitude, 600)) / 300.0
        aimOffset = .zero
        catchScale = 1.0

        // Start the time-driven flight; TimelineView samples the arc each frame.
        flightStart = Date()
        phase = .flying

        // Finite-duration, non-spring animation gives an exact completion time
        // at the slot. The catch reaction lives in the completion closure; the
        // empty body keeps it a pure timer with no competing visual tween.
        withAnimation(.linear(duration: flightDuration)) {
            // no-op visual; used only to hang completion off the same timing
        } completion: {
            self.catchHome()
        }
    }

    private func catchHome() {
        // Land in the slot, fire haptic, run the squash, settle to idle.
        // Bank the flight's spin into the resting orientation so the rotation
        // doesn't visually snap when we leave the flying phase.
        spinBase += Double(1.0) * 360.0 * spinRevs
        phase = .idle
        catchTrigger += 1
        catchScale = 0.72
        withAnimation(.spring(response: 0.42, dampingFraction: 0.42)) {
            catchScale = 1.0
        }
    }
}
"""###,
        "ges-two-finger-shear": ###"""
import SwiftUI

// MARK: - Two-Finger Shear Card
//
// Drag two fingers in opposite directions across the card (top half one way,
// bottom half the other) to shear it into a parallelogram with a glossy skew
// highlight. Release and it springs back to a true rectangle with an elastic
// wobble. The shear is dimensionless (offset / card height) so it behaves the
// same in a 120pt tile and in a large detail area.

struct TwoFingerShearView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { proxy in
            let side = min(proxy.size.width, proxy.size.height)
            let card = max(40, side * 0.74)

            ZStack {
                TwoFingerShearView_BackdropView()

                if demo {
                    TwoFingerShearView_DemoShearStage(cardSide: card)
                } else {
                    TwoFingerShearView_InteractiveShearStage(cardSide: card)
                }
            }
            .frame(maxWidth: .infinity, maxHeight: .infinity)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }
}

// MARK: - Animatable shear effect

/// A ProjectionTransform whose shear coefficient is animatable, so it tweens
/// smoothly under .interpolatingSpring and PhaseAnimator instead of snapping.
private struct TwoFingerShearView_ShearEffect: GeometryEffect {
    var shear: CGFloat

    var animatableData: CGFloat {
        get { shear }
        set { shear = newValue }
    }

    func effectValue(size: CGSize) -> ProjectionTransform {
        let cy = size.height / 2
        // x' = x + shear * y, compensated by -shear*cy so the vertical center
        // stays put and the card leans symmetrically into a parallelogram.
        let transform = CGAffineTransform(
            a: 1, b: 0,
            c: shear, d: 1,
            tx: -shear * cy, ty: 0
        )
        return ProjectionTransform(transform)
    }
}

// MARK: - Backdrop

private struct TwoFingerShearView_BackdropView: View {
    var body: some View {
        RoundedRectangle(cornerRadius: 18, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.07, green: 0.08, blue: 0.13),
                        Color(red: 0.04, green: 0.04, blue: 0.08)
                    ],
                    startPoint: .topLeading,
                    endPoint: .bottomTrailing
                )
            )
            .ignoresSafeArea()
    }
}

// MARK: - The card visual (shared by demo + interactive)

private struct TwoFingerShearView_ShearCard: View {
    var side: CGFloat
    var shear: CGFloat

    private var shape: RoundedRectangle {
        RoundedRectangle(cornerRadius: side * 0.16, style: .continuous)
    }

    // Normalized 0...1 magnitude used to intensify the gloss + rim under tension.
    private var tension: CGFloat {
        min(1, abs(shear) / 0.4)
    }

    var body: some View {
        ZStack {
            faceFill
            glossSheen
            rimStroke
            gripHints
        }
        .frame(width: side, height: side)
        .clipShape(shape)
        .modifier(TwoFingerShearView_ShearEffect(shear: shear))
        .shadow(
            color: Color(red: 0.0, green: 0.0, blue: 0.0).opacity(0.45),
            radius: 16, x: shear * side * 0.35, y: 12
        )
    }

    private var faceFill: some View {
        shape
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.42, green: 0.55, blue: 0.98),
                        Color(red: 0.62, green: 0.36, blue: 0.92),
                        Color(red: 0.32, green: 0.42, blue: 0.86)
                    ],
                    startPoint: .topLeading,
                    endPoint: .bottomTrailing
                )
            )
    }

    // Diagonal sheen that lives inside the (clipped) card, so it shears along
    // with the face. Its angle drifts with the shear amount to "track the skew".
    private var glossSheen: some View {
        let lean = shear * 0.9
        return LinearGradient(
            colors: [
                Color(red: 1, green: 1, blue: 1).opacity(0.0),
                Color(red: 1, green: 1, blue: 1).opacity(0.28 + 0.4 * tension),
                Color(red: 1, green: 1, blue: 1).opacity(0.0)
            ],
            startPoint: UnitPoint(x: 0.15 + lean, y: 0.0),
            endPoint: UnitPoint(x: 0.55 + lean, y: 1.0)
        )
        .blendMode(.screen)
    }

    private var rimStroke: some View {
        shape
            .strokeBorder(
                LinearGradient(
                    colors: [
                        Color(red: 1, green: 1, blue: 1).opacity(0.55 + 0.3 * tension),
                        Color(red: 1, green: 1, blue: 1).opacity(0.05)
                    ],
                    startPoint: .topLeading,
                    endPoint: .bottomTrailing
                ),
                lineWidth: 1.4
            )
    }

    // Two faint grip bars hint that the top and bottom edges are draggable.
    private var gripHints: some View {
        VStack {
            gripBar
            Spacer()
            gripBar
        }
        .padding(.vertical, side * 0.12)
        .opacity(0.5)
    }

    private var gripBar: some View {
        Capsule()
            .fill(Color(red: 1, green: 1, blue: 1).opacity(0.6))
            .frame(width: side * 0.42, height: 4)
    }
}

// MARK: - Demo: self-driving PhaseAnimator loop

private enum TwoFingerShearView_ShearPhase: CaseIterable {
    case rect, shearedLeft, rectMid, shearedRight

    var shear: CGFloat {
        switch self {
        case .rect:         return 0
        case .shearedLeft:  return -0.38
        case .rectMid:      return 0
        case .shearedRight: return 0.38
        }
    }

    var animation: Animation {
        switch self {
        case .rect, .rectMid:
            // Settle back square with a bouncy wobble.
            return .interpolatingSpring(stiffness: 120, damping: 9)
        case .shearedLeft, .shearedRight:
            // Lean into the parallelogram smoothly.
            return .easeInOut(duration: 0.85)
        }
    }
}

private struct TwoFingerShearView_DemoShearStage: View {
    var cardSide: CGFloat

    var body: some View {
        PhaseAnimator(TwoFingerShearView_ShearPhase.allCases) { phase in
            TwoFingerShearView_ShearCard(side: cardSide, shear: phase.shear)
        } animation: { phase in
            phase.animation
        }
    }
}

// MARK: - Interactive: two independent finger halves

private struct TwoFingerShearView_InteractiveShearStage: View {
    var cardSide: CGFloat

    @State private var topShear: CGFloat = 0      // contribution from top finger
    @State private var bottomShear: CGFloat = 0   // contribution from bottom finger
    @State private var releasedShear: CGFloat = 0 // spring-home target on release
    @State private var isDragging = false
    @State private var impactTrigger = 0

    // While dragging, shear pins 1:1 to the fingers; once released we hand off
    // to the spring-animated `releasedShear`.
    private var liveShear: CGFloat {
        let raw = topShear - bottomShear
        return max(-0.45, min(0.45, raw))
    }

    private var shear: CGFloat {
        isDragging ? liveShear : releasedShear
    }

    var body: some View {
        ZStack {
            TwoFingerShearView_ShearCard(side: cardSide, shear: shear)

            // Invisible, hittable top/bottom halves capture one finger each.
            // Two separate DragGestures on separate views = true two-finger
            // input without UIKit (a single DragGesture is single-touch).
            VStack(spacing: 0) {
                halfCatcher(isTop: true)
                halfCatcher(isTop: false)
            }
            .frame(width: cardSide, height: cardSide)
        }
        .sensoryFeedback(.impact, trigger: impactTrigger)
    }

    private func halfCatcher(isTop: Bool) -> some View {
        Color.clear
            .contentShape(Rectangle())
            .gesture(halfDrag(isTop: isTop))
    }

    private func halfDrag(isTop: Bool) -> some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                isDragging = true
                // Normalize by card height so the shear is size-independent.
                let contribution = value.translation.width / cardSide
                if isTop {
                    topShear = contribution
                } else {
                    bottomShear = contribution
                }
            }
            .onEnded { _ in
                let wasSheared = abs(liveShear) > 0.04
                // Capture the live value as the spring's starting point.
                releasedShear = liveShear
                isDragging = false
                topShear = 0
                bottomShear = 0
                if wasSheared {
                    impactTrigger += 1
                }
                withAnimation(.interpolatingSpring(stiffness: 130, damping: 8.5)) {
                    releasedShear = 0
                }
            }
    }
}
"""###,
        "ges-two-finger-tear-seam": ###"""
import SwiftUI

// MARK: - Two-Finger Rip Seam
//
// Place two fingers and spread (pinch-out) to rip a panel along a stretching
// vertical seam that stress-whitens under tension, then splits into two ragged
// halves that recoil apart and re-seal.
//
// demo == true  -> self-driving PhaseAnimator loop over [.sealed, .stressed, .torn]
// demo == false -> real MagnifyGesture (a pinch-out IS two fingers pulling apart)
//
// The ragged seam offsets are seeded ONCE and never re-rolled per frame, so the
// jag is rock-stable; only the separation/cut position animates. iOS 17.

struct TwoFingerTearSeamView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { geo in
            content(size: geo.size)
                .frame(width: geo.size.width, height: geo.size.height)
                .contentShape(Rectangle())
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    @ViewBuilder
    private func content(size: CGSize) -> some View {
        if demo {
            TwoFingerTearSeamView_DemoRig(size: size)
        } else {
            TwoFingerTearSeamView_InteractiveRig(size: size)
        }
    }
}

// MARK: - Phases

private enum TwoFingerTearSeamView_TearPhase: CaseIterable {
    case sealed, stressed, torn

    /// 0 = sealed, 1 = fully torn.
    var progress: CGFloat {
        switch self {
        case .sealed:   return 0.0
        case .stressed: return 0.42
        case .torn:     return 1.0
        }
    }
}

// MARK: - Demo rig (self-driving, never blank)

private struct TwoFingerTearSeamView_DemoRig: View {
    let size: CGSize
    // One stable seed for the whole lifetime of the tile.
    private let jag = TwoFingerTearSeamView_SeamJag(seed: 0xA17C_5EED, count: 16)

    var body: some View {
        PhaseAnimator(TwoFingerTearSeamView_TearPhase.allCases) { phase in
            TwoFingerTearSeamView_TearPanel(progress: phase.progress, size: size, jag: jag)
        } animation: { phase in
            switch phase {
            case .sealed:   return .easeInOut(duration: 0.5)
            case .stressed: return .easeIn(duration: 0.9)
            case .torn:     return .interpolatingSpring(stiffness: 140, damping: 9)
            }
        }
    }
}

// MARK: - Interactive rig (real two-finger spread)

private struct TwoFingerTearSeamView_InteractiveRig: View {
    let size: CGSize
    private let jag = TwoFingerTearSeamView_SeamJag(seed: 0xA17C_5EED, count: 16)

    @State private var progress: CGFloat = 0
    @State private var committed: Bool = false
    @State private var tearTrigger: Int = 0

    private let threshold: CGFloat = 0.62

    var body: some View {
        TwoFingerTearSeamView_TearPanel(progress: progress, size: size, jag: jag)
            .gesture(spread)
            .sensoryFeedback(.success, trigger: tearTrigger)
            .accessibilityLabel("Rip seam. Spread two fingers to tear.")
    }

    private var spread: some Gesture {
        MagnifyGesture(minimumScaleDelta: 0)
            .onChanged { value in
                guard !committed else { return }
                // pinch-out magnification > 1 => pulling apart
                let pulled = max(value.magnification - 1.0, 0)
                progress = min(pulled * 1.35, 1.0)
            }
            .onEnded { _ in
                if progress >= threshold {
                    committed = true
                    tearTrigger &+= 1
                    withAnimation(.interpolatingSpring(stiffness: 130, damping: 8)) {
                        progress = 1.0
                    }
                    // auto re-seal so the tile stays reusable
                    DispatchQueue.main.asyncAfter(deadline: .now() + 1.1) {
                        withAnimation(.easeInOut(duration: 0.55)) {
                            progress = 0
                        }
                        committed = false
                    }
                } else {
                    withAnimation(.interpolatingSpring(stiffness: 170, damping: 11)) {
                        progress = 0
                    }
                }
            }
    }
}

// MARK: - The torn panel (composition)

private struct TwoFingerTearSeamView_TearPanel: View {
    var progress: CGFloat
    let size: CGSize
    let jag: TwoFingerTearSeamView_SeamJag

    var body: some View {
        let dim = min(size.width, size.height)
        let panelW = min(size.width * 0.78, dim * 1.05)
        let panelH = min(size.height * 0.7, dim * 0.92)
        let corner = panelH * 0.12

        ZStack {
            halves(panelW: panelW, panelH: panelH, corner: corner)
            seamStress(panelW: panelW, panelH: panelH)
        }
        .frame(width: size.width, height: size.height)
    }

    @ViewBuilder
    private func halves(panelW: CGFloat, panelH: CGFloat, corner: CGFloat) -> some View {
        // Max recoil kept well inside the panel so a torn frame is never blank.
        let gap = (panelW * 0.5) * progress   // total opening grows with progress
        let recoilTilt = Double(progress) * 7.0

        ZStack {
            // Left half: ragged on its right (inner) edge.
            half(side: -1, panelW: panelW, panelH: panelH, corner: corner,
                 tilt: -recoilTilt, anchor: .leading, dx: -gap * 0.5, shadowX: -2)

            // Right half: ragged on its left (inner) edge.
            half(side: 1, panelW: panelW, panelH: panelH, corner: corner,
                 tilt: recoilTilt, anchor: .trailing, dx: gap * 0.5, shadowX: 2)
        }
        .overlay(seamLabel(panelH: panelH))
    }

    @ViewBuilder
    private func half(side: CGFloat,
                      panelW: CGFloat,
                      panelH: CGFloat,
                      corner: CGFloat,
                      tilt: Double,
                      anchor: UnitPoint,
                      dx: CGFloat,
                      shadowX: CGFloat) -> some View {
        let shape = TwoFingerTearSeamView_RaggedHalf(progress: progress, side: side, jag: jag, corner: corner)
        shape
            .fill(panelFill)
            .overlay(shape.stroke(edgeStroke, lineWidth: 1))
            .frame(width: panelW, height: panelH)
            .rotationEffect(.degrees(tilt), anchor: anchor)
            .offset(x: dx)
            .shadow(color: .black.opacity(0.35 * progress + 0.12),
                    radius: 6, x: shadowX, y: 4)
    }

    /// Tension/whitening accent that lives over the closing seam.
    @ViewBuilder
    private func seamStress(panelW: CGFloat, panelH: CGFloat) -> some View {
        // Whitening peaks just before the rip, then drops as it opens.
        let stress = stressOpacity(progress)
        let seamWidth = max(2.0, (1.0 - progress) * panelW * 0.05 + 2.0)

        RoundedRectangle(cornerRadius: seamWidth * 0.5)
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 1, green: 1, blue: 1).opacity(0),
                        Color(red: 1, green: 0.98, blue: 0.94),
                        Color(red: 1, green: 1, blue: 1).opacity(0)
                    ],
                    startPoint: .top, endPoint: .bottom
                )
            )
            .frame(width: seamWidth, height: panelH * (1.0 - progress * 0.45))
            .blur(radius: 1.5 + 2.0 * stress)
            .opacity(stress)
            .allowsHitTesting(false)
    }

    @ViewBuilder
    private func seamLabel(panelH: CGFloat) -> some View {
        Image(systemName: "scissors")
            .font(.system(size: panelH * 0.16, weight: .semibold))
            .foregroundStyle(Color(red: 1, green: 1, blue: 1).opacity(0.75 * (1 - progress)))
            .rotationEffect(.degrees(90))
            .opacity(Double(1 - progress))
            .allowsHitTesting(false)
    }

    private func stressOpacity(_ p: CGFloat) -> Double {
        // bell curve peaking near the tear threshold (~0.55)
        let peak: CGFloat = 0.55
        let width: CGFloat = 0.34
        let d = (p - peak) / width
        return Double(min(max(exp(-d * d), 0), 1)) * (p < 0.02 ? 0 : 1)
    }

    private var panelFill: LinearGradient {
        LinearGradient(
            colors: [
                Color(red: 0.36, green: 0.42, blue: 0.86),
                Color(red: 0.55, green: 0.33, blue: 0.78),
                Color(red: 0.86, green: 0.38, blue: 0.55)
            ],
            startPoint: .topLeading, endPoint: .bottomTrailing
        )
    }

    private var edgeStroke: LinearGradient {
        LinearGradient(
            colors: [
                Color(red: 1, green: 1, blue: 1).opacity(0.55),
                Color(red: 1, green: 1, blue: 1).opacity(0.12)
            ],
            startPoint: .top, endPoint: .bottom
        )
    }
}

// MARK: - Ragged half shape (animatable, stable jag)

/// One ragged half of the torn panel.
/// `side == -1` is the LEFT half (its right/inner edge is ragged).
/// `side == +1` is the RIGHT half (its left/inner edge is ragged).
/// `progress` widens the inner cut inward and grows the jag amplitude.
private struct TwoFingerTearSeamView_RaggedHalf: Shape {
    var progress: CGFloat
    let side: CGFloat
    let jag: TwoFingerTearSeamView_SeamJag
    let corner: CGFloat

    var animatableData: CGFloat {
        get { progress }
        set { progress = newValue }
    }

    func path(in rect: CGRect) -> Path {
        var path = Path()

        let centerX = rect.midX
        // How far the ragged edge pulls back from center as the rip opens.
        let pullback = rect.width * 0.30 * progress
        // Jag amplitude grows with tension/opening.
        let amp = rect.width * (0.015 + 0.06 * progress)

        // Inner edge x at a given vertex (toward center, offset by jag).
        func innerX(_ jagUnit: CGFloat) -> CGFloat {
            let base = centerX - side * pullback
            let jitter = side * (jagUnit - 0.4) * amp * 2.0
            return base - jitter
        }

        if side < 0 {
            // LEFT HALF: outer (left) straight edge, ragged right edge.
            path.move(to: CGPoint(x: rect.minX + corner, y: rect.minY))
            // top straight to seam
            path.addLine(to: CGPoint(x: innerX(jag.jag[0]), y: rect.minY))
            // ragged down the inner edge
            for i in 0..<jag.ys.count {
                let y = rect.minY + jag.ys[i] * rect.height
                path.addLine(to: CGPoint(x: innerX(jag.jag[i]), y: y))
            }
            // bottom edge back to outer
            path.addLine(to: CGPoint(x: rect.minX + corner, y: rect.maxY))
            // rounded outer-left corners
            path.addQuadCurve(
                to: CGPoint(x: rect.minX, y: rect.maxY - corner),
                control: CGPoint(x: rect.minX, y: rect.maxY)
            )
            path.addLine(to: CGPoint(x: rect.minX, y: rect.minY + corner))
            path.addQuadCurve(
                to: CGPoint(x: rect.minX + corner, y: rect.minY),
                control: CGPoint(x: rect.minX, y: rect.minY)
            )
        } else {
            // RIGHT HALF: outer (right) straight edge, ragged left edge.
            path.move(to: CGPoint(x: rect.maxX - corner, y: rect.minY))
            path.addLine(to: CGPoint(x: innerX(jag.jag[0]), y: rect.minY))
            for i in 0..<jag.ys.count {
                let y = rect.minY + jag.ys[i] * rect.height
                path.addLine(to: CGPoint(x: innerX(jag.jag[i]), y: y))
            }
            path.addLine(to: CGPoint(x: rect.maxX - corner, y: rect.maxY))
            path.addQuadCurve(
                to: CGPoint(x: rect.maxX, y: rect.maxY - corner),
                control: CGPoint(x: rect.maxX, y: rect.maxY)
            )
            path.addLine(to: CGPoint(x: rect.maxX, y: rect.minY + corner))
            path.addQuadCurve(
                to: CGPoint(x: rect.maxX - corner, y: rect.minY),
                control: CGPoint(x: rect.maxX, y: rect.minY)
            )
        }

        path.closeSubpath()
        return path
    }
}

// MARK: - Stable seeded jag geometry (generated ONCE, not per frame)

private struct TwoFingerTearSeamView_SeamJag {
    /// Normalized (0...1) vertical positions of jag vertices down the seam.
    let ys: [CGFloat]
    /// Per-vertex normalized jag amount (0...1).
    let jag: [CGFloat]

    init(seed: UInt64, count: Int) {
        var rng = TwoFingerTearSeamView_SplitMix64(seed: seed)
        let n = max(count, 6)
        var ys: [CGFloat] = []
        var jag: [CGFloat] = []
        for i in 0...n {
            let t = CGFloat(i) / CGFloat(n)
            let jitter = (rng.unitCGFloat() - 0.5) * (0.7 / CGFloat(n))
            ys.append(min(max(t + jitter, 0), 1))
            jag.append(rng.unitCGFloat())
        }
        self.ys = ys
        self.jag = jag
    }
}

/// Deterministic TwoFingerTearSeamView_SplitMix64 RNG so the ragged edge is identical every frame.
private struct TwoFingerTearSeamView_SplitMix64 {
    private var state: UInt64
    init(seed: UInt64) { state = seed }

    mutating func next() -> UInt64 {
        state &+= 0x9E3779B97F4A7C15
        var z = state
        z = (z ^ (z >> 30)) &* 0xBF58476D1CE4E5B9
        z = (z ^ (z >> 27)) &* 0x94D049BB133111EB
        return z ^ (z >> 31)
    }

    mutating func unitCGFloat() -> CGFloat {
        CGFloat(next() >> 11) / CGFloat(UInt64(1) << 53)
    }
}
"""###,
        "ges-zipper-unzip": ###"""
import SwiftUI

// MARK: - Zipper Unseal
// Drag the pull head downward and interlocking teeth disengage one pair at a
// time right at the moving front, splitting a sealed fabric panel open to
// reveal the content beneath with a faint cloth flex.

struct ZipperUnzipView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { geo in
            if demo {
                ZipperUnzipView_DemoDriver(size: geo.size)
            } else {
                ZipperUnzipView_InteractiveZipper(size: geo.size)
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }
}

// MARK: - Tunables

private enum ZipperUnzipView_Zip {
    static let toothCount: Int = 24
    // Window over which a tooth transitions from interlocked -> splayed,
    // measured in normalized track units. ~1.5x tooth spacing keeps the
    // disengagement reading as a traveling front rather than all-at-once.
    static let window: CGFloat = 0.07
}

// MARK: - Demo driver (self-running, no touch)

private struct ZipperUnzipView_DemoDriver: View {
    let size: CGSize

    var body: some View {
        TimelineView(.animation) { context in
            let front = Self.frontFromTime(context.date)
            ZipperUnzipView_ZipperBody(front: front, size: size, showHint: true)
        }
    }

    // Smoothed triangle wave on a ~3.4s loop with a short dwell at each end
    // so the sealed and fully-open states are both legible.
    private static func frontFromTime(_ date: Date) -> CGFloat {
        let period: Double = 3.4
        let t = date.timeIntervalSinceReferenceDate.truncatingRemainder(dividingBy: period) / period
        // Triangle 0->1->0
        let tri: Double = t < 0.5 ? (t * 2.0) : (2.0 - t * 2.0)
        // Dwell + ease: smoothstep maps a slightly clamped range, so the ends
        // hold briefly and the middle travels smoothly.
        let clamped = min(max((tri - 0.06) / 0.88, 0.0), 1.0)
        let eased = clamped * clamped * (3.0 - 2.0 * clamped)
        return CGFloat(eased)
    }
}

// MARK: - Interactive zipper (real component)

private struct ZipperUnzipView_InteractiveZipper: View {
    let size: CGSize
    @State private var front: CGFloat = 0
    @State private var dragging = false

    private var teethPassed: Int { Int((front * CGFloat(ZipperUnzipView_Zip.toothCount)).rounded(.down)) }

    var body: some View {
        ZipperUnzipView_ZipperBody(front: front, size: size, showHint: front > 0.04)
            .contentShape(Rectangle())
            .gesture(dragGesture)
            .sensoryFeedback(.selection, trigger: teethPassed)
    }

    private var dragGesture: some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                dragging = true
                let h = max(size.height, 1)
                let raw = value.location.y / h
                front = min(max(raw, 0), 1)
            }
            .onEnded { _ in
                dragging = false
                // Settle: spring to whichever end is closer.
                let target: CGFloat = front > 0.5 ? 1 : 0
                withAnimation(.spring(response: 0.5, dampingFraction: 0.72)) {
                    front = target
                }
            }
    }
}

// MARK: - Shared zipper body

private struct ZipperUnzipView_ZipperBody: View {
    let front: CGFloat        // 0 = sealed at top, 1 = fully open
    let size: CGSize
    var showHint: Bool = false

    private var trackWidth: CGFloat { min(size.width, size.height) * 0.10 }
    private var contentInset: CGFloat { min(size.width, size.height) * 0.12 }

    var body: some View {
        ZStack {
            revealedContent
            panels
            teeth
            pullHead
        }
    }

    // MARK: Content beneath the panels

    private var revealedContent: some View {
        RoundedRectangle(cornerRadius: 14, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.20, green: 0.62, blue: 0.86),
                        Color(red: 0.36, green: 0.30, blue: 0.78)
                    ],
                    startPoint: .topLeading,
                    endPoint: .bottomTrailing
                )
            )
            .overlay(alignment: .top) {
                hintLabel
                    .opacity(showHint ? Double(min(front * 1.6, 1.0)) : 0)
                    .padding(.top, size.height * 0.18)
            }
            .padding(contentInset)
    }

    private var hintLabel: some View {
        VStack(spacing: 6) {
            Image(systemName: "sparkles")
                .font(.system(size: min(size.width, size.height) * 0.16, weight: .semibold))
            Text("UNSEALED")
                .font(.system(size: min(size.width, size.height) * 0.07,
                               weight: .heavy, design: .rounded))
                .tracking(2)
        }
        .foregroundStyle(.white.opacity(0.92))
    }

    // MARK: Fabric panels

    private var panels: some View {
        let gap = maxGap * eased(front)
        return ZStack {
            ZipperUnzipView_FabricPanel(front: front, side: .left)
                .fill(panelGradient)
                .overlay(panelSeamShade(side: .left))
            ZipperUnzipView_FabricPanel(front: front, side: .right)
                .fill(panelGradient)
                .overlay(panelSeamShade(side: .right))
        }
        .compositingGroup()
        .shadow(color: .black.opacity(0.28), radius: 6, x: 0, y: 2)
        .accessibilityHidden(true)
        .environment(\.zipGap, gap)
    }

    private var maxGap: CGFloat { size.width * 0.34 }

    private var panelGradient: LinearGradient {
        LinearGradient(
            colors: [
                Color(red: 0.16, green: 0.17, blue: 0.22),
                Color(red: 0.10, green: 0.11, blue: 0.15)
            ],
            startPoint: .top, endPoint: .bottom
        )
    }

    private func panelSeamShade(side: ZipperUnzipView_PanelSide) -> some View {
        // A soft highlight along the inner (seam) edge to suggest folded cloth.
        ZipperUnzipView_FabricPanel(front: front, side: side)
            .stroke(
                LinearGradient(
                    colors: [.white.opacity(0.10), .clear],
                    startPoint: side == .left ? .trailing : .leading,
                    endPoint: side == .left ? .leading : .trailing
                ),
                lineWidth: 2
            )
            .blur(radius: 1)
    }

    // MARK: Teeth

    private var teeth: some View {
        let centerX = size.width / 2
        let topY = contentInset * 0.6
        let bottomY = size.height - contentInset * 0.6
        let span = max(bottomY - topY, 1)
        return ZStack {
            ForEach(0..<ZipperUnzipView_Zip.toothCount, id: \.self) { index in
                let p = CGFloat(index) / CGFloat(max(ZipperUnzipView_Zip.toothCount - 1, 1))
                ZipperUnzipView_ToothPair(
                    openness: openness(for: p),
                    width: trackWidth,
                    parity: index % 2 == 0
                )
                .position(x: centerX, y: topY + p * span)
            }
        }
    }

    // openness: 0 = interlocked at center, 1 = splayed apart.
    // Tooth above the front (p < front) opens; below stays sealed.
    private func openness(for p: CGFloat) -> CGFloat {
        let x = (front - p) / ZipperUnzipView_Zip.window
        return smoothstep(x)
    }

    // MARK: Pull head

    private var pullHead: some View {
        let centerX = size.width / 2
        let topY = contentInset * 0.6
        let bottomY = size.height - contentInset * 0.6
        let y = topY + front * (bottomY - topY)
        let d = trackWidth * 1.9
        return ZStack {
            Capsule(style: .continuous)
                .fill(
                    LinearGradient(
                        colors: [
                            Color(red: 0.90, green: 0.91, blue: 0.95),
                            Color(red: 0.62, green: 0.64, blue: 0.70)
                        ],
                        startPoint: .top, endPoint: .bottom
                    )
                )
                .frame(width: d, height: d * 1.15)
                .overlay(
                    Capsule(style: .continuous)
                        .stroke(.white.opacity(0.5), lineWidth: 1)
                )
            // Pull tab hanging below the slider.
            RoundedRectangle(cornerRadius: 3, style: .continuous)
                .fill(Color(red: 0.74, green: 0.76, blue: 0.82))
                .frame(width: d * 0.34, height: d * 0.7)
                .offset(y: d * 0.85)
        }
        .compositingGroup()
        .shadow(color: .black.opacity(0.4), radius: 3, x: 0, y: 2)
        .position(x: centerX, y: y)
    }

    // MARK: Easing helpers

    private func eased(_ v: CGFloat) -> CGFloat { smoothstep(v) }

    private func smoothstep(_ x: CGFloat) -> CGFloat {
        let c = min(max(x, 0), 1)
        return c * c * (3 - 2 * c)
    }
}

// MARK: - Tooth pair

private struct ZipperUnzipView_ToothPair: View {
    let openness: CGFloat   // 0 interlocked .. 1 splayed
    let width: CGFloat
    let parity: Bool

    var body: some View {
        let toothW = width * 0.92
        let toothH = width * 0.62
        let splay = width * 1.4 * openness
        let rot = Double(openness) * (parity ? 26 : 22)
        HStack(spacing: 0) {
            singleTooth(toothW, toothH)
                .rotationEffect(.degrees(-rot), anchor: .trailing)
                .offset(x: -splay)
            singleTooth(toothW, toothH)
                .rotationEffect(.degrees(rot), anchor: .leading)
                .offset(x: splay)
        }
    }

    private func singleTooth(_ w: CGFloat, _ h: CGFloat) -> some View {
        RoundedRectangle(cornerRadius: h * 0.32, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.86, green: 0.87, blue: 0.92),
                        Color(red: 0.58, green: 0.60, blue: 0.67)
                    ],
                    startPoint: .top, endPoint: .bottom
                )
            )
            .frame(width: w, height: h)
            .overlay(
                RoundedRectangle(cornerRadius: h * 0.32, style: .continuous)
                    .stroke(.black.opacity(0.22), lineWidth: 0.5)
            )
    }
}

// MARK: - Fabric panel shape

private enum ZipperUnzipView_PanelSide { case left, right }

private struct ZipperUnzipView_FabricPanel: Shape, @preconcurrency Animatable {
    var front: CGFloat
    let side: ZipperUnzipView_PanelSide

    var animatableData: CGFloat {
        get { front }
        set { front = newValue }
    }

    func path(in rect: CGRect) -> Path {
        let gap = rect.width * 0.34 * smooth(front)
        let centerX = rect.midX
        let inset: CGFloat = rect.width * 0.06
        let topY = rect.minY + inset
        let botY = rect.maxY - inset
        // Inner seam edge: gathers wider toward the top (where it's open),
        // tapers to the center at the unzip front for a cloth-flex curve.
        var path = Path()
        if side == .left {
            let outer = rect.minX + inset
            path.move(to: CGPoint(x: outer, y: topY))
            // top inner corner pulled left by the gap
            path.addLine(to: CGPoint(x: centerX - gap, y: topY))
            // flex curve down toward the sealed center
            path.addQuadCurve(
                to: CGPoint(x: centerX, y: botY),
                control: CGPoint(x: centerX - gap * 0.55, y: rect.midY)
            )
            path.addLine(to: CGPoint(x: outer, y: botY))
            path.closeSubpath()
        } else {
            let outer = rect.maxX - inset
            path.move(to: CGPoint(x: outer, y: topY))
            path.addLine(to: CGPoint(x: centerX + gap, y: topY))
            path.addQuadCurve(
                to: CGPoint(x: centerX, y: botY),
                control: CGPoint(x: centerX + gap * 0.55, y: rect.midY)
            )
            path.addLine(to: CGPoint(x: outer, y: botY))
            path.closeSubpath()
        }
        return path
    }

    private func smooth(_ x: CGFloat) -> CGFloat {
        let c = min(max(x, 0), 1)
        return c * c * (3 - 2 * c)
    }
}

// MARK: - Environment passthrough (kept lightweight)

private struct ZipperUnzipView_ZipGapKey: EnvironmentKey {
    static let defaultValue: CGFloat = 0
}

private extension EnvironmentValues {
    var zipGap: CGFloat {
        get { self[ZipperUnzipView_ZipGapKey.self] }
        set { self[ZipperUnzipView_ZipGapKey.self] = newValue }
    }
}
"""###,
        "ld-bouncing-payload": ###"""
import SwiftUI

/// Bouncing Payload — a classic squash-and-stretch loader.
///
/// A glossy ball drops under gravity, squashes on floor impact, stretches at the
/// apex, and loses a little height each bounce before auto-resetting and dropping
/// again. A blurred ellipse shadow tightens and darkens as the ball nears the floor.
///
/// - `demo == true`  → self-driving `KeyframeAnimator` loop, no touch required.
/// - `demo == false` → identical bounce loop, plus a sideways fling (`DragGesture`)
///   that adds friction-decayed horizontal travel layered onto the vertical bounce.
struct BouncingPayloadView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { geo in
            BounceStage(size: geo.size, interactive: !demo)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }
}

// MARK: - Keyframe state

/// Normalized animatable state driven by independent keyframe tracks.
/// `y` is normalized height: 1 == resting at the top, 0 == touching the floor.
/// Fields are `Double` so they match `KeyframeTrack`'s expected value type.
private struct BounceState {
    var y: Double = 1        // height fraction (1 top → 0 floor)
    var scaleX: Double = 1   // horizontal scale (squash > 1, stretch < 1)
    var scaleY: Double = 1   // vertical scale   (squash < 1, stretch > 1)
}

// MARK: - Stage

private struct BounceStage: View {
    let size: CGSize
    let interactive: Bool

    // Horizontal fling state (interactive mode only).
    @State private var flingOffset: CGFloat = 0   // committed, settling offset
    @State private var dragOffset: CGFloat = 0     // live finger offset while dragging

    var body: some View {
        let metrics = Metrics(size: size)

        ZStack {
            KeyframeAnimator(
                initialValue: BounceState(),
                repeating: true
            ) { state in
                payload(state: state, metrics: metrics)
            } keyframes: { _ in
                bounceTracks()
            }
        }
        .frame(width: size.width, height: size.height)
        .contentShape(Rectangle())
        .modifier(FlingModifier(
            enabled: interactive,
            metrics: metrics,
            flingOffset: $flingOffset,
            dragOffset: $dragOffset
        ))
    }

    @ViewBuilder
    private func payload(state: BounceState, metrics: Metrics) -> some View {
        let height = state.y                                  // 0…1
        let ballCenterY = metrics.topY + (metrics.floorY - metrics.topY) * (1 - height)
        let xOffset = flingOffset + dragOffset

        ZStack {
            // Shadow rests on the contact line (ball-bottom at impact),
            // so it stays planted beneath the ball rather than floating.
            ShadowBlob(height: height, metrics: metrics)
                .position(x: metrics.centerX + xOffset * 0.85,
                          y: metrics.floorY + metrics.ballRadius * 0.92)

            Ball(scaleX: state.scaleX, scaleY: state.scaleY, radius: metrics.ballRadius)
                .position(x: metrics.centerX + xOffset, y: ballCenterY)
        }
    }
}

// MARK: - Keyframe tracks (the mechanism: independent y / scaleX / scaleY)

@KeyframesBuilder<BounceState>
private func bounceTracks() -> some Keyframes<BounceState> {
        // Vertical height: gravity arcs with damped peaks, ending by easing back
        // up to the top so the loop seam reads as a deliberate rise, not a snap.
        KeyframeTrack(\.y) {
            // Drop 1 (full height) → floor
            CubicKeyframe(0.0, duration: 0.62)
            // Bounce 1 → ~55%
            CubicKeyframe(0.55, duration: 0.42)
            CubicKeyframe(0.0, duration: 0.42)
            // Bounce 2 → ~30%
            CubicKeyframe(0.30, duration: 0.32)
            CubicKeyframe(0.0, duration: 0.32)
            // Bounce 3 → ~13%
            CubicKeyframe(0.13, duration: 0.22)
            CubicKeyframe(0.0, duration: 0.22)
            // Tiny settle hop → ~5%
            CubicKeyframe(0.05, duration: 0.16)
            CubicKeyframe(0.0, duration: 0.16)
            // Reset: rise smoothly back to the top for a seamless loop
            SpringKeyframe(1.0, duration: 0.70, spring: .smooth)
        }

        // Horizontal scale: bulges wide on each floor impact (squash), narrows
        // during the fast fall/rise (stretch), neutral at apex and top.
        KeyframeTrack(\.scaleX) {
            CubicKeyframe(0.86, duration: 0.50)   // stretch thin on the fall
            CubicKeyframe(1.30, duration: 0.12)   // SQUASH wide at impact 1
            CubicKeyframe(0.92, duration: 0.30)   // stretch on rise
            CubicKeyframe(1.00, duration: 0.12)   // apex 1 neutral
            CubicKeyframe(0.92, duration: 0.30)   // stretch on fall
            CubicKeyframe(1.22, duration: 0.10)   // SQUASH impact 2
            CubicKeyframe(0.95, duration: 0.22)   // rise
            CubicKeyframe(1.00, duration: 0.10)   // apex 2
            CubicKeyframe(0.96, duration: 0.22)   // fall
            CubicKeyframe(1.14, duration: 0.08)   // SQUASH impact 3
            CubicKeyframe(1.00, duration: 0.30)   // settle hop
            CubicKeyframe(1.08, duration: 0.08)   // tiny squash
            CubicKeyframe(1.00, duration: 0.78)   // reset neutral
        }

        // Vertical scale: inverse of scaleX — stretches tall on fast travel,
        // flattens on impact. Anchored to the bottom in the Ball view.
        KeyframeTrack(\.scaleY) {
            CubicKeyframe(1.16, duration: 0.50)   // stretch tall on the fall
            CubicKeyframe(0.70, duration: 0.12)   // FLATTEN at impact 1
            CubicKeyframe(1.10, duration: 0.30)   // stretch on rise
            CubicKeyframe(1.00, duration: 0.12)   // apex 1 neutral
            CubicKeyframe(1.10, duration: 0.30)   // stretch on fall
            CubicKeyframe(0.78, duration: 0.10)   // FLATTEN impact 2
            CubicKeyframe(1.06, duration: 0.22)   // rise
            CubicKeyframe(1.00, duration: 0.10)   // apex 2
            CubicKeyframe(1.05, duration: 0.22)   // fall
            CubicKeyframe(0.86, duration: 0.08)   // FLATTEN impact 3
            CubicKeyframe(1.00, duration: 0.30)   // settle hop
            CubicKeyframe(0.92, duration: 0.08)   // tiny flatten
            CubicKeyframe(1.00, duration: 0.78)   // reset neutral
        }
}

// MARK: - Layout metrics

private struct Metrics {
    let size: CGSize
    let ballRadius: CGFloat
    let centerX: CGFloat
    let topY: CGFloat        // ball-center Y at full height
    let floorY: CGFloat      // ball-center Y resting on the floor
    let travelBound: CGFloat // max horizontal travel from center

    init(size: CGSize) {
        self.size = size
        let minDim = min(size.width, size.height)
        let r = max(6, minDim * 0.13)
        self.ballRadius = r
        self.centerX = size.width / 2
        // Floor sits a little above the bottom edge so the shadow has room.
        self.floorY = size.height * 0.80 - r * 0.2
        // Top leaves headroom for the apex stretch.
        self.topY = max(r * 1.2, size.height * 0.16)
        self.travelBound = max(0, size.width / 2 - r * 1.1)
    }
}

// MARK: - Ball

private struct Ball: View {
    let scaleX: CGFloat
    let scaleY: CGFloat
    let radius: CGFloat

    var body: some View {
        Circle()
            .fill(
                RadialGradient(
                    colors: [
                        Color(hexCode: 0xBFF0FF),
                        Color(hexCode: 0x4FC3F7),
                        Color(hexCode: 0x1E73C8),
                        Color(hexCode: 0x0E3F77)
                    ],
                    center: UnitPoint(x: 0.34, y: 0.30),
                    startRadius: radius * 0.05,
                    endRadius: radius * 1.25
                )
            )
            .overlay(specularHighlight)
            .overlay(
                Circle()
                    .strokeBorder(Color.white.opacity(0.18), lineWidth: max(0.5, radius * 0.03))
            )
            .frame(width: radius * 2, height: radius * 2)
            // Bottom anchor so squash reads as weight settling onto the floor.
            .scaleEffect(x: scaleX, y: scaleY, anchor: .bottom)
            .shadow(color: Color(hexCode: 0x0E3F77).opacity(0.45),
                    radius: radius * 0.18, x: 0, y: radius * 0.12)
    }

    private var specularHighlight: some View {
        Ellipse()
            .fill(
                RadialGradient(
                    colors: [Color.white.opacity(0.9), Color.white.opacity(0.0)],
                    center: .center,
                    startRadius: 0,
                    endRadius: radius * 0.55
                )
            )
            .frame(width: radius * 0.9, height: radius * 0.7)
            .offset(x: -radius * 0.28, y: -radius * 0.34)
            .blendMode(.screen)
    }
}

// MARK: - Shadow

private struct ShadowBlob: View {
    let height: CGFloat   // 0 (floor) … 1 (top)
    let metrics: Metrics

    var body: some View {
        // High → wide & faint; near floor → tight & dark.
        let widthFactor = 0.55 + (1 - height) * 0.55      // 0.55 … 1.10
        let opacity = 0.10 + (1 - height) * 0.30          // 0.10 … 0.40
        let w = metrics.ballRadius * 2 * widthFactor
        let h = max(3, metrics.ballRadius * 0.42 * (0.7 + (1 - height) * 0.6))

        Ellipse()
            .fill(
                RadialGradient(
                    colors: [Color.black.opacity(opacity), Color.black.opacity(0.0)],
                    center: .center,
                    startRadius: 0,
                    endRadius: w * 0.55
                )
            )
            .frame(width: w, height: h)
            .blur(radius: metrics.ballRadius * 0.16)
    }
}

// MARK: - Horizontal fling (interactive mode only)

private struct FlingModifier: ViewModifier {
    let enabled: Bool
    let metrics: Metrics
    @Binding var flingOffset: CGFloat
    @Binding var dragOffset: CGFloat

    func body(content: Content) -> some View {
        if enabled {
            content.gesture(flingGesture)
        } else {
            content
        }
    }

    private var flingGesture: some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                // Live follow, clamped to the stage.
                let proposed = flingOffset + value.translation.width
                dragOffset = clamp(proposed) - flingOffset
            }
            .onEnded { value in
                // Project the flick: a sideways flick adds momentum, then the ball
                // travels and settles back toward center while the bounce continues.
                let projected = flingOffset
                    + value.translation.width
                    + value.predictedEndTranslation.width * 0.35
                let landing = clamp(projected)

                dragOffset = 0
                // Quick momentum throw…
                withAnimation(.easeOut(duration: 0.45)) {
                    flingOffset = landing
                }
                // …then a gentle settle back to center, layered on the bounce loop.
                withAnimation(.spring(response: 1.1, dampingFraction: 0.72).delay(0.45)) {
                    flingOffset = 0
                }
            }
    }

    private func clamp(_ x: CGFloat) -> CGFloat {
        min(metrics.travelBound, max(-metrics.travelBound, x))
    }
}

// MARK: - Color hex helper

private extension Color {
    init(hexCode hex: UInt32, alpha: Double = 1.0) {
        let r = Double((hex >> 16) & 0xFF) / 255.0
        let g = Double((hex >> 8) & 0xFF) / 255.0
        let b = Double(hex & 0xFF) / 255.0
        self.init(.sRGB, red: r, green: g, blue: b, opacity: alpha)
    }
}

// MARK: - Preview
"""###,
        "ld-coin-flip-stack": ###"""
import SwiftUI

// MARK: - CoinFlipStackView_Coin Flip Stack
// A single coin flips on its horizontal (X) axis with 3D perspective.
// The heads/tails face swaps at the 90 degree crossing; a foreshortened
// ground shadow stretches and shrinks with cos(angle). In demo mode it
// auto-flips forever; the real component idle-spins AND accepts a vertical
// fling whose release velocity seeds a friction-decayed spin that eases to
// a face-up rest before resuming the idle spin.
struct CoinFlipStackView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { geo in
            CoinFlipStackView_CoinFlipStage(demo: demo, size: geo.size)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }
}

// MARK: - Motion model

private enum CoinFlipStackView_FlipPhase {
    /// Continuous self-driving spin. `velocity` in degrees/sec.
    case idle(startAngle: Double, startTime: TimeInterval, velocity: Double)
    /// Finger is down; angle is held externally via drag translation.
    case dragging(heldAngle: Double)
    /// Friction-decayed fling easing to a face-up target.
    case settling(startAngle: Double, target: Double, startTime: TimeInterval)
}

private struct CoinFlipStackView_CoinMotion {
    var phase: CoinFlipStackView_FlipPhase
    /// Angle captured when a drag begins, so translation is additive.
    var dragAnchor: Double = 0

    /// Closed-form angle as a pure function of the current clock — no
    /// state mutation happens during the view update.
    func angle(at now: TimeInterval) -> Double {
        switch phase {
        case let .idle(startAngle, startTime, velocity):
            return startAngle + velocity * (now - startTime)
        case let .dragging(heldAngle):
            return heldAngle
        case let .settling(startAngle, target, startTime):
            let k: Double = 2.6                 // friction coefficient
            let travel = target - startAngle
            let t = max(0, now - startTime)
            return startAngle + travel * (1 - exp(-k * t))
        }
    }

    /// Once settling has effectively asymptoted, hand back to idle so the
    /// coin keeps gently flipping and never freezes edge-on.
    func advanced(at now: TimeInterval) -> CoinFlipStackView_CoinMotion {
        guard case let .settling(_, target, startTime) = phase else { return self }
        if now - startTime > 2.4 {
            var copy = self
            copy.phase = .idle(startAngle: target, startTime: now, velocity: CoinFlipStackView_CoinMotion.idleVelocity)
            return copy
        }
        return self
    }

    static let idleVelocity: Double = 150   // degrees/sec resting spin
}

// MARK: - Stage (drives angle for both modes)

private struct CoinFlipStackView_CoinFlipStage: View {
    let demo: Bool
    let size: CGSize

    @State private var motion = CoinFlipStackView_CoinMotion(
        phase: .idle(startAngle: 0, startTime: 0, velocity: CoinFlipStackView_CoinMotion.idleVelocity)
    )
    @State private var didSeedIdle = false

    private var coinDiameter: CGFloat {
        min(size.width, size.height) * 0.56
    }

    var body: some View {
        TimelineView(.animation) { context in
            let now = context.date.timeIntervalSinceReferenceDate
            let angle = currentAngle(now: now)
            content(angle: angle, now: now)
        }
        .contentShape(Rectangle())
        .gesture(flingGesture, including: demo ? .none : .all)
        .onAppear {
            guard !didSeedIdle else { return }
            didSeedIdle = true
            let now = Date().timeIntervalSinceReferenceDate
            motion.phase = .idle(startAngle: 0, startTime: now, velocity: CoinFlipStackView_CoinMotion.idleVelocity)
        }
    }

    // MARK: angle source

    private func currentAngle(now: TimeInterval) -> Double {
        if demo {
            // Self-driving: a gentle ease so the flip has a little life,
            // never zero and never blank.
            let speed: Double = 200
            let base = now * speed
            let wobble = sin(now * 0.9) * 14
            return base + wobble
        } else {
            // Promote a finished settle back to idle without mutating
            // state inside the body update.
            let promoted = motion.advanced(at: now)
            if case .idle = promoted.phase, case .settling = motion.phase {
                DispatchQueue.main.async { motion = promoted }
            }
            return motion.angle(at: now)
        }
    }

    // MARK: layout

    @ViewBuilder
    private func content(angle: Double, now: TimeInterval) -> some View {
        let radians = angle * .pi / 180
        let faceFactor = cos(radians)               // +1 heads-flat ... -1 tails-flat
        let edgeFactor = abs(faceFactor)            // 1 flat, 0 edge-on
        let d = coinDiameter

        ZStack {
            CoinFlipStackView_GroundShadow(diameter: d, edgeFactor: edgeFactor)
                .offset(y: d * 0.52)

            CoinFlipStackView_LandingStack(diameter: d)
                .offset(y: d * 0.50)
                .opacity(0.9)

            CoinFlipStackView_Coin(angle: angle, faceFactor: faceFactor, edgeFactor: edgeFactor, diameter: d)
                .offset(y: liftOffset(edgeFactor: edgeFactor, d: d))
        }
        .frame(width: size.width, height: size.height)
    }

    /// A tiny vertical lift while edge-on sells the toss arc.
    private func liftOffset(edgeFactor: CGFloat, d: CGFloat) -> CGFloat {
        -(1 - edgeFactor) * d * 0.06
    }

    // MARK: gesture

    private var flingGesture: some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                if case .dragging = motion.phase {
                    let delta = Double(value.translation.height) * -0.9
                    motion.phase = .dragging(heldAngle: motion.dragAnchor + delta)
                } else {
                    let now = Date().timeIntervalSinceReferenceDate
                    let held = motion.angle(at: now)
                    motion.dragAnchor = held
                    motion.phase = .dragging(heldAngle: held)
                }
            }
            .onEnded { value in
                let now = Date().timeIntervalSinceReferenceDate
                let held: Double
                if case let .dragging(h) = motion.phase { held = h } else { held = motion.angle(at: now) }
                // Upward flick (negative height velocity) spins forward.
                let v0 = Double(value.velocity.height) * -0.9   // deg/sec
                let k: Double = 2.6
                let naturalRest = held + v0 / k
                let target = (naturalRest / 180).rounded() * 180   // nearest face-up
                motion.phase = .settling(startAngle: held, target: target, startTime: now)
            }
    }
}

// MARK: - The coin

private struct CoinFlipStackView_Coin: View {
    let angle: Double
    let faceFactor: Double      // cos(angle)
    let edgeFactor: CGFloat     // abs(cos(angle))
    let diameter: CGFloat

    private var headsVisible: Bool { faceFactor >= 0 }

    var body: some View {
        ZStack {
            // Metallic edge / rim — always present so the coin never reads
            // as a blank line when edge-on.
            CoinFlipStackView_CoinRim(diameter: diameter, edgeFactor: edgeFactor)

            // Heads
            CoinFlipStackView_CoinFace(
                diameter: diameter,
                emblem: "crown.fill",
                base: Color(red: 0.95, green: 0.80, blue: 0.40),
                rim: Color(red: 0.70, green: 0.52, blue: 0.18)
            )
            .opacity(headsVisible ? 1 : 0)

            // Tails — pre-rotated 180 about X so the back face is not mirrored.
            CoinFlipStackView_CoinFace(
                diameter: diameter,
                emblem: "star.fill",
                base: Color(red: 0.82, green: 0.84, blue: 0.90),
                rim: Color(red: 0.45, green: 0.50, blue: 0.60)
            )
            .rotation3DEffect(.degrees(180), axis: (x: 1, y: 0, z: 0))
            .opacity(headsVisible ? 0 : 1)
        }
        .frame(width: diameter, height: diameter)
        .rotation3DEffect(
            .degrees(angle),
            axis: (x: 1, y: 0, z: 0),
            anchor: .center,
            anchorZ: 0,
            perspective: 0.55
        )
        // Top-light specular sweep tied to the face tilt.
        .overlay(specular)
    }

    private var specular: some View {
        Ellipse()
            .fill(
                LinearGradient(
                    colors: [Color.white.opacity(0.32 * Double(edgeFactor)), .clear],
                    startPoint: .top,
                    endPoint: .center
                )
            )
            .frame(width: diameter * 0.7, height: diameter * 0.5)
            .offset(y: -diameter * 0.18)
            .scaleEffect(y: edgeFactor, anchor: .center)
            .rotation3DEffect(.degrees(angle), axis: (x: 1, y: 0, z: 0), perspective: 0.55)
            .allowsHitTesting(false)
            .blendMode(.screen)
    }
}

// MARK: - CoinFlipStackView_Coin face

private struct CoinFlipStackView_CoinFace: View {
    let diameter: CGFloat
    let emblem: String
    let base: Color
    let rim: Color

    var body: some View {
        ZStack {
            Circle()
                .fill(
                    RadialGradient(
                        colors: [base, base.opacity(0.92), rim],
                        center: .init(x: 0.38, y: 0.30),
                        startRadius: diameter * 0.04,
                        endRadius: diameter * 0.62
                    )
                )

            // Angular metallic glint around the disc.
            Circle()
                .strokeBorder(
                    AngularGradient(
                        colors: [
                            Color.white.opacity(0.55), rim.opacity(0.0),
                            Color.white.opacity(0.35), rim.opacity(0.0),
                            Color.white.opacity(0.55)
                        ],
                        center: .center
                    ),
                    lineWidth: diameter * 0.06
                )

            // Inner ring detail.
            Circle()
                .strokeBorder(rim.opacity(0.55), lineWidth: diameter * 0.018)
                .padding(diameter * 0.11)

            Image(systemName: emblem)
                .font(.system(size: diameter * 0.34, weight: .black))
                .foregroundStyle(rim.opacity(0.85))
                .shadow(color: .white.opacity(0.4), radius: 0.5, y: -0.5)
        }
        .frame(width: diameter, height: diameter)
        .clipShape(Circle())
    }
}

// MARK: - Metallic rim (visible edge-on)

private struct CoinFlipStackView_CoinRim: View {
    let diameter: CGFloat
    let edgeFactor: CGFloat   // 1 flat, 0 edge-on

    var body: some View {
        // Thickness reads when the coin turns toward its edge.
        let thickness = diameter * 0.10 * (1 - edgeFactor) + diameter * 0.014
        Capsule()
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.55, green: 0.50, blue: 0.42),
                        Color(red: 0.92, green: 0.88, blue: 0.78),
                        Color(red: 0.50, green: 0.46, blue: 0.40)
                    ],
                    startPoint: .leading,
                    endPoint: .trailing
                )
            )
            .frame(width: diameter, height: max(thickness, diameter * 0.02))
    }
}

// MARK: - Ground shadow

private struct CoinFlipStackView_GroundShadow: View {
    let diameter: CGFloat
    let edgeFactor: CGFloat   // wide when flat, thin when edge-on

    var body: some View {
        let w = diameter * (0.42 + 0.46 * edgeFactor)
        let h = diameter * 0.16
        Ellipse()
            .fill(Color.black.opacity(0.30 + 0.18 * Double(edgeFactor)))
            .frame(width: max(w, diameter * 0.18), height: h)
            .blur(radius: diameter * 0.05)
    }
}

// MARK: - Optional static landing stack (flavor)

private struct CoinFlipStackView_LandingStack: View {
    let diameter: CGFloat

    var body: some View {
        let w = diameter * 0.78
        let t = diameter * 0.07
        VStack(spacing: -t * 0.45) {
            stackCoin(width: w * 0.96, thickness: t, shade: 0.78)
            stackCoin(width: w, thickness: t, shade: 0.86)
            stackCoin(width: w * 0.94, thickness: t, shade: 0.74)
        }
        .opacity(0.85)
    }

    private func stackCoin(width: CGFloat, thickness: CGFloat, shade: Double) -> some View {
        Capsule()
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.62 * shade, green: 0.58 * shade, blue: 0.46 * shade),
                        Color(red: 0.90 * shade, green: 0.84 * shade, blue: 0.62 * shade),
                        Color(red: 0.55 * shade, green: 0.50 * shade, blue: 0.40 * shade)
                    ],
                    startPoint: .leading,
                    endPoint: .trailing
                )
            )
            .frame(width: width, height: thickness)
    }
}
"""###,
        "ld-comet-trail-orbit": ###"""
import SwiftUI

/// Comet Trail — a bright comet head laps an elliptical orbit, accelerating at
/// perihelion (Kepler), trailing a tapering particle tail that always streams
/// radially away from the focal "sun" (solar-wind motif). Fully self-driving;
/// `demo` does not change behavior because the spec's interaction is "auto".
struct CometTrailOrbitView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { _ in
            TimelineView(.animation) { timeline in
                let t = timeline.date.timeIntervalSinceReferenceDate
                Canvas { context, size in
                    drawScene(in: &context, size: size, time: t)
                }
            }
        }
        .background(background)
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // MARK: - Tunables

    private let period: Double = 3.4          // seconds per lap
    private let eccentricity: CGFloat = 0.62  // ellipse + speed variation
    private let trailCount: Int = 46          // particles in the tail
    private let trailStep: Double = 0.018     // time gap between particles (s)
    private let pushDistance: CGFloat = 0.10  // radial anti-focus push per age unit

    private var background: some View {
        // Deep space gradient so the glow reads on the tile and the detail view.
        RadialGradient(
            colors: [
                Color(red: 0.07, green: 0.09, blue: 0.16),
                Color(red: 0.03, green: 0.04, blue: 0.08)
            ],
            center: .center,
            startRadius: 4,
            endRadius: 260
        )
    }

    // MARK: - Geometry

    struct Orbit {
        var center: CGPoint
        var a: CGFloat      // semi-major (x)
        var b: CGFloat      // semi-minor (y)
        var focus: CGPoint  // the "sun"
        var unit: CGFloat   // base size unit for scaling visuals
    }

    private func makeOrbit(size: CGSize) -> Orbit {
        let unit = min(size.width, size.height)
        // Leave margin so the head never clips at aphelion, even in a 120pt tile.
        let a = unit * 0.34
        let b = a * sqrt(max(0.0001, 1 - Double(eccentricity) * Double(eccentricity)))
        let center = CGPoint(x: size.width / 2, y: size.height / 2)
        let c = a * eccentricity                    // center-to-focus distance
        let focus = CGPoint(x: center.x + c, y: center.y)
        return Orbit(center: center, a: a, b: b, focus: focus, unit: unit)
    }

    /// Solve Kepler's equation M = E - e·sinE for the eccentric anomaly E.
    private func solveE(meanAnomaly M: Double) -> Double {
        let e = Double(eccentricity)
        var E = M
        for _ in 0..<5 {
            let f = E - e * sin(E) - M
            let fp = 1 - e * cos(E)
            E -= f / fp
        }
        return E
    }

    /// Position on the orbit for an absolute time, using a Kepler time mapping.
    private func orbitPos(time: Double, orbit: Orbit) -> CGPoint {
        let M = 2 * Double.pi * (time / period)
        let E = solveE(meanAnomaly: M)
        let x = orbit.center.x + orbit.a * CGFloat(cos(E))
        let y = orbit.center.y + orbit.b * CGFloat(sin(E))
        return CGPoint(x: x, y: y)
    }

    // MARK: - Drawing

    private func drawScene(in context: inout GraphicsContext, size: CGSize, time: Double) {
        let orbit = makeOrbit(size: size)

        drawOrbitGuide(in: &context, orbit: orbit)
        drawSun(in: &context, orbit: orbit, time: time)

        // Instantaneous speed (numeric derivative) drives glow + tail length.
        let head = orbitPos(time: time, orbit: orbit)
        let prev = orbitPos(time: time - 0.012, orbit: orbit)
        let speed = hypot(head.x - prev.x, head.y - prev.y)
        let speedNorm = normalizedSpeed(speed, orbit: orbit)

        drawTail(in: &context, orbit: orbit, time: time, speedNorm: speedNorm)
        drawHead(in: &context, at: head, orbit: orbit, speedNorm: speedNorm)
    }

    /// Map raw per-frame displacement into a 0...1 liveliness factor.
    private func normalizedSpeed(_ speed: CGFloat, orbit: Orbit) -> CGFloat {
        let ref = orbit.unit * 0.012
        let v = speed / max(ref, 0.001)
        return min(1, max(0, (v - 0.4) / 1.6))
    }

    private func drawOrbitGuide(in context: inout GraphicsContext, orbit: Orbit) {
        let rect = CGRect(
            x: orbit.center.x - orbit.a,
            y: orbit.center.y - orbit.b,
            width: orbit.a * 2,
            height: orbit.b * 2
        )
        let path = Path(ellipseIn: rect)
        context.stroke(
            path,
            with: .color(Color(red: 0.36, green: 0.42, blue: 0.62).opacity(0.16)),
            style: StrokeStyle(lineWidth: 1, dash: [2, 5])
        )
    }

    private func drawSun(in context: inout GraphicsContext, orbit: Orbit, time: Double) {
        let pulse = 0.5 + 0.5 * sin(time * 2.0)
        let r = orbit.unit * 0.05
        let glowR = r * (2.4 + 0.5 * CGFloat(pulse))
        let glowRect = CGRect(
            x: orbit.focus.x - glowR,
            y: orbit.focus.y - glowR,
            width: glowR * 2,
            height: glowR * 2
        )
        context.fill(
            Path(ellipseIn: glowRect),
            with: .radialGradient(
                Gradient(colors: [
                    Color(red: 1.0, green: 0.78, blue: 0.42).opacity(0.45),
                    Color(red: 1.0, green: 0.6, blue: 0.25).opacity(0.0)
                ]),
                center: orbit.focus,
                startRadius: 0,
                endRadius: glowR
            )
        )
        let coreRect = CGRect(
            x: orbit.focus.x - r,
            y: orbit.focus.y - r,
            width: r * 2,
            height: r * 2
        )
        context.fill(
            Path(ellipseIn: coreRect),
            with: .radialGradient(
                Gradient(colors: [
                    Color(red: 1.0, green: 0.95, blue: 0.8),
                    Color(red: 1.0, green: 0.72, blue: 0.34)
                ]),
                center: orbit.focus,
                startRadius: 0,
                endRadius: r
            )
        )
    }

    private func drawTail(
        in context: inout GraphicsContext,
        orbit: Orbit,
        time: Double,
        speedNorm: CGFloat
    ) {
        // Tail is longer + brighter when the comet moves fast (near perihelion).
        let lengthFactor = 0.55 + 0.45 * speedNorm
        let count = max(8, Int(CGFloat(trailCount) * lengthFactor))
        let push = orbit.unit * pushDistance

        // Draw oldest particle first so the bright young head end paints on top.
        for index in stride(from: count - 1, through: 0, by: -1) {
            let age = Double(index)
            let sampleTime = time - age * trailStep
            let base = orbitPos(time: sampleTime, orbit: orbit)

            // Radial direction away from the focal "sun".
            let dx = base.x - orbit.focus.x
            let dy = base.y - orbit.focus.y
            let len = max(hypot(dx, dy), 0.001)
            let nx = dx / len
            let ny = dy / len

            // Radial anti-focus push dominates so the tail points AWAY from the
            // focus (solar wind) rather than tracing the orbit path.
            let ageNorm = CGFloat(index) / CGFloat(max(1, count - 1))
            let offset = push * ageNorm * (1.0 + 1.4 * speedNorm)
            let pos = CGPoint(x: base.x + nx * offset, y: base.y + ny * offset)

            let fade = pow(1.0 - ageNorm, 1.6)
            let dotR = orbit.unit * (0.026 * fade + 0.004)
            let opacity = Double(fade) * (0.5 + 0.5 * Double(speedNorm))

            let dotRect = CGRect(
                x: pos.x - dotR,
                y: pos.y - dotR,
                width: dotR * 2,
                height: dotR * 2
            )
            let color = tailColor(ageNorm: ageNorm).opacity(opacity)
            context.fill(Path(ellipseIn: dotRect), with: .color(color))
        }
    }

    private func tailColor(ageNorm: CGFloat) -> Color {
        // Hot white-blue near the head, cooling to deep blue at the tip.
        let r = 0.65 + (1.0 - Double(ageNorm)) * 0.35
        let g = 0.78 + (1.0 - Double(ageNorm)) * 0.18
        let b = 1.0
        return Color(red: r, green: g, blue: b)
    }

    private func drawHead(
        in context: inout GraphicsContext,
        at head: CGPoint,
        orbit: Orbit,
        speedNorm: CGFloat
    ) {
        let brightness = 0.6 + 0.4 * speedNorm
        let glowR = orbit.unit * (0.085 + 0.05 * speedNorm)
        let glowRect = CGRect(
            x: head.x - glowR,
            y: head.y - glowR,
            width: glowR * 2,
            height: glowR * 2
        )
        context.fill(
            Path(ellipseIn: glowRect),
            with: .radialGradient(
                Gradient(colors: [
                    Color(red: 0.85, green: 0.93, blue: 1.0).opacity(0.85 * brightness),
                    Color(red: 0.5, green: 0.72, blue: 1.0).opacity(0.0)
                ]),
                center: head,
                startRadius: 0,
                endRadius: glowR
            )
        )
        let coreR = orbit.unit * (0.022 + 0.008 * speedNorm)
        let coreRect = CGRect(
            x: head.x - coreR,
            y: head.y - coreR,
            width: coreR * 2,
            height: coreR * 2
        )
        context.fill(
            Path(ellipseIn: coreRect),
            with: .radialGradient(
                Gradient(colors: [
                    Color(red: 1.0, green: 1.0, blue: 1.0),
                    Color(red: 0.78, green: 0.9, blue: 1.0)
                ]),
                center: head,
                startRadius: 0,
                endRadius: coreR
            )
        )
    }
}
"""###,
        "ld-dna-helix": ###"""
import SwiftUI

/// DNA Helix — two phosphate strands corkscrew as a double helix with base-pair
/// rungs. Each strand node's horizontal position is a sine of its vertical phase,
/// and each rung's width/opacity scales by the cosine of that phase to fake 3D
/// depth, with nearer rungs drawn on top.
///
/// - `demo == true`: a self-driving `TimelineView(.animation)` corkscrews the
///   helix continuously, the depth scaling pulsing the rungs.
/// - `demo == false`: the same idle spin runs, but a horizontal `DragGesture`
///   scrubs the twist phase (move faster to scrub faster, direction sets sign);
///   releasing hands control back to the idle spin with no visible jump.
struct DnaHelixView: View {
    var demo: Bool = false

    // Committed twist accumulated from prior auto segments + finished drags.
    @State private var committedPhase: Double = 0
    // Wall-clock anchor for the current auto-spin segment.
    @State private var segmentStart: Date = .init()
    // Live horizontal drag translation (points) while a finger is down.
    @State private var dragWidth: CGFloat = 0
    // True while a finger is actively scrubbing.
    @State private var dragging: Bool = false

    // Visual constants.
    private let rungCount: Int = 18
    private let autoSpeed: Double = 1.05          // radians / second idle spin
    private let twists: Double = 2.4              // full turns across the height
    private let scrubSensitivity: Double = 0.012  // radians per drag point

    var body: some View {
        GeometryReader { geo in
            let size = geo.size

            TimelineView(.animation) { context in
                let phase = currentPhase(now: context.date)
                helixCanvas(size: size, phase: phase)
            }
            .contentShape(Rectangle())
            .modifier(
                DnaHelixView_ScrubGesture(
                    enabled: !demo,
                    onChanged: { translation in handleDragChanged(translation) },
                    onEnded: { handleDragEnded() }
                )
            )
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // MARK: - Phase bookkeeping (seamless auto <-> drag hand-off)

    private func currentPhase(now: Date) -> Double {
        let auto = dragging ? 0 : now.timeIntervalSince(segmentStart) * autoSpeed
        let scrub = Double(dragWidth) * scrubSensitivity
        return committedPhase + auto + scrub
    }

    private func handleDragChanged(_ translation: CGSize) {
        if !dragging {
            // Lock in the auto-spin accrued up to this instant, then freeze it.
            let elapsed = Date().timeIntervalSince(segmentStart) * autoSpeed
            committedPhase += elapsed
            dragging = true
        }
        dragWidth = translation.width
    }

    private func handleDragEnded() {
        committedPhase += Double(dragWidth) * scrubSensitivity
        dragWidth = 0
        dragging = false
        segmentStart = Date()
    }

    // MARK: - Rendering

    private func helixCanvas(size: CGSize, phase: Double) -> some View {
        Canvas { ctx, canvasSize in
            drawHelix(into: &ctx, size: canvasSize, phase: phase)
        }
    }

    private func drawHelix(into ctx: inout GraphicsContext, size: CGSize, phase: Double) {
        let w: CGFloat = size.width
        let h: CGFloat = size.height
        guard w > 1, h > 1 else { return }

        let centerX: CGFloat = w / 2
        let inset: CGFloat = max(8, min(w, h) * 0.10)
        let amplitude: CGFloat = max(6, (w / 2) - inset)
        let topY: CGFloat = inset
        let usableHeight: CGFloat = max(1, h - inset * 2)
        let freq: Double = twists * 2 * .pi  // radians across normalized [0,1]

        // Build rung descriptors, then sort so the back-facing ones draw first.
        var rungs: [Rung] = []
        rungs.reserveCapacity(rungCount)
        let count = rungCount
        for i in 0..<count {
            let t: Double = count > 1 ? Double(i) / Double(count - 1) : 0.5
            let y: CGFloat = topY + CGFloat(t) * usableHeight
            let angle: Double = t * freq + phase

            // Strand A and B are half a turn apart.
            let offsetA: CGFloat = CGFloat(sin(angle)) * amplitude
            let offsetB: CGFloat = CGFloat(sin(angle + .pi)) * amplitude
            // Depth term from cosine: +1 = front, -1 = back.
            let depth: Double = cos(angle)

            rungs.append(
                Rung(
                    y: y,
                    xA: centerX + offsetA,
                    xB: centerX + offsetB,
                    depth: depth,
                    nodeRadius: nodeRadius(forHeight: h),
                    hue: t
                )
            )
        }

        // Painter's algorithm: smallest depth (furthest back) first.
        rungs.sort { $0.depth < $1.depth }

        for rung in rungs {
            drawRung(rung, into: &ctx, height: h)
        }
    }

    private func drawRung(_ rung: Rung, into ctx: inout GraphicsContext, height: CGFloat) {
        // Map depth (-1...1) to legible, clamped scale & opacity (never blank).
        let norm: Double = (rung.depth + 1) / 2                 // 0 (back) ... 1 (front)
        let scale: CGFloat = CGFloat(0.5 + norm * 0.5)          // 0.5 ... 1.0
        let lineOpacity: Double = 0.22 + norm * 0.55            // 0.22 ... 0.77
        let nodeOpacity: Double = 0.45 + norm * 0.55            // 0.45 ... 1.0

        let nodeR: CGFloat = max(1.5, rung.nodeRadius * scale)
        let lineW: CGFloat = max(1.0, (height * 0.010) * scale)

        // Base-pair rung connecting the two strands.
        var rungPath = Path()
        rungPath.move(to: CGPoint(x: rung.xA, y: rung.y))
        rungPath.addLine(to: CGPoint(x: rung.xB, y: rung.y))
        let strokeColor = rungColor(forHue: rung.hue).opacity(lineOpacity)
        ctx.stroke(rungPath, with: .color(strokeColor), lineWidth: lineW)

        // Strand nodes (phosphate backbone beads). Glow halo + core.
        drawNode(at: CGPoint(x: rung.xA, y: rung.y),
                 radius: nodeR, opacity: nodeOpacity,
                 color: strandColorA, into: &ctx)
        drawNode(at: CGPoint(x: rung.xB, y: rung.y),
                 radius: nodeR, opacity: nodeOpacity,
                 color: strandColorB, into: &ctx)
    }

    private func drawNode(at point: CGPoint,
                          radius: CGFloat,
                          opacity: Double,
                          color: Color,
                          into ctx: inout GraphicsContext) {
        // Soft halo.
        let haloRect = CGRect(
            x: point.x - radius * 1.9,
            y: point.y - radius * 1.9,
            width: radius * 3.8,
            height: radius * 3.8
        )
        let halo = Path(ellipseIn: haloRect)
        ctx.fill(halo, with: .color(color.opacity(opacity * 0.22)))

        // Solid core.
        let coreRect = CGRect(
            x: point.x - radius,
            y: point.y - radius,
            width: radius * 2,
            height: radius * 2
        )
        let core = Path(ellipseIn: coreRect)
        ctx.fill(core, with: .color(color.opacity(opacity)))

        // Tiny specular highlight for a beaded sheen.
        let hiR: CGFloat = radius * 0.42
        let hiRect = CGRect(
            x: point.x - radius * 0.32 - hiR,
            y: point.y - radius * 0.32 - hiR,
            width: hiR * 2,
            height: hiR * 2
        )
        let highlight = Path(ellipseIn: hiRect)
        ctx.fill(highlight, with: .color(Color(red: 1, green: 1, blue: 1).opacity(opacity * 0.55)))
    }

    private func nodeRadius(forHeight h: CGFloat) -> CGFloat {
        max(3, h * 0.028)
    }

    // MARK: - Palette (literals only, no design-system deps)

    private var strandColorA: Color {
        Color(red: 0.30, green: 0.78, blue: 1.00)   // cyan-blue
    }
    private var strandColorB: Color {
        Color(red: 1.00, green: 0.42, blue: 0.62)   // warm pink
    }

    private func rungColor(forHue t: Double) -> Color {
        // Blend the two strand colors so base pairs read as bridges between them.
        let mix = (sin(t * .pi) + 1) / 2
        return Color(
            red: 0.30 + (1.00 - 0.30) * mix,
            green: 0.78 + (0.42 - 0.78) * mix,
            blue: 1.00 + (0.62 - 1.00) * mix
        )
    }

    // MARK: - Rung model

    struct Rung {
        let y: CGFloat
        let xA: CGFloat
        let xB: CGFloat
        let depth: Double
        let nodeRadius: CGFloat
        let hue: Double
    }
}

// MARK: - Conditional drag gesture

/// Attaches a horizontal scrub `DragGesture` only when `enabled`, keeping the
/// rendering path identical in both demo and interactive modes.
private struct DnaHelixView_ScrubGesture: ViewModifier {
    let enabled: Bool
    let onChanged: (CGSize) -> Void
    let onEnded: () -> Void

    func body(content: Content) -> some View {
        if enabled {
            content.gesture(
                DragGesture(minimumDistance: 0)
                    .onChanged { value in onChanged(value.translation) }
                    .onEnded { _ in onEnded() }
            )
        } else {
            content
        }
    }
}
"""###,
        "ld-dot-grid-wave": ###"""
import SwiftUI

// MARK: - Dot Grid Ripple
// A 2D grid of dots pulses in size and brightness as a circular wavefront
// sweeps outward from a moving origin. Each dot is delayed by its distance
// from the wave center. Idle: an auto-emitting origin drifts on a Lissajous
// path. Interactive: taps drop new wavefronts at the finger, layered on top.
struct DotGridWaveView: View {
    var demo: Bool = false

    // Tap-spawned wavefronts: where they started and when (reference-time seconds).
    @State private var waves: [DotGridWaveView_TapWave] = []

    var body: some View {
        GeometryReader { proxy in
            let size = proxy.size
            content(in: size)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .background(Color(red: 0.039, green: 0.063, blue: 0.078))
        .clipped()
    }

    @ViewBuilder
    private func content(in size: CGSize) -> some View {
        TimelineView(.animation) { timeline in
            let now = timeline.date.timeIntervalSinceReferenceDate
            canvas(in: size, now: now)
        }
        .contentShape(Rectangle())
        .modifier(DotGridWaveView_TapWaveModifier(enabled: !demo) { location, when in
            registerTap(at: location, when: when)
        })
    }

    private func canvas(in size: CGSize, now: TimeInterval) -> some View {
        Canvas { context, canvasSize in
            draw(in: &context, size: canvasSize, now: now)
        }
    }

    // MARK: Tap handling

    private func registerTap(at location: CGPoint, when: TimeInterval) {
        // Drop rings that have already finished so the array stays bounded.
        let alive = waves.filter { wave in (when - wave.birth) < DotGridWaveView_TapWave.lifetime }
        var next = alive
        next.append(DotGridWaveView_TapWave(origin: location, birth: when))
        // Hard cap as a safety net for rapid tapping.
        if next.count > 8 {
            next.removeFirst(next.count - 8)
        }
        waves = next
    }

    // MARK: Rendering

    private func draw(in context: inout GraphicsContext, size: CGSize, now: TimeInterval) {
        let layout = DotGridWaveView_GridLayout(size: size)
        guard layout.columns > 0, layout.rows > 0 else { return }

        let drift = driftOrigin(in: size, now: now)
        let baseColor = dotColor()

        for row in 0..<layout.rows {
            for col in 0..<layout.columns {
                let center = layout.point(col: col, row: row)
                let energy = totalEnergy(at: center, now: now, drift: drift)
                drawDot(in: &context,
                        center: center,
                        baseRadius: layout.baseRadius,
                        energy: energy,
                        color: baseColor)
            }
        }
    }

    private func drawDot(in context: inout GraphicsContext,
                         center: CGPoint,
                         baseRadius: CGFloat,
                         energy: CGFloat,
                         color: Color) {
        // energy is 0...1. Keep a floor so the grid is never blank/dark.
        let clamped = max(0.0, min(1.0, energy))
        let radius = baseRadius * (0.55 + 0.85 * clamped)
        let opacity = 0.32 + 0.68 * clamped

        let rect = CGRect(x: center.x - radius,
                          y: center.y - radius,
                          width: radius * 2,
                          height: radius * 2)

        // Soft glow under bright dots for a tactile pegboard feel.
        if clamped > 0.55 {
            let glowR = radius * 2.1
            let glowRect = CGRect(x: center.x - glowR,
                                  y: center.y - glowR,
                                  width: glowR * 2,
                                  height: glowR * 2)
            let glow = color.opacity(0.18 * Double(clamped))
            context.fill(Path(ellipseIn: glowRect), with: .color(glow))
        }

        context.fill(Path(ellipseIn: rect), with: .color(color.opacity(opacity)))
    }

    // MARK: Energy model

    // Combine the always-on idle wavefront with any decaying tap rings.
    private func totalEnergy(at point: CGPoint,
                             now: TimeInterval,
                             drift: CGPoint) -> CGFloat {
        var energy = idleEnergy(at: point, now: now, drift: drift)
        for wave in waves {
            energy += tapEnergy(at: point, now: now, wave: wave)
        }
        return energy
    }

    // Continuous distance-delayed sine radiating from the drifting origin.
    private func idleEnergy(at point: CGPoint,
                            now: TimeInterval,
                            drift: CGPoint) -> CGFloat {
        let dist = distance(point, drift)
        let k: Double = 0.045            // distance -> phase delay
        let speed: Double = 3.4          // radians/sec of the base oscillation
        let phase = now * speed - Double(dist) * k
        let raw = (sin(phase) + 1.0) * 0.5            // 0...1
        // Attenuate with distance so it reads as a wavefront, not a uniform pulse.
        let falloff = 1.0 / (1.0 + Double(dist) * 0.012)
        return CGFloat(raw * falloff * 0.85)
    }

    // A finite ring that expands from the tap and dies within its lifetime.
    private func tapEnergy(at point: CGPoint,
                           now: TimeInterval,
                           wave: DotGridWaveView_TapWave) -> CGFloat {
        let age = now - wave.birth
        if age < 0 || age > DotGridWaveView_TapWave.lifetime { return 0 }

        let dist = Double(distance(point, wave.origin))
        let ringRadius = age * DotGridWaveView_TapWave.ringSpeed
        // Gaussian band centred on the traveling ring radius.
        let band = dist - ringRadius
        let sigma: Double = 26.0
        let ring = exp(-(band * band) / (2.0 * sigma * sigma))
        // Fade the whole ring out over its lifetime (ease-out).
        let lifeFrac = age / DotGridWaveView_TapWave.lifetime
        let decay = pow(1.0 - lifeFrac, 1.6)
        return CGFloat(ring * decay)
    }

    // MARK: Drifting origin

    private func driftOrigin(in size: CGSize, now: TimeInterval) -> CGPoint {
        // Lissajous drift keeps the auto wavefront origin roaming the tile.
        let period: Double = 7.0
        let t = (now.truncatingRemainder(dividingBy: period)) / period * (.pi * 2.0)
        let cx = Double(size.width) * 0.5
        let cy = Double(size.height) * 0.5
        let ax = Double(size.width) * 0.32
        let ay = Double(size.height) * 0.32
        let x = cx + ax * sin(t * 1.0)
        let y = cy + ay * sin(t * 1.4 + .pi / 3.0)
        return CGPoint(x: x, y: y)
    }

    private func dotColor() -> Color {
        // Cool aqua-cyan that reads on the dark tint.
        Color(red: 0.42, green: 0.86, blue: 0.96)
    }

    private func distance(_ a: CGPoint, _ b: CGPoint) -> CGFloat {
        let dx = a.x - b.x
        let dy = a.y - b.y
        return CGFloat((Double(dx * dx) + Double(dy * dy)).squareRoot())
    }
}

// MARK: - Grid layout derived from geometry

private struct DotGridWaveView_GridLayout {
    let columns: Int
    let rows: Int
    let spacing: CGFloat
    let originX: CGFloat
    let originY: CGFloat
    let baseRadius: CGFloat

    init(size: CGSize) {
        let minSide = max(1.0, min(size.width, size.height))
        // Derive a count from width, clamp so both the 120pt tile and a large
        // detail view stay legible and Canvas cost stays bounded.
        let targetSpacing: CGFloat = max(14.0, minSide / 9.0)
        let cols = max(5, min(13, Int((size.width / targetSpacing).rounded())))
        let rws = max(5, min(13, Int((size.height / targetSpacing).rounded())))

        // Spacing that actually fits, then centre the grid.
        let spacingX = cols > 1 ? size.width / CGFloat(cols) : size.width
        let spacingY = rws > 1 ? size.height / CGFloat(rws) : size.height
        let sp = max(8.0, min(spacingX, spacingY))

        self.columns = cols
        self.rows = rws
        self.spacing = sp
        let gridW = sp * CGFloat(cols - 1)
        let gridH = sp * CGFloat(rws - 1)
        self.originX = (size.width - gridW) / 2.0
        self.originY = (size.height - gridH) / 2.0
        self.baseRadius = max(1.5, sp * 0.16)
    }

    func point(col: Int, row: Int) -> CGPoint {
        CGPoint(x: originX + CGFloat(col) * spacing,
                y: originY + CGFloat(row) * spacing)
    }
}

// MARK: - Tap wave model

private struct DotGridWaveView_TapWave: Identifiable {
    let id = UUID()
    let origin: CGPoint
    let birth: TimeInterval

    static let lifetime: Double = 1.8       // seconds a ring stays alive
    static let ringSpeed: Double = 170.0    // points/sec the wavefront expands
}

// MARK: - Conditional tap gesture (interactive mode only)

private struct DotGridWaveView_TapWaveModifier: ViewModifier {
    let enabled: Bool
    let onTap: (CGPoint, TimeInterval) -> Void

    func body(content: Content) -> some View {
        if enabled {
            content.gesture(
                SpatialTapGesture(coordinateSpace: .local)
                    .onEnded { value in
                        onTap(value.location, Date().timeIntervalSinceReferenceDate)
                    }
            )
        } else {
            content
        }
    }
}
"""###,
        "ld-flip-clock-progress": ###"""
import SwiftUI

// Flip-Clock Counter — a split-flap percentage counter (000% → 100%).
// Each digit is two stacked half-tiles. The top half hinges DOWN over the
// bottom with a 3D fold, a hinge-shadow gradient, and a damped overshoot as
// the new glyph snaps into place.
//
// Both demo==true and demo==false are auto-driven (the spec's interaction is
// "auto — same as previewLoop"): there is no gesture. demo loops 0→100→0
// forever; non-demo counts 0→100 once and holds at 100 like a real loader.
//
// Fold convention (the one render-time unknown — flip in ONE place if backward):
//   axis (1,0,0), anchor .bottom on the top flap, NEGATIVE degrees tips the
//   top edge toward the viewer and folds it down to edge-on at the seam.
//   perspective ~0.4 gives the fold depth instead of a flat vertical squash.

struct FlipClockProgressView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { geo in
            let side = min(geo.size.width, geo.size.height)
            TimelineView(.animation) { context in
                let count = currentCount(at: context.date)
                board(count: count, side: side)
                    .frame(width: geo.size.width, height: geo.size.height)
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // MARK: - Driver (stateless, derived from the timeline date)

    /// Continuous percentage in [0, 100], eased.
    private func currentCount(at date: Date) -> Double {
        let t = date.timeIntervalSinceReferenceDate
        if demo {
            // Loop 0→100→0 forever on a ~7s round trip with eased extremes.
            let period: Double = 7.0
            let phase = (t.truncatingRemainder(dividingBy: period)) / period // 0..1
            let triangle = phase < 0.5 ? (phase * 2.0) : (2.0 - phase * 2.0)  // 0→1→0
            return easeInOut(triangle) * 100.0
        } else {
            // Count up over ~4.5s, then hold at 100, then re-arm (real loader semantics).
            let fillDuration: Double = 4.5
            let elapsed = t.truncatingRemainder(dividingBy: fillDuration + 6.0) // long hold
            let progress = min(elapsed / fillDuration, 1.0)
            return easeOutCubic(progress) * 100.0
        }
    }

    private func easeInOut(_ x: Double) -> Double {
        x < 0.5 ? 2.0 * x * x : 1.0 - pow(-2.0 * x + 2.0, 2.0) / 2.0
    }

    private func easeOutCubic(_ x: Double) -> Double {
        1.0 - pow(1.0 - x, 3.0)
    }

    // MARK: - Board

    private func board(count: Double, side: CGFloat) -> some View {
        let digitW = side * 0.215
        let digitH = side * 0.34
        let gap = side * 0.018
        let percentW = side * 0.16

        let hundreds = digitState(count: count, place: 100.0)
        let tens = digitState(count: count, place: 10.0)
        let units = digitState(count: count, place: 1.0)

        return VStack(spacing: 0) {
            HStack(alignment: .center, spacing: gap) {
                FlipClockProgressView_FlipDigit(state: hundreds, width: digitW, height: digitH)
                FlipClockProgressView_FlipDigit(state: tens, width: digitW, height: digitH)
                FlipClockProgressView_FlipDigit(state: units, width: digitW, height: digitH)
                percentTile(width: percentW, height: digitH)
            }
            railShadow(width: digitW * 3 + percentW + gap * 3)
                .frame(height: digitH * 0.10)
        }
    }

    /// Computes the current glyph, the next glyph, and a fold weight w∈[0,1]
    /// for the digit at the given decimal place.
    private func digitState(count: Double, place: Double) -> FlipClockProgressView_DigitState {
        let scaled = count / place
        let floored = floor(scaled)
        let frac = scaled - floored                 // 0..1 progress toward next tick
        let current = Int(floored) % 10
        let next = (current + 1) % 10

        // Only fold in the tail of the fraction so the digit reads steady most
        // of the time, then snaps. Faster places (units) fold often, slower
        // places (hundreds) flip crisply — the desirable odometer look.
        let foldStart: Double = 0.78
        var w: Double = 0.0
        if frac > foldStart {
            w = (frac - foldStart) / (1.0 - foldStart)
        }
        // Above 100 there is no "next" to flip into; freeze the fold.
        let atCeiling = scaled >= 9.999 && place >= 100.0
        if atCeiling { w = 0.0 }

        return FlipClockProgressView_DigitState(current: current, next: next, fold: min(max(w, 0.0), 1.0))
    }

    // MARK: - Static tiles

    private func percentTile(width: CGFloat, height: CGFloat) -> some View {
        ZStack {
            tileBackground
            Text("%")
                .font(.system(size: height * 0.46, weight: .semibold, design: .rounded))
                .foregroundStyle(Self.glyphColor)
            seam.frame(height: 1)
        }
        .frame(width: width, height: height)
        .clipShape(RoundedRectangle(cornerRadius: height * 0.14, style: .continuous))
    }

    private var tileBackground: some View {
        RoundedRectangle(cornerRadius: 8, style: .continuous)
            .fill(Self.tileGradient)
    }

    private var seam: some View {
        Rectangle().fill(Color(red: 0.0, green: 0.0, blue: 0.0).opacity(0.55))
    }

    private func railShadow(width: CGFloat) -> some View {
        Ellipse()
            .fill(
                RadialGradient(
                    colors: [Color(red: 0, green: 0, blue: 0).opacity(0.35),
                             Color(red: 0, green: 0, blue: 0).opacity(0.0)],
                    center: .center, startRadius: 0, endRadius: width * 0.5
                )
            )
            .frame(width: width)
            .blur(radius: 2)
    }

    // MARK: - Shared palette

    static let glyphColor = Color(red: 0.93, green: 0.95, blue: 0.97)

    static let tileGradient = LinearGradient(
        colors: [Color(red: 0.13, green: 0.16, blue: 0.20),
                 Color(red: 0.07, green: 0.09, blue: 0.12)],
        startPoint: .top, endPoint: .bottom
    )
}

// MARK: - Digit state

private struct FlipClockProgressView_DigitState: Equatable {
    var current: Int
    var next: Int
    var fold: Double   // 0 = steady on `current`, 1 = fully folded to `next`
}

// MARK: - A single flapping digit

private struct FlipClockProgressView_FlipDigit: View {
    let state: FlipClockProgressView_DigitState
    let width: CGFloat
    let height: CGFloat

    var body: some View {
        ZStack {
            staticLayers
            if state.fold > 0.0001 {
                flaps
            }
            seamLine
        }
        .frame(width: width, height: height)
        .clipShape(RoundedRectangle(cornerRadius: height * 0.14, style: .continuous))
        .shadow(color: Color(red: 0, green: 0, blue: 0).opacity(0.3),
                radius: 3, x: 0, y: 2)
    }

    // Static backdrop.
    // Bottom half: always CURRENT (covered by the NEXT bottom flap as it lands,
    // then revealed once the tick increments and CURRENT becomes the new value).
    // Top half: CURRENT while resting (so a steady digit reads correctly on every
    // frame), switching to NEXT only while folding — the moment the top flap lifts
    // away it reveals NEXT behind it. Gating this on `folding` is essential: with
    // a bare NEXT here, a resting digit would show next-on-top / current-on-bottom.
    private var staticLayers: some View {
        let folding = state.fold > 0.0001
        return VStack(spacing: 0) {
            FlipClockProgressView_HalfTile(digit: folding ? state.next : state.current,
                     half: .top, width: width, height: height)
            FlipClockProgressView_HalfTile(digit: state.current, half: .bottom, width: width, height: height)
        }
    }

    // The two moving flaps. Each flap is exactly one half-tile (height/2 tall),
    // pinned to its seam edge inside the full-tile frame so the hinge anchor
    // lands on the center seam.
    private var flaps: some View {
        let w = state.fold
        // Phase 1 (w 0→0.5): top flap (CURRENT top) folds 0 → -90, anchored at bottom (seam).
        // Phase 2 (w 0.5→1): bottom flap (NEXT bottom) folds 90 → 0 with overshoot, anchored at top (seam).
        let topProgress = min(w / 0.5, 1.0)                 // 0..1
        let topAngle = -90.0 * topProgress                  // 0 → -90 (toward viewer, down)
        let topVisible = w < 0.5

        let bottomProgress = max((w - 0.5) / 0.5, 0.0)      // 0..1
        let bottomAngle = 90.0 * (1.0 - overshoot(bottomProgress)) // 90 → ~bounce → 0
        let bottomVisible = w >= 0.5

        return ZStack {
            // Top flap: shows CURRENT top, hinged at its bottom edge (the seam).
            if topVisible {
                topFlap(progress: topProgress, angle: topAngle)
            }
            // Bottom flap: shows NEXT bottom, hinged at its top edge, dropping in.
            if bottomVisible {
                bottomFlap(progress: bottomProgress, angle: bottomAngle)
            }
        }
        .frame(width: width, height: height)
    }

    // The flap is the native half-tile (height/2 tall). The rotation anchor
    // refers to the HALF-TILE's own bounds — so .bottom == the seam edge — and
    // only AFTER rotating do we pin it into the top half of the full tile.
    private func topFlap(progress: Double, angle: Double) -> some View {
        FlipClockProgressView_HalfTile(digit: state.current, half: .top, width: width, height: height)
            .overlay { hingeShade(startTop: false, opacity: progress * 0.75) }
            .rotation3DEffect(
                .degrees(angle),
                axis: (x: 1, y: 0, z: 0),
                anchor: .bottom,
                perspective: 0.4
            )
            .frame(width: width, height: height, alignment: .top)
    }

    private func bottomFlap(progress: Double, angle: Double) -> some View {
        FlipClockProgressView_HalfTile(digit: state.next, half: .bottom, width: width, height: height)
            .overlay { hingeShade(startTop: true, opacity: (1.0 - progress) * 0.75) }
            .rotation3DEffect(
                .degrees(angle),
                axis: (x: 1, y: 0, z: 0),
                anchor: .top,
                perspective: 0.4
            )
            .frame(width: width, height: height, alignment: .bottom)
    }

    // Damped-cosine landing bounce: a value that races to 1, OVERSHOOTS past it
    // (so bottomAngle = 90·(1-overshoot) swings slightly negative — the flap dips
    // below level), then settles back to 1. This is the spec's mechanical spring
    // bounce, baked into the easing curve since a frame-computed TimelineView
    // can't fire a real .spring().
    private func overshoot(_ p: Double) -> Double {
        if p >= 1.0 { return 1.0 }
        let decay = exp(-5.0 * p)
        return 1.0 - decay * cos(6.0 * p)
    }

    private var seamLine: some View {
        Rectangle()
            .fill(Color(red: 0, green: 0, blue: 0).opacity(0.55))
            .frame(height: 1)
    }

    // Hinge shadow: darkens the flap toward the seam edge as it folds, then
    // lifts as it lands. `startTop == true` darkens the top edge (bottom flap),
    // false darkens the bottom edge (top flap).
    private func hingeShade(startTop: Bool, opacity: Double) -> some View {
        LinearGradient(
            colors: [Color(red: 0, green: 0, blue: 0).opacity(opacity),
                     Color(red: 0, green: 0, blue: 0).opacity(0.0)],
            startPoint: startTop ? .top : .bottom,
            endPoint: startTop ? .bottom : .top
        )
    }
}

// MARK: - Half tile (top or bottom clip of a glyph)

private enum FlipClockProgressView_TileHalf { case top, bottom }

private struct FlipClockProgressView_HalfTile: View {
    let digit: Int
    let half: FlipClockProgressView_TileHalf
    let width: CGFloat
    let height: CGFloat

    var body: some View {
        ZStack {
            RoundedRectangle(cornerRadius: 0, style: .continuous)
                .fill(FlipClockProgressView.tileGradient)
            // Glyph centered in the FULL tile, then the half is cropped.
            Text(String(digit))
                .font(.system(size: height * 0.62, weight: .semibold, design: .rounded))
                .foregroundStyle(FlipClockProgressView.glyphColor)
                .frame(width: width, height: height)
            // A subtle top-edge highlight on the upper half for the curved plastic look.
            if half == .top {
                LinearGradient(
                    colors: [Color(red: 1, green: 1, blue: 1).opacity(0.10),
                             Color(red: 1, green: 1, blue: 1).opacity(0.0)],
                    startPoint: .top, endPoint: .bottom
                )
            }
        }
        // Crop to the requested half: pin the full-size content to top/bottom,
        // shrink the frame to half-height, then clip. (Clip lives INSIDE the
        // half-tile; rotation is applied later in the assembly — never after clip.)
        .frame(width: width, height: height, alignment: half == .top ? .top : .bottom)
        .frame(width: width, height: height / 2.0,
               alignment: half == .top ? .top : .bottom)
        .clipped()
    }
}
"""###,
        "ld-folding-origami": ###"""
import SwiftUI

/// Origami Fold — a flat square creases and folds along its diagonals through a
/// short scripted sequence into a peaked, crane-like paper form, then unfolds
/// back to flat and loops. Triangular facets are Paths; each facet rotates in 3D
/// about its shared crease edge (axis = crease direction, anchor = crease
/// midpoint, both in one shared full-square coordinate space) so facets stay
/// attached. Per-facet brightness tracks the fold angle to fake directional
/// paper lighting.
///
/// Both demo and interactive modes are self-driving (the spec is `auto`); the
/// interactive build simply breathes on a slightly slower cadence.
struct FoldingOrigamiView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { geo in
            let side = min(geo.size.width, geo.size.height)
            let paper = side * 0.66

            TimelineView(.animation) { timeline in
                let t = phase(at: timeline.date)
                ZStack {
                    FoldingOrigamiView_OrigamiBackdrop()
                    FoldingOrigamiView_OrigamiPaper(progress: t, side: paper)
                        .frame(width: paper, height: paper)
                }
                .frame(maxWidth: .infinity, maxHeight: .infinity)
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // Normalized loop phase 0...1. Slightly slower / calmer cadence in the
    // larger interactive surface so the detail view reads as more deliberate.
    private func phase(at date: Date) -> CGFloat {
        let period: Double = demo ? 4.0 : 5.0
        let secs = date.timeIntervalSinceReferenceDate
        return CGFloat((secs.truncatingRemainder(dividingBy: period)) / period)
    }
}

// MARK: - Backdrop

private struct FoldingOrigamiView_OrigamiBackdrop: View {
    var body: some View {
        RadialGradient(
            colors: [
                Color(red: 0.10, green: 0.13, blue: 0.17),
                Color(red: 0.04, green: 0.05, blue: 0.07)
            ],
            center: .center,
            startRadius: 4,
            endRadius: 220
        )
        .ignoresSafeArea()
    }
}

// MARK: - Paper assembly

private struct FoldingOrigamiView_OrigamiPaper: View {
    let progress: CGFloat   // 0...1 loop phase
    let side: CGFloat

    var body: some View {
        // Stage envelope: 0 flat → fold in → hold → unfold → flat.
        let fold = foldEnvelope(progress)        // 0 flat ... 1 fully folded
        let lift = liftEnvelope(progress)        // secondary wing lift, lags fold

        ZStack {
            // The flat base sheet (underside of the paper). Always visible so the
            // tile is never blank; it recedes as the facets fold up over it.
            baseSheet(fold: fold)

            // Four corner facets fold inward toward the center (blintz base).
            cornerFacet(.topLeft, fold: fold)
            cornerFacet(.topRight, fold: fold)
            cornerFacet(.bottomRight, fold: fold)
            cornerFacet(.bottomLeft, fold: fold)

            // Two upper petals lift further to suggest the crane's wings/neck.
            wingFacet(leading: true, fold: fold, lift: lift)
            wingFacet(leading: false, fold: fold, lift: lift)

            // A small crisp crease highlight along the central diagonals.
            creaseLines(fold: fold)
        }
        .compositingGroup()
        .shadow(color: .black.opacity(0.35 * Double(fold) + 0.08),
                radius: 10 * fold + 3, x: 0, y: 6 * fold + 2)
    }

    // MARK: Base sheet

    @ViewBuilder
    private func baseSheet(fold: CGFloat) -> some View {
        let shade = 0.52 - 0.14 * Double(fold)
        RoundedRectangle(cornerRadius: 2)
            .fill(paperColor(brightness: shade))
            .overlay(
                RoundedRectangle(cornerRadius: 2)
                    .strokeBorder(Color.white.opacity(0.06), lineWidth: 0.5)
            )
            .scaleEffect(1.0 - 0.04 * fold)
    }

    // MARK: FoldingOrigamiView_Corner facets (blintz fold)

    private func cornerFacet(_ corner: FoldingOrigamiView_Corner, fold: CGFloat) -> some View {
        // Each corner triangle folds toward the viewer about its inner chord.
        let angle = Double(fold) * 168.0            // up to a steep tuck
        let bright = facetBrightness(base: 0.74, angle: angle, swing: 0.30)

        return FoldingOrigamiView_CornerTriangle(corner: corner)
            .fill(
                LinearGradient(
                    colors: [
                        paperColor(brightness: bright + 0.08),
                        paperColor(brightness: bright - 0.06)
                    ],
                    startPoint: corner.gradientStart,
                    endPoint: corner.gradientEnd
                )
            )
            .overlay(
                FoldingOrigamiView_CornerTriangle(corner: corner)
                    .stroke(Color.white.opacity(0.10), lineWidth: 0.5)
            )
            .rotation3DEffect(
                .degrees(angle),
                axis: corner.creaseAxis,
                anchor: corner.creaseAnchor,
                anchorZ: 0,
                perspective: 0.45
            )
    }

    // MARK: Wing petals (secondary lift for crane silhouette)

    private func wingFacet(leading: Bool, fold: CGFloat, lift: CGFloat) -> some View {
        let angle = Double(lift) * 128.0
        let bright = facetBrightness(base: 0.82, angle: angle, swing: 0.34)
        let axis: (CGFloat, CGFloat, CGFloat) = leading ? (1, 1, 0) : (1, -1, 0)
        // Both petals hinge on the shared neck crease at the top-center point,
        // so they stay joined while tilting to opposite sides.
        let anchor = UnitPoint(x: 0.5, y: 0.18)

        return FoldingOrigamiView_WingTriangle(leading: leading)
            .fill(
                LinearGradient(
                    colors: [
                        paperColor(brightness: bright + 0.10),
                        paperColor(brightness: bright - 0.04)
                    ],
                    startPoint: .top,
                    endPoint: .bottom
                )
            )
            .overlay(
                FoldingOrigamiView_WingTriangle(leading: leading)
                    .stroke(Color.white.opacity(0.12), lineWidth: 0.5)
            )
            .rotation3DEffect(
                .degrees(angle),
                axis: axis,
                anchor: anchor,
                anchorZ: 0,
                perspective: 0.5
            )
            .opacity(0.35 + 0.65 * Double(fold))   // emerge as the base folds
    }

    // MARK: Crease detailing

    @ViewBuilder
    private func creaseLines(fold: CGFloat) -> some View {
        FoldingOrigamiView_DiagonalCreases()
            .stroke(Color.white.opacity(0.10 + 0.10 * Double(fold)), lineWidth: 0.6)
            .blendMode(.screen)
    }

    // MARK: Lighting + color helpers

    // Brightness as a function of the fold angle: flat-facing (0°/180°) is
    // brightest, edge-on (90°) is darkest — mimics paper catching the light.
    private func facetBrightness(base: Double, angle: Double, swing: Double) -> Double {
        let rad = angle * .pi / 180.0
        // |cos| peaks when the facet faces the camera, dips when edge-on.
        let facing = abs(cos(rad))
        return base - swing * (1.0 - facing)
    }

    // Warm paper / cream tinted toward the catalog's cool ink at low brightness.
    private func paperColor(brightness b: Double) -> Color {
        let v = max(0.0, min(1.0, b))
        let r = 0.30 + 0.66 * v
        let g = 0.40 + 0.55 * v
        let bl = 0.52 + 0.40 * v
        return Color(red: r, green: g, blue: bl)
    }

    // MARK: Fold envelopes

    // fold-in (0→1) over first 35%, hold to 55%, unfold to 90%, flat rest.
    private func foldEnvelope(_ t: CGFloat) -> CGFloat {
        if t < 0.35 {
            return easeInOut(t / 0.35)
        } else if t < 0.55 {
            return 1.0
        } else if t < 0.90 {
            return 1.0 - easeInOut((t - 0.55) / 0.35)
        } else {
            return 0.0
        }
    }

    // Wing lift lags the base fold and resolves later, then releases first.
    private func liftEnvelope(_ t: CGFloat) -> CGFloat {
        if t < 0.18 {
            return 0.0
        } else if t < 0.45 {
            return easeInOut((t - 0.18) / 0.27)
        } else if t < 0.55 {
            return 1.0
        } else if t < 0.82 {
            return 1.0 - easeInOut((t - 0.55) / 0.27)
        } else {
            return 0.0
        }
    }

    private func easeInOut(_ x: CGFloat) -> CGFloat {
        let c = max(0, min(1, x))
        return c * c * (3 - 2 * c)
    }
}

// MARK: - FoldingOrigamiView_Corner geometry

private enum FoldingOrigamiView_Corner {
    case topLeft, topRight, bottomRight, bottomLeft

    // Triangle vertices in unit space (0...1) of the FULL square frame.
    var vertices: (CGPoint, CGPoint, CGPoint) {
        switch self {
        case .topLeft:
            return (CGPoint(x: 0, y: 0), CGPoint(x: 0.5, y: 0), CGPoint(x: 0, y: 0.5))
        case .topRight:
            return (CGPoint(x: 1, y: 0), CGPoint(x: 0.5, y: 0), CGPoint(x: 1, y: 0.5))
        case .bottomRight:
            return (CGPoint(x: 1, y: 1), CGPoint(x: 1, y: 0.5), CGPoint(x: 0.5, y: 1))
        case .bottomLeft:
            return (CGPoint(x: 0, y: 1), CGPoint(x: 0, y: 0.5), CGPoint(x: 0.5, y: 1))
        }
    }

    // Crease = the inner chord (the hypotenuse facing the center). The rotation
    // axis is the crease's direction vector; anchor is the crease midpoint —
    // both expressed in the shared full-frame unit space so facets stay joined.
    var creaseAxis: (CGFloat, CGFloat, CGFloat) {
        switch self {
        case .topLeft:     return (1, -1, 0)   // (0.5,0)→(0,0.5)
        case .topRight:    return (1, 1, 0)    // (0.5,0)→(1,0.5)
        case .bottomRight: return (1, -1, 0)   // (1,0.5)→(0.5,1)
        case .bottomLeft:  return (1, 1, 0)    // (0,0.5)→(0.5,1)
        }
    }

    var creaseAnchor: UnitPoint {
        switch self {
        case .topLeft:     return UnitPoint(x: 0.25, y: 0.25)
        case .topRight:    return UnitPoint(x: 0.75, y: 0.25)
        case .bottomRight: return UnitPoint(x: 0.75, y: 0.75)
        case .bottomLeft:  return UnitPoint(x: 0.25, y: 0.75)
        }
    }

    var gradientStart: UnitPoint {
        switch self {
        case .topLeft:     return .topLeading
        case .topRight:    return .topTrailing
        case .bottomRight: return .bottomTrailing
        case .bottomLeft:  return .bottomLeading
        }
    }

    var gradientEnd: UnitPoint {
        switch self {
        case .topLeft:     return .center
        case .topRight:    return .center
        case .bottomRight: return .center
        case .bottomLeft:  return .center
        }
    }
}

private struct FoldingOrigamiView_CornerTriangle: Shape {
    let corner: FoldingOrigamiView_Corner

    func path(in rect: CGRect) -> Path {
        let (a, b, c) = corner.vertices
        var p = Path()
        p.move(to: scale(a, rect))
        p.addLine(to: scale(b, rect))
        p.addLine(to: scale(c, rect))
        p.closeSubpath()
        return p
    }

    private func scale(_ pt: CGPoint, _ rect: CGRect) -> CGPoint {
        CGPoint(x: rect.minX + pt.x * rect.width,
                y: rect.minY + pt.y * rect.height)
    }
}

// MARK: - Wing petals

// Two upper triangular petals sharing the top crease, lifting to read as the
// crane's neck/wings. Anchored on their lower crease near the top of the sheet.
private struct FoldingOrigamiView_WingTriangle: Shape {
    let leading: Bool

    func path(in rect: CGRect) -> Path {
        let w = rect.width
        let h = rect.height
        var p = Path()
        if leading {
            p.move(to: CGPoint(x: rect.minX + 0.5 * w, y: rect.minY + 0.18 * h))
            p.addLine(to: CGPoint(x: rect.minX + 0.18 * w, y: rect.minY + 0.06 * h))
            p.addLine(to: CGPoint(x: rect.minX + 0.5 * w, y: rect.minY + 0.55 * h))
        } else {
            p.move(to: CGPoint(x: rect.minX + 0.5 * w, y: rect.minY + 0.18 * h))
            p.addLine(to: CGPoint(x: rect.minX + 0.82 * w, y: rect.minY + 0.06 * h))
            p.addLine(to: CGPoint(x: rect.minX + 0.5 * w, y: rect.minY + 0.55 * h))
        }
        p.closeSubpath()
        return p
    }
}

// MARK: - Crease lines

private struct FoldingOrigamiView_DiagonalCreases: Shape {
    func path(in rect: CGRect) -> Path {
        var p = Path()
        // The inscribed diamond (corner-fold creases).
        p.move(to: CGPoint(x: rect.midX, y: rect.minY))
        p.addLine(to: CGPoint(x: rect.maxX, y: rect.midY))
        p.addLine(to: CGPoint(x: rect.midX, y: rect.maxY))
        p.addLine(to: CGPoint(x: rect.minX, y: rect.midY))
        p.closeSubpath()
        // Both main diagonals.
        p.move(to: CGPoint(x: rect.minX, y: rect.minY))
        p.addLine(to: CGPoint(x: rect.maxX, y: rect.maxY))
        p.move(to: CGPoint(x: rect.maxX, y: rect.minY))
        p.addLine(to: CGPoint(x: rect.minX, y: rect.maxY))
        return p
    }
}
"""###,
        "ld-gear-train": ###"""
import SwiftUI

/// A train of three meshed gears with mathematically correct tooth counts,
/// pitch radii and inverse-ratio rotation. Gear 1 drives gear 2 (counter-
/// rotating) which drives gear 3. In `demo` mode a TimelineView cranks the
/// drive gear automatically; otherwise a RotationGesture (or drag around the
/// hub) lets you turn the whole mechanism by hand and the spin resumes on
/// release.
struct GearTrainView: View {
    var demo: Bool = false

    // Tooth counts for the three meshed gears (the "train").
    private let teeth: [Int] = [12, 20, 14]

    // Idle spin rate: ~1 revolution every 3 seconds for the drive gear.
    private let speed: CGFloat = 2 * .pi / 3

    // Committed drive-gear angle (radians) + the live gesture delta layered on
    // top while cranking. Splitting them keeps the release handoff seamless.
    @State private var committedAngle: CGFloat = 0
    @State private var liveDelta: CGFloat = 0
    @State private var isCranking: Bool = false
    @State private var startAngle: CGFloat = 0
    // Reference time the idle spin is anchored to; re-anchored on release so
    // the gear never teleports when the auto-spin resumes.
    @State private var spinAnchor: TimeInterval = 0

    var body: some View {
        GeometryReader { geo in
            let layout = GearTrainView_GearLayout(size: geo.size, teeth: teeth)
            ZStack {
                backdrop
                if demo {
                    autoDrivenTrain(layout)
                } else {
                    interactiveTrain(layout)
                }
            }
            .frame(width: geo.size.width, height: geo.size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .background(Color(red: 0.039, green: 0.063, blue: 0.078))
    }

    // MARK: - Backdrop

    private var backdrop: some View {
        RadialGradient(
            colors: [
                Color(red: 0.10, green: 0.13, blue: 0.16),
                Color(red: 0.039, green: 0.063, blue: 0.078)
            ],
            center: .center,
            startRadius: 2,
            endRadius: 260
        )
    }

    // MARK: - Demo (self-driving) variant

    private func autoDrivenTrain(_ layout: GearTrainView_GearLayout) -> some View {
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            let theta = CGFloat(t) * speed
            trainBody(layout: layout, driveAngle: theta)
        }
    }

    // MARK: - Interactive variant

    private func interactiveTrain(_ layout: GearTrainView_GearLayout) -> some View {
        // The gesture lives on the stable container (outside TimelineView) so
        // the in-flight recognizer is preserved across frames; the timeline
        // only reads state to draw.
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            let idle = isCranking ? 0 : CGFloat(t - spinAnchor) * speed
            let theta = committedAngle + liveDelta + idle
            trainBody(layout: layout, driveAngle: theta)
        }
        .contentShape(Rectangle())
        .gesture(crankGesture(layout: layout))
    }

    private func crankGesture(layout: GearTrainView_GearLayout) -> some Gesture {
        // Drag around the drive hub: the angle swept from the hub to the finger
        // becomes the live crank delta. minimumDistance 0 so the piece wins
        // inside a ScrollView.
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                if !isCranking {
                    // Fold the idle spin accrued so far into committed so the
                    // gear does not jump when the crank engages.
                    let now = Date().timeIntervalSinceReferenceDate
                    committedAngle += CGFloat(now - spinAnchor) * speed
                    isCranking = true
                    startAngle = hubAngle(of: value.startLocation, hub: layout.center(0))
                }
                let current = hubAngle(of: value.location, hub: layout.center(0))
                liveDelta = angularDifference(from: startAngle, to: current)
            }
            .onEnded { _ in
                committedAngle += liveDelta
                liveDelta = 0
                // Re-anchor the idle clock so the auto-spin resumes from the
                // current angle instead of teleporting.
                spinAnchor = Date().timeIntervalSinceReferenceDate
                isCranking = false
            }
    }

    private func hubAngle(of point: CGPoint, hub: CGPoint) -> CGFloat {
        atan2(point.y - hub.y, point.x - hub.x)
    }

    /// Smallest signed difference so crossing the ±π seam does not snap.
    private func angularDifference(from a: CGFloat, to b: CGFloat) -> CGFloat {
        var d = b - a
        while d > .pi { d -= 2 * .pi }
        while d < -.pi { d += 2 * .pi }
        return d
    }

    // MARK: - Shared train body

    private func trainBody(layout: GearTrainView_GearLayout, driveAngle theta: CGFloat) -> some View {
        let r2 = layout.rotation(forGear: 1, driveAngle: theta)
        let r3 = layout.rotation(forGear: 2, driveAngle: theta)
        return ZStack {
            gearView(index: 1, layout: layout, angle: r2,
                     body: Color(red: 0.36, green: 0.44, blue: 0.52),
                     edge: Color(red: 0.52, green: 0.62, blue: 0.70))
            gearView(index: 2, layout: layout, angle: r3,
                     body: Color(red: 0.78, green: 0.55, blue: 0.28),
                     edge: Color(red: 0.92, green: 0.70, blue: 0.40))
            gearView(index: 0, layout: layout, angle: theta,
                     body: Color(red: 0.20, green: 0.62, blue: 0.74),
                     edge: Color(red: 0.42, green: 0.84, blue: 0.94))
        }
    }

    // MARK: - One gear

    private func gearView(index: Int, layout: GearTrainView_GearLayout, angle: CGFloat,
                          body: Color, edge: Color) -> some View {
        let center = layout.center(index)
        let outer = layout.tipRadius(index)
        let count = teeth[index]
        return ZStack {
            GearTrainView_GearShape(toothCount: count, geometry: layout.geometry(index))
                .fill(
                    LinearGradient(
                        colors: [edge, body],
                        startPoint: .topLeading,
                        endPoint: .bottomTrailing
                    )
                )
                .overlay(
                    GearTrainView_GearShape(toothCount: count, geometry: layout.geometry(index))
                        .stroke(edge.opacity(0.9), lineWidth: 1)
                )
            hubDetail(outer: outer, body: body, edge: edge)
        }
        .frame(width: outer * 2, height: outer * 2)
        .rotationEffect(.radians(Double(angle)))
        .shadow(color: .black.opacity(0.45), radius: 6, x: 0, y: 3)
        .position(center)
    }

    private func hubDetail(outer: CGFloat, body: Color, edge: Color) -> some View {
        let hub = outer * 0.34
        let bore = outer * 0.16
        return ZStack {
            Circle()
                .fill(body.opacity(0.55))
                .frame(width: hub * 2, height: hub * 2)
            Circle()
                .stroke(edge.opacity(0.8), lineWidth: 1.5)
                .frame(width: hub * 2, height: hub * 2)
            // Three spoke lightening holes for mechanical detail.
            ForEach(0..<3, id: \.self) { i in
                Circle()
                    .fill(Color(red: 0.039, green: 0.063, blue: 0.078).opacity(0.5))
                    .frame(width: bore, height: bore)
                    .offset(y: -(hub + bore) * 0.95)
                    .rotationEffect(.degrees(Double(i) * 120))
            }
            Circle()
                .fill(Color(red: 0.039, green: 0.063, blue: 0.078))
                .frame(width: bore * 1.1, height: bore * 1.1)
        }
    }
}

// MARK: - Per-gear pitch geometry

/// Radii (in the gear's own local frame, centered at 0,0) describing the tooth
/// profile of a single gear, scaled by the shared module.
private struct GearTrainView_GearGeometry {
    let pitchRadius: CGFloat   // pitch circle (where teeth mesh)
    let tipRadius: CGFloat     // outer tip of teeth
    let rootRadius: CGFloat    // inner valley of teeth
}

// MARK: - Layout: positions, sizing, ratios, phases

/// Computes a centered, colinear (diagonally tilted) gear train that fits the
/// available rect, plus the correct rotation for each dependent gear.
private struct GearTrainView_GearLayout {
    let teeth: [Int]
    let module: CGFloat          // pitch diameter per tooth
    let centers: [CGPoint]
    let geometries: [GearTrainView_GearGeometry]
    let lineAngle: CGFloat       // angle of the colinear center line

    init(size: CGSize, teeth: [Int]) {
        self.teeth = teeth

        // Tilt the train diagonally to fill a square tile.
        let angle: CGFloat = -0.42 // radians, gentle upward-right diagonal
        self.lineAngle = angle

        // Pitch radius is proportional to tooth count: r_i = module * t_i / 2.
        // Consecutive centers sit r_i + r_{i+1} apart along the line. The full
        // tip-to-tip span (in module units) is the center run plus the two
        // outer addendum tips:
        //   tip0 + (r0 + 2*r1 + r2) + tip2
        // = (t0 + 2*t1 + t2)/2 + 2   (addendum = 1 module on each end)
        let centerRun = CGFloat(teeth[0] + 2 * teeth[1] + teeth[2]) / 2
        let denom = centerRun + 2
        let span = max(size.width, size.height)
        let rawModule = (span * 0.86) / denom
        self.module = max(rawModule, 1)

        let m = self.module
        let pitch = teeth.map { m * CGFloat($0) / 2 }
        let addendum = m              // tip = pitch + addendum
        let dedendum = m * 1.25       // root = pitch - dedendum

        var geos: [GearTrainView_GearGeometry] = []
        for i in teeth.indices {
            geos.append(
                GearTrainView_GearGeometry(
                    pitchRadius: pitch[i],
                    tipRadius: pitch[i] + addendum,
                    rootRadius: max(pitch[i] - dedendum, pitch[i] * 0.45)
                )
            )
        }
        self.geometries = geos

        // Lay centers along the line: c0 at origin, then accumulate r_i+r_{i+1}.
        let dir = CGPoint(x: cos(angle), y: sin(angle))
        var local: [CGPoint] = [CGPoint(x: 0, y: 0)]
        var dist: CGFloat = 0
        for i in 1..<teeth.count {
            dist += pitch[i - 1] + pitch[i]
            local.append(CGPoint(x: dir.x * dist, y: dir.y * dist))
        }

        // Bounding box of the tip circles, so we can center the whole train.
        var minX = CGFloat.greatestFiniteMagnitude, minY = CGFloat.greatestFiniteMagnitude
        var maxX = -CGFloat.greatestFiniteMagnitude, maxY = -CGFloat.greatestFiniteMagnitude
        for i in teeth.indices {
            let tip = geos[i].tipRadius
            minX = min(minX, local[i].x - tip); maxX = max(maxX, local[i].x + tip)
            minY = min(minY, local[i].y - tip); maxY = max(maxY, local[i].y + tip)
        }
        let boxCenter = CGPoint(x: (minX + maxX) / 2, y: (minY + maxY) / 2)
        let target = CGPoint(x: size.width / 2, y: size.height / 2)
        self.centers = local.map {
            CGPoint(x: $0.x - boxCenter.x + target.x,
                    y: $0.y - boxCenter.y + target.y)
        }
    }

    func center(_ i: Int) -> CGPoint { centers[i] }
    func tipRadius(_ i: Int) -> CGFloat { geometries[i].tipRadius }
    func geometry(_ i: Int) -> GearTrainView_GearGeometry { geometries[i] }

    /// Angle (radians) from the center of gear `i` to gear `j`, in the same
    /// y-down coordinate space rotationEffect uses.
    private func meshAngle(from i: Int, to j: Int) -> CGFloat {
        atan2(centers[j].y - centers[i].y, centers[j].x - centers[i].x)
    }

    /// Correct rotation for a dependent gear so its teeth interlock with its
    /// driver. Gear 1 meshes gear 0 (counter-rotating); gear 2 meshes gear 1.
    ///
    ///   R_j = -(t_i/t_j)*R_i + (1 + t_i/t_j)*phi_ij + pi + pi/t_j
    ///
    /// where phi_ij is the line angle between the two hubs. The half-tooth
    /// (pi/t_j) term seats gear i's tooth into gear j's valley.
    func rotation(forGear j: Int, driveAngle theta: CGFloat) -> CGFloat {
        if j == 1 {
            return meshedRotation(driver: 0, drivee: 1, driverAngle: theta)
        } else {
            let r1 = meshedRotation(driver: 0, drivee: 1, driverAngle: theta)
            return meshedRotation(driver: 1, drivee: 2, driverAngle: r1)
        }
    }

    private func meshedRotation(driver i: Int, drivee j: Int, driverAngle Ri: CGFloat) -> CGFloat {
        let ratio = CGFloat(teeth[i]) / CGFloat(teeth[j])
        let phi = meshAngle(from: i, to: j)
        let halfTooth = CGFloat.pi / CGFloat(teeth[j])
        return -ratio * Ri + (1 + ratio) * phi + .pi + halfTooth
    }
}

// MARK: - Gear shape

/// A static involute-ish gear outline built from radial trapezoid teeth.
/// All motion comes from `rotationEffect`, so no animatableData is needed.
private struct GearTrainView_GearShape: Shape {
    let toothCount: Int
    let geometry: GearTrainView_GearGeometry

    func path(in rect: CGRect) -> Path {
        var path = Path()
        let c = CGPoint(x: rect.midX, y: rect.midY)
        let count = max(toothCount, 4)
        let tip = geometry.tipRadius
        let root = geometry.rootRadius

        let pitchAngle = (2 * CGFloat.pi) / CGFloat(count)
        // Generous gap: tooth occupies ~0.42 of the pitch angle, valley ~0.58.
        // This absorbs any half-tooth phase sign error so teeth still read as
        // meshed rather than interpenetrating.
        let toothFraction: CGFloat = 0.42
        let toothWidth = pitchAngle * toothFraction
        // Taper: tooth is narrower at the tip than at the root (trapezoid).
        let tipTaper: CGFloat = 0.6

        for i in 0..<count {
            let center = CGFloat(i) * pitchAngle
            let rootStart = center - pitchAngle / 2
            let rootBeforeTooth = center - toothWidth / 2
            let rootAfterTooth = center + toothWidth / 2
            let tipStart = center - (toothWidth * tipTaper) / 2
            let tipEnd = center + (toothWidth * tipTaper) / 2

            if i == 0 {
                path.move(to: point(c, root, rootStart))
            }
            // Along the root valley up to the rising flank.
            path.addLine(to: point(c, root, rootBeforeTooth))
            // Up the rising flank to the tip.
            path.addLine(to: point(c, tip, tipStart))
            // Across the tip.
            path.addLine(to: point(c, tip, tipEnd))
            // Down the falling flank back to the root.
            path.addLine(to: point(c, root, rootAfterTooth))
            // Along the root to the next tooth's start.
            path.addLine(to: point(c, root, center + pitchAngle / 2))
        }
        path.closeSubpath()
        return path
    }

    private func point(_ c: CGPoint, _ r: CGFloat, _ angle: CGFloat) -> CGPoint {
        CGPoint(x: c.x + r * cos(angle), y: c.y + r * sin(angle))
    }
}
"""###,
        "ld-infinity-flow": ###"""
import SwiftUI

/// Infinity Flow — a glowing bead races along a lemniscate (figure-eight) while a
/// gradient comet trail streaks behind it. The bead naturally accelerates through
/// the central crossover pinch and eases on the outer loops (a property of the
/// Gerono parametrization), so it reads as a real bead with momentum on a track.
///
/// Both `demo` states are self-driving via `TimelineView(.animation)` (the spec's
/// interaction is "auto"). `demo == true` is the calm grid-tile loop; `demo == false`
/// is a slightly richer detail variant with a wider, brighter ribbon. Neither uses
/// touch. Bead and trail are sampled from the SAME time-warped parameter inside a
/// single Canvas, so the bead's leading edge always sits exactly on the trail head —
/// no parametric-vs-arclength desync (which is why we avoid `.trim`).
struct InfinityFlowView: View {
    var demo: Bool = false

    var body: some View {
        TimelineView(.animation) { timeline in
            Canvas { context, size in
                draw(into: &context, size: size, time: timeline.date.timeIntervalSinceReferenceDate)
            }
            .frame(maxWidth: .infinity, maxHeight: .infinity)
        }
        .background(Self.backdrop)
        .drawingGroup()
    }

    // MARK: - Tunables

    /// Full laps of the figure-eight per second (one lap = the bead visits both lobes once).
    private var lapsPerSecond: Double { demo ? 0.34 : 0.40 }

    /// How far behind the bead, in parametric seconds, the trail extends.
    private var trailSpan: Double { demo ? 0.42 : 0.52 }

    /// Number of trail segments. More = smoother ribbon; this stays cheap in one Canvas.
    private var trailSamples: Int { demo ? 44 : 56 }

    private var trackLineWidth: CGFloat { demo ? 2.2 : 3.0 }
    private var ribbonWidth: CGFloat { demo ? 4.6 : 6.4 }
    private var beadCoreRadius: CGFloat { demo ? 4.2 : 5.6 }

    // MARK: - Palette (literal Color(red:green:blue:) — no app dependencies)

    private static let backdrop = Color(red: 0.039, green: 0.063, blue: 0.078)
    private let trackColor = Color(red: 0.16, green: 0.22, blue: 0.30)
    private let beadGlow  = Color(red: 0.62, green: 0.96, blue: 1.00)

    /// Ribbon endpoints kept as raw RGB tuples so blending never relies on `Color`
    /// equality (which is unreliable across SwiftUI versions and could silently make
    /// the whole trail render white).
    private let trailHeadRGB: (r: Double, g: Double, b: Double) = (0.42, 0.92, 1.00) // bright cyan at the head
    private let trailTailRGB: (r: Double, g: Double, b: Double) = (0.58, 0.38, 1.00) // violet fading into the tail

    // MARK: - Geometry

    /// Lemniscate of Gerono in unit space: x ∈ [-1, 1], y ∈ [-0.5, 0.5].
    /// x = cos(t), y = sin(t)·cos(t).  The natural |P'(t)| peaks at the crossover
    /// (t = π/2, 3π/2) and dips on the lobes, which IS the "momentum" the spec wants.
    private func unitPoint(_ t: Double) -> CGPoint {
        let x = cos(t)
        let y = sin(t) * cos(t)
        return CGPoint(x: x, y: y)
    }

    /// Maps a unit-space point into the view, fitting the 2:1 lemniscate with margin
    /// for the bead glow so nothing clips inside a small (~120pt) tile.
    private func transform(_ p: CGPoint, size: CGSize) -> CGPoint {
        let margin: CGFloat = beadCoreRadius * 2.6 + 6
        let usableW = max(size.width - margin * 2, 1)
        let usableH = max(size.height - margin * 2, 1)
        // Lemniscate spans 2 wide, 1 tall in unit space → scale by the tighter fit.
        let scale = min(usableW / 2.0, usableH / 1.0)
        let cx = size.width / 2
        let cy = size.height / 2
        return CGPoint(x: cx + p.x * scale, y: cy + p.y * scale)
    }

    // MARK: - Rendering

    private func draw(into context: inout GraphicsContext, size: CGSize, time: Double) {
        drawTrack(into: &context, size: size)

        // Leading parameter of the bead. A full lap of the Gerono curve is one 2π period.
        let head = time * lapsPerSecond * 2.0 * .pi

        drawTrail(into: &context, size: size, head: head)
        drawBead(into: &context, size: size, head: head)
    }

    /// Faint full lemniscate underneath — guarantees a never-blank, legible state and
    /// sells the "real track" the bead rides on.
    private func drawTrack(into context: inout GraphicsContext, size: CGSize) {
        var path = Path()
        let steps = 140
        for i in 0...steps {
            let t = (Double(i) / Double(steps)) * 2.0 * .pi
            let pt = transform(unitPoint(t), size: size)
            if i == 0 { path.move(to: pt) } else { path.addLine(to: pt) }
        }
        context.stroke(
            path,
            with: .color(trackColor.opacity(0.55)),
            style: StrokeStyle(lineWidth: trackLineWidth, lineCap: .round, lineJoin: .round)
        )
    }

    /// The comet ribbon. Each consecutive pair of samples is its own short stroke with
    /// an age-based opacity + color blend, so the fade tracks distance-behind-the-bead
    /// (NOT screen position) — correct even where the ribbon crosses itself at center.
    /// Sampling over a fixed parametric span stretches the ribbon where the bead is fast
    /// (the crossover) and compresses it on the slow lobes — free momentum.
    private func drawTrail(into context: inout GraphicsContext, size: CGSize, head: Double) {
        let n = trailSamples
        guard n >= 2 else { return }

        // Precompute points from the tail (oldest) to the head (newest).
        var points: [CGPoint] = []
        points.reserveCapacity(n + 1)
        for i in 0...n {
            let frac = Double(i) / Double(n)          // 0 = tail, 1 = head
            let t = head - trailSpan * (1.0 - frac)
            points.append(transform(unitPoint(t), size: size))
        }

        for i in 0..<n {
            let segFrac = Double(i) / Double(n)        // 0 tail → ~1 head
            // Ease the alpha so the tail dissolves smoothly rather than cutting off.
            let alpha = pow(segFrac, 1.7)
            let color = blend(trailTailRGB, trailHeadRGB, t: segFrac)
            let width = ribbonWidth * (0.35 + 0.65 * segFrac)

            var seg = Path()
            seg.move(to: points[i])
            seg.addLine(to: points[i + 1])
            context.stroke(
                seg,
                with: .color(color.opacity(alpha)),
                style: StrokeStyle(lineWidth: width, lineCap: .round, lineJoin: .round)
            )
        }
    }

    /// Bead = a few stacked circles (large/dim glow → small/bright core) placed exactly
    /// at the leading sample, so it always sits on the trail head.
    private func drawBead(into context: inout GraphicsContext, size: CGSize, head: Double) {
        let center = transform(unitPoint(head), size: size)
        let layers: [(scale: CGFloat, opacity: Double)] = [
            (3.4, 0.16),
            (2.2, 0.28),
            (1.45, 0.55),
            (1.0, 1.0)
        ]
        for layer in layers {
            let r = beadCoreRadius * layer.scale
            let rect = CGRect(x: center.x - r, y: center.y - r, width: r * 2, height: r * 2)
            let c = layer.scale <= 1.0 ? Color.white : beadGlow
            context.fill(Path(ellipseIn: rect), with: .color(c.opacity(layer.opacity)))
        }
    }

    // MARK: - Helpers

    /// Linear RGB interpolation between two raw color tuples. Takes tuples directly so
    /// it never depends on `Color` equality.
    private func blend(
        _ a: (r: Double, g: Double, b: Double),
        _ b: (r: Double, g: Double, b: Double),
        t: Double
    ) -> Color {
        let k = min(max(t, 0), 1)
        return Color(
            red: a.r + (b.r - a.r) * k,
            green: a.g + (b.g - a.g) * k,
            blue: a.b + (b.b - a.b) * k
        )
    }
}
"""###,
        "ld-knit-braid": ###"""
import SwiftUI

/// Braiding Threads — three colored strands weave over and under each other in a
/// continuous plait that scrolls upward. Per-crossing over/under z-order falls out
/// of a helix projection: horizontal position uses sin(θ) while depth uses cos(θ),
/// so at any crossing (equal sin) the two strands have opposite cos and the
/// front/back swap lands exactly on the crossing point. Self-driving via
/// TimelineView(.animation); `demo` and the real component render the same braid
/// because the spec marks this interaction as "auto".
struct KnitBraidView: View {
    var demo: Bool = false

    var body: some View {
        // Both branches render the identical self-driving braid (interaction: auto).
        KnitBraidView_BraidCanvas()
    }
}

// MARK: - Live braid

private struct KnitBraidView_BraidCanvas: View {
    // Three bright cord colors on the dark catalog background, stored as RGB
    // components so depth-shading is a plain arithmetic op (no Color resolution).
    private let strandRGB: [(r: Double, g: Double, b: Double)] = [
        (0.98, 0.43, 0.39),  // coral
        (0.40, 0.78, 0.98),  // sky
        (0.98, 0.82, 0.38)   // amber
    ]

    private let background = Color(red: 0.039, green: 0.063, blue: 0.078) // #0a1014
    private let strandCount = 3
    private let slices = 84

    var body: some View {
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            GeometryReader { geo in
                Canvas { context, size in
                    drawBraid(in: &context, size: size, time: t)
                }
                .background(background)
                .clipped()
                .frame(width: geo.size.width, height: geo.size.height)
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .background(background)
    }

    // MARK: Geometry

    /// Phase for a strand at a given vertical position and time.
    /// k controls wavelength (how many crossings appear); the `-time` term scrolls
    /// the braid upward; the per-strand offset spreads the three strands by 120°.
    private func phase(y: CGFloat, time: Double, strand: Int, height: CGFloat) -> CGFloat {
        let wavelengths: CGFloat = 2.4
        let k: CGFloat = (wavelengths * 2 * .pi) / max(height, 1)
        let scroll = CGFloat(time) * 2.0
        let strandOffset = CGFloat(strand) * (2 * .pi / CGFloat(strandCount))
        return k * y - scroll + strandOffset
    }

    private func xPosition(y: CGFloat, time: Double, strand: Int, size: CGSize) -> CGFloat {
        let theta = phase(y: y, time: time, strand: strand, height: size.height)
        let amplitude = size.width * 0.18
        return size.width / 2 + amplitude * sin(theta)
    }

    /// Depth in [-1, 1]; +1 is frontmost. Drives draw order and brightness.
    private func depth(y: CGFloat, time: Double, strand: Int, height: CGFloat) -> CGFloat {
        cos(phase(y: y, time: time, strand: strand, height: height))
    }

    // MARK: Drawing

    private func drawBraid(in context: inout GraphicsContext, size: CGSize, time: Double) {
        let lineWidth = max(size.width * 0.11, 3)
        // Extend a little past both edges so the scroll never reveals a blank gap.
        let margin = lineWidth * 1.5
        let top = -margin
        let bottom = size.height + margin
        let span = bottom - top
        let dy = span / CGFloat(slices)

        for i in 0..<slices {
            let y0 = top + CGFloat(i) * dy
            // Slight overlap (1.6 * dy) keeps the cords reading continuous, not dashed.
            let y1 = y0 + dy * 1.6
            let yMid = (y0 + y1) / 2

            drawSlice(in: &context,
                      y0: y0, y1: y1, yMid: yMid,
                      size: size, time: time, lineWidth: lineWidth)
        }
    }

    private func drawSlice(in context: inout GraphicsContext,
                           y0: CGFloat, y1: CGFloat, yMid: CGFloat,
                           size: CGSize, time: Double, lineWidth: CGFloat) {
        // Build per-strand segment data for this slice.
        var segments: [(strand: Int, z: CGFloat, p0: CGPoint, p1: CGPoint)] = []
        segments.reserveCapacity(strandCount)

        for s in 0..<strandCount {
            let x0 = xPosition(y: y0, time: time, strand: s, size: size)
            let x1 = xPosition(y: y1, time: time, strand: s, size: size)
            let z = depth(y: yMid, time: time, strand: s, height: size.height)
            segments.append((s,
                             z,
                             CGPoint(x: x0, y: y0),
                             CGPoint(x: x1, y: y1)))
        }

        // Sort ascending by depth so the frontmost (highest cos) strand draws LAST.
        // This is the over/under mechanism — back strands are painted over by front ones.
        segments.sort { $0.z < $1.z }

        for seg in segments {
            drawSegment(in: &context, seg: seg, lineWidth: lineWidth)
        }
    }

    private func drawSegment(in context: inout GraphicsContext,
                             seg: (strand: Int, z: CGFloat, p0: CGPoint, p1: CGPoint),
                             lineWidth: CGFloat) {
        var path = Path()
        path.move(to: seg.p0)
        path.addLine(to: seg.p1)

        // Brightness lifts the front cords; depthFactor in [0, 1].
        let depthFactor = (seg.z + 1) / 2
        let shaded = shadedColor(strand: seg.strand, depthFactor: depthFactor)

        // A faint dark casing under each cord deepens the woven look.
        let casing = StrokeStyle(lineWidth: lineWidth + 2, lineCap: .round)
        context.stroke(path,
                       with: .color(Color(red: 0.02, green: 0.03, blue: 0.04).opacity(0.65)),
                       style: casing)

        let coreStyle = StrokeStyle(lineWidth: lineWidth, lineCap: .round)
        context.stroke(path, with: .color(shaded), style: coreStyle)

        // A thin specular highlight on the frontmost portion adds the textile sheen.
        if depthFactor > 0.6 {
            let highlightWidth = lineWidth * 0.32
            let hStyle = StrokeStyle(lineWidth: highlightWidth, lineCap: .round)
            let hOpacity = (depthFactor - 0.6) / 0.4
            context.stroke(path,
                           with: .color(Color.white.opacity(0.45 * hOpacity)),
                           style: hStyle)
        }
    }

    /// Darken cords toward the back, brighten toward the front.
    private func shadedColor(strand: Int, depthFactor: CGFloat) -> Color {
        // Map depthFactor [0,1] -> brightness multiplier [0.45, 1.15], clamped.
        let m = Double(0.45 + depthFactor * 0.70)
        let base = strandRGB[strand]
        let r = min(base.r * m, 1)
        let g = min(base.g * m, 1)
        let b = min(base.b * m, 1)
        return Color(red: r, green: g, blue: b)
    }
}
"""###,
        "ld-liquid-flask-fill": ###"""
import SwiftUI

/// Liquid Flask Fill
/// A rounded flask fills from the bottom with tinted liquid whose surface tilts
/// and sloshes with inertia, settling level after a damped spring overshoot, while
/// tiny bubbles rise through the liquid.
///
/// - `demo == true`  : self-driving — the surface tilts on a slow sine and the fill
///                     level breathes up and down on a timer. Never blank.
/// - `demo == false` : interactive — a DragGesture maps horizontal translation to
///                     surface tilt and vertical translation to fill level. On release
///                     the surface settles level with a damped overshoot.
///
/// Everything is recomputed each frame from time + drag state (no animatableData),
/// so the timeline-driven traveling wave and the release overshoot compose cleanly.
struct LiquidFlaskFillView: View {
    var demo: Bool = false

    // MARK: - Interactive drag state

    /// Live tilt in radians while dragging (horizontal translation).
    @State private var dragTilt: CGFloat = 0
    /// Live fill level 0...1 while dragging (vertical translation).
    @State private var dragFill: CGFloat = 0.55
    /// Fill level captured at the moment a drag begins.
    @State private var fillAtDragStart: CGFloat = 0.55
    /// True while the finger is down.
    @State private var isDragging: Bool = false

    /// Reference-time snapshot of the release moment, used to seed the damped slosh.
    @State private var releaseTime: TimeInterval = 0
    /// Tilt magnitude at release; the slosh decays from here.
    @State private var releaseTilt: CGFloat = 0

    var body: some View {
        GeometryReader { geo in
            TimelineView(.animation) { timeline in
                let now = timeline.date.timeIntervalSinceReferenceDate
                let phase = now * 1.6            // traveling-wave phase, always moving
                let state = resolvedState(now: now)
                flask(in: geo.size, fill: state.fill, tilt: state.tilt, phase: phase, now: now)
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .contentShape(Rectangle())
        // Single view type: keep the gesture installed but mask it off in demo mode.
        .gesture(dragGesture, including: demo ? .subviews : .all)
    }

    // MARK: - State resolution

    struct LiquidState {
        var fill: CGFloat
        var tilt: CGFloat
    }

    /// Computes the current fill + tilt for this frame depending on mode and drag phase.
    private func resolvedState(now: TimeInterval) -> LiquidState {
        if demo {
            return autoState(now: now)
        }
        if isDragging {
            return LiquidState(fill: dragFill, tilt: dragTilt)
        }
        // Released: damped harmonic slosh back to level.
        let dt: Double = now - releaseTime
        let tilt = settleTilt(elapsed: dt)
        return LiquidState(fill: dragFill, tilt: tilt)
    }

    /// Self-driving loop: a gentle ~3.2s breathing fill and a slow tilt sine.
    private func autoState(now: TimeInterval) -> LiquidState {
        let fillWave: CGFloat = CGFloat(sin(now * 0.9))            // -1...1
        let fill: CGFloat = 0.575 + 0.275 * fillWave              // 0.30...0.85
        let tilt: CGFloat = CGFloat(sin(now * 1.25)) * 0.20        // ~±11.5°
        return LiquidState(fill: fill, tilt: tilt)
    }

    /// Hand-rolled damped oscillation for the release overshoot.
    /// tilt(Δ) = releaseTilt · e^(-k·Δ) · cos(ω·Δ)
    private func settleTilt(elapsed: Double) -> CGFloat {
        let clamped = max(0, elapsed)
        let k: Double = 3.4        // damping
        let omega: Double = 7.0    // angular frequency of the slosh
        let envelope = exp(-k * clamped)
        let osc = cos(omega * clamped)
        return releaseTilt * CGFloat(envelope * osc)
    }

    // MARK: - Composition

    @ViewBuilder
    private func flask(in size: CGSize, fill: CGFloat, tilt: CGFloat, phase: Double, now: TimeInterval) -> some View {
        let dims = flaskDimensions(for: size)
        let shape = RoundedRectangle(cornerRadius: dims.corner, style: .continuous)

        ZStack {
            // Glass body backdrop.
            shape
                .fill(glassFill)
                .frame(width: dims.width, height: dims.height)

            // Liquid + bubbles, clipped to the flask interior.
            liquidLayer(dims: dims, fill: fill, tilt: tilt, phase: phase, now: now)
                .frame(width: dims.width, height: dims.height)
                .clipShape(shape)

            // Glass rim + highlight.
            shape
                .strokeBorder(rimGradient, lineWidth: max(1.4, dims.width * 0.018))
                .frame(width: dims.width, height: dims.height)

            glassHighlight(dims: dims)
                .frame(width: dims.width, height: dims.height)
                .clipShape(shape)
        }
        .frame(width: size.width, height: size.height)
    }

    @ViewBuilder
    private func liquidLayer(dims: FlaskDimensions, fill: CGFloat, tilt: CGFloat, phase: Double, now: TimeInterval) -> some View {
        let interior = CGSize(width: dims.width, height: dims.height)
        let surfaceY = surfaceLineY(in: interior, fill: fill)
        let amplitude = dims.waveAmplitude(tilt: tilt)
        let meniscusWidth = max(1.0, dims.width * 0.012)

        ZStack {
            // The liquid body.
            LiquidFlaskFillView_LiquidShape(fill: fill, tilt: tilt, phase: phase, amplitude: amplitude)
                .fill(liquidGradient)
                .overlay {
                    // Brighter meniscus band riding the surface.
                    LiquidFlaskFillView_LiquidShape(fill: fill, tilt: tilt, phase: phase, amplitude: amplitude)
                        .stroke(meniscusColor, lineWidth: meniscusWidth)
                        .blur(radius: 0.6)
                }

            // Rising bubbles, only below the surface line.
            bubbles(interior: interior, surfaceY: surfaceY, fill: fill, now: now)
        }
    }

    @ViewBuilder
    private func bubbles(interior: CGSize, surfaceY: CGFloat, fill: CGFloat, now: TimeInterval) -> some View {
        Canvas { context, _ in
            guard fill > 0.04 else { return }
            let count = 11
            let bottom = interior.height
            for i in 0..<count {
                let seed = Double(i) * 12.9898
                let speed: Double = 0.45 + frac(sin(seed) * 43758.5453) * 0.5
                let xJitter: CGFloat = CGFloat(frac(sin(seed + 4.1) * 22578.1459))
                let radius: CGFloat = 1.4 + CGFloat(frac(sin(seed + 7.7) * 9301.17)) * 2.2

                // Vertical travel cycles from bottom up to the surface line.
                let cyclePos = frac(now * speed + Double(i) / Double(count))
                let travel = bottom - surfaceY
                let y = bottom - CGFloat(cyclePos) * travel
                guard y > surfaceY else { continue }

                // Gentle horizontal wobble as it rises.
                let wobble = CGFloat(sin(now * 2.0 + seed)) * (interior.width * 0.02)
                let x = interior.width * (0.12 + 0.76 * xJitter) + wobble

                // Fade in near the bottom, fade out as it nears the surface.
                let nearSurface = (y - surfaceY) / max(travel, 1)
                let alpha = Double(min(1, nearSurface * 3.0)) * 0.6

                let rect = CGRect(x: x - radius, y: y - radius, width: radius * 2, height: radius * 2)
                context.fill(Path(ellipseIn: rect), with: .color(.white.opacity(alpha)))
            }
        }
    }

    @ViewBuilder
    private func glassHighlight(dims: FlaskDimensions) -> some View {
        let w = dims.width
        let h = dims.height
        Capsule()
            .fill(
                LinearGradient(
                    colors: [Color.white.opacity(0.30), Color.white.opacity(0.02)],
                    startPoint: .top,
                    endPoint: .bottom
                )
            )
            .frame(width: w * 0.10, height: h * 0.72)
            .offset(x: -w * 0.28, y: -h * 0.04)
            .blur(radius: 1.0)
    }

    // MARK: - Geometry helpers

    struct FlaskDimensions {
        var width: CGFloat
        var height: CGFloat
        var corner: CGFloat

        func waveAmplitude(tilt: CGFloat) -> CGFloat {
            // Tilt drives surface slope; amplitude grows a touch with |tilt| for slosh feel.
            let base: CGFloat = height * 0.018
            let tiltBoost: CGFloat = abs(tilt) * height * 0.10
            return base + tiltBoost
        }
    }

    private func flaskDimensions(for size: CGSize) -> FlaskDimensions {
        let side = min(size.width, size.height)
        // A tall rounded flask: narrower than tall, comfortably inside the tile.
        let width = side * 0.56
        let height = side * 0.86
        let corner = width * 0.42
        return FlaskDimensions(width: width, height: height, corner: corner)
    }

    /// Y position of the resting surface line (no wave) inside the interior.
    private func surfaceLineY(in interior: CGSize, fill: CGFloat) -> CGFloat {
        let clamped = min(max(fill, 0), 1)
        return interior.height * (1 - clamped)
    }

    // MARK: - Gesture

    private var dragGesture: some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                if !isDragging {
                    isDragging = true
                    fillAtDragStart = dragFill
                }
                // Horizontal translation -> tilt, clamped to ~±25°.
                let maxTilt: CGFloat = 0.44   // radians (~25°)
                let tiltRaw = value.translation.width / 160.0
                dragTilt = min(max(tiltRaw, -maxTilt), maxTilt)

                // Vertical translation -> fill delta (drag up fills, down empties).
                let fillDelta = -value.translation.height / 220.0
                dragFill = min(max(fillAtDragStart + fillDelta, 0), 1)
            }
            .onEnded { _ in
                isDragging = false
                releaseTilt = dragTilt
                releaseTime = Date().timeIntervalSinceReferenceDate
            }
    }

    // MARK: - Palette

    private var liquidGradient: LinearGradient {
        LinearGradient(
            colors: [
                Color(red: 0.20, green: 0.78, blue: 0.92),
                Color(red: 0.10, green: 0.52, blue: 0.86),
                Color(red: 0.06, green: 0.34, blue: 0.74)
            ],
            startPoint: .top,
            endPoint: .bottom
        )
    }

    private var meniscusColor: Color {
        Color(red: 0.62, green: 0.92, blue: 1.0).opacity(0.85)
    }

    private var glassFill: LinearGradient {
        LinearGradient(
            colors: [
                Color(red: 0.16, green: 0.20, blue: 0.26).opacity(0.55),
                Color(red: 0.08, green: 0.11, blue: 0.16).opacity(0.55)
            ],
            startPoint: .topLeading,
            endPoint: .bottomTrailing
        )
    }

    private var rimGradient: LinearGradient {
        LinearGradient(
            colors: [
                Color.white.opacity(0.55),
                Color.white.opacity(0.12),
                Color.white.opacity(0.30)
            ],
            startPoint: .topLeading,
            endPoint: .bottomTrailing
        )
    }

    // MARK: - Math helpers

    /// Fractional part, always in 0..<1.
    private func frac(_ x: Double) -> Double {
        let f = x - floor(x)
        return f
    }
}

// MARK: - Liquid Shape

/// Draws the liquid body as a region under a tilted, traveling sine surface.
/// All inputs are plain values (recomputed per frame); no animatableData is used
/// because animation is driven externally by TimelineView + time-based slosh.
private struct LiquidFlaskFillView_LiquidShape: Shape {
    var fill: CGFloat       // 0...1
    var tilt: CGFloat       // radians, surface slope
    var phase: Double       // traveling-wave phase
    var amplitude: CGFloat  // wave amplitude in points

    func path(in rect: CGRect) -> Path {
        var path = Path()

        let clampedFill = min(max(fill, 0), 1)
        guard clampedFill > 0.001 else { return path }

        let baseY: CGFloat = rect.height * (1 - clampedFill)
        let slope: CGFloat = CGFloat(tan(Double(tilt)))   // surface tilt as vertical offset per unit x
        let midX: CGFloat = rect.width / 2
        let waveLength: CGFloat = rect.width * 0.9
        let k: CGFloat = (2 * .pi) / max(waveLength, 1)

        let step: CGFloat = max(2, rect.width / 48)
        var x: CGFloat = 0

        path.move(to: CGPoint(x: 0, y: surfaceY(at: 0, baseY: baseY, slope: slope, midX: midX, k: k)))
        while x <= rect.width {
            let y = surfaceY(at: x, baseY: baseY, slope: slope, midX: midX, k: k)
            path.addLine(to: CGPoint(x: x, y: y))
            x += step
        }
        // Ensure the right edge is captured.
        let edgeY = surfaceY(at: rect.width, baseY: baseY, slope: slope, midX: midX, k: k)
        path.addLine(to: CGPoint(x: rect.width, y: edgeY))

        // Close down the right side, across the bottom, up the left.
        path.addLine(to: CGPoint(x: rect.width, y: rect.height))
        path.addLine(to: CGPoint(x: 0, y: rect.height))
        path.closeSubpath()
        return path
    }

    private func surfaceY(at x: CGFloat, baseY: CGFloat, slope: CGFloat, midX: CGFloat, k: CGFloat) -> CGFloat {
        let tiltOffset: CGFloat = (x - midX) * slope
        let waveOffset: CGFloat = amplitude * CGFloat(sin(Double(k * x) + phase))
        return baseY + tiltOffset + waveOffset
    }
}
"""###,
        "ld-magnetic-filings": ###"""
import SwiftUI

/// Magnetic Filings — scattered iron-filing slivers align to the field of a
/// hidden magnetic pole. In `demo` the pole auto-orbits the center; interactively
/// a drag snaps the pole to the finger and the whole field swings to follow.
///
/// Self-contained: SwiftUI only, iOS 17, no app dependencies.
struct MagneticFilingsView: View {
    var demo: Bool = false

    // Pole motion is driven by time + values set ONLY in gesture callbacks,
    // so the Canvas render closure stays a pure read-only function (no state
    // writes during view update).

    /// Normalized (0...1) pole position the field is easing *from*.
    @State private var sourcePole: CGPoint = CGPoint(x: 0.5, y: 0.5)
    /// Normalized (0...1) pole position the field is easing *toward*.
    @State private var targetPole: CGPoint = CGPoint(x: 0.5, y: 0.5)
    /// When the current source→target transition began.
    @State private var transitionStart: Date = .distantPast
    /// True while a finger owns the pole.
    @State private var isDragging: Bool = false
    /// Orbit phase offset (radians) so the idle orbit resumes seamlessly
    /// from wherever the pole was released.
    @State private var orbitPhase: Double = 0
    /// Reference time used to compute the orbit angle.
    @State private var orbitStart: Date = .distantPast

    private let transitionDuration: Double = 0.55
    private let orbitPeriod: Double = 3.2          // seconds per lap when idle
    private let orbitRadius: CGFloat = 0.32        // fraction of min side

    var body: some View {
        GeometryReader { geo in
            TimelineView(.animation) { timeline in
                fieldCanvas(size: geo.size, now: timeline.date)
            }
        }
        .background(Color(red: 0.039, green: 0.063, blue: 0.078)) // #0a1014
        .contentShape(Rectangle())
        .modifier(MagneticFilingsView_PoleDragModifier(enabled: !demo, onChanged: handleDrag, onEnded: handleRelease))
        .onAppear { configureStart() }
    }

    // MARK: - Lifecycle

    private func configureStart() {
        let now = Date()
        if orbitStart == .distantPast { orbitStart = now }
        if transitionStart == .distantPast { transitionStart = now.addingTimeInterval(-transitionDuration) }
    }

    // MARK: - Canvas

    @ViewBuilder
    private func fieldCanvas(size: CGSize, now: Date) -> some View {
        let pole = displayedPole(size: size, now: now)
        Canvas { context, canvasSize in
            drawField(into: &context, size: canvasSize, pole: pole)
        }
        // Glow halo marking the hidden pole — keeps the tile legible at all times.
        .overlay {
            poleGlow(size: size, pole: pole)
        }
    }

    private func poleGlow(size: CGSize, pole: CGPoint) -> some View {
        let dim = min(size.width, size.height)
        let r = max(dim * 0.16, 14)
        return RadialGradient(
            colors: [
                Color(red: 0.55, green: 0.86, blue: 1.0).opacity(0.55),
                Color(red: 0.30, green: 0.62, blue: 0.95).opacity(0.0)
            ],
            center: .center,
            startRadius: 0,
            endRadius: r
        )
        .frame(width: r * 2, height: r * 2)
        .position(pole)
        .allowsHitTesting(false)
        .blendMode(.screen)
    }

    // MARK: - Pole position (pure function of time + callback-set state)

    private func displayedPole(size: CGSize, now: Date) -> CGPoint {
        let s = denormalize(sourcePole, in: size)
        let t = isDragging ? denormalize(targetPole, in: size) : orbitPoint(size: size, now: now)
        let elapsed = now.timeIntervalSince(transitionStart)
        let raw = transitionDuration > 0 ? elapsed / transitionDuration : 1
        let p = CGFloat(easeOut(min(max(raw, 0), 1)))
        return CGPoint(x: lerp(s.x, t.x, p), y: lerp(s.y, t.y, p))
    }

    /// The idle orbit position, phase-shifted so it lines up with the release point.
    private func orbitPoint(size: CGSize, now: Date) -> CGPoint {
        let dim = min(size.width, size.height)
        let cx = size.width / 2
        let cy = size.height / 2
        let r = dim * orbitRadius
        let elapsed = now.timeIntervalSince(orbitStart)
        let angle = (elapsed / orbitPeriod) * 2 * Double.pi + orbitPhase
        // Gentle vertical squash gives the orbit a tilted, lively feel.
        let x = cx + r * CGFloat(cos(angle))
        let y = cy + r * 0.62 * CGFloat(sin(angle))
        return CGPoint(x: x, y: y)
    }

    private func denormalize(_ p: CGPoint, in size: CGSize) -> CGPoint {
        CGPoint(x: p.x * size.width, y: p.y * size.height)
    }

    // MARK: - Drag handling

    private func handleDrag(_ location: CGPoint, _ size: CGSize) {
        let now = Date()
        if !isDragging {
            // Begin transition from wherever the field currently points.
            sourcePole = normalize(displayedPole(size: size, now: now), in: size)
            transitionStart = now
            isDragging = true
        }
        targetPole = normalize(location, in: size)
    }

    private func handleRelease(_ location: CGPoint, _ size: CGSize) {
        let now = Date()
        // Re-phase the idle orbit so it resumes from the release point with no snap.
        rephaseOrbit(toMatch: location, size: size, now: now)
        sourcePole = normalize(location, in: size)
        transitionStart = now
        isDragging = false
    }

    /// Choose orbitPhase + orbitStart so orbitPoint(now) == release location's
    /// nearest point on the orbit ellipse, then let the transition ease onto it.
    private func rephaseOrbit(toMatch location: CGPoint, size: CGSize, now: Date) {
        let cx = size.width / 2
        let cy = size.height / 2
        let dim = min(size.width, size.height)
        let r = max(dim * orbitRadius, 1)
        let dx = Double(location.x - cx) / Double(r)
        let dy = Double(location.y - cy) / Double(r * 0.62)
        let desiredAngle = atan2(dy, dx)
        let elapsed = now.timeIntervalSince(orbitStart)
        let base = (elapsed / orbitPeriod) * 2 * Double.pi
        orbitPhase = desiredAngle - base
    }

    private func normalize(_ p: CGPoint, in size: CGSize) -> CGPoint {
        let w = max(size.width, 1)
        let h = max(size.height, 1)
        return CGPoint(x: p.x / w, y: p.y / h)
    }

    // MARK: - Field drawing

    private func drawField(into context: inout GraphicsContext, size: CGSize, pole: CGPoint) {
        let layout = gridLayout(for: size)
        guard layout.cols > 0, layout.rows > 0 else { return }

        let half = layout.sliverLength / 2
        // Bucket slivers by field strength into a few Paths -> few stroke calls.
        let bucketCount = 4
        var buckets = Array(repeating: Path(), count: bucketCount)

        let maxDist = Double(max(size.width, size.height))

        for r in 0..<layout.rows {
            for c in 0..<layout.cols {
                let cx = layout.originX + CGFloat(c) * layout.spacing
                let cy = layout.originY + CGFloat(r) * layout.spacing
                let dx = Double(pole.x - cx)
                let dy = Double(pole.y - cy)
                let angle = atan2(dy, dx)
                let dist = (dx * dx + dy * dy).squareRoot()

                // Strength: near the pole the slivers are longer/brighter.
                let strength = 1.0 - min(dist / maxDist, 1.0)
                let lengthScale = CGFloat(0.7 + 0.55 * strength)
                let h = half * lengthScale

                let cosA = CGFloat(cos(angle))
                let sinA = CGFloat(sin(angle))
                let p0 = CGPoint(x: cx - cosA * h, y: cy - sinA * h)
                let p1 = CGPoint(x: cx + cosA * h, y: cy + sinA * h)

                let bucket = min(Int(strength * Double(bucketCount)), bucketCount - 1)
                buckets[bucket].move(to: p0)
                buckets[bucket].addLine(to: p1)
            }
        }

        let lineWidth = max(layout.sliverLength * 0.16, 1.1)
        for i in 0..<bucketCount {
            let t = Double(i) / Double(bucketCount - 1)
            let color = filingColor(strength: t)
            context.stroke(
                buckets[i],
                with: .color(color),
                style: StrokeStyle(lineWidth: lineWidth, lineCap: .round)
            )
        }
    }

    private func filingColor(strength t: Double) -> Color {
        // Steel-grey far field -> bright cyan-white near the pole.
        let lo = (r: 0.42, g: 0.47, b: 0.55)
        let hi = (r: 0.72, g: 0.92, b: 1.0)
        let rr = lerp(lo.r, hi.r, t)
        let gg = lerp(lo.g, hi.g, t)
        let bb = lerp(lo.b, hi.b, t)
        let alpha = 0.55 + 0.45 * t
        return Color(red: rr, green: gg, blue: bb).opacity(alpha)
    }

    // MARK: - Grid layout

    struct GridLayout {
        var cols: Int
        var rows: Int
        var spacing: CGFloat
        var originX: CGFloat
        var originY: CGFloat
        var sliverLength: CGFloat
    }

    private func gridLayout(for size: CGSize) -> GridLayout {
        let dim = min(size.width, size.height)
        guard dim > 1 else {
            return GridLayout(cols: 0, rows: 0, spacing: 0, originX: 0, originY: 0, sliverLength: 0)
        }
        // Spacing scales with the smaller side so density reads similarly in a
        // 120pt tile and a large detail view.
        let spacing = max(dim / 12.0, 12)
        let sliverLength = spacing * 0.78

        // Cap total slivers for perf (stated risk).
        let maxSlivers = 520
        var cols = max(Int(size.width / spacing), 2)
        var rows = max(Int(size.height / spacing), 2)
        while cols * rows > maxSlivers {
            if cols >= rows { cols -= 1 } else { rows -= 1 }
        }

        let usedW = CGFloat(cols - 1) * spacing
        let usedH = CGFloat(rows - 1) * spacing
        let originX = (size.width - usedW) / 2
        let originY = (size.height - usedH) / 2
        return GridLayout(cols: cols, rows: rows, spacing: spacing,
                          originX: originX, originY: originY, sliverLength: sliverLength)
    }

    // MARK: - Math helpers

    private func lerp(_ a: CGFloat, _ b: CGFloat, _ t: CGFloat) -> CGFloat { a + (b - a) * t }
    private func lerp(_ a: Double, _ b: Double, _ t: Double) -> Double { a + (b - a) * t }
    private func easeOut(_ t: Double) -> Double { 1 - pow(1 - t, 3) }
}

// MARK: - Drag wiring (conditionally attached)

/// Attaches a zero-distance DragGesture only when interactive, so the piece
/// wins inside a ScrollView. In demo mode no gesture is added.
private struct MagneticFilingsView_PoleDragModifier: ViewModifier {
    let enabled: Bool
    let onChanged: (CGPoint, CGSize) -> Void
    let onEnded: (CGPoint, CGSize) -> Void

    func body(content: Content) -> some View {
        if enabled {
            GeometryReader { geo in
                content
                    .gesture(
                        DragGesture(minimumDistance: 0)
                            .onChanged { onChanged($0.location, geo.size) }
                            .onEnded { onEnded($0.location, geo.size) }
                    )
            }
        } else {
            content
        }
    }
}
"""###,
        "ld-metaball-orbit": ###"""
import SwiftUI

/// Metaball Orbit — two gooey blobs chase each other around a ring; when they
/// meet they fuse into a single liquid mass with a bridging neck, then split
/// apart with surface tension as the loop repeats.
///
/// The goo is pure `Canvas`: every blob is filled into ONE `drawLayer`, and the
/// layer is wrapped in `.alphaThreshold` + `.blur` so overlapping blurred edges
/// snap into a single solid metaball with a connecting neck — zero Metal.
///
/// - `demo == true`  → fully self-driving auto-orbit (the spec's previewLoop).
/// - `demo == false` → the same auto-orbit, plus a `DragGesture` that spawns a
///   third blob following your finger so you can manually fuse/split the goo;
///   on release it dissolves and the idle orbit resumes.
struct MetaballOrbitView: View {
    var demo: Bool = false

    // Finger-driven blob (interactive mode only).
    @State private var touchPoint: CGPoint? = nil
    @State private var touchStrength: CGFloat = 0   // 0…1 fade-in / fade-out

    // MARK: Palette (literal colors — no app dependencies)

    private let background = Color(red: 0.039, green: 0.063, blue: 0.078)   // ~#0a1014
    private let gooCore    = Color(red: 0.40,  green: 0.85,  blue: 1.00)
    private let gooEdge    = Color(red: 0.10,  green: 0.45,  blue: 0.95)
    private let gooHot     = Color(red: 0.85,  green: 0.97,  blue: 1.00)

    var body: some View {
        GeometryReader { geo in
            let size = geo.size
            TimelineView(.animation) { timeline in
                let t = timeline.date.timeIntervalSinceReferenceDate
                metaballCanvas(time: t, size: size)
            }
            .contentShape(Rectangle())
            .gesture(dragGesture(in: size), including: demo ? .none : .all)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .background(background)
    }

    // MARK: - Gesture (interactive mode)

    private func dragGesture(in size: CGSize) -> some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                touchPoint = clampPoint(value.location, in: size)
                withAnimation(.easeOut(duration: 0.18)) { touchStrength = 1 }
            }
            .onEnded { _ in
                withAnimation(.easeIn(duration: 0.32)) { touchStrength = 0 }
                // Leave touchPoint in place so the blob shrinks where it was.
                touchPoint = nil
            }
    }

    private func clampPoint(_ p: CGPoint, in size: CGSize) -> CGPoint {
        CGPoint(x: min(max(p.x, 0), size.width),
                y: min(max(p.y, 0), size.height))
    }

    // MARK: - Canvas

    private func metaballCanvas(time: Double, size: CGSize) -> some View {
        Canvas { context, canvasSize in
            let blobs = blobLayout(time: time, size: canvasSize)
            drawMetaballs(blobs, in: &context, size: canvasSize)
            drawHighlights(blobs, in: &context)
        }
    }

    /// Composite all blobs into a single layer, then threshold + blur the layer
    /// as a group so neighbouring blobs grow a connecting neck. Filters apply
    /// innermost-first (last added runs first): the blur softens the raw circles,
    /// then alphaThreshold snaps the blurred union back to a hard liquid
    /// silhouette so overlapping blobs fuse with a neck.
    private func drawMetaballs(_ blobs: [Blob],
                               in context: inout GraphicsContext,
                               size: CGSize) {
        let minDim = min(size.width, size.height)
        let blurRadius = minDim * 0.055

        var layer = context
        layer.addFilter(.alphaThreshold(min: 0.5, color: gooEdge))
        layer.addFilter(.blur(radius: blurRadius))
        layer.drawLayer { inner in
            for blob in blobs {
                let rect = CGRect(x: blob.center.x - blob.radius,
                                  y: blob.center.y - blob.radius,
                                  width: blob.radius * 2,
                                  height: blob.radius * 2)
                inner.fill(Circle().path(in: rect), with: .color(gooCore))
            }
        }
    }

    /// Tiny specular dots sit on top of the goo (outside the filtered layer) for
    /// a wet, liquid sheen. These are NOT thresholded.
    private func drawHighlights(_ blobs: [Blob],
                                in context: inout GraphicsContext) {
        for blob in blobs {
            let r = blob.radius * 0.26
            let c = CGPoint(x: blob.center.x - blob.radius * 0.32,
                            y: blob.center.y - blob.radius * 0.34)
            let rect = CGRect(x: c.x - r, y: c.y - r, width: r * 2, height: r * 2)
            let shading = GraphicsContext.Shading.radialGradient(
                Gradient(colors: [gooHot.opacity(0.9), gooHot.opacity(0)]),
                center: c, startRadius: 0, endRadius: r
            )
            context.fill(Circle().path(in: rect), with: shading)
        }
    }

    // MARK: - Layout / motion

    struct Blob {
        var center: CGPoint
        var radius: CGFloat
    }

    /// Positions the two orbiting blobs (plus the optional finger blob).
    /// The pair orbits at a constant base angle, but their *angular separation*
    /// oscillates so they sweep together (fuse → neck) and apart (split) every
    /// loop instead of just spinning rigidly.
    private func blobLayout(time: Double, size: CGSize) -> [Blob] {
        let minDim = min(size.width, size.height)
        let center = CGPoint(x: size.width / 2, y: size.height / 2)
        let orbitRadius = minDim * 0.20
        let baseBlobRadius = minDim * 0.155

        let loop: Double = 3.2
        let phase = time.truncatingRemainder(dividingBy: loop) / loop  // 0…1

        // Steady revolution of the whole pair.
        let revolution = (time / loop) * 2 * Double.pi

        // Separation breathes from wide-apart (~π) toward together (~0) and back.
        // sep ∈ [minSep, π]; near minSep the blobs overlap → fuse with a neck.
        let minSep: Double = 0.18
        let breathe = (1 - cos(phase * 2 * Double.pi)) / 2   // 0→1→0 over loop
        let separation = minSep + (Double.pi - minSep) * (1 - breathe)

        let angleA = revolution + separation / 2
        let angleB = revolution - separation / 2

        // Squash radius slightly as they merge so the mass conserves volume.
        let mergeAmount = breathe                              // 1 when fused
        let radius = baseBlobRadius * (1 + 0.10 * CGFloat(mergeAmount))

        let blobA = Blob(center: orbitPoint(center, orbitRadius, angleA),
                         radius: radius)
        let blobB = Blob(center: orbitPoint(center, orbitRadius, angleB),
                         radius: radius)

        var blobs = [blobA, blobB]

        if touchStrength > 0.001, let touch = touchPoint {
            blobs.append(Blob(center: touch,
                              radius: baseBlobRadius * (0.55 + 0.55 * touchStrength)))
        }
        return blobs
    }

    private func orbitPoint(_ center: CGPoint,
                            _ radius: CGFloat,
                            _ angle: Double) -> CGPoint {
        CGPoint(x: center.x + radius * CGFloat(cos(angle)),
                y: center.y + radius * CGFloat(sin(angle)))
    }
}
"""###,
        "ld-morse-pulse": ###"""
import SwiftUI

// MorsePulseView
// A single bar emits a looping Morse transmission: long dashes and short dots,
// the bar glowing and stretching for each pulse with crisp gaps between symbols.
// The word "INSPIRE" is encoded so the wait hides a real message.
//
// interaction: auto — the self-driving TimelineView loop IS the real component
// in both demo modes. iOS 17. No Metal.

public struct MorsePulseView: View {
    public var demo: Bool = false

    public init(demo: Bool = false) {
        self.demo = demo
    }

    public var body: some View {
        GeometryReader { geo in
            MorsePulseView_MorseStage(size: geo.size)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }
}

// MARK: - Morse symbol model

private enum MorsePulseView_MorseSignal {
    case dot
    case dash
    case symbolGap   // gap between dots/dashes inside one letter (1 unit)
    case letterGap   // gap between letters (3 units)
    case wordGap     // gap between words / loop reset (7 units)
}

private struct MorsePulseView_MorseSlot {
    let on: Bool
    let units: CGFloat
    let isDash: Bool   // only meaningful when on == true
}

private enum MorsePulseView_MorseSchedule {
    // International Morse for the letters in INSPIRE.
    // . = dot, - = dash
    static let letters: [String] = [
        "..",     // I
        "-.",     // N
        "...",    // S
        ".--.",   // P
        "..",     // I
        ".-.",    // R
        "."       // E
    ]

    // Expand the word into a flat on/off slot timeline measured in Morse "units".
    static let slots: [MorsePulseView_MorseSlot] = build()

    static let totalUnits: CGFloat = slots.reduce(0) { $0 + $1.units }

    private static func build() -> [MorsePulseView_MorseSlot] {
        var out: [MorsePulseView_MorseSlot] = []
        for (li, letter) in letters.enumerated() {
            let chars = Array(letter)
            for (ci, ch) in chars.enumerated() {
                let isDash = (ch == "-")
                out.append(MorsePulseView_MorseSlot(on: true,
                                     units: isDash ? 3 : 1,
                                     isDash: isDash))
                // symbol gap (1 unit) between elements within the same letter
                if ci < chars.count - 1 {
                    out.append(MorsePulseView_MorseSlot(on: false, units: 1, isDash: false))
                }
            }
            // letter gap (3 units) between letters
            if li < letters.count - 1 {
                out.append(MorsePulseView_MorseSlot(on: false, units: 3, isDash: false))
            }
        }
        // word gap (7 units) before the loop repeats
        out.append(MorsePulseView_MorseSlot(on: false, units: 7, isDash: false))
        return out
    }
}

// MARK: - Current state derived statelessly from elapsed time

private struct MorsePulseView_MorseState {
    var lit: Bool          // is a pulse currently transmitting
    var isDash: Bool       // dash vs dot for the active pulse
    var slotProgress: CGFloat   // 0...1 progress through the current slot
    var activeIndex: Int        // index of currently transmitting symbol (-1 if gap)
}

private enum MorsePulseView_MorseClock {
    // Seconds per Morse unit. Tuned so the whole "INSPIRE" cycle stays lively
    // (~3.5s) rather than dragging.
    static let unitSeconds: Double = 0.066

    static var cycleSeconds: Double {
        Double(MorsePulseView_MorseSchedule.totalUnits) * unitSeconds
    }

    static func state(at date: Date) -> MorsePulseView_MorseState {
        let cycle = cycleSeconds
        guard cycle > 0 else {
            return MorsePulseView_MorseState(lit: false, isDash: false, slotProgress: 0, activeIndex: -1)
        }
        let elapsed = date.timeIntervalSinceReferenceDate
        var t = CGFloat(elapsed.truncatingRemainder(dividingBy: cycle) / unitSeconds)
        if t < 0 { t += MorsePulseView_MorseSchedule.totalUnits }

        var symbolIndex = 0
        var cursor: CGFloat = 0
        for slot in MorsePulseView_MorseSchedule.slots {
            let end = cursor + slot.units
            if t < end {
                let within = (t - cursor) / max(slot.units, 0.0001)
                return MorsePulseView_MorseState(lit: slot.on,
                                  isDash: slot.isDash,
                                  slotProgress: min(max(within, 0), 1),
                                  activeIndex: slot.on ? symbolIndex : -1)
            }
            cursor = end
            if slot.on { symbolIndex += 1 }
        }
        return MorsePulseView_MorseState(lit: false, isDash: false, slotProgress: 1, activeIndex: -1)
    }
}

// MARK: - Stage

private struct MorsePulseView_MorseStage: View {
    let size: CGSize

    private var unit: CGFloat { min(size.width, size.height) }

    // Layout metrics relative to the tile.
    private var trackWidth: CGFloat { size.width * 0.62 }
    private var barHeight: CGFloat { max(unit * 0.085, 4) }
    private var dotWidth: CGFloat { trackWidth * 0.18 }
    private var dashWidth: CGFloat { trackWidth * 0.52 }
    private var glyphSize: CGFloat { max(unit * 0.05, 3) }

    var body: some View {
        TimelineView(.animation) { timeline in
            let st = MorsePulseView_MorseClock.state(at: timeline.date)
            ZStack {
                background
                VStack(spacing: unit * 0.14) {
                    pulseBar(state: st)
                    glyphTicker(activeIndex: st.activeIndex)
                }
            }
            .frame(width: size.width, height: size.height)
        }
    }

    // MARK: Background

    private var background: some View {
        let top = Color(red: 0.04, green: 0.06, blue: 0.08)
        let bottom = Color(red: 0.02, green: 0.03, blue: 0.05)
        return LinearGradient(colors: [top, bottom],
                              startPoint: .top,
                              endPoint: .bottom)
    }

    // MARK: Pulse bar

    @ViewBuilder
    private func pulseBar(state: MorsePulseView_MorseState) -> some View {
        let live = liveWidth(state: state)
        let glow = glowStrength(state: state)
        ZStack {
            // Persistent dim baseline track — always legible, never blank.
            Capsule(style: .continuous)
                .fill(Color(red: 0.10, green: 0.16, blue: 0.20))
                .overlay(
                    Capsule(style: .continuous)
                        .strokeBorder(Color(red: 0.16, green: 0.24, blue: 0.30),
                                      lineWidth: 1)
                )
                .frame(width: trackWidth, height: barHeight)

            // The glowing transmitting pulse, stretching from the left.
            Capsule(style: .continuous)
                .fill(pulseGradient)
                .frame(width: live, height: barHeight)
                .shadow(color: pulseGlowColor.opacity(0.85 * glow),
                        radius: barHeight * (1.4 + 2.6 * glow))
                .shadow(color: pulseGlowColor.opacity(0.55 * glow),
                        radius: barHeight * (0.6 + 1.0 * glow))
                .frame(width: trackWidth, alignment: .leading)
                .animation(.easeOut(duration: 0.05), value: state.lit)
        }
        .frame(width: trackWidth, height: barHeight)
    }

    private var pulseGradient: LinearGradient {
        let a = Color(red: 0.30, green: 0.95, blue: 0.78)
        let b = Color(red: 0.16, green: 0.80, blue: 0.95)
        return LinearGradient(colors: [a, b],
                              startPoint: .leading,
                              endPoint: .trailing)
    }

    private var pulseGlowColor: Color {
        Color(red: 0.24, green: 0.92, blue: 0.86)
    }

    // Width of the lit pulse. During a gap it collapses to a tiny lit nub at the
    // left so the track origin stays anchored and the transition reads crisply.
    private func liveWidth(state: MorsePulseView_MorseState) -> CGFloat {
        let nub = barHeight * 0.9   // minimum lit dot during gaps (still legible)
        guard state.lit else { return nub }
        let target = state.isDash ? dashWidth : dotWidth
        // Quick attack on the leading edge of a symbol so it "snaps" open.
        let attack = min(state.slotProgress / 0.22, 1)
        let eased = 1 - pow(1 - attack, 3)   // easeOutCubic
        return nub + (target - nub) * eased
    }

    // 0 during gaps, ~1 while transmitting (with a soft breathing pulse).
    private func glowStrength(state: MorsePulseView_MorseState) -> CGFloat {
        guard state.lit else { return 0 }
        let attack = min(state.slotProgress / 0.18, 1)
        let breathe = 0.85 + 0.15 * sin(state.slotProgress * .pi)
        return min(attack * breathe, 1)
    }

    // MARK: Glyph ticker (the hidden-message readout)

    @ViewBuilder
    private func glyphTicker(activeIndex: Int) -> some View {
        let glyphs = MorsePulseView_MorseGlyphs.flat
        HStack(spacing: glyphSize * 1.1) {
            ForEach(glyphs.indices, id: \.self) { i in
                glyphDot(symbol: glyphs[i], active: i == activeIndex)
            }
        }
        // Clamp the full readout to the track width so the 17 symbols stay
        // legible in a tiny ~120pt tile as well as the larger detail area.
        .frame(maxWidth: trackWidth)
        .fixedSize()
        .scaleEffect(tickerScale(count: glyphs.count), anchor: .center)
        .frame(maxWidth: trackWidth)
    }

    // Estimate the intrinsic ticker width and scale it down to fit the track.
    private func tickerScale(count: Int) -> CGFloat {
        guard count > 0 else { return 1 }
        let dashes = MorsePulseView_MorseGlyphs.flat.filter { $0 == .dash }.count
        let dots = count - dashes
        let symbolsWidth = CGFloat(dots) * glyphSize + CGFloat(dashes) * glyphSize * 3
        let spacing = CGFloat(max(count - 1, 0)) * glyphSize * 1.1
        let intrinsic = symbolsWidth + spacing
        guard intrinsic > 0 else { return 1 }
        return min(1, trackWidth / intrinsic)
    }

    @ViewBuilder
    private func glyphDot(symbol: MorsePulseView_MorseGlyphs.Glyph, active: Bool) -> some View {
        let w: CGFloat = symbol == .dash ? glyphSize * 3 : glyphSize
        let dim = Color(red: 0.18, green: 0.26, blue: 0.31)
        let hot = Color(red: 0.30, green: 0.95, blue: 0.82)
        Capsule(style: .continuous)
            .fill(active ? hot : dim)
            .frame(width: w, height: glyphSize)
            .shadow(color: hot.opacity(active ? 0.8 : 0),
                    radius: active ? glyphSize * 1.6 : 0)
            .scaleEffect(active ? 1.25 : 1.0)
            .animation(.easeOut(duration: 0.12), value: active)
    }
}

// MARK: - Glyph list (mirrors the transmitting on-symbols in order)

private enum MorsePulseView_MorseGlyphs {
    enum Glyph: Equatable { case dot, dash }

    // Flat ordered list of just the ON symbols across the whole word, so the
    // ticker index lines up with MorsePulseView_MorseState.activeIndex.
    static let flat: [Glyph] = build()

    private static func build() -> [Glyph] {
        var out: [Glyph] = []
        for slot in MorsePulseView_MorseSchedule.slots where slot.on {
            out.append(slot.isDash ? .dash : .dot)
        }
        return out
    }
}
"""###,
        "ld-orbital-electrons": ###"""
import SwiftUI

// MARK: - Orbital Electrons
// Three electron dots travel along tilted elliptical orbits around a glowing
// nucleus. Each orbit has its own period and in-plane rotation, so the dots
// weave in front of and behind the core. Depth is computed from the
// pre-rotation parametric (independent of in-plane rotation) so the z-order
// swaps read as genuine 3D, not a side effect of on-screen Y.
//
// This item's interactiveSpec is "auto — same as previewLoop", so BOTH the
// demo tile and the detail component self-drive via TimelineView(.animation).
// No gesture is wired (a loading spinner has none to wire); the detail simply
// runs the same continuous orbit at a calmer pace and a touch larger scale.

struct OrbitalElectronsView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { geo in
            TimelineView(.animation) { timeline in
                let t = timeline.date.timeIntervalSinceReferenceDate
                OrbitalElectronsView_AtomCanvas(time: t, size: geo.size, compact: demo)
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }
}

// MARK: - One orbital track

private struct OrbitalElectronsView_Orbit {
    /// Semi-major axis as a fraction of the layout's short side.
    let semiMajor: CGFloat
    /// Out-of-plane tilt (radians). Drives the semi-minor axis (cos) and the
    /// depth amplitude (sin) — i.e. how far the dot dives behind the nucleus.
    let tilt: CGFloat
    /// In-plane rotation of the whole ellipse on screen (radians).
    let planeRotation: CGFloat
    /// Seconds for one full revolution.
    let period: Double
    /// Starting phase offset (radians) so the three dots desync.
    let phaseOffset: CGFloat
    let color: Color
}

// MARK: - Canvas renderer

private struct OrbitalElectronsView_AtomCanvas: View {
    let time: Double
    let size: CGSize
    let compact: Bool

    private var orbits: [OrbitalElectronsView_Orbit] {
        // Distinct periods so the dots drift out of lockstep and weave.
        // Slightly slower in the larger detail view for a calmer feel.
        let speed: Double = compact ? 1.0 : 0.78
        return [
            OrbitalElectronsView_Orbit(semiMajor: 0.78, tilt: 1.15, planeRotation: 0,
                  period: 2.4 / speed, phaseOffset: 0.0,
                  color: Color(red: 0.39, green: 0.86, blue: 1.00)),     // cyan
            OrbitalElectronsView_Orbit(semiMajor: 0.82, tilt: 1.05, planeRotation: .pi / 3,
                  period: 3.0 / speed, phaseOffset: 2.1,
                  color: Color(red: 0.62, green: 0.55, blue: 1.00)),     // indigo
            OrbitalElectronsView_Orbit(semiMajor: 0.76, tilt: 1.22, planeRotation: 2 * .pi / 3,
                  period: 3.7 / speed, phaseOffset: 4.0,
                  color: Color(red: 1.00, green: 0.55, blue: 0.78))      // pink
        ]
    }

    var body: some View {
        Canvas { context, canvasSize in
            let center = CGPoint(x: canvasSize.width / 2, y: canvasSize.height / 2)
            let s = min(canvasSize.width, canvasSize.height)
            let R = s * 0.40               // base orbit radius
            let nucleusR = s * 0.115       // nucleus core radius
            let allOrbits = orbits

            // 1) Behind pass: ring arcs + dots with depth < 0 (far side).
            drawRingArcs(in: context, orbits: allOrbits, center: center,
                         baseR: R, front: false)
            drawElectrons(in: context, orbits: allOrbits, center: center,
                          baseR: R, s: s, front: false)

            // 2) The glowing nucleus, occluding the far side.
            drawNucleus(in: context, center: center, coreR: nucleusR, s: s)

            // 3) Front pass: ring arcs + dots with depth >= 0 (near side).
            drawRingArcs(in: context, orbits: allOrbits, center: center,
                         baseR: R, front: true)
            drawElectrons(in: context, orbits: allOrbits, center: center,
                          baseR: R, s: s, front: true)
        }
        .background(Color(red: 0.039, green: 0.063, blue: 0.078))
        .drawingGroup()
    }

    // MARK: Parametric point + depth

    /// Returns the on-screen point and a signed depth for a given orbit angle.
    /// Depth comes from the PRE-rotation parametric (R·sinθ·sinα) so its sign
    /// is independent of the in-plane rotation φ — the front/back swap always
    /// lands at θ = 0 and θ = π, never wherever the rotated ellipse looks low.
    private func point(orbit: OrbitalElectronsView_Orbit, theta: CGFloat,
                       center: CGPoint, baseR: CGFloat) -> (CGPoint, CGFloat) {
        let r: CGFloat = baseR * orbit.semiMajor
        let cosA: CGFloat = cos(orbit.tilt)
        let sinA: CGFloat = sin(orbit.tilt)

        let ex: CGFloat = r * cos(theta)
        let ey: CGFloat = r * sin(theta) * cosA
        let depth: CGFloat = r * sin(theta) * sinA

        let cosP: CGFloat = cos(orbit.planeRotation)
        let sinP: CGFloat = sin(orbit.planeRotation)
        let x: CGFloat = ex * cosP - ey * sinP
        let y: CGFloat = ex * sinP + ey * cosP

        let pt = CGPoint(x: center.x + x, y: center.y + y)
        return (pt, depth)
    }

    private func currentTheta(for orbit: OrbitalElectronsView_Orbit) -> CGFloat {
        let frac = CGFloat((time.truncatingRemainder(dividingBy: orbit.period)) / orbit.period)
        return frac * 2 * .pi + orbit.phaseOffset
    }

    // MARK: Ring arcs (behind / front split)

    private func drawRingArcs(in context: GraphicsContext, orbits: [OrbitalElectronsView_Orbit],
                              center: CGPoint, baseR: CGFloat, front: Bool) {
        let steps = 96
        for orbit in orbits {
            var path = Path()
            var penDown = false
            for i in 0...steps {
                let theta = CGFloat(i) / CGFloat(steps) * 2 * .pi
                let (pt, depth) = point(orbit: orbit, theta: theta,
                                        center: center, baseR: baseR)
                let inThisPass = front ? (depth >= 0) : (depth < 0)
                if inThisPass {
                    if penDown {
                        path.addLine(to: pt)
                    } else {
                        path.move(to: pt)
                        penDown = true
                    }
                } else {
                    penDown = false
                }
            }
            let alpha: Double = front ? 0.30 : 0.13
            context.stroke(
                path,
                with: .color(orbit.color.opacity(alpha)),
                style: StrokeStyle(lineWidth: front ? 1.6 : 1.2,
                                   lineCap: .round)
            )
        }
    }

    // MARK: Electron dots (behind / front split)

    private func drawElectrons(in context: GraphicsContext, orbits: [OrbitalElectronsView_Orbit],
                               center: CGPoint, baseR: CGFloat,
                               s: CGFloat, front: Bool) {
        for orbit in orbits {
            let theta = currentTheta(for: orbit)
            let (pt, depth) = point(orbit: orbit, theta: theta,
                                    center: center, baseR: baseR)
            let inThisPass = front ? (depth >= 0) : (depth < 0)
            guard inThisPass else { continue }
            drawDot(in: context, at: pt, depth: depth, orbit: orbit, s: s)
        }
    }

    private func drawDot(in context: GraphicsContext, at pt: CGPoint,
                         depth: CGFloat, orbit: OrbitalElectronsView_Orbit, s: CGFloat) {
        // Normalised depth -1...1: near side reads bigger and brighter.
        let maxDepth: CGFloat = s * 0.40 * orbit.semiMajor * sin(orbit.tilt)
        let norm: CGFloat = maxDepth > 0 ? max(-1, min(1, depth / maxDepth)) : 0
        let sizeScale: CGFloat = 0.80 + 0.45 * (norm + 1) / 2   // 0.80...1.25
        let bright: Double = 0.55 + 0.45 * Double((norm + 1) / 2)

        let dotR: CGFloat = s * 0.045 * sizeScale
        let glowR: CGFloat = dotR * 3.4

        // Soft halo.
        let glowRect = CGRect(x: pt.x - glowR, y: pt.y - glowR,
                              width: glowR * 2, height: glowR * 2)
        let glow = GraphicsContext.Shading.radialGradient(
            Gradient(colors: [
                orbit.color.opacity(0.55 * bright),
                orbit.color.opacity(0.0)
            ]),
            center: pt, startRadius: 0, endRadius: glowR
        )
        context.fill(Path(ellipseIn: glowRect), with: glow)

        // Solid core with a tiny bright center.
        let dotRect = CGRect(x: pt.x - dotR, y: pt.y - dotR,
                             width: dotR * 2, height: dotR * 2)
        let core = GraphicsContext.Shading.radialGradient(
            Gradient(colors: [
                Color.white.opacity(bright),
                orbit.color.opacity(bright)
            ]),
            center: CGPoint(x: pt.x - dotR * 0.25, y: pt.y - dotR * 0.25),
            startRadius: 0, endRadius: dotR
        )
        context.fill(Path(ellipseIn: dotRect), with: core)
    }

    // MARK: Nucleus

    private func drawNucleus(in context: GraphicsContext, center: CGPoint,
                             coreR: CGFloat, s: CGFloat) {
        // Subtle pulse so the core feels alive.
        let pulse: CGFloat = 1.0 + 0.06 * CGFloat(sin(time * 2.2))
        let glowR: CGFloat = coreR * 2.6 * pulse

        // Outer aura.
        let auraRect = CGRect(x: center.x - glowR, y: center.y - glowR,
                              width: glowR * 2, height: glowR * 2)
        let aura = GraphicsContext.Shading.radialGradient(
            Gradient(colors: [
                Color(red: 1.0, green: 0.86, blue: 0.55).opacity(0.45),
                Color(red: 1.0, green: 0.70, blue: 0.40).opacity(0.0)
            ]),
            center: center, startRadius: coreR * 0.4, endRadius: glowR
        )
        context.fill(Path(ellipseIn: auraRect), with: aura)

        // Hot core.
        let cr: CGFloat = coreR * pulse
        let coreRect = CGRect(x: center.x - cr, y: center.y - cr,
                              width: cr * 2, height: cr * 2)
        let core = GraphicsContext.Shading.radialGradient(
            Gradient(colors: [
                Color.white,
                Color(red: 1.0, green: 0.85, blue: 0.55),
                Color(red: 1.0, green: 0.55, blue: 0.30)
            ]),
            center: CGPoint(x: center.x - cr * 0.2, y: center.y - cr * 0.2),
            startRadius: 0, endRadius: cr
        )
        context.fill(Path(ellipseIn: coreRect), with: core)
    }
}
"""###,
        "ld-particle-assemble-logo": ###"""
import SwiftUI

/// Particle Assemble — a scattered cloud of particles flies inward and snaps
/// into a glyph/ring with a spring overshoot, holds, then disperses back into
/// the cloud and loops. Rendered entirely in a single `Canvas` for cheap
/// batch drawing. Self-driving via `TimelineView(.animation)`.
///
/// `interaction == "auto"`: both `demo == true` and `demo == false` run the
/// same self-driving loop. The interactive (non-demo) branch additionally
/// lets a tap re-trigger the assemble for a tactile beat.
struct ParticleAssembleLogoView: View {
    var demo: Bool = false

    // Restart anchor — a tap (interactive branch) re-seeds this so the
    // assemble re-fires from scattered. demo branch leaves it fixed.
    @State private var startDate = Date()

    private let particleCount = 72
    private let cycleDuration: Double = 3.4

    var body: some View {
        GeometryReader { geo in
            let size = geo.size
            TimelineView(.animation) { timeline in
                let elapsed = timeline.date.timeIntervalSince(startDate)
                canvas(elapsed: elapsed)
            }
            .id(size.width)   // re-anchor Canvas when the tile resizes
            .contentShape(Rectangle())
            .modifier(ParticleAssembleLogoView_TapRestart(enabled: !demo) { startDate = .now })
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // MARK: - Canvas

    @ViewBuilder
    private func canvas(elapsed: Double) -> some View {
        let progress = cycleProgress(elapsed: elapsed)
        Canvas { context, canvasSize in
            draw(into: &context, size: canvasSize, progress: progress)
        }
    }

    private func draw(into context: inout GraphicsContext,
                      size: CGSize,
                      progress: Double) {
        let center = CGPoint(x: size.width / 2, y: size.height / 2)
        let minSide = min(size.width, size.height)
        let targetRadius = minSide * 0.30
        let scatterRadius = minSide * 0.46
        let dotBase = max(minSide * 0.018, 1.2)

        // Soft halo when assembled so the formed glyph reads as "lit".
        let formed = formationStrength(progress)
        if formed > 0.02 {
            drawHalo(into: &context,
                     center: center,
                     radius: targetRadius,
                     strength: formed)
        }

        for index in 0..<particleCount {
            let p = particle(index: index,
                             center: center,
                             targetRadius: targetRadius,
                             scatterRadius: scatterRadius)
            let resolved = resolve(particle: p,
                                   index: index,
                                   progress: progress)
            drawDot(into: &context,
                    at: resolved.position,
                    radius: dotBase * resolved.scale,
                    alpha: resolved.alpha,
                    hue: p.hue,
                    glow: resolved.glow)
        }
    }

    // MARK: - Particle model

    struct Particle {
        var target: CGPoint
        var scatter: CGPoint
        var hue: Double      // 0..<1 along the spectrum used for tint
    }

    /// Deterministic — derived purely from `index`, so it is identical on
    /// every SwiftUI struct re-creation (no random() in the hot path).
    private func particle(index: Int,
                          center: CGPoint,
                          targetRadius: CGFloat,
                          scatterRadius: CGFloat) -> Particle {
        let count = Double(particleCount)
        let t = Double(index) / count

        // Target: evenly spaced points on a ring (always legible) with a
        // tiny deterministic radial jitter so it reads organic, not robotic.
        let targetAngle = t * 2.0 * .pi - .pi / 2.0
        let jitter = (hash(index, 7.1) - 0.5) * 0.10
        let tr = targetRadius * CGFloat(1.0 + jitter)
        let target = CGPoint(
            x: center.x + CGFloat(cos(Double(targetAngle))) * tr,
            y: center.y + CGFloat(sin(Double(targetAngle))) * tr
        )

        // Scatter: a different deterministic angle + radius, clamped so dots
        // stay inside bounds (never drawn off-screen / invisible).
        let scatterAngle = hash(index, 21.3) * 2.0 * .pi
        let sr = scatterRadius * CGFloat(0.55 + 0.45 * hash(index, 4.7))
        let scatter = CGPoint(
            x: center.x + CGFloat(cos(Double(scatterAngle))) * sr,
            y: center.y + CGFloat(sin(Double(scatterAngle))) * sr
        )

        return Particle(target: target, scatter: scatter, hue: t)
    }

    // MARK: - Resolution per frame

    struct Resolved {
        var position: CGPoint
        var scale: CGFloat
        var alpha: Double
        var glow: Double
    }

    private func resolve(particle p: Particle,
                         index: Int,
                         progress: Double) -> Resolved {
        let staggerMax = 0.32
        let delay = (Double(index) / Double(particleCount)) * staggerMax

        let assembleEnd = 0.40
        let holdEnd = 0.66

        if progress < assembleEnd {
            // Scatter -> target with spring overshoot (easeOutBack).
            let seg = (progress / assembleEnd)
            let local = staggered(seg, delay: delay, span: staggerMax)
            let eased = easeOutBack(local)
            let pos = lerp(p.scatter, p.target, CGFloat(eased))
            let alpha = 0.45 + 0.55 * local
            let scale = 0.7 + 0.3 * CGFloat(local)
            return Resolved(position: pos, scale: scale, alpha: alpha, glow: local)
        } else if progress < holdEnd {
            // Hold assembled, with a gentle breathing shimmer.
            let holdT = (progress - assembleEnd) / (holdEnd - assembleEnd)
            let breathe = 0.5 - 0.5 * cos(holdT * 2.0 * .pi)
            let scale = 1.0 + 0.12 * CGFloat(breathe)
            return Resolved(position: p.target, scale: scale, alpha: 1.0, glow: 1.0)
        } else {
            // Disperse target -> scatter (plain ease, reverse stagger).
            let seg = (progress - holdEnd) / (1.0 - holdEnd)
            let revDelay = staggerMax - delay
            let local = staggered(seg, delay: revDelay, span: staggerMax)
            let eased = easeInOut(local)
            let pos = lerp(p.target, p.scatter, CGFloat(eased))
            let alpha = 1.0 - 0.55 * local       // floored at 0.45, never blank
            let scale = 1.0 - 0.3 * CGFloat(local)
            let glow = 1.0 - local
            return Resolved(position: pos, scale: scale, alpha: alpha, glow: glow)
        }
    }

    /// 1.0 while assembled (during assemble-end..hold), ramps at the edges.
    private func formationStrength(_ progress: Double) -> Double {
        let assembleEnd = 0.40
        let holdEnd = 0.66
        if progress < assembleEnd {
            return easeInOut(min(1.0, progress / assembleEnd))
        } else if progress < holdEnd {
            return 1.0
        } else {
            let seg = (progress - holdEnd) / (1.0 - holdEnd)
            return 1.0 - easeInOut(seg)
        }
    }

    // MARK: - Drawing helpers

    private func drawDot(into context: inout GraphicsContext,
                         at point: CGPoint,
                         radius: CGFloat,
                         alpha: Double,
                         hue: Double,
                         glow: Double) {
        let r = max(radius, 0.5)
        let color = tint(for: hue)

        if glow > 0.05 {
            let glowRect = CGRect(x: point.x - r * 3.0,
                                  y: point.y - r * 3.0,
                                  width: r * 6.0,
                                  height: r * 6.0)
            let glowShading = GraphicsContext.Shading.radialGradient(
                Gradient(colors: [color.opacity(0.45 * glow * alpha),
                                  color.opacity(0.0)]),
                center: point,
                startRadius: 0,
                endRadius: r * 3.0
            )
            context.fill(Path(ellipseIn: glowRect), with: glowShading)
        }

        let rect = CGRect(x: point.x - r, y: point.y - r,
                          width: r * 2.0, height: r * 2.0)
        context.fill(Path(ellipseIn: rect),
                     with: .color(color.opacity(alpha)))
    }

    private func drawHalo(into context: inout GraphicsContext,
                          center: CGPoint,
                          radius: CGFloat,
                          strength: Double) {
        let outer = radius * 1.7
        let rect = CGRect(x: center.x - outer, y: center.y - outer,
                          width: outer * 2.0, height: outer * 2.0)
        let accent = tint(for: 0.55)
        let shading = GraphicsContext.Shading.radialGradient(
            Gradient(colors: [accent.opacity(0.0),
                              accent.opacity(0.16 * strength),
                              accent.opacity(0.0)]),
            center: center,
            startRadius: radius * 0.4,
            endRadius: outer
        )
        context.fill(Path(ellipseIn: rect), with: shading)
    }

    // MARK: - Color

    /// Cool teal -> cyan -> soft violet spectrum (no design-system deps).
    private func tint(for hue: Double) -> Color {
        let h = hue.truncatingRemainder(dividingBy: 1.0)
        // Interpolate between three anchor colors.
        let a = (red: 0.20, green: 0.85, blue: 0.78)   // teal
        let b = (red: 0.30, green: 0.62, blue: 1.00)   // blue
        let c = (red: 0.62, green: 0.45, blue: 1.00)   // violet
        if h < 0.5 {
            let t = h / 0.5
            return Color(red: lerpD(a.red, b.red, t),
                         green: lerpD(a.green, b.green, t),
                         blue: lerpD(a.blue, b.blue, t))
        } else {
            let t = (h - 0.5) / 0.5
            return Color(red: lerpD(b.red, c.red, t),
                         green: lerpD(b.green, c.green, t),
                         blue: lerpD(b.blue, c.blue, t))
        }
    }

    // MARK: - Math

    private func cycleProgress(elapsed: Double) -> Double {
        let safe = max(elapsed, 0.0)
        let m = safe.truncatingRemainder(dividingBy: cycleDuration)
        return m / cycleDuration
    }

    /// Per-particle local progress with a leading delay window.
    private func staggered(_ seg: Double, delay: Double, span: Double) -> Double {
        let denom = max(1.0 - span, 0.0001)
        let local = (seg - delay) / denom
        return min(max(local, 0.0), 1.0)
    }

    private func easeOutBack(_ x: Double) -> Double {
        let c1 = 1.70158
        let c3 = c1 + 1.0
        let p = x - 1.0
        return 1.0 + c3 * p * p * p + c1 * p * p
    }

    private func easeInOut(_ x: Double) -> Double {
        let c = min(max(x, 0.0), 1.0)
        return c < 0.5 ? 2.0 * c * c : 1.0 - pow(-2.0 * c + 2.0, 2.0) / 2.0
    }

    private func lerp(_ a: CGPoint, _ b: CGPoint, _ t: CGFloat) -> CGPoint {
        CGPoint(x: a.x + (b.x - a.x) * t,
                y: a.y + (b.y - a.y) * t)
    }

    private func lerpD(_ a: Double, _ b: Double, _ t: Double) -> Double {
        a + (b - a) * t
    }

    /// Pure deterministic 0..<1 hash from an integer index + salt.
    private func hash(_ i: Int, _ salt: Double) -> Double {
        let v = sin(Double(i) * 12.9898 + salt) * 43758.5453
        return v - v.rounded(.down)
    }
}

/// Conditionally attaches a tap-to-restart gesture (interactive branch only).
private struct ParticleAssembleLogoView_TapRestart: ViewModifier {
    let enabled: Bool
    let action: () -> Void

    func body(content: Content) -> some View {
        if enabled {
            content.onTapGesture { action() }
        } else {
            content
        }
    }
}
"""###,
        "ld-pendulum-newton": ###"""
import SwiftUI

/// Newton's Cradle — five suspended balls; the end ball arcs in, momentum
/// transfers through the dead-still middle three, and the far ball kicks out,
/// alternating sides forever.
///
/// - `demo == true`  → self-driving cradle on a continuous loop.
/// - `demo == false` → drag an end ball up about its pivot; release hands off
///   to the eased auto cradle cycle.
struct PendulumNewtonView: View {
    var demo: Bool = false

    // Loop period for one full left+right strike cycle (seconds).
    private let period: Double = 3.0
    // Maximum swing angle in degrees.
    private let maxAngle: Double = 52

    // Interactive drag state.
    @State private var dragAngle: Double = 0          // current dragged angle (deg, negative = left)
    @State private var isDragging: Bool = false
    @State private var releaseDate: Date? = nil       // when the user let go
    @State private var releaseAngle: Double = 0        // angle at release (deg)

    var body: some View {
        GeometryReader { geo in
            content(in: geo.size)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .background(backgroundColor)
    }

    private var backgroundColor: Color {
        Color(red: 0.039, green: 0.063, blue: 0.078)
    }

    // MARK: - Layout-derived metrics

    private func metrics(for size: CGSize) -> Metrics {
        let w = size.width
        let h = size.height
        let side = min(w, h)

        // Ball diameter sized so five touching balls fit comfortably across.
        let diameter = max(8, side * 0.16)
        let radius = diameter / 2

        // String length scales with available height.
        let stringLength = max(diameter * 1.1, side * 0.42)

        // Suspension bar sits in the upper portion; pivots spaced one diameter
        // apart so balls touch at rest.
        let totalWidth = diameter * 5
        let centerX = w / 2
        let firstPivotX = centerX - totalWidth / 2 + radius
        let barY = h / 2 - stringLength / 2 - radius * 0.4

        return Metrics(
            size: size,
            diameter: diameter,
            radius: radius,
            stringLength: stringLength,
            firstPivotX: firstPivotX,
            barY: barY
        )
    }

    struct Metrics {
        let size: CGSize
        let diameter: CGFloat
        let radius: CGFloat
        let stringLength: CGFloat
        let firstPivotX: CGFloat
        let barY: CGFloat

        func pivot(_ index: Int) -> CGPoint {
            CGPoint(x: firstPivotX + CGFloat(index) * diameter, y: barY)
        }
    }

    // MARK: - Content

    @ViewBuilder
    private func content(in size: CGSize) -> some View {
        let m = metrics(for: size)
        let base = TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            let angles = currentAngles(at: t)
            cradle(m: m, angles: angles)
        }
        .contentShape(Rectangle())

        if demo {
            base
        } else {
            base.gesture(dragGesture(for: m))
        }
    }

    @ViewBuilder
    private func cradle(m: Metrics, angles: [Double]) -> some View {
        ZStack {
            suspensionBar(m: m)
            ForEach(0..<5, id: \.self) { i in
                pendulum(index: i, angle: angles[i], m: m)
            }
        }
    }

    // MARK: - Subviews

    private func suspensionBar(m: Metrics) -> some View {
        let leftX = m.pivot(0).x
        let rightX = m.pivot(4).x
        let barWidth = (rightX - leftX) + m.diameter
        return Capsule()
            .fill(barGradient)
            .frame(width: barWidth, height: max(4, m.diameter * 0.18))
            .overlay(
                Capsule()
                    .stroke(Color(red: 1, green: 1, blue: 1).opacity(0.18), lineWidth: 0.6)
            )
            .position(x: (leftX + rightX) / 2, y: m.barY)
            .shadow(color: Color(red: 0, green: 0, blue: 0).opacity(0.5),
                    radius: 4, x: 0, y: 2)
    }

    private var barGradient: LinearGradient {
        LinearGradient(
            colors: [
                Color(red: 0.42, green: 0.46, blue: 0.52),
                Color(red: 0.20, green: 0.23, blue: 0.28)
            ],
            startPoint: .top, endPoint: .bottom
        )
    }

    /// A single pendulum (string + ball) rotated about its top pivot.
    private func pendulum(index: Int, angle: Double, m: Metrics) -> some View {
        let pivot = m.pivot(index)
        return PendulumNewtonView_PendulumArm(stringLength: m.stringLength, radius: m.radius)
            .rotationEffect(.degrees(angle), anchor: .top)
            // The arm's natural top is the pivot point; place it there.
            .frame(width: m.diameter, height: m.stringLength + m.diameter)
            .position(x: pivot.x, y: pivot.y + (m.stringLength + m.diameter) / 2)
    }

    // MARK: - Angle model

    /// Phase progress in [0, 1) for the auto loop at a given absolute time.
    private func autoPhase(at t: Double) -> Double {
        let p = (t.truncatingRemainder(dividingBy: period)) / period
        return p < 0 ? p + 1 : p
    }

    /// Pure angle function: a single sine drives one end ball per half-cycle.
    /// Negative = the left end ball swung outward to the left;
    /// positive = the right end ball swung outward to the right.
    /// Returns angles (deg) for all five balls; middle three are always 0.
    private func autoAngles(phase: Double) -> [Double] {
        // Offset so the loop starts with a raised ball rather than centered.
        let shifted = (phase + 0.75).truncatingRemainder(dividingBy: 1.0)
        let s = sin(2.0 * .pi * shifted)
        let left = s < 0 ? maxAngle * s : 0      // s<0 → negative angle (left)
        let right = s > 0 ? maxAngle * s : 0     // s>0 → positive angle (right)
        return [left, 0, 0, 0, right]
    }

    /// Maps a raised left-ball angle (negative, in [-maxAngle, 0]) to the auto
    /// loop phase at which the left ball sits at that angle while swinging down.
    /// The left ball spans phase 0 (fully raised) → 0.25 (centered).
    private func phaseForLeftAngle(_ angle: Double) -> Double {
        let clamped = min(0, max(-maxAngle, angle))
        let s = clamped / maxAngle            // in [-1, 0]
        // left angle = maxAngle * sin(2π(phase + 0.75)); solve for phase.
        return 0.25 + asin(s) / (2.0 * .pi)   // in [0, 0.25]
    }

    /// Resolves the angle array for the current frame, blending in the
    /// interactive drag / release handoff when not in demo mode.
    private func currentAngles(at t: Double) -> [Double] {
        if demo {
            return autoAngles(phase: autoPhase(at: t))
        }

        if isDragging {
            // Left end ball follows the finger; others rest.
            return [dragAngle, 0, 0, 0, 0]
        }

        if let release = releaseDate {
            // Resume the loop at the phase matching the released angle so the
            // dragged left ball continues its eased swing-down without a jump,
            // then hands off to the auto cradle cycle.
            let elapsed = t - release.timeIntervalSinceReferenceDate
            let startPhase = phaseForLeftAngle(releaseAngle)
            let raw = (startPhase + elapsed / period).truncatingRemainder(dividingBy: 1.0)
            return autoAngles(phase: raw < 0 ? raw + 1 : raw)
        }

        // Idle before any interaction: keep it alive with the auto loop too.
        return autoAngles(phase: autoPhase(at: t))
    }

    // MARK: - Gesture

    private func dragGesture(for m: Metrics) -> some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                isDragging = true
                releaseDate = nil
                // Map horizontal translation to a swing angle about the left
                // pivot. Dragging left raises the left ball (negative angle).
                let dx = value.translation.width
                let dy = value.translation.height
                // atan2 about the pivot gives a natural arc; clamp to maxAngle.
                let raw = atan2(dx, max(1, m.stringLength + dy)) * 180 / .pi
                dragAngle = min(0, max(-maxAngle, raw))
            }
            .onEnded { _ in
                isDragging = false
                releaseAngle = dragAngle
                releaseDate = Date()
            }
    }
}

// MARK: - Pendulum arm (string + ball)

/// A top-anchored arm: a thin string from the top down to a metallic ball.
/// Its visual top edge is the pivot, so rotating with anchor `.top` swings it.
private struct PendulumNewtonView_PendulumArm: View {
    let stringLength: CGFloat
    let radius: CGFloat

    var body: some View {
        VStack(spacing: 0) {
            stringShape
                .stroke(stringGradient, lineWidth: max(1, radius * 0.07))
                .frame(width: radius * 2, height: stringLength)
            PendulumNewtonView_BallView(radius: radius)
        }
    }

    private var stringShape: some Shape {
        PendulumNewtonView_StringLine()
    }

    private var stringGradient: LinearGradient {
        LinearGradient(
            colors: [
                Color(red: 0.55, green: 0.58, blue: 0.62).opacity(0.9),
                Color(red: 0.30, green: 0.32, blue: 0.36).opacity(0.7)
            ],
            startPoint: .top, endPoint: .bottom
        )
    }
}

/// A vertical line down the center of its rect (the string).
private struct PendulumNewtonView_StringLine: Shape {
    func path(in rect: CGRect) -> Path {
        var p = Path()
        p.move(to: CGPoint(x: rect.midX, y: rect.minY))
        p.addLine(to: CGPoint(x: rect.midX, y: rect.maxY))
        return p
    }
}

/// A polished chrome ball with a specular highlight.
private struct PendulumNewtonView_BallView: View {
    let radius: CGFloat

    var body: some View {
        Circle()
            .fill(sphereGradient)
            .overlay(rim)
            .overlay(highlight)
            .frame(width: radius * 2, height: radius * 2)
            .shadow(color: Color(red: 0, green: 0, blue: 0).opacity(0.45),
                    radius: radius * 0.18, x: 0, y: radius * 0.12)
    }

    private var sphereGradient: RadialGradient {
        RadialGradient(
            colors: [
                Color(red: 0.86, green: 0.89, blue: 0.94),
                Color(red: 0.55, green: 0.60, blue: 0.68),
                Color(red: 0.20, green: 0.23, blue: 0.29)
            ],
            center: UnitPoint(x: 0.35, y: 0.30),
            startRadius: 0,
            endRadius: radius * 1.9
        )
    }

    private var rim: some View {
        Circle()
            .stroke(Color(red: 1, green: 1, blue: 1).opacity(0.22),
                    lineWidth: max(0.5, radius * 0.04))
    }

    private var highlight: some View {
        Ellipse()
            .fill(Color(red: 1, green: 1, blue: 1).opacity(0.55))
            .frame(width: radius * 0.6, height: radius * 0.4)
            .blur(radius: radius * 0.08)
            .offset(x: -radius * 0.32, y: -radius * 0.42)
    }
}
"""###,
        "ld-radar-sweep": ###"""
import SwiftUI

// MARK: - Radar Sweep
// A rotating gradient wedge sweeps around a circular grid of range rings.
// Randomly-placed (but FIXED) blips ignite as the beam crosses them, then
// fade on a CRT-phosphor exponential decay. Brightness is a pure stateless
// function of the current sweep angle — no per-blip mutation during render.

struct RadarSweepView: View {
    var demo: Bool = false

    // Phosphor green palette (no app dependencies, literal colors only).
    private let beamColor = Color(red: 0.36, green: 1.0, blue: 0.55)
    private let gridColor = Color(red: 0.22, green: 0.62, blue: 0.40)
    private let bgInner = Color(red: 0.02, green: 0.07, blue: 0.05)
    private let bgOuter = Color(red: 0.01, green: 0.03, blue: 0.02)

    // Fixed blips: angle + radiusFraction. Generated ONCE, never per frame.
    private let blips: [Blip] = RadarSweepView.makeBlips()

    // Interactive (demo == false) scrub state.
    @State private var manualAngle: Double? = nil   // non-nil while dragging

    // Sweep tuning.
    private let degreesPerSecond: Double = 110       // ~3.3s per revolution
    private let tau: Double = 48                      // phosphor tail length in degrees

    var body: some View {
        GeometryReader { geo in
            let side = min(geo.size.width, geo.size.height)
            let center = CGPoint(x: geo.size.width / 2, y: geo.size.height / 2)
            let radius = side * 0.46

            ZStack {
                background(radius: radius)
                TimelineView(.animation) { timeline in
                    let auto = autoAngle(at: timeline.date)
                    let angle = manualAngle ?? auto
                    scope(center: center, radius: radius, sweep: angle)
                }
            }
            .frame(width: geo.size.width, height: geo.size.height)
            .contentShape(Rectangle())
            // NOTE: `.gesture(demo ? nil : gesture)` fails to type-check on iOS 17
            // because Optional<Gesture> does not conform to Gesture. Always pass a
            // concrete gesture and mask it off in demo mode via `including:`.
            .gesture(scrubGesture(center: center), including: demo ? .subviews : .all)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // MARK: Layers

    private func background(radius: CGFloat) -> some View {
        RadialGradient(
            colors: [bgInner, bgOuter],
            center: .center,
            startRadius: 0,
            endRadius: max(radius * 1.4, 1)
        )
    }

    @ViewBuilder
    private func scope(center: CGPoint, radius: CGFloat, sweep: Double) -> some View {
        ZStack {
            rangeRings(center: center, radius: radius)
            crosshair(center: center, radius: radius)
            blipLayer(center: center, radius: radius, sweep: sweep)
            beam(center: center, radius: radius, sweep: sweep)
            hub(center: center, radius: radius)
        }
        .clipShape(Circle().path(in: scopeRect(center: center, radius: radius)))
        .overlay(
            Circle()
                .stroke(gridColor.opacity(0.9), lineWidth: 1.5)
                .frame(width: radius * 2, height: radius * 2)
                .position(center)
        )
    }

    private func scopeRect(center: CGPoint, radius: CGFloat) -> CGRect {
        CGRect(x: center.x - radius, y: center.y - radius,
               width: radius * 2, height: radius * 2)
    }

    // Concentric range rings.
    private func rangeRings(center: CGPoint, radius: CGFloat) -> some View {
        ForEach(1..<4, id: \.self) { i in
            let frac = CGFloat(i) / 4.0
            Circle()
                .stroke(gridColor.opacity(0.30), lineWidth: 1)
                .frame(width: radius * 2 * frac, height: radius * 2 * frac)
                .position(center)
        }
    }

    // Crosshair: four lines at 0/45/90/135 degrees through the center.
    private func crosshair(center: CGPoint, radius: CGFloat) -> some View {
        ZStack {
            ForEach(0..<4, id: \.self) { i in
                Rectangle()
                    .fill(gridColor.opacity(0.22))
                    .frame(width: radius * 2, height: 1)
                    .rotationEffect(.degrees(Double(i) * 45))
                    .position(center)
            }
        }
    }

    // The rotating gradient wedge (transparent -> green) trailing the leading edge.
    private func beam(center: CGPoint, radius: CGFloat, sweep: Double) -> some View {
        let grad = AngularGradient(
            gradient: Gradient(stops: [
                .init(color: beamColor.opacity(0.0), location: 0.0),
                .init(color: beamColor.opacity(0.05), location: 0.55),
                .init(color: beamColor.opacity(0.22), location: 0.86),
                .init(color: beamColor.opacity(0.55), location: 0.99),
                .init(color: beamColor.opacity(0.0), location: 1.0)
            ]),
            center: .center
        )
        return ZStack {
            // Soft wedge fill rotated to the sweep angle.
            Circle()
                .fill(grad)
                .frame(width: radius * 2, height: radius * 2)
                .rotationEffect(.degrees(sweep), anchor: .center)
                .position(center)
            // Crisp leading edge line of the sweep.
            Rectangle()
                .fill(
                    LinearGradient(
                        colors: [beamColor.opacity(0.0), beamColor.opacity(0.95)],
                        startPoint: .leading, endPoint: .trailing
                    )
                )
                .frame(width: radius, height: 2)
                .offset(x: radius / 2)
                .rotationEffect(.degrees(sweep), anchor: .center)
                .position(center)
                .shadow(color: beamColor.opacity(0.6), radius: 4)
        }
        .compositingGroup()
    }

    // Blips drawn in a single Canvas; brightness = phosphor decay of the sweep.
    private func blipLayer(center: CGPoint, radius: CGFloat, sweep: Double) -> some View {
        Canvas { ctx, _ in
            for blip in blips {
                let bright = brightness(for: blip.angle, sweep: sweep)
                let p = point(center: center, radius: radius, blip: blip)
                drawBlip(ctx: &ctx, at: p, brightness: bright, size: blip.size)
            }
        }
    }

    private func drawBlip(ctx: inout GraphicsContext, at p: CGPoint,
                          brightness: Double, size: CGFloat) {
        let glow = size * (1.4 + 2.2 * brightness)
        let glowRect = CGRect(x: p.x - glow, y: p.y - glow, width: glow * 2, height: glow * 2)
        let coreRect = CGRect(x: p.x - size, y: p.y - size, width: size * 2, height: size * 2)

        // Soft halo.
        ctx.fill(
            Circle().path(in: glowRect),
            with: .radialGradient(
                Gradient(colors: [
                    beamColor.opacity(0.45 * brightness),
                    beamColor.opacity(0.0)
                ]),
                center: p, startRadius: 0, endRadius: glow
            )
        )
        // Bright core (with a faint resting floor so it stays legible).
        ctx.fill(
            Circle().path(in: coreRect),
            with: .color(beamColor.opacity(0.20 + 0.80 * brightness))
        )
    }

    private func hub(center: CGPoint, radius: CGFloat) -> some View {
        let d = max(4, radius * 0.05)
        return Circle()
            .fill(beamColor.opacity(0.9))
            .frame(width: d, height: d)
            .shadow(color: beamColor.opacity(0.8), radius: 4)
            .position(center)
    }

    // MARK: Math (stateless phosphor decay)

    private func autoAngle(at date: Date) -> Double {
        let t = date.timeIntervalSinceReferenceDate
        return (t * degreesPerSecond).truncatingRemainder(dividingBy: 360)
    }

    // How far (in degrees, 0..<360) the beam has swept *past* this blip.
    // small lag -> just illuminated (bright); near 360 -> about to be hit again (dim).
    private func brightness(for blipAngle: Double, sweep: Double) -> Double {
        var lag = (sweep - blipAngle).truncatingRemainder(dividingBy: 360)
        if lag < 0 { lag += 360 }
        let decay = exp(-lag / tau)
        return max(decay, 0.06)   // resting floor keeps blips faintly visible
    }

    private func point(center: CGPoint, radius: CGFloat, blip: Blip) -> CGPoint {
        let r = radius * blip.radiusFraction
        let rad: CGFloat = CGFloat(blip.angle) * .pi / 180
        return CGPoint(x: center.x + r * cos(rad), y: center.y + r * sin(rad))
    }

    // MARK: Interaction (demo == false): drag to scrub, release resumes auto.

    private func scrubGesture(center: CGPoint) -> some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                let dx = value.location.x - center.x
                let dy = value.location.y - center.y
                var deg = atan2(dy, dx) * 180 / .pi
                if deg < 0 { deg += 360 }
                manualAngle = deg
            }
            .onEnded { _ in
                manualAngle = nil   // resume self-driving sweep
            }
    }

    // MARK: Fixed blip generation (ONCE, at init — never per frame).

    struct Blip {
        let angle: Double          // degrees, 0..<360
        let radiusFraction: CGFloat
        let size: CGFloat
    }

    private static func makeBlips() -> [Blip] {
        // Deterministic seeded generator so positions are fixed and never teleport.
        var rng = SeededGenerator(seed: 0xC0FFEE)
        var result: [Blip] = []
        for _ in 0..<7 {
            let angle = Double.random(in: 0..<360, using: &rng)
            let frac = CGFloat(Double.random(in: 0.22...0.92, using: &rng))
            let size = CGFloat(Double.random(in: 2.2...4.0, using: &rng))
            result.append(Blip(angle: angle, radiusFraction: frac, size: size))
        }
        return result
    }

    struct SeededGenerator: RandomNumberGenerator {
        private var state: UInt64
        init(seed: UInt64) { state = seed &+ 0x9E3779B97F4A7C15 }
        mutating func next() -> UInt64 {
            state = state &* 6364136223846793005 &+ 1442695040888963407
            var z = state
            z = (z ^ (z >> 30)) &* 0xBF58476D1CE4E5B9
            z = (z ^ (z >> 27)) &* 0x94D049BB133111EB
            return z ^ (z >> 31)
        }
    }
}
"""###,
        "ld-sand-hourglass": ###"""
import SwiftUI

/// Sand Hourglass — grains stream from the source chamber through the pinched
/// neck and pile into a sloped heap below; when the source empties the whole
/// glass flips 180° (auto, or on tap when interactive) and the flow reverses.
///
/// Architecture: the sim is a pure function of time. `fill` (0…1) is derived
/// from `now - lastFlip`. The ONLY mutating state is `flipCount` + `lastFlip`,
/// changed from `.onChange` (outside the view-update pass). A single
/// `sourceIsTop` boolean (parity of `flipCount`) drives the draining cone, the
/// growing heap, and the grain direction together so they can never desync.
struct SandHourglassView: View {
    var demo: Bool = false

    // Mutating state — kept minimal and changed only outside body.
    @State private var flipCount: Int = 0
    @State private var lastFlip: Date = .distantPast
    @State private var didAppear: Bool = false

    // Drain duration for one chamber, in seconds.
    private let period: Double = 3.0

    var body: some View {
        GeometryReader { geo in
            TimelineView(.animation) { timeline in
                let now = timeline.date
                let fill = drainFraction(now: now)
                let elapsed = elapsedSinceFlip(now: now)

                content(in: geo.size, now: now, fill: fill)
                    // Auto-flip when the source chamber empties. Fired from
                    // onChange so we never mutate state inside the timeline body.
                    .onChange(of: elapsed >= period) { _, full in
                        guard didAppear, full else { return }
                        performFlip(at: now)
                    }
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .onAppear {
            // Seed the clock on first frame so a stale init date can't trigger
            // an immediate phantom flip.
            if !didAppear {
                lastFlip = Date()
                didAppear = true
            }
        }
    }

    // MARK: - Derived sim values

    private func elapsedSinceFlip(now: Date) -> Double {
        guard didAppear else { return 0 }
        return max(0, now.timeIntervalSince(lastFlip))
    }

    /// Eased drain fraction 0…1 for the current chamber.
    private func drainFraction(now: Date) -> Double {
        let raw = min(1.0, elapsedSinceFlip(now: now) / period)
        // Ease-in-out so the stream feels like it tapers at the start/end.
        return raw * raw * (3.0 - 2.0 * raw)
    }

    private func performFlip(at now: Date) {
        withAnimation(.spring(response: 0.6, dampingFraction: 0.55)) {
            flipCount += 1
        }
        lastFlip = now
    }

    // MARK: - Composition

    @ViewBuilder
    private func content(in size: CGSize, now: Date, fill: Double) -> some View {
        let metrics = SandHourglassView_SandHourglassMetrics(size: size)
        let sourceIsTop = (flipCount % 2 == 0)

        ZStack {
            backdrop

            ZStack {
                glassBody(metrics: metrics)
                sandLayer(metrics: metrics, fill: fill, sourceIsTop: sourceIsTop)
                grainStream(metrics: metrics, fill: fill, sourceIsTop: sourceIsTop, now: now)
                glassFrame(metrics: metrics)
                neckBand(metrics: metrics)
            }
            // The whole assembly flips in-plane 180° per flip. 2D rotation
            // (not 3D about Y) avoids the horizontal mirror that would warp the
            // asymmetric heap.
            .rotationEffect(.degrees(Double(flipCount) * 180.0))
            .frame(width: metrics.glassWidth, height: metrics.glassHeight)

            capPair(metrics: metrics)
        }
        .frame(width: size.width, height: size.height)
        .contentShape(Rectangle())
        .modifier(SandHourglassView_TapFlip(enabled: !demo) { performFlip(at: now) })
    }

    private var backdrop: some View {
        RadialGradient(
            colors: [
                Color(red: 0.09, green: 0.12, blue: 0.16),
                Color(red: 0.04, green: 0.05, blue: 0.07)
            ],
            center: .center,
            startRadius: 2,
            endRadius: 220
        )
    }

    // MARK: - Glass

    private func glassBody(metrics: SandHourglassView_SandHourglassMetrics) -> some View {
        SandHourglassView_SandHourglassGlassShape(metrics: metrics)
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.16, green: 0.20, blue: 0.26).opacity(0.55),
                        Color(red: 0.08, green: 0.11, blue: 0.15).opacity(0.35)
                    ],
                    startPoint: .topLeading,
                    endPoint: .bottomTrailing
                )
            )
    }

    private func glassFrame(metrics: SandHourglassView_SandHourglassMetrics) -> some View {
        SandHourglassView_SandHourglassGlassShape(metrics: metrics)
            .stroke(
                LinearGradient(
                    colors: [
                        Color(red: 0.78, green: 0.84, blue: 0.92).opacity(0.85),
                        Color(red: 0.40, green: 0.48, blue: 0.58).opacity(0.65)
                    ],
                    startPoint: .top,
                    endPoint: .bottom
                ),
                lineWidth: max(1.4, metrics.glassWidth * 0.022)
            )
            // Subtle glassy highlight along one edge.
            .overlay(
                SandHourglassView_SandHourglassGlassShape(metrics: metrics)
                    .trim(from: 0.02, to: 0.20)
                    .stroke(Color.white.opacity(0.35),
                            style: StrokeStyle(lineWidth: max(1, metrics.glassWidth * 0.012),
                                               lineCap: .round))
            )
    }

    private func neckBand(metrics: SandHourglassView_SandHourglassMetrics) -> some View {
        Capsule()
            .fill(Color(red: 0.30, green: 0.36, blue: 0.44).opacity(0.7))
            .frame(width: metrics.neckWidth * 1.8,
                   height: metrics.neckHeight * 0.6)
            .position(x: metrics.midX, y: metrics.midY)
    }

    private func capPair(metrics: SandHourglassView_SandHourglassMetrics) -> some View {
        VStack(spacing: 0) {
            cap(metrics: metrics)
            Spacer(minLength: 0)
            cap(metrics: metrics)
        }
        .frame(width: metrics.glassWidth * 1.04, height: metrics.glassHeight)
    }

    private func cap(metrics: SandHourglassView_SandHourglassMetrics) -> some View {
        RoundedRectangle(cornerRadius: metrics.capHeight * 0.45, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.52, green: 0.36, blue: 0.20),
                        Color(red: 0.32, green: 0.21, blue: 0.11)
                    ],
                    startPoint: .top,
                    endPoint: .bottom
                )
            )
            .frame(height: metrics.capHeight)
    }

    // MARK: - Sand (cone + heap)

    @ViewBuilder
    private func sandLayer(metrics: SandHourglassView_SandHourglassMetrics,
                           fill: Double,
                           sourceIsTop: Bool) -> some View {
        let sand = sandGradient
        let remaining = 1.0 - fill

        // Draining cone in the source chamber; growing heap in the dest chamber.
        SandHourglassView_SandHourglassConeShape(metrics: metrics, level: remaining, atTop: sourceIsTop)
            .fill(sand)
            .clipShape(SandHourglassView_SandHourglassGlassShape(metrics: metrics))

        SandHourglassView_SandHourglassHeapShape(metrics: metrics, amount: fill, atTop: !sourceIsTop)
            .fill(sand)
            .clipShape(SandHourglassView_SandHourglassGlassShape(metrics: metrics))
            // soft top edge on the heap
            .overlay(
                SandHourglassView_SandHourglassHeapShape(metrics: metrics, amount: fill, atTop: !sourceIsTop)
                    .stroke(Color(red: 0.98, green: 0.86, blue: 0.55).opacity(0.5),
                            lineWidth: 1)
                    .clipShape(SandHourglassView_SandHourglassGlassShape(metrics: metrics))
            )
    }

    private var sandGradient: LinearGradient {
        LinearGradient(
            colors: [
                Color(red: 0.97, green: 0.82, blue: 0.45),
                Color(red: 0.85, green: 0.62, blue: 0.28)
            ],
            startPoint: .top,
            endPoint: .bottom
        )
    }

    // MARK: - Falling grains (deterministic per-grain functions of time)

    private func grainStream(metrics: SandHourglassView_SandHourglassMetrics,
                             fill: Double,
                             sourceIsTop: Bool,
                             now: Date) -> some View {
        // Hide the stream only at the very end of a chamber, so a fresh stream
        // is always visible just after the flip.
        let intensity = grainIntensity(fill: fill)
        let t = now.timeIntervalSinceReferenceDate

        return Canvas { ctx, _ in
            guard intensity > 0.01 else { return }
            let count = 26
            // Travel goes from the neck toward the destination floor in LOCAL y.
            let startY = metrics.midY
            // Destination floor in local coords (where the heap sits).
            let destFloor = sourceIsTop ? metrics.bottomFloorY : metrics.topFloorY
            let dir: CGFloat = sourceIsTop ? 1 : -1   // +y down, -y up after flip
            let travel = abs(destFloor - startY)

            for i in 0..<count {
                let seed = Double(i) * 0.61803398875
                let phase = (t * 1.15 + seed).truncatingRemainder(dividingBy: 1.0)
                // progress 0 (neck) → 1 (landing)
                let p = CGFloat(phase)
                // small horizontal jitter scattering around the neck axis
                let wobble = sin((t * 3.0) + seed * 6.28) * Double(metrics.neckWidth) * 0.22
                let x = metrics.midX + CGFloat(wobble) * (0.3 + p * 0.7)
                let y = startY + dir * travel * p
                let r = metrics.neckWidth * 0.10

                let rect = CGRect(x: x - r, y: y - r, width: r * 2, height: r * 2)
                let alpha = (0.35 + 0.65 * (1 - p)) * CGFloat(intensity)
                ctx.fill(
                    Path(ellipseIn: rect),
                    with: .color(Color(red: 0.99, green: 0.85, blue: 0.50).opacity(Double(alpha)))
                )
            }
        }
        .frame(width: metrics.glassWidth, height: metrics.glassHeight)
        .allowsHitTesting(false)
    }

    private func grainIntensity(fill: Double) -> Double {
        // Fade the stream in at the start and out as the chamber empties.
        let inRamp = min(1.0, fill / 0.06)
        let outRamp = min(1.0, (1.0 - fill) / 0.06)
        return max(0.0, min(inRamp, outRamp))
    }
}

// MARK: - Tap-to-flip modifier (only active when interactive)

private struct SandHourglassView_TapFlip: ViewModifier {
    let enabled: Bool
    let action: () -> Void

    func body(content: Content) -> some View {
        if enabled {
            content.onTapGesture { action() }
        } else {
            content
        }
    }
}

// MARK: - Metrics

private struct SandHourglassView_SandHourglassMetrics {
    let size: CGSize
    let glassWidth: CGFloat
    let glassHeight: CGFloat
    let originX: CGFloat
    let originY: CGFloat

    init(size: CGSize) {
        self.size = size
        let side = min(size.width, size.height)
        // Glass is taller than wide.
        let w = side * 0.62
        let h = side * 0.92
        self.glassWidth = w
        self.glassHeight = h
        self.originX = (size.width - w) / 2
        self.originY = (size.height - h) / 2
    }

    // All coordinates below are in the rotated assembly's local frame, which is
    // sized exactly glassWidth × glassHeight (origin at 0,0 top-left).
    var midX: CGFloat { glassWidth / 2 }
    var midY: CGFloat { glassHeight / 2 }

    var capHeight: CGFloat { glassHeight * 0.06 }
    var topFloorY: CGFloat { capHeight }                 // inside top, just below cap
    var bottomFloorY: CGFloat { glassHeight - capHeight } // inside bottom, above cap
    var chamberHeight: CGFloat { midY - topFloorY }

    var neckWidth: CGFloat { glassWidth * 0.12 }
    var neckHeight: CGFloat { glassHeight * 0.05 }
    var bulbWidth: CGFloat { glassWidth }
}

// MARK: - Glass outline shape

private struct SandHourglassView_SandHourglassGlassShape: Shape {
    let metrics: SandHourglassView_SandHourglassMetrics

    func path(in rect: CGRect) -> Path {
        let m = metrics
        let halfNeck = m.neckWidth / 2
        let halfBulb = m.bulbWidth / 2 - m.bulbWidth * 0.04
        let cx = rect.midX
        let top = m.capHeight * 0.5
        let bot = rect.height - m.capHeight * 0.5
        let midY = rect.midY
        let neckTop = midY - m.neckHeight / 2
        let neckBot = midY + m.neckHeight / 2

        var p = Path()
        // Top-left → curve into neck → bottom-left → bottom-right → curve back up.
        p.move(to: CGPoint(x: cx - halfBulb, y: top))
        // left wall down to neck
        p.addCurve(
            to: CGPoint(x: cx - halfNeck, y: neckTop),
            control1: CGPoint(x: cx - halfBulb, y: top + (neckTop - top) * 0.55),
            control2: CGPoint(x: cx - halfNeck, y: neckTop - (neckTop - top) * 0.30)
        )
        // through neck
        p.addLine(to: CGPoint(x: cx - halfNeck, y: neckBot))
        // neck down to bottom-left
        p.addCurve(
            to: CGPoint(x: cx - halfBulb, y: bot),
            control1: CGPoint(x: cx - halfNeck, y: neckBot + (bot - neckBot) * 0.30),
            control2: CGPoint(x: cx - halfBulb, y: bot - (bot - neckBot) * 0.55)
        )
        // bottom edge
        p.addLine(to: CGPoint(x: cx + halfBulb, y: bot))
        // bottom-right up to neck
        p.addCurve(
            to: CGPoint(x: cx + halfNeck, y: neckBot),
            control1: CGPoint(x: cx + halfBulb, y: bot - (bot - neckBot) * 0.55),
            control2: CGPoint(x: cx + halfNeck, y: neckBot + (bot - neckBot) * 0.30)
        )
        // through neck
        p.addLine(to: CGPoint(x: cx + halfNeck, y: neckTop))
        // neck up to top-right
        p.addCurve(
            to: CGPoint(x: cx + halfBulb, y: top),
            control1: CGPoint(x: cx + halfNeck, y: neckTop - (neckTop - top) * 0.30),
            control2: CGPoint(x: cx + halfBulb, y: top + (neckTop - top) * 0.55)
        )
        p.closeSubpath()
        return p
    }
}

// MARK: - Draining cone (source chamber)

/// A cone of sand hanging from the chamber's outer wall down toward the neck.
/// `level` 1 = chamber full, 0 = empty. `atTop` selects which chamber it lives in.
private struct SandHourglassView_SandHourglassConeShape: Shape {
    let metrics: SandHourglassView_SandHourglassMetrics
    var level: Double
    var atTop: Bool

    var animatableData: Double {
        get { level }
        set { level = newValue }
    }

    func path(in rect: CGRect) -> Path {
        let m = metrics
        let cx = rect.midX
        let lvl = CGFloat(max(0, min(1, level)))
        var p = Path()

        if atTop {
            // Surface drops from the top floor toward the neck as it drains.
            let floor = m.topFloorY
            let neckY = rect.midY - m.neckHeight * 0.4
            let surfaceY = floor + (neckY - floor) * (1 - lvl)
            let halfW = (m.bulbWidth / 2 - m.bulbWidth * 0.06) * (0.18 + 0.82 * lvl)
            p.move(to: CGPoint(x: cx - halfW, y: surfaceY))
            p.addLine(to: CGPoint(x: cx + halfW, y: surfaceY))
            // funnel down to the neck mouth
            p.addLine(to: CGPoint(x: cx + m.neckWidth * 0.4, y: neckY))
            p.addLine(to: CGPoint(x: cx - m.neckWidth * 0.4, y: neckY))
            p.closeSubpath()
        } else {
            let floor = m.bottomFloorY
            let neckY = rect.midY + m.neckHeight * 0.4
            let surfaceY = floor - (floor - neckY) * (1 - lvl)
            let halfW = (m.bulbWidth / 2 - m.bulbWidth * 0.06) * (0.18 + 0.82 * lvl)
            p.move(to: CGPoint(x: cx - halfW, y: surfaceY))
            p.addLine(to: CGPoint(x: cx + halfW, y: surfaceY))
            p.addLine(to: CGPoint(x: cx + m.neckWidth * 0.4, y: neckY))
            p.addLine(to: CGPoint(x: cx - m.neckWidth * 0.4, y: neckY))
            p.closeSubpath()
        }
        return p
    }
}

// MARK: - Growing heap (destination chamber, angle-of-repose slope)

/// A sloped heap rising from the chamber's outer floor. `amount` 0 = empty,
/// 1 = chamber full (which is geometrically the cone-full region rotated 180°,
/// so there is no pop at the flip).
private struct SandHourglassView_SandHourglassHeapShape: Shape {
    let metrics: SandHourglassView_SandHourglassMetrics
    var amount: Double
    var atTop: Bool

    var animatableData: Double {
        get { amount }
        set { amount = newValue }
    }

    func path(in rect: CGRect) -> Path {
        let m = metrics
        let cx = rect.midX
        let amt = CGFloat(max(0, min(1, amount)))
        var p = Path()

        if atTop {
            // Heap grows downward from the top cap floor (chamber is "above" neck).
            let floor = m.topFloorY
            let peakMax = rect.midY - m.neckHeight * 0.4
            let peakY = floor + (peakMax - floor) * amt
            let halfW = (m.bulbWidth / 2 - m.bulbWidth * 0.06) * (0.18 + 0.82 * amt)
            // peak at center pointing toward neck, sloping back up to the cap walls
            p.move(to: CGPoint(x: cx - halfW, y: floor))
            p.addLine(to: CGPoint(x: cx, y: peakY))
            p.addLine(to: CGPoint(x: cx + halfW, y: floor))
            p.closeSubpath()
        } else {
            // Heap grows upward from the bottom cap floor (chamber is "below" neck).
            let floor = m.bottomFloorY
            let peakMax = rect.midY + m.neckHeight * 0.4
            let peakY = floor - (floor - peakMax) * amt
            let halfW = (m.bulbWidth / 2 - m.bulbWidth * 0.06) * (0.18 + 0.82 * amt)
            p.move(to: CGPoint(x: cx - halfW, y: floor))
            p.addLine(to: CGPoint(x: cx, y: peakY))
            p.addLine(to: CGPoint(x: cx + halfW, y: floor))
            p.closeSubpath()
        }
        return p
    }
}
"""###,
        "ld-segment-relay": ###"""
import SwiftUI

/// Segment Relay — twelve discrete rounded segments arranged in a ring light up
/// one-by-one in a baton-pass relay, each lit segment fading on a trailing comet
/// tail as the next ignites.
///
/// Both `demo == true` and `demo == false` are self-driving (the spec's
/// interaction is "auto"). The interactive build adds a subtle direction/speed
/// nudge gesture so a touch still produces a tactile response, while never
/// stopping the relay.
struct SegmentRelayView: View {

    var demo: Bool = false

    // Ring configuration.
    private let segmentCount: Int = 12

    // Interactive state — a horizontal drag nudges relay speed & direction.
    // Idle (and `demo`) keep the baton walking on its own.
    @State private var speedScale: Double = 1.0

    var body: some View {
        GeometryReader { proxy in
            let size = min(proxy.size.width, proxy.size.height)
            content(size: size, full: proxy.size)
                .frame(width: proxy.size.width, height: proxy.size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .contentShape(Rectangle())
        // `.gesture(_:including:)` is the idiomatic way to conditionally disable
        // a gesture: an `Optional<Gesture>` does not conform to `Gesture`, so a
        // `demo ? nil : speedGesture` ternary would fail to type-check.
        .gesture(speedGesture, including: demo ? .none : .all)
    }

    // MARK: - Content

    @ViewBuilder
    private func content(size: CGFloat, full: CGSize) -> some View {
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            // Phase advances continuously; `speedScale` lets the gesture nudge it
            // without ever stalling (clamped away from zero).
            let phase = relayPhase(at: t)
            ZStack {
                backdrop(size: size)
                ring(size: size, phase: phase)
                hub(size: size, phase: phase)
            }
            .frame(width: full.width, height: full.height)
        }
    }

    // MARK: - Backdrop

    private func backdrop(size: CGFloat) -> some View {
        Circle()
            .fill(
                RadialGradient(
                    colors: [
                        Color(red: 0.05, green: 0.07, blue: 0.10),
                        Color(red: 0.02, green: 0.03, blue: 0.05)
                    ],
                    center: .center,
                    startRadius: 0,
                    endRadius: size * 0.62
                )
            )
            .frame(width: size * 0.98, height: size * 0.98)
    }

    // MARK: - Ring of segments

    private func ring(size: CGFloat, phase: Double) -> some View {
        // The head position walks the ring; fractional so the leading edge
        // glides between discrete segments for a smoother baton hand-off.
        let head = phase * Double(segmentCount)
        return ZStack {
            ForEach(0..<segmentCount, id: \.self) { index in
                segment(index: index, size: size, head: head)
            }
        }
    }

    @ViewBuilder
    private func segment(index: Int, size: CGFloat, head: Double) -> some View {
        let intensity = intensity(for: index, head: head)
        let segLength = size * 0.20
        let segWidth = size * 0.072
        let radius = size * 0.355
        let angle = Double(index) / Double(segmentCount) * 360.0
        let glow = color(glowRGB)

        Capsule(style: .continuous)
            .fill(segmentFill(intensity: intensity))
            .frame(width: segWidth, height: segLength)
            .shadow(
                color: glow.opacity(0.85 * intensity),
                radius: size * 0.05 * intensity,
                x: 0,
                y: 0
            )
            .overlay(
                Capsule(style: .continuous)
                    .stroke(
                        Color.white.opacity(0.16 + 0.34 * intensity),
                        lineWidth: max(0.5, size * 0.004)
                    )
                    .frame(width: segWidth, height: segLength)
            )
            .offset(y: -radius)
            .rotationEffect(.degrees(angle))
            // Lit segments lift very slightly toward the viewer.
            .scaleEffect(1.0 + 0.06 * intensity)
    }

    private func segmentFill(intensity: Double) -> LinearGradient {
        let dim: RGB = (0.12, 0.16, 0.21)
        let lit = blend(dim, glowRGB, intensity)
        let litBright = blend(lit, (0.85, 0.97, 1.0), intensity * 0.55)
        return LinearGradient(
            colors: [color(litBright), color(lit)],
            startPoint: .top,
            endPoint: .bottom
        )
    }

    // MARK: - Center hub

    private func hub(size: CGFloat, phase: Double) -> some View {
        // A faint pulsing core that breathes once per lap, tying the relay together.
        let pulse = 0.5 + 0.5 * sin(phase * 2.0 * .pi)
        let core = size * 0.10
        let glow = color(glowRGB)
        return ZStack {
            Circle()
                .fill(
                    RadialGradient(
                        colors: [
                            glow.opacity(0.55 + 0.30 * pulse),
                            glow.opacity(0.0)
                        ],
                        center: .center,
                        startRadius: 0,
                        endRadius: core * 1.8
                    )
                )
                .frame(width: core * 3.4, height: core * 3.4)
            Circle()
                .fill(Color(red: 0.55, green: 0.85, blue: 1.0).opacity(0.9))
                .frame(width: core * 0.5, height: core * 0.5)
                .blur(radius: size * 0.004)
        }
    }

    // MARK: - Relay math

    /// Continuous lap phase in [0, 1). One lap takes ~3s at speedScale 1.0,
    /// which keeps the tile alive on a satisfying ~2.5–4s rhythm.
    private func relayPhase(at time: TimeInterval) -> Double {
        let lapDuration: Double = 3.0
        let effective = time * clampedSpeed() / lapDuration
        let wrapped = effective.truncatingRemainder(dividingBy: 1.0)
        return wrapped < 0 ? wrapped + 1.0 : wrapped
    }

    /// Each segment's brightness from its angular distance *behind* the head,
    /// producing the trailing comet tail. The segment at/just-passed the head is
    /// brightest; opacity decays around the ring so older segments fade out.
    private func intensity(for index: Int, head: Double) -> Double {
        let n = Double(segmentCount)
        // Distance measured as "how far behind the head this segment sits",
        // walking backward around the ring (0 = on the head).
        var behind = head - Double(index)
        behind = behind.truncatingRemainder(dividingBy: n)
        if behind < 0 { behind += n }

        // Exponential phosphor-style decay for the tail.
        let tailLength: Double = 4.5
        let decayed = exp(-behind / tailLength)

        // A small floor so segments are never fully invisible — the ring always
        // reads as a complete, legible loader on every frame.
        let floor: Double = 0.14
        return floor + (1.0 - floor) * decayed
    }

    private func clampedSpeed() -> Double {
        // Never zero: the relay always keeps moving, the gesture only nudges it.
        max(0.35, min(2.4, speedScale))
    }

    // MARK: - Interaction

    private var speedGesture: some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                // Horizontal drag maps to relay speed. Right = faster, left =
                // slower. (Clamped well away from zero so the relay never stalls.)
                let delta = value.translation.width / 120.0
                speedScale = 1.0 + delta
            }
            .onEnded { _ in
                withAnimation(.spring(response: 0.6, dampingFraction: 0.8)) {
                    speedScale = 1.0
                }
            }
    }

    // MARK: - Palette helpers

    private typealias RGB = (Double, Double, Double)

    /// Cyan-leaning activity tint, carried as a self-contained RGB tuple so the
    /// blending math stays in numeric space (no UIKit `UIColor` round-trip).
    private var glowRGB: RGB { (0.30, 0.78, 1.0) }

    private func color(_ c: RGB) -> Color {
        Color(red: c.0, green: c.1, blue: c.2)
    }

    private func blend(_ a: RGB, _ b: RGB, _ t: Double) -> RGB {
        let ct = max(0.0, min(1.0, t))
        return (
            a.0 + (b.0 - a.0) * ct,
            a.1 + (b.1 - a.1) * ct,
            a.2 + (b.2 - a.2) * ct
        )
    }
}
"""###,
        "mi-bubble-wrap-pop": ###"""
import SwiftUI

/// Bubble Wrap Pop — a grid of glossy bubbles that deflate with a wet squish on tap.
///
/// - `demo == true`  → a self-driving `TimelineView(.animation)` loop pops and
///   re-inflates bubbles on staggered per-cell cycles, so the tile is always alive.
/// - `demo == false` → real interactive bubble wrap: tap a bubble to squish it flat
///   (with haptic), and it re-inflates after a short delay.
struct BubbleWrapPopView: View {
    var demo: Bool = false

    // Grid configuration.
    private let columns: Int = 5
    private let rows: Int = 6

    // Interactive state: which bubbles are currently popped (flat).
    @State private var poppedAt: [Int: Date] = [:]
    @State private var lastPoppedIndex: Int = -1

    var body: some View {
        GeometryReader { geo in
            content(in: geo.size)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    @ViewBuilder
    private func content(in size: CGSize) -> some View {
        let cell: CGFloat = cellSide(for: size)
        let gridWidth: CGFloat = cell * CGFloat(columns)
        let gridHeight: CGFloat = cell * CGFloat(rows)

        ZStack {
            backdrop
            TimelineView(.animation) { timeline in
                grid(cell: cell, now: timeline.date)
            }
            .frame(width: gridWidth, height: gridHeight)
        }
        .frame(width: size.width, height: size.height)
        .clipped()
        .sensoryFeedback(.impact(weight: .light), trigger: lastPoppedIndex)
    }

    private var backdrop: some View {
        RadialGradient(
            colors: [Color(hexCode: "1d1626"), Color(hexCode: "120c1b")],
            center: .topLeading,
            startRadius: 4,
            endRadius: 320
        )
    }

    // MARK: - Grid

    private func grid(cell: CGFloat, now: Date) -> some View {
        VStack(spacing: 0) {
            ForEach(0..<rows, id: \.self) { r in
                HStack(spacing: 0) {
                    ForEach(0..<columns, id: \.self) { c in
                        let index: Int = r * columns + c
                        BubbleCell(
                            squish: squish(for: index, now: now),
                            side: cell
                        )
                        .frame(width: cell, height: cell)
                        .contentShape(Rectangle())
                        .onTapGesture { handleTap(index) }
                    }
                }
            }
        }
    }

    // MARK: - Layout helpers

    private func cellSide(for size: CGSize) -> CGFloat {
        let byWidth: CGFloat = size.width / CGFloat(columns)
        let byHeight: CGFloat = size.height / CGFloat(rows)
        return max(8, min(byWidth, byHeight))
    }

    // MARK: - Squish computation
    // squish: 0 = fully inflated (round, glossy), 1 = fully popped (flat dimple).

    private func squish(for index: Int, now: Date) -> CGFloat {
        if demo {
            return demoSquish(for: index, now: now)
        } else {
            return interactiveSquish(for: index, now: now)
        }
    }

    /// Deterministic, staggered self-pop derived from time + a per-cell phase seed.
    /// Each bubble lives on its own ~3s cycle; at most a thin slice of the cycle is
    /// "popped", so the grid is never blank and stays mostly inflated and glossy.
    private func demoSquish(for index: Int, now: Date) -> CGFloat {
        let period: Double = 3.2
        let t: Double = now.timeIntervalSinceReferenceDate
        let phase: Double = cellPhase(index)
        // Normalised position within this cell's own cycle.
        let local: Double = ((t / period) + phase).truncatingRemainder(dividingBy: 1.0)

        // Popped only during a short window of the cycle.
        let popStart: Double = 0.10
        let popEnd: Double = 0.34
        guard local >= popStart, local <= popEnd else { return 0 }

        let span: Double = popEnd - popStart
        let p: Double = (local - popStart) / span        // 0→1 across the window
        // Fast squish in, slower re-inflate out — an asymmetric pulse.
        let shaped: Double = p < 0.32
            ? easeOut(p / 0.32)                           // cave in quickly
            : 1.0 - easeInOut((p - 0.32) / 0.68)          // ease back to round
        return CGFloat(min(1, max(0, shaped)))
    }

    /// Interactive squish: a tapped bubble springs flat then re-inflates after a delay,
    /// computed against the timeline clock so it animates smoothly without per-cell springs.
    private func interactiveSquish(for index: Int, now: Date) -> CGFloat {
        guard let popped = poppedAt[index] else { return 0 }
        let elapsed: Double = now.timeIntervalSince(popped)

        let squishIn: Double = 0.14    // time to cave in
        let hold: Double = 0.9         // stay flat
        let reinflate: Double = 0.5    // ease back to round

        if elapsed < squishIn {
            return CGFloat(easeOut(elapsed / squishIn))
        } else if elapsed < squishIn + hold {
            return 1
        } else if elapsed < squishIn + hold + reinflate {
            let p: Double = (elapsed - squishIn - hold) / reinflate
            return CGFloat(1.0 - easeInOut(p))
        } else {
            return 0
        }
    }

    private func cellPhase(_ index: Int) -> Double {
        // Cheap deterministic hash → spread phases across [0,1).
        var h: UInt64 = UInt64(bitPattern: Int64(index &* 2654435761))
        h ^= h >> 33
        h = h &* 0xff51afd7ed558ccd
        h ^= h >> 33
        return Double(h % 1000) / 1000.0
    }

    // MARK: - Interaction

    private func handleTap(_ index: Int) {
        guard !demo else { return }
        // Re-pop even if already animating, so it always feels responsive.
        poppedAt[index] = Date()
        lastPoppedIndex = index
    }
}

// MARK: - Single bubble

private struct BubbleCell: View {
    /// 0 = inflated, 1 = popped flat.
    let squish: CGFloat
    let side: CGFloat

    var body: some View {
        let inset: CGFloat = side * 0.10
        let diameter: CGFloat = side - inset * 2

        // Anisotropic squish: widen slightly, flatten a lot — a wet cave-in.
        let scaleX: CGFloat = 1.0 + 0.08 * squish
        let scaleY: CGFloat = 1.0 - 0.46 * squish
        // Highlight collapses and dims as the dome flattens.
        let gloss: CGFloat = 1.0 - 0.85 * squish

        ZStack {
            dimple(diameter: diameter)        // the pressed-in seat, always visible
            dome(diameter: diameter, gloss: gloss)
                .scaleEffect(x: scaleX, y: scaleY)
                .shadow(
                    color: Color.black.opacity(0.35 * (1 - squish) + 0.08),
                    radius: 3 * (1 - squish) + 0.5,
                    x: 0,
                    y: 2 * (1 - squish) + 0.5
                )
        }
        .frame(width: diameter, height: diameter)
        .animation(nil, value: squish) // squish is driven by the timeline clock, not implicit anim
    }

    /// The static recessed seat beneath each bubble — keeps a popped cell legible.
    private func dimple(diameter: CGFloat) -> some View {
        Circle()
            .fill(
                RadialGradient(
                    colors: [Color(hexCode: "0d0913"), Color(hexCode: "241a31")],
                    center: .center,
                    startRadius: 0,
                    endRadius: diameter * 0.55
                )
            )
            .overlay(
                Circle().strokeBorder(Color.white.opacity(0.05), lineWidth: 0.5)
            )
            .frame(width: diameter * 0.96, height: diameter * 0.96)
    }

    /// The glossy inflated dome.
    private func dome(diameter: CGFloat, gloss: CGFloat) -> some View {
        Circle()
            .fill(
                RadialGradient(
                    colors: [
                        Color(hexCode: "b59cff").opacity(0.95),
                        Color(hexCode: "7d5cf0"),
                        Color(hexCode: "4a32a8")
                    ],
                    center: UnitPoint(x: 0.38, y: 0.34),
                    startRadius: 1,
                    endRadius: diameter * 0.7
                )
            )
            .overlay(specularHighlight(diameter: diameter, gloss: gloss))
            .overlay(rimLight(diameter: diameter, gloss: gloss))
            .opacity(0.55 + 0.45 * gloss)
    }

    private func specularHighlight(diameter: CGFloat, gloss: CGFloat) -> some View {
        Circle()
            .fill(
                RadialGradient(
                    colors: [Color.white.opacity(0.95 * gloss), Color.white.opacity(0)],
                    center: .center,
                    startRadius: 0,
                    endRadius: diameter * 0.22
                )
            )
            .frame(width: diameter * 0.42, height: diameter * 0.42)
            .offset(x: -diameter * 0.16, y: -diameter * 0.18)
    }

    private func rimLight(diameter: CGFloat, gloss: CGFloat) -> some View {
        Circle()
            .strokeBorder(
                LinearGradient(
                    colors: [
                        Color.white.opacity(0.4 * gloss),
                        Color.white.opacity(0.02)
                    ],
                    startPoint: .topLeading,
                    endPoint: .bottomTrailing
                ),
                lineWidth: max(0.5, diameter * 0.03)
            )
    }
}

// MARK: - Easing

private func easeOut(_ t: Double) -> Double {
    let c: Double = min(1, max(0, t))
    return 1 - pow(1 - c, 2.4)
}

private func easeInOut(_ t: Double) -> Double {
    let c: Double = min(1, max(0, t))
    return c < 0.5 ? 2 * c * c : 1 - pow(-2 * c + 2, 2) / 2
}

// MARK: - Color hex helper

private extension Color {
    init(hexCode hex: String) {
        let s = Scanner(string: hex.hasPrefix("#") ? String(hex.dropFirst()) : hex)
        var rgb: UInt64 = 0
        s.scanHexInt64(&rgb)
        let r = Double((rgb >> 16) & 0xFF) / 255.0
        let g = Double((rgb >> 8) & 0xFF) / 255.0
        let b = Double(rgb & 0xFF) / 255.0
        self.init(.sRGB, red: r, green: g, blue: b, opacity: 1)
    }
}
"""###,
        "mi-copy-shred": ###"""
import SwiftUI

// MARK: - Copy Shred-Reform
//
// On copy, the label "Copy" splits into vertical strips that shuffle/scatter
// (paper-shredder in reverse), then reassemble into "Copied" with a checkmark
// sliding in. demo == true self-cycles via a TimelineView clock that sweeps a
// continuous progress 0 → 1 → hold → 0 so the per-strip scatter/stagger math
// is actually exercised; demo == false fires on tap and auto-resets so it
// stays re-tappable.

public struct CopyShredView: View {
    public var demo: Bool = false

    public init(demo: Bool = false) {
        self.demo = demo
    }

    public var body: some View {
        GeometryReader { proxy in
            let size = proxy.size
            Group {
                if demo {
                    DemoDriver(size: size)
                } else {
                    InteractiveDriver(size: size)
                }
            }
            .frame(width: size.width, height: size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }
}

// MARK: - Shared progress model

/// A single 0...1 progress drives both modes.
///  0.00 → idle "Copy", fully assembled
///  0.50 → mid-shred (Copy fading/scattered out, Copied scattering in)
///  1.00 → reformed "Copied" + checkmark in
private struct ShredState {
    var progress: CGFloat        // 0...1 overall
    var stripCount: Int

    // How far through the "Copy shreds out" portion (0...1).
    // Wide windows overlap the out/in so no frame is ever blank at the crossover.
    var outPhase: CGFloat {
        clamp((progress - 0.10) / 0.52)
    }

    // How far through the "Copied reforms in" portion (0...1).
    var inPhase: CGFloat {
        clamp((progress - 0.32) / 0.46)
    }

    var copyOpacity: Double {
        // Stays fully visible early, fades as it shreds out.
        Double(1 - smooth(outPhase))
    }

    var copiedOpacity: Double {
        // Fades in as it reforms.
        Double(smooth(inPhase))
    }

    var checkProgress: CGFloat {
        // Slides in only at the tail end.
        smooth(clamp((progress - 0.72) / 0.28))
    }

    /// Per-strip scatter offset (points) for the outgoing "Copy" strips.
    func outOffset(index: Int, height: CGFloat) -> CGSize {
        let amp = height * 0.34
        let t = staggered(outPhase, index: index)
        let dir: CGFloat = (index % 2 == 0) ? -1 : 1
        // Strips fly up/down and drift sideways like shredded ribbons.
        let dy = dir * amp * t
        let dx = (index % 3 == 0 ? -1 : 1) * height * 0.08 * t
        return CGSize(width: dx, height: dy)
    }

    /// Per-strip incoming offset for the assembling "Copied" strips (settles to 0).
    func inOffset(index: Int, height: CGFloat) -> CGSize {
        let amp = height * 0.30
        // inPhase 0 → scattered, 1 → assembled.
        let t = 1 - staggered(inPhase, index: index)
        let dir: CGFloat = (index % 2 == 0) ? 1 : -1
        let dy = dir * amp * t
        return CGSize(width: 0, height: dy)
    }

    func outStripOpacity(index: Int) -> Double {
        Double(1 - staggered(outPhase, index: index))
    }

    func inStripOpacity(index: Int) -> Double {
        Double(staggered(inPhase, index: index))
    }

    // Staggered easing so strips move slightly out of sync (the "shuffle").
    private func staggered(_ p: CGFloat, index: Int) -> CGFloat {
        let span: CGFloat = 0.45
        let start = (CGFloat(index) / CGFloat(max(stripCount - 1, 1))) * span
        let local = clamp((p - start) / (1 - span))
        return smooth(local)
    }

    private func smooth(_ x: CGFloat) -> CGFloat {
        let c = clamp(x)
        return c * c * (3 - 2 * c) // smoothstep
    }

    private func clamp(_ x: CGFloat) -> CGFloat {
        min(max(x, 0), 1)
    }
}

private func clamp(_ x: CGFloat) -> CGFloat {
    min(max(x, 0), 1)
}

private func smooth(_ x: CGFloat) -> CGFloat {
    let c = clamp(x)
    return c * c * (3 - 2 * c)
}

// MARK: - Demo driver (self-cycling)

private struct DemoDriver: View {
    let size: CGSize

    // One full loop: shred-out/reform-in, hold on "Copied", reset, hold on "Copy".
    private let cycle: Double = 3.4

    var body: some View {
        // A TimelineView(.animation) clock sweeps a CONTINUOUS progress so the
        // per-strip scatter / staggered-smoothstep math in ShredState is actually
        // exercised every frame (a PhaseAnimator[0,1,0] would only ever sample the
        // endpoints, collapsing the effect to a plain crossfade). Never blank:
        // copyOpacity fades out as copiedOpacity fades in across the overlap window.
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            let progress = Self.loopProgress(t, cycle: cycle)
            ShredContent(progress: progress, size: size, animated: false)
        }
    }

    /// Maps wall-clock time → 0...1 progress with holds at each end so the word
    /// is legible before and after the shred:
    ///   [0.00–0.38] shred "Copy" → reform "Copied"
    ///   [0.38–0.55] hold on "Copied"
    ///   [0.55–0.88] reform back to "Copy"
    ///   [0.88–1.00] hold on "Copy"
    static func loopProgress(_ time: Double, cycle: Double) -> CGFloat {
        let phase = (time.truncatingRemainder(dividingBy: cycle)) / cycle // 0...1
        let p: Double
        switch phase {
        case ..<0.38:
            p = ease(phase / 0.38)              // 0 → 1
        case ..<0.55:
            p = 1                               // hold "Copied"
        case ..<0.88:
            p = 1 - ease((phase - 0.55) / 0.33) // 1 → 0
        default:
            p = 0                               // hold "Copy"
        }
        return CGFloat(p)
    }

    /// Smoothstep so the sweep accelerates in and eases out.
    private static func ease(_ x: Double) -> Double {
        let c = min(max(x, 0), 1)
        return c * c * (3 - 2 * c)
    }
}

// MARK: - Interactive driver (tap + auto-reset)

private struct InteractiveDriver: View {
    let size: CGSize
    @State private var copied: Bool = false

    var body: some View {
        ShredContent(progress: copied ? 1 : 0, size: size, animated: true)
            .contentShape(Rectangle())
            .onTapGesture { fire() }
            .sensoryFeedbackCompat(trigger: copied)
            .accessibilityAddTraits(.isButton)
            .accessibilityLabel(copied ? "Copied" : "Copy")
    }

    private func fire() {
        guard !copied else { return }
        withAnimation(.spring(response: 0.7, dampingFraction: 0.7)) {
            copied = true
        }
        // Auto-reset so the tile stays re-tappable.
        DispatchQueue.main.asyncAfter(deadline: .now() + 1.5) {
            withAnimation(.easeInOut(duration: 0.8)) {
                copied = false
            }
        }
    }
}

// MARK: - Content

private struct ShredContent: View {
    var progress: CGFloat
    let size: CGSize
    /// When true, per-strip staggered springs are applied for the tactile feel.
    let animated: Bool

    private let stripCount = 10

    private var state: ShredState {
        ShredState(progress: clamp(progress), stripCount: stripCount)
    }

    private var regionWidth: CGFloat { size.width * 0.84 }
    private var regionHeight: CGFloat { size.height * 0.42 }
    private var fontSize: CGFloat {
        // Sized to "Copied" (the longer word) so it never truncates.
        min(regionHeight * 0.74, regionWidth * 0.26)
    }

    var body: some View {
        ZStack {
            backdrop
            wordStack
        }
        .frame(width: size.width, height: size.height)
    }

    private var backdrop: some View {
        RoundedRectangle(cornerRadius: size.width * 0.10, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color(hexCode: 0x1B1726),
                        Color(hexCode: 0x120F1B)
                    ],
                    startPoint: .top,
                    endPoint: .bottom
                )
            )
            .overlay(
                RoundedRectangle(cornerRadius: size.width * 0.10, style: .continuous)
                    .strokeBorder(Color.white.opacity(0.06), lineWidth: 1)
            )
            .frame(width: size.width * 0.92, height: size.height * 0.66)
    }

    private var wordStack: some View {
        ZStack {
            shredLayer(
                word: "Copy",
                color: Color(hexCode: 0xC7BEE6),
                opacity: state.copyOpacity,
                offset: { state.outOffset(index: $0, height: regionHeight) },
                stripOpacity: { state.outStripOpacity(index: $0) }
            )

            reformLayer(
                word: "Copied",
                color: Color(hexCode: 0x8BE6B0),
                opacity: state.copiedOpacity,
                offset: { state.inOffset(index: $0, height: regionHeight) },
                stripOpacity: { state.inStripOpacity(index: $0) }
            )
            .overlay(alignment: .trailing) {
                checkmark
            }
        }
        .frame(width: regionWidth, height: regionHeight)
    }

    // MARK: Layers

    private func shredLayer(
        word: String,
        color: Color,
        opacity: Double,
        offset: @escaping (Int) -> CGSize,
        stripOpacity: @escaping (Int) -> Double
    ) -> some View {
        ZStack {
            ForEach(0..<stripCount, id: \.self) { i in
                strip(index: i, word: word, color: color)
                    .offset(offset(i))
                    .opacity(stripOpacity(i))
                    .modifier(StripSpring(index: i, animated: animated, value: progress))
            }
        }
        .opacity(opacity)
    }

    private func reformLayer(
        word: String,
        color: Color,
        opacity: Double,
        offset: @escaping (Int) -> CGSize,
        stripOpacity: @escaping (Int) -> Double
    ) -> some View {
        ZStack {
            ForEach(0..<stripCount, id: \.self) { i in
                strip(index: i, word: word, color: color)
                    .offset(offset(i))
                    .opacity(stripOpacity(i))
                    .modifier(StripSpring(index: i, animated: animated, value: progress))
            }
        }
        .opacity(opacity)
    }

    /// One vertical band of the full word, masked from an identical full Text.
    /// Every strip shares the same layout, so offset==0 reconstructs the word
    /// with zero sub-pixel seams.
    private func strip(index: Int, word: String, color: Color) -> some View {
        let bandWidth = regionWidth / CGFloat(stripCount)
        let x = bandWidth * CGFloat(index)
        return label(word: word, color: color)
            .frame(width: regionWidth, height: regionHeight)
            .mask(
                Rectangle()
                    .frame(width: bandWidth, height: regionHeight)
                    .offset(x: x - regionWidth / 2 + bandWidth / 2)
            )
    }

    private func label(word: String, color: Color) -> some View {
        Text(word)
            .font(.system(size: fontSize, weight: .bold, design: .rounded))
            .foregroundStyle(color)
            .lineLimit(1)
            .minimumScaleFactor(0.5)
            .frame(width: regionWidth, height: regionHeight)
    }

    // MARK: Checkmark

    private var checkmark: some View {
        let p = state.checkProgress
        let glyph = fontSize * 0.9
        return Image(systemName: "checkmark.circle.fill")
            .font(.system(size: glyph, weight: .bold))
            .foregroundStyle(Color(hexCode: 0x8BE6B0))
            .opacity(Double(p))
            .scaleEffect(0.6 + 0.4 * p)
            .offset(x: glyph * (1.1 - p * 1.1))
            // Sit just past the trailing edge of the word region.
            .offset(x: glyph * 0.9)
    }
}

// MARK: - Per-strip staggered spring

private struct StripSpring: ViewModifier {
    let index: Int
    let animated: Bool
    let value: CGFloat

    func body(content: Content) -> some View {
        if animated {
            content.animation(
                .spring(response: 0.55, dampingFraction: 0.72)
                    .delay(Double(index) * 0.03),
                value: value
            )
        } else {
            content
        }
    }
}

// MARK: - Compatibility helpers

private extension View {
    /// sensoryFeedback is iOS 17+; available at our deployment target, but
    /// kept behind a tiny wrapper for clarity / forward-safety.
    @ViewBuilder
    func sensoryFeedbackCompat(trigger: Bool) -> some View {
        if #available(iOS 17.0, *) {
            self.sensoryFeedback(.success, trigger: trigger) { _, new in new }
        } else {
            self
        }
    }
}

private extension Color {
    init(hexCode hex: UInt32, alpha: Double = 1.0) {
        let r = Double((hex >> 16) & 0xFF) / 255.0
        let g = Double((hex >> 8) & 0xFF) / 255.0
        let b = Double(hex & 0xFF) / 255.0
        self.init(.sRGB, red: r, green: g, blue: b, opacity: alpha)
    }
}

// MARK: - Preview
"""###,
        "mi-copy-vanish": ###"""
import SwiftUI

// MARK: - Copy Vanish Confirm
// On copy, the text duplicates, lifts off, and slides along an animatable
// bezier into a clipboard glyph that bulges to swallow it, then a checkmark
// crossfades in. `demo == true` self-drives the whole cycle on a loop;
// `demo == false` fires the same cycle on tap.

struct CopyVanishView: View {
    var demo: Bool = false

    // Single source of truth: one trigger increments to fire one interactive cycle.
    @State private var tapTrigger: Int = 0

    var body: some View {
        GeometryReader { geo in
            content(in: geo.size)
                .frame(maxWidth: .infinity, maxHeight: .infinity)
        }
    }

    @ViewBuilder
    private func content(in size: CGSize) -> some View {
        if demo {
            // Self-driving: PhaseAnimator with no explicit trigger loops forever.
            PhaseAnimator(CopyPhase.allCases) { phase in
                CopyVanishStage(phase: phase, size: size)
            } animation: { phase in
                phase.animation
            }
        } else {
            // Interactive: tap fires exactly one cycle.
            PhaseAnimator(CopyPhase.allCases, trigger: tapTrigger) { phase in
                CopyVanishStage(phase: phase, size: size)
            } animation: { phase in
                // Only animate once a tap has happened so the resting state is stable.
                tapTrigger == 0 ? nil : phase.animation
            }
            .contentShape(Rectangle())
            .onTapGesture { tapTrigger += 1 }
        }
    }
}

// MARK: - Phases

private enum CopyPhase: CaseIterable {
    case idle    // ghost sits on the label, clipboard calm, no tick
    case lift    // ghost lifts off the row (scale up, rise)
    case fly     // ghost travels the bezier into the clipboard
    case swallow // clipboard bulges, ghost shrinks to nothing
    case confirm // checkmark crossfades in
    case settle  // tick eases out, ready to repeat

    var animation: Animation {
        switch self {
        case .idle:    return .easeInOut(duration: 0.5)
        case .lift:    return .spring(response: 0.32, dampingFraction: 0.62)
        case .fly:     return .timingCurve(0.42, 0.0, 0.30, 1.0, duration: 0.55)
        case .swallow: return .spring(response: 0.28, dampingFraction: 0.55)
        case .confirm: return .spring(response: 0.40, dampingFraction: 0.70)
        case .settle:  return .easeInOut(duration: 0.85)
        }
    }
}

// MARK: - Stage renderer (shared by demo + interactive)

private struct CopyVanishStage: View {
    let phase: CopyPhase
    let size: CGSize

    private var dim: CGFloat { min(size.width, size.height) }

    var body: some View {
        ZStack {
            background

            // The persistent source label — never disappears, so no blank frame.
            sourceLabel
                .position(labelAnchor)

            // The flying ghost duplicate.
            ghost

            // Clipboard glyph that swallows the ghost, with checkmark crossfade.
            clipboard
                .position(clipboardAnchor)
        }
        .frame(width: size.width, height: size.height)
    }

    // MARK: Layout anchors (all relative to GeometryReader size)

    private var labelAnchor: CGPoint {
        CGPoint(x: size.width * 0.40, y: size.height * 0.66)
    }

    private var clipboardAnchor: CGPoint {
        CGPoint(x: size.width * 0.72, y: size.height * 0.30)
    }

    // Quadratic bezier control point: arc up-and-over between the two anchors.
    private var flightControl: CGPoint {
        CGPoint(
            x: (labelAnchor.x + clipboardAnchor.x) * 0.5,
            y: min(labelAnchor.y, clipboardAnchor.y) - dim * 0.18
        )
    }

    // MARK: Progress derived from phase

    // 0 at label, 1 at clipboard.
    private var flightProgress: CGFloat {
        switch phase {
        case .idle, .lift:           return 0
        case .fly:                   return 1
        case .swallow, .confirm, .settle: return 1
        }
    }

    private var ghostScale: CGFloat {
        switch phase {
        case .idle:    return 1.0
        case .lift:    return 1.14
        case .fly:     return 0.74
        case .swallow: return 0.18
        default:       return 0.18
        }
    }

    private var ghostOpacity: Double {
        switch phase {
        case .idle:    return 0.0   // hidden until lift, source label carries the frame
        case .lift:    return 1.0
        case .fly:     return 1.0
        case .swallow: return 0.0
        default:       return 0.0
        }
    }

    private var clipboardBulge: CGFloat {
        switch phase {
        case .swallow: return 1.34
        case .confirm: return 1.10
        default:       return 1.0
        }
    }

    private var showCheck: Bool {
        switch phase {
        case .confirm, .settle: return true
        default:                return false
        }
    }

    private var labelDimmed: Double {
        // The source label dips slightly while the copy is in flight, then returns.
        switch phase {
        case .fly, .swallow, .confirm: return 0.45
        default:                       return 1.0
        }
    }

    // MARK: Subviews

    private var background: some View {
        RoundedRectangle(cornerRadius: dim * 0.14, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [Color(hexCode: "1c1726"), Color(hexCode: "141019")],
                    startPoint: .top,
                    endPoint: .bottom
                )
            )
            .overlay(
                RoundedRectangle(cornerRadius: dim * 0.14, style: .continuous)
                    .strokeBorder(Color.white.opacity(0.06), lineWidth: 1)
            )
    }

    private var sourceLabel: some View {
        codePill(text: "#A3E635")
            .opacity(labelDimmed)
    }

    private var ghost: some View {
        codePill(text: "#A3E635")
            .scaleEffect(ghostScale)
            .opacity(ghostOpacity)
            .modifier(
                BezierFlight(
                    progress: flightProgress,
                    start: labelAnchor,
                    control: flightControl,
                    end: clipboardAnchor
                )
            )
            .shadow(color: Color(hexCode: "A3E635").opacity(0.35), radius: dim * 0.04)
    }

    private func codePill(text: String) -> some View {
        Text(text)
            .font(.system(size: dim * 0.115, weight: .semibold, design: .monospaced))
            .foregroundStyle(Color(hexCode: "D9F99D"))
            .padding(.horizontal, dim * 0.07)
            .padding(.vertical, dim * 0.045)
            .background(
                Capsule(style: .continuous)
                    .fill(Color(hexCode: "A3E635").opacity(0.12))
                    .overlay(
                        Capsule(style: .continuous)
                            .strokeBorder(Color(hexCode: "A3E635").opacity(0.30), lineWidth: 1)
                    )
            )
    }

    private var clipboard: some View {
        ZStack {
            // Soft glow that pulses as it swallows.
            Circle()
                .fill(Color(hexCode: "A3E635").opacity(showCheck ? 0.22 : 0.12))
                .frame(width: dim * 0.34, height: dim * 0.34)
                .scaleEffect(clipboardBulge)
                .blur(radius: dim * 0.03)

            clipboardGlyph
                .scaleEffect(clipboardBulge)
        }
    }

    @ViewBuilder
    private var clipboardGlyph: some View {
        let symbol = showCheck ? "checkmark.circle.fill" : "doc.on.clipboard.fill"
        Image(systemName: symbol)
            .font(.system(size: dim * 0.22, weight: .medium))
            .foregroundStyle(showCheck ? Color(hexCode: "A3E635") : Color(hexCode: "C8B8E8"))
            .contentTransition(.symbolEffect(.replace))
            .symbolRenderingMode(.hierarchical)
    }
}

// MARK: - Animatable bezier flight modifier

// Moves the modified view along a quadratic bezier as `progress` animates 0→1.
private struct BezierFlight: ViewModifier, Animatable {
    var progress: CGFloat
    let start: CGPoint
    let control: CGPoint
    let end: CGPoint

    var animatableData: CGFloat {
        get { progress }
        set { progress = newValue }
    }

    private func point(at t: CGFloat) -> CGPoint {
        let mt = 1 - t
        let x = mt * mt * start.x + 2 * mt * t * control.x + t * t * end.x
        let y = mt * mt * start.y + 2 * mt * t * control.y + t * t * end.y
        return CGPoint(x: x, y: y)
    }

    func body(content: Content) -> some View {
        let p = point(at: progress)
        content.position(p)
    }
}

// MARK: - Local hex color helper (private to avoid batch-wide redeclaration)

private extension Color {
    init(hexCode hex: String) {
        let s = hex.trimmingCharacters(in: CharacterSet(charactersIn: "#"))
        var v: UInt64 = 0
        Scanner(string: s).scanHexInt64(&v)
        let r, g, b, a: Double
        switch s.count {
        case 6:
            r = Double((v & 0xFF0000) >> 16) / 255
            g = Double((v & 0x00FF00) >> 8) / 255
            b = Double(v & 0x0000FF) / 255
            a = 1
        case 8:
            r = Double((v & 0xFF000000) >> 24) / 255
            g = Double((v & 0x00FF0000) >> 16) / 255
            b = Double((v & 0x0000FF00) >> 8) / 255
            a = Double(v & 0x000000FF) / 255
        default:
            r = 1; g = 1; b = 1; a = 1
        }
        self.init(.sRGB, red: r, green: g, blue: b, opacity: a)
    }
}
"""###,
        "mi-day-night-toggle": ###"""
import SwiftUI

// MARK: - Day-Night Toggle
// A switch that morphs a sun into a crescent moon by sliding an opaque eraser
// disc across a glowing disc (carving the crescent via destinationOut), while
// tiny stars fade in and the track crossfades from sky-blue to indigo.
//
// One scalar `progress` in [0, 1] drives every visual:
//   0 -> full day  (sun, blue sky, rays, no stars, thumb on the left)
//   1 -> full night (crescent moon, indigo sky, stars, thumb on the right)
//
// CRITICAL: every day/night transition rides on an *animatable* modifier
// (.offset / .opacity) — never on a ShapeStyle fill parameter. Gradients are
// ShapeStyles and do NOT interpolate, so each color shift is done by stacking
// two fills and crossfading the top one with .opacity(progress). This keeps
// the slide, the carve, and the color morph all in sync when SwiftUI animates
// `progress` from 0 to 1 on tap.
//
// In demo mode `progress` is driven by a raised-cosine TimelineView loop so the
// tile is always alive and legible. Interactive mode toggles `isOn` on tap and
// animates `progress` 0<->1 with .easeInOut.

public struct DayNightToggleView: View {
    var demo: Bool = false

    @State private var isOn: Bool = false

    public var body: some View {
        GeometryReader { geo in
            content(in: geo.size)
                .frame(maxWidth: .infinity, maxHeight: .infinity)
        }
    }

    @ViewBuilder
    private func content(in size: CGSize) -> some View {
        if demo {
            TimelineView(.animation) { timeline in
                DayNightToggleView_ToggleScene(progress: demoProgress(at: timeline.date), size: size)
            }
        } else {
            DayNightToggleView_ToggleScene(progress: isOn ? 1 : 0, size: size)
                .contentShape(Rectangle())
                .onTapGesture {
                    withAnimation(.easeInOut(duration: 0.6)) {
                        isOn.toggle()
                    }
                }
                .sensoryFeedback(.selection, trigger: isOn)
        }
    }

    // Raised-cosine 0->1->0 over ~3.4s: smooth dwell at both ends, never blank.
    private func demoProgress(at date: Date) -> CGFloat {
        let period: Double = 3.4
        let t = date.timeIntervalSinceReferenceDate
        let phase = t.truncatingRemainder(dividingBy: period) / period
        return CGFloat((1 - cos(phase * 2 * .pi)) / 2)
    }
}

// MARK: - Scene

private struct DayNightToggleView_ToggleScene: View {
    var progress: CGFloat
    var size: CGSize

    private var unit: CGFloat {
        // Toggle height; clamp so we never produce NaN on first layout.
        let byHeight = size.height * 0.42
        let byWidth = size.width / 2.1
        return max(8, min(byHeight, byWidth))
    }

    var body: some View {
        let trackH = unit
        let trackW = unit * 1.85
        let pad = trackH * 0.12
        let diameter = trackH - pad * 2
        let travel = trackW - trackH   // spare horizontal room (symmetric pad)

        ZStack {
            DayNightToggleView_TrackView(progress: progress, width: trackW, height: trackH)
            DayNightToggleView_StarField(progress: progress, width: trackW, height: trackH)
            DayNightToggleView_DiscStack(progress: progress, diameter: diameter)
                .offset(x: -travel / 2 + travel * progress) // animatable slide
        }
        .frame(width: trackW, height: trackH)
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }
}

// MARK: - Track (sky-blue -> indigo crossfade)

private struct DayNightToggleView_TrackView: View {
    var progress: CGFloat
    var width: CGFloat
    var height: CGFloat

    private var dayGradient: LinearGradient {
        LinearGradient(
            colors: [
                Color(red: 0.42, green: 0.74, blue: 0.98),
                Color(red: 0.26, green: 0.56, blue: 0.92)
            ],
            startPoint: .topLeading,
            endPoint: .bottomTrailing
        )
    }

    private var nightGradient: LinearGradient {
        LinearGradient(
            colors: [
                Color(red: 0.16, green: 0.13, blue: 0.34),
                Color(red: 0.05, green: 0.04, blue: 0.14)
            ],
            startPoint: .topLeading,
            endPoint: .bottomTrailing
        )
    }

    var body: some View {
        ZStack {
            Capsule().fill(dayGradient)
            // .opacity is animatable -> smooth crossfade in both branches.
            Capsule().fill(nightGradient).opacity(Double(progress))
        }
        .overlay(
            Capsule().strokeBorder(Color.white.opacity(0.10), lineWidth: 0.6)
        )
        .frame(width: width, height: height)
        .shadow(color: Color.black.opacity(0.28), radius: height * 0.10, y: height * 0.05)
    }
}

// MARK: - Stars (fixed positions, opacity by progress)

private struct DayNightToggleView_StarField: View {
    var progress: CGFloat
    var width: CGFloat
    var height: CGFloat

    // Hardcoded unit-fraction positions + relative radius. Never randomized in
    // body, so they don't re-roll every frame. Kept on the left half so the
    // moon thumb (which slides to the right) doesn't sit on top of them.
    private static let stars: [(x: CGFloat, y: CGFloat, r: CGFloat)] = [
        (0.14, 0.28, 0.030),
        (0.24, 0.62, 0.022),
        (0.34, 0.34, 0.026),
        (0.20, 0.46, 0.018),
        (0.40, 0.66, 0.020),
        (0.30, 0.20, 0.016),
        (0.46, 0.44, 0.024)
    ]

    var body: some View {
        ZStack {
            ForEach(Array(Self.stars.enumerated()), id: \.offset) { _, s in
                Circle()
                    .fill(Color.white)
                    .frame(width: s.r * width * 2, height: s.r * width * 2)
                    .position(x: s.x * width, y: s.y * height)
                    .blur(radius: s.r * width * 0.25)
            }
        }
        .frame(width: width, height: height)
        .opacity(Double(progress))
        .allowsHitTesting(false)
    }
}

// MARK: - Disc (sun <-> crescent moon)

private struct DayNightToggleView_DiscStack: View {
    var progress: CGFloat
    var diameter: CGFloat

    var body: some View {
        ZStack {
            // Soft outer halo (sun glow -> moon glow). Blurred + low alpha, so a
            // structural color crossfade here is cheap and unobtrusive.
            haloLayer

            // Carved disc. compositingGroup() MUST wrap THIS inner ZStack only,
            // so destinationOut erases within the disc, not the track behind it.
            ZStack {
                Circle().fill(sunGradient)
                // Animatable color morph: moon fill crossfades in over the sun.
                Circle().fill(moonGradient).opacity(Double(progress))
                // Opaque eraser (alpha 1) — required for destinationOut to bite.
                Circle()
                    .fill(Color.black)
                    .frame(width: diameter, height: diameter)
                    .offset(x: eraserOffset)
                    .blendMode(.destinationOut)
            }
            .compositingGroup()
        }
        .frame(width: diameter, height: diameter)
        .overlay(rayBurst.opacity(Double(1 - progress)))
    }

    // At progress 0 the eraser sits clear of the disc (full sun). As progress
    // -> 1 it slides in to about a third of the diameter to carve the crescent.
    private var eraserOffset: CGFloat {
        let start = diameter * 1.05   // fully clear of the disc
        let end = diameter * 0.34     // overlapped -> crescent bite
        return start + (end - start) * progress
    }

    private var sunGradient: RadialGradient {
        RadialGradient(
            colors: [
                Color(red: 1.0, green: 0.93, blue: 0.62),
                Color(red: 1.0, green: 0.78, blue: 0.28)
            ],
            center: .init(x: 0.38, y: 0.34),
            startRadius: 0,
            endRadius: diameter * 0.75
        )
    }

    private var moonGradient: RadialGradient {
        RadialGradient(
            colors: [
                Color(red: 0.97, green: 0.97, blue: 1.0),
                Color(red: 0.74, green: 0.78, blue: 0.90)
            ],
            center: .init(x: 0.38, y: 0.34),
            startRadius: 0,
            endRadius: diameter * 0.75
        )
    }

    private var haloLayer: some View {
        ZStack {
            Circle().fill(sunHalo)
            Circle().fill(moonHalo).opacity(Double(progress))
        }
        .scaleEffect(1.42)
        .blur(radius: diameter * 0.10)
        .allowsHitTesting(false)
    }

    private var sunHalo: RadialGradient {
        RadialGradient(
            colors: [Color(red: 1.0, green: 0.85, blue: 0.40).opacity(0.55), Color.clear],
            center: .center,
            startRadius: diameter * 0.30,
            endRadius: diameter * 0.78
        )
    }

    private var moonHalo: RadialGradient {
        RadialGradient(
            colors: [Color(red: 0.78, green: 0.82, blue: 0.98).opacity(0.50), Color.clear],
            center: .center,
            startRadius: diameter * 0.30,
            endRadius: diameter * 0.78
        )
    }

    // Radiating sun rays, fading out as night arrives.
    private var rayBurst: some View {
        ZStack {
            ForEach(0..<8, id: \.self) { i in
                Capsule()
                    .fill(Color(red: 1.0, green: 0.86, blue: 0.42))
                    .frame(width: diameter * 0.06, height: diameter * 0.22)
                    .offset(y: -diameter * 0.80)
                    .rotationEffect(.degrees(Double(i) / 8 * 360))
            }
        }
        .allowsHitTesting(false)
    }
}
"""###,
        "mi-dogear-bookmark": ###"""
import SwiftUI

// MARK: - Dog-Ear Bookmark
// Tapping a card folds its top-trailing corner down into a triangular
// dog-ear with a progress-driven lifted-flap shadow and a darker page
// underside, revealing a warm bookmark accent pocket beneath.
// demo == true  -> PhaseAnimator self-drives the fold/unfold on a ~3.2s loop.
// demo == false -> a tap toggles the saved state and folds the corner.

public struct DogearBookmarkView: View {
    public var demo: Bool = false

    public init(demo: Bool = false) {
        self.demo = demo
    }

    @State private var isSaved: Bool = false

    public var body: some View {
        GeometryReader { proxy in
            let size = proxy.size
            content(in: size)
                .frame(width: size.width, height: size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    @ViewBuilder
    private func content(in size: CGSize) -> some View {
        if demo {
            demoContent(in: size)
        } else {
            interactiveContent(in: size)
        }
    }

    // MARK: Demo (self-driving)

    private func demoContent(in size: CGSize) -> some View {
        PhaseAnimator(DogearBookmarkView_DogEarPhase.allCases) { phase in
            cardView(in: size, foldProgress: phase.progress)
        } animation: { phase in
            switch phase {
            case .flat, .folded:
                return .spring(duration: 0.62, bounce: 0.30)
            case .flatHold, .foldedHold:
                return .linear(duration: 0.95)
            }
        }
    }

    // MARK: Interactive (tap)

    private func interactiveContent(in size: CGSize) -> some View {
        cardView(in: size, foldProgress: isSaved ? 1 : 0)
            .contentShape(Rectangle())
            .onTapGesture {
                withAnimation(.spring(duration: 0.55, bounce: 0.30)) {
                    isSaved.toggle()
                }
            }
            .sensoryFeedback(.impact(weight: .light), trigger: isSaved)
    }

    // MARK: Card composition

    private func cardView(in size: CGSize, foldProgress p: CGFloat) -> some View {
        let dim = min(size.width, size.height)
        let ear: CGFloat = dim * 0.30
        let inset: CGFloat = dim * 0.085
        let cardW = size.width - inset * 2
        let cardH = size.height - inset * 2
        let corner: CGFloat = max(8, dim * 0.10)

        return ZStack {
            DogearBookmarkView_CardFace(cornerRadius: corner, ear: ear)
                .fill(cardFaceColor)
                .overlay(
                    cardContent(width: cardW, height: cardH, ear: ear, progress: p)
                )
                .overlay(
                    DogearBookmarkView_CardFace(cornerRadius: corner, ear: ear)
                        .stroke(strokeColor, lineWidth: max(0.75, dim * 0.006))
                )
                .frame(width: cardW, height: cardH)
                .background(
                    DogearBookmarkView_CardFace(cornerRadius: corner, ear: ear)
                        .fill(cardFaceColor)
                        .frame(width: cardW, height: cardH)
                        .shadow(color: ambientShadow, radius: dim * 0.05,
                                x: 0, y: dim * 0.025)
                )
                .compositingGroup()

            dogEarLayer(width: cardW, height: cardH, ear: ear, progress: p)
                .frame(width: cardW, height: cardH)
        }
        .frame(width: size.width, height: size.height)
    }

    // MARK: Dog-ear layers

    private func dogEarLayer(width: CGFloat, height: CGFloat,
                             ear: CGFloat, progress p: CGFloat) -> some View {
        // Local card space origin is the layer's top-left.
        let halfW = width / 2
        let halfH = height / 2

        return ZStack {
            // Reveal pocket — the warm bookmark accent exposed as the page lifts.
            DogearBookmarkView_RevealPocket(ear: ear, progress: p)
                .fill(pocketGradient)
                .opacity(Double(min(1, p * 1.4)))

            // Folded flap (the page's back, darker underside) with lifted shadow.
            DogearBookmarkView_FoldFlap(ear: ear, foldProgress: p)
                .fill(undersideGradient(progress: p))
                .overlay(
                    DogearBookmarkView_FoldFlap(ear: ear, foldProgress: p)
                        .fill(flapSheen(progress: p))
                )
                .shadow(color: flapShadowColor(progress: p),
                        radius: ear * 0.22 * p,
                        x: -ear * 0.18 * p,
                        y: ear * 0.20 * p)
        }
        // Position the (0,0)…(width,height) shape space within the layer frame.
        .offset(x: -halfW, y: -halfH)
        .frame(width: width, height: height, alignment: .topLeading)
        .offset(x: halfW, y: halfH)
        .allowsHitTesting(false)
    }

    // MARK: Card inner content (title / bookmark hint)

    private func cardContent(width: CGFloat, height: CGFloat,
                             ear: CGFloat, progress p: CGFloat) -> some View {
        let pad: CGFloat = max(6, width * 0.10)
        let lineColor = textColor.opacity(0.9)
        let barH: CGFloat = max(3, height * 0.045)

        return VStack(alignment: .leading, spacing: barH * 0.9) {
            HStack(spacing: barH * 0.7) {
                Circle()
                    .fill(accentColor.opacity(0.9))
                    .frame(width: barH * 2.0, height: barH * 2.0)
                    .overlay(
                        Image(systemName: p > 0.5 ? "bookmark.fill" : "bookmark")
                            .font(.system(size: barH * 1.05, weight: .bold))
                            .foregroundStyle(Color(red: 1, green: 1, blue: 1))
                    )
                    .scaleEffect(1 + 0.10 * p)
                Spacer(minLength: 0)
            }
            RoundedRectangle(cornerRadius: barH / 2)
                .fill(lineColor)
                .frame(width: width * 0.55, height: barH)
            RoundedRectangle(cornerRadius: barH / 2)
                .fill(lineColor.opacity(0.55))
                .frame(width: width * 0.72, height: barH * 0.8)
            RoundedRectangle(cornerRadius: barH / 2)
                .fill(lineColor.opacity(0.45))
                .frame(width: width * 0.40, height: barH * 0.8)
            Spacer(minLength: 0)
        }
        .padding(pad)
        .frame(width: width, height: height, alignment: .topLeading)
        .clipShape(Rectangle())
    }

    // MARK: Palette (literal colors — no app dependencies)

    private var cardFaceColor: Color {
        Color(red: 0.97, green: 0.96, blue: 0.93)
    }

    private var strokeColor: Color {
        Color(red: 0.0, green: 0.0, blue: 0.0).opacity(0.06)
    }

    private var ambientShadow: Color {
        Color(red: 0.05, green: 0.04, blue: 0.10).opacity(0.30)
    }

    private var textColor: Color {
        Color(red: 0.20, green: 0.18, blue: 0.16)
    }

    private var accentColor: Color {
        Color(red: 0.93, green: 0.46, blue: 0.30)
    }

    private var pocketGradient: LinearGradient {
        LinearGradient(
            colors: [
                Color(red: 0.96, green: 0.55, blue: 0.32),
                Color(red: 0.89, green: 0.36, blue: 0.28)
            ],
            startPoint: .topTrailing,
            endPoint: .bottomLeading
        )
    }

    private func undersideGradient(progress p: CGFloat) -> LinearGradient {
        // Card color at rest -> darker page back as it folds, so the
        // flap is invisible (matches the card) at p == 0.
        let t = Double(p)
        let face = (r: 0.97, g: 0.96, b: 0.93)
        let topTint = (r: 0.80, g: 0.77, b: 0.71)
        let botTint = (r: 0.64, g: 0.61, b: 0.55)
        let top = Color(red: lerp(face.r, topTint.r, t),
                        green: lerp(face.g, topTint.g, t),
                        blue: lerp(face.b, topTint.b, t))
        let bottom = Color(red: lerp(face.r, botTint.r, t),
                           green: lerp(face.g, botTint.g, t),
                           blue: lerp(face.b, botTint.b, t))
        return LinearGradient(colors: [top, bottom],
                              startPoint: .top, endPoint: .bottomLeading)
    }

    private func flapSheen(progress p: CGFloat) -> LinearGradient {
        LinearGradient(
            colors: [
                Color(red: 1, green: 1, blue: 1).opacity(0.18 * Double(p)),
                Color(red: 0, green: 0, blue: 0).opacity(0.0)
            ],
            startPoint: .topTrailing,
            endPoint: .bottomLeading
        )
    }

    private func flapShadowColor(progress p: CGFloat) -> Color {
        Color(red: 0.10, green: 0.08, blue: 0.06).opacity(0.42 * Double(p))
    }

    private func lerp(_ a: Double, _ b: Double, _ t: Double) -> Double {
        let clamped = min(max(t, 0), 1)
        return a + (b - a) * clamped
    }
}

// MARK: - Demo phases

private enum DogearBookmarkView_DogEarPhase: CaseIterable {
    case flat, flatHold, folded, foldedHold

    var progress: CGFloat {
        switch self {
        case .flat, .flatHold: return 0
        case .folded, .foldedHold: return 1
        }
    }
}

// MARK: - Card silhouette with the corner notch

/// The card outline, with its top-trailing corner cut along the fold line so
/// the lifted flap reads as a real removed corner rather than an overlay.
private struct DogearBookmarkView_CardFace: Shape {
    var cornerRadius: CGFloat
    var ear: CGFloat

    func path(in rect: CGRect) -> Path {
        let w = rect.width
        let h = rect.height
        let r = min(cornerRadius, min(w, h) / 2)
        let s = min(ear, min(w, h))

        var p = Path()
        // Start just after the top-leading rounded corner.
        p.move(to: CGPoint(x: r, y: 0))
        // Top edge to the fold-line start A = (w - s, 0).
        p.addLine(to: CGPoint(x: w - s, y: 0))
        // Fold line down to B = (w, s).
        p.addLine(to: CGPoint(x: w, y: s))
        // Right edge down to bottom-right rounded corner.
        p.addLine(to: CGPoint(x: w, y: h - r))
        p.addQuadCurve(to: CGPoint(x: w - r, y: h),
                       control: CGPoint(x: w, y: h))
        // Bottom edge.
        p.addLine(to: CGPoint(x: r, y: h))
        p.addQuadCurve(to: CGPoint(x: 0, y: h - r),
                       control: CGPoint(x: 0, y: h))
        // Left edge.
        p.addLine(to: CGPoint(x: 0, y: r))
        p.addQuadCurve(to: CGPoint(x: r, y: 0),
                       control: CGPoint(x: 0, y: 0))
        p.closeSubpath()
        return p
    }
}

// MARK: - The reveal pocket (accent behind the lifted corner)

private struct DogearBookmarkView_RevealPocket: Shape {
    var ear: CGFloat
    var progress: CGFloat

    func path(in rect: CGRect) -> Path {
        let w = rect.width
        let s = min(ear, min(w, rect.height))
        // Triangle A, B, C0 — the area exposed when the corner folds away.
        let a = CGPoint(x: w - s, y: 0)
        let b = CGPoint(x: w, y: s)
        let c0 = CGPoint(x: w, y: 0)

        var p = Path()
        p.move(to: a)
        p.addLine(to: c0)
        p.addLine(to: b)
        p.closeSubpath()
        return p
    }
}

// MARK: - The folding flap (Animatable on foldProgress)

/// Triangle [A, B, C] where C lerps from the unfolded corner C0 = (W, 0)
/// to the fully-folded corner C1 = (W - s, s) — the reflection of C0 across
/// the fold line A->B. At foldProgress == 0 the triangle is the normal corner
/// (filled with the card color, so invisible); at 1 it lies fully folded in.
private struct DogearBookmarkView_FoldFlap: Shape {
    var ear: CGFloat
    var foldProgress: CGFloat

    var animatableData: CGFloat {
        get { foldProgress }
        set { foldProgress = newValue }
    }

    func path(in rect: CGRect) -> Path {
        let w = rect.width
        let s = min(ear, min(w, rect.height))
        let p = min(max(foldProgress, 0), 1)

        let a = CGPoint(x: w - s, y: 0)
        let b = CGPoint(x: w, y: s)
        let c0 = CGPoint(x: w, y: 0)
        let c1 = CGPoint(x: w - s, y: s)
        let c = CGPoint(x: c0.x + (c1.x - c0.x) * p,
                        y: c0.y + (c1.y - c0.y) * p)

        var path = Path()
        path.move(to: a)
        path.addLine(to: c)
        path.addLine(to: b)
        path.closeSubpath()
        return path
    }
}
"""###,
        "mi-elastic-segmented": ###"""
import SwiftUI

// MARK: - Elastic Segmented Control
// A selection pill that rubber-bands between segments: the edge moving in the
// direction of travel leads (fast spring, overshoots), the trailing edge lags
// (slow spring), so the capsule momentarily spans the gap before collapsing to
// a single segment width on arrival. The active label crossfades to a bolder
// weight. demo == true self-drives the selection on a ~3s loop.

struct ElasticSegmentedView: View {
    var demo: Bool = false

    private let labels: [String] = ["Day", "Week", "Month"]

    var body: some View {
        GeometryReader { geo in
            let size = geo.size
            content(in: size)
                .frame(width: size.width, height: size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    @ViewBuilder
    private func content(in size: CGSize) -> some View {
        if demo {
            ElasticSegmentedView_ElasticSegDemoDriver(labels: labels, canvas: size)
        } else {
            ElasticSegmentedView_ElasticSegInteractive(labels: labels, canvas: size)
        }
    }
}

// MARK: - Shared layout math

private struct ElasticSegmentedView_ElasticSegMetrics {
    let canvas: CGSize
    let count: Int

    // The control occupies a centered, inset band of the canvas so it reads
    // well both in a tiny tile and a large detail area.
    var trackInset: CGFloat { max(6, min(canvas.width, canvas.height) * 0.10) }

    var trackWidth: CGFloat { max(0, canvas.width - trackInset * 2) }

    var trackHeight: CGFloat {
        let h = canvas.height - trackInset * 2
        // Keep the track a sane height regardless of aspect ratio.
        return max(0, min(h, max(28, canvas.height * 0.42)))
    }

    var trackOriginX: CGFloat { trackInset }
    var trackOriginY: CGFloat { (canvas.height - trackHeight) / 2 }

    var segmentWidth: CGFloat {
        guard count > 0 else { return 0 }
        return trackWidth / CGFloat(count)
    }

    var innerPadding: CGFloat { max(3, trackHeight * 0.10) }

    var fontSize: CGFloat { max(9, min(20, trackHeight * 0.34)) }

    var hasRoom: Bool { trackWidth > 1 && trackHeight > 1 }

    // Given the fractional leading/trailing edge indices, return the pill rect
    // in track-local coordinates. The pill is never narrower than one segment.
    func pillRect(leftFrac: Double, rightFrac: Double) -> CGRect {
        let lo = CGFloat(min(leftFrac, rightFrac))
        let hi = CGFloat(max(leftFrac, rightFrac))
        let segW = segmentWidth
        let x = lo * segW + innerPadding
        let span = (hi - lo) * segW
        let w = segW + span - innerPadding * 2
        let y = innerPadding
        let h = trackHeight - innerPadding * 2
        return CGRect(x: x, y: y, width: max(0, w), height: max(0, h))
    }

    func segmentCenterX(_ index: Int) -> CGFloat {
        (CGFloat(index) + 0.5) * segmentWidth
    }
}

// MARK: - Palette (literal colors only; no design-system dependency)

private enum ElasticSegmentedView_ElasticSegPalette {
    static let trackTop = Color(red: 0.12, green: 0.10, blue: 0.18)
    static let trackBottom = Color(red: 0.08, green: 0.07, blue: 0.13)
    static let trackStroke = Color(red: 1.0, green: 1.0, blue: 1.0).opacity(0.06)

    static let pillTop = Color(red: 0.55, green: 0.42, blue: 0.98)
    static let pillBottom = Color(red: 0.38, green: 0.30, blue: 0.92)
    static let pillGlow = Color(red: 0.60, green: 0.48, blue: 1.0)

    static let labelIdle = Color(red: 1.0, green: 1.0, blue: 1.0).opacity(0.45)
    static let labelActive = Color(red: 1.0, green: 1.0, blue: 1.0)
}

// MARK: - The pill renderer (used by both modes)

private struct ElasticSegmentedView_ElasticSegPill: View {
    let rect: CGRect
    let height: CGFloat

    var body: some View {
        let radius = max(4, min(rect.width, height) / 2)
        Capsule(style: .continuous)
            .fill(
                LinearGradient(
                    colors: [ElasticSegmentedView_ElasticSegPalette.pillTop, ElasticSegmentedView_ElasticSegPalette.pillBottom],
                    startPoint: .top,
                    endPoint: .bottom
                )
            )
            .overlay(
                Capsule(style: .continuous)
                    .stroke(Color.white.opacity(0.22), lineWidth: 0.8)
            )
            .frame(width: rect.width, height: rect.height)
            .shadow(color: ElasticSegmentedView_ElasticSegPalette.pillGlow.opacity(0.45), radius: radius * 0.55, y: 1)
            .position(x: rect.midX, y: rect.midY)
    }
}

// MARK: - Track background + label row (shared)

private struct ElasticSegmentedView_ElasticSegTrack: View {
    let metrics: ElasticSegmentedView_ElasticSegMetrics
    let labels: [String]
    let activeIndex: Int
    let activeStrength: Double // 0...1 how "settled" the active label is

    var body: some View {
        ZStack(alignment: .topLeading) {
            background
            labelRow
        }
        .frame(width: metrics.trackWidth, height: metrics.trackHeight)
    }

    private var background: some View {
        RoundedRectangle(cornerRadius: metrics.trackHeight / 2, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [ElasticSegmentedView_ElasticSegPalette.trackTop, ElasticSegmentedView_ElasticSegPalette.trackBottom],
                    startPoint: .top,
                    endPoint: .bottom
                )
            )
            .overlay(
                RoundedRectangle(cornerRadius: metrics.trackHeight / 2, style: .continuous)
                    .stroke(ElasticSegmentedView_ElasticSegPalette.trackStroke, lineWidth: 1)
            )
    }

    private var labelRow: some View {
        HStack(spacing: 0) {
            ForEach(Array(labels.enumerated()), id: \.offset) { index, text in
                segmentLabel(index: index, text: text)
                    .frame(width: metrics.segmentWidth, height: metrics.trackHeight)
            }
        }
    }

    // Two stacked weight variants crossfaded by proximity to the pill keep the
    // label legible on every frame and give the "weight crossfade" effect
    // without relying on contentTransition(.interpolate) on fontWeight.
    private func segmentLabel(index: Int, text: String) -> some View {
        let isActive = index == activeIndex
        let activeAmt = isActive ? activeStrength : 0
        return ZStack {
            Text(text)
                .font(.system(size: metrics.fontSize, weight: .medium))
                .foregroundStyle(ElasticSegmentedView_ElasticSegPalette.labelIdle)
                .opacity(1 - activeAmt)
            Text(text)
                .font(.system(size: metrics.fontSize, weight: .bold))
                .foregroundStyle(ElasticSegmentedView_ElasticSegPalette.labelActive)
                .opacity(activeAmt)
        }
        .lineLimit(1)
        .minimumScaleFactor(0.55)
        .padding(.horizontal, 2)
    }
}

// MARK: - Demo mode (self-driving, pure function of time)

private struct ElasticSegmentedView_ElasticSegDemoDriver: View {
    let labels: [String]
    let canvas: CGSize

    var body: some View {
        let metrics = ElasticSegmentedView_ElasticSegMetrics(canvas: canvas, count: labels.count)
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            let state = ElasticSegmentedView_ElasticSegDemoDriver.driveState(time: t, count: labels.count)
            ZStack(alignment: .topLeading) {
                ElasticSegmentedView_ElasticSegTrack(
                    metrics: metrics,
                    labels: labels,
                    activeIndex: state.activeIndex,
                    activeStrength: state.activeStrength
                )
                if metrics.hasRoom {
                    let r = metrics.pillRect(leftFrac: state.leftFrac, rightFrac: state.rightFrac)
                    ElasticSegmentedView_ElasticSegPill(rect: r, height: metrics.trackHeight)
                }
            }
            .frame(width: metrics.trackWidth, height: metrics.trackHeight)
            .position(
                x: metrics.trackOriginX + metrics.trackWidth / 2,
                y: metrics.trackOriginY + metrics.trackHeight / 2
            )
        }
    }

    struct State {
        var leftFrac: Double
        var rightFrac: Double
        var activeIndex: Int
        var activeStrength: Double
    }

    // Pure function of time: cycles through segments, baking the lead/lag
    // asymmetry into the eased ramps so the pill spans the gap mid-travel and
    // collapses to one segment on arrival. Never narrower than one segment.
    private static func driveState(time: Double, count: Int) -> State {
        let dwell: Double = 0.55      // fraction of a step spent settled
        let stepDuration: Double = 1.2
        let cycle = stepDuration * Double(count)
        let phase = time.truncatingRemainder(dividingBy: cycle)
        let stepIndex = Int(phase / stepDuration) % count
        let nextIndex = (stepIndex + 1) % count
        let local = (phase / stepDuration) - Double(Int(phase / stepDuration)) // 0...1 in step

        // The first `dwell` of each step is settled on `stepIndex`; the rest is
        // the transition toward `nextIndex`.
        if local < dwell {
            let from = Double(stepIndex)
            return State(leftFrac: from, rightFrac: from,
                         activeIndex: stepIndex, activeStrength: 1)
        }

        let p = (local - dwell) / (1 - dwell) // 0...1 transition progress
        let from = Double(stepIndex)
        let to = Double(nextIndex)

        // Wrap-around (e.g. 2 -> 0) moves left visually; otherwise right.
        let movingRight = nextIndex > stepIndex

        // Lead edge: fast with overshoot. Trail edge: slow, no overshoot.
        let leadEase = overshoot(p)            // arrives early, overshoots
        let trailEase = easeInOutSlow(p)       // lags behind

        let leadPos = from + (to - from) * leadEase
        let trailPos = from + (to - from) * trailEase

        let left: Double
        let right: Double
        if movingRight {
            // Right edge is the lead; left edge is the trail.
            right = leadPos
            left = trailPos
        } else {
            // Moving left: left edge is the lead; right edge trails.
            left = leadPos
            right = trailPos
        }

        // Active label: hand over weight near the midpoint of travel.
        let handover = smoothstep(p, edge0: 0.35, edge1: 0.75)
        let activeIndex = handover < 0.5 ? stepIndex : nextIndex
        let strength = handover < 0.5 ? (1 - handover * 2) : ((handover - 0.5) * 2)

        return State(leftFrac: left, rightFrac: right,
                     activeIndex: activeIndex, activeStrength: max(0.15, strength))
    }

    // Fast ramp that overshoots past 1 then settles — drives the lead edge.
    private static func overshoot(_ p: Double) -> Double {
        let c = clamp01(p)
        // Slightly compressed time so the lead arrives early.
        let q = clamp01(c * 1.18)
        let s = 1.70158
        let x = q - 1
        return 1 + (s + 1) * x * x * x + s * x * x
    }

    // Slow ease for the trailing edge so it lags behind the lead.
    private static func easeInOutSlow(_ p: Double) -> Double {
        let c = clamp01(p)
        // Delay the start so the trail visibly lags, then ease in-out.
        let q = clamp01((c - 0.12) / 0.88)
        return q < 0.5 ? 4 * q * q * q : 1 - pow(-2 * q + 2, 3) / 2
    }

    private static func smoothstep(_ x: Double, edge0: Double, edge1: Double) -> Double {
        let t = clamp01((x - edge0) / (edge1 - edge0))
        return t * t * (3 - 2 * t)
    }

    private static func clamp01(_ v: Double) -> Double { min(1, max(0, v)) }
}

// MARK: - Interactive mode

private struct ElasticSegmentedView_ElasticSegInteractive: View {
    let labels: [String]
    let canvas: CGSize

    @State private var selectedIndex: Int = 0
    @State private var leadFrac: Double = 0
    @State private var trailFrac: Double = 0
    @State private var activeStrength: Double = 1

    var body: some View {
        let metrics = ElasticSegmentedView_ElasticSegMetrics(canvas: canvas, count: labels.count)
        ZStack(alignment: .topLeading) {
            ElasticSegmentedView_ElasticSegTrack(
                metrics: metrics,
                labels: labels,
                activeIndex: selectedIndex,
                activeStrength: activeStrength
            )
            if metrics.hasRoom {
                let r = metrics.pillRect(leftFrac: leadFrac, rightFrac: trailFrac)
                ElasticSegmentedView_ElasticSegPill(rect: r, height: metrics.trackHeight)
            }
            tapRow(metrics: metrics)
        }
        .frame(width: metrics.trackWidth, height: metrics.trackHeight)
        .position(
            x: metrics.trackOriginX + metrics.trackWidth / 2,
            y: metrics.trackOriginY + metrics.trackHeight / 2
        )
        .sensoryFeedback(.selection, trigger: selectedIndex)
    }

    private func tapRow(metrics: ElasticSegmentedView_ElasticSegMetrics) -> some View {
        HStack(spacing: 0) {
            ForEach(Array(labels.enumerated()), id: \.offset) { index, _ in
                Color.clear
                    .frame(width: metrics.segmentWidth, height: metrics.trackHeight)
                    .contentShape(Rectangle())
                    .onTapGesture { select(index) }
            }
        }
    }

    // Direction-dependent springs: the edge moving in the travel direction is
    // the lead (fast, bouncy → overshoot/squash); the opposite edge is the
    // trail (slow, no bounce → lags and spans the gap mid-travel).
    private func select(_ index: Int) {
        guard index != selectedIndex else { return }
        let movingRight = index > selectedIndex
        let target = Double(index)

        let fastSpring = Animation.spring(response: 0.26, dampingFraction: 0.55)
        let slowSpring = Animation.spring(response: 0.46, dampingFraction: 0.85)

        selectedIndex = index

        // leadFrac / trailFrac map to the geometric left/right edges via
        // min/max inside pillRect, so we just animate them with the right
        // springs depending on which edge leads.
        if movingRight {
            // lead = right edge → animate the larger-bound edge fast.
            withAnimation(fastSpring) { leadFrac = target }
            withAnimation(slowSpring) { trailFrac = target }
        } else {
            // moving left: lead = left edge.
            withAnimation(fastSpring) { trailFrac = target }
            withAnimation(slowSpring) { leadFrac = target }
        }

        withAnimation(.easeInOut(duration: 0.28)) { activeStrength = 0.2 }
        withAnimation(.spring(response: 0.4, dampingFraction: 0.7).delay(0.12)) {
            activeStrength = 1
        }
    }
}
"""###,
        "mi-emoji-fountain": ###"""
import SwiftUI

// MARK: - Particle Model

private struct EmojiFountainView_EmojiParticle {
    var x: CGFloat
    var y: CGFloat
    var vx: CGFloat
    var vy: CGFloat
    var angle: CGFloat
    var spin: CGFloat
    var age: Double
    var life: Double
    var size: CGFloat
    var glyphIndex: Int

    var isDead: Bool { age >= life }
}

// MARK: - Particle Engine
// A plain reference type held in @State. Its mutations happen inside the
// Canvas draw closure and are intentionally invisible to SwiftUI's
// dependency tracking; TimelineView(.animation) drives the redraws.

private final class EmojiFountainView_EmojiFountainEngine {
    var particles: [EmojiFountainView_EmojiParticle] = []
    var lastTime: Double = -1
    var emissionAccumulator: Double = 0
    var seed: UInt64 = 0x9E3779B97F4A7C15

    let maxParticles = 150

    // Cheap deterministic PRNG so spawn jitter is stable & fast.
    private func nextUnit() -> CGFloat {
        seed = seed &* 6364136223846793005 &+ 1442695040888963407
        let bits = (seed >> 33) & 0xFFFFFF
        return CGFloat(bits) / CGFloat(0xFFFFFF)
    }

    private func nextRange(_ lo: CGFloat, _ hi: CGFloat) -> CGFloat {
        lo + (hi - lo) * nextUnit()
    }

    /// Advance the simulation by a clamped delta and emit at the given rate.
    /// - Parameters:
    ///   - dt: seconds elapsed (already clamped by caller)
    ///   - rate: particles per second to spawn this step (0 = none)
    ///   - origin: nozzle position in canvas space
    ///   - gravity: downward acceleration in points/s^2
    ///   - glyphCount: number of available emoji glyphs
    func step(dt: Double,
              rate: Double,
              origin: CGPoint,
              gravity: CGFloat,
              glyphCount: Int) {
        // Emit
        if rate > 0 {
            emissionAccumulator += rate * dt
            var toSpawn = Int(emissionAccumulator)
            if toSpawn > 0 {
                emissionAccumulator -= Double(toSpawn)
                // Don't overshoot the cap in a single hitchy frame.
                let room = maxParticles - particles.count
                toSpawn = min(toSpawn, max(0, room))
                for _ in 0..<toSpawn {
                    spawn(at: origin, glyphCount: glyphCount)
                }
            }
        } else {
            emissionAccumulator = 0
        }

        // Integrate (semi-implicit Euler) + cull.
        let g = gravity
        let drag: CGFloat = 0.06
        for i in particles.indices {
            particles[i].vy += g * CGFloat(dt)
            // mild horizontal air drag so the spray feathers out
            particles[i].vx -= particles[i].vx * drag * CGFloat(dt)
            particles[i].x += particles[i].vx * CGFloat(dt)
            particles[i].y += particles[i].vy * CGFloat(dt)
            particles[i].angle += particles[i].spin * CGFloat(dt)
            particles[i].age += dt
        }

        particles.removeAll { p in
            p.isDead || p.y > origin.y + 2000
        }
    }

    private func spawn(at origin: CGPoint, glyphCount: Int) {
        // Upward arcing burst with a spread cone biased to vertical.
        let speed = nextRange(360, 620)
        // angle measured from straight up; +/- spread
        let spread = nextRange(-0.42, 0.42)
        let vx = sin(spread) * speed
        let vy = -cos(spread) * speed
        let p = EmojiFountainView_EmojiParticle(
            x: origin.x + nextRange(-6, 6),
            y: origin.y,
            vx: vx,
            vy: vy,
            angle: nextRange(0, .pi * 2),
            spin: nextRange(-7, 7),
            age: 0,
            life: Double(nextRange(1.5, 2.6)),
            size: nextRange(20, 34),
            glyphIndex: Int(nextUnit() * CGFloat(glyphCount)) % max(1, glyphCount)
        )
        particles.append(p)
    }
}

// MARK: - View

struct EmojiFountainView: View {
    var demo: Bool = false

    @State private var engine = EmojiFountainView_EmojiFountainEngine()
    @State private var isPressing = false
    @State private var pressStart: Double = 0
    @State private var holdRamp: Double = 0   // 0...1 interactive hold intensity

    private let glyphs: [String] = ["🎉", "✨", "💖", "🌟", "🎈", "🥳", "💫", "🔥"]

    var body: some View {
        GeometryReader { geo in
            let size = geo.size
            ZStack {
                background
                fountainCanvas(size: size)
                nozzle(size: size)
            }
            .frame(width: size.width, height: size.height)
            .contentShape(Rectangle())
            .gesture(pressGesture, including: demo ? .none : .all)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .clipped()
    }

    // MARK: Layers

    private var background: some View {
        LinearGradient(
            colors: [
                Color(red: 0.09, green: 0.07, blue: 0.13),
                Color(red: 0.05, green: 0.04, blue: 0.09)
            ],
            startPoint: .top,
            endPoint: .bottom
        )
        .ignoresSafeArea()
    }

    private func fountainCanvas(size: CGSize) -> some View {
        TimelineView(.animation) { timeline in
            let now = timeline.date.timeIntervalSinceReferenceDate
            Canvas { context, canvasSize in
                advance(now: now, canvasSize: canvasSize)
                draw(in: &context, canvasSize: canvasSize)
            }
        }
        .allowsHitTesting(false)
    }

    private func nozzle(size: CGSize) -> some View {
        let dim = min(size.width, size.height)
        let buttonSize = max(34, dim * 0.34)
        return VStack {
            Spacer(minLength: 0)
            ZStack {
                Circle()
                    .fill(
                        RadialGradient(
                            colors: [
                                Color(red: 1.0, green: 0.52, blue: 0.72),
                                Color(red: 0.86, green: 0.27, blue: 0.55)
                            ],
                            center: .topLeading,
                            startRadius: 1,
                            endRadius: buttonSize
                        )
                    )
                    .overlay(
                        Circle().strokeBorder(
                            Color.white.opacity(0.35), lineWidth: 1.5)
                    )
                    .shadow(color: Color(red: 0.86, green: 0.27, blue: 0.55)
                        .opacity(0.6),
                        radius: glowRadius, x: 0, y: 0)
                    .scaleEffect(buttonScale)
                Text("🎊")
                    .font(.system(size: buttonSize * 0.5))
                    .scaleEffect(buttonScale)
            }
            .frame(width: buttonSize, height: buttonSize)
            .padding(.bottom, max(8, dim * 0.1))
            .animation(.spring(response: 0.3, dampingFraction: 0.6),
                       value: isPressing)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity, alignment: .bottom)
        .allowsHitTesting(false)
    }

    // MARK: Derived visuals

    private var buttonScale: CGFloat {
        isPressing ? 0.86 : 1.0
    }

    private var glowRadius: CGFloat {
        isPressing ? 18 : 8
    }

    // MARK: Simulation driving

    private func advance(now: Double, canvasSize: CGSize) {
        if engine.lastTime < 0 {
            engine.lastTime = now
        }
        var dt = now - engine.lastTime
        engine.lastTime = now
        // Clamp: first frame & background-return produce huge dt.
        dt = min(max(dt, 0), 1.0 / 30.0)

        let origin = nozzleOrigin(in: canvasSize)
        let rate = emissionRate(now: now)
        engine.step(dt: dt,
                    rate: rate,
                    origin: origin,
                    gravity: gravity(for: canvasSize),
                    glyphCount: glyphs.count)
    }

    private func gravity(for size: CGSize) -> CGFloat {
        // Scale gravity with view height so the arc shape is size-agnostic.
        let h = max(size.height, 1)
        return h * 2.6
    }

    private func nozzleOrigin(in size: CGSize) -> CGPoint {
        let dim = min(size.width, size.height)
        let buttonSize = max(34, dim * 0.34)
        let bottomPad = max(8, dim * 0.1)
        let y = size.height - bottomPad - buttonSize * 0.75
        return CGPoint(x: size.width / 2, y: y)
    }

    /// Particles per second. Demo: sinusoidal pulse with a non-zero floor so
    /// the canvas is never empty. Interactive: ramps with hold duration.
    private func emissionRate(now: Double) -> Double {
        if demo {
            // ~3.2s loop, oscillating between a calm floor and a lively peak.
            let phase = sin(now * (2 * Double.pi / 3.2))
            let normalized = (phase + 1) / 2          // 0...1
            let floor = 24.0
            let peak = 95.0
            return floor + (peak - floor) * normalized
        } else {
            guard isPressing else { return 0 }
            let held = now - pressStart
            // Ramp 0.4s ease-in from a baseline to a fat stream.
            let ramp = min(1.0, held / 1.2)
            let eased = ramp * ramp * (3 - 2 * ramp)  // smoothstep
            let base = 28.0
            let maxRate = 110.0
            return base + (maxRate - base) * eased
        }
    }

    // MARK: Drawing

    private func draw(in context: inout GraphicsContext, canvasSize: CGSize) {
        // Resolve each glyph once (no per-emoji view allocation).
        var resolved: [GraphicsContext.ResolvedText] = []
        resolved.reserveCapacity(glyphs.count)
        for g in glyphs {
            let text = Text(g).font(.system(size: 28))
            resolved.append(context.resolve(text))
        }

        for p in engine.particles {
            let t = p.age / max(p.life, 0.0001)
            let opacity = fade(t)
            if opacity <= 0.01 { continue }

            // Copy the value-type context per particle so transforms don't
            // accumulate across the whole canvas.
            var c = context
            c.opacity = opacity
            c.translateBy(x: p.x, y: p.y)
            c.rotate(by: .radians(Double(p.angle)))
            let scale = p.size / 28.0
            c.scaleBy(x: scale, y: scale)
            c.draw(resolved[p.glyphIndex], at: .zero, anchor: .center)
        }
    }

    private func fade(_ t: Double) -> Double {
        // Quick fade-in, long hold, fade-out near end of life.
        if t < 0.08 {
            return t / 0.08
        } else if t > 0.75 {
            return max(0, (1 - t) / 0.25)
        }
        return 1
    }

    // MARK: Gesture

    private var pressGesture: some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { _ in
                if !isPressing {
                    isPressing = true
                    pressStart = Date().timeIntervalSinceReferenceDate
                }
            }
            .onEnded { _ in
                isPressing = false
            }
    }
}
"""###,
        "mi-favorite-fold": ###"""
import SwiftUI

// MARK: - FavoriteFoldView
/// A star favorite that folds origami-style: its five points fold inward to a
/// flat disc when off and unfold with a springy snap when favorited.
struct FavoriteFoldView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { geo in
            let side = min(geo.size.width, geo.size.height)
            ZStack {
                backdrop
                content(side: side)
            }
            .frame(width: geo.size.width, height: geo.size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // MARK: Backdrop

    private var backdrop: some View {
        RadialGradient(
            colors: [
                Color(red: 0.13, green: 0.10, blue: 0.17),
                Color(red: 0.08, green: 0.06, blue: 0.11)
            ],
            center: .center,
            startRadius: 0,
            endRadius: 220
        )
        .ignoresSafeArea()
    }

    // MARK: Content router

    @ViewBuilder
    private func content(side: CGFloat) -> some View {
        if demo {
            FavoriteFoldView_DemoDriver(side: side)
        } else {
            FavoriteFoldView_InteractiveStar(side: side)
        }
    }
}

// MARK: - Demo (self-driving, no touch)

private struct FavoriteFoldView_DemoDriver: View {
    let side: CGFloat

    var body: some View {
        // Auto-looping PhaseAnimator (no trigger) so the tile is always alive.
        // Three phases give a dwell on the open star, then fold shut, then a
        // brief over-folded settle before springing back open. Never blank.
        PhaseAnimator([0, 1, 2]) { phase in
            FavoriteFoldView_FoldingStar(favorited: phase == 0, side: side)
        } animation: { phase in
            switch phase {
            case 0:
                return .spring(response: 0.55, dampingFraction: 0.52)
                    .delay(0.2)
            case 1:
                return .spring(response: 0.5, dampingFraction: 0.7)
            default:
                return .easeInOut(duration: 0.9)
            }
        }
    }
}

// MARK: - Interactive (tap to toggle)

private struct FavoriteFoldView_InteractiveStar: View {
    let side: CGFloat
    @State private var favorited: Bool = true

    var body: some View {
        FavoriteFoldView_FoldingStar(favorited: favorited, side: side)
            .contentShape(Rectangle())
            .onTapGesture {
                withAnimation(.spring(response: 0.5, dampingFraction: 0.5)) {
                    favorited.toggle()
                }
            }
            .sensoryFeedback(.impact(flexibility: .soft), trigger: favorited)
    }
}

// MARK: - The folding star assembly

private struct FavoriteFoldView_FoldingStar: View {
    var favorited: Bool
    let side: CGFloat

    /// Drives all geometry. 0 == fully open sharp star, 1 == flat disc.
    private var fold: CGFloat { favorited ? 0 : 1 }

    private var dim: CGFloat { side * 0.62 }
    private var outerR: CGFloat { dim * 0.5 }
    private var innerR: CGFloat { dim * 0.5 * 0.40 }

    var body: some View {
        ZStack {
            haloGlow
            baseDisc
            starFill
            facetShading
            outlineStroke
            centerSheen
        }
        .frame(width: dim, height: dim)
        .scaleEffect(favorited ? 1.0 : 0.96)
    }

    // Soft warm glow that strengthens when favorited.
    private var haloGlow: some View {
        FavoriteFoldView_FoldingStarShape(fold: fold, outerR: outerR, innerR: innerR)
            .fill(Color(red: 1.0, green: 0.78, blue: 0.30))
            .blur(radius: dim * 0.16)
            .opacity(0.55 - Double(fold) * 0.4)
    }

    // A constant disc underneath so the shape never reads as empty mid-fold.
    private var baseDisc: some View {
        Circle()
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.30, green: 0.26, blue: 0.34),
                        Color(red: 0.20, green: 0.17, blue: 0.24)
                    ],
                    startPoint: .top,
                    endPoint: .bottom
                )
            )
            .frame(width: innerR * 2.06, height: innerR * 2.06)
            .opacity(Double(fold))
    }

    private var starFill: some View {
        FavoriteFoldView_FoldingStarShape(fold: fold, outerR: outerR, innerR: innerR)
            .fill(bodyGradient)
            .shadow(color: .black.opacity(0.35), radius: 6, x: 0, y: 4)
    }

    private var bodyGradient: LinearGradient {
        // Lerp known literal stops as plain (r,g,b) tuples — no UIColor.
        let openTop: (Double, Double, Double) = (1.0, 0.86, 0.34)
        let openBot: (Double, Double, Double) = (0.98, 0.62, 0.16)
        let foldTop: (Double, Double, Double) = (0.42, 0.37, 0.46)
        let foldBot: (Double, Double, Double) = (0.28, 0.24, 0.32)
        let f = Double(fold)
        return LinearGradient(
            colors: [
                lerpColor(openTop, foldTop, f),
                lerpColor(openBot, foldBot, f)
            ],
            startPoint: .topLeading,
            endPoint: .bottomTrailing
        )
    }

    // Per-point directional fold shadows registered to the same vertices.
    private var facetShading: some View {
        FavoriteFoldView_FacetShadeShape(fold: fold, outerR: outerR, innerR: innerR)
            .fill(Color.black)
            .opacity(0.04 + Double(fold) * 0.30)
            .blendMode(.multiply)
    }

    private var outlineStroke: some View {
        FavoriteFoldView_FoldingStarShape(fold: fold, outerR: outerR, innerR: innerR)
            .stroke(
                Color.white.opacity(0.18 + (1 - Double(fold)) * 0.22),
                lineWidth: max(1, dim * 0.012)
            )
    }

    // A small bright crease highlight in the middle that fades when folded.
    private var centerSheen: some View {
        Circle()
            .fill(Color.white)
            .frame(width: innerR * 0.5, height: innerR * 0.5)
            .blur(radius: innerR * 0.28)
            .opacity(0.5 * (1 - Double(fold)))
            .offset(x: -innerR * 0.18, y: -innerR * 0.22)
    }

    private func lerpColor(
        _ a: (Double, Double, Double),
        _ b: (Double, Double, Double),
        _ t: Double
    ) -> Color {
        let ct = min(max(t, 0), 1)
        return Color(
            red: a.0 + (b.0 - a.0) * ct,
            green: a.1 + (b.1 - a.1) * ct,
            blue: a.2 + (b.2 - a.2) * ct
        )
    }
}

// MARK: - Star geometry helpers (shared formula keeps facets registered)

private func starVertices(
    fold: CGFloat,
    outerR: CGFloat,
    innerR: CGFloat,
    center: CGPoint
) -> [CGPoint] {
    // Always 10 vertices: 5 outer tips + 5 inner valleys, constant count so
    // interpolation is clean. The outer radius lerps from a sharp star toward
    // the inner radius (a near-regular decagon ~ flat disc) as fold -> 1.
    let clamped = max(min(fold, 1.05), -0.25)
    // On the folding-shut side, floor the outer radius at the inner radius so a
    // spring overshoot past fold=1 cannot invert the shape. Overshoot below 0
    // is allowed (tips pop out past the full star = the satisfying snap).
    let rawOuter = outerR + (innerR - outerR) * clamped
    let liveOuter = max(rawOuter, innerR)

    var pts: [CGPoint] = []
    pts.reserveCapacity(10)
    let startAngle = -CGFloat.pi / 2
    for i in 0..<5 {
        let outerAngle = startAngle + CGFloat(i) * (.pi * 2 / 5)
        let innerAngle = outerAngle + (.pi / 5)
        pts.append(CGPoint(
            x: center.x + liveOuter * cos(outerAngle),
            y: center.y + liveOuter * sin(outerAngle)
        ))
        pts.append(CGPoint(
            x: center.x + innerR * cos(innerAngle),
            y: center.y + innerR * sin(innerAngle)
        ))
    }
    return pts
}

// MARK: - Animatable star shape

private struct FavoriteFoldView_FoldingStarShape: Shape {
    var fold: CGFloat
    var outerR: CGFloat
    var innerR: CGFloat

    var animatableData: CGFloat {
        get { fold }
        set { fold = newValue }
    }

    func path(in rect: CGRect) -> Path {
        let center = CGPoint(x: rect.midX, y: rect.midY)
        let pts = starVertices(
            fold: fold, outerR: outerR, innerR: innerR, center: center
        )
        var path = Path()
        guard let first = pts.first else { return path }
        path.move(to: first)
        for p in pts.dropFirst() { path.addLine(to: p) }
        path.closeSubpath()
        return path
    }
}

// MARK: - Facet shade shape (alternating triangles darken as fold increases)

private struct FavoriteFoldView_FacetShadeShape: Shape {
    var fold: CGFloat
    var outerR: CGFloat
    var innerR: CGFloat

    var animatableData: CGFloat {
        get { fold }
        set { fold = newValue }
    }

    func path(in rect: CGRect) -> Path {
        let center = CGPoint(x: rect.midX, y: rect.midY)
        let pts = starVertices(
            fold: fold, outerR: outerR, innerR: innerR, center: center
        )
        var path = Path()
        guard pts.count == 10 else { return path }
        // Shade one flank of each point (a triangle from center to the tip and
        // its trailing valley) to read as a folded crease side.
        for i in 0..<5 {
            let tip = pts[i * 2]
            let valley = pts[(i * 2 + 1) % 10]
            path.move(to: center)
            path.addLine(to: tip)
            path.addLine(to: valley)
            path.closeSubpath()
        }
        return path
    }
}
"""###,
        "mi-jelly-count-badge": ###"""
import SwiftUI

// MARK: - Jelly Count Badge
// A notification badge whose number drops in from above, squashing the badge
// into a wobbly gelatin blob that springs back to a clean circle.
// interaction == "auto": both demo states are self-driving on a ~2.8s loop.
// demo == false additionally lets a tap bump the count for tactility.
struct JellyCountBadgeView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { geo in
            JellyCountBadgeView_JellyBadgeStage(side: min(geo.size.width, geo.size.height),
                            interactive: !demo)
                .frame(width: geo.size.width, height: geo.size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }
}

// MARK: - Stage (host icon + badge), drives the auto loop

private struct JellyCountBadgeView_JellyBadgeStage: View {
    let side: CGFloat
    let interactive: Bool

    // Cycle over a small, legible range so the loop stays clean.
    private let sequence: [Int] = [1, 2, 3, 5, 8, 12, 1]

    @State private var index: Int = 0
    @State private var count: Int = 1
    @State private var didAppear: Bool = false

    private let loopInterval: TimeInterval = 2.8

    var body: some View {
        let host = side * 0.62
        let corner = host * 0.26

        ZStack {
            hostIcon(side: host, corner: corner)

            JellyCountBadgeView_JellyBadge(count: count, diameter: badgeDiameter(host: host))
                .offset(x: host * 0.40, y: -host * 0.40)
                .contentShape(Circle())
                .onTapGesture {
                    guard interactive else { return }
                    bump()
                }
        }
        .frame(width: side, height: side)
        // Bare increments won't move; the transition needs an animation
        // transaction keyed to the displayed count.
        .animation(.spring(response: 0.42, dampingFraction: 0.62), value: count)
        .onAppear { startLoop() }
    }

    private func badgeDiameter(host: CGFloat) -> CGFloat {
        let base = host * 0.46
        // Widen slightly for two-digit values so digits stay legible.
        return count >= 10 ? base * 1.18 : base
    }

    // MARK: Host app-icon look

    @ViewBuilder
    private func hostIcon(side: CGFloat, corner: CGFloat) -> some View {
        RoundedRectangle(cornerRadius: corner, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.30, green: 0.32, blue: 0.46),
                        Color(red: 0.16, green: 0.17, blue: 0.27)
                    ],
                    startPoint: .topLeading,
                    endPoint: .bottomTrailing
                )
            )
            .overlay(
                RoundedRectangle(cornerRadius: corner, style: .continuous)
                    .strokeBorder(Color.white.opacity(0.10), lineWidth: 1)
            )
            .overlay(envelopeGlyph(side: side))
            .frame(width: side, height: side)
            .shadow(color: Color.black.opacity(0.35),
                    radius: side * 0.10, x: 0, y: side * 0.06)
    }

    @ViewBuilder
    private func envelopeGlyph(side: CGFloat) -> some View {
        Image(systemName: "bell.fill")
            .font(.system(size: side * 0.40, weight: .semibold))
            .foregroundStyle(Color.white.opacity(0.92))
    }

    // MARK: Loop + interaction

    private func startLoop() {
        guard !didAppear else { return }
        didAppear = true
        advance() // first hop is part of the loop, not instant
    }

    private func advance() {
        DispatchQueue.main.asyncAfter(deadline: .now() + loopInterval) {
            index = (index + 1) % sequence.count
            count = sequence[index]
            advance()
        }
    }

    private func bump() {
        if count >= 99 {
            count = 1
        } else {
            count += 1
        }
    }
}

// MARK: - The jelly badge itself

private struct JellyCountBadgeView_JellyBadge: View {
    let count: Int
    let diameter: CGFloat

    var body: some View {
        // PhaseAnimator(trigger:) runs the full squash->overshoot->settle
        // sequence exactly once per count change — the spec's behavior.
        PhaseAnimator(JellyCountBadgeView_JellyPhase.allCases, trigger: count) { phase in
            badgeBody
                .scaleEffect(x: phase.scaleX, y: phase.scaleY, anchor: .bottom)
        } animation: { phase in
            phase.animation
        }
    }

    private var badgeBody: some View {
        ZStack {
            // Soft contact shadow grounds the blob.
            Circle()
                .fill(Color.black.opacity(0.30))
                .frame(width: diameter, height: diameter)
                .blur(radius: diameter * 0.10)
                .offset(y: diameter * 0.06)

            Circle()
                .fill(
                    LinearGradient(
                        colors: [
                            Color(red: 1.00, green: 0.38, blue: 0.42),
                            Color(red: 0.93, green: 0.16, blue: 0.27)
                        ],
                        startPoint: .top,
                        endPoint: .bottom
                    )
                )
                .overlay(glossHighlight)
                .overlay(
                    Circle().strokeBorder(Color.white.opacity(0.22),
                                          lineWidth: max(1, diameter * 0.03))
                )
                .frame(width: diameter, height: diameter)

            countLabel
        }
        .compositingGroup()
    }

    private var glossHighlight: some View {
        Circle()
            .fill(
                RadialGradient(
                    colors: [Color.white.opacity(0.55), Color.clear],
                    center: UnitPoint(x: 0.32, y: 0.26),
                    startRadius: 0,
                    endRadius: diameter * 0.55
                )
            )
            .padding(diameter * 0.06)
    }

    private var countLabel: some View {
        // The number drops in from above on each new value. The .id forces a
        // fresh view so the move/opacity transition fires; this is the hero
        // motion, so we do NOT also layer contentTransition(.numericText).
        Text("\(count)")
            .font(.system(size: diameter * 0.52, weight: .heavy, design: .rounded))
            .monospacedDigit()
            .foregroundStyle(.white)
            .shadow(color: Color.black.opacity(0.25), radius: 1, y: 1)
            .id(count)
            .transition(
                .asymmetric(
                    insertion: .move(edge: .top).combined(with: .opacity),
                    removal: .move(edge: .bottom).combined(with: .opacity)
                )
            )
            .frame(width: diameter, height: diameter)
            .clipShape(Circle())
    }
}

// MARK: - Jelly squash phases

private enum JellyCountBadgeView_JellyPhase: CaseIterable {
    case rest        // resting circle
    case squash      // number lands: wide + short
    case rebound     // overshoot tall + thin
    case settle      // springs back to a circle

    var scaleX: CGFloat {
        switch self {
        case .rest:    return 1.00
        case .squash:  return 1.26
        case .rebound: return 0.90
        case .settle:  return 1.00
        }
    }

    var scaleY: CGFloat {
        switch self {
        case .rest:    return 1.00
        case .squash:  return 0.76
        case .rebound: return 1.12
        case .settle:  return 1.00
        }
    }

    var animation: Animation {
        switch self {
        case .rest:    return .easeOut(duration: 0.10)
        case .squash:  return .spring(response: 0.18, dampingFraction: 0.55)
        case .rebound: return .spring(response: 0.26, dampingFraction: 0.50)
        case .settle:  return .spring(response: 0.55, dampingFraction: 0.42) // bouncy jelly settle
        }
    }
}
"""###,
        "mi-knurled-stepper": ###"""
import SwiftUI

/// A plus/minus stepper whose number rides a knurled metal thumbwheel.
/// Each step rotates the wheel exactly one notch with a detent bounce and a
/// brief motion-blur smear; the value stays crisp on a fixed center plate.
///
/// - `demo == true`  : a self-driving loop ramps the value up and down so the
///                     wheel keeps clicking through detents with no touch.
/// - `demo == false` : the real component — `+` / `−` buttons plus a vertical
///                     drag that scrubs the wheel and snaps to the nearest notch.
struct KnurledStepperView: View {
    var demo: Bool = false

    // MARK: Tuning

    /// Angle between two adjacent notches. This single value drives the spin,
    /// the drag snap, and the haptic trigger.
    private let detent: Double = .pi / 6          // 30° per notch
    private let minValue: Int = 0
    private let maxValue: Int = 99

    // MARK: Interactive state

    @State private var value: Int = 12
    /// Wheel phase in radians. `phase / detent` is the (fractional) notch index.
    @State private var phase: Double = 0
    /// Transient angular speed used to drive the motion-blur smear.
    @State private var smear: Double = 0
    @State private var dragStartPhase: Double = 0

    var body: some View {
        GeometryReader { proxy in
            let side = min(proxy.size.width, proxy.size.height)
            let unit = side / 120.0                // scale everything off the tile

            Group {
                if demo {
                    demoBody(unit: unit)
                } else {
                    interactiveBody(unit: unit)
                }
            }
            .frame(width: proxy.size.width, height: proxy.size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // MARK: - Demo (self-driving)

    private func demoBody(unit: CGFloat) -> some View {
        TimelineView(.animation) { context in
            let t = context.date.timeIntervalSinceReferenceDate
            let model = demoModel(at: t)
            stepperLayout(unit: unit,
                          value: model.value,
                          phase: model.phase,
                          smear: model.smear,
                          plusActive: model.plusActive,
                          minusActive: model.minusActive)
        }
    }

    /// Drives a triangle wave of values (ramp up then down) on a ~3.4s loop.
    private func demoModel(at time: Double) -> (value: Int, phase: Double, smear: Double, plusActive: Bool, minusActive: Bool) {
        let stepDuration: Double = 0.42
        let stepsUp = 4
        let total = stepsUp * 2
        let cycle = Double(total) * stepDuration
        let local = time.truncatingRemainder(dividingBy: cycle)
        let rawIndex = local / stepDuration
        let stepIndex = Int(rawIndex)
        let frac = rawIndex - Double(stepIndex)

        // Triangle: 0,1,2,3,4,3,2,1 ...
        let goingUp = stepIndex < stepsUp
        let baseFrom: Int
        let baseTo: Int
        if goingUp {
            baseFrom = stepIndex
            baseTo = stepIndex + 1
        } else {
            let down = stepIndex - stepsUp
            baseFrom = stepsUp - down
            baseTo = stepsUp - down - 1
        }

        // Eased settle within each step gives the detent bounce feel.
        let eased = detentEase(frac)
        let phaseFrom = Double(baseFrom) * detent
        let phaseTo = Double(baseTo) * detent
        let phase = phaseFrom + (phaseTo - phaseFrom) * eased

        // Number swaps at the midpoint of the rotation so it reads with the click.
        let value = 12 + (frac > 0.5 ? baseTo : baseFrom)

        // Smear peaks early in the step and decays to crisp.
        let smear = pow(max(0, 1 - frac * 2.2), 2) * 6

        let plusActive = goingUp && frac < 0.30
        let minusActive = !goingUp && frac < 0.30
        return (value, phase, smear, plusActive, minusActive)
    }

    /// Overshooting ease so each demo step lands with a small detent bounce.
    private func detentEase(_ x: Double) -> Double {
        let c: Double = 1.70158 * 1.2
        let p = x - 1
        return 1 + (c + 1) * p * p * p + c * p * p
    }

    // MARK: - Interactive

    private func interactiveBody(unit: CGFloat) -> some View {
        stepperLayout(unit: unit,
                      value: value,
                      phase: phase,
                      smear: smear,
                      plusActive: false,
                      minusActive: false)
        .contentShape(Rectangle())
        .gesture(wheelDrag(unit: unit))
        .sensoryFeedback(.selection, trigger: value)
    }

    private func wheelDrag(unit: CGFloat) -> some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { g in
                if g.translation == .zero {
                    dragStartPhase = phase
                }
                // Drag up to increase. ~22pt per notch feels machined.
                let perNotch = 22.0 * unit
                let delta = Double(-g.translation.height) / perNotch * detent
                let newPhase = dragStartPhase + delta
                smear = min(8, abs(delta) * 14)
                phase = newPhase
                value = clampValue(baseValueForPhase(newPhase))
            }
            .onEnded { g in
                let perNotch = 22.0 * unit
                let predicted = Double(-g.predictedEndTranslation.height) / perNotch * detent
                let target = dragStartPhase + predicted
                let snapped = (target / detent).rounded() * detent
                withAnimation(.spring(response: 0.45, dampingFraction: 0.62)) {
                    phase = snapped
                }
                value = clampValue(baseValueForPhase(snapped))
                withAnimation(.easeOut(duration: 0.35)) { smear = 0 }
            }
    }

    /// Maps an absolute phase to the displayed value, anchored at the start
    /// value of the drag so scrubbing reads as continuous counting.
    private func baseValueForPhase(_ p: Double) -> Int {
        let notch = Int((p / detent).rounded())
        return 12 + notch
    }

    private func step(_ direction: Int) {
        let next = clampValue(value + direction)
        guard next != value else {
            // At the limit: a small recoil instead of a real step.
            withAnimation(.spring(response: 0.25, dampingFraction: 0.5)) {
                phase += Double(direction) * detent * 0.18
            }
            withAnimation(.spring(response: 0.4, dampingFraction: 0.7).delay(0.05)) {
                phase -= Double(direction) * detent * 0.18
            }
            return
        }
        smear = 6
        withAnimation(.spring(response: 0.42, dampingFraction: 0.55)) {
            value = next
            phase += Double(direction) * detent
        }
        withAnimation(.easeOut(duration: 0.32)) { smear = 0 }
    }

    private func clampValue(_ v: Int) -> Int { min(maxValue, max(minValue, v)) }

    // MARK: - Shared layout

    @ViewBuilder
    private func stepperLayout(unit: CGFloat,
                               value: Int,
                               phase: Double,
                               smear: Double,
                               plusActive: Bool,
                               minusActive: Bool) -> some View {
        let wheelHeight = 78.0 * unit
        let wheelWidth = 56.0 * unit
        let buttonSize = 30.0 * unit

        HStack(spacing: 10.0 * unit) {
            stepButton(symbol: "minus",
                       unit: unit,
                       size: buttonSize,
                       active: minusActive,
                       direction: -1)

            wheel(unit: unit,
                  width: wheelWidth,
                  height: wheelHeight,
                  value: value,
                  phase: phase,
                  smear: smear)

            stepButton(symbol: "plus",
                       unit: unit,
                       size: buttonSize,
                       active: plusActive,
                       direction: 1)
        }
        .padding(8.0 * unit)
    }

    // MARK: Buttons

    @ViewBuilder
    private func stepButton(symbol: String,
                            unit: CGFloat,
                            size: CGFloat,
                            active: Bool,
                            direction: Int) -> some View {
        let pressed = active
        Button {
            step(direction)
        } label: {
            ZStack {
                Circle()
                    .fill(buttonGradient)
                    .overlay(
                        Circle().strokeBorder(
                            Color(red: 1, green: 1, blue: 1).opacity(0.12),
                            lineWidth: 1)
                    )
                Image(systemName: symbol)
                    .font(.system(size: size * 0.42, weight: .bold))
                    .foregroundStyle(Color(red: 0.86, green: 0.88, blue: 0.95))
            }
            .frame(width: size, height: size)
            .scaleEffect(pressed ? 0.86 : 1.0)
            .shadow(color: Color(red: 0, green: 0, blue: 0).opacity(0.45),
                    radius: pressed ? 1 : 3,
                    x: 0, y: pressed ? 1 : 2)
            .animation(.spring(response: 0.3, dampingFraction: 0.5), value: pressed)
        }
        .buttonStyle(.plain)
        .disabled(demo)
    }

    private var buttonGradient: LinearGradient {
        LinearGradient(
            colors: [
                Color(red: 0.27, green: 0.29, blue: 0.36),
                Color(red: 0.15, green: 0.16, blue: 0.21)
            ],
            startPoint: .top, endPoint: .bottom)
    }

    // MARK: Wheel

    @ViewBuilder
    private func wheel(unit: CGFloat,
                       width: CGFloat,
                       height: CGFloat,
                       value: Int,
                       phase: Double,
                       smear: Double) -> some View {
        let radius = Double(height) / 2.0
        ZStack {
            // Cylinder body
            RoundedRectangle(cornerRadius: 9.0 * unit, style: .continuous)
                .fill(cylinderGradient)
                .overlay(
                    RoundedRectangle(cornerRadius: 9.0 * unit, style: .continuous)
                        .strokeBorder(Color(red: 0, green: 0, blue: 0).opacity(0.5),
                                      lineWidth: 1)
                )

            // Knurled ridges scrolling vertically (faked cylinder).
            KnurledStepperView_KnurlRidges(phase: phase, detent: detent, radius: radius)
                .frame(width: width, height: height)
                .blur(radius: min(6, smear) * 0.5 + smear * 0.1)
                .clipShape(RoundedRectangle(cornerRadius: 9.0 * unit, style: .continuous))

            // Top / bottom shading to sell the curvature of the cylinder.
            rimShade
                .clipShape(RoundedRectangle(cornerRadius: 9.0 * unit, style: .continuous))
                .allowsHitTesting(false)

            // Fixed center plate carrying the crisp, swappable number.
            numberPlate(unit: unit, width: width, value: value, smear: smear)

            // Specular sheen sweeping the metal.
            LinearGradient(
                colors: [
                    Color(red: 1, green: 1, blue: 1).opacity(0.0),
                    Color(red: 1, green: 1, blue: 1).opacity(0.18),
                    Color(red: 1, green: 1, blue: 1).opacity(0.0)
                ],
                startPoint: .leading, endPoint: .trailing)
            .clipShape(RoundedRectangle(cornerRadius: 9.0 * unit, style: .continuous))
            .allowsHitTesting(false)
        }
        .frame(width: width, height: height)
    }

    private var cylinderGradient: LinearGradient {
        LinearGradient(
            colors: [
                Color(red: 0.10, green: 0.11, blue: 0.15),
                Color(red: 0.22, green: 0.24, blue: 0.30),
                Color(red: 0.10, green: 0.11, blue: 0.15)
            ],
            startPoint: .top, endPoint: .bottom)
    }

    private var rimShade: some View {
        LinearGradient(
            colors: [
                Color(red: 0, green: 0, blue: 0).opacity(0.85),
                Color(red: 0, green: 0, blue: 0).opacity(0.0),
                Color(red: 0, green: 0, blue: 0).opacity(0.0),
                Color(red: 0, green: 0, blue: 0).opacity(0.85)
            ],
            startPoint: .top, endPoint: .bottom)
    }

    @ViewBuilder
    private func numberPlate(unit: CGFloat,
                             width: CGFloat,
                             value: Int,
                             smear: Double) -> some View {
        let plateHeight = 30.0 * unit
        ZStack {
            RoundedRectangle(cornerRadius: 6.0 * unit, style: .continuous)
                .fill(
                    LinearGradient(
                        colors: [
                            Color(red: 0.32, green: 0.34, blue: 0.42).opacity(0.55),
                            Color(red: 0.10, green: 0.11, blue: 0.15).opacity(0.55)
                        ],
                        startPoint: .top, endPoint: .bottom)
                )
                .overlay(
                    RoundedRectangle(cornerRadius: 6.0 * unit, style: .continuous)
                        .stroke(Color(red: 1, green: 1, blue: 1).opacity(0.10),
                                lineWidth: 1)
                )
                .frame(width: width - 8.0 * unit, height: plateHeight)
                .shadow(color: Color(red: 0, green: 0, blue: 0).opacity(0.5),
                        radius: 2, x: 0, y: 1)

            Text("\(value)")
                .font(.system(size: 22.0 * unit, weight: .heavy, design: .rounded))
                .monospacedDigit()
                .contentTransition(.numericText(value: Double(value)))
                .foregroundStyle(Color(red: 0.95, green: 0.97, blue: 1.0))
                .shadow(color: Color(red: 0.4, green: 0.7, blue: 1.0).opacity(0.35),
                        radius: 3)
                .blur(radius: min(3.5, smear * 0.45))
        }
    }
}

// MARK: - Knurled ridges (analytic cylinder)

/// Draws horizontal knurl ridges positioned by `y = R·sin(θ)`, lit by the
/// front hemisphere `max(0, cos(θ))`, so they scroll and compress at the rim
/// like a real machined thumbwheel.
private struct KnurledStepperView_KnurlRidges: View {
    var phase: Double
    var detent: Double
    var radius: Double

    var body: some View {
        Canvas { context, size in
            let cy = size.height / 2
            let r = radius
            // Place one ridge per half-detent for a fine knurl.
            let step = detent / 2.0
            let count = Int((Double.pi / step)) + 1

            for i in -count...count {
                let theta = phase.truncatingRemainder(dividingBy: .pi * 2) + Double(i) * step
                let c = cos(theta)
                guard c > 0.02 else { continue }      // front face only
                let y = cy - CGFloat(r * sin(theta))
                guard y >= -4 && y <= size.height + 4 else { continue }

                // Brightness and thickness follow the curvature.
                let bright = pow(c, 0.8)
                let lineHeight = CGFloat(1.4 + 2.6 * c)
                let inset: CGFloat = 4

                let rect = CGRect(x: inset,
                                  y: y - lineHeight / 2,
                                  width: size.width - inset * 2,
                                  height: lineHeight)
                let highlight = 0.18 + 0.62 * bright
                context.fill(
                    Path(roundedRect: rect, cornerRadius: lineHeight / 2),
                    with: .color(Color(red: 0.78, green: 0.82, blue: 0.92)
                        .opacity(highlight)))

                // Thin dark groove just beneath each ridge for depth.
                let grooveRect = CGRect(x: inset,
                                        y: y + lineHeight / 2,
                                        width: size.width - inset * 2,
                                        height: 1)
                context.fill(
                    Path(grooveRect),
                    with: .color(Color(red: 0, green: 0, blue: 0)
                        .opacity(0.32 * bright)))
            }
        }
    }
}
"""###,
        "mi-magnetic-radio-snap": ###"""
import SwiftUI

// Snap-Together Choice Chips
// Selectable chips drift slightly apart at rest; the chosen chip snaps to a
// magnetic notch (its idle drift collapses to zero) with a click-in scale pop
// while siblings recoil away, like puzzle pieces settling into a slot.

struct MagneticRadioSnapView: View {
    var demo: Bool = false

    private let labels = ["Light", "Auto", "Dark", "System"]

    @State private var selected: Int = 1

    var body: some View {
        GeometryReader { geo in
            content(geo: geo)
                .frame(maxWidth: .infinity, maxHeight: .infinity)
        }
        .sensoryFeedback(.selection, trigger: selected)
    }

    @ViewBuilder
    private func content(geo: GeometryProxy) -> some View {
        let metrics = MagneticRadioSnapView_MRSMetrics(size: geo.size, count: labels.count)

        ZStack {
            backdrop(metrics: metrics)
            chipRow(metrics: metrics)
        }
        .frame(width: geo.size.width, height: geo.size.height)
        .modifier(MagneticRadioSnapView_MRSDriver(demo: demo, count: labels.count, selected: $selected))
    }

    // MARK: - Backdrop

    private func backdrop(metrics: MagneticRadioSnapView_MRSMetrics) -> some View {
        RoundedRectangle(cornerRadius: metrics.trackCorner, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.11, green: 0.10, blue: 0.16),
                        Color(red: 0.07, green: 0.06, blue: 0.11)
                    ],
                    startPoint: .top,
                    endPoint: .bottom
                )
            )
            .overlay(
                RoundedRectangle(cornerRadius: metrics.trackCorner, style: .continuous)
                    .stroke(Color.white.opacity(0.06), lineWidth: 1)
            )
            .frame(width: metrics.trackWidth, height: metrics.trackHeight)
            .shadow(color: .black.opacity(0.35), radius: metrics.trackHeight * 0.12, y: 4)
    }

    // MARK: - Chip row

    private func chipRow(metrics: MagneticRadioSnapView_MRSMetrics) -> some View {
        HStack(spacing: metrics.spacing) {
            ForEach(labels.indices, id: \.self) { index in
                chipView(index: index, metrics: metrics)
            }
        }
    }

    private func chipView(index: Int, metrics: MagneticRadioSnapView_MRSMetrics) -> some View {
        let isSelected = index == selected
        // Magnetic snap: the chosen chip's idle drift collapses to the notch (0,0).
        // Because `selected` changes inside withAnimation(.spring), this glides in.
        let drift = isSelected
            ? (dx: CGFloat(0), dy: CGFloat(0))
            : MagneticRadioSnapView_MRSDrift.offset(for: index, magnitude: metrics.driftMagnitude)
        // Siblings recoil away from the selected chip.
        let recoilSign: CGFloat = index < selected ? -1 : (index > selected ? 1 : 0)

        return MagneticRadioSnapView_MRSChip(
            label: labels[index],
            isSelected: isSelected,
            metrics: metrics
        )
        .offset(x: drift.dx, y: drift.dy)
        .keyframeAnimator(
            initialValue: MagneticRadioSnapView_MRSPop(),
            trigger: selected
        ) { view, value in
            view
                .scaleEffect(value.scale)
                .offset(x: value.recoil * recoilSign)
                .rotationEffect(.degrees(value.tilt))
        } keyframes: { _ in
            // All three tracks always emitted (no result-builder conditionals);
            // the per-chip condition lives in the keyframe values.
            KeyframeTrack(\.scale) {
                SpringKeyframe(isSelected ? 1.18 : 1.0, duration: 0.16, spring: .bouncy(extraBounce: 0.2))
                SpringKeyframe(1.0, duration: 0.42, spring: Spring(duration: 0.4, bounce: 0.5))
            }
            KeyframeTrack(\.tilt) {
                CubicKeyframe(isSelected ? -3 : 0, duration: 0.10)
                SpringKeyframe(0, duration: 0.42, spring: Spring(bounce: 0.45))
            }
            KeyframeTrack(\.recoil) {
                CubicKeyframe(isSelected ? 0 : metrics.recoilMagnitude, duration: 0.12)
                SpringKeyframe(0, duration: 0.5, spring: Spring(bounce: 0.4))
            }
        }
        .zIndex(isSelected ? 1 : 0)
        .contentShape(Rectangle())
        .onTapGesture {
            guard !demo else { return }
            withAnimation(.spring(duration: 0.4, bounce: 0.5)) {
                selected = index
            }
        }
    }
}

// MARK: - Chip

private struct MagneticRadioSnapView_MRSChip: View {
    let label: String
    let isSelected: Bool
    let metrics: MagneticRadioSnapView_MRSMetrics

    var body: some View {
        Text(label)
            .font(.system(size: metrics.fontSize, weight: isSelected ? .bold : .medium, design: .rounded))
            .foregroundStyle(isSelected ? Color(red: 0.10, green: 0.08, blue: 0.14) : Color.white.opacity(0.72))
            .lineLimit(1)
            .minimumScaleFactor(0.6)
            .padding(.horizontal, metrics.chipPaddingH)
            .padding(.vertical, metrics.chipPaddingV)
            .frame(minWidth: metrics.chipMinWidth)
            .background(chipBackground)
            .overlay(notch)
            .animation(.easeInOut(duration: 0.3), value: isSelected)
    }

    private var chipBackground: some View {
        Capsule(style: .continuous)
            .fill(
                isSelected
                    ? AnyShapeStyle(
                        LinearGradient(
                            colors: [
                                Color(red: 0.62, green: 0.78, blue: 1.0),
                                Color(red: 0.40, green: 0.56, blue: 0.98)
                            ],
                            startPoint: .top,
                            endPoint: .bottom
                        )
                    )
                    : AnyShapeStyle(Color.white.opacity(0.08))
            )
            .overlay(
                Capsule(style: .continuous)
                    .stroke(
                        isSelected ? Color.white.opacity(0.55) : Color.white.opacity(0.12),
                        lineWidth: isSelected ? 1.2 : 1
                    )
            )
            .shadow(
                color: isSelected ? Color(red: 0.40, green: 0.56, blue: 0.98).opacity(0.55) : .clear,
                radius: isSelected ? metrics.chipMinWidth * 0.18 : 0,
                y: isSelected ? 2 : 0
            )
    }

    // A small magnetic "notch" indicator under the selected chip.
    @ViewBuilder
    private var notch: some View {
        if isSelected {
            Circle()
                .fill(Color.white.opacity(0.9))
                .frame(width: metrics.notchSize, height: metrics.notchSize)
                .frame(maxHeight: .infinity, alignment: .bottom)
                .offset(y: metrics.notchSize * 0.9)
                .transition(.scale.combined(with: .opacity))
        }
    }
}

// MARK: - Animatable pop value

private struct MagneticRadioSnapView_MRSPop {
    var scale: CGFloat = 1.0
    var recoil: CGFloat = 0.0
    var tilt: Double = 0.0
}

// MARK: - Deterministic idle drift

private enum MagneticRadioSnapView_MRSDrift {
    static func offset(for index: Int, magnitude: CGFloat) -> (dx: CGFloat, dy: CGFloat) {
        let i = Double(index)
        // Seeded, frame-stable pseudo-random drift — never re-randomized in body.
        let dx = CGFloat(sin(i * 2.3 + 0.7)) * magnitude
        let dy = CGFloat(cos(i * 1.7 + 1.3)) * magnitude * 0.6
        return (dx, dy)
    }
}

// MARK: - Layout metrics derived from geometry

private struct MagneticRadioSnapView_MRSMetrics {
    let trackWidth: CGFloat
    let trackHeight: CGFloat
    let trackCorner: CGFloat
    let spacing: CGFloat
    let fontSize: CGFloat
    let chipPaddingH: CGFloat
    let chipPaddingV: CGFloat
    let chipMinWidth: CGFloat
    let driftMagnitude: CGFloat
    let recoilMagnitude: CGFloat
    let notchSize: CGFloat

    init(size: CGSize, count: Int) {
        let w = max(size.width, 1)
        let h = max(size.height, 1)
        let minSide = min(w, h)

        let base: CGFloat = max(min(w, h * 2.2), 1)
        self.fontSize = max(min(base * 0.052, 18), 8)
        self.spacing = max(minSide * 0.04, 4)
        self.chipPaddingH = fontSize * 0.7
        self.chipPaddingV = fontSize * 0.5
        self.chipMinWidth = fontSize * 2.6
        self.trackWidth = min(w * 0.94, w - 8)
        self.trackHeight = min(h * 0.5, fontSize * 4.2)
        self.trackCorner = trackHeight * 0.3
        self.driftMagnitude = max(minSide * 0.012, 1.2)
        self.recoilMagnitude = max(minSide * 0.05, 4)
        self.notchSize = max(fontSize * 0.22, 2.5)
    }
}

// MARK: - Driver: demo auto-cycle vs. interactive

private struct MagneticRadioSnapView_MRSDriver: ViewModifier {
    let demo: Bool
    let count: Int
    @Binding var selected: Int

    func body(content: Content) -> some View {
        if demo {
            content
                .onReceive(
                    Timer.publish(every: 0.85, on: .main, in: .common).autoconnect()
                ) { _ in
                    withAnimation(.spring(duration: 0.42, bounce: 0.5)) {
                        selected = (selected + 1) % max(count, 1)
                    }
                }
        } else {
            content
        }
    }
}
"""###,
        "mi-magnetic-snap-toggle": ###"""
import SwiftUI

/// Magnetic Snap Toggle — a draggable toggle whose knob accelerates with
/// spring overshoot toward the nearest end on release, the track color
/// sweeping behind it. `demo == true` auto-cycles the magnetic yank, no touch.
struct MagneticSnapToggleView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { geo in
            let metrics = MagneticSnapToggleView_ToggleMetrics(size: geo.size)
            Group {
                if demo {
                    MagneticSnapToggleView_DemoToggle(metrics: metrics)
                } else {
                    MagneticSnapToggleView_InteractiveToggle(metrics: metrics)
                }
            }
            .frame(width: geo.size.width, height: geo.size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }
}

// MARK: - Layout metrics (size-relative, recomputed from live geometry)

private struct MagneticSnapToggleView_ToggleMetrics {
    let trackWidth: CGFloat
    let trackHeight: CGFloat
    let knobDiameter: CGFloat
    let padding: CGFloat
    let overshootReserve: CGFloat
    let originX: CGFloat
    let centerY: CGFloat

    init(size: CGSize) {
        let maxTrackW = max(size.width - 24, 40)
        let idealW = min(maxTrackW, size.width * 0.74)
        let idealH = min(size.height * 0.42, idealW * 0.5)
        let h = max(min(idealH, idealW * 0.55), 22)
        self.trackHeight = h
        self.trackWidth = max(idealW, h * 1.9)
        self.padding = h * 0.12
        self.knobDiameter = h - padding * 2
        // Headroom so a 0.6-damping spring overshoots without poking past the capsule.
        self.overshootReserve = max(h * 0.16, 4)
        self.originX = (size.width - trackWidth) / 2
        self.centerY = size.height / 2
    }

    /// Horizontal distance the knob center travels between resting ends.
    var travel: CGFloat {
        max(trackWidth - knobDiameter - padding * 2 - overshootReserve * 2, 1)
    }

    /// Knob center X (local to the track) for normalized progress 0...1.
    func knobCenterX(progress: Double) -> CGFloat {
        let p = CGFloat(min(max(progress, 0), 1))
        return padding + overshootReserve + knobDiameter / 2 + travel * p
    }
}

// MARK: - Shared visual (track + fill + knob), parameterized by progress

private struct MagneticSnapToggleView_ToggleBody: View {
    let metrics: MagneticSnapToggleView_ToggleMetrics
    let progress: Double
    let isDragging: Bool

    private var clamped: Double { min(max(progress, 0), 1) }

    private var fillColor: Color {
        let t = clamped
        return Color(red: lerp(0.20, 0.30, t),
                     green: lerp(0.22, 0.80, t),
                     blue: lerp(0.28, 0.46, t))
    }

    var body: some View {
        ZStack(alignment: .leading) {
            trackBase
            trackFill
            knob
        }
        .frame(width: metrics.trackWidth, height: metrics.trackHeight)
        .position(x: metrics.originX + metrics.trackWidth / 2, y: metrics.centerY)
    }

    private var trackBase: some View {
        Capsule()
            .fill(Color(red: 0.13, green: 0.13, blue: 0.17))
            .overlay(
                Capsule().stroke(Color(red: 0.30, green: 0.30, blue: 0.36), lineWidth: 1)
            )
    }

    private var trackFill: some View {
        let knobX = metrics.knobCenterX(progress: clamped)
        let fillW = max(knobX + metrics.knobDiameter / 2 + metrics.padding,
                        metrics.trackHeight)
        return Capsule()
            .fill(
                LinearGradient(colors: [fillColor.opacity(0.95), fillColor.opacity(0.62)],
                               startPoint: .leading, endPoint: .trailing)
            )
            .frame(width: fillW)
            .opacity(0.18 + clamped * 0.82)
            .frame(width: metrics.trackWidth, alignment: .leading)
            .clipShape(Capsule())
            .allowsHitTesting(false)
    }

    private var knob: some View {
        let d = metrics.knobDiameter
        let cx = metrics.knobCenterX(progress: clamped)
        return Circle()
            .fill(
                LinearGradient(colors: [Color(red: 1, green: 1, blue: 1),
                                        Color(red: 0.88, green: 0.90, blue: 0.94)],
                               startPoint: .top, endPoint: .bottom)
            )
            .frame(width: d, height: d)
            .overlay(
                Circle().stroke(Color(red: 0, green: 0, blue: 0).opacity(0.06), lineWidth: 1)
            )
            .shadow(color: Color(red: 0, green: 0, blue: 0).opacity(0.30),
                    radius: isDragging ? 5 : 3, x: 0, y: isDragging ? 3 : 2)
            .scaleEffect(isDragging ? 1.07 : 1.0)
            .position(x: cx, y: metrics.trackHeight / 2)
    }

    private func lerp(_ a: Double, _ b: Double, _ t: Double) -> Double { a + (b - a) * t }
}

// MARK: - Interactive (demo == false)

private struct MagneticSnapToggleView_InteractiveToggle: View {
    let metrics: MagneticSnapToggleView_ToggleMetrics

    @State private var progress: Double = 0
    @State private var dragStartProgress: Double = 0
    @State private var isDragging = false
    @State private var snapCount: Int = 0       // changes only on landing -> .impact
    @State private var midCrossings: Int = 0    // changes on live midpoint cross -> .selection
    @State private var wasPastMid: Bool = false

    var body: some View {
        MagneticSnapToggleView_ToggleBody(metrics: metrics, progress: progress, isDragging: isDragging)
            .contentShape(Rectangle())
            .gesture(dragGesture)
            .sensoryFeedback(.selection, trigger: midCrossings)
            .sensoryFeedback(.impact(flexibility: .solid, intensity: 0.85), trigger: snapCount)
    }

    private var dragGesture: some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                if !isDragging {
                    isDragging = true
                    dragStartProgress = progress
                    wasPastMid = progress >= 0.5
                }
                let delta = Double(value.translation.width / max(metrics.travel, 1))
                progress = min(max(dragStartProgress + delta, 0), 1)
                let pastMid = progress >= 0.5
                if pastMid != wasPastMid {
                    wasPastMid = pastMid
                    midCrossings += 1
                }
            }
            .onEnded { value in
                isDragging = false
                let moved = abs(value.translation.width)
                let target: Double
                if moved < 6 {
                    // No meaningful drag -> treat as a tap, flip to the opposite end.
                    target = dragStartProgress < 0.5 ? 1 : 0
                } else {
                    // Snap to the nearest end by current position (midpoint rule).
                    target = progress >= 0.5 ? 1 : 0
                }
                withAnimation(.spring(response: 0.35, dampingFraction: 0.6)) {
                    progress = target
                }
                snapCount += 1
            }
    }
}

// MARK: - Demo (demo == true) — self-driving magnetic yank loop

private struct MagneticSnapToggleView_DemoToggle: View {
    let metrics: MagneticSnapToggleView_ToggleMetrics

    var body: some View {
        PhaseAnimator(MagneticSnapToggleView_DemoPhase.allCases) { phase in
            MagneticSnapToggleView_ToggleBody(metrics: metrics, progress: phase.progress, isDragging: phase.dragging)
        } animation: { phase in
            phase.animation
        }
    }
}

private enum MagneticSnapToggleView_DemoPhase: CaseIterable {
    case settleOff, yankOn, holdOn, yankOff, holdOff

    var progress: Double {
        switch self {
        case .settleOff: return 0
        case .yankOn:    return 1
        case .holdOn:    return 1
        case .yankOff:   return 0
        case .holdOff:   return 0
        }
    }

    var dragging: Bool {
        // Lift the knob during the snap legs for a tactile, alive feel.
        switch self {
        case .yankOn, .yankOff:             return true
        case .settleOff, .holdOn, .holdOff: return false
        }
    }

    var animation: Animation {
        switch self {
        case .settleOff:
            return .easeInOut(duration: 0.12)
        case .yankOn:
            return .spring(response: 0.35, dampingFraction: 0.6).delay(0.15)
        case .holdOn:
            return .easeInOut(duration: 0.1).delay(0.95)
        case .yankOff:
            return .spring(response: 0.35, dampingFraction: 0.6).delay(0.15)
        case .holdOff:
            return .easeInOut(duration: 0.1).delay(0.95)
        }
    }
}
"""###,
        "mi-mood-morph-rating": ###"""
import SwiftUI

// MARK: - Mood-Morph Rating
// A single face whose mouth path continuously morphs from frown to grin as the
// rating value changes. MoodMorphRatingView_Eyes widen near the top score. The mouth is an
// Animatable closed lens (two quadratic curves, constant topology) so the morph
// stays perfectly smooth. demo == true self-drives a sine sweep; demo == false
// is a live DragGesture that snaps to the nearest notch on release.

struct MoodMorphRatingView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { proxy in
            content(in: proxy.size)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    @ViewBuilder
    private func content(in size: CGSize) -> some View {
        if demo {
            MoodMorphRatingView_DemoDriver(size: size)
        } else {
            MoodMorphRatingView_InteractiveDriver(size: size)
        }
    }
}

// MARK: - Demo driver (self-running, never blank)

private struct MoodMorphRatingView_DemoDriver: View {
    let size: CGSize
    private let period: Double = 3.2

    var body: some View {
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            let phase = t.truncatingRemainder(dividingBy: period) / period
            // 0 -> 1 -> 0 smooth sweep, starts at frown.
            let morph = (1.0 - cos(2.0 * .pi * phase)) / 2.0
            MoodMorphRatingView_MoodFace(morph: CGFloat(morph), size: size)
        }
    }
}

// MARK: - Interactive driver (real DragGesture)

private struct MoodMorphRatingView_InteractiveDriver: View {
    let size: CGSize
    @State private var morph: CGFloat = 0.0
    @State private var lastNotch: Int = 0

    private let notches: Int = 5 // 0...4 -> five mood steps

    var body: some View {
        let layout = MoodMorphRatingView_FaceLayout(size: size)
        ZStack {
            MoodMorphRatingView_MoodFace(morph: morph, size: size)
        }
        .contentShape(Rectangle())
        .gesture(dragGesture(track: layout.trackRect))
        .sensoryFeedback(.selection, trigger: lastNotch)
        .onAppear {
            // Start at a legible neutral-ish smile so it is never expressionless.
            morph = 0.5
            lastNotch = notchIndex(for: 0.5)
        }
    }

    private func dragGesture(track: CGRect) -> some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                let raw = (value.location.x - track.minX) / max(track.width, 1)
                let clamped = min(max(raw, 0.0), 1.0)
                morph = clamped
                let idx = notchIndex(for: clamped)
                if idx != lastNotch { lastNotch = idx }
            }
            .onEnded { _ in
                let idx = notchIndex(for: morph)
                let snapped = CGFloat(idx) / CGFloat(notches - 1)
                lastNotch = idx
                withAnimation(.spring(response: 0.45, dampingFraction: 0.62)) {
                    morph = snapped
                }
            }
    }

    private func notchIndex(for value: CGFloat) -> Int {
        let scaled = value * CGFloat(notches - 1)
        return Int((scaled).rounded())
    }
}

// MARK: - Layout

private struct MoodMorphRatingView_FaceLayout {
    let size: CGSize

    var side: CGFloat { min(size.width, size.height) }

    /// The face sits in the upper portion; a thin track lives below it.
    var facePadding: CGFloat { side * 0.12 }

    var faceRect: CGRect {
        let s = side * 0.74
        let x = (size.width - s) / 2.0
        let y = (size.height - s) / 2.0 - side * 0.06
        return CGRect(x: x, y: y, width: s, height: s)
    }

    var trackRect: CGRect {
        let f = faceRect
        let w = f.width * 1.04
        let x = (size.width - w) / 2.0
        let h = max(side * 0.05, 6)
        let y = f.maxY + side * 0.08
        return CGRect(x: x, y: y, width: w, height: h)
    }
}

// MARK: - The face (pure function of `morph`)

private struct MoodMorphRatingView_MoodFace: View {
    let morph: CGFloat   // 0 = frown, 1 = grin
    let size: CGSize

    var body: some View {
        let layout = MoodMorphRatingView_FaceLayout(size: size)
        ZStack {
            MoodMorphRatingView_FaceBubble(morph: morph, rect: layout.faceRect)
            MoodMorphRatingView_Eyes(morph: morph, faceRect: layout.faceRect)
            MoodMorphRatingView_MouthLayer(morph: morph, faceRect: layout.faceRect)
            MoodMorphRatingView_NotchTrack(morph: morph, rect: layout.trackRect)
        }
    }
}

// MARK: - Face bubble background

private struct MoodMorphRatingView_FaceBubble: View {
    let morph: CGFloat
    let rect: CGRect

    var body: some View {
        let fill = faceColor(for: morph)
        Circle()
            .fill(
                RadialGradient(
                    colors: [fill.0, fill.1],
                    center: .init(x: 0.35, y: 0.3),
                    startRadius: 1,
                    endRadius: rect.width * 0.85
                )
            )
            .overlay(
                Circle().stroke(
                    Color(red: 0.0, green: 0.0, blue: 0.0).opacity(0.10),
                    lineWidth: max(rect.width * 0.012, 0.5)
                )
            )
            .frame(width: rect.width, height: rect.height)
            .position(x: rect.midX, y: rect.midY)
            .shadow(color: fill.1.opacity(0.45), radius: rect.width * 0.06, y: rect.width * 0.03)
    }

    /// Warm/golden at high morph, cool/violet at low morph.
    private func faceColor(for m: CGFloat) -> (Color, Color) {
        let t = min(max(m, 0.0), 1.0)
        // sad: muted periwinkle  -> happy: warm gold
        let topR = lerp(0.62, 1.00, t)
        let topG = lerp(0.66, 0.86, t)
        let topB = lerp(0.92, 0.36, t)
        let botR = lerp(0.45, 0.98, t)
        let botG = lerp(0.49, 0.69, t)
        let botB = lerp(0.82, 0.20, t)
        return (
            Color(red: topR, green: topG, blue: topB),
            Color(red: botR, green: botG, blue: botB)
        )
    }
}

// MARK: - MoodMorphRatingView_Eyes

private struct MoodMorphRatingView_Eyes: View {
    let morph: CGFloat
    let faceRect: CGRect

    var body: some View {
        let eyeY = faceRect.minY + faceRect.height * 0.40
        let dx = faceRect.width * 0.20
        let baseSize = faceRect.width * 0.115
        let widen = topRamp(morph)            // 0 until ~0.7, ramps to 1 by 1.0
        let scale = 1.0 + widen * 0.55
        let eyeColor = Color(red: 0.16, green: 0.13, blue: 0.20)

        ZStack {
            eye(color: eyeColor, size: baseSize)
                .scaleEffect(scale)
                .position(x: faceRect.midX - dx, y: eyeY)
            eye(color: eyeColor, size: baseSize)
                .scaleEffect(scale)
                .position(x: faceRect.midX + dx, y: eyeY)
        }
    }

    @ViewBuilder
    private func eye(color: Color, size: CGFloat) -> some View {
        ZStack {
            Circle()
                .fill(color)
                .frame(width: size, height: size)
            // Catch-light: brighter as eyes widen for a livelier top score.
            Circle()
                .fill(Color(red: 1.0, green: 1.0, blue: 1.0).opacity(0.85))
                .frame(width: size * 0.32, height: size * 0.32)
                .offset(x: -size * 0.18, y: -size * 0.20)
        }
    }

    /// Returns 0 below 0.7, eased ramp to 1 at 1.0.
    private func topRamp(_ m: CGFloat) -> CGFloat {
        let start: CGFloat = 0.7
        guard m > start else { return 0 }
        let t = (m - start) / (1.0 - start)
        // smoothstep
        return t * t * (3 - 2 * t)
    }
}

// MARK: - Mouth

private struct MoodMorphRatingView_MouthLayer: View {
    let morph: CGFloat
    let faceRect: CGRect

    var body: some View {
        let mouthColor = Color(red: 0.16, green: 0.10, blue: 0.16)
        MoodMorphRatingView_MouthShape(morph: morph)
            .fill(mouthColor)
            .overlay(
                MoodMorphRatingView_MouthShape(morph: morph)
                    .stroke(mouthColor, lineWidth: max(faceRect.width * 0.02, 1))
            )
            .frame(width: faceRect.width, height: faceRect.height)
            .position(x: faceRect.midX, y: faceRect.midY)
    }
}

/// A closed-lens mouth made of exactly two quadratic curves + close.
/// Topology is identical at every `morph`, so the morph animates smoothly.
private struct MoodMorphRatingView_MouthShape: Shape {
    var morph: CGFloat // 0 = frown, 1 = grin

    var animatableData: CGFloat {
        get { morph }
        set { morph = newValue }
    }

    func path(in rect: CGRect) -> Path {
        let m = min(max(morph, 0.0), 1.0)

        // Mouth band sits in the lower third of the face rect.
        let cx = rect.midX
        let baseY = rect.minY + rect.height * 0.66
        let halfWidth = rect.width * 0.24

        let left = CGPoint(x: cx - halfWidth, y: cornerY(baseY: baseY, rect: rect, m: m))
        let right = CGPoint(x: cx + halfWidth, y: cornerY(baseY: baseY, rect: rect, m: m))

        // Control point Y for the upper edge and the lower edge.
        // Frown (m=0): both bow UP (smaller y). Grin (m=1): both bow DOWN (larger y).
        // The lens always keeps a non-zero thickness so it reads as a mouth.
        let span = rect.height
        // Center offset of the whole mouth: frown -> up curve, grin -> down curve.
        let curveAmt = lerp(-span * 0.11, span * 0.20, m)   // negative = up (frown)
        let thickness = lerp(span * 0.045, span * 0.085, m) // a touch fuller when grinning

        let upperCtrl = CGPoint(x: cx, y: baseY + curveAmt - thickness)
        let lowerCtrl = CGPoint(x: cx, y: baseY + curveAmt + thickness)

        var path = Path()
        path.move(to: left)
        path.addQuadCurve(to: right, control: upperCtrl)
        path.addQuadCurve(to: left, control: lowerCtrl)
        path.closeSubpath()
        return path
    }

    /// Corners lift slightly upward toward a grin for a richer smile.
    private func cornerY(baseY: CGFloat, rect: CGRect, m: CGFloat) -> CGFloat {
        // grin pulls corners up; frown lets them sit / droop a bit.
        let lift = lerp(rect.height * 0.02, -rect.height * 0.05, m)
        return baseY + lift
    }
}

// MARK: - Notch track (secondary affordance)

private struct MoodMorphRatingView_NotchTrack: View {
    let morph: CGFloat
    let rect: CGRect

    private let notches: Int = 5

    var body: some View {
        ZStack(alignment: .leading) {
            Capsule()
                .fill(Color(red: 0.0, green: 0.0, blue: 0.0).opacity(0.16))
                .frame(width: rect.width, height: rect.height)

            Capsule()
                .fill(
                    LinearGradient(
                        colors: [
                            Color(red: 1.00, green: 0.78, blue: 0.30),
                            Color(red: 0.98, green: 0.55, blue: 0.22)
                        ],
                        startPoint: .leading,
                        endPoint: .trailing
                    )
                )
                .frame(width: max(rect.width * morph, rect.height), height: rect.height)

            HStack(spacing: 0) {
                ForEach(0..<notches, id: \.self) { i in
                    Circle()
                        .fill(Color(red: 1.0, green: 1.0, blue: 1.0).opacity(0.55))
                        .frame(width: rect.height * 0.34, height: rect.height * 0.34)
                        .frame(maxWidth: .infinity)
                        .opacity(i == 0 || i == notches - 1 ? 0.0 : 1.0)
                }
            }
            .frame(width: rect.width, height: rect.height)
        }
        .frame(width: rect.width, height: rect.height)
        .position(x: rect.midX, y: rect.midY)
    }
}

// MARK: - Helpers

private func lerp(_ a: CGFloat, _ b: CGFloat, _ t: CGFloat) -> CGFloat {
    a + (b - a) * t
}
"""###,
        "mi-mute-morph": ###"""
import SwiftUI

// MARK: - Mute Wave Morph
// Tapping the speaker collapses three animated sound waves inward and draws a
// slash across it; unmuting springs the waves back out. A single fluid morph
// driven by one `muteProgress` value (0 = audible, 1 = muted).

struct MuteMorphView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { geo in
            let side = min(geo.size.width, geo.size.height)
            Group {
                if demo {
                    MuteMorphView_DemoDriver(side: side)
                } else {
                    MuteMorphView_InteractiveDriver(side: side)
                }
            }
            .frame(width: geo.size.width, height: geo.size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }
}

// MARK: - Drivers

/// Self-driving loop for tile previews. Never blank: the speaker body is always
/// drawn; only the waves retract and the slash strokes on across the ~3.2s loop.
private struct MuteMorphView_DemoDriver: View {
    let side: CGFloat
    private let period: Double = 3.2

    var body: some View {
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            let progress = Self.loopProgress(time: t, period: period)
            MuteMorphView_MuteGlyph(progress: progress, side: side)
        }
    }

    /// Ping-pong 0->1->0 with a smoothstep ease and a short hold at each end so
    /// both the audible and muted states are legible for a beat.
    static func loopProgress(time: Double, period: Double) -> CGFloat {
        let phase = (time.truncatingRemainder(dividingBy: period)) / period
        // First half ramps to muted, second half ramps back.
        let triangle: Double = phase < 0.5 ? phase * 2.0 : (1.0 - phase) * 2.0
        // Hold at the extremes by stretching the middle of the ramp.
        let held = smoothHold(triangle)
        return CGFloat(smoothstep(held))
    }

    static func smoothHold(_ x: Double) -> Double {
        // Push values toward 0 and 1 to create a dwell at each end.
        let c = min(max(x, 0.0), 1.0)
        return c * c * (3.0 - 2.0 * c)
    }

    static func smoothstep(_ x: Double) -> Double {
        let c = min(max(x, 0.0), 1.0)
        return c * c * (3.0 - 2.0 * c)
    }
}

/// Real interactive component: a tap toggles `isMuted` with a spring.
private struct MuteMorphView_InteractiveDriver: View {
    let side: CGFloat
    @State private var muteProgress: CGFloat = 0

    var body: some View {
        MuteMorphView_MuteGlyph(progress: muteProgress, side: side)
            .contentShape(Rectangle())
            .onTapGesture {
                withAnimation(.spring(response: 0.42, dampingFraction: 0.62)) {
                    muteProgress = muteProgress < 0.5 ? 1 : 0
                }
            }
            .sensoryFeedback(.selection, trigger: muteProgress >= 0.5)
    }
}

// MARK: - Glyph composition

/// The full speaker glyph. `progress` 0 = waves out / no slash,
/// 1 = waves retracted / slash fully drawn.
private struct MuteMorphView_MuteGlyph: View {
    let progress: CGFloat
    let side: CGFloat

    private var unit: CGFloat { side }

    private var mutedTint: Color {
        Color(red: 1.0, green: 0.40, blue: 0.42)
    }
    private var bodyTint: Color {
        // Interpolate audible (cyan-blue) -> muted (red) directly from the
        // known component endpoints. Self-contained, no UIKit color bridging.
        Color(
            red: lerpD(0.45, 1.0, progress),
            green: lerpD(0.78, 0.40, progress),
            blue: lerpD(1.0, 0.42, progress)
        )
    }

    var body: some View {
        ZStack {
            background
            content
        }
        .frame(width: unit, height: unit)
    }

    private var background: some View {
        RoundedRectangle(cornerRadius: unit * 0.22, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.10, green: 0.09, blue: 0.13),
                        Color(red: 0.05, green: 0.05, blue: 0.08)
                    ],
                    startPoint: .topLeading,
                    endPoint: .bottomTrailing
                )
            )
            .overlay(
                RoundedRectangle(cornerRadius: unit * 0.22, style: .continuous)
                    .strokeBorder(bodyTint.opacity(0.18), lineWidth: max(0.6, unit * 0.006))
            )
    }

    private var content: some View {
        ZStack {
            glow
            waves
            speaker
            slash
        }
        .frame(width: unit * 0.62, height: unit * 0.62)
    }

    // Soft halo behind the glyph; never fully off so the tile stays alive.
    private var glow: some View {
        Circle()
            .fill(bodyTint.opacity(0.16 + 0.10 * (1 - progress)))
            .blur(radius: unit * 0.06)
            .scaleEffect(0.9 + 0.10 * (1 - progress))
    }

    private var speaker: some View {
        MuteMorphView_SpeakerBody()
            .fill(bodyTint)
            .overlay(
                MuteMorphView_SpeakerBody()
                    .stroke(Color.white.opacity(0.10), lineWidth: max(0.5, unit * 0.004))
            )
            .shadow(color: bodyTint.opacity(0.5 * progress), radius: unit * 0.03)
    }

    // Three concentric arcs that retract outer-first as progress rises.
    private var waves: some View {
        ZStack {
            ForEach(0..<3, id: \.self) { index in
                waveArc(index: index)
            }
        }
    }

    private func waveArc(index: Int) -> some View {
        // Outer arcs retract first: give later indices an earlier collapse.
        let stagger = CGFloat(index) * 0.22
        let local = clamp01((progress - stagger) / (1.0 - stagger))
        let extend = 1.0 - local                 // 1 = fully out, 0 = retracted
        let lineWidth = max(1.0, unit * 0.034)
        return MuteMorphView_WaveArc(index: index, extend: extend)
            .trim(from: 0, to: extend)
            .stroke(
                bodyTint.opacity(0.35 + 0.55 * extend),
                style: StrokeStyle(lineWidth: lineWidth, lineCap: .round)
            )
            .scaleEffect(0.82 + 0.18 * extend)   // pull inward toward the cone
    }

    private var slash: some View {
        MuteMorphView_SlashLine()
            .trim(from: 0, to: progress)
            .stroke(
                mutedTint,
                style: StrokeStyle(lineWidth: max(1.2, unit * 0.040), lineCap: .round)
            )
            .shadow(color: mutedTint.opacity(0.6 * progress), radius: unit * 0.02)
    }
}

// MARK: - Shapes

/// A flat speaker icon: a rectangular driver plus a triangular cone, sitting in
/// the left third of the rect so the waves have room on the right.
private struct MuteMorphView_SpeakerBody: Shape {
    func path(in rect: CGRect) -> Path {
        var path = Path()
        let w = rect.width
        let h = rect.height
        let midY = rect.midY

        // Square driver box.
        let boxLeft = rect.minX + w * 0.06
        let boxRight = rect.minX + w * 0.30
        let boxTop = midY - h * 0.14
        let boxBottom = midY + h * 0.14
        path.addRoundedRect(
            in: CGRect(x: boxLeft, y: boxTop, width: boxRight - boxLeft, height: boxBottom - boxTop),
            cornerSize: CGSize(width: w * 0.02, height: w * 0.02)
        )

        // Triangular cone flaring out to the right.
        let coneTop = midY - h * 0.30
        let coneBottom = midY + h * 0.30
        let coneRight = rect.minX + w * 0.50
        path.move(to: CGPoint(x: boxRight - w * 0.01, y: boxTop))
        path.addLine(to: CGPoint(x: coneRight, y: coneTop))
        path.addLine(to: CGPoint(x: coneRight, y: coneBottom))
        path.addLine(to: CGPoint(x: boxRight - w * 0.01, y: boxBottom))
        path.closeSubpath()

        return path
    }
}

/// Concentric right-opening arcs centered on the speaker cone mouth.
private struct MuteMorphView_WaveArc: Shape {
    let index: Int
    var extend: CGFloat  // animatable retract amount, 1 = out, 0 = in

    var animatableData: CGFloat {
        get { extend }
        set { extend = newValue }
    }

    func path(in rect: CGRect) -> Path {
        var path = Path()
        let w = rect.width
        let h = rect.height
        // Arc center sits at the cone mouth on the right of the speaker.
        let center = CGPoint(x: rect.minX + w * 0.50, y: rect.midY)
        let baseRadius = w * 0.16
        let step = w * 0.13
        let radius = baseRadius + CGFloat(index) * step
        // Spread of each arc narrows slightly as it retracts.
        let spread: CGFloat = 38 + 6 * extend
        path.addArc(
            center: center,
            radius: max(radius, 0.5),
            startAngle: .degrees(Double(-spread)),
            endAngle: .degrees(Double(spread)),
            clockwise: false
        )
        _ = h
        return path
    }
}

/// Diagonal mute slash from upper-left to lower-right across the glyph.
private struct MuteMorphView_SlashLine: Shape {
    func path(in rect: CGRect) -> Path {
        var path = Path()
        let inset: CGFloat = rect.width * 0.06
        path.move(to: CGPoint(x: rect.minX + inset, y: rect.minY + inset))
        path.addLine(to: CGPoint(x: rect.maxX - inset, y: rect.maxY - inset))
        return path
    }
}

// MARK: - Math helpers

private func clamp01(_ x: CGFloat) -> CGFloat {
    min(max(x, 0), 1)
}

/// Linear interpolation between two Double endpoints by a clamped CGFloat t.
private func lerpD(_ a: Double, _ b: Double, _ t: CGFloat) -> Double {
    a + (b - a) * Double(clamp01(t))
}
"""###,
        "mi-orbit-badge": ###"""
import SwiftUI

// MARK: - OrbitBadgeView
//
// Micro-interaction: when a count crosses a milestone threshold, the badge
// spawns a tiny satellite dot that orbits it once trailing a comet streak,
// then merges back in via scale + opacity.
//
// demo == true  -> self-driving loop: count ticks up on a clock, milestone
//                  crossings fire the orbit automatically (~3.4s cycle).
// demo == false -> auto loop runs out of the box (spec interaction is "auto");
//                  additionally, tapping the badge increments the count and a
//                  milestone crossing fires the orbit, a non-milestone tap gives
//                  a small reactive bump. The badge + number stay legible always.
//
// The comet trail is derived analytically from the current orbit angle inside
// a Canvas (no mutated point buffer), so it streaks correctly per frame and
// never warns about modifying state during view update.

struct OrbitBadgeView: View {
    var demo: Bool = false

    // Interactive state. Only ever written from the tap handler — never from
    // inside the TimelineView closure.
    @State private var count: Int = 11
    @State private var triggerDate: Date? = nil
    @State private var bumpDate: Date? = nil

    // Timing.
    private let cycleDuration: Double = 3.4   // demo loop length
    private let orbitDuration: Double = 1.45  // one full orbit
    private let mergeDuration: Double = 0.42   // satellite merge tail
    private let milestoneStep: Int = 5

    var body: some View {
        GeometryReader { geo in
            TimelineView(.animation) { timeline in
                let now = timeline.date.timeIntervalSinceReferenceDate
                let phase = currentPhase(now: now)
                content(geo: geo, phase: phase, now: now)
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .contentShape(Rectangle())
        .onTapGesture { handleTap() }
        .sensoryFeedback(.impact(weight: .medium), trigger: triggerDate)
        .sensoryFeedback(.selection, trigger: bumpDate)
    }

    // MARK: - Composition

    @ViewBuilder
    private func content(geo: GeometryProxy, phase: OrbitBadgeView_OrbitPhase, now: Double) -> some View {
        let side = min(geo.size.width, geo.size.height)
        let badgeRadius = side * 0.20
        let orbitRadius = badgeRadius + side * 0.16
        let displayedCount = currentCount(now: now)

        ZStack {
            backdrop(side: side)

            // Comet trail + satellite live behind/around the badge.
            OrbitBadgeView_CometCanvas(
                phase: phase,
                orbitRadius: orbitRadius,
                dotRadius: side * 0.045
            )
            .frame(width: side, height: side)

            OrbitBadgeView_BadgeGlyph(
                count: displayedCount,
                radius: badgeRadius,
                pulse: phase.badgePulse
            )
        }
        .frame(width: geo.size.width, height: geo.size.height)
    }

    private func backdrop(side: CGFloat) -> some View {
        Circle()
            .fill(
                RadialGradient(
                    colors: [
                        Color(red: 0.16, green: 0.13, blue: 0.24),
                        Color(red: 0.078, green: 0.063, blue: 0.098)
                    ],
                    center: .center,
                    startRadius: 0,
                    endRadius: side * 0.62
                )
            )
            .frame(width: side * 1.15, height: side * 1.15)
            .opacity(0.9)
    }

    // MARK: - Phase computation (pure — never writes state)

    private func currentPhase(now: Double) -> OrbitBadgeView_OrbitPhase {
        if demo {
            let t = now.truncatingRemainder(dividingBy: cycleDuration)
            // Orbit fires near the start of each cycle; the rest of the cycle is "rest".
            return phase(forElapsed: t)
        } else {
            guard let start = triggerDate?.timeIntervalSinceReferenceDate else {
                // No milestone tapped yet: keep the tile alive with the auto
                // loop so an "auto" spec is never static between renders.
                let t = now.truncatingRemainder(dividingBy: cycleDuration)
                return phase(forElapsed: t)
            }
            let elapsed = now - start
            if elapsed < 0 || elapsed > orbitDuration + mergeDuration {
                return restPhase(now: now)
            }
            return phase(forElapsed: elapsed)
        }
    }

    /// A satellite phase derived from elapsed seconds since the trigger.
    private func phase(forElapsed elapsed: Double) -> OrbitBadgeView_OrbitPhase {
        if elapsed < 0 || elapsed > orbitDuration + mergeDuration {
            return OrbitBadgeView_OrbitPhase.rest
        }

        if elapsed <= orbitDuration {
            // Orbiting: ease the angle so it accelerates out and decelerates in.
            let raw = elapsed / orbitDuration
            let eased = easeInOut(raw)
            let angle = eased * (.pi * 2.0) - (.pi / 2.0) // start at top
            // Satellite springs in at launch, full size while orbiting.
            let appear = min(1.0, raw / 0.12)
            return OrbitBadgeView_OrbitPhase(
                visible: true,
                angle: angle,
                trailSpan: 1.0,
                scale: 0.55 + 0.45 * appear,
                opacity: appear,
                badgePulse: badgePulse(raw: raw)
            )
        } else {
            // Merge tail: dot pulls into the badge center, scaling + fading.
            let mt = (elapsed - orbitDuration) / mergeDuration
            let mEased = easeOut(min(1.0, mt))
            let angle = -(.pi / 2.0) + (.pi * 2.0) * 0.0 // back at top
            return OrbitBadgeView_OrbitPhase(
                visible: true,
                angle: angle,
                trailSpan: 1.0 - mEased,           // trail shrinks as it merges
                mergeProgress: mEased,
                scale: 1.0 - 0.7 * mEased,
                opacity: 1.0 - mEased,
                badgePulse: 1.0 + 0.18 * (1.0 - mEased)
            )
        }
    }

    private func restPhase(now: Double) -> OrbitBadgeView_OrbitPhase {
        // At rest, optionally apply a small badge bump from a non-milestone tap.
        guard !demo, let b = bumpDate?.timeIntervalSinceReferenceDate else {
            return OrbitBadgeView_OrbitPhase.rest
        }
        let dt = now - b
        let bumpLen = 0.4
        if dt < 0 || dt > bumpLen { return OrbitBadgeView_OrbitPhase.rest }
        let p = dt / bumpLen
        let pulse = 1.0 + 0.14 * sin(p * .pi)
        return OrbitBadgeView_OrbitPhase(visible: false, angle: 0, trailSpan: 0,
                          scale: 0, opacity: 0, badgePulse: pulse)
    }

    private func badgePulse(raw: Double) -> Double {
        // Subtle anticipation as the satellite launches.
        1.0 + 0.10 * exp(-pow((raw - 0.04) * 14.0, 2.0))
    }

    // MARK: - Count (pure — derived, never mutated in closure)

    private func currentCount(now: Double) -> Int {
        if demo {
            // Cycle a small, always-legible count that lands on a milestone each
            // cycle so the viewer actually sees it cross a threshold (the orbit
            // is driven off the time cycle, so this value is cosmetic).
            let cycles = Int(now / cycleDuration)
            return ((cycles % 6) + 1) * milestoneStep // 5,10,...,30 then wraps
        } else {
            return count
        }
    }

    // MARK: - Interaction

    private func handleTap() {
        guard !demo else { return }
        let newCount = count + 1
        count = newCount
        if newCount % milestoneStep == 0 {
            triggerDate = Date()
        } else {
            bumpDate = Date()
        }
    }

    // MARK: - Easing helpers

    private func easeInOut(_ t: Double) -> Double {
        t < 0.5 ? 2.0 * t * t : 1.0 - pow(-2.0 * t + 2.0, 2.0) / 2.0
    }

    private func easeOut(_ t: Double) -> Double {
        1.0 - pow(1.0 - t, 3.0)
    }
}

// MARK: - Phase model

private struct OrbitBadgeView_OrbitPhase {
    var visible: Bool
    var angle: Double          // radians around the badge center
    var trailSpan: Double      // 0...1 length multiplier for the comet streak
    var mergeProgress: Double = 0
    var scale: Double
    var opacity: Double
    var badgePulse: Double

    static let rest = OrbitBadgeView_OrbitPhase(
        visible: false, angle: 0, trailSpan: 0,
        scale: 0, opacity: 0, badgePulse: 1.0
    )
}

// MARK: - Comet Canvas (analytic trail — no mutated buffer)

private struct OrbitBadgeView_CometCanvas: View {
    let phase: OrbitBadgeView_OrbitPhase
    let orbitRadius: CGFloat
    let dotRadius: CGFloat

    private let trailSamples: Int = 14
    private let trailArc: Double = 1.05 // radians of trail behind the dot

    var body: some View {
        Canvas { context, size in
            guard phase.visible, phase.opacity > 0.001 else { return }
            let center = CGPoint(x: size.width / 2.0, y: size.height / 2.0)
            // Pull radius in as the dot merges toward the badge center.
            let radius = orbitRadius * (1.0 - 0.85 * phase.mergeProgress)

            drawTrail(context: context, center: center, radius: radius)
            drawHead(context: context, center: center, radius: radius)
        }
    }

    private func point(center: CGPoint, radius: CGFloat, angle: Double) -> CGPoint {
        CGPoint(
            x: center.x + radius * CGFloat(cos(angle)),
            y: center.y + radius * CGFloat(sin(angle))
        )
    }

    private func drawTrail(context: GraphicsContext, center: CGPoint, radius: CGFloat) {
        let span = max(0.0, phase.trailSpan)
        guard span > 0.01 else { return }
        let baseColor = Color(red: 1.0, green: 0.78, blue: 0.35)

        for i in 1...trailSamples {
            let frac = Double(i) / Double(trailSamples) // 0..1 back along trail
            let back = frac * trailArc * span
            let a = phase.angle - back
            let p = point(center: center, radius: radius, angle: a)
            let fade = (1.0 - frac)
            let r = dotRadius * (0.78 * fade + 0.12)
            let alpha = phase.opacity * fade * fade * 0.85
            guard alpha > 0.004 else { continue }

            let rect = CGRect(
                x: p.x - r, y: p.y - r,
                width: r * 2.0, height: r * 2.0
            )
            var ctx = context
            ctx.addFilter(.blur(radius: r * 0.45))
            ctx.fill(Path(ellipseIn: rect), with: .color(baseColor.opacity(alpha)))
        }
    }

    private func drawHead(context: GraphicsContext, center: CGPoint, radius: CGFloat) {
        let p = point(center: center, radius: radius, angle: phase.angle)
        let r = dotRadius * CGFloat(max(0.05, phase.scale))
        let headRect = CGRect(x: p.x - r, y: p.y - r, width: r * 2.0, height: r * 2.0)

        // Soft glow halo.
        var glow = context
        glow.addFilter(.blur(radius: r * 1.1))
        let glowRect = headRect.insetBy(dx: -r * 0.6, dy: -r * 0.6)
        glow.fill(
            Path(ellipseIn: glowRect),
            with: .color(Color(red: 1.0, green: 0.7, blue: 0.3).opacity(phase.opacity * 0.5))
        )

        // Bright core.
        context.fill(
            Path(ellipseIn: headRect),
            with: .radialGradient(
                Gradient(colors: [
                    Color(red: 1.0, green: 0.97, blue: 0.88).opacity(phase.opacity),
                    Color(red: 1.0, green: 0.74, blue: 0.30).opacity(phase.opacity)
                ]),
                center: p,
                startRadius: 0,
                endRadius: r
            )
        )
    }
}

// MARK: - Badge glyph (always legible)

private struct OrbitBadgeView_BadgeGlyph: View {
    let count: Int
    let radius: CGFloat
    let pulse: Double

    var body: some View {
        ZStack {
            Circle()
                .fill(
                    LinearGradient(
                        colors: [
                            Color(red: 1.0, green: 0.36, blue: 0.42),
                            Color(red: 0.93, green: 0.22, blue: 0.55)
                        ],
                        startPoint: .topLeading,
                        endPoint: .bottomTrailing
                    )
                )
                .overlay(
                    Circle()
                        .strokeBorder(
                            Color(red: 1.0, green: 1.0, blue: 1.0).opacity(0.35),
                            lineWidth: max(1.0, radius * 0.06)
                        )
                )
                .shadow(
                    color: Color(red: 0.93, green: 0.22, blue: 0.55).opacity(0.6),
                    radius: radius * 0.5
                )

            Text(label)
                .font(.system(size: radius * 0.9, weight: .heavy, design: .rounded))
                .minimumScaleFactor(0.4)
                .lineLimit(1)
                .foregroundStyle(Color(red: 1.0, green: 1.0, blue: 1.0))
                .padding(.horizontal, radius * 0.18)
        }
        .frame(width: radius * 2.0, height: radius * 2.0)
        .scaleEffect(pulse)
        .animation(.spring(response: 0.3, dampingFraction: 0.55), value: count)
    }

    private var label: String {
        count > 99 ? "99+" : "\(count)"
    }
}
"""###,
        "mi-otp-cascade": ###"""
import SwiftUI

// MARK: - OTP Cascade Entry
// As each code digit is entered its box flips up to reveal the number with a
// staggered domino delay; a wrong code shakes the whole row in unison.
//
// demo == true  -> a self-driving TimelineView clock auto-types the digits with
//                  a domino flip stagger, holds, runs a failure shake, then clears
//                  and loops. The empty box outlines are always visible so no frame
//                  is ever blank.
// demo == false -> a real interactive OTP field: a hidden focusable TextField
//                  captures keystrokes, each new digit flips its box up, and once
//                  the row is full the code is validated against a fixed target.
//                  A wrong code shakes the row and clears; the right code tints green.

struct OtpCascadeView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { geo in
            let metrics = OtpCascadeView_OtpMetrics(size: geo.size)
            ZStack {
                background
                Group {
                    if demo {
                        OtpCascadeView_OtpCascadeDemo(metrics: metrics)
                    } else {
                        OtpCascadeView_OtpCascadeInteractive(metrics: metrics)
                    }
                }
                .frame(maxWidth: .infinity, maxHeight: .infinity)
            }
            .frame(width: geo.size.width, height: geo.size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    private var background: some View {
        LinearGradient(
            colors: [
                Color(red: 0.078, green: 0.063, blue: 0.098),
                Color(red: 0.043, green: 0.035, blue: 0.063)
            ],
            startPoint: .top,
            endPoint: .bottom
        )
        .ignoresSafeArea()
    }
}

// MARK: - Shared layout metrics

private struct OtpCascadeView_OtpMetrics {
    let size: CGSize
    let count: Int = 4

    var minSide: CGFloat { min(size.width, size.height) }

    // Box width derived from available width so it works in a 120pt tile and a
    // large detail area alike. Spacing scales with the box.
    var boxWidth: CGFloat {
        let usable = size.width * 0.86
        let spacingTotal = spacing * CGFloat(count - 1)
        let raw = (usable - spacingTotal) / CGFloat(count)
        return max(18, min(raw, size.height * 0.55))
    }

    var boxHeight: CGFloat { boxWidth * 1.32 }

    var spacing: CGFloat { max(6, size.width * 0.035) }

    var corner: CGFloat { boxWidth * 0.22 }

    var digitFont: CGFloat { boxHeight * 0.52 }

    var captionFont: CGFloat { max(8, minSide * 0.075) }
}

// MARK: - Palette

private enum OtpCascadeView_OtpPalette {
    static let slotIdle = Color(red: 0.14, green: 0.12, blue: 0.18)
    static let slotStroke = Color(red: 0.32, green: 0.28, blue: 0.42)
    static let slotActive = Color(red: 0.46, green: 0.38, blue: 0.95)
    static let digit = Color(red: 0.96, green: 0.95, blue: 1.0)
    static let success = Color(red: 0.36, green: 0.86, blue: 0.58)
    static let failure = Color(red: 0.98, green: 0.40, blue: 0.44)
    static let caption = Color(red: 0.62, green: 0.58, blue: 0.74)

    static func slotFill(_ accent: Color, filled: Bool) -> Color {
        filled ? accent.opacity(0.16) : slotIdle
    }
}

// MARK: - A single digit slot

// The empty outline container is ALWAYS rendered as the resting layer; only the
// digit face on top flips. That guarantees the row is never blank mid-cascade.
private struct OtpCascadeView_DigitSlot: View {
    let metrics: OtpCascadeView_OtpMetrics
    let character: String      // empty string == not yet filled
    let flip: Double           // 0 == flat down (hidden), 1 == fully revealed
    let accent: Color          // tint for this slot (active / success / failure)
    let highlighted: Bool      // active cursor position glow

    private var revealAngle: Double {
        // -90deg (edge-on, hidden) -> 0deg (face-on, revealed)
        (1.0 - flip) * -90.0
    }

    private var faceOpacity: Double {
        // Fade the face in only over the back half of the flip so the early
        // edge-on sliver never shows a ghost digit.
        max(0, min(1, (flip - 0.25) / 0.55))
    }

    var body: some View {
        ZStack {
            container
            digitFace
        }
        .frame(width: metrics.boxWidth, height: metrics.boxHeight)
    }

    private var container: some View {
        RoundedRectangle(cornerRadius: metrics.corner, style: .continuous)
            .fill(OtpCascadeView_OtpPalette.slotFill(accent, filled: !character.isEmpty))
            .overlay(
                RoundedRectangle(cornerRadius: metrics.corner, style: .continuous)
                    .stroke(
                        highlighted ? accent : OtpCascadeView_OtpPalette.slotStroke,
                        lineWidth: highlighted ? 2.0 : 1.2
                    )
            )
            .overlay(cursor)
            .shadow(
                color: highlighted ? accent.opacity(0.55) : .clear,
                radius: highlighted ? 8 : 0
            )
    }

    @ViewBuilder
    private var cursor: some View {
        if highlighted && character.isEmpty {
            OtpCascadeView_BlinkingCaret(color: accent)
                .frame(width: 2, height: metrics.boxHeight * 0.42)
        }
    }

    @ViewBuilder
    private var digitFace: some View {
        if !character.isEmpty {
            Text(character)
                .font(.system(size: metrics.digitFont, weight: .bold, design: .rounded))
                .minimumScaleFactor(0.4)
                .foregroundStyle(OtpCascadeView_OtpPalette.digit)
                .opacity(faceOpacity)
                .rotation3DEffect(
                    .degrees(revealAngle),
                    axis: (x: 1, y: 0, z: 0),
                    anchor: .bottom,
                    perspective: 0.55
                )
        }
    }
}

// MARK: - Blinking caret for the active empty slot

private struct OtpCascadeView_BlinkingCaret: View {
    let color: Color
    var body: some View {
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            let on = (sin(t * 4.5) > -0.2)
            Capsule()
                .fill(color)
                .opacity(on ? 0.95 : 0.12)
        }
    }
}

// MARK: - Row of slots + shared shake

private struct OtpCascadeView_OtpRow: View {
    let metrics: OtpCascadeView_OtpMetrics
    let digits: [String]       // exactly metrics.count entries, "" for empty
    let flips: [Double]        // per-slot reveal 0..1
    let accent: Color
    let activeIndex: Int       // -1 == none highlighted
    let shake: CGFloat         // current horizontal shake offset

    var body: some View {
        HStack(spacing: metrics.spacing) {
            ForEach(0..<metrics.count, id: \.self) { i in
                OtpCascadeView_DigitSlot(
                    metrics: metrics,
                    character: safeDigit(i),
                    flip: safeFlip(i),
                    accent: accent,
                    highlighted: i == activeIndex
                )
            }
        }
        .offset(x: shake)
    }

    private func safeDigit(_ i: Int) -> String {
        i < digits.count ? digits[i] : ""
    }

    private func safeFlip(_ i: Int) -> Double {
        i < flips.count ? flips[i] : 0
    }
}

// MARK: - Demo (self-driving)

private struct OtpCascadeView_OtpCascadeDemo: View {
    let metrics: OtpCascadeView_OtpMetrics

    // One full loop: type digits, hold, shake, clear, pause.
    private let period: Double = 3.4
    private let code = ["4", "8", "1", "6"]

    var body: some View {
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            let p = (t.truncatingRemainder(dividingBy: period)) / period // 0..1
            let model = phase(for: p)

            VStack(spacing: metrics.boxHeight * 0.28) {
                OtpCascadeView_OtpRow(
                    metrics: metrics,
                    digits: model.digits,
                    flips: model.flips,
                    accent: model.accent,
                    activeIndex: model.activeIndex,
                    shake: model.shake
                )
                caption(model.statusText, color: model.captionColor)
            }
        }
    }

    private func caption(_ text: String, color: Color) -> some View {
        Text(text)
            .font(.system(size: metrics.captionFont, weight: .semibold, design: .rounded))
            .foregroundStyle(color)
            .lineLimit(1)
            .minimumScaleFactor(0.5)
    }

    struct DemoModel {
        var digits: [String]
        var flips: [Double]
        var accent: Color
        var activeIndex: Int
        var shake: CGFloat
        var statusText: String
        var captionColor: Color
    }

    // Slice the normalized clock into named windows. This keeps the never-blank
    // invariant: the empty outlines always render and we only animate the faces.
    private func phase(for p: Double) -> DemoModel {
        // Windows (fractions of the loop):
        //  0.00 - 0.55  typing the 4 digits with a domino stagger
        //  0.55 - 0.70  hold (all revealed)
        //  0.70 - 0.90  failure shake
        //  0.90 - 1.00  clear + brief empty pause
        let stagger = 0.11
        let flipWindow = 0.13

        if p < 0.70 {
            // Typing + hold
            var flips = [Double](repeating: 0, count: 4)
            var digits = [String](repeating: "", count: 4)
            var active = -1
            for i in 0..<4 {
                let start = Double(i) * stagger
                let local = (p - start) / flipWindow
                let f = max(0, min(1, easeOut(local)))
                flips[i] = f
                if f > 0.02 { digits[i] = code[i] }
                else if active == -1 { active = i }
            }
            // If everything started flipping, cursor sits at last unfinished.
            if active == -1 {
                for i in 0..<4 where flips[i] < 0.95 { active = i; break }
            }
            return DemoModel(
                digits: digits,
                flips: flips,
                accent: OtpCascadeView_OtpPalette.slotActive,
                activeIndex: active,
                shake: 0,
                statusText: "Enter code",
                captionColor: OtpCascadeView_OtpPalette.caption
            )
        } else if p < 0.90 {
            // Failure shake: full row, all revealed, red tint, damped sine offset.
            let local = (p - 0.70) / 0.20            // 0..1
            let amp = metrics.boxWidth * 0.34
            let decay = exp(-3.0 * local)
            let shake = CGFloat(sin(local * .pi * 6) * decay) * amp
            return DemoModel(
                digits: code,
                flips: [1, 1, 1, 1],
                accent: OtpCascadeView_OtpPalette.failure,
                activeIndex: -1,
                shake: shake,
                statusText: "Incorrect code",
                captionColor: OtpCascadeView_OtpPalette.failure
            )
        } else {
            // Clear: boxes empty out, brief pause before loop restarts.
            return DemoModel(
                digits: ["", "", "", ""],
                flips: [0, 0, 0, 0],
                accent: OtpCascadeView_OtpPalette.slotActive,
                activeIndex: 0,
                shake: 0,
                statusText: "Enter code",
                captionColor: OtpCascadeView_OtpPalette.caption
            )
        }
    }

    private func easeOut(_ x: Double) -> Double {
        let c = max(0, min(1, x))
        return 1 - pow(1 - c, 2.4)
    }
}

// MARK: - Interactive

private struct OtpCascadeView_OtpCascadeInteractive: View {
    let metrics: OtpCascadeView_OtpMetrics

    private let correctCode = "4816"

    @State private var entry: String = ""
    @State private var flips: [Double] = [0, 0, 0, 0]
    @State private var shake: CGFloat = 0
    @State private var status: Status = .typing
    @FocusState private var focused: Bool

    enum Status: Equatable {
        case typing
        case success
        case failure
    }

    private var accent: Color {
        switch status {
        case .typing:  return OtpCascadeView_OtpPalette.slotActive
        case .success: return OtpCascadeView_OtpPalette.success
        case .failure: return OtpCascadeView_OtpPalette.failure
        }
    }

    private var digits: [String] {
        var out = [String](repeating: "", count: metrics.count)
        for (i, ch) in entry.prefix(metrics.count).enumerated() {
            out[i] = String(ch)
        }
        return out
    }

    private var activeIndex: Int {
        guard status == .typing else { return -1 }
        return entry.count < metrics.count ? entry.count : -1
    }

    var body: some View {
        VStack(spacing: metrics.boxHeight * 0.24) {
            OtpCascadeView_OtpRow(
                metrics: metrics,
                digits: digits,
                flips: flips,
                accent: accent,
                activeIndex: activeIndex,
                shake: shake
            )
            .background(hiddenField)
            caption
        }
        .contentShape(Rectangle())
        .onTapGesture { focused = true }
        .onAppear { DispatchQueue.main.async { focused = true } }
        .sensoryFeedback(.selection, trigger: entry)
        .sensoryFeedback(.success, trigger: status == .success)
        .sensoryFeedback(.error, trigger: status == .failure)
    }

    private var caption: some View {
        Text(captionText)
            .font(.system(size: metrics.captionFont, weight: .semibold, design: .rounded))
            .foregroundStyle(status == .typing ? OtpCascadeView_OtpPalette.caption : accent)
            .lineLimit(1)
            .minimumScaleFactor(0.5)
    }

    private var captionText: String {
        switch status {
        case .typing:  return "Tap, type \(correctCode)"
        case .success: return "Verified"
        case .failure: return "Incorrect code"
        }
    }

    // A real focusable text field, kept invisible behind the boxes. It captures
    // the OS keyboard so the boxes are driven by genuine input.
    private var hiddenField: some View {
        TextField("", text: $entry)
            .keyboardType(.numberPad)
            .textContentType(.oneTimeCode)
            .focused($focused)
            .foregroundStyle(.clear)
            .tint(.clear)
            .frame(width: 1, height: 1)
            .opacity(0.01)
            .onChange(of: entry) { old, new in
                handleChange(old: old, new: new)
            }
    }

    private func handleChange(old: String, new: String) {
        // Sanitize to digits, cap at count.
        let cleaned = String(new.filter { $0.isNumber }.prefix(metrics.count))
        if cleaned != new {
            entry = cleaned
            return
        }
        if status != .typing {
            // Re-typing after a result resets the row.
            status = .typing
            flips = [0, 0, 0, 0]
        }
        // Flip up any newly added digit boxes with a domino stagger.
        if cleaned.count > old.count {
            for i in old.count..<cleaned.count {
                let delay = Double(i - old.count) * 0.07
                withAnimation(.spring(response: 0.42, dampingFraction: 0.62).delay(delay)) {
                    if i < flips.count { flips[i] = 1 }
                }
            }
        } else if cleaned.count < old.count {
            for i in cleaned.count..<flips.count {
                withAnimation(.easeOut(duration: 0.18)) { flips[i] = 0 }
            }
        }
        if cleaned.count == metrics.count {
            validate(cleaned)
        }
    }

    private func validate(_ value: String) {
        if value == correctCode {
            withAnimation(.spring(response: 0.4, dampingFraction: 0.7)) {
                status = .success
            }
        } else {
            withAnimation(.spring(response: 0.4, dampingFraction: 0.7)) {
                status = .failure
            }
            runShake()
        }
    }

    // Shared row shake via a keyframe-style damped sequence, then clear.
    private func runShake() {
        let amp = metrics.boxWidth * 0.32
        let steps: [(CGFloat, Double)] = [
            (amp, 0.05), (-amp * 0.8, 0.06), (amp * 0.55, 0.06),
            (-amp * 0.32, 0.06), (amp * 0.15, 0.06), (0, 0.06)
        ]
        var delay: Double = 0
        for (value, dur) in steps {
            withAnimation(.easeInOut(duration: dur).delay(delay)) {
                shake = value
            }
            delay += dur
        }
        // After the shake settles, clear the row back to empty.
        DispatchQueue.main.asyncAfter(deadline: .now() + delay + 0.35) {
            guard status == .failure else { return }
            withAnimation(.easeOut(duration: 0.2)) {
                flips = [0, 0, 0, 0]
            }
            entry = ""
            status = .typing
        }
    }
}
"""###,
        "mi-particle-assemble-check": ###"""
import SwiftUI

/// Particle Assemble Check
/// Dozens of scattered dots fly inward via Canvas and lock into the silhouette
/// of a checkmark, the last few settling with a springy jitter, then scatter
/// back out — a self-looping particle assembly.
///
/// - `demo == true`  : a free-running loop driven entirely off the TimelineView
///                     clock (no state) so the tile always looks alive.
/// - `demo == false` : the same self-driving assembly, plus a tap re-triggers a
///                     fresh converge → hold cycle from the moment of touch
///                     (interaction spec is "auto").
struct ParticleAssembleCheckView: View {
    var demo: Bool = false

    // Fixed particle budget (spec: ~40–60, reuse one Canvas).
    private static let particleCount = 52

    // Precomputed ONCE with a seeded RNG — never randomized per frame.
    private let particles: [Particle] = ParticleAssembleCheckView.makeParticles(
        count: ParticleAssembleCheckView.particleCount
    )

    // Loop timing.
    private let period: Double = 3.4

    // Interactive (demo == false): records the moment of the last tap so we can
    // measure elapsed time off the same TimelineView clock.
    @State private var restartDate: Date = .distantPast

    var body: some View {
        GeometryReader { geo in
            let side = min(geo.size.width, geo.size.height)
            TimelineView(.animation) { timeline in
                let now = timeline.date
                let progress = phaseProgress(at: now)
                Canvas { context, size in
                    draw(context: context, size: size, side: side, progress: progress)
                }
                .frame(width: geo.size.width, height: geo.size.height)
            }
            .frame(maxWidth: .infinity, maxHeight: .infinity)
            .contentShape(Rectangle())
            .modifier(ParticleAssembleCheckView_TapRestart(enabled: !demo, restartDate: $restartDate))
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // MARK: - Progress driver

    /// Returns a normalized 0…1 *assembly* progress where:
    ///   0.00–0.45 converge, 0.45–0.65 hold assembled,
    ///   0.65–0.95 scatter, 0.95–1.0 hold scattered.
    private func phaseProgress(at now: Date) -> CGFloat {
        let raw: Double
        if demo {
            // Free-running loop with no @State — stable across redraws.
            let t = now.timeIntervalSinceReferenceDate
            raw = t.truncatingRemainder(dividingBy: period) / period
        } else {
            // Interactive: run one cycle from the last tap. Before any tap we
            // still show a slow ambient loop so the component is never blank.
            if restartDate == .distantPast {
                let t = now.timeIntervalSinceReferenceDate
                raw = t.truncatingRemainder(dividingBy: period) / period
            } else {
                let elapsed = now.timeIntervalSince(restartDate)
                // After one full cycle, settle on the assembled-hold frame.
                raw = elapsed >= period ? 0.55 : (elapsed / period)
            }
        }
        return CGFloat(raw)
    }

    // MARK: - Drawing

    private func draw(context: GraphicsContext, size: CGSize, side: CGFloat, progress: CGFloat) {
        // Map the normalized checkmark box into the available area, centered.
        let inset = side * 0.16
        let boxSide = side - inset * 2.0
        let originX = (size.width - boxSide) / 2.0
        let originY = (size.height - boxSide) / 2.0

        // assembleAmount: 0 = scattered, 1 = locked into the check.
        let assemble = assembleAmount(for: progress)

        let dotRadius = max(1.5, side * 0.022)

        // Soft glow halo behind the check when assembled — adds the "lock" beat.
        if assemble > 0.35 {
            drawHalo(context: context, size: size, side: side, amount: assemble)
        }

        for p in particles {
            // Local arrival timing: late particles start later and overshoot.
            let local = localProgress(global: assemble, delay: p.delay)
            let eased = p.isLate ? overshoot(local) : easeOutCubic(local)

            // Scattered start and assembled target, both in absolute coordinates.
            let start = CGPoint(
                x: originX + p.scatter.x * boxSide,
                y: originY + p.scatter.y * boxSide
            )
            let target = checkTarget(for: p, originX: originX, originY: originY, boxSide: boxSide)

            var pos = lerpPoint(start, target, eased)

            // Residual springy wobble for the last arrivals as they settle.
            if p.isLate {
                let settle = max(0.0, eased - 0.7) / 0.3
                let wobbleAmp = (1.0 - settle) * side * 0.012
                let wx = CGFloat(sin(Double(local) * 18.0 + Double(p.phase)))
                let wy = CGFloat(cos(Double(local) * 16.0 + Double(p.phase)))
                pos.x += wx * wobbleAmp
                pos.y += wy * wobbleAmp
            }

            // Opacity floor so scattered dots stay legible (never blank).
            let opacity = 0.35 + 0.65 * eased
            let color = blend(Self.scatteredRGB, Self.assembledRGB, eased).opacity(opacity)

            // Dots grow slightly as they lock in.
            let r = dotRadius * (0.7 + 0.3 * eased)
            let rect = CGRect(x: pos.x - r, y: pos.y - r, width: r * 2.0, height: r * 2.0)
            context.fill(Path(ellipseIn: rect), with: .color(color))
        }
    }

    private func drawHalo(context: GraphicsContext, size: CGSize, side: CGFloat, amount: CGFloat) {
        let center = CGPoint(x: size.width / 2.0, y: size.height / 2.0)
        let radius = side * 0.42
        let rect = CGRect(
            x: center.x - radius, y: center.y - radius,
            width: radius * 2.0, height: radius * 2.0
        )
        let glow = Color(red: 0.36, green: 0.91, blue: 0.62)
        let shading = GraphicsContext.Shading.radialGradient(
            Gradient(colors: [glow.opacity(0.22 * amount), glow.opacity(0.0)]),
            center: center,
            startRadius: 0,
            endRadius: radius
        )
        context.fill(Path(ellipseIn: rect), with: shading)
    }

    // MARK: - Geometry

    /// Two-segment checkmark in a normalized [0,1] box.
    /// A → vertex B → C, BC ≈ 2.5× longer than AB.
    private static let pointA = CGPoint(x: 0.20, y: 0.55)
    private static let pointB = CGPoint(x: 0.42, y: 0.74)
    private static let pointC = CGPoint(x: 0.80, y: 0.28)

    private func checkTarget(for p: Particle, originX: CGFloat, originY: CGFloat, boxSide: CGFloat) -> CGPoint {
        let n: CGPoint
        if p.onFirstSegment {
            n = lerpPoint(Self.pointA, Self.pointB, p.segmentT)
        } else {
            n = lerpPoint(Self.pointB, Self.pointC, p.segmentT)
        }
        return CGPoint(x: originX + n.x * boxSide, y: originY + n.y * boxSide)
    }

    // MARK: - Easing helpers

    /// Convert the phased assembly progress into a 0…1 "assembled" amount with a
    /// hold at the top and a hold at the bottom (never blank).
    private func assembleAmount(for progress: CGFloat) -> CGFloat {
        switch progress {
        case ..<0.45:
            return easeInOut(progress / 0.45)        // converge
        case ..<0.65:
            return 1.0                                // hold assembled
        case ..<0.95:
            return 1.0 - easeInOut((progress - 0.65) / 0.30) // scatter
        default:
            return 0.0                                // hold scattered
        }
    }

    /// Per-particle staggered local progress given a 0…1 delay offset.
    private func localProgress(global: CGFloat, delay: CGFloat) -> CGFloat {
        let span: CGFloat = 0.65 // fraction of the move consumed before all started
        let scaled = (global - delay * span) / (1.0 - span)
        return min(1.0, max(0.0, scaled))
    }

    private func easeInOut(_ t: CGFloat) -> CGFloat {
        let x = min(1.0, max(0.0, t))
        return x * x * (3.0 - 2.0 * x)
    }

    private func easeOutCubic(_ t: CGFloat) -> CGFloat {
        let x = min(1.0, max(0.0, t))
        let inv = 1.0 - x
        return 1.0 - inv * inv * inv
    }

    /// Damped overshoot (back-ease-out style) for the springy late arrivals.
    private func overshoot(_ t: CGFloat) -> CGFloat {
        let x = min(1.0, max(0.0, t))
        let c1: CGFloat = 1.70158
        let c3: CGFloat = c1 + 1.0
        let inv = x - 1.0
        return 1.0 + c3 * inv * inv * inv + c1 * inv * inv
    }

    private func lerpPoint(_ a: CGPoint, _ b: CGPoint, _ t: CGFloat) -> CGPoint {
        CGPoint(x: a.x + (b.x - a.x) * t, y: a.y + (b.y - a.y) * t)
    }

    // MARK: - Color

    // Palettes stored as plain RGB tuples so blending never depends on
    // SwiftUI's fragile Color equality.
    private static let scatteredRGB: (Double, Double, Double) = (0.42, 0.78, 0.96) // cool blue
    private static let assembledRGB: (Double, Double, Double) = (0.36, 0.91, 0.62) // success green

    private func blend(_ a: (Double, Double, Double), _ b: (Double, Double, Double), _ t: CGFloat) -> Color {
        let x = Double(min(1.0, max(0.0, t)))
        return Color(
            red: a.0 + (b.0 - a.0) * x,
            green: a.1 + (b.1 - a.1) * x,
            blue: a.2 + (b.2 - a.2) * x
        )
    }

    // MARK: - Particle model & seeded generation

    struct Particle {
        var scatter: CGPoint     // normalized [0,1] start within the box
        var segmentT: CGFloat    // 0…1 along its assigned segment
        var onFirstSegment: Bool // AB vs BC
        var delay: CGFloat       // 0…1 arrival stagger
        var phase: CGFloat       // wobble phase
        var isLate: Bool         // late arrivals overshoot + jitter
    }

    /// Deterministic per-particle randomness, computed once.
    private static func makeParticles(count: Int) -> [Particle] {
        var rng = ParticleAssembleCheckView_SeededGenerator(seed: 0xC0FFEE)

        // Distribute proportional to segment length (BC ≈ 2.5× AB).
        let abLen = distance(pointA, pointB)
        let bcLen = distance(pointB, pointC)
        let firstCount = Int((Double(count) * (abLen / (abLen + bcLen))).rounded())

        var result: [Particle] = []
        result.reserveCapacity(count)

        for i in 0..<count {
            let onFirst = i < firstCount
            let denom = onFirst ? max(1, firstCount) : max(1, count - firstCount)
            let idx = onFirst ? i : (i - firstCount)
            // Even spacing along the segment, nudged slightly for organic feel.
            let baseT = (CGFloat(idx) + 0.5) / CGFloat(denom)
            let jitterT = (CGFloat(rng.nextUnit()) - 0.5) * 0.06
            let segT = min(1.0, max(0.0, baseT + jitterT))

            let scatter = CGPoint(
                x: CGFloat(rng.nextUnit()),
                y: CGFloat(rng.nextUnit())
            )
            let delay = CGFloat(rng.nextUnit())
            let phase = CGFloat(rng.nextUnit()) * .pi * 2.0
            // ~30% of particles are "late" settlers.
            let isLate = rng.nextUnit() > 0.7

            result.append(
                Particle(
                    scatter: scatter,
                    segmentT: segT,
                    onFirstSegment: onFirst,
                    delay: delay,
                    phase: phase,
                    isLate: isLate
                )
            )
        }
        return result
    }

    private static func distance(_ a: CGPoint, _ b: CGPoint) -> CGFloat {
        let dx = a.x - b.x
        let dy = a.y - b.y
        return (dx * dx + dy * dy).squareRoot()
    }
}

// MARK: - Deterministic RNG (SplitMix64)

private struct ParticleAssembleCheckView_SeededGenerator {
    private var state: UInt64
    init(seed: UInt64) { state = seed }

    mutating func next() -> UInt64 {
        state &+= 0x9E3779B97F4A7C15
        var z = state
        z = (z ^ (z >> 30)) &* 0xBF58476D1CE4E5B9
        z = (z ^ (z >> 27)) &* 0x94D049BB133111EB
        return z ^ (z >> 31)
    }

    /// Returns a Double in [0, 1).
    mutating func nextUnit() -> Double {
        Double(next() >> 11) * (1.0 / 9007199254740992.0)
    }
}

// MARK: - Tap-to-restart modifier (interactive mode only)

private struct ParticleAssembleCheckView_TapRestart: ViewModifier {
    let enabled: Bool
    @Binding var restartDate: Date

    func body(content: Content) -> some View {
        if enabled {
            content.onTapGesture {
                restartDate = Date()
            }
        } else {
            content
        }
    }
}
"""###,
        "mi-password-reveal": ###"""
import SwiftUI

// Password Reveal Flip — Micro-interactions
// Tapping the eye toggles each masked dot flipping in sequence (rotation3DEffect axis:.y,
// per-index delay) to reveal its character at the 90° midpoint, while the SF Symbol eye
// blinks open/shut via contentTransition(.symbolEffect(.replace)).
// demo == true  -> PhaseAnimator self-drives the reveal/hide loop (transaction fires the
//                  symbolEffect blink + per-dot value-keyed staggered springs).
// demo == false -> tapping the eye toggles `revealed`, driving the same staggered flips.
struct PasswordRevealView: View {
    var demo: Bool = false

    @State private var revealed: Bool = false

    // Fixed demo string — six glyphs so the row reads as a short password.
    private let chars: [String] = ["S", "w", "i", "f", "t", "!"]

    var body: some View {
        GeometryReader { geo in
            content(size: geo.size)
                .frame(maxWidth: .infinity, maxHeight: .infinity)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    @ViewBuilder
    private func content(size: CGSize) -> some View {
        if demo {
            PhaseAnimator([false, true]) { phase in
                rowAndEye(revealed: phase, size: size)
            } animation: { _ in
                // Timed curve (not a spring) so the loop length is deterministic.
                // ~1.6s per phase -> ~3.2s round-trip, inside the 2.5–4s window.
                // Longer than the last dot's delay (5 * 0.08) + flip (~0.5s) so the
                // staggered springs always finish before the phase flips back.
                .easeInOut(duration: 1.6)
            }
        } else {
            rowAndEye(revealed: revealed, size: size)
        }
    }

    // One render function for both modes guarantees parity: the per-dot springs are
    // keyed on the `revealed` argument, so in demo they fire off the PhaseAnimator's
    // changing `phase` value.
    private func rowAndEye(revealed: Bool, size: CGSize) -> some View {
        let metrics = PasswordRevealView_Metrics(size: size, count: chars.count)
        return VStack(spacing: metrics.vGap) {
            dotRow(revealed: revealed, metrics: metrics)
            eyeButton(revealed: revealed, metrics: metrics)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    private func dotRow(revealed: Bool, metrics: PasswordRevealView_Metrics) -> some View {
        HStack(spacing: metrics.hGap) {
            ForEach(chars.indices, id: \.self) { i in
                PasswordRevealView_FlipDot(
                    angle: revealed ? 180 : 0,
                    char: chars[i],
                    side: metrics.dot
                )
                .animation(
                    .spring(response: 0.5, dampingFraction: 0.72)
                        .delay(Double(i) * 0.08),
                    value: revealed
                )
            }
        }
    }

    @ViewBuilder
    private func eyeButton(revealed: Bool, metrics: PasswordRevealView_Metrics) -> some View {
        let symbol = revealed ? "eye.fill" : "eye.slash.fill"
        Image(systemName: symbol)
            .font(.system(size: metrics.eye, weight: .semibold))
            .foregroundStyle(Self.accent)
            .contentTransition(.symbolEffect(.replace))
            .symbolEffect(.bounce, value: revealed)
            .frame(width: metrics.eye * 2.0, height: metrics.eye * 2.0)
            .background(
                Circle().fill(Self.eyeWell)
            )
            .overlay(
                Circle().strokeBorder(Self.accent.opacity(0.22), lineWidth: 1)
            )
            .contentShape(Circle())
            .onTapGesture {
                guard !demo else { return }
                // withAnimation so the symbolEffect blink + the per-dot flips both
                // run inside one transaction.
                withAnimation { self.revealed.toggle() }
            }
            .allowsHitTesting(!demo)
            .accessibilityLabel(revealed ? "Hide password" : "Reveal password")
    }

    // MARK: - Palette (literal colors, no design-system dependency)

    private static let accent = Color(red: 0.55, green: 0.80, blue: 1.0)
    private static let eyeWell = Color(red: 0.10, green: 0.10, blue: 0.16)
}

// MARK: - Layout metrics derived from the container size.

private struct PasswordRevealView_Metrics {
    let dot: CGFloat
    let hGap: CGFloat
    let vGap: CGFloat
    let eye: CGFloat

    init(size: CGSize, count: Int) {
        let w = max(size.width, 1)
        let h = max(size.height, 1)
        let n = CGFloat(max(count, 1))
        // Width budget: each dot plus a gap of ~0.35 * dot.
        let byWidth = w / (n * 1.45)
        let byHeight = h * 0.34
        let side = max(8, min(byWidth, byHeight, 64))
        self.dot = side
        self.hGap = max(3, side * 0.28)
        self.vGap = max(8, h * 0.10)
        self.eye = max(10, min(side * 0.62, 26))
    }
}

// MARK: - A single Animatable flipping dot.
// Conforms to Animatable so `body` re-runs every interpolated frame with the live
// `angle`; the mask/char swap therefore happens exactly at 90°, frame-synced to the
// spring with no separate opacity animation to desync.

private struct PasswordRevealView_FlipDot: View, Animatable {
    var angle: Double
    let char: String
    let side: CGFloat

    var animatableData: Double {
        get { angle }
        set { angle = newValue }
    }

    var body: some View {
        // Past 90° the card is edge-on and we show the reverse (character) face.
        let showChar = angle >= 90

        return ZStack {
            maskFace
                .opacity(showChar ? 0 : 1)

            charFace
                .opacity(showChar ? 1 : 0)
                // Un-mirror the back face so revealed text isn't reversed.
                .rotation3DEffect(.degrees(180), axis: (x: 0, y: 1, z: 0))
        }
        .frame(width: side, height: side * 1.25)
        .rotation3DEffect(
            .degrees(angle),
            axis: (x: 0, y: 1, z: 0),
            perspective: 0.4
        )
    }

    // Masked state: a faint card with a filled bullet so even an edge-on dot shows a sliver.
    private var maskFace: some View {
        cardBackground
            .overlay(
                Circle()
                    .fill(Self.dotInk)
                    .frame(width: side * 0.40, height: side * 0.40)
            )
    }

    // Revealed state: the character on the same card.
    private var charFace: some View {
        cardBackground
            .overlay(
                Text(char)
                    .font(.system(size: side * 0.62, weight: .semibold, design: .monospaced))
                    .foregroundStyle(Self.charInk)
                    .minimumScaleFactor(0.5)
                    .lineLimit(1)
            )
    }

    private var cardBackground: some View {
        RoundedRectangle(cornerRadius: side * 0.24, style: .continuous)
            .fill(Self.cardFill)
            .overlay(
                RoundedRectangle(cornerRadius: side * 0.24, style: .continuous)
                    .strokeBorder(Self.cardStroke, lineWidth: 1)
            )
    }

    private static let cardFill = Color(red: 0.13, green: 0.14, blue: 0.21)
    private static let cardStroke = Color(red: 0.30, green: 0.34, blue: 0.46).opacity(0.55)
    private static let dotInk = Color(red: 0.66, green: 0.72, blue: 0.86)
    private static let charInk = Color(red: 0.93, green: 0.96, blue: 1.0)
}
"""###,
        "mi-pin-shake-success": ###"""
import SwiftUI

// PIN Shake-to-Success
// PIN dots fill as you type; on success they merge into a single dot that
// expands into a checkmark, on failure they scatter and shake.
//
// demo == true  -> self-driving TimelineView loop that auto-fills the dots
//                  then alternates success (merge -> check) and failure
//                  (scatter + shake) on a ~3.5s loop. No haptics.
// demo == false -> a real keypad. Taps fill the dots; a correct PIN merges
//                  into the check, a wrong PIN shakes and resets. Haptics on.

struct PinShakeSuccessView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { geo in
            let side = min(geo.size.width, geo.size.height)
            Group {
                if demo {
                    PinShakeSuccessView_PinDemoStage(side: side)
                } else {
                    PinShakeSuccessView_PinInteractiveStage(side: side, fullSize: geo.size)
                }
            }
            .frame(width: geo.size.width, height: geo.size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }
}

// MARK: - Shared model

private enum PinShakeSuccessView_PinOutcome {
    case success
    case failure
}

/// A normalized description of the whole effect at a single instant.
/// Everything (dots, merge, check, shake) is derived from this so the demo
/// and interactive paths render through the exact same visual code.
private struct PinShakeSuccessView_PinVisualState {
    /// 0..1 fraction of dots that read as "filled".
    var fillFraction: CGFloat
    /// 0..1 progress of dots converging to center (success only).
    var mergeProgress: CGFloat
    /// 0..1 progress of the central dot growing + check trimming on.
    var checkProgress: CGFloat
    /// 0..1 progress of the scatter (failure only).
    var scatterProgress: CGFloat
    /// Live horizontal shake offset in points (failure only).
    var shakeOffset: CGFloat
    /// Outcome currently being expressed.
    var outcome: PinShakeSuccessView_PinOutcome

    static let idle = PinShakeSuccessView_PinVisualState(
        fillFraction: 0, mergeProgress: 0, checkProgress: 0,
        scatterProgress: 0, shakeOffset: 0, outcome: .success
    )
}

private enum PinShakeSuccessView_PinPalette {
    static let bg = Color(red: 0.078, green: 0.063, blue: 0.098)
    static let ring = Color(red: 0.42, green: 0.40, blue: 0.52)
    static let fill = Color(red: 0.66, green: 0.62, blue: 0.95)
    static let success = Color(red: 0.36, green: 0.84, blue: 0.62)
    static let failure = Color(red: 0.95, green: 0.42, blue: 0.46)
    static let ink = Color(red: 0.95, green: 0.95, blue: 0.98)
}

private let pinCount: Int = 4

// MARK: - Checkmark shape

private struct PinShakeSuccessView_CheckShape: Shape {
    var trimEnd: CGFloat

    var animatableData: CGFloat {
        get { trimEnd }
        set { trimEnd = newValue }
    }

    func path(in rect: CGRect) -> Path {
        var p = Path()
        let w = rect.width
        let h = rect.height
        // A clean check tucked inside the rect.
        let p0 = CGPoint(x: rect.minX + w * 0.20, y: rect.minY + h * 0.54)
        let p1 = CGPoint(x: rect.minX + w * 0.42, y: rect.minY + h * 0.74)
        let p2 = CGPoint(x: rect.minX + w * 0.80, y: rect.minY + h * 0.28)
        p.move(to: p0)
        p.addLine(to: p1)
        p.addLine(to: p2)
        return p.trimmedPath(from: 0, to: max(0, min(1, trimEnd)))
    }
}

// MARK: - Core visual (shared by both paths)

private struct PinShakeSuccessView_PinEffectView: View {
    let state: PinShakeSuccessView_PinVisualState
    let side: CGFloat

    private var dotRadius: CGFloat { side * 0.052 }
    private var spacing: CGFloat { side * 0.072 }

    private var rowWidth: CGFloat {
        let n = CGFloat(pinCount)
        return n * (dotRadius * 2) + (n - 1) * spacing
    }

    var body: some View {
        ZStack {
            dotsLayer
            mergedCore
        }
        .frame(width: rowWidth, height: dotRadius * 2)
        .offset(x: state.shakeOffset)
    }

    // Persistent ring outlines + fills. The rings NEVER disappear, so no
    // frame is ever blank.
    private var dotsLayer: some View {
        HStack(spacing: spacing) {
            ForEach(0..<pinCount, id: \.self) { index in
                singleDot(index: index)
            }
        }
        // Dots fade as they merge into the central core.
        .opacity(Double(1 - state.mergeProgress * 0.92))
    }

    private func singleDot(index: Int) -> some View {
        let filled = isFilled(index)
        let toCenter = centerOffset(forIndex: index)
        let scatter = scatterVector(forIndex: index)
        return ZStack {
            Circle()
                .stroke(PinShakeSuccessView_PinPalette.ring, lineWidth: max(1.4, side * 0.012))
            Circle()
                .fill(fillColor)
                .scaleEffect(filled ? 1 : 0.0001)
                .opacity(filled ? 1 : 0)
        }
        .frame(width: dotRadius * 2, height: dotRadius * 2)
        // Success: slide toward the row center. Failure: fling outward.
        .offset(
            x: toCenter.x * state.mergeProgress + scatter.x * state.scatterProgress,
            y: toCenter.y * state.mergeProgress + scatter.y * state.scatterProgress
        )
        .scaleEffect(1 - state.scatterProgress * 0.35)
        .animation(.spring(response: 0.32, dampingFraction: 0.7), value: filled)
    }

    // The single dot that the four converge into, which then grows and hosts
    // the checkmark.
    private var mergedCore: some View {
        let grow = 1 + state.checkProgress * 2.6
        let coreVisible = state.mergeProgress > 0.02
        return ZStack {
            Circle()
                .fill(PinShakeSuccessView_PinPalette.success)
                .frame(width: dotRadius * 2, height: dotRadius * 2)
                .scaleEffect(grow)
                .opacity(coreVisible ? Double(min(1, state.mergeProgress * 1.4)) : 0)
            PinShakeSuccessView_CheckShape(trimEnd: state.checkProgress)
                .stroke(
                    PinShakeSuccessView_PinPalette.ink,
                    style: StrokeStyle(lineWidth: max(2, side * 0.022),
                                       lineCap: .round, lineJoin: .round)
                )
                .frame(width: dotRadius * 3.0, height: dotRadius * 3.0)
                .opacity(state.checkProgress > 0.01 ? 1 : 0)
        }
    }

    private var fillColor: Color {
        switch state.outcome {
        case .success: return PinShakeSuccessView_PinPalette.fill
        case .failure:
            // Tint warm red as the failure resolves.
            return state.scatterProgress > 0.01 ? PinShakeSuccessView_PinPalette.failure : PinShakeSuccessView_PinPalette.fill
        }
    }

    private func isFilled(_ index: Int) -> Bool {
        let threshold = state.fillFraction * CGFloat(pinCount)
        return CGFloat(index) + 0.999 <= threshold
    }

    // Vector from a dot's slot to the row center.
    private func centerOffset(forIndex index: Int) -> CGPoint {
        let step = dotRadius * 2 + spacing
        let centerIndex = CGFloat(pinCount - 1) / 2
        let dx = (centerIndex - CGFloat(index)) * step
        return CGPoint(x: dx, y: 0)
    }

    // Deterministic scatter direction so the shudder reads as an explosion.
    private func scatterVector(forIndex index: Int) -> CGPoint {
        let dirs: [CGPoint] = [
            CGPoint(x: -1.0, y: -0.7),
            CGPoint(x: -0.5, y: 0.9),
            CGPoint(x: 0.6, y: -0.85),
            CGPoint(x: 1.1, y: 0.6)
        ]
        let d = dirs[index % dirs.count]
        let mag = side * 0.10
        return CGPoint(x: d.x * mag, y: d.y * mag)
    }
}

// MARK: - Demo path (self-driving tile)

private struct PinShakeSuccessView_PinDemoStage: View {
    let side: CGFloat

    var body: some View {
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            PinShakeSuccessView_PinEffectView(state: state(at: t), side: side)
                .frame(maxWidth: .infinity, maxHeight: .infinity)
        }
    }

    private let cycle: Double = 3.6

    private func state(at time: TimeInterval) -> PinShakeSuccessView_PinVisualState {
        let cycleIndex = Int(floor(time / cycle))
        let local = (time.truncatingRemainder(dividingBy: cycle)) / cycle // 0..1
        let outcome: PinShakeSuccessView_PinOutcome = (cycleIndex % 2 == 0) ? .success : .failure

        // Phase split inside one cycle:
        //   0.00 - 0.42  fill dots
        //   0.42 - 0.78  express outcome
        //   0.78 - 1.00  hold + reset
        var s = PinShakeSuccessView_PinVisualState.idle
        s.outcome = outcome

        if local < 0.42 {
            let f = local / 0.42
            s.fillFraction = eased(f)
        } else if local < 0.78 {
            s.fillFraction = 1
            let f = (local - 0.42) / 0.36 // 0..1 across the outcome phase
            apply(outcome: outcome, f: f, into: &s)
        } else {
            // Brief hold of the resolved state, then fade back to filled idle.
            s.fillFraction = 1
            apply(outcome: outcome, f: 1, into: &s)
            let r = (local - 0.78) / 0.22
            // Ease the resolved state back out so the next cycle starts clean.
            let fade = eased(min(1, r))
            s.mergeProgress *= Double(1 - fade)
            s.checkProgress *= Double(1 - fade)
            s.scatterProgress *= Double(1 - fade)
            s.shakeOffset *= CGFloat(1 - fade)
            s.fillFraction = 1 - eased(min(1, max(0, (r - 0.5) * 2)))
        }
        return s
    }

    private func apply(outcome: PinShakeSuccessView_PinOutcome, f: Double, into s: inout PinShakeSuccessView_PinVisualState) {
        switch outcome {
        case .success:
            // First merge to center, then grow + draw the check.
            s.mergeProgress = eased(min(1, f * 1.8))
            let cf = max(0, (f - 0.45) / 0.55)
            s.checkProgress = eased(min(1, cf))
        case .failure:
            // Scatter outward, with a damped-sine shudder riding on top.
            s.scatterProgress = eased(min(1, f * 1.6))
            let k: Double = 6.5   // decay
            let freq: Double = 26 // shake speed
            let amp = side * 0.05
            s.shakeOffset = CGFloat(sin(f * freq) * exp(-f * k)) * amp
        }
    }

    private func eased(_ x: Double) -> Double {
        // smoothstep
        let c = min(1, max(0, x))
        return c * c * (3 - 2 * c)
    }
}

// MARK: - Interactive path (keypad)

private enum PinShakeSuccessView_PinStatus {
    case typing
    case success
    case failure
}

private struct PinShakeSuccessView_PinInteractiveStage: View {
    let side: CGFloat
    let fullSize: CGSize

    private let secret = "1234"

    @State private var entered: String = ""
    @State private var status: PinShakeSuccessView_PinStatus = .typing
    @State private var mergeProgress: CGFloat = 0
    @State private var checkProgress: CGFloat = 0
    @State private var scatterProgress: CGFloat = 0
    @State private var shakeOffset: CGFloat = 0
    @State private var successTick: Int = 0
    @State private var failureTick: Int = 0

    var body: some View {
        VStack(spacing: fullSize.height * 0.06) {
            PinShakeSuccessView_PinEffectView(state: currentState, side: side)
                .frame(maxWidth: .infinity)
                .frame(height: side * 0.16)

            if showKeypad {
                keypad
                    .frame(maxWidth: fullSize.width * 0.92)
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .contentShape(Rectangle())
        .sensoryFeedback(.success, trigger: successTick)
        .sensoryFeedback(.error, trigger: failureTick)
    }

    // Hide the keypad in very small renders (e.g. grid tile) so the dots
    // stay legible; show it once there is room.
    private var showKeypad: Bool {
        fullSize.height > 220 && fullSize.width > 180
    }

    private var currentState: PinShakeSuccessView_PinVisualState {
        var s = PinShakeSuccessView_PinVisualState.idle
        s.fillFraction = CGFloat(entered.count) / CGFloat(pinCount)
        s.mergeProgress = mergeProgress
        s.checkProgress = checkProgress
        s.scatterProgress = scatterProgress
        s.shakeOffset = shakeOffset
        s.outcome = (status == .failure) ? .failure : .success
        return s
    }

    // MARK: keypad

    private var keypad: some View {
        let rows: [[String]] = [
            ["1", "2", "3"],
            ["4", "5", "6"],
            ["7", "8", "9"],
            ["", "0", "<"]
        ]
        return VStack(spacing: fullSize.height * 0.018) {
            ForEach(rows.indices, id: \.self) { r in
                HStack(spacing: fullSize.width * 0.05) {
                    ForEach(rows[r].indices, id: \.self) { c in
                        keyButton(rows[r][c])
                    }
                }
            }
        }
    }

    @ViewBuilder
    private func keyButton(_ label: String) -> some View {
        if label.isEmpty {
            Color.clear
                .frame(maxWidth: .infinity)
                .frame(height: side * 0.16)
        } else {
            Button {
                handleKey(label)
            } label: {
                ZStack {
                    Circle()
                        .fill(Color.white.opacity(0.06))
                        .overlay(Circle().stroke(PinShakeSuccessView_PinPalette.ring.opacity(0.5),
                                                 lineWidth: 1))
                    if label == "<" {
                        Image(systemName: "delete.left")
                            .font(.system(size: side * 0.05, weight: .medium))
                            .foregroundStyle(PinShakeSuccessView_PinPalette.ink)
                    } else {
                        Text(label)
                            .font(.system(size: side * 0.06, weight: .semibold,
                                          design: .rounded))
                            .foregroundStyle(PinShakeSuccessView_PinPalette.ink)
                    }
                }
                .frame(maxWidth: .infinity)
                .frame(height: side * 0.16)
            }
            .buttonStyle(.plain)
        }
    }

    // MARK: input handling

    private func handleKey(_ label: String) {
        guard status == .typing else {
            // Tapping after a resolved attempt restarts entry.
            resetEntry()
            if label != "<" { append(label) }
            return
        }
        if label == "<" {
            if !entered.isEmpty { entered.removeLast() }
            return
        }
        append(label)
    }

    private func append(_ digit: String) {
        guard entered.count < pinCount else { return }
        entered.append(digit)
        if entered.count == pinCount {
            evaluate()
        }
    }

    private func evaluate() {
        if entered == secret {
            status = .success
            successTick &+= 1
            withAnimation(.spring(response: 0.34, dampingFraction: 0.72)) {
                mergeProgress = 1
            }
            withAnimation(.spring(response: 0.45, dampingFraction: 0.8)
                .delay(0.18)) {
                checkProgress = 1
            }
        } else {
            status = .failure
            failureTick &+= 1
            withAnimation(.spring(response: 0.30, dampingFraction: 0.6)) {
                scatterProgress = 1
            }
            playShake()
            DispatchQueue.main.asyncAfter(deadline: .now() + 0.85) {
                resetEntry()
            }
        }
    }

    private func playShake() {
        let amp = side * 0.05
        let steps: [CGFloat] = [-1, 0.85, -0.6, 0.4, -0.22, 0.1, 0]
        var delay: Double = 0
        for v in steps {
            withAnimation(.easeInOut(duration: 0.06).delay(delay)) {
                shakeOffset = v * amp
            }
            delay += 0.06
        }
    }

    private func resetEntry() {
        withAnimation(.easeOut(duration: 0.25)) {
            entered = ""
            status = .typing
            mergeProgress = 0
            checkProgress = 0
            scatterProgress = 0
            shakeOffset = 0
        }
    }
}
"""###,
        "mi-popcorn-emoji": ###"""
import SwiftUI

// MARK: - PopcornEmojiView
/// Tapping pops a cluster of emoji that fire upward at staggered times with
/// slight horizontal drift, each rotating and shrinking like popping kernels.
///
/// - `demo == true`  : a self-driving loop auto-fires a fresh burst every few
///                     seconds, derived purely from the timeline clock (no timers,
///                     no state mutation during view update).
/// - `demo == false` : a real interactive component — tap anywhere to pop a
///                     cluster from the touch point, with haptic feedback.
struct PopcornEmojiView: View {

    var demo: Bool = false

    var body: some View {
        GeometryReader { proxy in
            let size = proxy.size
            if demo {
                PopcornEmojiView_DemoPopcorn(size: size)
            } else {
                PopcornEmojiView_InteractivePopcorn(size: size)
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }
}

// MARK: - Shared model

/// Immutable per-kernel seed. All randomness is baked in ONCE at spawn so the
/// physics is a pure function of elapsed time (no per-frame jitter).
private struct PopcornEmojiView_Kernel: Identifiable {
    let id: Int
    let emoji: String
    let launchDelay: Double      // seconds before this kernel pops
    let lifetime: Double         // seconds visible after launch
    let originX: CGFloat         // 0...1 normalized horizontal start near source
    let driftX: CGFloat          // -1...1 normalized horizontal drift
    let power: CGFloat           // 0.7...1.3 launch-velocity multiplier
    let spin: Double             // radians/second rotation
    let baseScale: CGFloat       // 0.8...1.25 size multiplier
}

private enum PopcornEmojiView_PopcornConfig {
    static let emojis = ["🍿", "🌽", "✨", "🎉", "🧈"]
    static let kernelsPerBurst = 22
    static let maxLifetime: Double = 1.9
    static let loopPeriod: Double = 3.2
}

/// A live burst: a start date plus its baked kernels.
private struct PopcornEmojiView_Burst: Identifiable {
    let id = UUID()
    let startDate: Date
    let origin: CGPoint        // tap point in view coordinates
    let kernels: [PopcornEmojiView_Kernel]
}

// MARK: - PopcornEmojiView_Kernel generation (seeded, stable)

private func makeKernels(seed: UInt64) -> [PopcornEmojiView_Kernel] {
    var rng = PopcornEmojiView_SplitMix64(seed: seed)
    let count = PopcornEmojiView_PopcornConfig.kernelsPerBurst
    return (0..<count).map { i in
        let emoji = PopcornEmojiView_PopcornConfig.emojis[Int(rng.next() % UInt64(PopcornEmojiView_PopcornConfig.emojis.count))]
        let launchDelay: Double = rng.double(in: 0.0...0.55)
        let lifetime: Double = rng.double(in: 1.0...PopcornEmojiView_PopcornConfig.maxLifetime)
        let originX: CGFloat = CGFloat(rng.double(in: 0.32...0.68))
        let driftX: CGFloat = CGFloat(rng.double(in: -1.0...1.0))
        let power: CGFloat = CGFloat(rng.double(in: 0.72...1.3))
        let spin: Double = rng.double(in: -7.0...7.0)
        let baseScale: CGFloat = CGFloat(rng.double(in: 0.8...1.25))
        return PopcornEmojiView_Kernel(id: i,
                      emoji: emoji,
                      launchDelay: launchDelay,
                      lifetime: lifetime,
                      originX: originX,
                      driftX: driftX,
                      power: power,
                      spin: spin,
                      baseScale: baseScale)
    }
}

/// Tiny deterministic RNG so a given seed always yields the same burst shape,
/// keeping the popcorn stable across frames.
private struct PopcornEmojiView_SplitMix64 {
    private var state: UInt64
    init(seed: UInt64) { state = seed &+ 0x9E37_79B9_7F4A_7C15 }
    mutating func next() -> UInt64 {
        state = state &+ 0x9E37_79B9_7F4A_7C15
        var z = state
        z = (z ^ (z >> 30)) &* 0xBF58_476D_1CE4_E5B9
        z = (z ^ (z >> 27)) &* 0x94D0_49BB_1331_11EB
        return z ^ (z >> 31)
    }
    mutating func double(in range: ClosedRange<Double>) -> Double {
        let unit = Double(next() >> 11) * (1.0 / 9_007_199_254_740_992.0)
        return range.lowerBound + unit * (range.upperBound - range.lowerBound)
    }
}

// MARK: - Physics + drawing (shared by demo & interactive)

private struct PopcornEmojiView_PopcornFrame: View {
    let size: CGSize
    /// Each entry: kernels + the elapsed seconds since that burst started.
    let bursts: [(origin: CGPoint, kernels: [PopcornEmojiView_Kernel], elapsed: Double)]
    let pulse: Double   // 0...1 source "pop" pulse for the always-on base

    var body: some View {
        Canvas { context, _ in
            drawSource(in: &context)
            drawBursts(in: &context)
        }
    }

    // Always-visible popcorn source so the view is never blank between pops.
    private func drawSource(in context: inout GraphicsContext) {
        let dim = min(size.width, size.height)
        let baseFont = dim * 0.34
        let bounce = 1.0 + 0.12 * sin(pulse * .pi)   // gentle breathing pop
        let sourcePoint = CGPoint(x: size.width / 2, y: size.height * 0.82)

        var sub = context
        sub.translateBy(x: sourcePoint.x, y: sourcePoint.y)
        sub.scaleBy(x: bounce, y: bounce)
        let resolved = sub.resolve(Text("🍿").font(.system(size: baseFont)))
        let s = resolved.measure(in: size)
        sub.draw(resolved, at: CGPoint(x: 0, y: -s.height * 0.1), anchor: .center)
    }

    private func drawBursts(in context: inout GraphicsContext) {
        let dim = min(size.width, size.height)
        let kernelFont = dim * 0.18
        let v0 = size.height * 0.95        // launch speed (points/sec), screen-relative
        let gravity = size.height * 1.9    // gravity (points/sec^2)
        let driftSpan = size.width * 0.45

        // Resolve glyphs once per frame, reuse per kernel.
        var resolvedCache: [String: GraphicsContext.ResolvedText] = [:]
        for e in PopcornEmojiView_PopcornConfig.emojis {
            resolvedCache[e] = context.resolve(Text(e).font(.system(size: kernelFont)))
        }

        for burst in bursts {
            for kernel in burst.kernels {
                let t = burst.elapsed - kernel.launchDelay
                guard t >= 0, t <= kernel.lifetime else { continue }
                drawKernel(kernel,
                           t: t,
                           burstOrigin: burst.origin,
                           v0: v0,
                           gravity: gravity,
                           driftSpan: driftSpan,
                           cache: resolvedCache,
                           context: context)
            }
        }
    }

    private func drawKernel(_ kernel: PopcornEmojiView_Kernel,
                            t: Double,
                            burstOrigin: CGPoint,
                            v0: CGFloat,
                            gravity: CGFloat,
                            driftSpan: CGFloat,
                            cache: [String: GraphicsContext.ResolvedText],
                            context: GraphicsContext) {
        guard let glyph = cache[kernel.emoji] else { return }

        let tt = CGFloat(t)
        let life = CGFloat(kernel.lifetime)
        let progress = tt / life                       // 0...1 across lifetime

        // Projectile motion: up then gravity pulls it back down.
        let launch = v0 * kernel.power
        let dy = -(launch * tt) + 0.5 * gravity * tt * tt
        let dx = kernel.driftX * driftSpan * tt

        // Origin: blend the burst point with a small per-kernel spread.
        let spread = (kernel.originX - 0.5) * driftSpan * 0.6
        let x = burstOrigin.x + spread + dx
        let y = burstOrigin.y + dy

        // Shrink + fade as the kernel ages, with a quick pop-in at the start.
        let popIn = min(1.0, tt / 0.09)
        let shrink = 1.0 - 0.55 * progress
        let scale = kernel.baseScale * shrink * popIn
        let fadeStart: CGFloat = 0.6
        let opacity: Double = progress < fadeStart
            ? 1.0
            : Double(max(0.0, 1.0 - (progress - fadeStart) / (1.0 - fadeStart)))

        guard scale > 0.01, opacity > 0.01 else { return }

        let angle = kernel.spin * t

        var sub = context
        sub.opacity = opacity
        sub.translateBy(x: x, y: y)
        sub.rotate(by: .radians(angle))
        sub.scaleBy(x: scale, y: scale)
        sub.draw(glyph, at: .zero, anchor: .center)
    }
}

// MARK: - Demo (self-driving)

private struct PopcornEmojiView_DemoPopcorn: View {
    let size: CGSize

    var body: some View {
        TimelineView(.animation) { timeline in
            let now = timeline.date.timeIntervalSinceReferenceDate
            let period = PopcornEmojiView_PopcornConfig.loopPeriod
            let loopIndex = floor(now / period)
            let phase = now - loopIndex * period          // 0...period

            // One burst per loop, fired at phase 0, plus the previous loop's tail
            // so pops overlap and never leave a fully empty frame.
            let bursts = demoBursts(loopIndex: loopIndex, phase: phase)
            let pulse = max(0.0, 1.0 - phase / 0.5)        // source pulse at fire

            PopcornEmojiView_PopcornFrame(size: size, bursts: bursts, pulse: pulse)
        }
        .accessibilityLabel("Popcorn emoji burst animation")
    }

    private func demoBursts(loopIndex: Double,
                            phase: Double) -> [(origin: CGPoint, kernels: [PopcornEmojiView_Kernel], elapsed: Double)] {
        let origin = CGPoint(x: size.width / 2, y: size.height * 0.74)
        var result: [(CGPoint, [PopcornEmojiView_Kernel], Double)] = []

        // Current loop's burst.
        let curSeed = UInt64(bitPattern: Int64(loopIndex)) &* 2_654_435_761
        result.append((origin, makeKernels(seed: curSeed), phase))

        // Previous loop's burst (its tail still fading early in this loop).
        let prevElapsed = phase + PopcornEmojiView_PopcornConfig.loopPeriod
        if prevElapsed <= PopcornEmojiView_PopcornConfig.maxLifetime + 0.6 {
            let prevSeed = UInt64(bitPattern: Int64(loopIndex - 1)) &* 2_654_435_761
            result.append((origin, makeKernels(seed: prevSeed), prevElapsed))
        }
        return result.map { (origin: $0.0, kernels: $0.1, elapsed: $0.2) }
    }
}

// MARK: - Interactive (tap to pop)

private struct PopcornEmojiView_InteractivePopcorn: View {
    let size: CGSize
    @State private var bursts: [PopcornEmojiView_Burst] = []
    @State private var burstCount: Int = 0
    @State private var lastTap: CGPoint = .zero

    var body: some View {
        TimelineView(.animation) { timeline in
            let now = timeline.date
            let live = liveBursts(now: now)
            let pulse = sourcePulse(now: now)

            PopcornEmojiView_PopcornFrame(size: size, bursts: live, pulse: pulse)
        }
        .contentShape(Rectangle())
        .gesture(
            SpatialTapGesture()
                .onEnded { value in
                    spawnBurst(at: value.location)
                }
        )
        // Tapping the always-on source is the obvious affordance; a tap anywhere
        // also works thanks to contentShape above.
        .sensoryFeedback(.impact(weight: .light), trigger: burstCount)
        .accessibilityLabel("Tap to pop popcorn emoji")
    }

    private func liveBursts(now: Date) -> [(origin: CGPoint, kernels: [PopcornEmojiView_Kernel], elapsed: Double)] {
        bursts.compactMap { burst in
            let elapsed = now.timeIntervalSince(burst.startDate)
            guard elapsed <= PopcornEmojiView_PopcornConfig.maxLifetime + 0.6 else { return nil }
            return (origin: burst.origin, kernels: burst.kernels, elapsed: elapsed)
        }
    }

    private func sourcePulse(now: Date) -> Double {
        guard let recent = bursts.last else { return 0 }
        let dt = now.timeIntervalSince(recent.startDate)
        guard dt < 0.5 else { return 0 }
        return max(0.0, 1.0 - dt / 0.5)
    }

    private func spawnBurst(at point: CGPoint) {
        let nowDate = Date()
        // Prune expired bursts here (cannot mutate inside Canvas).
        bursts.removeAll { nowDate.timeIntervalSince($0.startDate) > PopcornEmojiView_PopcornConfig.maxLifetime + 0.6 }

        let seed = UInt64(bitPattern: Int64(nowDate.timeIntervalSinceReferenceDate * 1000))
        let origin = CGPoint(x: point.x, y: point.y)
        bursts.append(PopcornEmojiView_Burst(startDate: nowDate, origin: origin, kernels: makeKernels(seed: seed)))
        lastTap = point
        burstCount &+= 1
    }
}
"""###,
        "mi-pressure-pop": ###"""
import SwiftUI

// MARK: - Pressure Pop
// A long-press fills a radial pressure ring that, on completion, releases with a
// sudden scale-pop and an outward shockwave puff.
//
//  - demo == true  : a self-driving ~3s loop (TimelineView) auto-charges the ring,
//                    plays the pop + shockwave, then resets. Pure function of phase.
//  - demo == false : the real interactive component. A long press (0.6s) charges the
//                    ring; on genuine completion a KeyframeAnimator fires the pop and
//                    shockwave, with sensory feedback. Early release drains the ring.

struct PressurePopView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { geo in
            let side = min(geo.size.width, geo.size.height)
            ZStack {
                if demo {
                    PressurePopView_DemoLoop(side: side)
                } else {
                    PressurePopView_Interactive(side: side)
                }
            }
            .frame(width: geo.size.width, height: geo.size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }
}

// MARK: - PressurePopView_Palette

private enum PressurePopView_Palette {
    static let backdrop = Color(red: 0.078, green: 0.063, blue: 0.098)
    static let track = Color(red: 1.0, green: 1.0, blue: 1.0).opacity(0.12)
    static let ringHot = Color(red: 1.0, green: 0.42, blue: 0.45)
    static let ringWarm = Color(red: 1.0, green: 0.66, blue: 0.36)
    static let core = Color(red: 1.0, green: 0.52, blue: 0.42)
    static let coreHi = Color(red: 1.0, green: 0.86, blue: 0.74)
    static let shock = Color(red: 1.0, green: 0.58, blue: 0.50)
}

// MARK: - Demo (self-driving, pure function of one phase t)

private struct PressurePopView_DemoLoop: View {
    let side: CGFloat
    private let period: Double = 3.0

    var body: some View {
        TimelineView(.animation) { context in
            let t = phase(context.date)
            let f = frame(for: t)
            PressurePopView_PopBody(
                side: side,
                ringProgress: f.ring,
                corePop: f.pop,
                shockScale: f.shockScale,
                shockOpacity: f.shockOpacity,
                glow: f.glow
            )
        }
    }

    private func phase(_ date: Date) -> Double {
        let secs = date.timeIntervalSinceReferenceDate
        return (secs.truncatingRemainder(dividingBy: period)) / period
    }

    // One normalized cycle phase 0->1 drives every quantity, so the loop is stateless.
    private func frame(for t: Double) -> PressurePopView_PopFrame {
        // Charge phase: 0.0 ..< 0.55  ring fills 0 -> 1
        // Pop phase:    0.55 ..< 0.78 core punches out, shockwave expands & fades
        // Rest phase:   0.78 ..< 1.0  everything calm, ring empty, core idle-breathes
        if t < 0.55 {
            let p = t / 0.55
            let eased = easeInOut(p)
            // subtle anticipatory squeeze as it nears full charge
            let tension = pow(eased, 3.0) * 0.06
            return PressurePopView_PopFrame(
                ring: eased,
                pop: 1.0 - tension,
                shockScale: 0.2,
                shockOpacity: 0.0,
                glow: eased * 0.6
            )
        } else if t < 0.78 {
            let p = (t - 0.55) / 0.23
            // pop: quick overshoot then settle (1 -> 1.32 -> 1.0)
            let pop = 1.0 + popCurve(p) * 0.32
            let shock = 0.25 + easeOut(p) * 1.15
            let shockOpacity = (1.0 - p) * 0.7
            return PressurePopView_PopFrame(
                ring: 1.0 - easeOut(p),          // ring discharges as it pops
                pop: pop,
                shockScale: shock,
                shockOpacity: shockOpacity,
                glow: 0.6 * (1.0 - p) + 0.4
            )
        } else {
            let p = (t - 0.78) / 0.22
            // gentle idle breathe so the core is never static/blank during rest
            let breathe = sin(p * .pi * 2.0) * 0.018
            return PressurePopView_PopFrame(
                ring: 0.0,
                pop: 1.0 + breathe,
                shockScale: 0.2,
                shockOpacity: 0.0,
                glow: 0.18 + breathe * 2.0
            )
        }
    }

    private func easeInOut(_ x: Double) -> Double {
        x < 0.5 ? 2 * x * x : 1 - pow(-2 * x + 2, 2) / 2
    }
    private func easeOut(_ x: Double) -> Double { 1 - pow(1 - x, 3) }
    // 0 -> 1 -> 0 with a snappy front for the pop overshoot
    private func popCurve(_ x: Double) -> Double {
        let s = sin(x * .pi)
        return s * (1.0 - x * 0.35)
    }
}

private struct PressurePopView_PopFrame {
    let ring: Double
    let pop: Double
    let shockScale: Double
    let shockOpacity: Double
    let glow: Double
}

// MARK: - PressurePopView_Interactive (long-press charges; completion fires the pop)

private struct PressurePopView_Interactive: View {
    let side: CGFloat

    @State private var charging: Bool = false
    @State private var ringProgress: CGFloat = 0
    @State private var popCount: Int = 0

    var body: some View {
        // KeyframeAnimator(trigger:) plays the pop + shockwave once per genuine
        // completion only — never on early release.
        KeyframeAnimator(
            initialValue: PressurePopView_PopAnim(),
            trigger: popCount
        ) { anim in
            PressurePopView_PopBody(
                side: side,
                ringProgress: Double(ringProgress),
                corePop: anim.pop,
                shockScale: anim.shockScale,
                shockOpacity: anim.shockOpacity,
                glow: glowValue(anim)
            )
            .contentShape(Circle())
            .onLongPressGesture(
                minimumDuration: 0.6,
                maximumDistance: 60
            ) {
                // perform: fires only on a real long-press completion
                popCount += 1
            } onPressingChanged: { pressing in
                charging = pressing
                withAnimation(.linear(duration: pressing ? 0.6 : 0.16)) {
                    ringProgress = pressing ? 1 : 0
                }
            }
        } keyframes: { _ in
            // core scale-pop
            KeyframeTrack(\.pop) {
                SpringKeyframe(1.34, duration: 0.18, spring: .snappy)
                SpringKeyframe(1.0, duration: 0.42, spring: .bouncy)
            }
            // shockwave expansion
            KeyframeTrack(\.shockScale) {
                CubicKeyframe(0.3, duration: 0.0)
                CubicKeyframe(1.45, duration: 0.55)
            }
            // shockwave fade
            KeyframeTrack(\.shockOpacity) {
                CubicKeyframe(0.75, duration: 0.0)
                CubicKeyframe(0.0, duration: 0.55)
            }
        }
        // Haptics live only in the interactive path so a grid of demo tiles is silent.
        .sensoryFeedback(.impact(weight: .medium, intensity: 0.9), trigger: popCount)
    }

    private func glowValue(_ anim: PressurePopView_PopAnim) -> Double {
        // a touch of glow while charging, and a flash during the pop
        let chargeGlow = Double(ringProgress) * 0.6
        let popGlow = max(0.0, anim.shockOpacity * 0.6)
        return min(1.0, chargeGlow + popGlow + 0.16)
    }
}

private struct PressurePopView_PopAnim {
    var pop: Double = 1.0
    var shockScale: Double = 0.3
    var shockOpacity: Double = 0.0
}

// MARK: - Shared visual body

private struct PressurePopView_PopBody: View {
    let side: CGFloat
    let ringProgress: Double
    let corePop: Double
    let shockScale: Double
    let shockOpacity: Double
    let glow: Double

    private var ringDiameter: CGFloat { side * 0.62 }
    private var coreDiameter: CGFloat { side * 0.34 }
    private var lineWidth: CGFloat { max(3, side * 0.052) }

    var body: some View {
        ZStack {
            PressurePopView_Palette.backdrop

            shockwave
            trackRing
            progressRing
            core
        }
    }

    // expanding outward puff — fully faded between pops, so it is never the only visible thing
    private var shockwave: some View {
        Circle()
            .stroke(
                PressurePopView_Palette.shock.opacity(shockOpacity),
                lineWidth: lineWidth * 0.7
            )
            .frame(width: ringDiameter, height: ringDiameter)
            .scaleEffect(CGFloat(shockScale))
            .blur(radius: 0.5)
    }

    // always-visible faint track
    private var trackRing: some View {
        Circle()
            .stroke(PressurePopView_Palette.track, lineWidth: lineWidth)
            .frame(width: ringDiameter, height: ringDiameter)
    }

    // the charging fill
    private var progressRing: some View {
        Circle()
            .trim(from: 0, to: CGFloat(min(max(ringProgress, 0), 1)))
            .stroke(
                AngularGradient(
                    colors: [PressurePopView_Palette.ringWarm, PressurePopView_Palette.ringHot, PressurePopView_Palette.ringWarm],
                    center: .center
                ),
                style: StrokeStyle(lineWidth: lineWidth, lineCap: .round)
            )
            .frame(width: ringDiameter, height: ringDiameter)
            .rotationEffect(.degrees(-90))
            .shadow(color: PressurePopView_Palette.ringHot.opacity(glow * 0.8),
                    radius: lineWidth * glow)
    }

    // the central core that pops — always present (idle breathe in demo rest)
    private var core: some View {
        Circle()
            .fill(
                RadialGradient(
                    colors: [PressurePopView_Palette.coreHi, PressurePopView_Palette.core],
                    center: .init(x: 0.4, y: 0.36),
                    startRadius: 0,
                    endRadius: coreDiameter * 0.7
                )
            )
            .overlay(
                Circle()
                    .stroke(Color.white.opacity(0.18 + glow * 0.25), lineWidth: 1)
            )
            .frame(width: coreDiameter, height: coreDiameter)
            .scaleEffect(CGFloat(corePop))
            .shadow(color: PressurePopView_Palette.core.opacity(0.35 + glow * 0.4),
                    radius: coreDiameter * 0.25 * CGFloat(glow + 0.4))
    }
}
"""###,
        "mi-punchout-check": ###"""
import SwiftUI

// MARK: - Punch-Out Check
// A filled chip flips on its Y axis and a checkmark appears as negative space
// punched THROUGH the card (blendMode(.destinationOut) inside a compositingGroup),
// with light leaking through the cut edges via a gradient stroke layered on top.
//
// demo == true  -> a self-driving TimelineView loop: flips front -> punched (with a
//                  legible dwell so the check can be read) -> back, forever.
// demo == false -> tap toggles the flip with a spring settle (interaction == tap).
//
// The back face is counter-mirrored (scaleEffect(x:-1)) so the asymmetric checkmark
// reads FORWARD at the resting punched state rather than backwards.
struct PunchoutCheckView: View {
    var demo: Bool = false

    @State private var flipped: Bool = false

    var body: some View {
        GeometryReader { geo in
            let side = min(geo.size.width, geo.size.height) * 0.62
            let chip = max(40, side)

            ZStack {
                if demo {
                    autoDrivenChip(size: chip)
                } else {
                    interactiveChip(size: chip)
                }
            }
            .frame(width: geo.size.width, height: geo.size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .background(backdrop)
    }

    // MARK: Backdrop (persistent so the hole has something to leak through, and the
    // tile is never truly empty even at the edge-on flip frame).
    private var backdrop: some View {
        ZStack {
            RadialGradient(
                colors: [
                    Color(red: 0.10, green: 0.09, blue: 0.16),
                    Color(red: 0.05, green: 0.05, blue: 0.09)
                ],
                center: .center,
                startRadius: 2,
                endRadius: 260
            )
            // Faint glow that shows through the punched check.
            Circle()
                .fill(Color(red: 0.45, green: 0.85, blue: 0.62).opacity(0.10))
                .blur(radius: 40)
                .frame(width: 120, height: 120)
        }
        .ignoresSafeArea()
    }
}

// MARK: - Auto-driven (demo) loop
private extension PunchoutCheckView {
    func autoDrivenChip(size: CGFloat) -> some View {
        TimelineView(.animation) { context in
            let t = context.date.timeIntervalSinceReferenceDate
            let angle = loopAngle(at: t)
            chipFace(size: size, angle: angle)
        }
    }

    // Time -> angle in degrees over a ~4s loop with flat dwells so each
    // legible state (solid front, punched back) holds long enough to read.
    //
    // Segments (period = 4.0s):
    //   0.00 .. 0.60  hold front (angle 0)
    //   0.60 .. 1.50  flip to punched (0 -> 180), easeInOut
    //   1.50 .. 2.60  dwell punched (angle 180)   <- check is legible here
    //   2.60 .. 3.50  flip back (180 -> 0), easeInOut
    //   3.50 .. 4.00  hold front (angle 0)
    func loopAngle(at time: TimeInterval) -> Double {
        let period: Double = 4.0
        let p = time.truncatingRemainder(dividingBy: period)

        if p < 0.60 {
            return 0
        } else if p < 1.50 {
            let local = (p - 0.60) / 0.90
            return 180.0 * easeInOut(local)
        } else if p < 2.60 {
            return 180
        } else if p < 3.50 {
            let local = (p - 2.60) / 0.90
            return 180.0 * (1.0 - easeInOut(local))
        } else {
            return 0
        }
    }

    func easeInOut(_ x: Double) -> Double {
        let c = min(max(x, 0), 1)
        return c * c * (3.0 - 2.0 * c)
    }
}

// MARK: - Interactive (tap) variant
private extension PunchoutCheckView {
    func interactiveChip(size: CGFloat) -> some View {
        let angle: Double = flipped ? 180 : 0
        return chipFace(size: size, angle: angle)
            .contentShape(Rectangle())
            .onTapGesture {
                withAnimation(.spring(response: 0.55, dampingFraction: 0.62)) {
                    flipped.toggle()
                }
            }
            .sensoryFeedback(.impact(weight: .light), trigger: flipped)
    }
}

// MARK: - The flipping chip (shared)
private extension PunchoutCheckView {
    /// Renders the chip at a given Y-rotation. Two faces:
    ///  - Front (angle < 90): a solid, un-punched chip.
    ///  - Back  (angle >= 90): the punched chip, counter-mirrored so the check reads forward.
    func chipFace(size: CGFloat, angle: Double) -> some View {
        let showingBack = angle >= 90
        // How far "settled" into the back state we are (0 at edge-on, 1 fully punched)
        // used to ramp the edge light leaking through the cut.
        let settle = backSettle(angle: angle)

        return ZStack {
            // Soft drop shadow / pad behind the card so depth reads during the flip.
            RoundedRectangle(cornerRadius: size * 0.24, style: .continuous)
                .fill(Color.black.opacity(0.28))
                .frame(width: size, height: size)
                .blur(radius: 14)
                .offset(y: size * 0.08)
                .opacity(0.9)

            // FRONT FACE — solid chip, visible on the first half of the flip.
            frontFace(size: size)
                .opacity(showingBack ? 0 : 1)

            // BACK FACE — punched chip + leaking edge light, counter-mirrored
            // so the asymmetric check is not reversed at rest.
            backFace(size: size, settle: settle)
                .scaleEffect(x: -1, y: 1) // un-mirror the back of a Y-flip
                .opacity(showingBack ? 1 : 0)
        }
        .rotation3DEffect(
            .degrees(angle),
            axis: (x: 0, y: 1, z: 0),
            perspective: 0.55
        )
    }

    /// 0 at the 90-degree edge-on frame, ramping to 1 by ~150 degrees, so the
    /// light through the cut edges fades in as the card settles into the check.
    func backSettle(angle: Double) -> Double {
        guard angle > 90 else { return 0 }
        let v = (angle - 90.0) / 60.0
        return min(max(v, 0), 1)
    }
}

// MARK: - Faces
private extension PunchoutCheckView {
    func frontFace(size: CGFloat) -> some View {
        ZStack {
            RoundedRectangle(cornerRadius: size * 0.24, style: .continuous)
                .fill(chipGradient)
            // Glossy top sheen for a tactile, physical card feel.
            RoundedRectangle(cornerRadius: size * 0.24, style: .continuous)
                .fill(
                    LinearGradient(
                        colors: [Color.white.opacity(0.22), Color.clear],
                        startPoint: .top,
                        endPoint: .center
                    )
                )
            RoundedRectangle(cornerRadius: size * 0.24, style: .continuous)
                .strokeBorder(Color.white.opacity(0.16), lineWidth: 1)
        }
        .frame(width: size, height: size)
    }

    func backFace(size: CGFloat, settle: Double) -> some View {
        ZStack {
            // The punched card: fill + check-shaped hole, composited flat BEFORE
            // it sits in the rotated context. The hole clears alpha so the tile
            // background (and glow) leaks through.
            ZStack {
                RoundedRectangle(cornerRadius: size * 0.24, style: .continuous)
                    .fill(chipGradientBack)
                RoundedRectangle(cornerRadius: size * 0.24, style: .continuous)
                    .fill(
                        LinearGradient(
                            colors: [Color.white.opacity(0.18), Color.clear],
                            startPoint: .top,
                            endPoint: .center
                        )
                    )
                PunchoutCheckView_CheckShape()
                    .path(in: checkRect(size: size))
                    .fill(Color.black)
                    .blendMode(.destinationOut) // punch the hole
            }
            .compositingGroup() // REQUIRED for destinationOut to cut the layers above
            .overlay(
                RoundedRectangle(cornerRadius: size * 0.24, style: .continuous)
                    .strokeBorder(Color.white.opacity(0.14), lineWidth: 1)
            )

            // Light leaking through the CUT EDGES — layered OUTSIDE the
            // compositingGroup (otherwise destinationOut would erase it too).
            PunchoutCheckView_CheckShape()
                .path(in: checkRect(size: size))
                .stroke(edgeLightGradient, lineWidth: max(1.5, size * 0.018))
                .blur(radius: 0.6)
                .opacity(0.35 + 0.65 * settle)
                .shadow(color: Color(red: 0.55, green: 1.0, blue: 0.72).opacity(0.5 * settle), radius: 4)
        }
        .frame(width: size, height: size)
    }

    func checkRect(size: CGFloat) -> CGRect {
        let inset = size * 0.26
        return CGRect(x: inset, y: inset, width: size - inset * 2, height: size - inset * 2)
    }
}

// MARK: - Palette
private extension PunchoutCheckView {
    var chipGradient: LinearGradient {
        LinearGradient(
            colors: [
                Color(red: 0.32, green: 0.78, blue: 0.55),
                Color(red: 0.16, green: 0.55, blue: 0.42)
            ],
            startPoint: .topLeading,
            endPoint: .bottomTrailing
        )
    }

    var chipGradientBack: LinearGradient {
        LinearGradient(
            colors: [
                Color(red: 0.28, green: 0.72, blue: 0.52),
                Color(red: 0.12, green: 0.46, blue: 0.36)
            ],
            startPoint: .topLeading,
            endPoint: .bottomTrailing
        )
    }

    var edgeLightGradient: LinearGradient {
        LinearGradient(
            colors: [
                Color(red: 0.75, green: 1.0, blue: 0.85),
                Color(red: 0.40, green: 0.95, blue: 0.70),
                Color(red: 0.85, green: 1.0, blue: 0.92)
            ],
            startPoint: .topLeading,
            endPoint: .bottomTrailing
        )
    }
}

// MARK: - Checkmark shape (asymmetric — the counter-mirror correctness gate)
private struct PunchoutCheckView_CheckShape: Shape {
    func path(in rect: CGRect) -> Path {
        var p = Path()
        let w = rect.width
        let h = rect.height
        // Three points of a tick, expressed as fractions of the rect.
        let p1 = CGPoint(x: rect.minX + w * 0.08, y: rect.minY + h * 0.55)
        let p2 = CGPoint(x: rect.minX + w * 0.38, y: rect.minY + h * 0.84)
        let p3 = CGPoint(x: rect.minX + w * 0.92, y: rect.minY + h * 0.18)
        p.move(to: p1)
        p.addLine(to: p2)
        p.addLine(to: p3)
        // Give the punched hole real thickness by tracing back with an offset,
        // so destinationOut clears a band rather than a hairline.
        let t = min(w, h) * 0.16
        let p3b = CGPoint(x: p3.x, y: p3.y + t)
        let p2b = CGPoint(x: p2.x, y: p2.y + t * 0.55)
        let p1b = CGPoint(x: p1.x, y: p1.y + t)
        p.addLine(to: p3b)
        p.addLine(to: p2b)
        p.addLine(to: p1b)
        p.closeSubpath()
        return p
    }
}
"""###,
        "mi-radio-ink": ###"""
import SwiftUI

/// Ink-Fill Radio — selecting an option drops a spreading ink blot that fills
/// the circle from the touch point while the previously selected option drains
/// away. Self-contained, no app dependencies. iOS 17+.
struct RadioInkView: View {

    /// demo == true  -> self-driving PhaseAnimator loop cycling the selection.
    /// demo == false -> real interactive radio group (tap to select, ink blooms
    ///                  from the tap point).
    var demo: Bool = false

    // MARK: Options

    struct InkOption: Identifiable {
        let id: Int
        let glyph: String
    }

    private let options: [InkOption] = [
        InkOption(id: 0, glyph: "A"),
        InkOption(id: 1, glyph: "B"),
        InkOption(id: 2, glyph: "C")
    ]

    // MARK: Palette (literal colors only)

    private let paper = Color(red: 0.078, green: 0.082, blue: 0.094)
    private let inkCore = Color(red: 0.44, green: 0.52, blue: 0.98)
    private let inkEdge = Color(red: 0.30, green: 0.36, blue: 0.86)
    private let ringIdle = Color(red: 0.36, green: 0.38, blue: 0.46)
    private let ringActive = Color(red: 0.62, green: 0.68, blue: 1.00)
    private let labelColor = Color(red: 0.80, green: 0.82, blue: 0.90)

    // MARK: Interactive state

    @State private var selectedIndex: Int = 0
    /// Normalized drop origin per option (where the ink soaks in from).
    @State private var dropAnchors: [UnitPoint] = [.top, .top, .top]

    var body: some View {
        GeometryReader { geo in
            let metrics = RadioInkView_Metrics(size: geo.size, count: options.count)

            if demo {
                demoBody(metrics: metrics)
            } else {
                interactiveBody(metrics: metrics)
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .background(paper)
    }

    // MARK: Demo (self-driving) path

    private func demoBody(metrics: RadioInkView_Metrics) -> some View {
        // PhaseAnimator (auto-cycling init) walks the active index
        // 0 -> 1 -> 2 -> (wrap to 0) on a continuous loop. Each phase change
        // animates the bloom/drain via radioRow's internal easeOut keyed on
        // isSelected.
        PhaseAnimator(options.map(\.id)) { active in
            optionStack(metrics: metrics,
                        activeIndex: active,
                        anchorFor: { _ in .top })
        } animation: { _ in
            .easeInOut(duration: 1.1).delay(0.15)
        }
    }

    // MARK: Interactive path

    private func interactiveBody(metrics: RadioInkView_Metrics) -> some View {
        optionStack(metrics: metrics,
                    activeIndex: selectedIndex,
                    anchorFor: { index in dropAnchors[safe: index] ?? .top })
        .sensoryFeedback(.selection, trigger: selectedIndex)
    }

    // MARK: Shared layout

    private func optionStack(metrics: RadioInkView_Metrics,
                             activeIndex: Int,
                             anchorFor: @escaping (Int) -> UnitPoint) -> some View {
        VStack(spacing: metrics.rowSpacing) {
            ForEach(options) { option in
                row(option: option,
                    metrics: metrics,
                    isSelected: option.id == activeIndex,
                    anchor: anchorFor(option.id))
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .padding(metrics.outerPadding)
    }

    private func row(option: InkOption,
                     metrics: RadioInkView_Metrics,
                     isSelected: Bool,
                     anchor: UnitPoint) -> some View {
        HStack(spacing: metrics.labelGap) {
            radioRow(diameter: metrics.diameter,
                     isSelected: isSelected,
                     anchor: anchor)

            if metrics.showLabels {
                Text(option.glyph)
                    .font(.system(size: metrics.labelSize, weight: .semibold, design: .rounded))
                    .foregroundStyle(isSelected ? ringActive : labelColor)
                    .animation(.easeOut(duration: 0.35), value: isSelected)
            }

            if metrics.showLabels { Spacer(minLength: 0) }
        }
        .contentShape(Rectangle())
        .modifier(RadioInkView_TapToSelect(enabled: !demo,
                              optionID: option.id,
                              diameter: metrics.diameter,
                              onSelect: { id, unit in
                                  dropAnchors[safe2: id] = unit
                                  withAnimation(.easeOut(duration: 0.55)) {
                                      selectedIndex = id
                                  }
                              }))
    }

    // MARK: Radio (ring + ink bloom). Shared by both paths.

    private func radioRow(diameter: CGFloat,
                          isSelected: Bool,
                          anchor: UnitPoint) -> some View {
        let inkScale: CGFloat = isSelected ? 1.0 : 0.0
        let inkOpacity: Double = isSelected ? 1.0 : 0.0
        let overshoot: CGFloat = diameter * 2.4   // >= 2x so an off-center
                                                  // bloom still reaches the rim.

        return ZStack {
            // Idle disc so the radio always reads, never fully blank.
            Circle()
                .fill(paper)
                .overlay(
                    Circle()
                        .fill(Color(red: 0.13, green: 0.135, blue: 0.16))
                )

            // Ink bloom — oversized, clipped to the radio circle, scaling out
            // from the drop anchor with an easeOut soak. Drains on deselect.
            inkBlob(size: overshoot)
                .scaleEffect(inkScale, anchor: anchor)
                .opacity(inkOpacity)
                .frame(width: diameter, height: diameter)
                .clipShape(Circle())

            // Always-drawn ring sits outside the ink for legibility.
            Circle()
                .strokeBorder(isSelected ? ringActive : ringIdle,
                              lineWidth: max(1.5, diameter * 0.07))
        }
        .frame(width: diameter, height: diameter)
        // The single source of the bloom/drain curve for BOTH paths.
        .animation(.easeOut(duration: 0.55), value: isSelected)
        .animation(.easeOut(duration: 0.55), value: anchor)
    }

    private func inkBlob(size: CGFloat) -> some View {
        Circle()
            .fill(
                RadialGradient(
                    colors: [inkCore, inkEdge],
                    center: .center,
                    startRadius: 0,
                    endRadius: size * 0.5
                )
            )
            .overlay(
                Circle()
                    .stroke(inkCore.opacity(0.35), lineWidth: size * 0.02)
                    .blur(radius: size * 0.02)
            )
            .frame(width: size, height: size)
    }
}

// MARK: - Tap capture (records normalized drop origin within the radio)

private struct RadioInkView_TapToSelect: ViewModifier {
    let enabled: Bool
    let optionID: Int
    let diameter: CGFloat
    let onSelect: (Int, UnitPoint) -> Void

    func body(content: Content) -> some View {
        if enabled {
            content.gesture(
                SpatialTapGesture(coordinateSpace: .local)
                    .onEnded { value in
                        onSelect(optionID, unitPoint(from: value.location))
                    }
            )
        } else {
            content
        }
    }

    /// Map the tap point (in the row's local space) to a UnitPoint roughly
    /// inside the radio circle, which sits at the leading edge of the row.
    private func unitPoint(from location: CGPoint) -> UnitPoint {
        let x = (location.x / max(diameter, 1)).clampedUnit()
        let y = (location.y / max(diameter, 1)).clampedUnit()
        return UnitPoint(x: x, y: y)
    }
}

// MARK: - RadioInkView_Metrics

private struct RadioInkView_Metrics {
    let diameter: CGFloat
    let rowSpacing: CGFloat
    let labelGap: CGFloat
    let labelSize: CGFloat
    let outerPadding: CGFloat
    let showLabels: Bool

    init(size: CGSize, count: Int) {
        let minSide = min(size.width, size.height)
        let isCompact = minSide < 160

        // Diameter scales off available height across the rows.
        let perRow = size.height / CGFloat(max(count, 1))
        let raw = min(perRow * 0.46, size.width * 0.34)
        diameter = max(14, min(raw, 64))

        rowSpacing = max(8, diameter * 0.55)
        labelGap = max(8, diameter * 0.35)
        labelSize = max(11, diameter * 0.52)
        outerPadding = isCompact ? diameter * 0.4 : diameter * 0.8
        // Hide labels in very small tiles so the radios dominate and read.
        showLabels = size.width >= 96
    }
}

// MARK: - Small helpers

private extension CGFloat {
    func clampedUnit() -> CGFloat { Swift.min(1, Swift.max(0, self)) }
}

private extension Array {
    subscript(safe index: Int) -> Element? {
        indices.contains(index) ? self[index] : nil
    }
}

private extension Array where Element == UnitPoint {
    subscript(safe2 index: Int) -> UnitPoint {
        get { indices.contains(index) ? self[index] : .top }
        set { if indices.contains(index) { self[index] = newValue } }
    }
}
"""###,
        "mi-reaction-tray-roll": ###"""
import SwiftUI

/// Reaction Tray Roll
/// A long-press opens a row of emoji that arc up and scale into place in a
/// staggered spring sequence; sliding across magnifies the hovered one like a
/// fisheye macOS Dock / iMessage reaction tray.
///
/// - `demo == true`  : self-driving. The tray arcs open, holds, and a virtual
///                     cursor sweeps the row back and forth so the fisheye rides
///                     on its own. The loop is continuous at the wrap — never blank.
/// - `demo == false` : the real interactive component. LongPress opens the tray,
///                     a sequenced drag feeds the fisheye, release commits the
///                     hovered emoji.
struct ReactionTrayRollView: View {
    var demo: Bool = false

    // Interactive state (ignored in demo mode).
    @State private var isOpen: Bool = false
    @State private var cursorX: CGFloat? = nil
    @State private var hoveredIndex: Int? = nil
    @State private var committedIndex: Int? = nil

    private let emojis: [String] = ["👍", "❤️", "😂", "😮", "😢", "🙏"]

    var body: some View {
        GeometryReader { proxy in
            content(in: proxy.size)
                .frame(maxWidth: .infinity, maxHeight: .infinity)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    @ViewBuilder
    private func content(in size: CGSize) -> some View {
        if demo {
            demoContent(in: size)
        } else {
            interactiveContent(in: size)
        }
    }

    // MARK: - Demo (self-driving)

    private func demoContent(in size: CGSize) -> some View {
        let metrics = ReactionTrayRollView_Metrics(size: size, count: emojis.count)
        return TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            let openAmount: Double = openAmountForDemo(t)
            let cursor: CGFloat = demoCursorX(t, metrics: metrics)
            let hovered = nearestIndex(to: cursor, metrics: metrics)

            ZStack {
                backdrop
                ReactionTrayRollView_TrayRow(
                    emojis: emojis,
                    metrics: metrics,
                    openAmount: openAmount,
                    cursorX: cursor,
                    hoveredIndex: hovered,
                    committedIndex: nil
                )
            }
        }
    }

    /// Arc the tray open, hold, then arc back out — continuous at both ends of
    /// the loop so there is no single-frame collapse at the wrap.
    private func openAmountForDemo(_ t: TimeInterval) -> Double {
        let period: Double = 3.4
        let phase = (t.truncatingRemainder(dividingBy: period)) / period // 0..1
        let intro = min(1.0, phase / 0.18)                                // arc in
        let outro: Double = phase < 0.85
            ? 1.0
            : max(0.0, 1.0 - (phase - 0.85) / 0.15)                       // arc out
        return easeOutBack(intro) * outro
    }

    /// Triangle-wave cursor that sweeps a touch beyond each end-emoji center so
    /// the end items reach full boost and the turnaround feels natural. The
    /// position is continuous across the loop wrap.
    private func demoCursorX(_ t: TimeInterval, metrics: ReactionTrayRollView_Metrics) -> CGFloat {
        let period: Double = 3.4
        let phase = (t.truncatingRemainder(dividingBy: period)) / period // 0..1
        let tri = phase < 0.5 ? (phase * 2.0) : (2.0 - phase * 2.0)       // 0->1->0
        let smooth = smoothstep(tri)
        let overshoot = metrics.spacing * 0.55
        let lo = metrics.firstCenterX - overshoot
        let hi = metrics.lastCenterX + overshoot
        return lo + (hi - lo) * CGFloat(smooth)
    }

    // MARK: - Interactive

    private func interactiveContent(in size: CGSize) -> some View {
        let metrics = ReactionTrayRollView_Metrics(size: size, count: emojis.count)
        let openAmount: Double = isOpen ? 1.0 : 0.0

        return ZStack {
            backdrop

            // Idle affordance shown when closed; fades out as the tray opens.
            idleAffordance(metrics: metrics)
                .opacity(1.0 - openAmount)

            ReactionTrayRollView_TrayRow(
                emojis: emojis,
                metrics: metrics,
                openAmount: openAmount,
                cursorX: cursorX,
                hoveredIndex: hoveredIndex,
                committedIndex: committedIndex
            )
            .allowsHitTesting(false)
            // Keep the faint resting emoji from leaking behind the idle pill.
            .opacity(isOpen ? 1.0 : 0.0)
        }
        .contentShape(Rectangle())
        .gesture(trayGesture(metrics: metrics))
        .sensoryFeedback(.selection, trigger: hoveredIndex)
        .sensoryFeedback(.impact(weight: .medium), trigger: committedIndex)
    }

    private func idleAffordance(metrics: ReactionTrayRollView_Metrics) -> some View {
        VStack(spacing: metrics.itemSize * 0.18) {
            Capsule()
                .fill(trayFill)
                .overlay(
                    Capsule().stroke(trayStroke, lineWidth: 1)
                )
                .overlay(
                    Text(committedIndex.map { emojis[$0] } ?? "👍")
                        .font(.system(size: metrics.itemSize * 0.62))
                )
                .frame(width: metrics.itemSize * 1.7, height: metrics.itemSize * 1.05)
            Text("Hold")
                .font(.system(size: max(8, metrics.itemSize * 0.24), weight: .semibold, design: .rounded))
                .foregroundStyle(Color(red: 0.62, green: 0.60, blue: 0.70))
        }
        .position(x: metrics.size.width / 2, y: metrics.rowBaselineY)
    }

    // MARK: - Gesture

    private func trayGesture(metrics: ReactionTrayRollView_Metrics) -> some Gesture {
        LongPressGesture(minimumDuration: 0.28)
            .sequenced(before: DragGesture(minimumDistance: 0))
            .onChanged { value in
                switch value {
                case .first(true):
                    open()
                case .second(true, let drag):
                    if !isOpen { open() }
                    if let drag {
                        let x = clampedX(drag.location.x, metrics: metrics)
                        cursorX = x
                        hoveredIndex = nearestIndex(to: x, metrics: metrics)
                    }
                default:
                    break
                }
            }
            .onEnded { _ in
                if let h = hoveredIndex {
                    committedIndex = h
                }
                close()
            }
    }

    private func open() {
        guard !isOpen else { return }
        withAnimation(.spring(response: 0.42, dampingFraction: 0.7)) {
            isOpen = true
        }
    }

    private func close() {
        withAnimation(.spring(response: 0.4, dampingFraction: 0.78)) {
            isOpen = false
            cursorX = nil
            hoveredIndex = nil
        }
    }

    private func clampedX(_ x: CGFloat, metrics: ReactionTrayRollView_Metrics) -> CGFloat {
        min(max(x, 0), metrics.size.width)
    }

    // MARK: - Shared geometry helpers

    private func nearestIndex(to x: CGFloat, metrics: ReactionTrayRollView_Metrics) -> Int {
        var best = 0
        var bestDist = CGFloat.greatestFiniteMagnitude
        for i in 0..<emojis.count {
            let d = abs(metrics.centerX(i) - x)
            if d < bestDist {
                bestDist = d
                best = i
            }
        }
        return best
    }

    // MARK: - Palette

    private var backdrop: some View {
        // Tint #141019 with a soft vignette so the tile reads on its own.
        RadialGradient(
            colors: [
                Color(red: 0.118, green: 0.094, blue: 0.149),
                Color(red: 0.078, green: 0.063, blue: 0.098)
            ],
            center: .center,
            startRadius: 2,
            endRadius: 220
        )
    }

    private var trayFill: Color {
        Color(red: 0.18, green: 0.16, blue: 0.24).opacity(0.92)
    }

    private var trayStroke: Color {
        Color(red: 0.42, green: 0.40, blue: 0.55).opacity(0.55)
    }
}

// MARK: - Layout metrics

private struct ReactionTrayRollView_Metrics {
    let size: CGSize
    let count: Int
    let itemSize: CGFloat
    let spacing: CGFloat
    let rowWidth: CGFloat
    let rowOriginX: CGFloat
    let rowBaselineY: CGFloat

    init(size: CGSize, count: Int) {
        self.size = size
        self.count = count

        let w = max(size.width, 1)
        let h = max(size.height, 1)

        // Derive item size so the whole row (with magnification headroom) fits
        // even a ~120pt tile. Width is the binding constraint with 6 items.
        let byWidth = w / (CGFloat(count) + 1.4)
        let byHeight = h * 0.40
        let item = max(8, min(byWidth, byHeight))
        self.itemSize = item

        let gap = item * 0.30
        self.spacing = item + gap
        self.rowWidth = spacing * CGFloat(count - 1)
        self.rowOriginX = (w - rowWidth) / 2
        // Sit a touch below center; emoji grow upward from this baseline.
        self.rowBaselineY = h * 0.58
    }

    var firstCenterX: CGFloat { centerX(0) }
    var lastCenterX: CGFloat { centerX(count - 1) }

    func centerX(_ index: Int) -> CGFloat {
        rowOriginX + spacing * CGFloat(index)
    }
}

// MARK: - Tray row (single render path for both modes)

private struct ReactionTrayRollView_TrayRow: View {
    let emojis: [String]
    let metrics: ReactionTrayRollView_Metrics
    let openAmount: Double
    let cursorX: CGFloat?
    let hoveredIndex: Int?
    let committedIndex: Int?

    var body: some View {
        // The tray pill bows up behind the emoji.
        ZStack {
            trayPill
            ForEach(emojis.indices, id: \.self) { index in
                emojiItem(index)
            }
        }
    }

    private var trayPill: some View {
        let padX = metrics.itemSize * 0.62
        let pillW = metrics.rowWidth + metrics.itemSize + padX
        let pillH = metrics.itemSize * 1.45
        let lift = metrics.itemSize * 0.18
        return Capsule()
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.22, green: 0.20, blue: 0.30).opacity(0.96),
                        Color(red: 0.15, green: 0.13, blue: 0.21).opacity(0.96)
                    ],
                    startPoint: .top,
                    endPoint: .bottom
                )
            )
            .overlay(
                Capsule().stroke(
                    Color(red: 0.46, green: 0.44, blue: 0.60).opacity(0.45),
                    lineWidth: 1
                )
            )
            .shadow(color: Color.black.opacity(0.35 * openAmount), radius: 10, y: 5)
            .frame(width: pillW, height: pillH)
            .scaleEffect(
                x: 0.6 + 0.4 * CGFloat(openAmount),
                y: 0.5 + 0.5 * CGFloat(openAmount),
                anchor: .bottom
            )
            .opacity(openAmount)
            .position(
                x: metrics.size.width / 2,
                y: metrics.rowBaselineY - metrics.itemSize * 0.30 - lift * CGFloat(openAmount)
            )
    }

    private func emojiItem(_ index: Int) -> some View {
        let p = itemProgress(index)                     // 0..1 arc-in
        let baseX = metrics.centerX(index)
        let fisheye = fisheyeBoost(forCenterX: baseX)   // 0..1 nearness
        let scale = itemScale(progress: p, fisheye: fisheye)
        let lift = itemLift(progress: p, fisheye: fisheye)
        let isHover = (hoveredIndex == index)
        let isCommitted = (committedIndex == index)

        return Text(emojis[index])
            .font(.system(size: metrics.itemSize * 0.92))
            .scaleEffect(scale, anchor: .bottom)
            .background(
                Circle()
                    .fill(Color.white.opacity(isCommitted ? 0.10 : 0))
                    .frame(width: metrics.itemSize * 1.3, height: metrics.itemSize * 1.3)
            )
            .overlay(alignment: .top) {
                hoverLabel(index)
                    .opacity(isHover ? fisheye : 0)
            }
            .shadow(
                color: Color.black.opacity(0.30 * fisheye),
                radius: 4 * fisheye,
                y: 2
            )
            .position(
                x: baseX,
                y: metrics.rowBaselineY - lift
            )
            .opacity(itemOpacity(progress: p))
    }

    private func hoverLabel(_ index: Int) -> some View {
        Text(emojis[index])
            .font(.system(size: metrics.itemSize * 0.55))
            .padding(.horizontal, metrics.itemSize * 0.22)
            .padding(.vertical, metrics.itemSize * 0.10)
            .background(
                Capsule().fill(Color(red: 0.10, green: 0.09, blue: 0.14).opacity(0.95))
            )
            .offset(y: -metrics.itemSize * 1.5)
            .fixedSize()
    }

    // MARK: progress + fisheye math

    /// Staggered arc-in: derive each item's local progress from the single
    /// openAmount plus an index offset, so demo and interactive behave alike.
    private func itemProgress(_ index: Int) -> Double {
        let count = Double(metrics.count)
        let span: Double = 1.6
        let raw = openAmount * (count + span) - Double(index)
        return min(max(raw / span, 0), 1)
    }

    /// Gaussian nearness 0..1 of an item center to the cursor.
    private func fisheyeBoost(forCenterX x: CGFloat) -> Double {
        guard let cursor = cursorX else { return 0 }
        let sigma = max(metrics.spacing * 1.05, 1)
        let d = Double(abs(x - cursor) / sigma)
        return exp(-d * d)
    }

    private func itemScale(progress p: Double, fisheye: Double) -> CGFloat {
        let arc = 0.55 + 0.45 * easeOutBack(p)   // grows in from 0.55 -> 1.0
        let boost = 1.0 + 0.85 * fisheye          // up to +85% under the cursor
        return CGFloat(arc * boost)
    }

    private func itemLift(progress p: Double, fisheye: Double) -> CGFloat {
        let base = metrics.itemSize * 0.55 * CGFloat(easeOutBack(p))
        let hover = metrics.itemSize * 0.42 * CGFloat(fisheye)
        return base + hover
    }

    private func itemOpacity(progress p: Double) -> CGFloat {
        // Never fully invisible once any open begins; clamp a legible floor.
        CGFloat(min(1.0, 0.15 + p * 1.1))
    }
}

// MARK: - Easing (file-private free functions)

private func easeOutBack(_ x: Double) -> Double {
    let c1: Double = 1.70158
    let c3: Double = c1 + 1.0
    let t = x - 1.0
    return 1.0 + c3 * t * t * t + c1 * t * t
}

private func smoothstep(_ x: Double) -> Double {
    let t = min(max(x, 0), 1)
    return t * t * (3.0 - 2.0 * t)
}
"""###,
        "mi-ribbon-drop-bookmark": ###"""
import SwiftUI

/// Ribbon Drop Bookmark
///
/// A cloth ribbon unfurls downward from the top edge with a pendulum swing and a
/// swallowtail-notched bottom, settling with a gentle sway when saved.
///
/// - `demo == true`  : self-driving PhaseAnimator loop that toggles the saved state,
///                     dropping the ribbon with a pendulum swing, settling, then
///                     retracting — on a ~3.4s cycle so the tile always looks alive.
/// - `demo == false` : real interactive component. Tapping toggles `isSaved`, which
///                     triggers the same spring-driven drop-and-sway with a real
///                     pendulum kick that springs back to rest.
struct RibbonDropBookmarkView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { proxy in
            let size = proxy.size
            ZStack {
                background(size: size)

                if demo {
                    demoLoop(size: size)
                } else {
                    interactive(size: size)
                }
            }
            .frame(width: size.width, height: size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // MARK: - Demo (self-driving)

    private func demoLoop(size: CGSize) -> some View {
        PhaseAnimator(RibbonDropBookmarkView_RibbonPhase.allCases) { phase in
            stage(
                size: size,
                progress: phase.progress,
                swing: phase.swing
            )
        } animation: { phase in
            switch phase {
            case .hidden:
                return .easeInOut(duration: 0.55)
            case .dropping:
                // Springy drop produces the pendulum overshoot + sway.
                return .spring(response: 0.5, dampingFraction: 0.55)
            case .settled:
                return .spring(response: 0.5, dampingFraction: 0.7)
            }
        }
    }

    // MARK: - Interactive

    private func interactive(size: CGSize) -> some View {
        RibbonDropBookmarkView_InteractiveRibbon(size: size) { progress, swing in
            stage(size: size, progress: progress, swing: swing)
        }
    }

    // MARK: - Shared stage

    private func stage(size: CGSize, progress: CGFloat, swing: CGFloat) -> some View {
        let metrics = RibbonDropBookmarkView_RibbonMetrics(size: size)
        return RibbonDropBookmarkView_RibbonPiece(metrics: metrics, progress: progress, swing: swing)
    }

    // MARK: - Backdrop (always visible — never a blank frame)

    private func background(size: CGSize) -> some View {
        let metrics = RibbonDropBookmarkView_RibbonMetrics(size: size)
        return ZStack {
            // Journal page.
            RoundedRectangle(cornerRadius: metrics.pageCorner, style: .continuous)
                .fill(
                    LinearGradient(
                        colors: [
                            Color(red: 0.98, green: 0.97, blue: 0.94),
                            Color(red: 0.93, green: 0.91, blue: 0.86)
                        ],
                        startPoint: .topLeading,
                        endPoint: .bottomTrailing
                    )
                )
                .overlay(
                    RoundedRectangle(cornerRadius: metrics.pageCorner, style: .continuous)
                        .stroke(Color(red: 0.0, green: 0.0, blue: 0.0).opacity(0.06), lineWidth: 1)
                )
                .frame(width: metrics.pageWidth, height: metrics.pageHeight)
                .shadow(color: Color(red: 0.0, green: 0.0, blue: 0.0).opacity(0.12),
                        radius: metrics.pageWidth * 0.04, x: 0, y: metrics.pageWidth * 0.02)

            // Faint ruled lines for journal feel.
            RibbonDropBookmarkView_RuledLines(metrics: metrics)

            // Top rail the ribbon hangs from — a persistent visual anchor so the
            // retracted state still reads as "a bookmark slot", never empty.
            RibbonDropBookmarkView_TopRail(metrics: metrics)
        }
    }
}

// MARK: - Phases

private enum RibbonDropBookmarkView_RibbonPhase: CaseIterable {
    case hidden
    case dropping
    case settled

    /// How far the ribbon has unfurled (0 hidden ... 1 fully down).
    var progress: CGFloat {
        switch self {
        case .hidden:   return 0.0
        case .dropping: return 1.0
        case .settled:  return 1.0
        }
    }

    /// Initial pendulum swing (radians) injected at the moment of dropping; the
    /// spring resolves it back toward 0 producing the sway.
    var swing: CGFloat {
        switch self {
        case .hidden:   return 0.0
        case .dropping: return 0.16   // kicks to the side, then springs home
        case .settled:  return 0.0
        }
    }
}

// MARK: - Interactive wrapper

private struct RibbonDropBookmarkView_InteractiveRibbon<Content: View>: View {
    let size: CGSize
    let content: (CGFloat, CGFloat) -> Content

    @State private var isSaved: Bool = false
    @State private var swing: CGFloat = 0

    var body: some View {
        let progress: CGFloat = isSaved ? 1.0 : 0.0

        return content(progress, swing)
            // Spring on the saved transition drives the vertical drop overshoot.
            .animation(.spring(response: 0.5, dampingFraction: 0.55), value: isSaved)
            .contentShape(Rectangle())
            .onTapGesture {
                toggle()
            }
            .sensoryFeedback(.impact(weight: .light), trigger: isSaved)
            .overlay(alignment: .bottom) {
                hint
            }
    }

    private func toggle() {
        isSaved.toggle()
        // Kick the pendulum to one side, then spring it back to rest — this is
        // the named "sway". Dropping swings one way; retracting swings the other.
        swing = isSaved ? 0.16 : -0.12
        withAnimation(.spring(response: 0.5, dampingFraction: 0.55)) {
            swing = 0
        }
    }

    private var hint: some View {
        Text(isSaved ? "Saved" : "Tap to save")
            .font(.system(size: max(9, size.width * 0.05), weight: .semibold, design: .rounded))
            .foregroundStyle(Color(red: 0.32, green: 0.28, blue: 0.24).opacity(0.7))
            .padding(.bottom, size.height * 0.05)
            .allowsHitTesting(false)
    }
}

// MARK: - Metrics

private struct RibbonDropBookmarkView_RibbonMetrics {
    let size: CGSize

    var pageWidth: CGFloat { size.width * 0.78 }
    var pageHeight: CGFloat { size.height * 0.86 }
    var pageCorner: CGFloat { min(pageWidth, pageHeight) * 0.06 }

    /// Ribbon geometry.
    var ribbonWidth: CGFloat { pageWidth * 0.2 }
    /// Full length of the ribbon when fully unfurled, measured from the top rail.
    var ribbonLength: CGFloat { pageHeight * 0.74 }
    /// Horizontal position (centre x) of the ribbon — tucked toward the right.
    var ribbonCenterX: CGFloat { size.width / 2 + pageWidth * 0.22 }
    /// The top attachment point (where the ribbon hangs from the rail).
    var topY: CGFloat { (size.height - pageHeight) / 2 }
    var railHeight: CGFloat { pageHeight * 0.05 }
    /// Depth of the swallowtail V notch at the bottom.
    var swallowtail: CGFloat { ribbonWidth * 0.55 }
}

// MARK: - Backdrop pieces

private struct RibbonDropBookmarkView_RuledLines: View {
    let metrics: RibbonDropBookmarkView_RibbonMetrics

    var body: some View {
        let count = 5
        let top = metrics.topY + metrics.pageHeight * 0.22
        let spacing = metrics.pageHeight * 0.13
        return ZStack {
            ForEach(0..<count, id: \.self) { i in
                Rectangle()
                    .fill(Color(red: 0.55, green: 0.5, blue: 0.42).opacity(0.18))
                    .frame(width: metrics.pageWidth * 0.78, height: 1)
                    .position(
                        x: metrics.size.width / 2,
                        y: top + CGFloat(i) * spacing
                    )
            }
        }
    }
}

private struct RibbonDropBookmarkView_TopRail: View {
    let metrics: RibbonDropBookmarkView_RibbonMetrics

    var body: some View {
        RoundedRectangle(cornerRadius: metrics.railHeight / 2, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.36, green: 0.30, blue: 0.27),
                        Color(red: 0.22, green: 0.18, blue: 0.16)
                    ],
                    startPoint: .top,
                    endPoint: .bottom
                )
            )
            .frame(width: metrics.pageWidth * 0.92, height: metrics.railHeight)
            .overlay(
                Capsule()
                    .fill(Color(red: 1.0, green: 1.0, blue: 1.0).opacity(0.22))
                    .frame(width: metrics.pageWidth * 0.86, height: metrics.railHeight * 0.28)
                    .offset(y: -metrics.railHeight * 0.2)
            )
            .position(x: metrics.size.width / 2, y: metrics.topY + metrics.railHeight / 2)
            .shadow(color: Color(red: 0.0, green: 0.0, blue: 0.0).opacity(0.18),
                    radius: 2, x: 0, y: 1)
    }
}

// MARK: - Ribbon piece

private struct RibbonDropBookmarkView_RibbonPiece: View {
    let metrics: RibbonDropBookmarkView_RibbonMetrics
    let progress: CGFloat   // 0 retracted ... 1 unfurled
    let swing: CGFloat      // pendulum angle in radians

    var body: some View {
        let p = clamp01(progress)
        let visibleLength = lengthForProgress(p)
        let angle = Angle(radians: Double(swing))

        ribbonBody(length: visibleLength)
            // Anchor the rotation at the TOP attachment point so it reads as a
            // hanging piece of cloth swinging like a pendulum, not a spinning bar.
            .rotationEffect(angle, anchor: .top)
            // Position the top edge at the rail; the body grows downward.
            .position(
                x: metrics.ribbonCenterX,
                y: railBottomY + visibleLength / 2
            )
            // Always keep at least the nub visible so no frame is blank.
            .opacity(1.0)
    }

    // The visible ribbon as a single shape (rectangle + swallowtail notch),
    // gradient-filled with a soft cloth sheen and edge shadow.
    private func ribbonBody(length: CGFloat) -> some View {
        let shape = RibbonDropBookmarkView_SwallowtailRibbon(
            cornerInset: metrics.ribbonWidth * 0.12,
            notchDepth: notchDepth(for: length)
        )
        return shape
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.82, green: 0.16, blue: 0.22),
                        Color(red: 0.66, green: 0.09, blue: 0.16),
                        Color(red: 0.78, green: 0.14, blue: 0.20)
                    ],
                    startPoint: .leading,
                    endPoint: .trailing
                )
            )
            .overlay(
                // Centre-line sheen for the folded-cloth highlight.
                shape
                    .fill(
                        LinearGradient(
                            colors: [
                                Color.clear,
                                Color(red: 1.0, green: 1.0, blue: 1.0).opacity(0.28),
                                Color.clear
                            ],
                            startPoint: .leading,
                            endPoint: .trailing
                        )
                    )
                    .blendMode(.screen)
            )
            .overlay(
                shape
                    .stroke(Color(red: 0.4, green: 0.04, blue: 0.08).opacity(0.4), lineWidth: 0.75)
            )
            .frame(width: metrics.ribbonWidth, height: max(length, 0.001))
            .shadow(color: Color(red: 0.3, green: 0.02, blue: 0.05).opacity(0.35),
                    radius: metrics.ribbonWidth * 0.18,
                    x: metrics.ribbonWidth * 0.12, y: length * 0.02)
    }

    // MARK: helpers

    private var railBottomY: CGFloat {
        metrics.topY + metrics.railHeight * 0.5
    }

    private func lengthForProgress(_ p: CGFloat) -> CGFloat {
        // Always show a small nub even when retracted so the slot reads as
        // occupied; full length at p == 1.
        let nub = metrics.railHeight * 1.1
        return nub + (metrics.ribbonLength - nub) * p
    }

    private func notchDepth(for length: CGFloat) -> CGFloat {
        // Notch only fully forms once enough ribbon has dropped.
        let full = metrics.swallowtail
        let denom = metrics.ribbonLength * 0.4
        guard denom > 0 else { return 0 }
        let ratio = clamp01((length - metrics.railHeight * 2) / denom)
        return full * ratio
    }

    private func clamp01(_ v: CGFloat) -> CGFloat {
        min(1, max(0, v))
    }
}

// MARK: - Swallowtail ribbon shape

/// A rectangle with a V notch cut up into its bottom edge (swallowtail), plus
/// gently inset top corners so the cloth reads as soft rather than a hard bar.
private struct RibbonDropBookmarkView_SwallowtailRibbon: Shape {
    var cornerInset: CGFloat
    var notchDepth: CGFloat

    func path(in rect: CGRect) -> Path {
        var path = Path()
        let w = rect.width
        let h = rect.height
        let notch = min(notchDepth, h * 0.5)
        let inset = min(cornerInset, w * 0.4)

        // Start top-left (slightly inset for a soft shoulder).
        path.move(to: CGPoint(x: rect.minX + inset, y: rect.minY))
        path.addLine(to: CGPoint(x: rect.maxX - inset, y: rect.minY))
        path.addQuadCurve(
            to: CGPoint(x: rect.maxX, y: rect.minY + inset),
            control: CGPoint(x: rect.maxX, y: rect.minY)
        )
        // Right edge down to bottom-right.
        path.addLine(to: CGPoint(x: rect.maxX, y: rect.maxY))
        // Up into the V notch centre.
        path.addLine(to: CGPoint(x: rect.midX, y: rect.maxY - notch))
        // Down to bottom-left.
        path.addLine(to: CGPoint(x: rect.minX, y: rect.maxY))
        // Left edge up to the soft top-left shoulder.
        path.addLine(to: CGPoint(x: rect.minX, y: rect.minY + inset))
        path.addQuadCurve(
            to: CGPoint(x: rect.minX + inset, y: rect.minY),
            control: CGPoint(x: rect.minX, y: rect.minY)
        )
        path.closeSubpath()
        return path
    }
}
"""###,
        "mi-rolodex-quantity": ###"""
import SwiftUI

// Rolodex Quantity — a vertical cylinder of numbers you can fling.
// Each row is offset + rotated about the X axis and faded by its angular
// distance from center to fake a curved 3D drum. A flick seeds a
// friction-decayed offset (a dt-based integrator stepped inside
// .onChange(of: context.date)) that coasts and springs to a snapped value.
struct RolodexQuantityView: View {
    var demo: Bool = false

    // Inclusive value range shown on the drum.
    private let minValue: Int = 0
    private let maxValue: Int = 99

    var body: some View {
        GeometryReader { geo in
            let size = geo.size
            ZStack {
                background(size: size)
                if demo {
                    RolodexQuantityView_DemoDrum(size: size,
                             minValue: minValue,
                             maxValue: maxValue,
                             render: { offset in
                                 drum(offset: offset, size: size)
                             })
                } else {
                    RolodexQuantityView_InteractiveDrum(size: size,
                                    minValue: minValue,
                                    maxValue: maxValue,
                                    render: { offset in
                                        drum(offset: offset, size: size)
                                    })
                }
            }
            .frame(width: size.width, height: size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // MARK: - Derived metrics (all relative to the tile size)

    private func metrics(_ size: CGSize) -> (rowPitch: CGFloat, font: CGFloat, radius: CGFloat) {
        let dim = min(size.width, size.height)
        let pitch = max(dim * 0.26, 16)
        let font = max(dim * 0.30, 17)
        let radius = max(dim * 0.42, 22)
        return (pitch, font, radius)
    }

    // MARK: - Pure renderer: continuous offset -> 3D number column

    @ViewBuilder
    private func drum(offset: Double, size: CGSize) -> some View {
        let m = metrics(size)
        let center = Int(offset.rounded())
        // How many rows above/below center to draw (cull past ~90°).
        let span = 4
        ZStack {
            ForEach(-span...span, id: \.self) { delta in
                let value = center + delta
                if value >= minValue && value <= maxValue {
                    numberRow(value: value,
                              offset: offset,
                              metrics: m,
                              size: size)
                }
            }
            sheen(size: size, metrics: m)
            selectionFrame(size: size, metrics: m)
        }
        .frame(width: size.width, height: size.height)
    }

    @ViewBuilder
    private func numberRow(value: Int,
                           offset: Double,
                           metrics m: (rowPitch: CGFloat, font: CGFloat, radius: CGFloat),
                           size: CGSize) -> some View {
        // Distance (in row units) of this value from the centered offset.
        let rel: CGFloat = CGFloat(Double(value) - offset)
        // Angle on the cylinder; clamp so projection never folds past the rim.
        let rawAngle: CGFloat = rel * 40.0
        let angle: CGFloat = max(-92, min(92, rawAngle))
        let rad = angle * .pi / 180
        // Project onto the drum: vertical position follows sin, depth follows cos.
        let yPos = sin(rad) * m.radius
        let depth = cos(rad)
        let opacity = max(0.0, Double(depth)) * 0.9 + 0.1
        let scale = 0.55 + 0.45 * max(0.0, depth)

        Text("\(value)")
            .font(.system(size: m.font, weight: .semibold, design: .rounded))
            .monospacedDigit()
            .foregroundStyle(numberColor(depth: depth))
            .scaleEffect(scale)
            .rotation3DEffect(.degrees(Double(angle)),
                              axis: (x: 1, y: 0, z: 0),
                              anchor: .center,
                              perspective: 0.6)
            .opacity(opacity)
            .offset(y: yPos)
    }

    private func numberColor(depth: CGFloat) -> Color {
        // Center reads brightest; rim rows fade toward a dim slate.
        let t = max(0.0, min(1.0, Double(depth)))
        let r = 0.55 + 0.40 * t
        let g = 0.58 + 0.40 * t
        let b = 0.66 + 0.32 * t
        return Color(red: r, green: g, blue: b)
    }

    // MARK: - Chrome

    private func background(size: CGSize) -> some View {
        let dim = min(size.width, size.height)
        return RoundedRectangle(cornerRadius: dim * 0.16, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.09, green: 0.10, blue: 0.14),
                        Color(red: 0.05, green: 0.06, blue: 0.09)
                    ],
                    startPoint: .top,
                    endPoint: .bottom
                )
            )
            .overlay(
                RoundedRectangle(cornerRadius: dim * 0.16, style: .continuous)
                    .strokeBorder(Color(red: 1, green: 1, blue: 1).opacity(0.05),
                                  lineWidth: 1)
            )
            .padding(dim * 0.04)
    }

    // Top + bottom fade so numbers dissolve into the drum edges.
    private func sheen(size: CGSize, metrics m: (rowPitch: CGFloat, font: CGFloat, radius: CGFloat)) -> some View {
        let dim = min(size.width, size.height)
        return RoundedRectangle(cornerRadius: dim * 0.16, style: .continuous)
            .fill(
                LinearGradient(
                    stops: [
                        .init(color: Color(red: 0.05, green: 0.06, blue: 0.09).opacity(0.9), location: 0.0),
                        .init(color: .clear, location: 0.30),
                        .init(color: .clear, location: 0.70),
                        .init(color: Color(red: 0.05, green: 0.06, blue: 0.09).opacity(0.9), location: 1.0)
                    ],
                    startPoint: .top,
                    endPoint: .bottom
                )
            )
            .padding(dim * 0.04)
            .allowsHitTesting(false)
    }

    // Center selection band that frames the snapped value.
    private func selectionFrame(size: CGSize, metrics m: (rowPitch: CGFloat, font: CGFloat, radius: CGFloat)) -> some View {
        let bandHeight = m.font * 1.25
        let bandWidth = min(size.width, size.height) * 0.66
        return RoundedRectangle(cornerRadius: bandHeight * 0.28, style: .continuous)
            .fill(Color(red: 0.40, green: 0.52, blue: 1.0).opacity(0.10))
            .overlay(
                RoundedRectangle(cornerRadius: bandHeight * 0.28, style: .continuous)
                    .strokeBorder(Color(red: 0.45, green: 0.58, blue: 1.0).opacity(0.35),
                                  lineWidth: 1.5)
            )
            .frame(width: bandWidth, height: bandHeight)
            .allowsHitTesting(false)
    }
}

// MARK: - Demo driver (self-driving, no @State physics)

private struct RolodexQuantityView_DemoDrum<Content: View>: View {
    let size: CGSize
    let minValue: Int
    let maxValue: Int
    let render: (Double) -> Content

    var body: some View {
        TimelineView(.animation) { context in
            render(offset(at: context.date))
        }
    }

    // Pure function of time: a ~3.4s loop that flings, coasts, eases to a
    // snapped value, holds, then flings again. Never leaves the value range.
    private func offset(at date: Date) -> Double {
        let period: Double = 3.4
        let t = date.timeIntervalSinceReferenceDate.truncatingRemainder(dividingBy: period) / period
        let span = Double(maxValue - minValue)

        // Phase 1 (0..0.55): a decelerating fling that sweeps ~14 values.
        // Phase 2 (0.55..1): hold on the snapped value with a tiny settle.
        let base: Double = 6
        let sweep: Double = 14
        let value: Double
        if t < 0.55 {
            let p = t / 0.55
            let eased = 1 - pow(1 - p, 3) // easeOutCubic = coasting feel
            value = base + sweep * eased
        } else {
            let p = (t - 0.55) / 0.45
            // Small spring-like overshoot then settle onto the integer target.
            let target = base + sweep
            let snapped = (base + sweep).rounded()
            let settle = sin(p * .pi * 2) * 0.35 * (1 - p)
            value = target * (1 - p) + snapped * p + settle
        }
        return min(Double(maxValue), max(Double(minValue), value))
    }
}

// MARK: - Interactive driver (drag + friction integrator)

private struct RolodexQuantityView_InteractiveDrum<Content: View>: View {
    let size: CGSize
    let minValue: Int
    let maxValue: Int
    let render: (Double) -> Content

    // Continuous drum position (in value units). offset == value at center.
    @State private var offset: Double = 6
    @State private var dragStartOffset: Double = 6
    @State private var velocity: Double = 0          // value-units / sec
    @State private var coasting: Bool = false
    @State private var lastTick: Date? = nil
    @State private var lastIndex: Int = 6
    @State private var hapticTrigger: Int = 0
    @State private var isDragging: Bool = false

    var body: some View {
        // Paused timeline keeps the integrator idle at rest.
        TimelineView(.animation(paused: !coasting)) { context in
            render(offset)
                .onChange(of: context.date) { _, newDate in
                    step(to: newDate)
                }
        }
        .contentShape(Rectangle())
        .gesture(dragGesture)
        .sensoryFeedback(.selection, trigger: hapticTrigger)
        .onAppear { lastIndex = Int(offset.rounded()) }
    }

    private var pitch: CGFloat {
        max(min(size.width, size.height) * 0.26, 16)
    }

    private var dragGesture: some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                // First event of a fresh touch: grab the drum wherever it
                // actually is (mid-coast or mid-spring-snap) so translation==0
                // maps to the current position and there is no jump.
                if !isDragging {
                    isDragging = true
                    coasting = false
                    lastTick = nil
                    velocity = 0
                    dragStartOffset = offset
                }
                // Dragging down moves to lower values; map points -> value units.
                let deltaValues = Double(-value.translation.height / pitch)
                offset = clampOffset(dragStartOffset + deltaValues)
                fireHapticIfCrossed()
            }
            .onEnded { value in
                isDragging = false
                // Predicted end gives a velocity-like fling without relying on
                // DragGesture.Value.velocity (predictedEndTranslation is iOS 13+).
                let predicted = Double(-value.predictedEndTranslation.height / pitch)
                let actual = Double(-value.translation.height / pitch)
                let fling = predicted - actual // extra distance the flick implies
                // Convert remaining fling into an initial velocity (per second).
                let v0 = fling * 3.5
                if abs(v0) < 0.6 {
                    // Degenerate / tap: snap to nearest with a spring.
                    snapToNearest()
                } else {
                    velocity = v0
                    lastTick = nil
                    coasting = true
                }
            }
    }

    // dt-based friction integrator. Framerate-independent.
    private func step(to date: Date) {
        guard coasting else { return }
        guard let last = lastTick else { lastTick = date; return }
        let dt = date.timeIntervalSince(last)
        lastTick = date
        guard dt > 0, dt < 0.25 else { return }

        let frictionPerSec: Double = 0.10 // velocity retained per second
        velocity *= pow(frictionPerSec, dt)
        offset = clampOffset(offset + velocity * dt)
        fireHapticIfCrossed()

        // Clamp at the rails: kill momentum so it can't grind the edge.
        if offset <= Double(minValue) || offset >= Double(maxValue) {
            velocity = 0
        }

        if abs(velocity) < 0.4 {
            coasting = false
            lastTick = nil
            snapToNearest()
        }
    }

    private func snapToNearest() {
        let target = Double(min(maxValue, max(minValue, Int(offset.rounded()))))
        withAnimation(.spring(response: 0.35, dampingFraction: 0.7)) {
            offset = target
        }
        dragStartOffset = target
        fireHapticIfCrossed()
    }

    private func clampOffset(_ v: Double) -> Double {
        min(Double(maxValue), max(Double(minValue), v))
    }

    private func fireHapticIfCrossed() {
        let idx = Int(offset.rounded())
        if idx != lastIndex {
            lastIndex = idx
            hapticTrigger &+= 1
        }
    }
}
"""###,
        "mi-scrubber-wave": ###"""
import SwiftUI

/// Waveform Scrubber — dragging across an audio waveform parts the bars around the
/// playhead and ripples a height-wave outward from the touch point.
///
/// - `demo == true`  → a self-driving TimelineView sweeps the playhead 0→1→0 on a
///   loop so the tile is always alive (bars are always rendered at their baseline).
/// - `demo == false` → a real DragGesture sets the playhead; per-bar parting +
///   height bulge are computed from distance to the playhead with a falloff, with
///   `sensoryFeedback(.selection)` ticking as the bar under the finger changes.
///   The playhead is left wherever the finger releases (no spring back).
struct ScrubberWaveView: View {
    var demo: Bool = false

    // Persistent interactive playhead (normalized 0...1). Release leaves it in place.
    @State private var playhead: CGFloat = 0.5
    @State private var isDragging: Bool = false
    // Touch-down moment, used for a short bounded amplitude "kick" on grab.
    @State private var touchStart: Date = .distantPast
    // Integer bar index under the playhead — drives selection haptics on change.
    @State private var activeBar: Int = -1

    private let barCount: Int = 42

    var body: some View {
        GeometryReader { geo in
            content(in: geo.size)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // MARK: - Content router

    @ViewBuilder
    private func content(in size: CGSize) -> some View {
        if demo {
            demoContent(in: size)
        } else {
            interactiveContent(in: size)
        }
    }

    // MARK: - Demo (self-driving)

    private func demoContent(in size: CGSize) -> some View {
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            let head = Self.sweep(t)
            waveformCanvas(size: size, head: head, boost: 0.0)
        }
    }

    // MARK: - Interactive

    private func interactiveContent(in size: CGSize) -> some View {
        TimelineView(.animation) { timeline in
            let boost = touchBoost(now: timeline.date)
            waveformCanvas(size: size, head: playhead, boost: boost)
        }
        .contentShape(Rectangle())
        .gesture(dragGesture(in: size))
        .sensoryFeedback(.selection, trigger: activeBar)
    }

    private func dragGesture(in size: CGSize) -> some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                if !isDragging {
                    isDragging = true
                    touchStart = Date()
                }
                let w = max(size.width, 1)
                let x = min(max(value.location.x, 0), w)
                playhead = x / w
                let idx = Int((playhead * CGFloat(barCount - 1)).rounded())
                if idx != activeBar { activeBar = idx }
            }
            .onEnded { _ in
                // Release leaves the playhead — no spring back to zero.
                isDragging = false
            }
    }

    /// A short, bounded amplitude boost right after touch-down so the wave "kicks"
    /// when you grab it, then decays. Returns 0 in steady state.
    private func touchBoost(now: Date) -> CGFloat {
        guard isDragging else { return 0 }
        let elapsed = now.timeIntervalSince(touchStart)
        guard elapsed >= 0, elapsed < 0.6 else { return 0 }
        let decay = 1.0 - (elapsed / 0.6)
        return CGFloat(decay) * 0.35
    }

    // MARK: - Shared waveform draw path

    /// Single Canvas that draws every bar. `head` is the normalized playhead,
    /// `boost` is an optional transient extra amplitude near the playhead.
    private func waveformCanvas(size: CGSize, head: CGFloat, boost: CGFloat) -> some View {
        Canvas { context, canvasSize in
            drawWaveform(into: context, size: canvasSize, head: head, boost: boost)
        }
    }

    private func drawWaveform(into context: GraphicsContext, size: CGSize, head: CGFloat, boost: CGFloat) {
        let w = size.width
        let h = size.height
        guard w > 1, h > 1 else { return }

        let inset: CGFloat = w * 0.06
        let usableW = w - inset * 2
        let midY = h * 0.5
        let maxBarH = h * 0.72
        let minBarH = h * 0.12
        let slotW = usableW / CGFloat(barCount)
        let barW = min(slotW * 0.5, 6)

        let headX = inset + head * usableW

        // Parting + bulge influence radius in slot-units.
        let radius: CGFloat = 4.0

        for i in 0..<barCount {
            let baseX = inset + (CGFloat(i) + 0.5) * slotW
            // Distance from this bar to the playhead, in slot units.
            let dxSlots = (baseX - headX) / slotW
            let absD = abs(dxSlots)

            // Cosine bell centered on the playhead → height bulge that rides along.
            let bell = bellFalloff(distance: absD, radius: radius)

            // Horizontal parting: bars near the head push away from it.
            let partStrength = bell * slotW * 0.85
            let dir: CGFloat = dxSlots == 0 ? 0 : (dxSlots > 0 ? 1 : -1)
            let partOffset = dir * partStrength

            // Base amplitude is deterministic (precomputed once) — never per-frame random.
            let amp = Self.amplitudes[i]
            let bulge = 1.0 + bell * (1.35 + boost)
            var barH = (minBarH + (maxBarH - minBarH) * amp) * bulge
            barH = min(barH, h * 0.94)

            let x = baseX + partOffset
            let rect = CGRect(
                x: x - barW / 2,
                y: midY - barH / 2,
                width: barW,
                height: barH
            )
            let path = Path(roundedRect: rect, cornerRadius: barW / 2)

            // Bars at/behind the playhead read as "played" (warm), ahead are cool.
            let played = baseX <= headX
            let color = barColor(played: played, bell: bell)
            context.fill(path, with: .color(color))
        }

        drawPlayhead(into: context, x: headX, height: h)
    }

    private func drawPlayhead(into context: GraphicsContext, x: CGFloat, height: CGFloat) {
        let topPad = height * 0.08
        let lineRect = CGRect(x: x - 1.25, y: topPad, width: 2.5, height: height - topPad * 2)
        let line = Path(roundedRect: lineRect, cornerRadius: 1.25)
        context.fill(line, with: .color(playheadColor))

        // Soft glow halo so the playhead reads on any background.
        let haloR = height * 0.07
        let haloRect = CGRect(x: x - haloR, y: height * 0.5 - haloR, width: haloR * 2, height: haloR * 2)
        context.fill(Path(ellipseIn: haloRect), with: .color(playheadColor.opacity(0.18)))

        // Knob at top of the playhead line.
        let knobR = max(height * 0.045, 3)
        let knobRect = CGRect(x: x - knobR, y: topPad - knobR, width: knobR * 2, height: knobR * 2)
        context.fill(Path(ellipseIn: knobRect), with: .color(playheadColor))
    }

    // MARK: - Color helpers (RGB literals only — no design-system / UIKit deps)

    private typealias RGB = (r: CGFloat, g: CGFloat, b: CGFloat)

    private var playheadColor: Color {
        Color(red: 0.99, green: 0.86, blue: 0.42)
    }

    private func barColor(played: Bool, bell: CGFloat) -> Color {
        let warm: RGB = (0.98, 0.74, 0.36)
        let cool: RGB = (0.40, 0.44, 0.58)
        let bright: RGB = (1.0, 0.97, 0.85)
        let base = played ? warm : cool
        let amount = min(bell, 1.0) * 0.45
        let m = mix(base, bright, amount)
        return Color(red: Double(m.r), green: Double(m.g), blue: Double(m.b))
    }

    private func mix(_ a: RGB, _ b: RGB, _ amount: CGFloat) -> RGB {
        let t = min(max(amount, 0), 1)
        return (
            a.r + (b.r - a.r) * t,
            a.g + (b.g - a.g) * t,
            a.b + (b.b - a.b) * t
        )
    }

    // MARK: - Falloff math

    /// Smooth bell-shaped falloff: peak 1 at distance 0, ~0 beyond `radius`.
    private func bellFalloff(distance: CGFloat, radius: CGFloat) -> CGFloat {
        guard radius > 0 else { return 0 }
        let x = distance / radius
        if x >= 1 { return 0 }
        let c = (cos(.pi * x) + 1) * 0.5 // cosine bell, no exp() needed
        return c * c
    }

    // MARK: - Static, precomputed data

    /// Triangle sweep 0→1→0 over a ~3.2s loop for demo mode.
    private static func sweep(_ t: TimeInterval) -> CGFloat {
        let period: TimeInterval = 3.2
        let phase = (t.truncatingRemainder(dividingBy: period)) / period // 0...1
        let tri = phase < 0.5 ? (phase * 2) : (2 - phase * 2) // 0→1→0
        let eased = tri * tri * (3 - 2 * tri) // smoothstep — lingers at the ends
        return CGFloat(eased)
    }

    /// Deterministic per-bar base amplitudes (0...1), computed ONCE. Stable across
    /// every frame — only position/height *modulation* is animated, never the source.
    private static let amplitudes: [CGFloat] = {
        var out: [CGFloat] = []
        out.reserveCapacity(42)
        for i in 0..<42 {
            let f = Double(i)
            // Layered sinusoids → an organic, audio-like envelope. Fully deterministic.
            let a = sin(f * 0.55) * 0.5 + 0.5
            let b = sin(f * 1.30 + 1.7) * 0.5 + 0.5
            let c = sin(f * 0.21 + 0.4) * 0.5 + 0.5
            var v = a * 0.45 + b * 0.30 + c * 0.25
            // Gentle overall arc so the middle reads a touch louder.
            let arc = sin(f / 41.0 * .pi)
            v = v * (0.55 + 0.45 * arc)
            out.append(CGFloat(min(max(v, 0.08), 1.0)))
        }
        return out
    }()
}
"""###,
        "mi-slide-to-confirm": ###"""
import SwiftUI
import Foundation

// MARK: - Slide to Confirm
// A handle is dragged along a track that fills behind it with a liquid sheen.
// Reaching the end snaps it shut and morphs the arrow into a checkmark.
// demo == true  -> self-driving PhaseAnimator loop (slide -> lock -> reset).
// demo == false -> real DragGesture, clamped, with spring snap + haptics.
struct SlideToConfirmView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { geo in
            content(in: geo.size)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    @ViewBuilder
    private func content(in size: CGSize) -> some View {
        let metrics = SlideToConfirmView_Metrics(size: size)

        ZStack {
            if demo {
                demoTrack(metrics: metrics)
            } else {
                SlideToConfirmView_InteractiveTrack(metrics: metrics)
            }
        }
        .frame(width: metrics.trackWidth, height: metrics.trackHeight)
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // MARK: Demo (auto-driving)

    @ViewBuilder
    private func demoTrack(metrics: SlideToConfirmView_Metrics) -> some View {
        // Phases: rest -> slid-to-end (locked) -> hold -> reset.
        // Never lands on a blank frame; the held phase shows the checkmark.
        PhaseAnimator([SlideToConfirmView_DemoPhase.rest, .filling, .locked, .hold]) { phase in
            SlideToConfirmView_TrackBody(
                metrics: metrics,
                progress: phase.progress,
                locked: phase.locked
            )
        } animation: { phase in
            switch phase {
            case .rest:    return .easeInOut(duration: 0.35)
            case .filling: return .easeInOut(duration: 1.3)
            case .locked:  return .spring(response: 0.35, dampingFraction: 0.6)
            case .hold:    return .easeInOut(duration: 0.9)
            }
        }
    }
}

// MARK: - Phase model

private enum SlideToConfirmView_DemoPhase: CaseIterable {
    case rest, filling, locked, hold

    var progress: Double {
        switch self {
        case .rest:    return 0.0
        case .filling: return 0.92
        case .locked:  return 1.0
        case .hold:    return 1.0
        }
    }

    var locked: Bool {
        switch self {
        case .rest, .filling: return false
        case .locked, .hold:  return true
        }
    }
}

// MARK: - SlideToConfirmView_Metrics

private struct SlideToConfirmView_Metrics {
    let trackWidth: CGFloat
    let trackHeight: CGFloat
    let handleDiameter: CGFloat
    let inset: CGFloat

    init(size: CGSize) {
        let pad: CGFloat = max(8, size.width * 0.06)
        let w = max(60, size.width - pad * 2)
        // Cap height so it never becomes a giant bar in a large detail area.
        let h = min(max(size.height * 0.34, 44), min(64, w * 0.32))
        self.trackWidth = w
        self.trackHeight = h
        self.inset = max(3, h * 0.09)
        self.handleDiameter = h - inset * 2
    }

    // Center-x travel range of the handle.
    var handleMinX: CGFloat { inset + handleDiameter / 2 }
    var handleMaxX: CGFloat { trackWidth - inset - handleDiameter / 2 }
    var travel: CGFloat { max(1, handleMaxX - handleMinX) }

    func handleCenterX(progress: Double) -> CGFloat {
        handleMinX + travel * CGFloat(progress)
    }
}

// MARK: - Interactive

private struct SlideToConfirmView_InteractiveTrack: View {
    let metrics: SlideToConfirmView_Metrics

    @State private var progress: Double = 0
    @State private var locked: Bool = false
    @State private var dragging: Bool = false
    // Increments on each successful lock so .success haptic re-fires.
    @State private var successTick: Int = 0

    var body: some View {
        SlideToConfirmView_TrackBody(metrics: metrics, progress: progress, locked: locked)
            .contentShape(Rectangle())
            .gesture(drag)
            .sensoryFeedback(.success, trigger: successTick)
            .sensoryFeedback(.impact(weight: .light), trigger: crossingStep)
    }

    // Fires a light tick as the handle crosses quarter steps while dragging.
    private var crossingStep: Int {
        guard dragging else { return -1 }
        return Int(progress * 4)
    }

    private var drag: some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                guard !locked else { return }
                dragging = true
                let x = value.location.x
                let clamped = min(max(x, metrics.handleMinX), metrics.handleMaxX)
                progress = Double((clamped - metrics.handleMinX) / metrics.travel)
            }
            .onEnded { _ in
                dragging = false
                if progress > 0.9 {
                    withAnimation(.spring(response: 0.35, dampingFraction: 0.6)) {
                        progress = 1.0
                        locked = true
                    }
                    successTick += 1
                    // Auto-reset so the control can be tried again.
                    scheduleReset()
                } else {
                    withAnimation(.spring(response: 0.4, dampingFraction: 0.7)) {
                        progress = 0.0
                    }
                }
            }
    }

    private func scheduleReset() {
        DispatchQueue.main.asyncAfter(deadline: .now() + 1.4) {
            withAnimation(.spring(response: 0.5, dampingFraction: 0.8)) {
                progress = 0.0
                locked = false
            }
        }
    }
}

// MARK: - Track body (shared renderer)

private struct SlideToConfirmView_TrackBody: View {
    let metrics: SlideToConfirmView_Metrics
    let progress: Double
    let locked: Bool

    private var palette: SlideToConfirmView_Palette { SlideToConfirmView_Palette() }

    var body: some View {
        ZStack(alignment: .leading) {
            trackBase
            fill
            label
            handle
        }
        .frame(width: metrics.trackWidth, height: metrics.trackHeight)
    }

    // MARK: Base groove

    private var trackBase: some View {
        Capsule()
            .fill(palette.trackBase)
            .overlay(
                Capsule()
                    .stroke(palette.trackStroke, lineWidth: 1)
            )
    }

    // MARK: Liquid fill + sheen

    private var fill: some View {
        // Fill follows the handle's trailing edge (handle center + radius).
        let fillWidth = metrics.handleCenterX(progress: progress)
            + metrics.handleDiameter / 2

        return TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            Capsule()
                .fill(palette.fillGradient)
                .overlay(sheen(time: t))
                .frame(width: max(metrics.trackHeight, fillWidth))
                .clipShape(Capsule())
        }
        .frame(width: metrics.trackWidth, alignment: .leading)
        .opacity(0.95)
    }

    private func sheen(time: Double) -> some View {
        // A moving diagonal highlight that travels across the filled area.
        let phase = (time.truncatingRemainder(dividingBy: 2.2)) / 2.2
        let span: CGFloat = metrics.trackWidth
        let x = -span + CGFloat(phase) * (span * 2)

        return LinearGradient(
            colors: [
                Color.white.opacity(0.0),
                Color.white.opacity(0.35),
                Color.white.opacity(0.0)
            ],
            startPoint: .leading,
            endPoint: .trailing
        )
        .frame(width: span * 0.55)
        .offset(x: x)
        .blendMode(.screen)
        .allowsHitTesting(false)
    }

    // MARK: Label

    private var label: some View {
        // Fades out as the slide progresses; gone once locked.
        Text(locked ? "Confirmed" : "Slide to confirm")
            .font(.system(size: metrics.trackHeight * 0.3, weight: .semibold, design: .rounded))
            .foregroundStyle(labelColor)
            .lineLimit(1)
            .minimumScaleFactor(0.6)
            .frame(width: metrics.trackWidth, alignment: .center)
            .opacity(labelOpacity)
            .animation(.easeOut(duration: 0.25), value: locked)
    }

    private var labelColor: Color {
        locked ? Color.white : palette.labelRest
    }

    private var labelOpacity: Double {
        if locked { return 1.0 }
        // Fade the prompt out as the handle covers it.
        return max(0.0, 1.0 - progress * 1.6)
    }

    // MARK: Handle

    private var handle: some View {
        let d = metrics.handleDiameter
        let centerX = metrics.handleCenterX(progress: progress)

        return ZStack {
            Circle()
                .fill(palette.handleFill)
                .overlay(
                    Circle().stroke(palette.handleStroke, lineWidth: 1)
                )
                .shadow(color: Color.black.opacity(0.35), radius: 3, x: 0, y: 1)
            glyph
        }
        .frame(width: d, height: d)
        .scaleEffect(locked ? 1.06 : 1.0)
        .offset(x: centerX - d / 2)
        .animation(.spring(response: 0.3, dampingFraction: 0.6), value: locked)
    }

    private var glyph: some View {
        Image(systemName: locked ? "checkmark" : "arrow.right")
            .font(.system(size: metrics.handleDiameter * 0.42, weight: .bold))
            .foregroundStyle(palette.glyph)
            .contentTransition(.symbolEffect(.replace))
    }
}

// MARK: - SlideToConfirmView_Palette (no app dependencies; literal colors)

private struct SlideToConfirmView_Palette {
    let trackBase = Color(red: 0.13, green: 0.11, blue: 0.18)
    let trackStroke = Color(red: 0.32, green: 0.28, blue: 0.42).opacity(0.7)
    let labelRest = Color(red: 0.78, green: 0.76, blue: 0.86).opacity(0.85)
    let handleFill = Color(red: 0.97, green: 0.97, blue: 1.0)
    let handleStroke = Color(red: 0.70, green: 0.66, blue: 0.85).opacity(0.5)
    let glyph = Color(red: 0.36, green: 0.20, blue: 0.78)

    var fillGradient: LinearGradient {
        LinearGradient(
            colors: [
                Color(red: 0.42, green: 0.28, blue: 0.92),
                Color(red: 0.55, green: 0.36, blue: 0.98),
                Color(red: 0.36, green: 0.52, blue: 0.99)
            ],
            startPoint: .leading,
            endPoint: .trailing
        )
    }
}
"""###,
        "mi-staggered-star-rating": ###"""
import SwiftUI

/// Staggered Star Rating
///
/// Drag across the row to fill stars left-to-right. Each newly filled star
/// pops with a staggered spring that ripples behind your finger, and the
/// whole row tints warmer as the score rises.
///
/// - `demo == true`  : self-driving PhaseAnimator loop that ramps the rating
///                     up and back down so the tile looks alive untouched.
/// - `demo == false` : a real interactive rating control driven by a single
///                     DragGesture (which also covers taps).
struct StaggeredStarRatingView: View {
    var demo: Bool = false

    private let starCount: Int = 5

    // The live rating. During interaction this tracks the finger continuously;
    // in demo mode it is driven by the PhaseAnimator phase.
    @State private var rating: Double = 0

    var body: some View {
        GeometryReader { geo in
            content(in: geo.size)
                .frame(maxWidth: .infinity, maxHeight: .infinity)
        }
        // .frame here keeps the GeometryReader from collapsing in a tile.
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    @ViewBuilder
    private func content(in size: CGSize) -> some View {
        if demo {
            demoBody(in: size)
        } else {
            interactiveBody(in: size)
        }
    }

    // MARK: - Demo (self-driving)

    @ViewBuilder
    private func demoBody(in size: CGSize) -> some View {
        // Integer phases give a crisp per-star pop at each step; a continuous
        // ramp would smear the left-to-right stagger. Using the auto-looping
        // PhaseAnimator initializer (no trigger) so the tile cycles forever.
        let phases: [Double] = [0, 1, 2, 3, 4, 5, 4, 3, 2, 1]
        PhaseAnimator(phases) { phase in
            row(rating: phase, in: size)
        } animation: { _ in
            .spring(response: 0.45, dampingFraction: 0.65)
        }
    }

    // MARK: - Interactive

    @ViewBuilder
    private func interactiveBody(in size: CGSize) -> some View {
        let metrics = StaggeredStarRatingView_StarMetrics(size: size, count: starCount)
        row(rating: rating, in: size)
            .contentShape(Rectangle())
            .gesture(dragGesture(metrics: metrics))
            // Gate haptics to interactive use so a grid of demo tiles
            // doesn't buzz the device continuously.
            .sensoryFeedback(.selection, trigger: Int(rating.rounded()))
    }

    private func dragGesture(metrics: StaggeredStarRatingView_StarMetrics) -> some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                rating = rating(forX: value.location.x, metrics: metrics)
            }
            .onEnded { value in
                let raw = rating(forX: value.location.x, metrics: metrics)
                // Snap to nearest half-star with a settling spring.
                let snapped = (raw * 2).rounded() / 2
                withAnimation(.spring(response: 0.35, dampingFraction: 0.6)) {
                    rating = snapped
                }
            }
    }

    /// Maps an x position within the row to a 0...count rating.
    private func rating(forX x: CGFloat, metrics: StaggeredStarRatingView_StarMetrics) -> Double {
        let local = x - metrics.leadingInset
        guard metrics.rowWidth > 0 else { return 0 }
        let frac = Double(local / metrics.rowWidth)
        let clamped = min(max(frac, 0), 1)
        return clamped * Double(starCount)
    }

    // MARK: - Row

    @ViewBuilder
    private func row(rating: Double, in size: CGSize) -> some View {
        let metrics = StaggeredStarRatingView_StarMetrics(size: size, count: starCount)
        HStack(spacing: metrics.spacing) {
            ForEach(0..<starCount, id: \.self) { index in
                StaggeredStarRatingView_StarCell(
                    fill: fillFraction(rating: rating, index: index),
                    isFilled: isFilled(rating: rating, index: index),
                    fillColor: warmthColor(rating: rating),
                    side: metrics.starSide,
                    delay: Double(index) * 0.05
                )
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // MARK: - Derived values

    /// Continuous 0...1 fill for a star — tracks the finger live.
    private func fillFraction(rating: Double, index: Int) -> CGFloat {
        let raw = rating - Double(index)
        return CGFloat(min(max(raw, 0), 1))
    }

    /// Discrete "this star counts as lit" — the spring/pop is keyed to this so
    /// the ripple lags behind the live fill instead of fighting the finger.
    private func isFilled(rating: Double, index: Int) -> Bool {
        rating - Double(index) >= 0.5
    }

    /// Pale gold -> warm amber as the score climbs. Interpolates the raw RGB
    /// components directly so there is no UIKit/UIColor dependency.
    private func warmthColor(rating: Double) -> Color {
        let t = min(max(rating / Double(starCount), 0), 1)
        // soft gold
        let cr: Double = 1.00, cg: Double = 0.82, cb: Double = 0.36
        // warm amber-red
        let wr: Double = 1.00, wg: Double = 0.42, wb: Double = 0.27
        return Color(
            red: cr + (wr - cr) * t,
            green: cg + (wg - cg) * t,
            blue: cb + (wb - cb) * t
        )
    }
}

// MARK: - Layout metrics

private struct StaggeredStarRatingView_StarMetrics {
    let starSide: CGFloat
    let spacing: CGFloat
    let leadingInset: CGFloat
    let rowWidth: CGFloat

    init(size: CGSize, count: Int) {
        let n = CGFloat(max(count, 1))
        // Size a star so the full row fits a tiny tile and a large detail area.
        let byWidth = size.width / (n + 1.5)
        let byHeight = size.height * 0.62
        let side = max(min(byWidth, byHeight), 8)
        self.starSide = side
        self.spacing = side * 0.22
        let totalRow = side * n + spacing * (n - 1)
        self.rowWidth = totalRow
        self.leadingInset = max((size.width - totalRow) / 2, 0)
    }
}

// MARK: - Single star

private struct StaggeredStarRatingView_StarCell: View {
    var fill: CGFloat        // 0...1 continuous fill (tracks finger)
    var isFilled: Bool       // discrete lit state (drives the pop)
    var fillColor: Color
    var side: CGFloat
    var delay: Double

    var body: some View {
        ZStack {
            // Empty outline — always legible, never blank.
            StaggeredStarRatingView_StarShape()
                .stroke(
                    Color(red: 0.42, green: 0.40, blue: 0.50),
                    style: StrokeStyle(lineWidth: max(side * 0.05, 1), lineJoin: .round)
                )
                .background(
                    StaggeredStarRatingView_StarShape().fill(Color(red: 0.16, green: 0.16, blue: 0.22))
                )

            // Filled portion, masked to a leading rectangle whose width
            // tracks the live fill fraction.
            StaggeredStarRatingView_StarShape()
                .fill(fillGradient)
                .overlay(glint)
                .mask(alignment: .leading) {
                    Rectangle()
                        .frame(width: side * fill)
                        .frame(maxWidth: .infinity, alignment: .leading)
                }
        }
        .frame(width: side, height: side)
        // The spring overshoot IS the pop; the per-index delay makes it ripple
        // left-to-right. Keyed to the discrete bool so it never lags the finger.
        .scaleEffect(isFilled ? 1.0 : 0.86, anchor: .center)
        .shadow(
            color: fillColor.opacity(isFilled ? 0.55 : 0),
            radius: side * 0.12, x: 0, y: 0
        )
        .animation(
            .spring(response: 0.34, dampingFraction: 0.5).delay(delay),
            value: isFilled
        )
        // Fill width itself follows the finger near-instantly.
        .animation(.linear(duration: 0.06), value: fill)
    }

    private var fillGradient: LinearGradient {
        LinearGradient(
            colors: [
                fillColor.opacity(0.95),
                fillColor
            ],
            startPoint: .top,
            endPoint: .bottom
        )
    }

    private var glint: some View {
        StaggeredStarRatingView_StarShape()
            .fill(
                LinearGradient(
                    colors: [Color.white.opacity(0.55), Color.white.opacity(0.0)],
                    startPoint: .topLeading,
                    endPoint: .center
                )
            )
            .blendMode(.screen)
            .opacity(0.7)
    }
}

// MARK: - Star geometry

private struct StaggeredStarRatingView_StarShape: Shape {
    var points: Int = 5
    var innerRatio: CGFloat = 0.42

    func path(in rect: CGRect) -> Path {
        var path = Path()
        let center = CGPoint(x: rect.midX, y: rect.midY)
        let outer = min(rect.width, rect.height) / 2
        let inner = outer * innerRatio
        let step = CGFloat.pi / CGFloat(max(points, 1))
        // Start at the top tip.
        var angle = -CGFloat.pi / 2
        for i in 0..<(max(points, 1) * 2) {
            let radius = (i % 2 == 0) ? outer : inner
            let pt = CGPoint(
                x: center.x + cos(angle) * radius,
                y: center.y + sin(angle) * radius
            )
            if i == 0 {
                path.move(to: pt)
            } else {
                path.addLine(to: pt)
            }
            angle += step
        }
        path.closeSubpath()
        return path
    }
}
"""###,
        "mi-stretch-pill-switch": ###"""
import SwiftUI

// MARK: - Stretch Pill Switch
//
// On toggle the knob stretches into an elongated capsule mid-travel then
// squashes back to a circle on arrival; the track inherits the same elastic
// deformation. The stretch is a per-frame function of a single progress scalar
// (stretch = sin(progress * .pi), peaking mid-travel), so it is computed inside
// Animatable conformances rather than interpolated endpoint-to-endpoint.
//
// demo == true  -> TimelineView(.animation) ping-pongs progress on a ~3s loop.
// demo == false -> a tap toggles isOn; withAnimation(.spring(bounce:0.5))
//                  drives `progress`, fed through an Animatable knob Shape +
//                  Animatable track-squash modifier that recompute each frame.

struct StretchPillSwitchView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { geo in
            content(in: geo.size)
                .frame(maxWidth: .infinity, maxHeight: .infinity)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    @ViewBuilder
    private func content(in size: CGSize) -> some View {
        if demo {
            StretchPillSwitchView_DemoSwitch(size: size)
        } else {
            StretchPillSwitchView_InteractiveSwitch(size: size)
        }
    }
}

// MARK: - Shared geometry / palette

private enum StretchPillSwitchView_PillPalette {
    static let offTrack = Color(red: 0.20, green: 0.20, blue: 0.26)
    static let onTrackTop = Color(red: 0.36, green: 0.78, blue: 0.55)
    static let onTrackBottom = Color(red: 0.20, green: 0.62, blue: 0.42)
    static let knobTop = Color(red: 0.99, green: 0.99, blue: 1.00)
    static let knobBottom = Color(red: 0.86, green: 0.88, blue: 0.93)
    static let glow = Color(red: 0.45, green: 0.95, blue: 0.68)
}

private struct StretchPillSwitchView_PillMetrics {
    let trackWidth: CGFloat
    let trackHeight: CGFloat
    let diameter: CGFloat
    let inset: CGFloat
    let origin: CGPoint   // top-left of the track within the canvas

    init(canvas: CGSize) {
        // Size everything off the smaller dimension so it reads at 120pt and large.
        let minDim = min(canvas.width, canvas.height)
        let h = minDim * 0.42
        let w = h * 1.85
        trackHeight = h
        trackWidth = w
        inset = h * 0.11
        diameter = h - inset * 2
        origin = CGPoint(x: (canvas.width - w) / 2.0,
                         y: (canvas.height - h) / 2.0)
    }

    // Track tint blends from off-grey to green as progress rises.
    func trackColor(progress p: CGFloat) -> Color {
        let t = max(0, min(1, p))
        let off = StretchPillSwitchView_PillPalette.offTrack
        let on = StretchPillSwitchView_PillPalette.onTrackBottom
        func mix(_ a: Double, _ b: Double) -> Double { a + (b - a) * Double(t) }
        let comp = on.componentsApprox
        let offComp = off.componentsApprox
        return Color(red: mix(offComp.r, comp.r),
                     green: mix(offComp.g, comp.g),
                     blue: mix(offComp.b, comp.b))
    }
}

private extension Color {
    // Coarse component readback for the off/on track blend. Hard-coded fall-back
    // values keep this dependency-free and deterministic.
    var componentsApprox: (r: Double, g: Double, b: Double) {
        if self == StretchPillSwitchView_PillPalette.offTrack { return (0.20, 0.20, 0.26) }
        return (0.20, 0.62, 0.42)
    }
}

// stretch peaks at mid-travel, zero (clean circle) at both ends.
private func stretchAmount(progress p: CGFloat) -> CGFloat {
    max(0, sin(p * .pi))
}

// MARK: - Animatable knob shape
//
// progress 0..1 = travel from left rest to right rest. The capsule width grows
// toward the destination edge (taffy "reaches ahead") while the trailing edge
// lags, then both resolve to a circle on arrival. animatableData = progress so
// the interpolated value is re-evaluated every frame.

private struct StretchPillSwitchView_KnobShape: Shape {
    var progress: CGFloat
    var metrics: StretchPillSwitchView_PillMetrics

    var animatableData: CGFloat {
        get { progress }
        set { progress = newValue }
    }

    func path(in rect: CGRect) -> Path {
        let m = metrics
        let d = m.diameter
        let stretch = stretchAmount(progress: progress)

        // Centre travel between the two rest centres.
        let leftCenter = m.inset + d / 2.0
        let rightCenter = m.trackWidth - m.inset - d / 2.0
        let center = leftCenter + (rightCenter - leftCenter) * progress

        // Taffy: extra length splits asymmetrically toward the travel direction.
        let maxStretch = d * 0.85
        let extra = stretch * maxStretch
        // direction: +1 moving right, -1 moving left (based on travel sign)
        let dir: CGFloat = progress >= 0.5 ? 1.0 : -1.0
        let lead = extra * 0.62      // leading edge reaches ahead
        let trail = extra * 0.38     // trailing edge lags

        let halfBase = d / 2.0
        let leadingX = center + dir * (halfBase + lead)
        let trailingX = center - dir * (halfBase + trail)
        let minX = min(leadingX, trailingX)
        let maxX = max(leadingX, trailingX)

        let capsuleRect = CGRect(x: minX,
                                 y: m.trackHeight / 2.0 - d / 2.0,
                                 width: maxX - minX,
                                 height: d)
        return Capsule(style: .circular).path(in: capsuleRect)
    }
}

// MARK: - Animatable track squash
//
// Vertical scale shrinks at mid-travel (inheriting the knob's elastic
// deformation) and returns to full height at the ends. animatableData = progress
// so the scale is recomputed per frame, not tweened endpoint-to-endpoint.

private struct StretchPillSwitchView_TrackSquash: ViewModifier, Animatable {
    var progress: CGFloat

    var animatableData: CGFloat {
        get { progress }
        set { progress = newValue }
    }

    func body(content: Content) -> some View {
        let stretch = stretchAmount(progress: progress)
        let yScale = 1.0 - stretch * 0.15   // floor ~0.85, tasteful
        // Knob bulging widens the track a hair horizontally for cohesion.
        let xScale = 1.0 + stretch * 0.025
        return content.scaleEffect(x: xScale, y: yScale, anchor: .center)
    }
}

// MARK: - Reusable visual stack

private struct StretchPillSwitchView_PillBody: View {
    var progress: CGFloat
    var metrics: StretchPillSwitchView_PillMetrics

    var body: some View {
        let m = metrics
        ZStack(alignment: .topLeading) {
            track
            knob
        }
        .frame(width: m.trackWidth, height: m.trackHeight, alignment: .topLeading)
    }

    private var track: some View {
        let m = metrics
        let p = max(0, min(1, progress))
        return ZStack {
            Capsule(style: .circular)
                .fill(m.trackColor(progress: p))
            // Green sheen fades in with progress.
            Capsule(style: .circular)
                .fill(
                    LinearGradient(
                        colors: [StretchPillSwitchView_PillPalette.onTrackTop, StretchPillSwitchView_PillPalette.onTrackBottom],
                        startPoint: .top, endPoint: .bottom
                    )
                )
                .opacity(Double(p))
            Capsule(style: .circular)
                .strokeBorder(Color.white.opacity(0.08), lineWidth: 1)
        }
        .frame(width: m.trackWidth, height: m.trackHeight)
        .modifier(StretchPillSwitchView_TrackSquash(progress: progress))
        .shadow(color: StretchPillSwitchView_PillPalette.glow.opacity(Double(stretchAmount(progress: progress)) * 0.35),
                radius: 8)
    }

    private var knob: some View {
        let m = metrics
        return StretchPillSwitchView_KnobShape(progress: progress, metrics: m)
            .fill(
                LinearGradient(
                    colors: [StretchPillSwitchView_PillPalette.knobTop, StretchPillSwitchView_PillPalette.knobBottom],
                    startPoint: .top, endPoint: .bottom
                )
            )
            .overlay {
                StretchPillSwitchView_KnobShape(progress: progress, metrics: m)
                    .stroke(Color.black.opacity(0.06), lineWidth: 1)
            }
            .frame(width: m.trackWidth, height: m.trackHeight, alignment: .topLeading)
            .shadow(color: Color.black.opacity(0.28),
                    radius: 3, x: 0, y: 2)
    }
}

// MARK: - Demo (self-driving)

private struct StretchPillSwitchView_DemoSwitch: View {
    var size: CGSize
    private let period: Double = 3.0

    var body: some View {
        let m = StretchPillSwitchView_PillMetrics(canvas: size)
        TimelineView(.animation) { timeline in
            let p = pingPongProgress(at: timeline.date)
            StretchPillSwitchView_PillBody(progress: p, metrics: m)
        }
    }

    private func pingPongProgress(at date: Date) -> CGFloat {
        let t = date.timeIntervalSinceReferenceDate
        // 0->1->0 over `period` seconds, eased so the dwell at the ends reads.
        let phase = (t.truncatingRemainder(dividingBy: period)) / period // 0..1
        let tri = phase < 0.5 ? phase * 2.0 : (1.0 - phase) * 2.0          // 0..1..0
        // ease for a spring-like settle feel
        let eased = easeInOut(tri)
        return CGFloat(eased)
    }

    private func easeInOut(_ x: Double) -> Double {
        let c = max(0, min(1, x))
        return c < 0.5 ? 2 * c * c : 1 - pow(-2 * c + 2, 2) / 2
    }
}

// MARK: - Interactive (tap to toggle)

private struct StretchPillSwitchView_InteractiveSwitch: View {
    var size: CGSize
    @State private var isOn: Bool = false
    @State private var progress: CGFloat = 0

    var body: some View {
        let m = StretchPillSwitchView_PillMetrics(canvas: size)
        StretchPillSwitchView_PillBody(progress: progress, metrics: m)
            .contentShape(Capsule())
            .onTapGesture { toggle() }
            .sensoryFeedback(.impact(flexibility: .soft), trigger: isOn)
    }

    private func toggle() {
        withAnimation(.spring(response: 0.45, dampingFraction: 0.55)) {
            isOn.toggle()
            progress = isOn ? 1 : 0
        }
    }
}
"""###,
        "mi-swipe-reveal-trash": ###"""
import SwiftUI

// MARK: - Swipe-Reveal Trash
// Swiping a row leftward reveals a trash action whose lid lifts and bin mouth
// widens proportionally to the pull; released past threshold the row collapses
// inward as if swallowed, then resets. The bin itself is always visible so the
// tile is never blank.
struct SwipeRevealTrashView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { geo in
            content(in: geo.size)
                .frame(maxWidth: .infinity, maxHeight: .infinity)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    @ViewBuilder
    private func content(in size: CGSize) -> some View {
        if demo {
            SwipeRevealTrashView_DemoDriver(size: size)
        } else {
            SwipeRevealTrashView_InteractiveDriver(size: size)
        }
    }
}

// MARK: - SwipeRevealTrashView_Palette

private enum SwipeRevealTrashView_Palette {
    static let backdrop = Color(red: 0.078, green: 0.063, blue: 0.098)
    static let trayTop = Color(red: 0.745, green: 0.169, blue: 0.196)
    static let trayBottom = Color(red: 0.604, green: 0.106, blue: 0.137)
    static let binBody = Color(red: 0.918, green: 0.925, blue: 0.945)
    static let binShade = Color(red: 0.792, green: 0.808, blue: 0.847)
    static let binMouth = Color(red: 0.137, green: 0.110, blue: 0.157)
    static let lidTop = Color(red: 0.965, green: 0.969, blue: 0.984)
    static let lidEdge = Color(red: 0.808, green: 0.824, blue: 0.863)
    static let rowFill = Color(red: 0.188, green: 0.157, blue: 0.235)
    static let rowStroke = Color(red: 0.388, green: 0.349, blue: 0.475)
    static let rowText = Color(red: 0.918, green: 0.910, blue: 0.949)
    static let rowSubText = Color(red: 0.616, green: 0.596, blue: 0.690)
    static let avatar = Color(red: 0.498, green: 0.408, blue: 0.831)
}

// MARK: - Demo driver (self-running loop)

private struct SwipeRevealTrashView_DemoDriver: View {
    let size: CGSize

    enum Phase: CaseIterable {
        case closed, revealing, swallowing, reset
    }

    var body: some View {
        PhaseAnimator(Phase.allCases) { phase in
            SwipeRevealTrashView_SwipeStage(
                size: size,
                progress: progress(for: phase),
                rowScale: rowScale(for: phase),
                rowOpacity: rowOpacity(for: phase),
                showRow: true
            )
        } animation: { phase in
            switch phase {
            case .closed:     return .easeInOut(duration: 0.5)
            case .revealing:  return .easeInOut(duration: 0.9)
            case .swallowing: return .spring(response: 0.45, dampingFraction: 0.62)
            case .reset:      return .spring(response: 0.55, dampingFraction: 0.85)
            }
        }
    }

    // Reveal progress 0...1 (and slightly beyond at the swallow to feel forceful).
    private func progress(for phase: Phase) -> CGFloat {
        switch phase {
        case .closed:     return 0.0
        case .revealing:  return 0.82
        case .swallowing: return 1.0
        case .reset:      return 0.0
        }
    }

    private func rowScale(for phase: Phase) -> CGFloat {
        switch phase {
        case .swallowing: return 0.0
        default:          return 1.0
        }
    }

    private func rowOpacity(for phase: Phase) -> Double {
        switch phase {
        case .swallowing: return 0.0
        case .reset:      return 1.0
        default:          return 1.0
        }
    }
}

// MARK: - Interactive driver (real DragGesture)

private struct SwipeRevealTrashView_InteractiveDriver: View {
    let size: CGSize

    @State private var progress: CGFloat = 0      // committed reveal 0...1
    @State private var dragProgress: CGFloat = 0  // live drag contribution
    @State private var rowScale: CGFloat = 1
    @State private var rowOpacity: Double = 1
    @State private var showRow: Bool = true
    @State private var crossedThreshold: Bool = false
    @State private var armedHaptic: Bool = false
    @State private var deletedHaptic: Bool = false

    private let threshold: CGFloat = 0.78

    var body: some View {
        SwipeRevealTrashView_SwipeStage(
            size: size,
            progress: effectiveProgress,
            rowScale: rowScale,
            rowOpacity: rowOpacity,
            showRow: showRow
        )
        .contentShape(Rectangle())
        .gesture(dragGesture)
        .sensoryFeedback(.impact(weight: .medium), trigger: armedHaptic)
        .sensoryFeedback(.success, trigger: deletedHaptic)
    }

    private var effectiveProgress: CGFloat {
        min(1, max(0, progress + dragProgress))
    }

    private var dragGesture: some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                guard showRow else { return }
                // Horizontal-dominant left swipe drives the reveal.
                guard abs(value.translation.width) > abs(value.translation.height) else { return }
                let revealDistance = max(size.width * 0.55, 80)
                let pull = max(0, -value.translation.width)
                let p = min(1.15, pull / revealDistance)
                dragProgress = p
                handleThreshold(for: effectiveProgress)
            }
            .onEnded { value in
                let final = effectiveProgress
                dragProgress = 0
                if final >= threshold {
                    swallow()
                } else {
                    springClosed()
                }
            }
    }

    private func handleThreshold(for value: CGFloat) {
        if value >= threshold, !crossedThreshold {
            crossedThreshold = true
            armedHaptic.toggle()
        } else if value < threshold, crossedThreshold {
            crossedThreshold = false
        }
    }

    private func swallow() {
        deletedHaptic.toggle()
        withAnimation(.spring(response: 0.42, dampingFraction: 0.6)) {
            progress = 1
            rowScale = 0
            rowOpacity = 0
        }
        // Reset after the gulp so the detail view is never permanently empty.
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.55) {
            showRow = false
            withAnimation(.spring(response: 0.6, dampingFraction: 0.85)) {
                progress = 0
            }
            DispatchQueue.main.asyncAfter(deadline: .now() + 0.25) {
                rowScale = 1
                showRow = true
                withAnimation(.spring(response: 0.55, dampingFraction: 0.8)) {
                    rowOpacity = 1
                }
            }
        }
    }

    private func springClosed() {
        crossedThreshold = false
        withAnimation(.spring(response: 0.45, dampingFraction: 0.78)) {
            progress = 0
        }
    }
}

// MARK: - Composited stage (shared by demo + interactive)

private struct SwipeRevealTrashView_SwipeStage: View {
    let size: CGSize
    let progress: CGFloat
    let rowScale: CGFloat
    let rowOpacity: Double
    let showRow: Bool

    var body: some View {
        let metrics = SwipeRevealTrashView_StageMetrics(size: size)
        ZStack {
            SwipeRevealTrashView_Palette.backdrop
            // Red action tray (always present behind the row).
            actionTray(metrics)
            // The trash bin sits inside the tray; it is the persistent element.
            SwipeRevealTrashView_TrashBin(progress: progress, metrics: metrics)
                .frame(width: metrics.binWidth, height: metrics.trayHeight)
                .position(x: metrics.binCenterX, y: metrics.rowCenterY)
            // The row that slides away and gets gulped.
            if showRow {
                SwipeRevealTrashView_RowContent(metrics: metrics)
                    .frame(width: metrics.rowWidth, height: metrics.rowHeight * rowScale)
                    .opacity(rowOpacity)
                    .offset(x: -progress * metrics.revealOffset)
                    .position(x: metrics.rowWidth / 2, y: metrics.rowCenterY)
            }
        }
        .frame(width: size.width, height: size.height)
        .clipped()
    }

    private func actionTray(_ m: SwipeRevealTrashView_StageMetrics) -> some View {
        RoundedRectangle(cornerRadius: m.corner, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [SwipeRevealTrashView_Palette.trayTop, SwipeRevealTrashView_Palette.trayBottom],
                    startPoint: .top,
                    endPoint: .bottom
                )
            )
            .frame(width: m.rowWidth, height: m.rowHeight)
            .position(x: m.rowWidth / 2, y: m.rowCenterY)
    }
}

// MARK: - Layout metrics derived from tile size

private struct SwipeRevealTrashView_StageMetrics {
    let size: CGSize
    let rowWidth: CGFloat
    let rowHeight: CGFloat
    let rowCenterY: CGFloat
    let corner: CGFloat
    let trayHeight: CGFloat
    let binWidth: CGFloat
    let binCenterX: CGFloat
    let revealOffset: CGFloat

    init(size: CGSize) {
        self.size = size
        let w = size.width
        let h = size.height
        // Row fills most of the width, centered vertically with breathing room.
        self.rowWidth = w
        self.rowHeight = min(h * 0.62, w * 0.7)
        self.rowCenterY = h / 2
        self.corner = min(rowHeight, rowWidth) * 0.16
        self.trayHeight = rowHeight
        // Bin scaled to the tray height so it always reads as a bin at 120pt.
        self.binWidth = min(rowHeight * 0.62, w * 0.34)
        self.binCenterX = w - binWidth * 0.5 - w * 0.07
        // How far the row slides left when fully revealed.
        self.revealOffset = binWidth * 1.55
    }
}

// MARK: - Row content

private struct SwipeRevealTrashView_RowContent: View {
    let metrics: SwipeRevealTrashView_StageMetrics

    var body: some View {
        let m = metrics
        let pad = m.rowHeight * 0.18
        HStack(spacing: m.rowHeight * 0.16) {
            Circle()
                .fill(
                    LinearGradient(
                        colors: [SwipeRevealTrashView_Palette.avatar, SwipeRevealTrashView_Palette.avatar.opacity(0.65)],
                        startPoint: .topLeading,
                        endPoint: .bottomTrailing
                    )
                )
                .overlay(
                    Image(systemName: "envelope.fill")
                        .font(.system(size: m.rowHeight * 0.2, weight: .semibold))
                        .foregroundStyle(.white.opacity(0.92))
                )
                .frame(width: m.rowHeight * 0.46, height: m.rowHeight * 0.46)
            VStack(alignment: .leading, spacing: m.rowHeight * 0.1) {
                RoundedRectangle(cornerRadius: m.rowHeight * 0.06, style: .continuous)
                    .fill(SwipeRevealTrashView_Palette.rowText)
                    .frame(width: m.rowWidth * 0.32, height: m.rowHeight * 0.14)
                RoundedRectangle(cornerRadius: m.rowHeight * 0.05, style: .continuous)
                    .fill(SwipeRevealTrashView_Palette.rowSubText)
                    .frame(width: m.rowWidth * 0.46, height: m.rowHeight * 0.1)
            }
            Spacer(minLength: 0)
        }
        .padding(.horizontal, pad)
        .frame(width: m.rowWidth, height: m.rowHeight, alignment: .leading)
        .background(
            RoundedRectangle(cornerRadius: m.corner, style: .continuous)
                .fill(SwipeRevealTrashView_Palette.rowFill)
                .overlay(
                    RoundedRectangle(cornerRadius: m.corner, style: .continuous)
                        .strokeBorder(SwipeRevealTrashView_Palette.rowStroke.opacity(0.6), lineWidth: 1)
                )
        )
        .clipShape(RoundedRectangle(cornerRadius: m.corner, style: .continuous))
    }
}

// MARK: - Trash bin (body + widening mouth + lifting lid)

private struct SwipeRevealTrashView_TrashBin: View {
    let progress: CGFloat
    let metrics: SwipeRevealTrashView_StageMetrics

    var body: some View {
        GeometryReader { geo in
            bin(in: geo.size)
        }
    }

    private func bin(in size: CGSize) -> some View {
        let w = size.width
        let h = size.height
        // Bin body occupies the lower ~64% of the available height.
        let bodyHeight = h * 0.62
        let bodyWidth = w * 0.74
        let bodyTop = h * 0.34
        let bodyX = (w - bodyWidth) / 2

        // Mouth widens with progress.
        let mouthWidth = bodyWidth * (0.5 + 0.42 * progress)
        let mouthHeight = bodyHeight * 0.2
        let mouthX = (w - mouthWidth) / 2
        let mouthY = bodyTop - mouthHeight * 0.35

        // Lid lifts (rotates) about its right hinge as progress rises.
        let lidWidth = bodyWidth * 1.06
        let lidHeight = h * 0.12
        let lidAngle = Angle(degrees: -Double(progress) * 62)

        return ZStack(alignment: .topLeading) {
            // Body
            binBody(width: bodyWidth, height: bodyHeight)
                .offset(x: bodyX, y: bodyTop)

            // Dark mouth opening
            Capsule(style: .continuous)
                .fill(SwipeRevealTrashView_Palette.binMouth)
                .frame(width: mouthWidth, height: mouthHeight)
                .offset(x: mouthX, y: mouthY)
                .overlay(
                    Capsule(style: .continuous)
                        .strokeBorder(Color.black.opacity(0.28), lineWidth: 1)
                        .frame(width: mouthWidth, height: mouthHeight)
                        .offset(x: mouthX, y: mouthY)
                )

            // Lid (a rounded slab) hinged at its trailing corner.
            lid(width: lidWidth, height: lidHeight)
                .rotationEffect(lidAngle, anchor: .bottomTrailing)
                .frame(width: lidWidth, height: lidHeight, alignment: .bottomTrailing)
                .offset(x: (w - lidWidth) / 2, y: bodyTop - lidHeight * 0.78)

            // Trash glyph centered on the body, fades as the mouth opens.
            Image(systemName: "trash.fill")
                .font(.system(size: bodyHeight * 0.34, weight: .semibold))
                .foregroundStyle(SwipeRevealTrashView_Palette.trayBottom.opacity(0.75))
                .opacity(Double(0.85 - 0.85 * progress))
                .frame(width: bodyWidth, height: bodyHeight)
                .offset(x: bodyX, y: bodyTop + bodyHeight * 0.06)
        }
        .frame(width: w, height: h)
    }

    private func binBody(width: CGFloat, height: CGFloat) -> some View {
        SwipeRevealTrashView_BinBodyShape()
            .fill(
                LinearGradient(
                    colors: [SwipeRevealTrashView_Palette.binBody, SwipeRevealTrashView_Palette.binShade],
                    startPoint: .topLeading,
                    endPoint: .bottomTrailing
                )
            )
            .overlay(
                SwipeRevealTrashView_BinBodyShape()
                    .stroke(Color.black.opacity(0.12), lineWidth: 1)
            )
            .overlay(ribbing(width: width, height: height))
            .frame(width: width, height: height)
    }

    private func ribbing(width: CGFloat, height: CGFloat) -> some View {
        HStack(spacing: width * 0.12) {
            ForEach(0..<3, id: \.self) { _ in
                Capsule()
                    .fill(SwipeRevealTrashView_Palette.binShade.opacity(0.7))
                    .frame(width: width * 0.05)
            }
        }
        .frame(width: width * 0.6, height: height * 0.62)
        .padding(.top, height * 0.18)
    }

    private func lid(width: CGFloat, height: CGFloat) -> some View {
        RoundedRectangle(cornerRadius: height * 0.42, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [SwipeRevealTrashView_Palette.lidTop, SwipeRevealTrashView_Palette.lidEdge],
                    startPoint: .top,
                    endPoint: .bottom
                )
            )
            .overlay(
                RoundedRectangle(cornerRadius: height * 0.42, style: .continuous)
                    .stroke(Color.black.opacity(0.12), lineWidth: 1)
            )
            .overlay(
                // Small handle nub on the lid.
                Capsule()
                    .fill(SwipeRevealTrashView_Palette.lidEdge)
                    .frame(width: width * 0.22, height: height * 0.42)
                    .offset(y: -height * 0.5)
            )
    }
}

// MARK: - Bin body shape (tapered trapezoid)

private struct SwipeRevealTrashView_BinBodyShape: Shape {
    func path(in rect: CGRect) -> Path {
        var p = Path()
        let inset = rect.width * 0.1
        let r = rect.width * 0.14
        let topLeft = CGPoint(x: rect.minX, y: rect.minY)
        let topRight = CGPoint(x: rect.maxX, y: rect.minY)
        let botLeft = CGPoint(x: rect.minX + inset, y: rect.maxY)
        let botRight = CGPoint(x: rect.maxX - inset, y: rect.maxY)

        p.move(to: topLeft)
        p.addLine(to: topRight)
        p.addLine(to: CGPoint(x: botRight.x + r, y: botRight.y - r))
        p.addQuadCurve(
            to: CGPoint(x: botRight.x - r, y: botRight.y),
            control: CGPoint(x: botRight.x, y: botRight.y)
        )
        p.addLine(to: CGPoint(x: botLeft.x + r, y: botLeft.y))
        p.addQuadCurve(
            to: CGPoint(x: botLeft.x - r, y: botLeft.y - r),
            control: CGPoint(x: botLeft.x, y: botLeft.y)
        )
        p.closeSubpath()
        return p
    }
}
"""###,
        "mi-tactile-counter-flip": ###"""
import SwiftUI

// MARK: - Tactile Like Counter Flip
// A reaction count where the new digit slides up on a hinged flap from behind
// the old one with a split-flap snap and a tiny dust puff.
//
// demo == true  -> self-driving TimelineView loop auto-increments the count,
//                  playing the single hinged flap snap + dust puff on each tick.
// demo == false -> a tappable like button increments the count, driving the same flip.

struct TactileCounterFlipView: View {

    var demo: Bool = false

    var body: some View {
        GeometryReader { proxy in
            let size = proxy.size
            let unit = min(size.width, size.height)

            ZStack {
                backdrop
                Group {
                    if demo {
                        TactileCounterFlipView_DemoLoop(unit: unit)
                    } else {
                        TactileCounterFlipView_Interactive(unit: unit)
                    }
                }
            }
            .frame(width: size.width, height: size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    private var backdrop: some View {
        LinearGradient(
            colors: [
                Color(red: 0.10, green: 0.08, blue: 0.13),
                Color(red: 0.05, green: 0.04, blue: 0.07)
            ],
            startPoint: .top,
            endPoint: .bottom
        )
    }
}

// MARK: - Demo (self-driving)

private struct TactileCounterFlipView_DemoLoop: View {
    let unit: CGFloat

    // Loop timing: a full cycle is `cycle` seconds; the flip happens in the
    // last `flipDur` seconds. The count increments once per cycle.
    private let cycle: Double = 3.0
    private let flipDur: Double = 0.7
    private let baseCount: Int = 1247

    // Anchor the loop to when this view appeared so the count starts near
    // `baseCount` instead of being derived from absolute reference time
    // (which would render a ~9-digit number).
    @State private var epoch: Double = Date().timeIntervalSinceReferenceDate

    var body: some View {
        TimelineView(.animation) { timeline in
            let now = timeline.date.timeIntervalSinceReferenceDate
            let elapsed = max(0, now - epoch)
            let phase = elapsed.truncatingRemainder(dividingBy: cycle)
            let completed = Int(elapsed / cycle)

            // Flip window sits at the end of the cycle.
            let flipStart = cycle - flipDur
            let inFlip = phase >= flipStart
            let rawProgress = inFlip ? (phase - flipStart) / flipDur : 0.0
            let progress = flipEase(rawProgress)

            // Before the flip lands the card still reads the "from" value;
            // once we cross into a new cycle the increment is already baked in.
            let fromValue = baseCount + completed
            let toValue = fromValue + 1

            // Time since the flap snapped to 90 degrees (mid-cycle), for the puff.
            let landPhase = flipStart + flipDur * 0.5
            let sinceLand = phase - landPhase

            TactileCounterFlipView_FlipCounter(
                unit: unit,
                fromValue: fromValue,
                toValue: toValue,
                progress: progress,
                puffSinceLand: sinceLand,
                pressGlow: inFlip ? 1.0 : 0.0
            )
        }
    }

    // Mechanical ease: quick fall, then a tiny settle handled by the card itself.
    private func flipEase(_ x: Double) -> Double {
        let c = min(max(x, 0), 1)
        return 1 - pow(1 - c, 2.4)
    }
}

// MARK: - TactileCounterFlipView_Interactive (tap to like)

private struct TactileCounterFlipView_Interactive: View {
    let unit: CGFloat

    @State private var value: Int = 1247
    @State private var fromValue: Int = 1247
    @State private var progress: Double = 0
    @State private var puffSinceLand: Double = -1
    @State private var pressGlow: Double = 0
    @State private var liked: Bool = false
    @State private var puffTrigger: Int = 0

    var body: some View {
        ZStack {
            TactileCounterFlipView_FlipCounter(
                unit: unit,
                fromValue: fromValue,
                toValue: fromValue + 1,
                progress: progress,
                puffSinceLand: puffSinceLand,
                pressGlow: pressGlow
            )
        }
        .contentShape(Rectangle())
        .onTapGesture { trigger() }
        .sensoryFeedback(.impact(weight: .light), trigger: puffTrigger)
    }

    private func trigger() {
        // Don't stack flips on top of one another mid-animation.
        guard progress == 0 || progress >= 1 else { return }

        liked.toggle()
        fromValue = value
        progress = 0
        pressGlow = 1

        // Drop the flap (0 -> 1) with a snappy mechanical curve.
        withAnimation(.spring(response: 0.34, dampingFraction: 0.62)) {
            progress = 1
        }

        // Fire the dust puff at the mid-point when the flap "lands".
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.16) {
            value += 1
            puffTrigger += 1
            animatePuff()
        }

        // Reset for the next tap once the settle finishes.
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.55) {
            progress = 0
            withAnimation(.easeOut(duration: 0.3)) { pressGlow = 0 }
        }
    }

    private func animatePuff() {
        puffSinceLand = 0
        let start = Date()
        // Drive the puff fade with a short manual ticker.
        Timer.scheduledTimer(withTimeInterval: 1.0 / 60.0, repeats: true) { tmr in
            let elapsed = Date().timeIntervalSince(start)
            puffSinceLand = elapsed
            if elapsed > 0.55 {
                tmr.invalidate()
                puffSinceLand = -1
            }
        }
    }
}

// MARK: - Shared flip card

/// Renders the split-flap counter for a given flip `progress` (0...1).
/// At rest (progress 0 or 1) the flap and background read the same digit so it
/// looks static; mid-flip the background already shows the NEW value while the
/// flap (the OLD value's top half) hinges down to reveal it.
private struct TactileCounterFlipView_FlipCounter: View {
    let unit: CGFloat
    let fromValue: Int
    let toValue: Int
    let progress: Double        // 0 = closed (shows from), 1 = open (shows to)
    let puffSinceLand: Double    // seconds since flap snapped; < 0 = no puff
    let pressGlow: Double        // 0...1 extra glow while active

    var body: some View {
        let cardW = unit * 0.62
        let cardH = unit * 0.56
        let corner = cardH * 0.16

        // Once the flap passes the half-way point the new value is committed.
        let committed = progress >= 0.5
        let backgroundValue = committed ? toValue : fromValue
        let flapShowsValue = fromValue

        // Flap rotation 0 -> 90 degrees, clamped so the backface never mirrors.
        let angle = min(progress, 1.0) * 90.0
        let flapHidden = progress >= 0.999

        VStack(spacing: cardH * 0.18) {
            heart(size: unit * 0.16)
            ZStack {
                // The static back card painting the current/destination digit.
                cardFace(value: backgroundValue, w: cardW, h: cardH, corner: corner)

                // Center seam.
                Rectangle()
                    .fill(Color.black.opacity(0.55))
                    .frame(width: cardW, height: max(1, cardH * 0.012))

                // The falling flap: OLD value's TOP half hinging down from the top.
                // The flap view is half-card-height; rotate it about its OWN bottom
                // edge (the card's center seam), then pin it to the top of the card.
                if !flapHidden {
                    topHalf(value: flapShowsValue, w: cardW, h: cardH, corner: corner)
                        .rotation3DEffect(
                            .degrees(angle),
                            axis: (x: 1, y: 0, z: 0),
                            anchor: .bottom,
                            perspective: 0.55
                        )
                        .shadow(color: .black.opacity(0.35 * progress), radius: 4, y: 3)
                        // Pin the half-height flap to the top half of the card.
                        .frame(width: cardW, height: cardH, alignment: .top)
                }

                // Dust puff at the hinge line on snap.
                TactileCounterFlipView_DustPuff(since: puffSinceLand, width: cardW)
                    .frame(width: cardW, height: cardH * 0.5, alignment: .bottom)
                    .offset(y: -cardH * 0.02)
            }
            .frame(width: cardW, height: cardH)
            .shadow(color: warmGlow.opacity(0.45 * pressGlow), radius: 14)
            .compositingGroup()

            label(size: unit * 0.085)
        }
    }

    // MARK: card faces

    private func cardFace(value: Int, w: CGFloat, h: CGFloat, corner: CGFloat) -> some View {
        RoundedRectangle(cornerRadius: corner, style: .continuous)
            .fill(cardGradient)
            .overlay(
                RoundedRectangle(cornerRadius: corner, style: .continuous)
                    .strokeBorder(Color.white.opacity(0.06), lineWidth: 1)
            )
            .overlay(digitText(value).frame(width: w, height: h))
            .frame(width: w, height: h)
    }

    /// The top half of a card showing `value`: a full card clipped to its upper half.
    private func topHalf(value: Int, w: CGFloat, h: CGFloat, corner: CGFloat) -> some View {
        RoundedRectangle(cornerRadius: corner, style: .continuous)
            .fill(flapGradient)
            .overlay(
                RoundedRectangle(cornerRadius: corner, style: .continuous)
                    .strokeBorder(Color.white.opacity(0.08), lineWidth: 1)
            )
            .overlay(digitText(value).frame(width: w, height: h))
            .frame(width: w, height: h)
            // Keep only the upper half.
            .frame(height: h * 0.5, alignment: .top)
            .clipped()
    }

    private func digitText(_ value: Int) -> some View {
        Text(formatted(value))
            .font(.system(size: unit * 0.30, weight: .heavy, design: .rounded))
            .monospacedDigit()
            .foregroundStyle(
                LinearGradient(
                    colors: [Color(red: 1.0, green: 0.97, blue: 0.92),
                             Color(red: 0.86, green: 0.83, blue: 0.80)],
                    startPoint: .top, endPoint: .bottom
                )
            )
            .minimumScaleFactor(0.3)
            .lineLimit(1)
    }

    // Show the full integer (with grouping) so a single +1 visibly flips the
    // last digit. A "k"-rounded format would make consecutive counts identical.
    private func formatted(_ value: Int) -> String {
        var result = ""
        let digits = Array(String(abs(value)))
        let count = digits.count
        for (i, ch) in digits.enumerated() {
            if i > 0 && (count - i) % 3 == 0 {
                result.append(",")
            }
            result.append(ch)
        }
        return value < 0 ? "-" + result : result
    }

    // MARK: chrome

    private func heart(size: CGFloat) -> some View {
        let beat = 1.0 + 0.12 * pressGlow
        return Image(systemName: "heart.fill")
            .font(.system(size: size, weight: .bold))
            .foregroundStyle(
                LinearGradient(
                    colors: [Color(red: 1.0, green: 0.42, blue: 0.52),
                             Color(red: 0.95, green: 0.25, blue: 0.42)],
                    startPoint: .topLeading, endPoint: .bottomTrailing
                )
            )
            .scaleEffect(beat)
            .shadow(color: Color(red: 1.0, green: 0.3, blue: 0.45).opacity(0.6 * pressGlow),
                    radius: 8)
            .animation(.spring(response: 0.3, dampingFraction: 0.5), value: pressGlow)
    }

    private func label(size: CGFloat) -> some View {
        Text("LIKES")
            .font(.system(size: size, weight: .semibold, design: .rounded))
            .tracking(size * 0.35)
            .foregroundStyle(Color.white.opacity(0.4))
    }

    // MARK: palettes

    private var cardGradient: LinearGradient {
        LinearGradient(
            colors: [Color(red: 0.20, green: 0.17, blue: 0.24),
                     Color(red: 0.12, green: 0.10, blue: 0.15)],
            startPoint: .top, endPoint: .bottom
        )
    }

    private var flapGradient: LinearGradient {
        LinearGradient(
            colors: [Color(red: 0.24, green: 0.21, blue: 0.28),
                     Color(red: 0.17, green: 0.14, blue: 0.20)],
            startPoint: .top, endPoint: .bottom
        )
    }

    private var warmGlow: Color {
        Color(red: 1.0, green: 0.55, blue: 0.45)
    }
}

// MARK: - Dust puff (Canvas, fully derived from `since`)

private struct TactileCounterFlipView_DustPuff: View {
    let since: Double   // seconds since the flap landed; < 0 means inactive
    let width: CGFloat

    // Fixed particle directions so the puff is deterministic and cheap.
    private let dirs: [CGPoint] = [
        CGPoint(x: -1.0, y: -0.2), CGPoint(x: -0.6, y: -0.6),
        CGPoint(x: -0.2, y: -0.9), CGPoint(x:  0.2, y: -0.9),
        CGPoint(x:  0.6, y: -0.6), CGPoint(x:  1.0, y: -0.2),
        CGPoint(x: -0.85, y: 0.1), CGPoint(x:  0.85, y: 0.1)
    ]

    var body: some View {
        Canvas { ctx, size in
            guard since >= 0 else { return }
            let life = 0.5
            let p = min(max(since / life, 0), 1)
            guard p < 1 else { return }

            let opacity = (1.0 - p) * 0.8
            let spread = width * 0.42 * p
            let originX = size.width * 0.5
            let originY = size.height          // hinge line at the bottom of this band
            let r = max(0.6, width * 0.018 * (1.0 - 0.4 * p))

            for d in dirs {
                let cx = originX + CGFloat(d.x) * spread
                let cy = originY + CGFloat(d.y) * spread
                let rect = CGRect(x: cx - r, y: cy - r, width: r * 2, height: r * 2)
                ctx.fill(
                    Path(ellipseIn: rect),
                    with: .color(Color(red: 0.86, green: 0.82, blue: 0.78).opacity(opacity))
                )
            }
        }
        .allowsHitTesting(false)
    }
}
"""###,
        "mi-thumb-flip-like": ###"""
import SwiftUI

// MARK: - Thumb-Flip Like
// A thumbs-up that does a quick 3D flip on tap (or auto in demo), rotating
// from outline to filled with a knuckle-crack overshoot and a faint upward float.
//
// Implementation notes:
// - The flip is two-staged (rest -> edge-on, swap symbol + jump, edge-on -> rest)
//   so the rendered thumb is NEVER horizontally mirrored at rest. A naive 0<->180
//   rotation3DEffect(axis:.y) mirrors a non-symmetric glyph and would leave the
//   liked state showing a backwards thumb.
// - The outline->filled symbol swap happens at the ~90 degree edge-on midpoint,
//   so the morph is hidden behind the card edge rather than shown on the front face.
// - A persistent card background sits behind the symbol, so even at the edge-on
//   frame the tile is never blank.
public struct ThumbFlipLikeView: View {
    var demo: Bool = false

    // Interactive state.
    @State private var liked: Bool = false
    @State private var flipAngle: Double = 0      // accumulated Y rotation in degrees
    @State private var floatOffset: CGFloat = 0    // brief upward float on flip
    @State private var pop: CGFloat = 1            // knuckle-crack scale overshoot
    @State private var showFilled: Bool = false    // which symbol is rendered
    @State private var burst: Double = 0           // 0...1 radial spark progress
    @State private var tapTrigger: Int = 0

    public var body: some View {
        GeometryReader { geo in
            let side = min(geo.size.width, geo.size.height)
            ZStack {
                if demo {
                    demoContent(side: side)
                } else {
                    interactiveContent(side: side)
                }
            }
            .frame(width: geo.size.width, height: geo.size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // MARK: Demo (self-driving)

    private func demoContent(side: CGFloat) -> some View {
        // PhaseAnimator auto-cycles the full like/unlike flip on a ~3.2s loop.
        // The trigger-less initializer is the one that loops continuously; the
        // trigger variant only advances once per trigger change.
        PhaseAnimator(ThumbFlipLikeView_DemoPhase.allCases) { phase in
            thumbCard(side: side, state: demoState(for: phase))
        } animation: { phase in
            phase.animation
        }
    }

    // The visual state derived for each demo phase. Kept tiny for the type-checker.
    private func demoState(for phase: ThumbFlipLikeView_DemoPhase) -> ThumbFlipLikeView_ThumbVisualState {
        switch phase {
        case .restOutline:
            return ThumbFlipLikeView_ThumbVisualState(angle: 0, filled: false, float: 0, pop: 1, burst: 0)
        case .edgeToFilled:
            return ThumbFlipLikeView_ThumbVisualState(angle: 90, filled: false, float: -side90Float, pop: 1.04, burst: 0)
        case .landFilled:
            return ThumbFlipLikeView_ThumbVisualState(angle: 180, filled: true, float: 0, pop: 1, burst: 1)
        case .holdFilled:
            return ThumbFlipLikeView_ThumbVisualState(angle: 180, filled: true, float: 0, pop: 1, burst: 0)
        case .edgeToOutline:
            return ThumbFlipLikeView_ThumbVisualState(angle: 270, filled: true, float: -side90Float, pop: 1.02, burst: 0)
        case .landOutline:
            return ThumbFlipLikeView_ThumbVisualState(angle: 360, filled: false, float: 0, pop: 1, burst: 0)
        }
    }

    private var side90Float: CGFloat { 10 }

    // MARK: Interactive

    private func interactiveContent(side: CGFloat) -> some View {
        thumbCard(
            side: side,
            state: ThumbFlipLikeView_ThumbVisualState(
                angle: flipAngle,
                filled: showFilled,
                float: floatOffset,
                pop: pop,
                burst: burst
            )
        )
        .contentShape(Rectangle())
        .onTapGesture {
            performFlip()
        }
        .sensoryFeedback(.impact(flexibility: .soft, intensity: 0.8), trigger: tapTrigger)
        .sensoryFeedback(.success, trigger: liked) { _, now in now }
    }

    // Two-stage flip with a knuckle-crack overshoot spring and an upward float.
    private func performFlip() {
        let goingToLiked = !liked
        tapTrigger &+= 1

        // Stage 1: rotate to the edge-on midpoint + lift slightly.
        withAnimation(.easeIn(duration: 0.14)) {
            flipAngle += 90
            floatOffset = -10
            pop = 1.05
        }

        // At the edge-on midpoint, swap the symbol while it is hidden.
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.14) {
            showFilled = goingToLiked

            // Stage 2: continue past edge-on and land with a knuckle-crack overshoot.
            withAnimation(.spring(response: 0.34, dampingFraction: 0.42)) {
                flipAngle += 90
                pop = 1
            }
            // Float settles back down a touch slower than the snap.
            withAnimation(.spring(response: 0.5, dampingFraction: 0.7)) {
                floatOffset = 0
            }

            liked = goingToLiked

            if goingToLiked {
                triggerBurst()
            }

            // Keep the accumulated angle bounded so it never drifts huge.
            if flipAngle >= 360 {
                // Normalize after the spring has visually settled.
                DispatchQueue.main.asyncAfter(deadline: .now() + 0.55) {
                    if !isFlipMidAir {
                        flipAngle = flipAngle.truncatingRemainder(dividingBy: 360)
                    }
                }
            }
        }
    }

    private var isFlipMidAir: Bool {
        let r = flipAngle.truncatingRemainder(dividingBy: 180)
        return abs(r) > 4 && abs(r) < 176
    }

    private func triggerBurst() {
        burst = 0
        withAnimation(.easeOut(duration: 0.5)) {
            burst = 1
        }
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.52) {
            burst = 0
        }
    }

    // MARK: Shared card

    private func thumbCard(side: CGFloat, state: ThumbFlipLikeView_ThumbVisualState) -> some View {
        let cardSize = side * 0.62
        let symbolSize = cardSize * 0.5
        // Counter-mirror when the back face is showing so the glyph is never
        // rendered backwards. The symbol is swapped at the edge-on midpoint, so
        // the user only ever sees an upright thumb on a face.
        let normalized = ((state.angle.truncatingRemainder(dividingBy: 360)) + 360)
            .truncatingRemainder(dividingBy: 360)
        let showingBack = normalized > 90 && normalized < 270

        return ZStack {
            backdropGlow(size: side, active: state.filled)
            sparkRing(size: cardSize, progress: state.burst)

            cardFace(cardSize: cardSize, filled: state.filled)
                .overlay {
                    thumbSymbol(filled: state.filled, size: symbolSize)
                        .scaleEffect(x: showingBack ? -1 : 1, y: 1)
                }
                .scaleEffect(state.pop)
                .rotation3DEffect(
                    .degrees(state.angle),
                    axis: (x: 0, y: 1, z: 0),
                    perspective: 0.55
                )
                .offset(y: state.float)
        }
        .frame(width: side, height: side)
    }

    private func cardFace(cardSize: CGFloat, filled: Bool) -> some View {
        RoundedRectangle(cornerRadius: cardSize * 0.28, style: .continuous)
            .fill(
                LinearGradient(
                    colors: filled ? likedFaceColors : idleFaceColors,
                    startPoint: .topLeading,
                    endPoint: .bottomTrailing
                )
            )
            .overlay {
                RoundedRectangle(cornerRadius: cardSize * 0.28, style: .continuous)
                    .stroke(
                        Color(red: 1, green: 1, blue: 1).opacity(filled ? 0.28 : 0.16),
                        lineWidth: 1
                    )
            }
            .frame(width: cardSize, height: cardSize)
            .shadow(
                color: (filled ? accentColor : Color(red: 0, green: 0, blue: 0)).opacity(filled ? 0.45 : 0.3),
                radius: filled ? 16 : 8,
                x: 0,
                y: 6
            )
    }

    private func thumbSymbol(filled: Bool, size: CGFloat) -> some View {
        Image(systemName: filled ? "hand.thumbsup.fill" : "hand.thumbsup")
            .font(.system(size: size, weight: .semibold))
            .foregroundStyle(
                filled
                ? AnyShapeStyle(LinearGradient(
                    colors: [Color(red: 1, green: 1, blue: 1), Color(red: 0.92, green: 0.96, blue: 1)],
                    startPoint: .top, endPoint: .bottom))
                : AnyShapeStyle(accentColor)
            )
            .contentTransition(.symbolEffect(.replace))
            .shadow(color: accentColor.opacity(filled ? 0.6 : 0), radius: 6)
    }

    private func backdropGlow(size: CGFloat, active: Bool) -> some View {
        Circle()
            .fill(
                RadialGradient(
                    colors: [accentColor.opacity(active ? 0.4 : 0.12), .clear],
                    center: .center,
                    startRadius: 0,
                    endRadius: size * 0.55
                )
            )
            .frame(width: size, height: size)
            .blur(radius: 6)
            .opacity(active ? 1 : 0.65)
    }

    // One crisp radial spark ring on the like landing.
    private func sparkRing(size: CGFloat, progress: Double) -> some View {
        let p = CGFloat(progress)
        return ForEach(0..<8, id: \.self) { i in
            let angle = Double(i) / 8.0 * 2 * .pi
            let dist = size * 0.5 * (0.4 + p * 0.6)
            Capsule()
                .fill(accentColor.opacity(Double(1 - p)))
                .frame(width: 3, height: 9 + (1 - p) * 6)
                .offset(y: -dist)
                .rotationEffect(.radians(angle))
                .scaleEffect(0.6 + (1 - p) * 0.6)
        }
        .opacity(progress > 0.001 && progress < 0.999 ? 1 : 0)
    }

    // MARK: Palette

    private var accentColor: Color { Color(red: 0.30, green: 0.62, blue: 1.0) }

    private var idleFaceColors: [Color] {
        [Color(red: 0.16, green: 0.17, blue: 0.22),
         Color(red: 0.10, green: 0.11, blue: 0.15)]
    }

    private var likedFaceColors: [Color] {
        [Color(red: 0.24, green: 0.52, blue: 0.98),
         Color(red: 0.16, green: 0.36, blue: 0.86)]
    }
}

// MARK: - Supporting types

private struct ThumbFlipLikeView_ThumbVisualState {
    var angle: Double
    var filled: Bool
    var float: CGFloat
    var pop: CGFloat
    var burst: Double
}

private enum ThumbFlipLikeView_DemoPhase: CaseIterable {
    case restOutline
    case edgeToFilled
    case landFilled
    case holdFilled
    case edgeToOutline
    case landOutline

    var animation: Animation {
        switch self {
        case .restOutline:
            return .linear(duration: 0.01)
        case .edgeToFilled:
            return .easeIn(duration: 0.16)
        case .landFilled:
            return .spring(response: 0.34, dampingFraction: 0.42)
        case .holdFilled:
            return .easeInOut(duration: 1.0)
        case .edgeToOutline:
            return .easeIn(duration: 0.16)
        case .landOutline:
            return .spring(response: 0.4, dampingFraction: 0.55)
        }
    }
}
"""###,
        "mi-trace-checkmark": ###"""
import SwiftUI

// MARK: - Trace Checkmark
// A success tick that draws its ring clockwise via trim, then strokes the
// checkmark on with an overshoot snap and a single radial spark at the tip.
// demo == true  -> self-driving TimelineView loop (no touch, never blank).
// demo == false -> plays once on appear; tap to replay, with success haptic.

struct TraceCheckmarkView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { geo in
            let side = min(geo.size.width, geo.size.height)
            ZStack {
                if demo {
                    TraceCheckmarkView_DemoDriver(side: side)
                } else {
                    TraceCheckmarkView_InteractiveDriver(side: side)
                }
            }
            .frame(width: geo.size.width, height: geo.size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }
}

// MARK: - Phase math (shared, deterministic)

private enum TraceCheckmarkView_TracePhase {
    // Sub-progress windows inside one normalized 0...1 loop phase.
    static let circleEnd: Double = 0.30
    static let checkStart: Double = 0.30
    static let checkEnd: Double = 0.55
    static let sparkStart: Double = 0.55
    static let sparkEnd: Double = 0.72
    static let holdEnd: Double = 0.88
    // remainder 0.88...1.0 fades out and resets.

    static func clamp(_ v: Double) -> Double { min(1, max(0, v)) }

    static func easeOut(_ t: Double) -> Double {
        let c = clamp(t)
        return 1 - pow(1 - c, 3)
    }

    static func easeInOut(_ t: Double) -> Double {
        let c = clamp(t)
        return c < 0.5 ? 4 * c * c * c : 1 - pow(-2 * c + 2, 3) / 2
    }

    static func mapped(_ value: Double, from a: Double, to b: Double) -> Double {
        guard b > a else { return value >= b ? 1 : 0 }
        return clamp((value - a) / (b - a))
    }

    /// Returns the three render sub-progresses for a normalized phase 0...1.
    static func resolve(_ phase: Double) -> (circle: Double, check: Double, spark: Double, overshoot: Double) {
        let p = clamp(phase)

        // Circle draws first.
        let circle = easeOut(mapped(p, from: 0, to: circleEnd))

        // Check strokes after the circle.
        let check = easeInOut(mapped(p, from: checkStart, to: checkEnd))

        // Spark blooms once the check lands, then decays.
        let sparkRaw = mapped(p, from: sparkStart, to: sparkEnd)
        let spark = sparkRaw

        // Overshoot: a brief 0 -> 1 -> 0 pulse right as the check completes,
        // expressed as scaleEffect (NOT trim, which would clamp at 1).
        let overshootWindowStart = checkEnd - 0.04
        let overshootWindowEnd = sparkEnd
        let ow = mapped(p, from: overshootWindowStart, to: overshootWindowEnd)
        let overshoot = sin(ow * .pi) // 0 -> 1 -> 0

        // Fade-out at the tail so the wrap never flickers to empty hard.
        let fade: Double
        if p > holdEnd {
            fade = 1 - easeInOut(mapped(p, from: holdEnd, to: 1.0))
        } else {
            fade = 1
        }

        return (circle * fade, check * fade, spark * fade, overshoot)
    }
}

// MARK: - Demo driver (self-driving loop)

private struct TraceCheckmarkView_DemoDriver: View {
    let side: CGFloat
    private let period: Double = 3.2

    var body: some View {
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            let phase = (t.truncatingRemainder(dividingBy: period)) / period
            let r = TraceCheckmarkView_TracePhase.resolve(phase)
            TraceCheckmarkView_TraceRenderer(
                side: side,
                circleTrim: r.circle,
                checkTrim: r.check,
                sparkProgress: r.spark,
                overshoot: r.overshoot
            )
        }
    }
}

// MARK: - Interactive driver (play-on-appear, tap to replay)

private struct TraceCheckmarkView_InteractiveDriver: View {
    let side: CGFloat

    @State private var circleTrim: CGFloat = 0
    @State private var checkTrim: CGFloat = 0
    @State private var sparkProgress: CGFloat = 0
    @State private var overshoot: CGFloat = 0
    @State private var completionTick: Int = 0
    @State private var hasPlayed: Bool = false

    var body: some View {
        TraceCheckmarkView_TraceRenderer(
            side: side,
            circleTrim: Double(circleTrim),
            checkTrim: Double(checkTrim),
            sparkProgress: Double(sparkProgress),
            overshoot: Double(overshoot)
        )
        .contentShape(Rectangle())
        .onTapGesture { play() }
        .onAppear {
            if !hasPlayed {
                hasPlayed = true
                // Small delay so the appear transition reads.
                DispatchQueue.main.asyncAfter(deadline: .now() + 0.25) {
                    play()
                }
            }
        }
        .sensoryFeedback(.success, trigger: completionTick)
    }

    private func play() {
        // Reset.
        circleTrim = 0
        checkTrim = 0
        sparkProgress = 0
        overshoot = 0

        // 1. Ring draws clockwise.
        withAnimation(.easeOut(duration: 0.55)) {
            circleTrim = 1
        }

        // 2. Check strokes after the ring, with an overshoot scale snap.
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.5) {
            withAnimation(.easeInOut(duration: 0.30)) {
                checkTrim = 1
            }
            withAnimation(.spring(response: 0.32, dampingFraction: 0.45).delay(0.18)) {
                overshoot = 1
            }
            withAnimation(.easeOut(duration: 0.35).delay(0.40)) {
                overshoot = 0
            }
        }

        // 3. Spark blooms at the tip on completion + haptic.
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.85) {
            completionTick += 1
            sparkProgress = 0
            withAnimation(.easeOut(duration: 0.45)) {
                sparkProgress = 1
            }
        }
    }
}

// MARK: - Renderer (pure presentation, no animation logic)

private struct TraceCheckmarkView_TraceRenderer: View {
    let side: CGFloat
    let circleTrim: Double
    let checkTrim: Double
    let sparkProgress: Double
    let overshoot: Double

    // Palette (literal RGB only).
    private var accent: Color { Color(red: 0.22, green: 0.83, blue: 0.51) }
    private var accentDeep: Color { Color(red: 0.10, green: 0.62, blue: 0.40) }
    private var guideColor: Color { Color(red: 0.55, green: 0.60, blue: 0.58).opacity(0.22) }
    private var sparkColor: Color { Color(red: 0.78, green: 1.0, blue: 0.86) }

    private var lineWidth: CGFloat { max(2.5, side * 0.055) }
    private var ringInset: CGFloat { lineWidth * 0.9 }

    // Check geometry, normalized to the ring's bounding box (0...1 each axis),
    // measured inside the inset ring rect.
    private func checkPoints(in rect: CGRect) -> (start: CGPoint, mid: CGPoint, end: CGPoint) {
        let w = rect.width
        let h = rect.height
        let x0 = rect.minX
        let y0 = rect.minY
        let start = CGPoint(x: x0 + w * 0.30, y: y0 + h * 0.52)
        let mid = CGPoint(x: x0 + w * 0.44, y: y0 + h * 0.66)
        let end = CGPoint(x: x0 + w * 0.72, y: y0 + h * 0.36)
        return (start, mid, end)
    }

    var body: some View {
        ZStack {
            GeometryReader { geo in
                let rect = squareRect(in: geo.size)
                let inner = rect.insetBy(dx: ringInset, dy: ringInset)
                let pts = checkPoints(in: inner)
                let scale = 1.0 + overshoot * 0.13

                ZStack {
                    // Faint persistent guide ring (never blank).
                    Circle()
                        .stroke(guideColor, style: .init(lineWidth: lineWidth, lineCap: .round))
                        .frame(width: rect.width, height: rect.height)
                        .position(x: rect.midX, y: rect.midY)

                    // Drawn ring (clockwise from top).
                    Circle()
                        .trim(from: 0, to: circleTrim)
                        .stroke(
                            LinearGradient(
                                colors: [accent, accentDeep],
                                startPoint: .topLeading,
                                endPoint: .bottomTrailing
                            ),
                            style: .init(lineWidth: lineWidth, lineCap: .round)
                        )
                        .rotationEffect(.degrees(-90)) // start at top
                        .frame(width: rect.width, height: rect.height)
                        .position(x: rect.midX, y: rect.midY)
                        .shadow(color: accent.opacity(0.45 * circleTrim), radius: lineWidth * 0.8)

                    // Checkmark stroke.
                    TraceCheckmarkView_CheckShape(start: pts.start, mid: pts.mid, end: pts.end)
                        .trim(from: 0, to: checkTrim)
                        .stroke(accent, style: .init(lineWidth: lineWidth, lineCap: .round, lineJoin: .round))
                        .scaleEffect(scale, anchor: .center)
                        .shadow(color: accent.opacity(0.5 * checkTrim), radius: lineWidth * 0.7)

                    // Radial spark at the check tip on completion.
                    TraceCheckmarkView_SparkView(progress: sparkProgress, color: sparkColor, baseSize: side)
                        .position(pts.end)
                        .allowsHitTesting(false)
                }
                .frame(width: geo.size.width, height: geo.size.height)
            }
        }
    }

    private func squareRect(in size: CGSize) -> CGRect {
        let s = min(size.width, size.height) * 0.78
        let x = (size.width - s) / 2
        let y = (size.height - s) / 2
        return CGRect(x: x, y: y, width: s, height: s)
    }
}

// MARK: - Check shape

private struct TraceCheckmarkView_CheckShape: Shape {
    let start: CGPoint
    let mid: CGPoint
    let end: CGPoint

    func path(in rect: CGRect) -> Path {
        var p = Path()
        p.move(to: start)
        p.addLine(to: mid)
        p.addLine(to: end)
        return p
    }
}

// MARK: - Spark (Canvas radial burst)

private struct TraceCheckmarkView_SparkView: View {
    let progress: Double // 0...1
    let color: Color
    let baseSize: CGFloat

    private let rayCount = 8

    var body: some View {
        let p = min(1, max(0, progress))
        // 0 -> 1 -> 0 envelope for opacity; rays push outward as p rises.
        let opacity = sin(p * .pi)
        let reach = baseSize * 0.22
        let canvasSide = baseSize * 0.6

        Canvas { ctx, size in
            guard opacity > 0.001 else { return }
            let center = CGPoint(x: size.width / 2, y: size.height / 2)
            let inner = reach * (0.15 + p * 0.35)
            let outer = reach * (0.45 + p * 0.55)
            let w = max(1.0, baseSize * 0.018)

            for i in 0..<rayCount {
                let angle = (Double(i) / Double(rayCount)) * 2 * .pi
                let a = CGPoint(
                    x: center.x + CGFloat(cos(angle)) * inner,
                    y: center.y + CGFloat(sin(angle)) * inner
                )
                let b = CGPoint(
                    x: center.x + CGFloat(cos(angle)) * outer,
                    y: center.y + CGFloat(sin(angle)) * outer
                )
                var ray = Path()
                ray.move(to: a)
                ray.addLine(to: b)
                ctx.stroke(
                    ray,
                    with: .color(color.opacity(opacity)),
                    style: .init(lineWidth: w, lineCap: .round)
                )
            }

            // Bright core flash.
            let coreR = max(1.0, baseSize * 0.02) * (1 + p)
            let coreRect = CGRect(
                x: center.x - coreR, y: center.y - coreR,
                width: coreR * 2, height: coreR * 2
            )
            ctx.fill(Circle().path(in: coreRect), with: .color(color.opacity(opacity)))
        }
        .frame(width: canvasSide, height: canvasSide)
    }
}
"""###,
        "mi-volume-fluid": ###"""
import SwiftUI

// MARK: - Public View

/// Fluid Volume Fill — a vertical volume control rendered as liquid in a glass.
/// Dragging raises the level; drag velocity tilts and sloshes the surface,
/// which then settles flat via a clock-driven damped sine. In `demo` mode it
/// ramps the level and self-sloshes so the tile stays alive with no touch.
struct VolumeFluidView: View {
    var demo: Bool = false

    // Level the liquid rises to, 0...1 (set directly, never spring-animated).
    @State private var level: CGFloat = 0.55
    @State private var isDragging: Bool = false
    // Live tilt while a finger is down, driven by drag velocity. Gated on isDragging.
    @State private var liveTilt: CGFloat = 0
    // A recorded slosh impulse: when it started and its initial amplitude/sign.
    @State private var impulseStart: TimeInterval = -100
    @State private var impulseAmp: CGFloat = 0
    @State private var settleTrigger: Int = 0

    var body: some View {
        GeometryReader { geo in
            let size = geo.size
            content(size: size)
                .frame(width: size.width, height: size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .sensoryFeedback(.impact(weight: .light), trigger: settleTrigger)
    }

    @ViewBuilder
    private func content(size: CGSize) -> some View {
        if demo {
            fluidTimeline()
        } else {
            fluidTimeline()
                .gesture(dragGesture(in: size))
        }
    }

    private func fluidTimeline() -> some View {
        TimelineView(.animation) { timeline in
            let now = timeline.date.timeIntervalSinceReferenceDate
            let frame = frameValues(now: now)
            VolumeFluidView_FluidCanvas(
                level: frame.level,
                tilt: frame.tilt,
                slosh: frame.slosh,
                phase: frame.phase
            )
        }
        .contentShape(Rectangle())
    }

    // MARK: - Per-frame physics

    struct FrameValues {
        var level: CGFloat
        var tilt: CGFloat   // overall surface tilt (left↔right)
        var slosh: CGFloat  // standing-wave amplitude
        var phase: CGFloat  // wave phase for the rippling motion
    }

    private func frameValues(now: TimeInterval) -> FrameValues {
        if demo {
            return demoFrame(now: now)
        }
        return interactiveFrame(now: now)
    }

    /// Interactive: level follows the finger; slosh decays from the last impulse.
    private func interactiveFrame(now: TimeInterval) -> FrameValues {
        let elapsed = CGFloat(now - impulseStart)
        let decayed = dampedAmplitude(initial: impulseAmp, elapsed: elapsed)
        let phase = CGFloat(now) * waveSpeed
        let tilt = isDragging ? liveTilt : decayed
        let amp = isDragging ? max(abs(liveTilt) * 0.6, 0.012) : abs(decayed)
        return FrameValues(
            level: clampLevel(level),
            tilt: tilt,
            slosh: amp,
            phase: phase
        )
    }

    /// Demo: everything is a pure function of the clock so the tile auto-plays.
    private func demoFrame(now: TimeInterval) -> FrameValues {
        let period: CGFloat = 5.2
        let t = CGFloat(now).truncatingRemainder(dividingBy: period)
        let u = t / period // 0...1 around the loop

        // Smooth up/down ramp using a cosine so the reversal points are gentle.
        let ramp = 0.5 - 0.5 * cos(u * 2 * .pi)   // 0→1→0
        let lvl = clampLevel(0.22 + ramp * 0.62)  // floored well above empty

        // Each half-period (t=0 and t=period/2) is a ramp reversal — seed a
        // fresh decaying slosh from there. dampedAmplitude carries the cos(ωt).
        let sinceReversal = t.truncatingRemainder(dividingBy: period / 2)
        let amp = dampedAmplitude(initial: 0.09, elapsed: sinceReversal)

        let phase = CGFloat(now) * waveSpeed
        return FrameValues(
            level: lvl,
            tilt: amp,
            slosh: max(abs(amp), 0.016),
            phase: phase
        )
    }

    // MARK: - Physics helpers

    private var waveSpeed: CGFloat { 3.1 }

    /// Damped oscillator: A0 * e^(-k t) * cos(ω t). Returns ~0 once settled.
    private func dampedAmplitude(initial: CGFloat, elapsed: CGFloat) -> CGFloat {
        guard elapsed >= 0 else { return 0 }
        let k: CGFloat = 2.6     // decay rate
        let omega: CGFloat = 7.4 // bob frequency
        let env = exp(-k * elapsed)
        return initial * env * cos(omega * elapsed)
    }

    private func clampLevel(_ v: CGFloat) -> CGFloat {
        min(max(v, 0.12), 0.97)
    }

    // MARK: - Gesture

    private func dragGesture(in size: CGSize) -> some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                isDragging = true
                // Map finger Y to level (top = full). Use the glass insets.
                let inset = glassInset(for: size)
                let top = inset.height
                let bottom = size.height - inset.height
                let span = max(bottom - top, 1)
                let raw = (bottom - value.location.y) / span
                level = clampLevel(raw)
                // Vertical velocity drives the live tilt (points/sec → small tilt).
                let vy = value.velocity.height
                liveTilt = clampTilt(-vy / 4200)
            }
            .onEnded { value in
                isDragging = false
                // Hand the live energy to a decaying impulse from this instant.
                let seed = clampTilt(-value.velocity.height / 3200)
                impulseAmp = abs(seed) > 0.0001 ? seed : liveTilt
                impulseStart = Date().timeIntervalSinceReferenceDate
                liveTilt = 0
                settleTrigger &+= 1
            }
    }

    private func clampTilt(_ v: CGFloat) -> CGFloat {
        min(max(v, -0.13), 0.13)
    }

    private func glassInset(for size: CGSize) -> CGSize {
        let m = min(size.width, size.height)
        let pad = max(m * 0.10, 6)
        return CGSize(width: pad, height: pad)
    }
}

// MARK: - Canvas

private struct VolumeFluidView_FluidCanvas: View {
    let level: CGFloat
    let tilt: CGFloat
    let slosh: CGFloat
    let phase: CGFloat

    var body: some View {
        Canvas { context, size in
            let glass = glassRect(in: size)
            let corner = glass.width * 0.16

            drawBackdrop(in: &context, size: size)
            drawGlassBody(in: &context, rect: glass, corner: corner)

            // Clip all liquid to the inner glass and draw.
            context.drawLayer { layer in
                let clip = RoundedRectangle(cornerRadius: corner, style: .continuous)
                    .path(in: glass)
                layer.clip(to: clip)
                drawLiquid(in: &layer, glass: glass)
            }

            drawGlassRim(in: &context, rect: glass, corner: corner)
        }
    }

    // MARK: Geometry

    private func glassRect(in size: CGSize) -> CGRect {
        let m = min(size.width, size.height)
        let pad = max(m * 0.10, 6)
        let w = size.width - pad * 2
        let h = size.height - pad * 2
        // Keep a tall-ish glass even in a square tile.
        let glassW = min(w, h * 0.62)
        let x = (size.width - glassW) / 2
        return CGRect(x: x, y: pad, width: glassW, height: h)
    }

    // MARK: Backdrop

    private func drawBackdrop(in context: inout GraphicsContext, size: CGSize) {
        let bg = Path(CGRect(origin: .zero, size: size))
        let top = Color(red: 0.09, green: 0.07, blue: 0.12)
        let bottom = Color(red: 0.05, green: 0.04, blue: 0.08)
        context.fill(
            bg,
            with: .linearGradient(
                Gradient(colors: [top, bottom]),
                startPoint: .zero,
                endPoint: CGPoint(x: 0, y: size.height)
            )
        )
    }

    // MARK: Glass

    private func drawGlassBody(in context: inout GraphicsContext, rect: CGRect, corner: CGFloat) {
        let shape = RoundedRectangle(cornerRadius: corner, style: .continuous).path(in: rect)
        let fillTop = Color(red: 0.16, green: 0.17, blue: 0.22).opacity(0.55)
        let fillBottom = Color(red: 0.10, green: 0.11, blue: 0.16).opacity(0.55)
        context.fill(
            shape,
            with: .linearGradient(
                Gradient(colors: [fillTop, fillBottom]),
                startPoint: CGPoint(x: rect.minX, y: rect.minY),
                endPoint: CGPoint(x: rect.minX, y: rect.maxY)
            )
        )
    }

    private func drawGlassRim(in context: inout GraphicsContext, rect: CGRect, corner: CGFloat) {
        let shape = RoundedRectangle(cornerRadius: corner, style: .continuous).path(in: rect)
        // Outer rim.
        context.stroke(
            shape,
            with: .linearGradient(
                Gradient(colors: [
                    Color(red: 0.85, green: 0.88, blue: 0.95).opacity(0.55),
                    Color(red: 0.45, green: 0.50, blue: 0.62).opacity(0.30)
                ]),
                startPoint: CGPoint(x: rect.minX, y: rect.minY),
                endPoint: CGPoint(x: rect.maxX, y: rect.maxY)
            ),
            lineWidth: max(rect.width * 0.018, 1)
        )
        // A soft vertical specular streak on the left for glassiness.
        let streakW = rect.width * 0.10
        let streak = RoundedRectangle(cornerRadius: streakW / 2, style: .continuous)
            .path(in: CGRect(
                x: rect.minX + rect.width * 0.14,
                y: rect.minY + rect.height * 0.06,
                width: streakW,
                height: rect.height * 0.82
            ))
        context.fill(
            streak,
            with: .linearGradient(
                Gradient(colors: [
                    Color.white.opacity(0.14),
                    Color.white.opacity(0.0)
                ]),
                startPoint: CGPoint(x: rect.minX, y: rect.minY),
                endPoint: CGPoint(x: rect.minX, y: rect.maxY)
            )
        )
    }

    // MARK: Liquid

    private func drawLiquid(in context: inout GraphicsContext, glass: CGRect) {
        let surfaceY = surfaceBaseY(in: glass)
        let body = liquidBodyPath(glass: glass, surfaceY: surfaceY)

        // Liquid fill — vivid teal/blue gradient with depth.
        let cTop = Color(red: 0.20, green: 0.78, blue: 0.92)
        let cMid = Color(red: 0.12, green: 0.52, blue: 0.90)
        let cBot = Color(red: 0.08, green: 0.30, blue: 0.78)
        context.fill(
            body,
            with: .linearGradient(
                Gradient(colors: [cTop, cMid, cBot]),
                startPoint: CGPoint(x: glass.minX, y: surfaceY),
                endPoint: CGPoint(x: glass.minX, y: glass.maxY)
            )
        )

        drawSurfaceSheen(in: &context, glass: glass, surfaceY: surfaceY)
        drawMeniscus(in: &context, glass: glass, surfaceY: surfaceY)
        drawBubbles(in: &context, glass: glass, surfaceY: surfaceY)
    }

    /// Base Y of the waterline for the current level (no wave offset).
    private func surfaceBaseY(in glass: CGRect) -> CGFloat {
        glass.maxY - level * glass.height
    }

    /// y of the wave at horizontal fraction `fx` (0...1 across the glass).
    private func waveY(baseY: CGFloat, glass: CGRect, fx: CGFloat) -> CGFloat {
        // Tilt is a linear left↔right component centered at the middle.
        let tiltOffset = tilt * glass.height * (fx - 0.5)
        // Slosh is a standing wave; amplitude scaled to the glass.
        let amp = slosh * glass.height
        let twoPi: CGFloat = 2 * .pi
        let ripple = amp * sin(fx * twoPi + phase) * 0.6
        let ripple2 = amp * sin(fx * twoPi * 2 - phase * 1.3) * 0.25
        return baseY + tiltOffset + ripple + ripple2
    }

    /// The filled liquid body: across the wavy surface, then down and closed.
    private func liquidBodyPath(glass: CGRect, surfaceY: CGFloat) -> Path {
        var path = Path()
        let steps = 26
        let startY = waveY(baseY: surfaceY, glass: glass, fx: 0)
        path.move(to: CGPoint(x: glass.minX, y: startY))
        var i = 1
        while i <= steps {
            let fx = CGFloat(i) / CGFloat(steps)
            let x = glass.minX + fx * glass.width
            let y = waveY(baseY: surfaceY, glass: glass, fx: fx)
            path.addLine(to: CGPoint(x: x, y: y))
            i += 1
        }
        path.addLine(to: CGPoint(x: glass.maxX, y: glass.maxY))
        path.addLine(to: CGPoint(x: glass.minX, y: glass.maxY))
        path.closeSubpath()
        return path
    }

    private func drawSurfaceSheen(in context: inout GraphicsContext, glass: CGRect, surfaceY: CGFloat) {
        // A thin bright band riding just under the surface line.
        var band = Path()
        let steps = 26
        let bandThickness = max(glass.height * 0.012, 1.0)
        let topStart = waveY(baseY: surfaceY, glass: glass, fx: 0)
        band.move(to: CGPoint(x: glass.minX, y: topStart))
        var i = 1
        while i <= steps {
            let fx = CGFloat(i) / CGFloat(steps)
            let x = glass.minX + fx * glass.width
            band.addLine(to: CGPoint(x: x, y: waveY(baseY: surfaceY, glass: glass, fx: fx)))
            i += 1
        }
        i = steps
        while i >= 0 {
            let fx = CGFloat(i) / CGFloat(steps)
            let x = glass.minX + fx * glass.width
            band.addLine(to: CGPoint(x: x, y: waveY(baseY: surfaceY, glass: glass, fx: fx) + bandThickness))
            i -= 1
        }
        band.closeSubpath()
        context.fill(band, with: .color(Color.white.opacity(0.30)))
    }

    private func drawMeniscus(in context: inout GraphicsContext, glass: CGRect, surfaceY: CGFloat) {
        // Soft glow just above the surface to fake a meniscus highlight.
        let glowH = glass.height * 0.06
        let rect = CGRect(
            x: glass.minX,
            y: surfaceY - glowH,
            width: glass.width,
            height: glowH * 2
        )
        let glow = Path(rect)
        context.fill(
            glow,
            with: .linearGradient(
                Gradient(colors: [
                    Color.white.opacity(0.0),
                    Color.white.opacity(0.16),
                    Color.white.opacity(0.0)
                ]),
                startPoint: CGPoint(x: 0, y: rect.minY),
                endPoint: CGPoint(x: 0, y: rect.maxY)
            )
        )
    }

    private func drawBubbles(in context: inout GraphicsContext, glass: CGRect, surfaceY: CGFloat) {
        // A few rising bubbles whose vertical position is driven by `phase`.
        let count = 5
        var idx = 0
        while idx < count {
            let seed = CGFloat(idx) * 1.37
            let fx = (sin(seed * 2.1) * 0.5 + 0.5) * 0.7 + 0.15
            let x = glass.minX + fx * glass.width
            // Rise from bottom toward surface, cycling on phase.
            let cyc = (phase * 0.08 + seed).truncatingRemainder(dividingBy: 1.0)
            let bottomY = glass.maxY - glass.height * 0.04
            let y = bottomY - cyc * (bottomY - surfaceY - 2)
            if y > surfaceY + 2 {
                let r = max(glass.width * (0.02 + 0.012 * CGFloat(idx % 3)), 1.0)
                let dot = Path(ellipseIn: CGRect(x: x - r, y: y - r, width: r * 2, height: r * 2))
                let alpha = 0.18 * (1 - cyc)
                context.fill(dot, with: .color(Color.white.opacity(alpha)))
            }
            idx += 1
        }
    }
}
"""###,
        "mtl-heat-mirage": ###"""
//
//  HeatMirageView.swift
//  InspireCreativityApp — Bespoke catalog animation (Metal Shaders)
//
//  Heat Mirage: pixels bend with stacked noise octaves to create rising
//  heat-shimmer, with an intensity hotspot you drag to "aim the heat". Left
//  alone, a thermal column wanders up the view.
//
//  Requires the companion `HeatMirage.metal` in the same target.
//  `demo == true`  → self-driving wandering hotspot (grid tile).
//  `demo == false` → DragGesture aims the hotspot (Detail + the buyer's code).
//

import SwiftUI

struct HeatMirageView: View {
    var demo: Bool = false
    @State private var hotspot: CGPoint = .zero
    @State private var intensity: CGFloat = 0.6

    var body: some View {
        GeometryReader { geo in
            TimelineView(.animation) { ctx in
                let time = ctx.date.timeIntervalSinceReferenceDate
                let spot = demo ? Self.wander(time, in: geo.size) : effectiveHotspot(geo.size)
                heatContent
                    .distortionEffect(
                        ShaderLibrary.heatMirage(
                            .float(Float(time.truncatingRemainder(dividingBy: 1000))),
                            .float2(Float(spot.x), Float(spot.y)),
                            .float(Float(demo ? 1.0 : intensity))
                        ),
                        maxSampleOffset: CGSize(width: 14, height: 14)
                    )
            }
            .contentShape(Rectangle())
            .gesture(
                DragGesture(minimumDistance: 0)
                    .onChanged { value in
                        guard !demo else { return }
                        hotspot = value.location
                        intensity = 1.0
                    }
                    .onEnded { _ in
                        guard !demo else { return }
                        withAnimation(.easeOut(duration: 0.8)) { intensity = 0.45 }
                    }
            )
        }
    }

    private func effectiveHotspot(_ size: CGSize) -> CGPoint {
        hotspot == .zero ? CGPoint(x: size.width / 2, y: size.height * 0.6) : hotspot
    }

    private var heatContent: some View {
        ZStack {
            LinearGradient(
                colors: [Color(red: 0.95, green: 0.55, blue: 0.12),
                         Color(red: 0.55, green: 0.10, blue: 0.20),
                         .black],
                startPoint: .top, endPoint: .bottom
            )
            VStack {
                Spacer()
                Text("HEAT")
                    .font(.system(size: 40, weight: .black, design: .rounded))
                    .foregroundStyle(.white.opacity(0.85))
                Spacer()
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    static func wander(_ t: TimeInterval, in size: CGSize) -> CGPoint {
        CGPoint(x: (sin(t * 0.5) * 0.5 + 0.5) * size.width,
                y: (cos(t * 0.37) * 0.5 + 0.5) * size.height)
    }
}


// ---- Companion Metal shader (HeatMirage.metal) ----
// Add this as a .metal file in your target:
/*
//
//  HeatMirage.metal
//  InspireCreativityApp — Bespoke catalog animation (Metal Shaders)
//
//  Companion shader for HeatMirageView. A `[[ stitchable ]]` distortion that
//  offsets each sample coordinate by summed noise octaves scrolling upward to
//  fake rising heat-shimmer, with an intensity hotspot.
//

#include <metal_stdlib>
#include <SwiftUI/SwiftUI_Metal.h>
using namespace metal;

[[ stitchable ]]
float2 heatMirage(float2 position, float time, float2 hotspot, float intensity) {
    float2 p = position;
    float wave = sin(p.y * 0.06 - time * 3.0) * 2.0
               + sin(p.y * 0.13 - time * 5.0) * 1.2
               + sin(p.x * 0.05 + time * 2.0) * 0.8;
    float d = distance(p, hotspot);
    float falloff = exp(-d * 0.004) * intensity;
    p.x += wave * (0.6 + falloff * 5.0);
    p.y -= falloff * 3.0;
    return p;
}
*/
"""###,
        "nav-arc-fan-menu": ###"""
import SwiftUI

/// Arc Fan Menu — a floating action button that fans its child actions out along
/// an arc with a staggered, overshooting spring (dealt out like a hand of cards),
/// then sucks them back into the hub on release.
///
/// - `demo == true`  : self-driving PhaseAnimator loop that auto-blooms/retracts.
/// - `demo == false` : real hold-to-open `LongPressGesture` interaction.
struct ArcFanMenuView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { geo in
            let layout = FanLayout(size: geo.size)
            ZStack {
                backdrop(layout)
                content(layout)
            }
            .frame(width: geo.size.width, height: geo.size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // MARK: - Branches

    @ViewBuilder
    private func content(_ layout: FanLayout) -> some View {
        if demo {
            DemoFan(layout: layout)
        } else {
            InteractiveFan(layout: layout)
        }
    }

    @ViewBuilder
    private func backdrop(_ layout: FanLayout) -> some View {
        RoundedRectangle(cornerRadius: layout.size.width * 0.12, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [Color(hexCode: "#1b2230"), Color(hexCode: "#101418")],
                    startPoint: .topLeading,
                    endPoint: .bottomTrailing
                )
            )
            .overlay(
                RoundedRectangle(cornerRadius: layout.size.width * 0.12, style: .continuous)
                    .strokeBorder(Color.white.opacity(0.05), lineWidth: 1)
            )
    }
}

// MARK: - Layout

/// Centralized polar geometry so the demo and interactive branches share identical math.
private struct FanLayout {
    let size: CGSize

    /// Number of fanned action items.
    let count: Int = 5

    /// Hub anchor — bottom-center, leaving room for the arc to bloom upward.
    var hub: CGPoint {
        CGPoint(x: size.width * 0.5, y: size.height * 0.82)
    }

    var minSide: CGFloat { min(size.width, size.height) }

    /// Bloom radius, tuned to keep all items inside a 120pt tile.
    var radius: CGFloat { minSide * 0.42 }

    var hubDiameter: CGFloat { minSide * 0.22 }

    var itemDiameter: CGFloat { minSide * 0.155 }

    /// Arc spans from pointing left to pointing right, opening upward (a fan).
    /// Returns the unit direction for item `i`.
    func direction(_ i: Int) -> CGSize {
        let startDeg: Double = 200   // up-left
        let endDeg: Double = 340     // up-right
        let t = count > 1 ? Double(i) / Double(count - 1) : 0.5
        let deg = startDeg + (endDeg - startDeg) * t
        let rad = deg * .pi / 180
        return CGSize(width: cos(rad), height: sin(rad))
    }

    func offset(for i: Int, open: Bool) -> CGSize {
        guard open else { return .zero }
        let dir = direction(i)
        return CGSize(width: dir.width * radius, height: dir.height * radius)
    }

    /// Per-item stagger so items arrive a beat after the last.
    func delay(for i: Int) -> Double { Double(i) * 0.05 }
}

// MARK: - Item model

private struct FanAction: Identifiable {
    let id: Int
    let symbol: String
    let tint: Color
}

private let fanActions: [FanAction] = [
    FanAction(id: 0, symbol: "square.and.arrow.up", tint: Color(hexCode: "#5ac8fa")),
    FanAction(id: 1, symbol: "heart.fill",          tint: Color(hexCode: "#ff6482")),
    FanAction(id: 2, symbol: "bookmark.fill",       tint: Color(hexCode: "#ffd60a")),
    FanAction(id: 3, symbol: "bell.fill",           tint: Color(hexCode: "#bf5af2")),
    FanAction(id: 4, symbol: "paperplane.fill",     tint: Color(hexCode: "#30d158"))
]

// MARK: - Shared fan rendering

/// Renders the hub + fanned items for a given `open` state. The driver (PhaseAnimator
/// vs. gesture state) lives in the parent; the polar math + stagger are shared here.
private struct FanBody: View {
    let layout: FanLayout
    let open: Bool

    var body: some View {
        ZStack {
            ForEach(fanActions) { action in
                itemView(action)
            }
            hubView
        }
    }

    // MARK: Items

    @ViewBuilder
    private func itemView(_ action: FanAction) -> some View {
        let off = layout.offset(for: action.id, open: open)
        Circle()
            .fill(
                RadialGradient(
                    colors: [action.tint.opacity(0.95), action.tint.opacity(0.6)],
                    center: .topLeading,
                    startRadius: 0,
                    endRadius: layout.itemDiameter
                )
            )
            .overlay(
                Circle().strokeBorder(Color.white.opacity(0.25), lineWidth: 1)
            )
            .overlay(
                Image(systemName: action.symbol)
                    .font(.system(size: layout.itemDiameter * 0.42, weight: .semibold))
                    .foregroundStyle(.white)
            )
            .frame(width: layout.itemDiameter, height: layout.itemDiameter)
            .shadow(color: action.tint.opacity(open ? 0.5 : 0), radius: 6, x: 0, y: 3)
            .scaleEffect(open ? 1 : 0.35)
            .opacity(open ? 1 : 0)
            .position(layout.hub)
            .offset(off)
            .animation(
                .spring(response: 0.42, dampingFraction: 0.55)
                    .delay(layout.delay(for: action.id)),
                value: open
            )
    }

    // MARK: Hub — always full opacity, never blank.

    private var hubView: some View {
        ZStack {
            Circle()
                .fill(
                    LinearGradient(
                        colors: [Color(hexCode: "#ffffff"), Color(hexCode: "#cfd6e4")],
                        startPoint: .top,
                        endPoint: .bottom
                    )
                )
                .shadow(color: .black.opacity(0.35), radius: open ? 12 : 6, x: 0, y: 4)
            Image(systemName: "plus")
                .font(.system(size: layout.hubDiameter * 0.5, weight: .bold))
                .foregroundStyle(Color(hexCode: "#101418"))
                .rotationEffect(.degrees(open ? 135 : 0))
        }
        .frame(width: layout.hubDiameter, height: layout.hubDiameter)
        .scaleEffect(open ? 0.92 : 1.0)
        .position(layout.hub)
        .animation(.spring(response: 0.4, dampingFraction: 0.6), value: open)
    }
}

// MARK: - Demo driver (self-running)

private struct DemoFan: View {
    let layout: FanLayout

    var body: some View {
        // Two real phases (closed/open) plus a settle dwell phase stretches the
        // spring cycle into the ~2.5–4s window. PhaseAnimator auto-ping-pongs and
        // preserves each item's per-index delay, yielding genuine staggered overshoot.
        PhaseAnimator(DemoPhase.allCases) { phase in
            FanBody(layout: layout, open: phase.isOpen)
        } animation: { phase in
            switch phase {
            case .closed:    return .spring(response: 0.45, dampingFraction: 0.6)
            case .openBloom: return .spring(response: 0.5, dampingFraction: 0.55)
            case .openHold:  return .easeInOut(duration: 0.9)
            }
        }
    }
}

private enum DemoPhase: CaseIterable {
    case closed, openBloom, openHold

    var isOpen: Bool {
        switch self {
        case .closed:               return false
        case .openBloom, .openHold: return true
        }
    }
}

// MARK: - Interactive driver (hold-to-open)

private struct InteractiveFan: View {
    let layout: FanLayout
    @State private var open: Bool = false

    var body: some View {
        FanBody(layout: layout, open: open)
            .contentShape(Rectangle())
            // Hold-to-open: `pressing` fires true on press-down, false on release/
            // cancel — matching "fan on press, suck back on release".
            .onLongPressGesture(
                minimumDuration: 0.18,
                maximumDistance: 60,
                pressing: { isPressing in
                    withAnimation(.spring(response: 0.45, dampingFraction: 0.55)) {
                        open = isPressing
                    }
                },
                perform: {}
            )
            .sensoryFeedback(.impact(flexibility: .soft), trigger: open)
    }
}

// MARK: - Color hex helper

private extension Color {
    init(hexCode hex: String) {
        let s = hex.trimmingCharacters(in: CharacterSet(charactersIn: "#"))
        var rgb: UInt64 = 0
        Scanner(string: s).scanHexInt64(&rgb)
        let r, g, b, a: Double
        switch s.count {
        case 8:
            r = Double((rgb & 0xFF00_0000) >> 24) / 255
            g = Double((rgb & 0x00FF_0000) >> 16) / 255
            b = Double((rgb & 0x0000_FF00) >> 8) / 255
            a = Double(rgb & 0x0000_00FF) / 255
        case 6:
            r = Double((rgb & 0xFF0000) >> 16) / 255
            g = Double((rgb & 0x00FF00) >> 8) / 255
            b = Double(rgb & 0x0000FF) / 255
            a = 1
        default:
            r = 1; g = 1; b = 1; a = 1
        }
        self.init(.sRGB, red: r, green: g, blue: b, opacity: a)
    }
}

// MARK: - Preview
"""###,
        "nav-collapsing-chevron-crumbs": ###"""
import SwiftUI

// MARK: - Collapsing Chevron Crumbs
// A breadcrumb trail whose older crumbs telescope into a folded chevron-stacked
// chip that springs open like a paper fan on tap, and re-collapses with a
// staggered zip when you pick one.
//
// demo == true  -> self-driving TimelineView loop (deepen -> fan open -> collapse).
//                  The fan is interpolated MANUALLY from a continuous progress,
//                  because matchedGeometryEffect only interpolates across an
//                  animated state transition, never a per-frame TimelineView value.
// demo == false -> the real tap-driven component using @Namespace +
//                  matchedGeometryEffect with index-staggered springs.

public struct CollapsingChevronCrumbsView: View {
    public var demo: Bool = false

    public init(demo: Bool = false) {
        self.demo = demo
    }

    public var body: some View {
        GeometryReader { geo in
            let size = geo.size
            ZStack {
                CollapsingChevronCrumbsView_CCBackground()
                Group {
                    if demo {
                        CollapsingChevronCrumbsView_CCDemoTrail(size: size)
                    } else {
                        CollapsingChevronCrumbsView_CCInteractiveTrail(size: size)
                    }
                }
                .padding(.horizontal, max(8, size.width * 0.05))
            }
            .frame(width: size.width, height: size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }
}

// MARK: - Palette

private enum CollapsingChevronCrumbsView_CCPalette {
    static let bg0 = Color(red: 0.043, green: 0.055, blue: 0.071)
    static let bg1 = Color(red: 0.078, green: 0.094, blue: 0.118)

    static let chipFill = Color(red: 0.137, green: 0.165, blue: 0.204)
    static let chipFillHi = Color(red: 0.184, green: 0.220, blue: 0.271)
    static let chipStroke = Color(red: 0.298, green: 0.345, blue: 0.420)

    static let leaf0 = Color(red: 0.353, green: 0.733, blue: 0.965)
    static let leaf1 = Color(red: 0.557, green: 0.553, blue: 0.984)

    static let textBright = Color(red: 0.910, green: 0.937, blue: 0.984)
    static let textDim = Color(red: 0.604, green: 0.659, blue: 0.745)

    static let chevron = Color(red: 0.745, green: 0.804, blue: 0.902)
}

// MARK: - Model

private struct CollapsingChevronCrumbsView_CCCrumb: Identifiable, Equatable {
    let id: Int
    let label: String
    let symbol: String
}

private enum CollapsingChevronCrumbsView_CCData {
    /// Short labels + glyphs so the trail stays legible even in a ~120pt tile.
    static let all: [CollapsingChevronCrumbsView_CCCrumb] = [
        CollapsingChevronCrumbsView_CCCrumb(id: 0, label: "Home", symbol: "house.fill"),
        CollapsingChevronCrumbsView_CCCrumb(id: 1, label: "Files", symbol: "folder.fill"),
        CollapsingChevronCrumbsView_CCCrumb(id: 2, label: "Work", symbol: "tray.full.fill"),
        CollapsingChevronCrumbsView_CCCrumb(id: 3, label: "2026", symbol: "calendar"),
        CollapsingChevronCrumbsView_CCCrumb(id: 4, label: "Specs", symbol: "doc.fill")
    ]
}

// MARK: - Background

private struct CollapsingChevronCrumbsView_CCBackground: View {
    var body: some View {
        RoundedRectangle(cornerRadius: 22, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [CollapsingChevronCrumbsView_CCPalette.bg1, CollapsingChevronCrumbsView_CCPalette.bg0],
                    startPoint: .top,
                    endPoint: .bottom
                )
            )
            .overlay(
                RoundedRectangle(cornerRadius: 22, style: .continuous)
                    .stroke(Color.white.opacity(0.05), lineWidth: 1)
            )
    }
}

// MARK: - Shared chip rendering

/// A single breadcrumb pill. `scale`/`opacity` let the demo path animate it
/// without matchedGeometry; the interactive path leaves them at 1.
private struct CollapsingChevronCrumbsView_CCCrumbChip: View {
    let crumb: CollapsingChevronCrumbsView_CCCrumb
    let metric: CGFloat          // base sizing unit (≈ tile-relative)
    var isLeaf: Bool = false
    var compact: Bool = false    // icon-only (used in collapsed stack)
    var dim: Double = 1.0

    private var pad: CGFloat { metric * 0.34 }
    private var iconSize: CGFloat { metric * 0.46 }
    private var fontSize: CGFloat { metric * 0.42 }

    var body: some View {
        HStack(spacing: metric * 0.18) {
            Image(systemName: crumb.symbol)
                .font(.system(size: iconSize, weight: .semibold))
                .foregroundStyle(iconStyle)
            if !compact {
                Text(crumb.label)
                    .font(.system(size: fontSize, weight: .semibold, design: .rounded))
                    .foregroundStyle(isLeaf ? CollapsingChevronCrumbsView_CCPalette.textBright : CollapsingChevronCrumbsView_CCPalette.textDim)
                    .fixedSize()
            }
        }
        .padding(.vertical, pad * 0.55)
        .padding(.horizontal, pad)
        .background(chipBackground)
        .overlay(
            Capsule(style: .continuous)
                .stroke(strokeStyle, lineWidth: 1)
        )
        .opacity(dim)
    }

    private var iconStyle: AnyShapeStyle {
        if isLeaf {
            return AnyShapeStyle(
                LinearGradient(
                    colors: [CollapsingChevronCrumbsView_CCPalette.leaf0, CollapsingChevronCrumbsView_CCPalette.leaf1],
                    startPoint: .topLeading,
                    endPoint: .bottomTrailing
                )
            )
        }
        return AnyShapeStyle(CollapsingChevronCrumbsView_CCPalette.textDim)
    }

    private var chipBackground: some View {
        Capsule(style: .continuous)
            .fill(
                LinearGradient(
                    colors: isLeaf
                        ? [CollapsingChevronCrumbsView_CCPalette.chipFillHi, CollapsingChevronCrumbsView_CCPalette.chipFill]
                        : [CollapsingChevronCrumbsView_CCPalette.chipFill, CollapsingChevronCrumbsView_CCPalette.chipFill.opacity(0.85)],
                    startPoint: .top,
                    endPoint: .bottom
                )
            )
            .overlay(
                Capsule(style: .continuous)
                    .fill(leafGlow)
            )
    }

    private var leafGlow: Color {
        isLeaf ? CollapsingChevronCrumbsView_CCPalette.leaf0.opacity(0.10) : .clear
    }

    private var strokeStyle: Color {
        isLeaf ? CollapsingChevronCrumbsView_CCPalette.leaf0.opacity(0.55) : CollapsingChevronCrumbsView_CCPalette.chipStroke.opacity(0.7)
    }
}

/// The small chevron caret drawn between crumbs and inside the folded stack.
private struct CollapsingChevronCrumbsView_CCChevron: View {
    let metric: CGFloat
    var rotation: Double = 0      // 0 = pointing right (collapsed), 90 = down-ish (open)
    var opacity: Double = 1

    var body: some View {
        Image(systemName: "chevron.right")
            .font(.system(size: metric * 0.34, weight: .bold))
            .foregroundStyle(CollapsingChevronCrumbsView_CCPalette.chevron.opacity(0.85))
            .rotationEffect(.degrees(rotation))
            .opacity(opacity)
    }
}

// MARK: - DEMO PATH (self-driving, manual interpolation)

private struct CollapsingChevronCrumbsView_CCDemoTrail: View {
    let size: CGSize

    // Loop: deepen -> hold-collapsed -> fan open -> hold-open -> collapse.
    private let period: Double = 3.6

    var body: some View {
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            let phase = (t.truncatingRemainder(dividingBy: period)) / period // 0..1
            let frame = CollapsingChevronCrumbsView_CCDemoFrame(phase: phase)
            content(frame)
        }
    }

    private var metric: CGFloat { max(13, min(size.height, size.width * 0.5) * 0.30) }

    @ViewBuilder
    private func content(_ f: CollapsingChevronCrumbsView_CCDemoFrame) -> some View {
        // Folded crumbs = everything except the leaf; depth grows over the loop.
        let folded = Array(CollapsingChevronCrumbsView_CCData.all.prefix(f.foldedCount))
        let leaf = CollapsingChevronCrumbsView_CCData.all[f.foldedCount]

        HStack(spacing: metric * 0.22) {
            CollapsingChevronCrumbsView_CCFoldedChipDemo(
                folded: folded,
                metric: metric,
                progress: f.open,
                count: f.foldedCount
            )
            CollapsingChevronCrumbsView_CCChevron(metric: metric, rotation: f.open * 90, opacity: 0.6 + 0.4 * f.open)
            CollapsingChevronCrumbsView_CCCrumbChip(crumb: leaf, metric: metric, isLeaf: true)
                .scaleEffect(0.96 + 0.04 * f.leafPulse)
        }
        .frame(maxWidth: .infinity, alignment: .leading)
    }
}

/// Per-frame derived state for the demo loop.
private struct CollapsingChevronCrumbsView_CCDemoFrame {
    let foldedCount: Int   // how many crumbs are folded behind the chip
    let open: Double       // 0 = stacked chevron, 1 = fully fanned out
    let leafPulse: Double  // 0..1 little settle on the leaf

    init(phase p: Double) {
        // Beat layout across the loop (fractions of period):
        //  0.00–0.18  deepen: a crumb folds in (count grows)
        //  0.18–0.30  hold collapsed
        //  0.30–0.55  fan OPEN (spring-eased)
        //  0.55–0.78  hold open
        //  0.78–1.00  collapse (zip)
        let count: Int
        if p < 0.18 {
            count = 3
        } else {
            count = 4
        }
        self.foldedCount = count

        let o: Double
        if p < 0.30 {
            o = 0
        } else if p < 0.55 {
            o = CollapsingChevronCrumbsView_CCEase.spring((p - 0.30) / 0.25)
        } else if p < 0.78 {
            o = 1
        } else {
            o = 1 - CollapsingChevronCrumbsView_CCEase.inOut((p - 0.78) / 0.22)
        }
        self.open = min(max(o, 0), 1)

        // Leaf gives a tiny pop right when a deeper crumb lands.
        if p < 0.18 {
            self.leafPulse = CollapsingChevronCrumbsView_CCEase.inOut(p / 0.18)
        } else if p < 0.30 {
            self.leafPulse = 1 - CollapsingChevronCrumbsView_CCEase.inOut((p - 0.18) / 0.12)
        } else {
            self.leafPulse = 0
        }
    }
}

/// The folded chip for the demo path. At progress 0 the crumbs overlap as a
/// chevron stack; at progress 1 they fan out inline. Pure manual interpolation,
/// so it works perfectly under a per-frame TimelineView value (no matchedGeometry).
private struct CollapsingChevronCrumbsView_CCFoldedChipDemo: View {
    let folded: [CollapsingChevronCrumbsView_CCCrumb]
    let metric: CGFloat
    let progress: Double   // 0 collapsed -> 1 fanned
    let count: Int

    private var stackOverlap: CGFloat { metric * 0.62 }

    var body: some View {
        ZStack(alignment: .leading) {
            ForEach(Array(folded.enumerated()), id: \.element.id) { idx, crumb in
                let isLast = idx == folded.count - 1
                CollapsingChevronCrumbsView_CCDemoFoldedCrumb(
                    crumb: crumb,
                    index: idx,
                    total: folded.count,
                    metric: metric,
                    progress: staggered(progress, index: idx, total: folded.count),
                    stackOverlap: stackOverlap
                )
                .zIndex(Double(idx))
                .overlay(alignment: .topTrailing) {
                    if isLast && progress < 0.12 {
                        CollapsingChevronCrumbsView_CCStackBadge(count: count, metric: metric)
                            .opacity(1 - progress / 0.12)
                            .offset(x: metric * 0.18, y: -metric * 0.28)
                    }
                }
            }
        }
        // Reserve width so the fanned-out crumbs have room to spread.
        .frame(width: fannedWidth(), alignment: .leading)
    }

    private func fannedWidth() -> CGFloat {
        let collapsed = metric * 1.1 + stackOverlap * CGFloat(max(0, folded.count - 1)) * 0.0
        let perCrumb = metric * 2.4
        let fanned = perCrumb * CGFloat(folded.count)
        return collapsed + (fanned - collapsed) * CGFloat(progress)
    }

    /// Index-based stagger so the fan opens left-to-right like a paper fan.
    private func staggered(_ p: Double, index: Int, total: Int) -> Double {
        guard total > 1 else { return p }
        let span = 0.45
        let start = (Double(index) / Double(total)) * span
        let scaled = (p - start) / (1 - span)
        return min(max(scaled, 0), 1)
    }
}

private struct CollapsingChevronCrumbsView_CCDemoFoldedCrumb: View {
    let crumb: CollapsingChevronCrumbsView_CCCrumb
    let index: Int
    let total: Int
    let metric: CGFloat
    let progress: Double
    let stackOverlap: CGFloat

    var body: some View {
        let collapsedX = CGFloat(index) * (metric * 0.30)
        let fannedX = CGFloat(index) * (metric * 2.4)
        let x = collapsedX + (fannedX - collapsedX) * CGFloat(progress)

        // Folded crumbs read as a chevron stack: compact (icon-only), rotated
        // slightly, dimmed — but NEVER to zero so the tile is always legible.
        let dim = 0.45 + 0.55 * progress
        let tilt = (1 - progress) * Double(total - 1 - index) * -7.0
        let yLift: CGFloat = (1 - CGFloat(progress)) * CGFloat(total - 1 - index) * (metric * 0.06)

        CollapsingChevronCrumbsView_CCCrumbChip(
            crumb: crumb,
            metric: metric,
            isLeaf: false,
            compact: progress < 0.35,
            dim: dim
        )
        .rotationEffect(.degrees(tilt), anchor: .leading)
        .offset(x: x, y: -yLift)
        .scaleEffect(0.92 + 0.08 * progress, anchor: .leading)
    }
}

/// Tiny "+N" badge that sits on the folded chip while collapsed.
private struct CollapsingChevronCrumbsView_CCStackBadge: View {
    let count: Int
    let metric: CGFloat

    var body: some View {
        Text("+\(count)")
            .font(.system(size: metric * 0.3, weight: .heavy, design: .rounded))
            .foregroundStyle(CollapsingChevronCrumbsView_CCPalette.bg0)
            .padding(.horizontal, metric * 0.18)
            .padding(.vertical, metric * 0.05)
            .background(
                Capsule().fill(
                    LinearGradient(
                        colors: [CollapsingChevronCrumbsView_CCPalette.leaf0, CollapsingChevronCrumbsView_CCPalette.leaf1],
                        startPoint: .topLeading,
                        endPoint: .bottomTrailing
                    )
                )
            )
    }
}

private enum CollapsingChevronCrumbsView_CCEase {
    static func inOut(_ x: Double) -> Double {
        let c = min(max(x, 0), 1)
        return c * c * (3 - 2 * c)
    }

    /// A bouncy spring-ish ease used for the fan-open.
    static func spring(_ x: Double) -> Double {
        let c = min(max(x, 0), 1)
        let s = 1 - pow(1 - c, 2)
        let overshoot = sin(c * .pi) * 0.12 * (1 - c)
        return min(s + overshoot, 1)
    }
}

// MARK: - INTERACTIVE PATH (tap-driven, real matchedGeometryEffect)

private struct CollapsingChevronCrumbsView_CCInteractiveTrail: View {
    let size: CGSize

    @Namespace private var ns
    @State private var expanded: Bool = false
    /// How many leading crumbs are folded behind the chevron chip.
    @State private var foldedCount: Int = 3

    private var metric: CGFloat { max(13, min(size.height, size.width * 0.5) * 0.30) }

    private var foldedCrumbs: [CollapsingChevronCrumbsView_CCCrumb] { Array(CollapsingChevronCrumbsView_CCData.all.prefix(foldedCount)) }
    private var leaf: CollapsingChevronCrumbsView_CCCrumb { CollapsingChevronCrumbsView_CCData.all[foldedCount] }

    var body: some View {
        ZStack {
            if expanded {
                expandedTrail
            } else {
                collapsedTrail
            }
        }
        .frame(maxWidth: .infinity, alignment: .leading)
        .animation(.spring(response: 0.45, dampingFraction: 0.7), value: expanded)
    }

    // Collapsed: chevron stack chip + leaf.
    private var collapsedTrail: some View {
        HStack(spacing: metric * 0.22) {
            collapsedStack
                .contentShape(Rectangle())
                .onTapGesture { toggle() }
            CollapsingChevronCrumbsView_CCChevron(metric: metric, rotation: 0, opacity: 0.7)
            CollapsingChevronCrumbsView_CCCrumbChip(crumb: leaf, metric: metric, isLeaf: true)
                .matchedGeometryEffect(id: leaf.id, in: ns)
        }
        .frame(maxWidth: .infinity, alignment: .leading)
    }

    private var collapsedStack: some View {
        ZStack(alignment: .leading) {
            ForEach(Array(foldedCrumbs.enumerated()), id: \.element.id) { idx, crumb in
                CollapsingChevronCrumbsView_CCCrumbChip(crumb: crumb, metric: metric, isLeaf: false, compact: true, dim: 0.5 + 0.12 * Double(idx))
                    .matchedGeometryEffect(id: crumb.id, in: ns)
                    .rotationEffect(.degrees(Double(foldedCrumbs.count - 1 - idx) * -7), anchor: .leading)
                    .offset(x: CGFloat(idx) * (metric * 0.30))
                    .zIndex(Double(idx))
            }
        }
        .overlay(alignment: .topTrailing) {
            CollapsingChevronCrumbsView_CCStackBadge(count: foldedCount, metric: metric)
                .offset(x: metric * 0.2, y: -metric * 0.3)
        }
        .frame(width: metric * 1.4 + CGFloat(max(0, foldedCount - 1)) * metric * 0.30, alignment: .leading)
    }

    // Expanded: every crumb inline, index-staggered via per-crumb delay.
    private var expandedTrail: some View {
        HStack(spacing: metric * 0.18) {
            ForEach(Array(CollapsingChevronCrumbsView_CCData.all.prefix(foldedCount + 1).enumerated()), id: \.element.id) { idx, crumb in
                let isLeaf = idx == foldedCount
                CollapsingChevronCrumbsView_CCCrumbChip(crumb: crumb, metric: metric, isLeaf: isLeaf)
                    .matchedGeometryEffect(id: crumb.id, in: ns)
                    .onTapGesture { pick(idx) }
                    .transition(.identity)
                if idx < foldedCount {
                    CollapsingChevronCrumbsView_CCChevron(metric: metric, rotation: 0, opacity: 0.6)
                }
            }
        }
        .frame(maxWidth: .infinity, alignment: .leading)
    }

    private func toggle() {
        withAnimation(.spring(response: 0.5, dampingFraction: 0.66)) {
            expanded.toggle()
        }
    }

    /// Picking a crumb re-collapses with a staggered zip; if you pick an older
    /// crumb the trail shortens (you navigated back up the path).
    private func pick(_ idx: Int) {
        withAnimation(.spring(response: 0.45, dampingFraction: 0.7)) {
            if idx < foldedCount {
                foldedCount = max(1, idx)
            }
            expanded = false
        }
    }
}
"""###,
        "nav-comet-trail-crumbs": ###"""
import SwiftUI

// MARK: - Comet Trail Crumbs
// A breadcrumb trail where advancing fires a glowing comet head from the
// current crumb to the next, dragging a tapering, dissolving particle tail.
// The new child crumb lights up on arrival.
//
// demo == true  -> self-driving: the comet perpetually hops crumb -> crumb on
//                  a ~2.6s loop, derived purely from the TimelineView date.
// demo == false -> tap a crumb (or the advance affordance) to fire the comet
//                  toward it; the child crumb reveals when the comet arrives.

struct CometTrailCrumbsView: View {
    var demo: Bool = false

    // Interactive state (demo == false only).
    @State private var fromIndex: Int = 0
    @State private var toIndex: Int = 1
    @State private var revealedCount: Int = 2
    @State private var hopStart: Date = .distantPast
    @State private var arrivalTask: Task<Void, Never>? = nil

    // Tunables.
    private let crumbCount: Int = 4
    private let hopDuration: Double = 1.05
    private let trailParticles: Int = 64

    // Palette (literal colors, no design-system deps).
    private let bg0 = Color(red: 0.043, green: 0.063, blue: 0.086)
    private let bg1 = Color(red: 0.070, green: 0.094, blue: 0.137)
    private let cometCore = Color(red: 0.78, green: 0.92, blue: 1.0)
    private let cometGlow = Color(red: 0.36, green: 0.66, blue: 1.0)
    private let trailWarm = Color(red: 0.56, green: 0.80, blue: 1.0)
    private let crumbLive = Color(red: 0.62, green: 0.86, blue: 1.0)
    private let crumbDim = Color(red: 0.30, green: 0.40, blue: 0.52)

    var body: some View {
        GeometryReader { geo in
            content(in: geo.size)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .onDisappear { arrivalTask?.cancel() }
    }

    // MARK: Layout

    /// Crumb positions along a gentle horizontal arc, derived from size so it
    /// reads at both a 120pt tile and a large detail area.
    private func crumbPositions(in size: CGSize) -> [CGPoint] {
        let n = crumbCount
        guard n > 1 else {
            return [CGPoint(x: size.width / 2, y: size.height / 2)]
        }
        let marginX: CGFloat = max(18, min(size.width, size.height) * 0.16)
        let usableW = max(1, size.width - marginX * 2)
        let midY = size.height * 0.5
        let arc = min(size.height * 0.22, 34)
        var pts: [CGPoint] = []
        pts.reserveCapacity(n)
        for i in 0..<n {
            let f = CGFloat(i) / CGFloat(n - 1)
            let x = marginX + usableW * f
            // Gentle smile arc: lift the ends, dip the middle.
            let y = midY - sin(f * .pi) * arc
            pts.append(CGPoint(x: x, y: y))
        }
        return pts
    }

    private func crumbRadius(in size: CGSize) -> CGFloat {
        max(4.5, min(size.width, size.height) * 0.045)
    }

    // MARK: Content

    private func content(in size: CGSize) -> some View {
        let positions = crumbPositions(in: size)
        return ZStack {
            backdrop
            TimelineView(.animation) { tl in
                let phase = phaseInfo(at: tl.date)
                Canvas { ctx, sz in
                    drawScene(into: &ctx,
                              size: sz,
                              positions: positions,
                              phase: phase)
                }
                .drawingGroup()
            }
            if !demo {
                tapTargets(positions: positions, size: size)
            }
        }
    }

    private var backdrop: some View {
        RadialGradient(
            colors: [bg1, bg0],
            center: .center,
            startRadius: 2,
            endRadius: 220
        )
    }

    /// Invisible tap targets over each crumb for interactive mode.
    private func tapTargets(positions: [CGPoint], size: CGSize) -> some View {
        let r = crumbRadius(in: size)
        let hit = max(r * 2.4, 30)
        return ForEach(positions.indices, id: \.self) { i in
            Circle()
                .fill(Color.white.opacity(0.001))
                .frame(width: hit, height: hit)
                .position(positions[i])
                .contentShape(Circle())
                .onTapGesture { fire(to: i) }
        }
    }

    // MARK: Interaction

    private func fire(to index: Int) {
        guard index != toIndex, index >= 0, index < crumbCount else { return }
        arrivalTask?.cancel()
        fromIndex = toIndex
        toIndex = index
        hopStart = Date()
        let target = index
        let reveal = max(revealedCount, index + 1)
        arrivalTask = Task { @MainActor in
            try? await Task.sleep(nanoseconds: UInt64(hopDuration * 1_000_000_000))
            guard !Task.isCancelled else { return }
            if toIndex == target {
                revealedCount = reveal
            }
        }
    }

    // MARK: Phase derivation (deterministic from the timeline date)

    struct PhaseInfo {
        var from: Int
        var to: Int
        var progress: Double      // 0...1 eased hop progress
        var raw: Double           // 0...1 linear hop progress
        var revealed: Int         // crumbs currently lit
        var headVisible: Bool     // comet head currently in flight / glowing
    }

    private func phaseInfo(at date: Date) -> PhaseInfo {
        if demo {
            return demoPhase(at: date)
        } else {
            return interactivePhase(at: date)
        }
    }

    /// Self-driving loop: comet walks 0->1->2->3 then resets, on ~2.6s beats
    /// with a brief hold so each crumb reads before the next hop.
    private func demoPhase(at date: Date) -> PhaseInfo {
        let beat: Double = 0.95          // seconds per crumb segment
        let segments = crumbCount - 1
        let loop = beat * Double(segments) + 0.7   // + tail hold
        let t = date.timeIntervalSinceReferenceDate
        let local = t.truncatingRemainder(dividingBy: loop)

        // During the active span the comet hops segment by segment.
        let active = beat * Double(segments)
        if local >= active {
            // Hold on the final crumb, all revealed.
            return PhaseInfo(from: max(0, segments - 1),
                             to: segments,
                             progress: 1,
                             raw: 1,
                             revealed: crumbCount,
                             headVisible: false)
        }
        let segIndex = min(segments - 1, Int(local / beat))
        let within = (local - Double(segIndex) * beat) / beat
        let eased = easeInOut(within)
        return PhaseInfo(from: segIndex,
                         to: segIndex + 1,
                         progress: eased,
                         raw: within,
                         revealed: segIndex + 1 + (within > 0.92 ? 1 : 0),
                         headVisible: true)
    }

    private func interactivePhase(at date: Date) -> PhaseInfo {
        let elapsed = date.timeIntervalSince(hopStart)
        let raw = min(1, max(0, elapsed / hopDuration))
        let inFlight = elapsed >= 0 && elapsed <= hopDuration + 0.25
        return PhaseInfo(from: fromIndex,
                         to: toIndex,
                         progress: easeInOut(raw),
                         raw: raw,
                         revealed: revealedCount,
                         headVisible: inFlight && raw < 1.0)
    }

    private func easeInOut(_ x: Double) -> Double {
        let c = min(1, max(0, x))
        return c * c * (3 - 2 * c)
    }

    // MARK: Drawing

    private func drawScene(into ctx: inout GraphicsContext,
                           size: CGSize,
                           positions: [CGPoint],
                           phase: PhaseInfo) {
        guard positions.count >= 2 else { return }

        drawConnectors(into: &ctx, positions: positions, phase: phase)
        drawCrumbs(into: &ctx, size: size, positions: positions, phase: phase)

        let from = clampIndex(phase.from, positions.count)
        let to = clampIndex(phase.to, positions.count)
        let headPos = lerpPoint(positions[from], positions[to], CGFloat(phase.progress))

        if phase.headVisible {
            drawTrail(into: &ctx,
                      from: positions[from],
                      to: positions[to],
                      progress: phase.progress,
                      headPos: headPos)
            drawCometHead(into: &ctx, at: headPos, size: size, progress: phase.progress)
        }
    }

    private func clampIndex(_ i: Int, _ count: Int) -> Int {
        min(max(0, i), count - 1)
    }

    /// Faint static guide line between consecutive crumbs that have been reached.
    private func drawConnectors(into ctx: inout GraphicsContext,
                                positions: [CGPoint],
                                phase: PhaseInfo) {
        for i in 0..<(positions.count - 1) {
            let reached = (i + 1) < phase.revealed
            let opacity: Double = reached ? 0.18 : 0.06
            var path = Path()
            path.move(to: positions[i])
            path.addLine(to: positions[i + 1])
            ctx.stroke(
                path,
                with: .color(crumbDim.opacity(opacity)),
                style: StrokeStyle(lineWidth: 1.2, lineCap: .round, dash: [2, 5])
            )
        }
    }

    private func drawCrumbs(into ctx: inout GraphicsContext,
                            size: CGSize,
                            positions: [CGPoint],
                            phase: PhaseInfo) {
        let r = crumbRadius(in: size)
        for i in positions.indices {
            let lit = i < phase.revealed
            let isHead = (i == clampIndex(phase.to, positions.count)) && lit
            // Pulse the just-arrived crumb.
            let pulse: CGFloat = (isHead && phase.headVisible == false && phase.progress >= 1)
                ? 1.0 + 0.25 * CGFloat(arrivalPulse(phase))
                : 1.0
            drawCrumbDot(into: &ctx,
                         center: positions[i],
                         radius: r * pulse,
                         lit: lit)
        }
    }

    private func arrivalPulse(_ phase: PhaseInfo) -> Double {
        // Small decaying flash right after arrival (raw near/at 1).
        let x = max(0, min(1, (phase.raw - 0.85) / 0.15))
        return sin(x * .pi)
    }

    private func drawCrumbDot(into ctx: inout GraphicsContext,
                              center: CGPoint,
                              radius r: CGFloat,
                              lit: Bool) {
        let outer = CGRect(x: center.x - r, y: center.y - r, width: r * 2, height: r * 2)

        if lit {
            // Soft halo (additive) for a lit crumb.
            var glow = ctx
            glow.blendMode = .plusLighter
            let haloR = r * 2.4
            let halo = CGRect(x: center.x - haloR, y: center.y - haloR,
                              width: haloR * 2, height: haloR * 2)
            glow.fill(
                Circle().path(in: halo),
                with: .radialGradient(
                    Gradient(colors: [cometGlow.opacity(0.28), .clear]),
                    center: center, startRadius: 0, endRadius: haloR
                )
            )
        }

        // Ring.
        ctx.stroke(
            Circle().path(in: outer.insetBy(dx: -1, dy: -1)),
            with: .color((lit ? crumbLive : crumbDim).opacity(lit ? 0.9 : 0.5)),
            lineWidth: 1.4
        )
        // Core fill.
        ctx.fill(
            Circle().path(in: outer.insetBy(dx: r * 0.34, dy: r * 0.34)),
            with: .color(lit ? crumbLive : crumbDim.opacity(0.55))
        )
    }

    /// Tapering particle tail behind the head. Each particle k sits at the head
    /// position sampled a little earlier in the hop, with a deterministic
    /// perpendicular jitter so it scatters rather than reads as a smooth ribbon.
    private func drawTrail(into ctx: inout GraphicsContext,
                           from: CGPoint,
                           to: CGPoint,
                           progress: Double,
                           headPos: CGPoint) {
        var trail = ctx
        trail.blendMode = .plusLighter

        let dx = to.x - from.x
        let dy = to.y - from.y
        let len = max(0.0001, hypot(dx, dy))
        let nx = -dy / len   // unit perpendicular
        let ny = dx / len

        let n = trailParticles
        let span: Double = 0.42   // how far back (in progress units) the tail reaches
        for k in 0..<n {
            let f = Double(k) / Double(n - 1)         // 0 = head, 1 = tail end
            let sampleP = progress - f * span
            guard sampleP >= 0 else { continue }
            let px = from.x + CGFloat(sampleP) * dx
            let py = from.y + CGFloat(sampleP) * dy

            let jitterAmp = CGFloat(2.6 + 6.0 * f)    // spreads out toward the tail
            let j = (hash01(k) - 0.5) * 2.0 * jitterAmp
            let wobble = sin(Double(k) * 1.7 + progress * 6.0) * Double(2.0 * f)
            let off = j + CGFloat(wobble)
            let cx = px + nx * off
            let cy = py + ny * off

            let taper = (1.0 - f)
            let radius = CGFloat(0.8 + 2.6 * taper * taper)
            let alpha = (0.30 * taper * taper) * (0.6 + 0.4 * Double(hash01(k * 7 + 3)))

            let rect = CGRect(x: cx - radius, y: cy - radius,
                              width: radius * 2, height: radius * 2)
            let mix = trailWarm.opacity(alpha)
            trail.fill(Circle().path(in: rect), with: .color(mix))
        }
    }

    private func drawCometHead(into ctx: inout GraphicsContext,
                               at p: CGPoint,
                               size: CGSize,
                               progress: Double) {
        var glow = ctx
        glow.blendMode = .plusLighter

        let base = max(6, min(size.width, size.height) * 0.05)
        // Slight breathing so the head never reads as a flat dot.
        let pulse = 1.0 + 0.12 * sin(progress * .pi * 4)
        let glowR = base * 2.6 * CGFloat(pulse)
        let glowRect = CGRect(x: p.x - glowR, y: p.y - glowR,
                              width: glowR * 2, height: glowR * 2)
        glow.fill(
            Circle().path(in: glowRect),
            with: .radialGradient(
                Gradient(colors: [
                    cometGlow.opacity(0.55),
                    cometGlow.opacity(0.18),
                    .clear
                ]),
                center: p, startRadius: 0, endRadius: glowR
            )
        )

        // Bright hot core.
        let coreR = base * 0.55
        let coreRect = CGRect(x: p.x - coreR, y: p.y - coreR,
                              width: coreR * 2, height: coreR * 2)
        glow.fill(
            Circle().path(in: coreRect),
            with: .radialGradient(
                Gradient(colors: [Color.white, cometCore.opacity(0.9), .clear]),
                center: p, startRadius: 0, endRadius: coreR
            )
        )
    }

    // MARK: Helpers

    private func lerpPoint(_ a: CGPoint, _ b: CGPoint, _ t: CGFloat) -> CGPoint {
        CGPoint(x: a.x + (b.x - a.x) * t, y: a.y + (b.y - a.y) * t)
    }

    /// Deterministic 0...1 hash for stable per-particle jitter.
    private func hash01(_ i: Int) -> CGFloat {
        let x = sin(Double(i) * 127.1 + 311.7) * 43758.5453
        return CGFloat(x - floor(x))
    }
}
"""###,
        "nav-concertina-sidebar": ###"""
import SwiftUI

// MARK: - Concertina Sidebar
// Sidebar rows reveal as an accordion bellows: each row unfolds from a flattened
// sliver with a staggered spring (top-to-bottom), and collapses by squeezing back
// into a visible stack of thin slivers. A faint rotation3DEffect adds the pleat
// catching light.
//
//  - demo == true  : a self-driving TimelineView(.animation) breathes the panel
//                    open -> hold -> closed -> hold on a ~4s loop. Collapsed rows
//                    stay as a visible stack (never blank).
//  - demo == false : a real tappable menu button toggles `open` with a staggered
//                    per-row spring.

struct ConcertinaSidebarView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { geo in
            ConcertinaSidebarView_ConcertinaContent(demo: demo, size: geo.size)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // Shared palette (single source of truth referenced from every subview).
    static let ink = Color(red: 0.92, green: 0.94, blue: 0.97)
    static let accent = Color(red: 0.36, green: 0.78, blue: 0.98)
}

// MARK: - Content

private struct ConcertinaSidebarView_ConcertinaContent: View {
    let demo: Bool
    let size: CGSize

    @State private var open: Bool = true

    // Menu rows. Kept short so the panel reads in a 120pt tile.
    private let rows: [ConcertinaSidebarView_SidebarRowModel] = [
        ConcertinaSidebarView_SidebarRowModel(symbol: "square.grid.2x2.fill", title: "Dashboard"),
        ConcertinaSidebarView_SidebarRowModel(symbol: "tray.full.fill",       title: "Inbox"),
        ConcertinaSidebarView_SidebarRowModel(symbol: "chart.bar.fill",       title: "Insights"),
        ConcertinaSidebarView_SidebarRowModel(symbol: "person.2.fill",        title: "Team"),
        ConcertinaSidebarView_SidebarRowModel(symbol: "gearshape.fill",       title: "Settings")
    ]

    var body: some View {
        if demo {
            TimelineView(.animation) { timeline in
                let t = timeline.date.timeIntervalSinceReferenceDate
                panel(globalProgress: loopProgress(at: t))
            }
        } else {
            panel(globalProgress: open ? 1.0 : 0.0)
        }
    }

    // MARK: Layout

    private func panel(globalProgress: Double) -> some View {
        let metrics = ConcertinaSidebarView_PanelMetrics(size: size, rowCount: rows.count)
        return VStack(spacing: 0) {
            header(metrics: metrics)
            rowStack(globalProgress: globalProgress, metrics: metrics)
        }
        .padding(metrics.outerPadding)
        .frame(maxWidth: .infinity, maxHeight: .infinity, alignment: .top)
        .background(panelBackground(metrics: metrics))
    }

    private func header(metrics: ConcertinaSidebarView_PanelMetrics) -> some View {
        HStack(spacing: metrics.headerSpacing) {
            menuButton(metrics: metrics)
            if metrics.showsHeaderTitle {
                Text("Menu")
                    .font(.system(size: metrics.titleFont, weight: .semibold, design: .rounded))
                    .foregroundStyle(ConcertinaSidebarView.ink.opacity(0.9))
                Spacer(minLength: 0)
            } else {
                Spacer(minLength: 0)
            }
        }
        .frame(height: metrics.headerHeight)
        .padding(.bottom, metrics.headerGap)
    }

    @ViewBuilder
    private func menuButton(metrics: ConcertinaSidebarView_PanelMetrics) -> some View {
        if demo {
            // Non-interactive in the tile; just a static hamburger mark.
            ConcertinaSidebarView_HamburgerMark(size: metrics.chevronSize)
                .frame(width: metrics.buttonSize, height: metrics.buttonSize)
                .background(buttonBackground)
        } else {
            Button {
                withAnimation(.spring(response: 0.45, dampingFraction: 0.7)) {
                    open.toggle()
                }
            } label: {
                ConcertinaSidebarView_ChevronGlyph(open: open, size: metrics.chevronSize)
                    .frame(width: metrics.buttonSize, height: metrics.buttonSize)
                    .background(buttonBackground)
                    .contentShape(Rectangle())
            }
            .buttonStyle(.plain)
        }
    }

    private var buttonBackground: some View {
        RoundedRectangle(cornerRadius: 9, style: .continuous)
            .fill(ConcertinaSidebarView.accent.opacity(0.18))
            .overlay(
                RoundedRectangle(cornerRadius: 9, style: .continuous)
                    .strokeBorder(ConcertinaSidebarView.accent.opacity(0.35), lineWidth: 1)
            )
    }

    private func rowStack(globalProgress: Double, metrics: ConcertinaSidebarView_PanelMetrics) -> some View {
        VStack(spacing: metrics.rowSpacing) {
            ForEach(Array(rows.enumerated()), id: \.element.id) { index, model in
                ConcertinaSidebarView_ConcertinaRow(
                    model: model,
                    index: index,
                    count: rows.count,
                    progress: rowProgress(globalProgress: globalProgress, index: index),
                    demo: demo,
                    metrics: metrics
                )
            }
        }
    }

    private func panelBackground(metrics: ConcertinaSidebarView_PanelMetrics) -> some View {
        RoundedRectangle(cornerRadius: metrics.panelCorner, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.09, green: 0.11, blue: 0.14),
                        Color(red: 0.06, green: 0.07, blue: 0.10)
                    ],
                    startPoint: .top,
                    endPoint: .bottom
                )
            )
            .overlay(
                RoundedRectangle(cornerRadius: metrics.panelCorner, style: .continuous)
                    .strokeBorder(Color.white.opacity(0.06), lineWidth: 1)
            )
    }

    // MARK: Progress math

    /// Per-row progress with a top-to-bottom stagger. The stagger compresses the
    /// useful range of the global progress so earlier rows lead and later rows trail.
    private func rowProgress(globalProgress: Double, index: Int) -> Double {
        let count = max(rows.count, 1)
        let stagger = 0.45                       // total fraction reserved for the cascade
        let per = stagger / Double(count)
        let start = per * Double(index)
        let span = 1.0 - stagger
        let local = (globalProgress - start) / max(span, 0.0001)
        return clamp(local, lower: 0.0, upper: 1.0)
    }

    /// Self-driving schedule for demo: ease-open -> hold -> ease-closed -> hold.
    /// 4.0s loop (sits inside the 2.5-4s window).
    private func loopProgress(at time: Double) -> Double {
        let period = 4.0
        let phase = time.truncatingRemainder(dividingBy: period) / period   // 0..1
        let openDur = 0.30      // fraction spent opening
        let holdOpen = 0.20
        let closeDur = 0.30
        // remaining ~0.20 holds closed
        if phase < openDur {
            return easeInOut(phase / openDur)
        } else if phase < openDur + holdOpen {
            return 1.0
        } else if phase < openDur + holdOpen + closeDur {
            let p = (phase - openDur - holdOpen) / closeDur
            return easeInOut(1.0 - p)
        } else {
            return 0.0
        }
    }

    private func easeInOut(_ x: Double) -> Double {
        let c = clamp(x, lower: 0.0, upper: 1.0)
        return c * c * (3.0 - 2.0 * c)
    }

    private func clamp(_ x: Double, lower: Double, upper: Double) -> Double {
        min(max(x, lower), upper)
    }
}

// MARK: - Row

private struct ConcertinaSidebarView_ConcertinaRow: View {
    let model: ConcertinaSidebarView_SidebarRowModel
    let index: Int
    let count: Int
    let progress: Double          // 0 = squeezed sliver, 1 = fully unfolded
    let demo: Bool
    let metrics: ConcertinaSidebarView_PanelMetrics

    var body: some View {
        let p = progress

        // Floor the collapsed state so the panel squeezes into a *visible* stack,
        // never a blank frame. Scale eases from a thin sliver up to full height.
        let minScale: CGFloat = 0.10
        let scaleY = minScale + (1.0 - minScale) * CGFloat(p)

        // Opacity floor keeps collapsed rows legible (>= ~0.22).
        let opacity = 0.22 + 0.78 * p

        // Faint bellows pleat: the fold tips toward the viewer when collapsed.
        let foldAngle = (1.0 - p) * 58.0       // degrees

        // Collapsed rows overlap slightly to read as a stack of pleats.
        let collapseOffset = CGFloat(1.0 - p) * metrics.collapseStackOffset

        // Per-row staggered spring in tap mode (the bellows "wow"). Guarded to the
        // interactive branch so it never fights the per-frame TimelineView in demo.
        let rowAnimation: Animation? = demo
            ? nil
            : .spring(response: 0.5, dampingFraction: 0.72).delay(Double(index) * 0.06)

        return content
            .frame(height: metrics.rowHeight)
            .scaleEffect(x: 1.0, y: scaleY, anchor: .top)
            .rotation3DEffect(
                .degrees(foldAngle),
                axis: (x: 1, y: 0, z: 0),
                anchor: .top,
                anchorZ: 0,
                perspective: 0.55
            )
            .offset(y: -collapseOffset)
            .opacity(opacity)
            .zIndex(Double(count - index))     // upper rows fold over lower ones
            .animation(rowAnimation, value: progress)
    }

    private var content: some View {
        HStack(spacing: metrics.rowSpacing) {
            iconWell
            if metrics.showsRowTitle {
                Text(model.title)
                    .font(.system(size: metrics.rowFont, weight: .medium, design: .rounded))
                    .foregroundStyle(ConcertinaSidebarView.ink.opacity(0.92))
                    .lineLimit(1)
                Spacer(minLength: 0)
            } else {
                Spacer(minLength: 0)
            }
        }
        .padding(.horizontal, metrics.rowHPadding)
        .frame(maxWidth: .infinity, maxHeight: .infinity, alignment: .leading)
        .background(rowBackground)
    }

    private var iconWell: some View {
        Image(systemName: model.symbol)
            .font(.system(size: metrics.iconFont, weight: .semibold))
            .foregroundStyle(ConcertinaSidebarView.accent)
            .frame(width: metrics.iconWell, height: metrics.iconWell)
    }

    private var rowBackground: some View {
        // Top-edge highlight + body fill fakes the pleat catching light.
        RoundedRectangle(cornerRadius: metrics.rowCorner, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color.white.opacity(0.10),
                        Color.white.opacity(0.03)
                    ],
                    startPoint: .top,
                    endPoint: .bottom
                )
            )
            .overlay(
                RoundedRectangle(cornerRadius: metrics.rowCorner, style: .continuous)
                    .strokeBorder(Color.white.opacity(0.07), lineWidth: 0.75)
            )
    }
}

// MARK: - Chevron / Hamburger marks

private struct ConcertinaSidebarView_ChevronGlyph: View {
    let open: Bool
    let size: CGFloat

    var body: some View {
        Image(systemName: "line.3.horizontal")
            .font(.system(size: size, weight: .bold))
            .foregroundStyle(ConcertinaSidebarView.accent)
            .rotationEffect(.degrees(open ? 90 : 0))
            .scaleEffect(open ? 1.0 : 0.92)
    }
}

private struct ConcertinaSidebarView_HamburgerMark: View {
    let size: CGFloat
    var body: some View {
        Image(systemName: "line.3.horizontal")
            .font(.system(size: size, weight: .bold))
            .foregroundStyle(ConcertinaSidebarView.accent)
    }
}

// MARK: - Model

private struct ConcertinaSidebarView_SidebarRowModel: Identifiable {
    let id = UUID()
    let symbol: String
    let title: String
}

// MARK: - Metrics (all derived from the available size)

private struct ConcertinaSidebarView_PanelMetrics {
    let size: CGSize
    let rowCount: Int

    // A coarse "is this a tiny tile?" gate to drop labels in the grid preview.
    private var isCompact: Bool { size.width < 200 || size.height < 200 }

    var outerPadding: CGFloat { isCompact ? 7 : 16 }
    var panelCorner: CGFloat { isCompact ? 12 : 22 }

    var headerHeight: CGFloat {
        let h = size.height * 0.16
        return min(max(h, 22), 52)
    }
    var headerGap: CGFloat { isCompact ? 5 : 12 }
    var headerSpacing: CGFloat { isCompact ? 6 : 12 }
    var showsHeaderTitle: Bool { !isCompact }
    var titleFont: CGFloat { 16 }

    var buttonSize: CGFloat { min(headerHeight, isCompact ? 24 : 40) }
    var chevronSize: CGFloat { isCompact ? 10 : 16 }

    // Rows fill the remaining vertical space evenly so it works in tile + detail.
    var rowSpacing: CGFloat { isCompact ? 4 : 9 }

    private var availableRowSpace: CGFloat {
        let used = outerPadding * 2 + headerHeight + headerGap
        let spacingTotal = rowSpacing * CGFloat(max(rowCount - 1, 0))
        return max(size.height - used - spacingTotal, CGFloat(rowCount) * 6)
    }
    var rowHeight: CGFloat { availableRowSpace / CGFloat(max(rowCount, 1)) }

    var rowCorner: CGFloat { min(rowHeight * 0.32, isCompact ? 8 : 14) }
    var rowHPadding: CGFloat { isCompact ? 6 : 14 }
    var rowFont: CGFloat { isCompact ? 11 : 15 }
    var showsRowTitle: Bool { !isCompact && rowHeight > 26 }

    var iconWell: CGFloat { min(rowHeight * 0.72, isCompact ? 18 : 30) }
    var iconFont: CGFloat { isCompact ? 9 : 14 }

    // How far collapsed rows slide up to overlap into a stack of pleats.
    var collapseStackOffset: CGFloat { rowHeight * 0.42 }
}
"""###,
        "nav-flipboard-segment": ###"""
import SwiftUI

// MARK: - Flipboard Segment
// A segmented control whose labels are rendered as split-flap (airport board) tiles.
// Switching segments flips the old label's characters down and the new label's up
// in a staggered per-tile cascade with a small mechanical overshoot.
//
// demo == true  -> a PhaseAnimator steps the selected segment on a ~3s dwell so the
//                  board keeps clattering through label changes with no touch.
// demo == false -> tap a segment tab to select it; the change re-fires every tile's
//                  KeyframeAnimator with an index-based stagger.

struct FlipboardSegmentView: View {
    var demo: Bool = false

    // The segment labels. Kept short (<= 8 chars) per the mechanism's perf note.
    private let segments: [String] = ["HOME", "INBOX", "ALERTS"]

    @State private var selectedIndex: Int = 0

    // Stable tile count for the whole board: the widest label. Keeping the tile
    // count fixed means each tile flips in place across swaps (stable identity)
    // instead of tiles being added/removed.
    private var tileCount: Int {
        max(segments.map { $0.count }.max() ?? 1, 1)
    }

    var body: some View {
        GeometryReader { geo in
            content(in: geo.size)
                .frame(maxWidth: .infinity, maxHeight: .infinity)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    @ViewBuilder
    private func content(in size: CGSize) -> some View {
        if demo {
            demoBoard(in: size)
        } else {
            interactiveBoard(in: size)
        }
    }

    // MARK: Demo (self-driving)

    @ViewBuilder
    private func demoBoard(in size: CGSize) -> some View {
        // The no-trigger PhaseAnimator cycles continuously through the phases
        // (0,1,2,0,1,2,...). Each step bumps the label the tiles render and thus
        // their changeID, re-firing the flip cascade. The dwell is controlled by
        // the per-phase animation's .delay.
        PhaseAnimator(Array(segments.indices)) { phaseIndex in
            board(label: segments[phaseIndex],
                  size: size,
                  tabs: tabStrip(active: phaseIndex, tappable: false))
        } animation: { _ in
            // ~3s dwell on each label before stepping to the next.
            .easeInOut(duration: 0.01).delay(3.0)
        }
    }

    // MARK: Interactive (tap-driven)

    @ViewBuilder
    private func interactiveBoard(in size: CGSize) -> some View {
        board(label: segments[selectedIndex],
              size: size,
              tabs: tabStrip(active: selectedIndex, tappable: true))
    }

    // MARK: Shared board layout

    @ViewBuilder
    private func board(label: String, size: CGSize, tabs: some View) -> some View {
        let board = boardMetrics(in: size)

        VStack(spacing: board.gap) {
            FlipboardSegmentView_FlipLabel(text: label,
                      tileCount: tileCount,
                      tileWidth: board.tileWidth,
                      tileHeight: board.tileHeight,
                      spacing: board.tileSpacing)
                .frame(height: board.tileHeight)
            tabs
                .frame(height: board.tabHeight)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .padding(board.outerPadding)
        .background(boardBackground(corner: board.boardCorner))
    }

    private func tabStrip(active: Int, tappable: Bool) -> some View {
        HStack(spacing: 6) {
            ForEach(segments.indices, id: \.self) { idx in
                FlipboardSegmentView_SegmentTab(title: segments[idx],
                           isActive: idx == active)
                    .contentShape(Rectangle())
                    .onTapGesture {
                        guard tappable else { return }
                        withAnimation(.spring(response: 0.35, dampingFraction: 0.8)) {
                            selectedIndex = idx
                        }
                    }
            }
        }
    }

    private func boardBackground(corner: CGFloat) -> some View {
        RoundedRectangle(cornerRadius: corner, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.06, green: 0.08, blue: 0.10),
                        Color(red: 0.03, green: 0.04, blue: 0.06)
                    ],
                    startPoint: .top,
                    endPoint: .bottom
                )
            )
    }

    // MARK: Metrics

    struct BoardMetrics {
        var tileWidth: CGFloat
        var tileHeight: CGFloat
        var tileSpacing: CGFloat
        var gap: CGFloat
        var tabHeight: CGFloat
        var outerPadding: CGFloat
        var boardCorner: CGFloat
    }

    private func boardMetrics(in size: CGSize) -> BoardMetrics {
        let minSide: CGFloat = max(40, min(size.width, size.height))
        let maxChars: CGFloat = CGFloat(tileCount)

        // Fit the widest label horizontally with a little breathing room.
        let usableWidth: CGFloat = max(20, size.width * 0.92)
        let perChar: CGFloat = usableWidth / max(1, maxChars)
        var tileWidth: CGFloat = min(perChar * 0.82, minSide * 0.20)
        tileWidth = max(8, tileWidth)
        let tileHeight: CGFloat = tileWidth * 1.45

        return BoardMetrics(
            tileWidth: tileWidth,
            tileHeight: tileHeight,
            tileSpacing: max(1.5, tileWidth * 0.10),
            gap: max(6, minSide * 0.08),
            tabHeight: max(14, minSide * 0.16),
            outerPadding: max(6, minSide * 0.06),
            boardCorner: max(8, minSide * 0.10)
        )
    }
}

// MARK: - Flip Label

/// A fixed-width row of flip tiles. Pads to the widest segment so tile identity
/// (and therefore each tile's previous/current glyph) stays stable across swaps.
private struct FlipboardSegmentView_FlipLabel: View {
    let text: String
    let tileCount: Int
    let tileWidth: CGFloat
    let tileHeight: CGFloat
    let spacing: CGFloat

    private var characters: [Character] {
        Array(text.uppercased())
    }

    var body: some View {
        HStack(spacing: spacing) {
            ForEach(0..<max(tileCount, 1), id: \.self) { i in
                FlipboardSegmentView_FlipTile(
                    char: glyph(at: i),
                    index: i,
                    tileWidth: tileWidth,
                    tileHeight: tileHeight
                )
            }
        }
    }

    private func glyph(at i: Int) -> Character {
        guard i >= 0, i < characters.count else { return " " }
        return characters[i]
    }
}

// MARK: - Flip Tile

/// One split-flap character cell.
///
/// Layering (back -> front):
///   1. static upper  = NEW char top half   (revealed as the falling flap drops)
///   2. static lower  = OLD char bottom half (covered as the rising flap closes)
///   3. falling flap  = OLD char top half    (anchor .bottom, 0 -> -90 over p 0..0.5)
///   4. rising flap   = NEW char bottom half  (anchor .top,   90 -> 0 over p 0.5..1)
///
/// Driven by a single `progress` 0->1 per swap. The KeyframeAnimator replays on every
/// `changeID` change (and once on appear). A leading hold bakes in the per-tile stagger,
/// and a spring overshoot on the rising flap's final track gives the mechanical bounce.
private struct FlipboardSegmentView_FlipTile: View {
    let char: Character
    let index: Int
    let tileWidth: CGFloat
    let tileHeight: CGFloat

    // Track the glyph across changes so the animation has both OLD and NEW.
    @State private var oldChar: Character
    @State private var newChar: Character
    @State private var changeID: Int = 0

    init(char: Character, index: Int, tileWidth: CGFloat, tileHeight: CGFloat) {
        self.char = char
        self.index = index
        self.tileWidth = tileWidth
        self.tileHeight = tileHeight
        // Start settled: old == new so the opening replay does not flip to garbage.
        _oldChar = State(initialValue: char)
        _newChar = State(initialValue: char)
    }

    private var halfHeight: CGFloat { tileHeight / 2 }
    private var stagger: Double { Double(index) * 0.09 }
    private var flipDuration: Double { 0.42 }

    var body: some View {
        KeyframeAnimator(initialValue: 0.0, trigger: changeID) { progress in
            tileBody(progress: progress)
        } keyframes: { _ in
            // Leading hold = per-tile stagger (KeyframeAnimator has no .delay()).
            KeyframeTrack(\.self) {
                LinearKeyframe(0.0, duration: stagger)
                // Top flap falls 0 -> -90.
                CubicKeyframe(0.5, duration: flipDuration * 0.5)
                // Bottom flap rises 90 -> 0 with a touch of spring bounce on landing.
                SpringKeyframe(1.0, duration: flipDuration * 0.5,
                               spring: .init(response: 0.28, dampingRatio: 0.55))
            }
        }
        .frame(width: tileWidth, height: tileHeight)
        .onChange(of: char) { _, newValue in
            guard newValue != newChar else { return }
            oldChar = newChar
            newChar = newValue
            changeID &+= 1
        }
    }

    // MARK: Composition

    private func tileBody(progress p: Double) -> some View {
        let a = angles(p)
        return ZStack {
            // 1. static upper: NEW top half
            staticHalf(char: newChar, isTop: true)

            // 2. static lower: OLD bottom half
            staticHalf(char: oldChar, isTop: false)

            // 3. falling flap: OLD top half (front, occludes NEW top until it drops)
            flap(char: oldChar, isTop: true, angle: a.top)

            // 4. rising flap: NEW bottom half (front, closes over OLD bottom)
            flap(char: newChar, isTop: false, angle: a.bottom)
        }
        .frame(width: tileWidth, height: tileHeight)
        .background(tileShell)
        .clipShape(RoundedRectangle(cornerRadius: tileWidth * 0.16, style: .continuous))
        .overlay(hingeLine)
    }

    /// Top flap: 0 -> -90 over p in 0..0.5, then parked at -90 (edge-on, invisible).
    /// Bottom flap: parked at 90 (edge-on) over 0..0.5, then 90 -> 0 over 0.5..1.
    private func angles(_ p: Double) -> (top: Double, bottom: Double) {
        let topAngle: Double
        let bottomAngle: Double
        if p <= 0.5 {
            let t = p / 0.5
            topAngle = -90.0 * t
            bottomAngle = 90.0
        } else {
            let t = (p - 0.5) / 0.5
            topAngle = -90.0
            bottomAngle = 90.0 * (1.0 - t)
        }
        return (topAngle, bottomAngle)
    }

    // MARK: Halves

    /// A static (non-rotating) half of a glyph cell.
    private func staticHalf(char: Character, isTop: Bool) -> some View {
        halfGlyph(char: char, isTop: isTop)
            .frame(width: tileWidth, height: tileHeight, alignment: isTop ? .top : .bottom)
    }

    /// A hinged flap holding one half of a glyph, rotated about its hinge edge.
    private func flap(char: Character, isTop: Bool, angle: Double) -> some View {
        halfGlyph(char: char, isTop: isTop)
            .frame(width: tileWidth, height: tileHeight, alignment: isTop ? .top : .bottom)
            .rotation3DEffect(
                .degrees(angle),
                axis: (x: 1, y: 0, z: 0),
                anchor: isTop ? .bottom : .top,
                anchorZ: 0,
                perspective: 0.55
            )
    }

    /// One half of a full-size glyph, clipped to the top or bottom of the cell,
    /// with a subtle vertical shade so the hinge catches light.
    private func halfGlyph(char: Character, isTop: Bool) -> some View {
        ZStack {
            RoundedRectangle(cornerRadius: tileWidth * 0.16, style: .continuous)
                .fill(panelGradient(isTop: isTop))

            Text(String(char))
                .font(.system(size: tileHeight * 0.62, weight: .heavy, design: .rounded))
                .monospacedDigit()
                .foregroundColor(Color(red: 0.92, green: 0.95, blue: 0.98))
                .frame(width: tileWidth, height: tileHeight)
        }
        .frame(width: tileWidth, height: tileHeight, alignment: .center)
        // Show only the top or bottom half of the full-size composition.
        .frame(height: halfHeight, alignment: isTop ? .top : .bottom)
        .clipped()
    }

    // MARK: Decoration

    private func panelGradient(isTop: Bool) -> LinearGradient {
        let top = Color(red: 0.16, green: 0.18, blue: 0.21)
        let bottom = Color(red: 0.10, green: 0.11, blue: 0.13)
        return LinearGradient(
            colors: isTop ? [top, bottom] : [bottom, Color(red: 0.07, green: 0.08, blue: 0.10)],
            startPoint: .top,
            endPoint: .bottom
        )
    }

    private var tileShell: some View {
        RoundedRectangle(cornerRadius: tileWidth * 0.16, style: .continuous)
            .fill(Color(red: 0.05, green: 0.06, blue: 0.07))
    }

    private var hingeLine: some View {
        VStack(spacing: 0) {
            Spacer(minLength: 0)
            Rectangle()
                .fill(Color.black.opacity(0.55))
                .frame(height: max(0.75, tileHeight * 0.02))
            Spacer(minLength: 0)
        }
        .allowsHitTesting(false)
    }
}

// MARK: - Segment Tab

private struct FlipboardSegmentView_SegmentTab: View {
    let title: String
    let isActive: Bool

    var body: some View {
        Text(title)
            .font(.system(size: 11, weight: .semibold, design: .rounded))
            .lineLimit(1)
            .minimumScaleFactor(0.6)
            .foregroundColor(isActive
                              ? Color(red: 0.05, green: 0.06, blue: 0.08)
                              : Color(red: 0.62, green: 0.66, blue: 0.72))
            .padding(.horizontal, 8)
            .frame(maxWidth: .infinity, maxHeight: .infinity)
            .background(
                RoundedRectangle(cornerRadius: 7, style: .continuous)
                    .fill(isActive
                          ? Color(red: 0.96, green: 0.78, blue: 0.30)
                          : Color(red: 0.12, green: 0.14, blue: 0.17))
            )
    }
}
"""###,
        "nav-genie-magnify-dock": ###"""
import SwiftUI

// MARK: - Genie Magnify Dock
// A macOS-style dock: icons magnify on a Gaussian bell-curve as the touch
// glides across, neighbors falling off smoothly, and a tapped icon stretches
// up into a "genie" squash before popping back to rest.
//
// demo == true  -> a TimelineView sweeps a synthetic touchX back and forth on a
//                  sine loop so the magnification travels along the dock with no
//                  finger. Base icons are always visible, so it is never blank.
// demo == false -> a DragGesture(minimumDistance: 0) feeds location.x into the
//                  live Gaussian scale, and a tap fires the genie squash-pop.

public struct GenieMagnifyDockView: View {
    public var demo: Bool = false

    public init(demo: Bool = false) {
        self.demo = demo
    }

    public var body: some View {
        GeometryReader { geo in
            content(in: geo.size)
                .frame(maxWidth: .infinity, maxHeight: .infinity)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    @ViewBuilder
    private func content(in size: CGSize) -> some View {
        if demo {
            GenieMagnifyDockView_DemoDock(size: size)
        } else {
            GenieMagnifyDockView_InteractiveDock(size: size)
        }
    }
}

// MARK: - Shared geometry / styling

private struct GenieMagnifyDockView_DockMetrics {
    let size: CGSize
    let iconCount: Int

    // The dock content sits in the lower portion of the tile, leaving headroom
    // above for magnified icons to grow upward.
    var contentWidth: CGFloat { size.width }

    // Icon footprint scales with the available size so it works at ~120pt and large.
    var iconSize: CGFloat {
        let byWidth = size.width / (CGFloat(iconCount) + 1.4)
        let byHeight = size.height * 0.30
        return max(14, min(byWidth, byHeight))
    }

    var spacing: CGFloat { iconSize * 0.34 }

    // The pitch between icon centers.
    var pitch: CGFloat { iconSize + spacing }

    var rowWidth: CGFloat {
        iconSize * CGFloat(iconCount) + spacing * CGFloat(max(iconCount - 1, 0))
    }

    var leadingInset: CGFloat { (size.width - rowWidth) / 2 }

    // Center x of icon i within the full size.
    func centerX(_ i: Int) -> CGFloat {
        leadingInset + iconSize / 2 + CGFloat(i) * pitch
    }

    // The dock floor: icons rest just above the bottom of the tile.
    var floorY: CGFloat { size.height - max(8, size.height * 0.10) }

    // Sigma is tied to the pitch so the bell spans ~2 neighbors at any size.
    var sigma: CGFloat { pitch * 1.15 }

    // How much an icon may grow at the peak of the bell.
    var amplitude: CGFloat { 0.95 }
}

// Gaussian magnification factor for an icon center given the touch x.
// Factored out (and fully annotated) to keep the type-checker fast.
private func gaussianScale(iconCenterX: CGFloat,
                           touchX: CGFloat?,
                           sigma: CGFloat,
                           amplitude: CGFloat) -> CGFloat {
    guard let touchX else { return 1.0 }
    let safeSigma: CGFloat = max(sigma, 0.0001)
    let d: CGFloat = touchX - iconCenterX
    let denom: CGFloat = 2.0 * safeSigma * safeSigma
    let bell: CGFloat = exp(-(d * d) / denom)
    return 1.0 + amplitude * bell
}

private let dockIconNames: [String] = [
    "house.fill",
    "magnifyingglass",
    "bubble.left.fill",
    "heart.fill",
    "camera.fill",
    "gearshape.fill"
]

private let dockIconColors: [Color] = [
    Color(red: 0.36, green: 0.62, blue: 0.98),
    Color(red: 0.42, green: 0.80, blue: 0.55),
    Color(red: 0.98, green: 0.72, blue: 0.30),
    Color(red: 0.95, green: 0.42, blue: 0.50),
    Color(red: 0.62, green: 0.50, blue: 0.96),
    Color(red: 0.50, green: 0.78, blue: 0.86)
]

// MARK: - A single dock icon

private struct GenieMagnifyDockView_DockIcon: View {
    let index: Int
    let metrics: GenieMagnifyDockView_DockMetrics
    let touchX: CGFloat?
    let isPopping: Bool

    private var iconName: String {
        dockIconNames[index % dockIconNames.count]
    }

    private var iconColor: Color {
        dockIconColors[index % dockIconColors.count]
    }

    private var magnify: CGFloat {
        gaussianScale(iconCenterX: metrics.centerX(index),
                      touchX: touchX,
                      sigma: metrics.sigma,
                      amplitude: metrics.amplitude)
    }

    var body: some View {
        tile
            .frame(width: metrics.iconSize, height: metrics.iconSize)
            // The genie modifier applies the live magnify (anchored to the dock
            // floor so icons grow upward) AND the squash-pop in one scaleEffect,
            // so magnification is applied exactly once.
            .geniePop(active: isPopping, baseScale: magnify)
            .animation(.spring(response: 0.32, dampingFraction: 0.72), value: touchX == nil)
    }

    private var tile: some View {
        let r: CGFloat = metrics.iconSize * 0.26
        return RoundedRectangle(cornerRadius: r, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [iconColor, iconColor.opacity(0.78)],
                    startPoint: .top,
                    endPoint: .bottom
                )
            )
            .overlay(
                RoundedRectangle(cornerRadius: r, style: .continuous)
                    .stroke(Color.white.opacity(0.28), lineWidth: 0.8)
            )
            .overlay(
                Image(systemName: iconName)
                    .font(.system(size: metrics.iconSize * 0.46, weight: .semibold))
                    .foregroundStyle(Color.white)
                    .shadow(color: Color.black.opacity(0.25), radius: 1, y: 1)
            )
            .shadow(color: Color.black.opacity(0.30),
                    radius: metrics.iconSize * 0.14,
                    y: metrics.iconSize * 0.10)
    }
}

// MARK: - Genie squash-pop modifier (KeyframeAnimator, iOS 17)

private struct GenieMagnifyDockView_GeniePop: ViewModifier {
    let active: Bool
    let baseScale: CGFloat

    struct Frame {
        var stretchY: CGFloat = 1.0
        var squashX: CGFloat = 1.0
        var lift: CGFloat = 0.0
        var glow: CGFloat = 0.0
    }

    func body(content: Content) -> some View {
        content
            .keyframeAnimator(
                initialValue: Frame(),
                trigger: active
            ) { view, frame in
                view
                    // Combine the live magnify with the genie stretch/squash.
                    .scaleEffect(
                        x: baseScale * frame.squashX,
                        y: baseScale * frame.stretchY,
                        anchor: .bottom
                    )
                    .offset(y: -frame.lift)
                    .overlay(glowOverlay(frame.glow))
            } keyframes: { _ in
                // Tall genie stretch, then a brief squash, then settle to base (1.0).
                KeyframeTrack(\.stretchY) {
                    SpringKeyframe(1.55, duration: 0.16, spring: .snappy)
                    CubicKeyframe(0.80, duration: 0.10)
                    SpringKeyframe(1.0, duration: 0.30, spring: .bouncy)
                }
                KeyframeTrack(\.squashX) {
                    SpringKeyframe(0.74, duration: 0.16, spring: .snappy)
                    CubicKeyframe(1.14, duration: 0.10)
                    SpringKeyframe(1.0, duration: 0.30, spring: .bouncy)
                }
                KeyframeTrack(\.lift) {
                    SpringKeyframe(1.0, duration: 0.16, spring: .snappy)
                    CubicKeyframe(1.0, duration: 0.10)
                    SpringKeyframe(0.0, duration: 0.30, spring: .bouncy)
                }
                KeyframeTrack(\.glow) {
                    LinearKeyframe(1.0, duration: 0.16)
                    LinearKeyframe(0.0, duration: 0.40)
                }
            }
    }

    private func glowOverlay(_ amount: CGFloat) -> some View {
        RoundedRectangle(cornerRadius: 6, style: .continuous)
            .stroke(Color.white.opacity(Double(amount) * 0.9), lineWidth: 2)
            .blur(radius: 3)
            .opacity(Double(amount))
            .allowsHitTesting(false)
    }
}

private extension View {
    func geniePop(active: Bool, baseScale: CGFloat) -> some View {
        modifier(GenieMagnifyDockView_GeniePop(active: active, baseScale: baseScale))
    }
}

// MARK: - The dock row + tray (shared chrome)

private struct GenieMagnifyDockView_DockRow: View {
    let metrics: GenieMagnifyDockView_DockMetrics
    let touchX: CGFloat?
    let poppingIndex: Int?

    var body: some View {
        ZStack {
            tray
            icons
        }
        .frame(width: metrics.size.width, height: metrics.size.height)
    }

    private var tray: some View {
        // A frosted dock tray pinned to the floor.
        let trayHeight: CGFloat = metrics.iconSize * 1.5
        let trayWidth: CGFloat = metrics.rowWidth + metrics.iconSize * 0.9
        return RoundedRectangle(cornerRadius: trayHeight * 0.32, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.16, green: 0.18, blue: 0.22).opacity(0.92),
                        Color(red: 0.10, green: 0.11, blue: 0.14).opacity(0.92)
                    ],
                    startPoint: .top,
                    endPoint: .bottom
                )
            )
            .overlay(
                RoundedRectangle(cornerRadius: trayHeight * 0.32, style: .continuous)
                    .stroke(Color.white.opacity(0.10), lineWidth: 1)
            )
            .frame(width: max(trayWidth, 0), height: trayHeight)
            .position(x: metrics.size.width / 2,
                      y: metrics.floorY - trayHeight / 2 + metrics.iconSize * 0.18)
            .shadow(color: Color.black.opacity(0.35), radius: 10, y: 6)
    }

    private var icons: some View {
        ForEach(0..<metrics.iconCount, id: \.self) { i in
            GenieMagnifyDockView_DockIcon(
                index: i,
                metrics: metrics,
                touchX: touchX,
                isPopping: poppingIndex == i
            )
            // Bottom-anchored so the icon foot rests on the floor and grows up.
            .position(x: metrics.centerX(i),
                      y: metrics.floorY - metrics.iconSize / 2)
        }
    }
}

// MARK: - Demo (self-driving) dock

private struct GenieMagnifyDockView_DemoDock: View {
    let size: CGSize

    private var metrics: GenieMagnifyDockView_DockMetrics {
        GenieMagnifyDockView_DockMetrics(size: size, iconCount: resolvedCount)
    }

    private var resolvedCount: Int {
        // Fewer icons in a cramped tile, more when there's room.
        size.width < 220 ? 5 : 6
    }

    var body: some View {
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            let touchX = sweepX(at: t)
            let popping = autoPopIndex(at: t)
            GenieMagnifyDockView_DockRow(metrics: metrics, touchX: touchX, poppingIndex: popping)
        }
    }

    // Sine sweep eases at the turnarounds (no sawtooth snap).
    private func sweepX(at t: TimeInterval) -> CGFloat {
        let period: Double = 3.2
        let phase = (t.truncatingRemainder(dividingBy: period)) / period
        let s = (sin(phase * 2.0 * .pi - .pi / 2) + 1.0) / 2.0  // 0...1 eased
        let left = metrics.centerX(0)
        let right = metrics.centerX(metrics.iconCount - 1)
        return left + CGFloat(s) * (right - left)
    }

    // Pop the icon nearest the synthetic touch each time the sweep reverses
    // near an end, keyed so the KeyframeAnimator retriggers cleanly.
    private func autoPopIndex(at t: TimeInterval) -> Int? {
        let popPeriod: Double = 3.2
        let slot = Int(t / popPeriod)
        // Alternate ends so the genie pop is visible on both sides over time.
        return slot.isMultiple(of: 2) ? (metrics.iconCount - 1) : 0
    }
}

// MARK: - Interactive dock

private struct GenieMagnifyDockView_InteractiveDock: View {
    let size: CGSize

    @State private var touchX: CGFloat? = nil
    @State private var poppingIndex: Int? = nil

    private var metrics: GenieMagnifyDockView_DockMetrics {
        GenieMagnifyDockView_DockMetrics(size: size, iconCount: resolvedCount)
    }

    private var resolvedCount: Int {
        size.width < 220 ? 5 : 6
    }

    var body: some View {
        GenieMagnifyDockView_DockRow(metrics: metrics, touchX: touchX, poppingIndex: poppingIndex)
            .contentShape(Rectangle())
            .gesture(dragGesture)
    }

    private var dragGesture: some Gesture {
        // minimumDistance: 0 so the piece wins inside a ScrollView.
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                touchX = value.location.x
            }
            .onEnded { value in
                fireGenie(at: value.location.x)
                withAnimation(.spring(response: 0.36, dampingFraction: 0.72)) {
                    touchX = nil
                }
            }
    }

    // A drag that ends on/over an icon fires the genie squash-pop on it.
    private func fireGenie(at x: CGFloat) {
        guard let i = nearestIcon(to: x) else { return }
        let dx = abs(x - metrics.centerX(i))
        guard dx <= metrics.iconSize * 0.75 else { return }
        poppingIndex = nil
        DispatchQueue.main.async {
            poppingIndex = i
        }
    }

    private func nearestIcon(to x: CGFloat) -> Int? {
        guard metrics.iconCount > 0 else { return nil }
        var best = 0
        var bestD = CGFloat.greatestFiniteMagnitude
        for i in 0..<metrics.iconCount {
            let d = abs(x - metrics.centerX(i))
            if d < bestD { bestD = d; best = i }
        }
        return best
    }
}
"""###,
        "nav-inkbleed-segment": ###"""
import SwiftUI

/// Ink Bleed Segment — a segmented control where tapping a segment drops a spot
/// of ink that organically bleeds outward to fill exactly that segment's bounds
/// with a feathered, slightly jittering edge, while the previously-selected
/// segment's ink simultaneously drains away.
///
/// Rendering is done with `Canvas` clipped per-segment. Fill progress is a *pure
/// function of time* computed inside a `TimelineView(.animation)` render closure
/// (Canvas does not interpolate `withAnimation`-driven state), so the bleed tweens
/// smoothly in both the interactive and the self-driving demo modes.
struct InkbleedSegmentView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { geo in
            InkbleedSegmentView_InkbleedSegmentControl(demo: demo, size: geo.size)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }
}

// MARK: - Control

private struct InkbleedSegmentView_InkbleedSegmentControl: View {
    let demo: Bool
    let size: CGSize

    private let labels = ["Ink", "Bleed", "Flow"]

    /// The currently committed selection.
    @State private var selectedIndex: Int = 0
    /// Fill values captured at the moment the last transition began.
    @State private var fromFills: [Double] = [1, 0, 0]
    /// When the current transition started (TimelineView clock).
    @State private var transitionStart: Date = .distantPast
    /// Origins (0...1 within each segment) of the ink drop per segment.
    @State private var origins: [CGPoint]

    /// Duration of one bleed transition.
    private let transitionDuration: Double = 0.45
    /// Demo dwell per segment.
    private let demoDwell: Double = 1.0

    init(demo: Bool, size: CGSize) {
        self.demo = demo
        self.size = size
        _origins = State(initialValue: Array(repeating: CGPoint(x: 0.5, y: 0.5), count: 3))
    }

    var body: some View {
        let metrics = InkbleedSegmentView_Metrics(size: size, count: labels.count)

        TimelineView(.animation) { timeline in
            let now = timeline.date
            ZStack {
                background(metrics: metrics)
                inkCanvas(now: now, metrics: metrics)
                labelsOverlay(now: now, metrics: metrics)
            }
            .frame(width: metrics.width, height: metrics.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .contentShape(RoundedRectangle(cornerRadius: 24))
    }

    // MARK: Layers

    private func background(metrics: InkbleedSegmentView_Metrics) -> some View {
        let shape = RoundedRectangle(cornerRadius: metrics.cornerRadius, style: .continuous)
        return shape
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.93, green: 0.91, blue: 0.86),
                        Color(red: 0.88, green: 0.85, blue: 0.79)
                    ],
                    startPoint: .top, endPoint: .bottom
                )
            )
            .overlay(
                shape.stroke(Color(red: 0.74, green: 0.70, blue: 0.62), lineWidth: 1)
            )
            .frame(width: metrics.width, height: metrics.height)
    }

    private func inkCanvas(now: Date, metrics: InkbleedSegmentView_Metrics) -> some View {
        let fills = currentFills(now: now)
        let t = now.timeIntervalSinceReferenceDate
        return Canvas { ctx, _ in
            for i in 0..<labels.count {
                let progress = fills[i]
                guard progress > 0.001 else { continue }
                let rect = metrics.segmentRect(i)
                drawBlob(in: &ctx, rect: rect, progress: progress,
                         origin: origin(i), time: t, seed: Double(i),
                         cornerRadius: metrics.innerCornerRadius)
            }
        }
        .frame(width: metrics.width, height: metrics.height)
    }

    private func labelsOverlay(now: Date, metrics: InkbleedSegmentView_Metrics) -> some View {
        let fills = currentFills(now: now)
        return ZStack {
            ForEach(0..<labels.count, id: \.self) { i in
                segmentLabel(index: i, fill: fills[i], metrics: metrics)
            }
        }
        .frame(width: metrics.width, height: metrics.height)
        .contentShape(Rectangle())
        .gesture(tapGesture(metrics: metrics))
    }

    private func segmentLabel(index i: Int, fill: Double, metrics: InkbleedSegmentView_Metrics) -> some View {
        let rect = metrics.segmentRect(i)
        // Label flips from dark (on paper) to near-white (on ink) as the fill rises.
        let inkAmount = min(1.0, fill * 1.15)
        let textColor = Color(
            red: 0.12 + 0.84 * inkAmount,
            green: 0.13 + 0.83 * inkAmount,
            blue: 0.16 + 0.80 * inkAmount
        )
        return Text(labels[i])
            .font(.system(size: metrics.fontSize, weight: .semibold, design: .rounded))
            .foregroundStyle(textColor)
            .lineLimit(1)
            .minimumScaleFactor(0.5)
            .shadow(color: Color.black.opacity(0.18 * inkAmount), radius: 1, y: 0.5)
            .frame(width: rect.width, height: rect.height)
            .position(x: rect.midX, y: rect.midY)
    }

    // MARK: Ink drawing

    private func drawBlob(in ctx: inout GraphicsContext,
                          rect: CGRect,
                          progress: Double,
                          origin: CGPoint,
                          time: Double,
                          seed: Double,
                          cornerRadius: CGFloat) {
        var layer = ctx
        // 1. Clip to this segment's rounded rect — ink can never spill into neighbours.
        let segClip = Path(roundedRect: rect, cornerRadius: cornerRadius, style: .continuous)
        layer.clip(to: segClip)

        let center = CGPoint(
            x: rect.minX + origin.x * rect.width,
            y: rect.minY + origin.y * rect.height
        )
        // Reach the far diagonal so progress == 1 floods every corner.
        let maxReach = hypot(rect.width, rect.height)
        let baseRadius = CGFloat(progress) * maxReach * 1.04
        guard baseRadius > 0.5 else { return }

        // Build the wobbly front. `peak` is its maximum radial extent so the
        // feather can be aimed exactly at the irregular rim.
        let wobble = wobblyPath(center: center, radius: baseRadius,
                                time: time, seed: seed)

        // 2. Intersect the clip with the wobbly blob → containment AND an irregular,
        //    organic boundary (a radial gradient alone is radially symmetric).
        layer.clip(to: wobble.path)
        // 3. Soften that irregular cut so it reads as wet ink, not a hard stamp.
        //    (blur is added AFTER both clips, so it cannot bleed past the segment.)
        layer.addFilter(.blur(radius: max(0.6, baseRadius * 0.045)))

        let inkCore = Color(red: 0.07, green: 0.09, blue: 0.13)
        let inkEdge = Color(red: 0.10, green: 0.13, blue: 0.20)

        // 4. Feathered fill: dense core → translucent rim, with the rim landing at
        //    the wobbly edge (endRadius == path peak), so the feather is the boundary.
        let gradient = Gradient(stops: [
            .init(color: inkCore, location: 0.0),
            .init(color: inkCore, location: 0.66),
            .init(color: inkEdge.opacity(0.9), location: 0.85),
            .init(color: inkEdge.opacity(0.45), location: 0.95),
            .init(color: inkEdge.opacity(0.0), location: 1.0)
        ])
        let shading = GraphicsContext.Shading.radialGradient(
            gradient,
            center: center,
            startRadius: 0,
            endRadius: max(wobble.peak, 1)
        )
        // Fill the whole segment rect; the wobbly clip shapes it, the gradient feathers it.
        layer.fill(segClip, with: shading)

        // A few soaking satellite droplets near the front for organic bleed.
        drawSatellites(in: &layer, center: center, radius: baseRadius,
                       time: time, seed: seed, color: inkEdge)
    }

    /// A closed, time-animated wobbly circle plus its maximum radial extent.
    private func wobblyPath(center: CGPoint, radius: CGFloat,
                            time: Double, seed: Double) -> (path: Path, peak: CGFloat) {
        var path = Path()
        let steps = 48
        let amp = 0.08 + 0.025 * sin(time * 0.9 + seed)   // breathing edge amplitude
        var peak: CGFloat = radius
        for s in 0...steps {
            let frac = Double(s) / Double(steps)
            let angle = frac * 2 * Double.pi
            // Layered sine lobes (time-based, never re-seeded randomness).
            let w = 1.0
                + amp * sin(angle * 3 + time * 1.6 + seed * 1.7)
                + amp * 0.6 * sin(angle * 5 - time * 1.1 + seed)
                + amp * 0.4 * sin(angle * 8 + time * 0.7)
            let r = radius * CGFloat(max(0.2, w))
            if r > peak { peak = r }
            let p = CGPoint(
                x: center.x + r * CGFloat(cos(angle)),
                y: center.y + r * CGFloat(sin(angle))
            )
            if s == 0 { path.move(to: p) } else { path.addLine(to: p) }
        }
        path.closeSubpath()
        return (path, peak)
    }

    private func drawSatellites(in ctx: inout GraphicsContext,
                                center: CGPoint, radius: CGFloat,
                                time: Double, seed: Double, color: Color) {
        guard radius > 6 else { return }
        let count = 5
        for k in 0..<count {
            let a = Double(k) / Double(count) * 2 * Double.pi + seed
            let drift = 0.78 + 0.16 * sin(time * 1.3 + Double(k) * 2.1 + seed)
            let dr = radius * CGFloat(drift)
            let p = CGPoint(
                x: center.x + dr * CGFloat(cos(a + time * 0.25)),
                y: center.y + dr * CGFloat(sin(a + time * 0.25))
            )
            let dotR = radius * 0.06 * CGFloat(0.7 + 0.4 * sin(time * 2 + Double(k)))
            let dot = Path(ellipseIn: CGRect(x: p.x - dotR, y: p.y - dotR,
                                             width: dotR * 2, height: dotR * 2))
            ctx.fill(dot, with: .color(color.opacity(0.35)))
        }
    }

    // MARK: Fill computation (time-driven)

    private func currentFills(now: Date) -> [Double] {
        if demo { return demoFills(now: now) }
        return interactiveFills(now: now)
    }

    private func interactiveFills(now: Date) -> [Double] {
        let elapsed = now.timeIntervalSinceReferenceDate
            - transitionStart.timeIntervalSinceReferenceDate
        let raw = elapsed / transitionDuration
        let t = min(1.0, max(0.0, raw))
        let eased = easeOut(t)
        var result = [Double](repeating: 0, count: labels.count)
        for i in 0..<labels.count {
            let target: Double = (i == selectedIndex) ? 1.0 : 0.0
            let from = i < fromFills.count ? fromFills[i] : 0
            result[i] = from + (target - from) * eased
        }
        return result
    }

    /// Self-driving fills, computed purely from the clock — no state mutation.
    /// Each segment dwells `demoDwell`; the leading `transitionDuration` of every
    /// dwell tweens the new segment up and the previous one down.
    private func demoFills(now: Date) -> [Double] {
        let period = demoDwell * Double(labels.count)
        let phase = now.timeIntervalSinceReferenceDate
            .truncatingRemainder(dividingBy: period)
        let slot = Int(phase / demoDwell)                 // current segment index
        let prev = (slot - 1 + labels.count) % labels.count
        let localT = phase - Double(slot) * demoDwell     // time within this dwell
        let eased = easeOut(min(1.0, localT / transitionDuration))
        var result = [Double](repeating: 0, count: labels.count)
        for i in 0..<labels.count {
            if i == slot {
                result[i] = eased
            } else if i == prev {
                result[i] = 1 - eased
            } else {
                result[i] = 0
            }
        }
        return result
    }

    /// Demo ink origin varies per segment so the bleed never looks mechanical.
    private func demoOrigin(_ i: Int) -> CGPoint {
        let xs: [CGFloat] = [0.28, 0.5, 0.72]
        return CGPoint(x: xs[i % xs.count], y: 0.5)
    }

    private func origin(_ i: Int) -> CGPoint {
        demo ? demoOrigin(i) : origins[i]
    }

    private func easeOut(_ t: Double) -> Double {
        1 - pow(1 - t, 3)
    }

    // MARK: Interaction

    private func tapGesture(metrics: InkbleedSegmentView_Metrics) -> some Gesture {
        SpatialTapGesture()
            .onEnded { value in
                guard !demo else { return }
                let i = metrics.segmentIndex(forX: value.location.x)
                commit(to: i, at: value.location, metrics: metrics)
            }
    }

    private func commit(to index: Int, at location: CGPoint, metrics: InkbleedSegmentView_Metrics) {
        guard index != selectedIndex else { return }
        let now = Date()
        // Snapshot the fills as they are right now so the new transition tweens
        // smoothly from the live state (handles rapid re-taps mid-bleed).
        fromFills = currentFills(now: now)
        // Ink origin = local tap point inside the tapped segment (fallback center).
        let rect = metrics.segmentRect(index)
        let ox = rect.width > 0 ? (location.x - rect.minX) / rect.width : 0.5
        let oy = rect.height > 0 ? (location.y - rect.minY) / rect.height : 0.5
        origins[index] = CGPoint(
            x: min(0.95, max(0.05, ox)),
            y: min(0.9, max(0.1, oy))
        )
        selectedIndex = index
        transitionStart = now
    }
}

// MARK: - Layout metrics

private struct InkbleedSegmentView_Metrics {
    let width: CGFloat
    let height: CGFloat
    let count: Int
    let inset: CGFloat
    let cornerRadius: CGFloat

    init(size: CGSize, count: Int) {
        // Clamp to a control-shaped band so it reads well in both a 120pt tile
        // and a large detail area.
        let w = max(40, size.width)
        let h = max(28, size.height)
        let bandHeight = min(h, max(40, w * 0.32))
        self.width = w
        self.height = min(h, bandHeight)
        self.count = max(1, count)
        self.inset = max(3, self.height * 0.08)
        self.cornerRadius = min(self.height / 2, 26)
    }

    var innerWidth: CGFloat { width - inset * 2 }
    var innerHeight: CGFloat { height - inset * 2 }
    var segmentWidth: CGFloat { innerWidth / CGFloat(count) }
    var innerCornerRadius: CGFloat { max(0, cornerRadius - inset) }

    var fontSize: CGFloat {
        max(9, min(18, height * 0.34))
    }

    func segmentRect(_ i: Int) -> CGRect {
        CGRect(
            x: inset + segmentWidth * CGFloat(i),
            y: inset,
            width: segmentWidth,
            height: innerHeight
        )
    }

    func segmentIndex(forX x: CGFloat) -> Int {
        let local = x - inset
        let raw = Int(local / max(1, segmentWidth))
        return min(count - 1, max(0, raw))
    }
}
"""###,
        "nav-magnetic-grab-drawer": ###"""
import SwiftUI

// MARK: - Magnetic Grab Drawer
// A thin edge handle that leans toward your finger with a magnetic pull,
// stretches a rubbery neck as you drag the drawer out, and recoils with a
// velocity-aware spring on release.
struct MagneticGrabDrawerView: View {
    var demo: Bool = false

    // Single source of truth shared by interactive + demo render paths.
    // openProgress: 0 = drawer tucked at edge, 1 = fully pulled out.
    // handleLeanY:  0 = handle resting at its rail center,
    //              ±1 = handle leaned fully toward the touch (vertical offset).
    @State private var openProgress: CGFloat = 0
    @State private var handleLeanY: CGFloat = 0

    // Haptic latch: flips when the magnetic attraction first "grabs".
    @State private var snapLatch: Int = 0
    @State private var isGrabbed: Bool = false

    var body: some View {
        GeometryReader { geo in
            if demo {
                demoBody(in: geo.size)
            } else {
                interactiveBody(in: geo.size)
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .background(Color(red: 0.063, green: 0.078, blue: 0.094))
        .sensoryFeedback(.impact(weight: .medium), trigger: snapLatch)
    }

    // MARK: Demo (self-driving synthetic finger)

    private func demoBody(in size: CGSize) -> some View {
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            let phase = MagneticGrabDrawerView_DemoFinger.sample(at: t)
            MagneticGrabDrawerView_DrawerStage(
                size: size,
                openProgress: phase.open,
                handleLeanY: phase.lean
            )
            .onChange(of: phase.grabbed) { _, grabbed in
                if grabbed { snapLatch &+= 1 }
            }
        }
    }

    // MARK: Interactive

    private func interactiveBody(in size: CGSize) -> some View {
        MagneticGrabDrawerView_DrawerStage(
            size: size,
            openProgress: openProgress,
            handleLeanY: handleLeanY
        )
        .contentShape(Rectangle())
        .gesture(drawerDrag(in: size))
    }

    private func drawerDrag(in size: CGSize) -> some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                let metrics = MagneticGrabDrawerView_DrawerMetrics(size: size)
                // Pull-out distance maps drag.x onto open progress.
                let raw = value.translation.width / metrics.travel
                openProgress = clamp(raw, 0, 1.08) // small overscroll headroom

                // Handle leans toward the finger's vertical position.
                let railCenterY = metrics.railCenterY
                let dy = value.location.y - railCenterY
                let lean = attractionCurve(dy / (metrics.height * 0.5))
                handleLeanY = lean

                // Magnetic "grab": fire haptic once when lean first exceeds threshold.
                let grabbing = abs(lean) > 0.35 || openProgress > 0.06
                if grabbing && !isGrabbed {
                    isGrabbed = true
                    snapLatch &+= 1
                } else if !grabbing {
                    isGrabbed = false
                }
            }
            .onEnded { value in
                let metrics = MagneticGrabDrawerView_DrawerMetrics(size: size)
                // Velocity-aware: blend release point + predicted travel.
                let predicted = value.predictedEndTranslation.width / metrics.travel
                let projected = (openProgress + predicted) * 0.5
                let shouldOpen = projected > 0.5
                // Normalized initial velocity seed (kept reasonable, not exact physics).
                let v = value.velocity.width / metrics.travel
                let seedVelocity = clamp(v, -6, 6)

                isGrabbed = false
                withAnimation(.interpolatingSpring(
                    mass: 0.9,
                    stiffness: 140,
                    damping: 13,
                    initialVelocity: seedVelocity
                )) {
                    openProgress = shouldOpen ? 1 : 0
                    handleLeanY = 0
                }
            }
    }

    private func attractionCurve(_ x: CGFloat) -> CGFloat {
        // Eager near center, eases off near the rail ends so the handle
        // lunges to meet the finger without overshooting the edge.
        let c = clamp(x, -1, 1)
        let eased = c * (1.6 - 0.6 * abs(c))
        return clamp(eased, -1, 1)
    }
}

// MARK: - Demo finger script

private enum MagneticGrabDrawerView_DemoFinger {
    struct Phase {
        var open: CGFloat
        var lean: CGFloat
        var grabbed: Bool
    }

    // ~3.0s loop: approach (handle reaches) -> grab -> stretch out -> recoil.
    static func sample(at time: TimeInterval) -> Phase {
        let period: Double = 3.0
        let u = (time.truncatingRemainder(dividingBy: period)) / period // 0..1

        // Lean: finger sweeps in, handle lunges to meet it, then releases.
        // Stays non-zero through the active window; rests near 0 otherwise.
        let lean: CGFloat
        if u < 0.18 {
            // approach: lean ramps up toward finger
            lean = ease(CGFloat(u / 0.18)) * 0.85
        } else if u < 0.72 {
            // held: gentle sinusoidal sway while drawer is out
            let s = CGFloat((u - 0.18) / 0.54)
            lean = 0.85 - 0.45 * (1 - cos(s * .pi * 2)) * 0.5
        } else {
            // recoil: lean settles back to neutral
            let s = CGFloat((u - 0.72) / 0.28)
            lean = (1 - ease(s)) * 0.4
        }

        // Open: closed -> stretch out -> hold -> spring recoil closed.
        let open: CGFloat
        if u < 0.18 {
            open = ease(CGFloat(u / 0.18)) * 0.12 // handle nudges as it grabs
        } else if u < 0.55 {
            // stretch the drawer out
            open = 0.12 + ease(CGFloat((u - 0.18) / 0.37)) * 0.88
        } else if u < 0.72 {
            open = 1.0 // hold open
        } else {
            // recoil with a little overshoot then settle closed
            let s = CGFloat((u - 0.72) / 0.28)
            let settle = 1 - ease(s)
            let overshoot = sin(s * .pi * 3) * 0.06 * (1 - s)
            open = max(0, settle - overshoot)
        }

        // Grab moment: just after approach completes.
        let grabbed = u >= 0.16 && u < 0.20
        return Phase(open: open, lean: clamp(lean, -1, 1), grabbed: grabbed)
    }

    static func ease(_ t: CGFloat) -> CGFloat {
        let c = clamp(t, 0, 1)
        return c * c * (3 - 2 * c)
    }
}

// MARK: - Layout metrics

private struct MagneticGrabDrawerView_DrawerMetrics {
    let size: CGSize

    init(size: CGSize) { self.size = size }

    var width: CGFloat { size.width }
    var height: CGFloat { size.height }

    // Handle is a thin pill anchored to the left edge.
    var handleWidth: CGFloat { max(8, min(width, height) * 0.07) }
    var handleHeight: CGFloat { height * 0.34 }
    var handleRestX: CGFloat { handleWidth * 0.5 + width * 0.02 }
    var railCenterY: CGFloat { height * 0.5 }

    // How far the drawer body travels from tucked to fully open.
    var travel: CGFloat { width * 0.62 }

    // Drawer body geometry.
    var bodyWidth: CGFloat { max(28, width * 0.30) }
    var bodyHeight: CGFloat { height * 0.74 }
    // Tucked just off the left edge; pulled out by openProgress * travel.
    var bodyTuckedX: CGFloat { -bodyWidth * 0.62 }

    // Shared geometry resolvers so the stage AND the animatable neck compute
    // the handle/body anchor points from identical formulas. This keeps the
    // tether endpoints locked to the handle/body during the release spring.
    func clampedOpen(_ open: CGFloat) -> CGFloat { min(max(open, 0), 1.08) }

    func handleCenter(open: CGFloat, lean: CGFloat) -> CGPoint {
        let co = clampedOpen(open)
        let leanMax = height * 0.30
        let x = handleRestX + co * (handleWidth * 0.6)
        let y = railCenterY + lean * leanMax
        return CGPoint(x: x, y: y)
    }

    func bodyCenter(open: CGFloat, lean: CGFloat) -> CGPoint {
        let co = clampedOpen(open)
        let x = bodyTuckedX + bodyWidth * 0.5 + co * travel
        // Body lags slightly toward the handle's lean (tether drag).
        let y = railCenterY + lean * (height * 0.10) * co
        return CGPoint(x: x, y: y)
    }
}

// MARK: - The composed stage (shared by demo + interactive)

private struct MagneticGrabDrawerView_DrawerStage: View {
    let size: CGSize
    let openProgress: CGFloat
    let handleLeanY: CGFloat

    private var m: MagneticGrabDrawerView_DrawerMetrics { MagneticGrabDrawerView_DrawerMetrics(size: size) }

    // Resolved geometry from the two driving values.
    private var clampedOpen: CGFloat { m.clampedOpen(openProgress) }
    private var handleCenter: CGPoint { m.handleCenter(open: openProgress, lean: handleLeanY) }
    private var bodyCenter: CGPoint { m.bodyCenter(open: openProgress, lean: handleLeanY) }

    var body: some View {
        ZStack {
            railGuide
            neck
            drawerBody
            handle
        }
    }

    // Faint rail showing the handle's vertical track.
    private var railGuide: some View {
        Capsule()
            .fill(Color(red: 1, green: 1, blue: 1).opacity(0.05))
            .frame(width: m.handleWidth * 0.5, height: m.height * 0.62)
            .position(x: m.handleRestX, y: m.railCenterY)
    }

    // Rubbery tether connecting handle tip to the drawer body edge.
    // MagneticGrabDrawerView_NeckShape owns its geometry (resolves endpoints from open/lean internally)
    // so its endpoints animate on the same spring as the handle/body positions.
    private var neck: some View {
        MagneticGrabDrawerView_NeckShape(
            size: size,
            open: openProgress,
            lean: handleLeanY,
            thickness: m.handleWidth * 0.9
        )
        .fill(
            LinearGradient(
                colors: [
                    Color(red: 0.36, green: 0.58, blue: 0.98),
                    Color(red: 0.24, green: 0.40, blue: 0.86)
                ],
                startPoint: .leading,
                endPoint: .trailing
            )
        )
        .opacity(0.92)
    }

    private var drawerBody: some View {
        RoundedRectangle(cornerRadius: min(m.bodyWidth, m.bodyHeight) * 0.18, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.20, green: 0.35, blue: 0.80),
                        Color(red: 0.14, green: 0.24, blue: 0.62)
                    ],
                    startPoint: .topLeading,
                    endPoint: .bottomTrailing
                )
            )
            .overlay(
                RoundedRectangle(cornerRadius: min(m.bodyWidth, m.bodyHeight) * 0.18, style: .continuous)
                    .strokeBorder(Color(red: 1, green: 1, blue: 1).opacity(0.14), lineWidth: 1)
            )
            .overlay(drawerContent)
            .frame(width: m.bodyWidth, height: m.bodyHeight)
            .shadow(color: Color(red: 0, green: 0, blue: 0).opacity(0.35),
                    radius: 10 * clampedOpen + 2, x: 6 * clampedOpen, y: 4)
            .position(bodyCenter)
    }

    private var drawerContent: some View {
        VStack(spacing: m.bodyHeight * 0.08) {
            ForEach(0..<3, id: \.self) { _ in
                Capsule()
                    .fill(Color(red: 1, green: 1, blue: 1).opacity(0.22))
                    .frame(height: max(3, m.bodyHeight * 0.05))
            }
        }
        .padding(.horizontal, m.bodyWidth * 0.18)
        .opacity(Double(min(1, clampedOpen * 1.6)))
    }

    private var handle: some View {
        Capsule(style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.62, green: 0.78, blue: 1.0),
                        Color(red: 0.40, green: 0.60, blue: 0.98)
                    ],
                    startPoint: .top,
                    endPoint: .bottom
                )
            )
            .overlay(
                Capsule(style: .continuous)
                    .strokeBorder(Color(red: 1, green: 1, blue: 1).opacity(0.30), lineWidth: 1)
            )
            .frame(width: m.handleWidth, height: m.handleHeight)
            .shadow(color: Color(red: 0.2, green: 0.4, blue: 1).opacity(0.45),
                    radius: 6, x: 0, y: 0)
            .position(handleCenter)
    }
}

// MARK: - Animatable rubber neck

private struct MagneticGrabDrawerView_NeckShape: Shape {
    var size: CGSize         // stage size, used to resolve endpoint geometry
    var open: CGFloat        // openProgress  (animated on release)
    var lean: CGFloat        // handleLeanY   (animated on release)
    var thickness: CGFloat

    // BOTH open + lean are animated on release so the spring returns the
    // drawer AND handle endpoints together, in lockstep with the handle/body
    // .position(...) — no detachment, no kink.
    var animatableData: AnimatablePair<CGFloat, CGFloat> {
        get { AnimatablePair(open, lean) }
        set {
            open = newValue.first
            lean = newValue.second
        }
    }

    func path(in rect: CGRect) -> Path {
        let m = MagneticGrabDrawerView_DrawerMetrics(size: size)
        // Resolve endpoints from the SAME formulas the stage uses, at the
        // currently-interpolated open/lean — so the tether tracks the spring.
        let handleTip = m.handleCenter(open: open, lean: lean)
        let body = m.bodyCenter(open: open, lean: lean)
        let bodyEdge = CGPoint(x: body.x - m.bodyWidth * 0.5, y: body.y)

        let co = max(0, m.clampedOpen(open))
        // A bowed band from handle tip to body edge. As it stretches, the waist
        // pinches (rubbery tether) and the midline bows toward the handle lean.
        let p0 = handleTip
        let p1 = bodyEdge

        // Endpoint half-thicknesses: full at the handle, slightly fuller at body.
        let h0 = thickness * 0.5
        let h1 = thickness * 0.62
        // Waist thins as the neck stretches out.
        let waist = thickness * 0.5 * (1 - min(0.6, co * 0.6))

        // Control-point bow: sag toward the lean direction so it doesn't kink.
        let dx = p1.x - p0.x
        let dy = p1.y - p0.y
        let midX = (p0.x + p1.x) * 0.5
        let midYTop = (p0.y + p1.y) * 0.5 - waist
        let midYBot = (p0.y + p1.y) * 0.5 + waist
        let bow = lean * (abs(dx) * 0.10 + 6)

        var path = Path()
        // Top edge: handle-top -> waist-top -> body-top
        path.move(to: CGPoint(x: p0.x, y: p0.y - h0))
        path.addQuadCurve(
            to: CGPoint(x: midX, y: midYTop + bow),
            control: CGPoint(x: p0.x + dx * 0.30, y: p0.y - h0 + dy * 0.15)
        )
        path.addQuadCurve(
            to: CGPoint(x: p1.x, y: p1.y - h1),
            control: CGPoint(x: p0.x + dx * 0.70, y: p1.y - h1)
        )
        // Body cap (down its left edge)
        path.addLine(to: CGPoint(x: p1.x, y: p1.y + h1))
        // Bottom edge: body-bottom -> waist-bottom -> handle-bottom
        path.addQuadCurve(
            to: CGPoint(x: midX, y: midYBot + bow),
            control: CGPoint(x: p0.x + dx * 0.70, y: p1.y + h1)
        )
        path.addQuadCurve(
            to: CGPoint(x: p0.x, y: p0.y + h0),
            control: CGPoint(x: p0.x + dx * 0.30, y: p0.y + h0 + dy * 0.15)
        )
        path.closeSubpath()
        return path
    }
}

// MARK: - Utility

private func clamp<T: Comparable>(_ v: T, _ lo: T, _ hi: T) -> T {
    min(max(v, lo), hi)
}
"""###,
        "nav-magnetic-snap-dock": ###"""
import SwiftUI

// MARK: - Magnetic Snap Dock
// A reorderable dock: dragging an icon makes the others slide aside and the
// dragged icon snaps into slots with a magnetic click + overshoot wobble, while
// a soft attraction pulls it toward the nearest gap as you hover.
//
// Both the interactive path (LongPress -> Drag) and the self-driving demo feed
// the SAME pure slot math (`slotCenterX` / `visualSlot`), so the demo is a
// faithful replay of the real gesture — no second layout routine.

struct MagneticSnapDockView: View {
    var demo: Bool = false

    // Stable item identities. Kept low (5) so the shuffle is legible at 120pt.
    @State private var items: [MagneticSnapDockView_DockItem] = MagneticSnapDockView_DockItem.defaults

    // Single source of truth for the INTERACTIVE path.
    @State private var draggingIndex: Int? = nil      // logical index in `items`
    @State private var targetSlot: Int = 0            // slot the gap is opening at
    @State private var fingerX: CGFloat = 0           // live finger x in dock space
    @State private var snapTick: Int = 0              // drives the release haptic

    var body: some View {
        GeometryReader { geo in
            let metrics = MagneticSnapDockView_DockMetrics(size: geo.size, count: items.count)
            ZStack {
                background(metrics)
                if demo {
                    demoDock(metrics)
                } else {
                    interactiveDock(metrics)
                }
            }
            .frame(width: geo.size.width, height: geo.size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // MARK: Background

    private func background(_ m: MagneticSnapDockView_DockMetrics) -> some View {
        let r = m.dockHeight / 2
        return RoundedRectangle(cornerRadius: r, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.13, green: 0.15, blue: 0.20),
                        Color(red: 0.07, green: 0.08, blue: 0.11)
                    ],
                    startPoint: .top, endPoint: .bottom
                )
            )
            .overlay(
                RoundedRectangle(cornerRadius: r, style: .continuous)
                    .strokeBorder(Color.white.opacity(0.08), lineWidth: 1)
            )
            .frame(width: m.dockWidth, height: m.dockHeight)
            .shadow(color: .black.opacity(0.45), radius: m.tile * 0.18, y: m.tile * 0.10)
            .position(x: m.size.width / 2, y: m.midY)
    }

    // MARK: - Interactive dock (demo == false)

    private func interactiveDock(_ m: MagneticSnapDockView_DockMetrics) -> some View {
        ZStack {
            ForEach(Array(items.enumerated()), id: \.element.id) { logicalIndex, item in
                iconTile(item, m: m)
                    .scaleEffect(draggingIndex == logicalIndex ? 1.22 : 1.0)
                    .shadow(
                        color: .black.opacity(draggingIndex == logicalIndex ? 0.5 : 0.0),
                        radius: m.tile * 0.22, y: m.tile * 0.12
                    )
                    .position(position(forLogical: logicalIndex, m: m))
                    .zIndex(draggingIndex == logicalIndex ? 10 : 0)
                    .animation(shuffleAnimation, value: targetSlot)
                    .animation(shuffleAnimation, value: draggingIndex)
            }
        }
        .frame(width: m.size.width, height: m.size.height)
        .contentShape(Rectangle())
        .gesture(dragGesture(m))
        .sensoryFeedback(.impact(weight: .medium), trigger: snapTick)
        .sensoryFeedback(.selection, trigger: targetSlot)
    }

    private var shuffleAnimation: Animation {
        .spring(response: 0.34, dampingFraction: 0.72)
    }

    // Position of a logical item. The dragged item floats toward the finger with
    // a magnetic attraction to the nearest slot; everyone else sits at their
    // visual slot (which has shifted to open the gap at `targetSlot`).
    private func position(forLogical logicalIndex: Int, m: MagneticSnapDockView_DockMetrics) -> CGPoint {
        if draggingIndex == logicalIndex {
            return liftedPosition(m: m)
        }
        let slot = visualSlot(ofLogical: logicalIndex)
        return CGPoint(x: m.slotCenterX(slot), y: m.midY)
    }

    // The lifted icon: blend the raw finger position with the nearest slot center
    // so it "resists then clicks" toward the gap — the magnetic pull.
    private func liftedPosition(m: MagneticSnapDockView_DockMetrics) -> CGPoint {
        let nearest = m.slotCenterX(targetSlot)
        let pull: CGFloat = 0.30                      // attraction strength
        let x = fingerX * (1 - pull) + nearest * pull
        let clamped = min(max(x, m.slotCenterX(0)), m.slotCenterX(m.count - 1))
        return CGPoint(x: clamped, y: m.midY - m.tile * 0.16)   // lifted above rail
    }

    // MARK: Gesture — LongPress to lift, then Drag to move, snap on release.

    private func dragGesture(_ m: MagneticSnapDockView_DockMetrics) -> some Gesture {
        LongPressGesture(minimumDuration: 0.16)
            .sequenced(before: DragGesture(minimumDistance: 0))
            .onChanged { value in
                switch value {
                case .first:
                    break
                case .second(let pressed, let drag):
                    guard pressed, let drag else { return }
                    beginIfNeeded(at: drag.startLocation, m: m)
                    update(to: drag.location, m: m)
                }
            }
            .onEnded { _ in
                endDrag()
            }
    }

    private func beginIfNeeded(at start: CGPoint, m: MagneticSnapDockView_DockMetrics) {
        guard draggingIndex == nil else { return }
        let slot = m.slot(forX: start.x)
        // Before any drag, logical order == slot order, so slot == logical item.
        fingerX = start.x
        withAnimation(.spring(response: 0.28, dampingFraction: 0.7)) {
            draggingIndex = slot
            targetSlot = slot
        }
    }

    private func update(to location: CGPoint, m: MagneticSnapDockView_DockMetrics) {
        guard draggingIndex != nil else { return }
        fingerX = location.x
        let newTarget = m.slot(forX: location.x)
        if newTarget != targetSlot {
            withAnimation(shuffleAnimation) {
                targetSlot = newTarget       // gap opens AHEAD of the drop
            }
        }
    }

    private func endDrag() {
        guard let dragged = draggingIndex else { return }
        reorder(fromSlot: dragged, toSlot: targetSlot)   // logical index == home slot
        // Snap home with a bouncy overshoot wobble.
        withAnimation(.spring(response: 0.42, dampingFraction: 0.52)) {
            draggingIndex = nil
        }
        snapTick &+= 1   // fire the impact haptic on real release only
    }

    // MARK: Reorder bookkeeping (logical index <-> visual slot)
    //
    // `items` is kept in logical order. Between drags, logical order == slot order,
    // so a logical index IS its home slot. A drag always starts fresh
    // (draggingIndex == nil) and commits fully before the next, preserving the
    // invariant. During a drag we recompute the visual slot of each item.

    // The visual slot a non-dragged logical item occupies, given the gap opening
    // at `targetSlot`. Items between the dragged item's home slot and the target
    // shift by one to make room.
    private func visualSlot(ofLogical logicalIndex: Int) -> Int {
        guard let dragged = draggingIndex, dragged != logicalIndex else {
            return logicalIndex
        }
        return Self.shiftedSlot(index: logicalIndex, source: dragged, target: targetSlot)
    }

    // Pure shift rule shared by interactive + demo paths.
    static func shiftedSlot(index i: Int, source: Int, target: Int) -> Int {
        if source < target {
            // gap moves right: items in (source, target] slide LEFT by one
            if i > source && i <= target { return i - 1 }
        } else if source > target {
            // gap moves left: items in [target, source) slide RIGHT by one
            if i >= target && i < source { return i + 1 }
        }
        return i
    }

    private func reorder(fromSlot: Int, toSlot: Int) {
        guard fromSlot != toSlot,
              items.indices.contains(fromSlot),
              items.indices.contains(toSlot) else { return }
        let moved = items.remove(at: fromSlot)
        items.insert(moved, at: toSlot)
    }

    // MARK: - Demo dock (demo == true)
    // Self-driving: a TimelineView scripts a synthetic drag of the middle icon
    // back and forth between the two end slots, feeding the SAME slot math. The
    // dragged item's home slot is CONSTANT (no commit ever happens), and the live
    // target is derived from the floating icon's position — exactly like the real
    // gesture — so the gap always sits under the icon with no overlap. The release
    // overshoot wobble is baked into the travel easing so the snap reads as bouncy.

    private func demoDock(_ m: MagneticSnapDockView_DockMetrics) -> some View {
        TimelineView(.animation) { tl in
            let t = tl.date.timeIntervalSinceReferenceDate
            let state = MagneticSnapDockView_DemoState(time: t, metrics: m)
            let liveTarget = m.slot(forX: state.draggedX)
            ZStack {
                ForEach(Array(items.enumerated()), id: \.element.id) { logicalIndex, item in
                    demoTile(logicalIndex, item: item, state: state, target: liveTarget, m: m)
                }
            }
            .frame(width: m.size.width, height: m.size.height)
        }
    }

    @ViewBuilder
    private func demoTile(_ logicalIndex: Int, item: MagneticSnapDockView_DockItem,
                          state: MagneticSnapDockView_DemoState, target: Int, m: MagneticSnapDockView_DockMetrics) -> some View {
        let isDragged = (logicalIndex == state.draggedLogical)
        if isDragged {
            iconTile(item, m: m)
                .scaleEffect(1.0 + 0.22 * state.liftAmount)
                .shadow(color: .black.opacity(0.5 * state.liftAmount),
                        radius: m.tile * 0.22, y: m.tile * 0.12)
                .position(x: state.draggedX, y: m.midY - m.tile * 0.16 * state.liftAmount)
                .zIndex(10)
        } else {
            let slot = Self.shiftedSlot(index: logicalIndex,
                                        source: state.draggedLogical, target: target)
            iconTile(item, m: m)
                .position(x: m.slotCenterX(slot), y: m.midY)
                .zIndex(0)
                .animation(shuffleAnimation, value: slot)   // slide aside, don't teleport
        }
    }

    // MARK: - Shared icon tile

    private func iconTile(_ item: MagneticSnapDockView_DockItem, m: MagneticSnapDockView_DockMetrics) -> some View {
        let r = m.tile * 0.26
        return RoundedRectangle(cornerRadius: r, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [item.top, item.bottom],
                    startPoint: .topLeading, endPoint: .bottomTrailing
                )
            )
            .overlay(
                RoundedRectangle(cornerRadius: r, style: .continuous)
                    .strokeBorder(Color.white.opacity(0.22), lineWidth: 1)
            )
            .overlay(
                Image(systemName: item.symbol)
                    .font(.system(size: m.tile * 0.42, weight: .semibold))
                    .foregroundStyle(.white)
                    .shadow(color: .black.opacity(0.25), radius: 1, y: 1)
            )
            .frame(width: m.tile, height: m.tile)
    }
}

// MARK: - Demo state (derived, never written to @State during render)

private struct MagneticSnapDockView_DemoState {
    let draggedLogical: Int    // == home slot; CONSTANT because demo never commits
    let draggedX: CGFloat      // live x of the floating icon
    let liftAmount: CGFloat    // 0 = resting in slot, 1 = fully lifted

    init(time: Double, metrics m: MagneticSnapDockView_DockMetrics) {
        // The MIDDLE icon hops between the two end slots on a ~3.4s loop, so the
        // home slot is honest and the shuffle is symmetric in both directions.
        let dragged = m.count / 2          // 2 for a 5-item dock
        let endLeft = 0
        let endRight = m.count - 1
        self.draggedLogical = dragged

        let loop: Double = 3.4
        let phase = (time.truncatingRemainder(dividingBy: loop)) / loop  // 0..1

        let cHome = m.slotCenterX(dragged)
        let cLeft = m.slotCenterX(endLeft)
        let cRight = m.slotCenterX(endRight)

        // Phase plan:
        //   0.00–0.10  lift up in place
        //   0.10–0.40  travel home -> right end (overshoot wobble)
        //   0.40–0.50  hold lifted at right
        //   0.50–0.80  travel right end -> left end (overshoot wobble)
        //   0.80–0.90  hold lifted at left
        //   0.90–1.00  travel left -> home & drop down
        self.liftAmount = MagneticSnapDockView_DemoState.lift(phase)

        if phase < 0.10 {
            self.draggedX = cHome
        } else if phase < 0.40 {
            let local = (phase - 0.10) / 0.30
            self.draggedX = MagneticSnapDockView_DemoState.overshootLerp(cHome, cRight, local)
        } else if phase < 0.50 {
            self.draggedX = cRight
        } else if phase < 0.80 {
            let local = (phase - 0.50) / 0.30
            self.draggedX = MagneticSnapDockView_DemoState.overshootLerp(cRight, cLeft, local)
        } else if phase < 0.90 {
            self.draggedX = cLeft
        } else {
            let local = (phase - 0.90) / 0.10
            self.draggedX = MagneticSnapDockView_DemoState.overshootLerp(cLeft, cHome, local)
        }
    }

    // Lift envelope: rises fast, stays up through the travels, drops at the end.
    static func lift(_ phase: Double) -> CGFloat {
        let p: Double
        if phase < 0.10 {
            p = phase / 0.10
        } else if phase < 0.90 {
            p = 1.0
        } else {
            p = 1.0 - (phase - 0.90) / 0.10
        }
        let e = p * p * (3 - 2 * p)   // smoothstep
        return CGFloat(min(max(e, 0), 1))
    }

    // Travel with a baked damped-overshoot so the synthetic snap visibly wobbles
    // into the slot (replaces the event-driven spring of the interactive path).
    static func overshootLerp(_ a: CGFloat, _ b: CGFloat, _ tRaw: Double) -> CGFloat {
        let t = min(max(tRaw, 0), 1)
        let zeta = 0.42
        let omega = 9.0
        let decay = exp(-zeta * omega * t)
        let wd = omega * sqrt(max(0.0001, 1 - zeta * zeta))
        let osc = decay * (cos(wd * t) + (zeta * omega / wd) * sin(wd * t))
        let settle = 1.0 - osc           // 0 -> ~1 with overshoot past 1, then rings
        return a + (b - a) * CGFloat(settle)
    }
}

// MARK: - Metrics

private struct MagneticSnapDockView_DockMetrics {
    let size: CGSize
    let count: Int
    let tile: CGFloat
    let gap: CGFloat
    let slotWidth: CGFloat
    let dockWidth: CGFloat
    let dockHeight: CGFloat
    let midY: CGFloat
    let originX: CGFloat   // x of slot 0's center

    init(size: CGSize, count: Int) {
        self.size = size
        self.count = count
        let n = CGFloat(count)
        let shortest = min(size.width, size.height)

        // Slot geometry is derived FROM the final dock width so they can never
        // disagree (no clamped/unclamped mismatch). Layout model:
        //   gap = 0.34 * slotWidth, tile = 0.66 * slotWidth,
        //   dockWidth = count*slotWidth + gap = slotWidth * (count + 0.34)
        let gapFrac: CGFloat = 0.34
        let padFactor = n + gapFrac

        // Cap the dock by width AND by height (so tiles never get huge on wide tiles).
        let maxByWidth = size.width * 0.94
        let maxTileByHeight = shortest * 0.50
        let maxByHeight = (maxTileByHeight / 0.66) * padFactor
        let dw = max(40, min(maxByWidth, maxByHeight))
        self.dockWidth = dw

        let sw = dw / padFactor
        self.slotWidth = sw
        self.gap = sw * gapFrac
        self.tile = sw * 0.66
        self.dockHeight = self.tile + self.gap * 1.3
        self.midY = size.height / 2

        let dockLeft = (size.width - dw) / 2
        self.originX = dockLeft + self.gap + self.tile / 2
    }

    func slotCenterX(_ slot: Int) -> CGFloat {
        originX + slotWidth * CGFloat(slot)
    }

    func slot(forX x: CGFloat) -> Int {
        let raw = (x - originX) / slotWidth
        let rounded = Int(raw.rounded())
        return min(max(rounded, 0), count - 1)
    }
}

// MARK: - Model

private struct MagneticSnapDockView_DockItem: Identifiable, Equatable {
    let id: Int
    let symbol: String
    let top: Color
    let bottom: Color

    static let defaults: [MagneticSnapDockView_DockItem] = [
        MagneticSnapDockView_DockItem(id: 0, symbol: "house.fill",
                 top: Color(red: 0.36, green: 0.62, blue: 0.98),
                 bottom: Color(red: 0.20, green: 0.40, blue: 0.86)),
        MagneticSnapDockView_DockItem(id: 1, symbol: "magnifyingglass",
                 top: Color(red: 0.98, green: 0.55, blue: 0.42),
                 bottom: Color(red: 0.92, green: 0.34, blue: 0.36)),
        MagneticSnapDockView_DockItem(id: 2, symbol: "heart.fill",
                 top: Color(red: 0.96, green: 0.45, blue: 0.66),
                 bottom: Color(red: 0.82, green: 0.26, blue: 0.55)),
        MagneticSnapDockView_DockItem(id: 3, symbol: "bell.fill",
                 top: Color(red: 0.55, green: 0.78, blue: 0.52),
                 bottom: Color(red: 0.30, green: 0.62, blue: 0.42)),
        MagneticSnapDockView_DockItem(id: 4, symbol: "gearshape.fill",
                 top: Color(red: 0.74, green: 0.66, blue: 0.96),
                 bottom: Color(red: 0.52, green: 0.42, blue: 0.88))
    ]
}
"""###,
        "nav-orbital-satellite-menu": ###"""
import SwiftUI

// MARK: - Orbital OrbitalSatelliteMenuView_Satellite Menu
//
// Action icons orbit a central hub. Drag the ring to rotate it; whichever
// satellite reaches the top "focus" slot enlarges. A flick coasts with
// momentum and snaps to the nearest detent.
//
//  • demo == true  -> closed-form auto-orbit (pure function of time, no
//                     stored integrator state) that eases between detents
//                     on a loop so the tile is always alive and legible.
//  • demo == false -> real RotationGesture-style DragGesture wiring: atan2
//                     deltas accumulate into an unwrapped ring angle, and
//                     release projects a resting angle from the measured
//                     angular velocity, snaps it to the nearest detent, and
//                     settles with a plain spring (no terminal jitter).

struct OrbitalSatelliteMenuView: View {
    var demo: Bool = false

    // The current ring rotation, kept UNWRAPPED (never folded into
    // (-pi, pi]) so the spring can animate smoothly across the atan2 seam.
    @State private var ringAngle: Double = 0

    // Drag bookkeeping for measuring angular velocity at release.
    @State private var lastTouchAngle: Double = 0
    @State private var lastAngle: Double = 0          // ring angle snapshot
    @State private var lastDate: Date = .distantPast
    @State private var angularVelocity: Double = 0    // rad / s
    @State private var isDragging: Bool = false

    // The item currently sitting in the focus slot (drives haptic ticks).
    @State private var focusedIndex: Int = 0

    private let items: [OrbitalSatelliteMenuView_Satellite] = OrbitalSatelliteMenuView_Satellite.demoSet

    var body: some View {
        GeometryReader { proxy in
            let side = min(proxy.size.width, proxy.size.height)
            let center = CGPoint(x: proxy.size.width / 2, y: proxy.size.height / 2)
            let metrics = OrbitalSatelliteMenuView_Metrics(side: side)

            ZStack {
                backdrop(side: side)
                orbitRing(radius: metrics.orbitRadius, lineWidth: metrics.ringWidth)
                focusHalo(center: center, metrics: metrics)

                if demo {
                    demoContent(center: center, metrics: metrics)
                } else {
                    interactiveContent(center: center, metrics: metrics)
                }

                hub(metrics: metrics)
                    .position(center)
            }
            .frame(width: proxy.size.width, height: proxy.size.height)
            .contentShape(Rectangle())
            .gesture(rotationDrag(center: center), including: demo ? .none : .all)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .sensoryFeedback(.selection, trigger: demo ? -1 : focusedIndex)
    }

    // MARK: Demo (self-driving, closed form)

    @ViewBuilder
    private func demoContent(center: CGPoint, metrics: OrbitalSatelliteMenuView_Metrics) -> some View {
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            let angle = Self.demoAngle(at: t, step: step)
            satelliteField(ringAngle: angle, center: center, metrics: metrics)
                .onChange(of: nearestIndex(for: angle)) { _, newValue in
                    focusedIndex = newValue
                }
        }
    }

    // MARK: Interactive

    @ViewBuilder
    private func interactiveContent(center: CGPoint, metrics: OrbitalSatelliteMenuView_Metrics) -> some View {
        satelliteField(ringAngle: ringAngle, center: center, metrics: metrics)
            .onChange(of: nearestIndex(for: ringAngle)) { _, newValue in
                focusedIndex = newValue
            }
    }

    // MARK: OrbitalSatelliteMenuView_Satellite layout

    /// Lays out every satellite at its polar angle around the hub and
    /// applies a smooth focus falloff so the item nearest the top slot grows.
    @ViewBuilder
    private func satelliteField(ringAngle: Double, center: CGPoint, metrics: OrbitalSatelliteMenuView_Metrics) -> some View {
        ZStack {
            ForEach(items.indices, id: \.self) { index in
                let placement = placement(for: index, ringAngle: ringAngle, metrics: metrics)
                satelliteView(items[index], emphasis: placement.emphasis, metrics: metrics)
                    .position(x: center.x + placement.offset.width,
                              y: center.y + placement.offset.height)
                    .zIndex(placement.emphasis)
            }
        }
    }

    private func satelliteView(_ item: OrbitalSatelliteMenuView_Satellite, emphasis: Double, metrics: OrbitalSatelliteMenuView_Metrics) -> some View {
        let scale = 0.82 + emphasis * 0.62
        let dotSize = metrics.satelliteSize
        return ZStack {
            Circle()
                .fill(
                    RadialGradient(
                        colors: [
                            item.tint.opacity(0.95),
                            item.tint.opacity(0.45 + emphasis * 0.4)
                        ],
                        center: .topLeading,
                        startRadius: 1,
                        endRadius: dotSize
                    )
                )
                .overlay(
                    Circle().strokeBorder(Color(red: 1, green: 1, blue: 1).opacity(0.18 + emphasis * 0.3), lineWidth: 1)
                )
                .shadow(color: item.tint.opacity(0.5 * emphasis),
                        radius: 8 * emphasis, x: 0, y: 0)
            Image(systemName: item.symbol)
                .font(.system(size: dotSize * 0.42, weight: .semibold))
                .foregroundStyle(Color(red: 1, green: 1, blue: 1).opacity(0.6 + emphasis * 0.4))
        }
        .frame(width: dotSize, height: dotSize)
        .scaleEffect(scale)
        .opacity(0.55 + emphasis * 0.45)
    }

    // MARK: Hub & decoration

    private func hub(metrics: OrbitalSatelliteMenuView_Metrics) -> some View {
        ZStack {
            Circle()
                .fill(
                    RadialGradient(
                        colors: [
                            Color(red: 0.28, green: 0.32, blue: 0.42),
                            Color(red: 0.10, green: 0.12, blue: 0.18)
                        ],
                        center: .topLeading,
                        startRadius: 1,
                        endRadius: metrics.hubSize
                    )
                )
            Circle()
                .strokeBorder(Color(red: 1, green: 1, blue: 1).opacity(0.22), lineWidth: 1)
            Image(systemName: "circle.grid.cross.fill")
                .font(.system(size: metrics.hubSize * 0.4, weight: .medium))
                .foregroundStyle(Color(red: 0.62, green: 0.78, blue: 1.0))
        }
        .frame(width: metrics.hubSize, height: metrics.hubSize)
        .shadow(color: Color(red: 0.0, green: 0.0, blue: 0.0).opacity(0.4), radius: 6, x: 0, y: 3)
    }

    private func orbitRing(radius: CGFloat, lineWidth: CGFloat) -> some View {
        Circle()
            .strokeBorder(
                Color(red: 1, green: 1, blue: 1).opacity(0.10),
                style: StrokeStyle(lineWidth: lineWidth, dash: [2, 6])
            )
            .frame(width: radius * 2, height: radius * 2)
    }

    /// A soft glow marking the top-of-ring focus slot.
    private func focusHalo(center: CGPoint, metrics: OrbitalSatelliteMenuView_Metrics) -> some View {
        Circle()
            .fill(
                RadialGradient(
                    colors: [
                        Color(red: 0.55, green: 0.74, blue: 1.0).opacity(0.35),
                        Color(red: 0.55, green: 0.74, blue: 1.0).opacity(0.0)
                    ],
                    center: .center,
                    startRadius: 1,
                    endRadius: metrics.satelliteSize * 1.3
                )
            )
            .frame(width: metrics.satelliteSize * 2.6, height: metrics.satelliteSize * 2.6)
            .position(x: center.x, y: center.y - metrics.orbitRadius)
    }

    private func backdrop(side: CGFloat) -> some View {
        RoundedRectangle(cornerRadius: side * 0.10, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.07, green: 0.08, blue: 0.12),
                        Color(red: 0.04, green: 0.05, blue: 0.08)
                    ],
                    startPoint: .top,
                    endPoint: .bottom
                )
            )
    }

    // MARK: Gesture

    private func rotationDrag(center: CGPoint) -> some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                let now = Date()
                let touchAngle = atan2(Double(value.location.y - center.y),
                                       Double(value.location.x - center.x))
                if !isDragging {
                    // First sample of this drag — seed, don't rotate.
                    isDragging = true
                    lastTouchAngle = touchAngle
                    lastAngle = ringAngle
                    lastDate = now
                    angularVelocity = 0
                    return
                }

                // Normalize the DELTA into (-pi, pi] (never wrap ringAngle).
                var delta = touchAngle - lastTouchAngle
                delta = Self.normalizeDelta(delta)
                ringAngle += delta
                lastTouchAngle = touchAngle

                // Measure instantaneous angular velocity (rad/s).
                let dt = now.timeIntervalSince(lastDate)
                if dt > 0.0001 {
                    let measured = (ringAngle - lastAngle) / dt
                    // Light smoothing keeps the release reading stable.
                    angularVelocity = angularVelocity * 0.4 + measured * 0.6
                    lastAngle = ringAngle
                    lastDate = now
                }
            }
            .onEnded { _ in
                isDragging = false
                // Project a resting angle from momentum, then snap to the
                // nearest detent and settle with a plain spring (no jitter).
                let friction: Double = 3.2
                let projected = ringAngle + angularVelocity / friction
                let target = Self.snappedAngle(projected, step: step)
                angularVelocity = 0
                withAnimation(.spring(response: 0.55, dampingFraction: 0.72)) {
                    ringAngle = target
                }
            }
    }

    // MARK: Placement maths

    private var step: Double { (2 * Double.pi) / Double(items.count) }

    struct Placement {
        var offset: CGSize
        var emphasis: Double   // 0…1, 1 == perfectly in the focus slot
    }

    /// Item `i` is anchored at `-pi/2 + i*step` (top of ring = focus slot)
    /// and then rotated by the live `ringAngle`.
    private func placement(for index: Int, ringAngle: Double, metrics: OrbitalSatelliteMenuView_Metrics) -> Placement {
        let base = -Double.pi / 2 + Double(index) * step
        let angle = base + ringAngle
        let x = cos(angle) * Double(metrics.orbitRadius)
        let y = sin(angle) * Double(metrics.orbitRadius)

        // Angular distance from the focus slot (top, -pi/2).
        let toFocus = Self.normalizeDelta(angle - (-Double.pi / 2))
        let dist = abs(toFocus)
        // Smooth falloff: 1 at the slot, easing to 0 within ~one step.
        let span = step
        let raw = max(0, 1 - dist / span)
        let emphasis = raw * raw * (3 - 2 * raw) // smoothstep

        return Placement(offset: CGSize(width: x, height: y), emphasis: emphasis)
    }

    private func nearestIndex(for ringAngle: Double) -> Int {
        // Which item is closest to the focus slot for the given rotation.
        var best = 0
        var bestDist = Double.greatestFiniteMagnitude
        for index in items.indices {
            let base = -Double.pi / 2 + Double(index) * step
            let angle = base + ringAngle
            let d = abs(Self.normalizeDelta(angle - (-Double.pi / 2)))
            if d < bestDist {
                bestDist = d
                best = index
            }
        }
        return best
    }

    // MARK: Static helpers (pure, no state — safe to call from anywhere)

    /// Closed-form demo angle: eases between detents with a decelerating
    /// curve on a loop, mimicking flick-coast-snap with no integrator state.
    static func demoAngle(at time: TimeInterval, step: Double) -> Double {
        let period: Double = 3.4
        let phase = time.truncatingRemainder(dividingBy: period) / period // 0…1
        // Cycle index advances each period so the ring keeps progressing.
        let cycle = floor(time / period)
        // Move 2 detents per period for a lively spin.
        let perCycle = step * 2
        let startAngle = -cycle * perCycle
        // easeOut: fast start, decelerating into the detent (coast feel).
        let eased = 1 - pow(1 - phase, 3)
        return startAngle - eased * perCycle
    }

    /// Normalize an angle delta into (-pi, pi].
    static func normalizeDelta(_ value: Double) -> Double {
        var d = value.truncatingRemainder(dividingBy: 2 * Double.pi)
        if d > Double.pi { d -= 2 * Double.pi }
        if d <= -Double.pi { d += 2 * Double.pi }
        return d
    }

    /// Snap an (unwrapped) ring angle to the nearest detent, preserving the
    /// unwrapped magnitude so the spring animates over the shortest path.
    static func snappedAngle(_ angle: Double, step: Double) -> Double {
        (angle / step).rounded() * step
    }
}

// MARK: - Model

private struct OrbitalSatelliteMenuView_Satellite: Identifiable {
    let id = UUID()
    let symbol: String
    let tint: Color

    static let demoSet: [OrbitalSatelliteMenuView_Satellite] = [
        OrbitalSatelliteMenuView_Satellite(symbol: "house.fill",        tint: Color(red: 0.36, green: 0.70, blue: 1.00)),
        OrbitalSatelliteMenuView_Satellite(symbol: "magnifyingglass",   tint: Color(red: 0.55, green: 0.84, blue: 0.62)),
        OrbitalSatelliteMenuView_Satellite(symbol: "heart.fill",        tint: Color(red: 1.00, green: 0.46, blue: 0.55)),
        OrbitalSatelliteMenuView_Satellite(symbol: "bell.fill",         tint: Color(red: 1.00, green: 0.78, blue: 0.38)),
        OrbitalSatelliteMenuView_Satellite(symbol: "bookmark.fill",     tint: Color(red: 0.74, green: 0.58, blue: 1.00)),
        OrbitalSatelliteMenuView_Satellite(symbol: "gearshape.fill",    tint: Color(red: 0.55, green: 0.82, blue: 0.95))
    ]
}

// MARK: - OrbitalSatelliteMenuView_Metrics

private struct OrbitalSatelliteMenuView_Metrics {
    let side: CGFloat
    var orbitRadius: CGFloat { side * 0.34 }
    var satelliteSize: CGFloat { side * 0.18 }
    var hubSize: CGFloat { side * 0.22 }
    var ringWidth: CGFloat { max(1, side * 0.006) }
}
"""###,
        "nav-origami-fold-tabs": ###"""
import SwiftUI

/// Origami Fold Tabs — a tab bar built from paper panels.
///
/// Tapping a tab folds the strip inward along two crease lines, the chosen
/// icon pops forward off the page with a soft shadow, then the strip unfolds
/// flat again. The fold is a transient *pulse* (0 → peak → 0) on every switch,
/// not an end-state — at rest the bar lies flat with a persistent selection
/// indicator under the active tab.
///
/// - `demo == true`  : a self-driving loop auto-advances through the tabs,
///                     replaying the full crease-in → icon-pop → unfold cycle.
/// - `demo == false` : tap a tab; a KeyframeAnimator pulses the fold and
///                     commits the new selection at the peak of the crease.
struct OrigamiFoldTabsView: View {
    var demo: Bool = false

    // Persistent selection (the tab that stays highlighted at rest).
    @State private var selectedTab: Int = 0
    // The index whose fold pulse is currently playing (the icon that pops).
    @State private var activeTab: Int = 0

    private let tabCount: Int = 4

    var body: some View {
        GeometryReader { geo in
            if demo {
                demoStrip(geo: geo)
            } else {
                interactiveStrip(geo: geo)
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // MARK: - Demo (self-driving)

    @ViewBuilder
    private func demoStrip(geo: GeometryProxy) -> some View {
        // Period per tab; one full crease pulse plays inside each period.
        let period: Double = 1.3
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            let phase = t / period
            let index = Int(floor(phase)) % tabCount
            let local = phase - floor(phase)            // 0..<1 within this tab
            let fold = pulse(local)                     // 0 → 1 → 0 envelope

            strip(geo: geo, selected: index, popped: index, foldProgress: fold)
        }
    }

    // MARK: - Interactive (tap-driven)

    @ViewBuilder
    private func interactiveStrip(geo: GeometryProxy) -> some View {
        // KeyframeAnimator re-keys on `activeTab`; the fold track pulses
        // 0 → peak → 0 each time a tab is tapped.
        KeyframeAnimator(initialValue: CGFloat(0.0), trigger: activeTab) { fold in
            strip(geo: geo,
                  selected: selectedTab,
                  popped: activeTab,
                  foldProgress: fold)
        } keyframes: { _ in
            KeyframeTrack(\CGFloat.self) {
                SpringKeyframe(1.0, duration: 0.26, spring: .init(duration: 0.26, bounce: 0.30))
                SpringKeyframe(0.0, duration: 0.30, spring: .init(duration: 0.30, bounce: 0.22))
            }
        }
    }

    // MARK: - Shared strip (identical render for demo + interactive)

    /// The whole control. `selected` drives the persistent highlight,
    /// `popped` is the icon that lifts forward, `foldProgress` is the 0→1→0 pulse.
    @ViewBuilder
    private func strip(geo: GeometryProxy,
                       selected: Int,
                       popped: Int,
                       foldProgress: CGFloat) -> some View {
        let size = geo.size
        let slotW: CGFloat = size.width / CGFloat(tabCount)
        // Strip is centred vertically and sized to leave breathing room in a tile.
        let stripH: CGFloat = min(size.height * 0.62, slotW * 1.15)
        let stripW: CGFloat = size.width
        let stripY: CGFloat = size.height / 2

        ZStack {
            paperBackdrop(width: stripW, height: stripH)
                .position(x: size.width / 2, y: stripY)

            // The creasing two-panel base layer.
            foldingPanels(slotW: slotW,
                          stripH: stripH,
                          stripW: stripW,
                          selected: selected,
                          foldProgress: foldProgress)
                .position(x: size.width / 2, y: stripY)

            // The chosen icon, lifted forward on its own layer.
            poppingIcon(slotW: slotW,
                        stripH: stripH,
                        popped: popped,
                        foldProgress: foldProgress)
                .position(x: slotCenterX(index: popped, slotW: slotW),
                          y: stripY)
        }
        .compositingGroup()
        .contentShape(Rectangle())
        .modifier(OrigamiFoldTabsView_TapTabs(enabled: !demo, tabCount: tabCount, slotW: slotW) { idx in
            selectTab(idx)
        })
    }

    // MARK: - Layers

    private func paperBackdrop(width: CGFloat, height: CGFloat) -> some View {
        RoundedRectangle(cornerRadius: height * 0.22, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [paperLight, paperDark],
                    startPoint: .top, endPoint: .bottom
                )
            )
            .overlay(
                RoundedRectangle(cornerRadius: height * 0.22, style: .continuous)
                    .stroke(creaseLine.opacity(0.30), lineWidth: 1)
            )
            .frame(width: width, height: height)
            .shadow(color: .black.opacity(0.18), radius: 6, x: 0, y: 4)
    }

    /// Two HStacks creased toward the centre line via mirrored rotation3DEffect.
    @ViewBuilder
    private func foldingPanels(slotW: CGFloat,
                               stripH: CGFloat,
                               stripW: CGFloat,
                               selected: Int,
                               foldProgress: CGFloat) -> some View {
        // Modest angle so the demo never collapses to a line. Spec: cap perspective.
        let creaseAngle: Double = 34.0 * Double(foldProgress)
        let halfCount: Int = tabCount / 2
        let perspective: CGFloat = 0.6

        HStack(spacing: 0) {
            // Left half — hinges on its LEADING edge, folds back to the right.
            panelRow(range: 0..<halfCount,
                     slotW: slotW, stripH: stripH,
                     selected: selected, foldProgress: foldProgress)
                .rotation3DEffect(.degrees(creaseAngle),
                                  axis: (x: 0, y: 1, z: 0),
                                  anchor: .leading,
                                  perspective: perspective)
                .brightness(-0.10 * Double(foldProgress))

            // Right half — hinges on its TRAILING edge, folds back to the left.
            panelRow(range: halfCount..<tabCount,
                     slotW: slotW, stripH: stripH,
                     selected: selected, foldProgress: foldProgress)
                .rotation3DEffect(.degrees(-creaseAngle),
                                  axis: (x: 0, y: 1, z: 0),
                                  anchor: .trailing,
                                  perspective: perspective)
                .brightness(-0.10 * Double(foldProgress))
        }
        .frame(width: stripW, height: stripH)
        // Centre crease shading: darkens as the bar folds in.
        .overlay(centerCrease(height: stripH, foldProgress: foldProgress))
    }

    /// A contiguous row of base tab slots (icons sit flat here; the popped one
    /// is hidden because its forward-lifted copy renders in the overlay).
    @ViewBuilder
    private func panelRow(range: Range<Int>,
                          slotW: CGFloat,
                          stripH: CGFloat,
                          selected: Int,
                          foldProgress: CGFloat) -> some View {
        HStack(spacing: 0) {
            ForEach(range, id: \.self) { idx in
                tabSlot(index: idx,
                        slotW: slotW,
                        stripH: stripH,
                        selected: selected,
                        foldProgress: foldProgress)
            }
        }
    }

    private func tabSlot(index: Int,
                         slotW: CGFloat,
                         stripH: CGFloat,
                         selected: Int,
                         foldProgress: CGFloat) -> some View {
        let isSelected = index == selected
        // The base copy of the popping icon fades out as it lifts forward.
        let baseIconOpacity: Double = isSelected ? (1.0 - 0.85 * Double(foldProgress)) : 0.55
        let iconSize: CGFloat = stripH * 0.34

        return VStack(spacing: stripH * 0.10) {
            Image(systemName: symbolName(index))
                .font(.system(size: iconSize, weight: .semibold))
                .foregroundStyle(isSelected ? accent : ink.opacity(0.65))
                .opacity(baseIconOpacity)

            // Persistent selection dot — independent of the fold pulse.
            Capsule()
                .fill(accent)
                .frame(width: isSelected ? slotW * 0.30 : 0,
                       height: stripH * 0.055)
                .opacity(isSelected ? 1 : 0)
        }
        .frame(width: slotW, height: stripH)
        .contentShape(Rectangle())
    }

    /// The selected icon lifted toward the viewer with a soft tracking shadow.
    @ViewBuilder
    private func poppingIcon(slotW: CGFloat,
                             stripH: CGFloat,
                             popped: Int,
                             foldProgress: CGFloat) -> some View {
        let iconSize: CGFloat = stripH * 0.34
        let lift: CGFloat = foldProgress              // 0..1
        let scale: CGFloat = 1.0 + 0.42 * lift
        let forwardAngle: Double = -26.0 * Double(lift)   // tilt toward viewer
        let shadowRadius: CGFloat = 2 + 12 * lift
        let shadowY: CGFloat = 2 + 9 * lift

        Image(systemName: symbolName(popped))
            .font(.system(size: iconSize, weight: .semibold))
            .foregroundStyle(accent)
            .scaleEffect(scale)
            .rotation3DEffect(.degrees(forwardAngle),
                              axis: (x: 1, y: 0, z: 0),
                              anchor: .bottom,
                              perspective: 0.5)
            .shadow(color: .black.opacity(0.35 * Double(lift)),
                    radius: shadowRadius, x: 0, y: shadowY)
            // Never fully invisible — at rest it sits flush on the base icon.
            .opacity(0.15 + 0.85 * Double(lift) + 0.001)
    }

    private func centerCrease(height: CGFloat, foldProgress: CGFloat) -> some View {
        Rectangle()
            .fill(
                LinearGradient(
                    colors: [
                        creaseLine.opacity(0.0),
                        creaseLine.opacity(0.45 * Double(foldProgress)),
                        creaseLine.opacity(0.0)
                    ],
                    startPoint: .leading, endPoint: .trailing
                )
            )
            .frame(width: height * 0.10, height: height)
            .blur(radius: 1)
            .allowsHitTesting(false)
    }

    // MARK: - Logic

    private func selectTab(_ idx: Int) {
        guard idx != selectedTab || idx != activeTab else { return }
        // Commit the persistent selection up front so the dot is correct, then
        // re-key the fold pulse via `activeTab` to play the crease flourish.
        selectedTab = idx
        activeTab = idx
    }

    /// 0 → 1 → 0 envelope across a normalised local time `u` in [0, 1).
    private func pulse(_ u: Double) -> CGFloat {
        // sin gives a smooth bloom that returns to flat and holds near 0 at the
        // tail so the bar reads clearly flat before the next tab fires.
        let eased = sin(min(max(u, 0), 1) * .pi)
        return CGFloat(eased * eased)   // sharpen the peak slightly
    }

    private func slotCenterX(index: Int, slotW: CGFloat) -> CGFloat {
        slotW * (CGFloat(index) + 0.5)
    }

    private func symbolName(_ index: Int) -> String {
        let names = ["house.fill", "magnifyingglass", "heart.fill", "person.fill"]
        return names[index % names.count]
    }

    // MARK: - Palette (literal colors — no app dependencies)

    private var paperLight: Color { Color(red: 0.97, green: 0.96, blue: 0.93) }
    private var paperDark: Color  { Color(red: 0.90, green: 0.88, blue: 0.83) }
    private var ink: Color        { Color(red: 0.18, green: 0.20, blue: 0.24) }
    private var accent: Color     { Color(red: 0.91, green: 0.36, blue: 0.27) }
    private var creaseLine: Color { Color(red: 0.45, green: 0.42, blue: 0.38) }
}

// MARK: - Tap routing

/// Maps a tap's x position to a tab index. Kept as a modifier so the shared
/// `strip` renders identically in demo (disabled) and interactive (enabled).
private struct OrigamiFoldTabsView_TapTabs: ViewModifier {
    let enabled: Bool
    let tabCount: Int
    let slotW: CGFloat
    let onSelect: (Int) -> Void

    func body(content: Content) -> some View {
        if enabled {
            content.gesture(
                SpatialTapGesture()
                    .onEnded { value in
                        let raw = Int(value.location.x / max(slotW, 1))
                        let idx = min(max(raw, 0), tabCount - 1)
                        onSelect(idx)
                    }
            )
        } else {
            content
        }
    }
}
"""###,
        "nav-pagecurl-drawer": ###"""
import SwiftUI

// MARK: - Page Curl Drawer
// Dragging from the screen edge peels the top surface back like a turning page,
// revealing a navigation panel underneath. A lit, curved highlight rides the
// lifting edge with a shadow cast onto the panel; rubber-band resistance on
// drag and a velocity-aware spring snap to open/closed on release.

struct PagecurlDrawerView: View {
    var demo: Bool = false

    // Interactive state (demo == false)
    @State private var progress: CGFloat = 0      // 0 = closed (flat page), 1 = open (curled away)
    @State private var isOpen: Bool = false

    // Geometry constants
    private let maxAngle: Double = 82             // cap below 90 to avoid backface / z-fight
    private let loopDuration: Double = 3.0

    var body: some View {
        GeometryReader { geo in
            content(in: geo.size)
                .frame(maxWidth: .infinity, maxHeight: .infinity)
                .clipped()
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // MARK: Root content

    @ViewBuilder
    private func content(in size: CGSize) -> some View {
        if demo {
            TimelineView(.animation) { timeline in
                let p = autoProgress(timeline.date)
                stack(size: size, progress: p)
            }
        } else {
            stack(size: size, progress: progress)
                .contentShape(Rectangle())
                .gesture(dragGesture(width: size.width))
        }
    }

    // MARK: Composition

    private func stack(size: CGSize, progress p: CGFloat) -> some View {
        let clamped = max(0, min(1, p))
        return ZStack {
            // Panel sits BEHIND, full size, always legible.
            PagecurlDrawerView_NavPanel(reveal: clamped)

            // The curling top page, hinged on the trailing (right) edge.
            PagecurlDrawerView_CurlingPage(progress: clamped, maxAngle: maxAngle, size: size)
        }
    }

    // MARK: Auto-drive loop (demo)

    private func autoProgress(_ date: Date) -> CGFloat {
        let t = date.timeIntervalSinceReferenceDate
        let phase = (t.truncatingRemainder(dividingBy: loopDuration)) / loopDuration // 0..1
        // Smooth triangle: rise then fall, eased, with a hold near open.
        let tri: Double
        if phase < 0.45 {
            tri = ease(phase / 0.45)
        } else if phase < 0.60 {
            tri = 1.0                                  // brief hold open
        } else {
            tri = ease(1.0 - (phase - 0.60) / 0.40)
        }
        return CGFloat(tri)
    }

    private func ease(_ x: Double) -> Double {
        let c = min(1, max(0, x))
        return c * c * (3 - 2 * c)                     // smoothstep
    }

    // MARK: Drag wiring (interactive)

    private func dragGesture(width: CGFloat) -> some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                let raw = value.translation.width / max(width, 1)
                let base: CGFloat = isOpen ? 1 : 0
                let target = base + raw
                progress = rubberBand(target)
            }
            .onEnded { value in
                let predicted = (isOpen ? 1 : 0) + value.predictedEndTranslation.width / max(width, 1)
                let shouldOpen = predicted > 0.5
                isOpen = shouldOpen
                withAnimation(.spring(response: 0.45, dampingFraction: 0.72)) {
                    progress = shouldOpen ? 1 : 0
                }
            }
    }

    // Dampened overshoot beyond [0,1].
    private func rubberBand(_ x: CGFloat) -> CGFloat {
        if x < 0 { return x * 0.3 }
        if x > 1 { return 1 + (x - 1) * 0.3 }
        return x
    }
}

// MARK: - Navigation Panel (revealed underneath)

private struct PagecurlDrawerView_NavPanel: View {
    var reveal: CGFloat

    private let items: [(String, Color)] = [
        ("square.grid.2x2.fill", Color(red: 0.45, green: 0.78, blue: 0.95)),
        ("sparkles",             Color(red: 0.95, green: 0.78, blue: 0.42)),
        ("heart.fill",           Color(red: 0.96, green: 0.50, blue: 0.55)),
        ("bell.fill",            Color(red: 0.62, green: 0.86, blue: 0.62)),
        ("gearshape.fill",       Color(red: 0.74, green: 0.70, blue: 0.95))
    ]

    var body: some View {
        GeometryReader { geo in
            let s = geo.size
            ZStack {
                LinearGradient(
                    colors: [
                        Color(red: 0.10, green: 0.13, blue: 0.20),
                        Color(red: 0.06, green: 0.08, blue: 0.13)
                    ],
                    startPoint: .topLeading, endPoint: .bottomTrailing
                )
                rows(in: s)
            }
            .frame(width: s.width, height: s.height)
        }
    }

    private func rows(in s: CGSize) -> some View {
        let count = items.count
        let pad = s.height * 0.10
        let usable = s.height - pad * 2
        let spacing = usable / CGFloat(count)
        let dot = min(spacing * 0.52, s.width * 0.30)
        return ZStack(alignment: .topLeading) {
            ForEach(0..<count, id: \.self) { i in
                row(index: i, dot: dot, s: s)
                    .offset(
                        x: s.width * 0.12,
                        y: pad + spacing * CGFloat(i) + (spacing - dot) / 2
                    )
            }
        }
    }

    private func row(index i: Int, dot: CGFloat, s: CGSize) -> some View {
        let (symbol, tint) = items[i]
        // Stagger the entrance with reveal progress.
        let appear = max(0, min(1, (reveal - CGFloat(i) * 0.06) / 0.6))
        return HStack(spacing: dot * 0.5) {
            ZStack {
                Circle()
                    .fill(tint.opacity(0.20))
                Image(systemName: symbol)
                    .font(.system(size: dot * 0.5, weight: .semibold))
                    .foregroundStyle(tint)
            }
            .frame(width: dot, height: dot)

            Capsule()
                .fill(Color.white.opacity(0.12))
                .frame(width: s.width * 0.38 * appear, height: dot * 0.34)
        }
        .opacity(Double(appear))
        .offset(x: (1 - appear) * -s.width * 0.08)
    }
}

// MARK: - Curling Page (the peeling top surface)

private struct PagecurlDrawerView_CurlingPage: View {
    var progress: CGFloat            // 0..1 (rubber-banded values handled by caller clamp)
    var maxAngle: Double
    var size: CGSize

    var body: some View {
        let angle = Double(max(0, min(1, progress))) * maxAngle
        ZStack {
            pageFace
            // Lit fold highlight riding the lifting (leading / left) edge.
            PagecurlDrawerView_FoldLight(progress: progress)
            // Soft contact shadow near the hinge as the page lifts.
            hingeShade
        }
        // Cast a moving drop shadow onto the panel to sell the lift.
        .shadow(
            color: Color.black.opacity(0.35 * Double(min(1, progress))),
            radius: 14 * min(1, progress),
            x: -10 * min(1, progress),
            y: 4
        )
        // Hinge on the trailing (right) edge: the LEFT edge lifts toward viewer.
        .rotation3DEffect(
            .degrees(angle),
            axis: (x: 0, y: 1, z: 0),
            anchor: .trailing,
            anchorZ: 0,
            perspective: 0.55
        )
    }

    private var pageFace: some View {
        ZStack {
            LinearGradient(
                colors: [
                    Color(red: 0.97, green: 0.96, blue: 0.93),
                    Color(red: 0.90, green: 0.89, blue: 0.85)
                ],
                startPoint: .leading, endPoint: .trailing
            )
            pageContent
        }
    }

    // Faux page content so the lifting face stays legible (never blank).
    private var pageContent: some View {
        VStack(alignment: .leading, spacing: size.height * 0.045) {
            RoundedRectangle(cornerRadius: 4)
                .fill(Color(red: 0.20, green: 0.24, blue: 0.32))
                .frame(width: size.width * 0.42, height: size.height * 0.07)
            ForEach(0..<5, id: \.self) { i in
                Capsule()
                    .fill(Color(red: 0.55, green: 0.57, blue: 0.62).opacity(0.55))
                    .frame(width: size.width * (0.66 - CGFloat(i) * 0.07),
                           height: size.height * 0.035)
            }
        }
        .padding(.horizontal, size.width * 0.10)
        .frame(maxWidth: .infinity, maxHeight: .infinity, alignment: .topLeading)
        .padding(.top, size.height * 0.12)
    }

    private var hingeShade: some View {
        LinearGradient(
            colors: [
                Color.black.opacity(0.0),
                Color.black.opacity(0.22 * Double(min(1, progress)))
            ],
            startPoint: .leading, endPoint: .trailing
        )
        .allowsHitTesting(false)
    }
}

// MARK: - Fold Light (lit cylindrical highlight on the lifting edge)

private struct PagecurlDrawerView_FoldLight: View {
    var progress: CGFloat

    var body: some View {
        GeometryReader { geo in
            let w = geo.size.width
            let p = Double(max(0, min(1, progress)))
            // Highlight band rides from the leading (left) edge inward as it lifts.
            let bandW = w * 0.30
            ZStack(alignment: .leading) {
                // Bright specular streak on the curling edge.
                LinearGradient(
                    colors: [
                        Color.white.opacity(0.0),
                        Color.white.opacity(0.55 * p),
                        Color.white.opacity(0.85 * p),
                        Color.white.opacity(0.0)
                    ],
                    startPoint: .leading, endPoint: .trailing
                )
                .frame(width: bandW)
                .blur(radius: 2)

                // A thin crisp lit line at the very fold edge.
                Rectangle()
                    .fill(Color.white.opacity(0.7 * p))
                    .frame(width: 1.5)
                    .blur(radius: 0.5)
            }
            .frame(width: w, alignment: .leading)
            .blendMode(.screen)
            .allowsHitTesting(false)
        }
    }
}
"""###,
        "nav-parallax-deck-tabs": ###"""
import SwiftUI

/// Parallax Deck Tabs
///
/// Tabs live on three stacked depth planes. The selected tab rises toward the
/// viewer while neighbors recede and blur, with a light rotation3DEffect tilt
/// that gives the deck a parallax feel as selection moves. Selection becomes a
/// Z-axis move, not an X-axis slide — the active tab physically lifts out of a
/// deck of cards.
///
/// - demo == true : a PhaseAnimator auto-cycles which card is frontmost so the
///   deck keeps lifting one card forward and pushing the rest back, alive with
///   no touch.
/// - demo == false: tap a card to select it; a single spring drives the
///   Z-rise, neighbor recede, blur and tilt.
struct ParallaxDeckTabsView: View {
    var demo: Bool = false

    private let tabs: [ParallaxDeckTabsView_DeckTab] = ParallaxDeckTabsView_DeckTab.sample
    @State private var selected: Int = 1

    var body: some View {
        GeometryReader { proxy in
            let size = proxy.size

            ZStack {
                background

                if demo {
                    autoDriving(in: size)
                } else {
                    interactive(in: size)
                }
            }
            .frame(width: size.width, height: size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // MARK: - Backdrop

    private var background: some View {
        LinearGradient(
            colors: [
                Color(red: 0.05, green: 0.06, blue: 0.10),
                Color(red: 0.10, green: 0.11, blue: 0.16)
            ],
            startPoint: .top,
            endPoint: .bottom
        )
    }

    // MARK: - Auto-driving (demo)

    private func autoDriving(in size: CGSize) -> some View {
        PhaseAnimator(Array(0..<tabs.count)) { phase in
            deck(selectedIndex: phase, in: size)
        } animation: { _ in
            .spring(duration: 0.45, bounce: 0.3)
        }
    }

    // MARK: - Interactive

    private func interactive(in size: CGSize) -> some View {
        deck(selectedIndex: selected, in: size)
            .animation(.spring(response: 0.5, dampingFraction: 0.68), value: selected)
    }

    // MARK: - Deck

    @ViewBuilder
    private func deck(selectedIndex: Int, in size: CGSize) -> some View {
        let metrics = ParallaxDeckTabsView_DeckMetrics(size: size)

        ZStack {
            ForEach(Array(tabs.enumerated()), id: \.element.id) { index, tab in
                cardView(tab: tab, index: index, selectedIndex: selectedIndex, metrics: metrics)
            }
        }
        .frame(width: size.width, height: size.height)
    }

    @ViewBuilder
    private func cardView(tab: ParallaxDeckTabsView_DeckTab, index: Int, selectedIndex: Int, metrics: ParallaxDeckTabsView_DeckMetrics) -> some View {
        let distance: Double = Double(index - selectedIndex)
        let clamped: Double = max(-2.0, min(2.0, distance))
        let absClamped: Double = abs(clamped)

        ParallaxDeckTabsView_DeckCard(tab: tab, isFront: index == selectedIndex, metrics: metrics)
            .frame(width: metrics.cardWidth, height: metrics.cardHeight)
            .scaleEffect(scale(absClamped))
            .blur(radius: blurRadius(absClamped))
            .rotation3DEffect(
                .degrees(tilt(clamped)),
                axis: (x: 0, y: 1, z: 0),
                anchor: .center,
                perspective: 0.55
            )
            .offset(x: xOffset(clamped, metrics: metrics), y: yOffset(absClamped, metrics: metrics))
            .opacity(opacity(absClamped))
            .shadow(
                color: Color.black.opacity(shadowOpacity(absClamped)),
                radius: shadowRadius(absClamped),
                x: 0,
                y: shadowYOffset(absClamped)
            )
            .zIndex(zValue(absClamped))
            .contentShape(Rectangle())
            .onTapGesture {
                guard !demo else { return }
                selected = index
            }
    }

    // MARK: - Transform helpers (pure functions of clamped distance)

    private func scale(_ absD: Double) -> CGFloat {
        // Front card largest; recede ~14% per plane, floored so far cards stay legible.
        let s: Double = 1.0 - absD * 0.14
        return CGFloat(max(0.7, s))
    }

    private func blurRadius(_ absD: Double) -> CGFloat {
        // Front card sharp; neighbors soften, capped so they never dissolve.
        CGFloat(min(7.0, absD * 3.6))
    }

    private func tilt(_ d: Double) -> Double {
        // Signed tilt away from center sells the parallax depth, kept small.
        max(-11.0, min(11.0, d * 7.0))
    }

    private func xOffset(_ d: Double, metrics: ParallaxDeckTabsView_DeckMetrics) -> CGFloat {
        // Fan the deck sideways so back cards peek out behind the front one.
        CGFloat(d) * metrics.xSpread
    }

    private func yOffset(_ absD: Double, metrics: ParallaxDeckTabsView_DeckMetrics) -> CGFloat {
        // Front card lifts up; receding cards sink down into the stack.
        CGFloat(absD) * metrics.ySink
    }

    private func opacity(_ absD: Double) -> Double {
        // Never fully transparent — floored so every plane stays readable.
        max(0.45, 1.0 - absD * 0.26)
    }

    private func zValue(_ absD: Double) -> Double {
        // Closer to selected => higher in the stack.
        2.0 - absD
    }

    private func shadowOpacity(_ absD: Double) -> Double {
        absD < 0.5 ? 0.42 : 0.18
    }

    private func shadowRadius(_ absD: Double) -> CGFloat {
        absD < 0.5 ? 18.0 : 8.0
    }

    private func shadowYOffset(_ absD: Double) -> CGFloat {
        absD < 0.5 ? 14.0 : 6.0
    }
}

// MARK: - Layout metrics

private struct ParallaxDeckTabsView_DeckMetrics {
    let cardWidth: CGFloat
    let cardHeight: CGFloat
    let xSpread: CGFloat
    let ySink: CGFloat
    let corner: CGFloat
    let compact: Bool

    init(size: CGSize) {
        let minSide: CGFloat = min(size.width, size.height)
        compact = minSide < 220
        cardWidth = max(40, min(size.width * 0.62, 320))
        cardHeight = max(54, min(size.height * 0.72, 360))
        xSpread = cardWidth * 0.20
        ySink = cardHeight * 0.055
        corner = compact ? 14 : 24
    }
}

// MARK: - Card model

private struct ParallaxDeckTabsView_DeckTab: Identifiable {
    let id: Int
    let title: String
    let systemImage: String
    let top: Color
    let bottom: Color

    static let sample: [ParallaxDeckTabsView_DeckTab] = [
        ParallaxDeckTabsView_DeckTab(id: 0, title: "Discover", systemImage: "sparkles",
                top: Color(red: 0.36, green: 0.32, blue: 0.86),
                bottom: Color(red: 0.20, green: 0.18, blue: 0.55)),
        ParallaxDeckTabsView_DeckTab(id: 1, title: "Create", systemImage: "wand.and.stars",
                top: Color(red: 0.95, green: 0.42, blue: 0.55),
                bottom: Color(red: 0.62, green: 0.21, blue: 0.42)),
        ParallaxDeckTabsView_DeckTab(id: 2, title: "Library", systemImage: "books.vertical.fill",
                top: Color(red: 0.30, green: 0.74, blue: 0.78),
                bottom: Color(red: 0.13, green: 0.44, blue: 0.52)),
        ParallaxDeckTabsView_DeckTab(id: 3, title: "Profile", systemImage: "person.crop.circle.fill",
                top: Color(red: 0.98, green: 0.74, blue: 0.36),
                bottom: Color(red: 0.70, green: 0.45, blue: 0.16))
    ]
}

// MARK: - Card view

private struct ParallaxDeckTabsView_DeckCard: View {
    let tab: ParallaxDeckTabsView_DeckTab
    let isFront: Bool
    let metrics: ParallaxDeckTabsView_DeckMetrics

    var body: some View {
        ZStack {
            base
            sheen
            content
        }
        .overlay(border)
        .clipShape(RoundedRectangle(cornerRadius: metrics.corner, style: .continuous))
    }

    private var base: some View {
        RoundedRectangle(cornerRadius: metrics.corner, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [tab.top, tab.bottom],
                    startPoint: .topLeading,
                    endPoint: .bottomTrailing
                )
            )
    }

    private var sheen: some View {
        RoundedRectangle(cornerRadius: metrics.corner, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color.white.opacity(isFront ? 0.28 : 0.14),
                        Color.white.opacity(0.0)
                    ],
                    startPoint: .top,
                    endPoint: .center
                )
            )
    }

    private var border: some View {
        RoundedRectangle(cornerRadius: metrics.corner, style: .continuous)
            .strokeBorder(Color.white.opacity(0.22), lineWidth: 1)
    }

    @ViewBuilder
    private var content: some View {
        if metrics.compact {
            compactContent
        } else {
            fullContent
        }
    }

    private var compactContent: some View {
        Image(systemName: tab.systemImage)
            .font(.system(size: 26, weight: .semibold))
            .foregroundStyle(.white)
            .shadow(color: .black.opacity(0.25), radius: 3, y: 2)
    }

    private var fullContent: some View {
        VStack(spacing: 14) {
            ZStack {
                Circle()
                    .fill(Color.white.opacity(0.18))
                    .frame(width: 64, height: 64)
                Image(systemName: tab.systemImage)
                    .font(.system(size: 30, weight: .semibold))
                    .foregroundStyle(.white)
            }
            Text(tab.title)
                .font(.system(size: 18, weight: .bold, design: .rounded))
                .foregroundStyle(.white)
                .shadow(color: .black.opacity(0.3), radius: 2, y: 1)
        }
        .padding(.horizontal, 12)
    }
}
"""###,
        "nav-rolling-bead-tabs": ###"""
import SwiftUI

// MARK: - Rolling Bead Tabs
//
// The active-tab indicator is a solid marble that physically rolls along the
// tab bar to the selected tab. Its rolling spin is coupled to the SAME animated
// position value as its horizontal offset, so the spring's overshoot lives in
// one place and the spin overshoots in lockstep with the x-bounce (rolling
// without slipping: angle = distance / radius). A KeyframeAnimator layers a
// brake-phase squash (x-stretch during travel, then a damped settle wobble) on
// top, as an independent transform.
//
// demo == true  -> a PhaseAnimator auto-rolls the bead across the tabs forever.
// demo == false -> tap a tab to roll the bead there (the faithful tap-driven
//                  interaction from the spec).

struct RollingBeadTabsView: View {
    var demo: Bool = false

    @State private var selectedIndex: Int = 0

    private let tabCount = 4
    private let symbols = ["house.fill", "magnifyingglass", "bell.fill", "person.fill"]

    var body: some View {
        GeometryReader { proxy in
            let metrics = RollingBeadTabsView_Metrics(size: proxy.size, tabCount: tabCount)
            content(metrics: metrics)
                .frame(width: proxy.size.width, height: proxy.size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .background(backgroundFill)
    }

    // MARK: Mode switch

    @ViewBuilder
    private func content(metrics: RollingBeadTabsView_Metrics) -> some View {
        if demo {
            demoContent(metrics: metrics)
        } else {
            interactiveContent(metrics: metrics)
        }
    }

    // demo: a trigger-less PhaseAnimator continuously cycles the tab indices,
    // .spring(bounce:0.4) rolls the bead between them forever.
    @ViewBuilder
    private func demoContent(metrics: RollingBeadTabsView_Metrics) -> some View {
        PhaseAnimator(phaseSequence) { index in
            barBody(metrics: metrics, activeIndex: index)
        } animation: { _ in
            .spring(duration: 0.85, bounce: 0.4)
        }
    }

    // real: tap a tab -> selectedIndex; the same spring rolls the bead.
    @ViewBuilder
    private func interactiveContent(metrics: RollingBeadTabsView_Metrics) -> some View {
        barBody(metrics: metrics, activeIndex: selectedIndex)
            .animation(.spring(duration: 0.85, bounce: 0.4), value: selectedIndex)
            .overlay(tapTargets(metrics: metrics))
    }

    // A long, looping walk across the tabs so we exercise both short hops and
    // long jumps (where the overshoot is most visible).
    private var phaseSequence: [Int] {
        [0, 1, 2, 3, 2, 0, 3, 1]
    }

    // MARK: Shared bar

    @ViewBuilder
    private func barBody(metrics: RollingBeadTabsView_Metrics, activeIndex: Int) -> some View {
        ZStack {
            trackView(metrics: metrics)
            RollingBeadTabsView_BeadView(metrics: metrics, activeIndex: activeIndex)
            iconRow(metrics: metrics, activeIndex: activeIndex)
        }
    }

    // MARK: Track

    @ViewBuilder
    private func trackView(metrics: RollingBeadTabsView_Metrics) -> some View {
        let h = metrics.trackHeight
        Capsule()
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.10, green: 0.12, blue: 0.16),
                        Color(red: 0.06, green: 0.07, blue: 0.10)
                    ],
                    startPoint: .top, endPoint: .bottom
                )
            )
            .overlay(
                Capsule().strokeBorder(
                    Color(red: 1, green: 1, blue: 1).opacity(0.06),
                    lineWidth: 1
                )
            )
            .frame(width: metrics.trackWidth, height: h)
            .position(x: metrics.size.width / 2, y: metrics.midY)
            .shadow(color: Color(red: 0, green: 0, blue: 0).opacity(0.35),
                    radius: h * 0.18, y: h * 0.10)
    }

    // MARK: Icons

    @ViewBuilder
    private func iconRow(metrics: RollingBeadTabsView_Metrics, activeIndex: Int) -> some View {
        ForEach(0..<tabCount, id: \.self) { i in
            let active = (i == activeIndex)
            Image(systemName: symbols[i])
                .font(.system(size: metrics.iconSize, weight: .semibold))
                .foregroundStyle(
                    active
                    ? Color(red: 0.07, green: 0.08, blue: 0.11)
                    : Color(red: 0.62, green: 0.66, blue: 0.74)
                )
                .scaleEffect(active ? 1.04 : 1.0)
                .position(x: metrics.centerX(for: i), y: metrics.midY)
                .animation(.easeOut(duration: 0.3), value: activeIndex)
        }
    }

    // MARK: Tap layer (interactive only)

    @ViewBuilder
    private func tapTargets(metrics: RollingBeadTabsView_Metrics) -> some View {
        HStack(spacing: 0) {
            ForEach(0..<tabCount, id: \.self) { i in
                Rectangle()
                    .fill(Color.clear)
                    .contentShape(Rectangle())
                    .onTapGesture { selectedIndex = i }
            }
        }
        .frame(width: metrics.trackWidth, height: metrics.trackHeight * 1.6)
        .position(x: metrics.size.width / 2, y: metrics.midY)
    }

    private var backgroundFill: some View {
        LinearGradient(
            colors: [
                Color(red: 0.04, green: 0.05, blue: 0.07),
                Color(red: 0.02, green: 0.03, blue: 0.04)
            ],
            startPoint: .top, endPoint: .bottom
        )
    }
}

// MARK: - Bead

private struct RollingBeadTabsView_BeadView: View {
    let metrics: RollingBeadTabsView_Metrics
    let activeIndex: Int

    var body: some View {
        let targetX = metrics.centerX(for: activeIndex)
        beadSurface
            .frame(width: metrics.beadSize, height: metrics.beadSize)
            // Single carrier: offset + spin both interpolate from `centerX`,
            // so the spring overshoot is shared between travel and spin.
            .modifier(RollingBeadTabsView_RollingModifier(centerX: targetX,
                                      restingX: metrics.size.width / 2,
                                      radius: metrics.beadSize / 2))
            // Brake-phase squash, re-keyed by the index change.
            .modifier(RollingBeadTabsView_SquashModifier(trigger: activeIndex))
            .position(x: metrics.size.width / 2, y: metrics.midY)
            .shadow(color: Color(red: 0.30, green: 0.55, blue: 1.0).opacity(0.45),
                    radius: metrics.beadSize * 0.22, y: metrics.beadSize * 0.10)
    }

    // The bead carries off-center surface detail so its rotation is visible —
    // a uniform disc spinning looks identical to one at rest.
    private var beadSurface: some View {
        ZStack {
            Circle()
                .fill(
                    RadialGradient(
                        colors: [
                            Color(red: 0.55, green: 0.78, blue: 1.0),
                            Color(red: 0.22, green: 0.46, blue: 0.95),
                            Color(red: 0.12, green: 0.28, blue: 0.72)
                        ],
                        center: UnitPoint(x: 0.34, y: 0.30),
                        startRadius: 0,
                        endRadius: metrics.beadSize * 0.72
                    )
                )

            // Rotating surface marks (these reveal the spin).
            ForEach(0..<3, id: \.self) { k in
                Circle()
                    .fill(Color(red: 0.85, green: 0.93, blue: 1.0).opacity(0.55))
                    .frame(width: metrics.beadSize * 0.12,
                           height: metrics.beadSize * 0.12)
                    .offset(y: -metrics.beadSize * 0.27)
                    .rotationEffect(.degrees(Double(k) * 120))
            }

            // A meridian band so a full revolution is unmistakable.
            Capsule()
                .fill(Color(red: 0.10, green: 0.20, blue: 0.50).opacity(0.45))
                .frame(width: metrics.beadSize * 0.10,
                       height: metrics.beadSize * 0.86)

            Circle()
                .strokeBorder(Color(red: 1, green: 1, blue: 1).opacity(0.18),
                              lineWidth: max(1, metrics.beadSize * 0.03))
        }
        .overlay(
            // Fixed specular highlight (does NOT rotate — sells a glossy marble).
            Circle()
                .fill(Color(red: 1, green: 1, blue: 1).opacity(0.55))
                .frame(width: metrics.beadSize * 0.18,
                       height: metrics.beadSize * 0.18)
                .blur(radius: metrics.beadSize * 0.04)
                .offset(x: -metrics.beadSize * 0.18,
                        y: -metrics.beadSize * 0.20)
        )
        .clipShape(Circle())
    }
}

// MARK: - Rolling modifier (offset + spin from one Animatable value)

private struct RollingBeadTabsView_RollingModifier: ViewModifier, Animatable {
    var centerX: CGFloat
    let restingX: CGFloat
    let radius: CGFloat

    // Animating this drives the spring; offset & rotation read the same value,
    // so overshoot is shared and the marble rolls without slipping.
    var animatableData: CGFloat {
        get { centerX }
        set { centerX = newValue }
    }

    func body(content: Content) -> some View {
        let travel = centerX - restingX
        let angle = radius > 0 ? Double(travel / radius) : 0
        content
            .rotationEffect(.radians(angle))
            .offset(x: travel)
    }
}

// MARK: - Squash modifier (brake-phase, KeyframeAnimator)

private struct RollingBeadTabsView_SquashModifier: ViewModifier {
    let trigger: Int

    func body(content: Content) -> some View {
        KeyframeAnimator(initialValue: Squash(),
                         trigger: trigger) { s in
            content.scaleEffect(x: s.scaleX, y: s.scaleY, anchor: .center)
        } keyframes: { _ in
            // x-stretch as it launches & rolls, then a damped wobble settle.
            KeyframeTrack(\.scaleX) {
                SpringKeyframe(1.22, duration: 0.30, spring: .snappy)
                SpringKeyframe(0.92, duration: 0.28, spring: .bouncy)
                SpringKeyframe(1.05, duration: 0.18, spring: .bouncy)
                SpringKeyframe(1.0, duration: 0.20, spring: .smooth)
            }
            KeyframeTrack(\.scaleY) {
                SpringKeyframe(0.84, duration: 0.30, spring: .snappy)
                SpringKeyframe(1.08, duration: 0.28, spring: .bouncy)
                SpringKeyframe(0.96, duration: 0.18, spring: .bouncy)
                SpringKeyframe(1.0, duration: 0.20, spring: .smooth)
            }
        }
    }

    struct Squash {
        var scaleX: CGFloat = 1.0
        var scaleY: CGFloat = 1.0
    }
}

// MARK: - Layout metrics

private struct RollingBeadTabsView_Metrics {
    let size: CGSize
    let tabCount: Int

    var midY: CGFloat { size.height / 2 }

    // The track spans most of the width with side insets.
    var sideInset: CGFloat { max(10, size.width * 0.08) }
    var trackWidth: CGFloat { max(1, size.width - sideInset * 2) }

    var trackHeight: CGFloat {
        min(size.height * 0.46, size.width * 0.16).clampedLow(12)
    }

    var beadSize: CGFloat {
        (trackHeight * 0.82).clampedLow(10)
    }

    var iconSize: CGFloat {
        (trackHeight * 0.40).clampedLow(8)
    }

    var slotWidth: CGFloat {
        tabCount > 0 ? trackWidth / CGFloat(tabCount) : trackWidth
    }

    func centerX(for index: Int) -> CGFloat {
        let start = size.width / 2 - trackWidth / 2
        return start + slotWidth * (CGFloat(index) + 0.5)
    }
}

private extension CGFloat {
    func clampedLow(_ low: CGFloat) -> CGFloat { Swift.max(self, low) }
}
"""###,
        "ob-color-bleed": ###"""
import SwiftUI

// MARK: - Ink Bleed Wipe
// Advancing a page releases a blot of ink that organically blooms and bleeds
// outward in irregular wobbling lobes to flood the screen with the next page's
// color, carrying the new content in behind the wavefront. The idle demo blooms
// a fresh ink wipe from a corner on a loop.
//
// Mechanism: an animatable closed `ColorBleedView_BlobShape` whose vertex radius is
// baseRadius(progress) + sine lobe wobble. It is used as a `.mask` on the
// incoming page layer so the wavefront reveals the next color + glyph.
// Pure Shape (no Metal, no Canvas-for-the-grow). iOS 17.

struct ColorBleedView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { geo in
            let size = geo.size
            if demo {
                ColorBleedView_DemoBleed(size: size)
            } else {
                ColorBleedView_InteractiveBleed(size: size)
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .clipShape(RoundedRectangle(cornerRadius: 22, style: .continuous))
    }
}

// MARK: - Palette of "pages"

private struct ColorBleedView_InkPage {
    let top: Color
    let bottom: Color
    let symbol: String
    let accent: Color
}

private let inkPages: [ColorBleedView_InkPage] = [
    ColorBleedView_InkPage(top: Color(red: 0.36, green: 0.20, blue: 0.62),
            bottom: Color(red: 0.18, green: 0.09, blue: 0.34),
            symbol: "sparkles", accent: Color(red: 0.92, green: 0.86, blue: 1.00)),
    ColorBleedView_InkPage(top: Color(red: 0.05, green: 0.50, blue: 0.60),
            bottom: Color(red: 0.02, green: 0.24, blue: 0.34),
            symbol: "paintbrush.pointed.fill", accent: Color(red: 0.82, green: 0.98, blue: 0.98)),
    ColorBleedView_InkPage(top: Color(red: 0.86, green: 0.34, blue: 0.36),
            bottom: Color(red: 0.50, green: 0.12, blue: 0.24),
            symbol: "flame.fill", accent: Color(red: 1.00, green: 0.92, blue: 0.84)),
    ColorBleedView_InkPage(top: Color(red: 0.18, green: 0.55, blue: 0.34),
            bottom: Color(red: 0.07, green: 0.28, blue: 0.20),
            symbol: "leaf.fill", accent: Color(red: 0.90, green: 1.00, blue: 0.90))
]

// MARK: - The animatable ink blob

/// A closed organic blob. Its radius at angle a is:
///   r(a) = baseRadius * progress  +  lobeAmplitude * sin(a * lobeCount + phase)
/// Both `progress` (bloom) and `phase` (lobe wobble) are animatable so the rim
/// keeps breathing smoothly while the blob grows. We never re-seed noise per
/// frame — the wobble is a deterministic function of the animated `phase`.
private struct ColorBleedView_BlobShape: Shape {
    var progress: CGFloat
    var phase: CGFloat
    let origin: CGPoint
    let maxRadius: CGFloat
    let lobeCount: Int
    let lobeAmplitude: CGFloat

    var animatableData: AnimatablePair<CGFloat, CGFloat> {
        get { AnimatablePair(progress, phase) }
        set {
            progress = newValue.first
            phase = newValue.second
        }
    }

    func path(in rect: CGRect) -> Path {
        var path = Path()
        let clamped = max(0, min(1, progress))
        // Eased base radius so the bloom decelerates as it floods.
        let base = maxRadius * easeOut(clamped)
        if base <= 0.0001 {
            return path
        }
        // Wobble amplitude grows in then relaxes near full coverage so the edge
        // settles flat once the screen is flooded.
        let wobbleEnv = sin(clamped * .pi)               // 0 -> 1 -> 0
        let amp = lobeAmplitude * (0.35 + 0.65 * wobbleEnv) * min(1, base / 40)

        let steps = 64
        for i in 0...steps {
            let t = CGFloat(i) / CGFloat(steps)
            let angle = t * 2 * .pi
            // Two superimposed lobe sets for a less regular, more organic rim.
            let w1 = sin(angle * CGFloat(lobeCount) + phase)
            let w2 = sin(angle * CGFloat(lobeCount + 3) - phase * 0.7)
            let r = base + amp * (0.7 * w1 + 0.3 * w2)
            let x = origin.x + cos(angle) * r
            let y = origin.y + sin(angle) * r
            let point = CGPoint(x: x, y: y)
            if i == 0 {
                path.move(to: point)
            } else {
                path.addLine(to: point)
            }
        }
        path.closeSubpath()
        return path
    }

    private func easeOut(_ x: CGFloat) -> CGFloat {
        1 - pow(1 - x, 2.4)
    }
}

// MARK: - Shared "page" content

private struct ColorBleedView_PageContent: View {
    let page: ColorBleedView_InkPage
    let size: CGSize

    var body: some View {
        let dim = min(size.width, size.height)
        ZStack {
            LinearGradient(colors: [page.top, page.bottom],
                           startPoint: .topLeading,
                           endPoint: .bottomTrailing)
            // Carried content behind the wavefront.
            VStack(spacing: dim * 0.06) {
                Image(systemName: page.symbol)
                    .font(.system(size: dim * 0.28, weight: .semibold))
                    .foregroundStyle(page.accent)
                    .shadow(color: .black.opacity(0.25), radius: dim * 0.02, y: dim * 0.01)
                Capsule()
                    .fill(page.accent.opacity(0.85))
                    .frame(width: dim * 0.34, height: max(3, dim * 0.022))
            }
        }
    }
}

// MARK: - Interactive (demo == false)

private struct ColorBleedView_InteractiveBleed: View {
    let size: CGSize

    @State private var baseIndex: Int = 0
    @State private var progress: CGFloat = 0
    @State private var phase: CGFloat = 0
    @State private var origin: CGPoint = .zero

    private var incomingIndex: Int { (baseIndex + 1) % inkPages.count }

    var body: some View {
        let maxR = floodRadius(from: origin, in: size)
        ZStack {
            // Base layer: the currently-settled page, always full-screen.
            ColorBleedView_PageContent(page: inkPages[baseIndex], size: size)

            // Incoming layer revealed by the growing ink blob.
            ColorBleedView_PageContent(page: inkPages[incomingIndex], size: size)
                .mask {
                    ColorBleedView_BlobShape(progress: progress,
                              phase: phase,
                              origin: origin,
                              maxRadius: maxR,
                              lobeCount: 5,
                              lobeAmplitude: min(size.width, size.height) * 0.085)
                }

            hint
        }
        .contentShape(Rectangle())
        .gesture(
            SpatialTapGesture(coordinateSpace: .local)
                .onEnded { value in
                    advance(from: value.location)
                }
        )
    }

    private var hint: some View {
        VStack {
            Spacer()
            Text("tap to bleed")
                .font(.system(size: max(9, min(size.width, size.height) * 0.07),
                              weight: .semibold, design: .rounded))
                .foregroundStyle(.white.opacity(progress > 0.05 ? 0 : 0.55))
                .padding(.bottom, min(size.width, size.height) * 0.06)
                .animation(.easeInOut(duration: 0.25), value: progress)
        }
        .allowsHitTesting(false)
    }

    private func advance(from point: CGPoint) {
        guard progress < 0.001 else { return }
        origin = point
        // Drive bloom AND wobble phase inside the same withAnimation block so the
        // rim keeps breathing as it grows (no TimelineView here — that would make
        // the shape re-read the jumped model value and snap instead of grow).
        withAnimation(.easeOut(duration: 0.55)) {
            progress = 1
            phase += .pi * 1.6
        }
        // After the flood fully covers, promote the incoming page to the base and
        // reset progress to 0 with no visible change (full incoming == new base).
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.58) {
            baseIndex = incomingIndex
            progress = 0
        }
    }
}

// MARK: - Demo (demo == true)

private struct ColorBleedView_DemoBleed: View {
    let size: CGSize

    // ~3.2s per bleed cycle.
    private let period: Double = 3.2

    var body: some View {
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            content(time: t)
        }
    }

    @ViewBuilder
    private func content(time: Double) -> some View {
        // Compute all animation state up front so the ViewBuilder body holds only
        // view content (avoids any "() cannot conform to View" pitfalls).
        let cycle = (time / period).truncatingRemainder(dividingBy: 1)   // 0..<1
        // Which page is settled vs. blooming in. Each completed cycle advances one.
        let step = Int(time / period)
        let baseIndex = ((step % inkPages.count) + inkPages.count) % inkPages.count
        let incomingIndex = (baseIndex + 1) % inkPages.count

        // Bloom progress: grow over the first ~75% of the cycle, then hold full so
        // the wrap (full incoming -> new base) has no blank/flash frame.
        let raw = min(1, CGFloat(cycle) / 0.75)
        let progress = easeInOut(raw)

        // Origin rotates among the four corners each cycle so it blooms from a
        // fresh corner on the loop.
        let origin = corner(for: step, in: size)
        let maxR = floodRadius(from: origin, in: size)
        // Phase advances continuously with real time so the rim wobbles smoothly.
        let phase = CGFloat(time) * 1.4

        ZStack {
            ColorBleedView_PageContent(page: inkPages[baseIndex], size: size)

            ColorBleedView_PageContent(page: inkPages[incomingIndex], size: size)
                .mask {
                    ColorBleedView_BlobShape(progress: progress,
                              phase: phase,
                              origin: origin,
                              maxRadius: maxR,
                              lobeCount: 5,
                              lobeAmplitude: min(size.width, size.height) * 0.085)
                }
        }
    }

    private func corner(for step: Int, in size: CGSize) -> CGPoint {
        switch ((step % 4) + 4) % 4 {
        case 0: return CGPoint(x: size.width * 0.16, y: size.height * 0.82)
        case 1: return CGPoint(x: size.width * 0.84, y: size.height * 0.82)
        case 2: return CGPoint(x: size.width * 0.84, y: size.height * 0.18)
        default: return CGPoint(x: size.width * 0.16, y: size.height * 0.18)
        }
    }

    private func easeInOut(_ x: CGFloat) -> CGFloat {
        let c = max(0, min(1, x))
        return c * c * (3 - 2 * c)
    }
}

// MARK: - Shared geometry

/// Distance from the bloom origin to the farthest corner, plus a margin for the
/// lobe wobble amplitude so the blob fully floods with no surviving corner sliver.
private func floodRadius(from origin: CGPoint, in size: CGSize) -> CGFloat {
    let corners = [
        CGPoint(x: 0, y: 0),
        CGPoint(x: size.width, y: 0),
        CGPoint(x: 0, y: size.height),
        CGPoint(x: size.width, y: size.height)
    ]
    var maxDist: CGFloat = 0
    for c in corners {
        let dx = c.x - origin.x
        let dy = c.y - origin.y
        let d = sqrt(dx * dx + dy * dy)
        if d > maxDist { maxDist = d }
    }
    let wobbleMargin = min(size.width, size.height) * 0.10
    return maxDist + wobbleMargin
}
"""###,
        "ob-constellation-hero": ###"""
import SwiftUI

/// Constellation Hero — drifting star points that wire themselves into themed
/// constellations (heart, bell, key) by drawing connecting lines with an
/// animatable trim, then twinkle. Swiping re-routes the lines to the next
/// figure; the demo loop self-wires on a timer.
struct ConstellationHeroView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { geo in
            let side = min(geo.size.width, geo.size.height)
            ZStack {
                ConstellationHeroView_CHBackdrop()
                Group {
                    if demo {
                        ConstellationHeroView_CHDemoStage(side: side)
                    } else {
                        ConstellationHeroView_CHInteractiveStage(side: side)
                    }
                }
                .frame(width: side, height: side)
                .frame(maxWidth: .infinity, maxHeight: .infinity)
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .clipped()
    }
}

// MARK: - Figures

private struct ConstellationHeroView_CHFigure {
    let nodes: [CGPoint]   // normalized 0...1, ordered for the connecting polyline
    let closed: Bool
}

private enum ConstellationHeroView_CHCatalog {
    /// Heart traced clockwise from the bottom tip.
    static let heart = ConstellationHeroView_CHFigure(
        nodes: [
            CGPoint(x: 0.50, y: 0.86),
            CGPoint(x: 0.20, y: 0.55),
            CGPoint(x: 0.18, y: 0.34),
            CGPoint(x: 0.31, y: 0.22),
            CGPoint(x: 0.44, y: 0.30),
            CGPoint(x: 0.50, y: 0.40),
            CGPoint(x: 0.56, y: 0.30),
            CGPoint(x: 0.69, y: 0.22),
            CGPoint(x: 0.82, y: 0.34),
            CGPoint(x: 0.80, y: 0.55)
        ],
        closed: true
    )

    /// Bell: domed body, splayed base, hanging clapper.
    static let bell = ConstellationHeroView_CHFigure(
        nodes: [
            CGPoint(x: 0.50, y: 0.16),
            CGPoint(x: 0.36, y: 0.24),
            CGPoint(x: 0.30, y: 0.46),
            CGPoint(x: 0.24, y: 0.66),
            CGPoint(x: 0.18, y: 0.74),
            CGPoint(x: 0.82, y: 0.74),
            CGPoint(x: 0.76, y: 0.66),
            CGPoint(x: 0.70, y: 0.46),
            CGPoint(x: 0.64, y: 0.24),
            CGPoint(x: 0.50, y: 0.16)
        ],
        closed: false
    )

    /// Key: round bow, shaft, two teeth.
    static let key = ConstellationHeroView_CHFigure(
        nodes: [
            CGPoint(x: 0.30, y: 0.24),
            CGPoint(x: 0.22, y: 0.34),
            CGPoint(x: 0.30, y: 0.44),
            CGPoint(x: 0.40, y: 0.40),
            CGPoint(x: 0.52, y: 0.46),
            CGPoint(x: 0.64, y: 0.52),
            CGPoint(x: 0.64, y: 0.66),
            CGPoint(x: 0.72, y: 0.60),
            CGPoint(x: 0.80, y: 0.68),
            CGPoint(x: 0.86, y: 0.60)
        ],
        closed: false
    )

    /// Empty figure — no lines, used as the "before" state so the opening draw
    /// routes cleanly from nothing into the heart.
    static let blank = ConstellationHeroView_CHFigure(nodes: [], closed: false)

    static let all: [ConstellationHeroView_CHFigure] = [heart, bell, key]

    static func figure(_ index: Int) -> ConstellationHeroView_CHFigure {
        all[((index % all.count) + all.count) % all.count]
    }
}

// MARK: - Constellation polyline shape (uses SwiftUI's built-in .trim)

private struct ConstellationHeroView_CHConstellationPath: Shape {
    let figure: ConstellationHeroView_CHFigure
    let inset: CGFloat

    func path(in rect: CGRect) -> Path {
        var path = Path()
        let area = rect.insetBy(dx: inset, dy: inset)
        guard let first = figure.nodes.first else { return path }
        func mapped(_ p: CGPoint) -> CGPoint {
            CGPoint(x: area.minX + p.x * area.width,
                    y: area.minY + p.y * area.height)
        }
        path.move(to: mapped(first))
        for node in figure.nodes.dropFirst() {
            path.addLine(to: mapped(node))
        }
        if figure.closed {
            path.addLine(to: mapped(first))
        }
        return path
    }
}

// MARK: - Star drift math (deterministic, time-based)

private enum ConstellationHeroView_CHStars {
    /// Stable per-index phase so drift never strobes between frames.
    static func phase(_ index: Int) -> Double {
        let s = sin(Double(index) * 12.9898) * 43758.5453
        return (s - floor(s)) * 2.0 * .pi
    }

    /// Small wandering offset for a star, pure function of time.
    static func drift(index: Int, time: Double, amplitude: CGFloat) -> CGSize {
        let ph = phase(index)
        // Pin trig to CGFloat before mixing with the CGFloat amplitude so the
        // numeric type is unambiguous across toolchains.
        let dx = CGFloat(sin(time * 0.6 + ph)) * amplitude
        let dy = CGFloat(cos(time * 0.45 + ph * 1.3)) * amplitude
        return CGSize(width: dx, height: dy)
    }

    /// Per-star twinkle opacity, floored so the sky is never blank.
    static func twinkle(index: Int, time: Double) -> Double {
        let ph = phase(index)
        let raw = sin(time * 1.7 + ph) * 0.5 + 0.5  // 0...1
        return 0.55 + raw * 0.45                     // 0.55...1.0
    }
}

// MARK: - Shared constellation canvas

/// Renders an outgoing figure (un-drawing) cross-faded with an incoming figure
/// (drawing) plus the drifting / twinkling star layer. `progress` 0→1 means a
/// full hand-off from `figure` to `nextFigure`.
private struct ConstellationHeroView_CHConstellationCanvas: View {
    let side: CGFloat
    let figure: ConstellationHeroView_CHFigure
    let nextFigure: ConstellationHeroView_CHFigure
    let progress: CGFloat   // 0...1 cross-trim
    let time: Double
    let twinkleBoost: Double // 0...1 extra glow when a figure is fully wired

    private var inset: CGFloat { side * 0.14 }
    private var lineWidth: CGFloat { max(1.2, side * 0.012) }
    private var starRadius: CGFloat { max(1.6, side * 0.016) }

    var body: some View {
        ZStack {
            outgoingLines
            incomingLines
            starLayer
        }
        .frame(width: side, height: side)
    }

    // Outgoing figure recedes: full when progress==0, gone when progress==1.
    private var outgoingLines: some View {
        let p = 1.0 - progress
        return ConstellationHeroView_CHConstellationPath(figure: figure, inset: inset)
            .trim(from: 0, to: p)
            .stroke(lineGradient(opacity: lineOpacity(p)),
                    style: StrokeStyle(lineWidth: lineWidth, lineCap: .round, lineJoin: .round))
            .shadow(color: glowColor.opacity(0.55 * lineOpacity(p)),
                    radius: lineWidth * 1.6)
    }

    // Incoming figure draws in as progress climbs.
    private var incomingLines: some View {
        let p = progress
        return ConstellationHeroView_CHConstellationPath(figure: nextFigure, inset: inset)
            .trim(from: 0, to: p)
            .stroke(lineGradient(opacity: lineOpacity(p)),
                    style: StrokeStyle(lineWidth: lineWidth, lineCap: .round, lineJoin: .round))
            .shadow(color: glowColor.opacity(0.55 * lineOpacity(p)),
                    radius: lineWidth * 1.6)
    }

    // Both figures' stars are rendered and crossfaded by progress, so dots never
    // teleport at the midpoint. A blank side stays hidden and forces its partner
    // to full opacity, so the opening draw / blank hand-off is never empty.
    private func starOpacity(outgoing: Bool) -> Double {
        if figure.nodes.isEmpty { return outgoing ? 0 : 1 }
        if nextFigure.nodes.isEmpty { return outgoing ? 1 : 0 }
        return outgoing ? Double(1 - progress) : Double(progress)
    }

    private var starLayer: some View {
        let area = CGRect(x: 0, y: 0, width: side, height: side).insetBy(dx: inset, dy: inset)
        return ZStack {
            starField(figure.nodes, area: area)
                .opacity(starOpacity(outgoing: true))
            starField(nextFigure.nodes, area: area)
                .opacity(starOpacity(outgoing: false))
        }
    }

    private func starField(_ nodes: [CGPoint], area: CGRect) -> some View {
        ZStack {
            ForEach(nodes.indices, id: \.self) { i in
                star(at: nodes[i], index: i, area: area)
            }
        }
    }

    private func star(at norm: CGPoint, index: Int, area: CGRect) -> some View {
        let base = CGPoint(x: area.minX + norm.x * area.width,
                           y: area.minY + norm.y * area.height)
        let drift = ConstellationHeroView_CHStars.drift(index: index, time: time, amplitude: side * 0.012)
        let tw = min(1.0, ConstellationHeroView_CHStars.twinkle(index: index, time: time) + twinkleBoost * 0.25)
        return ZStack {
            Circle()
                .fill(glowColor)
                .frame(width: starRadius * 3.0, height: starRadius * 3.0)
                .blur(radius: starRadius * 1.1)
                .opacity(0.35 * tw)
            Circle()
                .fill(Color(red: 0.98, green: 0.96, blue: 1.0))
                .frame(width: starRadius * 2.0, height: starRadius * 2.0)
                .opacity(tw)
        }
        .position(x: base.x + drift.width, y: base.y + drift.height)
    }

    // MARK: derived style

    private func lineOpacity(_ p: CGFloat) -> Double {
        // Floor so a half-drawn line is always legible; brighten when complete.
        let base = 0.55 + Double(p) * 0.45
        return min(1.0, base + twinkleBoost * 0.2)
    }

    private var glowColor: Color {
        Color(red: 0.62, green: 0.74, blue: 1.0)
    }

    private func lineGradient(opacity: Double) -> LinearGradient {
        LinearGradient(
            colors: [
                Color(red: 0.75, green: 0.85, blue: 1.0).opacity(opacity),
                Color(red: 0.58, green: 0.66, blue: 1.0).opacity(opacity)
            ],
            startPoint: .topLeading,
            endPoint: .bottomTrailing
        )
    }
}

// MARK: - Backdrop

private struct ConstellationHeroView_CHBackdrop: View {
    var body: some View {
        RadialGradient(
            colors: [
                Color(red: 0.10, green: 0.09, blue: 0.18),
                Color(red: 0.05, green: 0.04, blue: 0.10)
            ],
            center: .center,
            startRadius: 0,
            endRadius: 400
        )
    }
}

// MARK: - Demo stage (self-driving)

private struct ConstellationHeroView_CHDemoStage: View {
    let side: CGFloat

    // Per beat the constellation hands off from one figure to the next:
    // hold (twinkle the current figure) → re-route (undraw current / draw next).
    private let beat: Double = 3.4
    @State private var start = Date()

    var body: some View {
        TimelineView(.animation) { context in
            // Relative clock so beat 0 (the opening draw-in) actually plays and
            // the drift/twinkle phase still uses absolute time for variety.
            let t = context.date.timeIntervalSince(start)
            let phase = computePhase(max(0, t))
            ConstellationHeroView_CHConstellationCanvas(
                side: side,
                figure: phase.from,
                nextFigure: phase.to,
                progress: phase.progress,
                time: t,
                twinkleBoost: phase.twinkleBoost
            )
        }
    }

    struct CHPhase {
        let from: ConstellationHeroView_CHFigure
        let to: ConstellationHeroView_CHFigure
        let progress: CGFloat
        let twinkleBoost: Double
    }

    /// Beat 0 routes from a blank figure into the heart (opening draw), so the
    /// first frame already shows the heart's stars — never blank. Every later
    /// beat holds the current figure (twinkling) then re-routes into the next.
    private func computePhase(_ t: Double) -> CHPhase {
        let beatIndex = Int(floor(t / beat))
        let local = t - Double(beatIndex) * beat

        let holdDur = 1.6
        let routeDur = beat - holdDur

        // `current` is the figure shown this beat (held, then un-drawn); `next`
        // is the one it re-routes into. The very first hold doubles as the
        // draw-in from blank so the opening frame is never empty.
        let current = ConstellationHeroView_CHCatalog.figure(beatIndex)
        let next = ConstellationHeroView_CHCatalog.figure(beatIndex + 1)

        if local < holdDur {
            if beatIndex == 0 {
                // Opening: draw the first figure in from blank during the hold.
                let p = easeOutCubic(local / holdDur)
                return CHPhase(from: ConstellationHeroView_CHCatalog.blank, to: current,
                               progress: CGFloat(p), twinkleBoost: p)
            }
            // Hold + twinkle the fully wired current figure.
            return CHPhase(from: current, to: next, progress: 0, twinkleBoost: 1)
        }

        // Re-route: undraw current, draw next.
        let route = easeInOutCubic((local - holdDur) / routeDur)
        return CHPhase(from: current,
                       to: next,
                       progress: CGFloat(route),
                       twinkleBoost: 1 - route)
    }

    private func easeOutCubic(_ x: Double) -> Double {
        let c = 1 - x
        return 1 - c * c * c
    }

    private func easeInOutCubic(_ x: Double) -> Double {
        x < 0.5 ? 4 * x * x * x : 1 - pow(-2 * x + 2, 3) / 2
    }
}

// MARK: - Interactive stage (real swipe)

private struct ConstellationHeroView_CHInteractiveStage: View {
    let side: CGFloat

    @State private var figureIndex: Int = 0
    // Live re-route progress 0...1: 0 = current figure wired, 1 = handed off to
    // the next figure. Updated directly in onChanged so onEnded can spring it.
    @State private var progress: CGFloat = 0
    @State private var dragStart: CGFloat = 0

    var body: some View {
        TimelineView(.animation) { context in
            let t = context.date.timeIntervalSinceReferenceDate
            // Glow swells when a figure is fully wired (p near 0 or 1) and dims
            // mid-scrub, so a settled constellation reads as "locked in".
            let boost = 1.0 - Double(min(progress, 1 - progress)) * 2.0
            ConstellationHeroView_CHConstellationCanvas(
                side: side,
                figure: ConstellationHeroView_CHCatalog.figure(figureIndex),
                nextFigure: ConstellationHeroView_CHCatalog.figure(figureIndex + 1),
                progress: progress,
                time: t,
                twinkleBoost: boost
            )
            .contentShape(Rectangle())
            .gesture(dragGesture)
        }
    }

    private var dragGesture: some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                // Swipe left advances (draws the next figure); width / side.
                let delta = -value.translation.width / max(side, 1)
                progress = clamp(dragStart + delta)
            }
            .onEnded { value in
                let predicted = -value.predictedEndTranslation.width / max(side, 1)
                let committed = clamp(dragStart + predicted)
                if committed > 0.5 {
                    // Finish the re-route, then re-base onto the new figure (tied
                    // to the spring, so a fast re-grab can't be clobbered) — the
                    // new figure at progress 0 renders identically to progress 1.
                    withAnimation(.spring(response: 0.45, dampingFraction: 0.8),
                                  completionCriteria: .logicallyComplete) {
                        progress = 1
                    } completion: {
                        figureIndex += 1
                        progress = 0
                        dragStart = 0
                    }
                } else {
                    withAnimation(.spring(response: 0.45, dampingFraction: 0.8)) {
                        progress = 0
                    }
                    dragStart = 0
                }
            }
    }

    private func clamp(_ v: CGFloat) -> CGFloat {
        min(1, max(0, v))
    }
}
"""###,
        "ob-depth-diorama": ###"""
import SwiftUI

// Depth Diorama Swipe
// A 4-layer, code-drawn parallax scene (sky, hills, midground, foreground).
// Dragging scrubs a paged "camera"; layers offset by their depth factor so the
// world has real depth. Released, it springs to the nearest page with each layer
// overshooting at its own parallaxed rate. In demo mode a TimelineView pans the
// camera gently side to side on a loop so the tile stays alive with no touch.

struct DepthDioramaView: View {
    var demo: Bool = false

    // Page state (interactive mode). Progress is measured in *page units*:
    // 0 = first page, 1 = second page, 2 = third page.
    @State private var page: Int = 1
    @State private var liveProgress: CGFloat = 1   // animatable camera position in page units
    @State private var dragFraction: CGFloat = 0   // live drag contribution, page units

    private let pageCount: Int = 3

    var body: some View {
        GeometryReader { geo in
            let size = geo.size
            content(size: size)
                .frame(width: size.width, height: size.height)
                .clipped()
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .onAppear {
            // Seed interactive camera at the middle page.
            liveProgress = CGFloat(startPage)
            page = startPage
        }
    }

    private var startPage: Int { pageCount / 2 }

    // MARK: - Content router

    @ViewBuilder
    private func content(size: CGSize) -> some View {
        if demo {
            demoScene(size: size)
        } else {
            interactiveScene(size: size)
        }
    }

    // MARK: - Demo (self-driving)

    private func demoScene(size: CGSize) -> some View {
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            // ~3.4s loop. Pan the camera around the middle page by ±0.62 of a page
            // so we reveal neighbouring scene content without ever sweeping past
            // the covered strip width.
            let phase = t.truncatingRemainder(dividingBy: 3.4) / 3.4
            let swing = sin(phase * 2 * .pi)
            let progress = CGFloat(startPage) + CGFloat(swing) * 0.62
            diorama(progress: progress, size: size)
        }
    }

    // MARK: - Interactive (real component)

    private func interactiveScene(size: CGSize) -> some View {
        let progress = liveProgress + dragFraction
        let pageWidth = max(size.width, 1)

        return diorama(progress: progress, size: size)
            .contentShape(Rectangle())
            .gesture(
                DragGesture(minimumDistance: 0)
                    .onChanged { value in
                        // translation.width / pageWidth -> page progress.
                        // Drag left (negative) advances forward (+progress).
                        var frac = -value.translation.width / pageWidth
                        let raw = CGFloat(page) + frac
                        // Rubber-band beyond the first/last page so over-drag
                        // resists instead of running off the scene.
                        if raw < 0 {
                            frac -= raw * 0.55
                        } else if raw > CGFloat(pageCount - 1) {
                            frac -= (raw - CGFloat(pageCount - 1)) * 0.55
                        }
                        dragFraction = frac
                    }
                    .onEnded { value in
                        let predicted = -value.predictedEndTranslation.width / pageWidth
                        let projected = CGFloat(page) + predicted
                        let target = clampPage(Int(projected.rounded()))

                        // Fold the live drag into liveProgress, then spring to the
                        // target page so layers overshoot at their own rates.
                        liveProgress += dragFraction
                        dragFraction = 0
                        page = target

                        let velocity = -value.velocity.width / pageWidth
                        withAnimation(
                            .interpolatingSpring(mass: 1.0, stiffness: 130, damping: 16, initialVelocity: Double(velocity))
                        ) {
                            liveProgress = CGFloat(target)
                        }
                    }
            )
    }

    private func clampPage(_ p: Int) -> Int {
        min(max(p, 0), pageCount - 1)
    }

    // MARK: - Shared offset math

    /// The single source of truth for both modes.
    /// offset = progress (in page units) * depth * pageWidth, negated so that
    /// increasing progress moves the world left (camera moves right).
    private func layerOffset(depth: CGFloat, progress: CGFloat, pageWidth: CGFloat) -> CGFloat {
        -progress * depth * pageWidth
    }

    /// Width each layer must be drawn at so no edge ever reveals blank, including
    /// the foreground (depth ~1.0) translating a full pageWidth per page across
    /// all pages, plus headroom for the spring overshoot.
    private func stripWidth(pageWidth: CGFloat) -> CGFloat {
        let pages = CGFloat(pageCount)
        let overshootMargin = pageWidth * 0.9
        return pageWidth * pages + overshootMargin
    }

    // MARK: - The diorama (4 layers)

    private func diorama(progress: CGFloat, size: CGSize) -> some View {
        let w = size.width
        let h = size.height
        let strip = stripWidth(pageWidth: w)

        // Depth factors: slow sky -> fast foreground.
        let skyDepth: CGFloat = 0.10
        let hillDepth: CGFloat = 0.32
        let midDepth: CGFloat = 0.62
        let fgDepth: CGFloat = 1.00

        return ZStack {
            skyLayer(strip: strip, height: h, progress: progress, pageWidth: w)
                .offset(x: layerOffset(depth: skyDepth, progress: progress, pageWidth: w))

            hillsLayer(strip: strip, height: h)
                .offset(x: layerOffset(depth: hillDepth, progress: progress, pageWidth: w))

            midgroundLayer(strip: strip, height: h, pageWidth: w)
                .offset(x: layerOffset(depth: midDepth, progress: progress, pageWidth: w))

            foregroundLayer(strip: strip, height: h)
                .offset(x: layerOffset(depth: fgDepth, progress: progress, pageWidth: w))
        }
        .frame(width: w, height: h)
    }

    // MARK: Layer 1 — Sky (with travelling sun/moon detents)

    private func skyLayer(strip: CGFloat, height: CGFloat, progress: CGFloat, pageWidth: CGFloat) -> some View {
        // Blend the sky gradient across pages: dawn -> day -> dusk.
        let frac = progress / CGFloat(max(pageCount - 1, 1))
        let topColor = blendColor(
            RGB(0.16, 0.21, 0.42),   // dawn indigo
            RGB(0.36, 0.62, 0.92),   // day blue
            RGB(0.45, 0.24, 0.40),   // dusk plum
            t: frac
        )
        let bottomColor = blendColor(
            RGB(0.55, 0.45, 0.58),
            RGB(0.78, 0.88, 0.96),
            RGB(0.95, 0.62, 0.46),
            t: frac
        )

        return ZStack {
            LinearGradient(
                colors: [topColor, bottomColor],
                startPoint: .top,
                endPoint: .bottom
            )
            celestialBody(strip: strip, height: height, frac: frac)
        }
        .frame(width: strip, height: height)
    }

    private func celestialBody(strip: CGFloat, height: CGFloat, frac: CGFloat) -> some View {
        // Sun arcs up and across the sky as we move through pages.
        let cx = strip * (0.22 + 0.56 * frac)
        let arc = CGFloat(sin(Double(frac) * .pi))   // 0 -> 1 -> 0
        let cy = height * (0.42 - 0.20 * arc)
        let r = max(height * 0.13, 14)
        let warm = blendColor(
            RGB(1.0, 0.93, 0.78),
            RGB(1.0, 0.97, 0.86),
            RGB(1.0, 0.78, 0.55),
            t: frac
        )
        return Circle()
            .fill(
                RadialGradient(
                    colors: [warm, warm.opacity(0.0)],
                    center: .center,
                    startRadius: 0,
                    endRadius: r * 1.6
                )
            )
            .frame(width: r * 2.2, height: r * 2.2)
            .position(x: cx, y: cy)
    }

    // MARK: Layer 2 — Far hills

    private func hillsLayer(strip: CGFloat, height: CGFloat) -> some View {
        DepthDioramaView_HillsShape(baseline: 0.46, amplitude: 0.12, waves: 4.5, phase: 0.0)
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.34, green: 0.45, blue: 0.55),
                        Color(red: 0.22, green: 0.32, blue: 0.42)
                    ],
                    startPoint: .top,
                    endPoint: .bottom
                )
            )
            .frame(width: strip, height: height)
    }

    // MARK: Layer 3 — Midground hills with trees (props)

    private func midgroundLayer(strip: CGFloat, height: CGFloat, pageWidth: CGFloat) -> some View {
        ZStack(alignment: .topLeading) {
            DepthDioramaView_HillsShape(baseline: 0.62, amplitude: 0.16, waves: 3.0, phase: 1.3)
                .fill(
                    LinearGradient(
                        colors: [
                            Color(red: 0.20, green: 0.40, blue: 0.34),
                            Color(red: 0.12, green: 0.28, blue: 0.24)
                        ],
                        startPoint: .top,
                        endPoint: .bottom
                    )
                )
                .frame(width: strip, height: height)

            // A few trees spaced along the strip — distinct props per "page".
            ForEach(0..<7, id: \.self) { i in
                let x = strip * (0.10 + 0.12 * CGFloat(i))
                let baseY = height * (0.60 + 0.015 * CGFloat(i % 3))
                tree(height: height * (0.16 + 0.03 * CGFloat(i % 2)))
                    .position(x: x, y: baseY)
            }
        }
        .frame(width: strip, height: height)
    }

    private func tree(height treeH: CGFloat) -> some View {
        VStack(spacing: -treeH * 0.28) {
            DepthDioramaView_Triangle()
                .fill(Color(red: 0.10, green: 0.30, blue: 0.22))
                .frame(width: treeH * 0.7, height: treeH * 0.7)
            DepthDioramaView_Triangle()
                .fill(Color(red: 0.13, green: 0.34, blue: 0.25))
                .frame(width: treeH * 0.9, height: treeH * 0.8)
        }
    }

    // MARK: Layer 4 — Foreground ground + grass tufts

    private func foregroundLayer(strip: CGFloat, height: CGFloat) -> some View {
        ZStack(alignment: .topLeading) {
            DepthDioramaView_HillsShape(baseline: 0.86, amplitude: 0.06, waves: 5.0, phase: 0.4)
                .fill(
                    LinearGradient(
                        colors: [
                            Color(red: 0.16, green: 0.24, blue: 0.16),
                            Color(red: 0.06, green: 0.12, blue: 0.08)
                        ],
                        startPoint: .top,
                        endPoint: .bottom
                    )
                )
                .frame(width: strip, height: height)

            ForEach(0..<14, id: \.self) { i in
                let x = strip * (0.04 + 0.066 * CGFloat(i))
                grassTuft(height: height * (0.10 + 0.04 * CGFloat(i % 3)))
                    .position(x: x, y: height * (0.86 + 0.01 * CGFloat(i % 2)))
            }
        }
        .frame(width: strip, height: height)
    }

    private func grassTuft(height tuftH: CGFloat) -> some View {
        Capsule()
            .fill(Color(red: 0.10, green: 0.20, blue: 0.12))
            .frame(width: max(tuftH * 0.18, 2), height: tuftH)
    }

    // MARK: - Color blending helper (dawn -> day -> dusk)

    /// A plain RGB triple so blending stays pure-Swift (no UIKit round-trip).
    struct RGB {
        var r: CGFloat
        var g: CGFloat
        var b: CGFloat
        init(_ r: CGFloat, _ g: CGFloat, _ b: CGFloat) {
            self.r = r
            self.g = g
            self.b = b
        }
        var color: Color {
            Color(red: Double(r), green: Double(g), blue: Double(b))
        }
    }

    private func blendColor(_ a: RGB, _ b: RGB, _ c: RGB, t: CGFloat) -> Color {
        let tt = min(max(t, 0), 1)
        if tt < 0.5 {
            return mix(a, b, ratio: tt / 0.5).color
        } else {
            return mix(b, c, ratio: (tt - 0.5) / 0.5).color
        }
    }

    private func mix(_ a: RGB, _ b: RGB, ratio: CGFloat) -> RGB {
        let r = min(max(ratio, 0), 1)
        return RGB(
            a.r + (b.r - a.r) * r,
            a.g + (b.g - a.g) * r,
            a.b + (b.b - a.b) * r
        )
    }
}

// MARK: - Shapes

/// A rolling hills silhouette filling from a baseline to the bottom of the rect.
private struct DepthDioramaView_HillsShape: Shape {
    var baseline: CGFloat   // 0..1 fraction of height where the ridge sits
    var amplitude: CGFloat  // 0..1 fraction of height of the wave swing
    var waves: CGFloat      // number of wave humps across the width
    var phase: CGFloat      // phase offset in radians

    func path(in rect: CGRect) -> Path {
        var path = Path()
        let w = rect.width
        let h = rect.height
        let baseY = h * baseline
        let amp = h * amplitude
        let step: CGFloat = max(w / 80, 2)

        path.move(to: CGPoint(x: 0, y: h))
        var x: CGFloat = 0
        while x <= w {
            let theta = (x / w) * waves * 2 * .pi + phase
            let y = baseY - CGFloat(sin(Double(theta))) * amp
            path.addLine(to: CGPoint(x: x, y: y))
            x += step
        }
        path.addLine(to: CGPoint(x: w, y: h))
        path.closeSubpath()
        return path
    }
}

/// An upward-pointing triangle (tree canopy tier).
private struct DepthDioramaView_Triangle: Shape {
    func path(in rect: CGRect) -> Path {
        var path = Path()
        path.move(to: CGPoint(x: rect.midX, y: rect.minY))
        path.addLine(to: CGPoint(x: rect.maxX, y: rect.maxY))
        path.addLine(to: CGPoint(x: rect.minX, y: rect.maxY))
        path.closeSubpath()
        return path
    }
}
"""###,
        "ob-ferrofluid-dots": ###"""
import SwiftUI

// MARK: - Ferrofluid Dots
//
// Page dots behave like magnetized ferrofluid: as a magnet (your finger, or
// an auto-swept virtual one) passes between them, the nearest dots stretch
// toward it and fuse into a gooey metaball bridge, then release and snap back
// round.
//
// The gooey fusion is pure SwiftUI Canvas. GraphicsContext applies stacked
// filters in REVERSE of the order they are added: the last-added filter hits
// the content first. So adding `.alphaThreshold` first and `.blur` second
// means the circles are blurred first, then alpha-thresholded — overlapping
// blurred circles raise the local alpha above the threshold and weld into a
// single crisp-edged blob. Classic metaball compositing, no Metal shader.
// Canvas filters ship since iOS 15, so iOS 17 needs no availability guard.

struct FerrofluidDotsView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { proxy in
            FerrofluidDotsView_FerrofluidStage(demo: demo, size: proxy.size)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }
}

// MARK: - Stage

private struct FerrofluidDotsView_FerrofluidStage: View {
    let demo: Bool
    let size: CGSize

    // Far-off-rail rest position so every dot relaxes fully round when the
    // magnet is released (a finite on-rail value would leave the nearest dot
    // permanently swollen). Distance is huge → Gaussian influence ~0.
    private static let restX: CGFloat = -100_000

    // Interactive magnet position. `nil` == magnet released → relax to rest.
    @State private var dragMagnetX: CGFloat? = nil
    // Eased magnet used while interactive so release springs smoothly.
    @State private var relaxedMagnetX: CGFloat = FerrofluidDotsView_FerrofluidStage.restX

    private var dotCount: Int { 5 }

    var body: some View {
        ZStack {
            background
            content
        }
        .contentShape(Rectangle())
    }

    @ViewBuilder
    private var background: some View {
        // Tint #120e18 — the tile backdrop the liquid sits on.
        let bg = Color(red: 0.071, green: 0.055, blue: 0.094)
        RadialGradient(
            colors: [
                Color(red: 0.12, green: 0.10, blue: 0.17),
                bg
            ],
            center: .center,
            startRadius: 0,
            endRadius: max(size.width, size.height) * 0.75
        )
    }

    @ViewBuilder
    private var content: some View {
        if demo {
            demoCanvas
        } else {
            interactiveCanvas
        }
    }

    // MARK: Demo — self-driving sine sweep of a virtual magnet

    private var demoCanvas: some View {
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            let magnetX = sweptMagnetX(time: t)
            let pulse = demoPulse(time: t)
            metaballCanvas(magnetX: magnetX, pull: pulse)
        }
        // Demo tile must not eat ScrollView pans — it never needs touches.
        .allowsHitTesting(false)
    }

    /// Magnet x oscillating across the full dot rail on a ~2.4s loop.
    private func sweptMagnetX(time: Double) -> CGFloat {
        let inset = railInset(for: size)
        let lo = inset
        let hi = size.width - inset
        let period: Double = 2.4
        let phase = (time.truncatingRemainder(dividingBy: period)) / period
        // Smooth ease-in-out triangle so it dwells at the ends.
        let angle = phase * 2 * Double.pi - Double.pi / 2
        let s = (sin(angle) + 1) / 2
        return lo + (hi - lo) * CGFloat(s)
    }

    /// Breathe the pull strength a touch so merges feel alive, never frozen.
    private func demoPulse(time: Double) -> CGFloat {
        let v = (sin(time * 2.7) + 1) / 2
        return 0.82 + 0.18 * CGFloat(v)
    }

    // MARK: Interactive — drag a real magnet, release springs home

    private var interactiveCanvas: some View {
        metaballCanvas(magnetX: activeMagnetX, pull: 1.0)
            // Make the whole tile hittable so the drag wins inside a ScrollView.
            .contentShape(Rectangle())
            .gesture(dragGesture)
    }

    private var activeMagnetX: CGFloat {
        dragMagnetX ?? relaxedMagnetX
    }

    private var dragGesture: some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                let clamped = clampToRail(value.location.x)
                dragMagnetX = clamped
                relaxedMagnetX = clamped
            }
            .onEnded { _ in
                // Release: spring the magnet back to rest (off-rail), letting
                // the bridged dots un-fuse and snap round.
                dragMagnetX = nil
                withAnimation(.spring(response: 0.5, dampingFraction: 0.55)) {
                    relaxedMagnetX = restMagnetX
                }
            }
    }

    private func clampToRail(_ x: CGFloat) -> CGFloat {
        let inset = railInset(for: size)
        return min(max(x, inset), size.width - inset)
    }

    /// Rest position parks the magnet far off-rail so every dot sits round.
    private var restMagnetX: CGFloat { FerrofluidDotsView_FerrofluidStage.restX }

    // MARK: Canvas

    private func metaballCanvas(magnetX: CGFloat, pull: CGFloat) -> some View {
        let metrics = FerrofluidDotsView_FerroMetrics(size: size, dotCount: dotCount)
        let pts = centers(magnetX: magnetX, metrics: metrics, pull: pull)
        let rs = radii(magnetX: magnetX, metrics: metrics, pull: pull)
        return Canvas { context, _ in
            drawMetaball(in: context, centers: pts, radii: rs, metrics: metrics)
        }
    }

    private func drawMetaball(
        in context: GraphicsContext,
        centers: [CGPoint],
        radii: [CGFloat],
        metrics: FerrofluidDotsView_FerroMetrics
    ) {
        var ctx = context
        let liquid = Color(red: 0.45, green: 0.62, blue: 1.0)

        // Filter ADD order is reverse of APPLY order. Adding alphaThreshold
        // first and blur second means circles get blurred FIRST, then hard-cut
        // by the threshold — so overlapping soft edges weld into one crisp
        // blob. drawLayer is mandatory — the per-circle alphas must composite
        // inside an isolated layer to fuse.
        ctx.addFilter(.alphaThreshold(min: 0.5, color: liquid))
        ctx.addFilter(.blur(radius: metrics.blurRadius))

        ctx.drawLayer { layer in
            for (i, center) in centers.enumerated() where i < radii.count {
                let r = radii[i]
                let rect = CGRect(
                    x: center.x - r,
                    y: center.y - r,
                    width: r * 2,
                    height: r * 2
                )
                layer.fill(Path(ellipseIn: rect), with: .color(.white))
            }
        }

        drawSpecular(in: context, centers: centers, radii: radii)
    }

    /// A tiny bright highlight on each dot for the wet, mercury sheen. Drawn
    /// outside the threshold layer so it always reads, never disappears.
    private func drawSpecular(
        in context: GraphicsContext,
        centers: [CGPoint],
        radii: [CGFloat]
    ) {
        let sheen = Color(red: 0.85, green: 0.92, blue: 1.0)
        for (i, center) in centers.enumerated() where i < radii.count {
            let r = radii[i]
            let hr = r * 0.34
            let hx = center.x - r * 0.28
            let hy = center.y - r * 0.30
            let rect = CGRect(x: hx - hr, y: hy - hr, width: hr * 2, height: hr * 2)
            context.fill(
                Path(ellipseIn: rect),
                with: .color(sheen.opacity(0.5))
            )
        }
    }

    // MARK: Physics (pure)

    /// Dot centers eased toward the magnet by a distance falloff so the two
    /// nearest dots lunge together and bridge.
    private func centers(
        magnetX: CGFloat,
        metrics: FerrofluidDotsView_FerroMetrics,
        pull: CGFloat
    ) -> [CGPoint] {
        let cy = size.height / 2
        return (0..<metrics.dotCount).map { i in
            let restX = metrics.slotX(i)
            let dx = magnetX - restX
            // Gaussian-ish falloff: dots near the magnet pull hard, far ones
            // barely move.
            let influence = gaussian(distance: dx, sigma: metrics.sigma)
            let maxReach = metrics.spacing * 0.62
            let shift = clampSign(dx) * min(abs(dx), maxReach) * influence * pull
            return CGPoint(x: restX + shift, y: cy)
        }
    }

    /// A dot swells slightly as it nears the magnet (gathered liquid).
    private func radii(
        magnetX: CGFloat,
        metrics: FerrofluidDotsView_FerroMetrics,
        pull: CGFloat
    ) -> [CGFloat] {
        return (0..<metrics.dotCount).map { i in
            let restX = metrics.slotX(i)
            let dx = magnetX - restX
            let influence = gaussian(distance: dx, sigma: metrics.sigma)
            let swell = metrics.dotRadius * 0.32 * influence * pull
            return metrics.dotRadius + swell
        }
    }

    private func gaussian(distance: CGFloat, sigma: CGFloat) -> CGFloat {
        let denom = 2 * sigma * sigma
        guard denom > 0 else { return 0 }
        let exponent = -(distance * distance) / denom
        return CGFloat(exp(Double(exponent)))
    }

    private func clampSign(_ v: CGFloat) -> CGFloat {
        v == 0 ? 0 : (v > 0 ? 1 : -1)
    }

    private func railInset(for size: CGSize) -> CGFloat {
        FerrofluidDotsView_FerroMetrics(size: size, dotCount: dotCount).railInset
    }
}

// MARK: - Metrics

/// All size-relative geometry in one place so the dots, blur and rail scale
/// identically at a 120pt tile and a large detail area. Crucially the blur
/// radius is tied to dot radius so an *isolated* (un-merged) dot's peak alpha
/// stays above the threshold and never silently vanishes.
private struct FerrofluidDotsView_FerroMetrics {
    let size: CGSize
    let dotCount: Int

    /// Base dot radius, clamped so very small tiles stay legible.
    var dotRadius: CGFloat {
        let r = size.width * 0.045
        return min(max(r, 4.0), 22.0)
    }

    /// Blur kept modest relative to the dot so a lone dot still composites
    /// solidly past the 0.5 threshold. ~0.7× dotRadius is the sweet spot.
    var blurRadius: CGFloat {
        dotRadius * 0.7
    }

    /// Horizontal spacing between rail slots.
    var spacing: CGFloat {
        let usable = size.width - railInset * 2
        return dotCount > 1 ? usable / CGFloat(dotCount - 1) : 0
    }

    /// Falloff width of the magnet's influence.
    var sigma: CGFloat {
        max(spacing * 0.62, 1)
    }

    var railInset: CGFloat {
        max(size.width * 0.14, dotRadius * 1.6)
    }

    func slotX(_ i: Int) -> CGFloat {
        railInset + spacing * CGFloat(i)
    }
}
"""###,
        "ob-odometer-dots": ###"""
import SwiftUI

// MARK: - Odometer Steps
// A horizontal step counter whose current step is a mechanical split-flap tile
// that flips "01" -> "02" digit-by-digit, while surrounding dots slide along a
// rail and recolor. demo == true self-flips through the sequence on a loop;
// demo == false is driven by a horizontal swipe.
struct OdometerDotsView: View {
    var demo: Bool = false

    // Step model: indices 0...(stepCount-1). `position` is continuous so a value
    // like 1.7 means "70% through the flip from step 1 -> step 2". This single
    // source of truth feeds both the demo loop and the interactive drag.
    private let stepCount: Int = 5

    // Interactive state (only used when demo == false).
    @State private var committed: Double = 0          // last settled integer step
    @State private var dragPosition: Double = 0        // live position during/after drag

    var body: some View {
        GeometryReader { geo in
            content(in: geo.size)
                .frame(maxWidth: .infinity, maxHeight: .infinity)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    @ViewBuilder
    private func content(in size: CGSize) -> some View {
        if demo {
            TimelineView(.animation) { timeline in
                let pos = demoPosition(at: timeline.date)
                board(position: pos, size: size)
            }
        } else {
            board(position: dragPosition, size: size)
                .contentShape(Rectangle())
                .gesture(stepDrag(size: size))
        }
    }

    // MARK: - Demo loop driver

    // Advances one step per segment, always flipping FORWARD, and wraps the
    // last -> first as a forward flip ("05" -> "01"). `position` stays in
    // [0, stepCount); the displayed digit is modular so the wrap reads cleanly.
    private func demoPosition(at date: Date) -> Double {
        let flipDuration: Double = 0.62
        let holdDuration: Double = 0.55
        let segment = flipDuration + holdDuration
        let cycle = segment * Double(stepCount)            // full pass then wrap
        let t = date.timeIntervalSinceReferenceDate.truncatingRemainder(dividingBy: cycle)
        let index = Int(t / segment)                       // step we are leaving
        let local = t - Double(index) * segment
        let base = Double(index)
        if local <= flipDuration {
            let raw = local / flipDuration                 // 0...1 across the flip
            return base + easeInOut(raw)                   // forward into base+1
        }
        // Hold: if we just flipped off the last step, snap to 0; else hold base+1.
        return (index == stepCount - 1) ? 0 : base + 1
    }

    private func easeInOut(_ x: Double) -> Double {
        x < 0.5 ? 2 * x * x : 1 - pow(-2 * x + 2, 2) / 2
    }

    // MARK: - Interactive drag

    private func stepDrag(size: CGSize) -> some Gesture {
        let tileW = tileWidth(for: size)
        return DragGesture(minimumDistance: 0)
            .onChanged { value in
                // Drag left = advance; map translation to fractional steps.
                let delta = Double(-value.translation.width / max(tileW, 1))
                let proposed = committed + delta
                dragPosition = clampPosition(proposed)
            }
            .onEnded { value in
                let delta = Double(-value.translation.width / max(tileW, 1))
                let predicted = Double(-value.predictedEndTranslation.width / max(tileW, 1))
                let proposed = committed + delta
                let withFlick = committed + predicted
                // Commit to the next/prev step if past the half-tile threshold or flicked.
                var target = (proposed).rounded()
                if abs(withFlick - committed) > 0.45 {
                    target = (committed + (withFlick > committed ? 1 : -1)).rounded()
                }
                target = clampPosition(target).rounded()
                committed = target
                withAnimation(.spring(response: 0.55, dampingFraction: 0.7)) {
                    dragPosition = target
                }
            }
    }

    private func clampPosition(_ p: Double) -> Double {
        min(max(p, 0), Double(stepCount - 1))
    }

    // MARK: - Board layout

    @ViewBuilder
    private func board(position: Double, size: CGSize) -> some View {
        let tileH = tileHeight(for: size)
        VStack(spacing: tileH * 0.22) {
            splitFlapTile(position: position, size: size)
            dotsRail(position: position, size: size)
            label(position: position, size: size)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .padding(tileH * 0.18)
    }

    private func tileHeight(for size: CGSize) -> CGFloat {
        let byHeight = size.height * 0.46
        let byWidth = size.width * 0.40
        return max(28, min(byHeight, byWidth))
    }

    private func tileWidth(for size: CGSize) -> CGFloat {
        tileHeight(for: size) * 0.74
    }

    // MARK: - Split-flap tile

    @ViewBuilder
    private func splitFlapTile(position: Double, size: CGSize) -> some View {
        let tileH = tileHeight(for: size)
        let tileW = tileWidth(for: size)
        let fromIndex = Int(floor(position))
        let p = position - floor(position)            // 0...1 fractional flip
        // `to` is the digit appearing. When p == 0 there is no flip in progress.
        let toIndex = min(fromIndex + 1, stepCount)
        let fromDigit = stepLabel(for: fromIndex)
        let toDigit = stepLabel(for: toIndex)

        ZStack {
            // Back layers: always show a settled, legible half so the tile is
            // never blank on any frame. The top back layer shows the NEW digit
            // (revealed only after the front top flap falls away in the 1st
            // half); the bottom back layer shows the OLD digit until the landing
            // flap covers it in the 2nd half.
            VStack(spacing: 0) {
                staticHalf(digit: toDigit, edge: .top,
                           tileW: tileW, tileH: tileH)
                staticHalf(digit: fromDigit, edge: .bottom,
                           tileW: tileW, tileH: tileH)
            }
            // Falling front flaps that animate the mechanical flip.
            frontFlaps(p: p, fromDigit: fromDigit, toDigit: toDigit,
                       tileW: tileW, tileH: tileH)
            // Center seam line.
            Rectangle()
                .fill(Color(red: 0.05, green: 0.05, blue: 0.07))
                .frame(width: tileW, height: max(1, tileH * 0.012))
        }
        .frame(width: tileW, height: tileH)
        .shadow(color: Color.black.opacity(0.35), radius: tileH * 0.06, y: tileH * 0.04)
    }

    @ViewBuilder
    private func frontFlaps(p: CGFloat, fromDigit: String, toDigit: String,
                            tileW: CGFloat, tileH: CGFloat) -> some View {
        // Top flap: the old digit's TOP half rotates down and away (0 -> -90).
        let topAngle: Double = p < 0.5 ? Double(-90 * (p / 0.5)) : -90
        // Bottom flap: the new digit's BOTTOM half rises into place (90 -> 0)
        // with a slight overshoot into the seam for that mechanical snap.
        let bottomRaw: CGFloat = p < 0.5 ? 1 : (1 - (p - 0.5) / 0.5)   // 1 -> 0 in 2nd half
        let bottomAngle: Double = Double(90 * bottomRaw) + overshoot(p)

        // A VStack (not ZStack) so each flap occupies its true half: the top
        // flap sits in [0, tileH/2] and `anchor: .bottom` pivots exactly on the
        // seam; the bottom flap sits in [tileH/2, tileH] and `anchor: .top`
        // pivots on the seam — matching the back layers' VStack exactly.
        VStack(spacing: 0) {
            // Old top half falling away.
            halfFace(digit: fromDigit, edge: .top, tileW: tileW, tileH: tileH,
                     shade: 0.10 + 0.30 * min(1, CGFloat(-topAngle) / 90))
                .rotation3DEffect(.degrees(topAngle),
                                  axis: (x: 1, y: 0, z: 0),
                                  anchor: .bottom, perspective: 0.45)
                .opacity(p < 0.5 ? 1 : 0)

            // New bottom half snapping up.
            halfFace(digit: toDigit, edge: .bottom, tileW: tileW, tileH: tileH,
                     shade: 0.10 + 0.30 * min(1, bottomRaw))
                .rotation3DEffect(.degrees(bottomAngle),
                                  axis: (x: 1, y: 0, z: 0),
                                  anchor: .top, perspective: 0.45)
                .opacity(p < 0.5 ? 0 : 1)
        }
        .frame(width: tileW, height: tileH)
    }

    // A small spring-like overshoot as the bottom flap lands (only near p ~ 1).
    // `phase` is pinned to Double so the exp()/sin() calls below are unambiguous.
    private func overshoot(_ p: CGFloat) -> Double {
        guard p > 0.82 else { return 0 }
        let phase: Double = Double((p - 0.82) / 0.18)       // 0...1 over the landing
        let decay: Double = exp(-3.4 * phase)
        return -7 * decay * sin(phase * Double.pi * 2.2)    // tiny wobble past 0
    }

    // MARK: - Tile halves

    enum HalfEdge { case top, bottom }

    // A static (non-rotating) half used in the back layers.
    @ViewBuilder
    private func staticHalf(digit: String, edge: HalfEdge,
                            tileW: CGFloat, tileH: CGFloat) -> some View {
        halfFace(digit: digit, edge: edge, tileW: tileW, tileH: tileH,
                 shade: edge == .top ? 0.0 : 0.06)
    }

    // Renders one half of a tile: the full glyph is laid out at full tile height,
    // then clipped to the top or bottom half so the seam aligns perfectly.
    @ViewBuilder
    private func halfFace(digit: String, edge: HalfEdge,
                          tileW: CGFloat, tileH: CGFloat, shade: CGFloat) -> some View {
        let alignment: Alignment = edge == .top ? .top : .bottom
        let corners = roundedHalf(edge: edge, radius: tileH * 0.14)
        ZStack {
            corners
                .fill(tileGradient(shade: shade))
            digitText(digit, tileH: tileH)
                .frame(width: tileW, height: tileH)
                .frame(width: tileW, height: tileH / 2, alignment: alignment)
                .clipped()
        }
        .frame(width: tileW, height: tileH / 2)
        .clipShape(corners)
        .overlay(
            corners.stroke(Color(red: 0.0, green: 0.0, blue: 0.0).opacity(0.25),
                           lineWidth: 0.5)
        )
    }

    private func tileGradient(shade: CGFloat) -> LinearGradient {
        let base = 0.16
        return LinearGradient(
            colors: [
                Color(red: base + 0.05, green: base + 0.06, blue: base + 0.09),
                Color(red: max(0, base - Double(shade)),
                      green: max(0, base + 0.01 - Double(shade)),
                      blue: max(0, base + 0.04 - Double(shade)))
            ],
            startPoint: .top, endPoint: .bottom)
    }

    private func roundedHalf(edge: HalfEdge, radius: CGFloat) -> UnevenRoundedRectangle {
        switch edge {
        case .top:
            return UnevenRoundedRectangle(topLeadingRadius: radius,
                                          bottomLeadingRadius: 0,
                                          bottomTrailingRadius: 0,
                                          topTrailingRadius: radius)
        case .bottom:
            return UnevenRoundedRectangle(topLeadingRadius: 0,
                                          bottomLeadingRadius: radius,
                                          bottomTrailingRadius: radius,
                                          topTrailingRadius: 0)
        }
    }

    @ViewBuilder
    private func digitText(_ value: String, tileH: CGFloat) -> some View {
        Text(value)
            .font(.system(size: tileH * 0.62, weight: .bold, design: .rounded))
            .monospacedDigit()
            .foregroundStyle(
                LinearGradient(colors: [
                    Color(red: 0.98, green: 0.97, blue: 0.94),
                    Color(red: 0.82, green: 0.83, blue: 0.88)
                ], startPoint: .top, endPoint: .bottom)
            )
            .minimumScaleFactor(0.4)
            .lineLimit(1)
    }

    // MARK: - Dots rail

    @ViewBuilder
    private func dotsRail(position: Double, size: CGSize) -> some View {
        let tileH = tileHeight(for: size)
        let dot = max(6, tileH * 0.16)
        let spacing = dot * 1.6
        let active = position
        ZStack {
            Capsule()
                .fill(Color(red: 0.16, green: 0.15, blue: 0.20))
                .frame(height: max(3, dot * 0.42))
            HStack(spacing: spacing) {
                ForEach(0..<stepCount, id: \.self) { i in
                    dotView(index: i, active: active, dot: dot)
                }
            }
        }
        .frame(height: dot * 1.6)
        .frame(maxWidth: .infinity)
    }

    @ViewBuilder
    private func dotView(index i: Int, active: Double, dot: CGFloat) -> some View {
        let distance = abs(Double(i) - active)
        let nearness = max(0, 1 - distance)                // 1 at the active step
        let scale = 1.0 + 0.65 * nearness
        let on = Color(red: 0.55, green: 0.42, blue: 0.95)
        let fill = blendActive(t: CGFloat(nearness))
        Circle()
            .fill(fill)
            .frame(width: dot, height: dot)
            .scaleEffect(scale)
            .overlay(
                Circle()
                    .stroke(on.opacity(nearness), lineWidth: dot * 0.12)
                    .scaleEffect(scale + CGFloat(nearness) * 0.5)
                    .opacity(nearness * 0.6)
            )
            .shadow(color: on.opacity(nearness * 0.7),
                    radius: dot * 0.5 * CGFloat(nearness))
    }

    // Interpolates the dot fill between the inactive grey and the active violet
    // using known literal components (no UIColor round-trip, fully SwiftUI).
    private func blendActive(t: CGFloat) -> Color {
        let off: (Double, Double, Double) = (0.34, 0.33, 0.42)
        let on: (Double, Double, Double) = (0.55, 0.42, 0.95)
        let k = Double(min(max(t, 0), 1))
        return Color(red: off.0 + (on.0 - off.0) * k,
                     green: off.1 + (on.1 - off.1) * k,
                     blue: off.2 + (on.2 - off.2) * k)
    }

    // MARK: - Caption label

    @ViewBuilder
    private func label(position: Double, size: CGSize) -> some View {
        let tileH = tileHeight(for: size)
        // Modular so the wrap segment (position ~ stepCount) reads "1" not "6".
        let current = (Int(position.rounded()) % stepCount) + 1
        HStack(spacing: 4) {
            Text("STEP")
                .font(.system(size: tileH * 0.16, weight: .semibold, design: .rounded))
                .foregroundStyle(Color(red: 0.62, green: 0.60, blue: 0.70))
            Text("\(current)")
                .font(.system(size: tileH * 0.18, weight: .bold, design: .rounded))
                .foregroundStyle(Color(red: 0.86, green: 0.84, blue: 0.94))
                .contentTransition(.numericText())
                .animation(.easeInOut(duration: 0.3), value: current)
            Text("OF \(stepCount)")
                .font(.system(size: tileH * 0.16, weight: .semibold, design: .rounded))
                .foregroundStyle(Color(red: 0.62, green: 0.60, blue: 0.70))
        }
        .tracking(1.2)
        .minimumScaleFactor(0.5)
        .lineLimit(1)
    }

    // MARK: - Helpers

    // Two-digit zero-padded label for a step index (0 -> "01").
    private func stepLabel(for index: Int) -> String {
        let n = (index % stepCount) + 1
        return String(format: "%02d", n)
    }
}
"""###,
        "ob-origami-hero": ###"""
import SwiftUI

/// Origami Hero Unfold
///
/// A folded paper hero that unfolds crease-by-crease. A ring of triangular
/// petals all hinge around one shared center point (so creases never separate),
/// rotating from a collapsed, viewer-facing folded triangle (`fold == 1`) into a
/// fully spread, flat figure (`fold == 0`). Each petal carries a LinearGradient
/// fold-shadow whose opacity tracks its crease angle.
///
/// - `demo == true`  : self-driving breathing loop that gently folds / unfolds
///                     with a per-petal stagger so creases open in sequence.
/// - `demo == false` : a horizontal drag scrubs the master fold parameter; on
///                     release it snaps folded / unfolded and, when unfolded,
///                     swaps in the next figure (different petal count + palette).
struct OrigamiHeroView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { geo in
            let side: CGFloat = min(geo.size.width, geo.size.height)
            ZStack {
                paperBackground
                if demo {
                    demoContent(side: side)
                } else {
                    OrigamiHeroView_InteractiveOrigami(side: side)
                }
            }
            .frame(width: geo.size.width, height: geo.size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // MARK: Background

    private var paperBackground: some View {
        LinearGradient(
            colors: [
                Color(red: 0.07, green: 0.055, blue: 0.10),
                Color(red: 0.12, green: 0.10, blue: 0.16)
            ],
            startPoint: .top,
            endPoint: .bottom
        )
        .ignoresSafeArea()
    }

    // MARK: Demo (self-driving)

    private func demoContent(side: CGFloat) -> some View {
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            // ~3.4s breathing loop, eased so the holds at each extreme feel paper-like.
            let phase = (sin(t * (2.0 * .pi / 3.4)) + 1.0) / 2.0
            let eased = OrigamiHeroView_OrigamiMath.easeInOut(phase)
            // Demo also drifts the figure slowly so the hero looks varied over time.
            let figure = Int((t / 6.8).truncatingRemainder(dividingBy: 3.0))
            OrigamiHeroView_OrigamiFigure(fold: eased, figureIndex: figure, side: side, staggered: true)
        }
    }
}

// MARK: - Interactive wrapper

private struct OrigamiHeroView_InteractiveOrigami: View {
    let side: CGFloat

    @State private var fold: Double = 1.0          // start folded (triangle)
    @State private var dragStart: Double? = nil
    @State private var figureIndex: Int = 0

    var body: some View {
        OrigamiHeroView_OrigamiFigure(fold: fold, figureIndex: figureIndex, side: side, staggered: false)
            .contentShape(Rectangle())
            .gesture(dragGesture)
    }

    private var dragGesture: some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                if dragStart == nil { dragStart = fold }
                let base = dragStart ?? fold
                // Drag right → unfold (toward 0); drag left → fold (toward 1).
                let delta = -value.translation.width / max(side, 1.0)
                fold = OrigamiHeroView_OrigamiMath.clamp(base + delta, 0.0, 1.0)
            }
            .onEnded { value in
                let predicted = -value.predictedEndTranslation.width / max(side, 1.0)
                let base = dragStart ?? fold
                let projected = OrigamiHeroView_OrigamiMath.clamp(base + predicted, 0.0, 1.0)
                dragStart = nil
                let target: Double = projected < 0.5 ? 0.0 : 1.0
                // Key the swap on the fold value where this gesture *began*, so a
                // slow, deliberate unfold still advances to the next figure.
                let wasFolded = base > 0.5
                withAnimation(.spring(response: 0.55, dampingFraction: 0.74)) {
                    fold = target
                    // Committing to fully unfolded reveals the next figure.
                    if target == 0.0 && wasFolded {
                        figureIndex = (figureIndex + 1) % 3
                    }
                }
            }
    }
}

// MARK: - The figure (a ring of hinged petals + center medallion)

private struct OrigamiHeroView_OrigamiFigure: View {
    let fold: Double            // 1 = folded triangle, 0 = flat spread
    let figureIndex: Int
    let side: CGFloat
    let staggered: Bool

    private var config: OrigamiHeroView_FigureConfig { OrigamiHeroView_FigureConfig.all[figureIndex % OrigamiHeroView_FigureConfig.all.count] }

    var body: some View {
        let petalCount = config.petalCount
        ZStack {
            // Soft contact shadow on the "paper" beneath the spread figure.
            groundShadow

            ForEach(0..<petalCount, id: \.self) { index in
                petal(index: index, count: petalCount)
            }

            centerMedallion
        }
        .frame(width: side, height: side)
        // Slight overall lift toward the viewer when folded, like paper held up.
        .scaleEffect(1.0 - 0.06 * fold)
    }

    // MARK: Ground shadow

    private var groundShadow: some View {
        // Fades in as the figure spreads flat onto the page.
        Ellipse()
            .fill(Color.black.opacity(0.28 * (1.0 - fold)))
            .frame(width: side * 0.78, height: side * 0.30)
            .blur(radius: 18)
            .offset(y: side * 0.30)
    }

    // MARK: A single hinged petal

    @ViewBuilder
    private func petal(index: Int, count: Int) -> some View {
        let localFold = staggeredFold(index: index, count: count)
        // When spread, each petal points outward at its own angle (the flat figure).
        let spreadAngle: Double = (Double(index) / Double(count)) * 360.0 + config.spreadRotation
        // When folded, all petals collapse onto a single direction → triangle stack.
        let foldedAngle: Double = config.foldedRotation
        let planarAngle: Double = OrigamiHeroView_OrigamiMath.lerp(spreadAngle, foldedAngle, localFold)

        // The crease lift: petals tip up out of the page toward the viewer as they fold.
        let creaseAngle: Double = localFold * 74.0

        OrigamiHeroView_PetalShape()
            .fill(petalGradient(index: index, count: count))
            .overlay(foldShadowOverlay(localFold: localFold))
            .overlay(creaseHighlight(localFold: localFold))
            .frame(width: side * 0.5, height: side * 0.5)
            // Anchor the petal base at the shared center of the frame.
            .offset(x: 0, y: -side * 0.25)
            // Hinge the crease lift around the petal base (its bottom edge = center).
            .rotation3DEffect(
                .degrees(creaseAngle),
                axis: (x: 1.0, y: 0.0, z: 0.0),
                anchor: .bottom,
                perspective: 0.6
            )
            // Rotate the whole petal around the shared center so creases stay joined.
            .rotationEffect(.degrees(planarAngle), anchor: .center)
            .zIndex(localFold)   // folded petals sit forward
    }

    // Per-petal staggered unfolding for the demo's sequential crease feel.
    private func staggeredFold(index: Int, count: Int) -> Double {
        guard staggered else { return fold }
        let spread = 0.22
        let center = Double(index) / Double(max(count - 1, 1))
        // Shift each petal's effective fold slightly so creases open in order.
        let shifted = fold + (center - 0.5) * spread
        return OrigamiHeroView_OrigamiMath.clamp(shifted, 0.0, 1.0)
    }

    // MARK: Petal fills & shading

    private func petalGradient(index: Int, count: Int) -> LinearGradient {
        let pair = config.palette[index % config.palette.count]
        return LinearGradient(
            colors: [pair.0, pair.1],
            startPoint: .top,
            endPoint: .bottom
        )
    }

    // Darkening fold-shadow that deepens as the crease lifts (tracks localFold).
    private func foldShadowOverlay(localFold: Double) -> some View {
        OrigamiHeroView_PetalShape()
            .fill(
                LinearGradient(
                    colors: [
                        Color.black.opacity(0.0),
                        Color.black.opacity(0.45)
                    ],
                    startPoint: .top,
                    endPoint: .bottom
                )
            )
            .opacity(localFold)
    }

    // A thin lit edge along the crease to sell the paper fold.
    private func creaseHighlight(localFold: Double) -> some View {
        OrigamiHeroView_PetalShape()
            .stroke(
                Color(red: 1.0, green: 0.97, blue: 0.90).opacity(0.35 * localFold),
                lineWidth: 1.0
            )
    }

    // MARK: Center medallion

    private var centerMedallion: some View {
        let size = side * 0.16
        return Circle()
            .fill(
                RadialGradient(
                    colors: [config.coreInner, config.coreOuter],
                    center: .center,
                    startRadius: 0,
                    endRadius: size
                )
            )
            .frame(width: size, height: size)
            .overlay(
                Circle().stroke(Color.white.opacity(0.18), lineWidth: 1.0)
            )
            // Shrinks a touch when folded so the triangle silhouette reads cleanly.
            .scaleEffect(0.7 + 0.3 * (1.0 - fold))
            .shadow(color: .black.opacity(0.35 * (1.0 - fold)), radius: 6, y: 3)
    }
}

// MARK: - Petal shape (an isosceles triangle hinging on its base)

private struct OrigamiHeroView_PetalShape: Shape {
    func path(in rect: CGRect) -> Path {
        var p = Path()
        let tip = CGPoint(x: rect.midX, y: rect.minY)
        let baseLeft = CGPoint(x: rect.midX - rect.width * 0.32, y: rect.maxY)
        let baseRight = CGPoint(x: rect.midX + rect.width * 0.32, y: rect.maxY)
        p.move(to: tip)
        p.addLine(to: baseRight)
        p.addLine(to: baseLeft)
        p.closeSubpath()
        return p
    }
}

// MARK: - Figure configuration (cheap variants for "next shape")

private struct OrigamiHeroView_FigureConfig {
    let petalCount: Int
    let palette: [(Color, Color)]
    let coreInner: Color
    let coreOuter: Color
    let spreadRotation: Double
    let foldedRotation: Double

    static let all: [OrigamiHeroView_FigureConfig] = [
        // Figure 0 — warm lotus
        OrigamiHeroView_FigureConfig(
            petalCount: 6,
            palette: [
                (Color(red: 0.98, green: 0.55, blue: 0.42), Color(red: 0.85, green: 0.30, blue: 0.42)),
                (Color(red: 0.99, green: 0.72, blue: 0.46), Color(red: 0.90, green: 0.42, blue: 0.40))
            ],
            coreInner: Color(red: 1.0, green: 0.90, blue: 0.66),
            coreOuter: Color(red: 0.92, green: 0.50, blue: 0.36),
            spreadRotation: 0.0,
            foldedRotation: 18.0
        ),
        // Figure 1 — cool star
        OrigamiHeroView_FigureConfig(
            petalCount: 5,
            palette: [
                (Color(red: 0.52, green: 0.78, blue: 0.98), Color(red: 0.32, green: 0.46, blue: 0.86)),
                (Color(red: 0.66, green: 0.86, blue: 0.99), Color(red: 0.40, green: 0.58, blue: 0.92))
            ],
            coreInner: Color(red: 0.86, green: 0.95, blue: 1.0),
            coreOuter: Color(red: 0.40, green: 0.56, blue: 0.92),
            spreadRotation: -90.0,
            foldedRotation: -30.0
        ),
        // Figure 2 — verdant bloom
        OrigamiHeroView_FigureConfig(
            petalCount: 8,
            palette: [
                (Color(red: 0.62, green: 0.90, blue: 0.62), Color(red: 0.26, green: 0.66, blue: 0.50)),
                (Color(red: 0.78, green: 0.94, blue: 0.58), Color(red: 0.40, green: 0.74, blue: 0.46))
            ],
            coreInner: Color(red: 0.96, green: 1.0, blue: 0.82),
            coreOuter: Color(red: 0.34, green: 0.68, blue: 0.46),
            spreadRotation: 22.5,
            foldedRotation: 12.0
        )
    ]
}

// MARK: - Math helpers

private enum OrigamiHeroView_OrigamiMath {
    static func clamp(_ v: Double, _ lo: Double, _ hi: Double) -> Double {
        min(max(v, lo), hi)
    }

    static func lerp(_ a: Double, _ b: Double, _ t: Double) -> Double {
        a + (b - a) * t
    }

    static func easeInOut(_ t: Double) -> Double {
        // smootherstep, gives gentle holds at the extremes
        let x = clamp(t, 0.0, 1.0)
        return x * x * x * (x * (x * 6.0 - 15.0) + 10.0)
    }
}
"""###,
        "ob-paper-popup": ###"""
import SwiftUI

/// Pop-Up Book — flat shape-drawn scenery hinges upward off the center spine using
/// 3D rotation so the illustration physically pops up from the fold, while the
/// previous page folds back down.
///
/// - `demo == true`  → a self-driving TimelineView loop that turns pages on a timer.
/// - `demo == false` → an interactive horizontal drag that scrubs the page turn and
///   commits / springs back on release.
struct PaperPopupView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { geo in
            let size = geo.size
            ZStack {
                PaperPopupView_BookBackground()
                if demo {
                    PaperPopupView_DemoStage(size: size)
                } else {
                    PaperPopupView_InteractiveStage(size: size)
                }
            }
            .frame(width: size.width, height: size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }
}

// MARK: - Page model

/// A small palette describing one pop-up spread. Three distinct scenes so the
/// page-turn visibly swaps content.
private struct PaperPopupView_PopupScene {
    let sky: (Color, Color)
    let ground: Color
    let accent: Color
    let kind: PaperPopupView_SceneKind
}

private enum PaperPopupView_SceneKind {
    case meadow      // house + trees + sun
    case mountains   // peaks + moon
    case city        // skyline + stars
}

private enum PaperPopupView_PopupScenes {
    static let all: [PaperPopupView_PopupScene] = [
        PaperPopupView_PopupScene(
            sky: (Color(red: 0.42, green: 0.66, blue: 0.92),
                  Color(red: 0.83, green: 0.90, blue: 0.98)),
            ground: Color(red: 0.46, green: 0.72, blue: 0.42),
            accent: Color(red: 0.98, green: 0.82, blue: 0.32),
            kind: .meadow
        ),
        PaperPopupView_PopupScene(
            sky: (Color(red: 0.18, green: 0.22, blue: 0.40),
                  Color(red: 0.45, green: 0.40, blue: 0.62)),
            ground: Color(red: 0.34, green: 0.40, blue: 0.55),
            accent: Color(red: 0.95, green: 0.94, blue: 0.86),
            kind: .mountains
        ),
        PaperPopupView_PopupScene(
            sky: (Color(red: 0.10, green: 0.13, blue: 0.27),
                  Color(red: 0.30, green: 0.20, blue: 0.42)),
            ground: Color(red: 0.16, green: 0.18, blue: 0.30),
            accent: Color(red: 0.99, green: 0.74, blue: 0.42),
            kind: .city
        )
    ]

    static func scene(_ index: Int) -> PaperPopupView_PopupScene {
        all[((index % all.count) + all.count) % all.count]
    }
}

// MARK: - Persistent backdrop (never hinges, always legible)

private struct PaperPopupView_BookBackground: View {
    var body: some View {
        GeometryReader { geo in
            let w = geo.size.width
            let h = geo.size.height
            ZStack {
                LinearGradient(
                    colors: [Color(red: 0.20, green: 0.16, blue: 0.24),
                             Color(red: 0.09, green: 0.07, blue: 0.12)],
                    startPoint: .top, endPoint: .bottom
                )
                openBook(width: w, height: h)
            }
        }
        .allowsHitTesting(false)
    }

    /// The open book base spread: two warm paper pages meeting at a shadowed spine.
    private func openBook(width w: CGFloat, height h: CGFloat) -> some View {
        let pageTop = h * 0.18
        let pageH = h * 0.66
        let pageW = w * 0.88
        let x = (w - pageW) / 2
        return ZStack {
            RoundedRectangle(cornerRadius: h * 0.04, style: .continuous)
                .fill(
                    LinearGradient(
                        colors: [Color(red: 0.98, green: 0.96, blue: 0.90),
                                 Color(red: 0.92, green: 0.88, blue: 0.79)],
                        startPoint: .top, endPoint: .bottom
                    )
                )
                .frame(width: pageW, height: pageH)
                .position(x: w / 2, y: pageTop + pageH / 2)
                .shadow(color: .black.opacity(0.35), radius: h * 0.03, y: h * 0.012)

            // Spine shadow down the center fold.
            LinearGradient(
                colors: [Color.black.opacity(0.0),
                         Color.black.opacity(0.22),
                         Color.black.opacity(0.0)],
                startPoint: .leading, endPoint: .trailing
            )
            .frame(width: w * 0.10, height: pageH)
            .position(x: w / 2, y: pageTop + pageH / 2)
            .blur(radius: w * 0.012)

            // Page lines suggesting paper.
            ForEach(0..<2, id: \.self) { side in
                ruleLines(width: pageW / 2 - x * 0.4)
                    .frame(width: pageW / 2 - x * 0.4, height: pageH * 0.5)
                    .position(
                        x: side == 0 ? w * 0.30 : w * 0.70,
                        y: pageTop + pageH * 0.72
                    )
            }
        }
    }

    private func ruleLines(width: CGFloat) -> some View {
        VStack(alignment: .leading, spacing: 7) {
            ForEach(0..<4, id: \.self) { _ in
                Capsule()
                    .fill(Color(red: 0.62, green: 0.55, blue: 0.45).opacity(0.30))
                    .frame(height: 2)
            }
        }
    }
}

// MARK: - Angle mapping shared by both drivers

/// Maps a continuous turn progress `p` (0 = page settled flat & standing,
/// 1 = fully turned to the next page) to hinge angles for the incoming and
/// outgoing pop-up layers.
///
/// At rest the *current* scene stands up at 0° (facing the viewer). As the page
/// turns the current scene lays back toward -90° while the next scene rises from
/// 90° to 0°.
private func hingeAngles(for p: Double) -> (incoming: Double, outgoing: Double) {
    let clamped = min(max(p, 0), 1)
    let eased = smoothstep(clamped)
    let outgoing: Double = -90.0 * eased        // 0 → -90 (lays flat away)
    let incoming: Double = 90.0 * (1.0 - eased) // 90 → 0  (stands up)
    return (incoming, outgoing)
}

private func smoothstep(_ x: Double) -> Double {
    x * x * (3.0 - 2.0 * x)
}

// MARK: - Demo (self-driving)

private struct PaperPopupView_DemoStage: View {
    let size: CGSize
    private let period: Double = 3.4

    var body: some View {
        TimelineView(.animation) { context in
            let t = context.date.timeIntervalSinceReferenceDate
            let phase = t.truncatingRemainder(dividingBy: period) / period
            let pageIndex = Int(t / period)

            // Hold flat ~55% of the loop, turn the page over the remaining ~45%.
            let progress = turnProgress(phase)

            PaperPopupView_PopupSpread(
                size: size,
                progress: progress,
                outgoingIndex: pageIndex,
                incomingIndex: pageIndex + 1
            )
        }
    }

    private func turnProgress(_ phase: Double) -> Double {
        let hold = 0.55
        if phase < hold { return 0 }
        return (phase - hold) / (1.0 - hold)
    }
}

// MARK: - Interactive (drag-scrubbed)

private struct PaperPopupView_InteractiveStage: View {
    let size: CGSize

    @State private var pageIndex: Int = 0
    @State private var dragProgress: Double = 0   // live scrub 0…1
    @State private var settleProgress: Double = 0 // animated commit/return

    var body: some View {
        let active = max(dragProgress, settleProgress)
        PaperPopupView_PopupSpread(
            size: size,
            progress: active,
            outgoingIndex: pageIndex,
            incomingIndex: pageIndex + 1
        )
        .contentShape(Rectangle())
        .gesture(turnGesture)
    }

    private var turnGesture: some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                // Dragging left advances the page; clamp 0…1.
                let raw = -value.translation.width / max(size.width * 0.7, 1)
                dragProgress = min(max(raw, 0), 1)
            }
            .onEnded { value in
                let predicted = -value.predictedEndTranslation.width / max(size.width * 0.7, 1)
                let shouldCommit = dragProgress > 0.5 || predicted > 0.85
                if shouldCommit {
                    withAnimation(.spring(response: 0.55, dampingFraction: 0.72)) {
                        settleProgress = 1
                    }
                    // Advance after the fold completes, then reset the scrub state.
                    DispatchQueue.main.asyncAfter(deadline: .now() + 0.42) {
                        pageIndex += 1
                        dragProgress = 0
                        settleProgress = 0
                    }
                } else {
                    withAnimation(.spring(response: 0.5, dampingFraction: 0.7)) {
                        dragProgress = 0
                        settleProgress = 0
                    }
                }
            }
    }
}

// MARK: - The spread: two hinged scenery layers sharing the spine

private struct PaperPopupView_PopupSpread: View {
    let size: CGSize
    let progress: Double
    let outgoingIndex: Int
    let incomingIndex: Int

    var body: some View {
        let angles = hingeAngles(for: progress)
        // Spine line: the hinge sits a bit below center so scenery stands above it.
        let spineY = size.height * 0.74
        let stageH = size.height * 0.52
        let stageW = size.width * 0.80

        ZStack {
            // Outgoing scene — folds DOWN/back as the page turns.
            PaperPopupView_PopupLayer(
                scene: PaperPopupView_PopupScenes.scene(outgoingIndex),
                angle: angles.outgoing,
                stageW: stageW,
                stageH: stageH
            )
            .position(x: size.width / 2, y: spineY)
            .zIndex(zForAngle(angles.outgoing))

            // Incoming scene — stands UP from the fold to face the viewer.
            PaperPopupView_PopupLayer(
                scene: PaperPopupView_PopupScenes.scene(incomingIndex),
                angle: angles.incoming,
                stageW: stageW,
                stageH: stageH
            )
            .position(x: size.width / 2, y: spineY)
            .zIndex(zForAngle(angles.incoming))
        }
    }

    /// A layer that is more upright (angle nearer 0) should sit on top.
    private func zForAngle(_ angle: Double) -> Double {
        // 0° → high, ±90° → low.
        2.0 - abs(angle) / 90.0
    }
}

/// One scenery layer: its hinge edge coincides with the spread's spine, pivoting
/// about its bottom edge with perspective so it pops up off the page.
private struct PaperPopupView_PopupLayer: View {
    let scene: PaperPopupView_PopupScene
    let angle: Double
    let stageW: CGFloat
    let stageH: CGFloat

    var body: some View {
        PaperPopupView_SceneryArt(scene: scene, width: stageW, height: stageH)
            .frame(width: stageW, height: stageH)
            // Hinge about the bottom edge (the spine) with depth perspective.
            .rotation3DEffect(
                .degrees(angle),
                axis: (x: 1, y: 0, z: 0),
                anchor: .bottom,
                perspective: 0.62
            )
            // Bottom of art rests ON the spine line (.position centers it there).
            .offset(y: -stageH / 2)
            // Fold shadow deepens as the piece lays back; never fully hides art.
            .overlay {
                Color.black
                    .opacity(foldShade)
                    .blendMode(.multiply)
                    .allowsHitTesting(false)
            }
            .compositingGroup()
            .opacity(layerOpacity)
    }

    /// Darken as the piece rotates away from upright (depth shading).
    private var foldShade: Double {
        let t = abs(angle) / 90.0
        return 0.45 * t
    }

    /// Keep upright pieces fully visible; only the deeply-folded one dims a touch.
    private var layerOpacity: Double {
        let t = abs(angle) / 90.0
        return 1.0 - 0.25 * t
    }
}

// MARK: - Scenery art (bold silhouettes, readable at 120pt)

private struct PaperPopupView_SceneryArt: View {
    let scene: PaperPopupView_PopupScene
    let width: CGFloat
    let height: CGFloat

    var body: some View {
        ZStack(alignment: .bottom) {
            // Stand-up backdrop card (the "page" the scene is printed on).
            RoundedRectangle(cornerRadius: width * 0.05, style: .continuous)
                .fill(
                    LinearGradient(
                        colors: [scene.sky.0, scene.sky.1],
                        startPoint: .top, endPoint: .bottom
                    )
                )
                .frame(width: width, height: height)
                .overlay(
                    RoundedRectangle(cornerRadius: width * 0.05, style: .continuous)
                        .strokeBorder(Color.white.opacity(0.25), lineWidth: 1)
                )

            content
                .frame(width: width, height: height)
                .clipShape(RoundedRectangle(cornerRadius: width * 0.05, style: .continuous))

            // Tab/base strip at the hinge that reads as the folded mount.
            Rectangle()
                .fill(
                    LinearGradient(
                        colors: [Color(red: 0.97, green: 0.95, blue: 0.88),
                                 Color(red: 0.85, green: 0.80, blue: 0.70)],
                        startPoint: .top, endPoint: .bottom
                    )
                )
                .frame(width: width, height: height * 0.07)
        }
    }

    @ViewBuilder
    private var content: some View {
        switch scene.kind {
        case .meadow:    PaperPopupView_MeadowArt(scene: scene, w: width, h: height)
        case .mountains: PaperPopupView_MountainArt(scene: scene, w: width, h: height)
        case .city:      PaperPopupView_CityArt(scene: scene, w: width, h: height)
        }
    }
}

private struct PaperPopupView_MeadowArt: View {
    let scene: PaperPopupView_PopupScene
    let w: CGFloat
    let h: CGFloat

    var body: some View {
        ZStack {
            // Sun.
            Circle()
                .fill(scene.accent)
                .frame(width: w * 0.20, height: w * 0.20)
                .position(x: w * 0.76, y: h * 0.26)
                .shadow(color: scene.accent.opacity(0.6), radius: w * 0.04)

            // Rolling ground.
            PaperPopupView_HillShape()
                .fill(scene.ground)
                .frame(width: w, height: h * 0.5)
                .position(x: w / 2, y: h * 0.78)

            // House.
            PaperPopupView_HouseShape()
                .fill(Color(red: 0.86, green: 0.42, blue: 0.34))
                .frame(width: w * 0.28, height: h * 0.34)
                .position(x: w * 0.36, y: h * 0.64)

            // Trees.
            PaperPopupView_TreeShape()
                .fill(Color(red: 0.22, green: 0.50, blue: 0.30))
                .frame(width: w * 0.16, height: h * 0.30)
                .position(x: w * 0.66, y: h * 0.66)
            PaperPopupView_TreeShape()
                .fill(Color(red: 0.26, green: 0.56, blue: 0.34))
                .frame(width: w * 0.12, height: h * 0.22)
                .position(x: w * 0.80, y: h * 0.70)
        }
    }
}

private struct PaperPopupView_MountainArt: View {
    let scene: PaperPopupView_PopupScene
    let w: CGFloat
    let h: CGFloat

    var body: some View {
        ZStack {
            // Moon.
            Circle()
                .fill(scene.accent)
                .frame(width: w * 0.16, height: w * 0.16)
                .position(x: w * 0.74, y: h * 0.24)
                .shadow(color: scene.accent.opacity(0.5), radius: w * 0.05)

            // Back peaks.
            PaperPopupView_PeaksShape(peaks: 3, jitter: 0.0)
                .fill(scene.ground.opacity(0.7))
                .frame(width: w, height: h * 0.55)
                .position(x: w / 2, y: h * 0.74)

            // Front peaks (snow-capped).
            PaperPopupView_PeaksShape(peaks: 2, jitter: 0.12)
                .fill(Color(red: 0.26, green: 0.30, blue: 0.46))
                .frame(width: w, height: h * 0.42)
                .position(x: w / 2, y: h * 0.82)

            PaperPopupView_SnowCapsShape()
                .fill(Color.white.opacity(0.9))
                .frame(width: w, height: h * 0.42)
                .position(x: w / 2, y: h * 0.82)
        }
    }
}

private struct PaperPopupView_CityArt: View {
    let scene: PaperPopupView_PopupScene
    let w: CGFloat
    let h: CGFloat

    var body: some View {
        ZStack {
            // Stars.
            ForEach(0..<6, id: \.self) { i in
                Circle()
                    .fill(Color.white.opacity(0.85))
                    .frame(width: w * 0.018, height: w * 0.018)
                    .position(
                        x: w * (0.12 + 0.14 * CGFloat(i)),
                        y: h * (0.18 + 0.06 * CGFloat(i % 3))
                    )
            }
            // Crescent accent.
            Circle()
                .fill(scene.accent)
                .frame(width: w * 0.13, height: w * 0.13)
                .position(x: w * 0.80, y: h * 0.22)

            // Skyline.
            PaperPopupView_SkylineShape()
                .fill(
                    LinearGradient(
                        colors: [Color(red: 0.22, green: 0.24, blue: 0.40),
                                 Color(red: 0.12, green: 0.13, blue: 0.24)],
                        startPoint: .top, endPoint: .bottom
                    )
                )
                .frame(width: w, height: h * 0.55)
                .position(x: w / 2, y: h * 0.76)

            // Lit windows.
            PaperPopupView_WindowsShape()
                .fill(scene.accent.opacity(0.9))
                .frame(width: w, height: h * 0.55)
                .position(x: w / 2, y: h * 0.76)
        }
    }
}

// MARK: - Shapes

private struct PaperPopupView_HillShape: Shape {
    func path(in rect: CGRect) -> Path {
        var p = Path()
        p.move(to: CGPoint(x: rect.minX, y: rect.maxY))
        p.addLine(to: CGPoint(x: rect.minX, y: rect.midY))
        p.addQuadCurve(
            to: CGPoint(x: rect.maxX, y: rect.midY),
            control: CGPoint(x: rect.midX, y: rect.minY)
        )
        p.addLine(to: CGPoint(x: rect.maxX, y: rect.maxY))
        p.closeSubpath()
        return p
    }
}

private struct PaperPopupView_HouseShape: Shape {
    func path(in rect: CGRect) -> Path {
        var p = Path()
        let roofH = rect.height * 0.42
        let bodyTop = rect.minY + roofH
        // Roof.
        p.move(to: CGPoint(x: rect.midX, y: rect.minY))
        p.addLine(to: CGPoint(x: rect.maxX, y: bodyTop))
        p.addLine(to: CGPoint(x: rect.minX, y: bodyTop))
        p.closeSubpath()
        // Body.
        let bodyW = rect.width * 0.74
        let bx = rect.minX + (rect.width - bodyW) / 2
        p.addRect(CGRect(x: bx, y: bodyTop, width: bodyW, height: rect.maxY - bodyTop))
        return p
    }
}

private struct PaperPopupView_TreeShape: Shape {
    func path(in rect: CGRect) -> Path {
        var p = Path()
        // Trunk.
        let trunkW = rect.width * 0.18
        let trunkH = rect.height * 0.26
        p.addRect(CGRect(
            x: rect.midX - trunkW / 2,
            y: rect.maxY - trunkH,
            width: trunkW, height: trunkH
        ))
        // Three stacked canopy triangles, widening toward the base.
        let tiers = 3
        let canopyH = rect.height - trunkH
        for i in 0..<tiers {
            let f = CGFloat(i)
            let top: CGFloat = rect.minY + canopyH * (f / CGFloat(tiers)) * 0.8
            let bottom: CGFloat = rect.minY + canopyH * (f + 1.4) / CGFloat(tiers) * 0.8
            let tierW: CGFloat = rect.width * (0.42 + 0.18 * f)
            p.move(to: CGPoint(x: rect.midX, y: top))
            p.addLine(to: CGPoint(x: rect.midX + tierW / 2, y: bottom))
            p.addLine(to: CGPoint(x: rect.midX - tierW / 2, y: bottom))
            p.closeSubpath()
        }
        return p
    }
}

private struct PaperPopupView_PeaksShape: Shape {
    let peaks: Int
    let jitter: CGFloat

    func path(in rect: CGRect) -> Path {
        var p = Path()
        p.move(to: CGPoint(x: rect.minX, y: rect.maxY))
        let segment = rect.width / CGFloat(peaks)
        for i in 0..<peaks {
            let baseX = rect.minX + segment * CGFloat(i)
            let peakX = baseX + segment * (0.5 + jitter * (i.isMultiple(of: 2) ? 1 : -1))
            let peakY = rect.minY + rect.height * (0.05 + jitter)
            p.addLine(to: CGPoint(x: peakX, y: peakY))
            p.addLine(to: CGPoint(x: baseX + segment, y: rect.maxY))
        }
        p.addLine(to: CGPoint(x: rect.maxX, y: rect.maxY))
        p.closeSubpath()
        return p
    }
}

private struct PaperPopupView_SnowCapsShape: Shape {
    func path(in rect: CGRect) -> Path {
        var p = Path()
        let segment = rect.width / 2
        for i in 0..<2 {
            let baseX = rect.minX + segment * CGFloat(i)
            let peakX = baseX + segment * (0.5 + 0.12 * (i.isMultiple(of: 2) ? 1 : -1))
            let peakY = rect.minY + rect.height * 0.17
            let capH = rect.height * 0.16
            let leftX = peakX - segment * 0.16
            let rightX = peakX + segment * 0.16
            p.move(to: CGPoint(x: peakX, y: peakY))
            p.addLine(to: CGPoint(x: rightX, y: peakY + capH))
            p.addQuadCurve(
                to: CGPoint(x: leftX, y: peakY + capH),
                control: CGPoint(x: peakX, y: peakY + capH * 0.5)
            )
            p.closeSubpath()
        }
        return p
    }
}

private struct PaperPopupView_SkylineShape: Shape {
    func path(in rect: CGRect) -> Path {
        var p = Path()
        let heights: [CGFloat] = [0.45, 0.72, 0.55, 0.88, 0.62, 0.78, 0.5]
        let n = heights.count
        let bw = rect.width / CGFloat(n)
        p.move(to: CGPoint(x: rect.minX, y: rect.maxY))
        for i in 0..<n {
            let x0 = rect.minX + bw * CGFloat(i)
            let topY = rect.maxY - rect.height * heights[i]
            p.addLine(to: CGPoint(x: x0, y: topY))
            p.addLine(to: CGPoint(x: x0 + bw, y: topY))
        }
        p.addLine(to: CGPoint(x: rect.maxX, y: rect.maxY))
        p.closeSubpath()
        return p
    }
}

private struct PaperPopupView_WindowsShape: Shape {
    func path(in rect: CGRect) -> Path {
        var p = Path()
        let heights: [CGFloat] = [0.45, 0.72, 0.55, 0.88, 0.62, 0.78, 0.5]
        let n = heights.count
        let bw = rect.width / CGFloat(n)
        let win = bw * 0.18
        for i in 0..<n {
            let x0 = rect.minX + bw * CGFloat(i)
            let topY = rect.maxY - rect.height * heights[i]
            let rows = max(1, Int((rect.maxY - topY) / (win * 2.2)))
            for r in 0..<rows {
                for c in 0..<2 {
                    if (r + c + i).isMultiple(of: 2) { continue }
                    let wx = x0 + bw * (0.28 + 0.40 * CGFloat(c))
                    let wy = topY + win * 1.6 + CGFloat(r) * win * 2.2
                    if wy + win > rect.maxY { continue }
                    p.addRect(CGRect(x: wx, y: wy, width: win, height: win * 1.3))
                }
            }
        }
        return p
    }
}
"""###,
        "ob-paper-tear": ###"""
import SwiftUI

// MARK: - PaperTearView
// Page Tear Reveal — dragging from the page edge tears the current page away along a
// procedurally jagged ripped-paper edge that follows your finger, revealing the next
// page underneath with a soft torn-fiber shadow. Release past threshold flicks the torn
// piece off; otherwise the seam springs closed. The demo loop tears a page on a ~3s cycle.
struct PaperTearView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { geo in
            Group {
                if demo {
                    PaperTearView_DemoTear(size: geo.size)
                } else {
                    PaperTearView_InteractiveTear(size: geo.size)
                }
            }
            .frame(width: geo.size.width, height: geo.size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }
}

// MARK: - Demo (self-driving)
private struct PaperTearView_DemoTear: View {
    let size: CGSize

    var body: some View {
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            let cycle: Double = 3.4
            let phase = (t.truncatingRemainder(dividingBy: cycle)) / cycle // 0..1
            let progress = demoProgress(phase)
            let wobble = t * 1.6 // gentle ambient ripple

            PaperTearView_PaperTearCanvas(size: size, progress: progress, wobble: wobble, falling: 0)
        }
    }

    // Ramp up, hold open briefly, then reset quickly so a fresh page is always shown.
    private func demoProgress(_ phase: Double) -> CGFloat {
        let p: Double
        if phase < 0.62 {
            // ease-out tear from 0 -> 1
            let x = phase / 0.62
            p = 1 - pow(1 - x, 2.4)
        } else if phase < 0.78 {
            p = 1 // hold fully torn
        } else {
            // quick reset back to a fresh page
            let x = (phase - 0.78) / 0.22
            p = 1 - easeInOut(x)
        }
        return CGFloat(min(max(p, 0), 1))
    }

    private func easeInOut(_ x: Double) -> Double {
        x < 0.5 ? 2 * x * x : 1 - pow(-2 * x + 2, 2) / 2
    }
}

// MARK: - Interactive
private struct PaperTearView_InteractiveTear: View {
    let size: CGSize

    @State private var progress: CGFloat = 0
    @State private var dragStart: CGFloat = 0
    @State private var falling: CGFloat = 0   // 0 attached, 1 fully flicked away

    var body: some View {
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            PaperTearView_PaperTearCanvas(size: size,
                            progress: progress,
                            wobble: t * 1.4,
                            falling: falling)
        }
        .contentShape(Rectangle())
        .gesture(tearGesture)
    }

    private var tearGesture: some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                if falling > 0 { resetTorn() }
                let w = max(size.width, 1)
                let delta = value.translation.width / w
                let raw = dragStart + delta
                progress = clamp(raw)
            }
            .onEnded { value in
                let w = max(size.width, 1)
                let predicted = dragStart + value.predictedEndTranslation.width / w
                let committed = progress > 0.5 || predicted > 0.78
                if committed {
                    withAnimation(.spring(response: 0.4, dampingFraction: 0.72)) {
                        progress = 1
                    }
                    withAnimation(.spring(response: 0.55, dampingFraction: 0.6).delay(0.02)) {
                        falling = 1
                    }
                    // After the torn sheet falls away, present the fresh page beneath.
                    DispatchQueue.main.asyncAfter(deadline: .now() + 0.62) {
                        resetTorn()
                    }
                } else {
                    withAnimation(.spring(response: 0.45, dampingFraction: 0.7)) {
                        progress = 0
                    }
                    dragStart = 0
                }
            }
    }

    private func resetTorn() {
        progress = 0
        falling = 0
        dragStart = 0
    }

    private func clamp(_ v: CGFloat) -> CGFloat { min(max(v, 0), 1) }
}

// MARK: - Shared canvas renderer
// Composites: bottom (next) page full-frame, then the top (current) page clipped to the
// still-attached region, plus a torn-fiber shadow along the rip line. When `falling` > 0
// the torn-off sheet slides and rotates away to reveal the fresh page.
private struct PaperTearView_PaperTearCanvas: View {
    let size: CGSize
    let progress: CGFloat
    let wobble: Double
    let falling: CGFloat

    var body: some View {
        ZStack {
            bottomPage
            shadowBand
            topPageLayer
        }
        .clipped()
    }

    // The next page, sitting beneath — always fully visible where the top page is torn.
    private var bottomPage: some View {
        PaperTearView_PaperPage(palette: .next)
    }

    // Soft torn-fiber shadow cast by the lifting/attached edge onto the page below.
    private var shadowBand: some View {
        PaperTearView_TornEdgeShape(progress: progress, wobble: wobble, fiber: true)
            .stroke(
                LinearGradient(
                    colors: [
                        Color(red: 0.05, green: 0.04, blue: 0.09).opacity(0.0),
                        Color(red: 0.05, green: 0.04, blue: 0.09).opacity(0.55)
                    ],
                    startPoint: .leading, endPoint: .trailing
                ),
                style: StrokeStyle(lineWidth: max(size.width, size.height) * 0.018,
                                   lineCap: .round, lineJoin: .round)
            )
            .blur(radius: max(size.width, size.height) * 0.012)
            .offset(x: progress > 0 ? -size.width * 0.012 : 0)
            .opacity(progress > 0.001 && falling < 0.5 ? 1 : 0)
    }

    // The current page, clipped to the attached region (rip line -> right edge),
    // carrying the torn sheet off-screen when `falling` engages.
    private var topPageLayer: some View {
        PaperTearView_PaperPage(palette: .current)
            .overlay(tornFiberHighlight)
            .clipShape(PaperTearView_AttachedRegionShape(progress: progress, wobble: wobble))
            .offset(x: fallingOffsetX, y: fallingOffsetY)
            .rotationEffect(.degrees(Double(falling) * 7), anchor: .bottomTrailing)
            .opacity(1 - Double(falling) * 0.35)
    }

    // A thin lit rim drawn right along the rip so the edge reads as ragged fibers.
    private var tornFiberHighlight: some View {
        PaperTearView_TornEdgeShape(progress: progress, wobble: wobble, fiber: false)
            .stroke(
                Color(red: 0.99, green: 0.98, blue: 0.95).opacity(0.85),
                style: StrokeStyle(lineWidth: max(1.2, max(size.width, size.height) * 0.006),
                                   lineCap: .round, lineJoin: .round)
            )
            .opacity(progress > 0.001 ? 1 : 0)
    }

    private var fallingOffsetX: CGFloat { -size.width * 0.5 * falling }
    private var fallingOffsetY: CGFloat { size.height * 0.35 * falling }
}

// MARK: - Tear geometry
// The rip is a near-vertical jagged line whose x-position = split. The jitter is a PURE
// function of segment index (no RNG, no stored state) so the edge is byte-identical every
// frame — it ripples only via the smooth `wobble` parameter, never boils.
private struct PaperTearView_TornEdge {
    let segments = 26

    // Deterministic pseudo-random in [-1, 1] from an index — stable across all redraws.
    func jitter(_ i: Int) -> CGFloat {
        let s = sin(Double(i) * 12.9898 + 4.137) * 43758.5453
        let f = s - floor(s)            // fract -> [0,1)
        return CGFloat(f * 2 - 1)
    }

    func secondary(_ i: Int) -> CGFloat {
        let s = sin(Double(i) * 7.233 + 1.91) * 21943.21
        let f = s - floor(s)
        return CGFloat(f * 2 - 1)
    }

    // Build the rip line points down the page at split x for the given size.
    func points(in size: CGSize, progress: CGFloat, wobble: Double) -> [CGPoint] {
        let splitX = size.width * progress
        let amp = max(size.width, size.height) * 0.045   // scales with tile/detail
        let micro = amp * 0.4
        var pts: [CGPoint] = []
        for i in 0...segments {
            let ty = CGFloat(i) / CGFloat(segments)
            let y = ty * size.height
            // ambient ripple grows toward the free (top) end, fades at anchored ends
            let envelope = sin(ty * .pi)
            let ripple = sin(wobble + Double(i) * 0.7) * Double(amp) * 0.25 * Double(envelope)
            let jag = jitter(i) * amp + secondary(i) * micro
            let x = splitX + jag + CGFloat(ripple)
            pts.append(CGPoint(x: x, y: y))
        }
        return pts
    }
}

// MARK: - Attached region clip (top page keeps rip-line -> right edge)
private struct PaperTearView_AttachedRegionShape: Shape {
    var progress: CGFloat
    var wobble: Double
    private let edge = PaperTearView_TornEdge()

    var animatableData: CGFloat {
        get { progress }
        set { progress = newValue }
    }

    func path(in rect: CGRect) -> Path {
        var p = Path()
        let pts = edge.points(in: rect.size, progress: progress, wobble: wobble)
        guard let first = pts.first else { return p }
        p.move(to: first)
        for pt in pts.dropFirst() { p.addLine(to: pt) }
        // close along the right edge -> bottom-right -> top-right
        p.addLine(to: CGPoint(x: rect.maxX, y: rect.maxY))
        p.addLine(to: CGPoint(x: rect.maxX, y: rect.minY))
        p.closeSubpath()
        return p
    }
}

// MARK: - Rip line as a stroked Shape (used for shadow + fiber highlight)
private struct PaperTearView_TornEdgeShape: Shape {
    var progress: CGFloat
    var wobble: Double
    var fiber: Bool
    private let edge = PaperTearView_TornEdge()

    var animatableData: CGFloat {
        get { progress }
        set { progress = newValue }
    }

    func path(in rect: CGRect) -> Path {
        var p = Path()
        let pts = edge.points(in: rect.size, progress: progress, wobble: wobble)
        guard let first = pts.first else { return p }
        p.move(to: first)
        for pt in pts.dropFirst() { p.addLine(to: pt) }
        return p
    }
}

// MARK: - Drawn paper page (no assets)
private struct PaperTearView_PaperPage: View {
    enum Palette { case current, next }
    let palette: Palette

    var body: some View {
        ZStack {
            base
            ruledLines
            cornerLabel
        }
    }

    private var base: some View {
        LinearGradient(colors: gradientColors,
                       startPoint: .topLeading, endPoint: .bottomTrailing)
            .overlay(
                RadialGradient(colors: [Color.white.opacity(0.10), Color.clear],
                               center: .topLeading, startRadius: 0, endRadius: 260)
            )
    }

    // Faint notepad rules so it reads as a real sheet at any size.
    private var ruledLines: some View {
        GeometryReader { g in
            let count = 7
            let step = g.size.height / CGFloat(count + 1)
            Path { path in
                for i in 1...count {
                    let y = step * CGFloat(i)
                    path.move(to: CGPoint(x: g.size.width * 0.10, y: y))
                    path.addLine(to: CGPoint(x: g.size.width * 0.90, y: y))
                }
            }
            .stroke(lineColor, lineWidth: 1)
        }
        .allowsHitTesting(false)
    }

    private var cornerLabel: some View {
        GeometryReader { g in
            Circle()
                .fill(dotColor)
                .frame(width: g.size.width * 0.16, height: g.size.width * 0.16)
                .position(x: g.size.width * 0.22, y: g.size.height * 0.18)
                .opacity(0.9)
        }
        .allowsHitTesting(false)
    }

    private var gradientColors: [Color] {
        switch palette {
        case .current:
            return [Color(red: 0.97, green: 0.96, blue: 0.92),
                    Color(red: 0.91, green: 0.89, blue: 0.83)]
        case .next:
            return [Color(red: 0.16, green: 0.20, blue: 0.34),
                    Color(red: 0.09, green: 0.11, blue: 0.22)]
        }
    }

    private var lineColor: Color {
        switch palette {
        case .current: return Color(red: 0.55, green: 0.60, blue: 0.78).opacity(0.45)
        case .next:    return Color(red: 0.62, green: 0.72, blue: 1.0).opacity(0.28)
        }
    }

    private var dotColor: Color {
        switch palette {
        case .current: return Color(red: 0.92, green: 0.45, blue: 0.40)
        case .next:    return Color(red: 0.55, green: 0.84, blue: 0.92)
        }
    }
}
"""###,
        "ob-permission-bell": ###"""
import SwiftUI

/// Wake-the-Bell notification permission hero.
///
/// A dim, sleeping notification bell that wakes when you long-press "Allow":
/// it rocks harder and harder as you hold, sound-wave rings pulse outward, a red
/// badge pops in with a spring, and on release past the threshold it settles with
/// a happy nod. `demo == true` self-drives the full wake-and-ring cycle on a loop.
struct PermissionBellView: View {
    var demo: Bool = false

    // Interactive hold state. `progress` itself is always derived analytically
    // inside the TimelineView from these anchors, so there is never a blank frame.
    @State private var isPressing: Bool = false
    @State private var pressStart: Date = .distantPast
    @State private var releaseAt: Date = .distantPast
    @State private var releaseProgress: Double = 0
    @State private var didLock: Bool = false
    @State private var lockTick: Int = 0

    // Tunables (seconds).
    private let windUp: Double = 1.15          // hold time to reach full progress
    private let lockThreshold: Double = 0.72   // progress needed to lock on release
    private let releaseDecay: Double = 0.55    // calm-down duration after a short hold

    var body: some View {
        GeometryReader { geo in
            let side: CGFloat = min(geo.size.width, geo.size.height)
            TimelineView(.animation) { timeline in
                let t: Double = timeline.date.timeIntervalSinceReferenceDate
                let progress: Double = demo ? demoProgress(t) : livePressProgress(now: timeline.date)
                let locked: Bool = demo ? (demoProgress(t) > lockThreshold && demoRinging(t))
                                        : didLock
                stage(side: side, t: t, progress: progress, locked: locked)
            }
            .frame(maxWidth: .infinity, maxHeight: .infinity)
            .contentShape(Rectangle())
            .gesture(holdGesture, including: demo ? .none : .all)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        // Haptics only in the live, interactive component — never in a grid of demo tiles.
        .modifier(PermissionBellView_LockHaptic(tick: lockTick, enabled: !demo))
    }

    // MARK: - Composed stage

    @ViewBuilder
    private func stage(side: CGFloat, t: Double, progress: Double, locked: Bool) -> some View {
        let p: Double = clamp01(progress)
        // Bell rocks with an amplitude that ramps with progress. Frequency rises
        // a touch as it winds up so it visibly speeds toward ringing.
        let rockFreq: Double = 7.5 + p * 4.5
        let rockAmp: Double = 27.0 * easeOut(p)
        let rock: Double = sin(t * rockFreq) * rockAmp

        // A gentle "settle nod" near lock: a small extra eased tilt that decays.
        let nod: Double = locked ? sin(t * 9.0) * 3.0 * Double(1.0) : 0

        let bellAngle: Double = rock + nod
        let dim: Double = 0.46 + 0.54 * p        // never fully dark — always legible

        ZStack {
            backdrop(side: side, progress: p)

            PermissionBellView_SoundWaveRings(side: side, t: t, progress: p, active: p > 0.18)

            PermissionBellView_BellGlyph(side: side,
                      angle: bellAngle,
                      dim: dim,
                      glow: p)

            PermissionBellView_NotificationBadge(side: side, shown: locked, t: t)

            promptLabel(side: side, progress: p, locked: locked)
        }
        .frame(width: side, height: side)
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // Soft radial glow behind the bell that brightens as it wakes.
    private func backdrop(side: CGFloat, progress: Double) -> some View {
        let warm = Color(red: 1.0, green: 0.82, blue: 0.42)
        return RadialGradient(
            colors: [warm.opacity(0.28 * progress), .clear],
            center: .init(x: 0.5, y: 0.42),
            startRadius: 0,
            endRadius: side * 0.5
        )
        .frame(width: side, height: side)
        .allowsHitTesting(false)
    }

    @ViewBuilder
    private func promptLabel(side: CGFloat, progress: Double, locked: Bool) -> some View {
        let txt: String = locked ? "Notifications On" : (progress > 0.05 ? "Hold to wake…" : "Hold to Allow")
        let on = Color(red: 0.36, green: 0.85, blue: 0.62)
        let off = Color(red: 0.78, green: 0.80, blue: 0.86)
        Text(txt)
            .font(.system(size: max(9, side * 0.072), weight: .semibold, design: .rounded))
            .foregroundStyle(locked ? on : off)
            .lineLimit(1)
            .minimumScaleFactor(0.6)
            .padding(.horizontal, side * 0.05)
            .frame(width: side, alignment: .center)
            .offset(y: side * 0.40)
            .allowsHitTesting(false)
    }

    // MARK: - Gesture (interactive only)

    private var holdGesture: some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { _ in
                if !isPressing {
                    isPressing = true
                    pressStart = Date()
                    didLock = false
                }
            }
            .onEnded { _ in
                let held: Double = max(0, Date().timeIntervalSince(pressStart))
                let reached: Double = clamp01(held / windUp)
                isPressing = false
                if reached >= lockThreshold {
                    didLock = true
                    lockTick &+= 1
                } else {
                    didLock = false
                    releaseAt = Date()
                    releaseProgress = reached
                }
            }
    }

    // MARK: - Progress sources

    /// Live progress driven by *time held*, not drag distance.
    private func livePressProgress(now: Date) -> Double {
        if didLock { return 1.0 }
        if isPressing {
            let held: Double = max(0, now.timeIntervalSince(pressStart))
            return clamp01(held / windUp)
        }
        // Calming back down after a short hold.
        let since: Double = now.timeIntervalSince(releaseAt)
        if since < releaseDecay && releaseProgress > 0 {
            let k: Double = clamp01(since / releaseDecay)
            return releaseProgress * (1.0 - easeOut(k))
        }
        return 0
    }

    /// Self-driving envelope: sleep → wind-up rock → ring/lock → settle nod → reset.
    /// Loop length ~3.4s. Floored so the bell is never invisible.
    private func demoProgress(_ t: Double) -> Double {
        let loop: Double = 3.4
        let phase: Double = (t.truncatingRemainder(dividingBy: loop) + loop)
            .truncatingRemainder(dividingBy: loop)
        if phase < 0.45 {                       // resting / waking start
            return 0.05
        } else if phase < 1.7 {                 // winding up
            return easeInOut(clamp01((phase - 0.45) / 1.25))
        } else if phase < 2.65 {                // held at full, ringing
            return 1.0
        } else {                                // settle back to sleep
            return 1.0 - easeInOut(clamp01((phase - 2.65) / 0.75))
        }
    }

    private func demoRinging(_ t: Double) -> Bool {
        let loop: Double = 3.4
        let phase: Double = (t.truncatingRemainder(dividingBy: loop) + loop)
            .truncatingRemainder(dividingBy: loop)
        return phase >= 1.55 && phase < 2.65
    }

    // MARK: - Math helpers

    private func clamp01(_ v: Double) -> Double { min(1, max(0, v)) }
    private func easeOut(_ x: Double) -> Double { 1 - pow(1 - clamp01(x), 3) }
    private func easeInOut(_ x: Double) -> Double {
        let c = clamp01(x)
        return c < 0.5 ? 4 * c * c * c : 1 - pow(-2 * c + 2, 3) / 2
    }
}

// MARK: - Bell glyph

private struct PermissionBellView_BellGlyph: View {
    let side: CGFloat
    let angle: Double
    let dim: Double
    let glow: Double

    var body: some View {
        let bellSize: CGFloat = side * 0.46
        let warm = Color(red: 1.0, green: 0.80, blue: 0.36)
        // Direct RGB lerp from cool (sleeping) to warm (awake) by `glow`.
        // Both endpoints are literal constants, so no UIKit color round-trip is needed.
        let k: Double = min(1, max(0, glow))
        let tint = Color(red: 0.62 + (1.0 - 0.62) * k,
                         green: 0.66 + (0.80 - 0.66) * k,
                         blue: 0.78 + (0.36 - 0.78) * k)

        Image(systemName: "bell.fill")
            .resizable()
            .scaledToFit()
            .frame(width: bellSize, height: bellSize)
            .foregroundStyle(tint)
            .opacity(dim)
            .shadow(color: warm.opacity(0.55 * glow),
                    radius: side * 0.05 * CGFloat(glow))
            // Pivot from the crown so it swings like a hung bell.
            .rotationEffect(.degrees(angle), anchor: .top)
            .offset(y: -side * 0.04)
            .allowsHitTesting(false)
    }
}

// MARK: - Sound-wave rings

private struct PermissionBellView_SoundWaveRings: View {
    let side: CGFloat
    let t: Double
    let progress: Double
    let active: Bool

    var body: some View {
        let warm = Color(red: 1.0, green: 0.78, blue: 0.40)
        let count = 3
        let maxR: CGFloat = side * 0.42
        let speed: Double = 0.7 + progress * 0.8   // rings emit faster as it winds up

        ZStack {
            ForEach(0..<count, id: \.self) { i in
                let local = ringPhase(index: i, count: count, speed: speed)
                let radius: CGFloat = maxR * CGFloat(local) * CGFloat(0.4 + progress * 0.6)
                let opacity: Double = active ? (1.0 - local) * 0.7 * progress : 0
                Circle()
                    .stroke(warm.opacity(opacity),
                            lineWidth: max(1.2, side * 0.02 * CGFloat(1.0 - local)))
                    .frame(width: radius * 2, height: radius * 2)
            }
        }
        .offset(y: -side * 0.04)
        .allowsHitTesting(false)
    }

    private func ringPhase(index: Int, count: Int, speed: Double) -> Double {
        let raw = t * speed + Double(index) / Double(count)
        return raw.truncatingRemainder(dividingBy: 1.0)
    }
}

// MARK: - Notification badge

private struct PermissionBellView_NotificationBadge: View {
    let side: CGFloat
    let shown: Bool
    let t: Double

    var body: some View {
        let badgeSize: CGFloat = side * 0.16
        let red = Color(red: 0.96, green: 0.26, blue: 0.30)
        // Subtle breathing while present, so a locked tile still feels alive.
        let breathe: Double = shown ? 1.0 + sin(t * 4.0) * 0.04 : 0.0

        Circle()
            .fill(red)
            .overlay(
                Circle().stroke(Color.white.opacity(0.85), lineWidth: max(1, side * 0.012))
            )
            .frame(width: badgeSize, height: badgeSize)
            .shadow(color: red.opacity(0.6), radius: side * 0.03)
            .scaleEffect(CGFloat(breathe))
            // Spring pop on appear / collapse on disappear.
            .animation(.spring(response: 0.34, dampingFraction: 0.42), value: shown)
            .offset(x: side * 0.16, y: -side * 0.18)
            .allowsHitTesting(false)
    }
}

// MARK: - Haptic on lock (interactive only)

private struct PermissionBellView_LockHaptic: ViewModifier {
    let tick: Int
    let enabled: Bool

    func body(content: Content) -> some View {
        if enabled {
            content.sensoryFeedback(.success, trigger: tick)
        } else {
            content
        }
    }
}
"""###,
        "ob-radar-lock": ###"""
import SwiftUI

// MARK: - Radar Lock-On Permission
// A location-permission hero: a sweeping radar hunts a wandering blip, then on
// "grant" the reticle snaps inward to lock on, a pin bounces down, and a
// "located" ring ripples out. demo == true self-drives the full hunt→lock loop;
// demo == false locks on tap and replays.

struct RadarLockView: View {
    var demo: Bool = false

    // Frozen blip position captured at the moment of a real tap-grant.
    @State private var lockedBlip: CGPoint = .zero
    // Increments on each tap to re-fire the KeyframeAnimator lock choreography.
    @State private var tapCount: Int = 0
    // Drives the "located" / settled state after a real lock.
    @State private var hasLocked: Bool = false

    var body: some View {
        GeometryReader { geo in
            let size = geo.size
            if demo {
                demoRadar(in: size)
            } else {
                interactiveRadar(in: size)
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // MARK: Demo (self-driving, single TimelineView, single phase function)

    private func demoRadar(in size: CGSize) -> some View {
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            let s = RadarLockView_RadarState.demoState(at: t, size: size)
            RadarLockView_RadarSceneView(state: s, showLocatedLabel: s.lock.ring > 0.05)
        }
    }

    // MARK: Interactive (sweep on its own clock + KeyframeAnimator lock)

    private func interactiveRadar(in size: CGSize) -> some View {
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            let geom = RadarLockView_RadarGeometry(size: size)
            let sweepAngle = RadarLockView_RadarState.huntSweepAngle(at: t)
            let liveBlip = hasLocked ? lockedBlip
                                     : RadarLockView_RadarState.huntBlip(at: t, geom: geom)

            KeyframeAnimator(initialValue: RadarLockView_LockProgress(),
                             trigger: tapCount) { lock in
                let state = RadarLockView_RadarState(
                    sweepAngle: sweepAngle,
                    blip: hasLocked ? lockedBlip : liveBlip,
                    lock: lock,
                    geom: geom
                )
                RadarLockView_RadarSceneView(state: state, showLocatedLabel: lock.ring > 0.05)
            } keyframes: { _ in
                // Reticle snaps inward (overshoot then settle).
                KeyframeTrack(\.reticle) {
                    SpringKeyframe(1.0, duration: 0.45, spring: .bouncy)
                    LinearKeyframe(1.0, duration: 1.6)
                }
                // Pin bounces down shortly after the reticle bites.
                KeyframeTrack(\.pin) {
                    LinearKeyframe(0.0, duration: 0.30)
                    SpringKeyframe(1.0, duration: 0.55,
                                   spring: .init(duration: 0.55, bounce: 0.55))
                    LinearKeyframe(1.0, duration: 1.20)
                }
                // "Located" ring ripples out last and fades.
                KeyframeTrack(\.ring) {
                    LinearKeyframe(0.0, duration: 0.55)
                    CubicKeyframe(1.0, duration: 0.95)
                    LinearKeyframe(1.0, duration: 0.55)
                }
            }
        }
        .contentShape(Rectangle())
        .onTapGesture {
            captureAndLock(in: size)
        }
        .sensoryFeedback(.success, trigger: tapCount)
    }

    private func captureAndLock(in size: CGSize) {
        let geom = RadarLockView_RadarGeometry(size: size)
        let t = Date().timeIntervalSinceReferenceDate
        // Snapshot the blip's live position so lock elements don't drift.
        lockedBlip = RadarLockView_RadarState.huntBlip(at: t, geom: geom)
        hasLocked = true
        tapCount += 1
    }
}

// MARK: - Geometry

private struct RadarLockView_RadarGeometry {
    let center: CGPoint
    let radius: CGFloat

    init(size: CGSize) {
        center = CGPoint(x: size.width / 2, y: size.height / 2)
        radius = min(size.width, size.height) * 0.5 * 0.84
    }
}

// MARK: - Lock progress (multi-track animatable struct)

private struct RadarLockView_LockProgress: Equatable {
    var reticle: CGFloat = 0   // 0 = wide open / invisible, 1 = locked tight
    var pin: CGFloat = 0       // 0 = above, 1 = dropped & settled
    var ring: CGFloat = 0      // 0 = none, 1 = fully expanded & faded
}

// MARK: - Full radar state (pure value the renderer consumes)

private struct RadarLockView_RadarState {
    var sweepAngle: Double      // radians
    var blip: CGPoint           // absolute point
    var lock: RadarLockView_LockProgress
    var geom: RadarLockView_RadarGeometry

    // --- Hunt sub-functions (shared by demo & interactive) ---

    static func huntSweepAngle(at t: TimeInterval) -> Double {
        // Continuous clockwise sweep, ~1 rev / 2.6s.
        let rev = 2.6
        return (t.truncatingRemainder(dividingBy: rev) / rev) * 2 * .pi
    }

    static func huntBlip(at t: TimeInterval, geom: RadarLockView_RadarGeometry) -> CGPoint {
        // A wandering blip on two out-of-phase sines, kept inside the dish.
        let rx = geom.radius * 0.52
        let ry = geom.radius * 0.40
        let ax = sin(t * 0.62) * cos(t * 0.27)
        let ay = sin(t * 0.48 + 1.3)
        let x = geom.center.x + CGFloat(ax) * rx
        let y = geom.center.y + CGFloat(ay) * ry
        return CGPoint(x: x, y: y)
    }

    // --- Demo state: single phase function over a ~3.4s loop ---

    static func demoState(at t: TimeInterval, size: CGSize) -> RadarLockView_RadarState {
        let geom = RadarLockView_RadarGeometry(size: size)
        let period = 3.4
        let p = t.truncatingRemainder(dividingBy: period) / period // 0..1
        let huntEnd = 0.46

        let sweep = huntSweepAngle(at: t)

        if p < huntEnd {
            // Hunting: blip wanders, no lock elements.
            let blip = huntBlip(at: t, geom: geom)
            return RadarLockView_RadarState(sweepAngle: sweep, blip: blip,
                              lock: RadarLockView_LockProgress(), geom: geom)
        }

        // Lock window: freeze the blip at the moment hunting ended.
        let freezeT = t - (p - huntEnd) * period
        let frozenBlip = huntBlip(at: freezeT, geom: geom)

        // Local progress through the lock window.
        let lp = (p - huntEnd) / (1.0 - huntEnd) // 0..1

        var lock = RadarLockView_LockProgress()
        lock.reticle = bouncyRamp(lp, start: 0.00, end: 0.34)
        lock.pin     = bouncyRamp(lp, start: 0.22, end: 0.62)
        lock.ring    = smoothRamp(lp, start: 0.46, end: 1.00)

        return RadarLockView_RadarState(sweepAngle: sweep, blip: frozenBlip,
                          lock: lock, geom: geom)
    }

    // Eased ramp with a slight overshoot, clamped, for snap-in feel.
    static func bouncyRamp(_ x: CGFloat, start: CGFloat, end: CGFloat) -> CGFloat {
        let u = clamped((x - start) / max(end - start, 0.0001))
        let eased = 1 - pow(1 - u, 3)
        let overshoot = sin(u * .pi) * 0.10 * (1 - u)
        return min(1.0, eased + overshoot)
    }

    static func smoothRamp(_ x: CGFloat, start: CGFloat, end: CGFloat) -> CGFloat {
        let u = clamped((x - start) / max(end - start, 0.0001))
        return u * u * (3 - 2 * u) // smoothstep
    }

    static func clamped(_ v: CGFloat) -> CGFloat { min(1, max(0, v)) }
}

// MARK: - Scene renderer (the single shared view)

private struct RadarLockView_RadarSceneView: View {
    let state: RadarLockView_RadarState
    var showLocatedLabel: Bool

    private var palette: RadarLockView_RadarPalette { RadarLockView_RadarPalette() }

    var body: some View {
        ZStack {
            background
            sweepAndDish
            blipDot
            reticle
            locatedRing
            pin
            label
        }
    }

    // Background gradient fill behind the dish.
    private var background: some View {
        RadialGradient(
            colors: [palette.bgInner, palette.bgOuter],
            center: .center,
            startRadius: 0,
            endRadius: state.geom.radius * 1.4
        )
    }

    // Canvas: concentric rings, cross-hair grid, sweep wedge + arm.
    private var sweepAndDish: some View {
        Canvas { ctx, _ in
            drawDish(in: &ctx)
            drawSweep(in: &ctx)
        }
        .allowsHitTesting(false)
    }

    private func drawDish(in ctx: inout GraphicsContext) {
        let c = state.geom.center
        let r = state.geom.radius

        // Concentric rings.
        for i in 1...4 {
            let rr = r * CGFloat(i) / 4.0
            let rect = CGRect(x: c.x - rr, y: c.y - rr, width: rr * 2, height: rr * 2)
            ctx.stroke(
                Circle().path(in: rect),
                with: .color(palette.grid.opacity(i == 4 ? 0.55 : 0.30)),
                lineWidth: i == 4 ? 1.6 : 0.9
            )
        }

        // Cross-hair grid lines.
        var cross = Path()
        cross.move(to: CGPoint(x: c.x - r, y: c.y))
        cross.addLine(to: CGPoint(x: c.x + r, y: c.y))
        cross.move(to: CGPoint(x: c.x, y: c.y - r))
        cross.addLine(to: CGPoint(x: c.x, y: c.y + r))
        ctx.stroke(cross, with: .color(palette.grid.opacity(0.22)), lineWidth: 0.8)
    }

    private func drawSweep(in ctx: inout GraphicsContext) {
        let c = state.geom.center
        let r = state.geom.radius
        let angle = state.sweepAngle

        // Trailing wedge: a cheap filled fan tapering in opacity behind the arm.
        let wedgeSpan = Double.pi * 0.42
        let steps = 9
        for i in 0..<steps {
            let f0 = Double(i) / Double(steps)
            let f1 = Double(i + 1) / Double(steps)
            let a0 = angle - wedgeSpan * f0
            let a1 = angle - wedgeSpan * f1
            var seg = Path()
            seg.move(to: c)
            seg.addLine(to: point(c, r, a0))
            seg.addLine(to: point(c, r, a1))
            seg.closeSubpath()
            let op = (1.0 - f0) * 0.22
            ctx.fill(seg, with: .color(palette.sweep.opacity(op)))
        }

        // Leading arm.
        var arm = Path()
        arm.move(to: c)
        arm.addLine(to: point(c, r, angle))
        ctx.stroke(arm, with: .color(palette.sweep.opacity(0.95)), lineWidth: 2.0)

        // Hub.
        let hubR = r * 0.045
        let hub = CGRect(x: c.x - hubR, y: c.y - hubR, width: hubR * 2, height: hubR * 2)
        ctx.fill(Circle().path(in: hub), with: .color(palette.sweep.opacity(0.9)))
    }

    private func point(_ c: CGPoint, _ r: CGFloat, _ a: Double) -> CGPoint {
        CGPoint(x: c.x + r * CGFloat(cos(a)), y: c.y + r * CGFloat(sin(a)))
    }

    // The wandering / locked blip.
    private var blipDot: some View {
        let r = state.geom.radius
        let baseR = r * 0.05
        // Blip dims a touch once the reticle bites (it's "caught").
        let glow = 1.0 - state.lock.reticle * 0.25
        return Circle()
            .fill(palette.blip)
            .frame(width: baseR * 2, height: baseR * 2)
            .shadow(color: palette.blip.opacity(0.8 * glow), radius: baseR * 1.2)
            .position(state.blip)
            .opacity(0.85 + 0.15 * glow)
    }

    // Reticle: four corner brackets that snap inward onto the blip.
    private var reticle: some View {
        let p = state.lock.reticle
        let r = state.geom.radius
        // Wide when open, tight when locked.
        let span = r * (0.42 - 0.30 * p)
        let opacity = min(1.0, p * 1.6)
        return RadarLockView_ReticleShape(span: span)
            .stroke(palette.reticle.opacity(opacity),
                    style: StrokeStyle(lineWidth: 2.0, lineCap: .round))
            .frame(width: span * 2, height: span * 2)
            .rotationEffect(.degrees(Double((1 - p) * 35)))
            .position(state.blip)
    }

    // "Located" ring ripple expanding out from the lock point.
    private var locatedRing: some View {
        let p = state.lock.ring
        let r = state.geom.radius
        let maxR = r * 0.95
        let cur = r * 0.10 + maxR * p
        let opacity = max(0.0, (1.0 - p)) * 0.9
        return Circle()
            .stroke(palette.ring.opacity(opacity),
                    style: StrokeStyle(lineWidth: 2.5))
            .frame(width: cur * 2, height: cur * 2)
            .position(state.blip)
            .opacity(p > 0.001 ? 1 : 0)
    }

    // Pin that bounces down onto the lock point.
    private var pin: some View {
        let p = state.lock.pin
        let r = state.geom.radius
        let pinH = r * 0.34
        // Rises from above and settles at the blip.
        let dropY = -pinH * 1.6 * (1 - p)
        let opacity = min(1.0, p * 2.2)
        let anchor = CGPoint(x: state.blip.x, y: state.blip.y + dropY)
        return RadarLockView_PinShape()
            .fill(palette.pin)
            .frame(width: pinH * 0.62, height: pinH)
            // Anchor the tip at the bottom of the frame onto the point.
            .offset(y: -pinH / 2)
            .shadow(color: .black.opacity(0.35 * Double(p)), radius: r * 0.03, y: r * 0.02)
            .scaleEffect(0.85 + 0.15 * p)
            .position(anchor)
            .opacity(opacity)
    }

    @ViewBuilder
    private var label: some View {
        if showLocatedLabel {
            VStack {
                Spacer()
                Text("LOCATED")
                    .font(.system(size: max(10, state.geom.radius * 0.14),
                                  weight: .bold, design: .rounded))
                    .tracking(2)
                    .foregroundStyle(palette.ring)
                    .padding(.bottom, state.geom.radius * 0.06)
            }
            .allowsHitTesting(false)
            .transition(.opacity)
        }
    }
}

// MARK: - Shapes

private struct RadarLockView_ReticleShape: Shape {
    var span: CGFloat
    func path(in rect: CGRect) -> Path {
        var path = Path()
        let c = CGPoint(x: rect.midX, y: rect.midY)
        let s = span
        let arm = s * 0.45 // length of each corner bracket arm
        let corners: [(CGFloat, CGFloat)] = [(-1, -1), (1, -1), (1, 1), (-1, 1)]
        for (sx, sy) in corners {
            let cx = c.x + sx * s
            let cy = c.y + sy * s
            path.move(to: CGPoint(x: cx - sx * arm, y: cy))
            path.addLine(to: CGPoint(x: cx, y: cy))
            path.addLine(to: CGPoint(x: cx, y: cy - sy * arm))
        }
        return path
    }
}

// A classic map pin: round head + tapered tail, tip at the bottom center.
private struct RadarLockView_PinShape: Shape {
    func path(in rect: CGRect) -> Path {
        var path = Path()
        let w = rect.width
        let h = rect.height
        let headR = w * 0.5
        let headC = CGPoint(x: rect.midX, y: rect.minY + headR)

        // Head circle.
        path.addEllipse(in: CGRect(x: headC.x - headR, y: rect.minY,
                                   width: headR * 2, height: headR * 2))
        // Tail to the tip.
        let tip = CGPoint(x: rect.midX, y: rect.maxY)
        path.move(to: CGPoint(x: headC.x - headR * 0.78, y: headC.y + headR * 0.55))
        path.addQuadCurve(to: tip,
                          control: CGPoint(x: headC.x - headR * 0.30, y: h * 0.78))
        path.addLine(to: tip)
        path.addQuadCurve(to: CGPoint(x: headC.x + headR * 0.78, y: headC.y + headR * 0.55),
                          control: CGPoint(x: headC.x + headR * 0.30, y: h * 0.78))
        path.closeSubpath()
        return path
    }
}

// MARK: - Palette

private struct RadarLockView_RadarPalette {
    let bgInner = Color(red: 0.07, green: 0.16, blue: 0.13)
    let bgOuter = Color(red: 0.03, green: 0.06, blue: 0.07)
    let grid    = Color(red: 0.35, green: 0.95, blue: 0.65)
    let sweep   = Color(red: 0.40, green: 1.00, blue: 0.70)
    let blip    = Color(red: 0.55, green: 1.00, blue: 0.78)
    let reticle = Color(red: 1.00, green: 0.92, blue: 0.45)
    let ring    = Color(red: 0.55, green: 0.95, blue: 1.00)
    let pin     = Color(red: 1.00, green: 0.40, blue: 0.42)
}
"""###,
        "ob-symbol-assembly": ###"""
import SwiftUI

// MARK: - Symbol Assembly Hero
//
// A scattered cloud of small particles flies in and locks together into a
// crisp SF Symbol, settling with a bounce. Swiping (interactive) explodes the
// symbol back into particles that re-converge into the next symbol; idle, it
// auto-cycles through the symbol set on a loop.
//
// Two modes:
//   demo == true  -> self-driving TimelineView loop (assemble -> hold -> explode -> next)
//   demo == false -> interactive DragGesture(minimumDistance: 0) scrubs the
//                     scatter; releasing past threshold advances/reverts the symbol.
//
// Design notes (the traps that sink this exact animation):
//   * Every particle's scatter origin + target offset + stagger is a DETERMINISTIC
//     function of its index. Nothing is randomized inside the Canvas/Timeline body,
//     so the swarm stays a coherent shape instead of shimmering static.
//   * Targets are sampled around the glyph's bounding region (NOT pixel-sampled),
//     and the real SF Symbol Image crossfades on top to sell the shape.
//   * SymbolAssemblyView_Particle opacity is decoupled from the symbol fade, so the mid-explode frame
//     (where both symbol images are near-zero) still shows a legible swarm.

struct SymbolAssemblyView: View {
    var demo: Bool = false

    // Symbols guaranteed available on iOS 17.
    private let symbols: [SymbolAssemblyView_SymbolStyle] = [
        SymbolAssemblyView_SymbolStyle(name: "sparkles",
                    color: Color(red: 0.62, green: 0.51, blue: 0.98)),
        SymbolAssemblyView_SymbolStyle(name: "heart.fill",
                    color: Color(red: 0.98, green: 0.44, blue: 0.55)),
        SymbolAssemblyView_SymbolStyle(name: "bolt.fill",
                    color: Color(red: 0.99, green: 0.79, blue: 0.36)),
        SymbolAssemblyView_SymbolStyle(name: "leaf.fill",
                    color: Color(red: 0.44, green: 0.84, blue: 0.60)),
        SymbolAssemblyView_SymbolStyle(name: "star.fill",
                    color: Color(red: 0.40, green: 0.74, blue: 0.99))
    ]

    private let particleCount: Int = 54

    var body: some View {
        GeometryReader { proxy in
            let size = proxy.size
            content(in: size)
                .frame(width: size.width, height: size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .background(backgroundFill)
    }

    @ViewBuilder
    private func content(in size: CGSize) -> some View {
        if demo {
            SymbolAssemblyView_DemoStage(symbols: symbols,
                      particleCount: particleCount,
                      size: size)
        } else {
            SymbolAssemblyView_InteractiveStage(symbols: symbols,
                             particleCount: particleCount,
                             size: size)
        }
    }

    private var backgroundFill: some View {
        RadialGradient(
            colors: [
                Color(red: 0.10, green: 0.07, blue: 0.13),
                Color(red: 0.05, green: 0.04, blue: 0.08)
            ],
            center: .center,
            startRadius: 4,
            endRadius: 260
        )
    }
}

// MARK: - Symbol descriptor

private struct SymbolAssemblyView_SymbolStyle {
    let name: String
    let color: Color
}

// MARK: - SymbolAssemblyView_Particle model (fully deterministic per index)

private struct SymbolAssemblyView_Particle {
    /// Direction (unit-ish) the particle scatters toward, as a fraction of the radius.
    let scatter: CGPoint
    /// Target offset from center as a fraction of the glyph radius.
    let target: CGPoint
    /// Per-particle dot radius as a fraction of min dimension.
    let dotScale: CGFloat
    /// Stagger 0..1 — later particles arrive later.
    let delay: CGFloat
    /// Subtle hue shift so the swarm isn't monotone.
    let tint: CGFloat
}

/// Builds the particle set ONCE from the index. No per-frame randomness:
/// a cheap integer hash gives stable pseudo-random values per index.
private func makeParticles(count: Int) -> [SymbolAssemblyView_Particle] {
    (0..<count).map { i in
        let a = hashUnit(i &* 2 &+ 1)          // scatter angle seed
        let b = hashUnit(i &* 7 &+ 13)         // scatter distance seed
        let c = hashUnit(i &* 3 &+ 5)          // target angle seed
        let d = hashUnit(i &* 11 &+ 17)        // target radial seed
        let e = hashUnit(i &* 5 &+ 23)         // dot size seed
        let f = hashUnit(i &* 13 &+ 31)        // tint seed

        // Scatter: spread across a wide ring well outside the glyph.
        let scatterAngle = a * 2.0 * Double.pi
        let scatterDist  = 1.55 + b * 1.05      // 1.55x .. 2.6x of glyph radius
        let scatter = CGPoint(
            x: CGFloat(cos(scatterAngle) * scatterDist),
            y: CGFloat(sin(scatterAngle) * scatterDist)
        )

        // Target: a filled-disk distribution (sqrt for even area coverage)
        // biased slightly outward so the swarm reads as the glyph's silhouette.
        let targetAngle = c * 2.0 * Double.pi
        let targetRad   = (0.18 + sqrt(d) * 0.82)   // 0.18 .. 1.0 of glyph radius
        let target = CGPoint(
            x: CGFloat(cos(targetAngle) * targetRad),
            y: CGFloat(sin(targetAngle) * targetRad)
        )

        return SymbolAssemblyView_Particle(
            scatter: scatter,
            target: target,
            dotScale: CGFloat(0.014 + e * 0.020),
            delay: CGFloat(b * 0.45),               // staggered arrival
            tint: CGFloat(f)
        )
    }
}

/// Deterministic 0..1 pseudo-random from an integer (Wang-style mix).
private func hashUnit(_ value: Int) -> Double {
    var x = UInt64(bitPattern: Int64(value)) &+ 0x9E3779B97F4A7C15
    x = (x ^ (x >> 30)) &* 0xBF58476D1CE4E5B9
    x = (x ^ (x >> 27)) &* 0x94D049BB133111EB
    x = x ^ (x >> 31)
    return Double(x % 1_000_000) / 1_000_000.0
}

// MARK: - SymbolAssemblyView_Resolved particle position / appearance (kept OUT of body)

private struct SymbolAssemblyView_Resolved {
    let position: CGPoint
    let radius: CGFloat
    let opacity: Double
}

/// progress: 0 = fully scattered, 1 = fully assembled (locked into glyph).
private func resolve(_ p: SymbolAssemblyView_Particle,
                     progress: CGFloat,
                     center: CGPoint,
                     glyphRadius: CGFloat,
                     minDim: CGFloat) -> SymbolAssemblyView_Resolved {
    // Per-particle eased local progress with stagger so they don't arrive in lockstep.
    let span: CGFloat = 1.0 - p.delay
    let raw = (progress - p.delay) / max(span, 0.0001)
    let t = smoothstep(clamp01(raw))

    let from = CGPoint(x: p.scatter.x * glyphRadius,
                       y: p.scatter.y * glyphRadius)
    let to   = CGPoint(x: p.target.x * glyphRadius,
                       y: p.target.y * glyphRadius)

    let ox = lerp(from.x, to.x, t)
    let oy = lerp(from.y, to.y, t)

    let pos = CGPoint(x: center.x + ox, y: center.y + oy)
    let radius = p.dotScale * minDim

    // Opacity NEVER hits zero anywhere in the cycle: scattered particles stay
    // clearly visible (this guarantees the mid-explode frame is never blank).
    // They fade only slightly as they lock in (the symbol image takes over).
    let scatteredOpacity: Double = 0.92
    let assembledOpacity: Double = 0.34
    let opacity = lerp(scatteredOpacity, assembledOpacity, t)

    return SymbolAssemblyView_Resolved(position: pos, radius: radius, opacity: opacity)
}

// MARK: - Canvas particle layer

private struct SymbolAssemblyView_ParticleCanvas: View {
    let particles: [SymbolAssemblyView_Particle]
    let progress: CGFloat        // 0 scattered .. 1 assembled
    let color: Color
    let size: CGSize

    var body: some View {
        Canvas { context, _ in
            let minDim = min(size.width, size.height)
            let center = CGPoint(x: size.width / 2, y: size.height / 2)
            let glyphRadius = minDim * 0.34

            for p in particles {
                let r = resolve(p,
                                progress: progress,
                                center: center,
                                glyphRadius: glyphRadius,
                                minDim: minDim)

                let rect = CGRect(x: r.position.x - r.radius,
                                  y: r.position.y - r.radius,
                                  width: r.radius * 2,
                                  height: r.radius * 2)

                let dotColor = color.opacity(0.55 + p.tint * 0.45)
                context.opacity = r.opacity
                context.fill(Path(ellipseIn: rect), with: .color(dotColor))
            }
        }
        .allowsHitTesting(false)
    }
}

// MARK: - Symbol image (crossfades in on lock)

private struct SymbolAssemblyView_GlyphImage: View {
    let style: SymbolAssemblyView_SymbolStyle
    let opacity: Double
    let bounceTrigger: Int      // changes drive symbolEffect(.bounce)
    let size: CGSize

    var body: some View {
        let minDim = min(size.width, size.height)
        let fontSize = minDim * 0.46

        Image(systemName: style.name)
            .font(.system(size: fontSize, weight: .semibold))
            .foregroundStyle(style.color)
            .symbolRenderingMode(.hierarchical)
            .modifier(SymbolAssemblyView_BounceModifier(trigger: bounceTrigger))
            .shadow(color: style.color.opacity(0.55 * opacity),
                    radius: minDim * 0.05)
            .opacity(opacity)
            .allowsHitTesting(false)
    }
}

/// symbolEffect(.bounce, value:) is iOS-17-safe, so no availability guard needed.
private struct SymbolAssemblyView_BounceModifier: ViewModifier {
    let trigger: Int
    func body(content: Content) -> some View {
        content.symbolEffect(.bounce, value: trigger)
    }
}

// MARK: - Demo stage (self-driving)

private struct SymbolAssemblyView_DemoStage: View {
    let symbols: [SymbolAssemblyView_SymbolStyle]
    let particleCount: Int
    let size: CGSize

    private let particles: [SymbolAssemblyView_Particle]
    private let period: Double = 3.0     // seconds per symbol cycle

    init(symbols: [SymbolAssemblyView_SymbolStyle], particleCount: Int, size: CGSize) {
        self.symbols = symbols
        self.particleCount = particleCount
        self.size = size
        self.particles = makeParticles(count: particleCount)
    }

    var body: some View {
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            let phase = cyclePhase(at: t)

            ZStack {
                SymbolAssemblyView_ParticleCanvas(particles: particles,
                               progress: phase.progress,
                               color: symbols[phase.index].color,
                               size: size)

                SymbolAssemblyView_GlyphImage(style: symbols[phase.index],
                           opacity: symbolOpacity(for: phase.progress),
                           bounceTrigger: phase.index,
                           size: size)
                    .scaleEffect(symbolScale(for: phase.progress))
            }
        }
    }

    struct Phase {
        let index: Int
        let progress: CGFloat    // 0 scattered .. 1 assembled
    }

    /// Maps absolute time into (symbol index, assemble progress).
    /// Each cycle: assemble (0->1) -> hold(1) -> explode (1->0).
    private func cyclePhase(at time: Double) -> Phase {
        let total = time / period
        let index = Int(floor(total)) % symbols.count
        let local = total - floor(total)        // 0..1 within this symbol

        let progress: CGFloat
        if local < 0.38 {
            // assemble
            progress = CGFloat(local / 0.38)
        } else if local < 0.72 {
            // hold assembled
            progress = 1.0
        } else {
            // explode back to scattered (handoff to next symbol's assemble)
            progress = CGFloat(1.0 - (local - 0.72) / 0.28)
        }
        return Phase(index: index, progress: clamp01(progress))
    }

    private func symbolOpacity(for progress: CGFloat) -> Double {
        // Symbol only appears once particles are mostly home.
        Double(smoothstep(clamp01((progress - 0.7) / 0.3)))
    }

    private func symbolScale(for progress: CGFloat) -> CGFloat {
        // Tiny settle bounce as it locks.
        let s = smoothstep(clamp01((progress - 0.7) / 0.3))
        return 0.86 + 0.14 * s + 0.04 * CGFloat(sin(Double(s) * Double.pi))
    }
}

// MARK: - Interactive stage (real DragGesture)

private struct SymbolAssemblyView_InteractiveStage: View {
    let symbols: [SymbolAssemblyView_SymbolStyle]
    let particleCount: Int
    let size: CGSize

    private let particles: [SymbolAssemblyView_Particle]

    @State private var index: Int = 0
    /// 0 scattered .. 1 assembled. Resting state is fully assembled (1).
    @State private var progress: CGFloat = 1.0
    @State private var dragging: Bool = false
    @State private var bounceTrigger: Int = 0

    init(symbols: [SymbolAssemblyView_SymbolStyle], particleCount: Int, size: CGSize) {
        self.symbols = symbols
        self.particleCount = particleCount
        self.size = size
        self.particles = makeParticles(count: particleCount)
    }

    var body: some View {
        ZStack {
            SymbolAssemblyView_ParticleCanvas(particles: particles,
                           progress: progress,
                           color: symbols[index].color,
                           size: size)

            SymbolAssemblyView_GlyphImage(style: symbols[index],
                       opacity: symbolOpacity(for: progress),
                       bounceTrigger: bounceTrigger,
                       size: size)
                .scaleEffect(symbolScale(for: progress))

            hintLabel
        }
        .contentShape(Rectangle())
        .gesture(dragGesture)
    }

    private var hintLabel: some View {
        VStack {
            Spacer()
            Text("Swipe to rebuild")
                .font(.system(size: max(9, min(size.width, size.height) * 0.07),
                              weight: .medium))
                .foregroundStyle(.white.opacity(progress > 0.9 ? 0.5 : 0.0))
                .padding(.bottom, min(size.width, size.height) * 0.06)
        }
        .allowsHitTesting(false)
    }

    private var dragGesture: some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                dragging = true
                // Horizontal drag scrubs the symbol apart: more drag -> more scatter.
                let span = max(size.width * 0.55, 1)
                let amount = min(abs(value.translation.width) / span, 1.0)
                progress = clamp01(1.0 - amount)
            }
            .onEnded { value in
                dragging = false
                let span = max(size.width * 0.55, 1)
                let predicted = abs(value.predictedEndTranslation.width) / span
                let actual = abs(value.translation.width) / span

                if max(predicted, actual) > 0.5 {
                    advanceSymbol(forward: value.translation.width < 0)
                } else {
                    // Snap back assembled.
                    withAnimation(.spring(response: 0.45, dampingFraction: 0.7)) {
                        progress = 1.0
                    }
                }
            }
    }

    private func advanceSymbol(forward: Bool) {
        // Explode fully, swap symbol, then converge into the new one with a bounce.
        withAnimation(.easeIn(duration: 0.18)) {
            progress = 0.0
        }
        DispatchQueue.main.asyncAfter(deadline: .now() + 0.18) {
            let count = symbols.count
            index = forward ? (index + 1) % count
                            : (index - 1 + count) % count
            withAnimation(.spring(response: 0.6, dampingFraction: 0.62)) {
                progress = 1.0
            }
            bounceTrigger &+= 1
        }
    }

    private func symbolOpacity(for progress: CGFloat) -> Double {
        Double(smoothstep(clamp01((progress - 0.7) / 0.3)))
    }

    private func symbolScale(for progress: CGFloat) -> CGFloat {
        let s = smoothstep(clamp01((progress - 0.7) / 0.3))
        return 0.86 + 0.14 * s
    }
}

// MARK: - Math helpers

private func clamp01(_ x: CGFloat) -> CGFloat { min(max(x, 0), 1) }

private func lerp(_ a: CGFloat, _ b: CGFloat, _ t: CGFloat) -> CGFloat {
    a + (b - a) * t
}

private func smoothstep(_ x: CGFloat) -> CGFloat {
    let t = clamp01(x)
    return t * t * (3 - 2 * t)
}
"""###,
        "tr-clock-pie-wipe": ###"""
import SwiftUI

/// Clock Pie Wipe — an angular sweep mask rotates around the center like a clock
/// hand, progressively unveiling the "next" scene in a radial pie sweep. A bright
/// leading-edge ray rides the sweeping radius like a radar beam.
///
/// `interaction: auto` — both `demo` states run the same self-driving sweep.
struct ClockPieWipeView: View {
    var demo: Bool = false

    /// Seconds for one full 360° sweep (one scene reveal).
    private let period: Double = 3.2

    var body: some View {
        GeometryReader { geo in
            let size = geo.size
            TimelineView(.animation) { timeline in
                let t = timeline.date.timeIntervalSinceReferenceDate
                content(in: size, time: t)
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // MARK: - Composed frame

    @ViewBuilder
    private func content(in size: CGSize, time t: TimeInterval) -> some View {
        let cycle = floor(t / period)
        let phase = t / period - cycle          // 0...1 within the current sweep
        let sweep = phase * 360.0               // degrees revealed so far
        let leading = sweep - 90.0              // leading radius, 0° = top (clock 12)

        let count = Self.scenes.count
        let baseIndex = Int(cycle.truncatingRemainder(dividingBy: Double(count)))
        let bgIndex = ((baseIndex % count) + count) % count
        let fgIndex = (bgIndex + 1) % count

        let radius = hypot(size.width, size.height) / 2.0

        ZStack {
            // Background: fully-opaque current scene — never blank on any frame.
            sceneView(Self.scenes[bgIndex], in: size)

            // Foreground: next scene, revealed through the rotating pie wedge.
            sceneView(Self.scenes[fgIndex], in: size)
                .mask(
                    PieWedge(startAngle: .degrees(-90), sweep: .degrees(sweep))
                        .frame(width: radius * 2, height: radius * 2)
                )

            // Radar ray riding the leading radius.
            radarRay(radius: radius, angleDegrees: leading)
                .opacity(phase < 0.004 || phase > 0.996 ? 0.0 : 1.0)

            // Static clock face overlay (hub + ticks) for mechanical precision.
            clockFurniture(radius: radius)
        }
        .frame(width: size.width, height: size.height)
        .clipped()
    }

    // MARK: - Radar ray

    private func radarRay(radius: CGFloat, angleDegrees: Double) -> some View {
        let beam = LinearGradient(
            stops: [
                .init(color: .white.opacity(0.0), location: 0.0),
                .init(color: .white.opacity(0.35), location: 0.55),
                .init(color: .white, location: 1.0)
            ],
            startPoint: .top,
            endPoint: .bottom
        )
        return ZStack {
            // Soft glow under the crisp ray.
            Capsule()
                .fill(Color.white.opacity(0.25))
                .frame(width: 6, height: radius)
                .blur(radius: 5)
                .offset(y: -radius / 2)
            Capsule()
                .fill(beam)
                .frame(width: 2.0, height: radius)
                .offset(y: -radius / 2)
        }
        .rotationEffect(.degrees(angleDegrees + 90))
    }

    // MARK: - Clock furniture

    private func clockFurniture(radius: CGFloat) -> some View {
        let r = min(radius, 600)
        return ZStack {
            ForEach(0..<12, id: \.self) { i in
                Capsule()
                    .fill(Color.white.opacity(i % 3 == 0 ? 0.30 : 0.14))
                    .frame(width: i % 3 == 0 ? 2.2 : 1.4,
                           height: i % 3 == 0 ? 9 : 5)
                    .offset(y: -(r * 0.46))
                    .rotationEffect(.degrees(Double(i) / 12.0 * 360.0))
            }
            Circle()
                .fill(
                    RadialGradient(
                        colors: [.white.opacity(0.9), .white.opacity(0.15)],
                        center: .center, startRadius: 0, endRadius: 7
                    )
                )
                .frame(width: 10, height: 10)
        }
    }

    // MARK: - Scenes (each cycle reveals a visibly different "next view")

    private struct Scene: Identifiable {
        let id = UUID()
        let symbol: String
        let title: String
        let top: Color
        let bottom: Color
        let tint: Color
    }

    private static let scenes: [Scene] = [
        Scene(symbol: "sunrise.fill", title: "MORNING",
              top: Color(hexCode: 0x2A1B3D), bottom: Color(hexCode: 0x44318D),
              tint: Color(hexCode: 0xFFB86B)),
        Scene(symbol: "sun.max.fill", title: "MIDDAY",
              top: Color(hexCode: 0x0E4D64), bottom: Color(hexCode: 0x137DC5),
              tint: Color(hexCode: 0xFFE08A)),
        Scene(symbol: "sunset.fill", title: "EVENING",
              top: Color(hexCode: 0x6A1E3A), bottom: Color(hexCode: 0xC0392B),
              tint: Color(hexCode: 0xFFC07A)),
        Scene(symbol: "moon.stars.fill", title: "NIGHT",
              top: Color(hexCode: 0x0B1026), bottom: Color(hexCode: 0x222B5A),
              tint: Color(hexCode: 0x9FB8FF))
    ]

    @ViewBuilder
    private func sceneView(_ scene: Scene, in size: CGSize) -> some View {
        let dim = min(size.width, size.height)
        ZStack {
            LinearGradient(
                colors: [scene.top, scene.bottom],
                startPoint: .topLeading, endPoint: .bottomTrailing
            )
            // Subtle angular sheen so the wedge edge catches light.
            AngularGradient(
                colors: [
                    .white.opacity(0.0), scene.tint.opacity(0.16),
                    .white.opacity(0.0), .white.opacity(0.0)
                ],
                center: .center
            )
            .blendMode(.screen)

            VStack(spacing: dim * 0.06) {
                Image(systemName: scene.symbol)
                    .font(.system(size: dim * 0.30, weight: .medium))
                    .foregroundStyle(scene.tint)
                    .shadow(color: scene.tint.opacity(0.6), radius: dim * 0.05)
                Text(scene.title)
                    .font(.system(size: max(9, dim * 0.11),
                                  weight: .heavy, design: .rounded))
                    .tracking(dim * 0.02)
                    .foregroundStyle(.white.opacity(0.92))
            }
        }
    }
}

// MARK: - Pie wedge shape (animatable sweep)

private struct PieWedge: Shape {
    var startAngle: Angle
    var sweep: Angle

    var animatableData: Double {
        get { sweep.degrees }
        set { sweep = .degrees(newValue) }
    }

    func path(in rect: CGRect) -> Path {
        var path = Path()
        let center = CGPoint(x: rect.midX, y: rect.midY)
        let radius = max(rect.width, rect.height)   // overshoot to guarantee corners
        let clamped = min(max(sweep.degrees, 0), 360)
        guard clamped > 0 else { return path }
        path.move(to: center)
        path.addArc(
            center: center,
            radius: radius,
            startAngle: startAngle,
            endAngle: startAngle + .degrees(clamped),
            clockwise: false
        )
        path.closeSubpath()
        return path
    }
}

// MARK: - Hex color helper

private extension Color {
    init(hexCode hex: UInt32) {
        let r = Double((hex >> 16) & 0xFF) / 255.0
        let g = Double((hex >> 8) & 0xFF) / 255.0
        let b = Double(hex & 0xFF) / 255.0
        self.init(red: r, green: g, blue: b)
    }
}
"""###,
        "tr-column-slat-slide": ###"""
import SwiftUI

/// Column Slat Slide — a transition where the outgoing card is sliced into
/// vertical column "slats" that slide off-screen at staggered speeds and
/// offsets, revealing the incoming card sitting behind each gap. The staggered
/// timing makes the columns appear to overtake each other in a rippling
/// vertical-blind cascade.
///
/// This is an `auto` transition: both `demo` states self-drive the cascade
/// continuously via `TimelineView(.animation)` — there is no scrub gesture per
/// the spec.
struct ColumnSlatSlideView: View {
    var demo: Bool = false

    var body: some View {
        TimelineView(.animation) { context in
            let t = context.date.timeIntervalSinceReferenceDate
            SlatStage(progress: loopProgress(at: t))
        }
    }

    /// Eases a 0→1→0 cascade on a ~3.4s loop with brief dwells at each end so
    /// both the fully-outgoing and fully-incoming states are clearly read.
    private func loopProgress(at time: TimeInterval) -> CGFloat {
        let period: Double = 3.4
        let phase = (time.truncatingRemainder(dividingBy: period)) / period
        // Two halves: 0→1 then 1→0, each smoothed, with a short hold at the apex.
        let raw: Double
        if phase < 0.5 {
            raw = smoothstep(phase / 0.5)
        } else {
            raw = smoothstep((1.0 - phase) / 0.5)
        }
        return CGFloat(raw)
    }

    private func smoothstep(_ x: Double) -> Double {
        let c = min(max(x, 0), 1)
        return c * c * (3 - 2 * c)
    }
}

// MARK: - Stage

private struct SlatStage: View {
    let progress: CGFloat

    private let slatCount = 6

    var body: some View {
        GeometryReader { geo in
            ZStack {
                // Incoming card always fills the frame behind the slats, so no
                // frame is ever blank: p=0 → outgoing, p=1 → incoming.
                CardFace(kind: .incoming)
                    .frame(maxWidth: .infinity, maxHeight: .infinity)

                // Outgoing card, sliced into vertical columns. Each column is a
                // full-size copy masked to its own x-range, then offset so it
                // slides away as a unit (global coords stay correct).
                ForEach(0..<slatCount, id: \.self) { index in
                    SlatColumn(
                        index: index,
                        count: slatCount,
                        size: geo.size,
                        offsetY: offsetY(index: index, size: geo.size)
                    )
                }
            }
            .clipShape(RoundedRectangle(cornerRadius: corner(for: geo.size), style: .continuous))
            .frame(maxWidth: .infinity, maxHeight: .infinity)
        }
    }

    private func corner(for size: CGSize) -> CGFloat {
        min(size.width, size.height) * 0.12
    }

    /// Per-column vertical offset. Each column has a staggered start delay and a
    /// slightly different speed, so columns overtake one another → cascade.
    /// Columns alternate sliding up / down for a woven-blind feel.
    private func offsetY(index: Int, size: CGSize) -> CGFloat {
        let n = Double(slatCount)
        let i = Double(index)

        // Left-to-right travelling wave: each column starts a beat later.
        let delay = 0.16 * (i / max(n - 1, 1))
        // Mild per-column speed variation so leaders get overtaken.
        let speed = 1.0 + 0.45 * (i / max(n - 1, 1))

        let local = (Double(progress) - delay) * speed
        let p = min(max(local, 0), 1)
        let eased = p * p * (3 - 2 * p) // smoothstep

        // Travel just past the edge to guarantee a clean exit (no hairline).
        let travel = size.height * 1.12
        let direction: CGFloat = (index % 2 == 0) ? -1 : 1
        return direction * CGFloat(eased) * travel
    }
}

// MARK: - One vertical slat

private struct SlatColumn: View {
    let index: Int
    let count: Int
    let size: CGSize
    let offsetY: CGFloat

    var body: some View {
        let columnWidth = size.width / CGFloat(count)
        // Overlap edges by 0.6pt to avoid sub-pixel seams between columns.
        let x = columnWidth * CGFloat(index) - 0.3
        let w = columnWidth + 0.6

        CardFace(kind: .outgoing)
            .frame(maxWidth: .infinity, maxHeight: .infinity)
            .mask(alignment: .topLeading) {
                Rectangle()
                    .frame(width: w, height: size.height)
                    .offset(x: x)
            }
            .offset(y: offsetY)
    }
}

// MARK: - Card faces

private enum FaceKind {
    case outgoing
    case incoming
}

private struct CardFace: View {
    let kind: FaceKind

    var body: some View {
        GeometryReader { geo in
            let side = min(geo.size.width, geo.size.height)
            ZStack {
                background(side: side)
                content(side: side)
            }
            .frame(maxWidth: .infinity, maxHeight: .infinity)
        }
    }

    @ViewBuilder
    private func background(side: CGFloat) -> some View {
        let colors = kind == .outgoing
            ? [Color(hexCode: 0x1A2030), Color(hexCode: 0x0D1016)]
            : [Color(hexCode: 0x16324A), Color(hexCode: 0x0B1B2A)]
        LinearGradient(
            colors: colors,
            startPoint: .topLeading,
            endPoint: .bottomTrailing
        )
        .overlay(slatSheen(side: side))
    }

    /// Subtle vertical sheen lines so the column boundaries read as physical slats.
    private func slatSheen(side: CGFloat) -> some View {
        let tint = kind == .outgoing ? Color.white.opacity(0.05) : Color.cyan.opacity(0.06)
        return LinearGradient(
            colors: [tint, .clear, tint],
            startPoint: .leading,
            endPoint: .trailing
        )
        .blendMode(.plusLighter)
    }

    @ViewBuilder
    private func content(side: CGFloat) -> some View {
        let symbol = kind == .outgoing ? "square.grid.3x3.fill" : "checkmark.seal.fill"
        let label = kind == .outgoing ? "PANEL A" : "PANEL B"
        let accent = kind == .outgoing ? Color(hexCode: 0x7C8AA8) : Color(hexCode: 0x35E0C8)

        VStack(spacing: side * 0.08) {
            Image(systemName: symbol)
                .font(.system(size: side * 0.26, weight: .semibold))
                .foregroundStyle(accent)
                .shadow(color: accent.opacity(0.5), radius: side * 0.05)
            Text(label)
                .font(.system(size: side * 0.1, weight: .heavy, design: .rounded))
                .tracking(side * 0.02)
                .foregroundStyle(.white.opacity(0.92))
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }
}

// MARK: - Hex color helper

private extension Color {
    init(hexCode hex: UInt32) {
        let r = Double((hex >> 16) & 0xFF) / 255.0
        let g = Double((hex >> 8) & 0xFF) / 255.0
        let b = Double(hex & 0xFF) / 255.0
        self = Color(.sRGB, red: r, green: g, blue: b, opacity: 1.0)
    }
}
"""###,
        "tr-crumple-fade": ###"""
import SwiftUI

// MARK: - Crumple Fade
// A tap-driven transition: the outgoing card scales inward while layered
// faceted light/shadow crease overlays bloom across it (faking a paper
// crumple) and it fades out, revealing the incoming card easing in beneath.
// Pure SwiftUI overlays + transforms, no shader. iOS 17.

struct CrumpleFadeView: View {
    var demo: Bool = false

    @State private var crumpled: Bool = false

    var body: some View {
        if demo {
            demoBody
        } else {
            interactiveBody
        }
    }

    // MARK: Demo — self-driving ping-pong loop

    private var demoBody: some View {
        // Trigger-less PhaseAnimator cycles the phases continuously (0→1→0…),
        // so the tile auto-crumples and un-crumples with no touch.
        PhaseAnimator([0.0, 1.0]) { phase in
            crumpleStage(progress: phase)
        } animation: { _ in
            .easeInOut(duration: 1.6)
        }
    }

    // MARK: Interactive — tap toggles the crumple

    private var interactiveBody: some View {
        crumpleStage(progress: crumpled ? 1.0 : 0.0)
            .contentShape(Rectangle())
            .onTapGesture {
                withAnimation(.spring(response: 0.55, dampingFraction: 0.72)) {
                    crumpled.toggle()
                }
            }
            .sensoryFeedback(.impact(weight: .light), trigger: crumpled)
    }

    // MARK: Shared stage — both modes feed a single progress value

    private func crumpleStage(progress: Double) -> some View {
        GeometryReader { geo in
            let size = geo.size
            ZStack {
                // Incoming card sits beneath and eases in as the outgoing leaves.
                CrumpleFadeView_IncomingCard(progress: progress)

                // Outgoing card crumples, creases and fades over the incoming one.
                CrumpleFadeView_OutgoingCard(progress: progress, size: size)
            }
            .frame(width: size.width, height: size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }
}

// MARK: - Incoming Card (revealed beneath)

private struct CrumpleFadeView_IncomingCard: View {
    let progress: Double

    var body: some View {
        // Reveal ramps in over the back half of the crumple so it's legible
        // by the time the outgoing card has shrunk away.
        let reveal = clamp((progress - 0.25) / 0.75)
        let scale = 0.92 + 0.08 * reveal

        RoundedRectangle(cornerRadius: 18, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.18, green: 0.55, blue: 0.62),
                        Color(red: 0.10, green: 0.32, blue: 0.46)
                    ],
                    startPoint: .topLeading,
                    endPoint: .bottomTrailing
                )
            )
            .overlay(
                RoundedRectangle(cornerRadius: 18, style: .continuous)
                    .strokeBorder(Color.white.opacity(0.16), lineWidth: 1)
            )
            .overlay(
                Image(systemName: "checkmark.seal.fill")
                    .font(.system(size: 34, weight: .semibold))
                    .foregroundStyle(.white.opacity(0.92))
                    .opacity(reveal)
            )
            .scaleEffect(scale)
            .opacity(0.35 + 0.65 * reveal)
            .padding(10)
    }
}

// MARK: - Outgoing Card (crumples + fades)

private struct CrumpleFadeView_OutgoingCard: View {
    let progress: Double
    let size: CGSize

    var body: some View {
        // Single progress drives scale, rotation, crease bloom and fade.
        let scale = 1.0 - 0.48 * progress
        let rotation = 6.0 * progress
        let cardOpacity = 1.0 - pow(progress, 1.4)
        let creaseOpacity = creaseBloom(progress)

        cardFace
            .overlay(
                CrumpleFadeView_CreaseOverlay(progress: progress, opacity: creaseOpacity)
                    .clipShape(RoundedRectangle(cornerRadius: 18, style: .continuous))
            )
            .scaleEffect(scale)
            .rotationEffect(.degrees(rotation))
            .opacity(cardOpacity)
            .padding(10)
            .shadow(
                color: .black.opacity(0.25 * progress),
                radius: 10 * progress,
                x: 0,
                y: 4 * progress
            )
    }

    private var cardFace: some View {
        RoundedRectangle(cornerRadius: 18, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.94, green: 0.93, blue: 0.90),
                        Color(red: 0.82, green: 0.80, blue: 0.76)
                    ],
                    startPoint: .top,
                    endPoint: .bottom
                )
            )
            .overlay(
                RoundedRectangle(cornerRadius: 18, style: .continuous)
                    .strokeBorder(Color.black.opacity(0.08), lineWidth: 1)
            )
            .overlay(
                VStack(spacing: 6) {
                    Image(systemName: "doc.text")
                        .font(.system(size: 30, weight: .regular))
                    Text("Tap")
                        .font(.system(size: 12, weight: .semibold))
                }
                .foregroundStyle(Color(red: 0.32, green: 0.30, blue: 0.27))
                .opacity(1.0 - progress)
            )
    }

    // Creases bloom in mid-crumple, peaking near the end.
    private func creaseBloom(_ p: Double) -> Double {
        let ramp = clamp(p / 0.85)
        return ramp * (0.55 + 0.45 * ramp)
    }
}

// MARK: - Crease Overlay (faceted light/shadow polygons)

private struct CrumpleFadeView_CreaseOverlay: View {
    let progress: Double
    let opacity: Double

    var body: some View {
        // A gentle expansion of the facets so creases appear to spread.
        let spread = 0.85 + 0.15 * progress

        ZStack {
            ForEach(CrumpleFadeView_Facet.all) { facet in
                CrumpleFadeView_FacetShape(points: facet.points)
                    .fill(facet.gradient)
                    .blendMode(facet.blend)
                    .opacity(facet.weight)
            }
        }
        .scaleEffect(spread)
        .opacity(opacity)
        .allowsHitTesting(false)
    }
}

// A single crease facet: a polygon in unit space with a light or shadow gradient.
private struct CrumpleFadeView_Facet: Identifiable {
    let id: Int
    let points: [CGPoint]
    let blend: BlendMode
    let weight: Double
    let gradient: LinearGradient

    static let all: [CrumpleFadeView_Facet] = makeFacets()

    private static func makeFacets() -> [CrumpleFadeView_Facet] {
        // Unit-square coordinates (0...1). Stable across all frames.
        let raw: [(pts: [CGPoint], light: Bool, w: Double, angle: Double)] = [
            ([CGPoint(x: 0.0, y: 0.0), CGPoint(x: 0.42, y: 0.10), CGPoint(x: 0.20, y: 0.46)], true, 0.55, 35),
            ([CGPoint(x: 0.42, y: 0.10), CGPoint(x: 0.78, y: 0.0), CGPoint(x: 0.58, y: 0.40)], false, 0.5, 120),
            ([CGPoint(x: 0.78, y: 0.0), CGPoint(x: 1.0, y: 0.18), CGPoint(x: 0.72, y: 0.42)], true, 0.5, 70),
            ([CGPoint(x: 0.20, y: 0.46), CGPoint(x: 0.58, y: 0.40), CGPoint(x: 0.40, y: 0.74)], false, 0.55, 160),
            ([CGPoint(x: 0.58, y: 0.40), CGPoint(x: 0.92, y: 0.50), CGPoint(x: 0.66, y: 0.78)], true, 0.5, 20),
            ([CGPoint(x: 0.0, y: 0.30), CGPoint(x: 0.20, y: 0.46), CGPoint(x: 0.06, y: 0.80)], false, 0.45, 140),
            ([CGPoint(x: 0.40, y: 0.74), CGPoint(x: 0.66, y: 0.78), CGPoint(x: 0.48, y: 1.0)], true, 0.5, 95),
            ([CGPoint(x: 0.66, y: 0.78), CGPoint(x: 1.0, y: 0.72), CGPoint(x: 0.84, y: 1.0)], false, 0.5, 50),
            ([CGPoint(x: 0.06, y: 0.80), CGPoint(x: 0.40, y: 0.74), CGPoint(x: 0.18, y: 1.0)], true, 0.45, 110),
            ([CGPoint(x: 0.72, y: 0.42), CGPoint(x: 1.0, y: 0.18), CGPoint(x: 0.92, y: 0.50)], false, 0.45, 130)
        ]

        return raw.enumerated().map { index, item in
            CrumpleFadeView_Facet(
                id: index,
                points: item.pts,
                blend: item.light ? .plusLighter : .multiply,
                weight: item.w,
                gradient: facetGradient(light: item.light, angle: item.angle)
            )
        }
    }

    private static func facetGradient(light: Bool, angle: Double) -> LinearGradient {
        let unit = unitPoints(for: angle)
        let colors: [Color]
        if light {
            colors = [
                Color.white.opacity(0.85),
                Color.white.opacity(0.15)
            ]
        } else {
            colors = [
                Color.black.opacity(0.55),
                Color.black.opacity(0.10)
            ]
        }
        return LinearGradient(colors: colors, startPoint: unit.start, endPoint: unit.end)
    }

    private static func unitPoints(for angle: Double) -> (start: UnitPoint, end: UnitPoint) {
        let radians = angle * .pi / 180.0
        let dx = cos(radians)
        let dy = sin(radians)
        let start = UnitPoint(x: 0.5 - dx * 0.5, y: 0.5 - dy * 0.5)
        let end = UnitPoint(x: 0.5 + dx * 0.5, y: 0.5 + dy * 0.5)
        return (start, end)
    }
}

// Renders a unit-space polygon into the available rect.
private struct CrumpleFadeView_FacetShape: Shape {
    let points: [CGPoint]

    func path(in rect: CGRect) -> Path {
        var path = Path()
        guard let first = points.first else { return path }
        path.move(to: scaled(first, in: rect))
        for point in points.dropFirst() {
            path.addLine(to: scaled(point, in: rect))
        }
        path.closeSubpath()
        return path
    }

    private func scaled(_ point: CGPoint, in rect: CGRect) -> CGPoint {
        CGPoint(
            x: rect.minX + point.x * rect.width,
            y: rect.minY + point.y * rect.height
        )
    }
}

// MARK: - Helpers

private func clamp(_ value: Double) -> Double {
    min(1.0, max(0.0, value))
}
"""###,
        "tr-cube-tumble": ###"""
import SwiftUI

// MARK: - Cube Tumble
// Pages map to the faces of a 3D cube that rotates through 90° turns with
// true perspective foreshortening, advancing one view per face.
//
// Mechanism: a two-face hinge. Both faces share the same center pivot
// (axis Y, anchor .center) with a `perspective:` m34 set on
// `.rotation3DEffect`. The outgoing face rotates 0→90° while the incoming
// face rotates −90°→0° with the next page's content; a z-order / opacity
// swap around the edge-on point keeps the seam from tearing and never
// reveals mirrored backface content.
//
// demo == true  : a self-driving TimelineView(.animation) continuously
//                 tumbles the cube through successive faces on a ~3s/face
//                 loop — always legible, never blank.
// demo == false : a horizontal DragGesture(minimumDistance: 0) scrubs the
//                 rotation mid-turn; on release it rubber-bands to the
//                 nearest 90° face, using predictedEndTranslation to decide
//                 whether to advance or snap back, with a spring + haptic.

struct CubeTumbleView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { geo in
            let side = min(geo.size.width, geo.size.height) * 0.74
            ZStack {
                CubeTumbleView_CubeBackdrop()
                Group {
                    if demo {
                        CubeTumbleView_DemoCube(side: side)
                    } else {
                        CubeTumbleView_InteractiveCube(side: side)
                    }
                }
                .frame(width: geo.size.width, height: geo.size.height)
            }
            .frame(width: geo.size.width, height: geo.size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }
}

// MARK: - Shared model

private enum CubeTumbleView_CubePalette {
    // Four distinct page faces so the rotation reads as *pages* turning,
    // not one panel spinning. Returns a top/bottom gradient pair.
    static func face(_ index: Int) -> (Color, Color, String) {
        let i = ((index % 4) + 4) % 4
        switch i {
        case 0:
            return (Color(red: 0.30, green: 0.55, blue: 0.98),
                    Color(red: 0.16, green: 0.30, blue: 0.74), "01")
        case 1:
            return (Color(red: 0.98, green: 0.46, blue: 0.40),
                    Color(red: 0.78, green: 0.22, blue: 0.34), "02")
        case 2:
            return (Color(red: 0.42, green: 0.86, blue: 0.62),
                    Color(red: 0.16, green: 0.55, blue: 0.42), "03")
        default:
            return (Color(red: 0.86, green: 0.66, blue: 0.36),
                    Color(red: 0.62, green: 0.40, blue: 0.16), "04")
        }
    }
}

private struct CubeTumbleView_CubeBackdrop: View {
    var body: some View {
        LinearGradient(
            colors: [
                Color(red: 0.05, green: 0.06, blue: 0.09),
                Color(red: 0.09, green: 0.10, blue: 0.15)
            ],
            startPoint: .top,
            endPoint: .bottom
        )
    }
}

// MARK: - A single cube face

private struct CubeTumbleView_CubeFace: View {
    let pageIndex: Int
    let side: CGFloat

    var body: some View {
        let (top, bottom, label) = CubeTumbleView_CubePalette.face(pageIndex)
        RoundedRectangle(cornerRadius: side * 0.10, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [top, bottom],
                    startPoint: .topLeading,
                    endPoint: .bottomTrailing
                )
            )
            .overlay(faceDetail(label: label, top: top))
            .overlay(
                RoundedRectangle(cornerRadius: side * 0.10, style: .continuous)
                    .strokeBorder(Color.white.opacity(0.22), lineWidth: 1)
            )
            .frame(width: side, height: side)
    }

    private func faceDetail(label: String, top: Color) -> some View {
        ZStack {
            // A soft sheen so the perspective foreshortening catches light.
            RoundedRectangle(cornerRadius: side * 0.10, style: .continuous)
                .fill(
                    LinearGradient(
                        colors: [Color.white.opacity(0.28), Color.clear],
                        startPoint: .top,
                        endPoint: .center
                    )
                )
            VStack(spacing: side * 0.06) {
                Circle()
                    .fill(Color.white.opacity(0.9))
                    .frame(width: side * 0.18, height: side * 0.18)
                    .overlay(
                        Text(label)
                            .font(.system(size: side * 0.09, weight: .heavy, design: .rounded))
                            .foregroundColor(top)
                    )
                Text("PAGE")
                    .font(.system(size: side * 0.085, weight: .bold, design: .rounded))
                    .tracking(side * 0.02)
                    .foregroundColor(.white.opacity(0.92))
            }
        }
    }
}

// MARK: - Hinge: two faces sharing the center pivot

private struct CubeTumbleView_CubeHinge: View {
    /// Page index currently considered the "front" baseline.
    let basePage: Int
    /// Continuous turn progress in degrees within the current 90° step.
    /// 0   → base page flat and centered.
    /// 90  → next page flat and centered.
    /// May go slightly negative or past 90 while scrubbing.
    let degrees: Double
    let side: CGFloat
    /// Direction of travel: +1 advancing to next page, used for content.
    let direction: Int

    private var perspective: CGFloat { 0.62 }

    var body: some View {
        let t = degrees
        // Outgoing (base) face: rotates 0 → 90.
        // Incoming (neighbor) face: rotates -90 → 0, showing adjacent page.
        let outgoingAngle = t
        let incomingAngle = t - 90.0 * Double(directionSign)

        let outgoingPage = basePage
        let incomingPage = basePage + directionSign

        // Crossfade / z-order swap around the edge-on midpoint (45°).
        let mid = 45.0
        let outFront = abs(t) < mid

        ZStack {
            face(page: incomingPage, angle: incomingAngle)
                .opacity(faceOpacity(for: incomingAngle))
                .zIndex(outFront ? 0 : 1)
            face(page: outgoingPage, angle: outgoingAngle)
                .opacity(faceOpacity(for: outgoingAngle))
                .zIndex(outFront ? 1 : 0)
        }
    }

    private var directionSign: Int { direction >= 0 ? 1 : -1 }

    private func face(page: Int, angle: Double) -> some View {
        CubeTumbleView_CubeFace(pageIndex: page, side: side)
            .rotation3DEffect(
                .degrees(angle),
                axis: (x: 0, y: 1, z: 0),
                anchor: .center,
                perspective: perspective
            )
    }

    // Fade a face out as it approaches edge-on (±90°) so we never show the
    // razor-thin sliver or any mirrored backface.
    private func faceOpacity(for angle: Double) -> Double {
        let a = min(abs(angle), 90.0)
        // Full opacity until ~55°, then ramp to 0 by 90°.
        if a <= 55 { return 1 }
        let fade = (90.0 - a) / 35.0
        return max(0, min(1, fade))
    }
}

// MARK: - Demo: self-driving auto-tumble

private struct CubeTumbleView_DemoCube: View {
    let side: CGFloat
    private let secondsPerFace: Double = 3.0

    var body: some View {
        TimelineView(.animation) { timeline in
            let elapsed = timeline.date.timeIntervalSinceReferenceDate
            let faces = elapsed / secondsPerFace
            let base = Int(floor(faces))
            let frac = faces - Double(base)
            // Ease the per-face turn so it accelerates in and settles out,
            // dwelling briefly flat at each face for legibility.
            let eased = easedTurn(frac)
            let degrees = eased * 90.0

            CubeTumbleView_CubeHinge(
                basePage: base,
                degrees: degrees,
                side: side,
                direction: 1
            )
        }
    }

    // Dwell flat at the start/end of each step, smooth turn in the middle.
    private func easedTurn(_ x: Double) -> Double {
        let dwell = 0.22
        if x < dwell { return 0 }
        if x > 1 - dwell { return 1 }
        let p = (x - dwell) / (1 - 2 * dwell)
        // smoothstep
        return p * p * (3 - 2 * p)
    }
}

// MARK: - Interactive: drag to scrub, spring-snap on release

private struct CubeTumbleView_InteractiveCube: View {
    let side: CGFloat

    @State private var basePage: Int = 0
    @State private var dragDegrees: Double = 0
    @State private var snapTrigger: Int = 0

    // How many drag points equal a full 90° face turn.
    private var pointsPerFace: CGFloat { max(side, 120) }

    var body: some View {
        CubeTumbleView_CubeHinge(
            basePage: basePage,
            degrees: dragDegrees,
            side: side,
            direction: dragDegrees >= 0 ? 1 : -1
        )
        .contentShape(Rectangle())
        .gesture(dragGesture)
        .sensoryFeedback(.impact(flexibility: .soft), trigger: snapTrigger)
    }

    private var dragGesture: some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                // Dragging left advances to the next face (+degrees).
                let raw = -value.translation.width / pointsPerFace * 90.0
                dragDegrees = clampScrub(raw)
            }
            .onEnded { value in
                let predicted = -value.predictedEndTranslation.width / pointsPerFace * 90.0
                resolveSnap(current: dragDegrees, predicted: clampScrub(predicted))
            }
    }

    // Allow a little overscroll past the current step while scrubbing.
    private func clampScrub(_ d: Double) -> Double {
        min(max(d, -120), 120)
    }

    private func resolveSnap(current: Double, predicted: Double) {
        // Decide the target step (-1, 0, or +1 relative to base) using the
        // predicted end position so a flick commits even from a small drag.
        let decider = predicted
        let target: Double
        let pageDelta: Int

        if decider >= 45 {
            target = 90
            pageDelta = 1
        } else if decider <= -45 {
            target = -90
            pageDelta = -1
        } else {
            target = 0
            pageDelta = 0
        }

        withAnimation(.spring(response: 0.45, dampingFraction: 0.72)) {
            dragDegrees = target
        }

        // After the spring lands on the neighbor face, fold that face back
        // to the flat baseline (degrees → 0) by committing the page index.
        if pageDelta != 0 {
            snapTrigger &+= 1
            DispatchQueue.main.asyncAfter(deadline: .now() + 0.46) {
                basePage += pageDelta
                dragDegrees = 0
            }
        } else {
            // Snapped back to base; reset trigger so a returned scrub
            // still feels responsive.
            dragDegrees = 0
        }
    }
}
"""###,
        "tr-depth-stack-push": ###"""
import SwiftUI

/// Depth Stack Push
///
/// The focused card recedes into a z-ordered stack with a scale-down,
/// downward drift and progressive blur while the next card rises forward into
/// focus, like a physical deck being shuffled in 3D space.
///
/// - `demo == true`: a `TimelineView(.animation)` advances the deck one card
///   per period on a continuous loop so the depth shuffle plays itself.
/// - `demo == false`: a horizontal `DragGesture` maps translation to a 0→1
///   push progress; releasing past a threshold commits the push with an
///   interactive spring, otherwise it springs back.
///
/// Both modes share ONE renderer (`DepthStackPushView_DeckLayer`). Each card's attributes are
/// the lerp of its resolved attributes at the current and next integer front,
/// and its `zIndex` always comes from the *integer* front — so the leaving
/// card stays painted on top while it shrinks and only drops to the back once
/// it has fully receded, keeping the depth illusion intact in both modes.
struct DepthStackPushView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { proxy in
            let size = proxy.size
            let dim = min(size.width, size.height)
            ZStack {
                DepthStackPushView_Background()
                Group {
                    if demo {
                        DepthStackPushView_DemoDriver(dim: dim)
                    } else {
                        DepthStackPushView_InteractiveDriver(dim: dim)
                    }
                }
                .frame(width: size.width, height: size.height)
            }
            .frame(width: size.width, height: size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }
}

// MARK: - DepthStackPushView_Deck model

private enum DepthStackPushView_Deck {
    /// Number of cards in the stack.
    static let count = 5

    /// Period of one full auto-advance in the demo loop (~3.5s, within 2.5–4s).
    static let demoPeriod: Double = 3.5

    /// Visual palette — distinct hues so the layered depth reads clearly.
    static let palette: [DepthStackPushView_DeckPalette] = [
        DepthStackPushView_DeckPalette(top: Color(red: 0.36, green: 0.56, blue: 0.98),
                    bottom: Color(red: 0.20, green: 0.32, blue: 0.78)),
        DepthStackPushView_DeckPalette(top: Color(red: 0.96, green: 0.46, blue: 0.62),
                    bottom: Color(red: 0.76, green: 0.24, blue: 0.46)),
        DepthStackPushView_DeckPalette(top: Color(red: 0.40, green: 0.82, blue: 0.70),
                    bottom: Color(red: 0.16, green: 0.56, blue: 0.52)),
        DepthStackPushView_DeckPalette(top: Color(red: 0.98, green: 0.74, blue: 0.38),
                    bottom: Color(red: 0.86, green: 0.50, blue: 0.18)),
        DepthStackPushView_DeckPalette(top: Color(red: 0.70, green: 0.56, blue: 0.96),
                    bottom: Color(red: 0.46, green: 0.32, blue: 0.80))
    ]

    /// Relative depth of `index` given the integer `front` card.
    /// 0 == focused, larger == deeper. `front` MUST be an integer — the modulo
    /// has a discontinuity at each crossing, so fractional fronts would teleport
    /// the focused card to the back.
    static func relativeDepth(index: Int, front: Int) -> Int {
        let raw = (index - front) % count
        return raw < 0 ? raw + count : raw
    }

    /// Visual attributes for a card at a given (possibly fractional) depth.
    /// Everything scales off the tile's smallest dimension so it renders the
    /// same in a 120pt grid tile and a large detail area.
    static func attributes(forDepth depth: CGFloat, dim: CGFloat) -> DepthStackPushView_CardAttributes {
        let d = max(0, depth)
        let scale: CGFloat = 1.0 - 0.085 * d
        let yOffset: CGFloat = -d * dim * 0.062
        let blur: CGFloat = min(d * dim * 0.012, dim * 0.05)
        // Floor the deepest opacity so no frame is ever blank.
        let fade: CGFloat = 1.0 - 0.18 * d
        let opacity: CGFloat = max(0.32, min(1.0, fade))
        return DepthStackPushView_CardAttributes(scale: max(0.4, scale),
                              yOffset: yOffset,
                              blur: blur,
                              opacity: opacity)
    }

    static func lerp(_ a: DepthStackPushView_CardAttributes, _ b: DepthStackPushView_CardAttributes, _ t: CGFloat) -> DepthStackPushView_CardAttributes {
        let k = max(0, min(1, t))
        return DepthStackPushView_CardAttributes(
            scale: a.scale + (b.scale - a.scale) * k,
            yOffset: a.yOffset + (b.yOffset - a.yOffset) * k,
            blur: a.blur + (b.blur - a.blur) * k,
            opacity: a.opacity + (b.opacity - a.opacity) * k
        )
    }
}

private struct DepthStackPushView_DeckPalette {
    let top: Color
    let bottom: Color
}

private struct DepthStackPushView_CardAttributes {
    var scale: CGFloat
    var yOffset: CGFloat
    var blur: CGFloat
    var opacity: CGFloat
}

// MARK: - Shared renderer

/// Renders the whole deck for a given integer `front` plus a 0→1 `fraction`
/// toward the next front. Used by both the demo and interactive drivers.
private struct DepthStackPushView_DeckLayer: View {
    let front: Int
    let fraction: CGFloat
    let dim: CGFloat

    var body: some View {
        ZStack {
            ForEach(0..<DepthStackPushView_Deck.count, id: \.self) { index in
                card(index: index)
            }
        }
    }

    private func card(index: Int) -> some View {
        let relNow = DepthStackPushView_Deck.relativeDepth(index: index, front: front)
        let relNext = DepthStackPushView_Deck.relativeDepth(index: index, front: front + 1)
        let attrsNow = DepthStackPushView_Deck.attributes(forDepth: CGFloat(relNow), dim: dim)
        let attrsNext = DepthStackPushView_Deck.attributes(forDepth: CGFloat(relNext), dim: dim)
        let attrs = DepthStackPushView_Deck.lerp(attrsNow, attrsNext, fraction)

        return DepthStackPushView_DepthCard(palette: DepthStackPushView_Deck.palette[index],
                         label: "0\(index + 1)",
                         attributes: attrs,
                         dim: dim)
            // zIndex from the INTEGER front: the leaving card keeps its high z
            // through the whole transition and only drops behind the deck at
            // the integer crossing, when it has already shrunk — masking the
            // (non-animatable) z snap.
            .zIndex(Double(DepthStackPushView_Deck.count - relNow))
    }
}

// MARK: - Demo driver (self-driving loop)

private struct DepthStackPushView_DemoDriver: View {
    let dim: CGFloat

    var body: some View {
        TimelineView(.animation) { context in
            let progress = context.date.timeIntervalSinceReferenceDate / DepthStackPushView_Deck.demoPeriod
            let wrapped = progress - floor(progress / Double(DepthStackPushView_Deck.count)) * Double(DepthStackPushView_Deck.count)
            let front = Int(wrapped) % DepthStackPushView_Deck.count
            let fraction = CGFloat(eased(wrapped - floor(wrapped)))
            DepthStackPushView_DeckLayer(front: front, fraction: fraction, dim: dim)
        }
    }

    /// Smoothstep so each auto-advance accelerates and settles instead of
    /// sliding linearly — gives the shuffle a tactile, physical cadence.
    private func eased(_ t: Double) -> Double {
        let x = max(0, min(1, t))
        return x * x * (3 - 2 * x)
    }
}

// MARK: - Interactive driver

private struct DepthStackPushView_InteractiveDriver: View {
    let dim: CGFloat

    @State private var committedFront: Int = 0
    @State private var dragFraction: CGFloat = 0
    @State private var commitTick: Int = 0

    var body: some View {
        DepthStackPushView_DeckLayer(front: committedFront, fraction: dragFraction, dim: dim)
            .contentShape(Rectangle())
            .gesture(pushGesture)
            .sensoryFeedback(.selection, trigger: commitTick)
    }

    private var pushGesture: some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                let travel = max(dim, 1)
                // Forward-only push: a leftward drag advances the deck.
                let raw = -value.translation.width / travel
                dragFraction = max(0, min(1, raw))
            }
            .onEnded { value in
                let travel = max(dim, 1)
                let predicted = -value.predictedEndTranslation.width / travel
                let current = -value.translation.width / travel
                let shouldCommit = current > 0.5 || predicted > 0.85

                if shouldCommit {
                    commitTick += 1
                    withAnimation(.interactiveSpring(response: 0.42,
                                                     dampingFraction: 0.78,
                                                     blendDuration: 0.25)) {
                        dragFraction = 1
                    } completion: {
                        // Re-base on the next integer front. Attributes are
                        // identical before/after (fraction 1 @ front == fraction
                        // 0 @ front+1), so the swap is seamless.
                        committedFront = (committedFront + 1) % DepthStackPushView_Deck.count
                        dragFraction = 0
                    }
                } else {
                    withAnimation(.spring(response: 0.4, dampingFraction: 0.8)) {
                        dragFraction = 0
                    }
                }
            }
    }
}

// MARK: - Card

private struct DepthStackPushView_DepthCard: View {
    let palette: DepthStackPushView_DeckPalette
    let label: String
    let attributes: DepthStackPushView_CardAttributes
    let dim: CGFloat

    var body: some View {
        let corner = dim * 0.09
        RoundedRectangle(cornerRadius: corner, style: .continuous)
            .fill(
                LinearGradient(colors: [palette.top, palette.bottom],
                               startPoint: .topLeading,
                               endPoint: .bottomTrailing)
            )
            .overlay(sheen(corner: corner))
            .overlay(content(corner: corner))
            .overlay(
                RoundedRectangle(cornerRadius: corner, style: .continuous)
                    .strokeBorder(Color.white.opacity(0.16), lineWidth: max(0.5, dim * 0.006))
            )
            .frame(width: dim * 0.62, height: dim * 0.78)
            .shadow(color: Color.black.opacity(0.32),
                    radius: dim * 0.05,
                    x: 0,
                    y: dim * 0.03)
            .scaleEffect(attributes.scale)
            .offset(y: attributes.yOffset)
            .blur(radius: attributes.blur)
            .opacity(attributes.opacity)
    }

    private func sheen(corner: CGFloat) -> some View {
        RoundedRectangle(cornerRadius: corner, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [Color.white.opacity(0.28), Color.clear],
                    startPoint: .top,
                    endPoint: .center
                )
            )
            .blendMode(.softLight)
    }

    private func content(corner: CGFloat) -> some View {
        VStack(alignment: .leading, spacing: dim * 0.03) {
            Capsule()
                .fill(Color.white.opacity(0.85))
                .frame(width: dim * 0.16, height: max(2, dim * 0.018))
            Spacer(minLength: 0)
            Text(label)
                .font(.system(size: dim * 0.16, weight: .bold, design: .rounded))
                .foregroundColor(Color.white.opacity(0.92))
            Capsule()
                .fill(Color.white.opacity(0.45))
                .frame(width: dim * 0.30, height: max(2, dim * 0.016))
        }
        .padding(dim * 0.06)
        .frame(maxWidth: .infinity, maxHeight: .infinity, alignment: .topLeading)
    }
}

// MARK: - DepthStackPushView_Background

private struct DepthStackPushView_Background: View {
    var body: some View {
        LinearGradient(
            colors: [Color(red: 0.07, green: 0.08, blue: 0.12),
                     Color(red: 0.03, green: 0.04, blue: 0.07)],
            startPoint: .top,
            endPoint: .bottom
        )
        .ignoresSafeArea()
    }
}
"""###,
        "tr-drawer-cascade": ###"""
import SwiftUI

/// Drawer Cascade — stacked horizontal drawer panels slide open sequentially from a
/// closed cabinet, each sliding out further than the last with deepening drop-shadows,
/// the open drawers revealing the destination content behind them.
///
/// - demo == true:  self-driving loop. A TimelineView(.animation) walks a continuous
///   0→1→0 triangle wave; each drawer reads a staggered sub-range of that progress so
///   the cascade pulls out one after another, then retracts, forever. Never blank.
/// - demo == false: real interactive component. An onTapGesture toggles `isOpen`, and
///   each panel carries its own `.delay(index * stagger)` spring so the open animation
///   genuinely cascades down the stack.
struct DrawerCascadeView: View {
    var demo: Bool = false

    private let drawerCount: Int = 5

    var body: some View {
        GeometryReader { geo in
            content(size: geo.size)
                .frame(width: geo.size.width, height: geo.size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    @ViewBuilder
    private func content(size: CGSize) -> some View {
        if demo {
            DrawerCascadeView_DemoCabinet(size: size, drawerCount: drawerCount)
        } else {
            DrawerCascadeView_InteractiveCabinet(size: size, drawerCount: drawerCount)
        }
    }
}

// MARK: - Demo (self-driving)

private struct DrawerCascadeView_DemoCabinet: View {
    let size: CGSize
    let drawerCount: Int

    private let loop: Double = 3.2

    var body: some View {
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            let phase = (t.truncatingRemainder(dividingBy: loop)) / loop
            // Smooth 0→1→0 triangle, eased so the ends linger (drawers fully out / fully in).
            let raw = triangle(phase)
            let p = ease(raw)
            DrawerCascadeView_Cabinet(size: size, drawerCount: drawerCount) { index in
                staggeredProgress(globalProgress: p, index: index)
            }
        }
    }

    /// Triangle wave 0→1→0 over a unit phase.
    private func triangle(_ x: Double) -> Double {
        x < 0.5 ? x * 2.0 : (1.0 - x) * 2.0
    }

    /// Smoothstep easing so motion settles at both ends.
    private func ease(_ x: Double) -> Double {
        let c = min(max(x, 0.0), 1.0)
        return c * c * (3.0 - 2.0 * c)
    }

    /// Map the single global progress to a per-drawer sub-range so each drawer leads
    /// the one above it — the cascade.
    private func staggeredProgress(globalProgress p: Double, index: Int) -> Double {
        let stagger: Double = 0.10
        let window: Double = 1.0 - stagger * Double(max(drawerCount - 1, 1))
        let start = Double(index) * stagger
        let local = (p - start) / max(window, 0.0001)
        return min(max(local, 0.0), 1.0)
    }
}

// MARK: - Interactive (tap to toggle)

private struct DrawerCascadeView_InteractiveCabinet: View {
    let size: CGSize
    let drawerCount: Int

    @State private var isOpen: Bool = false

    var body: some View {
        DrawerCascadeView_Cabinet(size: size, drawerCount: drawerCount, perDrawerDelay: { index in
            // Top drawer leads; lower drawers follow. This is what gives the cascade
            // under a single isOpen toggle (the spring delay differs per panel).
            Double(index) * 0.075
        }, targetProgress: { _ in
            isOpen ? 1.0 : 0.0
        })
        .contentShape(Rectangle())
        .onTapGesture {
            isOpen.toggle()
        }
    }
}

// MARK: - Shared cabinet + drawer stack

private struct DrawerCascadeView_Cabinet: View {
    let size: CGSize
    let drawerCount: Int

    /// Demo path: continuous progress already computed per index.
    var demoProgress: ((Int) -> Double)? = nil

    /// Interactive path: a per-index spring delay + a target (0/1) the panel animates toward.
    var perDrawerDelay: ((Int) -> Double)? = nil
    var targetProgress: ((Int) -> Double)? = nil

    init(size: CGSize,
         drawerCount: Int,
         demoProgress: @escaping (Int) -> Double) {
        self.size = size
        self.drawerCount = drawerCount
        self.demoProgress = demoProgress
    }

    init(size: CGSize,
         drawerCount: Int,
         perDrawerDelay: @escaping (Int) -> Double,
         targetProgress: @escaping (Int) -> Double) {
        self.size = size
        self.drawerCount = drawerCount
        self.perDrawerDelay = perDrawerDelay
        self.targetProgress = targetProgress
    }

    private var inset: CGFloat { size.width * 0.10 }
    private var cabinetWidth: CGFloat { size.width - inset * 2 }
    private var cabinetHeight: CGFloat { size.height - inset * 2 }
    private var corner: CGFloat { max(size.width * 0.06, 6) }

    private var slotGap: CGFloat { cabinetHeight * 0.04 }
    private var drawerHeight: CGFloat {
        let gaps = slotGap * CGFloat(drawerCount + 1)
        return (cabinetHeight - gaps) / CGFloat(drawerCount)
    }
    private var drawerWidth: CGFloat { cabinetWidth * 0.82 }

    /// Maximum horizontal pull for a given index — lower drawers pull further.
    private func maxPull(for index: Int) -> CGFloat {
        let base = cabinetWidth * 0.16
        let step = cabinetWidth * 0.052
        return base + step * CGFloat(index)
    }

    var body: some View {
        ZStack {
            DrawerCascadeView_CabinetShell(corner: corner)
                .frame(width: cabinetWidth, height: cabinetHeight)

            DrawerCascadeView_DrawerColumn(
                size: size,
                drawerCount: drawerCount,
                drawerWidth: drawerWidth,
                drawerHeight: drawerHeight,
                slotGap: slotGap,
                cabinetHeight: cabinetHeight,
                corner: corner * 0.7,
                maxPull: maxPull,
                demoProgress: demoProgress,
                perDrawerDelay: perDrawerDelay,
                targetProgress: targetProgress
            )
            .frame(width: cabinetWidth, height: cabinetHeight)
        }
        .frame(width: size.width, height: size.height)
    }
}

private struct DrawerCascadeView_CabinetShell: View {
    let corner: CGFloat

    private var bodyColor: Color { Color(red: 0.10, green: 0.12, blue: 0.17) }
    private var frameTop: Color { Color(red: 0.18, green: 0.21, blue: 0.28) }
    private var frameBottom: Color { Color(red: 0.07, green: 0.08, blue: 0.12) }

    var body: some View {
        ZStack {
            RoundedRectangle(cornerRadius: corner, style: .continuous)
                .fill(
                    LinearGradient(
                        colors: [frameTop, frameBottom],
                        startPoint: .top,
                        endPoint: .bottom
                    )
                )
            RoundedRectangle(cornerRadius: corner, style: .continuous)
                .strokeBorder(Color(red: 0.30, green: 0.34, blue: 0.44).opacity(0.7),
                              lineWidth: 1)
            // Interior cavity — the dark space the drawers reveal.
            RoundedRectangle(cornerRadius: corner * 0.8, style: .continuous)
                .fill(bodyColor)
                .padding(corner * 0.55)
        }
    }
}

private struct DrawerCascadeView_DrawerColumn: View {
    let size: CGSize
    let drawerCount: Int
    let drawerWidth: CGFloat
    let drawerHeight: CGFloat
    let slotGap: CGFloat
    let cabinetHeight: CGFloat
    let corner: CGFloat
    let maxPull: (Int) -> CGFloat

    var demoProgress: ((Int) -> Double)?
    var perDrawerDelay: ((Int) -> Double)?
    var targetProgress: ((Int) -> Double)?

    var body: some View {
        // Top drawer (index 0) is highest in the stack; deeper drawers (higher index)
        // are drawn later so they layer above when pulled — biggest shadow on top.
        ZStack {
            ForEach(0..<drawerCount, id: \.self) { index in
                panel(index: index)
            }
        }
        .frame(width: drawerWidth, height: cabinetHeight, alignment: .center)
    }

    private func yOffset(for index: Int) -> CGFloat {
        let totalDrawerSpan = drawerHeight * CGFloat(drawerCount)
            + slotGap * CGFloat(drawerCount - 1)
        let top = -totalDrawerSpan / 2 + drawerHeight / 2
        return top + CGFloat(index) * (drawerHeight + slotGap)
    }

    @ViewBuilder
    private func panel(index: Int) -> some View {
        let reveal = DrawerCascadeView_RevealSlot(
            width: drawerWidth,
            height: drawerHeight,
            corner: corner
        )
        .offset(y: yOffset(for: index))

        let drawer = drawerView(index: index)

        ZStack {
            reveal
            drawer
        }
    }

    @ViewBuilder
    private func drawerView(index: Int) -> some View {
        if let demoProgress {
            let p = CGFloat(demoProgress(index))
            DrawerCascadeView_DrawerPanel(
                index: index,
                width: drawerWidth,
                height: drawerHeight,
                corner: corner,
                pull: maxPull(index) * p,
                openness: p
            )
            .offset(y: yOffset(for: index))
        } else if let target = targetProgress, let delay = perDrawerDelay {
            DrawerCascadeView_AnimatedDrawer(
                index: index,
                width: drawerWidth,
                height: drawerHeight,
                corner: corner,
                maxPull: maxPull(index),
                yOffset: yOffset(for: index),
                target: CGFloat(target(index)),
                delay: delay(index)
            )
        }
    }
}

/// Interactive wrapper: animates its own progress toward `target` with a per-index
/// spring delay so a single isOpen toggle still cascades.
private struct DrawerCascadeView_AnimatedDrawer: View {
    let index: Int
    let width: CGFloat
    let height: CGFloat
    let corner: CGFloat
    let maxPull: CGFloat
    let yOffset: CGFloat
    let target: CGFloat
    let delay: Double

    var body: some View {
        DrawerCascadeView_DrawerPanel(
            index: index,
            width: width,
            height: height,
            corner: corner,
            pull: maxPull * target,
            openness: target
        )
        .offset(y: yOffset)
        .animation(
            .spring(response: 0.55, dampingFraction: 0.76).delay(delay),
            value: target
        )
    }
}

/// The dark recessed slot a drawer sits in; visible (revealed) once the drawer slides out.
private struct DrawerCascadeView_RevealSlot: View {
    let width: CGFloat
    let height: CGFloat
    let corner: CGFloat

    var body: some View {
        RoundedRectangle(cornerRadius: corner, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.05, green: 0.06, blue: 0.09),
                        Color(red: 0.02, green: 0.02, blue: 0.04)
                    ],
                    startPoint: .top,
                    endPoint: .bottom
                )
            )
            .overlay(
                // A hint of "contents" inside the cabinet behind the drawer.
                RoundedRectangle(cornerRadius: corner * 0.7, style: .continuous)
                    .fill(Color(red: 0.16, green: 0.45, blue: 0.62).opacity(0.28))
                    .padding(.horizontal, width * 0.06)
                    .padding(.vertical, height * 0.22)
            )
            .frame(width: width, height: height)
    }
}

/// One drawer face. `pull` is the horizontal slide-out distance (always >= 0),
/// `openness` (0…1) drives shadow depth, handle highlight, and edge shading.
private struct DrawerCascadeView_DrawerPanel: View {
    let index: Int
    let width: CGFloat
    let height: CGFloat
    let corner: CGFloat
    let pull: CGFloat
    let openness: CGFloat

    private var faceTop: Color { Color(red: 0.34, green: 0.40, blue: 0.52) }
    private var faceBottom: Color { Color(red: 0.20, green: 0.24, blue: 0.33) }
    private var edgeColor: Color { Color(red: 0.46, green: 0.53, blue: 0.66) }

    // Deeper drawers cast heavier shadows; the pull amount deepens it further.
    private var shadowRadius: CGFloat {
        let base: CGFloat = 1.5
        let perIndex: CGFloat = 1.4
        let perOpen: CGFloat = 9.0
        return base + perIndex * CGFloat(index) + perOpen * openness
    }

    private var shadowYOffset: CGFloat {
        2.0 + 4.0 * openness + CGFloat(index)
    }

    var body: some View {
        RoundedRectangle(cornerRadius: corner, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [faceTop, faceBottom],
                    startPoint: .top,
                    endPoint: .bottom
                )
            )
            .overlay(topSheen)
            .overlay(handle)
            .overlay(leadingEdge)
            .overlay(
                RoundedRectangle(cornerRadius: corner, style: .continuous)
                    .strokeBorder(edgeColor.opacity(0.55), lineWidth: 0.8)
            )
            .frame(width: width, height: height)
            .shadow(
                color: Color.black.opacity(0.35 + 0.30 * Double(openness)),
                radius: shadowRadius,
                x: -shadowRadius * 0.35,
                y: shadowYOffset
            )
            .offset(x: pull)
    }

    // Soft highlight across the top of the drawer face.
    private var topSheen: some View {
        RoundedRectangle(cornerRadius: corner, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color.white.opacity(0.18),
                        Color.white.opacity(0.0)
                    ],
                    startPoint: .top,
                    endPoint: .center
                )
            )
    }

    // Pill handle, centered; brightens slightly as the drawer opens.
    private var handle: some View {
        Capsule(style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.62, green: 0.70, blue: 0.84)
                            .opacity(0.75 + 0.25 * Double(openness)),
                        Color(red: 0.30, green: 0.36, blue: 0.47)
                    ],
                    startPoint: .top,
                    endPoint: .bottom
                )
            )
            .frame(width: width * 0.30, height: max(height * 0.16, 3))
            .overlay(
                Capsule(style: .continuous)
                    .strokeBorder(Color.white.opacity(0.30), lineWidth: 0.6)
            )
    }

    // The leading (right) edge picks up a brighter rim as it emerges from the cabinet.
    private var leadingEdge: some View {
        HStack {
            Spacer()
            RoundedRectangle(cornerRadius: corner * 0.5, style: .continuous)
                .fill(
                    LinearGradient(
                        colors: [
                            edgeColor.opacity(0.0),
                            edgeColor.opacity(0.55 * Double(openness) + 0.10)
                        ],
                        startPoint: .leading,
                        endPoint: .trailing
                    )
                )
                .frame(width: width * 0.10)
        }
        .padding(2)
    }
}
"""###,
        "tr-fan-deck": ###"""
import SwiftUI

/// Fan Deck — a stack of cards fans out radially like a held hand of playing
/// cards, then collapses back into a single stack centered on the chosen card.
///
/// `demo == true`  → a PhaseAnimator self-drives the fan progress 0→1→0 on a
///                   ~3s loop so the tile looks alive with no touch.
/// `demo == false` → tap the deck to fan it out; tap any fanned card to
///                   recollapse the stack centered on that card.
struct FanDeckView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { geo in
            ZStack {
                backdrop
                content(in: geo.size)
            }
            .frame(maxWidth: .infinity, maxHeight: .infinity)
        }
    }

    // MARK: - Content router

    @ViewBuilder
    private func content(in size: CGSize) -> some View {
        if demo {
            FanDeckView_DemoFan(size: size)
        } else {
            FanDeckView_InteractiveFan(size: size)
        }
    }

    private var backdrop: some View {
        RoundedRectangle(cornerRadius: 22, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.07, green: 0.08, blue: 0.12),
                        Color(red: 0.04, green: 0.05, blue: 0.08)
                    ],
                    startPoint: .top,
                    endPoint: .bottom
                )
            )
    }
}

// MARK: - Demo (self-driving loop)

private struct FanDeckView_DemoFan: View {
    let size: CGSize

    var body: some View {
        PhaseAnimator([0.0, 1.0]) { progress in
            FanDeckView_FanLayout(progress: progress, centerIndex: FanDeckView_FanConfig.centerDefault, size: size)
        } animation: { _ in
            // Slow, bouncy spring so each phase snaps then dwells: ~3s cycle.
            .spring(response: 0.95, dampingFraction: 0.55)
        }
    }
}

// MARK: - Interactive (tap to fan / tap card to recollapse)

private struct FanDeckView_InteractiveFan: View {
    let size: CGSize

    @State private var fanned: Bool = false
    @State private var centerIndex: Int = FanDeckView_FanConfig.centerDefault
    @State private var frontIndex: Int = FanDeckView_FanConfig.centerDefault

    var body: some View {
        FanDeckView_FanLayout(
            progress: fanned ? 1.0 : 0.0,
            centerIndex: centerIndex,
            frontIndex: frontIndex,
            size: size,
            onTapCard: handleTap(_:)
        )
        .contentShape(Rectangle())
        .onTapGesture { toggleFan() }
        .animation(.spring(response: 0.5, dampingFraction: 0.62), value: fanned)
        .animation(.spring(response: 0.5, dampingFraction: 0.62), value: centerIndex)
        .sensoryFeedback(.impact(weight: .light), trigger: fanned)
    }

    private func toggleFan() {
        fanned.toggle()
    }

    private func handleTap(_ index: Int) {
        if fanned {
            // Recollapse centered on the chosen card; raise it to the front
            // first so it collapses to the top of the deck (never hidden).
            frontIndex = index
            centerIndex = index
            fanned = false
        } else {
            fanned = true
        }
    }
}

// MARK: - Shared renderer

/// Single layout used identically by both modes. Only the *source* of
/// `progress` differs, so demo and interactive always look the same.
private struct FanDeckView_FanLayout: View {
    let progress: CGFloat
    let centerIndex: Int
    var frontIndex: Int = FanDeckView_FanConfig.centerDefault
    let size: CGSize
    var onTapCard: ((Int) -> Void)? = nil

    var body: some View {
        let metrics = FanDeckView_FanMetrics(size: size)
        ZStack {
            ForEach(0..<FanDeckView_FanConfig.count, id: \.self) { i in
                card(i, metrics: metrics)
            }
        }
        .frame(width: size.width, height: size.height)
    }

    @ViewBuilder
    private func card(_ i: Int, metrics: FanDeckView_FanMetrics) -> some View {
        FanDeckView_CardFace(index: i, size: metrics.card)
            // Pivot every card about the SAME low point so tops spread in an
            // arc while bottoms stay pinned — a true fan, not a scale.
            .rotationEffect(.degrees(angle(for: i)), anchor: metrics.pivotAnchor)
            // Residual non-progress offset keeps the collapsed state reading
            // as a layered deck rather than one flat card.
            .offset(y: residualOffset(for: i))
            .offset(y: metrics.pivotLift)
            .zIndex(zIndex(for: i))
            .contentShape(Rectangle())
            .onTapGesture { onTapCard?(i) }
    }

    // Single source of truth for the angle. centerIndex stays upright; the
    // fan is symmetric around it; progress→0 brings every card back to rest.
    private func angle(for i: Int) -> Double {
        let spread = CGFloat(i - centerIndex) * FanDeckView_FanConfig.perCardDegrees
        let floor = CGFloat(i - centerIndex) * FanDeckView_FanConfig.collapsedDegrees
        let value = floor + (spread - floor) * progress
        return Double(value)
    }

    private func residualOffset(for i: Int) -> CGFloat {
        CGFloat(i - centerIndex) * FanDeckView_FanConfig.deckStep
    }

    private func zIndex(for i: Int) -> Double {
        if i == frontIndex { return 100 }
        // Cards nearer the chosen center sit higher in the deck.
        return Double(FanDeckView_FanConfig.count - abs(i - centerIndex))
    }
}

// MARK: - Geometry

private struct FanDeckView_FanConfig {
    static let count: Int = 5
    static let centerDefault: Int = 2
    static let perCardDegrees: CGFloat = 15   // fanned spread per card
    static let collapsedDegrees: CGFloat = 1.4 // residual tilt when stacked
    static let deckStep: CGFloat = 1.6        // residual y-step when stacked
}

private struct FanDeckView_FanMetrics {
    let card: CGSize
    let pivotLift: CGFloat
    let pivotAnchor: UnitPoint

    init(size: CGSize) {
        let minSide = min(size.width, size.height)
        let h = max(40, minSide * 0.55)
        let w = h * 0.66
        card = CGSize(width: w, height: h)
        // Anchor low on the card and lift the whole stack down a touch so the
        // fanned arc stays inside a near-square tile (no parent clipping).
        pivotAnchor = UnitPoint(x: 0.5, y: 0.92)
        pivotLift = minSide * 0.10
    }
}

// MARK: - Card face

private struct FanDeckView_CardFace: View {
    let index: Int
    let size: CGSize

    var body: some View {
        RoundedRectangle(cornerRadius: cornerRadius, style: .continuous)
            .fill(faceGradient)
            .overlay(border)
            .overlay(pip)
            .frame(width: size.width, height: size.height)
            .shadow(color: Color.black.opacity(0.35), radius: 6, x: 0, y: 3)
    }

    private var cornerRadius: CGFloat { max(6, size.width * 0.12) }

    private var faceGradient: LinearGradient {
        LinearGradient(
            colors: [topTint, bottomTint],
            startPoint: .topLeading,
            endPoint: .bottomTrailing
        )
    }

    private var topTint: Color {
        Color(red: 0.99, green: 0.98, blue: 0.96)
    }

    private var bottomTint: Color {
        // Subtle per-card hue variation so the fan reads as distinct cards.
        let t = Double(index) / Double(max(1, FanDeckView_FanConfig.count - 1))
        let r = 0.90 - 0.04 * t
        let g = 0.92 - 0.10 * t
        let b = 0.98 - 0.02 * t
        return Color(red: r, green: g, blue: b)
    }

    private var border: some View {
        RoundedRectangle(cornerRadius: cornerRadius, style: .continuous)
            .strokeBorder(Color.black.opacity(0.12), lineWidth: 1)
    }

    private var pip: some View {
        // A small colored suit pip in the upper-left corner per card.
        Circle()
            .fill(pipColor)
            .frame(width: size.width * 0.16, height: size.width * 0.16)
            .padding(size.width * 0.14)
            .frame(maxWidth: .infinity, maxHeight: .infinity, alignment: .topLeading)
    }

    private var pipColor: Color {
        let palette: [Color] = [
            Color(red: 0.85, green: 0.22, blue: 0.28),
            Color(red: 0.18, green: 0.20, blue: 0.24),
            Color(red: 0.90, green: 0.55, blue: 0.16),
            Color(red: 0.20, green: 0.52, blue: 0.74),
            Color(red: 0.36, green: 0.62, blue: 0.34)
        ]
        return palette[index % palette.count]
    }
}
"""###,
        "tr-flip-book": ###"""
import SwiftUI

// Flip FlipBookView_Book — pages riffle past in book style with motion blur on the
// turning leaf, landing on a target page. Drag scrubs the flip-through at
// any speed; release springs to the nearest whole page. The demo flavor
// auto-riffles forward then back on a loop.
//
// Mechanism: a stack of pages with the top turning leaf using
// rotation3DEffect about the spine (.y axis, leading anchor) with
// perspective. A continuous `progress` value selects which leaf turns
// (floor) and how far (fractional part). Blur scales with turn speed for
// the riffle smear and decays to 0 at rest so the landed page stays crisp.
struct FlipBookView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { geo in
            let size = geo.size
            if demo {
                FlipBookView_AutoRiffleBook(size: size)
            } else {
                FlipBookView_InteractiveBook(size: size)
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }
}

// MARK: - Shared constants

private enum FlipBookView_Book {
    static let pageCount: Int = 7          // leaves you can riffle through
    static let maxBlur: CGFloat = 9        // cap so landed pages read crisp
    static let perspective: CGFloat = 0.42 // rotation3DEffect perspective
}

// MARK: - Demo: self-driving riffle

private struct FlipBookView_AutoRiffleBook: View {
    let size: CGSize

    var body: some View {
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            let driven = Self.riffle(at: t)
            FlipBookView_BookStage(size: size,
                      progress: driven.progress,
                      blur: driven.blur)
        }
    }

    // Eased triangular wave: riffle forward to the last page, then back.
    // Speed → 0 at the turnarounds so a full page is always crisp & legible,
    // and blur peaks mid-riffle for the fast-turn smear.
    private static func riffle(at time: TimeInterval) -> (progress: CGFloat, blur: CGFloat) {
        let loop: Double = 3.4
        let phase = (time.truncatingRemainder(dividingBy: loop)) / loop // 0...1
        // Triangle 0→1→0 with cosine easing for smooth turnarounds.
        let tri = phase < 0.5 ? (phase * 2) : (2 - phase * 2)           // 0..1..0
        let eased = (1 - cos(tri * .pi)) / 2                            // ease in/out
        let maxProgress = CGFloat(FlipBookView_Book.pageCount - 1)
        let progress = CGFloat(eased) * maxProgress

        // Analytic speed of `eased` → blur. Derivative magnitude of the
        // eased triangle is largest at mid-riffle, zero at the ends.
        let speed = abs(sin(tri * .pi))                                  // 0..1..0
        let blur = FlipBookView_Book.maxBlur * CGFloat(speed)
        return (progress, blur)
    }
}

// MARK: - Interactive: drag to scrub, release to spring to a page

private struct FlipBookView_InteractiveBook: View {
    let size: CGSize

    @State private var progress: CGFloat = 0          // committed page-progress
    @State private var dragProgress: CGFloat = 0      // live offset during drag
    @State private var isDragging: Bool = false
    @State private var dragSpeed: CGFloat = 0         // for blur while scrubbing
    @State private var landTick: Int = 0              // sensoryFeedback trigger

    var body: some View {
        let live = clampedProgress(progress + dragProgress)
        let blur = currentBlur()
        FlipBookView_BookStage(size: size, progress: live, blur: blur)
            .contentShape(Rectangle())
            .gesture(scrubGesture)
            .sensoryFeedback(.impact(flexibility: .soft), trigger: landTick)
    }

    private var scrubGesture: some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                isDragging = true
                // Map horizontal drag to leaves; the book width is the natural
                // travel for ~2 page turns, so divide by half-width per leaf.
                let perLeaf = max(size.width, 1) * 0.42
                dragProgress = -value.translation.width / perLeaf
                // Live speed from instantaneous translation → smear while fast.
                let dist = abs(value.translation.width)
                dragSpeed = min(1, dist / (perLeaf * 1.4))
            }
            .onEnded { value in
                isDragging = false
                let perLeaf = max(size.width, 1) * 0.42
                // Coast using predicted end translation, then snap to a page.
                let predicted = -value.predictedEndTranslation.width / perLeaf
                let target = clampedProgress(progress + predicted)
                let landed = (target).rounded()
                dragProgress = 0
                dragSpeed = 0
                withAnimation(.spring(response: 0.5, dampingFraction: 0.72)) {
                    progress = clampedProgress(landed)
                }
                landTick &+= 1
            }
    }

    private func currentBlur() -> CGFloat {
        guard isDragging else { return 0 }      // crisp at rest
        return FlipBookView_Book.maxBlur * dragSpeed
    }

    private func clampedProgress(_ p: CGFloat) -> CGFloat {
        min(max(p, 0), CGFloat(FlipBookView_Book.pageCount - 1))
    }
}

// MARK: - The book stage (shared by demo + interactive)

private struct FlipBookView_BookStage: View {
    let size: CGSize
    let progress: CGFloat   // 0 ... pageCount-1
    let blur: CGFloat       // smear on the turning leaf

    var body: some View {
        // Lay out a book centered in the available space with a small margin.
        let margin: CGFloat = min(size.width, size.height) * 0.10
        let bookW = max(size.width - margin * 2, 1)
        let bookH = max(size.height - margin * 2, 1)
        let leafW = bookW / 2          // each page is half the open spread
        let spineX = bookW / 2         // center of the spread

        ZStack {
            background

            ZStack {
                // Static base: nothing in any frame depends on the turning
                // leaf being visible, so the 90° edge-on instant is never blank.
                rightStack(leafW: leafW, leafH: bookH, spineX: spineX)
                leftStack(leafW: leafW, leafH: bookH, spineX: spineX)
                turningLeaf(leafW: leafW, leafH: bookH, spineX: spineX)
                spine(height: bookH, x: spineX)
            }
            .frame(width: bookW, height: bookH)
            .shadow(color: .black.opacity(0.35), radius: 14, x: 0, y: 10)
        }
        .frame(width: size.width, height: size.height)
    }

    private var currentLeaf: Int { Int(floor(progress)) }
    private var turnFraction: CGFloat { progress - floor(progress) }

    // MARK: Layers

    // The page currently lying flat on the right (the destination once the
    // turning leaf has fully turned). Always visible — keeps frames legible.
    private func rightStack(leafW: CGFloat, leafH: CGFloat, spineX: CGFloat) -> some View {
        let nextIndex = min(currentLeaf + 1, FlipBookView_Book.pageCount - 1)
        return FlipBookView_PageFace(index: nextIndex, isFront: true, leafW: leafW, leafH: leafH)
            .overlay(stackEdges(count: FlipBookView_Book.pageCount - 1 - currentLeaf, trailing: true,
                                leafW: leafW, leafH: leafH))
            .frame(width: leafW, height: leafH, alignment: .leading)
            .position(x: spineX + leafW / 2, y: leafH / 2)
            .zIndex(1)
    }

    // The most recently turned page lying flat on the left.
    private func leftStack(leafW: CGFloat, leafH: CGFloat, spineX: CGFloat) -> some View {
        // When fully on a whole page, the back face of the current leaf is
        // showing. Use the current leaf's back tone as the resting left page.
        let leftIndex = max(currentLeaf, 0)
        return FlipBookView_PageFace(index: leftIndex, isFront: false, leafW: leafW, leafH: leafH)
            .overlay(stackEdges(count: currentLeaf, trailing: false,
                                leafW: leafW, leafH: leafH))
            .frame(width: leafW, height: leafH, alignment: .trailing)
            .position(x: spineX - leafW / 2, y: leafH / 2)
            .zIndex(2)
    }

    // The single in-flight leaf, rotating continuously about the spine
    // (.leading edge) from 0° to 180°. SwiftUI shows the back face mirrored
    // once past 90°; because page identity is hue/shape coded (never text),
    // the mirroring is harmless, so we avoid any fragile un-mirror transform.
    private func turningLeaf(leafW: CGFloat, leafH: CGFloat, spineX: CGFloat) -> some View {
        let angle = Double(turnFraction) * 180.0     // 0 → 180°
        let showingBack = angle > 90.0
        let index = currentLeaf
        let faceShade = abs(cos(Angle(degrees: angle).radians)) // dim near edge-on

        return ZStack {
            if showingBack {
                FlipBookView_PageFace(index: index, isFront: false, leafW: leafW, leafH: leafH)
            } else {
                FlipBookView_PageFace(index: index, isFront: true, leafW: leafW, leafH: leafH)
            }
        }
        .frame(width: leafW, height: leafH)
        // Page-curl shading: the leaf darkens as it approaches edge-on.
        .overlay(Color.black.opacity((1 - faceShade) * 0.28))
        .blur(radius: blur)
        .rotation3DEffect(
            .degrees(angle),
            axis: (x: 0, y: 1, z: 0),
            anchor: .leading,
            perspective: FlipBookView_Book.perspective
        )
        .frame(width: leafW, height: leafH, alignment: .leading)
        .position(x: spineX + leafW / 2, y: leafH / 2)
        .zIndex(10)
    }

    private func spine(height: CGFloat, x: CGFloat) -> some View {
        Rectangle()
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.05, green: 0.05, blue: 0.07),
                        Color(red: 0.16, green: 0.16, blue: 0.20),
                        Color(red: 0.05, green: 0.05, blue: 0.07)
                    ],
                    startPoint: .leading, endPoint: .trailing
                )
            )
            .frame(width: max(height * 0.018, 2), height: height)
            .position(x: x, y: height / 2)
            .zIndex(5)
    }

    // Thin stacked page edges fanning at the cut side to suggest thickness.
    private func stackEdges(count: Int, trailing: Bool, leafW: CGFloat, leafH: CGFloat) -> some View {
        let n = min(max(count, 0), 5)
        return HStack(spacing: 0) {
            if trailing { Spacer(minLength: 0) }
            ZStack {
                ForEach(0..<n, id: \.self) { i in
                    RoundedRectangle(cornerRadius: 1)
                        .fill(Color(red: 0.92, green: 0.90, blue: 0.84))
                        .frame(width: 1.4, height: leafH * 0.97)
                        .offset(x: CGFloat(i) * 1.6 * (trailing ? 1 : -1))
                        .opacity(0.5)
                }
            }
            if !trailing { Spacer(minLength: 0) }
        }
        .allowsHitTesting(false)
    }

    private var background: some View {
        LinearGradient(
            colors: [
                Color(red: 0.05, green: 0.06, blue: 0.09),
                Color(red: 0.09, green: 0.10, blue: 0.15)
            ],
            startPoint: .top, endPoint: .bottom
        )
    }
}

// MARK: - A single page face (hue-coded so identity survives mirroring)

private struct FlipBookView_PageFace: View {
    let index: Int
    let isFront: Bool
    let leafW: CGFloat
    let leafH: CGFloat

    var body: some View {
        ZStack {
            RoundedRectangle(cornerRadius: 4)
                .fill(paperGradient)
            // A simple decorative motif keyed to the page — mirror-safe shapes,
            // never text, so a flipped back face never reads as broken.
            motif
                .padding(leafW * 0.14)
            // Inner shadow toward the spine to seat the page in the gutter.
            gutterShade
        }
        .clipShape(RoundedRectangle(cornerRadius: 4))
        .overlay(
            RoundedRectangle(cornerRadius: 4)
                .stroke(Color.black.opacity(0.10), lineWidth: 0.5)
        )
    }

    // Each page gets a distinct hue ramp; the back face is a slightly
    // desaturated, darker version of the same hue so a turn reads continuous.
    private var paperGradient: LinearGradient {
        let base = Self.hue(for: index)
        let top = isFront ? base.opacity(1.0) : base.opacity(0.78)
        let bottom = isFront ? base.opacity(0.82) : base.opacity(0.6)
        return LinearGradient(colors: [top, bottom],
                              startPoint: .topLeading, endPoint: .bottomTrailing)
    }

    private var motif: some View {
        let accent = Self.accent(for: index)
        return GeometryReader { g in
            let s = min(g.size.width, g.size.height)
            ZStack {
                Circle()
                    .fill(accent.opacity(0.16))
                    .frame(width: s * 0.9, height: s * 0.9)
                Capsule()
                    .fill(accent.opacity(0.55))
                    .frame(width: s * 0.62, height: s * 0.10)
                Capsule()
                    .fill(accent.opacity(0.35))
                    .frame(width: s * 0.42, height: s * 0.08)
                    .offset(y: s * 0.20)
                Capsule()
                    .fill(accent.opacity(0.35))
                    .frame(width: s * 0.42, height: s * 0.08)
                    .offset(y: -s * 0.20)
            }
            .frame(width: g.size.width, height: g.size.height)
        }
    }

    private var gutterShade: some View {
        LinearGradient(
            colors: [Color.black.opacity(0.22), .clear],
            startPoint: isFront ? .leading : .trailing,
            endPoint: isFront ? .trailing : .leading
        )
        .blendMode(.multiply)
        .allowsHitTesting(false)
    }

    // Warm paper tones cycling through a pleasant book palette.
    static func hue(for index: Int) -> Color {
        let palette: [Color] = [
            Color(red: 0.97, green: 0.95, blue: 0.90),
            Color(red: 0.96, green: 0.92, blue: 0.86),
            Color(red: 0.93, green: 0.94, blue: 0.97),
            Color(red: 0.95, green: 0.90, blue: 0.92),
            Color(red: 0.90, green: 0.95, blue: 0.93),
            Color(red: 0.97, green: 0.93, blue: 0.85),
            Color(red: 0.91, green: 0.93, blue: 0.96)
        ]
        let i = ((index % palette.count) + palette.count) % palette.count
        return palette[i]
    }

    static func accent(for index: Int) -> Color {
        let palette: [Color] = [
            Color(red: 0.83, green: 0.42, blue: 0.30),
            Color(red: 0.86, green: 0.62, blue: 0.24),
            Color(red: 0.30, green: 0.52, blue: 0.80),
            Color(red: 0.74, green: 0.34, blue: 0.55),
            Color(red: 0.26, green: 0.62, blue: 0.52),
            Color(red: 0.78, green: 0.50, blue: 0.22),
            Color(red: 0.38, green: 0.46, blue: 0.78)
        ]
        let i = ((index % palette.count) + palette.count) % palette.count
        return palette[i]
    }
}
"""###,
        "tr-fold-accordion": ###"""
import SwiftUI

/// Fold-Down Accordion
///
/// Stacked list rows concertina-collapse along shared horizontal hinges. Each row
/// folds flat (rotation3DEffect about its top edge on the .x axis with a perspective
/// anchor) while its layout slot shrinks, so the whole stack compresses up into a
/// single always-visible header. A per-row darkening LinearGradient hinge overlay
/// fades in at each crease so the collapse reads as one continuous folding ribbon.
///
/// - demo == true:  a PhaseAnimator auto-cycles the collapse progress 0->1->0 so the
///                  rows concertina shut into the header then unfold continuously.
/// - demo == false: tapping the header toggles `collapsed`, driving the collapse via
///                  withAnimation(.spring); per-row hinge angles interpolate from the
///                  single progress with staggered offsets.
struct FoldAccordionView: View {
    var demo: Bool = false

    @State private var collapsed: Bool = false

    private let rowCount: Int = 5

    var body: some View {
        GeometryReader { geo in
            content(size: geo.size)
                .frame(maxWidth: .infinity, maxHeight: .infinity)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    @ViewBuilder
    private func content(size: CGSize) -> some View {
        if demo {
            PhaseAnimator([0.0, 1.0]) { phase in
                accordion(progress: CGFloat(phase), size: size)
            } animation: { _ in
                .easeInOut(duration: 1.6)
            }
        } else {
            accordion(progress: collapsed ? 1 : 0, size: size)
        }
    }

    // MARK: - Layout

    private func accordion(progress: CGFloat, size: CGSize) -> some View {
        let metrics = layoutMetrics(for: size)
        return VStack(spacing: metrics.gap) {
            ForEach(0..<rowCount, id: \.self) { index in
                row(index: index, progress: progress, metrics: metrics)
            }
            header(progress: progress, metrics: metrics)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity, alignment: .top)
        .padding(.horizontal, metrics.sidePadding)
        .padding(.vertical, metrics.sidePadding)
        .contentShape(Rectangle())
    }

    struct Metrics {
        var rowHeight: CGFloat
        var headerHeight: CGFloat
        var gap: CGFloat
        var corner: CGFloat
        var sidePadding: CGFloat
        var fontSize: CGFloat
    }

    private func layoutMetrics(for size: CGSize) -> Metrics {
        let minSide = min(size.width, size.height)
        let scale = minSide / 120.0
        let pad = max(4.0, 6.0 * scale)
        let usableHeight = max(40.0, size.height - pad * 2)
        // Reserve a share for the header; rows split the remainder.
        let headerH = usableHeight * 0.20
        let gap = max(1.0, 1.5 * scale)
        let totalGap = gap * CGFloat(rowCount)
        let rowsH = distributedRowHeight(count: rowCount, available: usableHeight - headerH - totalGap)
        return Metrics(
            rowHeight: rowsH,
            headerHeight: headerH,
            gap: gap,
            corner: max(3.0, 6.0 * scale),
            sidePadding: pad,
            fontSize: max(7.0, 9.0 * scale)
        )
    }

    private func distributedRowHeight(count: Int, available: CGFloat) -> CGFloat {
        Swift.max(8.0, available / CGFloat(count))
    }

    // MARK: - Staggered fold

    /// Bottom row folds first so the stack zips up into the header.
    /// Returns 0 (open / face-on) ... 1 (fully folded / edge-on) for a given row.
    private func localFold(index: Int, progress: CGFloat) -> CGFloat {
        let n = CGFloat(rowCount)
        // Fold order: last row (n-1) starts first, first row last.
        let order = n - 1 - CGFloat(index)
        // Each row gets a window; windows overlap for a continuous ribbon feel.
        let window: CGFloat = 0.55
        let span = Swift.max(0.0001, 1.0 - window)
        let start = (order / Swift.max(1, n - 1)) * span
        let raw = (progress - start) / window
        return clamp(raw)
    }

    private func clamp(_ v: CGFloat) -> CGFloat {
        Swift.min(1.0, Swift.max(0.0, v))
    }

    // MARK: - Row

    private func row(index: Int, progress: CGFloat, metrics: Metrics) -> some View {
        let fold = localFold(index: index, progress: progress)
        let angle = Double(fold) * 88.0          // fold flat against the next row
        let collapsedHeight = metrics.rowHeight * (1.0 - fold)
        let tint = rowTint(index: index)

        return rowFace(index: index, tint: tint, metrics: metrics, fold: fold)
            // Hinge crease shadow: darkens toward the top edge as the row folds.
            .overlay(hingeShadow(corner: metrics.corner).opacity(Double(fold) * 0.9))
            // Edge-on dimming so the folded face reads as in-shadow.
            .brightness(-0.18 * Double(fold))
            .rotation3DEffect(
                .degrees(angle),
                axis: (x: 1, y: 0, z: 0),
                anchor: .top,
                anchorZ: 0,
                perspective: 0.55
            )
            // Collapse the layout slot so the VStack shrinks upward into the header.
            .frame(height: Swift.max(0.5, collapsedHeight), alignment: .top)
            .zIndex(Double(rowCount - index))    // upper rows sit above lower ones
    }

    private func rowFace(index: Int, tint: Color, metrics: Metrics, fold: CGFloat) -> some View {
        RoundedRectangle(cornerRadius: metrics.corner, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [tint.opacity(0.96), tint.opacity(0.74)],
                    startPoint: .top,
                    endPoint: .bottom
                )
            )
            .overlay(alignment: .leading) {
                rowContent(index: index, metrics: metrics)
                    .opacity(1.0 - Double(fold) * 0.85)
            }
            .frame(height: metrics.rowHeight, alignment: .top)
    }

    private func rowContent(index: Int, metrics: Metrics) -> some View {
        HStack(spacing: metrics.fontSize * 0.6) {
            Circle()
                .fill(Color(red: 0.55, green: 0.78, blue: 1.0).opacity(0.85))
                .frame(width: metrics.fontSize * 0.9, height: metrics.fontSize * 0.9)
            VStack(alignment: .leading, spacing: metrics.fontSize * 0.28) {
                Capsule()
                    .fill(Color.white.opacity(0.82))
                    .frame(width: metrics.fontSize * 5.5, height: metrics.fontSize * 0.42)
                Capsule()
                    .fill(Color.white.opacity(0.42))
                    .frame(width: metrics.fontSize * 3.2, height: metrics.fontSize * 0.36)
            }
            Spacer(minLength: 0)
        }
        .padding(.horizontal, metrics.fontSize * 0.8)
    }

    private func hingeShadow(corner: CGFloat) -> some View {
        RoundedRectangle(cornerRadius: corner, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color.black.opacity(0.85),
                        Color.black.opacity(0.30),
                        Color.clear
                    ],
                    startPoint: .top,
                    endPoint: .center
                )
            )
            .allowsHitTesting(false)
    }

    // MARK: - Header (always opaque, drawn last / on top)

    private func header(progress: CGFloat, metrics: Metrics) -> some View {
        let chevronAngle = Double(progress) * 180.0
        return RoundedRectangle(cornerRadius: metrics.corner, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.16, green: 0.20, blue: 0.30),
                        Color(red: 0.09, green: 0.11, blue: 0.17)
                    ],
                    startPoint: .top,
                    endPoint: .bottom
                )
            )
            .overlay(alignment: .top) {
                // Subtle top highlight so the header reads as the lid the rows fold under.
                RoundedRectangle(cornerRadius: metrics.corner, style: .continuous)
                    .stroke(Color.white.opacity(0.12), lineWidth: 0.6)
            }
            .overlay {
                headerContent(angle: chevronAngle, metrics: metrics)
            }
            .frame(height: metrics.headerHeight)
            .shadow(color: Color.black.opacity(0.35), radius: metrics.corner, x: 0, y: -1)
            .zIndex(Double(rowCount + 1))
            .contentShape(Rectangle())
            .onTapGesture {
                guard !demo else { return }
                withAnimation(.spring(response: 0.5, dampingFraction: 0.74)) {
                    collapsed.toggle()
                }
            }
    }

    private func headerContent(angle: Double, metrics: Metrics) -> some View {
        HStack(spacing: metrics.fontSize * 0.5) {
            Capsule()
                .fill(Color(red: 0.55, green: 0.78, blue: 1.0))
                .frame(width: metrics.fontSize * 4.0, height: metrics.fontSize * 0.5)
            Spacer(minLength: 0)
            Image(systemName: "chevron.down")
                .font(.system(size: metrics.fontSize, weight: .bold))
                .foregroundStyle(Color.white.opacity(0.85))
                .rotationEffect(.degrees(angle))
        }
        .padding(.horizontal, metrics.fontSize * 0.9)
    }

    // MARK: - Colors

    private func rowTint(index: Int) -> Color {
        let palette: [Color] = [
            Color(red: 0.31, green: 0.46, blue: 0.92),
            Color(red: 0.42, green: 0.40, blue: 0.90),
            Color(red: 0.55, green: 0.36, blue: 0.86),
            Color(red: 0.66, green: 0.34, blue: 0.74),
            Color(red: 0.78, green: 0.36, blue: 0.62)
        ]
        return palette[index % palette.count]
    }
}
"""###,
        "tr-genie-warp": ###"""
import SwiftUI

/// Genie Warp — the outgoing card squeezes and stretches into a narrowing
/// tapered neck that sucks down toward a dock point, like the macOS
/// minimize-to-Dock genie effect. Built with pure SwiftUI by slicing the
/// content into horizontal strips and giving each strip its own horizontal
/// scale (anchored at the dock column) plus a downward descent, so the
/// content genuinely bends along the warp curve instead of merely being
/// clipped by a genie-shaped hole.
///
/// - `demo == true`  → a self-driving loop that sucks the card down to a
///   tapering neck and springs it back out forever, never going blank.
/// - `demo == false` → tap the card to minimize it toward the dock, tap
///   again (or tap the dock) to restore it.
struct GenieWarpView: View {
    var demo: Bool = false

    // Interactive state.
    @State private var minimized: Bool = false

    var body: some View {
        GeometryReader { geo in
            content(in: geo.size)
                .frame(maxWidth: .infinity, maxHeight: .infinity)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    @ViewBuilder
    private func content(in size: CGSize) -> some View {
        if demo {
            demoBody(size: size)
        } else {
            interactiveBody(size: size)
        }
    }

    // MARK: - Demo (self-driving)

    @ViewBuilder
    private func demoBody(size: CGSize) -> some View {
        // PhaseAnimator (no trigger) auto-loops through the phases forever; the
        // spring between phases gives the suck-down and spring-back its tactile
        // feel. We clamp the peak below 1 so the neck never fully vanishes
        // (always legible) and dwell at each end so the loop breathes.
        PhaseAnimator(GenieWarpView_GeniePhase.allCases) { phase in
            GenieWarpView_GenieStage(progress: phase.progress, dockPoint: dockPoint(in: size), size: size)
        } animation: { phase in
            switch phase {
            case .rest:        return .spring(response: 0.6, dampingFraction: 0.82)
            case .restHold:    return .easeInOut(duration: 0.7)
            case .minimized:   return .spring(response: 0.7, dampingFraction: 0.85)
            case .minimizedHold: return .easeInOut(duration: 0.7)
            }
        }
    }

    // MARK: - Interactive

    @ViewBuilder
    private func interactiveBody(size: CGSize) -> some View {
        GenieWarpView_GenieStage(progress: minimized ? 0.92 : 0.0,
                   dockPoint: dockPoint(in: size),
                   size: size)
            .contentShape(Rectangle())
            .onTapGesture {
                withAnimation(.spring(response: 0.6, dampingFraction: 0.8)) {
                    minimized.toggle()
                }
            }
    }

    // MARK: - Geometry

    /// The dock point lives at bottom-centre, derived from the live size so it
    /// works in a 120pt tile and a large detail area alike.
    private func dockPoint(in size: CGSize) -> CGPoint {
        CGPoint(x: size.width * 0.5, y: size.height * 0.93)
    }
}

// MARK: - Phases

private enum GenieWarpView_GeniePhase: CaseIterable {
    case rest          // full card at rest
    case minimized     // sucked down into the dock neck
    case minimizedHold // dwell at the dock
    case restHold      // dwell back at rest before repeating

    var progress: Double {
        switch self {
        case .rest, .restHold:           return 0.0
        case .minimized, .minimizedHold: return 0.92  // clamped < 1 so the neck never vanishes
        }
    }
}

// MARK: - Stage (animatable container)

/// Renders the warped card for a given `progress`. `progress` is the single
/// animatable value (0 = full card at rest, 1 = fully sucked into the dock).
/// Animating it produces smooth, continuous interpolation of every strip.
private struct GenieWarpView_GenieStage: View, Animatable {
    var progress: Double
    var dockPoint: CGPoint
    var size: CGSize

    var animatableData: Double {
        get { progress }
        set { progress = newValue }
    }

    var body: some View {
        ZStack {
            backdrop
            dockGlow
            GenieWarpView_GenieWarpedCard(progress: clampedProgress,
                            dockPoint: dockPoint,
                            size: size)
        }
        .frame(width: size.width, height: size.height)
    }

    private var clampedProgress: Double {
        min(max(progress, 0.0), 1.0)
    }

    // Soft dark stage so the warped card and dock read clearly.
    private var backdrop: some View {
        RoundedRectangle(cornerRadius: 0, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.05, green: 0.06, blue: 0.10),
                        Color(red: 0.02, green: 0.02, blue: 0.05)
                    ],
                    startPoint: .top,
                    endPoint: .bottom
                )
            )
    }

    // Persistent glowing dock dot — always visible so the tile never reads as
    // blank, and it brightens as the card arrives.
    private var dockGlow: some View {
        let dim: CGFloat = max(6, min(size.width, size.height) * 0.06)
        let intensity: Double = 0.35 + 0.65 * clampedProgress
        return ZStack {
            Circle()
                .fill(Color(red: 0.45, green: 0.75, blue: 1.0))
                .frame(width: dim * 2.4, height: dim * 2.4)
                .blur(radius: dim)
                .opacity(0.28 * intensity)
            Circle()
                .fill(
                    RadialGradient(
                        colors: [
                            Color(red: 0.78, green: 0.90, blue: 1.0),
                            Color(red: 0.30, green: 0.62, blue: 0.98)
                        ],
                        center: .center,
                        startRadius: 0,
                        endRadius: dim * 0.6
                    )
                )
                .frame(width: dim, height: dim)
                .opacity(0.55 + 0.45 * clampedProgress)
        }
        .position(dockPoint)
    }
}

// MARK: - Warped card

/// Slices a card into horizontal strips and warps each one. The taper is a
/// smoothstep over the strip's normalized y, and the descent is a second
/// smoothstep — both continuous functions of `progress`, so there is no
/// velocity discontinuity (no mid-warp kink).
private struct GenieWarpView_GenieWarpedCard: View {
    var progress: Double
    var dockPoint: CGPoint
    var size: CGSize

    var body: some View {
        let metrics = GenieWarpView_CardMetrics(size: size)
        let stripCount = stripCount(for: size)

        ZStack {
            ForEach(0..<stripCount, id: \.self) { index in
                stripView(index: index, count: stripCount, metrics: metrics)
            }
        }
        // Fade the whole warped body slightly as it bottoms out so the dock
        // dot becomes the focal point, but never to zero (stays legible).
        .opacity(0.55 + 0.45 * (1.0 - smoothstep(0.78, 1.0, progress)))
    }

    // MARK: Strip

    @ViewBuilder
    private func stripView(index: Int, count: Int, metrics: GenieWarpView_CardMetrics) -> some View {
        // Normalized vertical centre of this strip within the card (0 = top).
        let yNorm: CGFloat = (CGFloat(index) + 0.5) / CGFloat(count)

        // A tiny overlap removes hairline seams between adjacent strips.
        let bandHeight: CGFloat = metrics.height / CGFloat(count)
        let overlap: CGFloat = min(1.0, bandHeight * 0.18)
        let drawHeight: CGFloat = bandHeight + overlap

        // Where this strip's centre sits before warping (card-local space).
        let restCenterY: CGFloat = metrics.minY + bandHeight * (CGFloat(index) + 0.5)

        // --- Warp factors (all smooth functions of progress) ---

        // Horizontal narrowing: lower strips (closer to the dock) narrow more,
        // and the whole thing narrows as progress rises. smoothstep avoids the
        // piecewise-linear kink.
        let neckLead: Double = smoothstep(0.0, 0.85, progress)
        let depthBias: Double = Double(smoothstep(0.0, 1.0, yNorm)) // bottom narrows first
        let widthFactor: CGFloat = widthFactor(neckLead: neckLead, depthBias: depthBias)

        // Vertical descent: strips slide toward the dock; the bottom leads so
        // the card bunches as it pours in. Second smoothstep, phase-shifted but
        // still continuous, so neck-leads-descent reads without a kink.
        let descentP: Double = smoothstep(0.06, 1.0, progress)
        let targetY: CGFloat = dockPoint.y
        let pull: CGFloat = CGFloat(descentP) * (0.55 + 0.45 * CGFloat(depthBias))
        let centerY: CGFloat = restCenterY + (targetY - restCenterY) * pull

        // Horizontal slide of the strip's centre toward the dock column.
        let restCenterX: CGFloat = size.width * 0.5
        let centerX: CGFloat = restCenterX + (dockPoint.x - restCenterX) * CGFloat(descentP)

        // Slight vertical squash on lower strips as they bunch into the dock.
        let vSquash: CGFloat = 1.0 - CGFloat(descentP) * 0.35 * CGFloat(depthBias)

        cardBand(metrics: metrics, drawHeight: drawHeight, bandTop: restCenterY - drawHeight / 2)
            .frame(width: metrics.width, height: drawHeight)
            // Narrow horizontally toward the dock x-column, anchored so the
            // silhouette converges into a neck at the dock point.
            .scaleEffect(x: widthFactor, y: vSquash, anchor: .center)
            .position(x: centerX, y: centerY)
    }

    /// One horizontal band of the card content, clipped to its band so the
    /// strip shows the correct slice of the same artwork.
    @ViewBuilder
    private func cardBand(metrics: GenieWarpView_CardMetrics, drawHeight: CGFloat, bandTop: CGFloat) -> some View {
        GenieWarpView_CardArtwork(metrics: metrics)
            .frame(width: metrics.width, height: metrics.height)
            // Shift the full artwork up so this band's slice sits in view, then
            // clip to the band height. This keeps every strip a faithful slice
            // of one continuous image.
            .offset(y: -(bandTop - metrics.minY))
            .frame(width: metrics.width, height: drawHeight, alignment: .top)
            .clipped()
    }

    // MARK: Factors

    private func widthFactor(neckLead: Double, depthBias: Double) -> CGFloat {
        // Minimum width is clamped so the neck stays a thin ribbon rather than
        // collapsing to literally zero (never fully blank).
        let minWidth: CGFloat = 0.10
        let narrowing: CGFloat = CGFloat(neckLead) * (0.55 + 0.45 * CGFloat(depthBias))
        return max(minWidth, 1.0 - narrowing)
    }

    private func stripCount(for size: CGSize) -> Int {
        // Adapt density to size: fewer strips keep a tiny tile clean, more
        // strips keep a large detail view smooth.
        let h = size.height
        if h < 160 { return 14 }
        if h < 320 { return 20 }
        return 28
    }
}

// MARK: - Card metrics

private struct GenieWarpView_CardMetrics {
    let size: CGSize
    let width: CGFloat
    let height: CGFloat
    let minX: CGFloat
    let minY: CGFloat

    init(size: CGSize) {
        self.size = size
        // Card occupies the upper portion of the stage, leaving room for the
        // dock at the bottom. Padded so it never touches the edges.
        let pad: CGFloat = min(size.width, size.height) * 0.12
        self.width = max(1, size.width - pad * 2)
        self.height = max(1, size.height * 0.62)
        self.minX = pad
        self.minY = pad * 0.7
    }
}

// MARK: - Card artwork

/// A self-contained, attractive card face. Pure SwiftUI, no assets.
private struct GenieWarpView_CardArtwork: View {
    var metrics: GenieWarpView_CardMetrics

    var body: some View {
        let corner: CGFloat = min(metrics.width, metrics.height) * 0.10

        RoundedRectangle(cornerRadius: corner, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.35, green: 0.42, blue: 0.95),
                        Color(red: 0.62, green: 0.30, blue: 0.92),
                        Color(red: 0.95, green: 0.42, blue: 0.62)
                    ],
                    startPoint: .topLeading,
                    endPoint: .bottomTrailing
                )
            )
            .overlay(face(corner: corner))
            .overlay(
                RoundedRectangle(cornerRadius: corner, style: .continuous)
                    .strokeBorder(Color(red: 1.0, green: 1.0, blue: 1.0).opacity(0.25), lineWidth: 1)
            )
            .shadow(color: Color(red: 0.0, green: 0.0, blue: 0.0).opacity(0.35),
                    radius: corner * 0.4, x: 0, y: corner * 0.18)
    }

    @ViewBuilder
    private func face(corner: CGFloat) -> some View {
        GeometryReader { proxy in
            let w = proxy.size.width
            let h = proxy.size.height
            let unit = min(w, h)

            ZStack {
                // Soft sheen sweep.
                LinearGradient(
                    colors: [
                        Color(red: 1.0, green: 1.0, blue: 1.0).opacity(0.22),
                        Color(red: 1.0, green: 1.0, blue: 1.0).opacity(0.0)
                    ],
                    startPoint: .top,
                    endPoint: .center
                )

                // Decorative orbiting rings.
                Circle()
                    .strokeBorder(Color(red: 1.0, green: 1.0, blue: 1.0).opacity(0.35),
                                  lineWidth: unit * 0.012)
                    .frame(width: unit * 0.62, height: unit * 0.62)
                    .position(x: w * 0.30, y: h * 0.34)

                Circle()
                    .fill(Color(red: 1.0, green: 0.86, blue: 0.45).opacity(0.9))
                    .frame(width: unit * 0.20, height: unit * 0.20)
                    .position(x: w * 0.70, y: h * 0.30)

                // Header / body bars to read as "content".
                VStack(alignment: .leading, spacing: unit * 0.07) {
                    RoundedRectangle(cornerRadius: unit * 0.03)
                        .fill(Color(red: 1.0, green: 1.0, blue: 1.0).opacity(0.85))
                        .frame(width: w * 0.5, height: unit * 0.07)
                    RoundedRectangle(cornerRadius: unit * 0.025)
                        .fill(Color(red: 1.0, green: 1.0, blue: 1.0).opacity(0.45))
                        .frame(width: w * 0.66, height: unit * 0.05)
                    RoundedRectangle(cornerRadius: unit * 0.025)
                        .fill(Color(red: 1.0, green: 1.0, blue: 1.0).opacity(0.30))
                        .frame(width: w * 0.4, height: unit * 0.05)
                }
                .frame(maxWidth: .infinity, maxHeight: .infinity, alignment: .bottomLeading)
                .padding(unit * 0.10)
            }
        }
        .clipShape(RoundedRectangle(cornerRadius: corner, style: .continuous))
    }
}

// MARK: - Math helpers

/// Classic Hermite smoothstep — C1-continuous, so chaining it through the
/// warp factors never introduces a velocity discontinuity (no kink).
private func smoothstep(_ edge0: Double, _ edge1: Double, _ x: Double) -> Double {
    guard edge1 > edge0 else { return x < edge0 ? 0 : 1 }
    let t = min(max((x - edge0) / (edge1 - edge0), 0.0), 1.0)
    return t * t * (3.0 - 2.0 * t)
}

private func smoothstep(_ edge0: CGFloat, _ edge1: CGFloat, _ x: CGFloat) -> CGFloat {
    guard edge1 > edge0 else { return x < edge0 ? 0 : 1 }
    let t = min(max((x - edge0) / (edge1 - edge0), 0.0), 1.0)
    return t * t * (3.0 - 2.0 * t)
}
"""###,
        "tr-glass-shatter": ###"""
import SwiftUI

// MARK: - Glass Shatter
//
// The outgoing glass pane fractures into precomputed triangular/polygonal shards
// that tumble, spin, and fall away under gravity, uncovering the view behind.
// Each shard catches a raking specular highlight that sweeps as it rotates,
// so the break sparkles like real broken glass.
//
// demo == true  -> a self-driving TimelineView loop shatters and reassembles
//                  on a smoothed triangle wave so the tile is always alive.
// demo == false -> tap to shatter; tap again to reassemble.

struct GlassShatterView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { proxy in
            content(size: proxy.size)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    @ViewBuilder
    private func content(size: CGSize) -> some View {
        if demo {
            GlassShatterView_DemoStage(size: size)
        } else {
            GlassShatterView_InteractiveStage(size: size)
        }
    }
}

// MARK: - Demo (self-driving loop)

private struct GlassShatterView_DemoStage: View {
    let size: CGSize
    private let period: Double = 3.4

    var body: some View {
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            let phase = (t.truncatingRemainder(dividingBy: period)) / period
            GlassShatterView_ShatterStage(size: size, progress: GlassShatterView_ShatterMath.loopProgress(phase))
        }
    }
}

// MARK: - Interactive (tap to shatter / reassemble)

private struct GlassShatterView_InteractiveStage: View {
    let size: CGSize

    @State private var anchor: Date? = nil    // moment the current transition began
    @State private var fromValue: Double = 0  // progress at the start of the transition
    @State private var toValue: Double = 0     // progress target of the transition
    @State private var resting: Double = 0     // value to hold when no transition runs

    private let duration: Double = 1.15

    var body: some View {
        TimelineView(.animation) { timeline in
            let p = currentProgress(now: timeline.date)
            GlassShatterView_ShatterStage(size: size, progress: p)
                .contentShape(Rectangle())
                .onTapGesture { handleTap(now: timeline.date, current: p) }
        }
    }

    private func currentProgress(now: Date) -> Double {
        guard let anchor else { return resting }
        let elapsed = now.timeIntervalSince(anchor)
        let f = min(max(elapsed / duration, 0), 1)
        let eased = GlassShatterView_ShatterMath.smoothstep(f)
        return fromValue + (toValue - fromValue) * eased
    }

    private func handleTap(now: Date, current: Double) {
        // Resume from wherever we are so mid-flight taps don't jump.
        fromValue = current
        toValue = current < 0.5 ? 1 : 0
        resting = toValue
        anchor = now
    }
}

// MARK: - Stage: revealed background + glass overlay

private struct GlassShatterView_ShatterStage: View {
    let size: CGSize
    let progress: Double   // 0 = intact glass, 1 = fully dispersed (revealed)

    var body: some View {
        ZStack {
            GlassShatterView_RevealedBackground()           // opaque floor -- never blank
            GlassShatterView_GlassOverlay(progress: progress)
        }
        .frame(width: size.width, height: size.height)
        .clipped()
    }
}

// The always-legible destination view behind the glass.
private struct GlassShatterView_RevealedBackground: View {
    var body: some View {
        GeometryReader { proxy in
            let s = min(proxy.size.width, proxy.size.height)
            ZStack {
                LinearGradient(
                    colors: [
                        Color(red: 0.07, green: 0.10, blue: 0.20),
                        Color(red: 0.16, green: 0.09, blue: 0.26)
                    ],
                    startPoint: .topLeading,
                    endPoint: .bottomTrailing
                )
                RadialGradient(
                    colors: [
                        Color(red: 0.42, green: 0.55, blue: 0.95).opacity(0.55),
                        Color.clear
                    ],
                    center: .center,
                    startRadius: 0,
                    endRadius: s * 0.65
                )
                Image(systemName: "sparkles")
                    .font(.system(size: s * 0.30, weight: .regular))
                    .foregroundStyle(
                        LinearGradient(
                            colors: [
                                Color(red: 0.98, green: 0.99, blue: 1.0),
                                Color(red: 0.74, green: 0.82, blue: 1.0)
                            ],
                            startPoint: .top,
                            endPoint: .bottom
                        )
                    )
                    .shadow(color: Color(red: 0.30, green: 0.45, blue: 0.95).opacity(0.6),
                            radius: s * 0.05)
            }
        }
    }
}

// MARK: - Glass overlay (Canvas-rendered shards)

private struct GlassShatterView_GlassOverlay: View {
    let progress: Double

    var body: some View {
        Canvas { context, size in
            let p = max(0, min(1, progress))
            for shard in GlassShatterView_ShatterMath.shards {
                draw(shard, into: context, size: size, p: p)
            }
            // Hairline impact-point spark while still mostly intact.
            if p < 0.18 {
                drawImpactSpark(in: context, size: size, p: p)
            }
        }
        .allowsHitTesting(false)
    }

    private func draw(_ shard: GlassShatterView_Shard, into context: GraphicsContext, size: CGSize, p: Double) {
        let st = GlassShatterView_ShatterMath.state(for: shard, p: p, size: size)
        guard st.opacity > 0.001 else { return }

        var layer = context
        layer.opacity = st.opacity
        layer.translateBy(x: st.position.x, y: st.position.y)
        layer.rotate(by: .radians(st.angle))

        // GlassShatterView_Shard path is built around its own centroid -> rotation pivots on center.
        let path = shard.localPath(size: size)

        // Base glass body.
        layer.fill(path, with: .color(glassTint(shard)))

        // Raking specular band, defined in shard-LOCAL coordinates so the
        // highlight sweeps across the shard as the layer rotates.
        let bounds = shard.localBounds(size: size)
        layer.drawLayer { inner in
            inner.clip(to: path)
            inner.fill(
                Path(bounds),
                with: .linearGradient(
                    Gradient(stops: [
                        .init(color: Color.white.opacity(0.0), location: 0.30),
                        .init(color: Color.white.opacity(0.85), location: 0.50),
                        .init(color: Color.white.opacity(0.0), location: 0.70)
                    ]),
                    startPoint: CGPoint(x: bounds.minX, y: bounds.minY),
                    endPoint: CGPoint(x: bounds.maxX, y: bounds.maxY)
                )
            )
        }

        // Crisp edge so the crack gaps read.
        layer.stroke(
            path,
            with: .color(Color(red: 0.80, green: 0.90, blue: 1.0).opacity(0.55)),
            lineWidth: max(0.5, size.width * 0.0035)
        )
    }

    private func glassTint(_ shard: GlassShatterView_Shard) -> Color {
        // Subtle per-shard tint variation, derived deterministically.
        let v = shard.tintBias
        return Color(
            red: 0.62 + 0.10 * v,
            green: 0.74 + 0.08 * v,
            blue: 0.92 + 0.06 * v
        ).opacity(0.34)
    }

    private func drawImpactSpark(in context: GraphicsContext, size: CGSize, p: Double) {
        let center = CGPoint(x: GlassShatterView_ShatterMath.impact.x * size.width,
                             y: GlassShatterView_ShatterMath.impact.y * size.height)
        let r = size.width * 0.05 * (1 - p / 0.18)
        guard r > 0 else { return }
        let rect = CGRect(x: center.x - r, y: center.y - r, width: r * 2, height: r * 2)
        context.fill(
            Path(ellipseIn: rect),
            with: .radialGradient(
                Gradient(colors: [Color.white.opacity(0.9), Color.white.opacity(0.0)]),
                center: center, startRadius: 0, endRadius: r
            )
        )
    }
}

// MARK: - GlassShatterView_Shard model

private struct GlassShatterView_Shard {
    /// Centroid in normalized [0,1] space.
    let centroid: CGPoint
    /// Polygon vertices in normalized [0,1] space.
    let vertices: [CGPoint]
    /// Outward + jittered launch velocity, normalized units per unit progress-time.
    let velocity: CGVector
    /// Angular velocity (radians per unit progress-time).
    let spin: Double
    /// Per-shard tint bias in [-1, 1].
    let tintBias: Double

    /// Path built around the shard's own centroid (local space), scaled to `size`.
    func localPath(size: CGSize) -> Path {
        var path = Path()
        guard let first = vertices.first else { return path }
        let cx = centroid.x
        let cy = centroid.y
        func map(_ pt: CGPoint) -> CGPoint {
            CGPoint(x: (pt.x - cx) * size.width, y: (pt.y - cy) * size.height)
        }
        path.move(to: map(first))
        for v in vertices.dropFirst() {
            path.addLine(to: map(v))
        }
        path.closeSubpath()
        return path
    }

    func localBounds(size: CGSize) -> CGRect {
        localPath(size: size).boundingRect
    }
}

private struct GlassShatterView_ShardState {
    let position: CGPoint  // centroid position in screen space
    let angle: Double      // radians
    let opacity: Double
}

// MARK: - Math / mesh (deterministic, computed once)

private enum GlassShatterView_ShatterMath {

    /// Impact point in normalized space.
    static let impact = CGPoint(x: 0.5, y: 0.46)

    /// Precomputed spider-web fracture -- radial spokes x concentric rings.
    /// Built once with a seeded generator so the mesh NEVER re-randomizes.
    static let shards: [GlassShatterView_Shard] = buildShards()

    /// Smoothstep easing.
    static func smoothstep(_ x: Double) -> Double {
        let t = max(0, min(1, x))
        return t * t * (3 - 2 * t)
    }

    /// Maps a 0->1 loop phase to a smoothed 0->1->0 triangle (shatter then reassemble).
    static func loopProgress(_ phase: Double) -> Double {
        let tri: Double
        if phase < 0.5 {
            tri = phase / 0.5             // 0 -> 1
        } else {
            tri = (1 - phase) / 0.5       // 1 -> 0
        }
        return smoothstep(tri)
    }

    /// Physics for one shard at normalized progress p in [0,1].
    /// Identical mapping is used by both demo and interactive modes.
    static func state(for shard: GlassShatterView_Shard, p: Double, size: CGSize) -> GlassShatterView_ShardState {
        // Base (intact) centroid in screen space.
        let baseX = shard.centroid.x * size.width
        let baseY = shard.centroid.y * size.height

        // Ease-in launch so shards stay put at p~0 then accelerate.
        let launch = p * p   // quadratic ramp

        let dx = shard.velocity.dx * launch * size.width
        // Gravity grows with progress^2; positive y is downward.
        let gravity = 0.9 * (p * p) * size.height
        let dy = shard.velocity.dy * launch * size.height + gravity

        let position = CGPoint(x: baseX + dx, y: baseY + dy)
        let angle = shard.spin * p

        // Stay fully opaque until late, then fade so they don't pop at the edge.
        let opacity: Double
        if p < 0.72 {
            opacity = 1.0
        } else {
            opacity = max(0, 1 - (p - 0.72) / 0.28)
        }
        return GlassShatterView_ShardState(position: position, angle: angle, opacity: opacity)
    }

    // MARK: Mesh construction

    private static func buildShards() -> [GlassShatterView_Shard] {
        var rng = GlassShatterView_SeededRNG(seed: 0x9E3779B97F4A7C15)
        var result: [GlassShatterView_Shard] = []

        let cx = impact.x
        let cy = impact.y
        let spokes = 9
        // Last ring overflows the frame so the intact pane fully covers the
        // rectangle (the overflow is caught by .clipped() on GlassShatterView_ShatterStage),
        // leaving no bare corners or floating boundary seam.
        let rings: [Double] = [0.0, 0.16, 0.34, 0.58, 1.25]

        // Per-spoke angle with slight jitter, sorted around the circle.
        var angles: [Double] = []
        for i in 0..<spokes {
            let base = (Double(i) / Double(spokes)) * 2 * .pi
            let jitter = (rng.nextUnit() - 0.5) * (2 * .pi / Double(spokes)) * 0.5
            angles.append(base + jitter)
        }
        angles.sort()

        func ringPoint(angle: Double, radius: Double) -> CGPoint {
            // Per-vertex radial jitter for an irregular, glass-like break.
            let jr = radius * (1 + (rng.nextUnit() - 0.5) * 0.18)
            let x = cx + cos(angle) * jr
            let y = cy + sin(angle) * jr
            return CGPoint(x: x, y: y)
        }

        // Precompute the lattice of ring points per spoke.
        var lattice: [[CGPoint]] = []
        for a in angles {
            var col: [CGPoint] = []
            for r in rings {
                col.append(r == 0 ? CGPoint(x: cx, y: cy) : ringPoint(angle: a, radius: r))
            }
            lattice.append(col)
        }

        // Build triangle/quad cells between adjacent spokes and rings.
        for s in 0..<spokes {
            let s2 = (s + 1) % spokes
            for ri in 0..<(rings.count - 1) {
                let inner = rings[ri]
                let verts: [CGPoint]
                if inner == 0 {
                    // Innermost cells are triangles fanning from the impact point.
                    verts = [
                        CGPoint(x: cx, y: cy),
                        lattice[s][ri + 1],
                        lattice[s2][ri + 1]
                    ]
                } else {
                    // Outer cells are quads (two spokes x two rings).
                    verts = [
                        lattice[s][ri],
                        lattice[s][ri + 1],
                        lattice[s2][ri + 1],
                        lattice[s2][ri]
                    ]
                }
                result.append(makeShard(vertices: verts, rng: &rng))
            }
        }
        return result
    }

    private static func makeShard(vertices: [CGPoint], rng: inout GlassShatterView_SeededRNG) -> GlassShatterView_Shard {
        // Centroid = average of vertices.
        var sx: Double = 0
        var sy: Double = 0
        for v in vertices {
            sx += v.x
            sy += v.y
        }
        let n = Double(vertices.count)
        let centroid = CGPoint(x: sx / n, y: sy / n)

        // Outward direction from the impact point.
        var ux = centroid.x - impact.x
        var uy = centroid.y - impact.y
        let len = max(0.0001, (ux * ux + uy * uy).squareRoot())
        ux /= len
        uy /= len

        // Speed scales with distance (outer shards fly farther) + jitter.
        let speed = 0.55 + len * 1.4 + (rng.nextUnit() - 0.5) * 0.25
        let tangentialJitter = (rng.nextUnit() - 0.5) * 0.30
        // A little tangential spread for a natural scatter.
        let vx = ux * speed - uy * tangentialJitter
        let vy = uy * speed + ux * tangentialJitter

        let spin = (rng.nextUnit() - 0.5) * 7.0       // radians over full progress
        let tintBias = (rng.nextUnit() - 0.5) * 2.0   // [-1, 1]

        return GlassShatterView_Shard(
            centroid: centroid,
            vertices: vertices,
            velocity: CGVector(dx: vx, dy: vy),
            spin: spin,
            tintBias: tintBias
        )
    }
}

// MARK: - Seeded RNG (SplitMix64) -- deterministic, so the mesh is stable

private struct GlassShatterView_SeededRNG {
    private var state: UInt64

    init(seed: UInt64) {
        state = seed
    }

    mutating func next() -> UInt64 {
        state = state &+ 0x9E3779B97F4A7C15
        var z = state
        z = (z ^ (z >> 30)) &* 0xBF58476D1CE4E5B9
        z = (z ^ (z >> 27)) &* 0x94D049BB133111EB
        return z ^ (z >> 31)
    }

    /// Uniform Double in [0, 1).
    mutating func nextUnit() -> Double {
        Double(next() >> 11) * (1.0 / 9007199254740992.0)
    }
}
"""###,
        "tr-hero-zoom-scatter": ###"""
import SwiftUI

/// Hero Zoom Scatter
///
/// A tapped grid thumbnail expands to a full detail view while every surrounding
/// grid cell scatters outward and fades, then settles back on dismiss.
///
/// The whole effect is driven by a single shared `progress` value (0 = grid,
/// 1 = hero zoomed). This deliberately avoids `matchedGeometryEffect` + a phase
/// animator (which do not compose, and risk a blank frame inside a small tile):
/// - `demo == true`  -> a TimelineView smoothstep loop with a dwell at each end.
/// - `demo == false` -> a real `onTapGesture` toggling the progress via a spring.
///
/// Both paths feed the same render core, so the demo tile is pixel-faithful to
/// the interactive component.
struct HeroZoomScatterView: View {
    var demo: Bool = false

    // Interactive state.
    @State private var zoomed: Bool = false

    // 3x3 grid; index 4 (the center cell) is the hero.
    private let columns: Int = 3
    private let rows: Int = 3
    private var heroIndex: Int { (rows * columns) / 2 }

    var body: some View {
        GeometryReader { geo in
            if demo {
                demoContent(in: geo.size)
            } else {
                interactiveContent(in: geo.size)
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // MARK: - Demo (self-driving)

    private func demoContent(in size: CGSize) -> some View {
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            let progress = loopProgress(at: t)
            scene(in: size, progress: progress, staggered: false)
        }
    }

    /// A ~3.4s loop: ease up to fully zoomed, dwell so the detail reads,
    /// ease back down, dwell in the grid state. Never reaches a blank frame.
    private func loopProgress(at time: TimeInterval) -> CGFloat {
        let period: Double = 3.4
        let phase = time.truncatingRemainder(dividingBy: period) / period // 0..<1

        let openEnd: Double = 0.32   // ramp up
        let holdEnd: Double = 0.55   // dwell zoomed
        let closeEnd: Double = 0.85  // ramp down
        // remainder: dwell in grid state

        let raw: Double
        if phase < openEnd {
            raw = smoothstep(phase / openEnd)
        } else if phase < holdEnd {
            raw = 1.0
        } else if phase < closeEnd {
            raw = 1.0 - smoothstep((phase - holdEnd) / (closeEnd - holdEnd))
        } else {
            raw = 0.0
        }
        return CGFloat(raw)
    }

    private func smoothstep(_ x: Double) -> Double {
        let c = min(max(x, 0.0), 1.0)
        return c * c * (3.0 - 2.0 * c)
    }

    // MARK: - Interactive

    private func interactiveContent(in size: CGSize) -> some View {
        let progress: CGFloat = zoomed ? 1.0 : 0.0
        return scene(in: size, progress: progress, staggered: true)
            .contentShape(Rectangle())
            .onTapGesture {
                withAnimation(.spring(response: 0.55, dampingFraction: 0.78)) {
                    zoomed.toggle()
                }
            }
    }

    // MARK: - Shared scene

    private func scene(in size: CGSize, progress: CGFloat, staggered: Bool) -> some View {
        let metrics = HeroZoomScatterView_GridMetrics(size: size, columns: columns, rows: rows)
        return ZStack {
            // Backdrop dims as the hero takes focus.
            Color(red: 0.05, green: 0.06, blue: 0.09)
                .opacity(0.0)
                .background(
                    Color(red: 0.04, green: 0.045, blue: 0.07)
                        .opacity(Double(0.85 * progress))
                )
                .allowsHitTesting(false)

            // Siblings scatter outward & fade.
            ForEach(siblingIndices, id: \.self) { index in
                siblingCell(index: index,
                            metrics: metrics,
                            progress: progress,
                            staggered: staggered)
            }

            // Hero grows from its slot to fill the bounds.
            heroCell(metrics: metrics, progress: progress, staggered: staggered)
        }
        .frame(width: size.width, height: size.height)
        .clipped()
    }

    private var siblingIndices: [Int] {
        Array(0 ..< (rows * columns)).filter { $0 != heroIndex }
    }

    // MARK: - Hero cell

    @ViewBuilder
    private func heroCell(metrics: HeroZoomScatterView_GridMetrics, progress: CGFloat, staggered: Bool) -> some View {
        let slot = metrics.frame(forIndex: heroIndex)
        let full = metrics.fullFrame
        let rect = lerp(rect: slot, to: full, t: progress)
        let cornerSlot: CGFloat = min(slot.width, slot.height) * 0.22
        let cornerFull: CGFloat = min(full.width, full.height) * 0.10
        let corner = mix(cornerSlot, cornerFull, progress)

        HeroZoomScatterView_HeroTile(progress: progress, corner: corner)
            .frame(width: rect.width, height: rect.height)
            .position(x: rect.midX, y: rect.midY)
            .shadow(color: Color.black.opacity(Double(0.35 * progress)),
                    radius: 18 * progress, x: 0, y: 10 * progress)
            .modifier(HeroZoomScatterView_StaggeredSpring(enabled: staggered, delay: 0, value: progress))
    }

    // MARK: - Sibling cell

    @ViewBuilder
    private func siblingCell(index: Int,
                             metrics: HeroZoomScatterView_GridMetrics,
                             progress: CGFloat,
                             staggered: Bool) -> some View {
        let slot = metrics.frame(forIndex: index)
        let dir = metrics.outwardDirection(forIndex: index)
        let scatter: CGFloat = metrics.scatterDistance
        let dx = dir.dx * scatter * progress
        let dy = dir.dy * scatter * progress
        let scale = 1.0 - 0.12 * progress
        let opacity = Double(max(0.0, 1.0 - 1.15 * progress))
        let ring = metrics.ringDistance(forIndex: index) // 1 for edges, etc.
        let delay = 0.03 * Double(ring)

        HeroZoomScatterView_SiblingTile(hue: metrics.hue(forIndex: index))
            .frame(width: slot.width, height: slot.height)
            .scaleEffect(scale)
            .position(x: slot.midX + dx, y: slot.midY + dy)
            .opacity(opacity)
            .modifier(HeroZoomScatterView_StaggeredSpring(enabled: staggered, delay: delay, value: progress))
    }

    // MARK: - Interpolation helpers

    private func lerp(rect a: CGRect, to b: CGRect, t: CGFloat) -> CGRect {
        CGRect(x: mix(a.minX, b.minX, t),
               y: mix(a.minY, b.minY, t),
               width: mix(a.width, b.width, t),
               height: mix(a.height, b.height, t))
    }

    private func mix(_ a: CGFloat, _ b: CGFloat, _ t: CGFloat) -> CGFloat {
        a + (b - a) * t
    }
}

// MARK: - Staggered spring modifier

/// Applies a per-cell staggered spring only in the interactive path. In the
/// demo path the progress is already a smooth continuous value, so no implicit
/// animation is attached (it would fight the TimelineView clock).
private struct HeroZoomScatterView_StaggeredSpring: ViewModifier, Animatable {
    let enabled: Bool
    let delay: Double
    let value: CGFloat

    func body(content: Content) -> some View {
        if enabled {
            content.animation(.spring(response: 0.5, dampingFraction: 0.74)
                .delay(delay), value: value)
        } else {
            content
        }
    }
}

// MARK: - Grid metrics

private struct HeroZoomScatterView_GridMetrics {
    let size: CGSize
    let columns: Int
    let rows: Int

    private let inset: CGFloat
    private let gap: CGFloat

    init(size: CGSize, columns: Int, rows: Int) {
        self.size = size
        self.columns = columns
        self.rows = rows
        let minDim = min(size.width, size.height)
        self.inset = minDim * 0.10
        self.gap = minDim * 0.055
    }

    var contentRect: CGRect {
        CGRect(x: inset, y: inset,
               width: max(size.width - inset * 2, 1),
               height: max(size.height - inset * 2, 1))
    }

    var fullFrame: CGRect {
        let pad = min(size.width, size.height) * 0.06
        return CGRect(x: pad, y: pad,
                      width: max(size.width - pad * 2, 1),
                      height: max(size.height - pad * 2, 1))
    }

    private var cellWidth: CGFloat {
        (contentRect.width - gap * CGFloat(columns - 1)) / CGFloat(columns)
    }

    private var cellHeight: CGFloat {
        (contentRect.height - gap * CGFloat(rows - 1)) / CGFloat(rows)
    }

    var scatterDistance: CGFloat {
        min(size.width, size.height) * 0.55
    }

    func column(of index: Int) -> Int { index % columns }
    func row(of index: Int) -> Int { index / columns }

    func frame(forIndex index: Int) -> CGRect {
        let c = column(of: index)
        let r = row(of: index)
        let x = contentRect.minX + CGFloat(c) * (cellWidth + gap)
        let y = contentRect.minY + CGFloat(r) * (cellHeight + gap)
        return CGRect(x: x, y: y, width: max(cellWidth, 1), height: max(cellHeight, 1))
    }

    private var heroCenter: CGPoint {
        let f = frame(forIndex: (rows * columns) / 2)
        return CGPoint(x: f.midX, y: f.midY)
    }

    /// Normalised outward direction from the hero center to this cell's center.
    func outwardDirection(forIndex index: Int) -> CGVector {
        let f = frame(forIndex: index)
        let dx = f.midX - heroCenter.x
        let dy = f.midY - heroCenter.y
        let len = max(sqrt(dx * dx + dy * dy), 0.0001)
        return CGVector(dx: dx / len, dy: dy / len)
    }

    /// Chebyshev ring distance from the hero (used for stagger delay).
    func ringDistance(forIndex index: Int) -> Int {
        let heroC = columns / 2
        let heroR = rows / 2
        return max(abs(column(of: index) - heroC), abs(row(of: index) - heroR))
    }

    func hue(forIndex index: Int) -> Double {
        let total = Double(max(rows * columns - 1, 1))
        return Double(index) / total
    }
}

// MARK: - Hero tile content

private struct HeroZoomScatterView_HeroTile: View {
    let progress: CGFloat
    let corner: CGFloat

    var body: some View {
        ZStack {
            RoundedRectangle(cornerRadius: corner, style: .continuous)
                .fill(
                    LinearGradient(
                        colors: [
                            Color(red: 0.36, green: 0.52, blue: 0.96),
                            Color(red: 0.62, green: 0.34, blue: 0.92)
                        ],
                        startPoint: .topLeading,
                        endPoint: .bottomTrailing
                    )
                )
                .overlay(
                    RoundedRectangle(cornerRadius: corner, style: .continuous)
                        .strokeBorder(Color.white.opacity(0.16), lineWidth: 1)
                )

            // Detail content fades in only when the hero is mostly expanded,
            // so the zoom reads as "becoming a detail view," not just scaling.
            detailOverlay
                .opacity(Double(detailOpacity))
                .padding(corner * 0.9)
        }
        .compositingGroup()
    }

    private var detailOpacity: CGFloat {
        // Ramp 0 -> 1 across the second half of the zoom.
        let p = (progress - 0.45) / 0.45
        return max(0.0, min(1.0, p))
    }

    private var detailOverlay: some View {
        GeometryReader { g in
            let unit = min(g.size.width, g.size.height)
            VStack(alignment: .leading, spacing: unit * 0.08) {
                Circle()
                    .fill(Color.white.opacity(0.9))
                    .frame(width: unit * 0.22, height: unit * 0.22)
                    .overlay(
                        Image(systemName: "sparkles")
                            .font(.system(size: unit * 0.11, weight: .bold))
                            .foregroundStyle(Color(red: 0.45, green: 0.36, blue: 0.95))
                    )
                Spacer(minLength: 0)
                RoundedRectangle(cornerRadius: unit * 0.04, style: .continuous)
                    .fill(Color.white.opacity(0.88))
                    .frame(width: g.size.width * 0.7, height: unit * 0.09)
                RoundedRectangle(cornerRadius: unit * 0.03, style: .continuous)
                    .fill(Color.white.opacity(0.5))
                    .frame(width: g.size.width * 0.5, height: unit * 0.06)
                RoundedRectangle(cornerRadius: unit * 0.03, style: .continuous)
                    .fill(Color.white.opacity(0.32))
                    .frame(width: g.size.width * 0.88, height: unit * 0.05)
            }
            .frame(maxWidth: .infinity, maxHeight: .infinity, alignment: .topLeading)
        }
    }
}

// MARK: - Sibling tile content

private struct HeroZoomScatterView_SiblingTile: View {
    let hue: Double

    var body: some View {
        GeometryReader { g in
            let r = min(g.size.width, g.size.height) * 0.22
            RoundedRectangle(cornerRadius: r, style: .continuous)
                .fill(
                    LinearGradient(
                        colors: gradientColors,
                        startPoint: .top,
                        endPoint: .bottom
                    )
                )
                .overlay(
                    RoundedRectangle(cornerRadius: r, style: .continuous)
                        .strokeBorder(Color.white.opacity(0.10), lineWidth: 1)
                )
        }
    }

    private var gradientColors: [Color] {
        let base = Color(hue: hue, saturation: 0.42, brightness: 0.62)
        let dark = Color(hue: hue, saturation: 0.5, brightness: 0.4)
        return [base, dark]
    }
}
"""###,
        "tr-iris-shutter": ###"""
import SwiftUI

/// Iris Shutter Wipe — a ring of overlapping camera-aperture blades spirals open
/// from the center, the polygonal opening growing to reveal the destination view.
///
/// The reveal is a real SwiftUI `Path` N-gon mask over the destination; the blades
/// are a decorative `Canvas` overlay registered to the SAME center / radius /
/// rotation / blade-count so the polygon reads as the hole the blades define.
///
/// Geometry is rebuilt every frame from a single `progress` value. Because
/// `Canvas` and `Path` are not interpolated by SwiftUI on their own, the content
/// is wrapped in an `Animatable` view (`IrisShutterView_IrisContent`) whose `animatableData` IS
/// the progress — so both the `withAnimation(.spring)` tap and the continuous
/// `TimelineView(.animation)` demo loop produce smooth, frame-by-frame motion.
struct IrisShutterView: View {
    var demo: Bool = false

    // Interactive state: tap toggles the aperture open/closed.
    @State private var isOpen: Bool = false

    private let bladeCount: Int = 7

    var body: some View {
        GeometryReader { geo in
            if demo {
                demoBody(size: geo.size)
            } else {
                interactiveBody(size: geo.size)
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // MARK: - Modes

    @ViewBuilder
    private func demoBody(size: CGSize) -> some View {
        // Continuous, self-driving triangle-wave 0 -> 1 -> 0 over a ~3s period.
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            let progress: CGFloat = Self.triangleWave(time: t, period: 3.0)
            IrisShutterView_IrisContent(progress: progress, size: size, bladeCount: bladeCount)
        }
    }

    @ViewBuilder
    private func interactiveBody(size: CGSize) -> some View {
        let progress: CGFloat = isOpen ? 1 : 0
        IrisShutterView_IrisContent(progress: progress, size: size, bladeCount: bladeCount)
            .contentShape(Rectangle())
            .onTapGesture {
                withAnimation(.spring(response: 0.7, dampingFraction: 0.72)) {
                    isOpen.toggle()
                }
            }
    }

    /// Smooth 0 -> 1 -> 0 wave. Built from a smoothstep'd triangle so the demo
    /// eases at the extremes instead of bouncing linearly.
    private static func triangleWave(time: TimeInterval, period: TimeInterval) -> CGFloat {
        let phase = (time.truncatingRemainder(dividingBy: period)) / period
        let tri: CGFloat = phase < 0.5 ? CGFloat(phase * 2) : CGFloat((1 - phase) * 2)
        // smoothstep for soft ends
        return tri * tri * (3 - 2 * tri)
    }
}

// MARK: - Animatable content

/// Renders the full iris for a given `progress`. Conforming to `Animatable` with
/// `animatableData == progress` makes SwiftUI interpolate progress every frame,
/// so the Canvas-drawn blades + polygon mask animate smoothly under both
/// `withAnimation` (tap) and a continuous `TimelineView` value (demo).
private struct IrisShutterView_IrisContent: View, Animatable {
    var progress: CGFloat
    let size: CGSize
    let bladeCount: Int

    var animatableData: CGFloat {
        get { progress }
        set { progress = newValue }
    }

    var body: some View {
        let p: CGFloat = min(max(progress, 0), 1)
        let metrics = IrisShutterView_IrisMetrics(size: size, progress: p, bladeCount: bladeCount)

        return ZStack {
            // 1. Dark camera housing behind everything.
            housing(metrics: metrics)

            // 2. Destination "scene" revealed through the polygonal opening.
            destinationScene(metrics: metrics)
                .mask(
                    IrisShutterView_OpeningPolygon(metrics: metrics)
                        .fill(style: FillStyle(eoFill: false, antialiased: true))
                )

            // 3. Decorative aperture blades in the annulus between opening and rim.
            bladeCanvas(metrics: metrics)
                .allowsHitTesting(false)

            // 4. Bezel rim ring so it always reads as a lens aperture.
            bezel(metrics: metrics)
                .allowsHitTesting(false)
        }
        .clipShape(Circle().inset(by: metrics.bezelInset))
    }

    // MARK: - Layers

    @ViewBuilder
    private func housing(metrics: IrisShutterView_IrisMetrics) -> some View {
        ZStack {
            Color(red: 0.05, green: 0.06, blue: 0.09)
            RadialGradient(
                colors: [
                    Color(red: 0.16, green: 0.17, blue: 0.21),
                    Color(red: 0.05, green: 0.05, blue: 0.07)
                ],
                center: .center,
                startRadius: 0,
                endRadius: metrics.outerRadius
            )
        }
    }

    @ViewBuilder
    private func destinationScene(metrics: IrisShutterView_IrisMetrics) -> some View {
        ZStack {
            // A warm, vivid "next screen" so the reveal is satisfying.
            LinearGradient(
                colors: [
                    Color(red: 0.99, green: 0.55, blue: 0.32),
                    Color(red: 0.93, green: 0.27, blue: 0.49),
                    Color(red: 0.40, green: 0.20, blue: 0.74)
                ],
                startPoint: .topLeading,
                endPoint: .bottomTrailing
            )
            // Soft glow disc to give the scene some life through the iris.
            RadialGradient(
                colors: [
                    Color(red: 1.0, green: 0.96, blue: 0.80).opacity(0.85),
                    Color(red: 1.0, green: 0.96, blue: 0.80).opacity(0.0)
                ],
                center: UnitPoint(x: 0.42, y: 0.38),
                startRadius: 0,
                endRadius: metrics.outerRadius * 0.9
            )
            sunburst(metrics: metrics)
        }
    }

    /// Faint radiating rays so the destination has detail, not a flat fill.
    @ViewBuilder
    private func sunburst(metrics: IrisShutterView_IrisMetrics) -> some View {
        Canvas { ctx, _ in
            let center = metrics.center
            let rays = 24
            for i in 0..<rays {
                let a: CGFloat = (CGFloat(i) / CGFloat(rays)) * .pi * 2
                var path = Path()
                path.move(to: center)
                let end = CGPoint(
                    x: center.x + cos(a) * metrics.outerRadius * 1.4,
                    y: center.y + sin(a) * metrics.outerRadius * 1.4
                )
                path.addLine(to: end)
                ctx.stroke(
                    path,
                    with: .color(Color(red: 1.0, green: 1.0, blue: 1.0).opacity(0.06)),
                    lineWidth: 2
                )
            }
        }
    }

    @ViewBuilder
    private func bladeCanvas(metrics: IrisShutterView_IrisMetrics) -> some View {
        Canvas { ctx, _ in
            drawBlades(in: &ctx, metrics: metrics)
        }
    }

    @ViewBuilder
    private func bezel(metrics: IrisShutterView_IrisMetrics) -> some View {
        let lineWidth: CGFloat = max(metrics.minDim * 0.035, 2)
        ZStack {
            Circle()
                .inset(by: metrics.bezelInset)
                .strokeBorder(
                    AngularGradient(
                        colors: [
                            Color(red: 0.55, green: 0.58, blue: 0.66),
                            Color(red: 0.12, green: 0.13, blue: 0.16),
                            Color(red: 0.72, green: 0.75, blue: 0.82),
                            Color(red: 0.10, green: 0.11, blue: 0.14),
                            Color(red: 0.55, green: 0.58, blue: 0.66)
                        ],
                        center: .center
                    ),
                    lineWidth: lineWidth
                )
            Circle()
                .inset(by: metrics.bezelInset + lineWidth)
                .strokeBorder(
                    Color(red: 0.02, green: 0.02, blue: 0.03).opacity(0.7),
                    lineWidth: max(lineWidth * 0.4, 1)
                )
        }
    }

    // MARK: - Blade drawing

    private func drawBlades(in ctx: inout GraphicsContext, metrics: IrisShutterView_IrisMetrics) {
        let n = metrics.bladeCount
        for i in 0..<n {
            let blade = bladePath(index: i, metrics: metrics)

            // Base blade fill — brushed metal gradient across the blade.
            let g = Gradient(colors: [
                Color(red: 0.30, green: 0.32, blue: 0.38),
                Color(red: 0.16, green: 0.17, blue: 0.21),
                Color(red: 0.09, green: 0.10, blue: 0.13)
            ])
            let baseAngle: CGFloat = metrics.bladeBaseAngle(index: i)
            let shading = GraphicsContext.Shading.linearGradient(
                g,
                startPoint: CGPoint(
                    x: metrics.center.x + cos(baseAngle) * metrics.outerRadius,
                    y: metrics.center.y + sin(baseAngle) * metrics.outerRadius
                ),
                endPoint: metrics.center
            )
            ctx.fill(blade, with: shading)

            // Seam line where this blade overlaps its neighbour — adds depth.
            ctx.stroke(
                blade,
                with: .color(Color(red: 0.0, green: 0.0, blue: 0.0).opacity(0.45)),
                lineWidth: 0.8
            )

            // Specular highlight along the inner (aperture-facing) edge.
            let edge = bladeInnerEdge(index: i, metrics: metrics)
            ctx.stroke(
                edge,
                with: .color(Color(red: 0.85, green: 0.88, blue: 0.95).opacity(0.55)),
                lineWidth: max(metrics.minDim * 0.006, 0.8)
            )
        }
    }

    /// One curved blade: a quad spanning from the rim inward, with its inner edge
    /// hugging two adjacent vertices of the opening polygon (so blades register
    /// exactly with the mask).
    private func bladePath(index: Int, metrics: IrisShutterView_IrisMetrics) -> Path {
        let inner = metrics.openingVertices
        let n = inner.count
        let a = inner[index % n]
        let b = inner[(index + 1) % n]

        // Outer arc points pushed out to (beyond) the rim along each vertex angle.
        let outerR: CGFloat = metrics.outerRadius * 1.25
        let aAng: CGFloat = metrics.vertexAngle(index)
        let bAng: CGFloat = metrics.vertexAngle(index + 1)
        let outerA = metrics.point(angle: aAng, radius: outerR)
        let outerB = metrics.point(angle: bAng, radius: outerR)

        var path = Path()
        path.move(to: a)
        // Inner edge bows slightly outward for the curved-iris look.
        path.addQuadCurve(to: b, control: metrics.innerEdgeControl(index))
        path.addLine(to: outerB)
        path.addLine(to: outerA)
        path.closeSubpath()
        return path
    }

    private func bladeInnerEdge(index: Int, metrics: IrisShutterView_IrisMetrics) -> Path {
        let inner = metrics.openingVertices
        let n = inner.count
        let a = inner[index % n]
        let b = inner[(index + 1) % n]
        var path = Path()
        path.move(to: a)
        path.addQuadCurve(to: b, control: metrics.innerEdgeControl(index))
        return path
    }
}

// MARK: - Iris geometry

/// All shared geometry for a given size + progress. Both the mask polygon and the
/// decorative blades derive from this single source so they stay registered.
private struct IrisShutterView_IrisMetrics {
    let size: CGSize
    let progress: CGFloat
    let bladeCount: Int

    let center: CGPoint
    let minDim: CGFloat
    let outerRadius: CGFloat
    let bezelInset: CGFloat
    let openingRadius: CGFloat
    let rotation: CGFloat
    let openingVertices: [CGPoint]

    init(size: CGSize, progress: CGFloat, bladeCount: Int) {
        self.size = size
        self.progress = progress
        self.bladeCount = bladeCount

        let c = CGPoint(x: size.width / 2, y: size.height / 2)
        self.center = c
        let m: CGFloat = min(size.width, size.height)
        self.minDim = m

        let inset: CGFloat = m * 0.02
        self.bezelInset = inset
        // Outer radius reaches the bezel ring.
        self.outerRadius = m / 2 - inset

        // Opening grows linearly with progress from a tiny pinhole to slightly
        // past the rim so it fully clears the frame when open. (Easing is applied
        // by the caller's spring / demo wave, so we keep this linear to avoid
        // double-easing.)
        let minR: CGFloat = m * 0.02
        let maxR: CGFloat = (m / 2) * 1.18
        self.openingRadius = minR + (maxR - minR) * progress

        // Blades spiral: rotate ~52 degrees as the aperture opens.
        self.rotation = (52 * .pi / 180) * progress

        // Precompute polygon vertices.
        var verts: [CGPoint] = []
        let n = bladeCount
        for i in 0..<n {
            let ang: CGFloat = IrisShutterView_IrisMetrics.angle(index: i, count: n, rotation: rotation)
            verts.append(CGPoint(
                x: c.x + cos(ang) * openingRadius,
                y: c.y + sin(ang) * openingRadius
            ))
        }
        self.openingVertices = verts
    }

    func vertexAngle(_ index: Int) -> CGFloat {
        IrisShutterView_IrisMetrics.angle(index: index, count: bladeCount, rotation: rotation)
    }

    func point(angle: CGFloat, radius: CGFloat) -> CGPoint {
        CGPoint(x: center.x + cos(angle) * radius, y: center.y + sin(angle) * radius)
    }

    /// Control point that bows the inner edge of a blade outward from center,
    /// giving the curved-iris polygon its convex sides.
    func innerEdgeControl(_ index: Int) -> CGPoint {
        let a0: CGFloat = vertexAngle(index)
        let a1: CGFloat = vertexAngle(index + 1)
        let mid: CGFloat = (a0 + a1) / 2
        let bow: CGFloat = openingRadius * 1.12
        return point(angle: mid, radius: bow)
    }

    func bladeBaseAngle(index: Int) -> CGFloat {
        let a0: CGFloat = vertexAngle(index)
        let a1: CGFloat = vertexAngle(index + 1)
        return (a0 + a1) / 2
    }

    static func angle(index: Int, count: Int, rotation: CGFloat) -> CGFloat {
        let step: CGFloat = (.pi * 2) / CGFloat(count)
        return CGFloat(index) * step + rotation - .pi / 2
    }
}

// MARK: - Opening polygon shape (the actual reveal mask)

private struct IrisShutterView_OpeningPolygon: Shape {
    let metrics: IrisShutterView_IrisMetrics

    func path(in rect: CGRect) -> Path {
        let verts = metrics.openingVertices
        guard verts.count >= 3 else { return Path() }
        var path = Path()
        path.move(to: verts[0])
        for i in 0..<verts.count {
            let next = verts[(i + 1) % verts.count]
            // Bowed sides match the blade inner edges exactly.
            path.addQuadCurve(to: next, control: metrics.innerEdgeControl(i))
        }
        path.closeSubpath()
        return path
    }
}
"""###,
        "tr-liquid-drip": ###"""
import SwiftUI

/// Liquid Drip Reveal
///
/// The top view's lower edge develops droplets that bulge, neck, and detach,
/// the surface melting downward to expose the view beneath. The melt is drawn
/// into a `Canvas` whose `.blur` + `.alphaThreshold` filters fuse overlapping
/// shapes into a single gooey surface (metaball necking), and that Canvas is
/// used as a `.mask` over the top view so material disappears as it drips away.
///
/// Interaction is `auto`: both the demo tile and the interactive component run
/// the same self-driving `TimelineView(.animation)` melt loop. Tapping in the
/// interactive mode re-syncs the melt to the start for a tactile restart.
struct LiquidDripView: View {
    var demo: Bool = false

    // Re-sync point for the interactive restart tap. The looped progress is
    // measured relative to this so a tap snaps the melt back to its dry state.
    @State private var loopStart: Date = .init()

    private let loopDuration: Double = 3.4

    var body: some View {
        GeometryReader { geo in
            content(size: geo.size)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .clipShape(RoundedRectangle(cornerRadius: 18, style: .continuous))
        .contentShape(Rectangle())
        .onTapGesture {
            guard !demo else { return }
            loopStart = .init()
        }
    }

    @ViewBuilder
    private func content(size: CGSize) -> some View {
        TimelineView(.animation) { timeline in
            let phase = loopPhase(now: timeline.date)
            let progress = meltProgress(phase: phase)
            ZStack {
                // The view revealed beneath the melting surface — always legible.
                bottomView(size: size)

                // The melting surface. Masked by the metaball Canvas so it
                // recedes and drips away, exposing the bottom view. During the
                // tail of the loop it crossfades back in for a seamless reset.
                topView(size: size)
                    .mask {
                        meltCanvas(progress: progress, size: size)
                    }
                    .opacity(surfaceOpacity(phase: phase))
            }
            .frame(width: size.width, height: size.height)
        }
    }

    // MARK: - Looped phase / progress

    /// 0 → 1 wall-clock loop phase derived from time so the tile animates with
    /// no touch.
    private func loopPhase(now: Date) -> CGFloat {
        let elapsed = now.timeIntervalSince(loopStart)
        let t = elapsed.truncatingRemainder(dividingBy: loopDuration) / loopDuration
        return CGFloat(t)
    }

    /// The melt itself runs over the first 82% of the loop; the final 18% holds
    /// the revealed view, then a short crossfade restores the dry surface.
    private func meltProgress(phase: CGFloat) -> CGFloat {
        let meltSpan: CGFloat = 0.82
        let raw = min(phase / meltSpan, 1.0)
        return easeInOut(raw)
    }

    /// Keeps the top surface fully opaque during the melt, then fades it back
    /// in over the last sliver of the loop so the reset reads as a soft
    /// re-forming of the surface rather than a hard snap/flash.
    private func surfaceOpacity(phase: CGFloat) -> Double {
        let fadeStart: CGFloat = 0.94
        guard phase >= fadeStart else { return 1 }
        let f = (phase - fadeStart) / (1 - fadeStart)
        return Double(easeInOut(f))
    }

    private func easeInOut(_ x: CGFloat) -> CGFloat {
        let c = min(max(x, 0), 1)
        return c * c * (3 - 2 * c)
    }

    // MARK: - Metaball melt mask

    /// White = remaining top material. A receding rect (the surface body) is
    /// unioned via the metaball filters with a row of droplet circles that
    /// travel downward and detach. The blur is applied to the raw shapes and
    /// the alphaThreshold then sharpens the blurred union into crisp necking
    /// edges (the canonical gooey-metaball recipe).
    private func meltCanvas(progress: CGFloat, size: CGSize) -> some View {
        let blur = blurRadius(for: size)
        let waterline = waterlineY(progress: progress, size: size)
        let drops = droplets(at: progress, size: size, waterline: waterline)

        return Canvas { context, _ in
            context.addFilter(.alphaThreshold(min: 0.5, color: .white))
            context.addFilter(.blur(radius: blur))
            context.drawLayer { layer in
                // The body of the surface above the waterline stays solid.
                if waterline > 0 {
                    let body = CGRect(x: -blur, y: -blur,
                                      width: size.width + blur * 2,
                                      height: waterline + blur)
                    layer.fill(Path(body), with: .color(.white))
                }
                // Droplets — circles fused to the body until their neck thins
                // past the blur threshold, then detaching and falling away.
                for drop in drops {
                    let rect = CGRect(x: drop.x - drop.radius,
                                      y: drop.y - drop.radius,
                                      width: drop.radius * 2,
                                      height: drop.radius * 2)
                    layer.fill(Path(ellipseIn: rect), with: .color(.white))
                }
            }
        }
    }

    /// Blur radius scaled to the smaller dimension so the surface-tension
    /// threshold reads identically in a 120pt tile and a large detail area.
    private func blurRadius(for size: CGSize) -> CGFloat {
        max(min(size.width, size.height) * 0.05, 3)
    }

    /// The flat surface recedes upward as the melt advances, eventually
    /// clearing the frame entirely so the bottom view is fully exposed.
    private func waterlineY(progress: CGFloat, size: CGSize) -> CGFloat {
        // Hold a thin lip early so the first droplets read as forming on a
        // surface, then sweep the waterline off the top edge.
        let receded = max(progress - 0.18, 0) / 0.82
        return size.height * (1 - easeInOut(receded))
    }

    // MARK: - Droplet model

    struct Droplet {
        var x: CGFloat
        var y: CGFloat
        var radius: CGFloat
    }

    /// Pure function: places a row of droplets along the waterline. Each has a
    /// staggered phase so they bulge, neck, and detach at different moments,
    /// giving the row a surface-tension cadence rather than marching in unison.
    private func droplets(at progress: CGFloat, size: CGSize, waterline: CGFloat) -> [Droplet] {
        let count = dropletCount(for: size)
        guard count > 0 else { return [] }

        let spacing = size.width / CGFloat(count)
        let baseRadius = spacing * 0.42
        let fallSpan = size.height + baseRadius * 2

        var result: [Droplet] = []
        result.reserveCapacity(count)

        for i in 0..<count {
            // Deterministic per-drop variation without RNG noise.
            let seed = CGFloat((i * 1664525 + 1013904223) % 997) / 997
            let phase = seed * 0.45
            let xJitter = (seed - 0.5) * spacing * 0.3
            let x = spacing * (CGFloat(i) + 0.5) + xJitter

            // Local melt for this drop: ramps after its phase delay.
            let local = clamp((progress - phase) / max(1 - phase, 0.001))

            // Bulge: radius swells from a nub to full size as it forms.
            let radius = baseRadius * (0.45 + 0.55 * easeInOut(min(local * 2, 1)))

            // Travel: the drop slides down from the waterline, accelerating
            // like gravity once it has necked off.
            let travel = easeIn(local) * fallSpan
            let y = waterline + radius * 0.4 + travel

            result.append(Droplet(x: x, y: y, radius: radius))
        }
        return result
    }

    private func dropletCount(for size: CGSize) -> Int {
        // Cap the count for Canvas redraw cost; scale gently with width.
        let n = Int((size.width / 46).rounded())
        return min(max(n, 4), 11)
    }

    private func easeIn(_ x: CGFloat) -> CGFloat {
        let c = clamp(x)
        return c * c
    }

    private func clamp(_ x: CGFloat) -> CGFloat {
        min(max(x, 0), 1)
    }

    // MARK: - Content layers

    /// The melting top surface: a warm molten gradient with a label, kept
    /// full-bleed (no inset/clip) so the mask aligns to its content.
    private func topView(size: CGSize) -> some View {
        let glyphSize = min(size.width, size.height) * 0.26
        return ZStack {
            LinearGradient(
                colors: [
                    Color(red: 0.98, green: 0.42, blue: 0.20),
                    Color(red: 0.92, green: 0.20, blue: 0.36),
                    Color(red: 0.62, green: 0.10, blue: 0.42)
                ],
                startPoint: .topLeading,
                endPoint: .bottomTrailing
            )
            // A soft top sheen so the molten surface catches light.
            LinearGradient(
                colors: [Color.white.opacity(0.35), .clear],
                startPoint: .top,
                endPoint: .center
            )
            .blendMode(.softLight)

            Image(systemName: "drop.fill")
                .font(.system(size: glyphSize, weight: .bold))
                .foregroundStyle(Color.white.opacity(0.92))
                .shadow(color: Color(red: 0.55, green: 0.05, blue: 0.30).opacity(0.5),
                        radius: glyphSize * 0.08, y: glyphSize * 0.04)
        }
        .frame(width: size.width, height: size.height)
    }

    /// The view revealed beneath: a cool teal gradient with its own glyph, so
    /// the fully-melted frame is always legible content, never blank.
    private func bottomView(size: CGSize) -> some View {
        let glyphSize = min(size.width, size.height) * 0.26
        return ZStack {
            LinearGradient(
                colors: [
                    Color(red: 0.06, green: 0.22, blue: 0.34),
                    Color(red: 0.10, green: 0.42, blue: 0.52),
                    Color(red: 0.20, green: 0.62, blue: 0.60)
                ],
                startPoint: .top,
                endPoint: .bottom
            )
            // Faint vertical streaks evoke the wet surface left behind.
            LinearGradient(
                colors: [Color.white.opacity(0.10), .clear, Color.white.opacity(0.06)],
                startPoint: .leading,
                endPoint: .trailing
            )
            .blendMode(.screen)

            Image(systemName: "sparkles")
                .font(.system(size: glyphSize, weight: .semibold))
                .foregroundStyle(Color.white.opacity(0.9))
        }
        .frame(width: size.width, height: size.height)
    }
}
"""###,
        "tr-magnetic-swap": ###"""
import SwiftUI

// MARK: - Magnetic Swap
// Two cards trade slots with a springy magnetic pull and overshoot recoil.
// demo == true  -> a self-driving PhaseAnimator loop cycles the swap continuously.
// demo == false -> a real DragGesture on a card drives the swap; release past the
//                  midpoint commits both cards with .spring(bounce:) + a haptic tick.
struct MagneticSwapView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { geo in
            if demo {
                MagneticSwapView_DemoDriver(size: geo.size)
            } else {
                MagneticSwapView_InteractiveDriver(size: geo.size)
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }
}

// MARK: - Shared geometry / colors

private enum MagneticSwapView_SwapMetrics {
    // Slot layout is computed from the available size so it reads at 120pt and large.
    static func cardSize(for size: CGSize) -> CGSize {
        let w = min(size.width, size.height * 1.6)
        let cardW = max(28, w * 0.34)
        let cardH = max(36, min(size.height * 0.62, cardW * 1.32))
        return CGSize(width: cardW, height: cardH)
    }

    // Horizontal centers of the two slots, as a fraction-driven absolute point.
    static func leftSlot(for size: CGSize) -> CGPoint {
        CGPoint(x: size.width * 0.31, y: size.height * 0.5)
    }
    static func rightSlot(for size: CGSize) -> CGPoint {
        CGPoint(x: size.width * 0.69, y: size.height * 0.5)
    }

    // Vertical arc amplitude so the two cards pass each other instead of colliding.
    static func arc(for size: CGSize) -> CGFloat {
        min(size.height * 0.22, 26)
    }
}

private enum MagneticSwapView_SwapPalette {
    static let backdropTop = Color(red: 0.07, green: 0.08, blue: 0.11)
    static let backdropBottom = Color(red: 0.04, green: 0.05, blue: 0.07)

    static let cardATop = Color(red: 0.36, green: 0.62, blue: 1.0)
    static let cardABottom = Color(red: 0.20, green: 0.34, blue: 0.92)

    static let cardBTop = Color(red: 1.0, green: 0.52, blue: 0.42)
    static let cardBBottom = Color(red: 0.93, green: 0.30, blue: 0.46)

    static let slotStroke = Color(red: 1.0, green: 1.0, blue: 1.0).opacity(0.10)
}

// MARK: - Pure progress -> layout helpers
// One render path: both drivers feed `progress` (0 = original, 1 = swapped) and
// `lean` (0...1 magnetic-attraction strength) into the same Stage view.

private struct MagneticSwapView_SwapLayout {
    let size: CGSize
    let progress: CGFloat   // 0...1 (can mildly overshoot during a spring)
    let lean: CGFloat       // 0...1 magnetic lean strength

    private var clampedP: CGFloat { min(max(progress, 0), 1) }

    // Card A travels left -> right over the top arc.
    func centerA() -> CGPoint {
        let l = MagneticSwapView_SwapMetrics.leftSlot(for: size)
        let r = MagneticSwapView_SwapMetrics.rightSlot(for: size)
        let x = l.x + (r.x - l.x) * progress
        let arc = MagneticSwapView_SwapMetrics.arc(for: size)
        // bell curve peak at p=0.5, lifting upward (negative y).
        let y = l.y - arc * bell(clampedP)
        return CGPoint(x: x, y: y)
    }

    // Card B travels right -> left under the bottom arc.
    func centerB() -> CGPoint {
        let l = MagneticSwapView_SwapMetrics.leftSlot(for: size)
        let r = MagneticSwapView_SwapMetrics.rightSlot(for: size)
        let x = r.x + (l.x - r.x) * progress
        let arc = MagneticSwapView_SwapMetrics.arc(for: size)
        let y = r.y + arc * bell(clampedP)
        return CGPoint(x: x, y: y)
    }

    // Rotation: a base tilt as it travels, plus a magnetic lean toward the partner
    // that becomes perceptible as the cards approach the swap threshold.
    func rotationA() -> Angle {
        let travel = sin(clampedP * .pi) * 8.0          // gentle banking through the arc
        let magnet = leanCurve() * 14.0 * Double(lean)  // lean toward partner
        return .degrees(Double(travel) + magnet)
    }
    func rotationB() -> Angle {
        let travel = -sin(clampedP * .pi) * 8.0
        let magnet = -leanCurve() * 14.0 * Double(lean)
        return .degrees(Double(travel) + magnet)
    }

    // A tiny pull-together offset so the stationary card visibly "reaches" toward
    // the dragged one before they commit. Scaled by card width to stay legible.
    func magneticPull() -> CGFloat {
        let cw = MagneticSwapView_SwapMetrics.cardSize(for: size).width
        return CGFloat(leanCurve()) * lean * cw * 0.16
    }

    // Lift / scale while mid-flight so the moving card feels picked up.
    func scaleA() -> CGFloat { 1.0 + 0.07 * CGFloat(bell(clampedP)) }
    func scaleB() -> CGFloat { 1.0 + 0.07 * CGFloat(bell(clampedP)) }

    // Shadow grows as the cards lift off their slots.
    func shadowRadius() -> CGFloat {
        let cw = MagneticSwapView_SwapMetrics.cardSize(for: size).width
        return cw * (0.06 + 0.16 * CGFloat(bell(clampedP)))
    }

    private func bell(_ p: CGFloat) -> Double {
        // 0 at the ends, 1 at the middle.
        Double(sin(p * .pi))
    }

    // Lean ramps up as progress approaches the midpoint and fades after passing it.
    private func leanCurve() -> Double {
        let p = Double(clampedP)
        // peak near the midpoint, signed so both halves pull inward.
        let centred = 1.0 - abs(p - 0.5) * 2.0   // 0 at ends, 1 at middle
        return max(0, centred)
    }
}

// MARK: - The shared visual stage

private struct MagneticSwapView_SwapStage: View {
    let layout: MagneticSwapView_SwapLayout
    // labels swap at the midpoint so the cards convincingly trade identities.
    var labelFlipped: Bool

    var body: some View {
        ZStack {
            backdrop
            slotGuides
            // Draw the lower-arc card first so the upper-arc card overlaps it
            // as they cross — sells the physical "lift over" swap.
            cardB
            cardA
        }
    }

    private var backdrop: some View {
        LinearGradient(
            colors: [MagneticSwapView_SwapPalette.backdropTop, MagneticSwapView_SwapPalette.backdropBottom],
            startPoint: .top, endPoint: .bottom
        )
    }

    private var slotGuides: some View {
        let cs = MagneticSwapView_SwapMetrics.cardSize(for: layout.size)
        let l = MagneticSwapView_SwapMetrics.leftSlot(for: layout.size)
        let r = MagneticSwapView_SwapMetrics.rightSlot(for: layout.size)
        return ZStack {
            slotShape(cs).position(l)
            slotShape(cs).position(r)
        }
    }

    private func slotShape(_ cs: CGSize) -> some View {
        RoundedRectangle(cornerRadius: cs.width * 0.18, style: .continuous)
            .strokeBorder(MagneticSwapView_SwapPalette.slotStroke, style: StrokeStyle(lineWidth: 1.5, dash: [5, 5]))
            .frame(width: cs.width, height: cs.height)
    }

    private var cardA: some View {
        let cs = MagneticSwapView_SwapMetrics.cardSize(for: layout.size)
        let pull = layout.magneticPull()
        return MagneticSwapView_CardFace(
            size: cs,
            top: MagneticSwapView_SwapPalette.cardATop,
            bottom: MagneticSwapView_SwapPalette.cardABottom,
            symbol: labelFlipped ? "bolt.fill" : "sparkles",
            shadow: layout.shadowRadius()
        )
        .scaleEffect(layout.scaleA())
        .rotationEffect(layout.rotationA())
        .position(layout.centerA())
        // pull toward partner (A pulls right toward B's origin slot).
        .offset(x: pull)
    }

    private var cardB: some View {
        let cs = MagneticSwapView_SwapMetrics.cardSize(for: layout.size)
        let pull = layout.magneticPull()
        return MagneticSwapView_CardFace(
            size: cs,
            top: MagneticSwapView_SwapPalette.cardBTop,
            bottom: MagneticSwapView_SwapPalette.cardBBottom,
            symbol: labelFlipped ? "sparkles" : "bolt.fill",
            shadow: layout.shadowRadius()
        )
        .scaleEffect(layout.scaleB())
        .rotationEffect(layout.rotationB())
        .position(layout.centerB())
        // B pulls left toward A's origin slot.
        .offset(x: -pull)
    }
}

private struct MagneticSwapView_CardFace: View {
    let size: CGSize
    let top: Color
    let bottom: Color
    let symbol: String
    let shadow: CGFloat

    var body: some View {
        let radius = size.width * 0.18
        RoundedRectangle(cornerRadius: radius, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [top, bottom],
                    startPoint: .topLeading, endPoint: .bottomTrailing
                )
            )
            .overlay(sheen(radius: radius))
            .overlay(
                RoundedRectangle(cornerRadius: radius, style: .continuous)
                    .strokeBorder(Color(red: 1, green: 1, blue: 1).opacity(0.22), lineWidth: 1)
            )
            .overlay(glyph)
            .frame(width: size.width, height: size.height)
            .shadow(color: Color(red: 0, green: 0, blue: 0).opacity(0.45),
                    radius: shadow, x: 0, y: shadow * 0.45)
    }

    private func sheen(radius: CGFloat) -> some View {
        RoundedRectangle(cornerRadius: radius, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 1, green: 1, blue: 1).opacity(0.30),
                        Color(red: 1, green: 1, blue: 1).opacity(0.0)
                    ],
                    startPoint: .top, endPoint: .center
                )
            )
            .blendMode(.screen)
    }

    private var glyph: some View {
        Image(systemName: symbol)
            .font(.system(size: size.width * 0.30, weight: .bold))
            .foregroundStyle(Color(red: 1, green: 1, blue: 1).opacity(0.92))
            .shadow(color: Color(red: 0, green: 0, blue: 0).opacity(0.3), radius: 2, y: 1)
    }
}

// MARK: - Demo driver (self-playing, no touch, ~3.2s loop)

private struct MagneticSwapView_DemoDriver: View {
    let size: CGSize

    // Phases: hold at 0, swap to 1, hold at 1, swap back to 0.
    private let phases: [CGFloat] = [0, 0, 1, 1, 0]

    var body: some View {
        PhaseAnimator(phases) { p in
            let lean = leanStrength(for: p)
            MagneticSwapView_SwapStage(
                layout: MagneticSwapView_SwapLayout(size: size, progress: p, lean: lean),
                labelFlipped: p >= 0.5
            )
        } animation: { _ in
            // Bouncy commit gives the overshoot recoil; the held phases keep the
            // overall cadence inside the 2.5-4s window without strobing.
            .spring(response: 0.7, dampingFraction: 0.55).delay(0.35)
        }
    }

    private func leanStrength(for p: CGFloat) -> CGFloat {
        // Always show some magnetism so the tile reads as "magnetic" even at rest.
        0.85
    }
}

// MARK: - Interactive driver

private struct MagneticSwapView_InteractiveDriver: View {
    let size: CGSize

    @State private var committed: CGFloat = 0      // 0 or 1: last settled state
    @State private var dragProgress: CGFloat = 0   // live progress while dragging
    @State private var isDragging: Bool = false
    @State private var snapTick: Int = 0           // drives sensory feedback on commit

    var body: some View {
        let progress = isDragging ? dragProgress : committed
        let lean: CGFloat = isDragging ? 1.0 : 0.0

        MagneticSwapView_SwapStage(
            layout: MagneticSwapView_SwapLayout(size: size, progress: progress, lean: lean),
            labelFlipped: progress >= 0.5
        )
        .contentShape(Rectangle())
        .gesture(dragGesture)
        .sensoryFeedback(.impact(flexibility: .soft), trigger: snapTick)
    }

    private var dragGesture: some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                if !isDragging { isDragging = true }
                let span = travelSpan()
                // Translation along the swap axis; direction depends on which way
                // we're currently swapping (0->1 moves right, 1->0 moves left).
                let raw = committed == 0 ? value.translation.width : -value.translation.width
                let delta = raw / span
                let base = committed
                dragProgress = clamp(base + delta)
            }
            .onEnded { value in
                let span = travelSpan()
                let raw = committed == 0 ? value.translation.width : -value.translation.width
                let velocity = committed == 0 ? value.predictedEndTranslation.width
                                              : -value.predictedEndTranslation.width
                let projected = (raw + (velocity - raw) * 0.25) / span
                let target: CGFloat = (committed + projected) >= 0.5 ? 1 : 0

                let changed = target != committed
                withAnimation(.spring(response: 0.5, dampingFraction: 0.55)) {
                    committed = target
                    dragProgress = target
                    isDragging = false
                }
                if changed { snapTick += 1 } // haptic only on a real commit
            }
    }

    private func travelSpan() -> CGFloat {
        let l = MagneticSwapView_SwapMetrics.leftSlot(for: size)
        let r = MagneticSwapView_SwapMetrics.rightSlot(for: size)
        return max(1, r.x - l.x)
    }

    private func clamp(_ v: CGFloat) -> CGFloat { min(max(v, 0), 1) }
}
"""###,
        "tr-metaball-merge": ###"""
import SwiftUI

/// Metaball Merge Reveal — two rounded pill blobs slide toward each other inside a
/// Canvas whose layer is blurred then alpha-thresholded, so the overlapping blurred
/// fields snap into a gooey liquid neck that pinches and separates. The thresholded
/// Canvas is used as a `.mask` over a gradient-filled container, so the merge resolves
/// into a clean destination shape rather than a flat fill.
///
/// - demo == true  → a self-driving TimelineView loop scrubs the blob separation on a
///                   ~3s cycle: blobs fuse into one, stretch a neck, pinch, separate.
/// - demo == false → still TimelineView-driven, but a DragGesture lets you scrub the
///                   separation by hand (drag to pull the blobs together / apart and
///                   watch the neck form and snap); release resumes the auto loop.
///
/// Pure SwiftUI Canvas filters (`.blur` + `.alphaThreshold`, both iOS 15+), iOS 17 clean.
struct MetaballMergeView: View {
    var demo: Bool = false

    // Live hand-scrub state (only used when demo == false).
    @State private var isDragging: Bool = false
    @State private var dragProgress: CGFloat = 0.5

    var body: some View {
        GeometryReader { geo in
            let size = geo.size
            content(size: size)
                .frame(maxWidth: .infinity, maxHeight: .infinity)
                .contentShape(Rectangle())
                // Attach the scrub gesture always, but mask it off in demo mode so
                // demo == true stays a pure auto-loop. (`Optional<Gesture>` is not a
                // Gesture, so a `demo ? nil : gesture` ternary would not type-check.)
                .gesture(scrubGesture(size: size), including: demo ? .subviews : .all)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .background(Color(red: 0.051, green: 0.063, blue: 0.086)) // #0d1016 tint
    }

    // MARK: - Composition

    @ViewBuilder
    private func content(size: CGSize) -> some View {
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            let progress = currentProgress(time: t)
            ZStack {
                backdrop(size: size)
                MetaballMergeView_MetaballField(progress: progress, gradient: blobGradient)
                    .allowsHitTesting(false)
                glints(size: size, progress: progress)
                    .allowsHitTesting(false)
            }
        }
    }

    /// The resolved progress (0…1) that drives blob separation.
    /// 0   → fully merged (one blob)
    /// ~0.5 → necked gooey bridge
    /// 1   → separated (two distinct capsules)
    private func currentProgress(time t: TimeInterval) -> CGFloat {
        if !demo && isDragging {
            return dragProgress
        }
        // Smooth, eased back-and-forth: merge → neck → separate → neck → merge.
        let period: Double = 3.2
        let phase = (t.truncatingRemainder(dividingBy: period)) / period // 0..1
        let triangle = phase < 0.5 ? phase * 2.0 : (1.0 - phase) * 2.0    // 0..1..0
        let eased = easeInOut(CGFloat(triangle))
        return eased
    }

    private func easeInOut(_ x: CGFloat) -> CGFloat {
        let c = min(max(x, 0), 1)
        return c * c * (3 - 2 * c)
    }

    // MARK: - Subviews

    private func backdrop(size: CGSize) -> some View {
        let m = min(size.width, size.height)
        return RoundedRectangle(cornerRadius: m * 0.16, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.078, green: 0.094, blue: 0.137),
                        Color(red: 0.043, green: 0.051, blue: 0.078)
                    ],
                    startPoint: .top, endPoint: .bottom
                )
            )
            .overlay(
                RoundedRectangle(cornerRadius: m * 0.16, style: .continuous)
                    .strokeBorder(Color.white.opacity(0.05), lineWidth: 1)
            )
            .padding(m * 0.07)
    }

    /// Specular glints anchored to the two blob centers so the goo reads as glossy.
    private func glints(size: CGSize, progress: CGFloat) -> some View {
        let layout = MetaballMergeView_MetaballField.layout(for: size)
        let sep = MetaballMergeView_MetaballField.separation(progress: progress, blobR: layout.blobR)
        let left = CGPoint(x: layout.center.x - sep, y: layout.center.y)
        let right = CGPoint(x: layout.center.x + sep, y: layout.center.y)
        let glintR = layout.blobR * 0.42
        return ZStack {
            glintDot(at: left, radius: glintR)
            glintDot(at: right, radius: glintR)
        }
    }

    private func glintDot(at p: CGPoint, radius: CGFloat) -> some View {
        Circle()
            .fill(
                RadialGradient(
                    colors: [Color.white.opacity(0.55), Color.white.opacity(0.0)],
                    center: .center, startRadius: 0, endRadius: radius
                )
            )
            .frame(width: radius * 2, height: radius * 2)
            .position(x: p.x - radius * 0.45, y: p.y - radius * 0.5)
            .blendMode(.screen)
    }

    private var blobGradient: LinearGradient {
        LinearGradient(
            colors: [
                Color(red: 0.404, green: 0.522, blue: 1.0),   // periwinkle
                Color(red: 0.706, green: 0.420, blue: 0.973),  // violet
                Color(red: 0.984, green: 0.451, blue: 0.643)   // pink
            ],
            startPoint: .topLeading, endPoint: .bottomTrailing
        )
    }

    // MARK: - Gesture (demo == false)

    private func scrubGesture(size: CGSize) -> some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                isDragging = true
                // Map horizontal drag position across the view to separation 0…1.
                let w = max(size.width, 1)
                let p = value.location.x / w
                dragProgress = min(max(p, 0), 1)
            }
            .onEnded { _ in
                isDragging = false
            }
    }
}

// MARK: - Metaball Canvas (blur → alphaThreshold) used as a gradient mask

private struct MetaballMergeView_MetaballField: View {
    var progress: CGFloat
    var gradient: LinearGradient

    struct Layout {
        var center: CGPoint
        var blobR: CGFloat
        var blurR: CGFloat
    }

    /// Proportional geometry so the neck-pinch holds at BOTH a 120pt tile and a large detail view.
    static func layout(for size: CGSize) -> Layout {
        let m = min(size.width, size.height)
        let blobR = m * 0.17
        let blurR = blobR * 0.62
        return Layout(
            center: CGPoint(x: size.width / 2, y: size.height / 2),
            blobR: blobR,
            blurR: blurR
        )
    }

    /// Half the center-to-center distance. The travel range is a multiple of blobR,
    /// which is what makes the gooey neck form mid-range and snap past the threshold.
    /// progress 0 → centers coincident (merged); progress 1 → ~2.2×blobR apart (separated).
    static func separation(progress: CGFloat, blobR: CGFloat) -> CGFloat {
        let p = min(max(progress, 0), 1)
        let maxHalfGap = blobR * 1.12          // full center gap ≈ 2.24×blobR at p=1
        return maxHalfGap * p
    }

    var body: some View {
        GeometryReader { geo in
            let size = geo.size
            let l = MetaballMergeView_MetaballField.layout(for: size)
            gradient
                .mask(maskCanvas(size: size, layout: l))
        }
    }

    private func maskCanvas(size: CGSize, layout l: Layout) -> some View {
        Canvas { ctx, canvasSize in
            // Filter order matters: a filter added LATER applies INNERMOST.
            // We want draw → blur → threshold, so add threshold first, blur second.
            ctx.addFilter(.alphaThreshold(min: 0.5, color: .white))
            ctx.addFilter(.blur(radius: l.blurR))
            ctx.drawLayer { layer in
                let sep = MetaballMergeView_MetaballField.separation(progress: progress, blobR: l.blobR)
                let left = CGPoint(x: l.center.x - sep, y: l.center.y)
                let right = CGPoint(x: l.center.x + sep, y: l.center.y)
                drawCapsule(in: layer, center: left, blobR: l.blobR)
                drawCapsule(in: layer, center: right, blobR: l.blobR)
            }
        }
    }

    private func drawCapsule(in layer: GraphicsContext, center: CGPoint, blobR: CGFloat) {
        // A vertically-oriented rounded pill blob. Opaque white so the threshold reads cleanly.
        let w = blobR * 1.7
        let h = blobR * 2.2
        let rect = CGRect(x: center.x - w / 2, y: center.y - h / 2, width: w, height: h)
        let path = Capsule(style: .continuous).path(in: rect)
        layer.fill(path, with: .color(.white))
    }
}
"""###,
        "tr-mosaic-flip": ###"""
import SwiftUI

// MARK: - Mosaic Tile Flip
// A 2D grid of tiles flips in a diagonal wave, each tile rotating on
// rotation3DEffect about .y and swapping its face from the old view to the new
// one at 90 degrees, like a split-flap departures board reshuffling.
//
// Demo: a TimelineView(.animation) drives a continuous triangle progress so the
// staggered per-tile localProgress is live every frame and the wave renders.
// Interactive: a tap toggles `flipped`; every tile springs from its OWN delayed
// .animation keyed to (row+col), which is what produces the diagonal wave (not a
// single shared withAnimation, which would flip everything in unison).

struct MosaicFlipView: View {
    var demo: Bool = false

    private let rows: Int = 5
    private let cols: Int = 6

    var body: some View {
        GeometryReader { geo in
            content(in: geo.size)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    @ViewBuilder
    private func content(in size: CGSize) -> some View {
        if demo {
            demoBody(in: size)
        } else {
            interactiveBody(in: size)
        }
    }

    // MARK: Demo (self-driving, no touch)

    private func demoBody(in size: CGSize) -> some View {
        TimelineView(.animation) { timeline in
            let progress: Double = triangleProgress(at: timeline.date)
            grid(in: size, globalProgress: progress, flipped: nil)
        }
    }

    // Continuous 0 -> 1 -> 0 triangle over `period` seconds. A triangle (not a
    // sawtooth) avoids a hard snap-reverse at the loop point so the wave breathes.
    private func triangleProgress(at date: Date) -> Double {
        let period: Double = 3.6
        let t: Double = date.timeIntervalSinceReferenceDate
        let phase: Double = (t.truncatingRemainder(dividingBy: period)) / period
        return phase < 0.5 ? phase * 2.0 : (1.0 - phase) * 2.0
    }

    // MARK: Interactive (tap to flip the wave)

    private func interactiveBody(in size: CGSize) -> some View {
        MosaicFlipView_InteractiveMosaic { flipped in
            grid(in: size, globalProgress: flipped ? 1.0 : 0.0, flipped: flipped)
        }
    }

    // MARK: Shared grid

    // `flipped` is nil in demo (value is already live per-frame, no per-tile
    // animation needed) and a Bool in interactive (drives each tile's own
    // staggered spring).
    private func grid(in size: CGSize, globalProgress: Double, flipped: Bool?) -> some View {
        let inset: CGFloat = max(4, min(size.width, size.height) * 0.05)
        let boardW: CGFloat = max(1, size.width - inset * 2)
        let boardH: CGFloat = max(1, size.height - inset * 2)
        let tileW: CGFloat = boardW / CGFloat(cols)
        let tileH: CGFloat = boardH / CGFloat(rows)
        let maxDiag: Double = Double((rows - 1) + (cols - 1))

        return ZStack {
            backdrop
            tiles(boardW: boardW, boardH: boardH,
                  tileW: tileW, tileH: tileH,
                  maxDiag: maxDiag, globalProgress: globalProgress, flipped: flipped)
                .frame(width: boardW, height: boardH)
                .clipShape(RoundedRectangle(cornerRadius: inset, style: .continuous))
                .overlay(
                    RoundedRectangle(cornerRadius: inset, style: .continuous)
                        .strokeBorder(Color(red: 1, green: 1, blue: 1).opacity(0.08), lineWidth: 1)
                )
                .shadow(color: Color(red: 0, green: 0, blue: 0).opacity(0.45),
                        radius: 12, x: 0, y: 8)
        }
        .frame(width: size.width, height: size.height)
    }

    private func tiles(boardW: CGFloat, boardH: CGFloat,
                       tileW: CGFloat, tileH: CGFloat,
                       maxDiag: Double, globalProgress: Double, flipped: Bool?) -> some View {
        ZStack(alignment: .topLeading) {
            ForEach(0..<rows, id: \.self) { row in
                ForEach(0..<cols, id: \.self) { col in
                    tile(row: row, col: col,
                         boardW: boardW, boardH: boardH,
                         tileW: tileW, tileH: tileH,
                         maxDiag: maxDiag, globalProgress: globalProgress, flipped: flipped)
                }
            }
        }
    }

    private func tile(row: Int, col: Int,
                      boardW: CGFloat, boardH: CGFloat,
                      tileW: CGFloat, tileH: CGFloat,
                      maxDiag: Double, globalProgress: Double, flipped: Bool?) -> some View {
        // Demo: localProgress is a live per-tile value (the wave lives in the value).
        // Interactive: targetProgress is the same 0/1 for every tile; the wave lives
        // entirely in the per-tile staggered .animation delay below.
        let isInteractive: Bool = flipped != nil
        let target: Double
        if isInteractive {
            target = globalProgress
        } else {
            target = localProgress(row: row, col: col, maxDiag: maxDiag, global: globalProgress)
        }

        let anim: Animation?
        if isInteractive {
            let unit: Double = 0.06
            let delay: Double = Double(row + col) * unit
            anim = .spring(response: 0.55, dampingFraction: 0.74).delay(delay)
        } else {
            anim = nil // value is already live per-frame; suppress ambient smear.
        }

        return MosaicFlipView_MosaicTile(
            row: row, col: col,
            boardW: boardW, boardH: boardH,
            tileW: tileW, tileH: tileH,
            targetProgress: target,
            animation: anim
        )
        .frame(width: tileW, height: tileH)
        .offset(x: CGFloat(col) * tileW, y: CGFloat(row) * tileH)
    }

    // Diagonal wave: stagger each tile's local progress by (row+col), windowed so
    // the flip is shorter than the full timeline. Keeps the wave readable and
    // guarantees the board is never fully edge-on at once.
    private func localProgress(row: Int, col: Int, maxDiag: Double, global: Double) -> Double {
        let diag: Double = Double(row + col)
        let norm: Double = maxDiag > 0 ? diag / maxDiag : 0
        let window: Double = 0.55           // each tile flips over 55% of the timeline
        let spread: Double = 1.0 - window   // leading delay span
        let start: Double = norm * spread
        let raw: Double = (global - start) / window
        return min(1, max(0, raw))
    }

    private var backdrop: some View {
        RoundedRectangle(cornerRadius: 18, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.05, green: 0.06, blue: 0.09),
                        Color(red: 0.02, green: 0.02, blue: 0.04)
                    ],
                    startPoint: .top, endPoint: .bottom
                )
            )
            .ignoresSafeArea()
    }
}

// MARK: - Interactive wrapper

private struct MosaicFlipView_InteractiveMosaic<Content: View>: View {
    @ViewBuilder var content: (Bool) -> Content

    @State private var flipped: Bool = false

    var body: some View {
        content(flipped)
            .contentShape(Rectangle())
            .onTapGesture {
                // No withAnimation here: each tile owns its delayed spring so the
                // angles fan out into a diagonal wave instead of flipping in unison.
                flipped.toggle()
            }
    }
}

// MARK: - Single flipping tile

private struct MosaicFlipView_MosaicTile: View {
    let row: Int
    let col: Int
    let boardW: CGFloat
    let boardH: CGFloat
    let tileW: CGFloat
    let tileH: CGFloat
    let targetProgress: Double      // 0 -> 1 for THIS tile
    let animation: Animation?       // non-nil => interactive (per-tile staggered spring)

    private var angle: Double { targetProgress * 180.0 }
    private var showsBack: Bool { angle >= 90.0 }

    var body: some View {
        ZStack {
            // Front face (old view) visible 0..<90.
            slice(of: MosaicFlipView_FaceA(boardW: boardW, boardH: boardH))
                .opacity(showsBack ? 0 : 1)

            // Back face (new view) visible 90..180.
            // Pre-rotated 180 about .y so the parent's mirroring at full flip
            // cancels out and the new face reassembles un-mirrored.
            slice(of: MosaicFlipView_FaceB(boardW: boardW, boardH: boardH))
                .rotation3DEffect(.degrees(180), axis: (x: 0, y: 1, z: 0))
                .opacity(showsBack ? 1 : 0)
        }
        .overlay(seamSheen)
        .rotation3DEffect(
            .degrees(angle),
            axis: (x: 0, y: 1, z: 0),
            anchor: .center,
            perspective: 0.55
        )
        .compositingGroup()
        .shadow(color: Color(red: 0, green: 0, blue: 0).opacity(edgeShadowOpacity),
                radius: 3, x: 0, y: 0)
        // Outermost: governs angle AND face opacities together (both derive from
        // targetProgress) so the swap stays glued to the rotation. nil in demo.
        .animation(animation, value: targetProgress)
    }

    // Edge-on tiles darken slightly for depth as they pass 90.
    private var edgeShadowOpacity: Double {
        let t: Double = abs(sin(angle * .pi / 180.0))   // peaks at 90
        return 0.05 + t * 0.35
    }

    // A thin specular line + edge shading that rakes as the tile turns.
    private var seamSheen: some View {
        let t: Double = abs(sin(angle * .pi / 180.0))
        return Rectangle()
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 1, green: 1, blue: 1).opacity(0.0),
                        Color(red: 1, green: 1, blue: 1).opacity(0.22 * t),
                        Color(red: 0, green: 0, blue: 0).opacity(0.30 * t)
                    ],
                    startPoint: .leading, endPoint: .trailing
                )
            )
            .blendMode(.plusLighter)
            .allowsHitTesting(false)
    }

    // Crop tile (row,col) out of a full-bleed face. Offset BEFORE the clipping
    // frame, top-leading alignment, so tiles reassemble seamlessly.
    private func slice<F: View>(of face: F) -> some View {
        face
            .frame(width: boardW, height: boardH)
            .offset(x: -CGFloat(col) * tileW, y: -CGFloat(row) * tileH)
            .frame(width: tileW, height: tileH, alignment: .topLeading)
            .clipped()
    }
}

// MARK: - Full-bleed faces (must span the whole rect so every slice is legible)

private struct MosaicFlipView_FaceA: View {
    let boardW: CGFloat
    let boardH: CGFloat

    var body: some View {
        ZStack {
            LinearGradient(
                colors: [
                    Color(red: 0.36, green: 0.20, blue: 0.62),
                    Color(red: 0.16, green: 0.10, blue: 0.42),
                    Color(red: 0.08, green: 0.06, blue: 0.24)
                ],
                startPoint: .topLeading, endPoint: .bottomTrailing
            )

            // Diagonal motif so edge tiles still carry detail.
            ForEach(0..<7, id: \.self) { i in
                Capsule()
                    .fill(Color(red: 1, green: 1, blue: 1).opacity(0.06))
                    .frame(width: boardW * 1.4, height: max(6, boardH * 0.05))
                    .rotationEffect(.degrees(-30))
                    .offset(y: CGFloat(i) * boardH * 0.18 - boardH * 0.6)
            }

            RadialGradient(
                colors: [
                    Color(red: 0.95, green: 0.55, blue: 0.95).opacity(0.55),
                    Color(red: 0.95, green: 0.55, blue: 0.95).opacity(0.0)
                ],
                center: .init(x: 0.3, y: 0.3),
                startRadius: 0,
                endRadius: max(boardW, boardH) * 0.7
            )
        }
        .frame(width: boardW, height: boardH)
    }
}

private struct MosaicFlipView_FaceB: View {
    let boardW: CGFloat
    let boardH: CGFloat

    var body: some View {
        ZStack {
            LinearGradient(
                colors: [
                    Color(red: 0.04, green: 0.55, blue: 0.58),
                    Color(red: 0.05, green: 0.32, blue: 0.55),
                    Color(red: 0.03, green: 0.14, blue: 0.30)
                ],
                startPoint: .topLeading, endPoint: .bottomTrailing
            )

            // Grid motif so every slice reads as part of the new face.
            ForEach(0..<8, id: \.self) { i in
                Rectangle()
                    .fill(Color(red: 1, green: 1, blue: 1).opacity(0.05))
                    .frame(width: max(2, boardW * 0.012), height: boardH * 1.4)
                    .offset(x: CGFloat(i) * boardW * 0.14 - boardW * 0.5)
            }

            RadialGradient(
                colors: [
                    Color(red: 0.45, green: 1.0, blue: 0.85).opacity(0.55),
                    Color(red: 0.45, green: 1.0, blue: 0.85).opacity(0.0)
                ],
                center: .init(x: 0.7, y: 0.7),
                startRadius: 0,
                endRadius: max(boardW, boardH) * 0.7
            )
        }
        .frame(width: boardW, height: boardH)
    }
}
"""###,
        "tr-origami-unfold": ###"""
import SwiftUI

/// Origami Unfold — a folded paper card opens along three creased panels that
/// rotate in sequence on alternating hinge axes, revealing the destination view
/// as the paper flattens. Each panel casts a soft crease-shadow on the one
/// beneath it so it reads as real folded paper unfurling rather than a flat flip.
///
/// A single 0→1 `progress` drives all three hinge angles via STAGGERED windows
/// (`panelProgress`), so the flaps open one after another. For the stagger to
/// actually render, `progress` must flow through continuous intermediate values
/// — SwiftUI only re-evaluates a body at animation endpoints, so we never let it
/// interpolate the raw rotation angles directly:
/// - demo == true  → `TimelineView(.animation)` feeds a continuous 0→1→0 ramp.
/// - demo == false → `OrigamiUnfoldView_FoldingCard` is `Animatable` on `progress`, so
///   `withAnimation(.spring)` interpolates `progress` THROUGH the body, which
///   re-runs `panelProgress` every frame and surfaces the real staggered fold.
struct OrigamiUnfoldView: View {
    var demo: Bool = false

    @State private var isOpen: Bool = false

    var body: some View {
        GeometryReader { geo in
            content(size: geo.size)
                .frame(width: geo.size.width, height: geo.size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    @ViewBuilder
    private func content(size: CGSize) -> some View {
        if demo {
            TimelineView(.animation) { timeline in
                let p = OrigamiUnfoldView.loopProgress(timeline.date)
                OrigamiUnfoldView_FoldingCard(progress: p, size: size)
            }
        } else {
            OrigamiUnfoldView_FoldingCard(progress: isOpen ? 1.0 : 0.0, size: size)
                .contentShape(Rectangle())
                .onTapGesture {
                    withAnimation(.spring(duration: 0.6, bounce: 0.22)) {
                        isOpen.toggle()
                    }
                }
        }
    }

    /// Continuous, looping 0→1→0 triangle ramp (~3.2s) with a smooth ease so the
    /// demo tile breathes open and closed forever with no input. Never settles
    /// at a blank state — the base card is always legible underneath.
    private static func loopProgress(_ date: Date) -> Double {
        let period: Double = 3.2
        let t = date.timeIntervalSinceReferenceDate.truncatingRemainder(dividingBy: period) / period
        let triangle = t < 0.5 ? (t * 2.0) : (2.0 - t * 2.0)   // 0→1→0
        return triangle * triangle * (3.0 - 2.0 * triangle)     // smoothstep ease
    }
}

// MARK: - Animatable folding card

/// The folded card: a fixed base panel plus three flaps that fold over it.
/// Conforming to `Animatable` on `progress` is what makes the staggered
/// sequence visible during `withAnimation` — SwiftUI interpolates `progress`
/// and re-runs `body` (hence `panelProgress`) on every frame.
private struct OrigamiUnfoldView_FoldingCard: View, Animatable {
    var progress: Double
    var size: CGSize

    var animatableData: Double {
        get { progress }
        set { progress = newValue }
    }

    var body: some View {
        let side = min(size.width, size.height)
        // Open, the card is a cross 3·unit tall × 2·unit wide; unit = 0.30·side
        // keeps it inside both a ~120pt grid tile and a large detail area.
        let unit = side * 0.30
        let cx = size.width / 2
        let cy = size.height / 2

        return ZStack {
            backdrop
            card(unit: unit)
                .position(x: cx, y: cy)
        }
    }

    /// Soft ambient backdrop that warms slightly as the card opens, so a frame
    /// is never blank even at the folded extreme.
    private var backdrop: some View {
        let warm = 0.06 + clamp(progress, 0, 1) * 0.05
        return LinearGradient(
            colors: [
                Color(red: 0.05 + warm, green: 0.06 + warm, blue: 0.10 + warm),
                Color(red: 0.03, green: 0.035, blue: 0.06)
            ],
            startPoint: .top, endPoint: .bottom
        )
    }
}

// MARK: - Card composition

private extension OrigamiUnfoldView_FoldingCard {

    func card(unit: CGFloat) -> some View {
        // Three flaps unfold over overlapping staggered windows so only one is
        // ever near edge-on at a time and the motion reads as a sequence.
        let pAbove = panelProgress(index: 0)   // .x hinge (top)
        let pRight = panelProgress(index: 1)   // .y hinge
        let pBelow = panelProgress(index: 2)   // .x hinge (bottom)

        return ZStack {
            // Base — always face-on, the anchor the flaps fold onto. Its emblem
            // is the revealed content, so something legible shows beneath the
            // folding paper at every frame.
            basePanel(unit: unit)

            foldingPanel(unit: unit, fold: pAbove, slot: .above,
                         glyph: "leaf.fill",
                         tint: Color(red: 0.36, green: 0.72, blue: 0.62))
            foldingPanel(unit: unit, fold: pRight, slot: .right,
                         glyph: "sparkles",
                         tint: Color(red: 0.95, green: 0.78, blue: 0.42))
            foldingPanel(unit: unit, fold: pBelow, slot: .below,
                         glyph: "moon.stars.fill",
                         tint: Color(red: 0.62, green: 0.55, blue: 0.95))
        }
        .frame(width: unit, height: unit)
    }

    /// The fixed base square; the emblem fades up as the card opens.
    func basePanel(unit: CGFloat) -> some View {
        let reveal = smoothstep(progress)
        return RoundedRectangle(cornerRadius: unit * 0.07, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.97, green: 0.96, blue: 0.93),
                        Color(red: 0.90, green: 0.88, blue: 0.83)
                    ],
                    startPoint: .topLeading, endPoint: .bottomTrailing
                )
            )
            .overlay {
                Image(systemName: "circle.hexagongrid.fill")
                    .font(.system(size: unit * 0.34, weight: .light))
                    .foregroundStyle(
                        LinearGradient(
                            colors: [
                                Color(red: 0.40, green: 0.66, blue: 0.95),
                                Color(red: 0.66, green: 0.46, blue: 0.92)
                            ],
                            startPoint: .top, endPoint: .bottom
                        )
                    )
                    .opacity(0.28 + reveal * 0.62)
                    .scaleEffect(0.84 + reveal * 0.16)
            }
            .overlay(
                RoundedRectangle(cornerRadius: unit * 0.07, style: .continuous)
                    .stroke(Color(red: 0.82, green: 0.80, blue: 0.74), lineWidth: 0.8)
            )
            .frame(width: unit, height: unit)
            .shadow(color: Color.black.opacity(0.35), radius: unit * 0.06, y: unit * 0.03)
    }
}

// MARK: - Folding flap

private extension OrigamiUnfoldView_FoldingCard {

    /// Describes a flap by its OPEN position relative to the base. Its hinge is
    /// the edge SHARED with the base, so the flap anchors on its inner edge and
    /// a constant offset + a 180°→0° rotation lands it exactly on the base when
    /// closed. Alternating .x / .y / .x axes per the spec.
    enum FlapSlot {
        case above, right, below

        var axis: (x: CGFloat, y: CGFloat, z: CGFloat) {
            switch self {
            case .above, .below: return (1, 0, 0)   // .x hinge
            case .right:         return (0, 1, 0)    // .y hinge
            }
        }

        /// Anchor = the edge shared with the base (the flap's inner edge).
        var anchor: UnitPoint {
            switch self {
            case .above: return .bottom
            case .right: return .leading
            case .below: return .top
            }
        }

        /// Constant offset placing the flap at its OPEN (coplanar) location.
        func offset(unit: CGFloat) -> (CGFloat, CGFloat) {
            switch self {
            case .above: return (0, -unit)
            case .right: return (unit, 0)
            case .below: return (0, unit)
            }
        }

        /// Crease-shadow gradient: dark at the hinge (inner) edge → clear at
        /// the free (outer) edge.
        var gradientPoints: (UnitPoint, UnitPoint) {
            switch self {
            case .above: return (.bottom, .top)
            case .right: return (.leading, .trailing)
            case .below: return (.top, .bottom)
            }
        }
    }

    /// One flap. `fold` 0 = folded flat over the base (closed card), 1 = laid
    /// flat outward beside the base (open sheet). The flap sits at a CONSTANT
    /// open offset and rotates 180°→0° about its shared (hinge) edge: at 180°
    /// the flip lands it exactly on the base (covering it, fully legible); at 0°
    /// it lies coplanar, extending the sheet. The rotation does all the
    /// translation — no animated offset needed. Layer order keeps flaps
    /// composited over the base, so the sweep direction reads as a fold.
    func foldingPanel(unit: CGFloat, fold: Double, slot: FlapSlot,
                      glyph: String, tint: Color) -> some View {
        let f = smoothstep(fold)
        let angle: Double = 180.0 * (1.0 - f)   // 180° closed → 0° open
        let (dx, dy) = slot.offset(unit: unit)

        return panelFace(unit: unit, glyph: glyph, tint: tint, openness: f)
            .overlay { creaseShadow(unit: unit, slot: slot, fold: fold) }
            .frame(width: unit, height: unit)
            .rotation3DEffect(
                .degrees(angle),
                axis: slot.axis,
                anchor: slot.anchor,
                perspective: 0.45
            )
            .offset(x: dx, y: dy)
            .zIndex(2.0 - f)   // closed flaps stack on top; open they recede
    }

    /// The paper face of a flap — warm card stock with a soft tinted glyph.
    func panelFace(unit: CGFloat, glyph: String, tint: Color, openness: Double) -> some View {
        // Past 90° (openness < 0.5) the flap shows its back; SwiftUI mirrors
        // front content, so fade the glyph out while folded.
        let glyphOpacity = max(0.0, (openness - 0.5) * 2.0) * 0.9
        return RoundedRectangle(cornerRadius: unit * 0.07, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.99, green: 0.98, blue: 0.96),
                        Color(red: 0.93, green: 0.91, blue: 0.86)
                    ],
                    startPoint: .topLeading, endPoint: .bottomTrailing
                )
            )
            .overlay {
                Image(systemName: glyph)
                    .font(.system(size: unit * 0.26, weight: .regular))
                    .foregroundStyle(tint)
                    .opacity(glyphOpacity)
            }
            .overlay(
                RoundedRectangle(cornerRadius: unit * 0.07, style: .continuous)
                    .stroke(Color(red: 0.84, green: 0.81, blue: 0.75), lineWidth: 0.8)
            )
    }

    /// A gradient that darkens toward the hinge edge and deepens while the flap
    /// is still folded, so the crease reads as a real shadowed fold.
    func creaseShadow(unit: CGFloat, slot: FlapSlot, fold: Double) -> some View {
        let depth = 1.0 - smoothstep(fold)   // strong when folded, gone when flat
        let (start, end) = slot.gradientPoints
        return RoundedRectangle(cornerRadius: unit * 0.07, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color.black.opacity(depth * 0.55),
                        Color.black.opacity(0.0)
                    ],
                    startPoint: start, endPoint: end
                )
            )
            .blendMode(.multiply)
    }
}

// MARK: - Progress shaping

private extension OrigamiUnfoldView_FoldingCard {

    /// Stagger the three flaps across the master progress so they open in
    /// sequence (above → right → below). Each opens over a 0.6-wide window
    /// offset by 0.2 per index; windows overlap so the motion stays fluid while
    /// only one flap is ever near edge-on at a time.
    func panelProgress(index: Int) -> Double {
        let start = Double(index) * 0.20
        let span: Double = 0.60
        let local = (progress - start) / span
        return clamp(local, 0.0, 1.0)
    }
}

// MARK: - Math helpers (file-private free functions)

private func smoothstep(_ x: Double) -> Double {
    let t = clamp(x, 0.0, 1.0)
    return t * t * (3.0 - 2.0 * t)
}

private func clamp(_ v: Double, _ lo: Double, _ hi: Double) -> Double {
    min(max(v, lo), hi)
}
"""###,
        "tr-page-peel": ###"""
import SwiftUI

// MARK: - Page Peel
// A corner-anchored faked page curl. The bottom-right corner lifts and rotates
// away via a single rotation3DEffect about the anti-diagonal axis, anchored at
// the opposite (top-leading) corner that stays pinned. A LinearGradient shadow
// gutter widens along the fold and a tinted back-of-page shows through, while
// the next page is revealed underneath.
//
// demo == true  -> a TimelineView self-drives the curl progress 0 -> 1 -> 0.
// demo == false -> a DragGesture on the lifted corner maps finger distance to
//                  the curl progress; release past a threshold springs the page
//                  fully off (advancing to the next page), else springs flat.

struct PagePeelView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { proxy in
            content(in: proxy.size)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    @ViewBuilder
    private func content(in size: CGSize) -> some View {
        if demo {
            PagePeelView_PagePeelDemo(size: size)
        } else {
            PagePeelView_PagePeelInteractive(size: size)
        }
    }
}

// MARK: - Shared palette / content

private enum PagePeelView_PeelPalette {
    static let paperTop = Color(red: 0.97, green: 0.96, blue: 0.93)
    static let paperBottom = Color(red: 0.93, green: 0.91, blue: 0.86)
    static let backTintTop = Color(red: 0.82, green: 0.80, blue: 0.74)
    static let backTintBottom = Color(red: 0.70, green: 0.67, blue: 0.60)
    static let ink = Color(red: 0.16, green: 0.17, blue: 0.22)
    static let accentA = Color(red: 0.20, green: 0.52, blue: 0.96)
    static let accentB = Color(red: 0.55, green: 0.30, blue: 0.92)

    static func pageTint(for index: Int) -> Color {
        let palette: [Color] = [
            Color(red: 0.97, green: 0.96, blue: 0.93),
            Color(red: 0.95, green: 0.93, blue: 0.97),
            Color(red: 0.93, green: 0.97, blue: 0.95),
            Color(red: 0.97, green: 0.95, blue: 0.92)
        ]
        return palette[((index % palette.count) + palette.count) % palette.count]
    }
}

// MARK: - A single page's face content

private struct PagePeelView_PageFace: View {
    let index: Int
    let size: CGSize

    private var corner: CGFloat { min(size.width, size.height) * 0.06 }
    private var pad: CGFloat { max(8.0, min(size.width, size.height) * 0.1) }
    private var numberSize: CGFloat { min(size.width, size.height) * 0.42 }
    private var lineColor: Color {
        Color(red: 0.16, green: 0.17, blue: 0.22).opacity(0.10)
    }

    var body: some View {
        ZStack {
            RoundedRectangle(cornerRadius: corner, style: .continuous)
                .fill(
                    LinearGradient(
                        colors: [PagePeelView_PeelPalette.pageTint(for: index), PagePeelView_PeelPalette.paperBottom],
                        startPoint: .top,
                        endPoint: .bottom
                    )
                )

            ruledLines

            pageNumber
        }
        .clipShape(RoundedRectangle(cornerRadius: corner, style: .continuous))
        .overlay(
            RoundedRectangle(cornerRadius: corner, style: .continuous)
                .strokeBorder(PagePeelView_PeelPalette.ink.opacity(0.08), lineWidth: 1)
        )
    }

    private var ruledLines: some View {
        VStack(spacing: max(6.0, size.height * 0.075)) {
            ForEach(0..<7, id: \.self) { _ in
                Capsule().fill(lineColor).frame(height: 2)
            }
        }
        .padding(.horizontal, pad)
        .padding(.vertical, pad * 0.6)
    }

    private var pageNumber: some View {
        Text("\(index + 1)")
            .font(.system(size: numberSize, weight: .heavy, design: .rounded))
            .foregroundStyle(
                LinearGradient(
                    colors: [PagePeelView_PeelPalette.accentA, PagePeelView_PeelPalette.accentB],
                    startPoint: .topLeading,
                    endPoint: .bottomTrailing
                )
            )
            .minimumScaleFactor(0.3)
            .opacity(0.92)
    }
}

// MARK: - The peeling top page (front + tinted back share ONE rotation)

private struct PagePeelView_PeelingPage: View {
    let frontIndex: Int
    let progress: CGFloat        // 0 = flat, 1 = folded fully back
    let size: CGSize

    // The lifted (bottom-right) corner rotates about the anti-diagonal axis,
    // pinned at the opposite top-leading corner. Stop short of 180 so the back
    // stays visible and the page never flattens perfectly onto the next one.
    private var angle: Double { Double(progress) * 158.0 }
    private var corner: CGFloat { min(size.width, size.height) * 0.06 }

    // Past 90deg the front is hidden and the tinted back faces us. Because the
    // back is a flat gradient, the mirroring rotation3DEffect applies is invisible,
    // so we avoid any counter-rotation.
    private var showBack: Bool { angle >= 90.0 }

    var body: some View {
        ZStack {
            PagePeelView_PageFace(index: frontIndex, size: size)
                .opacity(showBack ? 0 : 1)

            backFace
                .opacity(showBack ? 1 : 0)
        }
        .frame(width: size.width, height: size.height)
        // ASSUMPTION: positive angle lifts the bottom-right corner toward the
        // viewer. If it folds the wrong way on device, negate `angle` or flip
        // the axis signs — geometry is otherwise correct by construction.
        .rotation3DEffect(
            .degrees(angle),
            axis: (x: 1.0, y: -1.0, z: 0.0),
            anchor: .topLeading,
            perspective: 0.55
        )
        // Soft self-shadow that deepens as the page lifts, grounding the curl.
        .shadow(
            color: Color.black.opacity(0.28 * Double(progress)),
            radius: 14 * progress,
            x: -8 * progress,
            y: 8 * progress
        )
    }

    private var backFace: some View {
        RoundedRectangle(cornerRadius: corner, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [PagePeelView_PeelPalette.backTintTop, PagePeelView_PeelPalette.backTintBottom],
                    startPoint: .topLeading,
                    endPoint: .bottomTrailing
                )
            )
            .overlay(curlSheen)
            .overlay(
                RoundedRectangle(cornerRadius: corner, style: .continuous)
                    .strokeBorder(PagePeelView_PeelPalette.ink.opacity(0.12), lineWidth: 1)
            )
    }

    // A bright band running along the fold crease sells the paper's curved back.
    private var curlSheen: some View {
        LinearGradient(
            colors: [
                Color.white.opacity(0.0),
                Color.white.opacity(0.35),
                Color.white.opacity(0.0)
            ],
            startPoint: .topTrailing,
            endPoint: .bottomLeading
        )
        .blendMode(.softLight)
    }
}

// MARK: - Shadow gutter cast on the next page along the fold

private struct PagePeelView_ShadowGutter: View {
    let progress: CGFloat
    let size: CGSize

    private var corner: CGFloat { min(size.width, size.height) * 0.06 }

    var body: some View {
        RoundedRectangle(cornerRadius: corner, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color.black.opacity(0.0),
                        Color.black.opacity(0.30 * Double(progress)),
                        Color.black.opacity(0.0)
                    ],
                    startPoint: .topTrailing,
                    endPoint: .bottomLeading
                )
            )
            // The gutter widens as the fold opens.
            .scaleEffect(x: 0.4 + 0.9 * progress, y: 0.4 + 0.9 * progress, anchor: .bottomTrailing)
            .opacity(Double(min(1.0, progress * 1.6)))
            .allowsHitTesting(false)
    }
}

// MARK: - Composed peel stack (shared by demo + interactive)

private struct PagePeelView_PeelStack: View {
    let topIndex: Int
    let progress: CGFloat
    let size: CGSize

    var body: some View {
        ZStack {
            // Bottom: the next page, always fully rendered so the edge-on
            // mid-frame never goes blank.
            PagePeelView_PageFace(index: topIndex + 1, size: size)

            // Middle: the fold's cast shadow on the next page.
            PagePeelView_ShadowGutter(progress: progress, size: size)

            // Top: the peeling page itself.
            PagePeelView_PeelingPage(frontIndex: topIndex, progress: progress, size: size)
        }
        .frame(width: size.width, height: size.height)
    }
}

// MARK: - Demo (self-driving)

private struct PagePeelView_PagePeelDemo: View {
    let size: CGSize

    var body: some View {
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            PagePeelView_PeelStack(topIndex: 0, progress: demoProgress(t), size: insetSize)
                .padding(insetPadding)
        }
        .frame(width: size.width, height: size.height)
    }

    private var insetPadding: CGFloat { min(size.width, size.height) * 0.08 }
    private var insetSize: CGSize {
        CGSize(
            width: max(1, size.width - insetPadding * 2),
            height: max(1, size.height - insetPadding * 2)
        )
    }

    // ~3.4s loop: ease 0 -> 1 -> 0 with a brief hold at each end so the reveal reads.
    private func demoProgress(_ time: TimeInterval) -> CGFloat {
        let period: Double = 3.4
        let phase = (time.truncatingRemainder(dividingBy: period)) / period // 0..1
        let triangle: Double = phase < 0.5 ? (phase * 2.0) : (2.0 - phase * 2.0)
        let eased = easeInOut(triangle)
        return CGFloat(eased)
    }

    private func easeInOut(_ x: Double) -> Double {
        let c = min(max(x, 0.0), 1.0)
        return c * c * (3.0 - 2.0 * c)
    }
}

// MARK: - Interactive (drag the corner)

private struct PagePeelView_PagePeelInteractive: View {
    let size: CGSize

    @State private var topIndex: Int = 0
    @State private var progress: CGFloat = 0
    @State private var dragging: Bool = false

    var body: some View {
        PagePeelView_PeelStack(topIndex: topIndex, progress: progress, size: insetSize)
            .padding(insetPadding)
            .contentShape(Rectangle())
            .gesture(peelGesture)
            .animation(dragging ? nil : .spring(response: 0.5, dampingFraction: 0.72), value: progress)
            .frame(width: size.width, height: size.height)
    }

    private var insetPadding: CGFloat { min(size.width, size.height) * 0.08 }
    private var insetSize: CGSize {
        CGSize(
            width: max(1, size.width - insetPadding * 2),
            height: max(1, size.height - insetPadding * 2)
        )
    }

    // The lifted corner is the bottom-right of the inset page.
    private var liftedCorner: CGPoint {
        CGPoint(x: size.width - insetPadding, y: size.height - insetPadding)
    }

    private var diagonalLength: CGFloat {
        let w = insetSize.width
        let h = insetSize.height
        return max(1.0, sqrt(w * w + h * h))
    }

    private var peelGesture: some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                dragging = true
                progress = progressFor(location: value.location)
            }
            .onEnded { value in
                dragging = false
                let final = progressFor(location: value.location)
                if final > 0.5 {
                    // Commit: peel fully off, then swap in the next page flat.
                    withAnimation(.spring(response: 0.45, dampingFraction: 0.78)) {
                        progress = 1.0
                    }
                    DispatchQueue.main.asyncAfter(deadline: .now() + 0.42) {
                        // Swap the revealed page in instantly: suppress the
                        // `.animation(value: progress)` so the fresh page does
                        // not peel down from folded — it appears flat.
                        var txn = Transaction()
                        txn.disablesAnimations = true
                        withTransaction(txn) {
                            topIndex += 1
                            progress = 0.0
                        }
                    }
                } else {
                    withAnimation(.spring(response: 0.5, dampingFraction: 0.72)) {
                        progress = 0.0
                    }
                }
            }
    }

    // Distance the finger has pulled the lifted corner toward the hinge maps to
    // curl progress, clamped to 0...1.
    private func progressFor(location: CGPoint) -> CGFloat {
        let dx = liftedCorner.x - location.x
        let dy = liftedCorner.y - location.y
        let pulled = sqrt(dx * dx + dy * dy)
        let raw = pulled / diagonalLength
        return min(max(raw, 0.0), 1.0)
    }
}
"""###,
        "tr-spotlight-sweep": ###"""
import SwiftUI

/// Spotlight Sweep — a moving radial spotlight mask travels across the view, and
/// wherever its soft-edged beam falls the "after" scene is revealed over the
/// "before" scene. A penumbra falloff makes content fade up gradually, like a
/// torch sweeping a dark room.
///
/// - demo == true:  a TimelineView(.animation) drives the beam along a looping
///   path on a ~3.2s cycle so the tile is always alive with no touch.
/// - demo == false: a DragGesture aims the beam; the beam springs toward the
///   finger. Content fades back as the beam moves away (the plain "re-hidden
///   behind the beam" reading).
struct SpotlightSweepView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { proxy in
            let size = proxy.size
            if demo {
                demoContent(in: size)
            } else {
                interactiveContent(in: size)
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .clipShape(RoundedRectangle(cornerRadius: 18, style: .continuous))
    }

    // MARK: - Demo (self-driving)

    private func demoContent(in size: CGSize) -> some View {
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            let center = demoBeamCenter(at: t, in: size)
            let radius = beamRadius(for: size)
            sweepStack(beamCenter: center, radius: radius, in: size)
        }
    }

    /// A looping path: a left↔right sweep with a gentle vertical bob.
    /// Period ~3.2s so the spotlight crosses and returns smoothly.
    private func demoBeamCenter(at time: TimeInterval, in size: CGSize) -> CGPoint {
        let period: Double = 3.2
        let phase = (time.truncatingRemainder(dividingBy: period)) / period
        // Smooth back-and-forth on x (triangle-ish via cosine), bob on y.
        let sweep = (1.0 - cos(phase * 2.0 * .pi)) / 2.0          // 0→1→0
        let bob = sin(phase * 2.0 * .pi * 2.0)                    // -1…1, two bobs
        let margin: CGFloat = 0.16
        let x = (margin + CGFloat(sweep) * (1.0 - margin * 2.0)) * size.width
        let y = (0.5 + CGFloat(bob) * 0.16) * size.height
        return CGPoint(x: x, y: y)
    }

    // MARK: - Interactive

    private func interactiveContent(in size: CGSize) -> some View {
        SpotlightSweepView_InteractiveSweep(size: size,
                         radius: beamRadius(for: size)) { center, radius in
            sweepStack(beamCenter: center, radius: radius, in: size)
        }
    }

    // MARK: - Shared composition

    private func sweepStack(beamCenter: CGPoint, radius: CGFloat, in size: CGSize) -> some View {
        ZStack {
            SpotlightSweepView_BeforeScene()
            SpotlightSweepView_AfterScene()
                .mask(spotlightMask(center: beamCenter, radius: radius, in: size))
            // A faint warm rim so the beam reads as light, not just a reveal.
            beamGlow(center: beamCenter, radius: radius, in: size)
                .allowsHitTesting(false)
        }
    }

    private func spotlightMask(center: CGPoint, radius: CGFloat, in size: CGSize) -> some View {
        let cx = size.width > 0 ? center.x / size.width : 0.5
        let cy = size.height > 0 ? center.y / size.height : 0.5
        return RadialGradient(
            stops: [
                .init(color: .white, location: 0.0),
                .init(color: .white, location: 0.55),
                .init(color: .white.opacity(0.0), location: 1.0)
            ],
            center: UnitPoint(x: cx, y: cy),
            startRadius: 0,
            endRadius: radius
        )
    }

    private func beamGlow(center: CGPoint, radius: CGFloat, in size: CGSize) -> some View {
        let cx = size.width > 0 ? center.x / size.width : 0.5
        let cy = size.height > 0 ? center.y / size.height : 0.5
        return RadialGradient(
            stops: [
                .init(color: Color(red: 1.0, green: 0.93, blue: 0.74).opacity(0.22), location: 0.0),
                .init(color: Color(red: 1.0, green: 0.85, blue: 0.55).opacity(0.05), location: 0.5),
                .init(color: .clear, location: 1.0)
            ],
            center: UnitPoint(x: cx, y: cy),
            startRadius: 0,
            endRadius: radius * 0.95
        )
        .blendMode(.screen)
    }

    private func beamRadius(for size: CGSize) -> CGFloat {
        0.45 * min(size.width, size.height)
    }
}

// MARK: - Interactive driver

/// Holds the beam point and springs it toward the finger. Kept separate so the
/// demo path never touches @State (and never fights the TimelineView clock).
private struct SpotlightSweepView_InteractiveSweep<Content: View>: View {
    let size: CGSize
    let radius: CGFloat
    let content: (CGPoint, CGFloat) -> Content

    @State private var beam: CGPoint? = nil

    var body: some View {
        let center = beam ?? CGPoint(x: size.width / 2, y: size.height / 2)
        content(center, radius)
            .contentShape(Rectangle())
            .gesture(
                DragGesture(minimumDistance: 0)
                    .onChanged { value in
                        withAnimation(.spring(response: 0.32, dampingFraction: 0.78)) {
                            beam = clamp(value.location, in: size)
                        }
                    }
            )
    }

    private func clamp(_ point: CGPoint, in size: CGSize) -> CGPoint {
        CGPoint(
            x: min(max(point.x, 0), size.width),
            y: min(max(point.y, 0), size.height)
        )
    }
}

// MARK: - Scenes

/// Dim, cool "before" state — a dark room before the torch arrives.
private struct SpotlightSweepView_BeforeScene: View {
    var body: some View {
        ZStack {
            LinearGradient(
                colors: [
                    Color(red: 0.05, green: 0.06, blue: 0.09),
                    Color(red: 0.07, green: 0.08, blue: 0.13)
                ],
                startPoint: .top, endPoint: .bottom
            )
            SpotlightSweepView_SceneMotif(
                stroke: Color(red: 0.20, green: 0.24, blue: 0.34),
                fill: Color(red: 0.11, green: 0.13, blue: 0.20),
                glyph: Color(red: 0.28, green: 0.33, blue: 0.45),
                dimmed: true
            )
        }
    }
}

/// Bright, warm "after" state — the same motif lit by the spotlight.
private struct SpotlightSweepView_AfterScene: View {
    var body: some View {
        ZStack {
            RadialGradient(
                colors: [
                    Color(red: 0.16, green: 0.12, blue: 0.06),
                    Color(red: 0.09, green: 0.07, blue: 0.05)
                ],
                center: .center, startRadius: 0, endRadius: 220
            )
            SpotlightSweepView_SceneMotif(
                stroke: Color(red: 1.0, green: 0.82, blue: 0.42),
                fill: Color(red: 0.98, green: 0.62, blue: 0.20),
                glyph: Color(red: 1.0, green: 0.95, blue: 0.84),
                dimmed: false
            )
        }
    }
}

/// A simple, layout-independent motif (concentric arc + centered star) so the
/// before/after states share geometry but differ clearly in color/brightness.
private struct SpotlightSweepView_SceneMotif: View {
    let stroke: Color
    let fill: Color
    let glyph: Color
    let dimmed: Bool

    var body: some View {
        GeometryReader { proxy in
            let size = proxy.size
            let dim = min(size.width, size.height)
            ZStack {
                Circle()
                    .stroke(stroke.opacity(dimmed ? 0.5 : 0.95), lineWidth: dim * 0.018)
                    .frame(width: dim * 0.78, height: dim * 0.78)
                Circle()
                    .stroke(stroke.opacity(dimmed ? 0.28 : 0.6),
                            style: StrokeStyle(lineWidth: dim * 0.012, dash: [dim * 0.05, dim * 0.045]))
                    .frame(width: dim * 0.54, height: dim * 0.54)
                SpotlightSweepView_Star(points: 5, smoothness: 0.46)
                    .fill(fill.opacity(dimmed ? 0.55 : 1.0))
                    .frame(width: dim * 0.34, height: dim * 0.34)
                    .shadow(color: dimmed ? .clear : fill.opacity(0.6),
                            radius: dim * 0.05)
                Image(systemName: "sun.max.fill")
                    .font(.system(size: dim * 0.10, weight: .bold))
                    .foregroundStyle(glyph.opacity(dimmed ? 0.5 : 1.0))
                    .offset(y: dim * 0.30)
            }
            .frame(width: size.width, height: size.height)
        }
    }
}

/// A pointed star shape used by the motif. Pure path math, size-relative.
private struct SpotlightSweepView_Star: Shape {
    var points: Int = 5
    var smoothness: CGFloat = 0.45

    func path(in rect: CGRect) -> Path {
        var path = Path()
        let center = CGPoint(x: rect.midX, y: rect.midY)
        let outer = min(rect.width, rect.height) / 2
        let inner = outer * smoothness
        let count = max(points, 2) * 2
        let step = (.pi * 2.0) / CGFloat(count)
        var angle = -CGFloat.pi / 2.0
        for i in 0..<count {
            let radius = (i % 2 == 0) ? outer : inner
            let pt = CGPoint(
                x: center.x + cos(angle) * radius,
                y: center.y + sin(angle) * radius
            )
            if i == 0 { path.move(to: pt) } else { path.addLine(to: pt) }
            angle += step
        }
        path.closeSubpath()
        return path
    }
}
"""###,
        "tr-taffy-bridge": ###"""
import SwiftUI

// MARK: - Taffy Bridge Morph
//
// A source blob stretches a thinning 1D liquid bridge toward a destination
// position. The connecting strand necks and snaps with surface-tension recoil
// as the shape arrives and re-rounds. Pure-SwiftUI metaball via Canvas
// blur + alphaThreshold filters (blur is the inner filter so shapes are
// blurred THEN thresholded into a hard gooey edge — that ordering is what
// produces the neck-snap rather than a soft fuzzy fade).
//
// Spec interaction == "auto": both demo and non-demo run the same continuous
// TimelineView(.animation) loop. The non-demo branch additionally lets a tap
// re-launch the pull early. Both blobs are on screen every frame, so the tile
// is never blank or zero-opacity.

struct TaffyBridgeView: View {
    var demo: Bool = false

    // Re-launch token: bumping it restarts the pull on tap (non-demo only).
    @State private var launchDate: Date = .now

    private let loopDuration: Double = 3.2

    var body: some View {
        GeometryReader { geo in
            TimelineView(.animation) { timeline in
                let t = phase(now: timeline.date, size: geo.size)
                TaffyBridgeView_MetaballCanvas(progress: t, size: geo.size)
            }
            .contentShape(Rectangle())
            .onTapGesture {
                guard !demo else { return }
                launchDate = .now
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .background(Color(red: 0.051, green: 0.063, blue: 0.086))
    }

    // 0 → 1 → (reset) loop phase. Demo loops freely from a fixed epoch;
    // interactive resets the clock origin to the most recent tap/launch.
    private func phase(now: Date, size: CGSize) -> CGFloat {
        let origin = demo ? referenceEpoch : launchDate
        let elapsed = now.timeIntervalSince(origin)
        let frac = (elapsed.truncatingRemainder(dividingBy: loopDuration)) / loopDuration
        return CGFloat(max(0.0, min(1.0, frac)))
    }
}

// Stable epoch so the demo loop is deterministic across instances/frames.
private let referenceEpoch = Date(timeIntervalSince1970: 0)

// MARK: - Metaball Canvas

private struct TaffyBridgeView_MetaballCanvas: View {
    let progress: CGFloat   // 0 → 1 loop position
    let size: CGSize

    var body: some View {
        let geo = TaffyBridgeView_BridgeGeometry(progress: progress, size: size)
        ZStack {
            // The thresholded metaball field, rendered white, then masked
            // over a candy gradient so the taffy reads as a glossy material
            // rather than a flat fill.
            taffyGradient
                .mask(metaballField(geo: geo))
            // A soft inner glow re-rounds visually at the ends.
            metaballField(geo: geo)
                .blur(radius: max(1.0, minSide * 0.012))
                .blendMode(.plusLighter)
                .opacity(0.35)
        }
        .drawingGroup()
    }

    private var minSide: CGFloat { min(size.width, size.height) }

    private var taffyGradient: some View {
        LinearGradient(
            colors: [
                Color(red: 1.00, green: 0.55, blue: 0.78),
                Color(red: 0.99, green: 0.36, blue: 0.62),
                Color(red: 0.62, green: 0.40, blue: 0.98)
            ],
            startPoint: .topLeading,
            endPoint: .bottomTrailing
        )
    }

    @ViewBuilder
    private func metaballField(geo: TaffyBridgeView_BridgeGeometry) -> some View {
        Canvas { ctx, _ in
            // Filter order matters: alphaThreshold added first (outermost),
            // blur added second (innermost). Result: contents are blurred,
            // then the blurred alpha is hard-thresholded → gooey hard edge.
            ctx.addFilter(.alphaThreshold(min: 0.42, color: .white))
            ctx.addFilter(.blur(radius: geo.blurRadius))
            ctx.drawLayer { layer in
                drawSourceAndDest(in: &layer, geo: geo)
                drawStrand(in: &layer, geo: geo)
            }
        }
    }

    private func drawSourceAndDest(in layer: inout GraphicsContext,
                                   geo: TaffyBridgeView_BridgeGeometry) {
        layer.fill(circlePath(center: geo.sourceCenter, radius: geo.sourceRadius),
                   with: .color(.white))
        layer.fill(circlePath(center: geo.destCenter, radius: geo.destRadius),
                   with: .color(.white))
    }

    // The taffy strand: a chain of overlapping circles sampled along the
    // line from source → dest, whose radius dips at the waist. As travel
    // progresses the waist thins until neighbouring circles no longer
    // overlap; the threshold then severs the connection — the snap.
    private func drawStrand(in layer: inout GraphicsContext,
                            geo: TaffyBridgeView_BridgeGeometry) {
        guard geo.strandOpacity > 0.001 else { return }
        let samples = geo.strandSamples
        guard samples > 1 else { return }
        for i in 0...samples {
            let u = CGFloat(i) / CGFloat(samples)           // 0..1 along strand
            let p = lerpPoint(geo.sourceCenter, geo.destCenter, u)
            let r = geo.strandRadius(atU: u)
            guard r > 0.2 else { continue }
            layer.fill(circlePath(center: p, radius: r),
                       with: .color(.white.opacity(geo.strandOpacity)))
        }
    }

    private func circlePath(center: CGPoint, radius: CGFloat) -> Path {
        Path(ellipseIn: CGRect(x: center.x - radius,
                               y: center.y - radius,
                               width: radius * 2,
                               height: radius * 2))
    }

    private func lerpPoint(_ a: CGPoint, _ b: CGPoint, _ t: CGFloat) -> CGPoint {
        CGPoint(x: a.x + (b.x - a.x) * t,
                y: a.y + (b.y - a.y) * t)
    }
}

// MARK: - Bridge Geometry (all size-relative)

private struct TaffyBridgeView_BridgeGeometry {
    let progress: CGFloat
    let size: CGSize

    var minSide: CGFloat { min(size.width, size.height) }

    // Blur scales with geometry so the gooey edge looks identical in a 120pt
    // tile and a large detail area.
    var blurRadius: CGFloat { max(2.0, minSide * 0.045) }

    var strandSamples: Int {
        // A few more samples on larger canvases for a smoother strand.
        Int(max(10.0, min(22.0, minSide * 0.12)))
    }

    // Endpoints sit on a gentle diagonal, inset from the edges.
    private var anchorSource: CGPoint {
        CGPoint(x: size.width * 0.26, y: size.height * 0.62)
    }
    private var anchorDest: CGPoint {
        CGPoint(x: size.width * 0.74, y: size.height * 0.38)
    }

    private var baseRadius: CGFloat { minSide * 0.16 }

    // --- Phase shaping over the loop ----------------------------------------
    // travel : how far the source has moved toward the destination (0..1)
    // strand : how present/thick the connecting bridge is (1 → 0 as it snaps)
    // arrive : re-round / settle pop at the destination

    private var travel: CGFloat {
        // Ease the source across during the first ~62% of the loop, then hold.
        let raw = clamp(progress / 0.62)
        return easeInOut(raw)
    }

    // The strand is fully present early, thins through the middle, snaps near
    // arrival, then is absent while the shape re-rounds and resets.
    private var strandLife: CGFloat {
        // Present 0..0.58, thinning, gone by ~0.6 (the snap moment).
        if progress < 0.58 {
            return easeOut(1.0 - clamp(progress / 0.58))
        }
        return 0
    }

    var strandOpacity: CGFloat { strandLife }

    var sourceCenter: CGPoint {
        lerp(anchorSource, anchorDest, travel)
    }

    var destCenter: CGPoint { anchorDest }

    // Source loses a touch of mass as it pays it into the strand, then the
    // destination gains a recoil pop the instant the neck snaps.
    var sourceRadius: CGFloat {
        let drain = 0.10 * strandLife
        return baseRadius * (1.0 - drain)
    }

    var destRadius: CGFloat {
        // Surface-tension recoil: a quick overshoot just after the snap.
        let recoil = recoilPop(progress)
        return baseRadius * (0.88 + 0.22 * recoil)
    }

    // Strand radius profile along u (0 at source, 1 at dest). A catenary-like
    // waist that dips in the middle; overall thickness collapses with progress.
    func strandRadius(atU u: CGFloat) -> CGFloat {
        // Waist factor: ~1 at the ends, dips toward the middle.
        let waistDip = 0.55 + 0.45 * abs(cos(u * .pi))   // 0.55..1.0
        // Global thinning as the pull stretches (and travel lengthens it).
        let stretch = 1.0 - 0.35 * travel
        let thickness = baseRadius * 0.42 * waistDip * stretch * strandLife
        return max(0, thickness)
    }

    // MARK: helpers
    private func recoilPop(_ p: CGFloat) -> CGFloat {
        // Bell centred just after the snap (~0.62) so the dest blob pulses.
        let center: CGFloat = 0.66
        let width: CGFloat = 0.14
        let x = (p - center) / width
        return exp(-x * x)
    }

    private func lerp(_ a: CGPoint, _ b: CGPoint, _ t: CGFloat) -> CGPoint {
        CGPoint(x: a.x + (b.x - a.x) * t, y: a.y + (b.y - a.y) * t)
    }
    private func clamp(_ v: CGFloat) -> CGFloat { max(0, min(1, v)) }
    private func easeInOut(_ t: CGFloat) -> CGFloat {
        t < 0.5 ? 2 * t * t : 1 - pow(-2 * t + 2, 2) / 2
    }
    private func easeOut(_ t: CGFloat) -> CGFloat { 1 - pow(1 - t, 2) }
}
"""###,
        "tr-theater-curtain": ###"""
import SwiftUI

// MARK: - Theater Curtain
// Two gathered velvet curtain panels, drawn as pleated Animatable Shapes,
// draw apart from the center to reveal the stage behind.
//   demo == true  -> a PhaseAnimator loops openFraction 0 -> 1 -> 0.
//   demo == false -> tap toggles the curtain open / closed with a spring.

struct TheaterCurtainView: View {
    var demo: Bool = false

    @State private var isOpen: Bool = false

    var body: some View {
        GeometryReader { proxy in
            content(size: proxy.size)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .clipped()
    }

    @ViewBuilder
    private func content(size: CGSize) -> some View {
        if demo {
            PhaseAnimator([CGFloat(0.0), CGFloat(1.0)]) { open in
                stage(size: size, open: open)
            } animation: { _ in
                .spring(response: 1.5, dampingFraction: 0.78)
            }
        } else {
            stage(size: size, open: isOpen ? 1.0 : 0.0)
                .contentShape(Rectangle())
                .onTapGesture {
                    withAnimation(.spring(response: 0.7, dampingFraction: 0.72)) {
                        isOpen.toggle()
                    }
                }
        }
    }

    // MARK: - Stage (backdrop + two curtain panels)

    private func stage(size: CGSize, open: CGFloat) -> some View {
        ZStack {
            TheaterCurtainView_StageBackdrop(open: open)

            TheaterCurtainView_CurtainPanel(openFraction: open, side: .leading, size: size)
            TheaterCurtainView_CurtainPanel(openFraction: open, side: .trailing, size: size)
        }
    }
}

// MARK: - Stage backdrop

private struct TheaterCurtainView_StageBackdrop: View {
    var open: CGFloat

    var body: some View {
        GeometryReader { proxy in
            let size = proxy.size
            ZStack {
                // Deep stage floor.
                LinearGradient(
                    colors: [
                        Color(red: 0.05, green: 0.04, blue: 0.07),
                        Color(red: 0.10, green: 0.07, blue: 0.11),
                        Color(red: 0.04, green: 0.03, blue: 0.05)
                    ],
                    startPoint: .top,
                    endPoint: .bottom
                )

                // Warm follow-spot that blooms brighter as the reveal happens.
                RadialGradient(
                    colors: [
                        Color(red: 1.0, green: 0.92, blue: 0.74).opacity(0.55 * Double(open) + 0.10),
                        Color(red: 0.95, green: 0.78, blue: 0.50).opacity(0.20 * Double(open)),
                        .clear
                    ],
                    center: UnitPoint(x: 0.5, y: 0.42),
                    startRadius: 2,
                    endRadius: max(size.width, size.height) * 0.62
                )

                // Floorboard glow line for a hint of depth.
                LinearGradient(
                    colors: [.clear, Color(red: 0.55, green: 0.40, blue: 0.22).opacity(0.30 * Double(open))],
                    startPoint: .center,
                    endPoint: .bottom
                )
            }
        }
    }
}

// MARK: - One curtain panel

private struct TheaterCurtainView_CurtainPanel: View {
    enum Side { case leading, trailing }

    var openFraction: CGFloat
    var side: Side
    var size: CGSize

    var body: some View {
        let shape = TheaterCurtainView_CurtainPanelShape(openFraction: openFraction)
        panelBody(shape: shape)
            // Mirror the trailing panel so the pair is symmetric about the center.
            .scaleEffect(x: side == .trailing ? -1 : 1, y: 1, anchor: .center)
    }

    @ViewBuilder
    private func panelBody(shape: TheaterCurtainView_CurtainPanelShape) -> some View {
        ZStack {
            // Velvet body: horizontal multi-stop gradient -> folds bunch as the
            // shape narrows on opening.
            LinearGradient(
                stops: TheaterCurtainView_VelvetPalette.stops(),
                startPoint: .leading,
                endPoint: .trailing
            )
            .clipShape(shape)

            // Vertical depth shading: darker at top (under the valance) and toward hem.
            LinearGradient(
                colors: [
                    Color.black.opacity(0.32),
                    Color.clear,
                    Color.black.opacity(0.10),
                    Color.black.opacity(0.30)
                ],
                startPoint: .top,
                endPoint: .bottom
            )
            .clipShape(shape)
            .blendMode(.multiply)

            // Moving sheen riding across the folds.
            TheaterCurtainView_SheenOverlay(openFraction: openFraction)
                .clipShape(shape)
                .blendMode(.screen)

            // Crisp inner-edge highlight where the gathered fabric catches light.
            shape
                .stroke(
                    LinearGradient(
                        colors: [
                            Color(red: 1.0, green: 0.86, blue: 0.74).opacity(0.0),
                            Color(red: 1.0, green: 0.88, blue: 0.76).opacity(0.45),
                            Color(red: 1.0, green: 0.86, blue: 0.74).opacity(0.0)
                        ],
                        startPoint: .top,
                        endPoint: .bottom
                    ),
                    lineWidth: 1.2
                )
        }
        .compositingGroup()
        .shadow(
            color: Color.black.opacity(0.45),
            radius: 10 + 8 * openFraction,
            x: 6 + 8 * openFraction,
            y: 4
        )
    }
}

// MARK: - Velvet palette

private enum TheaterCurtainView_VelvetPalette {
    // Alternating darker / lighter velvet reds. A fixed set of stops means the
    // folds compress automatically as the clipped shape narrows.
    static func stops() -> [Gradient.Stop] {
        let deep = Color(red: 0.34, green: 0.03, blue: 0.07)
        let mid = Color(red: 0.58, green: 0.07, blue: 0.12)
        let bright = Color(red: 0.78, green: 0.16, blue: 0.21)
        let shadow = Color(red: 0.22, green: 0.02, blue: 0.05)

        var result: [Gradient.Stop] = []
        let foldCount: Int = 9
        for index in 0...foldCount {
            let location = CGFloat(index) / CGFloat(foldCount)
            let phase = index % 2 == 0
            let crest = index % 3 == 0
            let color: Color = crest ? bright : (phase ? deep : mid)
            result.append(Gradient.Stop(color: color, location: location))
            // Tuck a thin shadow line at each fold valley.
            if index < foldCount {
                let valley = location + (0.5 / CGFloat(foldCount))
                result.append(Gradient.Stop(color: shadow, location: valley))
            }
        }
        return result
    }
}

// MARK: - Moving sheen

private struct TheaterCurtainView_SheenOverlay: View {
    var openFraction: CGFloat

    var body: some View {
        // A diagonal band of light that drifts across the panel as it gathers.
        let travel: CGFloat = -0.4 + 1.4 * openFraction
        LinearGradient(
            colors: [
                Color.clear,
                Color(red: 1.0, green: 0.95, blue: 0.85).opacity(0.0),
                Color(red: 1.0, green: 0.96, blue: 0.88).opacity(0.35),
                Color(red: 1.0, green: 0.95, blue: 0.85).opacity(0.0),
                Color.clear
            ],
            startPoint: UnitPoint(x: travel - 0.25, y: 0.0),
            endPoint: UnitPoint(x: travel + 0.25, y: 1.0)
        )
    }
}

// MARK: - Animatable curtain shape

private struct TheaterCurtainView_CurtainPanelShape: Shape {
    var openFraction: CGFloat

    var animatableData: CGFloat {
        get { openFraction }
        set { openFraction = newValue }
    }

    func path(in rect: CGRect) -> Path {
        var path = Path()

        let clamped = min(max(openFraction, 0), 1)

        // The leading panel covers the left half when closed. As it opens it
        // narrows toward the left edge but never collapses past a bunched floor.
        let halfWidth = rect.width / 2.0
        let minWidth = halfWidth * 0.16           // bunched velvet floor — never blank
        let panelWidth = minWidth + (halfWidth - minWidth) * (1.0 - clamped)

        let left = rect.minX
        let topY = rect.minY
        let bottomY = rect.maxY

        // Scalloped inner edge: a fixed number of vertical scallops so the
        // wavelength compresses for free as panelWidth shrinks.
        let innerBase = left + panelWidth
        let scallopCount: Int = 7
        let scallopDepth = panelWidth * (0.10 + 0.16 * clamped)

        // Bottom hem: sine pleats, fixed count -> bunches as the panel narrows.
        let hemCount: Int = 8
        let hemRise = rect.height * (0.02 + 0.07 * clamped)

        // --- Top edge: straight under the valance.
        path.move(to: CGPoint(x: left, y: topY))
        path.addLine(to: CGPoint(x: innerBase, y: topY))

        // --- Inner (right) edge: scalloped, gathering inward as it opens.
        let innerSteps: Int = scallopCount * 6
        for step in 0...innerSteps {
            let t = CGFloat(step) / CGFloat(innerSteps)
            let y = topY + t * (bottomY - topY)
            let wave = sin(t * CGFloat(scallopCount) * .pi * 2.0)
            // Scallops deepen toward the bottom where fabric pools.
            let depthRamp = 0.35 + 0.65 * t
            let x = innerBase - scallopDepth * depthRamp * (0.5 + 0.5 * wave)
            path.addLine(to: CGPoint(x: x, y: y))
        }

        // --- Bottom hem: sine pleats from inner edge back to the left edge.
        let hemSteps: Int = hemCount * 5
        let hemStartX = innerBase - scallopDepth * (0.5)
        for step in 0...hemSteps {
            let t = CGFloat(step) / CGFloat(hemSteps)
            let x = hemStartX + (left - hemStartX) * t
            let wave = sin(t * CGFloat(hemCount) * .pi * 2.0)
            let y = bottomY - hemRise * (0.5 + 0.5 * wave)
            path.addLine(to: CGPoint(x: x, y: y))
        }

        // --- Left edge back up to the start (outer edge stays anchored).
        path.addLine(to: CGPoint(x: left, y: topY))
        path.closeSubpath()

        return path
    }
}
"""###,
        "tr-venetian-blinds": ###"""
import SwiftUI

// MARK: - Venetian Blinds
// Horizontal slats flip in unison on their long axis (rotation3DEffect about .x).
// As each slat turns edge-on the destination view shows through the gaps; at the
// 90-degree apex the slat's content swaps from the "old" face to the "new" face,
// then flattens back face-on to compose the next view. A directional light rake
// (brightness gradient keyed to tilt, phase-shifted per slat) sweeps the row.

public struct VenetianBlindsView: View {
    public var demo: Bool = false

    public init(demo: Bool = false) {
        self.demo = demo
    }

    public var body: some View {
        GeometryReader { geo in
            content(in: geo.size)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    @ViewBuilder
    private func content(in size: CGSize) -> some View {
        if demo {
            TimelineView(.animation) { timeline in
                let p = Self.loopProgress(timeline.date)
                VenetianBlindsView_BlindsStage(size: size, progress: p)
            }
        } else {
            VenetianBlindsView_InteractiveBlinds(size: size)
        }
    }

    // Triangle ping-pong 0 -> 1 -> 0 over a ~3.4s loop for the self-driving demo.
    private static func loopProgress(_ date: Date) -> Double {
        let period: Double = 3.4
        let t = date.timeIntervalSinceReferenceDate
        let phase = (t.truncatingRemainder(dividingBy: period)) / period
        // ease the triangle a touch so the swap feels less mechanical
        let tri = phase < 0.5 ? phase * 2.0 : (1.0 - phase) * 2.0
        return Self.easeInOut(tri)
    }

    private static func easeInOut(_ x: Double) -> Double {
        let c = min(max(x, 0), 1)
        return c * c * (3 - 2 * c)
    }
}

// MARK: - Interactive (tap to flip)

private struct VenetianBlindsView_InteractiveBlinds: View {
    let size: CGSize
    @State private var flipped: Bool = false

    var body: some View {
        VenetianBlindsView_BlindsStage(size: size, progress: flipped ? 1 : 0, staggered: true)
            .contentShape(Rectangle())
            .onTapGesture {
                withAnimation(.spring(response: 0.6, dampingFraction: 0.72)) {
                    flipped.toggle()
                }
            }
    }
}

// MARK: - Stage (shared by demo + interactive)

private struct VenetianBlindsView_BlindsStage: View {
    let size: CGSize
    let progress: Double
    var staggered: Bool = false

    private var slatCount: Int {
        // Derive from height so it works in a 120pt tile and a large detail area.
        let h = max(size.height, 1)
        let n = Int((h / 26).rounded())
        return min(max(n, 7), 13)
    }

    var body: some View {
        let count = slatCount
        let slatHeight = size.height / CGFloat(count)

        ZStack {
            // Backing destination view: ALWAYS visible through the gaps, so the
            // frame is never blank even when every slat is near edge-on.
            VenetianBlindsView_DestinationFace(size: size)

            // Soft inner vignette for depth behind the slats.
            Rectangle()
                .fill(
                    RadialGradient(
                        colors: [Color(red: 0, green: 0, blue: 0).opacity(0),
                                 Color(red: 0, green: 0, blue: 0).opacity(0.35)],
                        center: .center,
                        startRadius: size.height * 0.2,
                        endRadius: size.height * 0.75
                    )
                )
                .allowsHitTesting(false)

            ForEach(0..<count, id: \.self) { i in
                VenetianBlindsView_Slat(
                    index: i,
                    count: count,
                    size: size,
                    slatHeight: slatHeight,
                    progress: slatProgress(for: i, count: count)
                )
                .modifier(
                    VenetianBlindsView_StaggerAnimation(
                        enabled: staggered,
                        index: i,
                        progress: progress
                    )
                )
            }
        }
        .frame(width: size.width, height: size.height)
        .clipped()
    }

    // Per-slat progress with a small index stagger so the row isn't all edge-on
    // on the same frame (drives the light-rake sweep and avoids a blank frame).
    private func slatProgress(for index: Int, count: Int) -> Double {
        guard !staggered else { return progress }
        let spread = 0.18
        let frac = count > 1 ? Double(index) / Double(count - 1) : 0
        let delay = (frac - 0.5) * spread
        return min(max(progress + delay, 0), 1)
    }
}

// In the interactive path a single `flipped` toggle drives `progress`; we apply
// a per-slat delayed spring so the flip reads as a top-to-bottom wave.
private struct VenetianBlindsView_StaggerAnimation: ViewModifier {
    let enabled: Bool
    let index: Int
    let progress: Double

    func body(content: Content) -> some View {
        if enabled {
            content.animation(
                .spring(response: 0.6, dampingFraction: 0.72)
                    .delay(Double(index) * 0.035),
                value: progress
            )
        } else {
            content
        }
    }
}

// MARK: - Single slat

private struct VenetianBlindsView_Slat: View, Animatable {
    let index: Int
    let count: Int
    let size: CGSize
    let slatHeight: CGFloat
    var progress: Double   // 0 = old face flat, 1 = new face flat

    // Make `progress` the animatable attribute so the slat's body re-evaluates
    // at every interpolated step of a withAnimation/.animation transaction.
    // Without this, an endpoint-only progress (flipped ? 1 : 0) would interpolate
    // the already-derived rotation angle (0 at both ends) and never rotate
    // edge-on — degrading the tap into a plain cross-fade.
    var animatableData: Double {
        get { progress }
        set { progress = newValue }
    }

    // Map 0->1 progress into a 0 -> 90 -> 0 tilt. The content swaps at the apex,
    // so the slat returns to face-on but now shows the new view (no mirrored
    // back-face math required).
    private var tilt: Double {
        let half = progress <= 0.5 ? progress : (1 - progress)
        return Double(half) * 2.0 * 90.0
    }

    // How "edge-on" the slat is, 0 (flat) -> 1 (edge-on). Drives the light rake.
    private var edgeOn: Double {
        tilt / 90.0
    }

    private var showingNewFace: Bool { progress > 0.5 }

    var body: some View {
        ZStack {
            faceBand(isNew: false)
                .opacity(showingNewFace ? 0 : 1)
            faceBand(isNew: true)
                .opacity(showingNewFace ? 1 : 0)
        }
        .frame(width: size.width, height: slatHeight)
        .overlay(lightRake)
        .overlay(slatSeams)
        .compositingGroup()
        .rotation3DEffect(
            .degrees(tilt),
            axis: (x: 1, y: 0, z: 0),
            anchor: .center,
            anchorZ: 0,
            perspective: 0.7
        )
        // Foreshorten height as it tilts toward edge-on for a physical read.
        .scaleEffect(x: 1, y: CGFloat(0.18 + 0.82 * (1 - edgeOn)), anchor: .center)
        .position(
            x: size.width / 2,
            y: slatHeight * CGFloat(index) + slatHeight / 2
        )
        .zIndex(edgeOn)
    }

    // A horizontal BAND of the full source/destination view, offset so the slats
    // reconstruct the complete image when face-on (slice, not tile).
    @ViewBuilder
    private func faceBand(isNew: Bool) -> some View {
        let face = Group {
            if isNew {
                VenetianBlindsView_DestinationFace(size: size)
            } else {
                VenetianBlindsView_SourceFace(size: size)
            }
        }
        face
            .frame(width: size.width, height: size.height)
            .offset(y: -slatHeight * CGFloat(index))
            .frame(width: size.width, height: slatHeight, alignment: .top)
            .clipped()
    }

    // Directional light gradient that brightens as the slat turns edge-on, with
    // a per-index phase shift so the highlight sweeps along the row.
    private var lightRake: some View {
        let phase = count > 1 ? Double(index) / Double(count - 1) : 0
        let sweep = 0.5 + 0.5 * sin((phase + progress) * .pi * 2)
        let intensity = edgeOn * (0.35 + 0.55 * sweep)
        return LinearGradient(
            colors: [
                Color(red: 1, green: 1, blue: 1).opacity(0),
                Color(red: 1, green: 1, blue: 1).opacity(intensity),
                Color(red: 1, green: 1, blue: 1).opacity(0)
            ],
            startPoint: .top,
            endPoint: .bottom
        )
        .blendMode(.screen)
        .allowsHitTesting(false)
    }

    // Thin top/bottom edge shading so adjacent slats read as separate louvres.
    private var slatSeams: some View {
        VStack(spacing: 0) {
            Rectangle()
                .fill(Color(red: 1, green: 1, blue: 1).opacity(0.12 + 0.18 * edgeOn))
                .frame(height: 1)
            Spacer(minLength: 0)
            Rectangle()
                .fill(Color(red: 0, green: 0, blue: 0).opacity(0.22 + 0.28 * edgeOn))
                .frame(height: 1)
        }
        .allowsHitTesting(false)
    }
}

// MARK: - The two faces being composed

// "Old" / source view shown before the flip.
private struct VenetianBlindsView_SourceFace: View {
    let size: CGSize

    var body: some View {
        ZStack {
            LinearGradient(
                colors: [
                    Color(red: 0.07, green: 0.09, blue: 0.16),
                    Color(red: 0.16, green: 0.12, blue: 0.26),
                    Color(red: 0.06, green: 0.10, blue: 0.20)
                ],
                startPoint: .topLeading,
                endPoint: .bottomTrailing
            )
            // a soft moon/sun disc for recognizable composition
            Circle()
                .fill(
                    RadialGradient(
                        colors: [
                            Color(red: 0.95, green: 0.86, blue: 0.62),
                            Color(red: 0.85, green: 0.62, blue: 0.40).opacity(0.0)
                        ],
                        center: .center,
                        startRadius: 0,
                        endRadius: size.height * 0.28
                    )
                )
                .frame(width: size.height * 0.42, height: size.height * 0.42)
                .position(x: size.width * 0.72, y: size.height * 0.32)
        }
    }
}

// "New" / destination view revealed by the flip. Also the always-on backing.
private struct VenetianBlindsView_DestinationFace: View {
    let size: CGSize

    var body: some View {
        ZStack {
            LinearGradient(
                colors: [
                    Color(red: 0.99, green: 0.72, blue: 0.40),
                    Color(red: 0.96, green: 0.45, blue: 0.42),
                    Color(red: 0.55, green: 0.28, blue: 0.55)
                ],
                startPoint: .top,
                endPoint: .bottom
            )
            // bright horizon glow to read clearly through the slat gaps
            Ellipse()
                .fill(
                    RadialGradient(
                        colors: [
                            Color(red: 1, green: 0.97, blue: 0.86).opacity(0.9),
                            Color(red: 1, green: 0.85, blue: 0.55).opacity(0.0)
                        ],
                        center: .center,
                        startRadius: 0,
                        endRadius: size.height * 0.35
                    )
                )
                .frame(width: size.width * 0.9, height: size.height * 0.5)
                .position(x: size.width * 0.5, y: size.height * 0.62)
        }
    }
}
"""###,
        "tr-vortex-spiral": ###"""
import SwiftUI

// MARK: - Vortex Spiral
// The outgoing view rotates and scales down into a vanishing spiral while
// concentric ring overlays sweep inward, then the next view un-spirals back
// out to full size. Pure transforms + overlay rings, no shader. iOS 17.
//
// A single `progress` (0...1) is the only input to the render. Both card faces
// stay mounted at all times; opacity carries the handoff so the center is never
// blank — at progress ≈ 0.5 the rings peak and both faces are mid-fade, so there
// is always a legible state on screen.
//
// IMPORTANT: the render lives in an `Animatable` child view (`VortexSpiralView_VortexContent`)
// so its `body` is re-evaluated at every interpolated `progress`. Without that,
// SwiftUI would only sample the endpoint outputs (0 and 1) and the non-monotonic
// ring sweep / ring opacity (which peak at 0.5) would never appear.
struct VortexSpiralView: View {
    var demo: Bool = false

    // Interactive: a tap toggles `spiraled`, animating progress 0 <-> 1.
    @State private var spiraled: Bool = false

    var body: some View {
        GeometryReader { geo in
            let side = min(geo.size.width, geo.size.height)

            ZStack {
                backdrop

                if demo {
                    autoDrivenContent(side: side)
                } else {
                    interactiveContent(side: side)
                }
            }
            .frame(width: geo.size.width, height: geo.size.height)
            .contentShape(Rectangle())
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // MARK: Demo loop (self-driving)

    @ViewBuilder
    private func autoDrivenContent(side: CGFloat) -> some View {
        PhaseAnimator([0.0, 1.0]) { value in
            VortexSpiralView_VortexContent(progress: value, side: side)
        } animation: { _ in
            .easeInOut(duration: 1.7)
        }
    }

    // MARK: Interactive (tap to spiral the swap)

    @ViewBuilder
    private func interactiveContent(side: CGFloat) -> some View {
        let progress: Double = spiraled ? 1.0 : 0.0
        VortexSpiralView_VortexContent(progress: progress, side: side)
            .contentShape(Rectangle())
            .onTapGesture {
                withAnimation(.spring(response: 0.7, dampingFraction: 0.72)) {
                    spiraled.toggle()
                }
            }
    }

    // MARK: Backdrop

    private var backdrop: some View {
        RadialGradient(
            colors: [
                Color(red: 0.07, green: 0.08, blue: 0.13),
                Color(red: 0.02, green: 0.02, blue: 0.05)
            ],
            center: .center,
            startRadius: 2,
            endRadius: 240
        )
        .ignoresSafeArea()
    }
}

// MARK: - Animatable vortex render
//
// `progress` is exposed as `animatableData`, so SwiftUI re-evaluates `body`
// at every interpolated progress value during a `withAnimation` transition or
// across `PhaseAnimator` phases. This is what lets the inward ring sweep and
// the mid-transition ring opacity peak (both non-monotonic in progress) play.
private struct VortexSpiralView_VortexContent: View, Animatable {
    var progress: Double
    var side: CGFloat

    var animatableData: Double {
        get { progress }
        set { progress = newValue }
    }

    var body: some View {
        let clamped: Double = min(max(progress, 0.0), 1.0)
        let corner: CGFloat = side * 0.14

        ZStack {
            // Face A: full at progress 0, drains into the vortex by ~0.55.
            VortexSpiralView_CardFace(index: 0)
                .modifier(VortexSpiralView_SpiralTransform(progress: faceAProgress(clamped), side: side))
                .opacity(faceAOpacity(clamped))

            // Face B: emerges from the vortex starting ~0.45, full at progress 1.
            VortexSpiralView_CardFace(index: 1)
                .modifier(VortexSpiralView_SpiralTransform(progress: faceBProgress(clamped), side: side))
                .opacity(faceBOpacity(clamped))

            // Concentric ring sweep — peaks at mid-transition so the center
            // always carries something legible during the crossover.
            VortexSpiralView_RingsOverlay(progress: clamped, side: side)
                .opacity(ringOpacity(clamped))
                .allowsHitTesting(false)
        }
        .frame(width: side, height: side)
        .clipShape(RoundedRectangle(cornerRadius: corner, style: .continuous))
        .overlay(
            RoundedRectangle(cornerRadius: corner, style: .continuous)
                .strokeBorder(Color(red: 1, green: 1, blue: 1).opacity(0.10), lineWidth: 1)
        )
    }

    // MARK: Progress mapping helpers
    //
    // Face A: drains 0 -> 0.55 (1 = full present, 0 = fully spiralled away).
    private func faceAProgress(_ p: Double) -> Double {
        let t: Double = min(p / 0.55, 1.0)
        return 1.0 - t
    }

    // Face B: emerges 0.45 -> 1 (0 = fully spiralled away, 1 = full present).
    private func faceBProgress(_ p: Double) -> Double {
        let t: Double = max((p - 0.45) / 0.55, 0.0)
        return min(t, 1.0)
    }

    private func faceAOpacity(_ p: Double) -> Double {
        // Fades out as it drains; never starts from literal 0 at p=0.
        let t: Double = min(p / 0.58, 1.0)
        return max(1.0 - t, 0.0)
    }

    private func faceBOpacity(_ p: Double) -> Double {
        let t: Double = max((p - 0.42) / 0.58, 0.0)
        return min(t, 1.0)
    }

    private func ringOpacity(_ p: Double) -> Double {
        // Triangle peak at p = 0.5, clamped non-negative.
        let tri: Double = 1.0 - abs(p * 2.0 - 1.0)
        return max(tri, 0.0) * 0.9
    }
}

// MARK: - Spiral transform
//
// A single 0...1 `presence` value drives rotation + scale together. At
// presence 1 the face is upright and full; at 0 it is spun several turns and
// shrunk to a floored scale (never literal zero) — the drain-down vortex.
private struct VortexSpiralView_SpiralTransform: ViewModifier {
    var progress: Double   // 1 = present/full, 0 = spiralled away
    var side: CGFloat

    private let turns: Double = 2.5
    private let minScale: CGFloat = 0.06

    func body(content: Content) -> some View {
        content
            .scaleEffect(scale)
            .rotationEffect(angle)
            .blur(radius: blur)
    }

    private var scale: CGFloat {
        let presence: CGFloat = CGFloat(progress)
        return minScale + (1.0 - minScale) * presence
    }

    private var angle: Angle {
        // Spins more the further it is drained (presence -> 0).
        let drained: Double = 1.0 - progress
        return .degrees(turns * 360.0 * drained)
    }

    private var blur: CGFloat {
        // A touch of motion-blur as it whirls into the vortex.
        let drained: CGFloat = CGFloat(1.0 - progress)
        return drained * (side * 0.012)
    }
}

// MARK: - Card faces
//
// Two distinct legible faces so the swap actually reads as a transition
// between content, not a single thing vanishing.
private struct VortexSpiralView_CardFace: View {
    let index: Int

    var body: some View {
        GeometryReader { geo in
            let s = min(geo.size.width, geo.size.height)
            ZStack {
                LinearGradient(
                    colors: palette,
                    startPoint: .topLeading,
                    endPoint: .bottomTrailing
                )

                // Soft swirl glyph reinforcing the vortex theme.
                VortexSpiralView_SwirlMark()
                    .stroke(
                        Color(red: 1, green: 1, blue: 1).opacity(0.22),
                        style: StrokeStyle(lineWidth: max(s * 0.012, 1.0), lineCap: .round)
                    )
                    .frame(width: s * 0.62, height: s * 0.62)

                VStack(spacing: s * 0.04) {
                    Text(symbol)
                        .font(.system(size: s * 0.30, weight: .heavy, design: .rounded))
                        .foregroundColor(Color(red: 1, green: 1, blue: 1).opacity(0.95))
                    Text(label)
                        .font(.system(size: s * 0.085, weight: .semibold, design: .rounded))
                        .tracking(s * 0.012)
                        .foregroundColor(Color(red: 1, green: 1, blue: 1).opacity(0.78))
                }
            }
            .frame(width: geo.size.width, height: geo.size.height)
            .clipShape(RoundedRectangle(cornerRadius: s * 0.14, style: .continuous))
        }
    }

    private var palette: [Color] {
        if index == 0 {
            return [
                Color(red: 0.36, green: 0.30, blue: 0.92),
                Color(red: 0.62, green: 0.24, blue: 0.78)
            ]
        } else {
            return [
                Color(red: 0.98, green: 0.55, blue: 0.26),
                Color(red: 0.92, green: 0.27, blue: 0.45)
            ]
        }
    }

    private var symbol: String { index == 0 ? "A" : "B" }
    private var label: String { index == 0 ? "ORIGIN" : "ARRIVAL" }
}

// MARK: - Swirl mark (decorative spiral path)
private struct VortexSpiralView_SwirlMark: Shape {
    func path(in rect: CGRect) -> Path {
        var path = Path()
        let center = CGPoint(x: rect.midX, y: rect.midY)
        let maxR: CGFloat = min(rect.width, rect.height) / 2.0
        let turns: Double = 3.0
        let steps: Int = 220

        for i in 0...steps {
            let t: Double = Double(i) / Double(steps)
            let theta: Double = t * turns * 2.0 * .pi
            let r: CGFloat = maxR * CGFloat(t)
            let x: CGFloat = center.x + r * CGFloat(cos(theta))
            let y: CGFloat = center.y + r * CGFloat(sin(theta))
            let pt = CGPoint(x: x, y: y)
            if i == 0 {
                path.move(to: pt)
            } else {
                path.addLine(to: pt)
            }
        }
        return path
    }
}

// MARK: - Concentric ring sweep overlay
//
// Several stroked circles whose radii sweep inward with progress. Clipped to
// the card bounds so they read as a vortex drawing toward the center.
private struct VortexSpiralView_RingsOverlay: View {
    var progress: Double
    var side: CGFloat

    private let count: Int = 5

    var body: some View {
        ZStack {
            ForEach(0..<count, id: \.self) { i in
                ring(index: i)
            }
        }
        .frame(width: side, height: side)
        .clipShape(RoundedRectangle(cornerRadius: side * 0.14, style: .continuous))
    }

    @ViewBuilder
    private func ring(index i: Int) -> some View {
        let base: Double = Double(i) / Double(count)          // 0...~0.8 staggered
        // Each ring's radius sweeps inward as progress crosses 0.5.
        let sweep: Double = 1.0 - abs(progress * 2.0 - 1.0)   // 0 at ends, 1 at mid
        let phase: Double = max(0.0, min(1.0, base + sweep * 0.6))
        let radius: CGFloat = side * 0.5 * CGFloat(1.0 - phase * 0.85)
        let diameter: CGFloat = max(radius * 2.0, 1.0)
        let line: CGFloat = max(side * 0.012, 1.0)

        Circle()
            .stroke(
                Color(red: 0.85, green: 0.92, blue: 1.0).opacity(0.45),
                lineWidth: line
            )
            .frame(width: diameter, height: diameter)
            .blur(radius: 0.5)
    }
}
"""###,
        "tr-zipper-unzip": ###"""
import SwiftUI

// MARK: - Zipper Unzip

/// Two halves of a front cover are joined by interleaving Path-drawn zipper
/// teeth along a center seam. Pulling the slider down separates the halves —
/// the region the puller has passed (above it) spreads open to reveal the
/// destination view behind, while the region below stays meshed.
///
/// progress (p): 0 = fully zipped (puller at top, cover closed)
///               1 = fully unzipped (puller at bottom, destination revealed)
struct ZipperUnzipTransitionView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { proxy in
            ZipperUnzipTransitionView_ZipperBoard(size: proxy.size, demo: demo)
                .frame(width: proxy.size.width, height: proxy.size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }
}

// MARK: - Board

private struct ZipperUnzipTransitionView_ZipperBoard: View {
    let size: CGSize
    let demo: Bool

    // Interactive state
    @State private var progress: CGFloat = 0
    @State private var dragStartProgress: CGFloat? = nil

    // Geometry-derived tooth metrics
    private var toothHeight: CGFloat { max(10, size.height / 16) }
    private var teethCount: Int { max(6, Int(size.height / toothHeight)) }

    // Where the puller sits vertically for a given progress.
    private func pullerY(_ p: CGFloat) -> CGFloat { p * size.height }

    var body: some View {
        if demo {
            PhaseAnimator([CGFloat(0), CGFloat(1)]) { phase in
                content(for: phase)
            } animation: { _ in
                .easeInOut(duration: 1.6)
            }
        } else {
            content(for: progress)
                .gesture(dragGesture)
                .sensoryFeedback(.impact(weight: .light, intensity: 0.6),
                                 trigger: crossedToothCount(progress))
        }
    }

    // The live progress value the visuals should use:
    // in demo it follows the phase; interactively it follows @State.
    private func content(for p: CGFloat) -> some View {
        let py = pullerY(p)
        return ZStack {
            destinationLayer(p: p)
            frontHalves(p: p, pullerY: py)
            seam(p: p, pullerY: py)
            puller(p: p, pullerY: py)
        }
        .compositingGroup()
        .clipShape(RoundedRectangle(cornerRadius: cornerRadius, style: .continuous))
        .contentShape(Rectangle())
    }

    private var cornerRadius: CGFloat { min(size.width, size.height) * 0.10 }

    // MARK: Destination (always mounted, revealed as the cover opens)

    private func destinationLayer(p: CGFloat) -> some View {
        let reveal = Double(min(1, p * 1.2))
        return ZStack {
            LinearGradient(
                colors: [
                    Color(red: 0.16, green: 0.36, blue: 0.62),
                    Color(red: 0.34, green: 0.20, blue: 0.55)
                ],
                startPoint: .topLeading, endPoint: .bottomTrailing
            )
            VStack(spacing: size.height * 0.05) {
                Image(systemName: "sparkles")
                    .font(.system(size: min(size.width, size.height) * 0.22,
                                  weight: .semibold))
                    .foregroundStyle(.white)
                Text("Unzipped")
                    .font(.system(size: min(size.width, size.height) * 0.10,
                                  weight: .bold, design: .rounded))
                    .foregroundStyle(.white.opacity(0.9))
            }
            .opacity(reveal)
            .scaleEffect(0.92 + 0.08 * reveal)
        }
    }

    // MARK: Front cover halves

    private func frontHalves(p: CGFloat, pullerY: CGFloat) -> some View {
        // Each half splays its top corner outward as the puller descends,
        // forming a V-shaped opening above the puller while staying sealed
        // at the center seam below it.
        ZStack {
            coverHalf(isLeft: true, p: p, pullerY: pullerY)
            coverHalf(isLeft: false, p: p, pullerY: pullerY)
        }
    }

    private func coverHalf(isLeft: Bool, p: CGFloat, pullerY: CGFloat) -> some View {
        let halfW = size.width / 2
        // Maximum horizontal splay of a half's top corner once fully opened.
        let maxSpread = halfW * 0.96
        let spread = maxSpread * easeOut(p)
        let dir: CGFloat = isLeft ? -1 : 1

        return ZipperUnzipTransitionView_ZipperHalfClip(isLeft: isLeft, pullerY: pullerY, spread: spread, size: size)
            .fill(coverGradient(isLeft: isLeft))
            .overlay(
                ZipperUnzipTransitionView_ZipperHalfClip(isLeft: isLeft, pullerY: pullerY, spread: spread, size: size)
                    .fill(coverSheen(isLeft: isLeft))
            )
            .shadow(color: .black.opacity(0.35 * Double(p)),
                    radius: 8 * p, x: dir * 4 * p, y: 0)
    }

    private func coverGradient(isLeft: Bool) -> LinearGradient {
        LinearGradient(
            colors: [
                Color(red: 0.12, green: 0.13, blue: 0.17),
                Color(red: 0.06, green: 0.07, blue: 0.10)
            ],
            startPoint: isLeft ? .topLeading : .topTrailing,
            endPoint: isLeft ? .bottomTrailing : .bottomLeading
        )
    }

    private func coverSheen(isLeft: Bool) -> LinearGradient {
        LinearGradient(
            colors: [
                Color.white.opacity(0.10),
                Color.white.opacity(0.0),
                Color.black.opacity(0.12)
            ],
            startPoint: isLeft ? .leading : .trailing,
            endPoint: isLeft ? .trailing : .leading
        )
    }

    // MARK: Seam (the teeth)

    private func seam(p: CGFloat, pullerY: CGFloat) -> some View {
        let halfW = size.width / 2
        let maxSpread = halfW * 0.96
        let spread = maxSpread * easeOut(p)

        return ZStack {
            // Meshed tape below the puller — a darker channel.
            ZipperUnzipTransitionView_ZipperTape(pullerY: pullerY, size: size)
                .fill(Color(red: 0.04, green: 0.04, blue: 0.06))

            ZipperUnzipTransitionView_ZipperTeeth(pullerY: pullerY,
                        spread: spread,
                        toothHeight: toothHeight,
                        teethCount: teethCount,
                        size: size)
                .fill(teethGradient)
                .overlay(
                    ZipperUnzipTransitionView_ZipperTeeth(pullerY: pullerY,
                                spread: spread,
                                toothHeight: toothHeight,
                                teethCount: teethCount,
                                size: size)
                        .stroke(Color.black.opacity(0.35), lineWidth: 0.75)
                )
        }
    }

    private var teethGradient: LinearGradient {
        LinearGradient(
            colors: [
                Color(red: 0.86, green: 0.87, blue: 0.90),
                Color(red: 0.55, green: 0.57, blue: 0.62),
                Color(red: 0.80, green: 0.81, blue: 0.85)
            ],
            startPoint: .leading, endPoint: .trailing
        )
    }

    // MARK: Puller (slider)

    private func puller(p: CGFloat, pullerY: CGFloat) -> some View {
        let bodyW = max(14, size.width * 0.14)
        let bodyH = max(18, size.height * 0.10)
        let tabH = bodyH * 0.85

        return VStack(spacing: 0) {
            // Trapezoidal slider body
            ZipperUnzipTransitionView_PullerBody()
                .fill(pullerGradient)
                .overlay(
                    ZipperUnzipTransitionView_PullerBody()
                        .stroke(Color.black.opacity(0.4), lineWidth: 1)
                )
                .frame(width: bodyW, height: bodyH)
            // Pull tab
            ZStack {
                Capsule()
                    .fill(pullerGradient)
                    .overlay(Capsule().stroke(Color.black.opacity(0.4), lineWidth: 1))
                Capsule()
                    .stroke(Color.black.opacity(0.25), lineWidth: 1)
                    .frame(width: bodyW * 0.28, height: tabH * 0.55)
            }
            .frame(width: bodyW * 0.62, height: tabH)
        }
        .shadow(color: .black.opacity(0.5), radius: 3, x: 0, y: 2)
        .position(x: size.width / 2, y: max(bodyH / 2, pullerY))
    }

    private var pullerGradient: LinearGradient {
        LinearGradient(
            colors: [
                Color(red: 0.93, green: 0.94, blue: 0.97),
                Color(red: 0.62, green: 0.64, blue: 0.70),
                Color(red: 0.40, green: 0.42, blue: 0.47)
            ],
            startPoint: .top, endPoint: .bottom
        )
    }

    // MARK: Gesture

    private var dragGesture: some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                if dragStartProgress == nil { dragStartProgress = progress }
                let base = dragStartProgress ?? progress
                let delta = value.translation.height / max(1, size.height)
                progress = clamp(base + delta)
            }
            .onEnded { value in
                dragStartProgress = nil
                // Use velocity (predicted end) to decide open vs. snap-back.
                let predicted = value.predictedEndTranslation.height
                let base = progress
                let goOpen: Bool
                if predicted > size.height * 0.25 {
                    goOpen = true
                } else if predicted < -size.height * 0.25 {
                    goOpen = false
                } else {
                    goOpen = base > 0.5
                }
                withAnimation(.spring(response: 0.45, dampingFraction: 0.72)) {
                    progress = goOpen ? 1 : 0
                }
            }
    }

    // MARK: Helpers

    private func crossedToothCount(_ p: CGFloat) -> Int {
        Int(p * CGFloat(teethCount))
    }

    private func clamp(_ v: CGFloat) -> CGFloat { min(1, max(0, v)) }

    private func easeOut(_ t: CGFloat) -> CGFloat {
        let c = clamp(t)
        return 1 - (1 - c) * (1 - c)
    }
}

// MARK: - Cover half clip Shape
//
// Each half occupies its side of the board. Its inner edge is flush at the
// center seam from the bottom up to the puller (meshed), then splays out to
// `spread` at the very top so the opening widens into a V above the puller.

private struct ZipperUnzipTransitionView_ZipperHalfClip: Shape {
    let isLeft: Bool
    var pullerY: CGFloat
    var spread: CGFloat
    let size: CGSize

    var animatableData: AnimatablePair<CGFloat, CGFloat> {
        get { AnimatablePair(pullerY, spread) }
        set { pullerY = newValue.first; spread = newValue.second }
    }

    func path(in rect: CGRect) -> Path {
        let centerX = rect.midX
        let py = max(0, min(rect.height, pullerY))
        // Inner edge is flush at the center seam from the bottom up to the
        // puller (meshed), then splays out to `spread` at the very top so the
        // opening widens into a V above the puller — closed below, open above.
        var p = Path()

        if isLeft {
            // Down the left edge, across the bottom, up the inner (center)
            // edge to the puller, then out to the splayed top corner.
            p.move(to: CGPoint(x: rect.minX, y: rect.minY))
            p.addLine(to: CGPoint(x: rect.minX, y: rect.maxY))
            p.addLine(to: CGPoint(x: centerX, y: rect.maxY))
            p.addLine(to: CGPoint(x: centerX, y: py))                   // sealed up to puller
            p.addLine(to: CGPoint(x: centerX - spread, y: rect.minY))   // splay at top
            p.closeSubpath()
        } else {
            p.move(to: CGPoint(x: rect.maxX, y: rect.minY))
            p.addLine(to: CGPoint(x: rect.maxX, y: rect.maxY))
            p.addLine(to: CGPoint(x: centerX, y: rect.maxY))
            p.addLine(to: CGPoint(x: centerX, y: py))
            p.addLine(to: CGPoint(x: centerX + spread, y: rect.minY))
            p.closeSubpath()
        }
        return p
    }
}

// MARK: - Zipper tape (meshed channel below puller)

private struct ZipperUnzipTransitionView_ZipperTape: Shape {
    var pullerY: CGFloat
    let size: CGSize

    var animatableData: CGFloat {
        get { pullerY }
        set { pullerY = newValue }
    }

    func path(in rect: CGRect) -> Path {
        let w = max(3, rect.width * 0.045)
        let py = max(0, min(rect.height, pullerY))
        let r = CGRect(x: rect.midX - w / 2, y: py,
                       width: w, height: max(0, rect.maxY - py))
        return Path(roundedRect: r, cornerRadius: w / 2)
    }
}

// MARK: - Zipper teeth Shape
//
// Interleaved trapezoids along the seam. Below the puller they mesh at the
// center (left and right teeth interlock). Above the puller each side's teeth
// ride outward with the opening half, so they un-mesh tooth-by-tooth.

private struct ZipperUnzipTransitionView_ZipperTeeth: Shape {
    var pullerY: CGFloat
    var spread: CGFloat
    let toothHeight: CGFloat
    let teethCount: Int
    let size: CGSize

    var animatableData: AnimatablePair<CGFloat, CGFloat> {
        get { AnimatablePair(pullerY, spread) }
        set { pullerY = newValue.first; spread = newValue.second }
    }

    func path(in rect: CGRect) -> Path {
        var path = Path()
        let centerX = rect.midX
        let py = max(0, min(rect.height, pullerY))
        let toothW = max(6, rect.width * 0.075)
        let h = toothHeight
        let count = teethCount

        for i in 0..<count {
            let topY = CGFloat(i) * h
            let isLeftTooth = (i % 2 == 0)
            // Is this tooth above the puller (separated) or below (meshed)?
            let isOpen = topY + h * 0.5 < py
            // Fraction of how far above the puller (for a graded V spread).
            let openFrac: CGFloat = isOpen
                ? min(1, max(0, (py - (topY + h * 0.5)) / max(1, py)))
                : 0
            let sideSpread = spread * openFrac
            let dir: CGFloat = isLeftTooth ? -1 : 1
            // Meshed teeth poke slightly past center; opened ones ride out.
            let baseOffset: CGFloat = isLeftTooth ? -toothW * 0.15 : toothW * 0.15
            let cx = centerX + baseOffset + dir * sideSpread

            appendTooth(to: &path,
                        centerX: cx,
                        topY: topY,
                        toothW: toothW,
                        h: h,
                        pointsRight: isLeftTooth)
        }
        return path
    }

    // A trapezoid tooth. Left-side teeth point right (into the seam), and
    // right-side teeth point left, so they interleave when meshed.
    private func appendTooth(to path: inout Path,
                             centerX: CGFloat,
                             topY: CGFloat,
                             toothW: CGFloat,
                             h: CGFloat,
                             pointsRight: Bool) {
        let halfW = toothW / 2
        let inset = toothW * 0.30
        let midY = topY + h / 2
        let top = topY + h * 0.12
        let bot = topY + h * 0.88

        var t = Path()
        if pointsRight {
            // wide on the left, tapered point toward the right
            t.move(to: CGPoint(x: centerX - halfW, y: top))
            t.addLine(to: CGPoint(x: centerX + halfW - inset, y: top))
            t.addLine(to: CGPoint(x: centerX + halfW, y: midY))
            t.addLine(to: CGPoint(x: centerX + halfW - inset, y: bot))
            t.addLine(to: CGPoint(x: centerX - halfW, y: bot))
        } else {
            t.move(to: CGPoint(x: centerX + halfW, y: top))
            t.addLine(to: CGPoint(x: centerX - halfW + inset, y: top))
            t.addLine(to: CGPoint(x: centerX - halfW, y: midY))
            t.addLine(to: CGPoint(x: centerX - halfW + inset, y: bot))
            t.addLine(to: CGPoint(x: centerX + halfW, y: bot))
        }
        t.closeSubpath()
        path.addPath(t)
    }
}

// MARK: - Puller body Shape (trapezoid slider)

private struct ZipperUnzipTransitionView_PullerBody: Shape {
    func path(in rect: CGRect) -> Path {
        let inset = rect.width * 0.18
        var p = Path()
        p.move(to: CGPoint(x: rect.minX + inset, y: rect.minY))
        p.addLine(to: CGPoint(x: rect.maxX - inset, y: rect.minY))
        p.addLine(to: CGPoint(x: rect.maxX, y: rect.maxY))
        p.addLine(to: CGPoint(x: rect.minX, y: rect.maxY))
        p.closeSubpath()
        return p
    }
}
"""###,
        "tx-confetti-letters": ###"""
import SwiftUI

// MARK: - Letter Confetti Drop
// The word explodes into its glyphs which tumble and fall under gravity,
// bounce off the floor, then magnetically reassemble into the word with a
// spring. demo == true auto-loops the burst; demo == false flings on drag.
//
// iOS 18 uses TextRenderer for true per-glyph slices. iOS 17 falls back to a
// per-character HStack — both drive the SAME closed-form physics so motion is
// identical. Physics is a pure function of elapsed time (no integrator state)
// so the loop is seamless and stable.

struct ConfettiLettersView: View {
    var demo: Bool = false

    private let word = "CONFETTI"
    private let period: Double = 3.0

    @State private var releaseDate: Date? = nil
    @State private var flingSeed: CGSize = .zero

    var body: some View {
        GeometryReader { geo in
            content(size: geo.size)
                .frame(maxWidth: .infinity, maxHeight: .infinity)
                .contentShape(Rectangle())
                .gesture(demo ? nil : flingGesture)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // MARK: Layout

    @ViewBuilder
    private func content(size: CGSize) -> some View {
        TimelineView(.animation) { timeline in
            let p = phase(now: timeline.date)
            ConfettiText(word: word, fling: activeFling, progress: p, size: size)
        }
    }

    // MARK: Physics phase (0...1 within one explode→reassemble cycle)

    private func phase(now: Date) -> Double {
        if demo {
            let t = now.timeIntervalSinceReferenceDate.truncatingRemainder(dividingBy: period)
            return t / period
        }
        guard let release = releaseDate else { return 0 } // legible, assembled
        let elapsed = now.timeIntervalSince(release)
        if elapsed >= period { return 0 }
        return elapsed / period
    }

    private var activeFling: CGSize {
        if demo { return CGSize(width: 0.25, height: -1.0) } // canned lively fling
        return flingSeed
    }

    // MARK: Interaction

    private var flingGesture: some Gesture {
        DragGesture(minimumDistance: 0)
            .onEnded { value in
                let vx = clampVel(value.velocity.width)
                let vy = clampVel(value.velocity.height)
                // Bias upward so the burst always lifts before falling.
                flingSeed = CGSize(width: vx, height: min(vy, -0.4) - 0.6)
                releaseDate = Date()
            }
    }

    private func clampVel(_ v: CGFloat) -> CGFloat {
        let norm = Double(v) / 1400.0
        return CGFloat(max(-1.6, min(1.6, norm)))
    }
}

// MARK: - The text + its dual rendering paths

private struct ConfettiText: View {
    let word: String
    let fling: CGSize
    let progress: Double
    let size: CGSize

    private var fontSize: CGFloat {
        // Scale to the smaller dimension so it fits both a 120pt tile and detail.
        let perGlyph: CGFloat = size.width / CGFloat(max(word.count, 1)) * 1.3
        let byHeight: CGFloat = size.height * 0.4
        let base: CGFloat = min(perGlyph, byHeight)
        return max(14, base)
    }

    var body: some View {
        let font = Font.system(size: fontSize, weight: .heavy, design: .rounded)
        Group {
            if #available(iOS 18.0, *) {
                Text(word)
                    .font(font)
                    .foregroundStyle(.white)
                    .textRenderer(
                        ConfettiGlyphRenderer(
                            progress: progress,
                            fling: fling,
                            canvasSize: size
                        )
                    )
            } else {
                FallbackConfettiText(
                    word: word,
                    progress: progress,
                    fling: fling,
                    size: size,
                    font: font
                )
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }
}

// MARK: - Per-glyph confetti tint (shared by both render paths)

private func glyphTint(_ index: Int) -> Color {
    let hues: [Double] = [0.95, 0.58, 0.13, 0.45, 0.78]
    return Color(hue: hues[index % hues.count], saturation: 0.7, brightness: 1.0)
}

// MARK: - iOS 18 TextRenderer (true per-glyph slices)

@available(iOS 18.0, *)
private struct ConfettiGlyphRenderer: TextRenderer {
    var progress: Double
    var fling: CGSize
    var canvasSize: CGSize

    func draw(layout: Text.Layout, in ctx: inout GraphicsContext) {
        let slices = layout.flatMap { line in line.flatMap { run in run } }
        let count = slices.count
        guard count > 0 else { return }

        for (index, slice) in slices.enumerated() {
            let state = glyphState(
                index: index,
                count: count,
                progress: progress,
                fling: fling,
                size: canvasSize
            )
            let rect = slice.typographicBounds.rect
            let center = CGPoint(x: rect.midX, y: rect.midY)

            var copy = ctx
            copy.translateBy(x: state.offset.width, y: state.offset.height)
            copy.translateBy(x: center.x, y: center.y)
            copy.rotate(by: state.angle)
            copy.scaleBy(x: state.scale, y: state.scale)
            copy.translateBy(x: -center.x, y: -center.y)
            copy.opacity = state.opacity
            // White base glyph × hue == the hue, matching the iOS 17 fallback.
            copy.addFilter(.colorMultiply(glyphTint(index)))
            copy.draw(slice)
        }
    }
}

// MARK: - iOS 17 fallback (per-character HStack driving the same physics)

private struct FallbackConfettiText: View {
    let word: String
    let progress: Double
    let fling: CGSize
    let size: CGSize
    let font: Font

    private var characters: [Character] { Array(word) }

    var body: some View {
        HStack(spacing: 0) {
            ForEach(Array(characters.enumerated()), id: \.offset) { index, char in
                let state = glyphState(
                    index: index,
                    count: characters.count,
                    progress: progress,
                    fling: fling,
                    size: size
                )
                Text(String(char))
                    .font(font)
                    .foregroundStyle(glyphTint(index))
                    .offset(state.offset)
                    .rotationEffect(state.angle)
                    .scaleEffect(state.scale)
                    .opacity(state.opacity)
            }
        }
    }
}

// MARK: - Shared closed-form physics

private struct GlyphState {
    var offset: CGSize
    var angle: Angle
    var scale: CGFloat
    var opacity: Double
}

/// Pure function of elapsed `progress` (0...1) for one explode→reassemble cycle.
/// Returns an OFFSET from the glyph's layout home, so both render paths agree.
private func glyphState(
    index: Int,
    count: Int,
    progress: Double,
    fling: CGSize,
    size: CGSize
) -> GlyphState {
    let p = max(0, min(1, progress))

    // Per-glyph deterministic variation (seeded by index — no shimmer).
    let r1 = pseudoRandom(index, salt: 1)        // 0...1
    let r2 = pseudoRandom(index, salt: 2)
    let r3 = pseudoRandom(index, salt: 3)

    // Scale all magnitudes to the canvas so behavior matches at any tile size.
    let unit: Double = max(min(Double(size.width), Double(size.height)), 1)
    let floorY: Double = Double(size.height) * 0.5 - Double(size.height) * 0.06

    // Phase split: explode/fall/bounce (0 → 0.62), reassemble (0.62 → 1).
    let explodeEnd = 0.62

    if p <= explodeEnd {
        let t = p / explodeEnd // 0...1 within explode
        return explodePhase(
            t: t, r1: r1, r2: r2, r3: r3,
            fling: fling, unit: unit, floorY: floorY, index: index, count: count
        )
    } else {
        let t = (p - explodeEnd) / (1 - explodeEnd) // 0...1 within reassemble
        // Where the glyph "was" when reassembly began (end of explode).
        let from = explodePhase(
            t: 1, r1: r1, r2: r2, r3: r3,
            fling: fling, unit: unit, floorY: floorY, index: index, count: count
        )
        return reassemblePhase(t: t, from: from)
    }
}

private func explodePhase(
    t: Double, r1: Double, r2: Double, r3: Double,
    fling: CGSize, unit: Double, floorY: Double,
    index: Int, count: Int
) -> GlyphState {
    // Launch vector: spread glyphs outward fan + fling bias.
    let centered = Double(index) - Double(count - 1) / 2.0
    let spread = centered / Double(max(count, 1))

    let vx = (spread * 1.1 + (r1 - 0.5) * 0.8 + Double(fling.width)) * unit
    let vyBase = -(0.9 + r2 * 0.7) - Double(fling.height) * 0.5
    let vy = vyBase * unit

    let gravity = 2.6 * unit

    // Closed-form vertical position: home + v0·t + ½g·t²
    var y = vy * t + 0.5 * gravity * t * t
    let x = vx * t

    // Analytic floor bounce: reflect once the parabola crosses the floor.
    // Use a damped |sin| envelope past impact for a clean, stable bounce.
    if y > floorY {
        let overshoot = y - floorY
        // Damped bounce around the floor (loses energy).
        let bounceEnv = exp(-3.0 * t) * abs(sin(t * .pi * 3.0))
        y = floorY - overshoot * 0.0 - bounceEnv * unit * 0.55
        // Keep it from sinking below the floor visually.
        y = min(y, floorY)
    }

    // Spin scales with horizontal launch energy.
    let spin = (vx / unit) * 2.4 + (r3 - 0.5) * 6.0
    let angle = Angle.degrees(spin * t * 180.0)

    // Slight scale pulse on launch, settle to 1.
    let scale = 1.0 + 0.18 * sin(t * .pi)

    // Never fully transparent — floor at 0.62.
    let opacity = 1.0 - 0.38 * smoothstep(0.0, 1.0, t)

    let clampedX = clampOffset(x, limit: unit * 0.9)
    let clampedY = clampOffset(y, limit: unit * 0.9)

    return GlyphState(
        offset: CGSize(width: clampedX, height: clampedY),
        angle: angle,
        scale: CGFloat(scale),
        opacity: max(0.62, opacity)
    )
}

private func reassemblePhase(t: Double, from: GlyphState) -> GlyphState {
    // Magnetic snap home with slight overshoot (ease-out-back).
    let e = easeOutBack(t)
    let w = Double(from.offset.width) * (1 - e)
    let h = Double(from.offset.height) * (1 - e)

    // Unwind rotation back to upright.
    let angle = Angle.degrees(from.angle.degrees * (1 - e))

    // Scale eases to 1 with a tiny pop near the end.
    let pop = 1.0 + 0.12 * sin(min(1, t) * .pi) * t
    let fromScale = Double(from.scale)
    let scale = fromScale + (pop - fromScale) * easeOutCubic(t)

    let opacity = from.opacity + (1.0 - from.opacity) * easeOutCubic(t)

    return GlyphState(
        offset: CGSize(width: w, height: h),
        angle: angle,
        scale: CGFloat(scale),
        opacity: min(1.0, opacity)
    )
}

// MARK: - Math helpers

private func pseudoRandom(_ i: Int, salt: Int) -> Double {
    // Deterministic hash → 0...1. Stable across frames (no shimmer).
    var x = UInt64(bitPattern: Int64(i &* 73856093 ^ salt &* 19349663))
    x ^= x >> 33
    x = x &* 0xff51afd7ed558ccd
    x ^= x >> 33
    return Double(x % 10_000) / 10_000.0
}

private func clampOffset(_ v: Double, limit: Double) -> CGFloat {
    CGFloat(max(-limit, min(limit, v)))
}

private func smoothstep(_ a: Double, _ b: Double, _ x: Double) -> Double {
    let t = max(0, min(1, (x - a) / (b - a)))
    return t * t * (3 - 2 * t)
}

private func easeOutCubic(_ t: Double) -> Double {
    let p = 1 - max(0, min(1, t))
    return 1 - p * p * p
}

private func easeOutBack(_ t: Double) -> Double {
    let c1 = 1.70158
    let c3 = c1 + 1
    let x = max(0, min(1, t))
    let p = x - 1
    return 1 + c3 * p * p * p + c1 * p * p
}

// MARK: - Previews



// MARK: - Hex color (self-contained, no app dependency)

private extension Color {
    init(hexCode hex: String) {
        let s = hex.trimmingCharacters(in: CharacterSet(charactersIn: "#"))
        var rgb: UInt64 = 0
        Scanner(string: s).scanHexInt64(&rgb)
        let r = Double((rgb >> 16) & 0xFF) / 255.0
        let g = Double((rgb >> 8) & 0xFF) / 255.0
        let b = Double(rgb & 0xFF) / 255.0
        self.init(red: r, green: g, blue: b)
    }
}
"""###,
        "tx-decode-matrix": ###"""
import SwiftUI

/// Glyph Decode Cascade — text resolves out of a column of rapidly cycling
/// random glyphs per slot. Each character locks from left to right: the
/// still-scrambling characters dim and jitter while the locked ones brighten
/// and settle. A wave of order sweeps across the chaos.
///
/// - `demo == true`  : self-driving loop derived purely from the timeline clock.
/// - `demo == false` : real interactive component — tap to replay the cascade.
struct DecodeMatrixView: View {
    var demo: Bool = false

    // MARK: - Tunables

    /// The string that resolves out of the noise. Short so it fits a 120pt tile.
    private let target: [Character] = Array("INSPIRE")

    /// Glyph pool the unlocked slots cycle through.
    private let glyphPool: [Character] = Array("ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789#$%&*+=<>/\\")

    /// Quantum for the ~20fps glyph flip (0.05s == 20 flips/sec).
    private let flipQuantum: Double = 0.05

    /// Delay before the first slot may lock.
    private let baseDelay: Double = 0.35

    /// Extra delay per slot index, producing the left-to-right cascade.
    private let stagger: Double = 0.26

    /// How long to hold the fully-resolved word before the demo re-scrambles.
    private let holdDuration: Double = 1.1

    // MARK: - State (interactive only)

    /// When the current cascade began. Tapping resets this to "now".
    @State private var cascadeStart: Date = Date()

    // MARK: - Body

    var body: some View {
        GeometryReader { geo in
            content(in: geo.size)
                .frame(maxWidth: .infinity, maxHeight: .infinity)
                .background(backgroundFill)
                .contentShape(Rectangle())
                .modifier(DecodeMatrixView_TapReplay(enabled: !demo) {
                    cascadeStart = Date()
                })
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // MARK: - Driver

    @ViewBuilder
    private func content(in size: CGSize) -> some View {
        let dimension = min(size.width, size.height)
        let fontSize = max(13.0, dimension * 0.20)
        let slotWidth = fontSize * 0.74
        let jitter = fontSize * 0.10

        TimelineView(.animation) { timeline in
            let elapsed = elapsedTime(now: timeline.date)
            let step = Int(elapsed / flipQuantum)

            row(elapsed: elapsed,
                step: step,
                fontSize: fontSize,
                slotWidth: slotWidth,
                jitter: jitter)
        }
    }

    /// `demo` derives a looping clock; interactive measures from the last tap.
    private func elapsedTime(now: Date) -> Double {
        if demo {
            let period = loopPeriod
            let raw = now.timeIntervalSince1970.truncatingRemainder(dividingBy: period)
            return raw < 0 ? raw + period : raw
        } else {
            return now.timeIntervalSince(cascadeStart)
        }
    }

    /// Total loop length: last slot locks, then we hold the resolved word.
    private var loopPeriod: Double {
        let lastLock = lockTime(for: target.count - 1)
        return lastLock + holdDuration
    }

    // MARK: - Layout

    @ViewBuilder
    private func row(elapsed: Double,
                     step: Int,
                     fontSize: CGFloat,
                     slotWidth: CGFloat,
                     jitter: CGFloat) -> some View {
        HStack(spacing: slotWidth * 0.16) {
            ForEach(target.indices, id: \.self) { index in
                slotView(index: index,
                         elapsed: elapsed,
                         step: step,
                         fontSize: fontSize,
                         slotWidth: slotWidth,
                         jitter: jitter)
            }
        }
        .padding(.horizontal, fontSize * 0.4)
    }

    // MARK: - Per-slot rendering

    @ViewBuilder
    private func slotView(index: Int,
                          elapsed: Double,
                          step: Int,
                          fontSize: CGFloat,
                          slotWidth: CGFloat,
                          jitter: CGFloat) -> some View {
        let locked = elapsed >= lockTime(for: index)
        let character = locked ? target[index] : scrambleGlyph(slot: index, step: step)

        // Slot just before the lock front gets a brief "charging" pulse.
        let nearFront = !locked && (elapsed >= lockTime(for: index) - flipQuantum * 4)
        let yOffset = locked ? 0.0 : jitterOffset(slot: index, step: step, amount: jitter)

        Text(String(character))
            .font(.system(size: fontSize, weight: locked ? .bold : .regular, design: .monospaced))
            .foregroundStyle(slotColor(locked: locked, nearFront: nearFront))
            .brightness(locked ? 0.10 : 0.0)
            .shadow(color: lockedGlow.opacity(locked ? 0.9 : 0.0),
                    radius: locked ? fontSize * 0.28 : 0)
            .scaleEffect(lockScale(locked: locked, index: index, elapsed: elapsed))
            .offset(y: yOffset)
            .frame(width: slotWidth)
            .animation(.spring(response: 0.28, dampingFraction: 0.55), value: locked)
    }

    // MARK: - Timing

    /// When slot `index` is permitted to lock onto its target glyph.
    private func lockTime(for index: Int) -> Double {
        baseDelay + Double(index) * stagger
    }

    /// A small settle pop the instant a slot locks, decaying back to 1.0.
    private func lockScale(locked: Bool, index: Int, elapsed: Double) -> CGFloat {
        guard locked else { return 0.96 }
        let sinceLock = elapsed - lockTime(for: index)
        guard sinceLock < 0.22 else { return 1.0 }
        // Snap up then ease back to rest.
        let t = sinceLock / 0.22
        let pop = sin(t * .pi) * 0.16
        return 1.0 + CGFloat(pop)
    }

    // MARK: - Deterministic glyph selection (quantized to ~20fps)

    /// Pure function of (slot, step) so the glyph is stable within a frame
    /// quantum and flips ~20 times/sec instead of re-rolling every render frame.
    private func scrambleGlyph(slot: Int, step: Int) -> Character {
        let h = hash(slot: slot, step: step)
        return glyphPool[h % glyphPool.count]
    }

    /// Deterministic vertical jitter for unlocked slots, also quantized.
    private func jitterOffset(slot: Int, step: Int, amount: CGFloat) -> CGFloat {
        let h = hash(slot: slot &+ 101, step: step)
        let normalized = (Double(h % 1000) / 1000.0) * 2.0 - 1.0 // -1...1
        return CGFloat(normalized) * amount
    }

    /// Cheap integer hash mixing slot and step into a well-spread value.
    private func hash(slot: Int, step: Int) -> Int {
        var x = UInt64(bitPattern: Int64(slot &* 73856093 ^ step &* 19349663))
        x ^= x >> 33
        x = x &* 0xff51afd7ed558ccd
        x ^= x >> 33
        return Int(x & 0x7fff_ffff)
    }

    // MARK: - Palette

    /// Locked = bright phosphor green-white; unlocked = dim, never invisible.
    private func slotColor(locked: Bool, nearFront: Bool) -> Color {
        if locked {
            return Color(red: 0.78, green: 1.0, blue: 0.86)
        } else if nearFront {
            return Color(red: 0.42, green: 0.78, blue: 0.55)
        } else {
            return Color(red: 0.26, green: 0.46, blue: 0.36)
        }
    }

    private var lockedGlow: Color {
        Color(red: 0.30, green: 1.0, blue: 0.55)
    }

    private var backgroundFill: some View {
        LinearGradient(
            colors: [
                Color(red: 0.015, green: 0.020, blue: 0.040),
                Color(red: 0.020, green: 0.035, blue: 0.030)
            ],
            startPoint: .top,
            endPoint: .bottom
        )
    }
}

// MARK: - Tap replay modifier

/// Adds an onTapGesture only for the real interactive component, keeping the
/// demo tile purely self-driving.
private struct DecodeMatrixView_TapReplay: ViewModifier {
    let enabled: Bool
    let action: () -> Void

    func body(content: Content) -> some View {
        if enabled {
            content.onTapGesture { action() }
        } else {
            content
        }
    }
}
"""###,
        "tx-elastic-pop": ###"""
import SwiftUI

// MARK: - Per-Character Pop
// Characters spring in from zero scale with an overshoot bounce, one after
// another, each landing with a tiny squash-and-stretch and a soft shadow that
// settles — like letters dropping onto a trampoline surface.
//
// demo == true  → self-driving TimelineView loop: a continuous staggered
//                 "breathing" spring pop. Letters spring up to full scale with
//                 a squash-and-stretch landing, hold legibly, then ease back to
//                 a still-legible floor (popFloor) before the next cycle — they
//                 never fully exit and never re-enter from zero, so the word is
//                 never blank or discontinuous on any frame.
// demo == false → real interactive component: starts fully formed; a tap
//                 replays the staggered per-letter spring pop with the
//                 squash-and-stretch landing.

struct ElasticPopView: View {
    var demo: Bool = false

    private let word = "BOUNCE"
    private let stagger: Double = 0.07

    // Tap-incremented trigger for the interactive (demo == false) path.
    @State private var popToken: Int = 0

    var body: some View {
        GeometryReader { geo in
            let metrics = ElasticPopView_Metrics(size: geo.size, count: word.count)
            ZStack {
                backdrop
                content(metrics: metrics)
            }
            .frame(width: geo.size.width, height: geo.size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .contentShape(Rectangle())
        .onTapGesture {
            guard !demo else { return }
            popToken += 1
        }
    }

    // MARK: Backdrop

    private var backdrop: some View {
        // The catalog tint (#04050a) as a soft vertical wash.
        LinearGradient(
            colors: [
                Color(red: 0.035, green: 0.043, blue: 0.078),
                Color(red: 0.012, green: 0.016, blue: 0.039)
            ],
            startPoint: .top,
            endPoint: .bottom
        )
        .ignoresSafeArea()
    }

    // MARK: Content router

    @ViewBuilder
    private func content(metrics: ElasticPopView_Metrics) -> some View {
        if demo {
            demoRow(metrics: metrics)
        } else {
            interactiveRow(metrics: metrics)
        }
    }

    // MARK: Demo — self-driving loop

    private func demoRow(metrics: ElasticPopView_Metrics) -> some View {
        TimelineView(.animation) { timeline in
            let loop = loopPhase(date: timeline.date)
            characterRow(metrics: metrics) { index in
                demoProgress(loopPhase: loop, index: index)
            }
        }
    }

    // MARK: Interactive — tap to replay

    private func interactiveRow(metrics: ElasticPopView_Metrics) -> some View {
        characterRow(metrics: metrics) { _ in 1.0 }
            .overlay(alignment: .center) {
                // Per-character keyframe pop, retriggered by popToken.
                interactiveOverlay(metrics: metrics)
            }
            // The resting row beneath stays fully formed so the detail view is
            // never blank; the overlay supplies the animated replay.
            .opacity(popToken == 0 ? 1 : 0)
    }

    @ViewBuilder
    private func interactiveOverlay(metrics: ElasticPopView_Metrics) -> some View {
        if popToken > 0 {
            HStack(spacing: metrics.spacing) {
                ForEach(Array(word.enumerated()), id: \.offset) { index, ch in
                    ElasticPopView_KeyframePopCharacter(
                        character: String(ch),
                        fontSize: metrics.fontSize,
                        delay: Double(index) * stagger,
                        trigger: popToken
                    )
                }
            }
        }
    }

    // MARK: Shared row of pop characters

    private func characterRow(
        metrics: ElasticPopView_Metrics,
        progress: @escaping (Int) -> Double
    ) -> some View {
        HStack(spacing: metrics.spacing) {
            ForEach(Array(word.enumerated()), id: \.offset) { index, ch in
                ElasticPopView_PopCharacter(
                    character: String(ch),
                    fontSize: metrics.fontSize,
                    progress: progress(index)
                )
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // MARK: Demo timing

    // Normalized 0→1 phase over a ~3.2s loop.
    private func loopPhase(date: Date) -> Double {
        let period: Double = 3.2
        let t = date.timeIntervalSinceReferenceDate.truncatingRemainder(dividingBy: period)
        return t / period
    }

    // Per-character progress for the demo loop.
    //
    // A single continuous, seam-safe "breathing" pop per letter:
    //   - A per-letter local phase is offset by the stagger wave, so letters
    //     bounce left-to-right.
    //   - The shaping curve `bump` is exactly 0 at both ends of the local
    //     phase and rises (with a little spring overshoot) to 1 in between.
    //   - We map [0, 1] of that bump onto [popFloor, ~1.0] so the *minimum*
    //     progress any letter ever reaches is popFloor (never 0).
    //
    // Result: progress == popFloor at both phase→0 and phase→1 (no wrap
    // discontinuity), and never below popFloor (never blank: opacity is
    // min(1, prog*1.6) and popFloor*1.6 > 1, so it stays fully opaque).
    private func demoProgress(loopPhase: Double, index: Int) -> Double {
        let count = Double(word.count)
        let norm = count > 1 ? Double(index) / (count - 1) : 0

        // Floor the breathing pop never drops below (keeps every letter legible).
        let popFloor: Double = 0.66

        // Per-letter local phase in [0, 1), staggered left-to-right.
        let spreadFrac: Double = 0.18
        var local = loopPhase - norm * spreadFrac
        local = local - floor(local)          // wrap into [0, 1)

        // Shaping bump: 0 at both ends, springs up to ~1 in between.
        let shaped = bump(local)

        return popFloor + (1.0 - popFloor) * shaped
    }

    // A 0→(overshoot)→hold→0 bump over [0,1] that is exactly 0 at both ends,
    // giving a spring-like rise, a legible hold near the top, then an ease back.
    private func bump(_ x: Double) -> Double {
        let t = clamp(x)
        let riseEnd: Double = 0.34   // spring up
        let fallStart: Double = 0.78 // start easing back

        if t < riseEnd {
            let p = t / riseEnd
            return clamp(easeOutBack(p))      // 0 → ~1 with overshoot
        } else if t < fallStart {
            return 1.0                        // legible hold at full scale
        } else {
            let span = max(1.0 - fallStart, 0.0001)
            let p = (t - fallStart) / span    // 0 → 1
            return clamp(1.0 - easeInCubic(p)) // 1 → 0, smooth landing at the seam
        }
    }

    private func clamp(_ v: Double) -> Double { min(1, max(0, v)) }

    private func easeInCubic(_ x: Double) -> Double { x * x * x }

    // Overshoot ease for the spring rise (back-out). Note easeOutBack(0)==0
    // and easeOutBack(1)==1, so the bump pins to 0 at the seam.
    private func easeOutBack(_ x: Double) -> Double {
        let c1: Double = 1.70158
        let c3: Double = c1 + 1
        let p = x - 1
        return 1 + c3 * p * p * p + c1 * p * p
    }
}

// MARK: - Layout metrics

private struct ElasticPopView_Metrics {
    let fontSize: CGFloat
    let spacing: CGFloat

    init(size: CGSize, count: Int) {
        let w = max(size.width, 1)
        let h = max(size.height, 1)
        // Fit the word horizontally and keep headroom for the bounce vertically.
        let byWidth = w / (CGFloat(max(count, 1)) * 0.92)
        let byHeight = h * 0.42
        let f = min(byWidth, byHeight)
        self.fontSize = max(12, min(f, 120))
        self.spacing = self.fontSize * 0.04
    }
}

// MARK: - Squash/stretch model

// Maps a 0→1 entrance progress to non-uniform scaleX/scaleY, a vertical drop,
// and a soft landing shadow. The non-uniform scales near landing are what
// produce the squash-and-stretch, which fully settles to (1, 1) at rest.
private struct ElasticPopView_PopShape {
    var scaleX: CGFloat
    var scaleY: CGFloat
    var yOffset: CGFloat
    var shadowRadius: CGFloat
    var shadowOpacity: Double
    var opacity: Double

    static func from(progress p: Double, fontSize: CGFloat) -> ElasticPopView_PopShape {
        let prog = min(1, max(0, p))

        // Base uniform scale follows the back-out ease already applied upstream.
        let base = CGFloat(prog)

        // Squash window: a brief non-uniform pulse around the landing (~0.6–0.95).
        // bell peaks near landing; a (1 - prog) falloff forces it to exactly 0
        // at prog == 1 so the letter settles perfectly square at rest.
        let raw = bell(prog, center: 0.80, width: 0.16)
        let settle = max(0, 1 - prog)            // → 0 at rest
        let squash = CGFloat(raw * settle)

        // At landing the letter flattens: wider X, shorter Y, then settles to 1.
        let sx = base + squash * 0.26
        let sy = base - squash * 0.24

        // Drop in from slightly above; settle to baseline with the bounce.
        let drop = (1 - CGFloat(easeOutSoft(prog))) * fontSize * 0.18

        // Shadow grows as the letter approaches the surface.
        let shadowR = fontSize * 0.10 * CGFloat(prog)
        let shadowO = 0.45 * prog

        // Opacity ramps quickly so letters read almost immediately, never harsh.
        let op = min(1, prog * 1.6)

        return ElasticPopView_PopShape(
            scaleX: max(0.001, sx),
            scaleY: max(0.001, sy),
            yOffset: drop,
            shadowRadius: shadowR,
            shadowOpacity: shadowO,
            opacity: op
        )
    }

    // Gaussian-ish bell, 0..1.
    private static func bell(_ x: Double, center: Double, width: Double) -> Double {
        let d = (x - center) / width
        return exp(-d * d)
    }

    private static func easeOutSoft(_ x: Double) -> Double {
        1 - pow(1 - x, 3)
    }
}

// MARK: - Demo character (driven by external progress)

private struct ElasticPopView_PopCharacter: View {
    let character: String
    let fontSize: CGFloat
    let progress: Double

    var body: some View {
        let shape = ElasticPopView_PopShape.from(progress: progress, fontSize: fontSize)
        glyph
            .scaleEffect(x: shape.scaleX, y: shape.scaleY, anchor: .bottom)
            .offset(y: shape.yOffset)
            .shadow(
                color: Color.black.opacity(shape.shadowOpacity),
                radius: shape.shadowRadius,
                x: 0,
                y: shape.shadowRadius * 0.6
            )
            .opacity(shape.opacity)
    }

    private var glyph: some View {
        Text(character)
            .font(.system(size: fontSize, weight: .heavy, design: .rounded))
            .foregroundStyle(glyphFill)
            .lineLimit(1)
            .fixedSize()
    }

    private var glyphFill: LinearGradient {
        LinearGradient(
            colors: [
                Color(red: 0.62, green: 0.83, blue: 1.0),
                Color(red: 0.38, green: 0.55, blue: 0.98)
            ],
            startPoint: .top,
            endPoint: .bottom
        )
    }
}

// MARK: - Interactive character (KeyframeAnimator, replays on tap)

private struct ElasticPopView_KeyframePopCharacter: View {
    let character: String
    let fontSize: CGFloat
    let delay: Double
    let trigger: Int

    struct PopValues {
        var scaleX: CGFloat = 0.001
        var scaleY: CGFloat = 0.001
        var yOffset: CGFloat = 0
        var shadow: Double = 0
        var opacity: Double = 0
    }

    var body: some View {
        KeyframeAnimator(
            initialValue: PopValues(),
            trigger: trigger
        ) { v in
            Text(character)
                .font(.system(size: fontSize, weight: .heavy, design: .rounded))
                .foregroundStyle(fill)
                .lineLimit(1)
                .fixedSize()
                .scaleEffect(x: v.scaleX, y: v.scaleY, anchor: .bottom)
                .offset(y: v.yOffset)
                .shadow(
                    color: Color.black.opacity(v.shadow),
                    radius: fontSize * 0.10 * CGFloat(v.opacity),
                    x: 0,
                    y: fontSize * 0.06 * CGFloat(v.opacity)
                )
                .opacity(v.opacity)
        } keyframes: { _ in
            // scaleX: grows, overshoots wide at landing (stretch), settles to 1.
            KeyframeTrack(\.scaleX) {
                LinearKeyframe(0.001, duration: delay)
                SpringKeyframe(0.82, duration: 0.18, spring: .bouncy)
                SpringKeyframe(1.18, duration: 0.12)   // stretch wide on landing
                SpringKeyframe(1.0, duration: 0.30, spring: .snappy)
            }
            // scaleY: grows tall, then squashes short at landing, settles to 1.
            KeyframeTrack(\.scaleY) {
                LinearKeyframe(0.001, duration: delay)
                SpringKeyframe(1.20, duration: 0.18, spring: .bouncy) // tall arriving
                SpringKeyframe(0.80, duration: 0.12)   // squash short on landing
                SpringKeyframe(1.0, duration: 0.30, spring: .snappy)
            }
            // yOffset: drops in from above, lands at baseline.
            KeyframeTrack(\.yOffset) {
                LinearKeyframe(-fontSize * 0.22, duration: delay)
                SpringKeyframe(0, duration: 0.30, spring: .bouncy)
            }
            // shadow: blooms as it lands, eases off slightly.
            KeyframeTrack(\.shadow) {
                LinearKeyframe(0, duration: delay)
                LinearKeyframe(0, duration: 0.16)
                CubicKeyframe(0.5, duration: 0.12)
                CubicKeyframe(0.38, duration: 0.30)
            }
            // opacity: snaps in fast so the letter is legible immediately.
            KeyframeTrack(\.opacity) {
                LinearKeyframe(0, duration: delay)
                CubicKeyframe(1, duration: 0.12)
            }
        }
    }

    private var fill: LinearGradient {
        LinearGradient(
            colors: [
                Color(red: 0.62, green: 0.83, blue: 1.0),
                Color(red: 0.38, green: 0.55, blue: 0.98)
            ],
            startPoint: .top,
            endPoint: .bottom
        )
    }
}
"""###,
        "tx-elastic-rope": ###"""
import SwiftUI

// MARK: - Elastic Rope Text
// Drag anywhere on the line to pluck the nearest glyphs toward your finger on
// damped springs; release and a traveling recoil wave snaps everything back.
// Idle, a virtual touch point sweeps the line so the rope ripples on its own.

public struct ElasticRopeView: View {
    public var demo: Bool = false

    public init(demo: Bool = false) {
        self.demo = demo
    }

    private let phrase: String = "ELASTIC"

    public var body: some View {
        GeometryReader { proxy in
            content(in: proxy.size)
                .frame(maxWidth: .infinity, maxHeight: .infinity)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    @ViewBuilder
    private func content(in size: CGSize) -> some View {
        let amplitude = ElasticRopeView_ElasticRopeMath.amplitude(for: size)
        let fontSize = ElasticRopeView_ElasticRopeMath.fontSize(for: size, charCount: phrase.count)

        ElasticRopeView_ElasticRopeStage(
            phrase: phrase,
            demo: demo,
            size: size,
            amplitude: amplitude,
            fontSize: fontSize
        )
    }
}

// MARK: - Shared math (single source of truth for displacement)

private enum ElasticRopeView_ElasticRopeMath {

    static func amplitude(for size: CGSize) -> CGFloat {
        // Clamp pull strength to the tile so glyphs never fly off / clip.
        let base = min(size.width, size.height) * 0.42
        return max(8, min(base, 80))
    }

    static func fontSize(for size: CGSize, charCount: Int) -> CGFloat {
        let byWidth = size.width / (CGFloat(max(charCount, 1)) * 0.72)
        let byHeight = size.height * 0.42
        return max(13, min(min(byWidth, byHeight), 64))
    }

    /// Falloff weight in fraction-space (0...1 along the line).
    /// Nearest glyph to the touch fraction gets the strongest pull.
    static func weight(glyphFraction: CGFloat, touchFraction: CGFloat) -> CGFloat {
        let d = abs(glyphFraction - touchFraction)
        let sigma: CGFloat = 0.18
        let x = d / sigma
        return CGFloat(exp(Double(-x * x)))      // Gaussian bell, peak 1 at the finger
    }

    /// Pure displacement for one glyph given its position along the line and the
    /// current touch state. Returns an (dx, dy) offset in points.
    /// `touchFraction`/`touchY` describe where the finger (or virtual sweep) is.
    /// `pull` is 0...1 active grip strength; `recoil` carries the snap-back wave.
    static func displacement(
        glyphFraction: CGFloat,
        touchFraction: CGFloat,
        touchY: CGFloat,
        pull: CGFloat,
        recoil: ElasticRopeView_RecoilState,
        amplitude: CGFloat,
        index: Int,
        count: Int
    ) -> CGSize {

        // 1. Active grip: glyphs near the finger are tugged toward it.
        let w = weight(glyphFraction: glyphFraction, touchFraction: touchFraction)
        let dir = touchFraction - glyphFraction
        let gripX = dir * amplitude * w * pull
        let gripY = touchY * amplitude * 0.55 * w * pull

        // 2. Recoil: after release, a damped spring wave travels down the line.
        var recoilX: CGFloat = 0
        var recoilY: CGFloat = 0
        if recoil.active {
            // Per-index delay so the snap-back ripples along the rope.
            let travel = CGFloat(index) / CGFloat(max(count - 1, 1))
            let delayed = recoil.elapsed - travel * 0.28
            if delayed > 0 {
                let decay = CGFloat(exp(Double(-delayed * 6.5)))
                let osc = CGFloat(sin(Double(delayed * 34)))
                let releaseWeight = weight(
                    glyphFraction: glyphFraction,
                    touchFraction: recoil.fraction
                )
                let energy = recoil.strength * releaseWeight * decay
                recoilX = (recoil.fraction - glyphFraction) * amplitude * 0.9 * osc * energy
                recoilY = recoil.y * amplitude * 0.5 * osc * energy
            }
        }

        return CGSize(width: gripX + recoilX, height: gripY + recoilY)
    }
}

/// Snapshot of the release-recoil wave.
private struct ElasticRopeView_RecoilState {
    var active: Bool = false
    var fraction: CGFloat = 0.5   // where the finger let go (0...1)
    var y: CGFloat = 0            // vertical pull at release (normalized)
    var strength: CGFloat = 0     // 0...1 captured grip strength
    var elapsed: Double = 0       // seconds since release
}

// MARK: - Stage: one always-on TimelineView drives both modes

private struct ElasticRopeView_ElasticRopeStage: View {
    let phrase: String
    let demo: Bool
    let size: CGSize
    let amplitude: CGFloat
    let fontSize: CGFloat

    // Live drag state (interactive mode only).
    @State private var isDragging: Bool = false
    @State private var dragFraction: CGFloat = 0.5
    @State private var dragY: CGFloat = 0

    // Release info, captured the instant the finger lifts.
    @State private var releaseDate: Date? = nil
    @State private var releaseFraction: CGFloat = 0.5
    @State private var releaseY: CGFloat = 0
    @State private var releaseStrength: CGFloat = 0

    private var characters: [Character] { Array(phrase) }

    var body: some View {
        TimelineView(.animation) { timeline in
            let now = timeline.date
            let t = now.timeIntervalSinceReferenceDate
            let state = resolveTouch(now: now, t: t)

            ZStack {
                background
                ropeContent(state: state)
            }
            .contentShape(Rectangle())
            .gesture(dragGesture, including: demo ? .none : .all)
        }
    }

    // MARK: Touch resolution

    struct TouchState {
        var fraction: CGFloat
        var y: CGFloat
        var pull: CGFloat
        var recoil: ElasticRopeView_RecoilState
    }

    private func resolveTouch(now: Date, t: TimeInterval) -> TouchState {
        if !demo && isDragging {
            // Live grip.
            return TouchState(
                fraction: dragFraction,
                y: dragY,
                pull: 1.0,
                recoil: ElasticRopeView_RecoilState(active: false)
            )
        }

        // Build any active recoil wave from the last release.
        var recoil = ElasticRopeView_RecoilState(active: false)
        if let release = releaseDate {
            let elapsed = now.timeIntervalSince(release)
            if elapsed < 1.4 {
                recoil = ElasticRopeView_RecoilState(
                    active: true,
                    fraction: releaseFraction,
                    y: releaseY,
                    strength: releaseStrength,
                    elapsed: elapsed
                )
            }
        }

        if demo {
            // Virtual sweep travels the line on a ~3.2s loop, always visible.
            let period: Double = 3.2
            let phase = (t.truncatingRemainder(dividingBy: period)) / period
            let frac = 0.5 + 0.46 * CGFloat(sin(phase * 2 * .pi))
            let yWobble = 0.5 * CGFloat(sin(phase * 4 * .pi))
            // Pull eases in/out so the rope breathes rather than snapping.
            let pull = 0.55 + 0.45 * CGFloat(0.5 - 0.5 * cos(phase * 4 * .pi))
            return TouchState(fraction: frac, y: yWobble, pull: pull, recoil: recoil)
        }

        // Interactive, idle (not dragging): gentle auto sine so the tile stays alive.
        let period: Double = 3.6
        let phase = (t.truncatingRemainder(dividingBy: period)) / period
        let frac = 0.5 + 0.30 * CGFloat(sin(phase * 2 * .pi))
        let idlePull: CGFloat = recoil.active ? 0 : 0.28
        return TouchState(fraction: frac, y: 0, pull: idlePull, recoil: recoil)
    }

    // MARK: Content (iOS 18 TextRenderer, with iOS 17 fallback)

    @ViewBuilder
    private func ropeContent(state: TouchState) -> some View {
        if #available(iOS 18.0, *) {
            renderedText(state: state)
        } else {
            fallbackText(state: state)
        }
    }

    @available(iOS 18.0, *)
    @ViewBuilder
    private func renderedText(state: TouchState) -> some View {
        let renderer = ElasticRopeView_ElasticRopeRenderer(
            touchFraction: state.fraction,
            touchY: state.y,
            pull: state.pull,
            recoil: state.recoil,
            amplitude: amplitude,
            count: characters.count
        )
        styledText
            .textRenderer(renderer)
    }

    // iOS 17 fallback: per-character offset HStack sharing the same math.
    @ViewBuilder
    private func fallbackText(state: TouchState) -> some View {
        HStack(spacing: 0) {
            ForEach(Array(characters.enumerated()), id: \.offset) { idx, ch in
                let frac = characters.count <= 1
                    ? 0.5
                    : CGFloat(idx) / CGFloat(characters.count - 1)
                let offset = ElasticRopeView_ElasticRopeMath.displacement(
                    glyphFraction: frac,
                    touchFraction: state.fraction,
                    touchY: state.y,
                    pull: state.pull,
                    recoil: state.recoil,
                    amplitude: amplitude,
                    index: idx,
                    count: characters.count
                )
                Text(String(ch))
                    .font(.system(size: fontSize, weight: .heavy, design: .rounded))
                    .kerning(1.5)
                    .foregroundStyle(glyphStyle)
                    .offset(x: offset.width, y: offset.height)
            }
        }
    }

    private var styledText: some View {
        Text(phrase)
            .font(.system(size: fontSize, weight: .heavy, design: .rounded))
            .kerning(2)
            .foregroundStyle(glyphStyle)
    }

    private var glyphStyle: LinearGradient {
        LinearGradient(
            colors: [
                Color(red: 0.62, green: 0.86, blue: 1.00),
                Color(red: 0.46, green: 0.62, blue: 0.98),
                Color(red: 0.78, green: 0.58, blue: 0.99)
            ],
            startPoint: .leading,
            endPoint: .trailing
        )
    }

    private var background: some View {
        LinearGradient(
            colors: [
                Color(red: 0.015, green: 0.020, blue: 0.040),
                Color(red: 0.040, green: 0.050, blue: 0.090)
            ],
            startPoint: .top,
            endPoint: .bottom
        )
    }

    // MARK: Gesture

    private var dragGesture: some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                isDragging = true
                releaseDate = nil
                let f = size.width > 0 ? value.location.x / size.width : 0.5
                dragFraction = min(max(f, 0), 1)
                // Vertical pull normalized about the line center.
                let center = size.height / 2
                let dy = size.height > 0 ? (value.location.y - center) / (size.height / 2) : 0
                dragY = min(max(dy, -1), 1)
            }
            .onEnded { value in
                isDragging = false
                let f = size.width > 0 ? value.location.x / size.width : 0.5
                releaseFraction = min(max(f, 0), 1)
                releaseY = dragY
                releaseStrength = 1.0
                releaseDate = Date()
            }
    }
}

// MARK: - iOS 18 TextRenderer

@available(iOS 18.0, *)
private struct ElasticRopeView_ElasticRopeRenderer: TextRenderer {
    let touchFraction: CGFloat
    let touchY: CGFloat
    let pull: CGFloat
    let recoil: ElasticRopeView_RecoilState
    let amplitude: CGFloat
    let count: Int

    func draw(layout: Text.Layout, in context: inout GraphicsContext) {
        // Collect every glyph slice in reading order so we can index them
        // for the per-glyph traveling recoil wave.
        var slices: [Text.Layout.RunSlice] = []
        for line in layout {
            for run in line {
                for slice in run {
                    slices.append(slice)
                }
            }
        }

        let total = max(slices.count, 1)
        for (idx, slice) in slices.enumerated() {
            let glyphFraction = total <= 1
                ? 0.5
                : CGFloat(idx) / CGFloat(total - 1)

            let offset = ElasticRopeView_ElasticRopeMath.displacement(
                glyphFraction: glyphFraction,
                touchFraction: touchFraction,
                touchY: touchY,
                pull: pull,
                recoil: recoil,
                amplitude: amplitude,
                index: idx,
                count: count
            )

            var copy = context
            copy.translateBy(x: offset.width, y: offset.height)
            copy.draw(slice)
        }
    }
}
"""###,
        "tx-fold-origami": ###"""
import SwiftUI

/// Origami Letter Unfold — each glyph unfolds from a flat folded triangle,
/// hinging open across two creases with 3D rotation and a gradient fold-shadow
/// that resolves to a flat face, staggered like a paper fan opening.
///
/// - demo == true  : self-driving PhaseAnimator-style loop (via TimelineView)
///                   folds the word shut then open on a ~2.8s loop.
/// - demo == false : tap to replay the staggered unfold from folded triangles
///                   to flat faces.
struct FoldOrigamiView: View {
    var demo: Bool = false

    // The short word keeps the per-letter fan legible inside a ~120pt tile.
    private let word: [Character] = Array("FOLD")

    // Loop timing for the auto-driving preview.
    private let loopDuration: Double = 2.8

    // How much of the loop each successive letter is delayed (paper-fan stagger).
    private let stagger: Double = 0.16
    // The window over which a single letter completes its unfold.
    private let foldWindow: Double = 0.55

    @State private var tapProgress: Double = 1.0
    @State private var loopStart: Date = .now

    var body: some View {
        GeometryReader { geo in
            content(in: geo.size)
                .frame(maxWidth: .infinity, maxHeight: .infinity)
                .contentShape(Rectangle())
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    @ViewBuilder
    private func content(in size: CGSize) -> some View {
        if demo {
            autoDriven(in: size)
        } else {
            interactive(in: size)
        }
    }

    // MARK: - Auto-driving preview

    private func autoDriven(in size: CGSize) -> some View {
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSince(loopStart)
            let global = loopProgress(t)
            letterRow(in: size, globalProgress: global)
        }
    }

    // Maps elapsed time to a 0→1→0 triangle wave so the fan opens then folds shut.
    private func loopProgress(_ elapsed: Double) -> Double {
        let phase = (elapsed / loopDuration).truncatingRemainder(dividingBy: 1.0)
        // Ease the ramp so the open/close feels paper-soft, not linear.
        let ramp = phase < 0.5 ? phase * 2.0 : (1.0 - phase) * 2.0
        return easeInOut(ramp)
    }

    // MARK: - Interactive (tap to replay)

    private func interactive(in size: CGSize) -> some View {
        letterRow(in: size, globalProgress: tapProgress)
            .onTapGesture {
                replayUnfold()
            }
    }

    private func replayUnfold() {
        // Snap shut instantly, then unfold open with a staggered spring-ish ramp.
        tapProgress = 0.0
        withAnimation(.timingCurve(0.22, 0.9, 0.3, 1.0, duration: 1.5)) {
            tapProgress = 1.0
        }
    }

    // MARK: - Shared layout

    private func letterRow(in size: CGSize, globalProgress: Double) -> some View {
        let metrics = layoutMetrics(for: size)
        return HStack(spacing: metrics.spacing) {
            ForEach(Array(word.enumerated()), id: \.offset) { index, char in
                FoldOrigamiView_FoldingLetter(
                    character: char,
                    fontSize: metrics.fontSize,
                    progress: letterProgress(globalProgress, index: index)
                )
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // Per-letter progress: stagger the start, then complete over a fixed window.
    private func letterProgress(_ global: Double, index: Int) -> Double {
        let start = Double(index) * stagger
        let local = (global - start) / foldWindow
        return clamp01(local)
    }

    // MARK: - Metrics

    struct Metrics {
        let fontSize: CGFloat
        let spacing: CGFloat
    }

    private func layoutMetrics(for size: CGSize) -> Metrics {
        let count = CGFloat(max(word.count, 1))
        // Reserve some breathing room; size the type to the smaller axis budget.
        let widthBudget: CGFloat = size.width * 0.82
        let perLetterWidth = widthBudget / count
        // Glyph aspect heuristic: width ≈ 0.66 * fontSize for this caps word.
        let byWidth = perLetterWidth / 0.78
        let byHeight = size.height * 0.5
        let raw = min(byWidth, byHeight)
        let fontSize = max(14.0, min(raw, 120.0))
        let spacing = max(1.0, fontSize * 0.06)
        return Metrics(fontSize: fontSize, spacing: spacing)
    }

    // MARK: - Math helpers

    private func clamp01(_ v: Double) -> Double {
        min(1.0, max(0.0, v))
    }

    private func easeInOut(_ x: Double) -> Double {
        // Smoothstep.
        let c = min(1.0, max(0.0, x))
        return c * c * (3.0 - 2.0 * c)
    }
}

// MARK: - FoldOrigamiView_FoldingLetter

/// One glyph rendered as two half-faces hinging open along a central crease.
/// progress == 0 → folded shut (a foreshortened triangle, still legible),
/// progress == 1 → flat, the two halves recomposing into the whole glyph.
private struct FoldOrigamiView_FoldingLetter: View {
    let character: Character
    let fontSize: CGFloat
    let progress: Double   // 0 folded ... 1 flat

    // Clamp the maximum fold so the "shut" extreme is a legible foreshortened
    // triangle rather than an invisible edge-on line (never-blank guarantee).
    private let maxFold: Double = 74.0

    // Paper tints.
    private let paper = Color(red: 0.97, green: 0.96, blue: 0.93)
    private let ink = Color(red: 0.07, green: 0.08, blue: 0.11)

    var body: some View {
        ZStack {
            topHalf
            bottomHalf
        }
        .frame(width: glyphWidth, height: glyphHeight)
        // A faint cast shadow that grows when folded for a touch of depth.
        .background(castShadow)
        .compositingGroup()
        .opacity(faceOpacity)
    }

    // MARK: - Halves

    private var topHalf: some View {
        glyphFace
            .mask(halfMask(top: true))
            .overlay(creaseShadow(top: true).mask(halfMask(top: true)))
            .rotation3DEffect(
                .degrees(foldAngle),
                axis: (x: 1.0, y: 0.22, z: 0.0),
                anchor: .bottom,
                perspective: 0.55
            )
    }

    private var bottomHalf: some View {
        glyphFace
            .mask(halfMask(top: false))
            .overlay(creaseShadow(top: false).mask(halfMask(top: false)))
            .rotation3DEffect(
                .degrees(-foldAngle),
                axis: (x: 1.0, y: -0.22, z: 0.0),
                anchor: .top,
                perspective: 0.55
            )
    }

    // The actual letter face — identical frame for both copies so the flat
    // state recomposes seamlessly with no seam between halves.
    private var glyphFace: some View {
        Text(String(character))
            .font(.system(size: fontSize, weight: .heavy, design: .rounded))
            .foregroundStyle(ink)
            .frame(width: glyphWidth, height: glyphHeight)
    }

    // MARK: - Masks

    private func halfMask(top: Bool) -> some View {
        VStack(spacing: 0) {
            if top {
                Rectangle().fill(.black)
                Rectangle().fill(.clear)
            } else {
                Rectangle().fill(.clear)
                Rectangle().fill(.black)
            }
        }
        .frame(width: glyphWidth, height: glyphHeight)
    }

    // MARK: - Crease shadow

    // A gradient that darkens toward the crease and fades as the face opens flat.
    private func creaseShadow(top: Bool) -> some View {
        let start: UnitPoint = top ? .bottom : .top
        let end: UnitPoint = top ? .top : .bottom
        return LinearGradient(
            colors: [
                Color.black.opacity(creaseOpacity),
                Color.black.opacity(creaseOpacity * 0.18),
                Color.clear
            ],
            startPoint: start,
            endPoint: end
        )
        .blendMode(.multiply)
    }

    // MARK: - Cast shadow under the folded paper

    private var castShadow: some View {
        Ellipse()
            .fill(Color.black.opacity(0.10 + 0.10 * (1.0 - clampedProgress)))
            .frame(width: glyphWidth * 0.82, height: glyphHeight * 0.16)
            .blur(radius: 3)
            .offset(y: glyphHeight * 0.46)
    }

    // MARK: - Derived values

    private var clampedProgress: Double {
        min(1.0, max(0.0, progress))
    }

    // Fold angle: full clamped fold when shut, 0 when flat/open.
    private var foldAngle: Double {
        maxFold * (1.0 - clampedProgress)
    }

    // Crease shadow strongest when folded, fading to nothing when flat.
    private var creaseOpacity: Double {
        0.55 * (1.0 - clampedProgress)
    }

    // Keep the glyph fully visible; only nudge opacity at the very start so a
    // freshly-snapped-shut letter still reads.
    private var faceOpacity: Double {
        0.55 + 0.45 * clampedProgress
    }

    private var glyphWidth: CGFloat {
        fontSize * 0.78
    }

    private var glyphHeight: CGFloat {
        fontSize * 1.12
    }
}
"""###,
        "tx-gooey-merge": ###"""
import SwiftUI

// MARK: - Gooey Letter Merge
//
// Characters slide together and their soft blurred-threshold edges fuse into
// gooey metaball blobs, then crisp apart into clean letters, looping the
// melt-and-resolve via a blur + alpha-threshold mask drawn in a Canvas.
//
// Mechanism (pure Canvas, no Metal):
//   * All glyphs are drawn inside ONE drawLayer so their blur halos can overlap
//     and bridge into metaballs.
//   * Filter order matters: SwiftUI applies the LAST-added filter innermost, so
//     to get  content -> blur -> alphaThreshold  the threshold is added FIRST
//     and the blur SECOND.
//   * A single sine phase drives BOTH inter-letter spacing and blur radius so the
//     merge (spacing closed, blur high) and the resolve (spacing open, blur ~0)
//     stay perfectly locked together.
//   * The thresholded blobs are drawn in white and used as the alpha mask for a
//     warm gradient, which supplies the color.
//
// interaction == "auto": both demo branches run the same self-driving loop.
struct GooeyMergeView: View {
    var demo: Bool = false

    private let word = "GOO"

    var body: some View {
        GeometryReader { proxy in
            let size = proxy.size
            TimelineView(.animation) { timeline in
                let t = timeline.date.timeIntervalSinceReferenceDate
                let phase = self.phase(at: t)
                content(size: size, phase: phase)
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // MARK: - Phase

    // A smooth 0...1 melt-and-resolve cycle on a ~3s loop.
    // 0 == fully resolved (crisp, spread). 1 == fully merged (gooey, tight).
    private func phase(at t: TimeInterval) -> CGFloat {
        let period: TimeInterval = 3.0
        let raw = (sin(t / period * 2.0 * .pi) + 1.0) / 2.0 // continuous, no seam
        return CGFloat(raw)
    }

    // MARK: - Composition

    @ViewBuilder
    private func content(size: CGSize, phase: CGFloat) -> some View {
        let dims = GooeyMergeView_Dimensions(size: size)

        ZStack {
            backdrop(dims: dims)

            // The gradient is the visible fill; the white thresholded blobs are
            // the alpha. Canvas background stays clear so the mask is shaped.
            gooGradient(phase: phase)
                .mask {
                    gooCanvas(dims: dims, phase: phase)
                }
                .shadow(color: shadowColor(phase: phase),
                        radius: dims.glow * phase,
                        x: 0, y: 0)
        }
        .frame(width: size.width, height: size.height)
    }

    private func backdrop(dims: GooeyMergeView_Dimensions) -> some View {
        RoundedRectangle(cornerRadius: dims.corner, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 0.015, green: 0.020, blue: 0.040),
                        Color(red: 0.040, green: 0.030, blue: 0.070)
                    ],
                    startPoint: .topLeading,
                    endPoint: .bottomTrailing
                )
            )
    }

    // MARK: - The metaball Canvas
    //
    // Draws the word's glyphs into a single thresholded+blurred layer so adjacent
    // letters fuse. All output is WHITE; color is supplied by the gradient mask.
    private func gooCanvas(dims: GooeyMergeView_Dimensions, phase: CGFloat) -> some View {
        Canvas { context, canvasSize in
            // Blur shrinks toward ~0 as the word resolves (phase -> 0), giving
            // genuinely crisp letters at rest and gooey blobs at full merge.
            let blurRadius = dims.maxBlur * phase + dims.minBlur

            // FILTER ORDER (critical):
            //   alphaThreshold added FIRST  -> outermost  (runs last)
            //   blur            added SECOND -> innermost  (runs first)
            // Effective pipeline: glyphs -> blur -> alphaThreshold == metaballs.
            context.addFilter(.alphaThreshold(min: 0.5, color: .white))
            context.addFilter(.blur(radius: blurRadius))

            // ONE drawLayer enclosing every glyph so their halos can bridge.
            context.drawLayer { layer in
                self.drawGlyphs(in: layer,
                                canvasSize: canvasSize,
                                dims: dims,
                                phase: phase)
            }
        }
    }

    private func drawGlyphs(in layer: GraphicsContext,
                            canvasSize: CGSize,
                            dims: GooeyMergeView_Dimensions,
                            phase: CGFloat) {
        let chars = Array(word)
        guard !chars.isEmpty else { return }

        // Resolve each glyph once.
        let resolved: [GraphicsContext.ResolvedText] = chars.map { ch in
            let text = Text(String(ch))
                .font(.system(size: dims.fontSize, weight: .black, design: .rounded))
                .foregroundStyle(.white)
            return layer.resolve(text)
        }

        let glyphSizes = resolved.map { $0.measure(in: canvasSize) }
        let totalGlyphWidth = glyphSizes.reduce(CGFloat(0)) { $0 + $1.width }

        // Spacing interpolates between spread (resolved) and tight/overlapping
        // (merged). At full merge the gap goes slightly negative so blur halos
        // overlap and bridge.
        let gap = dims.spreadGap + (dims.mergeGap - dims.spreadGap) * phase
        let count = CGFloat(chars.count)
        let totalWidth = totalGlyphWidth + gap * (count - 1)

        var cursorX = (canvasSize.width - totalWidth) / 2.0
        let centerY = canvasSize.height / 2.0

        for index in resolved.indices {
            let glyphSize = glyphSizes[index]
            let point = CGPoint(x: cursorX + glyphSize.width / 2.0, y: centerY)
            layer.draw(resolved[index], at: point, anchor: .center)
            cursorX += glyphSize.width + gap
        }
    }

    // MARK: - Color & glow

    private func gooGradient(phase: CGFloat) -> LinearGradient {
        // Palette stored as raw RGB components (no Color/UIColor round-trip),
        // so the in-file mix is self-contained and SwiftUI-only.
        let warm: RGB = (0.99, 0.62, 0.30)
        let pink: RGB = (0.98, 0.32, 0.55)
        let violet: RGB = (0.55, 0.35, 0.98)
        let cool: RGB = (0.30, 0.78, 0.98)

        // Hue warms slightly as the letters merge for extra life.
        let topRGB = mix(cool, warm, t: phase)
        let midRGB = mix(pink, warm, t: phase)
        let bottomRGB = mix(violet, pink, t: phase)

        let topColor = color(topRGB)
        let midColor = color(midRGB)
        let bottomColor = color(bottomRGB)

        return LinearGradient(
            colors: [topColor, midColor, bottomColor],
            startPoint: .topLeading,
            endPoint: .bottomTrailing
        )
    }

    private func shadowColor(phase: CGFloat) -> Color {
        Color(red: 0.98, green: 0.38, blue: 0.60).opacity(0.55 * phase + 0.10)
    }

    // MARK: - Pure RGB interpolation helpers (no UIKit, no Color round-trip)

    private typealias RGB = (r: Double, g: Double, b: Double)

    private func mix(_ a: RGB, _ b: RGB, t: CGFloat) -> RGB {
        let ta = Double(max(0, min(1, t)))
        return (
            r: a.r + (b.r - a.r) * ta,
            g: a.g + (b.g - a.g) * ta,
            b: a.b + (b.b - a.b) * ta
        )
    }

    private func color(_ c: RGB) -> Color {
        Color(red: c.r, green: c.g, blue: c.b)
    }
}

// MARK: - Geometry, all derived from the tile / detail size

private struct GooeyMergeView_Dimensions {
    let fontSize: CGFloat
    let spreadGap: CGFloat
    let mergeGap: CGFloat
    let maxBlur: CGFloat
    let minBlur: CGFloat
    let glow: CGFloat
    let corner: CGFloat

    init(size: CGSize) {
        let minSide = max(1, min(size.width, size.height))

        // Scale the heavy glyphs to the available space; bold + large so strokes
        // survive blur + threshold and never vanish.
        self.fontSize = minSide * 0.46

        // Positive spread when resolved; negative when merged so halos overlap.
        self.spreadGap = minSide * 0.06
        self.mergeGap = -fontSize * 0.34

        // Blur scales with geometry so bridges form identically at 120pt and at
        // a large detail size. Min blur keeps a soft tactile edge even at rest.
        self.maxBlur = fontSize * 0.22
        self.minBlur = max(0.6, fontSize * 0.015)

        self.glow = minSide * 0.10
        self.corner = minSide * 0.18
    }
}
"""###,
        "tx-gradient-flow": ###"""
import SwiftUI

/// Liquid Gradient Flow — a flowing multi-stop gradient travels through a text
/// mask with the colors warping along a sine path, so hues appear to pour and
/// swirl inside the glyphs rather than sweeping in a flat straight line.
///
/// - `demo == true`  : self-driving TimelineView loop (never blank, always legible).
/// - `demo == false` : same continuous flow (spec interaction is "auto"), with an
///                     optional, non-gating drag that nudges flow direction/phase.
struct GradientFlowView: View {
    var demo: Bool = false

    // Optional, non-gating interactive nudge. The TimelineView animates with or
    // without touch; the drag only adds a bias to the flow phase + direction.
    @State private var dragBias: CGFloat = 0
    @State private var directionBias: CGFloat = 0

    var body: some View {
        GeometryReader { proxy in
            let size = proxy.size
            content(in: size)
                .frame(width: size.width, height: size.height)
                .contentShape(Rectangle())
                // Keep the gesture always attached; gate recognition with a mask.
                // A bare `demo ? nil : gesture` ternary would unify to
                // `Optional<Gesture>`, which does not conform to `Gesture`.
                .gesture(flowDrag(in: size), including: demo ? .none : .all)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // MARK: - Content

    @ViewBuilder
    private func content(in size: CGSize) -> some View {
        TimelineView(.animation) { timeline in
            let phase = flowPhase(at: timeline.date)
            ZStack {
                background(in: size)
                flowText(phase: phase, size: size)
            }
        }
    }

    private func background(in size: CGSize) -> some View {
        // Near-black tint from the spec (#04050a). A faint vignette adds depth
        // without ever competing with the bright glyph flow.
        let endRadius: CGFloat = Swift.max(size.width, size.height) * 0.7 + 1
        return ZStack {
            Color(red: 0.016, green: 0.020, blue: 0.039)
            RadialGradient(
                colors: [
                    Color(red: 0.06, green: 0.07, blue: 0.12).opacity(0.9),
                    Color(red: 0.016, green: 0.020, blue: 0.039)
                ],
                center: .center,
                startRadius: 0,
                endRadius: endRadius
            )
            .opacity(0.6)
        }
        .ignoresSafeArea()
    }

    // MARK: - Flowing, sine-warped color masked by the word

    @ViewBuilder
    private func flowText(phase: Double, size: CGSize) -> some View {
        let fontSize = glyphFontSize(for: size)

        ZStack {
            // A faint constant base so even the dimmest flow frame stays legible
            // against the near-black background.
            wordText(fontSize: fontSize)
                .foregroundStyle(Color(red: 0.30, green: 0.34, blue: 0.46).opacity(0.55))

            // The warped, pouring color, clipped to the glyph shapes.
            warpedFlowCanvas(phase: phase, size: size)
                .mask {
                    wordText(fontSize: fontSize)
                }
                .overlay {
                    // A soft meniscus-like sheen riding the flow for extra liquidity.
                    sheenCanvas(phase: phase, size: size)
                        .mask { wordText(fontSize: fontSize) }
                        .blendMode(.plusLighter)
                }
        }
        .frame(width: size.width, height: size.height)
    }

    private func wordText(fontSize: CGFloat) -> some View {
        Text(Self.word)
            .font(.system(size: fontSize, weight: .heavy, design: .rounded))
            .kerning(fontSize * 0.02)
            .lineLimit(1)
            .minimumScaleFactor(0.4)
            .multilineTextAlignment(.center)
    }

    // MARK: - Canvas: per-column vertical sine displacement = literal warp

    private func warpedFlowCanvas(phase: Double, size: CGSize) -> some View {
        Canvas { context, canvasSize in
            drawFlowBands(in: &context, size: canvasSize, phase: phase)
        }
        .drawingGroup()
    }

    /// Draws several angled, phase-shifted gradient bands whose columns are
    /// pushed up/down by a traveling sine, so the superposition reads as
    /// swirling liquid currents rather than a flat linear sweep.
    private func drawFlowBands(in context: inout GraphicsContext, size: CGSize, phase: Double) {
        let columns = 56
        let safeWidth = Swift.max(size.width, 1)
        let safeHeight = Swift.max(size.height, 1)
        let columnWidth = safeWidth / CGFloat(columns)
        let amplitude = safeHeight * 0.22

        for index in 0..<columns {
            let x = CGFloat(index) * columnWidth
            let normalizedX = Double(index) / Double(columns)

            // Two superimposed sine waves at different spatial frequencies give a
            // curved, non-repeating-looking flow front.
            let waveA = sin((normalizedX * 6.2) + phase + Double(directionBias))
            let waveB = sin((normalizedX * 3.1) - (phase * 0.7))
            let yOffset = amplitude * CGFloat((waveA * 0.6) + (waveB * 0.4))

            // The color sampled for this column scrolls through the palette,
            // sine-warped so hues pour and curve along the glyphs.
            let colorPhase = normalizedX + (Double(yOffset) / Double(safeHeight)) + (phase * 0.16)
            let color = flowColor(at: colorPhase)

            let columnRect = CGRect(
                x: x - 0.5,
                y: (safeHeight * 0.5) + yOffset - (safeHeight * 0.9),
                width: columnWidth + 1.0,
                height: safeHeight * 1.8
            )
            context.fill(Path(columnRect), with: .color(color))
        }
    }

    /// A thin bright sheen band that travels across the flow, adding a liquid
    /// highlight without ever darkening any frame.
    private func sheenCanvas(phase: Double, size: CGSize) -> some View {
        Canvas { context, canvasSize in
            let center = (sin(phase * 0.8) * 0.5 + 0.5) * Double(canvasSize.width)
            let bandWidth = canvasSize.width * 0.28
            let rect = CGRect(
                x: CGFloat(center) - bandWidth / 2,
                y: 0,
                width: bandWidth,
                height: canvasSize.height
            )
            let gradient = Gradient(stops: [
                .init(color: .white.opacity(0.0), location: 0.0),
                .init(color: .white.opacity(0.45), location: 0.5),
                .init(color: .white.opacity(0.0), location: 1.0)
            ])
            context.fill(
                Path(rect),
                with: .linearGradient(
                    gradient,
                    startPoint: CGPoint(x: rect.minX, y: 0),
                    endPoint: CGPoint(x: rect.maxX, y: 0)
                )
            )
        }
        .drawingGroup()
    }

    // MARK: - Palette

    /// A wide, looping, bright multi-stop palette. Always saturated so glyphs
    /// never blend into the near-black background on any frame. The phase wraps
    /// through the stops; first and last hue match for a seamless cycle.
    private func flowColor(at rawPhase: Double) -> Color {
        let stops = Self.paletteStops
        let count = stops.count
        let safe = rawPhase.isFinite ? rawPhase : 0
        let wrapped = safe - floor(safe) // 0..<1
        let scaled = wrapped * Double(count - 1)
        let lowerIndex = Int(floor(scaled))
        let upperIndex = min(lowerIndex + 1, count - 1)
        let t = scaled - Double(lowerIndex)

        let lower = stops[lowerIndex]
        let upper = stops[upperIndex]
        return lerp(lower, upper, CGFloat(t))
    }

    private func lerp(_ a: RGB, _ b: RGB, _ t: CGFloat) -> Color {
        Color(
            red: Double(a.r + (b.r - a.r) * t),
            green: Double(a.g + (b.g - a.g) * t),
            blue: Double(a.b + (b.b - a.b) * t)
        )
    }

    // MARK: - Phase & sizing

    /// Maps wall-clock time to a continuous flow phase, biased by any drag.
    /// Targets a calm, liquid pace; the sine inside the Canvas keeps the loop seamless.
    private func flowPhase(at date: Date) -> Double {
        let t = date.timeIntervalSinceReferenceDate
        let speed = 0.95 // radians per second of base scroll
        return (t * speed) + Double(dragBias)
    }

    private func glyphFontSize(for size: CGSize) -> CGFloat {
        let basis = min(size.width, size.height)
        // Scale to fit a short heavy word in both a ~120pt tile and a large area.
        return Swift.max(18, basis * 0.42)
    }

    // MARK: - Optional non-gating interaction

    private func flowDrag(in size: CGSize) -> some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                let dx = value.translation.width / Swift.max(size.width, 1)
                let dy = value.translation.height / Swift.max(size.height, 1)
                withAnimation(.interactiveSpring(response: 0.35, dampingFraction: 0.8)) {
                    dragBias = CGFloat(dx) * 3.0
                    directionBias = CGFloat(dy) * 2.2
                }
            }
            .onEnded { _ in
                withAnimation(.spring(response: 1.2, dampingFraction: 0.9)) {
                    dragBias = 0
                    directionBias = 0
                }
            }
    }

    // MARK: - Constants

    private static let word = "FLOW"

    struct RGB { let r: CGFloat; let g: CGFloat; let b: CGFloat }

    /// Bright, saturated liquid palette. Index 0 == last index for a seamless wrap.
    private static let paletteStops: [RGB] = [
        RGB(r: 0.31, g: 0.78, b: 0.98), // cyan
        RGB(r: 0.45, g: 0.55, b: 0.99), // periwinkle
        RGB(r: 0.74, g: 0.45, b: 0.98), // violet
        RGB(r: 0.99, g: 0.43, b: 0.74), // pink
        RGB(r: 0.99, g: 0.62, b: 0.40), // coral
        RGB(r: 0.98, g: 0.86, b: 0.40), // gold
        RGB(r: 0.42, g: 0.93, b: 0.74), // mint
        RGB(r: 0.31, g: 0.78, b: 0.98)  // cyan (== first, seamless)
    ]
}
"""###,
        "tx-handwriting": ###"""
import SwiftUI

// MARK: - Handwriting Stroke
// A script headline draws itself stroke by stroke as if written by an invisible
// pen: a trimmed Path reveal with a small ink-nib dot that leads the line and
// lifts off between letters. Both demo and interactive modes are the same
// self-driving draw-on loop (interactiveSpec: "auto — same as previewLoop"),
// so everything is driven from a single TimelineView(.animation) progress value
// to keep the stroke reveal and the nib position perfectly locked.

public struct HandwritingView: View {
    public var demo: Bool = false

    public init(demo: Bool = false) {
        self.demo = demo
    }

    public var body: some View {
        GeometryReader { geo in
            content(in: geo.size)
                .frame(width: geo.size.width, height: geo.size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    @ViewBuilder
    private func content(in size: CGSize) -> some View {
        // ~3.4s loop: draw, brief hold at full, gentle fade of the bright ink,
        // then restart. The ghost guideline is always visible so no frame is
        // ever blank.
        let period: Double = 3.4
        ZStack {
            backdrop(in: size)
            TimelineView(.animation) { timeline in
                let t: Double = timeline.date.timeIntervalSinceReferenceDate
                let loop: Double = t.truncatingRemainder(dividingBy: period) / period
                let progress: CGFloat = drawProgress(for: loop)
                let inkOpacity: Double = inkFade(for: loop)
                HandwritingView_HandwritingCanvas(
                    progress: progress,
                    inkOpacity: inkOpacity,
                    canvasSize: size
                )
            }
        }
    }

    // MARK: Static backdrop

    private func backdrop(in size: CGSize) -> some View {
        let dim: CGFloat = min(size.width, size.height)
        return ZStack {
            LinearGradient(
                colors: [
                    Color(red: 0.05, green: 0.06, blue: 0.10),
                    Color(red: 0.02, green: 0.02, blue: 0.05)
                ],
                startPoint: .topLeading,
                endPoint: .bottomTrailing
            )
            // faint ruled baseline so the script reads as written on paper
            HandwritingView_RuledLine()
                .stroke(
                    Color(red: 1.0, green: 1.0, blue: 1.0).opacity(0.05),
                    style: StrokeStyle(lineWidth: max(0.6, dim * 0.006))
                )
        }
    }

    // MARK: Progress shaping

    // Maps the raw 0..1 loop into a draw curve that:
    //  - eases the pen across the page (ease-in-out),
    //  - holds at full for a short beat,
    //  - never returns a degenerate 0 (clamped to a small floor).
    private func drawProgress(for loop: Double) -> CGFloat {
        let drawPortion: Double = 0.78   // fraction of the loop spent drawing
        if loop >= drawPortion {
            return 1.0                   // hold + fade phase: stay fully drawn
        }
        let x: Double = loop / drawPortion
        let eased: Double = x * x * (3.0 - 2.0 * x) // smoothstep
        return CGFloat(max(0.02, eased))
    }

    // The bright ink layer gently fades out at the very end of the loop, so the
    // restart is a soft dissolve rather than a hard blank cut.
    private func inkFade(for loop: Double) -> Double {
        let fadeStart: Double = 0.9
        if loop < fadeStart { return 1.0 }
        let x: Double = (loop - fadeStart) / (1.0 - fadeStart)
        return max(0.0, 1.0 - x)
    }
}

// MARK: - Handwriting canvas

private struct HandwritingView_HandwritingCanvas: View {
    let progress: CGFloat
    let inkOpacity: Double
    let canvasSize: CGSize

    var body: some View {
        let dim: CGFloat = min(canvasSize.width, canvasSize.height)
        let lineWidth: CGFloat = max(2.0, dim * 0.022)
        let path: Path = HandwritingView_ScriptSignature.path(in: canvasSize)
        let nib: CGPoint = nibPoint(in: path)

        ZStack {
            ghostLayer(path: path, lineWidth: lineWidth)
            inkLayer(path: path, lineWidth: lineWidth)
            nibDot(at: nib, lineWidth: lineWidth)
        }
        .frame(width: canvasSize.width, height: canvasSize.height)
    }

    // MARK: Layers

    // Always-visible faint full stroke: the guideline the pen "follows".
    private func ghostLayer(path: Path, lineWidth: CGFloat) -> some View {
        path.stroke(
            Color(red: 0.55, green: 0.62, blue: 0.85).opacity(0.14),
            style: StrokeStyle(lineWidth: lineWidth, lineCap: .round, lineJoin: .round)
        )
    }

    // The bright drawn-so-far ink, with a soft glow.
    private func inkLayer(path: Path, lineWidth: CGFloat) -> some View {
        let ink: Color = Color(red: 0.75, green: 0.88, blue: 1.0)
        return path
            .trimmedPath(from: 0, to: progress)
            .stroke(
                ink,
                style: StrokeStyle(lineWidth: lineWidth, lineCap: .round, lineJoin: .round)
            )
            .shadow(color: ink.opacity(0.55), radius: lineWidth * 0.8)
            .opacity(inkOpacity)
    }

    // The traveling ink-nib dot at the current tip of the stroke.
    private func nibDot(at point: CGPoint, lineWidth: CGFloat) -> some View {
        let r: CGFloat = lineWidth * 0.9
        let core: Color = Color(red: 0.95, green: 0.98, blue: 1.0)
        let halo: Color = Color(red: 0.65, green: 0.82, blue: 1.0)
        return ZStack {
            Circle()
                .fill(halo.opacity(0.45))
                .frame(width: r * 2.6, height: r * 2.6)
                .blur(radius: r * 0.6)
            Circle()
                .fill(core)
                .frame(width: r * 1.4, height: r * 1.4)
                .shadow(color: halo.opacity(0.8), radius: r)
        }
        .position(point)
        .opacity(inkOpacity)
    }

    // MARK: Nib position

    // The tip of the drawn stroke. trimmedPath(...).currentPoint is nil at
    // progress ≈ 0 and across subpath "pen lifts", so fall back to a real
    // on-path point (the path's first move) to keep the nib on screen on
    // every frame rather than the path's end.
    private func nibPoint(in path: Path) -> CGPoint {
        if let p = path.trimmedPath(from: 0, to: progress).currentPoint {
            return p
        }
        if let first = path.boundingRect.isNull ? nil : Optional(path.boundingRect.origin) {
            return first
        }
        return path.cgPath.currentPoint
    }
}

// MARK: - Ruled baseline (decorative paper line)

private struct HandwritingView_RuledLine: Shape {
    func path(in rect: CGRect) -> Path {
        var p = Path()
        let y: CGFloat = rect.midY + rect.height * 0.20
        p.move(to: CGPoint(x: rect.minX + rect.width * 0.06, y: y))
        p.addLine(to: CGPoint(x: rect.maxX - rect.width * 0.06, y: y))
        return p
    }
}

// MARK: - Script signature path

// A stylized cursive "hello" flourish built from normalized 0..1 control points
// scaled to the canvas. Multiple subpaths (move(to:) between letters) create the
// natural "lifts off at each letter's end" — the nib jumps between strokes.
private enum HandwritingView_ScriptSignature {

    // Control points are expressed in a normalized space and mapped into a
    // centered, aspect-aware box so the script stays legible in a 120pt tile
    // and a large detail area alike.
    static func path(in size: CGSize) -> Path {
        let dim: CGFloat = min(size.width, size.height)
        // A wide writing box centered in the available space.
        let boxW: CGFloat = min(size.width * 0.84, dim * 2.6)
        let boxH: CGFloat = boxW * 0.42
        let originX: CGFloat = (size.width - boxW) / 2.0
        let originY: CGFloat = (size.height - boxH) / 2.0

        func pt(_ nx: CGFloat, _ ny: CGFloat) -> CGPoint {
            CGPoint(x: originX + nx * boxW, y: originY + ny * boxH)
        }

        var path = Path()
        appendH(to: &path, pt: pt)
        appendE(to: &path, pt: pt)
        appendDoubleL(to: &path, pt: pt)
        appendO(to: &path, pt: pt)
        appendFlourish(to: &path, pt: pt)
        return path
    }

    private typealias Mapper = (CGFloat, CGFloat) -> CGPoint

    // h: a tall ascender looping down into a hump.
    private static func appendH(to path: inout Path, pt: Mapper) {
        path.move(to: pt(0.04, 0.30))
        path.addCurve(
            to: pt(0.08, 0.80),
            control1: pt(0.10, 0.02),
            control2: pt(0.10, 0.55)
        )
        path.addCurve(
            to: pt(0.16, 0.50),
            control1: pt(0.07, 0.95),
            control2: pt(0.12, 0.40)
        )
        path.addCurve(
            to: pt(0.20, 0.80),
            control1: pt(0.20, 0.58),
            control2: pt(0.21, 0.95)
        )
    }

    // e: a small closed loop.
    private static func appendE(to path: inout Path, pt: Mapper) {
        path.move(to: pt(0.23, 0.62))
        path.addCurve(
            to: pt(0.30, 0.55),
            control1: pt(0.25, 0.48),
            control2: pt(0.32, 0.46)
        )
        path.addCurve(
            to: pt(0.27, 0.82),
            control1: pt(0.29, 0.66),
            control2: pt(0.22, 0.78)
        )
        path.addQuadCurve(
            to: pt(0.34, 0.74),
            control: pt(0.32, 0.86)
        )
    }

    // ll: two ascender loops.
    private static func appendDoubleL(to path: inout Path, pt: Mapper) {
        path.move(to: pt(0.37, 0.80))
        path.addCurve(
            to: pt(0.40, 0.18),
            control1: pt(0.33, 0.45),
            control2: pt(0.36, 0.20)
        )
        path.addCurve(
            to: pt(0.42, 0.80),
            control1: pt(0.44, 0.16),
            control2: pt(0.41, 0.55)
        )

        path.move(to: pt(0.45, 0.80))
        path.addCurve(
            to: pt(0.48, 0.18),
            control1: pt(0.41, 0.45),
            control2: pt(0.44, 0.20)
        )
        path.addCurve(
            to: pt(0.50, 0.80),
            control1: pt(0.52, 0.16),
            control2: pt(0.49, 0.55)
        )
    }

    // o: a round closed loop.
    private static func appendO(to path: inout Path, pt: Mapper) {
        path.move(to: pt(0.55, 0.60))
        path.addCurve(
            to: pt(0.62, 0.62),
            control1: pt(0.55, 0.46),
            control2: pt(0.63, 0.46)
        )
        path.addCurve(
            to: pt(0.56, 0.66),
            control1: pt(0.61, 0.80),
            control2: pt(0.54, 0.80)
        )
        path.addQuadCurve(
            to: pt(0.60, 0.58),
            control: pt(0.56, 0.55)
        )
    }

    // Trailing underline flourish — the signature swoosh.
    private static func appendFlourish(to path: inout Path, pt: Mapper) {
        path.move(to: pt(0.60, 0.58))
        path.addCurve(
            to: pt(0.92, 0.74),
            control1: pt(0.74, 0.40),
            control2: pt(0.82, 0.92)
        )
        path.addQuadCurve(
            to: pt(0.66, 0.88),
            control: pt(0.99, 0.62)
        )
    }
}
"""###,
        "tx-liquid-fill": ###"""
import SwiftUI

// MARK: - Liquid Fill Letters
//
// Each glyph is masked by a rising liquid level with a wobbling sine surface
// and a couple of buoyant bubbles, filling from an empty outline to full
// color, with a subtle meniscus highlight at the waterline.
//
// The load-bearing masking is `.mask { Text }`, which clips identically on
// iOS 17 and 18, so no version split touches the core effect. The "empty"
// glyph state is a dim translucent fill with a thin lighter overlay so the
// letters always read as hollow vessels waiting to be filled.

struct LiquidFillView: View {
    var demo: Bool = false

    private let word: String = "LIQUID"

    var body: some View {
        GeometryReader { geo in
            let size: CGSize = geo.size
            let fs: CGFloat = fontSize(for: size)

            TimelineView(.animation) { timeline in
                let t: Double = timeline.date.timeIntervalSinceReferenceDate
                let level: CGFloat = fillLevel(at: t)

                ZStack {
                    // Empty letters — always legible so the tile is never blank.
                    emptyGlyphs(fontSize: fs)

                    // Rising liquid, clipped to the exact glyph shapes.
                    liquidLayer(level: level, time: t)
                        .mask { glyphText(fontSize: fs) }
                }
                .frame(width: size.width, height: size.height)
            }
            .frame(maxWidth: .infinity, maxHeight: .infinity)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // MARK: Fill progression (fill up, hold, drain — no hard reset flash)

    private func fillLevel(at time: Double) -> CGFloat {
        let period: Double = 3.4
        let phase: Double = time.truncatingRemainder(dividingBy: period) / period
        let raw: Double
        if phase < 0.5 {
            raw = eased(phase / 0.5)           // 0 -> 1 fill
        } else if phase < 0.62 {
            raw = 1.0                           // brief full hold
        } else {
            raw = 1.0 - eased((phase - 0.62) / 0.38)  // 1 -> 0 drain
        }
        // Never fully empty: keep a sliver of liquid so motion always reads.
        return CGFloat(0.06 + raw * 0.94)
    }

    private func eased(_ x: Double) -> Double {
        let c: Double = min(max(x, 0), 1)
        return c * c * (3 - 2 * c)             // smoothstep
    }

    // MARK: Glyph layers

    private func glyphText(fontSize fs: CGFloat) -> some View {
        Text(word)
            .font(.system(size: fs, weight: .heavy, design: .rounded))
            .tracking(fs * 0.04)
            .lineLimit(1)
            .minimumScaleFactor(0.3)
            .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    private func emptyGlyphs(fontSize fs: CGFloat) -> some View {
        ZStack {
            // Dim translucent body — the "empty" vessel.
            glyphText(fontSize: fs)
                .foregroundStyle(emptyFillColor)
            // Thin lighter edge to suggest a hollow outline.
            glyphText(fontSize: fs)
                .foregroundStyle(outlineColor)
                .blendMode(.screen)
                .opacity(0.5)
        }
    }

    // MARK: Liquid

    private func liquidLayer(level: CGFloat, time: Double) -> some View {
        Canvas { ctx, canvasSize in
            let band: ClosedRange<CGFloat> = glyphBand(in: canvasSize)
            let waterY: CGFloat = band.upperBound - level * (band.upperBound - band.lowerBound)

            drawBody(ctx: ctx, size: canvasSize, waterY: waterY, time: time)
            drawBubbles(ctx: ctx, size: canvasSize, waterY: waterY, time: time)
            drawMeniscus(ctx: ctx, size: canvasSize, waterY: waterY, time: time)
        }
    }

    // The vertical band the glyphs roughly occupy (centered cap-height region).
    private func glyphBand(in size: CGSize) -> ClosedRange<CGFloat> {
        let fs: CGFloat = fontSize(for: size)
        let capHeight: CGFloat = fs * 0.72
        let center: CGFloat = size.height / 2
        let top: CGFloat = center - capHeight / 2
        let bottom: CGFloat = center + capHeight / 2
        return top...bottom
    }

    // MARK: Surface geometry

    private func surfaceY(_ x: CGFloat, size: CGSize, waterY: CGFloat, time: Double) -> CGFloat {
        let amp: CGFloat = max(size.height * 0.012, 1.5)
        let k1: CGFloat = 2.4 * .pi / max(size.width, 1)
        let k2: CGFloat = 5.1 * .pi / max(size.width, 1)
        let p1: CGFloat = CGFloat(time * 1.6)
        let p2: CGFloat = CGFloat(time * 2.7)
        let wobble: CGFloat = sin(x * k1 + p1) * amp + sin(x * k2 + p2) * (amp * 0.45)
        return waterY + wobble
    }

    private func surfacePath(size: CGSize, waterY: CGFloat, time: Double) -> Path {
        var path = Path()
        let step: CGFloat = max(size.width / 48, 2)
        path.move(to: CGPoint(x: 0, y: size.height))
        path.addLine(to: CGPoint(x: 0, y: surfaceY(0, size: size, waterY: waterY, time: time)))
        var x: CGFloat = step
        while x <= size.width {
            path.addLine(to: CGPoint(x: x, y: surfaceY(x, size: size, waterY: waterY, time: time)))
            x += step
        }
        path.addLine(to: CGPoint(x: size.width, y: size.height))
        path.closeSubpath()
        return path
    }

    private func drawBody(ctx: GraphicsContext, size: CGSize, waterY: CGFloat, time: Double) {
        let body: Path = surfacePath(size: size, waterY: waterY, time: time)
        let gradient = Gradient(stops: [
            .init(color: liquidTop, location: 0.0),
            .init(color: liquidMid, location: 0.45),
            .init(color: liquidDeep, location: 1.0)
        ])
        ctx.fill(
            body,
            with: .linearGradient(
                gradient,
                startPoint: CGPoint(x: size.width / 2, y: waterY),
                endPoint: CGPoint(x: size.width / 2, y: size.height)
            )
        )
    }

    private func drawMeniscus(ctx: GraphicsContext, size: CGSize, waterY: CGFloat, time: Double) {
        var line = Path()
        let step: CGFloat = max(size.width / 48, 2)
        line.move(to: CGPoint(x: 0, y: surfaceY(0, size: size, waterY: waterY, time: time)))
        var x: CGFloat = step
        while x <= size.width {
            line.addLine(to: CGPoint(x: x, y: surfaceY(x, size: size, waterY: waterY, time: time)))
            x += step
        }
        ctx.stroke(
            line,
            with: .color(meniscusColor),
            style: StrokeStyle(lineWidth: max(size.height * 0.01, 1.4), lineCap: .round)
        )
    }

    private func drawBubbles(ctx: GraphicsContext, size: CGSize, waterY: CGFloat, time: Double) {
        for seed in bubbleSeeds {
            let cycle: Double = time / seed.duration + seed.offset
            let prog: Double = cycle.truncatingRemainder(dividingBy: 1.0)

            // Bubble rises from near the bottom up toward the waterline.
            let bottom: CGFloat = size.height * 0.96
            let target: CGFloat = waterY + size.height * 0.04
            let by: CGFloat = bottom - CGFloat(prog) * (bottom - target)

            // Only show bubbles that are submerged (below the wobbling surface).
            guard by > waterY else { continue }

            let sway: CGFloat = sin(CGFloat(time) * seed.swaySpeed + seed.phase) * size.width * 0.012
            let bx: CGFloat = size.width * seed.x + sway
            let r: CGFloat = size.height * seed.radius
            let rect = CGRect(x: bx - r, y: by - r, width: r * 2, height: r * 2)

            // Fade in near birth, fade out as it nears the surface.
            let fade: Double = max(min(prog * 5, 1) * min((1 - prog) * 4, 1), 0)
            ctx.fill(Path(ellipseIn: rect),
                     with: .color(bubbleColor.opacity(0.55 * fade)))

            // Tiny specular dot on each bubble.
            let hr: CGFloat = r * 0.4
            let hrect = CGRect(x: bx - r * 0.3 - hr / 2, y: by - r * 0.3 - hr / 2,
                               width: hr, height: hr)
            ctx.fill(Path(ellipseIn: hrect),
                     with: .color(Color(red: 1, green: 1, blue: 1).opacity(0.5 * fade)))
        }
    }

    // MARK: Layout

    private func fontSize(for size: CGSize) -> CGFloat {
        let byHeight: CGFloat = size.height * 0.5
        let byWidth: CGFloat = size.width / CGFloat(max(word.count, 1)) * 1.5
        return min(byHeight, byWidth)
    }

    // MARK: Palette (literals only — no design-system dependency)

    private var liquidTop: Color { Color(red: 0.38, green: 0.82, blue: 0.98) }
    private var liquidMid: Color { Color(red: 0.20, green: 0.56, blue: 0.95) }
    private var liquidDeep: Color { Color(red: 0.10, green: 0.30, blue: 0.78) }
    private var meniscusColor: Color { Color(red: 0.80, green: 0.95, blue: 1.0).opacity(0.9) }
    private var bubbleColor: Color { Color(red: 0.85, green: 0.96, blue: 1.0) }
    private var outlineColor: Color { Color(red: 0.42, green: 0.55, blue: 0.72) }
    private var emptyFillColor: Color { Color(red: 0.30, green: 0.42, blue: 0.62).opacity(0.40) }

    private var bubbleSeeds: [LiquidFillView_BubbleSeed] {
        [
            LiquidFillView_BubbleSeed(x: 0.22, radius: 0.045, duration: 2.6, offset: 0.0,
                       swaySpeed: 2.1, phase: 0.0),
            LiquidFillView_BubbleSeed(x: 0.55, radius: 0.032, duration: 3.3, offset: 0.45,
                       swaySpeed: 2.7, phase: 1.3),
            LiquidFillView_BubbleSeed(x: 0.80, radius: 0.052, duration: 2.9, offset: 0.78,
                       swaySpeed: 1.8, phase: 2.6)
        ]
    }
}

// MARK: - Bubble seed

private struct LiquidFillView_BubbleSeed {
    var x: CGFloat
    var radius: CGFloat
    var duration: Double
    var offset: Double
    var swaySpeed: CGFloat
    var phase: CGFloat
}
"""###,
        "tx-magnetic-poetry": ###"""
import SwiftUI

// MARK: - Magnetic Poetry
//
// Word tiles laid out like fridge magnets on a metal door. A drag flings any
// tile while its neighbors physically nudge aside on a distance-falloff shove,
// then everything springs back to its baseline slot. In demo mode a virtual
// "finger" auto-flings one tile after another on a continuous loop so the tile
// looks alive with no touch.
//
// Both modes feed the SAME pure layout function (`tileOffset`) so the neighbor
// coupling is identical whether driven by a real drag or the demo timeline.

public struct MagneticPoetryView: View {
    var demo: Bool = false

    // The little poem. Capped well under the ~12-tile budget.
    private let words: [String] = [
        "magnet", "words", "drift", "on",
        "cold", "steel", "quiet", "hum", "shove"
    ]

    // Interactive drag state.
    @State private var draggedIndex: Int? = nil
    @State private var dragTranslation: CGSize = .zero
    @State private var releasing: Bool = false
    @State private var settleTick: Int = 0

    public init(demo: Bool = false) {
        self.demo = demo
    }

    public var body: some View {
        GeometryReader { geo in
            let layout = makeLayout(in: geo.size)
            ZStack {
                background
                if demo {
                    demoBoard(layout: layout, size: geo.size)
                } else {
                    interactiveBoard(layout: layout, size: geo.size)
                }
            }
            .frame(width: geo.size.width, height: geo.size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .clipped()
    }

    // MARK: Background — brushed metal door.

    private var background: some View {
        ZStack {
            LinearGradient(
                colors: [
                    Color(red: 0.10, green: 0.11, blue: 0.13),
                    Color(red: 0.06, green: 0.07, blue: 0.09)
                ],
                startPoint: .topLeading,
                endPoint: .bottomTrailing
            )
            LinearGradient(
                colors: [
                    Color.white.opacity(0.05),
                    Color.clear,
                    Color.white.opacity(0.03)
                ],
                startPoint: .leading,
                endPoint: .trailing
            )
        }
    }

    // MARK: Demo board — virtual finger auto-flings tiles on a loop.

    private func demoBoard(layout: TileLayout, size: CGSize) -> some View {
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            let drive = demoDrive(time: t, count: words.count)
            board(
                layout: layout,
                size: size,
                activeIndex: drive.activeIndex,
                source: drive.translation,
                liftAmount: drive.lift
            )
        }
    }

    // MARK: Interactive board — real drag with neighbor shove.

    private func interactiveBoard(layout: TileLayout, size: CGSize) -> some View {
        board(
            layout: layout,
            size: size,
            activeIndex: draggedIndex,
            source: dragTranslation,
            liftAmount: draggedIndex == nil ? 0 : (releasing ? 0 : 1)
        )
    }

    // MARK: Shared board renderer.

    private func board(
        layout: TileLayout,
        size: CGSize,
        activeIndex: Int?,
        source: CGSize,
        liftAmount: CGFloat
    ) -> some View {
        ZStack {
            ForEach(words.indices, id: \.self) { index in
                tileView(
                    index: index,
                    layout: layout,
                    activeIndex: activeIndex,
                    source: source,
                    liftAmount: liftAmount
                )
            }
        }
        .sensoryFeedbackCompat(trigger: settleTick)
    }

    // MARK: One positioned tile (factored to keep type-checking cheap).

    @ViewBuilder
    private func tileView(
        index: Int,
        layout: TileLayout,
        activeIndex: Int?,
        source: CGSize,
        liftAmount: CGFloat
    ) -> some View {
        let slot = layout.slots[index]
        let shove = tileOffset(
            index: index,
            activeIndex: activeIndex,
            source: source,
            layout: layout
        )
        let isActive = (index == activeIndex)
        tile(
            word: words[index],
            fontSize: layout.fontSize,
            isActive: isActive,
            lift: isActive ? liftAmount : 0
        )
        .position(x: slot.x, y: slot.y)
        .offset(shove)
        .zIndex(isActive ? 100 : Double(index))
        .gesture(dragGesture(for: index), including: demo ? .none : .all)
    }

    // MARK: A single magnet tile.

    private func tile(word: String, fontSize: CGFloat, isActive: Bool, lift: CGFloat) -> some View {
        let safeLift = max(0, lift)
        return Text(word)
            .font(.system(size: fontSize, weight: .heavy, design: .serif))
            .minimumScaleFactor(0.5)
            .lineLimit(1)
            .foregroundStyle(
                LinearGradient(
                    colors: [
                        Color(red: 0.16, green: 0.17, blue: 0.20),
                        Color(red: 0.05, green: 0.05, blue: 0.07)
                    ],
                    startPoint: .top,
                    endPoint: .bottom
                )
            )
            .padding(.horizontal, fontSize * 0.5)
            .padding(.vertical, fontSize * 0.32)
            .background(tileBackground(fontSize: fontSize))
            .scaleEffect(1 + safeLift * 0.06)
            .shadow(
                color: Color.black.opacity(0.35 + safeLift * 0.25),
                radius: 3 + safeLift * 7,
                x: 0,
                y: 2 + safeLift * 5
            )
    }

    private func tileBackground(fontSize: CGFloat) -> some View {
        let radius = fontSize * 0.28
        return ZStack {
            RoundedRectangle(cornerRadius: radius, style: .continuous)
                .fill(
                    LinearGradient(
                        colors: [
                            Color(red: 0.96, green: 0.95, blue: 0.92),
                            Color(red: 0.86, green: 0.85, blue: 0.82)
                        ],
                        startPoint: .top,
                        endPoint: .bottom
                    )
                )
            RoundedRectangle(cornerRadius: radius, style: .continuous)
                .strokeBorder(Color.white.opacity(0.7), lineWidth: 0.75)
        }
    }

    // MARK: - Pure physics: one function, two drivers.

    /// Returns the live offset for a tile given which tile is "active" (grabbed
    /// or virtually flung) and that active tile's current translation. The
    /// active tile follows `source`; every other tile is shoved away from the
    /// active tile's *displaced* position with a smooth distance falloff.
    private func tileOffset(
        index: Int,
        activeIndex: Int?,
        source: CGSize,
        layout: TileLayout
    ) -> CGSize {
        guard let active = activeIndex else { return .zero }
        if index == active { return source }

        let slot = layout.slots[index]
        let activeSlot = layout.slots[active]
        // Active tile's live centre.
        let activeNow = CGPoint(x: activeSlot.x + source.width,
                                y: activeSlot.y + source.height)

        let dx = slot.x - activeNow.x
        let dy = slot.y - activeNow.y
        let dist = max(sqrt(dx * dx + dy * dy), 0.0001)

        // Smooth falloff: full strength when overlapping, zero past `reach`.
        let reach = layout.reach
        let falloff = max(0, 1 - dist / reach)
        let strength = falloff * falloff  // ease so distant tiles barely move
        let push = layout.maxShove * strength

        let nx = dx / dist
        let ny = dy / dist
        return CGSize(width: nx * push, height: ny * push)
    }

    // MARK: - Demo drive: virtual finger.

    struct DemoDrive {
        var activeIndex: Int
        var translation: CGSize
        var lift: CGFloat
    }

    /// Cycles one tile at a time: fling out, then a damped spring back to rest,
    /// then the next tile. One fling-and-settle cycle lasts ~3.2s.
    private func demoDrive(time: Double, count: Int) -> DemoDrive {
        let safeCount = max(count, 1)
        let cycle: Double = 3.2
        let phase = time.truncatingRemainder(dividingBy: cycle) / cycle  // 0..1
        let cycleNumber = Int(floor(time / cycle))
        let active = ((cycleNumber % safeCount) + safeCount) % safeCount

        // A wandering fling direction so each cycle differs.
        let dirAngle = Double(cycleNumber) * 2.39996  // golden-ish angle
        let dirX = CGFloat(cos(dirAngle))
        let dirY = CGFloat(sin(dirAngle))

        // Magnitude: rises quickly (fling out) then a damped spring recoil to 0.
        let magnitude = flingMagnitude(phase: phase)
        let amp = demoReach()
        let translation = CGSize(width: dirX * amp * magnitude,
                                 height: dirY * amp * magnitude)
        let lift = CGFloat(min(1, max(0, magnitude) * 1.4))
        return DemoDrive(activeIndex: active, translation: translation, lift: lift)
    }

    /// Normalised fling profile over the cycle phase 0...1.
    /// Fast rise to a peak, then a decaying oscillation back to rest.
    private func flingMagnitude(phase p: Double) -> CGFloat {
        if p < 0.18 {
            // Snappy pull-out.
            let x = p / 0.18
            return CGFloat(sin(x * Double.pi / 2))
        } else {
            // Damped recoil: e^-kt * cos back to rest.
            let x = (p - 0.18) / 0.82            // 0..1
            let decay = exp(-3.4 * x)
            let wobble = cos(x * Double.pi * 3.0)
            let value = decay * wobble
            return CGFloat(value)
        }
    }

    private func demoReach() -> CGFloat { 1.0 }  // scaled inside demoDrive via amp

    // MARK: - Drag gesture (interactive only).

    private func dragGesture(for index: Int) -> some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                releasing = false
                if draggedIndex != index {
                    draggedIndex = index
                }
                dragTranslation = value.translation
            }
            .onEnded { _ in
                // Keep `draggedIndex` set through the spring so the active tile
                // AND its shoved neighbours spring back together; only release
                // control once the recoil completes. Without this the offset
                // would snap to .zero the instant activeIndex went nil.
                settleTick &+= 1
                withAnimation(.spring(response: 0.5, dampingFraction: 0.45)) {
                    releasing = true
                    dragTranslation = .zero
                } completion: {
                    // Only clear if no new tile was grabbed mid-recoil; a fresh
                    // `onChanged` sets `releasing = false`, so this guard avoids
                    // clobbering an in-progress second drag.
                    if releasing {
                        draggedIndex = nil
                        releasing = false
                    }
                }
            }
    }

    // MARK: - Layout: slot positions + physics scale, all from geometry.

    struct TileLayout {
        var slots: [CGPoint]
        var fontSize: CGFloat
        var maxShove: CGFloat
        var reach: CGFloat
    }

    /// A simple flowing wrap: tiles fill left-to-right, wrapping to new rows,
    /// centred vertically. Everything scales off `size` so it reads in a 120pt
    /// tile and a large detail area alike.
    private func makeLayout(in size: CGSize) -> TileLayout {
        let count = words.count
        let safeWidth = max(size.width, 1)
        let safeHeight = max(size.height, 1)
        let minSide = min(safeWidth, safeHeight)

        // Pick a row count that keeps tiles legible across sizes.
        let rows = max(rowCount(for: count, size: size), 1)
        let perRow = max(Int(ceil(Double(count) / Double(rows))), 1)

        let fontSize = max(8, min(safeHeight / CGFloat(rows) * 0.34,
                                  safeWidth / CGFloat(perRow) * 0.30))

        let rowHeight = safeHeight / CGFloat(rows + 1)
        var slots: [CGPoint] = []
        slots.reserveCapacity(count)

        for r in 0..<rows {
            let start = r * perRow
            let end = min(start + perRow, count)
            if start >= end { continue }
            let n = end - start
            let colWidth = safeWidth / CGFloat(n + 1)
            let y = rowHeight * CGFloat(r + 1)
                + (safeHeight - rowHeight * CGFloat(rows + 1)) / 2
                + rowHeight / 2
            for c in 0..<n {
                let x = colWidth * CGFloat(c + 1)
                slots.append(CGPoint(x: x, y: y))
            }
        }
        // Safety: ensure we always have a slot per word.
        while slots.count < count {
            slots.append(CGPoint(x: safeWidth / 2, y: safeHeight / 2))
        }

        let maxShove = minSide * 0.16
        let reach = max(minSide * 0.55, 1)
        return TileLayout(slots: slots, fontSize: fontSize, maxShove: maxShove, reach: reach)
    }

    private func rowCount(for count: Int, size: CGSize) -> Int {
        let aspect = size.width / max(size.height, 1)
        if aspect > 1.6 { return 2 }        // wide detail area
        if size.height < 200 { return 3 }   // small grid tile
        return 4
    }
}

// MARK: - sensoryFeedback compatibility shim.

private extension View {
    @ViewBuilder
    func sensoryFeedbackCompat(trigger: Int) -> some View {
        if #available(iOS 17.0, *) {
            self.sensoryFeedback(.impact(flexibility: .soft), trigger: trigger)
        } else {
            self
        }
    }
}
"""###,
        "tx-marquee-3d": ###"""
import SwiftUI

/// 3D Cylinder Marquee
///
/// A scrolling ticker of words wraps around an invisible vertical-axis drum.
/// Words curl away with perspective at the left/right rim, shrinking, fading
/// and blurring as they rotate off one edge and arrive on the other.
///
/// - `demo == true`  : a self-driving constant-rate spin (no touch needed).
/// - `demo == false` : a real `DragGesture` scrubs/flicks the drum; on release
///                     the spin coasts to a stop via closed-form friction decay.
///
/// Curl direction note: the curl/perspective sign is governed by `perspective`
/// in `wordRotation(...)` together with the angle->degrees mapping. If the drum
/// reads inside-out on device, negate the degrees in `wordRotation` (single spot).
struct Marquee3dView: View {
    var demo: Bool = false

    // The ticker tokens. Kept short so they stay legible inside a ~120pt tile.
    private let words: [String] = [
        "INSPIRE", "CREATE", "DREAM", "BUILD",
        "DESIGN", "SHIP", "MAKE", "FLOW"
    ]

    // MARK: - Interactive drum state (only mutated in gesture callbacks)

    /// Phase committed from finished drags (radians).
    @State private var committedPhase: Double = 0
    /// Live phase contribution from the in-flight drag (radians).
    @State private var liveDragPhase: Double = 0
    /// Release velocity in radians/sec, seeded on `.onEnded`.
    @State private var releaseVelocity: Double = 0
    /// Timestamp of the last release; coast is measured from here.
    @State private var releaseDate: Date = .distantPast
    /// Whether a finger is currently down (pauses the coast).
    @State private var isDragging: Bool = false

    var body: some View {
        GeometryReader { geo in
            let content = TimelineView(.animation) { timeline in
                drum(in: geo.size, now: timeline.date)
            }
            .frame(maxWidth: .infinity, maxHeight: .infinity)
            .contentShape(Rectangle())
            .background(backdrop)
            .clipShape(RoundedRectangle(cornerRadius: geo.size.width * 0.06,
                                        style: .continuous))

            if demo {
                content
            } else {
                content.gesture(drumGesture(width: geo.size.width))
            }
        }
    }

    // MARK: - Backdrop

    private var backdrop: some View {
        // Deep neutral panel with a soft vertical light gradient so the drum
        // reads as recessed. Never fully black so the tile is always legible.
        LinearGradient(
            colors: [
                Color(red: 0.05, green: 0.06, blue: 0.10),
                Color(red: 0.02, green: 0.02, blue: 0.05)
            ],
            startPoint: .top,
            endPoint: .bottom
        )
    }

    // MARK: - The rotating drum

    private func drum(in size: CGSize, now: Date) -> some View {
        let phase = currentPhase(now: now)
        let radius = drumRadius(for: size)
        let fontSize = wordFontSize(for: size)
        let count = words.count

        return ZStack {
            // Faint center guide line so the band of the ticker reads as a slot.
            slotHighlight(size: size)

            ForEach(Array(words.enumerated()), id: \.offset) { index, word in
                let angle = wordAngle(index: index, count: count, phase: phase)
                wordTile(word: word,
                         angle: angle,
                         radius: radius,
                         fontSize: fontSize)
            }
        }
        .frame(width: size.width, height: size.height)
    }

    private func slotHighlight(size: CGSize) -> some View {
        RoundedRectangle(cornerRadius: size.height * 0.18, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        Color(red: 1, green: 1, blue: 1).opacity(0.06),
                        Color(red: 1, green: 1, blue: 1).opacity(0.0)
                    ],
                    startPoint: .top,
                    endPoint: .bottom
                )
            )
            .frame(width: size.width * 0.9, height: size.height * 0.42)
    }

    // MARK: - Single word tile

    @ViewBuilder
    private func wordTile(word: String,
                          angle: Double,
                          radius: CGFloat,
                          fontSize: CGFloat) -> some View {
        let depth = cos(angle)                 // +1 = front center, -1 = far back
        let xOffset = xPosition(angle: angle, radius: radius)
        let scale = wordScale(depth: depth)
        let opacity = wordOpacity(depth: depth)
        let blur = wordBlur(depth: depth, fontSize: fontSize)

        // Cull words on the far hemisphere: invisible AND behind, so they never
        // clutter the front. There is always >= 1 word near center at full
        // opacity, so the tile is never blank.
        if depth > -0.15 {
            Text(word)
                .font(.system(size: fontSize, weight: .heavy, design: .rounded))
                .lineLimit(1)
                .minimumScaleFactor(0.5)
                .foregroundStyle(wordFill(depth: depth))
                .fixedSize()
                .scaleEffect(scale)
                .rotation3DEffect(
                    wordRotation(angle: angle),
                    axis: (x: 0, y: 1, z: 0),
                    anchor: .center,
                    perspective: 0.55
                )
                .offset(x: xOffset)
                .blur(radius: blur)
                .opacity(opacity)
                .zIndex(depth)
        }
    }

    private func wordFill(depth: Double) -> LinearGradient {
        // Front words get a warm bright face; rim words desaturate toward steel.
        let frontness = max(0, depth)
        let r = 0.78 + 0.20 * frontness
        let g = 0.80 + 0.18 * frontness
        let b = 0.86 + 0.14 * frontness
        return LinearGradient(
            colors: [
                Color(red: min(r, 1), green: min(g, 1), blue: min(b, 1)),
                Color(red: 0.55 + 0.25 * frontness,
                      green: 0.58 + 0.25 * frontness,
                      blue: 0.70 + 0.20 * frontness)
            ],
            startPoint: .top,
            endPoint: .bottom
        )
    }

    // MARK: - Per-word math (small, type-annotated helpers)

    /// Base evenly-spaced angle for a word plus the running phase.
    private func wordAngle(index: Int, count: Int, phase: Double) -> Double {
        let base = Double(index) * (2 * .pi) / Double(count)
        return base + phase
    }

    /// Horizontal screen position from the angle on the drum.
    private func xPosition(angle: Double, radius: CGFloat) -> CGFloat {
        radius * CGFloat(sin(angle))
    }

    /// Front words are larger; rim words shrink toward the back.
    private func wordScale(depth: Double) -> CGFloat {
        let s: Double = 0.58 + 0.42 * ((depth + 1) / 2)
        return CGFloat(s)
    }

    /// Fade out toward and past the rim; clamp so center stays fully legible.
    private func wordOpacity(depth: Double) -> Double {
        let raw = (depth + 0.4) / 1.4   // ~0 at the rim, 1 at the front
        return min(1, max(0, raw))
    }

    /// Rim blur grows as words rotate edge-on. Scaled to the type size.
    private func wordBlur(depth: Double, fontSize: CGFloat) -> CGFloat {
        let amount = (1 - depth) / 2      // 0 at front, 1 at back
        let maxBlur = fontSize * 0.08
        return maxBlur * CGFloat(amount)
    }

    /// 3D y-axis rotation. Negate the degrees here to reverse the curl.
    private func wordRotation(angle: Double) -> Angle {
        .degrees(angle * 180 / .pi)
    }

    // MARK: - Layout sizing (relative to the geometry)

    private func drumRadius(for size: CGSize) -> CGFloat {
        size.width * 0.40
    }

    private func wordFontSize(for size: CGSize) -> CGFloat {
        // Scale to the smaller side so it fits both a 120pt tile and a big
        // detail area; cap so detail mode doesn't explode the type.
        let base = min(size.width, size.height)
        return min(base * 0.16, 40)
    }

    // MARK: - Phase composition

    /// Pure function of time: committed + live drag + coast. No state mutation.
    private func currentPhase(now: Date) -> Double {
        if demo {
            return autoPhase(now: now)
        }
        return committedPhase + liveDragPhase + coastPhase(now: now)
    }

    /// Self-driving constant-rate spin for the preview tile (~one lap / 4.5s).
    private func autoPhase(now: Date) -> Double {
        let speed: Double = (2 * .pi) / 4.5
        let t = now.timeIntervalSinceReferenceDate
        return t * speed
    }

    /// Closed-form exponential friction decay of the release flick.
    /// coast(t) = (v0 / k) * (1 - exp(-k * t)) - bounded, settles on its own.
    private func coastPhase(now: Date) -> Double {
        guard !isDragging, releaseVelocity != 0 else { return 0 }
        let friction: Double = 2.4
        let elapsed = now.timeIntervalSince(releaseDate)
        guard elapsed > 0 else { return 0 }
        return (releaseVelocity / friction) * (1 - exp(-friction * elapsed))
    }

    // MARK: - Interaction

    private func drumGesture(width: CGFloat) -> some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                if !isDragging {
                    // First frame of a new drag: fold any in-progress coast into
                    // the committed phase before killing it, so grabbing the drum
                    // mid-flick is continuous (no backward jump).
                    committedPhase += coastPhase(now: Date())
                    releaseDate = .distantPast
                }
                isDragging = true
                releaseVelocity = 0
                // Map horizontal drag distance to drum rotation.
                liveDragPhase = dragToPhase(translationX: value.translation.width,
                                            width: width)
            }
            .onEnded { value in
                // Fold the live drag into the committed phase.
                committedPhase += dragToPhase(translationX: value.translation.width,
                                              width: width)
                liveDragPhase = 0
                // Seed the coast from the release velocity (pts/s -> rad/s).
                releaseVelocity = velocityToPhaseRate(velocityX: value.velocity.width,
                                                      width: width)
                releaseDate = Date()
                isDragging = false
            }
    }

    /// A full drum width of horizontal travel ~ half a revolution.
    private func dragToPhase(translationX: CGFloat, width: CGFloat) -> Double {
        let span = max(width, 1)
        return Double(translationX / span) * .pi
    }

    private func velocityToPhaseRate(velocityX: CGFloat, width: CGFloat) -> Double {
        let span = max(width, 1)
        return Double(velocityX / span) * .pi
    }
}
"""###,
        "tx-neon-flicker": ###"""
import SwiftUI

// MARK: - Neon Sign Flicker
//
// A glowing neon-tube headline that buzzes to life with a realistic startup
// flicker. One stubborn letter stutters on and off a few times before it
// catches, then the whole sign settles into a steady warm-glow hum with a
// faintly pulsing halo.
//
// - demo == true:  self-driving ~3.4s loop (dark-ish → stutter → catch → hum).
// - demo == false: lit & humming at rest; a tap replays the buzz-to-life.
//
// Single always-running TimelineView(.animation) drives everything. A dim
// unlit tube of every glyph is ALWAYS visible underneath the lit layer, so no
// frame is ever blank — exactly how a real neon sign reads when "off".
//
// iOS 17. Pure SwiftUI, no shaders, no external dependencies.

struct NeonFlickerView: View {
    var demo: Bool = false

    // The headline. The character at `stutterIndex` is the misbehaving one.
    private let word: String = "NEON"
    private let stutterIndex: Int = 1   // the "E" stutters on its way to life

    // Full buzz-to-life duration before the steady hum takes over.
    private let flickerDuration: Double = 1.45
    // Total demo loop length (buzz-to-life + a stretch of steady hum).
    private let loopDuration: Double = 3.4

    // Neon tube hue — a warm bar-window magenta/pink.
    private var tubeColor: Color { Color(red: 1.0, green: 0.27, blue: 0.62) }
    private var tubeCore: Color { Color(red: 1.0, green: 0.82, blue: 0.92) }

    // Interactive replay anchor (tap date). nil → resting hum.
    @State private var tapDate: Date? = nil
    @State private var appearDate: Date = .now

    var body: some View {
        GeometryReader { geo in
            TimelineView(.animation) { timeline in
                let metrics = Metrics(size: geo.size)
                content(now: timeline.date, metrics: metrics)
                    .frame(width: geo.size.width, height: geo.size.height)
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .background(backgroundWall)
        .contentShape(Rectangle())
        .onTapGesture {
            // Replay the startup flicker from "dark".
            tapDate = .now
        }
        .onAppear { appearDate = .now }
    }

    // MARK: Layout metrics derived from the tile/detail size

    struct Metrics {
        let fontSize: CGFloat
        let spacing: CGFloat
        let haloRadius: CGFloat

        init(size: CGSize) {
            let minSide = min(size.width, size.height)
            // Scale font to fit the word horizontally with comfortable margin.
            let byWidth = size.width / 4.6
            let byHeight = minSide * 0.42
            let f = max(20, min(byWidth, byHeight))
            fontSize = f
            spacing = f * 0.06
            haloRadius = f * 0.5
        }
    }

    // MARK: Background — a dark wall the tubes glow against

    private var backgroundWall: some View {
        let base = Color(red: 0.016, green: 0.020, blue: 0.039) // #04050a
        return RadialGradient(
            colors: [
                Color(red: 0.10, green: 0.04, blue: 0.10),
                base
            ],
            center: .center,
            startRadius: 0,
            endRadius: 320
        )
    }

    // MARK: Composed lit headline

    private func content(now: Date, metrics: Metrics) -> some View {
        // Elapsed time since the flicker anchor.
        let elapsed = flickerElapsed(now: now)
        // Sine phase for the steady-hum halo breathe.
        let hum = humPhase(now: now)
        // Index over the glyphs; keyed on index so duplicate letters (the two
        // N's in "NEON") stay distinct identities.
        let letters = Array(word)

        return HStack(spacing: metrics.spacing) {
            ForEach(letters.indices, id: \.self) { index in
                NeonFlickerView_NeonLetter(
                    character: String(letters[index]),
                    fontSize: metrics.fontSize,
                    haloRadius: metrics.haloRadius,
                    tubeColor: tubeColor,
                    coreColor: tubeCore,
                    litOpacity: litOpacity(for: index, elapsed: elapsed),
                    haloIntensity: haloIntensity(for: index, elapsed: elapsed, hum: hum)
                )
            }
        }
    }

    // MARK: Timing

    /// Seconds elapsed within the current buzz-to-life cycle.
    private func flickerElapsed(now: Date) -> Double {
        if demo {
            // Self-driving: loop the whole sequence forever.
            let t = now.timeIntervalSince(appearDate)
            return t.truncatingRemainder(dividingBy: loopDuration)
        } else if let tap = tapDate {
            // Interactive: count up from the tap; past flickerDuration we hold lit.
            return now.timeIntervalSince(tap)
        } else {
            // At rest before any tap: already fully lit & humming.
            return flickerDuration + 1.0
        }
    }

    /// Continuous phase for the steady hum (independent of flicker anchor).
    private func humPhase(now: Date) -> Double {
        let t = now.timeIntervalSince(appearDate)
        return t
    }

    // MARK: Per-letter lit opacity (the electrical flicker track)

    /// The lit-glow opacity for a glyph, 0 (tube dark) ... 1 (full glow).
    /// The dim unlit tube is drawn separately and never disappears.
    private func litOpacity(for index: Int, elapsed: Double) -> Double {
        // After the buzz-to-life window everything is solidly lit.
        if elapsed >= flickerDuration { return 1.0 }
        if elapsed < 0 { return 1.0 }

        if index == stutterIndex {
            return stutterTrack(elapsed: elapsed)
        } else {
            return normalCatchTrack(elapsed: elapsed)
        }
    }

    /// Well-behaved letters: a couple of quick electrical blinks, then steady.
    private func normalCatchTrack(elapsed: Double) -> Double {
        // Irregular on/off keyframes (start dim, snap on, brief drop, hold).
        // Times are within [0, flickerDuration].
        switch elapsed {
        case ..<0.08:  return 0.0   // initial dark
        case ..<0.14:  return 0.9   // first strike
        case ..<0.20:  return 0.15  // brief dropout
        case ..<0.26:  return 1.0   // catches
        case ..<0.30:  return 0.45  // tiny flutter
        default:       return 1.0   // steady on
        }
    }

    /// The stubborn stutter letter: stutters on/off several times before catching.
    private func stutterTrack(elapsed: Double) -> Double {
        switch elapsed {
        case ..<0.10:  return 0.0
        case ..<0.16:  return 0.85
        case ..<0.24:  return 0.0
        case ..<0.30:  return 0.7
        case ..<0.40:  return 0.05
        case ..<0.46:  return 0.95
        case ..<0.58:  return 0.0   // stubborn dropout
        case ..<0.66:  return 0.6
        case ..<0.78:  return 0.1
        case ..<0.86:  return 1.0   // nearly there
        case ..<0.96:  return 0.3   // final flutter
        default:       return 1.0   // finally catches & holds
        }
    }

    // MARK: Per-letter halo intensity (glow radius/strength multiplier)

    /// Combines the flicker-driven litness with the steady-hum sine pulse.
    private func haloIntensity(for index: Int, elapsed: Double, hum: Double) -> Double {
        let lit = litOpacity(for: index, elapsed: elapsed)

        // Steady-hum breathe: low-amplitude sine, slight per-letter phase offset.
        let phase = hum * 2.4 + Double(index) * 0.5
        let breathe = 0.85 + 0.15 * (sin(phase) * 0.5 + 0.5)

        // While catching, the halo follows the lit track tightly; once settled,
        // it gently hums.
        if elapsed >= flickerDuration {
            return breathe
        }
        return lit * breathe
    }
}

// MARK: - A single neon glyph

private struct NeonFlickerView_NeonLetter: View {
    let character: String
    let fontSize: CGFloat
    let haloRadius: CGFloat
    let tubeColor: Color
    let coreColor: Color
    /// 0 = lit glow off (only dim tube shows), 1 = full glow.
    let litOpacity: Double
    /// Multiplier on the halo strength/spread for the steady hum.
    let haloIntensity: Double

    var body: some View {
        ZStack {
            // 1) The ALWAYS-VISIBLE dim unlit tube. Never disappears, so the
            //    sign reads as a real (currently-off) neon shape, not blank.
            glyph
                .foregroundStyle(unlitTube)
                .opacity(0.42)

            // 2) The lit tube body with stacked shadow halos for the glow.
            glyph
                .foregroundStyle(litBody)
                .shadow(color: tubeColor.opacity(0.95 * haloIntensity),
                        radius: haloRadius * 0.30 * clampedIntensity)
                .shadow(color: tubeColor.opacity(0.70 * haloIntensity),
                        radius: haloRadius * 0.62 * clampedIntensity)
                .shadow(color: tubeColor.opacity(0.45 * haloIntensity),
                        radius: haloRadius * 1.05 * clampedIntensity)
                .shadow(color: tubeColor.opacity(0.25 * haloIntensity),
                        radius: haloRadius * 1.6 * clampedIntensity)
                .opacity(litOpacity)

            // 3) Bright hot core for the lit tube so it reads as glass + gas.
            glyph
                .foregroundStyle(coreColor)
                .blur(radius: max(0.4, fontSize * 0.012))
                .opacity(litOpacity * 0.9)
        }
        .animation(.linear(duration: 0.04), value: litOpacity)
    }

    private var clampedIntensity: CGFloat {
        CGFloat(max(0.2, min(1.4, haloIntensity)))
    }

    private var glyph: some View {
        Text(character)
            .font(.system(size: fontSize, weight: .bold, design: .rounded))
            .kerning(fontSize * 0.04)
    }

    private var unlitTube: Color {
        // Desaturated dark version of the tube — the glass with the gas off.
        Color(red: 0.34, green: 0.12, blue: 0.24)
    }

    private var litBody: LinearGradient {
        LinearGradient(
            colors: [
                Color(red: 1.0, green: 0.55, blue: 0.80),
                tubeColor
            ],
            startPoint: .top,
            endPoint: .bottom
        )
    }
}
"""###,
        "tx-odometer-blur": ###"""
import SwiftUI

// Odometer Blur — a numeric value that rolls like a mechanical odometer.
// Each digit sits on a vertical drum; the fastest-moving wheels (the low-
// order digits) pick up motion blur and a slight vertical stretch, while a
// top/bottom curvature gradient fakes the cylinder shading. Everything is
// driven deterministically from elapsed time so per-wheel velocity (and thus
// blur) is analytic rather than guessed.
//
// The spec interaction is "auto": both demo states run the same self-driving
// loop, where the value auto-increments (+137 on a ~1.2s cadence) so the
// drums keep spinning and re-settling with velocity-proportional blur.
struct OdometerBlurView: View {

    var demo: Bool = false

    // How many digit wheels to show. Fixed so layout never reflows.
    private let digitCount: Int = 5

    // Auto-roll choreography.
    private let increment: Double = 137
    private let cadence: Double = 1.2      // seconds between increments
    private let rollDuration: Double = 0.7 // seconds the roll itself takes

    var body: some View {
        GeometryReader { geo in
            content(in: geo.size)
                .frame(maxWidth: .infinity, maxHeight: .infinity)
                .background(backgroundFill)
        }
    }

    // MARK: - Layout

    @ViewBuilder
    private func content(in size: CGSize) -> some View {
        let metrics = layoutMetrics(for: size)

        TimelineView(.animation) { timeline in
            let elapsed = timeline.date.timeIntervalSinceReferenceDate
            let state = autoState(at: elapsed)

            drum(state: state, metrics: metrics)
                .frame(width: metrics.totalWidth, height: metrics.windowHeight)
                .frame(maxWidth: .infinity, maxHeight: .infinity)
        }
    }

    private func drum(state: DrumState, metrics: LayoutMetrics) -> some View {
        HStack(spacing: metrics.wheelSpacing) {
            ForEach(0..<digitCount, id: \.self) { index in
                // place value: leftmost wheel is the highest power.
                let power = digitCount - 1 - index
                let wheel = wheelInfo(value: state.value,
                                      velocity: state.velocity,
                                      power: power)
                OdometerBlurView_DigitWheel(digit: wheel.digit,
                           frac: wheel.frac,
                           blur: wheel.blur,
                           stretch: wheel.stretch,
                           digitHeight: metrics.digitHeight,
                           fontSize: metrics.fontSize,
                           color: digitColor)
                    .frame(width: metrics.wheelWidth, height: metrics.windowHeight)
                    .clipShape(RoundedRectangle(cornerRadius: metrics.wheelCorner,
                                                style: .continuous))
                    .overlay(curvatureOverlay(corner: metrics.wheelCorner))
                    .overlay(wheelBorder(corner: metrics.wheelCorner))
            }
        }
    }

    // MARK: - Engine (deterministic, time-driven)

    struct DrumState {
        var value: Double
        var velocity: Double // units per second, on the value scale
    }

    private func autoState(at elapsed: TimeInterval) -> DrumState {
        let step = floor(elapsed / cadence)
        let local = elapsed - step * cadence
        let t = min(max(local / rollDuration, 0), 1)
        let eased = easeOut(t)
        let value = increment * step + increment * eased
        // Analytic velocity: d/dt of (increment * easeOut(local/rollDuration)).
        var velocity: Double = 0
        if local < rollDuration {
            velocity = increment * easeOutDerivative(t) / rollDuration
        }
        return DrumState(value: value, velocity: velocity)
    }

    // Easing: a cubic ease-out so the roll launches fast and settles soft.
    private func easeOut(_ t: Double) -> Double {
        let inv = 1 - t
        return 1 - inv * inv * inv
    }

    private func easeOutDerivative(_ t: Double) -> Double {
        let inv = 1 - t
        return 3 * inv * inv
    }

    // MARK: - Per-wheel resolution

    struct WheelInfo {
        var digit: Int
        var frac: Double
        var blur: CGFloat
        var stretch: CGFloat
    }

    private func wheelInfo(value: Double, velocity: Double, power: Int) -> WheelInfo {
        let scale = pow(10.0, Double(power))
        let modulus = pow(10.0, Double(digitCount))
        // Keep the displayed value within the fixed digit window.
        let wrapped = positiveMod(value, modulus)
        let wheelPos = wrapped / scale
        let base = floor(wheelPos)
        let frac = wheelPos - base
        let digit = positiveModInt(Int(base), 10)

        // This wheel's spin rate in digits/sec.
        let wheelVelocity = abs(velocity) / scale
        let blur = blurAmount(forWheelVelocity: wheelVelocity)
        let stretch = stretchAmount(forWheelVelocity: wheelVelocity)
        return WheelInfo(digit: digit, frac: frac, blur: blur, stretch: stretch)
    }

    private func blurAmount(forWheelVelocity v: Double) -> CGFloat {
        // v is in digits/second. A wheel doing a few digits/sec reads as a
        // fast cylinder; cap so it never dissolves entirely.
        let normalized = min(v / 22.0, 1.0)
        return CGFloat(normalized) * 5.0
    }

    private func stretchAmount(forWheelVelocity v: Double) -> CGFloat {
        let normalized = min(v / 22.0, 1.0)
        return 1.0 + CGFloat(normalized) * 0.14
    }

    private func positiveMod(_ a: Double, _ n: Double) -> Double {
        let r = a.truncatingRemainder(dividingBy: n)
        return r < 0 ? r + n : r
    }

    private func positiveModInt(_ a: Int, _ n: Int) -> Int {
        let r = a % n
        return r < 0 ? r + n : r
    }

    // MARK: - Decoration

    private func curvatureOverlay(corner: CGFloat) -> some View {
        // Top + bottom shading fades to clear at the centre to fake the
        // cylinder's curvature, using the dark catalogue tint.
        let dark = Color(red: 0.016, green: 0.020, blue: 0.039)
        return LinearGradient(
            stops: [
                .init(color: dark.opacity(0.95), location: 0.0),
                .init(color: dark.opacity(0.30), location: 0.22),
                .init(color: .clear, location: 0.46),
                .init(color: .clear, location: 0.54),
                .init(color: dark.opacity(0.30), location: 0.78),
                .init(color: dark.opacity(0.95), location: 1.0)
            ],
            startPoint: .top,
            endPoint: .bottom
        )
        .clipShape(RoundedRectangle(cornerRadius: corner, style: .continuous))
        .allowsHitTesting(false)
    }

    private func wheelBorder(corner: CGFloat) -> some View {
        RoundedRectangle(cornerRadius: corner, style: .continuous)
            .strokeBorder(
                LinearGradient(
                    colors: [Color.white.opacity(0.16), Color.white.opacity(0.02)],
                    startPoint: .top,
                    endPoint: .bottom
                ),
                lineWidth: 0.75
            )
            .allowsHitTesting(false)
    }

    private var backgroundFill: some View {
        LinearGradient(
            colors: [
                Color(red: 0.05, green: 0.06, blue: 0.10),
                Color(red: 0.02, green: 0.03, blue: 0.05)
            ],
            startPoint: .top,
            endPoint: .bottom
        )
    }

    private var digitColor: Color {
        Color(red: 0.94, green: 0.96, blue: 0.99)
    }

    // MARK: - Metrics

    struct LayoutMetrics {
        var fontSize: CGFloat
        var digitHeight: CGFloat
        var windowHeight: CGFloat
        var wheelWidth: CGFloat
        var wheelSpacing: CGFloat
        var wheelCorner: CGFloat
        var totalWidth: CGFloat
    }

    private func layoutMetrics(for size: CGSize) -> LayoutMetrics {
        let minSide = min(size.width, size.height)
        // Wheel sizing scales with the smaller dimension so it works in both a
        // ~120pt tile and a large detail area.
        let spacingGuess: CGFloat = max(2, minSide * 0.03)
        let available = size.width - spacingGuess * CGFloat(digitCount - 1)
        let widthPerWheel = available / CGFloat(digitCount)
        let wheelWidth = max(8, min(widthPerWheel, minSide * 0.42))
        let fontSize = min(wheelWidth * 1.08, size.height * 0.62)
        let digitHeight = max(1, fontSize * 1.18)
        let windowHeight = digitHeight
        let corner = max(2, wheelWidth * 0.18)
        let total = wheelWidth * CGFloat(digitCount)
                    + spacingGuess * CGFloat(digitCount - 1)
        return LayoutMetrics(
            fontSize: fontSize,
            digitHeight: digitHeight,
            windowHeight: windowHeight,
            wheelWidth: wheelWidth,
            wheelSpacing: spacingGuess,
            wheelCorner: corner,
            totalWidth: total
        )
    }
}

// MARK: - OdometerBlurView_DigitWheel

// A single odometer wheel rendered as a 2-digit window: the current digit and
// the next one stacked above it, slid up by `frac` of a digit's height so 9
// wraps cleanly to 0. Velocity-driven blur + vertical stretch sell the spin.
private struct OdometerBlurView_DigitWheel: View {

    let digit: Int
    let frac: Double
    let blur: CGFloat
    let stretch: CGFloat
    let digitHeight: CGFloat
    let fontSize: CGFloat
    let color: Color

    var body: some View {
        let nextDigit = (digit + 1) % 10
        let offset = -CGFloat(frac) * digitHeight

        ZStack {
            wheelBackground
            VStack(spacing: 0) {
                glyph(digit)
                glyph(nextDigit)
            }
            .offset(y: offset)
            .scaleEffect(x: 1.0, y: stretch, anchor: .center)
            .blur(radius: blur)
        }
    }

    private func glyph(_ value: Int) -> some View {
        Text("\(value)")
            .font(.system(size: fontSize, weight: .semibold, design: .monospaced))
            .monospacedDigit()
            .foregroundStyle(color)
            .frame(height: digitHeight)
            .frame(maxWidth: .infinity)
            // A soft inner glow so the lit digit reads against the dark drum.
            .shadow(color: Color.white.opacity(0.18), radius: 0.6)
    }

    private var wheelBackground: some View {
        LinearGradient(
            colors: [
                Color(red: 0.10, green: 0.12, blue: 0.17),
                Color(red: 0.04, green: 0.05, blue: 0.08),
                Color(red: 0.10, green: 0.12, blue: 0.17)
            ],
            startPoint: .top,
            endPoint: .bottom
        )
    }
}
"""###,
        "tx-ransom-note": ###"""
import SwiftUI

/// Ransom Note Assembly — letters slap onto the page as mismatched cut-out
/// clippings, each with a random typeface, tilt, torn-paper background and
/// drop shadow, entering with a quick scale-overshoot stamp.
///
/// - `demo == true`  : a self-driving TimelineView re-rolls the collage and
///   replays the staggered slap-in on a ~2.6s loop. The word stays fully
///   assembled and legible at every frame (letters re-stamp in place, they
///   never clear to empty).
/// - `demo == false` : tapping anywhere re-seeds the randomness and replays
///   the staggered scale-overshoot slap-in.
struct RansomNoteView: View {
    var demo: Bool = false

    // The shared driver. Bumping it re-rolls every letter's attributes and
    // restarts the stamp-in stagger. In demo mode a TimelineView bumps it;
    // interactively a tap bumps it.
    @State private var generation: Int = 1
    @State private var reseedTime: Date = .now

    private let phrase: [Character] = Array("RANSOM")
    private let cycle: Double = 2.6

    var body: some View {
        GeometryReader { proxy in
            let metrics = RansomNoteView_Metrics(size: proxy.size, count: phrase.count)
            ZStack {
                background
                content(metrics: metrics)
            }
            .frame(maxWidth: .infinity, maxHeight: .infinity)
            .contentShape(Rectangle())
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // MARK: - Content (driven vs. interactive)

    @ViewBuilder
    private func content(metrics: RansomNoteView_Metrics) -> some View {
        if demo {
            TimelineView(.animation) { timeline in
                let t = timeline.date.timeIntervalSinceReferenceDate
                let gen = Int(t / cycle) + 1
                let phase = (t.truncatingRemainder(dividingBy: cycle)) / cycle
                collage(metrics: metrics, generation: gen, cyclePhase: phase)
            }
        } else {
            TimelineView(.animation) { timeline in
                let elapsed = timeline.date.timeIntervalSince(reseedTime)
                let phase = min(max(elapsed / cycle, 0), 1)
                collage(metrics: metrics, generation: generation, cyclePhase: phase)
            }
            // Expand the hit area to fill the whole tile so a tap ANYWHERE
            // (including the margins) re-seeds, per the behavior contract.
            .frame(maxWidth: .infinity, maxHeight: .infinity)
            .contentShape(Rectangle())
            .onTapGesture {
                generation += 1
                reseedTime = .now
            }
        }
    }

    // MARK: - Collage

    private func collage(metrics: RansomNoteView_Metrics, generation gen: Int, cyclePhase: Double) -> some View {
        HStack(spacing: metrics.spacing) {
            ForEach(Array(phrase.enumerated()), id: \.offset) { index, character in
                let attrs = RansomNoteView_LetterAttributes(generation: gen, index: index, baseSize: metrics.fontSize)
                let stamp = stampPhase(cyclePhase: cyclePhase, index: index)
                RansomNoteView_LetterClipping(character: character, attrs: attrs, stamp: stamp)
            }
        }
        .padding(.horizontal, metrics.spacing)
    }

    // MARK: - Stagger timing

    /// Returns a per-letter "stamp phase" in [0, 1] describing where this letter
    /// is in its own slap-in window. Letters rest (phase 0) before their slice,
    /// run 0→1 across their slice (one-by-one), then rest (phase 1) after. The
    /// RansomNoteView_LetterClipping turns 0 and 1 into the SAME settled look (scale 1.0), with
    /// the overshoot happening in between — so a letter is legible at every
    /// frame, including the cycle boundary, yet still slaps in sequentially.
    private func stampPhase(cyclePhase: Double, index: Int) -> Double {
        let count = max(phrase.count, 1)
        // Slap-in cascade occupies the first ~72% of the cycle, leaving a short
        // settled beat before the collage re-rolls.
        let window = 0.72
        let perLetter = window / Double(count)
        let start = perLetter * Double(index)
        // Each letter's own pop runs slightly longer than its slot for overlap.
        let span = perLetter * 1.35
        let local = (cyclePhase - start) / max(span, 0.0001)
        return min(max(local, 0), 1)
    }

    // MARK: - Background (paper-ish base)

    private var background: some View {
        ZStack {
            LinearGradient(
                colors: [
                    Color(red: 0.09, green: 0.10, blue: 0.13),
                    Color(red: 0.05, green: 0.05, blue: 0.07)
                ],
                startPoint: .topLeading,
                endPoint: .bottomTrailing
            )
            // Faint vignette so the bright clippings pop.
            RadialGradient(
                colors: [Color.white.opacity(0.04), Color.clear],
                center: .center,
                startRadius: 0,
                endRadius: 220
            )
        }
    }
}

// MARK: - Layout metrics

private struct RansomNoteView_Metrics {
    let fontSize: CGFloat
    let spacing: CGFloat

    init(size: CGSize, count: Int) {
        let w = max(size.width, 1)
        let h = max(size.height, 1)
        let n = CGFloat(max(count, 1))
        // Per-letter footprint at rest ≈ 0.94 × fontSize (glyph + padding).
        // Budget the 1.4× scale-overshoot and ±13° tilt plus an outer margin
        // so the whole word stays inside the tile even at peak pop.
        let footprintPerLetter: CGFloat = 0.94
        let overshootBudget: CGFloat = 1.45
        let marginFactor: CGFloat = 0.86
        let byWidth = (w * marginFactor) / (n * footprintPerLetter * overshootBudget)
        let byHeight = h * 0.30
        let raw = min(byWidth, byHeight)
        fontSize = max(min(raw, 96), 9)
        spacing = max(fontSize * 0.03, 1)
    }
}

// MARK: - Per-letter randomized attributes

/// Pure function of (generation, index) — deterministic so it is stable across
/// the many body re-evaluations a TimelineView triggers per second. Randomness
/// only changes when `generation` changes.
private struct RansomNoteView_LetterAttributes {
    let design: Font.Design
    let weight: Font.Weight
    let italic: Bool
    let size: CGFloat
    let rotation: Double
    let yOffset: CGFloat
    let paper: Color
    let ink: Color
    let tornInset: CGFloat
    let tornSeed: UInt64

    init(generation: Int, index: Int, baseSize: CGFloat) {
        let seedValue = UInt64(bitPattern: Int64(generation &* 1_000 &+ index &+ 7))
        tornSeed = seedValue &* 0x2545F4914F6CDD1D | 1
        var rng = RansomNoteView_SeededGenerator(seed: seedValue)

        let designs: [Font.Design] = [.default, .serif, .rounded, .monospaced]
        design = designs[Int(rng.next() % UInt64(designs.count))]

        let weights: [Font.Weight] = [.regular, .medium, .semibold, .bold, .heavy, .black]
        weight = weights[Int(rng.next() % UInt64(weights.count))]

        italic = (rng.next() % 4 == 0)

        // Size jitter so clippings look cut at different scales.
        let sizeJitter = 0.82 + rng.unit() * 0.4
        size = baseSize * CGFloat(sizeJitter)

        // Tilt: mismatched paste angles.
        rotation = (rng.unit() * 2 - 1) * 13

        // Slight vertical scatter along the baseline.
        yOffset = CGFloat((rng.unit() * 2 - 1)) * baseSize * 0.10

        // Paper tints — newsprint / magazine clipping palette.
        paper = RansomNoteView_LetterAttributes.paperColor(&rng)
        ink = RansomNoteView_LetterAttributes.inkColor(&rng)

        tornInset = CGFloat(0.10 + rng.unit() * 0.08)
    }

    private static func paperColor(_ rng: inout RansomNoteView_SeededGenerator) -> Color {
        let palette: [(Double, Double, Double)] = [
            (0.96, 0.94, 0.88),   // cream newsprint
            (0.98, 0.97, 0.95),   // bright white
            (0.92, 0.86, 0.70),   // aged tan
            (0.86, 0.90, 0.94),   // cool grey
            (0.99, 0.84, 0.36),   // highlighter yellow
            (0.95, 0.55, 0.42),   // warm coral scrap
            (0.62, 0.82, 0.74)    // mint scrap
        ]
        let c = palette[Int(rng.next() % UInt64(palette.count))]
        return Color(red: c.0, green: c.1, blue: c.2)
    }

    private static func inkColor(_ rng: inout RansomNoteView_SeededGenerator) -> Color {
        let palette: [(Double, Double, Double)] = [
            (0.07, 0.07, 0.09),   // near-black ink
            (0.10, 0.10, 0.12),
            (0.55, 0.08, 0.10),   // red ink
            (0.10, 0.18, 0.45)    // blue ballpoint
        ]
        let c = palette[Int(rng.next() % UInt64(palette.count))]
        return Color(red: c.0, green: c.1, blue: c.2)
    }

    var font: Font {
        let base = Font.system(size: size, weight: weight, design: design)
        return italic ? base.italic() : base
    }
}

// MARK: - A single torn-paper letter clipping

private struct RansomNoteView_LetterClipping: View {
    let character: Character
    let attrs: RansomNoteView_LetterAttributes
    /// 0 = resting (not yet stamped or fully settled), runs 0→1 across the
    /// letter's slap-in slice with an overshoot in the middle.
    let stamp: Double

    var body: some View {
        let scale = stampScale(stamp)
        let activity = popActivity(stamp)          // 0 at rest, ~1 mid-pop
        let settleRotation = attrs.rotation * (1.0 + activity * 0.55)
        let isActive = stamp > 0.001 && stamp < 0.999

        clipping
            .rotationEffect(.degrees(settleRotation))
            .offset(y: attrs.yOffset - CGFloat(activity) * attrs.size * 0.12)
            .scaleEffect(scale)
            .opacity(stampOpacity(stamp))
            .zIndex(isActive ? 1 : 0)
    }

    private var clipping: some View {
        Text(String(character))
            .font(attrs.font)
            .foregroundStyle(attrs.ink)
            .padding(.horizontal, attrs.size * 0.16)
            .padding(.vertical, attrs.size * 0.10)
            .background {
                RansomNoteView_TornPaper(inset: attrs.tornInset, seed: attrs.tornSeed)
                    .fill(attrs.paper)
                    .overlay {
                        RansomNoteView_TornPaper(inset: attrs.tornInset, seed: attrs.tornSeed)
                            .stroke(Color.black.opacity(0.13), lineWidth: 0.6)
                    }
                    .shadow(color: Color.black.opacity(0.45),
                            radius: attrs.size * 0.10,
                            x: attrs.size * 0.04,
                            y: attrs.size * 0.06)
            }
    }

    // Pop-in-place: rests at 1.0, punches up to ~1.4 at the slice midpoint,
    // then settles back to 1.0. Because both ends are 1.0 the cycle boundary
    // is seamless and the letter is never small or blank.
    private func stampScale(_ p: Double) -> CGFloat {
        if p <= 0 || p >= 1 { return 1.0 }
        // Rise quickly, settle with a damped tail.
        let rise = sin(min(p / 0.30, 1.0) * Double.pi / 2)   // 0→1 fast
        let fall = 1 - pow(max((p - 0.30) / 0.70, 0), 2)      // 1→0 slow
        let amplitude = p < 0.30 ? rise : fall
        let value = 1.0 + 0.40 * max(min(amplitude, 1), 0)
        return CGFloat(value)
    }

    // How "mid-pop" the letter is (drives the lift and extra tilt).
    private func popActivity(_ p: Double) -> Double {
        if p <= 0 || p >= 1 { return 0 }
        return sin(p * Double.pi)
    }

    // Opacity floored at 0.78 so the word is always legible. It dips only very
    // slightly at the start of a pop to read as a fresh slap, never near blank.
    private func stampOpacity(_ p: Double) -> Double {
        if p <= 0 || p >= 1 { return 1.0 }
        let dip = 0.22 * (1 - sin(min(p / 0.18, 1.0) * Double.pi / 2))
        return 1.0 - dip
    }
}

// MARK: - Torn-paper edge shape

/// A rectangle whose edges are nibbled with small irregular notches to suggest
/// a hand-torn clipping. Deterministic per `seed` so it is stable across frames
/// yet varies per letter and per re-roll.
private struct RansomNoteView_TornPaper: Shape {
    let inset: CGFloat
    let seed: UInt64

    func path(in rect: CGRect) -> Path {
        var path = Path()
        let teeth = 9
        let amp = min(rect.width, rect.height) * inset * 0.4

        var rng = RansomNoteView_SeededGenerator(seed: seed)

        // Walk the perimeter producing a jagged torn outline.
        let points = perimeterPoints(rect: rect, teeth: teeth, amp: amp, rng: &rng)
        guard let first = points.first else { return path }
        path.move(to: first)
        for p in points.dropFirst() {
            path.addLine(to: p)
        }
        path.closeSubpath()
        return path
    }

    private func perimeterPoints(rect: CGRect, teeth: Int, amp: CGFloat, rng: inout RansomNoteView_SeededGenerator) -> [CGPoint] {
        var pts: [CGPoint] = []
        let edges: [(CGPoint, CGPoint)] = [
            (CGPoint(x: rect.minX, y: rect.minY), CGPoint(x: rect.maxX, y: rect.minY)),
            (CGPoint(x: rect.maxX, y: rect.minY), CGPoint(x: rect.maxX, y: rect.maxY)),
            (CGPoint(x: rect.maxX, y: rect.maxY), CGPoint(x: rect.minX, y: rect.maxY)),
            (CGPoint(x: rect.minX, y: rect.maxY), CGPoint(x: rect.minX, y: rect.minY))
        ]
        for (a, b) in edges {
            for i in 0..<teeth {
                let f = CGFloat(i) / CGFloat(teeth)
                let x = a.x + (b.x - a.x) * f
                let y = a.y + (b.y - a.y) * f
                // Offset perpendicular-ish by a small jitter to nibble the edge.
                let jitter = (CGFloat(rng.unit()) * 2 - 1) * amp
                let isHorizontal = abs(b.y - a.y) < abs(b.x - a.x)
                let px = isHorizontal ? x : x + jitter
                let py = isHorizontal ? y + jitter : y
                pts.append(CGPoint(x: px, y: py))
            }
        }
        return pts
    }
}

// MARK: - Deterministic RNG

/// SplitMix64 — a tiny, fast, fully deterministic generator so per-letter
/// attributes are a pure function of their seed (never re-rolled per frame).
private struct RansomNoteView_SeededGenerator: RandomNumberGenerator {
    private var state: UInt64

    init(seed: UInt64) {
        // Avoid a zero state.
        state = seed == 0 ? 0x9E3779B97F4A7C15 : seed
    }

    mutating func next() -> UInt64 {
        state = state &+ 0x9E3779B97F4A7C15
        var z = state
        z = (z ^ (z >> 30)) &* 0xBF58476D1CE4E5B9
        z = (z ^ (z >> 27)) &* 0x94D049BB133111EB
        return z ^ (z >> 31)
    }

    /// A Double in [0, 1).
    mutating func unit() -> Double {
        Double(next() >> 11) * (1.0 / 9007199254740992.0)
    }
}
"""###,
        "tx-shatter-glass": ###"""
//
//  GlassShatterSettleView.swift
//  InspireCreativityApp — Bespoke catalog animation
//
//  Glass Shatter Settle: the headline appears as offset angular shards that fly
//  back together from the edges, each glyph rotating and decelerating into
//  perfect alignment — like time-reversed breaking.
//
//  Uses iOS 18 `TextRenderer` for per-glyph transforms; falls back to a plain
//  fade on iOS 17. Self-contained: SwiftUI only.
//  `demo == true`  → self-driving shatter→assemble loop (grid tile).
//  `demo == false` → tap re-fires the assembly (Detail + the buyer's code).
//

import SwiftUI

struct GlassShatterSettleView: View {
    var demo: Bool = false
    @State private var assembled = false

    var body: some View {
        if #available(iOS 18.0, *) {
            modern
        } else {
            fallback
        }
    }

    @available(iOS 18.0, *)
    @ViewBuilder private var modern: some View {
        if demo {
            TimelineView(.animation) { ctx in
                shatterText(progress: Self.loopProgress(ctx.date))
            }
        } else {
            shatterText(progress: assembled ? 1 : 0)
                .contentShape(Rectangle())
                .onTapGesture { refire() }
                .onAppear { refire() }
        }
    }

    private func refire() {
        assembled = false
        withAnimation(.spring(response: 0.75, dampingFraction: 0.6)) { assembled = true }
    }

    @available(iOS 18.0, *)
    private func shatterText(progress: CGFloat) -> some View {
        ZStack {
            Color(red: 0.04, green: 0.05, blue: 0.09)
            Text("SHATTER")
                .font(.system(size: 34, weight: .heavy, design: .rounded))
                .foregroundStyle(
                    LinearGradient(colors: [.white, Color(red: 0.7, green: 0.9, blue: 1.0)],
                                   startPoint: .top, endPoint: .bottom)
                )
                .textRenderer(ShatterTextRenderer(progress: progress))
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    private var fallback: some View {
        ZStack {
            Color(red: 0.04, green: 0.05, blue: 0.09)
            Text("SHATTER")
                .font(.system(size: 34, weight: .heavy, design: .rounded))
                .foregroundStyle(.white)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    /// scatter → assemble → hold, on a ~3s loop.
    static func loopProgress(_ date: Date) -> CGFloat {
        let period = 3.0
        let t = date.timeIntervalSinceReferenceDate.truncatingRemainder(dividingBy: period) / period
        if t < 0.15 { return 0 }
        if t < 0.72 {
            let u = (t - 0.15) / 0.57
            return CGFloat(u * u * (3 - 2 * u))
        }
        return 1
    }
}

@available(iOS 18.0, *)
struct ShatterTextRenderer: TextRenderer {
    var progress: CGFloat
    var animatableData: CGFloat {
        get { progress }
        set { progress = newValue }
    }

    func draw(layout: Text.Layout, in ctx: inout GraphicsContext) {
        let scatter = 1 - max(0, min(progress, 1))
        var index = 0
        for line in layout {
            for run in line {
                for glyph in run {
                    index += 1
                    let seed = Double(index) * 12.9898
                    let dx = CGFloat(cos(seed)) * 130 * scatter
                    let dy = CGFloat(sin(seed * 1.7)) * 90 * scatter
                    let angle = Angle.degrees(cos(seed * 0.7) * 75 * Double(scatter))

                    let rect = glyph.typographicBounds.rect
                    let center = CGPoint(x: rect.midX, y: rect.midY)

                    var copy = ctx
                    copy.opacity = Double(min(1, progress * 1.5))
                    copy.translateBy(x: dx, y: dy)
                    copy.translateBy(x: center.x, y: center.y)
                    copy.rotate(by: angle)
                    copy.translateBy(x: -center.x, y: -center.y)
                    copy.draw(glyph)
                }
            }
        }
    }
}
"""###,
        "tx-split-flap": ###"""
import SwiftUI

// MARK: - Split-Flap Departure
// A mechanical airport split-flap board. Each character rolls through a
// clatter of random glyphs and locks onto a target letter via a double-hinge
// 3D fold (two stacked half-glyph flaps, each rotating only 90 deg so there is
// no back-face / mirror handling). Tiles cascade left-to-right with a per-tile
// delay. demo == true cycles through words on a self-driving ~3.2s loop;
// demo == false re-fires the cascade to a new word on tap.

public struct SplitFlapView: View {
    public var demo: Bool = false

    public init(demo: Bool = false) {
        self.demo = demo
    }

    public var body: some View {
        GeometryReader { geo in
            SplitFlapView_SplitFlapBoard(demo: demo, size: geo.size)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }
}

// MARK: - Board

private struct SplitFlapView_SplitFlapBoard: View {
    let demo: Bool
    let size: CGSize

    // Short words (3-6 chars) so the board stays legible inside a ~120pt tile.
    private static let words: [String] = ["FLY", "GATE", "BOARD", "DEPART", "CLEAR", "JAZZ"]

    // Timing budget. With charCount intermediate flips at flipDur each, plus the
    // cascade stagger, the last tile must finish comfortably before `period`.
    private let period: Double = 3.2
    private let flipDur: Double = 0.13
    private let stagger: Double = 0.14
    private let intermediateCount: Int = 5

    // Interactive state (demo == false). Time-derived from `cycleStart`.
    @State private var cycleStart: Date = .now
    @State private var tapIndex: Int = 0

    private var columns: Int {
        Self.words.map(\.count).max() ?? 6
    }

    var body: some View {
        TimelineView(.animation) { timeline in
            let layout = layout(for: timeline.date)
            board(layout: layout)
        }
        // Tap re-fires the cascade to the next word (faithful to interactiveSpec).
        .contentShape(Rectangle())
        .onTapGesture {
            guard !demo else { return }
            tapIndex += 1
            cycleStart = .now
        }
    }

    // MARK: Layout metrics derived from available size

    struct Metrics {
        var cardW: CGFloat
        var cardH: CGFloat
        var fontSize: CGFloat
        var spacing: CGFloat
    }

    private func metrics() -> Metrics {
        let cols = CGFloat(columns)
        let spacing: CGFloat = max(2, min(size.width, size.height) * 0.025)
        // Fit `cols` cards plus inter-card spacing across the width, leaving margin.
        let usableW = size.width * 0.92
        let cardW = max(8, (usableW - spacing * (cols - 1)) / cols)
        // Split-flap cards are tall; cap by height too.
        let cardH = min(cardW * 1.5, size.height * 0.62)
        let fontSize = min(cardH * 0.72, cardW * 1.05)
        return Metrics(cardW: cardW, cardH: cardH, fontSize: fontSize, spacing: spacing)
    }

    // MARK: Time -> word + local time

    struct BoardLayout {
        var oldWord: String
        var newWord: String
        var localT: Double
        var cycleIndex: Int
    }

    private func layout(for date: Date) -> BoardLayout {
        let n = Self.words.count
        if demo {
            // Self-driving: derive everything purely from elapsed time.
            let t = date.timeIntervalSinceReferenceDate
            let cycleIndex = Int(floor(t / period))
            let localT = t - Double(cycleIndex) * period
            let newWord = Self.words[((cycleIndex % n) + n) % n]
            let oldWord = Self.words[(((cycleIndex - 1) % n) + n) % n]
            return BoardLayout(oldWord: oldWord, newWord: newWord, localT: localT, cycleIndex: cycleIndex)
        } else {
            // Interactive: time since the last tap drives the same render path.
            let localT = max(0, date.timeIntervalSince(cycleStart))
            let newWord = Self.words[((tapIndex % n) + n) % n]
            let oldWord = Self.words[(((tapIndex - 1) % n) + n) % n]
            return BoardLayout(oldWord: oldWord, newWord: newWord, localT: localT, cycleIndex: tapIndex)
        }
    }

    // MARK: Views

    private func board(layout: BoardLayout) -> some View {
        let m = metrics()
        return HStack(spacing: m.spacing) {
            ForEach(0..<columns, id: \.self) { col in
                SplitFlapView_FlapTile(
                    oldChar: char(layout.oldWord, at: col),
                    targetChar: char(layout.newWord, at: col),
                    localT: layout.localT,
                    tileIndex: col,
                    cycleIndex: layout.cycleIndex,
                    flipDur: flipDur,
                    stagger: stagger,
                    intermediateCount: intermediateCount,
                    metrics: m
                )
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .padding(.horizontal, m.spacing)
    }

    // Pad shorter words with blanks so every word uses the same column count.
    private func char(_ word: String, at index: Int) -> Character {
        let chars = Array(word)
        return index < chars.count ? chars[index] : " "
    }
}

// MARK: - Single flap tile

private struct SplitFlapView_FlapTile: View {
    let oldChar: Character
    let targetChar: Character
    let localT: Double
    let tileIndex: Int
    let cycleIndex: Int
    let flipDur: Double
    let stagger: Double
    let intermediateCount: Int
    let metrics: SplitFlapView_SplitFlapBoard.Metrics

    private static let alphabet = Array("ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789 ")

    // Deterministic pseudo-random glyph from a seed (stable across frames).
    private func glyph(step: Int) -> Character {
        var h = UInt64(bitPattern: Int64(cycleIndex &* 92821 &+ tileIndex &* 6151 &+ step &* 2654435761))
        h ^= h >> 33
        h = h &* 0xff51afd7ed558ccd
        h ^= h >> 33
        let idx = Int(h % UInt64(Self.alphabet.count))
        return Self.alphabet[idx]
    }

    // The full clatter sequence: old -> N random glyphs -> target.
    private var sequence: [Character] {
        var chars: [Character] = [oldChar]
        for s in 0..<intermediateCount {
            chars.append(glyph(step: s))
        }
        chars.append(targetChar)
        return chars
    }

    var body: some View {
        let chars = sequence
        let localTile = localT - Double(tileIndex) * stagger
        let lastStart = Double(chars.count - 1) * flipDur

        Group {
            if localTile <= 0 {
                // Before this tile starts: hold the old glyph fully formed.
                SplitFlapView_StaticCard(char: oldChar, metrics: metrics)
            } else if localTile >= lastStart {
                // Settled on the target glyph.
                SplitFlapView_StaticCard(char: targetChar, metrics: metrics)
            } else {
                let flipIdx = min(Int(localTile / flipDur), chars.count - 2)
                let p = (localTile - Double(flipIdx) * flipDur) / flipDur
                SplitFlapView_FlippingCard(
                    from: chars[flipIdx],
                    to: chars[flipIdx + 1],
                    progress: min(max(p, 0), 1),
                    metrics: metrics
                )
            }
        }
        .frame(width: metrics.cardW, height: metrics.cardH)
    }
}

// MARK: - Card chrome (shared)

private func cardFace() -> some View {
    RoundedRectangle(cornerRadius: 3, style: .continuous)
        .fill(
            LinearGradient(
                colors: [
                    Color(red: 0.11, green: 0.12, blue: 0.15),
                    Color(red: 0.05, green: 0.05, blue: 0.07)
                ],
                startPoint: .top,
                endPoint: .bottom
            )
        )
}

private let glyphColor = Color(red: 0.96, green: 0.96, blue: 0.93)

// One half (top or bottom) of a glyph card. The glyph is rendered centered in
// the FULL card height, then cropped to a half — so the glyph's vertical center
// lands exactly on the seam (cardH / 2).
private struct SplitFlapView_HalfCard: View {
    let char: Character
    let top: Bool
    let metrics: SplitFlapView_SplitFlapBoard.Metrics

    var body: some View {
        let w = metrics.cardW
        let h = metrics.cardH
        ZStack {
            cardFace()
            Text(String(char))
                .font(.system(size: metrics.fontSize, weight: .bold, design: .monospaced))
                .foregroundStyle(glyphColor)
                .frame(width: w, height: h)
        }
        // Crop the (full-height) content to the requested half BEFORE any rotation.
        .frame(width: w, height: h, alignment: .center)
        .frame(height: h / 2, alignment: top ? .top : .bottom)
        .clipped()
        // The dark seam line across the middle of the board.
        .overlay(alignment: top ? .bottom : .top) {
            Rectangle()
                .fill(Color(red: 0.0, green: 0.0, blue: 0.0).opacity(0.55))
                .frame(height: 1.2)
        }
    }
}

// A fully-formed (non-flipping) card: top half + bottom half stacked.
private struct SplitFlapView_StaticCard: View {
    let char: Character
    let metrics: SplitFlapView_SplitFlapBoard.Metrics

    var body: some View {
        VStack(spacing: 0) {
            SplitFlapView_HalfCard(char: char, top: true, metrics: metrics)
            SplitFlapView_HalfCard(char: char, top: false, metrics: metrics)
        }
        .clipShape(RoundedRectangle(cornerRadius: 3, style: .continuous))
        .overlay(
            RoundedRectangle(cornerRadius: 3, style: .continuous)
                .strokeBorder(Color.black.opacity(0.35), lineWidth: 0.75)
        )
        .shadow(color: Color.black.opacity(0.35), radius: 1.5, x: 0, y: 1)
    }
}

// MARK: - The flipping card (double-hinge)

private struct SplitFlapView_FlippingCard: View {
    let from: Character
    let to: Character
    let progress: Double // 0...1 for a single old->new flip
    let metrics: SplitFlapView_SplitFlapBoard.Metrics

    private let perspective: CGFloat = 0.55

    var body: some View {
        let p = progress
        let h = metrics.cardH

        ZStack {
            // 1. Static background: new top half is revealed as the old top falls away.
            VStack(spacing: 0) {
                SplitFlapView_HalfCard(char: to, top: true, metrics: metrics)
                // 2. Static bottom: old bottom stays until the new bottom flap covers it.
                SplitFlapView_HalfCard(char: from, top: false, metrics: metrics)
            }

            // 3. Falling top flap: old TOP hinges down from the seam (0 -> -90deg).
            if p < 0.5 {
                let topP = p / 0.5 // 0...1
                SplitFlapView_HalfCard(char: from, top: true, metrics: metrics)
                    .frame(height: h / 2, alignment: .top)
                    .offset(y: -h / 4)
                    .rotation3DEffect(
                        .degrees(-90 * topP),
                        axis: (x: 1, y: 0, z: 0),
                        anchor: .bottom,
                        anchorZ: 0,
                        perspective: perspective
                    )
                    .brightness(-0.18 * topP)
                    .blur(radius: blurAmount(for: topP))
            } else {
                // 4. Falling bottom flap: new BOTTOM swings up to the seam (+90 -> 0).
                let botP = (p - 0.5) / 0.5 // 0...1
                SplitFlapView_HalfCard(char: to, top: false, metrics: metrics)
                    .frame(height: h / 2, alignment: .bottom)
                    .offset(y: h / 4)
                    .rotation3DEffect(
                        .degrees(90 * (1 - botP)),
                        axis: (x: 1, y: 0, z: 0),
                        anchor: .top,
                        anchorZ: 0,
                        perspective: perspective
                    )
                    .brightness(-0.18 * (1 - botP))
                    .blur(radius: blurAmount(for: 1 - botP))
            }
        }
        .frame(width: metrics.cardW, height: metrics.cardH)
        .clipShape(RoundedRectangle(cornerRadius: 3, style: .continuous))
        .overlay(
            RoundedRectangle(cornerRadius: 3, style: .continuous)
                .strokeBorder(Color.black.opacity(0.35), lineWidth: 0.75)
        )
        .shadow(color: Color.black.opacity(0.4), radius: 2, x: 0, y: 1.5)
    }

    // Motion blur peaks mid-swing (fastest angular speed) for the clatter feel.
    private func blurAmount(for t: Double) -> CGFloat {
        let v = sin(t * .pi) // 0 at ends, 1 mid-swing
        return CGFloat(v) * 0.7
    }
}
"""###,
        "tx-spotlight-sweep": ###"""
import SwiftUI

/// Spotlight Reveal — a soft radial spotlight glides across a dim embossed
/// headline, brightening and lifting only the characters it currently
/// illuminates, leaving a warm candlelight afterglow trail behind it.
///
/// - `demo == true`  → a self-driving TimelineView sweeps the spotlight
///   left → right → back on a ~3s loop, so the tile is always alive.
/// - `demo == false` → an idle auto-sweep that a `DragGesture` can grab:
///   your finger's x sets the spotlight center; releasing hands control
///   back to the gentle sweep, resuming from where you let go.
struct SpotlightSweepTextView: View {
    var demo: Bool = false

    private let phrase: String = "INSPIRE"

    // Interactive state (demo == false)
    @State private var dragX: CGFloat? = nil          // live finger x while dragging
    @State private var idlePhase: Double = 0           // 0...1 sweep position used at rest
    @State private var trailX: CGFloat = 0             // eased, lagged spotlight x for the wake
    @State private var lastSpotX: CGFloat = 0

    var body: some View {
        GeometryReader { geo in
            let size = geo.size
            ZStack {
                background
                if demo {
                    demoDriver(size: size)
                } else {
                    interactiveDriver(size: size)
                }
            }
            .frame(width: size.width, height: size.height)
            .contentShape(Rectangle())
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }

    // MARK: - Backdrop

    private var background: some View {
        LinearGradient(
            colors: [
                Color(red: 0.04, green: 0.05, blue: 0.10),
                Color(red: 0.02, green: 0.03, blue: 0.06)
            ],
            startPoint: .top,
            endPoint: .bottom
        )
        .ignoresSafeArea()
    }

    // MARK: - Drivers

    /// Self-driving loop for the grid tile.
    private func demoDriver(size: CGSize) -> some View {
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            let metrics = layout(for: size)
            // Smooth left↔right↔left sweep on a ~3s period.
            let phase = sweepPhase(time: t, period: 3.0)
            let spotX = spotlightX(phase: phase, metrics: metrics)
            // Trail = where the light was a small time-delta earlier, so the
            // wake flips direction correctly on the return pass.
            let trailPhase = sweepPhase(time: t - 0.28, period: 3.0)
            let trail = spotlightX(phase: trailPhase, metrics: metrics)
            headline(spotX: spotX, trailX: trail, metrics: metrics)
        }
    }

    /// Idle auto-sweep that a drag can grab and override.
    private func interactiveDriver(size: CGSize) -> some View {
        TimelineView(.animation) { timeline in
            let t = timeline.date.timeIntervalSinceReferenceDate
            let metrics = layout(for: size)
            let idleSpot = spotlightX(phase: sweepPhase(time: t, period: 3.0),
                                      metrics: metrics)
            // Finger wins when present; otherwise drift with the idle sweep.
            let spotX = dragX ?? idleSpot
            renderInteractive(spotX: spotX, metrics: metrics)
        }
        .gesture(dragGesture(size: size))
    }

    private func renderInteractive(spotX: CGFloat, metrics: Metrics) -> some View {
        // Ease the trailing afterglow toward the live spotlight so the wake
        // lags behind motion in either direction.
        let eased = trailX + (spotX - trailX) * 0.16
        DispatchQueue.main.async {
            trailX = eased
            lastSpotX = spotX
        }
        return headline(spotX: spotX, trailX: trailX, metrics: metrics)
    }

    private func dragGesture(size: CGSize) -> some Gesture {
        DragGesture(minimumDistance: 0)
            .onChanged { value in
                dragX = clampX(value.location.x, width: size.width)
            }
            .onEnded { _ in
                dragX = nil
            }
    }

    // MARK: - The single shared renderer

    private func headline(spotX: CGFloat, trailX: CGFloat, metrics: Metrics) -> some View {
        let chars = Array(phrase)
        return ZStack {
            // Dim embossed base — ALWAYS legible, never blank.
            embossedBase(chars: chars, metrics: metrics, spotX: spotX, trailX: trailX)

            // Warm afterglow blob trailing the light.
            afterglow(x: trailX, metrics: metrics)

            // Bright lit copy, additively layered, masked by the moving light.
            litWord(chars: chars, metrics: metrics, spotX: spotX)
                .mask(spotlightMask(x: spotX, metrics: metrics))
        }
        .frame(width: metrics.size.width, height: metrics.size.height)
    }

    // MARK: - Layers

    private func embossedBase(chars: [Character], metrics: Metrics,
                              spotX: CGFloat, trailX: CGFloat) -> some View {
        HStack(spacing: metrics.spacing) {
            ForEach(Array(chars.enumerated()), id: \.offset) { idx, ch in
                let cx = charCenterX(index: idx, metrics: metrics)
                let intensity = intensityFor(charX: cx, spotX: spotX, sigma: metrics.sigma)
                SpotlightSweepTextView_CharCell(character: ch,
                         fontSize: metrics.fontSize,
                         intensity: intensity)
            }
        }
        .frame(width: metrics.size.width, height: metrics.size.height)
    }

    private func litWord(chars: [Character], metrics: Metrics, spotX: CGFloat) -> some View {
        HStack(spacing: metrics.spacing) {
            ForEach(Array(chars.enumerated()), id: \.offset) { idx, ch in
                let cx = charCenterX(index: idx, metrics: metrics)
                let intensity = intensityFor(charX: cx, spotX: spotX, sigma: metrics.sigma)
                SpotlightSweepTextView_LitCharCell(character: ch,
                            fontSize: metrics.fontSize,
                            intensity: intensity)
            }
        }
        .frame(width: metrics.size.width, height: metrics.size.height)
    }

    private func spotlightMask(x: CGFloat, metrics: Metrics) -> some View {
        let r: CGFloat = metrics.spotRadius
        return RadialGradient(
            gradient: Gradient(stops: [
                .init(color: .white, location: 0.0),
                .init(color: .white.opacity(0.9), location: 0.45),
                .init(color: .white.opacity(0.25), location: 0.78),
                .init(color: .clear, location: 1.0)
            ]),
            center: .center,
            startRadius: 0,
            endRadius: r
        )
        .frame(width: r * 2, height: r * 2)
        .position(x: x, y: metrics.size.height / 2)
        .frame(width: metrics.size.width, height: metrics.size.height)
    }

    private func afterglow(x: CGFloat, metrics: Metrics) -> some View {
        let r: CGFloat = metrics.spotRadius * 1.15
        return RadialGradient(
            gradient: Gradient(colors: [
                Color(red: 1.0, green: 0.66, blue: 0.30).opacity(0.34),
                Color(red: 0.95, green: 0.50, blue: 0.18).opacity(0.10),
                Color.clear
            ]),
            center: .center,
            startRadius: 0,
            endRadius: r
        )
        .frame(width: r * 2, height: r * 2)
        .position(x: x, y: metrics.size.height / 2)
        .frame(width: metrics.size.width, height: metrics.size.height)
        .blendMode(.screen)
        .allowsHitTesting(false)
    }

    // MARK: - Math helpers

    /// Triangle/sine sweep position in 0...1 (eased), ping-ponging.
    private func sweepPhase(time: Double, period: Double) -> Double {
        let p = (time.truncatingRemainder(dividingBy: period)) / period
        // 0→1→0 via cosine for soft turnarounds.
        return (1 - cos(p * 2 * .pi)) / 2
    }

    private func spotlightX(phase: Double, metrics: Metrics) -> CGFloat {
        let pad = metrics.fontSize * 0.4
        let lo = pad
        let hi = metrics.size.width - pad
        return lo + (hi - lo) * CGFloat(phase)
    }

    private func charCenterX(index: Int, metrics: Metrics) -> CGFloat {
        let n = max(metrics.count, 1)
        let usable = metrics.size.width
        let step = usable / CGFloat(n)
        return step * (CGFloat(index) + 0.5)
    }

    /// Gaussian falloff of brightness vs. distance to the spotlight x.
    private func intensityFor(charX: CGFloat, spotX: CGFloat, sigma: CGFloat) -> Double {
        let dx = Double(charX - spotX)
        let s = Double(sigma)
        let v = exp(-(dx * dx) / (2 * s * s))
        return min(max(v, 0), 1)
    }

    private func clampX(_ x: CGFloat, width: CGFloat) -> CGFloat {
        min(max(x, 0), width)
    }

    // MARK: - Layout metrics

    struct Metrics {
        var size: CGSize
        var count: Int
        var fontSize: CGFloat
        var spacing: CGFloat
        var sigma: CGFloat
        var spotRadius: CGFloat
    }

    private func layout(for size: CGSize) -> Metrics {
        let count = max(phrase.count, 1)
        // Size the type to the geometry so it fits a 120pt tile and a big detail.
        let byWidth = size.width / CGFloat(count) * 1.18
        let byHeight = size.height * 0.42
        let fontSize = min(byWidth, byHeight)
        let sigma = max(size.width * 0.16, fontSize * 1.1)
        let spotRadius = max(size.width * 0.30, fontSize * 1.8)
        return Metrics(
            size: size,
            count: count,
            fontSize: fontSize,
            spacing: fontSize * 0.04,
            sigma: sigma,
            spotRadius: spotRadius
        )
    }
}

// MARK: - Character cells

/// The dim, embossed resting glyph. Stays legible on every frame; the
/// spotlight only nudges its scale/shadow so it lifts subtly into the light.
private struct SpotlightSweepTextView_CharCell: View {
    let character: Character
    let fontSize: CGFloat
    let intensity: Double

    var body: some View {
        let lift = CGFloat(intensity) * 6
        let scale = 1 + 0.16 * intensity
        Text(String(character))
            .font(.system(size: fontSize, weight: .heavy, design: .rounded))
            .kerning(fontSize * 0.02)
            // Cool dim base — readable floor, brightened a touch by the light.
            .foregroundStyle(baseColor)
            // Embossed feel: dark drop below, faint light above.
            .shadow(color: .black.opacity(0.55),
                    radius: 1, x: 0, y: 1.5)
            .shadow(color: .white.opacity(0.06 + 0.10 * intensity),
                    radius: 0.5, x: 0, y: -0.5)
            // Warm cast + lift only where illuminated.
            .shadow(color: Color(red: 1.0, green: 0.62, blue: 0.28)
                        .opacity(0.55 * intensity),
                    radius: 8 * CGFloat(intensity), x: 0, y: 0)
            .scaleEffect(scale)
            .offset(y: -lift)
            .lineLimit(1)
            .minimumScaleFactor(0.4)
    }

    private var baseColor: Color {
        // Dim slate at rest, easing toward a paler tone under the light.
        let lo = 0.30, hi = 0.55
        let v = lo + (hi - lo) * intensity
        return Color(red: v * 0.92, green: v * 0.96, blue: v)
    }
}

/// The bright "lit" copy. This whole layer is masked by the radial spotlight,
/// so it only shows through where the light is. Per-char intensity boosts the
/// warmth and glow of the letter currently under the beam.
private struct SpotlightSweepTextView_LitCharCell: View {
    let character: Character
    let fontSize: CGFloat
    let intensity: Double

    var body: some View {
        let scale = 1 + 0.16 * intensity
        let lift = CGFloat(intensity) * 6
        Text(String(character))
            .font(.system(size: fontSize, weight: .heavy, design: .rounded))
            .kerning(fontSize * 0.02)
            .foregroundStyle(warm)
            .shadow(color: Color(red: 1.0, green: 0.72, blue: 0.36)
                        .opacity(0.9), radius: 6, x: 0, y: 0)
            .shadow(color: Color(red: 1.0, green: 0.55, blue: 0.18)
                        .opacity(0.7), radius: 14, x: 0, y: 0)
            .scaleEffect(scale)
            .offset(y: -lift)
            .lineLimit(1)
            .minimumScaleFactor(0.4)
    }

    private var warm: LinearGradient {
        LinearGradient(
            colors: [
                Color(red: 1.0, green: 0.96, blue: 0.86),
                Color(red: 1.0, green: 0.82, blue: 0.50)
            ],
            startPoint: .top,
            endPoint: .bottom
        )
    }
}
"""###,
        "tx-stamp-ink": ###"""
import SwiftUI

// MARK: - Rubber Stamp Slam
// The word slams down as an over-rotated ink stamp that overshoots in scale,
// kicks up a faint dust ring, and leaves a textured uneven-ink imprint with
// slightly heavier edges and a tiny settle wobble.
//
// demo == true  -> self-driving PhaseAnimator loop (~3s, rest-dominant)
// demo == false -> tap to replay the KeyframeAnimator slam

struct StampInkView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { geo in
            let size = geo.size
            let side = min(size.width, size.height)

            ZStack {
                StampInkView_StampBackdrop(side: side)

                if demo {
                    StampInkView_DemoStamp(side: side)
                } else {
                    StampInkView_InteractiveStamp(side: side)
                }
            }
            .frame(width: size.width, height: size.height)
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
    }
}

// MARK: - Animatable pose shared by both drivers

private struct StampInkView_StampPose {
    var scale: CGFloat = 1.0
    var rotation: Double = -8.0   // resting over-rotated tilt (degrees)
    var inkOpacity: Double = 1.0  // legibility of the stamped word
    var dust: CGFloat = 0.0       // 0 = no ring, 1 = fully expanded/faded
    var press: CGFloat = 0.0      // 0 = lifted, 1 = pressed flat into page

    static let rest = StampInkView_StampPose(scale: 1.0, rotation: -8.0, inkOpacity: 1.0, dust: 0.0, press: 0.0)
}

// MARK: - Backdrop (paper card)

private struct StampInkView_StampBackdrop: View {
    let side: CGFloat

    var body: some View {
        let inset = side * 0.06
        RoundedRectangle(cornerRadius: side * 0.10, style: .continuous)
            .fill(paperGradient)
            .overlay(
                RoundedRectangle(cornerRadius: side * 0.10, style: .continuous)
                    .strokeBorder(Color(red: 0.86, green: 0.83, blue: 0.77), lineWidth: 1)
            )
            .padding(inset)
            .shadow(color: Color.black.opacity(0.18), radius: side * 0.04, x: 0, y: side * 0.02)
    }

    private var paperGradient: LinearGradient {
        LinearGradient(
            colors: [
                Color(red: 0.98, green: 0.97, blue: 0.93),
                Color(red: 0.94, green: 0.92, blue: 0.86)
            ],
            startPoint: .topLeading,
            endPoint: .bottomTrailing
        )
    }
}

// MARK: - The stamped face (renders from a StampInkView_StampPose)

private struct StampInkView_StampFace: View {
    let pose: StampInkView_StampPose
    let side: CGFloat

    private let word = "APPROVED"
    private let inkColor = Color(red: 0.74, green: 0.13, blue: 0.16)

    var body: some View {
        ZStack {
            dustRing
            stampedWord
        }
        .frame(width: side, height: side)
    }

    // The ink imprint: a textured/uneven word in stamp red.
    private var stampedWord: some View {
        let pressLift = 1.0 - Double(pose.press) * 0.12

        return wordText
            .overlay(StampInkView_GrainOverlay(side: side, ink: inkColor).mask(wordText))
            .overlay(StampInkView_EdgeBleed(side: side, ink: inkColor).mask(wordText))
            .opacity(pose.inkOpacity * pressLift)
            .scaleEffect(pose.scale)
            .rotationEffect(.degrees(pose.rotation))
            // soft impact shadow that tightens as it presses flat
            .shadow(
                color: inkColor.opacity(0.28 * (1.0 - Double(pose.press) * 0.5)),
                radius: side * 0.012 * (1.0 + (1.0 - pose.press) * 2.0),
                x: 0,
                y: 0
            )
    }

    private var wordText: some View {
        Text(word)
            .font(.system(size: side * 0.16, weight: .heavy, design: .rounded))
            .tracking(side * 0.012)
            .foregroundStyle(inkColor)
            .lineLimit(1)
            .minimumScaleFactor(0.4)
            .padding(.horizontal, side * 0.10)
            .overlay(
                RoundedRectangle(cornerRadius: side * 0.04, style: .continuous)
                    .strokeBorder(inkColor, lineWidth: side * 0.012)
                    .padding(.horizontal, side * 0.045)
                    .padding(.vertical, side * 0.02)
            )
    }

    // Expanding + fading dust ring kicked up by the slam.
    private var dustRing: some View {
        let ringScale = 0.25 + pose.dust * 1.05
        let ringOpacity = Double(max(0.0, 1.0 - pose.dust)) * 0.5

        return Circle()
            .strokeBorder(
                Color(red: 0.55, green: 0.50, blue: 0.42),
                lineWidth: side * 0.02 * (1.0 - pose.dust * 0.7)
            )
            .frame(width: side * 0.46, height: side * 0.46)
            .scaleEffect(ringScale)
            .rotationEffect(.degrees(pose.rotation))
            .opacity(ringOpacity)
            .blur(radius: side * 0.006)
    }
}

// MARK: - Static seeded grain (uneven-ink texture, generated once)

private struct StampInkView_GrainOverlay: View {
    let side: CGFloat
    let ink: Color

    var body: some View {
        Canvas { context, canvasSize in
            var rng = StampInkView_SeededRandom(seed: 0xA17C_E901)
            let count = 90
            for _ in 0..<count {
                let x = rng.nextUnit() * canvasSize.width
                let y = rng.nextUnit() * canvasSize.height
                let r = (0.6 + rng.nextUnit() * 1.8)
                let hole = rng.nextUnit() < 0.55
                let rect = CGRect(x: x - r, y: y - r, width: r * 2, height: r * 2)
                // "hole" speckles knock ink OUT (patchy coverage); others add density
                let alpha = hole ? 0.85 : 0.4
                let color = hole ? Color(red: 0.98, green: 0.97, blue: 0.93) : ink
                context.fill(Path(ellipseIn: rect), with: .color(color.opacity(alpha)))
            }
        }
    }
}

// Slightly heavier ink along edges — a subtle darker vignette inside the glyphs.
private struct StampInkView_EdgeBleed: View {
    let side: CGFloat
    let ink: Color

    var body: some View {
        RadialGradient(
            colors: [
                Color.clear,
                ink.opacity(0.0),
                Color(red: 0.50, green: 0.08, blue: 0.10).opacity(0.45)
            ],
            center: .center,
            startRadius: side * 0.05,
            endRadius: side * 0.42
        )
    }
}

// Tiny deterministic LCG so the grain is stable across redraws.
private struct StampInkView_SeededRandom {
    private var state: UInt64
    init(seed: UInt64) { state = seed == 0 ? 0x9E37_79B9 : seed }

    mutating func nextUnit() -> CGFloat {
        state = state &* 6364136223846793005 &+ 1442695040888963407
        let top = (state >> 33) & 0x7FFF_FFFF
        return CGFloat(top) / CGFloat(0x7FFF_FFFF)
    }
}

// MARK: - Demo driver (self-driving PhaseAnimator, ~3s, rest-dominant)

private struct StampInkView_DemoStamp: View {
    let side: CGFloat

    var body: some View {
        // Phases: a quick wind-up + slam, then a long legible rest.
        PhaseAnimator(StampInkView_StampPhase.allCases) { phase in
            StampInkView_StampFace(pose: phase.pose, side: side)
        } animation: { phase in
            phase.transition
        }
    }
}

private enum StampInkView_StampPhase: CaseIterable {
    case lifted     // raised, slightly transparent but legible
    case impact     // slammed past 1, hardest tilt, dust born
    case settle     // tiny overshoot wobble back
    case rest       // resting, full ink (dominant slice)

    var pose: StampInkView_StampPose {
        switch self {
        case .lifted:
            return StampInkView_StampPose(scale: 1.42, rotation: -16, inkOpacity: 0.82, dust: 0.0, press: 0.0)
        case .impact:
            return StampInkView_StampPose(scale: 0.94, rotation: -3, inkOpacity: 1.0, dust: 1.0, press: 1.0)
        case .settle:
            return StampInkView_StampPose(scale: 1.05, rotation: -10, inkOpacity: 1.0, dust: 1.0, press: 0.6)
        case .rest:
            return StampInkView_StampPose(scale: 1.0, rotation: -8, inkOpacity: 1.0, dust: 1.0, press: 0.0)
        }
    }

    var transition: Animation {
        switch self {
        case .lifted:
            // re-arm: ease back up, hold a beat
            return .easeInOut(duration: 0.55)
        case .impact:
            // the slam — fast and forceful
            return .spring(response: 0.18, dampingFraction: 0.45)
        case .settle:
            // bounce-back wobble
            return .spring(response: 0.30, dampingFraction: 0.55)
        case .rest:
            // long legible dwell so the tile never reads as dead/flickering
            return .easeOut(duration: 1.6)
        }
    }
}

// MARK: - Interactive driver (tap to slam)

private struct StampInkView_InteractiveStamp: View {
    let side: CGFloat
    @State private var tapCount: Int = 0

    var body: some View {
        KeyframeAnimator(initialValue: StampInkView_StampPose.rest, trigger: tapCount) { pose in
            StampInkView_StampFace(pose: pose, side: side)
                .overlay(alignment: .bottom) { hint }
        } keyframes: { _ in
            keyframeTrack
        }
        .contentShape(Rectangle())
        .onTapGesture { tapCount += 1 }
    }

    private var hint: some View {
        Text(tapCount == 0 ? "tap to stamp" : "")
            .font(.system(size: side * 0.055, weight: .semibold, design: .rounded))
            .foregroundStyle(Color(red: 0.45, green: 0.42, blue: 0.36).opacity(0.7))
            .padding(.bottom, side * 0.05)
            .allowsHitTesting(false)
    }

    @KeyframesBuilder<StampInkView_StampPose>
    private var keyframeTrack: some Keyframes<StampInkView_StampPose> {
        // Wind up high, slam past 1, wobble, settle to rest.
        KeyframeTrack(\.scale) {
            CubicKeyframe(1.55, duration: 0.0)
            SpringKeyframe(0.92, duration: 0.18, spring: .init(response: 0.18, dampingRatio: 0.42))
            SpringKeyframe(1.06, duration: 0.16, spring: .init(response: 0.22, dampingRatio: 0.5))
            SpringKeyframe(1.0, duration: 0.32, spring: .init(response: 0.30, dampingRatio: 0.6))
        }
        KeyframeTrack(\.rotation) {
            CubicKeyframe(-18, duration: 0.0)
            SpringKeyframe(-2, duration: 0.18, spring: .init(response: 0.18, dampingRatio: 0.42))
            SpringKeyframe(-11, duration: 0.16, spring: .init(response: 0.22, dampingRatio: 0.5))
            SpringKeyframe(-8, duration: 0.32, spring: .init(response: 0.30, dampingRatio: 0.6))
        }
        KeyframeTrack(\.inkOpacity) {
            CubicKeyframe(0.82, duration: 0.0)
            CubicKeyframe(1.0, duration: 0.18)
            CubicKeyframe(1.0, duration: 0.48)
        }
        KeyframeTrack(\.press) {
            CubicKeyframe(0.0, duration: 0.0)
            CubicKeyframe(1.0, duration: 0.18)
            CubicKeyframe(0.5, duration: 0.16)
            CubicKeyframe(0.0, duration: 0.32)
        }
        KeyframeTrack(\.dust) {
            CubicKeyframe(0.0, duration: 0.0)
            LinearKeyframe(0.05, duration: 0.16)
            CubicKeyframe(1.0, duration: 0.7)
        }
    }
}
"""###,
        "tx-typewriter-cursor": ###"""
import SwiftUI

// MARK: - Typewriter Carriage
// Characters type in one at a time over a prefix of each line with a blinking
// block cursor and a subtle per-key vertical jitter. When a line finishes, the
// page feeds up (carriage-return) and the cursor snaps back to the left margin
// with a soft damped mechanical settle before the next line types. Everything is
// derived in closed form from a single TimelineView(.animation) clock so it is
// fully self-driving and never blank. iOS 17.

struct TypewriterCursorView: View {
    var demo: Bool = false

    var body: some View {
        GeometryReader { geo in
            TimelineView(.animation) { context in
                let t = context.date.timeIntervalSince(Self.epoch)
                content(in: geo.size, elapsed: t)
            }
        }
        .frame(maxWidth: .infinity, maxHeight: .infinity)
        .background(Self.paper)
    }

    // Shared monotonic clock so the loop is stable across rebuilds.
    private static let epoch = Date()

    // Warm off-white "paper" so dark ink reads clearly at any tile size.
    private static let paper = Color(red: 0.96, green: 0.95, blue: 0.91)
    private static let ink = Color(red: 0.10, green: 0.10, blue: 0.13)

    // Two short lines so the signature carriage-return shift is always exercised.
    private var lines: [String] {
        demo
            ? ["hello, world.", "type type type."]
            : ["the quick brown fox", "jumps over it all."]
    }

    // MARK: - Timing model (all closed-form off `elapsed`)

    private let charInterval: Double = 0.12   // seconds per keystroke
    private let lineHold: Double = 0.9         // pause after a line completes
    private let returnTime: Double = 0.55      // carriage-return travel + settle

    private func lineDuration(_ s: String) -> Double {
        Double(s.count) * charInterval + lineHold + returnTime
    }

    private var cycleDuration: Double {
        lines.reduce(0) { $0 + lineDuration($1) } + 0.6 // trailing breath before repeat
    }

    // Resolve which line is active, how far into it, and how many of the
    // earlier lines are fully typed (shown above as the page scrolls up).
    private func phase(at elapsed: Double) -> Phase {
        let loop = elapsed.truncatingRemainder(dividingBy: cycleDuration)
        var acc: Double = 0
        for (i, line) in lines.enumerated() {
            let dur = lineDuration(line)
            if loop < acc + dur {
                return Phase(lineIndex: i, localTime: max(0, loop - acc), line: line)
            }
            acc += dur
        }
        // Trailing breath: hold the last fully-typed line.
        let last = max(0, lines.count - 1)
        return Phase(lineIndex: last, localTime: lineDuration(lines[last]), line: lines[last])
    }

    struct Phase {
        let lineIndex: Int
        let localTime: Double
        let line: String
    }

    // MARK: - Body content

    private func content(in size: CGSize, elapsed: Double) -> some View {
        let p = phase(at: elapsed)
        let fontSize = max(13.0, min(size.width, size.height) * 0.16)
        let typed = max(0, min(p.line.count, Int(p.localTime / charInterval)))
        let lineComplete = typed >= p.line.count
        let carriage = carriageReturn(phase: p, fontSize: fontSize)
        let priorCount = max(0, p.lineIndex)

        return VStack(alignment: .leading, spacing: fontSize * 0.42) {
            // Already-completed lines sit above, fully typed.
            ForEach(0..<priorCount, id: \.self) { i in
                lineView(text: lines[i],
                         visible: lines[i].count,
                         fontSize: fontSize,
                         localTime: 999,
                         showCursor: false,
                         carriageX: 0)
            }
            // Active line with the live cursor + per-key jitter.
            lineView(text: p.line,
                     visible: typed,
                     fontSize: fontSize,
                     localTime: p.localTime,
                     showCursor: true,
                     carriageX: lineComplete ? carriage : 0)
        }
        .font(.system(size: fontSize, weight: .medium, design: .monospaced))
        .foregroundStyle(Self.ink)
        // Feed the page up so the active line stays roughly centered.
        .frame(maxWidth: .infinity, maxHeight: .infinity, alignment: .leading)
        .padding(.horizontal, fontSize * 0.6)
        .offset(y: feedOffset(lineIndex: p.lineIndex, fontSize: fontSize, viewHeight: size.height))
        .clipped()
    }

    // Vertical paper feed: keep the cursor band near the middle of the tile.
    private func feedOffset(lineIndex: Int, fontSize: CGFloat, viewHeight: CGFloat) -> CGFloat {
        let lineStep = fontSize * 1.42
        let totalActive = CGFloat(lineIndex) * lineStep
        let target = viewHeight * 0.5 - fontSize * 0.6
        return max(0, target - totalActive)
    }

    // Damped mechanical settle for the carriage-return slide. The cursor has
    // just travelled back to the left margin; it overshoots slightly and rings
    // down via A*exp(-d*t)*cos(w*t).
    private func carriageReturn(phase p: Phase, fontSize: CGFloat) -> CGFloat {
        let doneAt = Double(p.line.count) * charInterval + lineHold
        let dt = p.localTime - doneAt
        guard dt > 0 else { return 0 }
        let amp = fontSize * 0.9
        let decay = 9.0
        let omega = 22.0
        let ring = amp * CGFloat(exp(-decay * dt) * cos(omega * dt))
        return ring
    }

    // MARK: - Line + cursor

    private func lineView(text: String,
                          visible: Int,
                          fontSize: CGFloat,
                          localTime: Double,
                          showCursor: Bool,
                          carriageX: CGFloat) -> some View {
        let chars = Array(text)
        let count = max(0, min(visible, chars.count))

        return HStack(alignment: .firstTextBaseline, spacing: 0) {
            ForEach(0..<count, id: \.self) { i in
                glyph(String(chars[i]), index: i, localTime: localTime, fontSize: fontSize)
            }
            if showCursor {
                cursor(fontSize: fontSize, localTime: localTime)
                    .offset(x: carriageX)
            }
        }
        .frame(maxWidth: .infinity, alignment: .leading) // left-anchored: no slosh
    }

    // A single glyph with a brief downward keystroke jitter that auto-settles.
    private func glyph(_ s: String, index i: Int, localTime: Double, fontSize: CGFloat) -> some View {
        let appearedAt = Double(i) * charInterval
        let age = localTime - appearedAt
        let jitter: CGFloat
        if age >= 0 && age < 0.5 {
            jitter = fontSize * 0.14 * CGFloat(exp(-14.0 * age) * cos(40.0 * age))
        } else {
            jitter = 0
        }
        return Text(s)
            .offset(y: jitter)
            .transition(.identity)
    }

    // Blinking solid block cursor — always rendered so a frame is never blank.
    private func cursor(fontSize: CGFloat, localTime: Double) -> some View {
        let blink = localTime.truncatingRemainder(dividingBy: 1.06) < 0.6 ? 1.0 : 0.18
        return RoundedRectangle(cornerRadius: 1)
            .fill(Self.ink)
            .frame(width: fontSize * 0.58, height: fontSize * 0.92)
            .opacity(blink)
            .padding(.leading, fontSize * 0.06)
    }
}
